namespace Wolf.Core
{
	public class App : MvxApplication
	{
		public override void Initialize()
		{
			RegisterAppStart(new CustomAppStart());
			_ = CrossDevice.Device.OperatingSystem;
			MvvmCross.Plugins.WebBrowser.PluginLoader.Instance.EnsureLoaded();
			MvvmCross.Plugins.Location.PluginLoader.Instance.EnsureLoaded();
		}
	}
	public class CustomAppStart : MvxNavigatingObject, IMvxAppStart
	{
		public void Start(object hint = null)
		{
			if (hint != null)
			{
				Mvx.Trace("Hint ignored in default MvxAppStart");
			}
			IHardwareInfo hardwareInfo = Mvx.Resolve<IHardwareInfo>();
			bool isAndroid = hardwareInfo.IsAndroid;
			Task.Run(async delegate
			{
				await EventService.Instance.LogAsync("App Launch Time").ConfigureAwait(continueOnCapturedContext: false);
			});
			Task.Run(async () => await EventService.Instance.CreateAsync("Launch Screen Time").ConfigureAwait(continueOnCapturedContext: false));
			if (isAndroid)
			{
				if (!NavigatingToDemoMode())
				{
					ShowViewModel<WelcomeViewModel>();
				}
			}
			else
			{
				ShowViewModel<LaunchScreenViewModel>();
			}
		}

		private bool NavigatingToDemoMode()
		{
			if (!Mvx.TryResolve<IDemoModeService>(out var service) || !service.IsInDemoMode || !service.CanEnterDemoMode())
			{
				return false;
			}
			service.ResumeDemoMode();
			return true;
		}
	}
	public class SettingsMessageTargetBinding : MvxTargetBinding
	{
		protected ISettingsMessage MessageTarget => (ISettingsMessage)base.Target;

		public override Type TargetType => typeof(string);

		public override MvxBindingMode DefaultMode => MvxBindingMode.OneWay;

		public SettingsMessageTargetBinding(ISettingsMessage target)
			: base(target)
		{
			if (target == null)
			{
				throw new ArgumentNullException("target", "Object must implement ISettingsMessage");
			}
		}

		public override void SetValue(object value)
		{
			string text = value as string;
			if (!string.IsNullOrEmpty(text))
			{
				Task task = MessageTarget?.ShowSettingsMessage(text);
			}
		}
	}
