	public static class CommonWolfAppSetup
	{
		public const string Tag = "Startup";

		public const string LogFolderName = ".wolflogs";

		public const string EruLogFolderName = "eru";

		public const string PreferredLocalContentFolderName = ".PersistentFiles";

		public const string LocalMachineCacheFileName = "blobs.db";

		public const string SecureCacheFileName = "secret.db";

		public const string UnobservedTaskExceptionTag = "UnobservedTaskException";

		public const string AkavacheApplicationName = "wolf";

		private const int LocalMachineValidationTimeoutSeconds = 10;

		private const string CorruptionCheckKey = "IsTheDatabaseFine";

		private const string CorruptionCheckValue = "DatabaseIsFine";

		private static IFilesystemProvider AkavacheFilesystemProvider => (IFilesystemProvider)Locator.Current.GetService(typeof(IFilesystemProvider));

		public static string SecureCacheDirectory => AkavacheFilesystemProvider.GetDefaultSecretCacheDirectory();

		public static string LocalMachineCacheDirectory => AkavacheFilesystemProvider.GetDefaultLocalMachineCacheDirectory();

		public static void SetupLogger()
		{
			Log.AddTag("BleData");
			Log.Trace("Startup", "Logger setup completed.");
		}

		public static async Task<ILocalSettings> SharedSetup(IBlobCacheFileManager blobCacheFileManager, IConnectivity connectivity = null)
		{
			bool isDebug = false;
			bool isAutomatedTesting = false;
			bool isRoboRun = false;
			Log.Trace("Startup", "Entering Shared Setup, Debug State: " + isDebug);
			BlobCache.ApplicationName = "wolf";
			BlobCache.EnsureInitialized();
			Log.Trace("Startup", "BlobCache EnsureInitialized has completed");
			IFitnessConsoleManager fitnessConsoleManager = CommonShireAppSetup.RegisterShireDependencies();
			IBlobCacheService blobCacheService = InitializeCaches();
			SettingsMigrationService settingsMigrationService = new SettingsMigrationService(blobCacheService);
			await settingsMigrationService.GetLocalSettings();
			Mvx.RegisterSingleton(settingsMigrationService);
			SettingsMigrationServiceV2 settingsMigrationServiceV2 = new SettingsMigrationServiceV2(blobCacheService);
			await settingsMigrationServiceV2.GetLocalSettings();
			Mvx.RegisterSingleton(settingsMigrationServiceV2);
			ILocalSettings localSettings = await LocalSettings.CreateAsync(blobCacheService, blobCacheFileManager);
			Mvx.RegisterSingleton(localSettings);
			localSettings.InDebugMode = isDebug;
			localSettings.IsAutomatedTestingMode = isAutomatedTesting;
			localSettings.IsRoboRunMode = isRoboRun;
			(IPersistentMusicSettings, IBlobCacheService) tuple = await InitializeMusicService(blobCacheService, blobCacheFileManager).ConfigureAwait(continueOnCapturedContext: false);
			_ = tuple.Item1;
			blobCacheService = tuple.Item2;
			(IPersistentLockPinSettings, IBlobCacheService) tuple2 = await InitializeLockPinService(blobCacheService, blobCacheFileManager).ConfigureAwait(continueOnCapturedContext: false);
			_ = tuple2.Item1;
			blobCacheService = tuple2.Item2;
			bool doResetEnvironment = UpdateStartupEnvironment(localSettings);
			IDeviceInformation deviceInformation = Mvx.Resolve<IDeviceInformation>();
			deviceInformation.LoadFromCache();
			IDeveloperSettings developerSettings = await DeveloperSettings.CreateAsync(blobCacheService);
			Mvx.RegisterSingleton(developerSettings);
			developerSettings.MockDevicesEnabled = isDebug;
			IWorkoutSettings workoutSettings = await WorkoutSettings.CreateAsync(blobCacheService);
			Mvx.RegisterSingleton(workoutSettings);
			Mvx.RegisterSingleton((IWebviewSettings)new WebviewSettings(blobCacheService, blobCacheFileManager));
			Mvx.RegisterSingleton(await RetailDemoModeSettings.CreateAsync(blobCacheService));
			Mvx.LazyConstructAndRegisterSingleton<IIfitApiInjectionService, IfitApiInjectionService>();
			IPlatformWolfAppSetup platformWolfAppSetup = Mvx.Resolve<IPlatformWolfAppSetup>();
			IIfitEnvironment environmentToUse = platformWolfAppSetup.DetermineEnvironment(Mvx.Resolve<IRaygunInfo>(), localSettings);
			Mvx.ConstructAndRegisterSingleton<IUserAgent, WolfUserAgent>();
			Log.Trace("Startup", "Creating IfitApiService: " + environmentToUse);
			bool gzipPostData = !isDebug;
			IfitApiService ifitApi = new IfitApiService(blobCacheService, environmentToUse, Mvx.Resolve<IAuthenticatedHttpClientHandlerFactory>(), gzipPostData, Mvx.Resolve<IIfitApiInjectionService>());
			Log.Trace("Startup", "Initializing API Cache");
			await ifitApi.InitCache().ConfigureAwait(continueOnCapturedContext: false);
			if (doResetEnvironment)
			{
				Log.Trace("DeviceAdmin", "Resetting environment users and cache");
				await ifitApi.ResetEnvironment().ConfigureAwait(continueOnCapturedContext: false);
			}
			Log.Trace("Startup", "Registering API");
			Mvx.RegisterSingleton((IIfitApiService)ifitApi);
			FeedFmToggleSettingService feedFmToggleSettingService = new FeedFmToggleSettingService(ifitApi, blobCacheService, deviceInformation);
			Mvx.RegisterSingleton((IFeedFmToggleSettingService)feedFmToggleSettingService);
			IMediaSettings mediaSettings = await MediaSettings.CreateAsync(blobCacheService, feedFmToggleSettingService, deviceInformation);
			Mvx.RegisterSingleton(mediaSettings);
			await MediaSettingsDataMigrationUtil.Shared.TransferMediaSettingsDataIfNecessary(blobCacheService, blobCacheFileManager, mediaSettings, deviceInformation);
			IClubLocalSettings clubLocalSettings = await ClubLocalSettings.CreateAsync(localSettings, blobCacheService, deviceInformation, workoutSettings, mediaSettings);
			Mvx.RegisterSingleton(clubLocalSettings);
			Mvx.ConstructAndRegisterSingleton<IConnectivityService, ConnectivityService>();
			Mvx.RegisterSingleton(await PersistentBluetoothDevices.CreateAsync(blobCacheService, ifitApi));
			IPreferenceResolver preferenceResolver = await PreferenceResolver.CreateAsync(clubLocalSettings, blobCacheService, Mvx.Resolve<IWebviewSettings>(), ifitApi);
			Mvx.RegisterSingleton(preferenceResolver);
			ICurrentConsoleService consoleSettings = await CurrentConsoleService.CreateAsync(fitnessConsoleManager, blobCacheService, Mvx.Resolve<IHardwareInfo>(), preferenceResolver, deviceInformation, workoutSettings);
			Mvx.RegisterSingleton(consoleSettings);
			IAppLifecycleService appLifecycleService = new AppLifecycleService();
			Mvx.RegisterSingleton(appLifecycleService);
			if (Mvx.TryResolve<IDialogPresenter>(out var service))
			{
				service.RegisterLifecycleListeners(appLifecycleService);
			}
			else
			{
				Log.Error("Startup", "Failed to resolve IDialogPresenter...");
			}
			Mvx.RegisterSingleton(() => connectivity ?? CrossConnectivity.Current);
			WolfTrackingService wolfTrackingService = await WolfTrackingService.CreateAsync(localSettings, blobCacheService, consoleSettings, workoutSettings);
			Mvx.RegisterSingleton((IWolfTrackingService)wolfTrackingService);
			SetIsAppOpenedForFirstTime(wolfTrackingService);
			IAppVersionService versionService = Mvx.Resolve<IAppVersionService>();
			Mvx.TryResolve<ISKAdNetworkConversionUpdater>(out var service2);
