		private static bool UpdateStartupEnvironment(ILocalSettings localSettings)
		{
			Log.Trace("DeviceAdmin", $"LocalSettings target environment {localSettings.EnvironmentToUse}");
			bool flag = IsNewAppBuild();
			Log.Trace("DeviceAdmin", $"App is new install: {flag}");
			Environments targetEnvironment = GetTargetEnvironment(localSettings);
			bool flag2 = targetEnvironment != localSettings.EnvironmentToUse;
			Log.Trace("DeviceAdmin", $"Target environment matches local: {flag2}");
			if (flag)
			{
				Log.Trace("DeviceAdmin", "Setting local environment to target environment");
				localSettings.EnvironmentToUse = targetEnvironment;
			}
			return flag2 && flag;
		}

		private static Environments GetTargetEnvironment(ILocalSettings localSettings)
		{
			if (localSettings.EnvironmentToUse == Environments.Custom)
			{
				Log.Trace("DeviceAdmin", "Test build, targeting custom enivornment");
				return Environments.Custom;
			}
			if (localSettings.EnvironmentToUse == Environments.Dev)
			{
				return Environments.Dev;
			}
			if (localSettings.EnvironmentToUse == Environments.Prod)
			{
				return Environments.Prod;
			}
			Log.Trace("DeviceAdmin", "Test build, targetting test environment");
			return Environments.Test;
		}

		private static bool IsNewAppBuild()
		{
			if (Mvx.TryResolve<IAppVersionService>(out var service) && Mvx.TryResolve<IDeviceInformation>(out var service2))
			{
				Log.Trace("Startup", $"App version: {service.MainAppVersionInfo.AppVersion}.{service.MainAppVersionInfo.BuildNumber}");
				Log.Trace("DeviceAdmin", $"LocalSettings build number: {service2.BuildNumber}");
				if (service2.BuildNumber == service.MainAppVersionInfo.BuildNumber)
				{
					return false;
				}
				service2.BuildNumber = service.MainAppVersionInfo.BuildNumber;
			}
			else
			{
				Log.Trace("DeviceAdmin", "Failed to resolve AppVersionService");
			}
			return true;
		}

