		private static void RunNecessaryCommonLaunchBehaviors(ILocalSettings settings, ILaunchBehaviorService launchBehaviorService)
		{
			RunAndSetLaunchBehaviorIfNecessary(settings, launchBehaviorService, LaunchBehaviorFlag.DefaultWorkoutVolumeMixerLevelsApplication, delegate
			{
				if (Mvx.TryResolve<IMediaSettings>(out var service))
				{
					service.ResetTrainerVolumeToDefault();
					service.ResetMusicVolumeToDefault();
				}
			});
			RunAndSetLaunchBehaviorIfNecessary(settings, launchBehaviorService, LaunchBehaviorFlag.MigratePropertiesOutOfLocalSettingsV1, async delegate
			{
				if (Mvx.TryResolve<SettingsMigrationService>(out var service))
				{
					await service.MigrateSettings();
				}
			});
			RunAndSetLaunchBehaviorIfNecessary(settings, launchBehaviorService, LaunchBehaviorFlag.MigratePropertiesOutOfLocalSettingsV2, async delegate
			{
				SettingsMigrationServiceV2 settingsMigrationServiceV = Mvx.Resolve<SettingsMigrationServiceV2>();
				await settingsMigrationServiceV.MigrateSettings();
			});
		}

		public static void RunAndSetLaunchBehaviorIfNecessary(ILocalSettings settings, ILaunchBehaviorService launchBehaviorService, LaunchBehaviorFlag launchBehaviorFlag, Action<ILocalSettings> behavior)
		{
			if (launchBehaviorService == null)
			{
				Log.Trace("Startup", string.Format("Launch behavior {0} could not run. {1} is null.", launchBehaviorFlag, "launchBehaviorService"));
				return;
			}
			if (behavior == null)
			{
				Log.Trace("Startup", string.Format("Launch behavior {0} could not run. {1} is null.", launchBehaviorFlag, "behavior"));
				return;
			}
			if (launchBehaviorService.HasLaunchBehaviorOccurred(launchBehaviorFlag))
			{
				Log.Trace("Startup", $"Launch behavior {launchBehaviorFlag} has already occurred.");
				return;
			}
			Log.Trace("Startup", $"Launch behavior {launchBehaviorFlag} has not occurred. Attempting to run corresponding behavior...");
			try
			{
				behavior(settings);
				launchBehaviorService.SetLaunchBehaviorOccurred(launchBehaviorFlag);
			}
			catch (Exception exception)
			{
				Log.Error("Startup", $"Error occurred while trying to run launch behavior for {launchBehaviorFlag}.", exception);
			}
		}

