			{
				service2.ListenForActivePulseEnabledChanges(service);
				service2.ListenForSmartAdjustEnabledChanges(service);
				Log.Trace("Startup", $"InitializeWorkoutFeatureService: ActivePulseEnabled={service2.ActivePulseEnabled}, SmartAdjustEnabled={service2.SmartAdjustEnabled}");
			}
		}

		private static async Task<(IPersistentMusicSettings, IBlobCacheService)> InitializeMusicService(IBlobCacheService cacheService, IBlobCacheFileManager blobCacheFileManager)
		{
			Log.Trace("Startup", "Initializing MusicService");
			PersistentMusicSettings persistentMusicSettings;
			if (Mvx.TryResolve<IPersistentMusicSettings>(out var service))
			{
				Log.Trace("Startup", "MUSIC SETTINGS ALREADY INITIALIZED");
				Log.Trace("Startup", "Last Station Chosen in Workout: " + service.LastStationUserSelected);
				Log.Trace("Startup", "List of Preferred Stations: " + service.UserPreferredStations);
				persistentMusicSettings = (PersistentMusicSettings)service;
			}
			else
			{
				Log.Trace("Startup", "Verified music settings clear");
				persistentMusicSettings = await PersistentMusicSettings.LoadMusicSettings(cacheService, blobCacheFileManager).ConfigureAwait(continueOnCapturedContext: false);
				Log.Trace("Audio", "Loaded musicSettings: With last station - " + persistentMusicSettings.LastStationUserSelected);
			}
			Log.Trace("Startup", "Registering MusicSettings");
			Mvx.RegisterSingleton((IPersistentMusicSettings)persistentMusicSettings);
			return (persistentMusicSettings, cacheService);
		}

		private static async Task<(IPersistentLockPinSettings, IBlobCacheService)> InitializeLockPinService(IBlobCacheService cacheService, IBlobCacheFileManager blobCacheFileManager)
		{
			Log.Trace("Startup", "Initializing LockPinService");
			PersistentLockPinSettings persistentLockPinSettings;
			if (Mvx.TryResolve<IPersistentLockPinSettings>(out var service))
			{
				Log.Trace("Startup", "LOCK PIN SETTINGS ALREADY INITIALIZED");
				Log.Trace("Startup", "Has lock pin number stored: " + (string.IsNullOrWhiteSpace(service.LockPinNumber) ? "false" : "true"));
				persistentLockPinSettings = (PersistentLockPinSettings)service;
			}
			else
			{
				Log.Trace("Startup", "Verified lock pin settings clear");
				persistentLockPinSettings = await PersistentLockPinSettings.LoadLockPinSettings(cacheService, blobCacheFileManager).ConfigureAwait(continueOnCapturedContext: false);
				Log.Trace("Settings", "Loaded InitializeLockPinService");
			}
			Log.Trace("Startup", "Registering LockPinSettings");
			Mvx.RegisterSingleton((IPersistentLockPinSettings)persistentLockPinSettings);
			return (persistentLockPinSettings, cacheService);
		}

		private static async Task CheckForDatabaseCorruption(IBlobCacheService cacheService)
		{
			await cacheService.Secure.InvalidateObject<string>("IsTheDatabaseFine");
			await cacheService.Secure.GetOrFetchObject("IsTheDatabaseFine", () => Task.FromResult("DatabaseIsFine"));
		}

		private static IBlobCacheService ClearExistingDatabase(IBlobCacheFileManager blobCacheFileManager, SQLiteException e, string callingFunction)
		{
			Log.Error("Startup", $"CommonWolfAppSetup: ${callingFunction}: SQLiteException: SQLite3.Result: {e.Result} | Exception: {e.GetBaseException()}");
			blobCacheFileManager.NukeSQLDB();
			if (Mvx.TryResolve<BlobCacheService>(out var service))
			{
				service.Dispose();
			}
			InitializeAkavache();
			return InitializeCaches();
		}

