		private static void InitializeAkavache()
		{
			Locator.CurrentMutable.InitializeAkavache(Locator.Current);
			BlobCache.ApplicationName = "wolf";
			BlobCache.EnsureInitialized();
		}

		public static IBlobCacheService InitializeCaches()
		{
			Log.Trace("Startup", "Initializing caches");
			BlobCacheService blobCacheService = new BlobCacheService(BlobCache.Secure, BlobCache.InMemory);
