		public static void LogCacheStatus(IBlobCache cache, string prefix)
		{
			Task.Run(async delegate
			{
				try
				{
					IEnumerable<string> enumerable = await cache.GetAllKeys().FirstAsync();
					Log.Trace("DeviceAdmin", $"{prefix} cache key count is {enumerable?.CountSafe()}");
				}
				catch (SQLiteException exception)
				{
					Log.Error("DeviceAdmin", $"Could not check status of {cache}, is it corrupt?", exception);
				}
			});
		}

		public static bool IsIgnorableException(Exception e)
		{
			if (e?.StackTrace?.Contains("Undisposed.DisposeTracker") == true)
			{
				Log.Error("UnobservedTaskException", "NOT re-throwing Undisposed.DisposeTracker error.");
				return true;
			}
			if (e?.InnerException?.StackTrace?.Contains("com.launchdarkly.android.LDFailure: Network error in stream connection") == true || e?.StackTrace?.Contains("LaunchDarkly.EventSource.EventSourceStreamReader") == true || e?.InnerException?.Message?.Contains("LDAwaitFuture") == true)
			{
				Log.Error("UnobservedTaskException", $"NOT re-throwing LaunchDarkly error {e.InnerException ?? e}");
				return true;
			}
			if (e is ObjectDisposedException ex && ex.ObjectName.Equals("MobileAuthenticatedStream"))
			{
				Log.Error("UnobservedTaskException", "NOT re-throwing MobileAuthenticatedStream ObjectDisposedException.");
				return true;
			}
			if (e is IOException)
			{
				Log.Error("UnobservedTaskException", "NOT re-throwing unobserved IOException.");
				if (Mvx.TryResolve<IWolfAnalytics>(out var service))
				{
					service.HandledUnobservedIoException(e);
				}
				return true;
			}
			if (e?.StackTrace?.Contains("feed.fm", StringComparison.OrdinalIgnoreCase) == true && e?.StackTrace?.Contains("UnknownHostException", StringComparison.OrdinalIgnoreCase) == true)
			{
				Log.Error("UnobservedTaskException", $"NOT re-throwing Feed.fm error {e.InnerException ?? e}");
				return true;
			}
			return false;
		}
	}
