		private void DoPressNumber(string number)
		{
			if (pinNumberIndex <= pinNumberArray.Length - 1)
			{
				pinNumberArray[pinNumberIndex] = number;
				UpdatePinNumberProperties();
				pinNumberIndex++;
				LockPinDoesntMatch.Value = false;
			}
		}

		private void DoPressDelete()
		{
			if (pinNumberIndex != 0)
			{
				Array.Clear(pinNumberArray, pinNumberIndex - 1, 1);
				UpdatePinNumberProperties();
				pinNumberIndex--;
				LockPinDoesntMatch.Value = false;
			}
		}

		private void DoPressConfirm()
		{
			if (!PinNumberConfirmationMatch())
			{
				failedPinCounter++;
				LockPinDoesntMatch.Value = true;
				ClearPinNumberProperties();
				if (failedPinCounter >= 3)
				{
					DoClose();
				}
			}
			else if (IsRetailDemoModeEnabled)
			{
				demoModeService.ExitDemoModeAsync();
				DoClose();
			}
			else
			{
				DoClose();
				demoModeService.EnterDemoModeAsync();
			}
		}

		private void UpdatePinNumberProperties()
		{
			PinNumber1.Value = pinNumberArray[0];
			PinNumber2.Value = pinNumberArray[1];
			PinNumber3.Value = pinNumberArray[2];
			PinNumber4.Value = pinNumberArray[3];
			ButtonConfirmEnabled.Value = !string.IsNullOrEmpty(LockPinNumber) && LockPinNumber.Length == 4;
			ButtonDeleteEnabled.Value = LockPinNumber.Length > 0;
		}

		private void ClearPinNumberProperties()
		{
			pinNumberIndex = 0;
			Array.Clear(pinNumberArray, 0, pinNumberArray.Length);
			UpdatePinNumberProperties();
		}

		private bool PinNumberConfirmationMatch()
		{
			return "5294" == string.Concat(pinNumberArray);
		}

