	{
		public const string NativeMethodOpenUrl = "OpenUrl";

		private const string UrlKey = "url";

		private readonly IDeviceInformation deviceInfo;

		private readonly IBrowserService browserService;

		public override string BehaviorName => "OpenUrl";

		public OpenUrlBehaviorProvider(IDeviceInformation deviceInfo, IBrowserService browserService)
		{
			this.deviceInfo = deviceInfo;
			this.browserService = browserService;
		}

		public override Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			string value = null;
			if (parameters != null && parameters.TryGetValue("url", out value))
			{
				IDeviceInformation deviceInformation = deviceInfo;
