	public interface IMultiClickSecretGesture
	{
		void Update();
	}
	public class MultiClickSecretGesture : IMultiClickSecretGesture
	{
		private readonly Action NormalCallback;

		private readonly Action SecretCallback;

		private readonly int ClickCount;

		private int touchCount;

		private Subject<bool> update = new Subject<bool>();

		private IObservable<long> timer;

		private IDisposable timerSubscription;

		public MultiClickSecretGesture(Action normalCallback, Action secretCallback, int clickCount = 10)
		{
			NormalCallback = normalCallback;
			SecretCallback = secretCallback;
			ClickCount = clickCount;
		}

		public void Update()
		{
			timer = update.Select((bool x) => Observable.Interval(TimeSpan.FromMilliseconds(250.0))).Switch();
			timerSubscription?.Dispose();
			timerSubscription = timer.Subscribe(delegate
			{
				TimerUpdate();
			});
			touchCount++;
			update.OnNext(value: true);
		}

		private void TimerUpdate()
		{
			if (touchCount >= ClickCount)
			{
				SecretCallback();
			}
			else
			{
				NormalCallback();
			}
			touchCount = 0;
			timerSubscription?.Dispose();
		}
	}
	public static class SettingsExtensions
