	public class WeeklyStatModel
	{
		public enum StatType
		{
			Calories,
			ActiveTime,
			Distance,
			ElevationGain,
			ActivityLogCount
		}

		public StatType Type { get; private set; }

		public string ValueText { get; private set; }

		public string UnitText { get; private set; }

		public string TypeLabelText { get; private set; }

		public static WeeklyStatModel Create(StatType statType, double statValue, bool isMetric)
		{
			return statType switch
			{
				StatType.Calories => CreateCalorieStat(statValue), 
				StatType.ActiveTime => CreateActiveTimeStat(statValue), 
				StatType.Distance => CreateDistanceStat(statValue, isMetric), 
				StatType.ElevationGain => CreateElevationStat(statValue, isMetric), 
				StatType.ActivityLogCount => CreateActivityLogCountStat(statValue), 
				_ => null, 
			};
		}

		private static WeeklyStatModel CreateCalorieStat(double statValue)
		{
			WeeklyStatModel weeklyStatModel = new WeeklyStatModel();
			weeklyStatModel.Type = StatType.Calories;
			double num = Math.Round(statValue);
			weeklyStatModel.ValueText = (string)new DoubleToStringValueConverter(0, showLeadingZero: true, showThousandsSeparator: true).Convert(num, typeof(string), null, CultureInfo.CurrentCulture);
			weeklyStatModel.UnitText = Wolf.Core.Resources.AppStrings.cal.ToUpper();
			weeklyStatModel.TypeLabelText = Wolf.Core.Resources.AppStrings.calorie_burn.ToUpper();
			return weeklyStatModel;
		}

		private static WeeklyStatModel CreateActiveTimeStat(double statValue)
		{
			WeeklyStatModel weeklyStatModel = new WeeklyStatModel();
			weeklyStatModel.Type = StatType.ActiveTime;
			int num = 1000;
			weeklyStatModel.ValueText = ValueFormatters.SecondsFormatter.Format(statValue / (double)num);
			weeklyStatModel.UnitText = "";
			weeklyStatModel.TypeLabelText = Wolf.Core.Resources.AppStrings.dashboard_weeklystats_active_time.ToUpper();
			return weeklyStatModel;
		}

		private static WeeklyStatModel CreateDistanceStat(double statValue, bool isMetric)
		{
			WeeklyStatModel weeklyStatModel = new WeeklyStatModel();
			weeklyStatModel.Type = StatType.Distance;
			double a = (isMetric ? UnitUtil.EnsureKilometers(DistanceUnit.M, statValue, 2) : UnitUtil.EnsureMiles(DistanceUnit.M, statValue, 2));
			double num = Math.Round(a);
			weeklyStatModel.ValueText = (string)new DoubleToStringValueConverter(0, showLeadingZero: true, showThousandsSeparator: true).Convert(num, typeof(string), null, CultureInfo.CurrentCulture);
			weeklyStatModel.UnitText = (isMetric ? Wolf.Core.Resources.AppStrings.km.ToUpper() : Wolf.Core.Resources.AppStrings.mi.ToUpper());
			weeklyStatModel.TypeLabelText = Wolf.Core.Resources.AppStrings.route_distance.ToUpper();
			return weeklyStatModel;
		}

		private static WeeklyStatModel CreateElevationStat(double statValue, bool isMetric)
		{
			WeeklyStatModel weeklyStatModel = new WeeklyStatModel();
			weeklyStatModel.Type = StatType.ElevationGain;
			double a = (isMetric ? statValue : UnitUtil.EnsureFeet(DistanceUnit.M, statValue));
			double num = Math.Round(a);
			weeklyStatModel.ValueText = (string)new DoubleToStringValueConverter(0, showLeadingZero: true, showThousandsSeparator: true).Convert(num, typeof(string), null, CultureInfo.CurrentCulture);
			weeklyStatModel.UnitText = (isMetric ? Wolf.Core.Resources.AppStrings.m.ToUpper() : Wolf.Core.Resources.AppStrings.ft.ToUpper());
			weeklyStatModel.TypeLabelText = Wolf.Core.Resources.AppStrings.elevation_gain.ToUpper();
			return weeklyStatModel;
		}

		private static WeeklyStatModel CreateActivityLogCountStat(double statValue)
		{
			WeeklyStatModel weeklyStatModel = new WeeklyStatModel();
			weeklyStatModel.Type = StatType.ActivityLogCount;
			weeklyStatModel.ValueText = statValue.ToString();
			weeklyStatModel.UnitText = "";
			weeklyStatModel.TypeLabelText = Wolf.Core.Resources.AppStrings.dashboard_weeklystats_workouts.ToUpper();
			return weeklyStatModel;
		}
	}
