		private async Task DeleteAccountAsync()
		{
			_ = 2;
			try
			{
				IsBusy.Value = true;
				if (!(await DoSignIn(Password.Value)))
				{
					ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.input_password_dialog_enter_valid_password, null, Wolf.Core.Resources.AppStrings.okay_title.ToUpper());
				}
				else if (await ifitApi.DeleteAccount())
				{
					await ResetAppData();
					if (Mvx.TryResolve<ISnackbarService>(out var service))
					{
						service.Show(Wolf.Core.Resources.AppStrings.account_deletion_account_deleted);
					}
				}
			}
			catch
			{
			}
			finally
			{
				DoClose();
				IsBusy.Value = false;
			}
		}

		private async Task<bool> DoSignIn(string password)
		{
			wifiService?.RefreshConnectivityState();
			IConnectivity obj = connectivity;
			LoginResult loginResult;
			if (obj == null || !obj.IsConnected)
			{
				loginResult = LoginResult.NoInternetConnection;
			}
			else
			{
				try
				{
					loginResult = await ifitLogin.Authenticate(ifitApi.CurrentlyAuthenticatedUser.Username, password, forceAuthentication: true).TimeoutAfter(TimeSpan.FromSeconds(30.0)).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (TimeoutException exception)
				{
					Log.Error("Api", "Authentication Timed Out", exception);
					loginResult = LoginResult.TimeOut;
				}
				catch (Exception exception2)
				{
					Log.Error("Api", "General Exception Occured", exception2);
					loginResult = LoginResult.UnknownFailure;
				}
			}
			return loginResult == LoginResult.Success;
		}

		private async Task ResetAppData()
		{
			Log.Trace("Settings", "Resetting app data from maintenance screen");
			if (Mvx.TryResolve<ISaveUpdateFilesService>(out var service))
			{
				await Task.Run((Func<Task>)service.CleanUpSavedFiles);
			}
			if (Mvx.TryResolve<IApplicationFileService>(out var service2))
			{
				service2.Clear();
			}
			lockPinService?.SaveLockPinNumber(string.Empty);
			ifitApi.ClearCurrentUser();
			ifitApi.AuthenticatedUsers?.Clear();
			trackingService.FirstRun = true;
			trackingService.ClearCompletedOnboardingUsers();
			IUserAvatarImage userAvatarImage = Mvx.Resolve<IUserAvatarImage>();
			userAvatarImage?.AvatarDictionary.Clear();
			try
			{
				blobCacheService.Wipe();
				await RebuildSecureCache(userAvatarImage);
				if (workoutEstimateCache != null)
				{
					await workoutEstimateCache.Clear(vacuum: true);
				}
			}
			catch (Exception exception)
			{
				Log.Error("DeviceAdmin", "Wiping Cache failed", exception);
				if (Mvx.TryResolve<IFatalityService>(out var service3))
				{
					string fatal_please_restart = Wolf.Core.Resources.AppStrings.fatal_please_restart;
					service3.ReportFatalEvent(exception, fatal_please_restart, isPermanent: true);
				}
			}
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			InvokeOnMainThread(delegate
			{
				try
				{
					webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
					webviewHolderFactory.WebviewHolderStore.FlushAll();
				}
				catch (Exception exception2)
				{
					Log.Error("DeviceAdmin", "Exception encountered while trying to wipe Secure Cache and Clear WebViewStore", exception2);
				}
				finally
				{
					tcs.SetResult(result: true);
				}
			});
			await tcs.Task;
			ShowLoginViewModel();
		}

		private async Task RebuildSecureCache(IUserAvatarImage avatarFactory)
		{
			if (blobCacheService.Secure != null)
			{
				blobCacheService.Secure.Dispose();
				await blobCacheService.Secure.Shutdown;
				blobCacheService.Secure = null;
			}
			blobCacheFileManager?.NukeCacheDir(BlobCacheType.Secure);
			string secureCacheDirectory = CommonWolfAppSetup.SecureCacheDirectory;
			string databaseFile = Path.Combine(secureCacheDirectory, "secret.db");
			IEncryptionProvider encryptionProvider = (IEncryptionProvider)Locator.Current.GetService(typeof(IEncryptionProvider));
			SQLiteEncryptedBlobCache sQLiteEncryptedBlobCache = new SQLiteEncryptedBlobCache(databaseFile, encryptionProvider, BlobCache.TaskpoolScheduler);
			blobCacheService.Secure = sQLiteEncryptedBlobCache;
			ifitApi.SecureCache = sQLiteEncryptedBlobCache;
			if (Mvx.TryResolve<IInAppPurchaseService>(out var service))
			{
				service.Cache = sQLiteEncryptedBlobCache;
			}
			if (avatarFactory != null)
			{
				avatarFactory.BlobCacheService = blobCacheService;
			}
			Log.Trace("DeviceAdmin", "Done rebuilding Secure cache.");
		}

