	public abstract class BaseSwappingBackgroundViewModel : BaseViewModel
	{
		private const int StandardScreensaverImageCount = 5;

		private const int StrengthMirrorScreenSaverImageCount = 3;

		public const int PositionFadeMillis = 500;

		protected IDisposable countDownSub;

		protected IDisposable positionSub;

		protected IDisposable imageSub;

		protected int StartingIndex;

		protected abstract int SecondsBetweenPositionMoves { get; }

		protected abstract int SecondsBetweenImageChanges { get; }

		protected int NumImages { get; }

		protected abstract int NumPositions { get; }

		public BaseSwappingBackgroundViewModel(ILocalSettings localSettings)
			: base(localSettings)
		{
			try
			{
				Random random = new Random();
				NumImages = (deviceInfo.IsStrengthMirror ? 3 : 5);
				StartingIndex = random.Next(0, NumImages);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected abstract void NextImage();

		protected abstract void NextPosition();

		public override void Dispose()
		{
			base.Dispose();
			Cleanup();
			UnregisterChangeHandlers();
		}

		protected virtual void Cleanup()
		{
			positionSub?.Dispose();
			imageSub?.Dispose();
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			await Task.Run(delegate
			{
				SetupPositionChanges();
				ImageChangeChanges();
			});
		}

		protected void SetupPositionChanges()
		{
			positionSub = Observable.Interval(TimeSpan.FromSeconds(SecondsBetweenPositionMoves), intervalScheduler).Subscribe(delegate
			{
				NextPosition();
			});
		}

		protected void ImageChangeChanges()
		{
			imageSub = Observable.Interval(TimeSpan.FromSeconds(SecondsBetweenImageChanges), intervalScheduler).Subscribe(delegate
			{
				NextImage();
			});
		}

