	public class PhoneCalibrateInclineViewModel : BaseViewModel
	{
		private IDisposable calibrationReceiver;

		public readonly INC<string> Status;

		public readonly INC<bool?> SendSuccess;

		public readonly INC<bool> HasStarted;

		public readonly INC<bool> IsInProgress;

		public readonly INC<bool> IsFinished;

		public ICommand CalibrateCommand => new MvxCommand(StartCalibrateIncline);

		public string Title => Wolf.Core.Resources.AppStrings.settings_calibrate_incline;

		public string InstructionsTitle => Wolf.Core.Resources.AppStrings.settings_calibrate_instructions_title;

		public string InstructionDetails
		{
			get
			{
				if (currentConsoleService?.CurrentConsoleType?.IsBeltBasedMachine() ?? true)
				{
					return Wolf.Core.Resources.AppStrings.settings_calibrate_instructions_no_belt_paragraph;
				}
				return Wolf.Core.Resources.AppStrings.settings_calibrate_instructions_paragraph;
			}
		}

		public PhoneCalibrateInclineViewModel(ILocalSettings localSettings)
		{
			try
			{
				Status = new NC<string>();
				SendSuccess = new NC<bool?>();
				HasStarted = new NC<bool>();
				IsInProgress = new NC<bool>();
				IsFinished = new NC<bool>();
				base..ctor(localSettings);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void StartCalibrateIncline()
		{
			IsInProgress.Value = true;
			HasStarted.Value = true;
			if (currentConsoleService.Console != null)
			{
				currentConsoleService.Console.CalibrateIncline();
				calibrationReceiver = currentConsoleService.Console.WhenCalibrationStatusChanged?.Subscribe(UpdateUiString);
			}
		}

		private void UpdateUiString(CalibrateInclineState status)
		{
			switch (status)
			{
			case CalibrateInclineState.Done:
				Status.Value = Wolf.Core.Resources.AppStrings.calibration_complete;
				CalibrationComplete();
				break;
			case CalibrateInclineState.Failed:
				Status.Value = Wolf.Core.Resources.AppStrings.calibration_failed;
				CalibrationFailed();
				break;
			case CalibrateInclineState.InProgress:
				Status.Value = Wolf.Core.Resources.AppStrings.calibrating_incline;
				break;
			}
		}

		private void CalibrationFailed()
		{
			StopCalibrationMonitoring();
			IsInProgress.Value = false;
			IsFinished.Value = true;
			Status.Value = Wolf.Core.Resources.AppStrings.calibration_failed;
			SendSuccess.Value = false;
		}

		private void CalibrationComplete()
		{
			StopCalibrationMonitoring();
			IsInProgress.Value = false;
			IsFinished.Value = true;
			Status.Value = Wolf.Core.Resources.AppStrings.calibration_complete;
			SendSuccess.Value = true;
		}

		private void StopCalibrationMonitoring()
		{
			if (calibrationReceiver != null)
			{
				calibrationReceiver.Dispose();
				calibrationReceiver = null;
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			StopCalibrationMonitoring();
			UnregisterChangeHandlers();
		}

