	public abstract class BasePreloadManager : IWebviewPreloader
	{
		protected readonly IWebviewHolderFactory webviewHolderFactory;

		protected readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		protected readonly IFeatureFlagManager ffm;

		protected readonly IIfitApiService apiService;

		protected readonly ILocalSettings localSettings;

		protected readonly IDeviceInformation deviceInfo;

		protected readonly IHardwareInfo hardwareInfo;

		protected readonly IPreferenceResolver preferenceResolver;

		protected readonly IConnectivity connectivity;

		protected readonly IWebViewConfigService webViewConfigService;

		public BasePreloadManager(IWebviewHolderFactory webviewHolderFactory, IMvxMainThreadDispatcher mainThreadDispatcher, IFeatureFlagManager ffm, IIfitApiService apiService, ILocalSettings localSettings, IDeviceInformation deviceInfo, IHardwareInfo hardwareInfo, IPreferenceResolver preferenceResolver, IConnectivity connectivity, IWebViewConfigService webViewConfigService)
		{
			this.webviewHolderFactory = webviewHolderFactory;
			this.mainThreadDispatcher = mainThreadDispatcher;
			this.ffm = ffm;
			this.apiService = apiService;
			this.localSettings = localSettings;
			this.deviceInfo = deviceInfo;
			this.hardwareInfo = hardwareInfo;
			this.preferenceResolver = preferenceResolver;
			this.connectivity = connectivity;
			this.webViewConfigService = webViewConfigService;
		}

		protected virtual void PreloadWebView(string url, int ttlSeconds, Func<Task<IDictionary<string, string>>> getAdditionalConfigs = null)
		{
			if (connectivity.IsConnected)
			{
				if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service))
				{
					url = service.GenerateWebViewUrlWithParameters(url);
				}
				mainThreadDispatcher.RequestMainThreadAction(delegate
				{
					webviewHolderFactory.WebviewHolderStore.PreloadWebView(url, ttlSeconds, WebviewHolderType.Default, getAdditionalConfigs);
				});
			}
		}

		public virtual Task DoPreload(MvxViewModelRequest request)
		{
			return Task.FromResult(0);
		}

		public virtual Task DoClose(ShireBaseViewModel whichViewModel)
		{
			return Task.FromResult(0);
		}
	}
	[WebviewPreloader(typeof(DashboardViewModel))]
	public class DashboardPreloadManager : BasePreloadManager
	{
		public DashboardPreloadManager(IWebviewHolderFactory webviewHolderFactory, IMvxMainThreadDispatcher mainThreadDispatcher, IFeatureFlagManager ffm, IIfitApiService apiService, ILocalSettings localSettings, IDeviceInformation deviceInfo, IHardwareInfo hardwareInfo, IPreferenceResolver preferenceResolver, IConnectivity connectivity, IWebViewConfigService webViewConfigService)
			: base(webviewHolderFactory, mainThreadDispatcher, ffm, apiService, localSettings, deviceInfo, hardwareInfo, preferenceResolver, connectivity, webViewConfigService)
		{
		}

		public override async Task DoPreload(MvxViewModelRequest request)
		{
			webviewHolderFactory.WebviewHolderStore.Flush(OnboardingPaymentViewModel.WebViewUrl);
			webviewHolderFactory.WebviewHolderStore.Flush(BleActivateInstructionStepsViewModel.WebViewUrl);
			if (!localSettings.ShouldUseFeedWebview)
			{
				Log.Trace("WebView", "Not preloading Feed webview b/c this device is set to use the native view");
			}
			else
			{
				PreloadWebView(FeedViewModel.GetWebViewUrl(ffm), 14400, FeedViewModel.ConfigsForWebView);
			}
		}
	}
