	{
		public static Workout Warmup(ConsoleType type, bool isMetric, int seconds = 180, double? initialIncline = null)
		{
			switch (type)
			{
			case ConsoleType.Treadmill:
			case ConsoleType.InclineTrainer:
				return TreadmillDefaultWorkouts.BasicRunWorkout(isMetric, seconds, initialIncline);
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return BikeDefaultWorkouts.BasicBikeWorkout(seconds, initialIncline);
			case ConsoleType.Elliptical:
				return EllipticalDefaultWorkouts.BasicEllipticalWorkout(seconds, initialIncline);
			case ConsoleType.Strider:
			case ConsoleType.FreeStrider:
			case ConsoleType.VerticalElliptical:
				return VerticalEllipticalDefaultWorkouts.BasicVerticalEllipticalWorkout(seconds, initialIncline);
			case ConsoleType.Rower:
				return RowerDefaultWorkouts.BasicRowerWorkout(seconds);
			case ConsoleType.Equipmentless:
			case ConsoleType.Mirror:
				return StrengthDefaultWorkouts.BasicStrengthWorkout(seconds);
			default:
				throw new NotImplementedException();
			}
		}

