		public virtual MvxViewModelRequest OnShowing(MvxViewModelRequest request)
		{
			return request;
		}
	}
	public class WebviewPreloadManager : BaseViewModelPresentationFilter
	{
		private static bool isInitialized;

		private static Dictionary<Type, Type> preloaderTypeMappings;

		private readonly ILocalSettings localSettings;

		private readonly IWebviewSettings webviewSettings;

		public static void RegisterPreloaders()
		{
			if (!isInitialized)
			{
				Type[] array = typeof(CommonWolfAppSetup).GetTypeInfo().Assembly.GetTypes().Where(IsPreloader).ToArray();
				Type[] array2 = array;
				foreach (Type type in array2)
				{
					Mvx.RegisterType(type, type);
				}
				preloaderTypeMappings = array.ToDictionary(GetViewModelType, (Type x) => x);
				Mvx.LazyConstructAndRegisterSingleton<WebviewPreloadManager, WebviewPreloadManager>();
				isInitialized = true;
			}
			static Type GetViewModelType(Type type2)
			{
				object[] customAttributes = type2.GetCustomAttributes(typeof(WebviewPreloaderAttribute), inherit: true);
				if (customAttributes == null || !customAttributes.Any())
				{
					throw new InvalidOperationException($"Type {type2} is a webview preloader but does not have a WebviewPreloaderAttribute");
				}
				return (customAttributes[0] as WebviewPreloaderAttribute)?.ViewModelType;
			}
			static bool IsPreloader(Type type2)
			{
				TypeInfo typeInfo = type2.GetTypeInfo();
				bool flag = typeof(IWebviewPreloader).IsAssignableFrom(type2);
				bool flag2 = typeInfo.IsClass && !typeInfo.IsAbstract;
				return flag && flag2;
			}
		}

		public WebviewPreloadManager(ILocalSettings localSettings, IWebviewSettings webviewSettings)
		{
			this.localSettings = localSettings;
			this.webviewSettings = webviewSettings;
		}

		public override MvxViewModelRequest OnShowing(MvxViewModelRequest request)
		{
			if (webviewSettings.IsWebviewCacheDisabled)
			{
				return request;
			}
			Type preloaderForType = GetPreloaderForType(request.ViewModelType);
			if (preloaderForType != null && Mvx.Resolve(preloaderForType) is IWebviewPreloader webviewPreloader)
			{
				webviewPreloader.DoPreload(request);
			}
			return request;
		}

		public override void OnClosing(ShireBaseViewModel viewModel)
		{
			if (!webviewSettings.IsWebviewCacheDisabled)
			{
				Type preloaderForType = GetPreloaderForType(viewModel.GetType());
				if (preloaderForType != null && Mvx.Resolve(preloaderForType) is IWebviewPreloader webviewPreloader)
				{
					webviewPreloader.DoClose(viewModel);
				}
			}
		}

		private Type GetPreloaderForType(Type requestedViewModel)
		{
			if (!isInitialized)
			{
				throw new InvalidOperationException("WebviewPreloadManager.RegisterPreloaders was not called and the class is not initialized correctly");
			}
			if (preloaderTypeMappings.TryGetValue(requestedViewModel, out var value))
			{
				return value;
			}
			return null;
		}
	}
