namespace Wolf.Core.WebView
{
	public abstract class BaseWebviewHolderStore : IWebviewHolderStore
	{
		private class TtlExpiredException : Exception
		{
		}

		private class BadWebviewException : Exception
		{
		}

		protected const int TimerIntervalInSeconds = 5;

		public const int DefaultWebviewTTL = 45;

		protected readonly ICrashReporter crashReporter;

		private readonly ICoreAnalytics coreAnalytics;

		private readonly object storeLock = new object();

		protected IDictionary<string, WebviewHolder> Store { get; private set; }

		public bool Contains(IWebView webView)
		{
			return Store?.Any((KeyValuePair<string, WebviewHolder> x) => x.Value.WebView == webView) ?? false;
		}

		public bool Contains(string url)
		{
			Uri uri = new Uri(url);
			string key = uri.WebviewHolderFactoryStoreKey();
			return Store?.ContainsKey(key) ?? false;
		}

		public bool ContainsBaseUrlAndFragment(string baseUrl, string fragment = null)
		{
			string text = fragment;
			if (text != null && text.StartsWith("#"))
			{
				fragment = fragment.Substring(1, fragment.Length);
			}
			return Store?.Any(delegate(KeyValuePair<string, WebviewHolder> x)
			{
				bool flag = x.Key.StartsWith(baseUrl);
				bool flag2 = (string.IsNullOrEmpty(fragment) ? (!x.Key.Contains("#")) : x.Key.EndsWith("#" + fragment));
				return flag && flag2;
			}) ?? false;
		}

		protected BaseWebviewHolderStore(ICoreAnalytics coreAnalytics, ICrashReporter crashReporter)
		{
			this.coreAnalytics = coreAnalytics;
			this.crashReporter = crashReporter;
			Store = new Dictionary<string, WebviewHolder>();
			if (Mvx.TryResolve<IIfitApiService>(out var service))
			{
				service.WhenApiEnvironmentChanged.SubscribeWithErrorLogging(delegate
				{
					FlushAll();
				});
			}
		}

		protected void TimerElapsedEvent()
		{
			lock (storeLock)
			{
				foreach (KeyValuePair<string, WebviewHolder> pair in Store.ToList())
				{
					if (pair.Value.TtlRemaining <= 0)
					{
						Mvx.Resolve<IMvxMainThreadDispatcher>().RequestMainThreadAction(delegate
						{
							CleanStorePair(pair);
						});
					}
					else
					{
						pair.Value.TtlRemaining -= 5;
					}
				}
			}
		}

		private void CleanStorePair(KeyValuePair<string, WebviewHolder> pair)
		{
			try
			{
				if (pair.Value.WebView?.IsFlushable == true)
				{
					pair.Value.Dispose();
					Store.Remove(pair.Key);
					Log.Trace("WebView", "TTL is up: Removing webview from store: " + pair.Key);
					if (Store.Count == 0)
					{
						TimerStop();
					}
				}
			}
			catch (ObjectDisposedException ex)
			{
				Log.Error("WebView", string.Format("Disposed object in {0}.{1}", this, "TimerElapsedEvent"), ex);
				ex.Data.Add("WebviewKey", pair.Key);
				ex.Data.Add("StoreObjectUrl", pair.Value.Url);
				if (Mvx.TryResolve<IDialogPresenter>(out var _))
				{
					ex.Data.Add("CurrentMainViewModel", "CurrentMainViewModel");
				}
				crashReporter.ReportError(ex.Message, ex, null);
				Log.Trace("WebView", "Removing " + (pair.Value?.Url ?? "null") + " from WebViewStore");
				Store.Remove(pair.Key);
				Log.Trace("WebView", "TTL is up: Removed webview from store: " + pair.Key);
				if (Store.Count == 0)
				{
					TimerStop();
				}
			}
		}

		public virtual void PreloadWebView(string url, int ttlSeconds = 45, WebviewHolderType webviewHolderType = WebviewHolderType.Default, Func<Task<IDictionary<string, string>>> getAdditionalConfig = null)
		{
			Uri uri = url.CreateUrlSafe();
			if (uri == null)
			{
				return;
			}
			string webviewStoreKey = uri.WebviewHolderFactoryStoreKey();
			string fullUrl = uri.OriginalString;
			Log.Trace("WebView", "WVS Preload requested...\nfor url: " + fullUrl + "\nuse key: " + webviewStoreKey);
			lock (storeLock)
			{
				if (!Store.ContainsKey(webviewStoreKey))
				{
					Mvx.Resolve<IMvxMainThreadDispatcher>().RequestMainThreadAction(delegate
					{
						WebviewHolder webviewHolder = FetchOrCreateWebviewHolderByUrl(fullUrl, new WebviewHolderCreationOptions
						{
							TtlIfCreating = ttlSeconds,
							GetAdditionalConfig = getAdditionalConfig,
							WebviewHolderType = webviewHolderType
						});
						webviewHolder.TtlRequested = ttlSeconds;
						webviewHolder.TtlRemaining = ttlSeconds;
						Log.Trace("WebView", "Adding " + (webviewHolder?.Url ?? "null") + " to WebViewStore");
						Store[webviewStoreKey] = webviewHolder;
						Log.Trace("WebView", "WVS stored url: " + webviewStoreKey);
					});
				}
				else
				{
					Store[webviewStoreKey].TtlRequested = ttlSeconds;
					Store[webviewStoreKey].TtlRemaining = ttlSeconds;
					Log.Trace("WebView", $"WVS updated to {ttlSeconds} ttlSeconds for url: {webviewStoreKey}");
				}
			}
			TimerStart();
		}

		protected abstract IWebView CreateWebView();

		protected abstract IWebView CreateAndLoadWebViewByUrl(string url);

		protected abstract IWebView CreateAndLoadWebViewByHtml(string webviewHtml);

		public WebviewHolder FetchOrCreateWebviewHolderByUrl(string url, WebviewHolderCreationOptions creationOptions = null)
		{
			return FetchOrCreateWebviewHolder(url, isHtml: false, creationOptions);
		}

		public WebviewHolder FetchOrCreateWebviewHolderByHtml(string html, WebviewHolderCreationOptions creationOptions = null)
		{
			return FetchOrCreateWebviewHolder(html, isHtml: true, creationOptions);
		}

		protected WebviewHolder FetchOrCreateWebviewHolder(string data, bool isHtml, WebviewHolderCreationOptions creationOptions)
		{
			if (creationOptions == null)
			{
				creationOptions = new WebviewHolderCreationOptions();
			}
			string empty = string.Empty;
			string text = string.Empty;
			Uri uri = data.CreateUrlSafe();
			if (!isHtml && uri != null)
			{
				empty = uri.WebviewHolderFactoryStoreKey();
				text = uri.OriginalString;
			}
			else
			{
				empty = Guid.NewGuid().ToString();
			}
			Log.Trace("WebView", "WVS Fetch/create requested...\nfor url: " + text + "\nuse key: " + empty);
			WebviewHolder webviewHolder;
			lock (storeLock)
			{
				try
				{
					webviewHolder = Store[empty];
					if (webviewHolder.TtlRemaining <= 0)
					{
						throw new TtlExpiredException();
					}
					Store[empty].TtlRemaining = Store[empty].TtlRequested;
					if (webviewHolder.WebView?.Bridge == null)
					{
						throw new BadWebviewException();
					}
					Log.Trace("WebView", "WVS found webview for url: " + empty);
				}
				catch (KeyNotFoundException)
				{
					Log.Trace("WebView", "WVS DIDN'T find a webview for url: " + empty);
					webviewHolder = CreateAndStoreWebviewHolder(isHtml, data, creationOptions.WebviewHolderType, text, creationOptions.TtlIfCreating, empty, creationOptions.GetAdditionalConfig, creationOptions.ShouldCacheWebPages, creationOptions.LogTag);
				}
				catch (TtlExpiredException)
				{
					Log.Trace("WebView", "WVS TTL for key expired: " + empty);
					Flush(data);
					webviewHolder = CreateAndStoreWebviewHolder(isHtml, data, creationOptions.WebviewHolderType, text, creationOptions.TtlIfCreating, empty, creationOptions.GetAdditionalConfig, creationOptions.ShouldCacheWebPages, creationOptions.LogTag);
				}
				catch (BadWebviewException)
				{
					Log.Trace("WebView", "WVS store object had a bad webview for : " + empty);
					Flush(data);
					webviewHolder = CreateAndStoreWebviewHolder(isHtml, data, creationOptions.WebviewHolderType, text, creationOptions.TtlIfCreating, empty, creationOptions.GetAdditionalConfig, creationOptions.ShouldCacheWebPages, creationOptions.LogTag);
				}
			}
			return webviewHolder;
		}

		private WebviewHolder CreateAndStoreWebviewHolder(bool isHtml, string data, WebviewHolderType webviewHolderType, string fullUrl, int ttlIfCreating, string webviewStoreKey, Func<Task<IDictionary<string, string>>> getAdditionalConfig, bool shouldCacheWebPages, string logTag)
		{
			IWebView webView = (isHtml ? CreateAndLoadWebViewByHtml(data) : ((!string.IsNullOrEmpty(data)) ? CreateWebView() : CreateAndLoadWebViewByUrl(data)));
			WebviewHolder webviewHolder = (WebviewHolder)(webView.DidNavigateDelegate = WebviewHolderManager.Create(webviewHolderType, fullUrl, webView, ttlIfCreating, webviewStoreKey, getAdditionalConfig));
			webView.LoadUrl(fullUrl);
			Store[webviewStoreKey] = webviewHolder;
			webView.ChangeCacheMode(shouldCacheWebPages);
			webView.Bridge.LogTag = logTag;
			if (webView.IsLoaded)
			{
				webviewHolder.WebViewFinishedNavigating();
			}
			webviewHolder.IsReadyToCommunicate = webView.IsReadyToCommunicate;
			return webviewHolder;
		}

		public void FlushAll()
		{
			FlushAllExcluding();
		}

		public void FlushAllExcluding(params string[] excludedUrls)
		{
			Log.Trace("WebView", "Flushing WVS");
			string[] excludedBaseUrls = (from x in excludedUrls
				select x.CreateUrlSafe()?.BaseUrl() into x
				where x != null
				select x).ToArray();
			Mvx.Resolve<IMvxMainThreadDispatcher>().RequestMainThreadAction(delegate
			{
				List<string> list = new List<string>();
				lock (storeLock)
				{
					foreach (KeyValuePair<string, WebviewHolder> pair in Store)
					{
						if (!excludedBaseUrls.Any((string x) => pair.Key.Contains(x)))
						{
							IWebView webView = pair.Value.WebView;
							if (webView?.ShouldFlush(webView) == true)
							{
								pair.Value.Dispose();
								list.Add(pair.Key);
							}
							else
							{
								Log.Trace("WebView", "Not flushing url: " + pair.Key);
							}
						}
					}
					list.ForEach(delegate(string x)
					{
						Store.Remove(x);
					});
				}
			});
			if (Store.Count == 0)
			{
				TimerStop();
			}
		}

		public void Flush(string url)
		{
			if (string.IsNullOrWhiteSpace(url))
			{
				Log.Error("WebView", "Unable to flush a null URL.");
				return;
			}
			string webviewStoreKey = url.CreateUrlSafe()?.WebviewHolderFactoryStoreKey();
			Flush(url, webviewStoreKey);
		}

		public void FlushByKey(string key)
		{
			if (string.IsNullOrWhiteSpace(key))
			{
				Log.Error("WebView", "Unable to flush a null Key.");
			}
			else
			{
				Flush(string.Empty, key);
			}
		}

		public void Flush(string url, string webviewStoreKey)
		{
			if (webviewStoreKey == null)
			{
				return;
			}
			Log.Trace("WebView", "WVS Flush requested...\nfor url: " + url + "\nuse key: " + webviewStoreKey);
			lock (storeLock)
			{
				if (Store.ContainsKey(webviewStoreKey))
				{
					IWebView storedWebView = Store[webviewStoreKey].WebView;
					Mvx.Resolve<IMvxMainThreadDispatcher>().RequestMainThreadAction(delegate
					{
						if (storedWebView?.ShouldFlush(storedWebView) == true)
						{
							Store[webviewStoreKey].Dispose();
							Store.Remove(webviewStoreKey);
							Log.Trace("WebView", "Flushing WVS for url: " + url + " Base:" + webviewStoreKey);
						}
						else
						{
							Log.Trace("WebView", "Not flushing url: " + url + " Base:" + webviewStoreKey);
						}
					});
				}
			}
			if (Store.Count == 0)
			{
				TimerStop();
			}
		}

		public abstract void ClearWebViewCache();

		protected abstract void TimerStart();

		protected abstract void TimerStop();
	}
