	public class WebviewHolder : IWebViewNavigationDelegate, IDisposable
	{
		public const string WebviewMethodInitializeWebview = "InitializeWebview";

		protected readonly IWebViewDataService webViewDataService;

		private readonly IMainThreadService mainThreadService;

		private readonly IWebViewConfigService webViewConfigService;

		private readonly IIfitApiService ifitApi;

		private readonly ISettingsRouter settingsRouter;

		private readonly IDeviceInformation deviceInfo;

		private readonly IModalityChangeService modalityChangeService;

		private bool _isReadyToCommunicate;

		protected Func<Task<IDictionary<string, string>>> GetAdditionalConfig;

		public List<Tuple<string, IDictionary<string, string>>> WebViewMessages = new List<Tuple<string, IDictionary<string, string>>>();

		private readonly object synchronizeCallWebviewInitializationBridge = new object();

		public string LogTag => "WebViewStoreObject";

		public virtual string WebviewMethodOldInitializeWebview => "InitializeApp";

		public string Url { get; private set; }

		private string SavedDeepLinkToSend { get; set; }

		public string Key { get; private set; }

		public IWebView WebView { get; protected set; }

		public IDictionary<string, string> Configs { get; private set; }

		public bool IsReadyToCommunicate
		{
			get
			{
				return _isReadyToCommunicate;
			}
			set
			{
				if (_isReadyToCommunicate != value)
				{
					_isReadyToCommunicate = value;
					if (_isReadyToCommunicate)
					{
						HandlePreviousMessages();
					}
				}
			}
		}

		public IDictionary<string, string> InitializationParameters { get; set; }

		public int TtlRequested { get; set; }

		public int TtlRemaining { get; set; }

		public event EventHandler<WebViewState> WebviewStateChanged;

		public event EventHandler WebviewFinishedNavigating;

		public event EventHandler WebviewErrorLoading;

		public event EventHandler<IDictionary<string, string>> WebviewIsReady;

		public WebviewHolder(string url, IWebView webview, int ttl, string key, Func<Task<IDictionary<string, string>>> getAdditionalConfig)
		{
			Url = url;
			Key = key;
			WebView = webview;
			TtlRemaining = ttl;
			InitializationParameters = new Dictionary<string, string>();
			webViewDataService = Mvx.Resolve<IWebViewDataService>();
			mainThreadService = Mvx.Resolve<IMainThreadService>();
			webViewConfigService = Mvx.Resolve<IWebViewConfigService>();
			ifitApi = Mvx.Resolve<IIfitApiService>();
			settingsRouter = Mvx.Resolve<ISettingsRouter>();
			deviceInfo = Mvx.Resolve<IDeviceInformation>();
			modalityChangeService = Mvx.Resolve<IModalityChangeService>();
			GetAdditionalConfig = getAdditionalConfig;
			WebView.Bridge.ExposeTask("GetData", WebViewGetData);
		}

		protected void InvokeWebviewIsReady(IDictionary<string, string> initializationParameters = null)
		{
			this.WebviewIsReady?.Invoke(this, initializationParameters);
		}

		private void HandlePreviousMessages()
		{
			WebViewMessages?.DoForEach(delegate(Tuple<string, IDictionary<string, string>> x)
			{
				if (!string.IsNullOrWhiteSpace(x.Item1))
				{
					WebView.Bridge?.Call(x.Item1, x.Item2);
				}
			}, ignoreNulls: true);
			WebViewMessages?.Clear();
		}

		public virtual void WebViewIsReady(IDictionary<string, string> initializationParameters = null)
		{
			InitializationParameters.ContainsKey("deepLink");
			InitializationParameters = initializationParameters ?? new Dictionary<string, string>();
			WebView.IsReadyToCommunicate = true;
			InvokeWebviewIsReady(initializationParameters);
			WebviewInitialization();
		}

		protected async Task WebViewGetData(IDictionary<string, string> obj)
		{
			if (obj == null)
			{
				return;
			}
			IDictionary<string, string> dictionary = await webViewDataService.GetData(obj);
			if (dictionary != null)
			{
				string seed = JsonObfuscator.PrepareJsonForLogging(JsonConvert.SerializeObject(dictionary.ToList()), "\"", "\":\"");
				seed = WebViewDataService.SensitiveDataKeys.Aggregate(seed, (string current, string sensitiveKey) => Regex.Replace(current, "\"" + sensitiveKey + "\":\".+?\"", "\"" + sensitiveKey + "\":\"sensitive information hidden\""));
				if (WebView == null)
				{
					Log.Trace("WebView", "Tried to call DataAvailable with " + seed + " but the webview was null. Assuming we navigated away before GetData completed.");
					return;
				}
				WebView.Bridge?.Call("DataAvailable", dictionary);
				Log.Trace("WebView", "DataAvailable Called with $" + seed);
			}
		}

		public virtual void WebViewFinishedNavigating()
		{
			this.WebviewFinishedNavigating?.Invoke(this, EventArgs.Empty);
		}

		public virtual void WebViewErrorLoading()
		{
			this.WebviewErrorLoading?.Invoke(this, EventArgs.Empty);
		}

		public virtual void WebViewStateChanged(WebViewState state)
		{
			this.WebviewStateChanged?.Invoke(this, state);
		}

		public void OnWebViewRenderProcessGone()
		{
			Log.Trace("WebView", "OnWebViewRenderProcessGone called in WebviewHolder");
		}

		public virtual void WebViewErrorCodeResponse(HttpStatusCode statusCode)
		{
			Log.Trace("WebView", $"WebViewErrorCodeResponse WebViewErrorLoading on {statusCode}");
			WebViewErrorLoading();
		}

		public virtual void WebviewInitialization()
		{
			Task.Run(async delegate
			{
				await mainThreadService.InvokeOnMainThreadAsync((Func<Task>)InitializeConfigs);
				SetupWebview();
				CallWebviewInitializationBridge();
			});
		}

		public void InitializeWithUpdatedConfigs(Func<Task<IDictionary<string, string>>> getAdditionalConfig)
		{
			GetAdditionalConfig = getAdditionalConfig;
			WebviewInitialization();
		}

		public virtual async Task InitializeConfigs()
		{
			((!InitializationParameters.ContainsKey("keys")) ? (await GetOldConfig()) : (await webViewDataService.GetData(InitializationParameters)))?.ToList().ForEach(delegate(KeyValuePair<string, string> x)
			{
				InitializationParameters[x.Key] = x.Value;
			});
		}

		protected async Task<Dictionary<string, string>> GetOldConfig(OptionalConfigs excludedConfigs = (OptionalConfigs)0)
		{
			Dictionary<string, string> result = new Dictionary<string, string>();
			try
			{
				result = (await (webViewConfigService?.GetBaseConfigsExcluding(excludedConfigs))) ?? new Dictionary<string, string>();
				IDictionary<string, string> dictionary = ((GetAdditionalConfig == null) ? new Dictionary<string, string>() : (await GetAdditionalConfig()));
				IDictionary<string, string> source = dictionary;
				source.ForEach(delegate(KeyValuePair<string, string> x)
				{
					result[x.Key] = x.Value;
				});
			}
			catch (Exception ex)
			{
				Log.Error(LogTag, ex.Message, ex);
			}
			return result;
		}

		public virtual void SetupWebview()
		{
		}

		public virtual void CallWebviewInitializationBridge()
		{
			lock (synchronizeCallWebviewInitializationBridge)
			{
				string methodName = (InitializationParameters.ContainsKey("keys") ? "InitializeWebview" : WebviewMethodOldInitializeWebview);
				if (WebView?.Bridge == null)
				{
					Log.Warn("WebView", "Webview was bad when calling CallWebviewInitializationBridge (webview or bridge was null, skipping the webview initialization call");
					return;
				}
				InitializationParameters["deepLink"] = SavedDeepLinkToSend;
				SavedDeepLinkToSend = string.Empty;
				if (InitializationParameters.TryGetValue(JavascriptBridge.MethodToSetConfigs, out var value))
				{
					InitializationParameters.Remove(JavascriptBridge.MethodToSetConfigs);
					WebView.Bridge.Call(value, InitializationParameters);
				}
				else
				{
					WebView.Bridge.Call(methodName, InitializationParameters);
				}
				InitializationParameters.Remove("deepLink");
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		public async Task<bool> DidPayloadChange()
		{
			bool flag = DidUserChange();
			bool flag2 = flag;
			if (!flag2)
			{
				flag2 = await DidSoftwareNumberChange();
			}
			bool flag3 = flag2;
			if (!flag3)
			{
				flag3 = await DidUnitOfMeasurementChange();
			}
			return flag3;
		}

		protected virtual void Dispose(bool disposing)
		{
			Log.Trace("WebView", "Disposing the WebViewStoreObject with url: " + Url);
			Url = null;
			Configs?.Clear();
			Configs = null;
			if (WebView != null)
			{
				WebView.DidNavigateDelegate = null;
			}
			try
			{
				if (WebView != null && (!(WebView is IAndroidWebView) || WebView.IsFlushable))
				{
					WebView?.DisposeIfDisposable();
				}
			}
			catch (ObjectDisposedException exception)
			{
				Log.Error("WebView", "WebviewHolder - WebView already disposed on disposal.", exception);
			}
			catch (Exception exception2)
			{
				Log.Error("WebView", "WebviewHolder - there was a problem trying to dispose of the WebView.", exception2);
			}
			WebView = null;
		}

		private bool DidUserChange()
		{
			string text = InitializationParameters?.GetValueSafely("userId");
			if (text.HasValue())
			{
				return text != ifitApi.CurrentlyAuthenticatedUser?.Id;
			}
			return false;
		}

		private async Task<bool> DidSoftwareNumberChange()
		{
			string previousSN = InitializationParameters?.GetValueSafely("softwareNumber");
			string text = await modalityChangeService.GetOverrideSoftwareNumber(deviceInfo?.SoftwareNumber.ToString());
			return previousSN.HasValue() && previousSN != text;
		}

		private async Task<bool> DidUnitOfMeasurementChange()
		{
			string previous = InitializationParameters?.GetValueSafely("useMetricUnits");
			string text = (await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false)).ToString().ToLower();
			return previous.HasValue() && previous != text;
		}

		public virtual void SendDeepLink(string deepLink)
		{
			if (IsReadyToCommunicate)
			{
				WebView.Bridge.Call("DataAvailable", new Dictionary<string, string> { { "deepLink", deepLink } });
				return;
			}
			lock (synchronizeCallWebviewInitializationBridge)
			{
				SavedDeepLinkToSend = deepLink;
			}
		}
	}
