	public class WebviewReloader : IWebviewReloader, IDisposable
	{
		private readonly Subject<WebviewReloaderStatus> _reloadStatusChanged = new Subject<WebviewReloaderStatus>();

		private readonly IConnectivity connectivity;

		private readonly IWebviewHolderFactory webviewHolderFactory;

		private Func<string> GetViewUrl;

		private bool waitingToReload;

		private IDisposable reloadSub;

		private IDisposable timeoutSub;

		private int reloadAttempts;

		public IObservable<WebviewReloaderStatus> ReloadStatusChanged => _reloadStatusChanged;

		public WebviewReloaderProperties Properties { get; set; }

		public WebviewReloader(IConnectivity connectivity, IWebviewHolderFactory webviewHolderFactory, WebviewReloaderProperties properties)
		{
			Properties = properties;
			this.connectivity = connectivity;
			this.webviewHolderFactory = webviewHolderFactory;
		}

		public void StartReload(Func<string> getCurrentViewUrl, bool waitForNoInternetRecovery = false)
		{
			connectivity.ConnectivityChanged -= Connectivity_ConnectivityChanged;
			GetViewUrl = getCurrentViewUrl;
			Reload();
		}

		private void Reload()
		{
			if (!connectivity.IsConnected)
			{
				_reloadStatusChanged.OnNext(WebviewReloaderStatus.NoInternet);
				if (Properties.HandleNoInternetRecovery)
				{
					connectivity.ConnectivityChanged += Connectivity_ConnectivityChanged;
				}
			}
			else if (ViewDidLoadUrl())
			{
				_reloadStatusChanged.OnNext(WebviewReloaderStatus.Finished);
			}
			else if (waitingToReload)
			{
				_reloadStatusChanged.OnNext(WebviewReloaderStatus.WaitingOnReload);
			}
			else
			{
				waitingToReload = true;
				HandleWebViewErrorLoading();
			}
		}

		private void Connectivity_ConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			if (e.IsConnected && Properties.HandleNoInternetRecovery)
			{
				connectivity.ConnectivityChanged -= Connectivity_ConnectivityChanged;
				_reloadStatusChanged.OnNext(WebviewReloaderStatus.ShouldReload);
			}
		}

		private void HandleWebViewErrorLoading()
		{
			CleanUpReloaderSub();
			reloadSub = Observable.Timer(Properties.RetryDelay).SubscribeWithErrorLogging(delegate
			{
				DoRetryLoadWebView();
			});
		}

		private void DoRetryLoadWebView()
		{
			if (ViewDidLoadUrl())
			{
				CleanUpTimeout();
				_reloadStatusChanged.OnNext(WebviewReloaderStatus.Finished);
				return;
			}
			webviewHolderFactory?.WebviewHolderStore.Flush(Properties.DesiredWebviewUrl);
			if (reloadAttempts++ < Properties.MaxAttempts)
			{
				SubscribeTimeout();
				_reloadStatusChanged.OnNext(WebviewReloaderStatus.ShouldReload);
				return;
			}
			CleanUpTimeout();
			CleanUpReloaderSub();
			waitingToReload = false;
			_reloadStatusChanged.OnNext(WebviewReloaderStatus.Failed);
		}

		private bool ViewDidLoadUrl()
		{
			bool result = false;
			try
			{
				result = GetViewUrl?.Invoke() == Properties.DesiredWebviewUrl;
			}
			catch (Exception ex)
			{
				Log.Debug("WebView", "WebviewReloader - Error checking if WebviewUrl matches ViewModels => " + ex.Message);
			}
			return result;
		}

		private void SubscribeTimeout()
		{
			CleanUpTimeout();
			timeoutSub = Observable.Timer(TimeSpan.FromSeconds(Properties.LoadingTimeout.TotalSeconds)).SubscribeWithErrorLogging(delegate
			{
				OnTimeout();
			});
		}

		private void OnTimeout()
		{
			CleanUpTimeout();
			DoRetryLoadWebView();
		}

		private void CleanUpTimeout()
		{
			timeoutSub?.Dispose();
			timeoutSub = null;
		}

		private void CleanUpReloaderSub()
		{
			reloadSub?.Dispose();
			reloadSub = null;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			connectivity.ConnectivityChanged -= Connectivity_ConnectivityChanged;
			CleanUpReloaderSub();
			CleanUpTimeout();
			GetViewUrl = null;
		}
	}
}
namespace Wolf.Core.ScreenSaver
{
	public class ScreenSaverDialogViewModel : BaseSwappingBackgroundViewModel
	{
		private readonly IDisposable consoleStateSub;

		private readonly IScreenSaverHandler screenSaverHandler;

		private new readonly IDialogPresenter dialogPresenter;

		private readonly ILockScreenHandler lockScreenHandler;

		private IDisposable consoleButtonClickSub;

		public INC<int> CurrentImageIndex = new NC<int>();

		public readonly INC<int> CurrentPositionIndex = new NC<int>(0);

		protected override int SecondsBetweenPositionMoves => 30;

		protected override int SecondsBetweenImageChanges => 120;

		protected override int NumPositions => 5;

		public ICommand ScreenTouched => new MvxCommand(DoScreenTouched);

		public ScreenSaverDialogViewModel(ILocalSettings localSettings, IScreenSaverHandler screenSaverHandler, IDialogPresenter dialogPresenter, ICurrentConsoleService currentConsoleService, ILockScreenHandler lockScreenHandler = null)
			: base(localSettings)
		{
			try
			{
				this.screenSaverHandler = screenSaverHandler;
				this.dialogPresenter = dialogPresenter;
				this.lockScreenHandler = lockScreenHandler;
				CurrentImageIndex.Value = StartingIndex;
				consoleStateSub = currentConsoleService?.ActiveConsole?.WhenStateChanged.Subscribe(ConsoleStateChanged);
				if (currentConsoleService != null && currentConsoleService.IsBuiltinClub && currentConsoleService.CurrentConsoleType != ConsoleType.Equipmentless && currentConsoleService.CurrentConsoleType != ConsoleType.None)
				{
					consoleButtonClickSub = currentConsoleService.Console?.DetectOnBytesBeingSent.Subscribe(DetectOnBytesBeingSent);
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			Log.Trace("ScreenSaverDialogViewModel", "Screen Saver View has been shown.");
			wifiService.IsInternetSpeedTestRunning = false;
			return base.OnViewShown();
		}

		private void ConsoleStateChanged(StateChange state)
		{
			if (KeyInsertedOrRemoved(state) || IsConsoleError(state) || WorkoutEntered(state))
			{
				TouchAndDisposeScreenSaver();
				DoClose();
			}
		}

		protected virtual void DetectOnBytesBeingSent(bool value)
		{
			consoleButtonClickSub?.Dispose();
			consoleButtonClickSub = null;
			DoScreenTouched();
		}

		private bool KeyInsertedOrRemoved(StateChange state)
		{
			if (state.ChangedToOrFromState(ConsoleState.SafetyKeyRemoved, ConsoleState.Demo))
			{
				return true;
			}
			return false;
		}

		private bool IsConsoleError(StateChange state)
		{
			if (state.ChangedToOrFromState(ConsoleState.Error))
			{
				return true;
			}
			return false;
		}

		private bool WorkoutEntered(StateChange state)
		{
			if (state.ChangedToState(ConsoleState.WarmUp, ConsoleState.Workout, ConsoleState.CoolDown, ConsoleState.Paused))
			{
				Log.Trace("Workout", "Forced screen touch due to being in-workout while screen saver was showing.");
				return true;
			}
			return false;
		}

		public override void Dispose()
		{
			base.Dispose();
			consoleStateSub?.Dispose();
			consoleButtonClickSub?.Dispose();
			consoleButtonClickSub = null;
			UnregisterChangeHandlers();
		}

		protected override void NextPosition()
		{
			int value = CurrentPositionIndex.Value;
			value++;
			if (value == NumPositions)
			{
				value = 0;
			}
			CurrentPositionIndex.Value = value;
		}

		protected override void NextImage()
		{
			CurrentImageIndex.Value = (CurrentImageIndex.Value + 1) % base.NumImages;
		}

		protected override bool ShouldShowAccountSelection()
		{
			if (localSettings.IsAllAuthenticatedUsersLinked)
			{
				return base.ShouldShowAccountSelection();
			}
			return false;
		}

		protected void DoScreenTouched()
		{
			Log.Trace("ScreenSaverDialogViewModel", "Screen has been touched.");
			ILockScreenHandler obj = lockScreenHandler;
			if (obj != null && obj.CanShowLockScreen)
			{
				TouchAndDisposeScreenSaver();
				DoClose();
				lockScreenHandler.NavigateToLockScreen();
			}
			else if (ShouldShowAccountSelection() && dialogPresenter.CurrentMainViewModel.GetType() != typeof(AccountSelectionViewModel))
			{
				NavigateToAccountSelectionViewModel();
				TouchAndDisposeScreenSaver();
			}
			else
			{
				TouchAndDisposeScreenSaver();
				DoClose();
			}
		}

		private void TouchAndDisposeScreenSaver()
		{
			screenSaverHandler?.Touched();
			Task.Run(async delegate
			{
				await wifiService.CheckInternetSpeed(ShowPoorInternetConnectionDialog);
			});
			Dispose();
		}

