	public abstract class BaseInternetConnectionViewModel : BaseViewModel
	{
		public readonly INC<bool> ConnectedToInternet = new NC<bool>(value: true);

		private IDisposable internetChangedSub;

		private static bool isTestingInet;

		protected IFailedUploadMonitor FailedUploadMonitor { get; private set; }

		public abstract string LogTag { get; }

		protected virtual bool OverrideNoInternetDisplayTablets => false;

		protected BaseInternetConnectionViewModel(ILocalSettings localSettings, IFailedUploadMonitor failedUploadMonitor)
			: base(localSettings)
		{
			try
			{
				FailedUploadMonitor = failedUploadMonitor;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			ConnectedToInternet.SafeUpdateValue(connectivity?.IsConnected == true);
			SetUpInternetChangedSub();
			if (!ConnectedToInternet.Value)
			{
				Log.Trace("BaseInternetConnectionViewModel", $"Not connected in OnViewShown for {GetType()}. Showing no wifi screen.");
				DoShowNoWifiScreen();
			}
			else
			{
				if (isTestingInet)
				{
					return;
				}
				isTestingInet = true;
				Task.Run(async delegate
				{
					if (!(await wifiService.PingSucceeds()))
					{
						Log.Trace("BaseInternetConnectionViewModel", $"Poor internet connection in OnViewShown for {GetType()}. Showing no wifi screen.");
						DoShowNoWifiScreen();
					}
					isTestingInet = false;
				});
			}
		}

		public override void OnAfterViewShown()
		{
			base.OnAfterViewShown();
			FailedUploadMonitor.StartRetryTimer();
		}

		private void SetUpInternetChangedSub()
		{
			if (Mvx.TryResolve<INeedsRefreshService>(out var service))
			{
				internetChangedSub?.Dispose();
				internetChangedSub = service.WhenNeedsRefresh.Where((IRefreshPayload payload) => payload.Cause == RefreshCause.LostInternet || payload.Cause == RefreshCause.GainedInternet).SubscribeWithErrorLogging(delegate(IRefreshPayload payload)
				{
					InternetGainedOrLost(payload.Cause);
				});
			}
		}

		protected virtual void InternetGainedOrLost(RefreshCause cause)
		{
			Log.Trace("BaseInternetConnectionViewModel", $"Internet gained or lost. RefreshCause: {cause}");
			ConnectedToInternet.SafeUpdateValue(cause == RefreshCause.GainedInternet);
		}

		public override void Dispose()
		{
			internetChangedSub?.Dispose();
			internetChangedSub = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

