	public abstract class BasePrePostWorkoutWebviewViewModel : BaseWorkoutWebviewViewModel, IWebViewDataProvider
	{
		public class ModalClosedMethodCallMessage : BaseWebViewMethodCallMessage
		{
			public ModalClosedMethodCallMessage(object sender, string methodCallName, IDictionary<string, string> methodBody)
				: base(sender, methodCallName, methodBody)
			{
			}
		}

		public const string WebViewParamDoEnableScaling = "doEnableScaling";

		private IDisposable prepareWorkoutFailedSub;

		private IDisposable incompatibleWorkoutSub;

		private TaskCompletionSource<Workout> loadWorkoutTask;

		private MvxSubscriptionToken resolveConsoleToken;

		private CancellationTokenSource loadWorkoutCTS;

		private bool workoutLoadingErrorShown;

		private bool isClosing;

		private readonly IMvxMessenger messenger;

		protected readonly IWorkoutFeatureService WorkoutFeatureService;

		private readonly IPlanetFitnessService planetFitnessService;

		private readonly IWebViewDataService webViewDataService;

		public const string SchemeString = "workout";

		public const string RecordIdKeyString = "record-id";

		public const string ProgramIdKeyString = "program-id";

		public const string WorkoutIdKeyString = "workout-id";

		public const string ScheduleIdKeyString = "schedule-id";

		public const string AnalyticsWorkoutSourceKeyString = "analytics-workout-source";

		public const string AnalyticsDashboardIndexKeyString = "analytics-dashboard-index";

		public const string IsPreWorkoutKeyString = "is-pre-workout";

		public const string RecordContextKeyString = "record-context";

		public const string IsScalingEnabledKeyString = "is-scaling-enabled";

		protected virtual bool IsPreWorkout => false;

		protected string WorkoutId { get; set; }

		protected string ScheduleId { get; private set; }

		protected bool JustCompletedWorkout { get; set; }

		public bool SuccessfulInitialization { get; set; } = true;

		protected bool WebViewIsPreloaded { get; private set; }

		protected virtual bool ShouldShowDialogOnWorkoutPreloadFailure => false;

		public bool IsClosing => isClosing;

		private bool isScalingEnabled
		{
			get
			{
				if (personalTrainingSettings.SmartAdjustEnabled)
				{
					return WorkoutFeatureService.IsScalingAvailable(base.RequestedWorkout, base.RecordContext, currentConsoleService.ActiveConsole?.ConsoleInfo?.MachineType ?? ConsoleType.None);
				}
				return false;
			}
		}

		public string Scheme => "workout";

		public BasePrePostWorkoutWebviewViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IFeatureFlagManager featureFlagManager, IFailedUploadMonitor failedUploadMonitor, IWolfAnalytics wolfAnalytics, IMvxMessenger messenger, IPlanetFitnessService planetFitnessService, INeedsRefreshService refreshService, IWorkoutApiService workoutApiService, IWebViewDataService webViewDataService, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, IWorkoutFeatureService workoutFeatureService, ICurrentConsoleService currentConsoleService)
			: base(webViewDataService, localSettings, ifitApi, featureFlagManager, failedUploadMonitor, wolfAnalytics, refreshService, workoutApiService, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				this.messenger = messenger;
				this.planetFitnessService = planetFitnessService;
				WorkoutFeatureService = workoutFeatureService;
				CheckIfWebViewIsPreloaded();
				loadWorkoutCTS = new CancellationTokenSource();
				loadWorkoutTask = new TaskCompletionSource<Workout>();
				this.webViewDataService = webViewDataService;
				webViewDataService.RegisterProvider(this);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected async Task Initialize(string workoutId, WorkoutSource workoutSource, string scheduleId = null, string programId = null, Workout.WorkoutContext workoutContext = Workout.WorkoutContext.OnDemand, int dashboardIndex = -1)
		{
			prepareWorkoutFailedSub = base.StartWorkoutService?.WhenPrepareWorkoutFailed?.Subscribe(delegate
			{
				OnPrepareWorkoutFailed();
			});
			incompatibleWorkoutSub = base.StartWorkoutService?.WhenWorkoutIncompatible?.Subscribe(delegate(bool closeScreen)
			{
				this.OnIncompatibleWorkout(closeScreen, delegate
				{
					RunBehavior("ModalClosed", null).ConfigureAwait(continueOnCapturedContext: false);
				});
			});
			WorkoutId = workoutId;
			ScheduleId = scheduleId;
			base.ProgramId = programId;
			base.RecordContext = workoutContext;
			analyticsSource = new AnalyticsSource(workoutSource, dashboardIndex);
			if (!string.IsNullOrWhiteSpace(ScheduleId) && string.IsNullOrWhiteSpace(WorkoutId))
			{
				try
				{
					LiveWorkouts.WorkoutInfo workoutInfo = await LiveWorkouts.GetWorkout(IfitApi, ScheduleId);
					WorkoutId = workoutInfo.WorkoutId;
					base.ProgramId = null;
					base.RecordContext = workoutInfo.Context;
				}
				catch (ApiException exception)
				{
					Log.Trace(LogTag, "Error getting workout info from schedule ID $" + ScheduleId + ".", exception);
				}
			}
			await PreloadWorkout(WorkoutId);
			if (IsPreWorkout && localSettings.IsRoboRunMode)
			{
				await webViewBehaviorsService.RunBehavior("StartWorkout", new Dictionary<string, string>
				{
					{ "workoutId", WorkoutId },
					{ "programId", base.ProgramId }
				}, this);
			}
		}

		protected async Task PreloadWorkout(string workoutId)
		{
			try
			{
				base.RequestedWorkout = await workoutApiService.Get(workoutId, force: false, loadWorkoutCTS.Token).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Exception thrown getting workout data in BasePrePostWorkoutWebviewViewModel", exception);
			}
			finally
			{
				if (ValidateAndShowWorkoutError())
				{
					SuccessfulInitialization = false;
				}
				loadWorkoutTask?.TrySetResult(base.RequestedWorkout);
			}
		}

		public override async Task OnViewShown()
		{
			if (IsPreWorkout || !JustCompletedWorkout)
			{
				try
				{
					await loadWorkoutTask.Task;
				}
				catch (TaskCanceledException)
				{
					Log.Debug(LogTag, "Initial load workout task cancelled");
				}
			}
			await base.OnViewShown();
		}

		protected override void OnViewHidden()
		{
			if (!isClosing)
			{
				CheckIfWebViewIsPreloaded();
				base.IsAppInitialized = false;
			}
			base.OnViewHidden();
		}

		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			IDictionary<string, string> dictionary = (await base.GetAdditionalConfig()) ?? new Dictionary<string, string>();
			dictionary["doEnableScaling"] = isScalingEnabled.WebviewParamValue();
			return dictionary;
		}

		protected override void OnTrainerSelected(IDictionary<string, string> args)
		{
			if (!args.TryGetValue("trainerId", out var value))
			{
				Log.Error(LogTag, "Error getting trainerID parameter from PrePost TrainerSelected message.");
			}
			else if (planetFitnessService != null && planetFitnessService.ShouldNavigateToUpgradePath() && !planetFitnessService.AllowAccessToAthenaeum())
			{
				wolfAnalytics.NavigateToPlanetFitnessUpgradeFromLibrary(fromLockedContent: false);
				ShowViewModelThenClose<PFUpgradeSelectViewModel>();
			}
			else
			{
				LibraryAthenaeumViewModel.NavObject navObject = LibraryAthenaeumViewModel.NavObject.CreateTrainer(value);
				navObject.JustCompletedWorkout = JustCompletedWorkout;
				ShowViewModelThenClose<LibraryAthenaeumViewModel>(navObject);
			}
		}

		public virtual void ClosePrePostWebView()
		{
			if (IsPreWorkout)
			{
				ChangePresentation(new CloseFullScreenModalPresentationHint(this));
				if (!connectivity.IsConnected)
				{
					DoShowNoWifiScreen();
				}
				if (!string.IsNullOrWhiteSpace(workoutSettings.ProgramIdOfWorkout))
				{
					ShowViewModel<DetailsViewModel>(new DetailsViewModel.NavObject
					{
						Id = workoutSettings.ProgramIdOfWorkout
					});
					workoutSettings.ProgramIdOfWorkout = null;
				}
			}
			else
			{
				DoClose();
			}
		}

		private bool ValidateAndShowWorkoutError()
		{
			if (workoutLoadingErrorShown)
			{
				IsLoading.Value = false;
				return true;
			}
			if (loadWorkoutCTS == null || loadWorkoutCTS.IsCancellationRequested)
			{
				return false;
			}
			if (ShouldShowDialogOnWorkoutPreloadFailure && this.ShowErrorIfNoWorkout(base.RequestedWorkout))
			{
				workoutLoadingErrorShown = true;
				IsLoading.Value = false;
				return true;
			}
			return false;
		}

		public override void Dispose()
		{
			webViewDataService.UnregisterProvider(this);
			base.Dispose();
			loadWorkoutTask?.TrySetCanceled();
			loadWorkoutTask = null;
			prepareWorkoutFailedSub?.Dispose();
			prepareWorkoutFailedSub = null;
			incompatibleWorkoutSub?.Dispose();
			incompatibleWorkoutSub = null;
			loadWorkoutCTS?.Cancel();
			loadWorkoutCTS?.Dispose();
			loadWorkoutCTS = null;
			UnregisterChangeHandlers();
		}

		private void OnPrepareWorkoutFailed()
		{
			base.RequestedWorkout = null;
			this.ShowErrorIfNoWorkout(base.RequestedWorkout);
		}

		public void ResetWebViewState()
		{
			Bridge?.Call("ResetState");
		}

		public void WebviewCloseView()
		{
			if (base.WebviewControlsBackNav)
			{
				Bridge?.Call("BackClicked");
			}
			else
			{
				Bridge?.Call("CloseView");
			}
		}

		private void CheckIfWebViewIsPreloaded()
		{
			if (!string.IsNullOrWhiteSpace(Url))
			{
				try
				{
					Uri uri = new Uri(Url);
					WebViewIsPreloaded = base.WebviewHolderFactory.WebviewHolderStore.ContainsBaseUrlAndFragment(uri.BaseUrl(), uri.GetUrlFragment());
					return;
				}
				catch (Exception exception)
				{
					Log.Error(LogTag, "Error occurred in " + GetType().Name + " CheckIfWebViewIsPreloaded.", exception);
				}
			}
			WebViewIsPreloaded = false;
		}

		public override void RegisterCustomBehaviors(List<IWebViewBehaviorProvider> behaviorProviders)
		{
			base.RegisterCustomBehaviors(behaviorProviders);
			behaviorProviders.Add(Mvx.IocConstruct<BasePrePostModalClosedBehaviorProvider>());
			behaviorProviders.Add(Mvx.IocConstruct<JoinLiveWorkoutBehaviorProvider>());
		}

		protected override void DoClose()
		{
			isClosing = true;
			base.DoClose();
		}

		public Task<string> GetData(Uri uri)
		{
			string text = base.ProgramId;
			if (string.IsNullOrWhiteSpace(text))
			{
				text = ((!string.IsNullOrWhiteSpace(ScheduleId)) ? ScheduleId : WorkoutId);
			}
			return Task.FromResult(uri.Host switch
			{
				"record-id" => text, 
				"program-id" => base.ProgramId, 
				"workout-id" => WorkoutId, 
				"schedule-id" => ScheduleId, 
				"analytics-workout-source" => analyticsSource.Source.ToString(), 
				"analytics-dashboard-index" => analyticsSource.DashboardIndex.ToString(), 
				"is-pre-workout" => IsPreWorkout.WebviewParamValue(), 
				"record-context" => base.RecordContext.ToString(), 
				"is-scaling-enabled" => isScalingEnabled.ToString(), 
				_ => throw new KeyNotSupportedException("Workout didn't recognize key " + uri.OriginalString), 
			});
		}

		public string[] GetAllSupportedKeys()
		{
			return new string[9] { "record-id", "program-id", "workout-id", "schedule-id", "analytics-workout-source", "analytics-dashboard-index", "is-pre-workout", "record-context", "is-scaling-enabled" };
		}

