	public abstract class BaseVideoViewModel : BaseViewModel
	{
		private const double ShowLoadingBufferFloor = 0.75;

		private bool applicationPaused;

		private int showSkipTimerDuration = 1;

		private int secondsRemainingToPreloadWebView = 5;

		private IDisposable showSkipTimer;

		private IDisposable videoPlaybackCompletedSub;

		private IDisposable bufferUpdateTimer;

		private IDisposable wifiStateChanged;

		protected readonly IVideoService videoService;

		protected readonly IIfitApiService apiService;

		public readonly INC<bool> ShowSkipButton = new NC<bool>(value: false);

		private Subject<ICombinedAudioVideoPlayer> _videoPlayerReady = new Subject<ICombinedAudioVideoPlayer>();

		private int _showSkipSecondsRemaining = -1;

		public abstract string VideoSlug { get; }

		private string videoUrl { get; set; }

		public virtual bool LoopVideo => false;

		public virtual bool CanShowLoading => true;

		public int SkipButtonShownAnimationDuration => 750;

		public INC<double> VideoBuffer { get; } = new NC<double>();

		public ICommand SkipButtonPress => new MvxCommand(SkipButtonPressed);

		public ICombinedAudioVideoPlayer VideoPlayer { get; private set; }

		public Task PreloadVideoTask { get; private set; }

		public IObservable<ICombinedAudioVideoPlayer> VideoPlayerReady => _videoPlayerReady;

		public virtual int ShowSkipSecondsRemaining
		{
			get
			{
				return _showSkipSecondsRemaining;
			}
			set
			{
				_showSkipSecondsRemaining = value;
				StartTick();
			}
		}

		[DependsOn(new string[] { "VideoBuffer" })]
		public bool ShouldShowLoading
		{
			get
			{
				if (CanShowLoading)
				{
					ICombinedAudioVideoPlayer videoPlayer = VideoPlayer;
					if (videoPlayer != null && !videoPlayer.IsLoading)
					{
						return (VideoPlayer?.BufferSecondsRemaining ?? 0.0) < 0.75;
					}
					return true;
				}
				return false;
			}
		}

		protected BaseVideoViewModel(ILocalSettings localSettings, IVideoService videoService, IIfitApiService apiService)
			: base(localSettings)
		{
			try
			{
				this.videoService = videoService;
				this.apiService = apiService;
				PreloadVideoTask = Task.Run(async delegate
				{
					VideoPlayer = await GetPreBufferedVideoPlayer();
					StartBufferUpdater();
					_videoPlayerReady.OnNext(VideoPlayer);
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task<ICombinedAudioVideoPlayer> GetPreBufferedVideoPlayer()
		{
			if (videoService.PreBufferedVideoPlayer != null)
			{
				return videoService.PreBufferedVideoPlayer;
			}
			videoUrl = await GetVideoUrlFromSlug(VideoSlug).ConfigureAwait(continueOnCapturedContext: false);
			return await videoService.StartPrebufferingVodVideo(videoUrl).ConfigureAwait(continueOnCapturedContext: false);
		}

		public override void Dispose()
		{
			wifiStateChanged?.Dispose();
			wifiStateChanged = null;
			_videoPlayerReady?.Dispose();
			_videoPlayerReady = null;
			DisposePlayBackCompleteSub();
			DisposeBufferUpdateTimer();
			DisposeVideoPlayer();
			StopShowSkipTimer();
			base.Dispose();
			UnregisterChangeHandlers();
		}

		private void DisposePlayBackCompleteSub()
		{
			videoPlaybackCompletedSub?.Dispose();
			videoPlaybackCompletedSub = null;
		}

		private void DisposeVideoPlayer()
		{
			VideoPlayer?.Dispose();
			VideoPlayer = null;
		}

		private void DisposeBufferUpdateTimer()
		{
			bufferUpdateTimer?.Dispose();
			bufferUpdateTimer = null;
		}

		public override async Task OnViewShown()
		{
			try
			{
				await PreloadVideoTask;
			}
			catch (Exception exception)
			{
				Log.Trace("Video", "Unable to pre-buffer the video.", exception);
			}
			if (!LoopVideo)
			{
				StartPlayBackCompleteSub();
			}
			wifiStateChanged?.Dispose();
			wifiStateChanged = wifiService?.WhenNetworkStateChanged.Where((WifiNetworkState x) => WifiNetworkState.Connected == x).SubscribeAsync(async delegate
			{
				await ResumeVideoAfterWifiDisconnect();
			}, delegate(Exception ex)
			{
				Log.Error("Video", $"Error resuming video on wifi state change: {ex.GetBaseException()}");
			});
			await base.OnViewShown();
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			StopShowSkipTimer();
		}

		public async Task OnResume()
		{
			await PreloadVideoTask;
			if (applicationPaused)
			{
				applicationPaused = false;
				if (VideoPlayer != null)
				{
					await (VideoPlayer?.ApplicationResumed());
				}
			}
			VideoPlayer?.Play();
		}

		public void OnPause()
		{
			applicationPaused = true;
			VideoPlayer?.ApplicationPaused();
		}

		private void StartPlayBackCompleteSub()
		{
			videoPlaybackCompletedSub?.Dispose();
			videoPlaybackCompletedSub = VideoPlayer?.VideoPlaybackCompleted?.Subscribe(VideoPlaybackCompleted);
		}

		protected virtual void NavigateToNext()
		{
			VideoPlayer?.Pause();
			StopShowSkipTimer();
		}

		protected override void DoClose()
		{
			base.DoClose();
			VideoPlayer?.Pause();
			videoService?.Cleanup();
			VideoPlayer?.Dispose();
			VideoPlayer = null;
		}

		private void StartBufferUpdater()
		{
			bufferUpdateTimer?.Dispose();
			bufferUpdateTimer = Observable.Timer(TimeSpan.FromSeconds(1.0)).Repeat().Subscribe(OnBufferUpdate);
		}

		private void OnBufferUpdate(long x)
		{
			InvokeOnMainThread(delegate
			{
				VideoBuffer.Value = VideoPlayer?.BufferedSeconds ?? 0.0;
			});
		}

		private async Task ResumeVideoAfterWifiDisconnect()
		{
			PlaybackType playbackType = VideoPlayer?.SelectedPlaybackType ?? PlaybackType.Fixed;
			Log.Trace("Video", $"Reloading video stream on wifi connection state change with playback type: {playbackType}");
			try
			{
				if (VideoPlayer != null)
				{
					double position = VideoPlayer.LastVideoPositionSeconds;
					await VideoPlayer.StartLoadVodSource(videoUrl, VideoPlayer.SelectedPlaybackType);
					if (!VideoPlayer.VideoFailedToLoad)
					{
						VideoPlayer.SeekTo(position, PlayerType.Both, forceSeek: true);
					}
				}
			}
			catch (Exception ex)
			{
				Log.Error("Video", $"Failed to load video after wifi disconnect. Exception: {ex.GetBaseException()}");
			}
		}

		protected virtual void SkipButtonPressed()
		{
			NavigateToNext();
		}

		protected virtual void VideoPlaybackCompleted(bool completed)
		{
			NavigateToNext();
		}

		private void StartTick()
		{
			if (showSkipTimer == null)
			{
				showSkipTimer = Observable.Interval(TimeSpan.FromSeconds(showSkipTimerDuration)).Subscribe(ShowSkipTimerTick);
			}
		}

		private void StopShowSkipTimer()
		{
			showSkipTimer?.Dispose();
			showSkipTimer = null;
		}

		private void ShowSkipTimerTick(long _)
		{
			if (!applicationPaused)
			{
				_showSkipSecondsRemaining--;
				if (_showSkipSecondsRemaining <= 0)
				{
					StopShowSkipTimer();
					ShowSkipButton.Value = true;
					SkipButtonDidShow();
				}
			}
		}

		protected virtual void SkipButtonDidShow()
		{
		}

		private async Task<string> GetVideoUrlFromSlug(string slug)
		{
			return (await Video.Get(apiService, slug).ConfigureAwait(continueOnCapturedContext: false))?.Sources?.HlsSource?.SourceUrl;
		}

