		private void HandleDemoModeTouchMonitorTimeElapsed(object sender, EventArgs e)
		{
			if (isDisposed || !(sender is ITouchMonitor touchMonitor) || !ShouldDemoModeScreensaverShow || !Mvx.TryResolve<IOldDemoModeService>(out var service) || !service.IsInDemoMode || !((touchMonitor?.SecondsSinceLastTouch ?? 0.0) >= DemoModeScreensaverInactivityTimeout.TotalSeconds))
			{
				return;
			}
			if (isNavigatingToStrengthMirrorDemoMode)
			{
				Log.Trace("StrengthMirrorDemoMode", "isNavigatingToStrengthMirrorDemoMode is already true. Cancelling.");
				return;
			}
			isNavigatingToStrengthMirrorDemoMode = true;
			Log.Trace("StrengthMirrorDemoMode", "HandleDemoModeTouchMonitorTimeElapsed called in " + GetType().Name);
			Log.Trace("StrengthMirrorDemoMode", "ITouchMonitor TestTimeoutElapsed fired.");
			Log.Trace("StrengthMirrorDemoMode", string.Format("{0}: {1:0.000}", "SecondsSinceLastTouch", touchMonitor.SecondsSinceLastTouch));
			Log.Trace("StrengthMirrorDemoMode", string.Format("{0}: {1:0.000} sec", "DemoModeScreensaverInactivityTimeout", DemoModeScreensaverInactivityTimeout.TotalSeconds));
			if (service.ShouldUseSmdmAssets)
			{
				Log.Trace("StrengthMirrorDemoMode", "Navigating to Strength Mirror Demo Mode Screensaver page.");
				GoToStrengthMirrorDemoModeScreensaverIfInDemoMode();
			}
			else
			{
				Log.Trace("StrengthMirrorDemoMode", "Navigating to Retail Demo Mode Screensaver page.");
				GoToRetailDemoModeScreensaverIfInDemoMode(showScreensaver: true);
			}
		}

