		public async Task ScreenAnalytics(IWolfAnalytics analytics)
		{
			IFeatureFlagManager obj = featureFlagManager;
			if (obj == null || !obj.IsFeatureEnabled(FeatureFlags.ScreenAnalyticsEnabled))
			{
				Log.Trace("Analytics", "Not logging screen because FeatureFlags.ScreenAnalyticsEnabled is false.");
				return;
			}
			string advertisingId = await hardwareInfo.GetAdvertisingId();
			await analytics.Screen(GetType().ToString(), AnalyticsScreenProperties(), null, advertisingId);
		}

