		private void UpdateLastTheme()
		{
			Theme? lastLoadedTheme = LastLoadedTheme;
			Theme? theme = (LastLoadedTheme = themeService?.CurrentTheme());
			if (lastLoadedTheme.HasValue && theme.HasValue && lastLoadedTheme.Value != theme.Value)
			{
				HandleAppThemeChanged(theme.Value);
			}
		}

		protected virtual void HandleAppThemeChanged(Theme newTheme)
		{
			LastLoadedTheme = themeService?.CurrentTheme();
			_whenThemedElementsNeedUpdate?.OnNext(newTheme);
		}

		protected void ConfigureWorkoutStartSupport()
		{
			CreateStartWorkoutSubs();
			consoleStartButtonInteractor?.OnViewShown();
		}

		private void CreateStartWorkoutSubs()
		{
			if (!MonitorsForWorkoutStart)
			{
				return;
			}
			CleanupStartWorkoutSubs();
			if (StartWorkoutService == null)
			{
				return;
			}
			consoleNotConnectedSub?.Dispose();
			consoleNotConnectedSub = StartWorkoutService.WhenConsoleNotConnected.SubscribeWithErrorLogging(delegate
			{
				ShowBleScanningDialog();
			});
			usbErrorSub?.Dispose();
			usbErrorSub = StartWorkoutService.WhenUSBError.SubscribeWithErrorLogging(delegate
			{
				ShowUSBError();
			});
			workoutStartFailedSub?.Dispose();
			workoutStartFailedSub = StartWorkoutService.WhenWorkoutStartFailed.SubscribeWithErrorLogging(delegate
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.could_not_begin_workout, Wolf.Core.Resources.AppStrings.console_state_error, delegate
				{
				}, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper());
			});
			workoutStartedSub?.Dispose();
			workoutStartedSub = StartWorkoutService.WhenWorkoutStarted.Subscribe(delegate(StartingWorkoutParams x)
			{
				Log.Trace("Workout", GetType().Name + " is starting workout " + x.WorkoutId);
				PreparingWorkoutViewModel.NavObject parameterValuesObject = new PreparingWorkoutViewModel.NavObject(x.WorkoutId, x.ProgramId, x.ChallengeId, x.RunningContext, x.WorkoutSource, isForegrounding: false, x.DashboardIndex);
				MvxBundle presentationBundle = ShireViewParams.AnimateTransitionAndClearStack();
				OnNavigateToPreparingWorkoutViewModel();
				ShowViewModel<PreparingWorkoutViewModel>(parameterValuesObject, presentationBundle);
			}, delegate(Exception ex)
			{
				Log.Error("Workout", string.Format("Error in {0}: {1}", "workoutStartedSub", ex));
				StartWorkoutService.CancelWorkoutPreparations();
			});
			nonconnectedConsoleStartingManualWorkoutSub?.Dispose();
			nonconnectedConsoleStartingManualWorkoutSub = StartWorkoutService.WhenNonconnectedConsoleStartingManualWorkout.SubscribeWithErrorLogging(delegate
			{
				if (!isDisposed)
				{
					ShowSimpleConfirmationDialog(Shire.Core.Resources.AppStrings.manual_workout_title, Wolf.Core.Resources.AppStrings.dashboard_nonconnected_manual_error);
				}
			});
		}

