		protected void RegisterForStartButton()
		{
			startBtnSub?.Dispose();
			startBtnSub = currentConsoleService.ActiveConsole?.WhenStateChanged.Where((StateChange x) => (x.Old == ConsoleState.Unknown || x.Old == ConsoleState.Idle) && (x.Current == ConsoleState.WarmUp || x.Current == ConsoleState.Workout || x.Current == ConsoleState.CoolDown || x.Current == ConsoleState.Paused) && workoutSettings.WorkoutContainer == null).Subscribe(delegate
			{
				CheckForInRecoverableWorkout();
			});
		}

		protected async Task DisconnectBleConsole(IBleConsoleService bleConsoleService, bool forgetConsole = true)
		{
