		protected bool CheckForInRecoverableWorkout()
		{
			if (currentConsoleService.ActiveConsole?.LatestBasicInfo?.IsInRecoverableWorkout() == true && StartWorkoutService.CanBeginWorkoutPreparations())
			{
				Log.Trace("Workout", "We're in a recoverable workout.");
				OnNavigateToPreparingWorkoutViewModel();
				ShowViewModel<PreparingWorkoutViewModel>();
				base.viewShownCount = 0;
				return true;
			}
			return false;
		}

		protected async Task<bool> CheckForRecoverableConsole(IBleDevice device = null)
		{
			if (deviceInfo.IsBuiltIn)
			{
				return false;
			}
			bool flag = false;
			if (device != null)
			{
				flag = FitProConsoleDeviceFilterUtil.HasValidDfuDeviceName(device);
				if (!flag)
				{
					return false;
				}
			}
			Log.Trace("Updating", "Scanning for updateable equipment");
			if (Mvx.TryResolve<IDfuConnectionService>(out var service))
			{
				flag = await service.ScanForRecoverableDevices(null, showNoRecoverableDialog: true, showScanningDialog: true);
			}
			return flag;
		}

