		public virtual void NukeDbAndSubmitFatality(Exception exception = null)
		{
			try
			{
				localSettings.ReportWipeAndResetCache();
				if (exception != null)
				{
					SubmitFatality(exception);
				}
				throw new SQLiteException(SQLite3.Result.Error, "Database was malformed");
			}
			catch (SQLiteException ex)
			{
				SubmitFatality(ex);
			}
			static void SubmitFatality(Exception exception2)
			{
				if (Mvx.TryResolve<IFatalityService>(out var service))
				{
					service.ReportFatalEvent(exception2, Wolf.Core.Resources.AppStrings.fatal_please_restart, isPermanent: true);
				}
			}
		}

