		public void GoToRetailDemoModeScreensaverIfInDemoMode(bool showScreensaver, object parameterValuesObject = null, IMvxBundle presentationBundle = null)
		{
			IOldRetailDemoMode1Service service2;
			if (Mvx.TryResolve<IDemoModeService>(out var service) && service.IsInDemoMode)
			{
				service.DemoWorkoutCompleted();
			}
			else if (!Mvx.TryResolve<IOldRetailDemoMode1Service>(out service2) || !service2.IsInDemoMode)
			{
				Log.Warn("DemoMode", "No retail demo mode enabled, not navigating to screensaver or marketing");
			}
			else if (showScreensaver)
			{
				if (service2.ShouldUseSmdmAssets)
				{
					GoToViewModelAndClearNavStack<StrengthMirrorDemoModeScreensaverViewModel>(parameterValuesObject, presentationBundle);
				}
				else
				{
					GoToViewModelAndClearNavStack<RetailDemoModeScreensaverViewModel>(parameterValuesObject, presentationBundle);
				}
			}
			else if (service2.ShouldUseSmdmAssets)
			{
				GoToViewModelAndClearNavStack<StrengthMirrorDemoModeMarketingViewModel>(parameterValuesObject, presentationBundle);
			}
			else
			{
				GoToViewModelAndClearNavStack<RetailDemoModeMarketingViewModel>(parameterValuesObject, presentationBundle);
			}
		}

