		protected void PromptUserToDeleteDemoModeAssets()
		{
			IIfitApiService service;
			bool flag = Mvx.TryResolve<IIfitApiService>(out service) && service.CurrentlyAuthenticatedUser != null;
			if (deviceInfo.IsBuiltIn && flag && Mvx.TryResolve<IDemoModeService>(out var service2) && Mvx.TryResolve<IRetailDemoModeSettings>(out var service3) && service2.CanDeleteAssets() && !service3.HasDisplayedRdmDeletionDialog)
			{
				service3.HasDisplayedRdmDeletionDialog = true;
				ResetDemoMode();
			}
		}

