		public async Task<ProgressDialogResult> ShowProgressDialog(string title, IObservable<object> observable, Action<object> onNext = null, Action<Exception> onError = null, TimeSpan timeout = default(TimeSpan), string dialogTag = "", bool showSafety = true)
		{
			IDialogPresenter dialogPresenter = Mvx.Resolve<IDialogPresenter>();
			if (dialogPresenter != null)
			{
				TaskCompletionSource<ProgressDialogResult> tcs = new TaskCompletionSource<ProgressDialogResult>();
				InvokeOnMainThread(delegate
				{
					ProgressInitializationData arbitraryData = new ProgressInitializationData(title, observable, onNext, onError, tcs, timeout, dialogTag);
					dialogPresenter.ShowDialog<ProgressDialogViewModel>(null, showSafety, arbitraryData);
				});
				return await tcs.Task;
			}
			return ProgressDialogResult.FromError(new Exception("Dialog Presenter not resolvable."));
		}

