		public virtual void ShowBleScanningDialog(bool showSafely = true, BleDialogInitializationData initData = null)
		{
			if (Mvx.TryResolve<IPermissionsService>(out var service) && !service.HasPermissions(new PermissionType[2]
			{
				PermissionType.AccessCoarseLocation,
				PermissionType.AccessFineLocation
			}) && !localSettings.IsRoboRunMode)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.permissions_title, Wolf.Core.Resources.AppStrings.permission_location_explanation, ContinueToScanning, Wolf.Core.Resources.AppStrings.cancel_title.ToUpper(), Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), delegate
				{
				}, initData?.OnDismiss, dismissible: true, cancellable: true, "", null, null, isWarning: false, showSafely: false);
			}
			else
			{
				ContinueToScanning();
			}
			void ContinueToScanning()
			{
				InvokeOnMainThread(delegate
				{
					IDialogPresenter dialogPresenter = Mvx.Resolve<IDialogPresenter>();
					if (dialogPresenter != null)
					{
						if (initData == null)
						{
							initData = new BleDialogInitializationData
							{
								CanClose = true
							};
						}
						dialogPresenter.ShowDialog<BleScanningViewModel>(null, showSafely, initData);
					}
				});
			}
		}

		public static void ShowDialogViewModel<T>(object arbitraryData = null) where T : BaseViewModel
		{
			if (Mvx.TryResolve<IDialogPresenter>(out var dialogPresenter) && Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				service.RequestMainThreadAction(delegate
				{
					if (!dialogPresenter.IsDialogShown<T>())
					{
						dialogPresenter.ShowDialog<T>(null, showSafely: false, arbitraryData);
					}
				});
			}
			else
			{
				Log.Error("Navigation", "Unable to resolve IDialogPresenter or IMvxMainThreadDispatcher");
			}
		}

