		public void ShowSimpleConfirmationDialog(string title, string message, Func<CancellationToken, Task<object>> onConfirm, bool cancellableOperation, Action<Task<object>> onFinished, string cancelButtonText, string confirmButtonText, OnConfirmActionTiming timing, Action onClose = null, Action onCancel = null, bool dismissible = true, bool cancellable = true, string dialogTag = "", TaskCompletionSource<object> tcs = null, string subtitle = null, bool isWarning = false, bool showSafely = true)
