			ConfirmationInitializationData initData = new ConfirmationInitializationData(title, message, onConfirm, cancellableOperation, onFinished, cancelButtonText, confirmButtonText, timing, onClose, onCancel, dismissible, cancellable, dialogTag, tcs, subtitle, isWarning);
