		public void ShowUpdateConfirmationDialog(string pairKey = null, int softwareNumber = -1, bool cancellable = false, Action onUpdateComplete = null)
		{
			if (pairKey != null && softwareNumber != -1)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ble_update_required, Wolf.Core.Resources.AppStrings.ble_update_unfinished_update_found, OnConfirm, cancellable ? Wolf.Core.Resources.AppStrings.no.ToUpper() : "", cancellable ? Wolf.Core.Resources.AppStrings.yes.ToUpper() : Wolf.Core.Resources.AppStrings.dialog_continue.ToUpper(), null, null, cancellable, cancellable);
			}
			void OnConfirm()
			{
				Task.Run(async delegate
				{
					if (Mvx.TryResolve<ILaunchUpdate>(out var service))
					{
						service.RecoverMachine(softwareNumber, pairKey);
						if (Mvx.TryResolve<IUpdater>(out var service2))
						{
							service2.WhenIsUpdatingChanged.Where((bool x) => !x).Take(1).Subscribe(delegate
							{
								onUpdateComplete?.Invoke();
							});
							await ShowProgressDialog(Wolf.Core.Resources.AppStrings.getting_update, from x in service2.WhenIsUpdatingChanged.Timeout(TimeSpan.FromSeconds(30.0)).Take(1)
								select (object)null);
						}
					}
					else
					{
						ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.update, Wolf.Core.Resources.AppStrings.ble_update_unable_to_update, delegate
						{
						}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
					}
				});
			}
		}

