		protected async Task<bool> TestIsInternetConnectedAndReachable()
		{
			if (!connectivity.IsConnected)
			{
				Log.Trace("BaseViewModel", "TestIsInternetConnectedAndReachable - Not connected to internet, returning false.");
				return false;
			}
			try
			{
				bool flag = await wifiService.PingSucceeds();
				Log.Trace("BaseViewModel", string.Format("{0} - Result: {1}.", "TestIsInternetConnectedAndReachable", flag));
				return flag;
			}
			catch (Exception ex)
			{
				Log.Error("Wifi", ex.GetType().Name + " occurred in " + GetType().Name + ".TestIsInternetConnectedAndReachable", ex);
			}
			return false;
		}

		protected void ShowViewModelThenClose<TViewModel>(object parameterValuesObject = null, IMvxBundle presentationBundle = null, MvxRequestedBy requestedBy = null) where TViewModel : IMvxViewModel
