			MainToolbarViewModel mainToolbarViewModel = activeToolbarViewModelService?.ActiveToolbarViewModel;
			if (mainToolbarViewModel?.GetType() == typeof(TViewModel) && mainToolbarViewModel is IRefreshableViewModel refreshableViewModel)
			{
				refreshableViewModel.RefreshView(parameterValuesObject?.ToSimplePropertyDictionary());
			}
			else
