		public bool IsAutomationConnectedToBLEDeviceWithPairKey(string pairKey)
		{
			if (!Mvx.TryResolve<IBleConsoleService>(out var service))
			{
				return false;
			}
			if (service.ConnectionState != ConsoleConnectionState.Connected)
			{
				return false;
			}
			if (currentConsoleService?.ActiveConsole?.Initialized != true)
			{
				return false;
			}
			return service.CurrentDevice.PairKey == pairKey;
		}

		public void StartAutomationWorkout(string workoutId)
		{
			PreWorkoutViewModel.NavObject parameterValuesObject = new PreWorkoutViewModel.NavObject
			{
