			workoutFacade.EndWorkoutAsync();
		}

		public void ConnectAutomationToBLEDeviceWithPairKey(string pairKey)
		{
			if (!Mvx.TryResolve<IBleConsoleService>(out var service))
			{
				Log.Trace("Ble", "Unable to find BleConsoleService");
				return;
			}
			if (service.CurrentDevice?.PairKey == pairKey)
			{
				Log.Trace("Ble", "Device already connected");
				return;
			}
			service.Connect(pairKey);
			stateAutomationSub = service.WhenConnectionStateChanged.Where((ConsoleConnectionState state) => state == ConsoleConnectionState.Connected).Timeout(TimeSpan.FromSeconds(35.0)).Subscribe(delegate
			{
				TryToProgressForAutomationConnection();
			}, CleanupAutomationSubs);
			consoleAutomationSub = currentConsoleService?.WhenConsoleChanged.Where((IFitnessConsole x) => x?.WhenConsoleInitialized != null).Subscribe(delegate(IFitnessConsole x)
			{
				consoleInitAutomationSub?.Dispose();
				consoleInitAutomationSub = x.WhenConsoleInitialized.Subscribe(delegate
				{
					TryToProgressForAutomationConnection();
				});
			});
			TryToProgressForAutomationConnection();
		}

		private void TryToProgressForAutomationConnection()
		{
			if (Mvx.TryResolve<IBleConsoleService>(out var service) && service.ConnectionState == ConsoleConnectionState.Connected)
			{
				NavigateToDashboardViewModel();
				CleanupAutomationSubs();
			}
		}

		private void CleanupAutomationSubs(Exception ignored = null)
		{
			stateAutomationSub?.Dispose();
			consoleAutomationSub?.Dispose();
			consoleInitAutomationSub?.Dispose();
		}

		public bool IsAndroidBuiltIn()
		{
			if (deviceInfo.IsBuiltIn && Mvx.TryResolve<IHardwareInfo>(out var service))
			{
				return service.IsAndroid;
			}
			return false;
		}

		protected async Task LoadWorkoutData(string workoutId)
		{
			IsLoading.Value = true;
			try
			{
				RequestedWorkout = await workoutApiService.Get(workoutId).ConfigureAwait(continueOnCapturedContext: false);
				if (isDisposed)
				{
					RequestedWorkout?.Dispose();
					RequestedWorkout = null;
				}
				else if (RequestedWorkout == null)
				{
					throw new ArgumentException("The workout from the forced update call is null as well, abandon all hope");
				}
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error getting the requested workout on pre-workout screen - Workout ID " + workoutId, exception);
				this.ShowError(Wolf.Core.Resources.AppStrings.pre_workout_load_workout_error, closeAfterDismiss: true);
				IsLoading.Value = false;
				RequestedWorkout = null;
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		protected async Task DoStartManualWorkout()
		{
			if (!Mvx.TryResolve<ILockScreenHandler>(out var service) || !service.IsScreenLocked)
			{
				await Mvx.Resolve<IStartManualWorkoutService>().StartManualWorkout(WaitForConsoleReady, base.CloseViewModel, new AnalyticsSource(WorkoutSource.Dashboard));
			}
		}

		public async Task DisplayBlePairFilterVM(IMvxMessenger messenger, Action resolvedAction = null, Action cancelledAction = null, Workout workout = null, Func<Task> resolvedTask = null)
		{
			_whenBlePairFilterScreenDisplays?.OnNext(null);
			TaskCompletionSource<ResolvedConsoleMessage.Resolution> consoleResolved = new TaskCompletionSource<ResolvedConsoleMessage.Resolution>();
			resolveConsoleToken = messenger.Subscribe(delegate(ResolvedConsoleMessage msg)
			{
				resolveConsoleToken?.Dispose();
				resolveConsoleToken = null;
				if (!consoleResolved.TrySetResult(msg.Status))
				{
					Log.Error("Navigation", $"Notifying {this} of console status {msg.Status} failed.");
				}
			});
			BlePairFilterDialogViewModel.BlePairFilterOptions arbitraryData = new BlePairFilterDialogViewModel.BlePairFilterOptions
			{
				IsOnboarding = false,
				EnableAutoUpdate = false,
				DesiredType = (workout?.Type ?? RequestedWorkout.Type)
			};
			ShowDialogViewModel<BlePairFilterDialogViewModel>(arbitraryData);
			ResolvedConsoleMessage.Resolution consoleResult = await consoleResolved.Task;
			if (consoleResult == ResolvedConsoleMessage.Resolution.Resolved)
			{
				resolvedAction?.Invoke();
				if (resolvedTask != null)
				{
					await resolvedTask();
				}
			}
			if (consoleResult == ResolvedConsoleMessage.Resolution.Cancelled)
			{
				cancelledAction?.Invoke();
			}
		}

