		public virtual void Init(NavObject nav)
		{
			WebviewLoadErrored.Value = false;
			DeepLink = nav?.DeepLink;
			Task.Run(async delegate
			{
				await AddWebviewParams();
				OnUrlsUpdated(null);
			});
			if (!string.IsNullOrEmpty(nav?.path))
			{
				webviewPath = nav.path;
			}
			if (!ShouldPerformAdditionalHostCheck || hostCheckFinished)
			{
				return;
			}
			Task.Run(async delegate
			{
				bool flag = await CheckHostResponse();
				hostCheckFinished = true;
				if (!flag)
				{
					Log.Trace("WebView", "Error loading on host check");
					WebviewHolder.WebViewErrorLoading();
				}
			});
		}

