		private void DoNativeDialogResponse(OpenNativeDialogResponse openNativeDialogResponse)
		{
			string methodName = (openNativeDialogResponse.SendDialogInput ? "nativeDialogInputResponse" : "nativeDialogResponse");
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			dictionary.Add("action", openNativeDialogResponse.Action);
			if (openNativeDialogResponse.SendDialogInput)
			{
				dictionary.Add("input", openNativeDialogResponse.TextInput);
			}
			Bridge?.Call(methodName, dictionary);
			Log.Debug("WebView", "DoNativeDialogResponse: " + openNativeDialogResponse.Action);
		}

		private void HandleViewShown(string context)
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>
			{
				{
					"context",
					context ?? "default"
				},
				{
					"timestamp",
					DateTimeOffset.UtcNow.ToUnixTimeSeconds().ToString()
				}
			};
			WebviewHolder webviewHolder = WebviewHolder;
			if (webviewHolder != null && webviewHolder.IsReadyToCommunicate)
			{
				Bridge?.Call("ViewShown", dictionary);
				return;
			}
			Tuple<string, IDictionary<string, string>> item = new Tuple<string, IDictionary<string, string>>("ViewShown", dictionary);
			WebviewHolder?.WebViewMessages?.Add(item);
		}

		private async Task<bool> CheckHostResponse()
		{
			bool success = false;
			using (NativeMessageHandler handler = new NativeMessageHandler())
			{
				using HttpClient client = new HttpClient(handler);
				try
				{
					using HttpResponseMessage httpResponseMessage = await client.GetAsync(Url);
					if (httpResponseMessage != null && httpResponseMessage.IsSuccessStatusCode)
					{
						success = true;
					}
				}
				catch (Exception arg)
				{
					Log.Error("Api", $"Could not validate if host is responsive in {GetType().Name}: {arg}");
				}
			}
			return success;
		}

