		public virtual void BuildBridge(IJavascriptBridge bridge)
		{
			Bridge = bridge;
			bridge.Expose("CloseWebview", DoClose);
			bridge.Expose<OpenNativeDialogMessage>("requestNativeDialog", HandleOpenNativeDialog);
			bridge.Expose<OpenNativeDialogMessage>("requestNativeDialogInput", HandleOpenNativeDialogInput);
			bridge.ExposeTask("postAnalyticsEvent", PostAnalyticsEvent);
			bridge.Expose("OpenMenu", base.OpenMenu);
			bridge.Expose("CloseMenu", base.CloseMenu);
			bridge.Expose("TimeToInteractive", OnTimeToInteractive);
			bridge.ExposeTask("RunBehavior", RunBehaviorProvider);
			IEnumerable<string> allBehaviors = webViewBehaviorsService.GetAllBehaviors();
			foreach (string b in allBehaviors)
			{
				bridge.ExposeTask(b, (IDictionary<string, string> obj) => RunBehavior(b, obj));
			}
		}

		protected async Task RunBehaviorProvider(IDictionary<string, string> obj)
		{
			Dictionary<string, string> dict = new Dictionary<string, string> { 
			{
				"bridgeCall",
				JsonConvert.SerializeObject(obj)
			} };
			if (obj.TryGetValue("echo", out var value) && !string.IsNullOrWhiteSpace(value))
			{
				dict["echo"] = value;
				Bridge?.Call("RunBehaviorEcho", dict);
			}
			string value2;
			bool respond = obj.TryGetValue("respond", out value2) && !string.IsNullOrWhiteSpace(value2) && value2 == "True";
			if (!obj.TryGetValue("key", out var behaviorName))
			{
				Log.Trace(LogTag, "No key (behaviorProviderName) requested. Param object was: " + JsonConvert.SerializeObject(obj));
				if (respond)
				{
					dict["error"] = "No key was requested so no behavior was ran.";
					Bridge?.Call("BehaviorRan", dict);
				}
				return;
			}
			try
			{
				await webViewBehaviorsService.RunBehavior(behaviorName, obj, this);
				if (respond)
				{
					dict["response"] = behaviorName + " ran successfully";
					Bridge?.Call("BehaviorRan", dict);
				}
			}
			catch (Exception ex)
			{
				Log.Trace(LogTag, $"Something went wrong running the requested behavior: {ex}");
				if (respond)
				{
					dict["error"] = "Something went wrong running the requested behavior: " + ex.Message;
					Bridge?.Call("BehaviorRan", dict);
				}
			}
		}

