		private async Task PostAnalyticsEvent(IDictionary<string, string> args)
		{
			if (!args.ContainsKey("eventName"))
			{
				Log.Trace("WebView", GetType().Name + " webview called postAnalyticsEvent but did not include an eventName");
				return;
			}
			Dictionary<string, string> dictionary = new Dictionary<string, string>(args);
			dictionary.Remove("methodName");
			string eventName = dictionary["eventName"];
			Dictionary<string, object> properties = ((IEnumerable<KeyValuePair<string, string>>)dictionary).ToDictionary((Func<KeyValuePair<string, string>, string>)((KeyValuePair<string, string> x) => x.Key), (Func<KeyValuePair<string, string>, object>)((KeyValuePair<string, string> x) => x.Value));
			await analytics.PostEvent(eventName, properties).ConfigureAwait(continueOnCapturedContext: false);
		}

