		protected static List<IDictionary<string, string>> GeneratePreviousJsCallsDictionary(params BaseWebViewMethodCallMessage[] messages)
		{
			List<IDictionary<string, string>> result = new List<IDictionary<string, string>>();
			messages?.DoForEach(delegate(BaseWebViewMethodCallMessage x)
			{
				if (!string.IsNullOrWhiteSpace(x.MethodCallName))
				{
					Dictionary<string, string> item = new Dictionary<string, string>(x.MethodBody ?? new Dictionary<string, string>()) { { "MethodCallName", x.MethodCallName } };
					result.Add(item);
				}
			}, ignoreNulls: true);
			return result;
		}

