		public void UpdateKeyboardState(bool isOpen, float keyboardHeightPx = 0f)
		{
			string text = (isOpen ? "open" : "closed");
			string text2 = Convert.ToString(keyboardHeightPx);
			Log.Trace(LogTag, "Calling keyboard via JSBridge Keyboard State: " + text + " Height: " + text2);
			Bridge?.Call("keyboard", new Dictionary<string, string>
