		private async Task CheckMessagesReceivedBeforeViewModelShown()
		{
			if (Bridge?.NativeMessagesReceivedBeforeViewModelShown == null)
			{
				return;
			}
			List<DelayedMethodCall> list = Bridge?.NativeMessagesReceivedBeforeViewModelShown.ToList();
			foreach (DelayedMethodCall item in list)
			{
				if (item.MethodName == "WebviewControlsBackNav")
				{
					await RunBehavior("WebviewControlsBackNav", null);
				}
				else
				{
					Log.Trace(LogTag, $"Webview tried to call {item}, but it was not handled by the ViewModel");
				}
			}
		}

		protected virtual async Task AddWebviewParams()
		{
			new Dictionary<string, string>(WebViewQueryParams);
			Dictionary<string, string> newParams = webViewUrlParameterService.GetVerboseAndColorSchemeParameters(AppendVerboseToUrl, AppendColorSchemeToUrl);
			try
			{
				await lockAddWebviewParameters.WaitAsync();
				foreach (KeyValuePair<string, string> item in newParams.Where((KeyValuePair<string, string> item) => !WebViewQueryParams.ContainsKey(item.Key)))
				{
					WebViewQueryParams.Add(item.Key, item.Value);
				}
			}
			finally
			{
				lockAddWebviewParameters.Release();
			}
		}

