		private void LoadWebviewHolder()
		{
			if (WebviewHolder != null)
			{
				WebviewHolder.WebviewErrorLoading -= OnWebviewErrorLoading;
				WebviewHolder.WebviewStateChanged -= OnWebviewStateChanged;
				WebviewHolder.WebviewFinishedNavigating -= OnWebviewFinishedNavigating;
				WebviewHolder.WebviewIsReady -= OnWebviewIsReady;
			}
			WebviewHolderCreationOptions webviewHolderCreationOptions = new WebviewHolderCreationOptions
			{
				TtlIfCreating = WebviewTTL,
				WebviewHolderType = WebviewHolderType,
				GetAdditionalConfig = GetAdditionalConfig,
				ShouldCacheWebPages = ShouldCacheWebPages,
				EnableChromeDebugging = EnableChromeDebugging,
				LogTag = LogTag
			};
			if (string.IsNullOrWhiteSpace(WebviewHtml))
			{
				WebviewHolder = Mvx.Resolve<IWebviewHolderFactory>().FetchOrCreateWebviewHolderByUrl(GetUrlForViewSetup(), webviewHolderCreationOptions);
			}
			else
			{
				webviewHolderCreationOptions.TtlIfCreating = 0;
				WebviewHolder = Mvx.Resolve<IWebviewHolderFactory>().FetchOrCreateWebviewHolderByHtml(WebviewHtml, webviewHolderCreationOptions);
			}
			if (!DeepLink.IsNullOrWhitespace())
			{
				WebviewHolder.SendDeepLink(DeepLink);
			}
			WebviewHolder.WebviewErrorLoading += OnWebviewErrorLoading;
			WebviewHolder.WebviewStateChanged += OnWebviewStateChanged;
			WebviewHolder.WebviewFinishedNavigating += OnWebviewFinishedNavigating;
			WebviewHolder.WebviewIsReady += OnWebviewIsReady;
			if (string.IsNullOrWhiteSpace(WebviewHtml) && WebviewHolder.Url.IsNullOrEmpty())
			{
				Log.Info(LogTag, "Webview received an empty URL");
				WebviewLoadErrored.Value = true;
			}
		}

