		private void HandleWebviewLoadErrored()
		{
			if (WebviewHolder.IsReadyToCommunicate)
			{
				Log.Info(LogTag, "Webview loading error occurred but it's ready to communicate, not showing error screen.");
				return;
			}
			if (WebviewLoadErrored.Value)
			{
				Log.Info(LogTag, "Webview loading error occurred but it's already in errored state.");
				return;
			}
			if (!ConnectedToInternet.Value)
			{
				Log.Info(LogTag, "Webview loading error occurred, not connected to wifi. The refresh sub should navigate to nowifi screen.");
				return;
			}
			Log.Info(LogTag, "Webview loading error occurred");
			WebviewLoadErrored.Value = true;
		}

		public virtual void OnWebviewErrorLoading(object sender, EventArgs e)
		{
			if (WebviewHolder.WebView.IsLoaded)
			{
				Log.Info(LogTag, "WebViewErrorLoading occurred but it's webview state is loaded.");
			}
			else
			{
				HandleWebviewLoadErrored();
			}
		}

