	public abstract class BaseWorkoutWebviewViewModel : BaseWebViewViewModel
	{
		public const string WebViewMethodInitializeApp = "InitializeApp";

		public const string WebViewMethodCloseView = "CloseView";

		public const string NativeMethodStartWorkout = "WorkoutSelected";

		public const string NativeMethodTrainerSelected = "TrainerSelected";

		public const string WebViewMethodResetState = "ResetState";

		public const string NativeMethodAppFailed = "AppFailed";

		public const string NativeMethodAppIsInitialized = "AppIsInitialized";

		public const string WebViewParamRecordId = "recordId";

		public const string WebViewParamMediaType = "mediaType";

		public const string WebViewParamShouldDisplayRepeat = "shouldDisplayRepeat";

		public const string WebViewParamShouldDisableBackdrop = "shouldDisableBackdrop";

		public const string WebViewParamIsGuest = "isGuest";

		public const string WebViewParamLeaderboardEnabled = "leaderboardEnabled";

		protected const string MethodTrackingEvent = "TrackingEvent";

		public const string WebViewParamRecordContext = "recordContext";

		public const string NativeMethodJoinLiveWorkout = "JoinLiveWorkout";

		public const string WebviewMethodWebviewBackClicked = "BackClicked";

		public const string WebViewParamReferralSource = "referralSource";

		public const string NativeMethodManageMembership = "ManageMembership";

		protected BaseWorkoutDataProvider dataProvider;

		protected readonly IIfitApiService IfitApi;

		private readonly INeedsRefreshService needsRefreshService;

		protected string referralSource;

		protected IWolfAnalytics wolfAnalytics;

		protected IWorkoutApiService workoutApiService;

		private readonly IWebViewDataService webViewDataService;

		protected abstract string Route { get; }

		protected abstract string RecordLogId { get; }

		protected abstract bool ShouldDisplayRepeat { get; }

		protected bool IsAppInitialized { get; set; }

		protected Workout.WorkoutContext RecordContext { get; set; }

		protected override string Url => GenerateUrl(base.FeatureFlagManager, Route);

		public static string GenerateUrl(IFeatureFlagManager featureFlagManager, string route)
		{
			return DetermineUrl(featureFlagManager) + route;
		}

		protected BaseWorkoutWebviewViewModel(IWebViewDataService webViewDataService, ILocalSettings localSettings, IIfitApiService ifitApi, IFeatureFlagManager featureFlagManager, IFailedUploadMonitor failedUploadMonitor, IWolfAnalytics wolfAnalytics, INeedsRefreshService refreshService, IWorkoutApiService workoutApiService, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings)
			: base(localSettings, featureFlagManager, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				IfitApi = ifitApi;
				this.wolfAnalytics = wolfAnalytics;
				needsRefreshService = refreshService;
				this.workoutApiService = workoutApiService;
				this.webViewDataService = webViewDataService;
				dataProvider = new BaseWorkoutDataProvider(() => RecordLogId, () => ShouldDisplayRepeat.ToString(), () => referralSource, () => IsAppInitialized.ToString());
				webViewDataService.RegisterProvider(dataProvider);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("AppIsInitialized", OnAppInitialized);
			bridge.Expose("TrainerSelected", OnTrainerSelected);
			bridge.Expose("ManageMembership", OpenManageMembership);
			bridge.Expose("TrackingEvent", OnTrackingEvent);
			bridge.ExposeTask("WorkoutSelected", StartWorkout);
		}

