		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			try
			{
				if (string.IsNullOrWhiteSpace(RecordLogId) || IsAppInitialized)
				{
					return new Dictionary<string, string>();
				}
				bool leaderBoardEnabled = featureFlagManager?.IsLeaderboardFeatureEnabledForWorkout(RecordContext) ?? false;
				return await InvokeOnMainThreadAsync(() => GetInitializeAppConfig(localSettings, IfitApi, webViewConfigService, RecordLogId, RecordContext, IsTablet, ShouldDisplayRepeat, leaderBoardEnabled, referralSource));
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "BasePrePostWorkoutWebviewViewModel - Could not navigate - RecordLogId:($" + RecordLogId + ")", exception);
			}
			return null;
		}

