		private void OnTrackingEvent(IDictionary<string, string> args)
		{
			wolfAnalytics.WebviewEvent(args);
		}

		protected static async Task<IDictionary<string, string>> GetInitializeAppConfig(ILocalSettings localSettings, IIfitApiService ifitApi, IWebViewConfigService webViewConfigService, string recordLogId, Workout.WorkoutContext recordContext, bool isTablet, bool shouldDisplayRepeat, bool leaderboardEnabled, string referralSource, IDictionary<string, string> additionalConfigs = null)
		{
			Dictionary<string, string> dictionary = await webViewConfigService.GetBaseConfigsExcluding(OptionalConfigs.UserId);
			if (additionalConfigs != null)
			{
				dictionary = dictionary.Union(additionalConfigs).ToDictionary((KeyValuePair<string, string> k) => k.Key, (KeyValuePair<string, string> v) => v.Value);
			}
			if (!ifitApi.HasLoggedInUser)
			{
				dictionary["token"] = (ifitApi.Environment.ClientId + ":" + ifitApi.Environment.ClientSecret).Base64Encode();
				dictionary["isGuest"] = WebviewParamValues.WebviewParamValue(b: true);
			}
			dictionary["recordId"] = recordLogId;
			dictionary["recordContext"] = recordContext.ToString();
			dictionary["mediaType"] = (isTablet ? "tablet" : "phone");
			dictionary["shouldDisplayRepeat"] = shouldDisplayRepeat.ToJSONString();
			dictionary["shouldDisableBackdrop"] = WebviewParamValues.WebviewParamValue(b: true);
			dictionary["referralSource"] = referralSource;
			if (ifitApi.Environment is IWolfEnvironment wolfEnvironment)
			{
				dictionary["clientId"] = wolfEnvironment.LibraryClientId;
				dictionary["clientSecret"] = wolfEnvironment.LibraryClientSecret;
			}
			if (leaderboardEnabled)
			{
				dictionary["leaderboardEnabled"] = WebviewParamValues.WebviewParamValue(b: true);
			}
			return dictionary;
		}

		private static string DetermineUrl(IFeatureFlagManager featureFlagManager)
		{
			ILocalSettings localSettings = Mvx.Resolve<ILocalSettings>();
			string text = featureFlagManager.GetString(FeatureFlags.WolfWorkoutsWebviewUrl);
			if (text == null)
			{
				return localSettings.EnvironmentToUse switch
				{
					Environments.Test => FeatureFlags.WolfWorkoutWebViewDefaultUrlTest, 
					Environments.Dev => FeatureFlags.WolfWorkoutWebViewDefaultUrlDev, 
					_ => FeatureFlags.WolfWorkoutWebViewDefaultUrl, 
				};
			}
			if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service))
			{
				text = service.GenerateWebViewUrlWithParameters(text);
			}
			return text;
		}

