	public class BluetoothAccessoriesButtonViewModel : BaseViewModel
	{
		private readonly INC<int> BluetoothAccessoriesCount = new NC<int>();

		private readonly IDisposable connectedAccessoriesCountChangedSub;

		[DependsOn(new string[] { "BluetoothAccessoriesCount" })]
		public string BadgeText
		{
			get
			{
				if (BluetoothAccessoriesCount.Value <= 0)
				{
					return string.Empty;
				}
				return BluetoothAccessoriesCount.Value.ToString();
			}
		}

		[DependsOn(new string[] { "BluetoothAccessoriesCount" })]
		public bool IsBluetoothAccessoryConnected => BluetoothAccessoriesCount.Value > 0;

		[DependsOn(new string[] { "IsBluetoothAccessoryConnected" })]
		public string TitleText
		{
			get
			{
				if (IsBluetoothAccessoryConnected)
				{
					if (!currentConsoleService.IsCurrentConsoleClub)
					{
						return Wolf.Core.Resources.AppStrings.audio_device_button_text.ToUpper();
					}
					return Wolf.Core.Resources.AppStrings.headphones_button_activated_text.ToUpper();
				}
				if (!currentConsoleService.IsCurrentConsoleClub)
				{
					return Wolf.Core.Resources.AppStrings.audio_device_button_text.ToUpper();
				}
				return Wolf.Core.Resources.AppStrings.headphones_button_text.ToUpper();
			}
		}

		[DependsOn(new string[] { "BluetoothAccessoriesCount" })]
		public bool ShowBadge
		{
			get
			{
				if (BluetoothAccessoriesCount.Value > 0 && !currentConsoleService.IsCurrentConsoleClub)
				{
					return deviceInfo?.IsBuiltIn ?? false;
				}
				return false;
			}
		}

		public BluetoothAccessoriesButtonViewModel(ILocalSettings localSettings, IConnectedBluetoothAccessories connectedBluetoothAccessories)
			: base(localSettings)
		{
			try
			{
				BluetoothAccessoriesCount.Value = connectedBluetoothAccessories.DeviceCount;
				connectedAccessoriesCountChangedSub = connectedBluetoothAccessories.WhenDeviceCountChanged.SubscribeWithErrorLogging(delegate(int deviceCount)
				{
					BluetoothAccessoriesCount.Value = deviceCount;
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			connectedAccessoriesCountChangedSub.Dispose();
			UnregisterChangeHandlers();
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void OnBluetoothAccessoriesCountChanged()
		{
			RaisePropertyChanged("BadgeText");
			RaisePropertyChanged("IsBluetoothAccessoryConnected");
