	public abstract class MainToolbarViewModel : BaseWebViewViewModel
	{
		public enum ToolbarMode
		{
			Dashboard,
			CalendarOrFeed,
			DrawMap,
			Library,
			Challenges,
			Live
		}

		public const string WebMethodNameUpdateColorScheme = "updateColorScheme";

		private readonly TimeSpan DelayBeforeVMClose = TimeSpan.FromSeconds(1.0);

		public readonly INC<bool> IsBottomBarVisible = new NC<bool>();

		public readonly INC<bool> IsNativeModalitySelectorVisible = new NC<bool>();

		public readonly INC<bool> IsDrawMapButtonEnabled = new NC<bool>();

		public readonly INC<bool> IsLibraryButtonEnabled = new NC<bool>();

		public readonly INC<bool> IsLibraryAndLiveEnabled = new NC<bool>();

		public readonly INC<bool> IsNotLibraryAndNotLiveAndMapEnabled = new NC<bool>();

		public readonly INC<bool> IsLibraryAndNotLiveEnabled = new NC<bool>();

		public readonly INC<bool> IsLibraryAndNotMap = new NC<bool>();

		public readonly INC<bool> IsLibraryAndMap = new NC<bool>();

		public readonly INC<bool> IsNotLibraryAndLiveEnabled = new NC<bool>();

		public readonly INC<bool> IsNotLibraryAndNotLiveAndNotMapEnabled = new NC<bool>();

		public readonly INC<bool> IsNotLibraryAndLiveAndNotMapEnabled = new NC<bool>();

		public readonly INC<bool> ShouldShowDrawMapButton = new NC<bool>();

		public readonly INC<bool> IsLiveEnabled = new NC<bool>();

		public readonly INC<bool> IsChallengesEnabled = new NC<bool>();

		public readonly INC<bool> IsTrophyCaseEnabled = new NC<bool>();

		public readonly INC<bool> ShowChallengesButton = new NC<bool>();

		protected readonly IIfitApiService ifitApi;

		protected readonly IModalityChangeService modalityChangeService;

		protected readonly IUpgradeService upgradeService;

		protected readonly ILibraryViewModelSelectionService libraryViewModelSelectionService;

		public readonly INC<User> LoggedInUser = new NC<User>();

		public readonly INC<ToolbarMode> Mode = new NC<ToolbarMode>();

		public readonly INC<bool?> IsPremiumUser = new NC<bool?>(null);

		public readonly INC<bool> HasLoggedInUser = new NC<bool>(value: false);

		public readonly INC<string> HeaderToolbarText = new NC<string>();

		public readonly INC<bool> IsManualButtonEnabled = new NC<bool>();

		public readonly INC<int> NumberOfOptionalToolbarNavButtons = new NC<int>();

		public readonly INC<bool> ShowCalendarButton = new NC<bool>();

		public readonly INC<bool> ShowHeaderDivider = new NC<bool>(value: true);

		public readonly INC<bool> ShowHeaderShadow = new NC<bool>(value: true);

		public readonly INC<string> AppVersion = new NC<string>();

		public readonly INC<string> Environment = new NC<string>();

		protected readonly INC<bool> ViewModelHasHeaderDivider = new NC<bool>();

		protected readonly INC<bool> ViewModelHasHeaderShadow = new NC<bool>();

		public readonly INC<MockType> SelectedNonconnectedConsoleType = new NC<MockType>();

		private IDisposable activityLogDeletedSub;

		private IDisposable consoleTypeChangedSub;

		protected IDisposable needsRefreshSub;

		protected bool GetIsNativeModalitySelectorVisible => featureFlagManager.IsFeatureEnabled(FeatureFlags.ShowModalitySelector, defaultValue: true);

		protected bool GetIsLibraryButtonEnabled => featureFlagManager.IsFeatureEnabled(FeatureFlags.LibraryButtonEnabled, defaultValue: true);

		protected bool GetShouldShowDrawMapButton
		{
			get
			{
				if (IsTablet && !base.IsStrengthMirror && !base.IsHeadlessBike)
				{
					return featureFlagManager.IsFeatureEnabled(FeatureFlags.DrawMapButtonEnabled, defaultValue: true);
				}
				return false;
			}
		}

		public override bool ShouldInterceptConsoleStartButton => true;

		protected string InitialModality { get; set; }

		[DependsOn(new string[] { "ConnectedToInternet" })]
		public bool ConnectedAndLoggedIn
		{
			get
			{
				if (ifitApi.HasLoggedInUser)
				{
					return ConnectedToInternet.Value;
				}
				return false;
			}
		}

		public ToolbarMode DefaultToolbarMode { get; private set; }

		public ICommand DashboardButtonClicked => new MvxCommand(OnDashboardButtonClicked);

		public ICommand CalendarButtonClicked => new MvxCommand(OnCalendarButtonClicked);

		public ICommand DrawMapButtonClicked => new MvxCommand(OnDrawMapButtonClicked);

		public ICommand LibraryButtonClicked => new MvxCommand(OnLibraryButtonClicked);

		public ICommand ChallengesButtonClicked => new MvxCommand(OnChallengesButtonClicked);

		public ICommand HamburgerButtonClicked => new MvxCommand(OnHamburgerButtonClicked);

		public ICommand LiveScheduleButtonClicked => new MvxCommand(OnLiveScheduleButtonClicked);

		public ICommand StartManualWorkout => new MvxAsyncCommand(base.DoStartManualWorkout);

		public IMvxAsyncCommand NonconnectedConsoleTypeSwitch => new MvxAsyncCommand<MockType>(DoConsoleTypeSwitch);

		protected override bool AllowConsoleTypeChangeToResetNavigation => true;

		private bool softPaywallEnabled => base.FeatureFlagManager.IsFeatureEnabled(FeatureFlags.SoftPaywallEnabled);

		protected MainToolbarViewModel(ILocalSettings settings, IFeatureFlagManager featureFlagManager, ToolbarMode defaultMode, IIfitApiService ifitApi, IFailedUploadMonitor failedUploadMonitor, IModalityChangeService modalityChangeService, IWebViewUrlParameterService webViewUrlParameterService, IUpgradeService upgradeService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService)
			: base(settings, featureFlagManager, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.modalityChangeService = modalityChangeService;
				this.upgradeService = upgradeService;
				if (defaultMode != ToolbarMode.Library)
				{
					DefaultToolbarMode = defaultMode;
					Mode.Value = defaultMode;
				}
				RaisePropertyChanged("ConnectedAndLoggedIn");
				if (Mvx.TryResolve<ILogDeletedObserver>(out var service))
				{
					activityLogDeletedSub = service.WhenActivityLogDeleted.SubscribeWithErrorLogging(delegate
					{
						ReloadStatsAndFeed();
					});
				}
				if (Mvx.TryResolve<ILibraryViewModelSelectionService>(out var service2))
				{
					libraryViewModelSelectionService = service2;
				}
				SetLiveProperties();
				IsManualButtonEnabled.Value = false;
				ShowCalendarButton.Value = ifitApi.HasLoggedInUser || !currentConsoleService.IsBuiltinClub;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public virtual void UpdateFeatureFlags()
		{
			SetLiveProperties();
			IsBottomBarVisible.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.BottomBarVisibility, defaultValue: true);
			IsNativeModalitySelectorVisible.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.ShowModalitySelector, defaultValue: true);
			IsDrawMapButtonEnabled.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.DrawMapButtonEnabled, defaultValue: true);
			ShouldShowDrawMapButton.Value = GetShouldShowDrawMapButton;
			IsLibraryButtonEnabled.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.LibraryButtonEnabled, defaultValue: true);
			IsLibraryAndLiveEnabled.Value = GetIsLibraryButtonEnabled && IsLiveEnabled.Value;
			IsNotLibraryAndNotLiveAndMapEnabled.Value = !GetIsLibraryButtonEnabled && !IsLiveEnabled.Value && GetShouldShowDrawMapButton;
			IsLibraryAndNotLiveEnabled.Value = GetIsLibraryButtonEnabled && !IsLiveEnabled.Value;
			IsLibraryAndNotMap.Value = GetIsLibraryButtonEnabled && !GetShouldShowDrawMapButton;
			IsLibraryAndMap.Value = GetIsLibraryButtonEnabled && GetShouldShowDrawMapButton;
			IsNotLibraryAndLiveEnabled.Value = !GetIsLibraryButtonEnabled && IsLiveEnabled.Value && GetShouldShowDrawMapButton;
			IsNotLibraryAndNotLiveAndNotMapEnabled.Value = !GetIsLibraryButtonEnabled && !IsLiveEnabled.Value && !GetShouldShowDrawMapButton;
			IsNotLibraryAndLiveAndNotMapEnabled.Value = !GetIsLibraryButtonEnabled && IsLiveEnabled.Value && !GetShouldShowDrawMapButton;
			ViewModelHasHeaderDivider.Value = IsTablet;
			ViewModelHasHeaderShadow.Value = IsTablet;
			ShowHeaderDivider.Value = ViewModelHasHeaderDivider.Value;
			ShowHeaderShadow.Value = ViewModelHasHeaderShadow.Value;
		}

		protected void SetDefaultToolbarMode(ToolbarMode mode)
		{
			DefaultToolbarMode = mode;
			Mode.Value = DefaultToolbarMode;
		}

		protected virtual void ReloadStatsAndFeed()
		{
			webviewSettings.ReloadStatData = true;
			webviewSettings.ReloadFeedData = true;
		}

		public Task Init()
		{
			UpdateFeatureFlags();
			return Task.CompletedTask;
		}

		public override async Task OnViewShown()
		{
			Log.Trace(LogTag, "MainToolbarViewModel.OnViewShown() has been called");
			await base.OnViewShown();
			await SetInitialModality();
			ResetMode();
			SetCurrentUser();
			SetupHeaderToolbar();
			SetupNeedsRefreshSub();
			ResetEquipmentlessConsole();
			ResetDemoMode();
			ShowHeaderDivider.Value = ViewModelHasHeaderDivider.Value;
			ShowHeaderShadow.Value = ViewModelHasHeaderShadow.Value;
			Mvx.TryResolve<IPreferenceResolver>(out var _);
			await GetUserPremium(WebviewName);
			if (activeToolbarViewModelService != null)
			{
				activeToolbarViewModelService.ActiveToolbarViewModel = this;
			}
			if (!deviceInfo.IsBuiltIn && AllowConsoleTypeChangeToResetNavigation)
			{
				CleanupConsoleTypeChangedSub();
				consoleTypeChangedSub = consoleTypeChangeService?.WhenConsoleTypeChanged?.SubscribeWithErrorLogging(delegate
				{
					RefreshAfterModalityChange();
				});
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.ExposeTask("doConsoleTypeSwitch", WebviewDoConsoleTypeSwitch);
		}

		protected async Task SetInitialModality()
		{
			if (base.IsBuiltIn)
			{
				return;
			}
			if (currentConsoleService?.Console?.IsHybridMachine() == true)
			{
				SetHybridInitialModality();
			}
			else
			{
				SelectedNonconnectedConsoleType.Value = DashboardNonConnectedUtils.GetMockTypeFromConsole(currentConsoleService);
			}
			if (InitialModality.IsNullOrWhitespace())
			{
				return;
			}
			try
			{
				MockType desiredConsoleType = DashboardNonConnectedUtils.ConvertInitialModalityToMockType(InitialModality);
				await DoConsoleTypeSwitch(desiredConsoleType);
				InitialModality = null;
			}
			catch (ArgumentException ex)
			{
				Log.Trace(LogTag, "Error setting initial modality: " + ex.Message);
			}
		}

		private void SetHybridInitialModality()
		{
			if (modalityChangeService.HybridConsoleOverride == null)
			{
				modalityChangeService.HybridConsoleOverride = NonconnectedFitnessConsoleFactory.GetMockConsole(MockType.Elliptical, new MockFitnessConsoleOptions
				{
					AllRandomValues = false
				});
				SelectedNonconnectedConsoleType.Value = MockType.Elliptical;
			}
			else
			{
				SelectedNonconnectedConsoleType.Value = DashboardNonConnectedUtils.ConvertConsoleTypeToMockType(modalityChangeService.HybridConsoleOverride.ConsoleInfo.MachineType);
			}
		}

		private void ResetEquipmentlessConsole()
		{
			equipmentlessConsoleService.CleanUpConsole();
		}

		protected void SetCurrentUser()
		{
			LoggedInUser.Value = ifitApi.CurrentlyAuthenticatedUser;
			HasLoggedInUser.Value = ifitApi.HasLoggedInUser;
		}

		protected virtual void SetupHeaderToolbar()
		{
			string value = Wolf.Core.Resources.AppStrings.dashboard_unauthenticated_welcome;
			if (!string.IsNullOrWhiteSpace(LoggedInUser.Value?.Id))
			{
				value = string.Format(Wolf.Core.Resources.AppStrings.dashboard_authenticated_welcome, LoggedInUser.Value.Firstname);
			}
			else
			{
				Log.Error(LogTag, "Issue getting user details, SetupHeaderToolbar");
			}
			HeaderToolbarText.Value = value;
		}

		private void SetupNeedsRefreshSub()
		{
			if (Mvx.TryResolve<INeedsRefreshService>(out var service))
			{
				needsRefreshSub?.Dispose();
				needsRefreshSub = service.WhenNeedsRefresh.SubscribeWithErrorLogging(async delegate(IRefreshPayload payload)
				{
					await HandleNeedsRefresh(payload);
				});
			}
		}

		protected virtual async Task HandleNeedsRefresh(IRefreshPayload payload)
		{
			if (payload.Cause == RefreshCause.AuthenticatedUserChanged || payload.Cause == RefreshCause.TokenRefreshed)
			{
				SetCurrentUser();
				SetupHeaderToolbar();
				await Task.FromResult(0);
			}
		}

		protected void RemoveNeedsRefreshSub()
		{
			needsRefreshSub?.Dispose();
			needsRefreshSub = null;
		}

		private void SetLiveProperties()
		{
			IsLiveEnabled.Value = !base.IsStrengthMirror && featureFlagManager.IsFeatureEnabled(FeatureFlags.LiveButtonEnabled, defaultValue: true) && (IsTablet ? base.FeatureFlagManager.IsFeatureEnabled(FeatureFlags.LiveWorkoutTablet) : base.FeatureFlagManager.IsFeatureEnabled(FeatureFlags.LiveWorkoutPhone));
			IsChallengesEnabled.Value = base.FeatureFlagManager.IsFeatureEnabled(FeatureFlags.ChallengesButtonEnabled);
			IsTrophyCaseEnabled.Value = base.FeatureFlagManager.IsFeatureEnabled(FeatureFlags.TrophyCaseEnabled);
			ShowChallengesButton.Value = IsChallengesEnabled.Value || IsTrophyCaseEnabled.Value;
			int num = 0;
			if (GetShouldShowDrawMapButton)
			{
				num++;
			}
			if (IsLiveEnabled.Value)
			{
				num++;
			}
			if (ShowChallengesButton.Value)
			{
				num++;
			}
			if (GetIsLibraryButtonEnabled)
			{
				num++;
			}
			NumberOfOptionalToolbarNavButtons.Value = num;
			if (Mode.Value == ToolbarMode.Live && !IsLiveEnabled.Value)
			{
				NavigateToDashboardViewModel();
			}
			else if (Mode.Value == ToolbarMode.Challenges && !ShowChallengesButton.Value)
			{
				NavigateToDashboardViewModel();
			}
		}

		protected override void HandleAppThemeChanged(Theme newTheme)
		{
			base.HandleAppThemeChanged(newTheme);
			if (Bridge != null)
			{
				IFeatureFlagManager obj = featureFlagManager;
				if (obj == null || obj.IsFeatureEnabled(FeatureFlags.WolfColorSchemeFeature))
				{
					Bridge?.Call("updateColorScheme", new Dictionary<string, string> { ["colorScheme"] = newTheme.GetEnumMemberAttributeValue() });
				}
			}
		}

		public override void Dispose()
		{
			CleanupConsoleTypeChangedSub();
			activityLogDeletedSub?.Dispose();
			activityLogDeletedSub = null;
			needsRefreshSub?.Dispose();
			needsRefreshSub = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

		protected async Task GetUserPremium(string navigatedFrom = null)
		{
			if (!ifitApi.HasLoggedInUser)
			{
				IDeviceInformation deviceInformation = deviceInfo;
				if (deviceInformation != null && !deviceInformation.IsBuiltIn)
				{
					ShowMarketingViewModel(navigatedFrom);
					return;
				}
			}
			User user = null;
			try
			{
				user = ifitApi.CurrentlyAuthenticatedUser;
			}
			catch (SQLiteException ex)
			{
				Log.Error(LogTag, $"SQLiteException due to: SQLite3.Result: {ex.Result} when trying to get user", ex.GetBaseException());
				NukeDbAndSubmitFatality(ex);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Could not get user", exception);
			}
			bool isPremium = user?.Premium == true;
			if (!isPremium && ifitApi.HasLoggedInUser)
			{
				Log.Trace(LogTag, "Non-premium user detected, force refresh the user to refresh their premium status");
				try
				{
					isPremium = (await GetUser().ConfigureAwait(continueOnCapturedContext: false))?.Premium == true;
				}
				catch (ApiException)
				{
					Log.Trace(LogTag, string.Format("[ApiException] Failed to refresh user so continuing with {0} = {1}", "isPremium", isPremium));
				}
				catch (iFit.Api.Support.ConnectivityException exception2)
				{
					Log.Trace(LogTag, string.Format("[ConnectivityException] Failed to refresh user due to internet issues, so continuing with {0} = {1}", "isPremium", isPremium), exception2);
				}
			}
			IsPremiumUser.Value = isPremium;
		}

		protected virtual Task<User> GetUser()
		{
			return User.GetMe(ifitApi, populate: true, force: true);
		}

		protected virtual void OnDashboardButtonClicked()
		{
			if (Mode.Value != ToolbarMode.Dashboard)
			{
				ConfirmNavigationAwayFromMaps(Navigate);
			}
			void Navigate()
			{
				Mode.Value = ToolbarMode.Dashboard;
				CloseCurrentAndShowViewModel<DashboardViewModel>();
			}
		}

		protected virtual void OnCalendarButtonClicked()
		{
			if (!IsPremiumUser.Value.HasValue)
			{
				Log.Trace(LogTag, "Not navigating - still waiting on premium user status");
			}
			else
			{
				ConfirmNavigationAwayFromMaps(Navigate);
			}
			void Navigate()
			{
				if (Mode.Value != ToolbarMode.CalendarOrFeed)
				{
					Mode.Value = ToolbarMode.CalendarOrFeed;
					DirectUserBasedOnPremiumStatus<FeedViewModel>();
				}
			}
		}

		protected virtual void OnDrawMapButtonClicked()
		{
			if (!IsPremiumUser.Value.HasValue)
			{
				Log.Trace(LogTag, "Not navigating - still waiting on premium user status");
			}
			else
			{
				if (Mode.Value == ToolbarMode.DrawMap || localSettings.IsRoboRunMode)
				{
					return;
				}
				Mode.Value = ToolbarMode.DrawMap;
				if (!DirectUserBasedOnPlanetFitnessStatus())
				{
					if (ShouldDirectAsPremiumUser())
					{
						CloseCurrentAndShowViewModel<DrawMapViewModel>();
					}
					else
					{
						upgradeService.Upgrade(this);
					}
				}
			}
		}

		protected virtual void OnLibraryButtonClicked()
		{
			NavigateToLibrary(null, ToolbarMode.Library);
		}

		protected virtual void OnChallengesButtonClicked()
		{
			if (IsTrophyCaseEnabled.Value)
			{
				NavigateToTrophyCase();
				return;
			}
			LibraryAthenaeumViewModel.NavObject navObj = LibraryAthenaeumViewModel.NavObject.CreateChallenges();
			NavigateToLibrary(navObj, ToolbarMode.Challenges);
		}

		private void NavigateToTrophyCase()
		{
			if (Mode.Value != ToolbarMode.Challenges)
			{
				LibraryAthenaeumViewModel.NavObject navObj = LibraryAthenaeumViewModel.NavObject.CreateTrophyCase();
				Mode.Value = ToolbarMode.Challenges;
				CloseCurrentAndShowViewModel<TrophyCaseViewModel>(navObj);
			}
		}

		private void NavigateToLibrary(object navObj, ToolbarMode mode)
		{
			if (!IsPremiumUser.Value.HasValue)
			{
				Log.Trace(LogTag, "Not navigating - still waiting on premium user status");
			}
			else
			{
				ConfirmNavigationAwayFromMaps(Navigate);
			}
			void Navigate()
			{
				if (Mode.Value != mode)
				{
					Mode.Value = mode;
					if (base.IsBuiltIn)
					{
						CloseCurrentAndShowViewModel<LibraryAthenaeumViewModel>(navObj);
					}
					else
					{
						DirectUserBasedOnPremiumStatus<LibraryAthenaeumViewModel>(navObj);
					}
				}
			}
		}

		protected virtual void OnLiveScheduleButtonClicked()
		{
			if (!IsPremiumUser.Value.HasValue)
			{
				Log.Trace(LogTag, "Not navigating - still waiting on premium user status");
			}
			else if (Mode.Value != ToolbarMode.Live)
			{
				ConfirmNavigationAwayFromMaps(Navigate);
			}
			void Navigate()
			{
				Mode.Value = ToolbarMode.Live;
				if (!DirectUserBasedOnPlanetFitnessStatus())
				{
					DirectUserBasedOnPremiumStatus<LiveScheduleViewModel>();
				}
			}
		}

		private void ConfirmNavigationAwayFromMaps(Action confirmAction)
		{
			if (Mode.Value != ToolbarMode.DrawMap)
			{
				confirmAction();
			}
			else
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.exit_draw_maps_title, Wolf.Core.Resources.AppStrings.exit_draw_map_description, confirmAction, Wolf.Core.Resources.AppStrings.dialog_continue_drawing, Wolf.Core.Resources.AppStrings.dialog_exit);
			}
		}

		protected bool DirectUserBasedOnPlanetFitnessStatus()
		{
			if (Mvx.TryResolve<IPlanetFitnessService>(out var service) && service != null && service.ShouldNavigateToUpgradePath())
			{
				Log.Trace(LogTag, "Navigating user to PFUpgradeSelectViewModel");
				if (Mode.Value == ToolbarMode.DrawMap)
				{
					analytics.NavigateToPlanetFitnessUpgradeFromMap();
				}
				else if (Mode.Value == ToolbarMode.Live)
				{
					analytics.NavigateToPlanetFitnessUpgradeFromLive();
				}
				CloseCurrentAndShowViewModel<PFUpgradeSelectViewModel>();
				return true;
			}
			return false;
		}

		private void DirectUserBasedOnPremiumStatus<TViewModel>(object navObj = null) where TViewModel : IMvxViewModel
		{
			if (ShouldDirectAsPremiumUser())
			{
				CloseCurrentAndShowViewModel<TViewModel>(navObj);
			}
			else
			{
				upgradeService.Upgrade(this);
			}
		}

		private bool ShouldDirectAsPremiumUser()
		{
			if (!currentConsoleService.IsBuiltinClub)
			{
				return ifitApi.HasPremiumOrEnabledUser;
			}
			return true;
		}

		private void CleanUpBackstack()
		{
			if (!(this is DashboardViewModel))
			{
				Task.Delay(250).ContinueWith(delegate
				{
					DoClose();
				}).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private void CloseCurrentAndShowViewModel<TViewModel>(object navObj = null) where TViewModel : IMvxViewModel
		{
			if (typeof(TViewModel) == typeof(LibraryAthenaeumViewModel))
			{
				Task.Run((Func<Task>)CreateLibraryLoadTimeEvent);
			}
			ShowViewModel<TViewModel>(navObj);
			CleanUpBackstack();
		}

		private async Task CreateLibraryLoadTimeEvent()
		{
			TimedEvent timedEvent = await EventService.Instance.CreateAsync("Library Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null && !timedEvent.Properties.ContainsKey("origin"))
			{
				timedEvent.Properties["origin"] = "toolbar";
			}
		}

		protected virtual void OnHamburgerButtonClicked()
		{
			themeService.CurrentWebViewUrl = GetWebViewUrlFromMode();
			OpenMenu();
		}

		public string GetWebViewUrlFromMode()
		{
			switch (Mode.Value)
			{
			case ToolbarMode.Dashboard:
				return GetWallEUrlWhenNeed(featureFlagManager, FeatureFlags.WallEDashboardUrl, FeatureFlags.WolfDashboardWebviewUrl);
			case ToolbarMode.CalendarOrFeed:
				return featureFlagManager.GetString(FeatureFlags.PersonalFeedWebViewUrl);
			case ToolbarMode.Library:
			case ToolbarMode.Challenges:
				return featureFlagManager.GetString(FeatureFlags.WolfAthenaeumWebViewUrl);
			case ToolbarMode.Live:
				return featureFlagManager.GetString(FeatureFlags.LiveScheduleWebViewUrl);
			default:
				return string.Empty;
			}
		}

		public void ResetMode()
		{
			Mode.Value = DefaultToolbarMode;
		}

		private void SetAppVersion()
		{
			if (Mvx.TryResolve<IAppVersionService>(out var service))
			{
				AppVersion.Value = service.MainAppVersionInfo.FullAppVersion;
			}
		}

		private void SetEnvironment()
		{
			Environment.Value = (IsTablet ? "" : " - ") + localSettings.EnvironmentToUse.ToString() + $"- {ifitApi?.CurrentlyAuthenticatedUser?.SubscriptionType}";
		}

		protected virtual bool ShouldAllowManualWorkouts()
		{
			IDeviceInformation deviceInformation = deviceInfo;
			if (deviceInformation != null && deviceInformation.IsStrengthMirror)
			{
				return false;
			}
			return true;
		}

		public static string GetWallEUrlWhenNeed(IFeatureFlagManager featureFlagManager, FeatureFlag eFlag, FeatureFlag flag)
		{
			if (featureFlagManager.GetBool(FeatureFlags.WallEUseWebview))
			{
				return featureFlagManager.GetString(eFlag);
			}
			return featureFlagManager.GetString(flag);
		}

		protected async Task WebviewDoConsoleTypeSwitch(IDictionary<string, string> parameters)
		{
			SetIsLoading(isLoading: true);
			try
			{
				MockType mockTypeFromWebviewParams = modalityChangeService.GetMockTypeFromWebviewParams(parameters);
				await DoConsoleTypeSwitch(mockTypeFromWebviewParams);
			}
			catch (ArgumentException ex)
			{
				Log.Trace(LogTag, "WebviewDoConsoleTypeSwitch: Error setting modality: " + ex.Message);
			}
			finally
			{
				SetIsLoading(isLoading: false);
			}
		}

		protected async Task DoConsoleTypeSwitch(MockType desiredConsoleType)
		{
			try
			{
				INC<MockType> selectedNonconnectedConsoleType = SelectedNonconnectedConsoleType;
				selectedNonconnectedConsoleType.Value = await modalityChangeService.ChangeNonConnectedModality(desiredConsoleType);
			}
			catch (ArgumentException ex)
			{
				Log.Trace(LogTag, "DoConsoleTypeSwitch: Argument error: " + ex.Message);
			}
			catch (NotChangingModalityException)
			{
				Log.Trace(LogTag, "DoConsoleTypeSwitch: Not changing modality.");
			}
			catch (ModalityChangeErroredException ex3)
			{
				Log.Trace(LogTag, "DoConsoleTypeSwitch: Error changing modality: " + ex3.Message);
			}
			catch (OverrideModalityChangeException ex4)
			{
				Log.Trace(LogTag, "DoConsoleTypeSwitch: Not connecting to new console, must override modality change.");
				await OverrideModalityChange(ex4.OverrideType);
			}
			catch (MustDisconnectCurrentDeviceException ex5)
			{
				Log.Trace(LogTag, "DoConsoleTypeSwitch: Must disconnect current device.");
				await PromptForBleDisconnect(ex5.DesiredConsoleType);
			}
			catch (Exception ex6)
			{
				Log.Error(LogTag, "DoConsoleTypeSwitch: Unhandled error!!: " + ex6.Message);
			}
		}

		private async Task OverrideModalityChange(MockType overrideType)
		{
			SelectedNonconnectedConsoleType.Value = overrideType;
			modalityChangeService.HybridConsoleOverride = NonconnectedFitnessConsoleFactory.GetMockConsole(overrideType, new MockFitnessConsoleOptions
			{
				AllRandomValues = false
			});
			await RefreshAfterModalityChange();
		}

		private async Task PromptForBleDisconnect(MockType desiredConsoleType)
		{
			if (!(await PresentBleDisconnectForNonConnectedSwitch()))
			{
				return;
			}
			Subject<object> whenShouldDismissDialog = new Subject<object>();
			object obj = null;
			try
			{
				int num;
				_ = num - 1;
				_ = 1;
				try
				{
					ShowProgressDialog(Wolf.Core.Resources.AppStrings.disconnecting, whenShouldDismissDialog);
					INC<MockType> selectedNonconnectedConsoleType = SelectedNonconnectedConsoleType;
					selectedNonconnectedConsoleType.Value = await modalityChangeService.ContinueAndConnectToMockConsole(desiredConsoleType, (currentConsoleService.Console?.Connection as IFitProDeviceConnection)?.IsReconnecting ?? false);
					whenShouldDismissDialog.OnNext(null);
					await RefreshAfterModalityChange();
				}
				catch (ModalityChangeErroredException)
				{
					Log.Trace(LogTag, "PromptForBleDisconnect: Error changing modality.");
				}
			}
			catch (object obj2)
			{
				obj = obj2;
			}
			await Task.Delay(500);
			whenShouldDismissDialog.OnNext(null);
			object obj3 = obj;
			if (obj3 != null)
			{
				if (!(obj3 is Exception source))
				{
					throw obj3;
				}
				ExceptionDispatchInfo.Capture(source).Throw();
			}
		}

		protected virtual TaskCompletionSource<object> GetTcs()
		{
			return new TaskCompletionSource<object>();
		}

		protected virtual async Task<bool> PresentBleDisconnectForNonConnectedSwitch()
		{
			bool shouldContinueWithModalityChange = false;
			TaskCompletionSource<object> tcs = GetTcs();
			ConfirmationInitializationData initData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.dashboard_nonconnected_ble_connected_prompt_title, Wolf.Core.Resources.AppStrings.dashboard_nonconnected_ble_connected_prompt_message, delegate
			{
				shouldContinueWithModalityChange = true;
				return Task.FromResult<object>(null);
			}, cancellableOperation: true, null, Wolf.Core.Resources.AppStrings.cancel.ToUpper(), Wolf.Core.Resources.AppStrings.disconnect.ToUpper(), OnConfirmActionTiming.BeforeClose, null, delegate
			{
				shouldContinueWithModalityChange = false;
			}, dismissible: true, cancellable: true, "", tcs);
			BaseViewModel.ShowSimpleConfirmationDialog(this, initData);
			await tcs.Task;
			return shouldContinueWithModalityChange;
		}

		public virtual Task RefreshAfterModalityChange()
		{
			base.WebviewHolder.WebviewInitialization();
			SelectedNonconnectedConsoleType.Value = DashboardNonConnectedUtils.GetMockTypeFromConsole(currentConsoleService);
			return Task.CompletedTask;
		}

		private void CleanupConsoleTypeChangedSub()
		{
			consoleTypeChangedSub?.Dispose();
			consoleTypeChangedSub = null;
		}

