	public class TrophyCaseViewModel : MainToolbarViewModel, IWebViewDataProvider
	{
		private const string Tag = "TrophyCase";

		private string entryPoint;

		private readonly IWebViewDataService webViewDataService;

		public const string SchemeString = "library";

		public const string EntryPointKeyString = "entry-point";

		public override int WebviewTTL => 0;

		protected override string Url => LibraryAthenaeumViewModel.GetWebViewUrl(featureFlagManager, entryPoint ?? "trophy-case");

		public override string WebviewName => "TrophyCase";

		public override string LogTag => "TrophyCase";

		public string Scheme => "library";

		public TrophyCaseViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IFeatureFlagManager featureFlagManager, IFailedUploadMonitor failedUploadMonitor, IWebViewDataService webViewDataService, IModalityChangeService modalityChangeService, IWebViewUrlParameterService webViewUrlParameterService, IUpgradeService upgradeService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService)
			: base(localSettings, featureFlagManager, ToolbarMode.Challenges, ifitApi, failedUploadMonitor, modalityChangeService, webViewUrlParameterService, upgradeService, webviewSettings, currentConsoleService)
		{
			try
			{
				HeaderToolbarText.Value = Wolf.Core.Resources.AppStrings.TrophyCase;
				this.webViewDataService = webViewDataService;
				webViewDataService.RegisterProvider(this);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(LibraryAthenaeumViewModel.NavObject nav)
		{
			entryPoint = nav?.EntryPoint;
			SetDefaultToolbarMode(ToolbarMode.Challenges);
			OnUrlsUpdated(null);
		}

		protected override void SetupHeaderToolbar()
		{
			if (base.viewShownCount < 1)
			{
				HeaderToolbarText.Value = Wolf.Core.Resources.AppStrings.TrophyCase;
			}
		}

		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			Dictionary<string, string> setupParams = new Dictionary<string, string>();
			IWolfEnvironment wolfEnvironment = ifitApi.Environment as IWolfEnvironment;
			string libraryClientId = wolfEnvironment?.LibraryClientId;
			string libraryClientSecret = wolfEnvironment?.LibraryClientSecret;
			string token = await ifitApi.GetToken();
			bool b = await preferenceResolver.GetIsMetric();
			setupParams["clientId"] = libraryClientId;
			setupParams["clientSecret"] = libraryClientSecret;
			setupParams["token"] = token;
			setupParams["baseGatewayAPIUrl"] = ifitApi.Environment.BaseGatewayAPIUrl;
			setupParams["verbose"] = WebviewParamValues.WebviewParamValue(b: false);
			setupParams["useMetricUnits"] = b.WebviewParamValue();
			setupParams[JavascriptBridge.MethodToSetConfigs] = WebviewMethodOldInitializeWebview;
			if (entryPoint.IsNotNullOrWhiteSpace())
			{
				setupParams["entryPoint"] = Uri.UnescapeDataString(entryPoint);
			}
			return setupParams;
		}

		public Task<string> GetData(Uri uri)
		{
			if (uri.Host == "entry-point")
			{
				return Task.FromResult(entryPoint);
			}
			throw new KeyNotSupportedException("Library didn't recognize key " + uri.OriginalString);
		}

		public string[] GetAllSupportedKeys()
		{
			return new string[1] { "entry-point" };
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				webViewDataService.UnregisterProvider(this);
				base.WebviewHolder = null;
				base.Dispose();
				UnregisterChangeHandlers();
			}
		}

