namespace Wolf.Core.ViewModels.Settings
{
	public abstract class BaseEquipmentSettingsViewModel : BaseViewModel
	{
		public readonly ObservableCollection<VideoQualitySpinnerModel> VideoQualityData = new ObservableCollection<VideoQualitySpinnerModel>();

		public readonly INC<string> UnitOfMeasurementContent = new NC<string>();

		public readonly INC<VideoQualitySpinnerModel> SelectedVideoQuality = new NC<VideoQualitySpinnerModel>();

		public readonly INC<string> WorkoutClosedCaptionsTitle = new NC<string>();

		public readonly INC<string> TvClosedCaptionsTitle = new NC<string>();

		public readonly BooleanCycle TvClosedCaptionsEnabled = new BooleanCycle();

		public readonly INC<bool> ShowQuality = new NC<bool>();

		protected readonly ISettingsRouter settingsRouter;

		private readonly ITelevisionTunerService televisionTunerService;

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly ISetUnitsService setUnitsService;

		protected readonly IIfitApiService ifitApi;

		public BooleanCycle ClosedCaptionsFeatureEnabled = new BooleanCycle();

		public readonly INC<bool> FromClubOwnerSettings = new NC<bool>();

		public ICommand TvClosedCaptionsClicked => new MvxCommand(TvClosedCaptionsEnabled.SwitchValue);

		public ICommand DoUnitOfMeasurement => new MvxAsyncCommand(ToggleUnitOfMeasurement);

		public virtual string UnitOfMeasurementTitle { get; }

		public bool TelevisionTunerAvailable => televisionTunerService.IsAvailable == true;

		public BaseEquipmentSettingsViewModel(ILocalSettings localSettings, ISettingsRouter settingsRouter, IIfitApiService ifitApi, ITelevisionTunerService televisionTunerService, IWolfAnalytics wolfAnalytics, ISetUnitsService setUnitsService)
			: base(localSettings)
		{
			try
			{
				this.televisionTunerService = televisionTunerService;
				this.settingsRouter = settingsRouter;
				this.ifitApi = ifitApi;
				this.wolfAnalytics = wolfAnalytics;
				this.setUnitsService = setUnitsService;
				InitializeVideoQuality(VideoQualityData, SelectedVideoQuality, workoutSettings.VideoQuality);
				SelectedVideoQuality.Changed += OnVideoQualityChanged;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public virtual async Task Init(bool fromClubOwnerSettings)
		{
			FromClubOwnerSettings.Value = fromClubOwnerSettings;
			TvClosedCaptionsEnabled.Value = settingsRouter.GetShowTvClosedCaptions(FromClubOwnerSettings.Value);
			try
			{
				INC<string> unitOfMeasurementContent = UnitOfMeasurementContent;
				unitOfMeasurementContent.Value = FormattedUnitOfMeasurement(await settingsRouter.GetIsMetric(FromClubOwnerSettings.Value).ConfigureAwait(continueOnCapturedContext: false));
			}
			catch (Exception)
			{
				Log.Error("Settings", "EquipmentInfoViewModel Init() - Unable to update units of measurement");
			}
		}

		private void InitializeVideoQuality(ObservableCollection<VideoQualitySpinnerModel> models, INC<VideoQualitySpinnerModel> currentModel, VideoQuality currentQuality)
		{
			INC<bool> showQuality = ShowQuality;
			int value;
			if (deviceInfo.IsBuiltIn)
			{
				ICurrentConsoleService obj = currentConsoleService;
				value = ((obj == null || obj.Console?.ConsoleInfo?.IsClub != true) ? 1 : 0);
			}
			else
			{
				value = 0;
			}
			showQuality.Value = (byte)value != 0;
			int num = 0;
			if (!featureFlagManager.GetBool(FeatureFlags.VideoHlsEnabled))
			{
				models.Add(new VideoQualitySpinnerModel(num, VideoQuality.Auto));
				num++;
			}
			models.Add(new VideoQualitySpinnerModel(num, VideoQuality.Resolution1080P));
			models.Add(new VideoQualitySpinnerModel(num + 1, VideoQuality.Resolution720P));
			models.Add(new VideoQualitySpinnerModel(num + 2, VideoQuality.Resolution540P));
			models.Add(new VideoQualitySpinnerModel(num + 3, VideoQuality.Resolution360P));
			models.Add(new VideoQualitySpinnerModel(num + 4, VideoQuality.Resolution270P));
			foreach (VideoQualitySpinnerModel model in models)
			{
				if (model.Quality == currentQuality)
				{
					currentModel.Value = model;
					return;
				}
			}
			currentModel.Value = models.LastOrDefault();
		}

		private void OnVideoQualityChanged(object sender, EventArgs e)
		{
			workoutSettings.VideoQuality = SelectedVideoQuality.Value.Quality;
		}

		private async Task ToggleUnitOfMeasurement()
		{
			bool clubOwner = FromClubOwnerSettings.Value;
			bool flag = await settingsRouter.GetIsMetric(clubOwner).ConfigureAwait(continueOnCapturedContext: false);
			await setUnitsService.SetUnits(!flag, clubOwner);
			flag = await settingsRouter.GetIsMetric(clubOwner).ConfigureAwait(continueOnCapturedContext: false);
			UnitOfMeasurementContent.Value = FormattedUnitOfMeasurement(flag);
			CheckForAndDisplayRowerMessage(flag);
			await wolfAnalytics.ChangedUoM().ConfigureAwait(continueOnCapturedContext: false);
		}

		protected string FormattedUnitOfMeasurement(bool isMetric)
		{
			if (!isMetric)
			{
				return $"{Wolf.Core.Resources.AppStrings.settings_unit_standard} ({Wolf.Core.Resources.AppStrings.mph.ToUpper()})";
			}
			return $"{Wolf.Core.Resources.AppStrings.settings_unit_metric} ({Wolf.Core.Resources.AppStrings.kph.ToUpper()})";
		}

		private void CheckForAndDisplayRowerMessage(bool isMetric)
		{
			if (!(currentConsoleService.GetCurrentConsoleType(ConsoleType.Treadmill) != ConsoleType.Rower || isMetric))
			{
				BaseViewModel.ShowSimpleConfirmationDialog(this, new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.settings_equipment_info, Wolf.Core.Resources.AppStrings.rower_workout_data_metric, Wolf.Core.Resources.AppStrings.ok.ToUpper(), dismissible: false, cancellable: false));
			}
		}

		[DependsOn(new string[] { "TvClosedCaptionsEnabled" })]
		public void TvClosedCaptionsValueUpdated()
		{
			settingsRouter.SetShowTvClosedCaptions(TvClosedCaptionsEnabled.Value, FromClubOwnerSettings.Value);
		}

