	public abstract class PrimarySettingsViewModel : BaseViewModel
	{
		protected IMultiClickSecretGesture secretEquipmentApi;

		protected bool isNavigating;

		public readonly INCList<SettingsCollectionCellModel> AccountList = new NCList<SettingsCollectionCellModel>();

		public readonly INCList<SettingsCollectionCellModel> EquipmentList = new NCList<SettingsCollectionCellModel>();

		public readonly INCList<SettingsCollectionCellModel> AboutList = new NCList<SettingsCollectionCellModel>();

		private IMvxMessenger messenger;

		protected readonly IIfitApiService ifitApi;

		public bool ShouldShowEnvironmentLabel => !ifitApi.Environment.Name.Equals("Prod");

		public string EnvironmentString => "Environment: " + ifitApi.Environment.Name;

		protected ICommand LockPinFeatureAction => new MvxCommand<bool>(HandleLockPinFeatureAction);

		protected IMvxMessenger Messenger
		{
			get
			{
				if (messenger != null)
				{
					return messenger;
				}
				return messenger = Mvx.Resolve<IMvxMessenger>();
			}
		}

		protected abstract bool FromClubOwnerSettings { get; }

		protected PrimarySettingsViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, ICurrentConsoleService currentConsoleService)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			isNavigating = false;
		}

		protected virtual void BuildSettingsCollection()
		{
			InitializeSecretEquipmentApi();
		}

		protected void EquipmentAction()
		{
			isNavigating = true;
			ShowViewModel<EquipmentInfoViewModel>(new
			{
				fromClubOwnerSettings = FromClubOwnerSettings
			});
		}

		protected void SecretSettingsAction()
		{
			isNavigating = true;
			ShowViewModel<SecretSettingsViewModel>();
		}

		protected void InitializeSecretEquipmentApi()
		{
			secretEquipmentApi = new MultiClickSecretGesture(EquipmentAction, SecretSettingsAction);
		}

		protected abstract IList<SettingsCollectionCellModel> BuildEquipmentList();

		protected void DoOpenWifi()
		{
			ShowViewModel<SettingsWifiViewModel>();
		}

		protected void DoOpenEquipmentInfo()
		{
			if (!isNavigating)
			{
				secretEquipmentApi.Update();
			}
		}

		protected void DoOpenEquipmentSettings()
		{
			ShowViewModel<EquipmentSettingsViewModel>(new
			{
				fromClubOwnerSettings = FromClubOwnerSettings
			});
		}

		protected void DoOpenMaintenance()
		{
			ShowViewModel<MaintenanceViewModel>();
		}

		private void HandleLockPinFeatureAction(bool isLockPinConfigured)
		{
			if (ifitApi?.CurrentlyAuthenticatedUser == null)
			{
				CreateAndPublishToastMessage("Must be logged in to set Lock Pin");
				ShowLoginViewModel();
			}
			else if (isLockPinConfigured)
			{
				isNavigating = true;
				ShowViewModel<LockPinSettingsViewModel>();
			}
			else
			{
				BaseViewModel.ShowDialogViewModel<LockPinDialogViewModel>();
			}
		}

		protected void DoOpenLanguageSettings()
		{
			ShowViewModel<SettingsLanguagesViewModel>();
		}

		private void CreateAndPublishToastMessage(string text)
		{
			ToastMessage message = new ToastMessage(this, text);
			Messenger.Publish(message);
		}

