	public class SettingsViewModel : PrimarySettingsViewModel
	{
		[Flags]
		public enum SettingsState
		{
			None = 0,
			BLE = 1,
			BuiltInSignedOut = 2,
			BuiltInSignedIn = 4,
			BuiltInClubSignedOut = 8,
			BuiltInClubSignedIn = 0x10,
			All = 0x1F
		}

		protected List<string> BetaFeatures = new List<string>();

		public readonly SettingsState CurrentSettingsState;

		private readonly IHardwareInfo hardwareInfo;

		private readonly ILockPinService lockPinService;

		public bool IsBuiltInClub => currentConsoleService.IsBuiltinClub;

		public ICommand OpenClubOwnerSettings => new MvxCommand(base.DisplayViewModelIfNeeded<ClubOwnerSettingsViewModel>);

		protected override bool FromClubOwnerSettings => false;

		public SettingsViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, ICurrentConsoleService currentConsoleService, IHardwareInfo hardwareInfo, ILockPinService lockPinService)
			: base(localSettings, ifitApi, currentConsoleService)
		{
			try
			{
				this.hardwareInfo = hardwareInfo;
				this.lockPinService = lockPinService;
				if (!deviceInfo.IsBuiltIn)
				{
					CurrentSettingsState = SettingsState.BLE;
				}
				else if (currentConsoleService.IsBuiltinClub)
				{
					if (ifitApi.HasLoggedInUser)
					{
						CurrentSettingsState = SettingsState.BuiltInClubSignedIn;
					}
					else
					{
						CurrentSettingsState = SettingsState.BuiltInClubSignedOut;
					}
				}
				else if (ifitApi.HasLoggedInUser)
				{
					CurrentSettingsState = SettingsState.BuiltInSignedIn;
				}
				else
				{
					CurrentSettingsState = SettingsState.BuiltInSignedOut;
				}
				if (CurrentSettingsState.HasAnyFlag(SettingsState.BuiltInClubSignedOut))
				{
					InitializeSecretEquipmentApi();
					BuildSignedOutClubSettings();
				}
				else
				{
					BuildSettingsCollection();
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void BuildSignedOutClubSettings()
		{
			AccountList.Value = new List<SettingsCollectionCellModel>
			{
				CreateSettingsCollectionCellModel(Wolf.Core.Resources.AppStrings.settings_in_workout, "icn_exercise_line", new MvxCommand(base.DisplayViewModelIfNeeded<SettingsInWorkoutViewModel>), separatorLineVisiblity: true),
				CreateSettingsCollectionCellModel(Wolf.Core.Resources.AppStrings.settings_equipment_info, "icn_info_circle_line", new MvxCommand(base.DoOpenEquipmentInfo), separatorLineVisiblity: true),
				CreateSettingsCollectionCellModel(Wolf.Core.Resources.AppStrings.settings_legal, "icn_locked_line", new MvxCommand(base.DisplayViewModelIfNeeded<LegalListViewModel>))
			};
		}

		protected override void BuildSettingsCollection()
		{
			base.BuildSettingsCollection();
			AccountList.Value = BuildAccountList();
			EquipmentList.Value = BuildEquipmentList();
			AboutList.Value = BuildAboutList();
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
			isNavigating = false;
		}

		private List<SettingsCollectionCellModel> BuildAccountList()
		{
			List<SettingsCollectionCellModel> list = new List<SettingsCollectionCellModel>();
			bool flag = CurrentSettingsState.HasAnyFlag(SettingsState.BuiltInClubSignedIn);
			List<(string, string, ICommand)> list2 = new List<(string, string, ICommand)>();
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.UseLocalizedStrings))
			{
				list2.Add((Wolf.Core.Resources.AppStrings.settings_languages, "icn_language_settings_line", new MvxCommand(base.DoOpenLanguageSettings)));
			}
			if (CurrentSettingsState.HasAnyFlag(SettingsState.BLE | SettingsState.BuiltInSignedIn) && !ifitApi.CurrentlyAuthenticatedUser.IsSecondary)
			{
				list2.Add((Wolf.Core.Resources.AppStrings.settings_manage_accounts, "icn_user_add_line", new MvxCommand(base.DisplayViewModelIfNeeded<ManageAccountsViewModel>)));
			}
			list2.Add((Wolf.Core.Resources.AppStrings.settings_in_workout, "icn_exercise_line", new MvxCommand(base.DisplayViewModelIfNeeded<SettingsInWorkoutViewModel>)));
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.ConnectedAppsFeature) && CurrentSettingsState.HasFlag(SettingsState.BLE) && !hardwareInfo.IsTablet)
			{
				list2.Add((Wolf.Core.Resources.AppStrings.settings_connected_apps, "icn_connected_apps", new MvxCommand(base.DisplayViewModelIfNeeded<ConnectedAppsListViewModel>)));
			}
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.AICoachSettingsEnabled))
			{
				list2.Add((Wolf.Core.Resources.AppStrings.settings_ai_coach, "icn_ai_coach", new MvxCommand(base.DisplayViewModelIfNeeded<AICoachSettingsViewModel>)));
			}
			for (int i = 0; i < list2.Count; i++)
			{
				(string, string, ICommand) tuple = list2[i];
				list.Add(CreateSettingsCollectionCellModel(separatorLineVisiblity: flag || (list2.Count >= 3 && ((!list2.Count.IsEven()) ? (i < list2.Count - 1) : (i < list2.Count - 2))), title: tuple.Item1, iconSource: tuple.Item2, itemSelectedCommand: tuple.Item3));
			}
			return list;
		}

		protected override IList<SettingsCollectionCellModel> BuildEquipmentList()
		{
			if (CurrentSettingsState.HasAnyFlag(SettingsState.BuiltInClubSignedIn))
			{
				return new List<SettingsCollectionCellModel> { CreateSettingsCollectionCellModel(Wolf.Core.Resources.AppStrings.settings_equipment_info, "icn_info_circle_line", new MvxCommand(base.DoOpenEquipmentInfo), separatorLineVisiblity: true) };
			}
			List<(string, string, ICommand)> list = new List<(string, string, ICommand)>();
			List<SettingsCollectionCellModel> list2 = new List<SettingsCollectionCellModel>();
			list.Add((Wolf.Core.Resources.AppStrings.settings_equipment_info, "icn_info_circle_line", new MvxCommand(base.DoOpenEquipmentInfo)));
			list.Add((Wolf.Core.Resources.AppStrings.settings_maintenance, "icn_maintenance_line", new MvxCommand(base.DisplayViewModelIfNeeded<MaintenanceViewModel>)));
			if (CurrentSettingsState.HasAnyFlag(SettingsState.BuiltInSignedOut | SettingsState.BuiltInSignedIn))
			{
				list.Add((Wolf.Core.Resources.AppStrings.settings_equipment_settings, "icn_equipment_settings", new MvxCommand(base.DoOpenEquipmentSettings)));
				list.Add((Wolf.Core.Resources.AppStrings.settings_wi_fi, "icn_wifi_line", new MvxCommand(base.DoOpenWifi)));
			}
			if (IsLockPinVisible())
			{
				list.Add((lockPinService.IsLockPinNumberConfigured ? Wolf.Core.Resources.AppStrings.settings_lock_pin_settings : Wolf.Core.Resources.AppStrings.settings_lock_pin_set_up, "icn_locked_line", new MvxCommand(delegate
				{
					base.LockPinFeatureAction.Execute(lockPinService.IsLockPinNumberConfigured);
				})));
			}
			for (int num = 0; num < list.Count; num++)
			{
				(string, string, ICommand) tuple = list[num];
				list2.Add(CreateSettingsCollectionCellModel(separatorLineVisiblity: list.Count < 3 || ((!list.Count.IsEven()) ? (num < list.Count - 1) : (num < list.Count - 2)), title: tuple.Item1, iconSource: tuple.Item2, itemSelectedCommand: tuple.Item3));
			}
			return list2;
			bool IsLockPinVisible()
			{
				bool isLockPinEnabled = lockPinService.IsLockPinEnabled;
				bool isStrengthMirror = base.IsStrengthMirror;
				bool isBuiltinClub = currentConsoleService.IsBuiltinClub;
				if (deviceInfo.IsBuiltIn && !isBuiltinClub && isLockPinEnabled)
				{
					return !isStrengthMirror;
				}
				return false;
			}
		}

		private SettingsCollectionCellModel CreateSettingsCollectionCellModel(string title, string iconSource, ICommand itemSelectedCommand, bool separatorLineVisiblity = false)
		{
			return new SettingsCollectionCellModel(title, iconSource, itemSelectedCommand, separatorLineVisiblity, BetaFeatures.Contains(title));
		}

		private List<SettingsCollectionCellModel> BuildAboutList()
		{
			return new List<SettingsCollectionCellModel> { CreateSettingsCollectionCellModel(Wolf.Core.Resources.AppStrings.settings_legal, "icn_locked_line", new MvxCommand(base.DisplayViewModelIfNeeded<LegalListViewModel>)) };
		}

