namespace Wolf.Core.ViewModels.Settings.Wifi
{
	public class SettingsOtherWifiDialogViewModel : BaseViewModel
	{
		private CancellationTokenSource connectWifiCancellation;

		public readonly INC<bool> IsConnecting = new NC<bool>();

		public readonly INC<bool> PasswordIsHidden = new NC<bool>(value: true);

		public readonly INC<string> NetworkName = new NC<string>();

		public readonly INC<string> Ssid = new NC<string>();

		public readonly INC<string> Identity = new NC<string>();

		public readonly INC<string> Password = new NC<string>();

		public readonly INC<string> Security = new NC<string>();

		public bool IsHidden { get; private set; }

		public string InitialSecurity { get; private set; }

		public List<string> SecurityTypes { get; private set; }

		[DependsOn(new string[] { "Security" })]
		public bool NeedsPassword => !IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.None);

		[DependsOn(new string[] { "Security" })]
		public bool IsWpaEnt => IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.WpaEnt);

		[DependsOn(new string[] { "Ssid", "Security", "Password", "Identity", "IsConnecting" })]
		public bool ReadyToJoin
		{
			get
			{
				if (IsConnecting.Value)
				{
					return false;
				}
				if (string.IsNullOrEmpty(Ssid.Value))
				{
					return false;
				}
				if (IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.None))
				{
					return true;
				}
				if (IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.WpaEnt) && !string.IsNullOrEmpty(Password.Value) && !string.IsNullOrEmpty(Identity.Value))
				{
					return true;
				}
				if (IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.WpaEnt) && (string.IsNullOrEmpty(Password.Value) || string.IsNullOrEmpty(Identity.Value)))
				{
					return false;
				}
				if (string.IsNullOrEmpty(Password.Value))
				{
					return false;
				}
				return true;
			}
		}

		public IMvxAsyncCommand JoinClick => new MvxAsyncCommand(DoJoinClickAsync);

		public ICommand TogglePasswordVisibility => new MvxCommand(DoTogglePasswordVisibility);

		public SettingsOtherWifiDialogViewModel(ILocalSettings localSettings)
			: base(localSettings)
		{
			try
			{
				SecurityTypes = new List<string>();
				(from x in Enum.GetNames(typeof(WifiNetworkInfo.SecurityType))
					where x != "Unsupported"
					select x).ForEach(delegate(string x)
				{
					SecurityTypes.Add(x.ToUpper());
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(WifiNetworkInfo network)
		{
			Ssid.Value = network.Ssid;
			NetworkName.Value = network.DisplayName;
			IsHidden = network.IsHidden;
			InitialSecurity = SecurityTypes[(int)network.Security];
			Security.Value = InitialSecurity;
			Password.Value = network.Password;
			Identity.Value = network.EnterpiseIdentity;
		}

		private WifiNetworkInfo.SecurityType GetSecurityType(string security)
		{
			return (WifiNetworkInfo.SecurityType)Enum.Parse(typeof(WifiNetworkInfo.SecurityType), security, ignoreCase: true);
		}

		private string GetSecurityType(WifiNetworkInfo.SecurityType security)
		{
			return Enum.GetName(typeof(WifiNetworkInfo.SecurityType), (int)security);
		}

		private bool IsSecurityType(string actual, WifiNetworkInfo.SecurityType expected)
		{
			return actual.Equals(GetSecurityType(expected), StringComparison.OrdinalIgnoreCase);
		}

		private async Task DoJoinClickAsync()
		{
			IsConnecting.Value = true;
			connectWifiCancellation?.Cancel();
			connectWifiCancellation = new CancellationTokenSource();
			CancellationToken cancellationToken = connectWifiCancellation.Token;
			WifiNetworkInfo wifiNetworkInfo = new WifiNetworkInfo();
			wifiNetworkInfo.Ssid = Ssid.Value;
			wifiNetworkInfo.IsHidden = IsHidden;
			wifiNetworkInfo.Security = GetSecurityType(Security.Value);
			if (!IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.None))
			{
				wifiNetworkInfo.Password = Password.Value;
			}
			if (IsSecurityType(Security.Value, WifiNetworkInfo.SecurityType.WpaEnt))
			{
				wifiNetworkInfo.EnterpiseIdentity = Identity.Value;
			}
			WifiConnectionResults wifiConnectionResults = await wifiService.ConnectToNetwork(wifiNetworkInfo);
			IsConnecting.Value = false;
			if (!cancellationToken.IsCancellationRequested)
			{
				string title = Wolf.Core.Resources.AppStrings.error;
				string message = Wolf.Core.Resources.AppStrings.wifi_connect_error;
				string subtitle;
				switch (wifiConnectionResults)
				{
				case WifiConnectionResults.Success:
					DoClose();
					return;
				case WifiConnectionResults.AuthenticationError:
					title = Wolf.Core.Resources.AppStrings.wifi_authentication_failed_title;
					message = string.Format(Wolf.Core.Resources.AppStrings.wifi_authentication_failed_body, NetworkName.Value);
					subtitle = ErrorCode.WifiAuthenticationFailure.ToString();
					break;
				case WifiConnectionResults.TimeoutError:
					subtitle = ErrorCode.WifiTimedOutWhileConnecting.ToString();
					break;
				case WifiConnectionResults.NetworkNotFoundError:
					subtitle = ErrorCode.WifiNetworkNotFound.ToString();
					break;
				default:
					subtitle = ErrorCode.WifiUnknownError.ToString();
					break;
				}
				ShowSimpleConfirmationDialog(title, message, (Func<CancellationToken, Task<object>>)null, "", Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), (Action)DoClose, (Action)null, true, true, "", (TaskCompletionSource<object>)null, subtitle, true, true);
			}
		}

		protected override void DoClose()
		{
			connectWifiCancellation?.Cancel();
			base.DoClose();
		}

