	public class SettingsWifiViewModel : BaseViewModel
	{
		private readonly AsyncRetryPolicy scanAndRetryNetworksPolicy;

		private const int MaxWifiScanRetries = 5;

		private readonly ICrashReporter crashReporter;

		private IDisposable networkChangedSub;

		private IDisposable wifiStateChangeSub;

		private IDisposable wifiEnabledChangeSub;

		public readonly INC<bool> IsWifiOn = new NC<bool>();

		public readonly INC<string> ErrorMsg = new NC<string>();

		public readonly INC<WifiNetworkInfo> CurrentNetwork = new NC<WifiNetworkInfo>();

		public readonly INCList<WifiNetworkInfo> WifiNetworks = new NCList<WifiNetworkInfo>();

		public readonly INC<bool> IsScanning = new NC<bool>();

		public ICommand ToggleSwitch => new MvxCommand(DoToggleSwitch);

		public ICommand OtherNetworkClicked => new MvxCommand(DoOtherNetworkClicked);

		public ICommand ForgetCurrentNetwork => new MvxCommand(DoForgetCurrentNetwork);

		public ICommand SelectWifiNetwork => new MvxAsyncCommand<WifiNetworkInfo>(DoOpenNetworkDialog);

		[DependsOn(new string[] { "IsScanning" })]
		public bool IsLoadingIndicatorVisible => IsScanning.Value;

		public SettingsWifiViewModel(ILocalSettings localSettings, ICrashReporter crashReporter)
			: base(localSettings)
		{
			try
			{
				this.crashReporter = crashReporter;
				scanAndRetryNetworksPolicy = Policy.Handle<TimeoutException>().WaitAndRetryAsync(5, (int attempt) => TimeSpan.FromSeconds(Math.Pow(2.0, attempt)));
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			IsScanning.Value = true;
			await UpdateWifiNetworks();
			await VerifyCurrentActiveNetwork();
			IsWifiOn.Value = wifiService.IsWifiEnabled;
			IsScanning.Value = false;
			wifiStateChangeSub = wifiService.WhenNetworkStateChanged.SubscribeAsync(WifiStateChanged);
			networkChangedSub = wifiService.WhenNetworkChanged.SubscribeAsync(ConnectedNetworkChanged);
			wifiEnabledChangeSub = wifiService.WhenEnabledChanged.SubscribeAsync(WifiEnabledChanged);
		}

		public override Task OnViewShown()
		{
			IsWifiOn.Value = wifiService.IsWifiEnabled;
			return base.OnViewShown();
		}

		private async Task WifiEnabledChanged(WifiEnabledState enabledState)
		{
			IsWifiOn.Value = enabledState == WifiEnabledState.Enabled || enabledState == WifiEnabledState.Enabling;
			await UpdateWifiNetworks();
		}

		private async Task WifiStateChanged(WifiNetworkState state)
		{
			await VerifyCurrentActiveNetwork();
			if (!wifiService.IsWifiEnabled)
			{
				WifiNetworks.Value = null;
			}
			else
			{
				await UpdateWifiNetworks();
			}
		}

		private void DoToggleSwitch()
		{
			if (IsWifiOn.Value)
			{
				wifiService.TurnWifiOff();
				IsWifiOn.Value = false;
			}
			else
			{
				wifiService.TurnWifiOn();
				IsWifiOn.Value = true;
			}
		}

		private async Task ConnectedNetworkChanged(WifiNetworkInfo network)
		{
			await VerifyCurrentActiveNetwork();
			await UpdateWifiNetworks();
		}

		private async Task VerifyCurrentActiveNetwork()
		{
			bool flag = await wifiService.PingSucceeds();
			CurrentNetwork.Value = (flag ? wifiService.ActiveNetworkInfo : null);
			string text = (flag ? "connected" : "not connected");
			Log.Trace("Wifi", "Current active network status is " + text + ". " + $"Setting CurrentNetwork.Value to {CurrentNetwork.Value}");
		}

		private async Task UpdateWifiNetworks()
		{
			if (!wifiService.IsWifiEnabled)
			{
				return;
			}
			List<WifiNetworkInfo> networks = new List<WifiNetworkInfo>();
			try
			{
				await scanAndRetryNetworksPolicy.ExecuteAsync(async () => networks = await wifiService.GetNetworks());
			}
			catch (TimeoutException)
			{
				Log.Error("Wifi", "WifiService timed out scanning for networks");
				return;
			}
			networks?.Sort((WifiNetworkInfo a, WifiNetworkInfo b) => b.ConnectionStrength.CompareTo(a.ConnectionStrength));
			WifiNetworks.Value = networks;
		}

		private async Task DoOpenNetworkDialog(WifiNetworkInfo network)
		{
			Log.Trace("Wifi", "Attempting to connect to wifi network: " + network?.Ssid);
			try
			{
				switch (network?.Security)
				{
				case null:
					throw new ArgumentNullException(Wolf.Core.Resources.AppStrings.wifi_connect_error);
				case WifiNetworkInfo.SecurityType.Unsupported:
					throw new NotSupportedException(Wolf.Core.Resources.AppStrings.wifi_connect_error_security_type);
				case WifiNetworkInfo.SecurityType.None:
				{
					WifiConnectionResults wifiConnectionResults = await wifiService.ConnectToNetwork(network);
					if (wifiConnectionResults == WifiConnectionResults.AuthenticationError)
					{
						throw new WifiException(Wolf.Core.Resources.AppStrings.authentication_invalid_user_pass);
					}
					if (WifiConnectionResults.TimeoutError == wifiConnectionResults && Mvx.TryResolve<IWolfAnalytics>(out var service))
					{
						service.HandledWifiTimeoutError(new WifiException(Wolf.Core.Resources.AppStrings.wifi_connect_error));
						throw new WifiException(Wolf.Core.Resources.AppStrings.wifi_connect_error);
					}
					if (WifiConnectionResults.Success != wifiConnectionResults)
					{
						throw new NotSupportedException(Wolf.Core.Resources.AppStrings.wifi_connect_error);
					}
					break;
				}
				default:
					ShowViewModel<SettingsOtherWifiDialogViewModel>(network);
					break;
				}
			}
			catch (Exception ex)
			{
				Log.Error("Wifi", ex.GetType().Name + " occurred connecting to network " + network?.Ssid + ": " + ex.Message);
				ErrorMsg.Value = ex.Message;
				if (!(ex is WifiException))
				{
					await crashReporter.ReportError(ex.Message, ex, new Dictionary<string, object> { { "WifiNetworkInfo", network } });
				}
			}
		}

		private void DoOtherNetworkClicked()
		{
			ShowViewModel<SettingsOtherWifiDialogViewModel>(new WifiNetworkInfo());
		}

		private void DoForgetCurrentNetwork()
		{
			Action onConfirm = wifiService.DisableConfiguredNetworks;
			ShowSimpleConfirmationDialog(wifiService.ActiveNetworkInfo.DisplayName, Wolf.Core.Resources.AppStrings.forget_network_question, onConfirm, Wolf.Core.Resources.AppStrings.cancel, Wolf.Core.Resources.AppStrings.forget);
		}

		public override void Dispose()
		{
			networkChangedSub?.Dispose();
			wifiStateChangeSub?.Dispose();
			wifiEnabledChangeSub?.Dispose();
			base.Dispose();
			UnregisterChangeHandlers();
		}

