	public class FeatureFlagItemViewModel : MvxViewModel
	{
		private readonly IFeatureFlagManager featureFlagManager;

		private readonly FeatureFlag featureFlag;

		public string DisplayValue
		{
			get
			{
				switch (FeatureFlagType)
				{
				case FeatureFlagType.Bool:
					return featureFlagManager.IsFeatureEnabled(featureFlag).ToString();
				case FeatureFlagType.String:
				case FeatureFlagType.WebviewUrl:
					return featureFlagManager.GetString(featureFlag);
				case FeatureFlagType.Int:
					return featureFlagManager.GetInt(featureFlag).ToString();
				default:
					return "Something went wrong :(";
				}
			}
		}

		public string FeatureFlagName => featureFlag.Key;

		public FeatureFlagType FeatureFlagType => featureFlag.Type;

		public FeatureFlagItemViewModel(FeatureFlag flag, IFeatureFlagManager featureFlagManager)
		{
			featureFlag = flag;
			this.featureFlagManager = featureFlagManager;
		}

		public void ToggleBooleanValue()
		{
			featureFlagManager.SetBoolFlagTemporarily(featureFlag, !featureFlagManager.IsFeatureEnabled(featureFlag));
			RaisePropertyChanged(() => DisplayValue);
		}

		public void SetStringValue(string value)
		{
			featureFlagManager.SetStringFlagTemporarily(featureFlag, value);
			RaisePropertyChanged(() => DisplayValue);
		}

		public void SetIntValue(int value)
		{
			featureFlagManager.SetIntFlagTemporarily(featureFlag, value);
			RaisePropertyChanged(() => DisplayValue);
		}
	}
	public class FeatureFlagViewerViewModel : BaseViewModel
	{
