		public readonly INC<string> Message = new NC<string>();

		public readonly INC<bool> ShowLoadingContainer = new NC<bool>();

		private ObservableCollection<FeatureFlagItemViewModel> _allFlags;

		public ICommand RefreshFlags => new MvxCommand(DoRefreshFlags);

		public ObservableCollection<FeatureFlagItemViewModel> AllFlags
		{
			get
			{
				return _allFlags;
			}
			private set
			{
				_allFlags = value;
				RaisePropertyChanged(() => AllFlags);
			}
		}

		public FeatureFlagViewerViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager)
			: base(localSettings)
		{
			try
			{
				this.featureFlagManager = featureFlagManager;
				PopulateFlagsList();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void PopulateFlagsList()
		{
			IEnumerable<FeatureFlagItemViewModel> collection = FeatureFlags.AllFlags.Select((FeatureFlag x) => new FeatureFlagItemViewModel(x, featureFlagManager));
			AllFlags = new ObservableCollection<FeatureFlagItemViewModel>(collection);
		}

		private void DoRefreshFlags()
		{
			try
			{
				ShowLoadingContainer.Value = true;
				featureFlagManager.ClearTemporaryFlags();
			}
			catch (Exception)
			{
				Message.Value = "Failed to refresh feature flags";
				return;
			}
			finally
			{
				ShowLoadingContainer.Value = false;
			}
			PopulateFlagsList();
			Message.Value = "Feature flags refreshed";
		}

