		public SecretSettingsViewModel(ILocalSettings localSettings, IIfitApiService api, IFeatureFlagManager featureFlagManager, ILogFileService logFileService, IWolfAnalytics wolfAnalytics, ITelevisionTunerService televisionTunerService, IWebviewSettings webviewSettings, IDeveloperSettings developerSettings, ITelevisionSettings televisionSettings, ICurrentConsoleService currentConsoleService, IMediaSettings mediaSettings, IBleConsoleService bleConsoleService = null, IBlobCacheFileManager blobCacheFileManager = null)
			: base(localSettings)
		{
			try
			{
				SecretSettingsViewModel secretSettingsViewModel = this;
				this.api = api;
				this.featureFlagManager = featureFlagManager;
				this.logFileService = logFileService;
				this.wolfAnalytics = wolfAnalytics;
				this.televisionTunerService = televisionTunerService;
				this.webviewSettings = webviewSettings;
				this.developerSettings = developerSettings;
				this.televisionSettings = televisionSettings;
				this.mediaSettings = mediaSettings;
				this.bleConsoleService = bleConsoleService;
				this.blobCacheFileManager = blobCacheFileManager;
				ApiText.Value = localSettings.CustomApiUrl;
				IsWebviewVerboseMode.Value = webviewSettings.IsWebviewVerboseMode;
				IsWebviewCacheDisabled.Value = webviewSettings.IsWebviewCacheDisabled;
				SpoofedSoftwareNumberText.Value = deviceInfo.SpoofedSoftwareNumber?.ToString() ?? string.Empty;
				ShowCustomApi.Value = localSettings.EnvironmentToUse == Environments.Custom;
				AllowSubmit.Value = false;
				SelectedEnvironment.Value = localSettings.EnvironmentToUse;
				SelectedEnvironment.Changed -= HandleApiSelection;
				SelectedEnvironment.Changed += HandleApiSelection;
				ImABuiltIn.Value = deviceInfo.IsBuiltIn;
				MockDevicesEnabled.Value = developerSettings.MockDevicesEnabled;
				SafetyStartEnabledForDev.Value = developerSettings.EnableSafetyStartForDev;
				IsOfflineVideoStorageEnabled.Value = developerSettings.IsOfflineVideoStorageEnabled;
				AppVersionOverlayEnabled.Value = developerSettings.AppVersionOverlayEnabled;
				TelevisionUrl.Value = televisionSettings.TelevisionUrl?.ToString() ?? string.Empty;
				MockHeartRateUiEnabled.Value = developerSettings.MockHRUIEnabled;
				ShowWorkoutLevelChangeEnabled.Value = developerSettings.ShowHRDebugInfo;
				DisableLogoutService.Value = clubLocalSettings.DisableLogoutService;
				ExoPlayerOverlayEnabled.Value = developerSettings.ShowMediaPlayerDebugOverlay;
				IsPlanetFitnessUser.Value = developerSettings.SpoofIsPlanetFitnessUser;
				FeedFmShouldOverrideUserStation.Value = this.mediaSettings.SecretSettingFeedFmOverrideUserStation;
				HRWarmupTimer.Value = HRTrainingService.EnableHRWarmUpTimer;
				VisibleAnalytics.Value = developerSettings.VisibleAnalytics;
				IsStrengthMirrorSwitch.Value = base.IsStrengthMirror;
				EnableStrengthMirrorColorSchemeSwitching.Value = themeService.EnableStrengthMirrorColorSchemeSwitching;
				IsHeadlessBike.Value = deviceInfo.UseHeadlessBikeTheme;
				HermesViewModelsList = hermesViewModels.Keys.ToList();
				selectedHermesViewModel = hermesViewModels.FirstOrDefault((KeyValuePair<string, Type> x) => x.Value == localSettings.HermesViewModelType).Key;
				ShowSensitiveSecretSettings.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.SensitiveSecretFlagsEnabled);
				InitializeSpoofedSubscriptionModel(SpoofSubscriptionData, SelectedSpoofSubscription, developerSettings.SpoofSubscriptionType);
				SelectedSpoofSubscription.Changed -= SpoofSubChanged;
				SelectedSpoofSubscription.Changed += SpoofSubChanged;
				CanLock.Value = currentConsoleService.Console?.FitnessValueSupported(FitnessValue.ActivationLock) ?? false;
				GettingLockState.Value = true;
				lockSub = (from x in facadeFactoryDependencies.ActivationLockFacade.ObserveActivationLockChanges()
					select x.Current).Subscribe(delegate(ActivationLockState x)
				{
					secretSettingsViewModel.IsLocked.Value = x == ActivationLockState.Locked;
					Observable.Timer(TimeSpan.FromSeconds(3.0)).Subscribe(delegate
					{
						secretSettingsViewModel.GettingLockState.Value = false;
					});
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

