		private void ToggleLock()
		{
			if (CanLock.Value && !GettingLockState.Value)
			{
				Log.Trace("SecretSettings", $"setting \"All Smart Lock\" changed to {!IsLocked.Value} from {IsLocked.Value} ");
				GettingLockState.Value = true;
				ActivationLockState activationLock = ((!IsLocked.Value) ? ActivationLockState.Locked : ActivationLockState.Unlocked);
				facadeFactoryDependencies.ActivationLockFacade.SetActivationLock(activationLock);
			}
		}

