		private void DoToggleStrengthMirror()
		{
			ShowSimpleConfirmationDialog("Toggle Strength Mirror?", "Toggling Strength Mirror mode will require the app to restart. Are you sure you want to do this?", EnableOrDisableStrengthMirrorMode);
		}

		private void EnableOrDisableStrengthMirrorMode()
		{
			if (Mvx.TryResolve<IStrengthMirrorFileService>(out var service))
			{
				if (deviceInfo.IsStrengthMirror)
				{
					service.DisableConfig();
					Log.Trace("SecretSettings", "Strength Mirror mode toggled, .activeConfig file disabled.");
					deviceInfo.IsStrengthMirror = false;
				}
				else
				{
					if (!deviceInfo.IsBuiltIn)
					{
						DoToggleBuiltIn();
					}
					service.EnableConfig(copyFromStorageIfRequired: true, createDefaultsIfFileDoesNotExist: true);
					Log.Trace("SecretSettings", "Strength Mirror mode toggled, .activeConfig file created or enabled.");
				}
			}
			if (Mvx.TryResolve<IApplicationRestarter>(out var service2))
			{
				Log.Trace("SecretSettings", "Strength Mirror mode changed, restarting app.");
				service2.WaitingToRestart = true;
				HardResetNavigation();
			}
		}

