		private void DoToggleBuiltIn()
		{
			Log.Trace("SecretSettings", $"setting \"I'm A Built-In!!!\" changed to {!deviceInfo.IsBuiltIn} from {deviceInfo.IsBuiltIn} ");
			deviceInfo.IsBuiltIn = !deviceInfo.IsBuiltIn;
			wolfAnalytics.IsBuiltInDidChange();
			ImABuiltIn.Value = deviceInfo.IsBuiltIn;
			UpdateLogoutService();
		}

		private void DoToggleClubUnit()
		{
			IFitnessConsole console = currentConsoleService.Console;
			if (console != null && console is IForceClubUnit forceClubUnit)
			{
				forceClubUnit.ToggleClubStatus();
				IsClubUnitEnabled.Value = console.ConsoleInfo.IsClubUnit;
				if (console is MockFitnessConsoleBase mockFitnessConsoleBase)
				{
					mockFitnessConsoleBase.SetValue(FitnessValue.IsClubUnit, IsClubUnitEnabled.Value);
				}
				UpdateLogoutService();
			}
		}

		private void DoToggleLogoutService()
		{
			clubLocalSettings.DisableLogoutService = !clubLocalSettings.DisableLogoutService;
			DisableLogoutService.Value = clubLocalSettings.DisableLogoutService;
			UpdateLogoutService();
		}

		private void UpdateLogoutService()
		{
			if (Mvx.TryResolve<IIdleLogoutService>(out var service))
			{
				service.SetActive(currentConsoleService.IsBuiltinClub && !clubLocalSettings.DisableLogoutService);
			}
			else if (currentConsoleService.IsBuiltinClub && !clubLocalSettings.DisableLogoutService)
			{
				try
				{
					Mvx.ConstructAndRegisterSingleton<IIdleLogoutService, IdleLogoutService>();
				}
				catch (Exception exception)
				{
					Log.Error("Navigation", "Could not start Inactivity Logout Service", exception);
				}
			}
		}

