		private void DoToggleHeadlessBike()
		{
			ShowSimpleConfirmationDialog("Toggle Headless Bike?", "Toggling Headless Bike mode will restart the app. Are you sure you want to do this?", EnableOrDisableHeadlessBike);
		}

		protected void EnableOrDisableHeadlessBike()
		{
			Log.Trace("SecretSettings", $"setting \"Enable IsHeadlessBike\" changed to {!deviceInfo.UseHeadlessBikeTheme} from {deviceInfo.UseHeadlessBikeTheme} ");
			Log.Trace("SecretSettings", $"setting \"Enable IsHeadlessBike\" changed to {!deviceInfo.ForceHeadlessBikeVault} from {deviceInfo.ForceHeadlessBikeVault} ");
			if (!deviceInfo.UseHeadlessBikeTheme)
			{
				if (!deviceInfo.IsBuiltIn)
				{
					DoToggleBuiltIn();
				}
				deviceInfo.UseHeadlessBikeTheme = true;
				deviceInfo.ForceHeadlessBikeVault = true;
				currentConsoleService.IsAttachedConsoleActive = true;
				IsHeadlessBike.Value = deviceInfo.UseHeadlessBikeTheme;
				if (!deviceInfo.IsStrengthMirror)
				{
					EnableOrDisableStrengthMirrorMode();
					return;
				}
			}
			else
			{
				deviceInfo.ForceHeadlessBikeVault = false;
				deviceInfo.UseHeadlessBikeTheme = false;
				currentConsoleService.IsAttachedConsoleActive = false;
				deviceInfo.SpoofedSoftwareNumber = null;
				IsHeadlessBike.Value = deviceInfo.UseHeadlessBikeTheme;
			}
			if (Mvx.TryResolve<IApplicationRestarter>(out var service))
			{
				Log.Trace("SecretSettings", "Strength Mirror mode changed, restarting app.");
				service.ScheduleToRestartAndKillApp(TimeSpan.Zero);
			}
		}

		[DependsOn(new string[] { "ApiText" })]
		private void HandleApiTextValueChange()
		{
			AllowSubmit.Value = Uri.TryCreate(ApiText.Value, UriKind.Absolute, out var result) && (ApiText.Value.ToLower().StartsWith("http://", StringComparison.Ordinal) || ApiText.Value.ToLower().StartsWith("https://", StringComparison.Ordinal));
			Log.Trace("SecretSettings", $"setting \"Custom API Url\" changed to {result}");
		}

		[DependsOn(new string[] { "SpoofedSoftwareNumberText" })]
		private void HandleSpoofedSoftwareNumberTextValueChange()
		{
			string arg = (deviceInfo.SpoofedSoftwareNumber.HasValue ? deviceInfo.SpoofedSoftwareNumber.ToString() : "no value");
			if (int.TryParse(SpoofedSoftwareNumberText.Value, out var result))
			{
				deviceInfo.SpoofedSoftwareNumber = result;
			}
			else
			{
				deviceInfo.SpoofedSoftwareNumber = null;
			}
			Log.Trace("SecretSettings", $"setting \"Spoofed software number\" changed to {deviceInfo.SpoofedSoftwareNumber} from {arg}");
		}

