		{
			televisionSettings.TelevisionUrl = TelevisionUrl.Value;
			televisionTunerService.UpdateUrl();
		}

		private async Task EnvironmentUpdate()
		{
			if (SelectedEnvironment.Value == localSettings.EnvironmentToUse)
			{
				return;
			}
			if (SelectedEnvironment.Value == Environments.Custom)
			{
				if (localSettings.CustomApiUrl == ApiText.Value)
				{
					return;
				}
				localSettings.CustomApiUrl = ApiText.Value;
			}
			else
			{
				localSettings.CustomApiUrl = null;
			}
			await ResetEnvironment();
		}

		protected virtual async Task ResetEnvironment()
		{
			Log.Trace("SecretSettings", $"Setting \"Environment\" changed to {SelectedEnvironment.Value} from {localSettings.EnvironmentToUse} ");
			int buildNumber = deviceInfo.BuildNumber;
			deviceInfo.BuildNumber = 0;
			Log.Trace("DeviceAdmin", $"Settings swapping to environment {SelectedEnvironment.Value}");
			Log.Trace("DeviceAdmin", "Resetting environment users and cache");
			await api.ResetEnvironment();
			localSettings.EnvironmentToUse = SelectedEnvironment.Value;
			await CheckForiOSRestartCauseOfLaunchDarkly();
			CommonWolfAppSetup.UpdateEnvironment(Mvx.Resolve<IRaygunInfo>(), localSettings);
			deviceInfo.BuildNumber = buildNumber;
			HardResetNavigation();
		}

		private async Task<bool> CheckForiOSRestartCauseOfLaunchDarkly()
		{
			if (DeviceInfo.Platform == DevicePlatform.iOS)
			{
				TaskCompletionSource<object> tcs = new TaskCompletionSource<object>();
				ShowSimpleConfirmationDialog("RESTART THE APP", "Dear Developer or Tester,\n!!! YOU MUST RESTART THE APP IF YOU ARE READING THIS !!!\nChanging the environment on iOS changes the LaunchDarkly key and that now requires a restart.\nSorry, MGMT", async delegate
				{
					await CheckForiOSRestartCauseOfLaunchDarkly();
				}, null, "I FORGIVE YOU", async delegate
				{
					await CheckForiOSRestartCauseOfLaunchDarkly();
				}, async delegate
				{
					await CheckForiOSRestartCauseOfLaunchDarkly();
				}, dismissible: false, cancellable: false, "", tcs, null, isWarning: true);
				while (true)
				{
					await Task.Delay(1000);
				}
			}
			return false;
		}

		private void DoClearWebviewHolderFactory()
		{
			Log.Trace("SecretSettings", "Button \"CLEAR WEBVIEW STORE AND CACHE\" tapped");
			InvokeOnMainThread(delegate
			{
				webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
				webviewHolderFactory.WebviewHolderStore.FlushAll();
			});
			ShowSimpleConfirmationDialog("Cleared", "Webview cache and store has been cleared. Note that any webviews that are still on your backstack have not been cleared.");
		}

