		private void DoInvalidateAccessToken()
		{
			api.Token.CreatedAt = DateTime.Now - TimeSpan.FromMinutes(1.0);
			api.Token.ExpiresIn = 30;
			api.Token.AccessToken = "_invalid_" + api.Token.AccessToken;
		}

		private async Task DoResetWorkoutLiabilityDateButton()
		{
			User user = await User.GetMe(api);
			DateTime dateTime = DateTime.Now.AddYears(-2);
			user.WarningAccepted = dateTime;
			await user.UpdateAcceptance(api, dateTime);
		}

		private async Task DoExpireUserTokens()
		{
			IIfitApiService apiService = Mvx.Resolve<IIfitApiService>();
			AuthToken badToken = new AuthToken
			{
				TokenType = "Bearer",
				AccessToken = "invalid.jwtaccess.token",
				RefreshToken = "invalid_refresh_token",
				CreatedAt = DateTime.Now.AddHours(-24.0),
				ExpiresIn = 0
			};
			await apiService.SecureCache.InsertObject(apiService.CurrentlyAuthenticatedUserId + "-auth-token", badToken);
			apiService.Token = badToken;
			ShowSimpleConfirmationDialog("Expire Tokens", "User tokens are now expired. You may also want to clear the web view cache.");
		}

		public override void Dispose()
		{
			SelectedEnvironment.Changed -= HandleApiSelection;
			SelectedSpoofSubscription.Changed -= SpoofSubChanged;
			SpoofSubscriptionData?.Clear();
			lockSub?.Dispose();
			lockSub = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

		private void InitializeSpoofedSubscriptionModel(ObservableCollection<SubscriptionTypeSpinnerModel> model, INC<SubscriptionTypeSpinnerModel> current, User.SubscriptionTypes? currentSub)
		{
			model.Add(new SubscriptionTypeSpinnerModel(0, null));
			model.Add(new SubscriptionTypeSpinnerModel(1, User.SubscriptionTypes.CoachPlus));
			model.Add(new SubscriptionTypeSpinnerModel(2, User.SubscriptionTypes.Free));
			model.Add(new SubscriptionTypeSpinnerModel(3, User.SubscriptionTypes.Premium));
			model.Add(new SubscriptionTypeSpinnerModel(4, User.SubscriptionTypes.PremiumNonEquipment));
			foreach (SubscriptionTypeSpinnerModel item in model)
			{
				if (item.SubscriptionType == currentSub)
				{
					current.Value = item;
					return;
				}
			}
			current.Value = model[0];
		}

		private void SpoofSubChanged(object sender, EventArgs e)
		{
			Log.Trace("SecretSettings", $"setting \"Spoofed Subscription Type\" changed to {SelectedSpoofSubscription.Value.SubscriptionType} from {developerSettings.SpoofSubscriptionType} ");
			developerSettings.SpoofSubscriptionType = SelectedSpoofSubscription.Value.SubscriptionType;
		}

