			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
			UsernameTitle.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_username_dialog_maintext;
			PasswordTitle.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_password_dialog_maintext;
			PasswordContent.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_logininfo_password;
			EmailTitle.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_email_dialog_maintext;
			AutoLoginTitle.Value = Wolf.Core.Resources.AppStrings.settings_logininfo_autologin;
			await UpdateViewModelWithUser();
		}

		private async Task UpdateViewModelWithUser()
		{
			initData = true;
			try
			{
				User user = await User.GetMe(ifitApi);
				if (user != null)
				{
					UsernameContent.Value = user.Username;
					EmailContent.Value = user.Email;
				}
			}
			catch (Exception ex)
			{
				Log.Error("Settings", ex.Message);
			}
			finally
			{
				initData = false;
			}
		}

		[DependsOn(new string[] { "UsernameContent", "EmailContent" })]
		private async Task SaveUser()
		{
			if (initData)
			{
				return;
			}
			try
			{
				User user = await User.GetMe(ifitApi);
				if (user != null)
				{
					user.Username = UsernameContent.Value;
					user.Email = EmailContent.Value;
					await user.Update(ifitApi);
				}
			}
			catch (Exception ex)
			{
				Log.Error("Settings", ex.Message);
				FailedSettingsUpdate.Value = true;
			}
		}

		private void EditPasswordDialog()
		{
			dialogPresenter.ShowDialog<PasswordUpdateDialogViewModel>(null, showSafely: true);
			_whenPasswordDialogAppears.OnNext(null);
		}

		private void DoOpenUsernameDialog()
		{
			MainText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_username_dialog_maintext;
			SubText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_username_dialog_subtext;
			BelowText.Value = string.Empty;
			SecondBelowText.Value = string.Empty;
			AcceptButtonText.Value = Wolf.Core.Resources.AppStrings.settings_dialog_Save;
			DeclineButtonText.Value = Wolf.Core.Resources.AppStrings.settings_dialog_cancel;
			FirstInputText.Value = UsernameContent.Value;
			IsDialogVisible.Value = true;
			DialogErrorState.Value = false;
			IsSecureEntryField.Value = false;
			IsSecondInputVisible.Value = false;
			dialogType = DialogType.UsernameDialog;
		}

		private void DoOpenEditEmailDialog()
		{
			MainText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_email_dialog_maintext;
			SubText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_email_dialog_subtext;
			BelowText.Value = string.Empty;
			SecondBelowText.Value = string.Empty;
			AcceptButtonText.Value = Wolf.Core.Resources.AppStrings.settings_dialog_Save;
			DeclineButtonText.Value = Wolf.Core.Resources.AppStrings.settings_dialog_cancel;
			FirstInputText.Value = EmailContent.Value;
			DialogErrorState.Value = false;
			IsDialogVisible.Value = true;
			IsSecureEntryField.Value = false;
			IsSecondInputVisible.Value = false;
			dialogType = DialogType.EmailDialog;
		}

		private async Task DoAcceptButtonCommand()
		{
			switch (dialogType)
			{
			case DialogType.UsernameDialog:
				UsernameContent.Value = FirstInputText.Value;
				IsDialogVisible.Value = false;
				break;
			case DialogType.EmailDialog:
				CheckForValidEmail();
				break;
			default:
				throw new ArgumentOutOfRangeException();
			}
		}

		private void CheckForValidEmail()
		{
			if (FirstInputText.Value.IsValidEmail())
			{
				EmailContent.Value = FirstInputText.Value;
				IsDialogVisible.Value = false;
			}
			else
			{
				ShowError(Wolf.Core.Resources.AppStrings.invalid_email_address);
			}
		}

		private void ShowError(string errorMessage)
		{
			DialogErrorState.Value = true;
			IsDialogVisible.Value = true;
			SecondBelowText.Value = errorMessage;
		}

		private void DoDeclineButtonCommand()
		{
			IsDialogVisible.Value = false;
		}

