	public class MyMembershipViewModel : BaseViewModel
	{
		private readonly IIfitApiService _ifitApi;

		private readonly IManageSubscriptionService _manageSubscriptionService;

		public readonly INC<string> ExpirationDateStr = new NC<string>();

		public readonly INC<string> MembershipTypeStr = new NC<string>();

		public readonly INC<string> MembershipInfo = new NC<string>();

		public readonly INC<string> ManageMembershipLink = new NC<string>();

		public readonly INC<bool> ShowExpirationDate = new NC<bool>();

		public readonly INC<bool> ShowUpgradeMembership = new NC<bool>();

		public readonly INC<bool> ShowManageMembership = new NC<bool>();

		public string UpgradeMembershipLink => _manageSubscriptionService.GetUpgradeMembershipLink();

		public ICommand OpenUpgrade => new MvxAsyncCommand(DoOpenUpgrade);

		public ICommand ManageMembershipCommand => new MvxAsyncCommand(DoManageMembership);

		public ICommand ManageIfitMembershipCommand => new MvxCommand(DoManageIfitMembership, CanDoManageIfitMembership);

		public ICommand UpgradeIfitMembershipCommand => new MvxCommand(DoUpgradeIfitMembership, CanDoUpgradeIfitMembership);

		public MyMembershipViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IManageSubscriptionService manageSubscriptionService)
			: base(localSettings)
		{
			try
			{
				_ifitApi = ifitApi;
				_manageSubscriptionService = manageSubscriptionService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init()
		{
			User currentlyAuthenticatedUser = _ifitApi.CurrentlyAuthenticatedUser;
			int num;
			if (currentlyAuthenticatedUser != null && currentlyAuthenticatedUser.SubscriptionType == User.SubscriptionTypes.Free)
			{
				User currentlyAuthenticatedUser2 = _ifitApi.CurrentlyAuthenticatedUser;
				num = ((currentlyAuthenticatedUser2 != null && !currentlyAuthenticatedUser2.IsSecondary) ? 1 : 0);
			}
			else
			{
				num = 0;
			}
			bool flag = (byte)num != 0;
			INC<bool> showExpirationDate = ShowExpirationDate;
			User currentlyAuthenticatedUser3 = _ifitApi.CurrentlyAuthenticatedUser;
			showExpirationDate.Value = currentlyAuthenticatedUser3 != null && currentlyAuthenticatedUser3.Premium == true;
			ShowUpgradeMembership.Value = flag && deviceInfo.IsBuiltIn;
			ShowManageMembership.Value = !ShowUpgradeMembership.Value;
			User currentlyAuthenticatedUser4 = _ifitApi.CurrentlyAuthenticatedUser;
			if (currentlyAuthenticatedUser4 != null && currentlyAuthenticatedUser4.Expiration.HasValue)
			{
				ExpirationDateStr.Value = _ifitApi.CurrentlyAuthenticatedUser?.Expiration.GetValueOrDefault().ToString("MMMM dd, yyyy");
			}
			else
			{
				ExpirationDateStr.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_secondary_expiration;
			}
			MembershipTypeStr.Value = SettingsExtensions.SubscriptionTypeToStringMap(_ifitApi);
			ManageMembershipLink.Value = _manageSubscriptionService.GetManageMembershipLink();
			MembershipInfo.Value = string.Format(IsAndroidBuiltIn() ? Wolf.Core.Resources.AppStrings.settings_membership_manage_info_large : Wolf.Core.Resources.AppStrings.settings_membership_manage_info_format, ManageMembershipLink.Value);
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
		}

		private async Task DoOpenUpgrade()
		{
			TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ifit_subscription, Wolf.Core.Resources.AppStrings.membership_activation_message, Wolf.Core.Resources.AppStrings.ok.ToUpper(), dismissible: true, cancellable: true, "", taskCompletionSource);
			await taskCompletionSource.Task;
			DoClose();
		}

		private Task DoManageMembership()
		{
			return _manageSubscriptionService.ManageMembershipSubscription();
		}

		private void DoUpgradeIfitMembership()
		{
			_manageSubscriptionService.UpgradeIfitMembership();
		}

		private bool CanDoUpgradeIfitMembership()
		{
			return !deviceInfo.IsBuiltIn;
		}

		private void DoManageIfitMembership()
		{
			_manageSubscriptionService.ManageIfitMembershipSubscription();
		}

		private bool CanDoManageIfitMembership()
		{
			return !deviceInfo.IsBuiltIn;
		}

