		public MyProfileViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, ISettingsRouter settingsRouter, IFailedUploadMonitor failedUploadMonitor)
			: base(localSettings, failedUploadMonitor)
		{
			try
			{
				this.settingsRouter = settingsRouter;
				this.ifitApi = ifitApi;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void SetupUi(User user)
		{
			MembershipPhoneText.Value = SettingsExtensions.SubscriptionTypeToStringMap(ifitApi);
			FirstName.Value = user.Firstname;
			LastName.Value = user.Lastname;
			FullName.Value = user.FullName;
			Username.Value = user.Username;
			Email.Value = user.Email;
			Birthdate.Value = user.Birthday;
			Bio.Value = user.Bio;
			SetWeight(user.Weight);
			SetHeight(user.Height);
			SetGender(user.Gender);
			IsPremiumUser.Value = user.Premium == true;
			if (user.Expiration.HasValue)
			{
				expiration = user.Expiration.GetValueOrDefault();
				Expiration.Value = expiration;
				ExpirationDateStr.Value = expiration.ToString("MMMM dd, yyyy");
			}
			else
			{
				ExpirationDateStr.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_secondary_expiration;
			}
		}

		public void Init()
		{
			IMvxMessenger mvxMessenger = Mvx.Resolve<IMvxMessenger>();
			_subscriptionToken = mvxMessenger.Subscribe<FullNameMessage>(UpdateFullName);
			User currentlyAuthenticatedUser = ifitApi.CurrentlyAuthenticatedUser;
			int num;
			if (currentlyAuthenticatedUser != null && currentlyAuthenticatedUser.SubscriptionType == User.SubscriptionTypes.Free)
			{
				User currentlyAuthenticatedUser2 = ifitApi.CurrentlyAuthenticatedUser;
				num = ((currentlyAuthenticatedUser2 != null && !currentlyAuthenticatedUser2.IsSecondary) ? 1 : 0);
			}
			else
			{
				num = 0;
			}
			bool flag = (byte)num != 0;
			MembershipButtonStr.Value = ((flag && deviceInfo.IsBuiltIn) ? Wolf.Core.Resources.AppStrings.settings_myprofile_upgrade_membership_title.ToUpper() : Wolf.Core.Resources.AppStrings.settings_membership_button_text.ToUpper());
			Task.Run((Func<Task>)Initialize);
		}

		public async Task Initialize()
		{
			_ = 1;
			try
			{
				IsLoaded.Value = false;
				isMetric = await settingsRouter.GetIsMetric();
				SetupGenderData();
				PopulateHeightOptions();
				PopulateWeightOptions();
				User value = await ifitApi.RefreshCurrentlyAuthenticatedUser();
				CurrentUser.Value = value;
				SetupUi(CurrentUser.Value);
			}
			catch (Exception ex)
			{
				Log.Error(LogTag, ex.Message);
			}
			finally
			{
				IsLoaded.Value = true;
			}
		}

		private void SetupGenderData()
		{
			GenderData.AddRange(new GenderSpinnerModel[2]
			{
				new GenderSpinnerModel(0, Wolf.Core.Resources.AppStrings.settings_myprofile_gender_picker_male, "male"),
				new GenderSpinnerModel(1, Wolf.Core.Resources.AppStrings.settings_myprofile_gender_picker_female, "female")
			});
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.GenderInclusiveEnabled))
			{
				GenderData.AddRange(new GenderSpinnerModel[2]
				{
					new GenderSpinnerModel(2, Wolf.Core.Resources.AppStrings.settings_myprofile_gender_picker_nonbinary, "nonbinary"),
					new GenderSpinnerModel(3, Wolf.Core.Resources.AppStrings.settings_myprofile_gender_picker_prefer_not_to_say, "unspecified")
				});
			}
			SelectedGender.Value = GenderData[0];
		}

		private void SetGender(string gender)
		{
			switch (gender)
			{
			case "male":
				SelectedGender.Value = GenderData[0];
				break;
			case "female":
				SelectedGender.Value = GenderData[1];
				break;
			case "nonbinary":
				SelectedGender.Value = GenderData[2];
				break;
			case "unspecified":
				SelectedGender.Value = GenderData[3];
				break;
			}
		}

		public bool IsValidBirthdate(DateTime newDate)
		{
			if (newDate >= MinDate)
			{
				return newDate <= MaxDate;
			}
			return false;
		}

		private void PopulateHeightOptions()
		{
			int startHeight = MinimumHeight;
			int maximumHeight = MaximumHeight;
			HeightSpinnerModel.HeightUnits units = ((!isMetric) ? HeightSpinnerModel.HeightUnits.Inches : HeightSpinnerModel.HeightUnits.Centimeters);
			HeightData.AddRange(from x in Enumerable.Range(startHeight, maximumHeight - startHeight + 1)
				select new HeightSpinnerModel(x - startHeight, x, units));
			SelectedHeight.Value = HeightData[0];
		}

		private void SetHeight(double? meters)
		{
			if (meters.HasValue)
			{
				double num = ((!isMetric) ? Math.Round(UnitUtil.EnsureInches(DistanceUnit.M, meters.Value)) : (meters.Value * 100.0));
				double val = num - (double)MinimumHeight;
				int num2 = MaximumHeight - MinimumHeight;
				int index = (int)val.Clamp(0.0, num2);
				SelectedHeight.Value = HeightData[index];
			}
		}

		private void PopulateWeightOptions()
		{
			int startWeight = MinimumWeight;
			int maximumWeight = MaximumWeight;
			WeightSpinnerModel.WeightUnits units = ((!isMetric) ? WeightSpinnerModel.WeightUnits.Pounds : WeightSpinnerModel.WeightUnits.Kilograms);
			WeightData.AddRange(from x in Enumerable.Range(startWeight, maximumWeight - startWeight + 1)
				select new WeightSpinnerModel(x - startWeight, x, units));
			SelectedWeight.Value = WeightData[0];
		}

		private void SetWeight(double? kgs)
		{
			if (kgs.HasValue)
			{
				double num = kgs.Value;
				if (!isMetric)
				{
					num = Math.Round(UnitUtil.EnsureLbs(WeightUnit.Kg, num));
				}
				double val = num - (double)MinimumWeight;
				int num2 = MaximumWeight - MinimumWeight;
				int index = (int)val.Clamp(0.0, num2);
				SelectedWeight.Value = WeightData[index];
			}
		}

		[DependsOn(new string[] { "Email", "Birthdate", "Bio", "IsPremiumUser", "SelectedWeight", "SelectedHeight", "SelectedGender", "FirstName", "LastName" })]
		private void UserInfoChangedTrigger()
		{
			if (!IsLoading)
			{
				dataChanged = true;
			}
		}

		public override Task OnViewShown()
		{
			RegisterForStartButton();
			return base.OnViewShown();
		}

		protected override void OnViewHidden()
		{
			Task.Run((Func<Task>)SaveUser);
			base.OnViewHidden();
		}

		private async Task SaveUser()
		{
			if (IsLoading || !dataChanged)
			{
				return;
			}
			try
			{
				dataChanged = false;
				CurrentUser.Value.Firstname = FirstName.Value;
				CurrentUser.Value.Lastname = LastName.Value;
				CurrentUser.Value.Email = Email.Value;
				CurrentUser.Value.Gender = SelectedGender.Value.Gender;
				CurrentUser.Value.Birthday = Birthdate.Value;
				CurrentUser.Value.Weight = (isMetric ? ((double)SelectedWeight.Value.Weight) : UnitUtil.EnsureKgs(WeightUnit.Lb, SelectedWeight.Value.Weight));
				CurrentUser.Value.Height = (isMetric ? ((double)SelectedHeight.Value.Height / 100.0) : UnitUtil.EnsureMeters(DistanceUnit.In, SelectedHeight.Value.Height));
				CurrentUser.Value.Bio = Bio.Value;
				await CurrentUser.Value.Update(ifitApi);
				await ifitApi.InvalidateUserMemoryCache();
			}
			catch (Exception ex)
			{
				Log.Error(LogTag, ex.Message);
				FailedSettingsUpdate.Value = true;
			}
		}

		private void ShowGoToWebsite()
		{
			MsgToUser.Value = Wolf.Core.Resources.AppStrings.update_on_ifit_dot_com;
		}

		private void DoAcceptButtonCommand()
		{
			InputText1.Value = InputText1.Value?.Trim();
			InputText2.Value = InputText2.Value?.Trim();
			switch (dialogType)
			{
			case DialogType.DisplayNameDialog:
				if (HumanNameConverter.IsValidFirstLast(InputText1.Value.Trim(), InputText2.Value.Trim()))
				{
					FirstName.Value = InputText1.Value.Trim();
					LastName.Value = InputText2.Value.Trim();
					if (Mvx.TryResolve<ICulture>(out var service))
					{
						string text = service?.GetFormattedName(FirstName.Value, LastName.Value);
						FullName.Value = (string.IsNullOrEmpty(text) ? (FirstName.Value + " " + LastName.Value) : text);
					}
					else
					{
						FullName.Value = FirstName.Value + " " + LastName.Value;
					}
					Task.Run(async delegate
					{
						await SaveUser();
						User value = await ifitApi.RefreshCurrentlyAuthenticatedUser();
						CurrentUser.Value = value;
						SetupUi(CurrentUser.Value);
					});
					ResetDialog();
				}
				else
				{
					FullName.Value = FirstName.Value + " " + LastName.Value;
					ErrorText.Value = Wolf.Core.Resources.AppStrings.invalid_full_name;
					ShowError.Value = true;
					IsDialogVisible.Value = true;
				}
				break;
			case DialogType.EmailDialog:
				if (InputText1.Value.IsValidEmail())
				{
					Email.Value = InputText1.Value;
					ResetDialog();
				}
				else
				{
					ErrorText.Value = Wolf.Core.Resources.AppStrings.invalid_email_address;
					ShowError.Value = true;
					IsDialogVisible.Value = true;
				}
				break;
			case DialogType.BioDialog:
				Bio.Value = InputText1.Value;
				ResetDialog();
				break;
			default:
				throw new ArgumentOutOfRangeException();
			}
		}

		private void DoOpenDatePickerDialog()
		{
			DatePickerDialogViewModel.NavObj navObj = new DatePickerDialogViewModel.NavObj
			{
				Year = DateTime.Today.Year,
				Month = DateTime.Today.Month,
				Day = DateTime.Today.Day,
				MaxDate = MaxDate,
				MinDate = MinDate
			};
			if (Birthdate.Value.HasValue)
			{
				navObj.Year = Birthdate.Value.Value.Year;
				navObj.Month = Birthdate.Value.Value.Month;
				navObj.Day = Birthdate.Value.Value.Day;
			}
			ShowViewModel<MyProfileViewModel>(navObj, ShireViewParams.DialogView<DatePickerDialogViewModel>());
		}

		private void OpenEditNameDialog()
		{
			FullNameDialogViewModel.NavObj parameterValuesObject = new FullNameDialogViewModel.NavObj
			{
				First = FirstName.Value,
				Last = LastName.Value
			};
			ShowViewModel<MyProfileViewModel>(parameterValuesObject, ShireViewParams.DialogView<FullNameDialogViewModel>());
		}

		private void UpdateFullName(FullNameMessage message)
		{
			Task.Run(async delegate
			{
				FirstName.Value = message.FirstName;
				LastName.Value = message.SecondName;
				FullName.Value = FirstName.Value + " " + LastName.Value;
				await SaveUser();
				User value = await ifitApi.RefreshCurrentlyAuthenticatedUser();
				CurrentUser.Value = value;
				SetupUi(CurrentUser.Value);
			});
		}

		private void DoOpenDialog(DialogType dialog)
		{
			ResetDialog();
			dialogType = dialog;
			SetupDialog();
		}

		private void SetupDialog()
		{
			switch (dialogType)
			{
			case DialogType.DisplayNameDialog:
				MainText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_displayname_dialog_maintext;
				SubText.Value = Wolf.Core.Resources.AppStrings.first_name_hint;
				InputText1.Value = FirstName.Value;
				InputText2.Value = LastName.Value;
				IsNameVisible.Value = true;
				break;
			case DialogType.EmailDialog:
				MainText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_email_dialog_maintext;
				SubText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_email_dialog_subtext;
				InputText1.Value = Email.Value;
				break;
			case DialogType.BioDialog:
				MainText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_bio_dialog_maintext;
				SubText.Value = string.Empty;
				InputText1.Value = Bio.Value;
				IsBioVisible.Value = true;
				break;
			}
			IsDialogVisible.Value = true;
		}

		private void ResetDialog()
		{
			IsDialogVisible.Value = false;
			IsNameVisible.Value = false;
			IsBioVisible.Value = false;
			InputText1.Value = null;
			InputText2.Value = null;
			MainText.Value = null;
			SubText.Value = null;
		}

