	public class PrivacyAndSharingViewModel : BaseInternetConnectionViewModel
	{
		private readonly IIfitApiService ifitApi;

		private User user;

		public readonly INC<bool> AutoShareWorkouts = new NC<bool>();

		public readonly INC<bool> PrivateAccount = new NC<bool>();

		public readonly INC<bool> FailedSettingsUpdate = new NC<bool>();

		public readonly INC<bool> IsInitiating = new NC<bool>();

		public override string LogTag => GetType().Name;

		public ICommand OpenSocialPostingScreen => new MvxCommand(DoOpenSocialPostingScreen);

		public ICommand AutoShareWorkoutsClicked => new MvxCommand(DoAutoShareWorkoutsClicked);

		public ICommand PrivateAccountClicked => new MvxCommand(DoPrivateAccountClicked);

		public PrivacyAndSharingViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IFailedUploadMonitor failedUploadMonitor)
			: base(localSettings, failedUploadMonitor)
		{
			try
			{
				this.ifitApi = ifitApi;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			IsInitiating.Value = true;
			await Task.Run((Func<Task>)Initialize);
			IsInitiating.Value = false;
		}

		public Task Initialize()
		{
			RegisterForStartButton();
			return SetUi();
		}

		private async Task SetUi()
		{
			try
			{
				user = ifitApi.CurrentlyAuthenticatedUser;
				UserSettings userSettings = await user.GetSettings(ifitApi);
				AutoShareWorkouts.Value = userSettings.ShareAutomatically == true;
				PrivateAccount.Value = userSettings.PrivateProfile == true;
			}
			catch (Exception ex)
			{
				Log.Error("Settings", "SetUi failed: " + ex.Message);
			}
		}

		protected async Task SaveUser(int timeoutMls = 2000)
		{
			_ = 1;
			try
			{
				user.Settings.ShareAutomatically = AutoShareWorkouts.Value;
				user.Settings.PrivateProfile = PrivateAccount.Value;
				Log.Trace("Settings", "SaveUser started...");
				Task<UserSettings> updateSettingsTask = user.UpdateSettings(ifitApi);
				if (await Task.WhenAny(Task.Delay(timeoutMls), updateSettingsTask) == updateSettingsTask)
				{
					await updateSettingsTask;
					Log.Trace("Settings", "SaveUser ended...");
				}
				else
				{
					Log.Trace("Settings", "SaveUser timeout...");
					FailedSettingsUpdate.Value = true;
				}
			}
			catch (Exception ex)
			{
				Log.Error("Settings", "SaveUser failed: " + ex.Message);
				FailedSettingsUpdate.Value = true;
			}
		}

		private void DoOpenSocialPostingScreen()
		{
			ShowViewModel<SocialPostingViewModel>();
		}

		private void DoAutoShareWorkoutsClicked()
		{
			AutoShareWorkouts.Value = !AutoShareWorkouts.Value;
			Log.Trace("Settings", $"AutoShareWorkouts value set to {AutoShareWorkouts.Value}");
		}

		private void DoPrivateAccountClicked()
		{
			PrivateAccount.Value = !PrivateAccount.Value;
			Log.Trace("Settings", $"PrivateAccount value set to {PrivateAccount.Value}");
		}

		[DependsOn(new string[] { "AutoShareWorkouts", "PrivateAccount" })]
		private async Task UserDataChanged()
		{
			if (!IsInitiating.Value)
			{
				await Task.Run(() => SaveUser());
			}
			else
			{
				Log.Trace("Settings", "Initiation in progress, ignoring save..");
			}
		}

