	public class AddAccountPhoneViewModel : AddAccountViewModel
	{
		private IDisposable secondaryServiceSubscription;

		public new readonly INC<bool> IsLoading;

		public readonly INC<string> ToastMessage;

		public AddAccountPhoneViewModel(ILocalSettings localSettings, ISecondaryUsersService secondaryUsersService, IWolfAnalytics wolfAnalytics)
		{
			try
			{
				IsLoading = new NC<bool>();
				ToastMessage = new NC<string>();
				base..ctor(localSettings, secondaryUsersService, wolfAnalytics);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			secondaryServiceSubscription = secondaryServiceSubscription ?? secondaryUserService.SecondaryOpStatus.Subscribe(HandleSecondaryServiceResult);
		}

		protected override async Task DoInviteUser()
		{
			IsLoading.Value = true;
			if (string.IsNullOrEmpty(InviteText.Value))
			{
				(secondaryUserService.SecondaryOpStatus as Subject<SecondaryOperationResult>)?.OnNext(SecondaryOperationResult.ErrorInviteInvalidEmailAddress);
				Close(this);
			}
			else
			{
				await wolfAnalytics.UserInviteSentAsync(sourceScreen);
				await secondaryUserService.InviteAsSecondaryUser(InviteText.Value);
			}
		}

		private void HandleSecondaryServiceResult(SecondaryOperationResult result)
		{
			IsLoading.Value = false;
			switch (result)
			{
			case SecondaryOperationResult.InviteSent:
				ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_invite_success;
				break;
			case SecondaryOperationResult.ErrorSendingInvite:
				ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_invite_error;
				break;
			case SecondaryOperationResult.SecondaryRemoved:
				ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_remove_user_success;
				break;
			case SecondaryOperationResult.ErrorRemovingSecondary:
				ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_remove_user_failed;
				break;
			}
			DoClose();
		}

