	public class ManageAccountsViewModel : UserAccountViewModel
	{
		public enum BottomButtonType
		{
			None,
			AddAccount,
			NoMoreSecondary
		}

		public enum AddUsersAllowedState
		{
			Allowed,
			DeniedMaxReached,
			DeniedNotAllowedByPlan,
			DeniedUserNotPrimary
		}

		public class IsPrimaryToRightImageValueConverter : MvxValueConverter<bool, UserViewRightImageType>
		{
			protected override UserViewRightImageType Convert(bool value, Type targetType, object parameter, CultureInfo culture)
			{
				if (!value)
				{
					return UserViewRightImageType.None;
				}
				return UserViewRightImageType.Delete;
			}
		}

		private class UserAccountMenuItemModelComparer : IEqualityComparer<UserAccountMenuItemModel>
		{
			public bool Equals(UserAccountMenuItemModel x, UserAccountMenuItemModel y)
			{
				if (string.IsNullOrWhiteSpace(x?.ItemUser?.Id) || string.IsNullOrWhiteSpace(y?.ItemUser?.Id))
				{
					return false;
				}
				return x.ItemUser.Id.Equals(y.ItemUser.Id);
			}

			public int GetHashCode(UserAccountMenuItemModel obj)
			{
				return ("UserAccountMenuItemModel: User " + (obj?.ItemUser?.Id ?? null)).GetHashCode();
			}
		}

		private readonly ISecondaryUsersService secondaryUserService;

		public readonly INC<AddUsersAllowedState> AllowAddingState = new NC<AddUsersAllowedState>(AddUsersAllowedState.DeniedNotAllowedByPlan);

		public new readonly INC<bool> IsLoading = new NC<bool>();

		public readonly INC<BottomButtonType> BottomButton = new NC<BottomButtonType>(BottomButtonType.None);

		public readonly INC<int> NumPendingInvites = new NC<int>();

		public readonly INC<int> UserCount = new NC<int>(1);

		public readonly INC<int> InvitesLeft = new NC<int>();

		public ICommand ShowAddUserCmd => new MvxCommand(DoShowAddUser);

		public IMvxAsyncCommand CheckUserCount => new MvxAsyncCommand(Init);

		protected int NumSecondaryUsers { get; private set; }

		public ManageAccountsViewModel(ILocalSettings localSettings, IIfitApiService iFitApi, IDialogPresenter dialogPresenter, ISecondaryUsersService secondaryUserService, IFailedUploadMonitor failedUploadMonitor)
			: base(localSettings, iFitApi, dialogPresenter, failedUploadMonitor)
		{
			try
			{
				this.secondaryUserService = secondaryUserService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			try
			{
				IsLoading.Value = true;
				await PopulateUserList().ConfigureAwait(continueOnCapturedContext: false);
				CheckDisposedWhileLoading();
				SetAllowAdditionalUsersFlag();
				IsLoading.Value = false;
				InvitesLeft.Value = 5 - (NumSecondaryUsers + NumPendingInvites.Value);
			}
			catch (TaskCanceledException exception)
			{
				Log.Warn(GetType().Name, "Loading cancelled", exception);
			}
		}

		private void CheckDisposedWhileLoading()
		{
			if (isDisposed)
			{
				throw new TaskCanceledException("ViewModel disposed while still doing Init()");
			}
		}

		protected void DoShowAddUser()
		{
			if (!base.HasLoggedInUser)
			{
				ClearDialogs();
				ShowLoginViewModel(new PreLoginNavObject
				{
					AllowCancel = true
				}, ShireViewParams.ChildView<LoginIfitViewModel>());
			}
			else if (IsTablet)
			{
				ShowAddAccountDialogTablet();
			}
			else
			{
				ShowViewModel<AddAccountPhoneViewModel>();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			secondaryServiceSubscription = secondaryServiceSubscription ?? secondaryUserService.SecondaryOpStatus.SubscribeAsync(HandleSecondaryServiceResult);
		}

		protected Task<SecondaryUserListResult> GetSecondaryUserList()
		{
			return secondaryUserService.RetrieveUsers(LoggedInUser.Value);
		}

		private async Task PopulateUserList()
		{
			Task<SecondaryUserListResult> secondaryUserListTask = GetSecondaryUserList();
			Task<IList<User>> pendingInvitesTask = GetPendingInvites();
			await Task.WhenAll(secondaryUserListTask, pendingInvitesTask);
			CheckDisposedWhileLoading();
			SecondaryUserListResult result = secondaryUserListTask.Result;
			NumSecondaryUsers = result.UserList.Count;
			List<UserAccountMenuItemModel> list = result.UserList.Select((User user) => new UserAccountMenuItemModel(localSettings, api, user, UserViewRightImageType.Delete, (User selectedUser) => DoRemoveUser(selectedUser), showUsername: true)).ToList();
			IList<User> result2 = pendingInvitesTask.Result;
			if (result2 != null && result2.Count > 0)
			{
				List<UserAccountMenuItemModel> collection = result2.Select((User user) => new UserAccountMenuItemModel(localSettings, api, user, UserViewRightImageType.Delete, (User selectedUser) => DoRemoveUser(selectedUser, isInvitation: true), showUsername: true, isInvitation: true)).ToList();
				list.AddRange(collection);
			}
			UserAccountMenuItemModelComparer comparer = new UserAccountMenuItemModelComparer();
			if (!list.SequenceEqual(Users, comparer))
			{
				Users.ReplaceWith(list);
			}
			UserCount.Value = list.Count;
			foreach (UserAccountMenuItemModel item in list)
			{
				item?.Dispose();
			}
			list.Clear();
		}

		private Task DoRemoveUser(User user, bool isInvitation = false)
		{
			if (IsTablet)
			{
				ShowRemoveAccountDialogTablet(user, isInvitation);
			}
			else
			{
				ShowViewModel<RemoveAccountViewModel>(new RemoveAccountViewModel.NavObject
				{
					Id = user.Id,
					IsInvitation = isInvitation
				});
			}
			return Task.CompletedTask;
		}

		protected virtual void SetAllowAdditionalUsersFlag()
		{
			if (!LoggedInUser.Value.IsSecondary)
			{
				if (LoggedInUser.Value.SubscriptionType == User.SubscriptionTypes.CoachPlus)
				{
					if (NumSecondaryUsers + NumPendingInvites.Value < 5)
					{
						AllowAddingState.Value = AddUsersAllowedState.Allowed;
						BottomButton.Value = BottomButtonType.AddAccount;
						Log.Trace("Api", "SetAllowAdditionalUsersFlag: Secondary users can be added.");
					}
					else
					{
						AllowAddingState.Value = AddUsersAllowedState.DeniedMaxReached;
						BottomButton.Value = BottomButtonType.NoMoreSecondary;
						Log.Trace("Api", $"SetAllowAdditionalUsersFlag: This account is maxed out on secondary users. Users = {NumSecondaryUsers}, Invitations = {NumPendingInvites.Value}, Max = {5}");
					}
				}
				else
				{
					AllowAddingState.Value = AddUsersAllowedState.DeniedNotAllowedByPlan;
					BottomButton.Value = BottomButtonType.None;
					Log.Trace("Api", $"SetAllowAdditionalUsersFlag: This account cannot have secondary users. SubscriptionType = {LoggedInUser.Value.SubscriptionType}");
				}
			}
			else
			{
				AllowAddingState.Value = AddUsersAllowedState.DeniedUserNotPrimary;
				BottomButton.Value = BottomButtonType.None;
				Log.Trace("Api", "SetAllowAdditionalUsersFlag: The current logged in user is not the primary.");
			}
		}

		private async Task<IList<User>> GetPendingInvites()
		{
			try
			{
				IList<User> list = await secondaryUserService.GetPendingInvitations(api.CurrentlyAuthenticatedUserId);
				NumPendingInvites.Value = list.Count;
				return list;
			}
			catch (Exception ex)
			{
				Log.Error("Api", "secondaryUserService.GetPendingInvitations exception: " + ex.Message);
				Log.Error("Api", "Current ID: " + api.CurrentlyAuthenticatedUserId);
				Log.Error("Api", ex.StackTrace);
				NumPendingInvites.Value = 2147483647;
				return new List<User>();
			}
		}

		protected override async Task HandleSecondaryServiceResult(SecondaryOperationResult result)
		{
			await base.HandleSecondaryServiceResult(result);
			await Init().ConfigureAwait(continueOnCapturedContext: false);
		}

