		public RemoveAccountViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, ISecondaryUsersService secondaryUserService)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.secondaryUserService = secondaryUserService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init(NavObject nav)
		{
			User user = await User.Get(ifitApi, nav.Id).ConfigureAwait(continueOnCapturedContext: false);
			UserForAvatar.Value = user;
			Name.Value = user?.Firstname + " " + user?.Lastname;
			Username.Value = user?.Username;
			isInvitation = nav.IsInvitation;
		}

		private async Task DoRemoveUser()
		{
			if (!isInvitation)
			{
