	public class CalibrateInclineDialogViewModel : BaseViewModel
	{
		private IDisposable calibrationReceiver;

		public readonly INC<string> Status = new NC<string>();

		public readonly INC<bool?> SendSuccess = new NC<bool?>();

		public readonly INC<bool> HasStarted = new NC<bool>();

		public readonly INC<bool> IsInProgress = new NC<bool>();

		public readonly INC<bool> IsFinished = new NC<bool>();

		private IFitnessConsole Console;

		private readonly IIdleLogoutService IdleLogoutService;

		public ICommand CalibrateCommand => new MvxCommand(StartCalibrateIncline);

		public string Title => Wolf.Core.Resources.AppStrings.settings_calibrate_incline;

		public string Instructions
		{
			get
			{
				if (!(currentConsoleService?.GetCurrentConsoleType(ConsoleType.None).IsBeltBasedMachine() ?? true))
				{
					return Wolf.Core.Resources.AppStrings.settings_calibrate_instructions_no_belt;
				}
				return Wolf.Core.Resources.AppStrings.settings_calibrate_instructions;
			}
		}

		public CalibrateInclineDialogViewModel(ILocalSettings localSettings, ICurrentConsoleService currentConsoleService, IIdleLogoutService logoutService = null)
			: base(localSettings)
		{
			try
			{
				Console = currentConsoleService.ActiveConsole;
				IdleLogoutService = logoutService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			StopCalibrationMonitoring();
			UnregisterChangeHandlers();
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			StopCalibrationMonitoring();
		}

		private void StartCalibrateIncline()
		{
			IdleLogoutService?.SetActive(active: false);
			IsInProgress.Value = true;
			HasStarted.Value = true;
			if (Console != null)
			{
				Console.CalibrateIncline();
				calibrationReceiver = Console.WhenCalibrationStatusChanged?.Subscribe(UpdateUiString);
			}
		}

		private void UpdateUiString(CalibrateInclineState status)
		{
			switch (status)
			{
			case CalibrateInclineState.Done:
				Status.Value = Wolf.Core.Resources.AppStrings.calibration_complete;
				CalibrationComplete();
				break;
			case CalibrateInclineState.Failed:
				Status.Value = Wolf.Core.Resources.AppStrings.calibration_failed;
				CalibrationFailed();
				break;
			case CalibrateInclineState.InProgress:
				break;
			}
		}

		private void CalibrationComplete()
		{
			StopCalibrationMonitoring();
			IsInProgress.Value = false;
			IsFinished.Value = true;
			Status.Value = Wolf.Core.Resources.AppStrings.calibration_complete;
			SendSuccess.Value = true;
		}

		private void CalibrationFailed()
		{
			StopCalibrationMonitoring();
			IsInProgress.Value = false;
			IsFinished.Value = true;
			Status.Value = Wolf.Core.Resources.AppStrings.calibration_failed;
			SendSuccess.Value = false;
		}

		private void StopCalibrationMonitoring()
		{
			IdleLogoutService?.SetActive(active: true);
			if (calibrationReceiver != null)
			{
				calibrationReceiver.Dispose();
				calibrationReceiver = null;
			}
		}

