	public class MaintenanceViewModel : WifiStateAndPingViewModel
	{
		public readonly INC<CheckUpdateState> UpdateStatus = new NC<CheckUpdateState>();

		public readonly INC<bool> CanCalibrate = new NC<bool>();

		public readonly INC<bool> CanRunDiagnostics = new NC<bool>();

		public readonly INC<bool> IsUpdating = new NC<bool>();

		public readonly INC<bool> ReadyToScanForMachine = new NC<bool>(value: true);

		public readonly INC<bool> IsClearRdmAssetsVisible = new NC<bool>();

		public readonly INC<bool> RdmAssetsRemoved = new NC<bool>();

		public readonly INC<int> ProgressPercent = new NC<int>();

		private readonly ICheckUpdateService checkUpdateService;

		private readonly ILaunchUpdate launchUpdateService;

		private readonly IIfitApiService apiService;

		protected readonly IBlobCacheService blobCacheService;

		private new readonly IBleConsoleService bleConsoleService;

		private readonly IWorkoutEstimationCache workoutEstimateCache;

		private readonly IHardwareInfo hardwareInfo;

		private readonly IIdleLogoutService idleLogoutService;

		private readonly IBlobCacheFileManager blobCacheFileManager;

		private readonly ILockPinService lockPinService;

		private readonly IDemoModeService demoModeService;

		private IDisposable wifiSubscriber;

		private IDisposable canCalibrateSubscriber;

		public bool IsBuiltIn => deviceInfo?.IsBuiltIn ?? false;

		[DependsOn(new string[] { "UpdateStatus", "IsUpdating" })]
		public bool IsBusy
		{
			get
			{
				if (UpdateStatus.Value != CheckUpdateState.Checking)
				{
					return IsUpdating.Value;
				}
				return true;
			}
		}

		[DependsOn(new string[] { "UpdateStatus" })]
		public bool ShowScanBtn => UpdateStatus.Value == CheckUpdateState.NoMachine;

		[DependsOn(new string[] { "UpdateStatus", "IsUpdating" })]
		public bool IsUpdateButtonClickable
		{
			get
			{
				if (UpdateStatus.Value == CheckUpdateState.UpdateAvailable)
				{
					return !IsUpdating.Value;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "ProgressPercent", "IsUpdating" })]
		public bool IsStartingUpdate
		{
			get
			{
				if (IsUpdating.Value)
				{
					return ProgressPercent.Value == 0;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "ProgressPercent", "IsUpdating" })]
		public bool IsFinishingingUpdate
		{
			get
			{
				if (IsUpdating.Value)
				{
					return ProgressPercent.Value == 100;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsClearRdmAssetsVisible", "RdmAssetsRemoved" })]
		public bool IsClearRdmAssetsClickable
		{
			get
			{
				if (IsClearRdmAssetsVisible.Value)
				{
					return !RdmAssetsRemoved.Value;
				}
				return false;
			}
		}

		public ICommand StartUpdate => new MvxCommand(LaunchUpdate);

		public ICommand SelectCalibration => new MvxCommand(ShowCalibration);

		public ICommand SelectNetworkDiagnostics => new MvxCommand(ShowNetworkDiagnostics);

		public ICommand SelectResetData => new MvxCommand(ShowResetDataConfirmDialog);

		public ICommand SelectDeleteRdmAssets => new MvxCommand(ClearRdmAssets);

		public ICommand ScanForRecoverableMachine => new MvxCommand(ScanForRecoverableEquipment);

		public MaintenanceViewModel(ILocalSettings localSettings, ICheckUpdateService checkUpdateService, ILaunchUpdate launchUpdateService, IIfitApiService apiService, IBlobCacheService blobCacheService, IWorkoutEstimationCache workoutEstimateCache, IHardwareInfo hardwareInfo, IGeoLocationService geoLocationService, IFeatureFlagManager featureFlagManager, ICurrentConsoleService currentConsoleService, ILockPinService lockPinService, IIdleLogoutService idleLogoutService = null, IBleConsoleService bleConsoleService = null, IBlobCacheFileManager blobCacheFileManager = null, IDemoModeService demoModeService = null)
			: base(localSettings, geoLocationService)
		{
			try
			{
				this.checkUpdateService = checkUpdateService;
				this.launchUpdateService = launchUpdateService;
				this.apiService = apiService;
				this.blobCacheService = blobCacheService;
				this.workoutEstimateCache = workoutEstimateCache;
				this.bleConsoleService = bleConsoleService;
				this.hardwareInfo = hardwareInfo;
				this.idleLogoutService = idleLogoutService;
				this.blobCacheFileManager = blobCacheFileManager;
				this.lockPinService = lockPinService;
				this.demoModeService = demoModeService;
				if (IsBuiltIn)
				{
					CanCalibrate.Value = !base.IsStrengthMirror && currentConsoleService?.ActiveConsole?.ConsoleInfo?.CanSetIncline == true;
					canCalibrateSubscriber = currentConsoleService?.WhenConsoleChanged?.SubscribeWithErrorLogging(OnConsoleChanged);
					if (demoModeService != null && demoModeService.CanDeleteAssets())
					{
						IsClearRdmAssetsVisible.Value = true;
					}
				}
				else if (bleConsoleService != null)
				{
					SetCanCalibrate();
					canCalibrateSubscriber = bleConsoleService.WhenConnectionStateChanged?.Subscribe(OnConnectionStateChange);
				}
				else
				{
					Log.Error("Settings", "The IBleConsoleService could not resolve.  Closing the MaintenanceViewModel");
					DoClose();
				}
				CanRunDiagnostics.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfNetworkDiagnosticsEnabled) && IsBuiltIn && currentConsoleService != null && !currentConsoleService.IsBuiltinClub;
				wifiSubscriber = wifiService?.WhenNetworkStateChanged?.SubscribeWithErrorLogging(OnWifiStateChange);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			IsUpdating.Value = false;
			RegisterForStartButton();
			Task.Run((Func<Task>)StartCheckForUpdate);
		}

		protected override void DoClose()
		{
			idleLogoutService?.SetActive(active: true);
			base.DoClose();
		}

		private void SetCanCalibrate()
		{
			if (currentConsoleService?.Console?.IsNonconnectedConsole() ?? true)
			{
				CanCalibrate.Value = false;
				return;
			}
			INC<bool> canCalibrate = CanCalibrate;
			int value;
			if (bleConsoleService.ConnectionState == ConsoleConnectionState.Connected)
			{
				IFitnessConsole console = currentConsoleService.Console;
				value = ((console != null && console.ConsoleInfo?.CanSetIncline == true) ? 1 : 0);
			}
			else
			{
				value = 0;
			}
			canCalibrate.Value = (byte)value != 0;
		}

		public override void Dispose()
		{
			wifiSubscriber?.Dispose();
			wifiSubscriber = null;
			canCalibrateSubscriber?.Dispose();
			canCalibrateSubscriber = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

		private void OnWifiStateChange(WifiNetworkState wifiState)
		{
			Task.Run((Func<Task>)StartCheckForUpdate);
		}

		private void OnConnectionStateChange(ConsoleConnectionState connectionState)
		{
			INC<bool> canCalibrate = CanCalibrate;
			int value;
			if (connectionState == ConsoleConnectionState.Connected)
			{
				ICurrentConsoleService obj = currentConsoleService;
				value = ((obj != null && obj.Console?.ConsoleInfo?.CanSetIncline == true) ? 1 : 0);
			}
			else
			{
				value = 0;
			}
			canCalibrate.Value = (byte)value != 0;
			Task.Run((Func<Task>)StartCheckForUpdate);
		}

		private void ScanForRecoverableEquipment()
		{
			Log.Trace("Updating", "Scanning for updateable equipment");
			if (Mvx.TryResolve<IDfuConnectionService>(out var service))
			{
				service.ScanForRecoverableDevices();
			}
			ReadyToScanForMachine.Value = false;
			Observable.Timer(TimeSpan.FromSeconds(30.0)).SubscribeWithErrorLogging(delegate
			{
				ReadyToScanForMachine.Value = true;
			});
		}

		private void OnConsoleChanged(IFitnessConsole console)
		{
			CanCalibrate.Value = currentConsoleService?.Console?.ConsoleInfo?.CanSetIncline == true;
			Task.Run((Func<Task>)StartCheckForUpdate);
		}

		private async Task StartCheckForUpdate()
		{
			if (IsBusy)
			{
				Log.Trace("Updating", $"Update is already busy: {UpdateStatus.Value}");
				return;
			}
			UpdateStatus.Value = CheckUpdateState.Checking;
			idleLogoutService?.SetActive(active: false);
			INC<CheckUpdateState> updateStatus = UpdateStatus;
			updateStatus.Value = await checkUpdateService.CheckForUpdate();
			idleLogoutService?.SetActive(active: true);
		}

		private void LaunchUpdate()
		{
			IsUpdating.Value = true;
			idleLogoutService?.SetActive(active: false);
			launchUpdateService.UpdateConnectedMachine();
		}

		private void ShowCalibration()
		{
			if (deviceInfo.IsTablet)
			{
				ShowViewModel<MaintenanceViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.DialogView<CalibrateInclineDialogViewModel>(), (MvxRequestedBy)null);
			}
			else
			{
				ShowViewModel<PhoneCalibrateInclineViewModel>();
			}
		}

		private void ShowNetworkDiagnostics()
		{
			ShowViewModel<MaintenanceViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.DialogView<NetworkDiagnosticsViewModel>(), (MvxRequestedBy)null);
		}

		private void ShowResetDataConfirmDialog()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.reset_app_data_title, Wolf.Core.Resources.AppStrings.reset_app_data_dialog, async delegate
			{
				await ResetAppData();
				return (object)null;
			}, cancellableOperation: false, delegate(Task<object> task)
			{
				if (task.IsFaulted)
				{
					Log.Error("Settings", "Could not reset user's app data: " + (task.Exception?.GetBaseException()?.ToString() ?? "<null>"));
				}
				else if (task.IsCompleted)
				{
					Log.Trace("Settings", "User's app data was reset.");
				}
			}, Wolf.Core.Resources.AppStrings.cancel.ToUpper(), Wolf.Core.Resources.AppStrings.yes.ToUpper(), OnConfirmActionTiming.BeforeClose);
		}

		private void ClearRdmAssets()
		{
			if (!RdmAssetsRemoved.Value)
			{
				RdmAssetsRemoved.Value = true;
				demoModeService.DeleteAllAssets();
			}
		}

		protected async Task ResetAppData()
		{
			Log.Trace("Settings", "Resetting app data from maintenance screen");
			if (Mvx.TryResolve<ISaveUpdateFilesService>(out var service))
			{
				await Task.Run((Func<Task>)service.CleanUpSavedFiles);
			}
			if (Mvx.TryResolve<IApplicationFileService>(out var service2))
			{
				service2.Clear();
			}
			lockPinService?.SaveLockPinNumber(string.Empty);
			apiService.ClearCurrentUser();
			apiService.AuthenticatedUsers?.Clear();
			trackingService.FirstRun = true;
			trackingService.ClearCompletedOnboardingUsers();
			Mvx.Resolve<IUserAvatarImage>()?.AvatarDictionary.Clear();
			try
			{
				blobCacheService.Wipe();
				if (workoutEstimateCache != null)
				{
					await workoutEstimateCache.Clear(vacuum: true);
				}
			}
			catch (Exception exception)
			{
				Log.Error("DeviceAdmin", "Wiping Cache failed", exception);
				if (Mvx.TryResolve<IFatalityService>(out var service3))
				{
					string displayMessage = (IsBuiltIn ? Shire.Core.Resources.AppStrings.database_malformed_error : Wolf.Core.Resources.AppStrings.fatal_please_restart);
					service3.ReportFatalEvent(exception, displayMessage, isPermanent: true);
					if (IsBuiltIn)
					{
						return;
					}
				}
			}
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			InvokeOnMainThread(delegate
			{
				try
				{
					webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
					webviewHolderFactory.WebviewHolderStore.FlushAll();
				}
				catch (Exception exception2)
				{
					Log.Error("DeviceAdmin", "Exception encountered while trying to wipe Secure Cache and Clear WebViewStore", exception2);
				}
				finally
				{
					tcs.SetResult(result: true);
				}
			});
			await tcs.Task;
			if (hardwareInfo.IsAndroid)
			{
				ShowViewModel<WelcomeViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ClearStackToRequested(), (MvxRequestedBy)null);
			}
			else
			{
				ShowLoginViewModel();
			}
		}

