	public class NetworkDiagnosticsViewModel : BaseViewModel
	{
		private const string LogTag = "NetworkDiagnosticsViewModel";

		public readonly INC<int> ProgressPercentage = new NC<int>();

		public readonly INC<bool> AnalysisRunning = new NC<bool>();

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly INetworkDiagnostics networkDiagnostics;

		private readonly Progress<int> progress = new Progress<int>();

		private CancellationTokenSource cancellationTokenSource;

		private TaskCompletionSource<bool> analysisRunningTask;

		public ICommand RunAnalysis => new MvxAsyncCommand(StartAnalysis, () => !AnalysisRunning.Value);

		public ICommand CloseAnalysis => new MvxAsyncCommand(CancelAnalysis);

		public NetworkDiagnosticsViewModel(ILocalSettings localSettings, INetworkDiagnostics networkDiagnostics, IWolfAnalytics wolfAnalytics)
			: base(localSettings)
		{
			try
			{
				this.networkDiagnostics = networkDiagnostics;
				this.wolfAnalytics = wolfAnalytics;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task CancelAnalysis()
		{
			cancellationTokenSource?.Cancel();
			await (analysisRunningTask?.Task ?? Task.Delay(0).ContinueWith((Task t) => true));
			DoClose();
		}

		private async Task StartAnalysis()
		{
			if (AnalysisRunning.Value)
			{
				return;
			}
			ProgressPercentage.Value = 0;
			progress.ProgressChanged -= ProgressChanged;
			progress.ProgressChanged += ProgressChanged;
			cancellationTokenSource?.Dispose();
			cancellationTokenSource = new CancellationTokenSource();
			analysisRunningTask = new TaskCompletionSource<bool>();
			try
			{
				AnalysisRunning.Value = true;
				Log.Trace("NetworkDiagnosticsViewModel", "Analysis complete! SelfHelp: " + await networkDiagnostics.RunAnalysis(progress, cancellationTokenSource.Token) + ", dashboard: " + networkDiagnostics.GetUserDashboardURL());
				ShowResults();
			}
			catch (OperationCanceledException)
			{
			}
			catch (NetworkDiagnosticsException ex2)
			{
				Log.Trace("NetworkDiagnosticsViewModel", $"Error: {ex2.Error}");
				ShowResults(ex2.Error);
				await wolfAnalytics.HandledNetworkDiagnosticsError(ex2);
			}
			finally
			{
				AnalysisRunning.Value = false;
				analysisRunningTask?.SetResult(result: false);
				ProgressPercentage.Value = 0;
			}
		}

		private void ProgressChanged(object sender, int progressPercent)
		{
			ProgressPercentage.Value = progressPercent;
		}

		private void ShowResults(NetworkDiagnosticsError? error = null)
		{
			var (message, errorCode) = GetResultsData(error);
			if (!error.HasValue)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.settings_network_diagnostics_scan_success_title, message, Wolf.Core.Resources.AppStrings.okay_title.ToUpper());
			}
			else
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.settings_network_diagnostics_title.ToUpper(), message, Wolf.Core.Resources.AppStrings.close, errorCode.HumanReadable(), isWarning: true);
			}
			DoClose();
		}

		private (string message, ErrorCode errorCode) GetResultsData(NetworkDiagnosticsError? error)
		{
			return error switch
			{
				null => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_scan_success, errorCode: ErrorCode.None), 
				NetworkDiagnosticsError.NoInternetConnection => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_internet, errorCode: ErrorCode.NetworkDiagnosticNoInternetConnection), 
				NetworkDiagnosticsError.NoWifi => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_internet, errorCode: ErrorCode.NetworkDiagnosticNoWifi), 
				NetworkDiagnosticsError.Timeout => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_internet, errorCode: ErrorCode.NetworkDiagnosticTimeout), 
				NetworkDiagnosticsError.BatterySaver => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_other, errorCode: ErrorCode.NetworkDiagnosticBatterySaver), 
				NetworkDiagnosticsError.InvalidApiKey => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_other, errorCode: ErrorCode.NetworkDiagnosticInvalidApiKey), 
				NetworkDiagnosticsError.AlreadyStarted => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_internet, errorCode: ErrorCode.NetworkDiagnosticAlreadyStarted), 
				_ => (message: Wolf.Core.Resources.AppStrings.settings_network_diagnostics_error_other, errorCode: ErrorCode.NetworkDiagnosticUnknownError), 
			};
		}

		public override void Dispose()
		{
			base.Dispose();
			progress.ProgressChanged -= ProgressChanged;
			cancellationTokenSource?.Dispose();
			cancellationTokenSource = null;
			analysisRunningTask = null;
			UnregisterChangeHandlers();
		}

