	public class SettingsUpdateViewModel : BaseViewModel
	{
		private class AbortUpdateException : Exception
		{
			public AbortUpdateException(string message)
				: base(message)
			{
			}
		}

		public readonly INC<string> StatusText = new NC<string>();

		public readonly INC<string> Message = new NC<string>();

		public readonly INC<int> Progress = new NC<int>(0);

		public readonly INC<bool> PreparingVisible = new NC<bool>(value: true);

		public readonly INC<bool> UploadingVisible = new NC<bool>(value: false);

		public readonly INC<bool> SuccessVisible = new NC<bool>(value: false);

		public readonly INC<bool> FailedVisible = new NC<bool>(value: false);

		public readonly INC<bool> CanClose = new NC<bool>();

		private IDisposable stateChangeSub;

		private IDisposable progressSub;

		private IDisposable updateStartedSub;

		private readonly IUpdater updater;

		private new readonly IBleConsoleService bleConsoleService;

		private readonly ILaunchUpdate updateLauncher;

		private UpdateState previousState;

		public int Size => updater?.UpdateSize ?? (-1);

		public ICommand RetryCommand => new MvxAsyncCommand(Retry);

		public SettingsUpdateViewModel(ILocalSettings localSettings, IUpdater updater, ILaunchUpdate updateLauncher)
			: base(localSettings)
		{
			try
			{
				this.updater = updater;
				this.updateLauncher = updateLauncher;
				Mvx.TryResolve<IBleConsoleService>(out bleConsoleService);
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_preparing;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init()
		{
			stateChangeSub?.Dispose();
			stateChangeSub = updater.WhenUpdateStateChanged.Subscribe(OnUpdateStateChanged);
			progressSub?.Dispose();
			progressSub = updater.WhenProgressChanged.Subscribe(delegate(int x)
			{
				Progress.Value = x;
			});
			updateStartedSub?.Dispose();
			updateStartedSub = updater.WhenIsUpdatingChanged.Subscribe(OnUpdating);
		}

		private void OnUpdateStateChanged(UpdateState state)
		{
			Log.Trace("Updating", $"DFU - SettingsUpdateViewModel.OnUpdateStateChanged() was call with state: {state}");
			switch (state)
			{
			case UpdateState.TransferComplete:
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_transfer_complete;
				ShowUISection(preparing: true);
				break;
			case UpdateState.ActivateAndReset:
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_activate_and_reset;
				ShowUISection(preparing: true);
				break;
			case UpdateState.Transfering:
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_transfering;
				ShowUISection(preparing: false, updating: true);
				break;
			case UpdateState.DisconnectedBeforeComplete:
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_disconnected_before_complete;
				ShowUISection(preparing: true);
				break;
			case UpdateState.Failed:
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_failed;
				ShowUISection(preparing: false, updating: false, failed: true);
				RequestEnableBluetooth(notifyIfCannotEnable: true);
				break;
			case UpdateState.Done:
				if (state != previousState)
				{
					StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_done;
					ShowUISection(preparing: false, updating: false, failed: false, success: true);
					Timers.UpdateFirmwareTimer.End("Done updating firmware");
					bleConsoleService.DisconnectImmediate(forgetDevice: false);
					bleConsoleService.ConnectToCachedConsole();
				}
				break;
			default:
				StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_preparing;
				ShowUISection(preparing: true);
				break;
			}
			previousState = state;
		}

		private void OnUpdating(bool isUpdating)
		{
			CanClose.Value = !isUpdating;
		}

		private void ShowUISection(bool preparing = false, bool updating = false, bool failed = false, bool success = false)
		{
			PreparingVisible.Value = preparing;
			UploadingVisible.Value = updating;
			FailedVisible.Value = failed;
			SuccessVisible.Value = success;
		}

		private async Task Retry()
		{
			if (!deviceInfo.IsBuiltIn && Mvx.TryResolve<IBleRadioStatusService>(out var service) && !service.IsBluetoothRadioEnabled())
			{
				RequestEnableBluetooth(notifyIfCannotEnable: true);
				return;
			}
			ShowUISection(preparing: true);
			StatusText.Value = Wolf.Core.Resources.AppStrings.ble_update_preparing;
			if (await CheckForRecoverableConsole())
			{
				return;
			}
			OnUpdateStateChanged(UpdateState.ScanningForDevice);
			try
			{
				Timers.UpdateFirmwareTimer.Start();
				updateLauncher.UpdateConnectedMachine(attemptToRecover: true);
			}
			catch (AbortUpdateException ex)
			{
				DoClose();
				Message.Value = ex.Message;
			}
			catch (Exception arg)
			{
				Log.Error("Updating", $"Exception => {arg}");
				OnUpdateStateChanged(UpdateState.Failed);
			}
		}

		protected override void DoClose()
		{
			CleanSubscriptions();
			base.DoClose();
		}

		public override void Dispose()
		{
			CleanSubscriptions();
			base.Dispose();
			UnregisterChangeHandlers();
		}

		private void CleanSubscriptions()
		{
			stateChangeSub?.Dispose();
			stateChangeSub = null;
			progressSub?.Dispose();
			progressSub = null;
			updateStartedSub?.Dispose();
			updateStartedSub = null;
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void OnPropertyChanged(object sender, PropertyChangedEventArgs args)
		{
			string propertyName = args.PropertyName;
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void RegisterOnPropertyChanged()
		{
			base.PropertyChanged += OnPropertyChanged;
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void RegisterChangeHandlers()
		{
			RegisterOnPropertyChanged();
			RegisterIncChangedHandlers();
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void UnregisterOnPropertyChanged()
		{
			base.PropertyChanged -= OnPropertyChanged;
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void UnregisterChangeHandlers()
		{
			UnregisterOnPropertyChanged();
			UnregisterIncChangedHandlers();
		}

