namespace Wolf.Core.ViewModels.Settings.LockPinSettings
{
	public class LockPinSettingsViewModel : BaseEquipmentSettingsViewModel
	{
		private readonly IIfitLoginService ifitLogin;

		private readonly ILockPinService lockPinService;

		private bool automaticShowLockPin;

		public readonly INC<string> LockPinText = new NC<string>(Wolf.Core.Resources.AppStrings.settings_lock_pin);

		public readonly INC<string> LockPinDescription = new NC<string>(Wolf.Core.Resources.AppStrings.settings_lock_pin_description);

		public readonly BooleanCycle LockPinEnabled = new BooleanCycle(value: true);

		public readonly INC<string> LockPinShow = new NC<string>(Wolf.Core.Resources.AppStrings.settings_lock_pin_show);

		public readonly INC<string> LockPinChange = new NC<string>(Wolf.Core.Resources.AppStrings.settings_lock_pin_change);

		public readonly BooleanCycle LockPinVisible = new BooleanCycle();

		public readonly INC<string> PinNumber1 = new NC<string>();

		public readonly INC<string> PinNumber2 = new NC<string>();

		public readonly INC<string> PinNumber3 = new NC<string>();

		public readonly INC<string> PinNumber4 = new NC<string>();

		public ICommand DoLockPinToggle { get; }

		public ICommand DoShowLockPin { get; }

		public ICommand DoChangeLockPin { get; }

		public LockPinSettingsViewModel(ILocalSettings localSettings, ISettingsRouter settingsRouter, IIfitApiService ifitApi, IIfitLoginService ifitLogin, ITelevisionTunerService televisionTunerService, IWolfAnalytics wolfAnalytics, ISetUnitsService setUnitsService, ILockPinService lockPinService)
			: base(localSettings, settingsRouter, ifitApi, televisionTunerService, wolfAnalytics, setUnitsService)
		{
			try
			{
				this.lockPinService = lockPinService;
				this.ifitLogin = ifitLogin;
				DoLockPinToggle = new MvxAsyncCommand(ToggleLockPin);
				DoShowLockPin = new MvxAsyncCommand(ShowLockPin);
				DoChangeLockPin = new MvxAsyncCommand(ChangeLockPin);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
		}

		public override void OnAfterViewShown()
		{
			base.OnAfterViewShown();
			if (automaticShowLockPin)
			{
				ShowLockPin().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public void Init(LockPinSettingsArbitraryData nav)
		{
			automaticShowLockPin = nav?.AutomaticShowLockPin ?? false;
		}

		protected override void DoClose()
		{
			base.DoClose();
			NavigateToDashboardViewModel();
			ShowViewModel<SettingsViewModel>();
		}

		private async Task ToggleLockPin()
		{
			if (!LockPinEnabled.Value)
			{
				LockPinDialogArbitraryData lockPinDialogArbitraryData = new LockPinDialogArbitraryData();
				lockPinDialogArbitraryData.FromViewModel = typeof(LockPinSettingsViewModel);
				BaseViewModel.ShowDialogViewModel<LockPinDialogViewModel>(lockPinDialogArbitraryData);
			}
			else if (CanOpenPromptForPassword() && await PromptForPassword(validatePinNumber: true))
			{
				lockPinService.SaveLockPinNumber(string.Empty);
				LockPinEnabled.Value = !LockPinEnabled.Value;
			}
		}

		private async Task ShowLockPin()
		{
			if (LockPinVisible.Value)
			{
				ShowHideLockPinNumbers();
			}
			else if (automaticShowLockPin)
			{
				automaticShowLockPin = false;
				GetPinNumbers();
				ShowHideLockPinNumbers();
			}
			else if (CanOpenPromptForPassword() && await PromptForPassword(validatePinNumber: false))
			{
				GetPinNumbers();
				ShowHideLockPinNumbers();
			}
		}

		private async Task ChangeLockPin()
		{
			if (LockPinEnabled.Value && CanOpenPromptForPassword() && await PromptForPassword(validatePinNumber: true))
			{
				LockPinDialogArbitraryData lockPinDialogArbitraryData = new LockPinDialogArbitraryData();
				lockPinDialogArbitraryData.ChangingLockPin = true;
				lockPinDialogArbitraryData.FromViewModel = typeof(LockPinSettingsViewModel);
				BaseViewModel.ShowDialogViewModel<LockPinDialogViewModel>(lockPinDialogArbitraryData);
			}
		}

		private void GetPinNumbers()
		{
			char[] array = lockPinService.GetLockPinNumber().ToCharArray();
			if (array.Length == 4)
			{
				PinNumber1.Value = array[0].ToString();
				PinNumber2.Value = array[1].ToString();
				PinNumber3.Value = array[2].ToString();
				PinNumber4.Value = array[3].ToString();
			}
		}

		private void ShowHideLockPinNumbers()
		{
			LockPinVisible.Value = !LockPinVisible.Value;
			LockPinShow.Value = (LockPinVisible.Value ? Wolf.Core.Resources.AppStrings.settings_lock_pin_hide : Wolf.Core.Resources.AppStrings.settings_lock_pin_show);
		}

		private Task<bool> PromptForPassword(bool validatePinNumber)
		{
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
			BaseViewModel.ShowDialogViewModel<InputPasswordDialogViewModel>(new InputPasswordDialogInitializationData(validatePinNumber ? Wolf.Core.Resources.AppStrings.input_password_dialog_title_account_pin_password : Wolf.Core.Resources.AppStrings.input_password_dialog_title_account_password, validatePinNumber ? Wolf.Core.Resources.AppStrings.input_password_dialog_input_pin_password_hint : Wolf.Core.Resources.AppStrings.input_password_dialog_input_password_hint, Wolf.Core.Resources.AppStrings.submit, null, null, validatePinNumber ? Wolf.Core.Resources.AppStrings.input_password_dialog_enter_valid_pin_password : Wolf.Core.Resources.AppStrings.input_password_dialog_enter_valid_password, validatePinNumber ? Wolf.Core.Resources.AppStrings.input_password_dialog_enter_error_pin_password : null, (string password) => DoValidatePasswords(validatePinNumber, password, tcs), delegate
			{
				tcs.TrySetResult(result: false);
			}, delegate
			{
				DoForgotPassword(tcs);
			}, tcs));
			return tcs.Task;
		}

		private async Task<bool> DoSignIn(string password)
		{
			Shire.Core.Util.NonGenericSubject obs = new Shire.Core.Util.NonGenericSubject();
			if (Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service) && Mvx.TryResolve<IDialogPresenter>(out var _))
			{
				service.RequestMainThreadAction(delegate
				{
					ShowProgressDialog(null, obs.ReactiveSubject, null, null, default(TimeSpan), "", showSafety: false).ConfigureAwait(continueOnCapturedContext: false);
				});
			}
			wifiService?.RefreshConnectivityState();
			IConnectivity obj = connectivity;
			LoginResult loginResult;
			if (obj == null || !obj.IsConnected)
			{
				loginResult = LoginResult.NoInternetConnection;
			}
			else
			{
				try
				{
					loginResult = await ifitLogin.Authenticate(ifitApi.CurrentlyAuthenticatedUser.Username, password, forceAuthentication: true).TimeoutAfter(LoginIfitViewModel.LoginTimeout).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (TimeoutException exception)
				{
					Log.Error("Api", "Authentication Timed Out", exception);
					loginResult = LoginResult.TimeOut;
				}
				catch (Exception exception2)
				{
					Log.Error("Api", "General Exception Occured", exception2);
					loginResult = LoginResult.UnknownFailure;
				}
			}
			obs.OnNext();
			return loginResult == LoginResult.Success;
		}

		private void DoForgotPassword(TaskCompletionSource<bool> tcs)
		{
			BaseViewModel.ShowDialogViewModel<ForgotPasswordDialogViewModel>();
			tcs.TrySetResult(result: false);
		}

		private bool LockPinMatch(string lockPinNumber)
		{
			if (lockPinNumber != null && lockPinNumber.Length == 4)
			{
				return lockPinNumber == lockPinService.GetLockPinNumber();
			}
			return false;
		}

		private async Task<bool> DoValidatePasswords(bool validatePinNumber, string password, TaskCompletionSource<bool> tcs)
		{
			if (validatePinNumber && LockPinMatch(password))
			{
				tcs.TrySetResult(result: true);
				return true;
			}
			bool result = await DoSignIn(password);
			tcs.TrySetResult(result);
			return result;
		}

		private bool CanOpenPromptForPassword()
		{
			return !dialogPresenter.IsDialogShown<InputPasswordDialogViewModel>();
		}

