				Wolf.Core.Resources.AppStrings.language_display_name_russian
			},
			{
				Language.Spanish,
				Wolf.Core.Resources.AppStrings.language_display_name_spanish
			},
			{
				Language.Klingon,
				Wolf.Core.Resources.AppStrings.language_display_name_klingon
			}
		};

		public INCList<LanguageItem> Languages = new NCList<LanguageItem>();

		public readonly INC<bool> LanguageListInitialized = new NC<bool>();

		public readonly INC<bool> ProgressViewVisible = new NC<bool>();

		private readonly IClosedCaptionsSettings closedCaptionsSettings;

		private readonly IChangeLanguageService changeLanguageService;

		private IDisposable reloadDashboardAfterLanguageChangeSub;

		public ICommand SelectLanguage => new MvxAsyncCommand<LanguageItem>(DoSelectLanguage);

		public SettingsLanguagesViewModel(ILocalSettings localSettings, IChangeLanguageService changeLanguageService, IClosedCaptionsSettings closedCaptionsSettings, ISupportedLanguageService supportedLanguageService)
			: base(localSettings)
		{
			try
			{
				this.changeLanguageService = changeLanguageService;
				Languages.Value = new List<LanguageItem>();
				IEnumerable<Language> enumerable = Enum.GetValues(typeof(Language)).Cast<Language>();
				foreach (Language item in enumerable)
				{
					bool flag = false;
					if ((1 == 0 || item != Language.Klingon) && supportedLanguageService.IsLanguageSupported(item) && item != Language.SystemDefault)
					{
						Languages.Value.Add(new LanguageItem(item, LanguageToTitleDictionary.GetValueSafely(item), changeLanguageService.CurrentLanguage == item));
					}
				}
				this.closedCaptionsSettings = closedCaptionsSettings;
				LanguageListInitialized.Value = true;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (changeLanguageService != null)
			{
				CleanupLanguageChangedSub();
				reloadDashboardAfterLanguageChangeSub = changeLanguageService.WhenLanguageChanged.SubscribeWithErrorLogging(delegate
				{
					webviewHolderFactory.WebviewHolderStore.FlushAll();
					NavigateToDashboardViewModel(null, clearStack: false);
					reloadDashboardAfterLanguageChangeSub.Dispose();
				});
			}
		}

		private async Task DoSelectLanguage(LanguageItem languageItem)
		{
			ProgressViewVisible.Value = true;
			await changeLanguageService.ChangeLanguage(languageItem.Language);
			await closedCaptionsSettings.SavePreferredLanguage(languageItem.Language);
		}

		private void CleanupLanguageChangedSub()
		{
			reloadDashboardAfterLanguageChangeSub?.Dispose();
			reloadDashboardAfterLanguageChangeSub = null;
		}

