namespace Wolf.Core.ViewModels.Settings.InWorkout
{
	public static class MaxHeartRateUtils
	{
		public const int DefaultMaxHR = 185;

		private const int MaxHRAgeBase = 220;

		public static int UserDefaultMaxHR(User user)
		{
			int result = 185;
			int age = user.Age;
			if (age > 0)
			{
				result = 220 - age;
			}
			return result;
		}
	}
	public class MaxHeartRateViewModel : BaseViewModel
	{
		private User user;

		private bool allowMaxHeartRateSave;

		private readonly IIfitApiService apiService;

		private readonly IHRTrainingService hrTrainingService;

		public readonly ObservableCollection<HeartRateSpinnerModel> SpinnerHRMaxValues = new ObservableCollection<HeartRateSpinnerModel>();

		public readonly INC<string> Title = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_max_heart_rate_title);

		public readonly INC<string> MaxHeartRateTitle = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_max_heart_rate_calculate);

		public readonly INC<string> MaxHeartRateDescription = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_max_heart_rate_description);

		public readonly INC<string> MyMaxHeartRateTitle = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_my_max_heart_rate_title);

		public readonly INC<string> MyMaxHeartRateReset = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_my_max_heart_rate_reset);

		public readonly INC<string> MaxHeartRateTestTitle = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_max_heart_rate_test_title);

		public readonly INC<string> MaxHeartRateTestCompleted = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_max_heart_rate_test_completed);

		public readonly INC<string> MaxHeartRateTestButtonTitle = new NC<string>(Wolf.Core.Resources.AppStrings.settings_maxhr_max_heart_rate_test_button_title);

		public new readonly INC<bool> IsLoading = new NC<bool>(value: false);

		public readonly INC<int> SelectedMaxHRIndex = new NC<int>();

		public readonly INC<HeartRateSpinnerModel> SelectedHRMax = new NC<HeartRateSpinnerModel>();

		public ICommand OnResetToDefaultClicked => new MvxCommand(DoResetToDefault);

		public ICommand OnTakeTheTestClicked => new MvxCommand(DoTakeTheTest);

		[DependsOn(new string[] { "SelectedHRMax" })]
		public string SelectedMaxHeartRateText
		{
			get
			{
				bool flag = user.HeartRateSettings.MaxHeartRate == MaxHeartRateUtils.UserDefaultMaxHR(user);
				string arg = (SelectedHRMax?.Value?.Bpm)?.ToString() ?? 185.ToString().ToUpper();
				return string.Format(flag ? Wolf.Core.Resources.AppStrings.settings_maxhr_my_max_heart_rate_estimated_bpm : Wolf.Core.Resources.AppStrings.settings_maxhr_my_max_heart_rate_bpm, arg).ToUpper();
			}
		}

		private int MinimumHRMax => 100;

		private int MaximumHRMax => 250;

		public MaxHeartRateViewModel(ILocalSettings localSettings, IIfitApiService apiService, IHRTrainingService hrTrainingService)
			: base(localSettings)
		{
			try
			{
				this.apiService = apiService;
				this.hrTrainingService = hrTrainingService;
				PopulateHRMaxOptions();
				SelectedHRMax.Changed += SelectedHeartRateMax_Changed;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			SelectedHRMax.Changed -= SelectedHeartRateMax_Changed;
			UnregisterChangeHandlers();
		}

		public async Task Init(UserHeartRateSettings settings)
		{
			user = await User.GetMe(apiService);
			user.UpdateHeartRateSettingsDirectly(settings);
			SetHeartRateMax(settings.MaxHeartRate);
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			SetHeartRateMax(user?.HeartRateSettings.MaxHeartRate);
			allowMaxHeartRateSave = true;
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			allowMaxHeartRateSave = false;
		}

		private void PopulateHRMaxOptions()
		{
			(from x in Enumerable.Range(MinimumHRMax, MaximumHRMax - MinimumHRMax + 1)
				select new HeartRateSpinnerModel(x - MinimumHRMax, x, Wolf.Core.Resources.AppStrings.settings_maxhr_my_max_heart_rate_bpm)).DoForEach(SpinnerHRMaxValues.Add);
			SelectedHRMax.Value = SpinnerHRMaxValues[0];
		}

		public void SetHeartRateMax(string bpm)
		{
			if (bpm != null && int.TryParse(bpm, out var result))
			{
				SetHeartRateMax(result);
			}
		}

		private void SetHeartRateMax(int? bpm)
		{
			if (bpm.HasValue)
			{
				int num = bpm.Value - MinimumHRMax;
				int num2 = MaximumHRMax - MinimumHRMax;
				if (num >= 0 && num <= num2)
				{
					SelectedHRMax.Value = SpinnerHRMaxValues[num];
				}
				SelectedMaxHRIndex.Value = SpinnerHRMaxValues.IndexOf(SelectedHRMax.Value);
			}
		}

		private void DoResetToDefault()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.settings_maxhr_reset_label, Wolf.Core.Resources.AppStrings.settings_maxhr_reset_text, ResetToDefaultMaxHR, Wolf.Core.Resources.AppStrings.settings_dialog_cancel, Wolf.Core.Resources.AppStrings.settings_maxhr_reset_label);
		}

		private void ResetToDefaultMaxHR()
		{
			int value = MaxHeartRateUtils.UserDefaultMaxHR(user);
			SetHeartRateMax(value);
		}

		private void DoTakeTheTest()
		{
			string workoutId = hrTrainingService.RetrieveHRTestWorkoutId(currentConsoleService.Console.ConsoleInfo.MachineType);
			PreWorkoutViewModel.NavObject parameterValuesObject = new PreWorkoutViewModel.NavObject
			{
				WorkoutId = workoutId,
				WorkoutSource = WorkoutSource.TestHR,
				DashboardIndex = -1
			};
			ShowViewModel<PreWorkoutViewModel>(parameterValuesObject);
		}

		private async void SelectedHeartRateMax_Changed(object sender, EventArgs e)
		{
			await SaveMaxHeartRate();
		}

		private async Task SaveMaxHeartRate()
		{
			if (!allowMaxHeartRateSave || SelectedHRMax.Value == null)
			{
				return;
			}
			if (SelectedHRMax.Value.Bpm < user.HeartRateSettings.RestingHeartRate)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.invalid_max_hr_title, Wolf.Core.Resources.AppStrings.invalid_max_hr_message);
				SetHeartRateMax(user.HeartRateSettings.MaxHeartRate);
				return;
			}
			IsLoading.Value = true;
			try
			{
				user.HeartRateSettings.MaxHeartRate = SelectedHRMax.Value.Bpm;
				await user.UpdateHeartRateSettings(apiService);
			}
			catch (Exception ex)
			{
				Log.Error("Settings", "Unable to save max heart rate: [" + ex.Message + "]", ex);
			}
			IsLoading.Value = false;
		}

