	public class MyHeartRateZoneViewModel : BaseViewModel
	{
		private bool isLoading;

		private UserHeartRateSettings hrSettings;

		private readonly IIfitApiService api;

		public readonly INC<string> ToolbarTitle = new NC<string>(Wolf.Core.Resources.AppStrings.my_hr_zone_title);

		public readonly INC<User> LoggedInUser = new NC<User>();

		public readonly INC<string> HRZoneDescription = new NC<string>(Wolf.Core.Resources.AppStrings.my_hr_zones_settings_description);

		public readonly INC<string> RestingHR = new NC<string>(Wolf.Core.Resources.AppStrings.resting_hr);

		public readonly INC<string> RestingHRvalue = new NC<string>(string.Format(Wolf.Core.Resources.AppStrings.ph_bpm, 0));

		public readonly INC<string> MaxHR = new NC<string>(Wolf.Core.Resources.AppStrings.max_hr);

		public readonly INC<string> MaxHRvalue = new NC<string>(string.Format(Wolf.Core.Resources.AppStrings.estimated_ph_bpm, 0));

		public readonly INC<string> HRZoneTitle = new NC<string>(Wolf.Core.Resources.AppStrings.my_hr_zone_breakdown);

