		public INC<UserHRZoneUIAdapter> Zone2 = new NC<UserHRZoneUIAdapter>();

		public INC<UserHRZoneUIAdapter> Zone1 = new NC<UserHRZoneUIAdapter>();

		protected User User { get; set; }

		public ICommand OnRestHRClicked => new MvxCommand(DoOpenRestingHeartRateScreen);

		public ICommand OnMaxHRClicked => new MvxCommand(DoMaxHeartRateScreen);

		public MyHeartRateZoneViewModel(ILocalSettings localSettings, IIfitApiService api)
			: base(localSettings)
		{
			try
			{
				this.api = api;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			LoggedInUser.Value = api.CurrentlyAuthenticatedUser;
			await LoadHeartRateSettings();
			RefreshHeartRateZones();
		}

		private void UpdateValues()
		{
			RestingHRvalue.Value = string.Format(Wolf.Core.Resources.AppStrings.ph_bpm, hrSettings.RestingHeartRate);
			MaxHRvalue.Value = string.Format((hrSettings.MaxHeartRate == MaxHeartRateUtils.UserDefaultMaxHR(User)) ? Wolf.Core.Resources.AppStrings.estimated_ph_bpm : Wolf.Core.Resources.AppStrings.ph_bpm, hrSettings.MaxHeartRate);
			Zone5.Value = (from x in hrSettings.Zones
				where x.ZoneNumber == 5
				select new UserHRZoneUIAdapter(x)).FirstOrDefault();
			Zone4.Value = (from x in hrSettings.Zones
				where x.ZoneNumber == 4
				select new UserHRZoneUIAdapter(x)).FirstOrDefault();
			Zone3.Value = (from x in hrSettings.Zones
				where x.ZoneNumber == 3
				select new UserHRZoneUIAdapter(x)).FirstOrDefault();
			Zone2.Value = (from x in hrSettings.Zones
				where x.ZoneNumber == 2
				select new UserHRZoneUIAdapter(x)).FirstOrDefault();
			Zone1.Value = (from x in hrSettings.Zones
				where x.ZoneNumber == 1
				select new UserHRZoneUIAdapter(x)).FirstOrDefault();
		}

		private void RefreshHeartRateZones()
		{
			Task.Run(async delegate
			{
				_ = 1;
				try
				{
					hrSettings = await (await User.GetMe(api)).GetHeartRateSettings(api, force: true);
					UpdateValues();
				}
				catch (Exception exception)
				{
					Log.Error("MyHeartRateZoneViewModel", "Error refreshing HR values", exception);
				}
			});
		}

		public async Task LoadHeartRateSettings()
		{
			isLoading = true;
			try
			{
				User = await User.GetMe(api);
				hrSettings = await User.GetHeartRateSettings(api);
				UpdateValues();
			}
			catch (iFit.Api.Support.ConnectivityException)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.internet_connection_error, DoClose, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper());
			}
			catch (Exception exception)
			{
				Log.Error("MyHeartRateZoneViewModel", "Error initializing HR values", exception);
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.settings_sync_error, DoClose, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper());
			}
			finally
			{
				isLoading = false;
			}
		}

		private void DoOpenRestingHeartRateScreen()
		{
			if (!isLoading)
			{
				ShowViewModel<SettingsRestingHRViewModel>(hrSettings);
			}
		}

		private void DoMaxHeartRateScreen()
		{
			if (!isLoading)
			{
				ShowViewModel<MaxHeartRateViewModel>(hrSettings);
			}
		}

