		public SettingsInWorkoutViewModel(ILocalSettings localSettings, ISettingsRouter settingsRouter, IIfitApiService ifitApi, ITelevisionTunerService televisionTunerService, IWolfAnalytics wolfAnalytics, IWorkoutFeatureService workoutFeatureService, IClosedCaptionsSettings closedCaptionsSettings, ISetUnitsService setUnitsService, IPreferenceResolver preferenceResolver)
			: base(localSettings, settingsRouter, ifitApi, televisionTunerService, wolfAnalytics, setUnitsService)
		{
			try
			{
				this.closedCaptionsSettings = closedCaptionsSettings;
				bool isMetric = preferenceResolver.IsMetric;
				MinimumMaxTreadmillSpeed = (isMetric ? 6 : 4);
				MaximumMaxTreadmillSpeed = (isMetric ? 24 : 15);
				RoundingStep = (isMetric ? WorkoutScalingSettings.MaxKphRoundingStep : WorkoutScalingSettings.MaxMphRoundingStep);
				PopulateMaxTreadmillOptions();
				UpdateWithUserSettings(null);
				personalTrainingSettings?.UserSettingsRefreshed.SubscribeWithErrorLogging(UpdateWithUserSettings);
				IsBuiltIn.Value = deviceInfo.IsBuiltIn;
				StreetViewEnabled.Value = localSettings.MapCycleViews.HasFlag(MapView.StreetView);
				MapViewEnabled.Value = localSettings.MapCycleViews.HasFlag(MapView.Map);
				SatelliteViewEnabled.Value = localSettings.MapCycleViews.HasFlag(MapView.Satellite);
				InitializeInterval(WarmupData, SelectedWarmup, workoutSettings.WarmUpSeconds / 60);
				SelectedWarmup.Changed += OnWarmupChanged;
				ShowSlidersEnabled.Value = workoutSettings.ShowSliders;
				selectedCaptionLanguageChangedSubscription = ((INotifyChange)SelectedCaptionLanguage).WeakSubscribe("Changed", (EventHandler)OnCaptionLanguageChanged);
				ShowSliders.Value = currentConsoleService.CurrentConsoleType != ConsoleType.Rower && !currentConsoleService.IsBuiltinClub && !deviceInfo.IsStrengthMirror && !deviceInfo.UseHeadlessBikeTheme;
				WorkoutClosedCaptionsTitle.Value = Wolf.Core.Resources.AppStrings.workout_closed_captions;
				TvClosedCaptionsTitle.Value = Wolf.Core.Resources.AppStrings.tv_closed_captions_default;
				ShowSliders.Value = currentConsoleService.CurrentConsoleType != ConsoleType.Rower && !currentConsoleService.IsBuiltinClub && !deviceInfo.IsStrengthMirror;
				ShowWarmupSeparator.Value = ShowSliders.Value || ShowQuality.Value || televisionTunerService.IsAvailable == true;
				SelectedMaxTreadmillSpeed.Changed += OnMaxTreadmillSpeedChanged;
				if (DashboardNonConnectedUtils.GetMockTypeFromConsole(currentConsoleService) != MockType.Strength)
				{
					EnableActivePulseSettings(workoutFeatureService);
					EnableSmartAdjustSettings(workoutFeatureService);
				}
				ShowMaxTreadmillSpeed.Value = ShouldShowMaxTreadmillSpeed();
				SetPulseText();
				InitializeCaptionLanguages(CaptionLanguagesData).SafeFireAndForget(continueOnCapturedContext: false, InitializeCaptionLanguagesException);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void InitializeCaptionLanguagesException(Exception ex)
		{
			if (ex.GetType() == typeof(iFit.Api.Support.ConnectivityException))
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.settings_sync_error, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok, (Action)DoClose, (Action)null, false, true, "", (TaskCompletionSource<object>)null, ErrorCode.StartingWorkoutFetchUserSettingsFailed.HumanReadable(), true, true);
			}
		}

		private void SetPulseText()
		{
			IConsoleInfo consoleInfo = currentConsoleService?.Console?.ConsoleInfo;
			string newValue = "";
			string newValue2 = "";
			if (consoleInfo != null)
			{
				if (consoleInfo.CanSetKph && consoleInfo.CanSetIncline)
				{
					newValue = Wolf.Core.Resources.AppStrings.inworkout_settings_speed_and_incline;
					newValue2 = Wolf.Core.Resources.AppStrings.inworkout_settings_speed_or_incline;
				}
				else if (consoleInfo.CanSetKph)
				{
					newValue2 = (newValue = Wolf.Core.Resources.AppStrings.inworkout_settings_speed);
				}
				else if (consoleInfo.CanSetResistance || consoleInfo.CanSetGear)
				{
					newValue2 = (newValue = Wolf.Core.Resources.AppStrings.inworkout_settings_resistance);
				}
				SmartHRtrainingViewDescription.Value = Wolf.Core.Resources.AppStrings.inworkout_settings_smart_hr_description.Replace("{0}", newValue);
				SmartAdjustViewDescription.Value = Wolf.Core.Resources.AppStrings.inworkout_settings_smartadjust_description.Replace("{0}", newValue2);
			}
		}

		private bool ShouldShowMaxTreadmillSpeed()
		{
			bool flag = currentConsoleService.CurrentConsoleType?.IsAerobicMachine() ?? false;
			if (!(currentConsoleService.Console is NonconnectedStrengthFitnessConsole))
			{
				return !flag;
			}
			return false;
		}

		public async Task Init()
		{
			await InitializeMaxTreadmillSpeed().ConfigureAwait(continueOnCapturedContext: false);
			IsLoaded.Value = true;
		}

		private void InitializeInterval(ObservableCollection<WorkoutIntervalSpinnerModel> model, INC<WorkoutIntervalSpinnerModel> current, int currentMinutes)
		{
			model.Add(new WorkoutIntervalSpinnerModel(0, 1));
			model.Add(new WorkoutIntervalSpinnerModel(1, 3));
			model.Add(new WorkoutIntervalSpinnerModel(2, 5));
			foreach (WorkoutIntervalSpinnerModel item in model)
			{
				if (item.Minutes == currentMinutes)
				{
					current.Value = item;
					return;
				}
			}
			current.Value = model[1];
		}

		private async Task InitializeCaptionLanguages(ObservableCollection<CaptionLanguageSpinnerModel> languageModelsCollection)
		{
			if (!(featureFlagManager?.IsFeatureEnabled(FeatureFlags.ClosedCaptioningEnabled) ?? false) || (base.IsStrengthMirror && !featureFlagManager.IsFeatureEnabled(FeatureFlags.ClosedCaptioningMirrorEnabled)))
			{
				ClosedCaptionsFeatureEnabled.Value = false;
				return;
			}
			IList<ClosedCaptionLanguage> closedCaptionsLanguages = closedCaptionsSettings.ClosedCaptionsLanguages;
			if (closedCaptionsLanguages == null)
			{
				Log.Warn("ClosedCaptions", "languages shouldn't be null.");
				SelectedCaptionLanguage.Value = null;
				ClosedCaptionsFeatureEnabled.Value = false;
				return;
			}
			for (int i = 0; i < closedCaptionsLanguages.Count; i++)
			{
				ClosedCaptionLanguage language = closedCaptionsLanguages[i];
				CaptionLanguageSpinnerModel item = new CaptionLanguageSpinnerModel(i, language);
				languageModelsCollection.Add(item);
			}
			ClosedCaptionLanguage preferredLangauge = await closedCaptionsSettings.GetPreferredLanguage().ConfigureAwait(continueOnCapturedContext: false);
			SelectedCaptionLanguage.Value = ((preferredLangauge == null) ? languageModelsCollection.FirstOrDefault() : languageModelsCollection.FirstOrDefault((CaptionLanguageSpinnerModel model) => model.Language.LanguageCode == preferredLangauge.LanguageCode));
			ClosedCaptionsFeatureEnabled.Value = SelectedCaptionLanguage != null;
		}

		private void OnWarmupChanged(object sender, EventArgs e)
		{
			workoutSettings.WarmUpSeconds = SelectedWarmup.Value.Minutes * 60;
		}

		private void OnCaptionLanguageChanged(object sender, EventArgs e)
		{
			if (SelectedCaptionLanguage?.Value?.Language != null)
			{
				closedCaptionsSettings.SavePreferredLanguage(SelectedCaptionLanguage.Value.Language).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		[DependsOn(new string[] { "StreetViewEnabled" })]
		private void StreetViewUpdate()
		{
			if (!AreTwoCyclesSelected())
			{
				StreetViewEnabled.Value = true;
			}
			else if (StreetViewEnabled.Value)
			{
				localSettings.MapCycleViews |= MapView.StreetView;
			}
			else
			{
				localSettings.MapCycleViews &= ~MapView.StreetView;
			}
		}

		[DependsOn(new string[] { "MapViewEnabled" })]
		private void MapViewUpdate()
		{
			if (!AreTwoCyclesSelected())
			{
				MapViewEnabled.Value = true;
			}
			else if (MapViewEnabled.Value)
			{
				localSettings.MapCycleViews |= MapView.Map;
			}
			else
			{
				localSettings.MapCycleViews &= ~MapView.Map;
			}
		}

		[DependsOn(new string[] { "SatelliteViewEnabled" })]
		private void SatelliteViewUpdate()
		{
			if (!AreTwoCyclesSelected())
			{
				SatelliteViewEnabled.Value = true;
			}
			else if (SatelliteViewEnabled.Value)
			{
