		public bool AreTwoCyclesSelected()
		{
			int num = new bool[3] { StreetViewEnabled.Value, MapViewEnabled.Value, SatelliteViewEnabled.Value }.Count((bool x) => x);
			if (num < 2)
			{
				Message.Value = Wolf.Core.Resources.AppStrings.settings_map_view_need_two_cycles;
				return false;
			}
			return true;
		}

		[DependsOn(new string[] { "ShowSlidersEnabled" })]
		private void ShowSlidersValueUpdated()
		{
			workoutSettings.ShowSliders = ShowSlidersEnabled.Value;
		}

		[DependsOn(new string[] { "SmartAdjustEnabled" })]
		private void ToggleSmartAdjust()
		{
			if (!SmartAdjustEnabled.Value && SmartHRtrainingViewEnabled.Value)
			{
				SmartHRtrainingViewClicked.Execute(null);
			}
			personalTrainingSettings.SmartAdjustEnabled = SmartAdjustEnabled.Value;
		}

		[DependsOn(new string[] { "SmartHRtrainingViewEnabled" })]
		private void DoSwapHRZonesEnabled()
		{
			if (SmartHRtrainingViewEnabled.Value && !SmartAdjustEnabled.Value)
			{
				SmartAdjustViewClicked.Execute(null);
			}
			personalTrainingSettings.ActivePulseEnabled = SmartHRtrainingViewEnabled.Value;
		}

		public override void Dispose()
		{
