			SelectedWarmup.Changed -= OnWarmupChanged;
			selectedCaptionLanguageChangedSubscription.Dispose();
			selectedCaptionLanguageChangedSubscription = null;
			SelectedMaxTreadmillSpeed.Changed -= OnMaxTreadmillSpeedChanged;
			WarmupData?.Clear();
			ObservableCollection<SpeedSpinnerModel> maxTreadmillSpeedData = MaxTreadmillSpeedData;
