		private void EnableSmartAdjustSettings(IWorkoutFeatureService workoutFeatureService)
		{
			ConsoleType? consoleType = currentConsoleService?.ActiveConsole?.ConsoleInfo?.MachineType;
			if (consoleType.HasValue)
			{
				SmartAdjustFeatureEnabled = workoutFeatureService.IsSmartAdjustAvailable(consoleType.Value);
			}
		}

		private void EnableActivePulseSettings(IWorkoutFeatureService workoutFeatureService)
		{
			ConsoleType? consoleType = currentConsoleService?.ActiveConsole?.ConsoleInfo?.MachineType;
			if (consoleType.HasValue)
			{
				ActivePulseFeatureEnabled = workoutFeatureService.IsActivePulseAvailable(consoleType.Value);
			}
		}

		private void PopulateMaxTreadmillOptions()
		{
			double num = (double)(MaximumMaxTreadmillSpeed - MinimumMaxTreadmillSpeed) * (1.0 / RoundingStep) + 1.0;
			for (int i = 0; (double)i < num; i++)
			{
				SpeedSpinnerModel item = new SpeedSpinnerModel(i, (double)MinimumMaxTreadmillSpeed + (double)i * RoundingStep, preferenceResolver.IsMetric);
				MaxTreadmillSpeedData.Add(item);
			}
			SelectedMaxTreadmillSpeed.Value = MaxTreadmillSpeedData.Last();
		}

		private async Task InitializeMaxTreadmillSpeed()
		{
			try
			{
				double maxTreadmillMPS = (await ifitApi.CurrentlyAuthenticatedUser.GetWorkoutScalingSettings(ifitApi)).MaxTreadmillMPS;
				bool isMetric = preferenceResolver.IsMetric;
				double num = UnitUtil.EnsureMph(SpeedUnit.Mps, maxTreadmillMPS);
				if (isMetric)
				{
					num = UnitUtil.EnsureKph(SpeedUnit.Mps, maxTreadmillMPS);
				}
				double num2 = 1.0 / RoundingStep;
				num = Math.Round(num * num2) / num2;
				double val = (num - (double)MinimumMaxTreadmillSpeed) * num2;
				double b = (double)(MaximumMaxTreadmillSpeed - MinimumMaxTreadmillSpeed) * num2;
				int num3 = (int)val.Clamp(0.0, b);
				if (MaxTreadmillSpeedData.CountSafe() > 0 && num3 < MaxTreadmillSpeedData.CountSafe())
				{
					SelectedMaxTreadmillSpeed.Value = MaxTreadmillSpeedData[num3];
				}
			}
			catch (Exception ex)
			{
				Log.Error("Settings", "Unable to retrieve Max Treadmill Speed: " + ex.Message, ex);
			}
		}

		private void OnMaxTreadmillSpeedChanged(object sender, EventArgs e)
		{
			SaveMaxTreadmillSpeed();
		}

		private async Task SaveMaxTreadmillSpeed()
		{
			if (SelectedMaxTreadmillSpeed.Value == null)
			{
				return;
			}
			try
			{
				double maxTreadmillMPS = (preferenceResolver.IsMetric ? UnitUtil.EnsureMps(SpeedUnit.Kph, SelectedMaxTreadmillSpeed.Value.Speed) : UnitUtil.EnsureMps(SpeedUnit.Mph, SelectedMaxTreadmillSpeed.Value.Speed));
				ifitApi.CurrentlyAuthenticatedUser.WorkoutScalingSettings.MaxTreadmillMPS = maxTreadmillMPS;
				await ifitApi.CurrentlyAuthenticatedUser.UpdateWorkoutScalingSettings(ifitApi);
			}
			catch (Exception ex)
			{
				Log.Error("Settings", ex.Message);
			}
		}

