	public class SettingsRestingHRViewModel : BaseViewModel
	{
		public const int DefaultRestHR = 65;

		private const int MinimumRestHR = 30;

		private const int MaximumRestHR = 120;

		private readonly IIfitApiService apiService;

		public readonly INC<HeartRateSpinnerModel> SelectedHeartRateRest = new NC<HeartRateSpinnerModel>();

		public readonly INC<int> SelectedHeartRateRestIndex = new NC<int>();

		public readonly ObservableCollection<HeartRateSpinnerModel> HeartRateRestData = new ObservableCollection<HeartRateSpinnerModel>();

		[DependsOn(new string[] { "SelectedHeartRateRest" })]
		public string SelectedRestHeartRateText => SelectedHeartRateRest?.Value?.Caption ?? $"{65} BPM";

		public ICommand ResetRestingToDefaultCommand => new MvxCommand(DoResetRestingHRWithDialog);

		public SettingsRestingHRViewModel(ILocalSettings localSettings, IIfitApiService apiService)
			: base(localSettings)
		{
			try
			{
				this.apiService = apiService;
				PopulateHRRestOptions();
				SelectedHeartRateRest.Changed += SelectedHeartRateRest_Changed;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void SelectedHeartRateRest_Changed(object sender, EventArgs e)
		{
			SaveRestingHeartRate();
		}

		public void Init(UserHeartRateSettings settings)
		{
			SelectedHeartRateRest.Value = HeartRateRestData?.FirstOrDefault((HeartRateSpinnerModel md) => md.Bpm == settings.RestingHeartRate);
		}

		private async Task SaveRestingHeartRate()
		{
			if (SelectedHeartRateRest.Value == null)
			{
				return;
			}
			try
			{
				User user = await User.GetMe(apiService);
				await user.GetHeartRateSettings(apiService);
				if (SelectedHeartRateRest.Value.Bpm > user.HeartRateSettings.MaxHeartRate)
				{
					ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.invalid_resting_hr_title, Wolf.Core.Resources.AppStrings.invalid_resting_hr_message);
					DoSetRestingHR(user.HeartRateSettings.RestingHeartRate.ToString());
				}
				else
				{
					user.HeartRateSettings.RestingHeartRate = SelectedHeartRateRest.Value.Bpm;
					await user.UpdateHeartRateSettings(apiService);
				}
			}
			catch (Exception ex)
			{
				Log.Error("Settings", ex.Message);
			}
		}

		private void PopulateHRRestOptions()
		{
			(from x in Enumerable.Range(30, 91)
				select new HeartRateSpinnerModel(x - 30, x)).DoForEach(HeartRateRestData.Add);
			DoResetRestingHR();
		}

		private void ConfirmResetRestingHR(Action confirmAction)
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.resting_heartrate_reset_dialog_title, Wolf.Core.Resources.AppStrings.resting_heartrate_dialog_message, confirmAction, Wolf.Core.Resources.AppStrings.no.ToUpper(), Wolf.Core.Resources.AppStrings.yes.ToUpper());
		}

		public void DoResetRestingHRWithDialog()
		{
			ConfirmResetRestingHR(ResetRestingHeartRate);
		}

		public void ResetRestingHeartRate()
		{
			SelectedHeartRateRest.Value = HeartRateRestData[35];
			SelectedHeartRateRestIndex.Value = HeartRateRestData.IndexOf(SelectedHeartRateRest.Value);
		}

		public void DoResetRestingHR()
		{
			SelectedHeartRateRest.Value = HeartRateRestData[35];
		}

		public void DoSetRestingHR(string bpm)
		{
			if (bpm != null && int.TryParse(bpm, out var result))
			{
				int num = result - 30;
				int num2 = 90;
				if (num <= num2 && num >= 0)
				{
					SelectedHeartRateRest.Value = HeartRateRestData[num];
				}
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			SelectedHeartRateRest.Changed -= SelectedHeartRateRest_Changed;
			UnregisterChangeHandlers();
		}

