	public class FirmwareUpdatingDialogViewModel : BaseViewModel
	{
		public readonly INC<bool> CancellationPermitted = new NC<bool>();

		public readonly INC<bool> IndeterminateProgressShown = new NC<bool>();

		public readonly INC<float> DeterminateProgress = new NC<float>();

		public readonly INC<int> MessageId = new NC<int>();

		public readonly INC<string> ProgressMessage = new NC<string>();

		[DependsOn(new string[] { "IndeterminateProgressShown" })]
		public bool DeterminateProgressShown => !IndeterminateProgressShown.Value;

		public ICommand Cancel => new MvxCommand(DoCancel);

		public FirmwareUpdatingDialogViewModel(ILocalSettings localSettings)
			: base(localSettings)
		{
			try
			{
				ProgressMessage.Value = Wolf.Core.Resources.AppStrings.downloading_firmware_title_text;
				Task.Run((Func<Task>)TestLoop);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task TestLoop()
		{
			while (true)
			{
				if (IndeterminateProgressShown.Value)
				{
					CancellationPermitted.Value = true;
					IndeterminateProgressShown.Value = false;
					DeterminateProgress.Value = 0f;
					while (DeterminateProgress.Value < 1f)
					{
						DeterminateProgress.Value += 0.05f;
						await Task.Delay(100);
					}
				}
				else
				{
					CancellationPermitted.Value = false;
					IndeterminateProgressShown.Value = true;
				}
				await Task.Delay(3000);
			}
		}

		private void DoCancel()
		{
			DoClose();
		}

