namespace Wolf.Core.ViewModels.Settings.Feedback
{
	public class FeedbackViewModel : BaseViewModel
	{
		public readonly INC<string> SendFeedbackMessage = new NC<string>();

		public readonly INC<bool> ShowActivityIndicator = new NC<bool>();

		public readonly BooleanCycle DidSendSuccessfully = new BooleanCycle();

		private readonly MvxInteraction<object> userRefreshed = new MvxInteraction<object>();

		private readonly MvxInteraction<object> sendInProgress = new MvxInteraction<object>();

		private readonly IIfitApiService ifitApi;

		private bool sendStarted;

		private readonly IFeedbackService feedbackService;

		private CancellationTokenSource cancellationTokenSource;

		public FeedbackInfo FeedbackInfo { get; private set; }

		public IMvxInteraction<object> UserRefreshed => userRefreshed;

		public IMvxInteraction<object> SendInProgress => sendInProgress;

		public string SupplementalCrashLogReport { get; set; }

		[DependsOn(new string[] { "ShowActivityIndicator" })]
		public bool CanSendFeedback
		{
			get
			{
				if (!ShowActivityIndicator.Value)
				{
					return !sendStarted;
				}
				return false;
			}
		}

		public DateTime MaxPurchaseDate => DateTime.Today;

		public DateTime MinPurchaseDate => DateTime.UnixEpoch;

		public ICommand EditDate => new MvxCommand(DoOpenDatePickerDialog);

		public string EmailHintStr => Wolf.Core.Resources.AppStrings.feedbackview_email_address_hint + "*";

		public FeedbackViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IFeedbackService feedbackService)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.feedbackService = feedbackService;
				ShowActivityIndicator.Value = false;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			FeedbackInfo = await feedbackService.GetDefaultFeedbackInfo();
			userRefreshed.Raise(FeedbackInfo.User);
			RegisterForStartButton();
		}

		private void DoOpenDatePickerDialog()
		{
			DatePickerDialogViewModel.NavObj parameterValuesObject = new DatePickerDialogViewModel.NavObj
			{
				Year = DateTime.Today.Year,
				Month = DateTime.Today.Month,
				Day = DateTime.Today.Day,
				MaxDate = MaxPurchaseDate,
				MinDate = MinPurchaseDate
			};
			ShowViewModel<FeedbackViewModel>(parameterValuesObject, ShireViewParams.DialogView<DatePickerDialogViewModel>());
		}

		public async Task DoSend(FeedbackInfo info)
		{
			if (string.IsNullOrWhiteSpace(info.Description) || !IsEmailValid(info.EmailAddress) || !CanSendFeedback)
			{
				return;
			}
			ShowActivityIndicator.Value = true;
			sendStarted = true;
			sendInProgress.Raise(sendStarted);
			cancellationTokenSource?.Dispose();
			cancellationTokenSource = new CancellationTokenSource();
			CancellationToken cancellationToken = cancellationTokenSource.Token;
			try
			{
				if (info.User == null && ifitApi.HasLoggedInUser)
				{
					try
					{
						info.User = await User.GetMe(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
					}
					catch (Exception ex)
					{
						Log.Error("Api", "Error getting current user", ex.GetBaseException());
					}
				}
				if (await feedbackService.SendFeedback(info, cancellationToken, SupplementalCrashLogReport).ConfigureAwait(continueOnCapturedContext: false))
				{
					SendFeedbackMessage.Value = Wolf.Core.Resources.AppStrings.feedback_success_message;
					DidSendSuccessfully.SetTrue();
				}
				else
				{
					SendFeedbackMessage.Value = Wolf.Core.Resources.AppStrings.feedback_error_sending;
					sendStarted = false;
				}
			}
			catch (TaskCanceledException)
			{
			}
			catch (ApiException ex3)
			{
				sendStarted = false;
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.feedback_error_sending, $"{Wolf.Core.Resources.AppStrings.error_code}: {ex3.StatusCode.BackgroundErrorCode()}");
			}
			catch (Exception ex4)
			{
				sendStarted = false;
				Log.Error("Api", "Error sending feedback", ex4.GetBaseException());
				SendFeedbackMessage.Value = Wolf.Core.Resources.AppStrings.feedback_error_sending;
			}
			finally
			{
				ShowActivityIndicator.Value = false;
			}
		}

		public bool IsEmailValid(string email)
		{
			return !string.IsNullOrWhiteSpace(email);
