				SelectedMaxWorkoutTime.Changed -= OnMaxWorkoutTimeChanged;
				SelectedMaxWorkoutTime.Changed += OnMaxWorkoutTimeChanged;
				InitializeSpinnerModel(MaxPauseTimeData, SelectedMaxPauseTime, settingsRouter.GetPauseTimeMinutes(), 1, 15);
				SelectedMaxPauseTime.Changed -= OnMaxPauseTimeChanged;
				SelectedMaxPauseTime.Changed += OnMaxPauseTimeChanged;
