		private void InitializeSpinnerModel(ObservableCollection<WorkoutIntervalSpinnerModel> model, INC<WorkoutIntervalSpinnerModel> currentModel, int currentValue, int minValue = 0, int maxValue = 0, int increment = 1)
		{
			for (int i = 0; i <= (maxValue - minValue) / increment; i++)
			{
				int num = i;
				int minutes = increment * num + minValue;
				model.Add(new WorkoutIntervalSpinnerModel(num, minutes));
			}
			foreach (WorkoutIntervalSpinnerModel item in model)
			{
				if (item.Minutes == currentValue)
				{
					currentModel.Value = item;
					return;
				}
			}
			currentModel.Value = model.LastOrDefault();
		}

		private void OnMaxWorkoutTimeChanged(object sender, EventArgs e)
		{
			clubLocalSettings.ClubMaxWorkoutTimeMinutes = SelectedMaxWorkoutTime.Value.Minutes;
		}

		private void OnMaxPauseTimeChanged(object sender, EventArgs e)
		{
			settingsRouter.SetPauseTimeMinutes(SelectedMaxPauseTime.Value.Minutes, FromClubOwnerSettings.Value);
		}

		public void UpdateCurrentTimeZone(AvailableTimeZone timezone = null)
		{
			if (timezone != null)
			{
				CurrentTimeZone.Value = timezone.Text;
				return;
			}
			string currentTimeZone = timeZoneService.GetCurrentTimeZone();
			CurrentTimeZone.Value = ((!string.IsNullOrWhiteSpace(currentTimeZone)) ? currentTimeZone : Wolf.Core.Resources.AppStrings.select_timezone_title);
		}

