		private readonly IIpcVersionInfo versionInfo;

		private readonly ISettingsRouter settingsRouter;

		private IDisposable stateChangeSub;

		private IDisposable timeoutSub;

		private IConsoleInfo ConsoleInfo => currentConsoleService?.Console?.ConsoleInfo;

		public EquipmentInfoModel MachineType { get; set; }

		public EquipmentInfoModel AttachedMachineType { get; set; }

		public EquipmentInfoModel BuiltInType { get; set; }

		public EquipmentInfoModel PartNo { get; set; }

		public EquipmentInfoModel AttachedPartNo { get; set; }

		public EquipmentInfoModel Version { get; set; }

		public EquipmentInfoModel BrainboardSerialNumber { get; set; }

		public EquipmentInfoModel MaxVolume { get; set; }

		public EquipmentInfoModel MaxResistance { get; set; }

		public EquipmentInfoModel MaxStrideLength { get; set; }

		public EquipmentInfoModel MaxIncline { get; set; }

		public EquipmentInfoModel MinIncline { get; set; }

		public EquipmentInfoModel MaxMph { get; set; }

		public EquipmentInfoModel MaxKph { get; set; }

		public EquipmentInfoModel NumberOfWorkouts { get; set; }

		public bool IsBuiltIn => deviceInfo?.IsBuiltIn ?? false;

		public MachineInfoViewModel(ILocalSettings localSettings, IIpcVersionInfo versionInfo, ISettingsRouter settingsRouter, ICurrentConsoleService currentConsoleService)
			: base(localSettings)
		{
			try
			{
				this.versionInfo = versionInfo;
				this.settingsRouter = settingsRouter;
				IConsoleInfo consoleInfo = ConsoleInfo;
				string not_available = Wolf.Core.Resources.AppStrings.not_available;
				double? num = consoleInfo?.MaxKph;
				double? num2 = ((consoleInfo == null || !consoleInfo.CanSetGear) ? ((consoleInfo != null && consoleInfo.CanSetResistance) ? consoleInfo?.MaxResistanceLevel : ((double?)null)) : ((double?)consoleInfo?.MaxGear));
				string text = ((consoleInfo != null) ? consoleInfo.FirmwareVersion : not_available);
				string text2 = ((consoleInfo == null || consoleInfo.BrainboardSerialNumber == null || consoleInfo.BrainboardSerialNumber == "N/A") ? not_available : consoleInfo.BrainboardSerialNumber);
				string value;
				string value2;
				if (consoleInfo?.CanSetIncline == true)
				{
					value = consoleInfo.MaxIncline.ToString();
					value2 = consoleInfo.MinIncline.ToString();
				}
				else
				{
					value = not_available;
					value2 = not_available;
				}
				MachineType = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_machine_type, currentConsoleService?.Console.ToMachineTypeLegalString() ?? not_available);
				AttachedMachineType = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_attached_machine_type, currentConsoleService?.AttachedConsole.ToDisplayName() ?? not_available);
				BuiltInType = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_built_in_type, deviceInfo?.BuiltInType.ToFriendlyString());
				PartNo = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_part_number, deviceInfo?.SpoofedSoftwareNumber?.ToString() ?? consoleInfo?.PartNumber.ToString() ?? not_available);
				AttachedPartNo = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_attached_part_number, deviceInfo?.SpoofedSoftwareNumber?.ToString() ?? currentConsoleService?.AttachedConsole?.ConsoleInfo?.PartNumber.ToString() ?? not_available);
				Version = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_version, text ?? not_available);
				BrainboardSerialNumber = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.brainboard_serial_number, text2 ?? not_available);
				MaxVolume = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_max_volume, not_available);
				MaxResistance = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_max_resistance, num2?.ToString() ?? not_available);
				MaxStrideLength = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_max_stride, not_available);
				MaxIncline = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_max_incline, value);
				MinIncline = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_min_incline, value2);
				MaxMph = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_max_mph, num.HasValue ? UnitUtil.EnsureMph(SpeedUnit.Kph, num.Value, 2).ToString() : not_available);
				MaxKph = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.settings_max_kph, num.HasValue ? num.ToString() : not_available);
				NumberOfWorkouts = new EquipmentInfoModel(Wolf.Core.Resources.AppStrings.number_of_workouts, deviceInfo.NumberOfWorkouts.ToString());
				ConsoleState valueOrDefault = (currentConsoleService?.Console?.LatestBasicInfo?.CurrentState).GetValueOrDefault();
				WhenStateChanged(valueOrDefault);
				stateChangeSub = currentConsoleService?.Console?.WhenStateChanged.Subscribe(async delegate(StateChange change)
				{
					await WhenStateChangedAsync(change.Current);
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void WhenStateChanged(ConsoleState state)
		{
			Task.Run(async delegate
			{
				await WhenStateChangedAsync(state);
			}).Wait();
		}

		private async Task WhenStateChangedAsync(ConsoleState state)
		{
			DisposeTimeoutSubscription();
			switch (state)
			{
			case ConsoleState.Error:
			{
				IConsoleError consoleError = await currentConsoleService.Console.GetConsoleErrorAsync();
				CurrentErrorTitle.Value = consoleError.UserFriendlyLocalizedDescription;
				CurrentErrorValue.Value = string.Empty;
				if (consoleError is ITimedError timedError)
				{
					timeoutSub = timedError.Timeout.Subscribe(WhenTimeoutChanged);
				}
				return;
			}
			case ConsoleState.SafetyKeyRemoved:
				CurrentErrorTitle.Value = Wolf.Core.Resources.AppStrings.console_error_DMK;
				CurrentErrorValue.Value = string.Empty;
				return;
			}
			Mvx.TryResolve<IConsoleErrorHandler>(out var service);
			PastConsoleError? pastConsoleError = service?.GetLastConsoleError();
			if (pastConsoleError?.Error != null)
			{
				CurrentErrorTitle.Value = pastConsoleError.Value.Error.UserFriendlyLocalizedDescription;
				CurrentErrorValue.Value = pastConsoleError.Value.Timestamp.ToString("g");
			}
			else
			{
				CurrentErrorTitle.Value = Wolf.Core.Resources.AppStrings.console_error_none;
				CurrentErrorValue.Value = string.Empty;
			}
		}

		private void WhenTimeoutChanged(TimeSpan timeout)
		{
			CurrentErrorValue.Value = Wolf.Core.Resources.AppStrings.console_error_timeout.Replace("{timeout}", timeout.ToString("m\\:ss"));
		}

		public async Task Init()
		{
			await UpdateTimeValues().ConfigureAwait(continueOnCapturedContext: false);
			await UpdateDistanceValues().ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task UpdateTimeValues()
		{
			if (currentConsoleService?.Console == null)
			{
				TotalTimeValue.Value = Wolf.Core.Resources.AppStrings.not_available;
				return;
			}
			double num = Math.Round(TimeSpan.FromSeconds(await facadeFactoryDependencies.TotalTimeFacade.GetTotalTimeAsync().ConfigureAwait(continueOnCapturedContext: false)).TotalHours);
			TotalTimeValue.Value = num.ToString(CultureInfo.CurrentCulture) + " " + Wolf.Core.Resources.AppStrings.hrs.ToUpper();
		}

		private async Task UpdateDistanceValues()
		{
			bool isMetric = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
			OdometerTitle.Value = (isMetric ? Wolf.Core.Resources.AppStrings.number_of_kilometers : Wolf.Core.Resources.AppStrings.number_of_miles);
			if (currentConsoleService?.Console == null)
			{
				OdometerDistance.Value = Wolf.Core.Resources.AppStrings.not_available;
				return;
			}
			double num = await facadeFactoryDependencies.MotorTotalDistanceFacade.GetMotorTotalDistanceAsync().ConfigureAwait(continueOnCapturedContext: false);
			double num2 = (isMetric ? (num / 1000.0) : UnitUtil.EnsureMph(SpeedUnit.Kph, num / 1000.0, 2));
			OdometerDistance.Value = $"{num2} {(isMetric ? Wolf.Core.Resources.AppStrings.km : Wolf.Core.Resources.AppStrings.mi).ToUpper()}";
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
			MacAddress.Value = Wolf.Core.Resources.AppStrings.loading;
			ConsoleGuid.Value = Wolf.Core.Resources.AppStrings.loading;
			if (IsBuiltIn)
			{
				await FetchMacAddress().ConfigureAwait(continueOnCapturedContext: false);
				await LoadConsoleGuid().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task FetchMacAddress()
		{
			await versionInfo.GetVersions().ConfigureAwait(continueOnCapturedContext: false);
			if (!string.IsNullOrWhiteSpace(versionInfo.MacAddress))
			{
				MacAddress.Value = versionInfo.MacAddress;
			}
		}

		private async Task LoadConsoleGuid()
		{
			if (Mvx.TryResolve<IConsoleUpdateInfo>(out var service))
			{
				Guid guid = (await service.GetInfo()).Guid;
				if (guid != Guid.Empty)
				{
					ConsoleGuid.Value = guid.ToString();
				}
			}
		}

		public override void Start()
		{
			base.Start();
			if (ConsoleInfo == null)
			{
				ShowUSBError();
			}
		}

		private void DisposeTimeoutSubscription()
		{
			timeoutSub?.Dispose();
			timeoutSub = null;
		}

		public override void Dispose()
		{
			base.Dispose();
			DisposeTimeoutSubscription();
			stateChangeSub?.Dispose();
			stateChangeSub = null;
			UnregisterChangeHandlers();
		}

