	public class ConnectedAppPermissionsViewModel : BaseInternetConnectionViewModel
	{
		private readonly IConnectedAppsCollection connectedAppsCollection;

		private readonly IMvxMessenger messenger;

		private IConnectedAppContainer connectedAppContainer;

		private bool isDisconnectAction;

		private bool isDisconnecting;

		private IDisposable whenIsUpdatingPermissionsChangedSub;

		public readonly MvxObservableCollection<ConnectedAppPermissionItemModel> ConnectedAppPermissionsItems = new MvxObservableCollection<ConnectedAppPermissionItemModel>();

		public ICommand ExecuteAction { get; }

		public ICommand BackButtonAction { get; }

		public override string LogTag => GetType().Name;

		public string ActionButtonText
		{
			get
			{
				if (!isDisconnectAction)
				{
					return Wolf.Core.Resources.AppStrings.settings_connected_apps_done_button;
				}
				if (connectedAppContainer.App == ConnectedApp.AppleHealth)
				{
					return Wolf.Core.Resources.AppStrings.settings_connected_apps_open_settings_button;
				}
				return Wolf.Core.Resources.AppStrings.settings_connected_apps_disconnect_button;
			}
		}

		public bool IsAppleHealth => connectedAppContainer.App == ConnectedApp.AppleHealth;

		public string ImageRef => connectedAppContainer?.LargeImageReference;

		public string DescriptionText => connectedAppContainer?.PermissionDescriptionText;

		public bool HasDescriptionText => !string.IsNullOrEmpty(DescriptionText);

		public ConnectedAppPermissionsViewModel(ILocalSettings localSettings, IFailedUploadMonitor failedUploadMonitor, IConnectedAppsCollection connectedAppsCollection, IMvxMessenger messenger)
			: base(localSettings, failedUploadMonitor)
		{
			try
			{
				this.connectedAppsCollection = connectedAppsCollection;
				this.messenger = messenger;
				ExecuteAction = new MvxAsyncCommand(DoExecuteActionAsync);
				BackButtonAction = new MvxCommand(DoBackButtonNavigationAction);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(ConnectedAppPermissionsNavObject navObject)
		{
			try
			{
				isDisconnectAction = navObject.IsDisconnectAction;
				connectedAppContainer = connectedAppsCollection.ConnectedApps.First((IConnectedAppContainer container) => container.App == navObject.App);
				IsLoading.Value = connectedAppContainer.IsUpdatingPermissions;
				whenIsUpdatingPermissionsChangedSub = connectedAppContainer.WhenIsUpdatingPermissionsChanged.Subscribe(delegate(bool isUpdatingPermissions)
				{
					IsLoading.Value = isUpdatingPermissions;
				});
				foreach (KeyValuePair<ConnectedAppPermission, bool> permission in connectedAppContainer.Permissions)
				{
					ConnectedAppPermissionItemModel item = new ConnectedAppPermissionItemModel(connectedAppContainer.DisplayName, permission.Key, permission.Value, connectedAppContainer.App);
					ConnectedAppPermissionsItems.Add(item);
				}
			}
			catch (Exception ex)
			{
				Log.Error(LogTag, "Init Error: " + ex.Message, ex);
			}
		}

		private void DoBackButtonNavigationAction()
		{
			if (!isDisconnecting)
			{
				base.CloseViewModel.Execute();
			}
		}

		private async Task DoExecuteActionAsync()
		{
			if (!isDisconnectAction)
			{
				base.CloseViewModel.Execute();
			}
			else if (!(connectedAppContainer.AuthorizationService is UrlAuthorizationService))
			{
				Log.Trace(LogTag, "DisconnectAsync Disconnecting non URL service");
				await connectedAppContainer.AuthorizationService.DeauthorizeAsync().ConfigureAwait(continueOnCapturedContext: false);
			}
			else if (!(await this.ShowSimpleConfirmationDialogAsync(string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_disconnect_title, connectedAppContainer.DisplayName), Wolf.Core.Resources.AppStrings.settings_connected_apps_disconnect_subtitle, null, Wolf.Core.Resources.AppStrings.settings_remove, true, true, "").ConfigureAwait(continueOnCapturedContext: false)))
			{
				Log.Trace(LogTag, "DisconnectAsync User cancelled disconnect");
			}
			else
			{
				await DisconnectAsync().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task DisconnectAsync()
		{
			try
			{
				IsLoading.Value = true;
				isDisconnecting = true;
				connectedAppContainer.IsConnected = false;
				Log.Trace(LogTag, string.Format("{0} Disconnecting {1}", "DisconnectAsync", connectedAppContainer.App));
				messenger.Publish(new ConnectedAppsCollectionUpdatedMessage(this));
				await connectedAppContainer.AuthorizationService.DeauthorizeAsync().ConfigureAwait(continueOnCapturedContext: false);
				base.CloseViewModel.Execute();
			}
			catch (Exception ex)
			{
				string error = string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_failed_to_disconnect_message_template, connectedAppContainer.DisplayName);
				this.ShowError(error);
				Log.Error(LogTag, "DisconnectAsync Error: " + ex.Message, ex);
				connectedAppContainer.IsConnected = true;
				messenger.Publish(new ConnectedAppsCollectionUpdatedMessage(this));
			}
			finally
			{
				IsLoading.Value = false;
				isDisconnecting = false;
			}
		}

		protected override void DoClose()
		{
			whenIsUpdatingPermissionsChangedSub?.Dispose();
			UpdatePermissionsAsync();
			base.DoClose();
		}

		private async Task UpdatePermissionsAsync()
		{
			Dictionary<ConnectedAppPermission, bool> oldPermissions = new Dictionary<ConnectedAppPermission, bool>(connectedAppContainer.Permissions);
			Dictionary<ConnectedAppPermission, bool> dictionary = ConnectedAppPermissionsItems.ToDictionary((ConnectedAppPermissionItemModel item) => item.Permission, (ConnectedAppPermissionItemModel item) => item.IsEnabled.Value);
			if (oldPermissions.SequenceEqual(dictionary))
			{
				return;
			}
			try
			{
				connectedAppContainer.IsUpdatingPermissions = true;
				Log.Trace(LogTag, "UpdatePermissionsAsync - Changing permissions to new values");
				foreach (KeyValuePair<ConnectedAppPermission, bool> item in dictionary)
				{
					connectedAppContainer.Permissions[item.Key] = item.Value;
				}
				await connectedAppContainer.PermissionsService.UpdatePermissionsAsync(dictionary).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception exception)
			{
				string error = string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_failed_to_update_permission_message_template, connectedAppContainer.DisplayName);
				this.ShowError(error);
				Log.Error(LogTag, "Reverting changes of permissions, something went wrong", exception);
				foreach (KeyValuePair<ConnectedAppPermission, bool> item2 in oldPermissions)
				{
					connectedAppContainer.Permissions[item2.Key] = item2.Value;
				}
			}
			finally
			{
				connectedAppContainer.IsUpdatingPermissions = false;
			}
		}

