	public class ConnectedAppsListViewModel : BaseInternetConnectionViewModel
	{
		private readonly CompositeDisposable disposables = new CompositeDisposable();

		private readonly CancellationTokenSource closeCts = new CancellationTokenSource();

		private readonly IIfitApiService apiService;

		private readonly IConnectedAppsCollection connectedAppsCollection;

		private readonly IHardwareInfo hardwareInfo;

		private bool shouldUpdateOnViewShown;

		private bool shouldDisableList = true;

		public readonly INC<User> CurrentUser = new NC<User>();

		public readonly INC<bool> IsLoaded = new NC<bool>();

		public readonly MvxObservableCollection<ConnectedAppsMenuItemModel> ConnectedAppsItemList = new MvxObservableCollection<ConnectedAppsMenuItemModel>();

		public readonly IMvxCommand AppMenuItemSelected;

		public readonly IMvxCommand UpgradeUserClicked;

		public override string LogTag => GetType().Name;

		public bool IsFreeUser
		{
			get
			{
				if (CurrentUser.Value.SubscriptionType == User.SubscriptionTypes.Free)
				{
					INC<User> currentUser = CurrentUser;
					if (currentUser == null)
					{
						return false;
					}
					return currentUser.Value?.IsSecondary == false;
				}
				return false;
			}
		}

		public string FreeUserInfoText => Wolf.Core.Resources.AppStrings.settings_connected_apps_free_user_info_text;

		public string FreeUserTitleInfoText => Wolf.Core.Resources.AppStrings.settings_connected_apps_free_user_title_info_text;

		public string FreeUserUpgradeButtonText => Wolf.Core.Resources.AppStrings.settings_connected_apps_free_user_upgrade_button_text;

		public ConnectedAppsListViewModel(ILocalSettings localSettings, IIfitApiService apiService, IFailedUploadMonitor failedUploadMonitor, IConnectedAppsCollection connectedAppsCollection, IHardwareInfo hardwareInfo, IMvxMessenger messenger)
			: base(localSettings, failedUploadMonitor)
		{
			try
			{
				this.apiService = apiService;
				this.connectedAppsCollection = connectedAppsCollection;
				this.hardwareInfo = hardwareInfo;
				messenger.SubscribeOnMainThread<ConnectedAppsCollectionUpdatedMessage>(OnCollectionUpdatedMessageReceived).DisposeWith(disposables);
				AppMenuItemSelected = new MvxCommand<ConnectedAppsMenuItemModel>(delegate(ConnectedAppsMenuItemModel item)
				{
					item?.ConnectedAppTapped?.Execute(null);
				}, (ConnectedAppsMenuItemModel _) => !IsFreeUser);
				UpgradeUserClicked = new MvxCommand(DoUpgradeUser);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			_ = 1;
			try
			{
				CurrentUser.Value = apiService.CurrentlyAuthenticatedUser;
				RefreshItemList();
				if (!IsFreeUser)
				{
					Task loadStatusesTask = connectedAppsCollection.UpdateAsync(closeCts.Token);
					await Task.WhenAny(Task.Delay(1000), loadStatusesTask).ConfigureAwait(continueOnCapturedContext: false);
					if (!loadStatusesTask.IsCompleted)
					{
						IsLoading.Value = true;
					}
					Log.Trace(LogTag, "Init - Updating list async.");
					await loadStatusesTask.ConfigureAwait(continueOnCapturedContext: false);
					shouldDisableList = false;
					RefreshItemList();
				}
			}
			catch (Exception ex) when (ex.RelatesTo<OperationCanceledException>())
			{
				Log.Trace(LogTag, "Init User cancelled connectedAppsCollection");
			}
			catch (Exception ex2)
			{
				Log.Error(LogTag, ex2.Message);
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (shouldUpdateOnViewShown)
			{
				Log.Trace(LogTag, "OnViewShown - Refreshing connected apps list.");
				RefreshItemList();
				shouldUpdateOnViewShown = false;
			}
		}

		private void OnCollectionUpdatedMessageReceived(ConnectedAppsCollectionUpdatedMessage message)
		{
			if (IsVisible)
			{
				Log.Trace(LogTag, "OnCollectionUpdatedMessageReceived - Refreshing connected apps list.");
				RefreshItemList();
			}
			else
			{
				shouldUpdateOnViewShown = true;
			}
		}

		private void RefreshItemList()
		{
			List<ConnectedAppsMenuItemModel> items = CreateItems().ToList();
			ConnectedAppsItemList.ReplaceWith(items);
		}

		private IEnumerable<ConnectedAppsMenuItemModel> CreateItems()
		{
			foreach (IConnectedAppContainer connectedApp in connectedAppsCollection.ConnectedApps)
			{
				if (!featureFlagManager.IsFeatureEnabled(connectedApp.FeatureFlag))
				{
					Log.Trace(LogTag, string.Format("{0} - {1} is not enabled.", "CreateItems", connectedApp.App));
				}
				else if ((!hardwareInfo.IsAndroid || !connectedApp.IsAndroidActivity) && (!hardwareInfo.IsIos || !connectedApp.IsIosActivity))
				{
					Log.Trace(LogTag, string.Format("{0} - {1} is not enabled on platform. IsAndroid: {2}", "CreateItems", connectedApp.App, hardwareInfo.IsAndroid));
				}
				else if (connectedApp.App != ConnectedApp.AppleHealth || ShouldAddAppleHealthItem(connectedApp))
				{
					yield return new ConnectedAppsMenuItemModel(connectedApp, !IsFreeUser && !shouldDisableList);
				}
			}
		}

		private bool ShouldAddAppleHealthItem(IConnectedAppContainer connectedApp)
		{
			if (IsTablet && !connectedApp.IsConnected)
			{
				Log.Trace(LogTag, "CreateItems - iPadOS doesnt support it, not enabling App.");
				return false;
			}
			string operatingSystemVersion = hardwareInfo.OperatingSystemVersion;
			try
			{
				if (new Version(operatingSystemVersion) < new Version("12.0"))
				{
					Log.Trace(LogTag, "CreateItems - iOS version is less than 12, not enabling AppleHealth.");
					return false;
				}
			}
			catch (Exception ex)
			{
				Log.Trace("Settings", $"Failed to convert operating system version string to Version. Exception: {ex.GetBaseException()}");
				return false;
			}
			return true;
		}

		protected virtual void DoUpgradeUser()
		{
			ShowPaymentViewModel();
		}

		protected override void DoClose()
		{
			closeCts.Cancel();
			base.DoClose();
		}

		public override void Dispose()
		{
			foreach (ConnectedAppsMenuItemModel connectedAppsItem in ConnectedAppsItemList)
			{
				connectedAppsItem.Dispose();
			}
			disposables.Dispose();
			base.Dispose();
			UnregisterChangeHandlers();
		}

