	public class ConnectToAppViewModel : BaseInternetConnectionViewModel
	{
		private readonly CancellationTokenSource closeCts = new CancellationTokenSource();

		private readonly IMvxMessenger messenger;

		private readonly IWolfAnalytics analytics;

		private readonly TimeSpan animationDelay = TimeSpan.FromSeconds(1.0);

		private IConnectedAppContainer connectedAppContainer;

		public IConnectedAppsCollection ConnectedAppsCollection { get; }

		public string Title { get; private set; }

		public string Description { get; private set; }

		public string LogoImageRef { get; private set; }

		public string LogoText { get; private set; }

		public bool HasLogoText => !string.IsNullOrWhiteSpace(LogoText);

		public ICommand ConnectButtonPressed { get; }

		public ICommand BackButtonAction { get; }

		public override string LogTag => "ConnectToAppViewModel".ToUpper();

		public ConnectToAppViewModel(ILocalSettings localSettings, IFailedUploadMonitor failedUploadMonitor, IConnectedAppsCollection connectedAppsCollection, IMvxMessenger messenger, IWolfAnalytics analytics = null)
			: base(localSettings, failedUploadMonitor)
		{
			try
			{
				ConnectedAppsCollection = connectedAppsCollection;
				this.messenger = messenger;
				this.analytics = analytics;
				ConnectButtonPressed = new MvxAsyncCommand(DoConnectAsync);
				BackButtonAction = new MvxCommand(delegate
				{
					base.CloseViewModel.Execute();
				}, () => !IsLoading.Value);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(ConnectToAppNavObject navObj)
		{
			connectedAppContainer = ConnectedAppsCollection.ConnectedApps.First((IConnectedAppContainer container) => container.App == navObj.App);
			Title = string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_connect_title, connectedAppContainer.DisplayName);
			Description = connectedAppContainer.AuthorizationDescriptionText;
			LogoImageRef = connectedAppContainer.LargeImageReference;
			LogoText = connectedAppContainer.Wordmark;
		}

		private async Task DoConnectAsync()
		{
			_ = 1;
			try
			{
				IsLoading.Value = true;
				if (!(await TryAuthorizeAsync(closeCts.Token).ConfigureAwait(continueOnCapturedContext: false)))
				{
					Log.Error(LogTag, string.Format("{0} - Failed to authorize {1}", "DoConnectAsync", connectedAppContainer.App));
					analytics?.ConnectedAppsFailedToAuthorize(connectedAppContainer.App).ConfigureAwait(continueOnCapturedContext: false);
					if (connectedAppContainer.AuthorizationService is UrlAuthorizationService)
					{
						string message = string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_app_was_not_connected_message_template, connectedAppContainer.DisplayName);
						ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.settings_connected_apps_app_was_not_connected, message, (string)null, true);
					}
				}
				else
				{
					analytics?.ConnectedAppsUserInitiatedConnection(connectedAppContainer.App).ConfigureAwait(continueOnCapturedContext: false);
					ConnectedAppPermissionsNavObject parameterValuesObject = new ConnectedAppPermissionsNavObject
					{
						App = connectedAppContainer.App
					};
					Log.Trace(LogTag, string.Format("{0} - Connected to {1}, showing {2}", "DoConnectAsync", connectedAppContainer.App, "ConnectedAppPermissionsViewModel"));
					ShowViewModel<ConnectedAppPermissionsViewModel>(parameterValuesObject);
					await Task.Delay(animationDelay).ConfigureAwait(continueOnCapturedContext: false);
					DoClose();
				}
			}
			catch (Exception ex) when (ex.RelatesTo<OperationCanceledException>())
			{
				Log.Trace(LogTag, "DoConnectAsync Normal Cancellation: " + ex.Message, ex);
			}
			catch (Exception ex2)
			{
				Log.Error(LogTag, "ConnectToAppViewModel: " + ex2.Message, ex2);
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		private async Task<bool> TryAuthorizeAsync(CancellationToken cancellationToken)
		{
			Log.Trace(LogTag, string.Format("{0} Connecting to service: {1}", "TryAuthorizeAsync", connectedAppContainer.App));
			if (await connectedAppContainer.AuthorizationService.AuthorizeAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false))
			{
				Log.Trace(LogTag, string.Format("{0} Updating collection async: {1}", "TryAuthorizeAsync", connectedAppContainer.App));
				await ConnectedAppsCollection.UpdateAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				messenger.Publish(new ConnectedAppsCollectionUpdatedMessage(this));
			}
			return connectedAppContainer.IsConnected;
		}

		protected override void DoClose()
		{
			closeCts.Cancel();
			base.DoClose();
		}

