namespace Wolf.Core.ViewModels.Settings.ConnectedApps.Items
{
	public class ConnectedAppPermissionItemModel : ShireBaseViewModel
	{
		private readonly ConnectedApp app;

		public readonly ConnectedAppPermission Permission;

		public readonly string Description;

		public readonly INC<bool> IsEnabled = new NC<bool>();

		public readonly IMvxCommand TogglePermission;

		public ConnectedAppPermissionItemModel(string connectedAppName, ConnectedAppPermission permission, bool isEnabled, ConnectedApp app)
		{
			try
			{
				Permission = permission;
				this.app = app;
				Description = GetDescription(connectedAppName);
				IsEnabled.Value = isEnabled;
				TogglePermission = new MvxCommand(DoTogglePermission);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private string GetDescription(string connectedAppName)
		{
			switch (Permission)
			{
			case ConnectedAppPermission.Send:
				return string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_permissions_export_row_toggle, connectedAppName);
			case ConnectedAppPermission.Receive:
			{
				string format = (app.Equals(ConnectedApp.Oura) ? Wolf.Core.Resources.AppStrings.settings_connected_apps_permissions_import_row_toggle_daily : Wolf.Core.Resources.AppStrings.settings_connected_apps_permissions_import_row_toggle);
				return string.Format(format, connectedAppName);
			}
			default:
				Log.Error("Settings", string.Format("{0}: Unable to identify permission - {1}", "ConnectedAppPermissionItemModel", Permission));
				return $"{connectedAppName} Permission: {Permission}";
			}
		}

		private void DoTogglePermission()
		{
			IsEnabled.Value = !IsEnabled.Value;
		}

