namespace Wolf.Core.ViewModels.Settings.Appearance
{
	public class AppearanceSettingsViewModel : BaseViewModel
	{
		private new readonly IThemeService themeService;

		public readonly INC<Theme> SelectedTheme = new NC<Theme>();

		public readonly INC<bool> DarkThemeEnabled = new NC<bool>();

		public readonly INC<bool> LightThemeEnabled = new NC<bool>();

		public readonly ICommand EnableLightTheme;

		public readonly ICommand EnableDarkTheme;

		private readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		public AppearanceSettingsViewModel(ILocalSettings localSettings, IThemeService themeService, IMvxMainThreadDispatcher mainThreadDispatcher)
			: base(localSettings)
		{
			try
			{
				this.themeService = themeService;
				this.mainThreadDispatcher = mainThreadDispatcher;
				EnableLightTheme = new MvxCommand(DoEnableLightTheme);
				EnableDarkTheme = new MvxCommand(DoEnableDarkTheme);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init()
		{
			RefreshThemePropertyFromSettings();
		}

		private void RefreshThemePropertyFromSettings()
		{
			SelectedTheme.Value = themeService.CurrentTheme();
			UpdateThemeBools();
		}

		private void DoEnableLightTheme()
		{
			EnableTheme(Theme.Light);
		}

		private void DoEnableDarkTheme()
		{
			EnableTheme(Theme.Dark);
		}

		private void UpdateThemeBools()
		{
			DarkThemeEnabled.Value = SelectedTheme.Value == Theme.Dark;
			LightThemeEnabled.Value = SelectedTheme.Value == Theme.Light;
		}

		protected void EnableTheme(Theme newTheme)
		{
			SelectedTheme.Value = newTheme;
			if (Mvx.TryResolve<IHardwareInfo>(out var service) && service.IsAndroid)
			{
				if (themeService.AppTheme != SelectedTheme.Value)
				{
					ShowThemeChangeConfirmationDialog(newTheme);
				}
				return;
			}
			themeService.AppTheme = SelectedTheme.Value;
			themeService.NotifyAppThemeChanged(themeService.CurrentTheme());
			string currentUrl = themeService.CurrentWebViewUrl;
			mainThreadDispatcher.RequestMainThreadAction(delegate
			{
				if (string.IsNullOrEmpty(currentUrl))
				{
					webviewHolderFactory.WebviewHolderStore.FlushAll();
				}
				else
				{
					webviewHolderFactory.WebviewHolderStore.FlushAllExcluding(currentUrl);
				}
			});
		}

		private void ShowThemeChangeConfirmationDialog(Theme theme)
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.android_theme_change_dialog_title, Wolf.Core.Resources.AppStrings.android_theme_change_dialog_message, delegate
			{
				themeService.AppTheme = theme;
				UpdateThemeBools();
				HardResetNavigation();
			}, Wolf.Core.Resources.AppStrings.no.ToUpper(), Wolf.Core.Resources.AppStrings.yes.ToUpper(), null, delegate
			{
				SelectedTheme.Value = themeService.AppTheme;
				UpdateThemeBools();
			}, dismissible: false);
		}

