namespace Wolf.Core.ViewModels.Settings.AICoachSettings
{
	public class AICoachSettingsViewModel : BaseViewModel
	{
		private const int AICOACH_UPDATE_INTERVAL = 15000;

		private readonly IIfitApiService apiService;

		private ChannelStatusData AIChannelStatusData;

		private System.Timers.Timer timer;

		public readonly INC<bool> CoachEnabled = new NC<bool>();

		public IMvxAsyncCommand AICoachAction { get; }

		public AICoachSettingsViewModel(ILocalSettings localSettings, IIfitApiService apiService)
			: base(localSettings)
		{
			try
			{
				this.apiService = apiService;
				AICoachAction = new MvxAsyncCommand((Func<Task>)async delegate
				{
					if (CoachEnabled.Value)
					{
						await DisableAICoachMethod();
					}
					else
					{
						EnableAICoachMethod();
					}
				}, (Func<bool>)null, false);
				EnableTimer();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			await LoadData();
		}

		private async Task LoadData()
		{
			try
			{
				IsLoading.Value = true;
				AIChannelStatusData = (await apiService.SmsApi.GetSmsChannelStatus()).FirstOrDefault((ChannelStatusData x) => x.channel == SmsChannel.AICoach);
				INC<bool> coachEnabled = CoachEnabled;
				ChannelStatusData aIChannelStatusData = AIChannelStatusData;
				coachEnabled.Value = aIChannelStatusData != null && aIChannelStatusData.status == AICoachStatus.Active;
			}
			catch (Exception ex)
			{
				Log.Trace(GetType().Name, "GetAICoachStatus error, " + ex.Message);
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		private void DisableTimer()
		{
			if (timer != null)
			{
				timer.Elapsed -= RefreshAICoachStatus;
				timer.Dispose();
				timer = null;
			}
		}

		private void EnableTimer()
		{
			DisableTimer();
			timer = new System.Timers.Timer(15000.0);
			timer.Elapsed += RefreshAICoachStatus;
			timer.Start();
		}

		private void RefreshAICoachStatus(object sender, ElapsedEventArgs e)
		{
			Task.Run((Func<Task>)LoadData);
		}

		private void EnableAICoachMethod()
		{
			BaseViewModel.ShowDialogViewModel<TurnOnAICoachViewModel>();
		}

		private async Task DisableAICoachMethod()
		{
			if (AIChannelStatusData == null)
			{
				return;
			}
			try
			{
				IsLoading.Value = true;
				await apiService.SmsApi.DisableChannel(new DisableChannelRequest(AIChannelStatusData.phoneNumber, AIChannelStatusData.channel.GetEnumMemberAttributeValue()));
				CoachEnabled.Value = false;
			}
			catch (Exception ex)
			{
				Log.Trace(GetType().Name, "DisableAICoach error, " + ex.Message);
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		public override void Dispose()
		{
			DisableTimer();
			base.Dispose();
			UnregisterChangeHandlers();
		}

