			: base(localSettings, api, dialogPresenter, failedUploadMonitor)
		{
			try
			{
				this.secondaryUsersService = secondaryUsersService;
				this.screenSaverHandler = screenSaverHandler ?? throw new ArgumentNullException("screenSaverHandler");
				this.lockScreenHandler = lockScreenHandler;
				this.ifitLogin = ifitLogin;
				SubmitPasswordCommand = new MvxAsyncCommand(DoValidatePasswordAsync);
				ForgotPasswordCommand = new MvxCommand(DoForgotPassword);
				GoBackCommand = new MvxAsyncCommand(BackPressedTask);
				InitialState();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			try
			{
				await Task.Run(() => LoadUsersAndInvitations(isInit: true)).ConfigureAwait(continueOnCapturedContext: false);
				CheckDisposedWhileLoading();
			}
			catch (TaskCanceledException exception)
			{
				ItemCollection.Clear();
				Log.Warn(LogTag, "Loading cancelled", exception);
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			secondaryServiceSubscription = secondaryServiceSubscription ?? secondaryUsersService.SecondaryOpStatus.SubscribeAsync(HandleSecondaryServiceResult);
			screenSaverVisibleChangedSubscription?.Dispose();
			screenSaverVisibleChangedSubscription = screenSaverHandler.WhenIsScreenSaverVisibleChanged.SubscribeWithErrorLogging(OnScreenSaverVisibleChanged);
		}

		public override void Dispose()
		{
			base.Dispose();
			secondaryServiceSubscription?.Dispose();
			secondaryServiceSubscription = null;
			StopEnableRefreshUsersInterval();
			DisposeScreenSaverVisibleChangedSubscription();
			UnregisterChangeHandlers();
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			StopEnableRefreshUsersInterval();
			DisposeScreenSaverVisibleChangedSubscription();
		}

		protected override async Task HandleSecondaryServiceResult(SecondaryOperationResult result)
		{
			await base.HandleSecondaryServiceResult(result);
			await LoadUsersAndInvitations();
		}

		private void StartEnableRefreshUsersInterval()
		{
			EnableRefreshUsersIntervalSubscription?.Dispose();
			EnableRefreshUsersIntervalSubscription = Observable.Interval(TimeSpan.FromSeconds(60.0)).SubscribeWithErrorLogging(OnEnableRefreshIntervalElapsed);
		}

		private void StopEnableRefreshUsersInterval()
		{
			EnableRefreshUsersIntervalSubscription?.Dispose();
			EnableRefreshUsersIntervalSubscription = null;
		}

		private async Task<(List<User> Users, List<User> Invites)> GetUsersAndInvitations()
		{
			Task<IList<User>> userListResultTask = secondaryUsersService.GetAllLinkedUsers(api.CurrentlyAuthenticatedUser.Id);
			Task<IList<User>> pendingInvitesTask = secondaryUsersService.GetPendingInvitations(api.CurrentlyAuthenticatedUserId);
			await Task.WhenAll<IList<User>>(userListResultTask, pendingInvitesTask).ConfigureAwait(continueOnCapturedContext: false);
			return (Users: userListResultTask.Result.ToList(), Invites: pendingInvitesTask.Result.ToList());
		}

		private void CheckDisposedWhileLoading()
		{
			if (isDisposed)
			{
				throw new TaskCanceledException("ViewModel disposed while still doing Init()");
			}
		}

		private void InviteUser()
		{
			if (IsDeviceConnected())
			{
				BaseViewModel.ShowDialogViewModel<AddAccountViewModel>();
			}
		}

		private async void OnScreenSaverVisibleChanged(bool isScreenSaverVisible)
		{
			if (!isScreenSaverVisible)
			{
				await LoadUsersAndInvitations().ConfigureAwait(continueOnCapturedContext: false);
			}
			Log.Debug(LogTag, string.Format("{0}: {1}", "OnScreenSaverVisibleChanged", isScreenSaverVisible));
		}

		private void DisposeScreenSaverVisibleChangedSubscription()
		{
			screenSaverVisibleChangedSubscription?.Dispose();
			screenSaverVisibleChangedSubscription = null;
		}

		private async Task LoadUsersAndInvitations(bool isInit = false)
		{
			var (updatedUsers, list) = await GetUsersAndInvitations();
			if (isInit)
			{
				ReloadFullCollection(updatedUsers, list);
			}
			else
			{
				UpdateItemCollection(updatedUsers, list);
			}
		}

		private void UpdateItemCollection(List<User> updatedUsers, List<User> updatedInvites)
		{
			List<User> list = (from itemModel in ItemCollection.OfType<AccountSelectionUserItemModel>()
				select itemModel.User).ToList();
			List<User> list2 = (from itemModel in ItemCollection.OfType<AccountSelectionPendingInviteItemModel>()
				select itemModel.User).ToList();
			if (list.SequenceEqual(updatedUsers, userEqualityComparer) && list2.SequenceEqual(updatedInvites, userEqualityComparer))
			{
				return;
			}
			(List<User> UsersToAdd, List<User> UserToRemove) usersToAddAndRemove = GetUsersToAddAndRemove(list, updatedUsers);
			List<User> item = usersToAddAndRemove.UsersToAdd;
			List<User> item2 = usersToAddAndRemove.UserToRemove;
			(List<User> InvitesToAdd, List<User> InvitesToRemove) invitesToAddAndRemove = GetInvitesToAddAndRemove(list2, updatedInvites);
			List<User> item3 = invitesToAddAndRemove.InvitesToAdd;
			List<User> item4 = invitesToAddAndRemove.InvitesToRemove;
			int num = item3.Count + item.Count + item2.Count + item4.Count;
			if (num > 1)
			{
				ReloadFullCollection(updatedUsers, updatedInvites);
			}
			else if (item.Count > 0)
			{
				AccountSelectionUserPasswordItemModel accountSelectionUserPasswordItemModel = ProduceUserItemModel(item[0]);
				if (!TryReplaceSendInviteItemViewModelWhileAddingNewItem(accountSelectionUserPasswordItemModel))
				{
					AccountSelectionUserItemModel accountSelectionUserItemModel = ItemCollection.OfType<AccountSelectionUserItemModel>().LastOrDefault();
					int index = ((accountSelectionUserPasswordItemModel.User.IsSecondary && accountSelectionUserItemModel != null) ? (ItemCollection.IndexOf(accountSelectionUserItemModel) + 1) : 0);
					ItemCollection.Insert(index, accountSelectionUserPasswordItemModel);
					UpdatePendingInvitesLeft();
				}
			}
			else if (item3.Count > 0)
			{
				AccountSelectionPendingInviteItemModel accountSelectionPendingInviteItemModel = ProducePendingInviteItemModel(item3[0]);
				if (!TryReplaceSendInviteItemViewModelWhileAddingNewItem(accountSelectionPendingInviteItemModel))
				{
					AccountSelectionPendingInviteItemModel accountSelectionPendingInviteItemModel2 = ItemCollection.OfType<AccountSelectionPendingInviteItemModel>().LastOrDefault();
					int num2 = ((accountSelectionPendingInviteItemModel2 == null) ? (ItemCollection.Count - 2) : ItemCollection.IndexOf(accountSelectionPendingInviteItemModel2));
					ItemCollection.Insert(num2 + 1, accountSelectionPendingInviteItemModel);
					UpdatePendingInvitesLeft();
				}
			}
			else if (item2.Count > 0)
			{
				User userToRemove = item2[0];
				AccountSelectionUserItemModel accountSelectionUserItemModel2 = ItemCollection.OfType<AccountSelectionUserItemModel>().FirstOrDefault((AccountSelectionUserItemModel model) => model.User.Id == userToRemove.Id);
				if (accountSelectionUserItemModel2 != null)
				{
					if (TryReplaceLastItemOrReloadCollectionWhileRemovingItem(accountSelectionUserItemModel2, updatedUsers, updatedInvites))
					{
						return;
					}
					ItemCollection.Remove(accountSelectionUserItemModel2);
				}
				UpdatePendingInvitesLeft();
			}
			else
			{
				if (item4.Count <= 0)
				{
					return;
				}
				User inviteToRemove = item4[0];
				AccountSelectionPendingInviteItemModel accountSelectionPendingInviteItemModel3 = ItemCollection.OfType<AccountSelectionPendingInviteItemModel>().FirstOrDefault((AccountSelectionPendingInviteItemModel model) => model.User?.Id == inviteToRemove?.Id);
				if (accountSelectionPendingInviteItemModel3 != null)
				{
					if (TryReplaceLastItemOrReloadCollectionWhileRemovingItem(accountSelectionPendingInviteItemModel3, updatedUsers, updatedInvites))
					{
						return;
					}
					ItemCollection.Remove(accountSelectionPendingInviteItemModel3);
				}
				UpdatePendingInvitesLeft();
			}
		}

		private void ReloadFullCollection(List<User> updatedUsers, List<User> invites)
		{
			List<BaseViewModel> list = new List<BaseViewModel>();
			IEnumerable<AccountSelectionUserPasswordItemModel> collection = updatedUsers.Select(ProduceUserItemModel);
			list.AddRange(collection);
			IEnumerable<AccountSelectionPendingInviteItemModel> collection2 = invites.Select(ProducePendingInviteItemModel);
			list.AddRange(collection2);
			if (list.Count < 5)
			{
				int invitesLeft = 5 - list.Count;
				list.Add(ProduceSendInviteItemModel(invitesLeft));
			}
			if (!IsCollectionLoaded.Value)
			{
				IsCollectionLoaded.Value = true;
			}
			ItemCollection.ReplaceWith(list);
		}

		private (List<User> UsersToAdd, List<User> UserToRemove) GetUsersToAddAndRemove(List<User> currentUsers, List<User> updatedUsers)
		{
			List<User> item = updatedUsers.Except(currentUsers, userEqualityComparer).ToList();
			List<User> item2 = currentUsers.Except(updatedUsers, userEqualityComparer).ToList();
			return (UsersToAdd: item, UserToRemove: item2);
		}

		private (List<User> InvitesToAdd, List<User> InvitesToRemove) GetInvitesToAddAndRemove(List<User> currentInvites, List<User> updatedInvites)
		{
			List<User> list = currentInvites.Where((User u) => u == null).ToList();
			List<User> list2 = currentInvites.Where((User u) => u != null).ToList();
			List<User> list3 = updatedInvites.Where((User u) => u == null).ToList();
			List<User> list4 = updatedInvites.Where((User u) => u != null).ToList();
			List<User> list5 = list4.Except(list2, userEqualityComparer).ToList();
			int num = list3.Count - list.Count;
			List<User> collection = ((num > 0) ? list3.Skip(list.Count).ToList() : new List<User>());
			list5.AddRange(collection);
			List<User> list6 = list2.Except(list4, userEqualityComparer).ToList();
			int num2 = list.Count - list3.Count;
			List<User> collection2 = ((num2 > 0) ? list.Skip(list3.Count).ToList() : new List<User>());
			list6.AddRange(collection2);
			return (InvitesToAdd: list5, InvitesToRemove: list6);
		}

		private AccountSelectionUserPasswordItemModel ProduceUserItemModel(User user)
		{
			return new AccountSelectionUserPasswordItemModel(localSettings, api, user, InputPasswordState);
		}

		private AccountSelectionPendingInviteItemModel ProducePendingInviteItemModel(User invitedUser)
		{
			return new AccountSelectionPendingInviteItemModel(localSettings, invitedUser);
		}

		private AccountSelectionSendInviteItemModel ProduceSendInviteItemModel(int invitesLeft)
		{
			bool isPossibleToInviteUsers = !api.CurrentlyAuthenticatedUser.IsSecondary && api.CurrentlyAuthenticatedUser.SubscriptionType == User.SubscriptionTypes.CoachPlus;
			return new AccountSelectionSendInviteItemModel(localSettings, invitesLeft, isPossibleToInviteUsers, InviteUser);
		}

		private void UpdatePendingInvitesLeft()
		{
			ItemCollection.OfType<AccountSelectionSendInviteItemModel>().FirstOrDefault()?.UpdateInvitesLeft(5 - ItemCollection.Count + 1);
		}

		private bool TryReplaceSendInviteItemViewModelWhileAddingNewItem(BaseViewModel itemToAdd)
		{
			if (ItemCollection.Count < 5)
			{
				return false;
			}
			AccountSelectionSendInviteItemModel accountSelectionSendInviteItemModel = ItemCollection.OfType<AccountSelectionSendInviteItemModel>().FirstOrDefault();
			if (accountSelectionSendInviteItemModel != null)
			{
				return TryReplaceItem(accountSelectionSendInviteItemModel, itemToAdd);
			}
			return false;
		}

		private bool TryReplaceLastItemOrReloadCollectionWhileRemovingItem(BaseViewModel itemToRemove, List<User> updatedUsers, List<User> updatedInvites)
		{
			if (ItemCollection.Count < 5)
			{
				return false;
			}
			AccountSelectionSendInviteItemModel accountSelectionSendInviteItemModel = ItemCollection.OfType<AccountSelectionSendInviteItemModel>().FirstOrDefault();
			if (accountSelectionSendInviteItemModel != null)
			{
				return false;
			}
			if (ItemCollection.IndexOf(itemToRemove) != ItemCollection.Count - 1)
			{
				ReloadFullCollection(updatedUsers, updatedInvites);
				return true;
			}
			accountSelectionSendInviteItemModel = ProduceSendInviteItemModel(1);
			return TryReplaceItem(itemToRemove, accountSelectionSendInviteItemModel);
		}

		private bool TryReplaceItem(BaseViewModel originalItem, BaseViewModel newItem)
		{
			int num = ItemCollection.IndexOf(originalItem);
			if (num < 0)
			{
				return false;
			}
			ItemCollection[num] = newItem;
			return true;
		}

		private async Task RefreshUsers()
		{
			await LoadUsersAndInvitations(isInit: true).ConfigureAwait(continueOnCapturedContext: false);
			StartEnableRefreshUsersInterval();
		}

		private void OnEnableRefreshIntervalElapsed(long arg)
		{
			StopEnableRefreshUsersInterval();
		}

		private void DoForgotPassword()
		{
			if (IsDeviceConnected())
			{
				BaseViewModel.ShowDialogViewModel<ForgotPasswordDialogViewModel>();
			}
		}

		private async Task DoValidatePasswordAsync()
		{
			if (!IsDeviceConnected() || SelectedUser?.Value == null)
			{
				return;
			}
			INC<User> selectedUser = SelectedUser;
			bool? obj;
			if (selectedUser == null)
			{
				obj = null;
			}
			else
			{
				User value = selectedUser.Value;
				obj = ((value != null) ? new bool?(!value.Equals(LoggedInUser.Value)) : ((bool?)null));
			}
			bool? needSwitchUser = obj;
			string message;
			switch (await DoSignIn(SelectedUser.Value, InputPassword.Value))
			{
			case LoginResult.NoInternetConnection:
				message = Wolf.Core.Resources.AppStrings.wifi_not_found;
				goto IL_0149;
			case LoginResult.InvalidPassword:
				message = Wolf.Core.Resources.AppStrings.input_password_dialog_enter_valid_password;
				goto IL_0149;
			case LoginResult.InvalidToken:
				message = Wolf.Core.Resources.AppStrings.authentication_invalid_token;
				goto IL_0149;
			default:
				message = Wolf.Core.Resources.AppStrings.error_logging_in;
				goto IL_0149;
			case LoginResult.Success:
				{
					await lockScreenHandler.UnlockScreen().ConfigureAwait(continueOnCapturedContext: false);
					if (needSwitchUser.Value)
					{
						ClearDialogs();
						webviewHolderFactory.WebviewHolderStore.FlushAll();
						try
						{
							await api.SwitchUser(SelectedUser.Value.Id);
							ClearCookies();
						}
						catch (Exception)
						{
							ForgotPasswordCommand.Execute(null);
						}
					}
					NavigateToDashboardViewModel();
					ShowViewModel<SettingsViewModel>();
					ShowViewModel<LockPinSettingsViewModel>(new LockPinSettingsArbitraryData
					{
						AutomaticShowLockPin = true
					});
					break;
				}
				IL_0149:
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, message, Wolf.Core.Resources.AppStrings.okay_title.ToUpper());
				InputPassword.Value = string.Empty;
				break;
			}
		}

		private async Task<LoginResult> DoSignIn(User toUser, string password)
		{
			Sindarin.Core.Util.NonGenericSubject obs = new Sindarin.Core.Util.NonGenericSubject();
			if (Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service) && Mvx.TryResolve<IDialogPresenter>(out var _))
			{
				service.RequestMainThreadAction(delegate
				{
					ShowProgressDialog(null, obs.ReactiveSubject, null, null, default(TimeSpan), "", showSafety: false).ConfigureAwait(continueOnCapturedContext: false);
				});
			}
			wifiService?.RefreshConnectivityState();
			IConnectivity obj = connectivity;
			LoginResult result;
			if (obj == null || !obj.IsConnected)
			{
				result = LoginResult.NoInternetConnection;
			}
			else
			{
				try
				{
					result = await ifitLogin.Authenticate(toUser.Username, password, forceAuthentication: true).TimeoutAfter(LoginIfitViewModel.LoginTimeout).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (TimeoutException exception)
				{
					Log.Error("Api", "Authentication Timed Out", exception);
					result = LoginResult.TimeOut;
				}
				catch (Exception exception2)
				{
					Log.Error("Api", "General Exception Occured", exception2);
					result = LoginResult.UnknownFailure;
				}
			}
			obs.OnNext();
			return result;
		}

		private void InitialState()
		{
			TitleString.Value = Wolf.Core.Resources.AppStrings.account_selection_verify_password_select_account;
			InputPassword.Value = string.Empty;
			SelectedUser.Value = null;
		}

		private void InputPasswordState(User user)
		{
			if (IsDeviceConnected())
			{
				List<User> list = new List<User>();
				list.Add(user);
				ItemCollection.Clear();
				ItemCollection.ReplaceWith(list.Select(ProduceUserItemModel));
				TitleString.Value = Wolf.Core.Resources.AppStrings.account_selection_verify_password_enter_password;
				InputPassword.Value = string.Empty;
				SelectedUser.Value = user;
			}
		}

		private async Task BackPressedTask()
		{
			if (!IsUserSelected)
			{
				DoClose();
				await Task.Delay(200);
				if (lockScreenHandler?.NavigateFrom == typeof(LaunchScreenViewModel))
				{
					ShowViewModel<LaunchScreenViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ClearStackToRequested(), (MvxRequestedBy)null);
				}
				else
				{
					lockScreenHandler?.NavigateToLockScreen();
				}
			}
			else
			{
				InitialState();
				await RefreshUsers().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private bool IsDeviceConnected()
		{
			if (NoWifi)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.default_lost_wifi_title, Wolf.Core.Resources.AppStrings.default_lost_wifi_message, Wolf.Core.Resources.AppStrings.okay_title);
				return false;
			}
			return true;
		}

