	public class AccountSelectionViewModel : UserAccountViewModel
	{
		private const int DefaultUpdateIntervalSeconds = 60;

		private readonly ISecondaryUsersService secondaryUsersService;

		private readonly IScreenSaverHandler screenSaverHandler;

		private IDisposable screenSaverVisibleChangedSubscription;

		public readonly INC<bool> IsCollectionLoaded = new NC<bool>();

		public readonly INC<bool> IsRefreshUsersAvailable = new NC<bool>();

		protected int RefreshUsersIntervalSeconds { get; set; }

		protected IDisposable EnableRefreshUsersIntervalSubscription { get; private set; }

		public override string LogTag => "AccountSelectionViewModel";

		public MvxObservableCollection<BaseViewModel> ItemCollection { get; } = new MvxObservableCollection<BaseViewModel>();

		public ICommand OpenManageAccountsCommand => new MvxCommand(OpenManageAccounts);

		public ICommand InviteCommand => new MvxCommand(InviteUser);

		public ICommand RefreshUsersCommand => new MvxAsyncCommand(RefreshUsers);

		public AccountSelectionViewModel(ILocalSettings localSettings, IIfitApiService api, IDialogPresenter dialogPresenter, IFailedUploadMonitor failedUploadMonitor, ISecondaryUsersService secondaryUsersService, IScreenSaverHandler screenSaverHandler)
			: base(localSettings, api, dialogPresenter, failedUploadMonitor)
		{
			try
			{
				this.secondaryUsersService = secondaryUsersService;
				this.screenSaverHandler = screenSaverHandler;
				RefreshUsersIntervalSeconds = 60;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			try
			{
				await LoadUsersAndInvitations(isInit: true);
				CheckDisposedWhileLoading();
			}
			catch (TaskCanceledException exception)
			{
				ItemCollection.Clear();
				Log.Warn(LogTag, "Loading cancelled", exception);
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			secondaryServiceSubscription = secondaryServiceSubscription ?? secondaryUsersService.SecondaryOpStatus.SubscribeAsync(HandleSecondaryServiceResult);
			screenSaverVisibleChangedSubscription?.Dispose();
			screenSaverVisibleChangedSubscription = screenSaverHandler.WhenIsScreenSaverVisibleChanged.SubscribeWithErrorLogging(OnScreenSaverVisibleChanged);
			IsRefreshUsersAvailable.Value = true;
		}

		public override void Dispose()
		{
			base.Dispose();
			secondaryServiceSubscription?.Dispose();
			secondaryServiceSubscription = null;
			StopEnableRefreshUsersInterval();
			DisposeScreenSaverVisibleChangedSubscription();
			MvxObservableCollection<BaseViewModel> itemCollection = ItemCollection;
			if (itemCollection == null || itemCollection.Count <= 0)
			{
				return;
			}
			foreach (BaseViewModel item in ItemCollection)
			{
				item?.Dispose();
			}
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			StopEnableRefreshUsersInterval();
			DisposeScreenSaverVisibleChangedSubscription();
		}

		protected override async Task HandleSecondaryServiceResult(SecondaryOperationResult result)
		{
			await base.HandleSecondaryServiceResult(result);
			await LoadUsersAndInvitations();
		}

		protected void StartEnableRefreshUsersInterval()
		{
			EnableRefreshUsersIntervalSubscription?.Dispose();
			EnableRefreshUsersIntervalSubscription = Observable.Interval(TimeSpan.FromSeconds(RefreshUsersIntervalSeconds)).SubscribeWithErrorLogging(OnEnableRefreshIntervalElapsed);
		}

		protected void StopEnableRefreshUsersInterval()
		{
			EnableRefreshUsersIntervalSubscription?.Dispose();
			EnableRefreshUsersIntervalSubscription = null;
		}

		private async Task<(IList<User> Users, IList<User> Invites)> GetUsersAndInvitations()
		{
			Task<IList<User>> userListResultTask = secondaryUsersService.GetAllLinkedUsers(api.CurrentlyAuthenticatedUser.Id);
			Task<IList<User>> pendingInvitesTask = secondaryUsersService.GetPendingInvitations(api.CurrentlyAuthenticatedUserId);
			await Task.WhenAll<IList<User>>(userListResultTask, pendingInvitesTask);
			return (Users: userListResultTask.Result, Invites: pendingInvitesTask.Result);
		}

		private void CheckDisposedWhileLoading()
		{
			if (isDisposed)
			{
				throw new TaskCanceledException("ViewModel disposed while still doing Init()");
			}
		}

