namespace Wolf.Core.ViewModels.SafetyKey
{
	public class SafetyKeyDialogViewModel : BaseSwappingBackgroundViewModel
	{
		private const int CountdownSeconds = 300;

		protected IDisposable dmkReplacedSub;

		protected IDisposable countdownSub;

		protected IDisposable dmkTimeoutSub;

		private IScreenBrightness screenBrightness;

		private readonly IIdleLogoutService idleLogoutService;

		private new readonly IDialogPresenter dialogPresenter;

		private readonly ILockScreenHandler lockScreenHandler;

		public readonly INC<int> SecondsRemaining = new NC<int>(300);

		public readonly INC<bool> CountdownVisible = new NC<bool>();

		public readonly INC<int> CurrentImageIndex = new NC<int>();

		public readonly INC<int> CurrentPositionIndex = new NC<int>(0);

		public new SafetyKeyDialogInitialization ArbitraryData
		{
			get
			{
				return base.ArbitraryData as SafetyKeyDialogInitialization;
			}
			set
			{
				base.ArbitraryData = value;
			}
		}

		protected override int SecondsBetweenPositionMoves => 60;

		protected override int SecondsBetweenImageChanges => 120;

		protected override int NumPositions => 5;

		private TimeSpan ClubSafetyKeyDialogTimeout => TimeSpan.FromMinutes(5.0);

		public bool DismissVisible => ArbitraryData?.DisplayDismiss ?? false;

		public IMvxCommand Dismiss => new MvxCommand(DoDismiss);

		public SafetyKeyDialogViewModel(ILocalSettings localSettings, IDialogPresenter dialogPresenter, ICurrentConsoleService currentConsoleService, IIdleLogoutService idleLogoutService = null, ILockScreenHandler lockScreenHandler = null)
			: base(localSettings)
		{
			try
			{
				this.dialogPresenter = dialogPresenter;
				this.idleLogoutService = idleLogoutService;
				this.lockScreenHandler = lockScreenHandler;
				CurrentImageIndex.Value = StartingIndex;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override void DoClose()
		{
			idleLogoutService?.SetActive(active: true);
			base.DoClose();
		}

		public override async Task OnViewShown()
		{
			idleLogoutService?.SetActive(active: false);
			await base.OnViewShown();
			await Task.Run(delegate
			{
				ConsoleState? consoleState = currentConsoleService.Console?.LatestBasicInfo?.CurrentState;
				if (consoleState != ConsoleState.SafetyKeyRemoved && consoleState != ConsoleState.Demo)
				{
					DmkReplaced();
				}
				else
				{
					dmkReplacedSub = currentConsoleService.Console.WhenStateChanged.Where((StateChange x) => !x.ChangedToState(ConsoleState.SafetyKeyRemoved, ConsoleState.Demo)).Take(1).Subscribe(delegate
					{
						DmkReplaced();
					});
					if (deviceInfo.IsBuiltIn)
					{
						SetupCountdown();
						CountdownVisible.Value = true;
						Mvx.TryResolve<IScreenBrightness>(out screenBrightness);
					}
					if (currentConsoleService.IsBuiltinClub)
					{
						SetupDMKTimeout();
					}
				}
			});
		}

		protected override void NextPosition()
		{
			int value = CurrentPositionIndex.Value;
			value++;
			if (value == NumPositions)
			{
				value = 0;
			}
			CurrentPositionIndex.Value = value;
		}

		protected override void NextImage()
		{
			int value = CurrentImageIndex.Value;
			value++;
			if (value == base.NumImages)
			{
				value = 0;
			}
			CurrentImageIndex.Value = value;
		}

		protected virtual void DmkReplaced()
		{
			screenBrightness?.SetBrightness(1f);
			Cleanup();
			DoDismiss();
		}

		private void DoDismiss()
		{
			ILockScreenHandler obj = lockScreenHandler;
			if (obj != null && obj.CanShowLockScreen)
			{
				DoClose();
				return;
			}
			SafetyKeyDialogInitialization arbitraryData = ArbitraryData;
			if (arbitraryData != null && arbitraryData.WasShowingScreenSaver && ShouldShowAccountSelection() && dialogPresenter.CurrentMainViewModel.GetType() != typeof(AccountSelectionViewModel))
			{
				NavigateToAccountSelectionViewModel();
			}
			else
			{
				DoClose();
			}
		}

		protected override void Cleanup()
		{
			base.Cleanup();
			dmkReplacedSub?.Dispose();
			dmkReplacedSub = null;
			countdownSub?.Dispose();
			countdownSub = null;
			dmkTimeoutSub?.Dispose();
			dmkTimeoutSub = null;
		}

		protected virtual void SetupCountdown()
		{
			countdownSub = (from x in Observable.Interval(TimeSpan.FromSeconds(1.0), intervalScheduler)
				where SecondsRemaining.Value > 0
				select x).Subscribe(delegate
			{
				SecondsRemaining.Value--;
				if (SecondsRemaining.Value <= 0)
				{
					CountdownVisible.Value = false;
					screenBrightness?.SetBrightness(0.1f);
				}
			});
		}

		protected virtual void SetupDMKTimeout()
		{
			dmkTimeoutSub = Observable.Interval(ClubSafetyKeyDialogTimeout, intervalScheduler).Take(1).SubscribeWithErrorLogging(delegate
			{
				InvokeOnMainThread(delegate
				{
					if (!(dialogPresenter.CurrentMainViewModel is InWorkoutViewModel))
					{
						Task.Run(async delegate
						{
							await DoLogOut().ConfigureAwait(continueOnCapturedContext: false);
						});
					}
				});
			});
		}

