namespace Wolf.Core.ViewModels.Registration
{
	public class RegisterEquipmentViewModel : BaseViewModel
	{
		public class NavObject
		{
			public enum OnComplete
			{
				PreLogin,
				Dashboard,
				PreWorkout,
				Close
			}

			public OnComplete NavOperation { get; set; }

			public string WorkoutId { get; set; } = string.Empty;

			public NavObject()
			{
			}

			public NavObject(OnComplete navOp)
			{
				NavOperation = navOp;
			}
		}

		private bool didRegister;

		private NavObject.OnComplete onComplete;

		private string workoutId;

		private IIfitApiService iFitApi;

		public readonly INC<bool> ReceiveUpdates = new NC<bool>(value: true);

		public readonly INC<string> Email = new NC<string>();

		public readonly INC<bool> Busy = new NC<bool>();

		public readonly INC<bool> RegistrationFailed = new NC<bool>();

		[DependsOn(new string[] { "Email" })]
		public bool CanRegister => Email.Value?.IsValidEmail() ?? false;

		public ICommand RegisterCommand => new MvxAsyncCommand(DoRegister);

		public ICommand BackCommand => new MvxCommand(DoClose);

		public ICommand SkipCommand => new MvxCommand(DoSkip);

		public RegisterEquipmentViewModel(ILocalSettings localSettings, IIfitApiService iFitApi, IBleConsoleService bleConsoleService)
			: base(localSettings)
		{
			try
			{
				this.iFitApi = iFitApi;
				trackingService.FirstRun = false;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObject nav)
		{
			onComplete = nav.NavOperation;
			workoutId = nav.WorkoutId;
		}

		private async Task DoRegister()
		{
			if (!Busy.Value && !didRegister)
			{
				Busy.Value = true;
				EquipmentUser equipmentUser = new EquipmentUser
				{
					Email = Email.Value,
					SoftwareNumber = deviceInfo.SoftwareNumber,
					Marketing = ReceiveUpdates.Value
				};
				try
				{
					await equipmentUser.Register(iFitApi);
					bleConsoleService.RegisterCurrentEquipment();
					didRegister = true;
				}
				catch (Exception ex)
				{
					Log.Error("Api", "Exception trying to register equipment", ex.GetBaseException());
					RegistrationFailed.Value = true;
					Busy.Value = false;
					return;
				}
				Busy.Value = false;
				switch (onComplete)
				{
				case NavObject.OnComplete.Close:
					Close(this);
					break;
				case NavObject.OnComplete.PreLogin:
					ShowLoginViewModel();
					break;
				case NavObject.OnComplete.Dashboard:
					NavigateToDashboardViewModel();
					break;
				case NavObject.OnComplete.PreWorkout:
				{
					PreWorkoutViewModel.NavObject parameterValuesObject = new PreWorkoutViewModel.NavObject
					{
						WorkoutId = workoutId,
						WorkoutSource = WorkoutSource.EquipmentRegister,
						DashboardIndex = -1
					};
					Close(this);
					ShowViewModel<PreWorkoutViewModel>(parameterValuesObject);
					break;
				}
				}
			}
		}

		private void DoSkip()
		{
			bleConsoleService.RegisterCurrentEquipment();
			if (deviceInfo.IsBuiltIn)
			{
				ShowLoginViewModel();
			}
			else
			{
				NavigateToDashboardViewModel();
			}
		}

