namespace Wolf.Core.ViewModels.RateWorkout
{
	public class RateWorkoutViewModel : BaseViewModel
	{
		private const int RequiredRatingToRequestAppReview = 4;

		private readonly IIfitApiService ifitApi;

		private readonly IWorkoutApiService workoutApiService;

		public readonly INC<double> AvgWorkoutRating = new NC<double>();

		public readonly BooleanCycle RatingLoading = new BooleanCycle();

		public readonly BooleanCycle ShouldShowRatingWindow = new BooleanCycle();

		public readonly INC<int> UserWorkoutRating = new NC<int>();

		public readonly BooleanCycle WorkoutRatingSaveError = new BooleanCycle();

		protected readonly IWolfAnalytics analytics;

		public ICommand CloseRatingWindow => new MvxCommand(ShouldShowRatingWindow.SetFalse);

		public ICommand OpenRatingWindow => new MvxCommand(ShouldShowRatingWindow.SetTrue, () => AllowRating && !RatingLoading.Value);

		public ICommand SetPopupRating => new MvxCommand<int>(DoSetPopupRating, (int x) => AllowRating);

		public bool AllowRating { get; set; } = true;

		public string WorkoutId { get; set; }

		public RateWorkoutViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IWolfAnalytics analytics = null, IWorkoutApiService workoutApiService = null)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.analytics = analytics;
				this.workoutApiService = workoutApiService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void DoSetPopupRating(int starRating)
		{
			if (UserWorkoutRating.Value != starRating)
			{
				UserWorkoutRating.Value = starRating;
				Task.Run((Func<Task>)SendRatingToApi);
			}
		}

		public async Task DoSetPopupRatingAsync(int starRating)
		{
			if (UserWorkoutRating.Value != starRating)
			{
				UserWorkoutRating.Value = starRating;
				await SendRatingToApi();
			}
		}

		public async Task UpdateRatingFromApi()
		{
			if (string.IsNullOrWhiteSpace(WorkoutId))
			{
				return;
			}
			string workoutIdToGetRatingFor = null;
			try
			{
				base.RequestedWorkout = await workoutApiService.Get(WorkoutId, force: true).ConfigureAwait(continueOnCapturedContext: false);
				workoutIdToGetRatingFor = await base.RequestedWorkout.DetermineWorkoutIdToUse(ifitApi);
				if (base.RequestedWorkout.Id != workoutIdToGetRatingFor)
				{
					base.RequestedWorkout = await workoutApiService.Get(workoutIdToGetRatingFor, force: true).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception ex)
			{
				Log.Trace("Workout", "Could not fetch workout " + WorkoutId + " - workoutIdToGetRatingFor " + workoutIdToGetRatingFor + ": " + ex.Message);
			}
			finally
			{
				AvgWorkoutRating.Value = (base.RequestedWorkout?.Ratings?.Average).GetValueOrDefault();
				UserWorkoutRating.Value = (base.RequestedWorkout?.Ratings?.CurrentUser).GetValueOrDefault();
				RatingLoading.SetFalse();
			}
		}

		private async Task SendRatingToApi()
		{
			if (string.IsNullOrWhiteSpace(WorkoutId) || RatingLoading.Value)
			{
				return;
			}
			ShouldShowRatingWindow.SetFalse();
			RatingLoading.SetTrue();
			string workoutIdToSetRatingFor = null;
			try
			{
				workoutIdToSetRatingFor = await base.RequestedWorkout.DetermineWorkoutIdToUse(ifitApi);
				await Workout.SetWorkoutRating(ifitApi, workoutIdToSetRatingFor, UserWorkoutRating.Value);
				await UpdateRatingFromApi();
				if (analytics != null)
				{
					await analytics.RatedWorkout(base.RequestedWorkout, UserWorkoutRating.Value);
				}
			}
			catch (Exception ex)
			{
				Log.Trace("Workout", "Could not update workout rating for " + workoutIdToSetRatingFor + ": " + ex.Message);
				WorkoutRatingSaveError.SetTrue();
				RatingLoading.SetFalse();
			}
		}

