{
	public interface IPreWorkoutGraphPageViewModel
	{
		Task InitializeChart(Workout workout);
	}
	public abstract class PreWorkoutGraphPageViewModel : BaseViewModel, IPreWorkoutGraphPageViewModel
	{
		public readonly INC<bool> ChartInitialized = new NC<bool>();

		public readonly INCList<Tuple<double, double>> DataPoints = new NCList<Tuple<double, double>>();

		public readonly INC<double> MaxValue = new NC<double>();

		public readonly INC<double> MinValue = new NC<double>();

		public readonly INC<double> MaxXValue = new NC<double>();

		public readonly INC<bool> IsMetric = new NC<bool>();

		public ChartDataCollection Data { get; } = new ChartDataCollection();

		public ChartDataCollection AlternateData { get; } = new ChartDataCollection();

		public IChartAxisScaler ElevationScalar { get; set; }

		protected abstract bool CalculateElevationProfile { get; }

		protected abstract Func<ChartDataProcessor, List<Tuple<double, double>>> DataRetriever { get; }

		protected virtual double MinMaxValueMultiplier => 1.0;

		protected abstract double SampleToleranceRatioX { get; }

		protected abstract double SampleToleranceRatioY { get; }

		public abstract string Title { get; }

		public IChartLabelUtil XAxisFormatter { get; protected set; }

		protected ISettingsRouter settingsRouter { get; set; }

		protected new IPreferenceResolver preferenceResolver { get; set; }

		protected override bool MonitorsForWorkoutStart => false;

		protected PreWorkoutGraphPageViewModel(ILocalSettings localSettings, IPreferenceResolver preferenceResolver, ISettingsRouter settingsRouter)
			: base(localSettings)
		{
			try
			{
				this.preferenceResolver = preferenceResolver;
				this.settingsRouter = settingsRouter;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override void InitFromBundle(IMvxBundle parameters)
		{
			base.InitFromBundle(parameters);
		}

		public async Task InitializeChart(Workout workout)
		{
			await Task.Run(() => CreateChart(workout));
		}

		private async Task CreateChart(Workout workout)
		{
			_ = 5;
			try
			{
				INC<bool> isMetric = IsMetric;
				isMetric.Value = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
				double userWeight = await settingsRouter.GetWeightKgs().ConfigureAwait(continueOnCapturedContext: false);
				double userHeightMeters = await preferenceResolver.UserHeightMeters().ConfigureAwait(continueOnCapturedContext: false);
				double userAge = await preferenceResolver.UserAge().ConfigureAwait(continueOnCapturedContext: false);
				bool? userMale = await preferenceResolver.UserMale().ConfigureAwait(continueOnCapturedContext: false);
				ChartDataProcessor chartDataProcessor = new ChartDataProcessor(workout, IsMetric.Value, currentConsoleService.ActiveConsole, userWeight, userHeightMeters, userAge, userMale);
				XAxisFormatter = new WorkoutChartLabelUtil(workout.Target);
				MaxXValue.Value = workout.TargetValue;
				await chartDataProcessor.ProcessControls();
				DataPoints.Value = DataRetriever(chartDataProcessor).SampleData(SampleToleranceRatioX, SampleToleranceRatioY);
				double num = 0.0;
				double num2 = 0.0;
				double val = 0.0;
				if (DataPoints.Value.Count > 0)
				{
					num = Math.Floor(DataPoints.Value.Min((Tuple<double, double> p) => p.Item2) * MinMaxValueMultiplier);
					num2 = Math.Ceiling(DataPoints.Value.Max((Tuple<double, double> p) => p.Item2) * MinMaxValueMultiplier);
					val = Math.Abs(num2 - num);
				}
				val = Math.Max(val, 1.0);
				double num3 = val * 0.1;
				MinValue.Value = num - num3;
				MaxValue.Value = num2 + num3 + (double)((num2 - num < 1.5) ? 1 : 0);
				if (CalculateElevationProfile)
				{
					double rawMin = currentConsoleService.ActiveConsole.ConsoleInfo.MinIncline / 100.0 * chartDataProcessor.PredictedDistance;
					double rawMax = currentConsoleService.ActiveConsole.ConsoleInfo.MaxIncline / 100.0 * chartDataProcessor.PredictedDistance;
					ElevationScalar = new ElevationAxisScaler(MaxValue.Value - 1.0, MinValue.Value, rawMax, rawMin, isPercent: true);
					chartDataProcessor.PredictedElevationProfile.Insert(0, new Tuple<double, double>(0.0, 0.0));
					AlternateData.AddRange(chartDataProcessor.PredictedElevationProfile.SampleData(SampleToleranceRatioX, SampleToleranceRatioY));
					Data.AddRange(DataPoints.Value);
				}
				else
				{
					Data.AddRange(DataPoints.Value);
				}
				ChartInitialized.Value = true;
				chartDataProcessor?.Dispose();
			}
			catch (Exception exception)
			{
				Log.Error("Charting", "PreWorkoutGraphPageViewModel -> chart not initialized correctly", exception);
			}
		}

