		public PreWorkoutViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, ISettingsRouter settingsRouter, IIfitApiService ifitApi, IBleRadioStatusService bleRadioService, IBlobCacheService cacheService, IIFitGatewayApiService iFitGatewayApi, IWolfAnalytics analytics, IScreenSaverHandler screenSaverHandler, IFailedUploadMonitor failedUploadMonitor, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService, IBleConsoleService bleConsoleService = null)
			: base(localSettings, featureFlagManager, ifitApi, iFitGatewayApi, failedUploadMonitor, webViewUrlParameterService, webviewSettings, currentConsoleService)
		{
			try
			{
				StartWorkout = new MvxAsyncCommand((Func<Task>)async delegate
				{
					await webViewBehaviorsService.RunBehavior("StartWorkout", new Dictionary<string, string>
					{
						{ "workoutId", WorkoutId },
						{ "programId", base.ProgramId }
					}, this);
				}, (Func<bool>)null, false);
				_rateWorkoutModel = new RateWorkoutViewModel(localSettings, ifitApi, analytics)
				{
					AllowRating = false
				};
				this.settingsRouter = settingsRouter;
				cache = cacheService.LocalMachine;
				if (connectivity != null)
				{
					connectivity.ConnectivityChanged -= HandleConnectivityChanged;
					connectivity.ConnectivityChanged += HandleConnectivityChanged;
				}
				prepareWorkoutFailedSub = base.StartWorkoutService?.WhenPrepareWorkoutFailed.Subscribe(delegate
				{
					OnPrepareWorkoutFailed();
				});
				incompatibleWorkoutSub = base.StartWorkoutService?.WhenWorkoutIncompatible.Subscribe(delegate(bool closeScreen)
				{
					this.OnIncompatibleWorkout(closeScreen);
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			isDisposed = true;
			streetImagesSubscriber?.Dispose();
			streetImagesSubscriber = null;
			prepareWorkoutFailedSub?.Dispose();
			prepareWorkoutFailedSub = null;
			incompatibleWorkoutSub?.Dispose();
			incompatibleWorkoutSub = null;
			_rateWorkoutModel?.Dispose();
			Route?.Clear();
			WorkoutControls?.Clear();
			WorkoutDisplay.Value?.Dispose();
			WorkoutDisplay.Value = null;
			if (connectivity != null)
			{
				connectivity.ConnectivityChanged -= HandleConnectivityChanged;
			}
