			analyticsSource = new AnalyticsSource(nav.WorkoutSource, nav.DashboardIndex);
		}

		private void HandleConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			if (e.IsConnected)
			{
				Task.Run((Func<Task>)LoadAllPreWorkoutData);
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (base.viewShownCount <= 1)
			{
				await Task.Run((Func<Task>)LoadAllPreWorkoutData);
			}
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			if (!base.StartWorkoutService.StartingWorkout && currentConsoleService.ActiveConsole != null)
			{
				currentConsoleService.ActiveConsole.StartKeyEnabled = false;
			}
			streetImagesSubscriber?.Dispose();
			for (int i = 1; i <= 7; i++)
			{
				cache.Invalidate($"map_workout_banner_image_{i}");
			}
			base.RequestedWorkout?.Dispose();
			base.RequestedWorkout = null;
		}

		public void ClosePreWorkout()
		{
			if (analyticsSource.Source == WorkoutSource.DrawMap)
			{
				NavigateToDashboardViewModel();
			}
			else
			{
				DoClose();
			}
		}

		public void RegisterChildVm(BaseViewModel viewModel)
		{
			ChildVms.Add(viewModel);
		}

		private async Task LoadAllPreWorkoutData()
		{
			if (isDisposed)
			{
				return;
			}
			try
			{
				INC<bool> isMetric = IsMetric;
				isMetric.Value = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
				Workout workout = await LoadWorkoutData();
				if (workout == null)
				{
					Log.Trace("Workout", "There was an error loading the workout");
					return;
				}
				bool flag = deviceInfo?.IsBuiltIn ?? false;
				bool flag2 = flag;
				if (flag2)
				{
					flag2 = await ShowErrorIfWorkoutIncompatible(displayBlePairFilter: false, closeScreen: true);
				}
				if (!flag2)
				{
					VideoWorkoutMetadata.Value = workout.Metadata;
					IsMapWorkout.Value = workout.IsGoogleMap;
					if (currentConsoleService.ActiveConsole != null)
					{
						currentConsoleService.ActiveConsole.StartKeyEnabled = true;
					}
					Task item = CheckIfFavorite();
					Task item2 = LoadCompletionData();
					Task videoTrainer = GetVideoTrainer(workout.Metadata?.TrainerId);
					Task item3 = _rateWorkoutModel.UpdateRatingFromApi();
					List<Task> tasks = new List<Task> { item, item2, videoTrainer, item3 };
					await Task.WhenAll(tasks);
					RaisePropertyChanged("RateWorkoutModel");
					if (IsMapWorkout?.Value == true)
					{
						IsDownloadingBannerImage.Value = true;
						StartStreetViewImageCycling();
					}
					else if (base.IsVideoWorkout)
					{
						await TrySetVideoWorkoutHeaderImage();
					}
					else
					{
						await LoadBaseImage();
					}
				}
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error loading workout data on pre-workout screen - Workout ID " + workoutId, exception);
				this.ShowError(Wolf.Core.Resources.AppStrings.pre_workout_load_workout_error, closeAfterDismiss: true);
			}
		}

		protected async Task LoadBaseImage()
		{
			if (!string.IsNullOrEmpty(base.RequestedWorkout?.ImageUri))
			{
				await DownloadBannerImage(base.RequestedWorkout.ImageUri);
			}
		}

		private async Task LoadCompletionData()
		{
			try
			{
				CompletedCount completedCount = await Workout.GetCompletedCount(ifitApi, workoutId);
				CompletedCount.Value = completedCount.Count;
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Error retrieving completion data for workout id " + workoutId, ex.GetBaseException());
			}
		}

		private async Task<Workout> LoadWorkoutData()
		{
			await LoadWorkoutData(workoutId);
			if (base.RequestedWorkout == null)
			{
				return null;
			}
			bool flag = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
			bool valueOrDefault = currentConsoleService?.CurrentConsoleType?.IsAerobicMachine() == true;
			bool flag2 = valueOrDefault || base.RequestedWorkout.IsGoogleMap || base.RequestedWorkout.MustUseEstimatedPace();
			if (valueOrDefault)
			{
				base.RequestedWorkout.Controls = base.RequestedWorkout.ConvertRelativeResistanceControlsToResistance(currentConsoleService.ActiveConsole.ConsoleInfo);
			}
			base.RequestedWorkout.ConvertInclineWorkoutToResistanceIfNecessary(currentConsoleService?.ActiveConsole);
			List<Type> list = new List<Type>();
			if (base.RequestedWorkout.IsGoogleMap)
			{
				list.Add(typeof(PreWorkoutMapPageViewModel));
				Route = base.RequestedWorkout.Geo?.Path?.LatLngs.Select((iFit.Api.DataObjects.LatLng x) => x.ToGoogleLatLng()).ToList();
			}
			if (!flag2)
			{
				list.Add(typeof(PreWorkoutSpeedPageViewModel));
			}
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.ActiveConsole?.ConsoleInfo?.CanSetIncline == true && base.RequestedWorkout.HasControlsFor(Workout.Control.ControlType.Incline))
			{
				list.Add(typeof(PreWorkoutInclinePageViewModel));
			}
			ICurrentConsoleService obj2 = currentConsoleService;
			if (obj2 == null || obj2.ActiveConsole?.ConsoleInfo?.CanSetResistance != true)
			{
				ICurrentConsoleService obj3 = currentConsoleService;
				if (obj3 == null || obj3.ActiveConsole?.ConsoleInfo?.CanSetGear != true)
				{
					goto IL_03ab;
				}
			}
			if (base.RequestedWorkout.HasControlsFor(Workout.Control.ControlType.Resistance) || base.RequestedWorkout.HasControlsFor(Workout.Control.ControlType.RelativeResistance) || base.RequestedWorkout.HasControlsFor(Workout.Control.ControlType.Gear))
			{
				list.Add(typeof(PreWorkoutResistancePageViewModel));
			}
			goto IL_03ab;
			IL_03ab:
			WorkoutControls = base.RequestedWorkout.Controls;
			ConsoleType type = ((currentConsoleService != null) ? currentConsoleService.GetCurrentConsoleType(ConsoleType.Treadmill) : ConsoleType.None);
			double? num = base.RequestedWorkout.ConstantMapWorkoutPaceMps(flag, type);
			WorkoutDisplay.Value = new WorkoutDisplayModel(base.RequestedWorkout, flag);
			_rateWorkoutModel.WorkoutId = workoutId;
			_rateWorkoutModel.AvgWorkoutRating.Value = (int)Math.Round((base.RequestedWorkout.Ratings?.Average).GetValueOrDefault(), MidpointRounding.AwayFromZero);
			_rateWorkoutModel.UserWorkoutRating.Value = (base.RequestedWorkout.Ratings?.CurrentUser).GetValueOrDefault();
			bool valueOrDefault2 = currentConsoleService?.CurrentConsoleType?.IsRower() == true;
			ElevationGain.Value = base.RequestedWorkout.Estimates.GrossElevationGain;
			WorkoutSpeedByUser.Value = !valueOrDefault2 && flag2 && num.HasValue;
			if (WorkoutSpeedByUser.Value)
			{
				double num2 = UnitUtil.Ensure(SpeedUnit.Mps, flag ? SpeedUnit.Kph : SpeedUnit.Mph, num.Value, 1);
				string arg = (flag ? Wolf.Core.Resources.AppStrings.kph : Wolf.Core.Resources.AppStrings.mph);
				EstimatedTime.Value = string.Format(Wolf.Core.Resources.AppStrings.estimated_speed, num2.ToString(), arg);
			}
			Level.Value = base.RequestedWorkout.Difficulty?.Level;
			PagerTypes.Value = list.ToArray();
			IsLoading.Value = false;
			totalDistanceEstimate = base.RequestedWorkout.Estimates.Distance;
			return base.RequestedWorkout;
		}

		private void DoShowSettings()
		{
			ShowViewModel<SettingsViewModel>();
			DoClose();
		}

		private void OnPrepareWorkoutFailed()
		{
			base.RequestedWorkout = null;
			this.ShowErrorIfNoWorkout(base.RequestedWorkout);
		}

		private string SetHeaderLabel()
		{
			if (base.IsVideoWorkout)
			{
				return Wolf.Core.Resources.AppStrings.video.ToUpper();
			}
			if (IsMapWorkout?.Value == true)
			{
				return Wolf.Core.Resources.AppStrings.map.ToUpper();
			}
			return string.Empty;
		}

		protected void StartStreetViewImageCycling()
		{
			nextBannerIdx = 1;
			nextBannerDistance = 0.0;
			bannerDistanceInterval = totalDistanceEstimate / 7.0;
			streetImagesSubscriber = Observable.Timer(TimeSpan.FromSeconds(0.0), TimeSpan.FromSeconds(5.0)).SubscribeAsync((long x) => Task.Run((Func<Task>)DoSwapBannerImageAsync));
		}

		private async Task DoSwapBannerImageAsync()
		{
			INC<byte[]> bannerImage = BannerImage;
			bannerImage.Value = await cache.GetOrFetchObject($"map_workout_banner_image_{nextBannerIdx}", async () => await FetchNextBannerImageAsync(), DateTimeOffset.Now.AddDays(1.0));
			nextBannerIdx++;
			if (nextBannerIdx > 7)
			{
				nextBannerIdx = 1;
			}
			IsDownloadingBannerImage.Value = false;
		}

		private async Task<byte[]> FetchNextBannerImageAsync()
		{
			byte[] result = await LoadStreetViewImage(nextBannerDistance);
			nextBannerDistance += bannerDistanceInterval;
			return result;
		}

