	public static class PreWorkoutViewModelExtensions
	{
		public static void OnIncompatibleWorkout(this IShowSimpleConfirmationDialog viewModel, bool closeScreen = false, Action closeAction = null)
		{
			if (closeAction == null)
			{
				closeAction = delegate
				{
					if (closeScreen)
					{
						viewModel.CloseViewModel.Execute(null);
					}
				};
			}
			viewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.incompatible_workout_error, (Func<CancellationToken, Task<object>>)null, false, (Action<Task<object>>)delegate
			{
				closeAction();
			}, (string)null, Wolf.Core.Resources.AppStrings.ok, (Action)null, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false);
		}

		public static bool ShowDmkError(this IShowSimpleConfirmationDialog viewModel, ConsoleState? currentConsoleState)
		{
			if (currentConsoleState == ConsoleState.SafetyKeyRemoved)
			{
				ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(string.Empty, Wolf.Core.Resources.AppStrings.safety_key_begin_workout, null, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), OnConfirmActionTiming.AfterClose);
				Mvx.Resolve<IDialogPresenter>().ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, arbitraryData);
				return true;
			}
			return false;
		}

		public static bool ShowErrorIfNoWorkout(this IShowSimpleConfirmationDialog viewModel, Workout requestedWorkout)
		{
			if (requestedWorkout == null)
			{
				viewModel.ShowError(Wolf.Core.Resources.AppStrings.preparing_workout_error, closeAfterDismiss: true);
				return true;
			}
			return false;
		}

		public static void ShowError(this IShowSimpleConfirmationDialog viewModel, string error, bool closeAfterDismiss = false)
		{
			viewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, error, (Func<CancellationToken, Task<object>>)null, false, (Action<Task<object>>)delegate
			{
				if (closeAfterDismiss)
				{
					viewModel.CloseViewModel.Execute(null);
				}
			}, (string)null, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false);
		}
	}
	public class PreWorkoutWebviewViewModel : BasePrePostWorkoutWebviewViewModel
	{
		public const int PreWorkoutWebviewTTL = 14400;

		public const string PreWorkoutRoute = "pre";

		public const string WebViewParamProgramId = "programId";

		private IDisposable timeoutSub;

		private PreWorkoutViewModel.NavObject navObject;

		public override int WebviewTTL => 14400;

		public override string WebviewName => "PreWorkoutWebView";

		public override string LogTag => "PreWorkoutWebView";

		protected override string Route => "pre";

		protected override string RecordLogId => base.ScheduleId ?? base.WorkoutId;

		protected override bool ShouldDisplayRepeat => false;

		protected override bool IsPreWorkout => true;

		private TimeSpan timeoutLength { get; set; }

		public PreWorkoutWebviewViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IFeatureFlagManager featureFlagManager, IFailedUploadMonitor failedUploadMonitor, IWolfAnalytics wolfAnalytics, IMvxMessenger messenger, IPlanetFitnessService planetFitnessService, INeedsRefreshService refreshService, IWorkoutApiService workoutApiService, IWebViewDataService webViewDataService, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, IWorkoutFeatureService workoutFeatureService, ICurrentConsoleService currentConsoleService)
		{
			try
			{
				timeoutLength = TimeSpan.FromSeconds(30.0);
				base..ctor(localSettings, ifitApi, featureFlagManager, failedUploadMonitor, wolfAnalytics, messenger, planetFitnessService, refreshService, workoutApiService, webViewDataService, webViewUrlParameterService, webviewSettings, workoutFeatureService, currentConsoleService);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init(PreWorkoutViewModel.NavObject nav)
		{
			SubscribeTimeout();
			navObject = nav;
			referralSource = nav.ReferralSource;
			base.DeepLink = nav.DeepLink;
			await Initialize(nav.WorkoutId, nav.WorkoutSource, nav.ScheduleId, nav.ProgramId, nav.WorkoutContext, nav.DashboardIndex);
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (!base.SuccessfulInitialization)
			{
				ClosePrePostWebView();
				return;
			}
			PreloadWebview();
			if (base.viewShownCount > 1)
			{
				SubscribeTimeout();
			}
			if (base.WebViewIsPreloaded)
			{
				base.WebviewHolder.InitializeWithUpdatedConfigs(GetAdditionalConfig);
			}
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			CleanUpTimeout();
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("AppFailed", (Action)delegate
			{
				Timeout(0L);
			});
		}

		private void SubscribeTimeout()
		{
			CleanUpTimeout();
			if (!base.IsAppInitialized)
			{
				timeoutSub = Observable.Timer(timeoutLength).Subscribe(Timeout);
			}
		}

		protected override void OnTimeToInteractive(IDictionary<string, string> obj)
		{
			base.OnTimeToInteractive(obj);
			Task.Run(async delegate
			{
				await BaseWebViewViewModel.LogEventKey("PreWorkout WebView Screen Time");
			});
		}

		private void Timeout(long time = 0L)
		{
			CleanUpTimeout();
			ShowWorkoutLoadError();
		}

		private void ShowWorkoutLoadError()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.load_workout_details_error, ReloadWebView, confirmButtonText: Wolf.Core.Resources.AppStrings.retry.ToUpper(), cancelButtonText: Wolf.Core.Resources.AppStrings.close.ToUpper(), onClose: null, onCancel: FlushAndClose, dismissible: false);
		}

		private void FlushAndClose()
		{
			base.WebviewHolderFactory.WebviewHolderStore.Flush(Url);
			ClosePrePostWebView();
		}

		private void ReloadWebView()
		{
			base.WebviewHolderFactory.WebviewHolderStore.Flush(Url);
			ClosePrePostWebView();
			ShowViewModel<PreWorkoutWebviewViewModel>(navObject);
		}

		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			IDictionary<string, string> dictionary = (await base.GetAdditionalConfig()) ?? new Dictionary<string, string>();
			dictionary["programId"] = base.ProgramId;
			return dictionary;
		}

		public static void PreloadWebview()
		{
			if (Mvx.TryResolve<IPreWorkoutNavigator>(out var service) && service.IsPreWorkoutWebviewEnabled && Mvx.TryResolve<IConnectivity>(out var service2) && service2.IsConnected && Mvx.TryResolve<IFeatureFlagManager>(out var service3))
			{
				string url = BaseWorkoutWebviewViewModel.GenerateUrl(service3, "pre");
				if (Mvx.TryResolve<IWebviewHolderFactory>(out var service4))
				{
					service4.WebviewHolderStore.PreloadWebView(url, 14400);
				}
			}
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				base.WebviewHolderFactory.WebviewHolderStore.Flush(Url);
				CleanUpTimeout();
				base.Dispose();
				UnregisterChangeHandlers();
			}
		}

		private void CleanUpTimeout()
		{
			timeoutSub?.Dispose();
			timeoutSub = null;
		}

		public override void OnWebviewErrorLoading(object sender, EventArgs e)
		{
			if (ShouldShowDialogOnWorkoutPreloadFailure)
			{
				Timeout(0L);
			}
		}

		protected override void OnAppInitialized()
		{
			base.OnAppInitialized();
			CleanUpTimeout();
		}

		protected override void DoClose()
		{
			ClosePrePostWebView();
		}

