	public class ClubRequestInformationDialogViewModel : ClubEmailProcessingDialogViewModel
	{
		public INC<bool> ConfirmCheckBoxChecked = new NC<bool>(value: false);

		private readonly IIdleLogoutService idleLogoutService;

		public override string Title => Wolf.Core.Resources.AppStrings.club_signup_title;

		public override string Tagline => Wolf.Core.Resources.AppStrings.club_signup_tagline;

		public override string SuccessTitle => Wolf.Core.Resources.AppStrings.club_signup_success_title.ToUpper();

		public string EmailHint => Wolf.Core.Resources.AppStrings.club_signup_email_hint;

		public string CheckboxString => Wolf.Core.Resources.AppStrings.club_signup_checkbox;

		public string SuccessTagline => Wolf.Core.Resources.AppStrings.club_signup_success_tagline;

		[DependsOn(new string[] { "Email", "ConfirmCheckBoxChecked" })]
		public override bool SubmitButtonEnabled
		{
			get
			{
				if (ConfirmCheckBoxChecked.Value && !string.IsNullOrWhiteSpace(Email.Value))
				{
					return userExistenceService.CheckEmailFormat(Email.Value);
				}
				return false;
			}
		}

		public ClubRequestInformationDialogViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IIfitUserExistenceService userExistenceService, IIdleLogoutService idleLogoutService)
			: base(localSettings, ifitApi, userExistenceService)
		{
			try
			{
				this.idleLogoutService = idleLogoutService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override async Task DoSubmit()
		{
			if (!connectivity.IsConnected)
			{
				EmailError.Value = Wolf.Core.Resources.AppStrings.wifi_not_found;
				return;
			}
			SuccessVisible.Value = false;
			try
			{
				Loading.Value = true;
				idleLogoutService?.SetActive(active: false);
				if (await User.ExistsWithEmail(ifitApi, Email.Value).ConfigureAwait(continueOnCapturedContext: false))
				{
					EmailError.Value = Wolf.Core.Resources.AppStrings.club_signup_user_already_exists;
					return;
				}
				if ((await ClubActivity.Create(ifitApi.GatewayService, Email.Value).ConfigureAwait(continueOnCapturedContext: false)).Email == Email.Value)
				{
					SuccessVisible.Value = true;
					return;
				}
				Log.Error("Api", "Club Activity API Returned Unexpected Results");
				EmailError.Value = Wolf.Core.Resources.AppStrings.club_signup_error;
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Erorr sending email address to Club Activity API", exception);
				EmailError.Value = Wolf.Core.Resources.AppStrings.club_signup_error;
			}
			finally
			{
				Loading.Value = false;
				idleLogoutService?.SetActive(active: true);
			}
		}

