	public class ClubUnitAccountSelectionViewModel : WifiStateAndPingViewModel
	{
		private static readonly List<Type> PreLoginDialogTypes = new List<Type>
		{
			typeof(ClubUnitLoginDialogViewModel),
			typeof(ClubUnitForgotPasswordDialogViewModel),
			typeof(ClubRequestInformationDialogViewModel)
		};

		private const string LogTag = "ClubUnitAccountSelection";

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly HeadphoneConnectionHelperBase headphoneConnectionHelper;

		private double minIncline;

		private IDisposable actualInclineChangeSub;

		public IMvxCommand LoginAsGuest => new MvxCommand(DoLoginAsGuest);

		public IMvxCommand LoginUser => new MvxCommand(DoLoginAsUser);

		public override bool ShouldInterceptConsoleStartButton => true;

		public string LogoResourceName { get; private set; }

		public string LoginIconResourceName { get; private set; }

		public string GuestIconResourceName { get; private set; }

		public string BackgroundImageResourceName { get; private set; }

		public string TagLine { get; private set; }

		public string MyAccountString { get; private set; }

		public string WorkoutString { get; private set; }

		public string LoginString { get; private set; }

		public string StartString { get; private set; }

		public ClubUnitAccountSelectionViewModel(ILocalSettings localSettings, IClubLocalSettings clubLocalSettings, IGeoLocationService geoLocationService, IWolfAnalytics wolfAnalytics, HeadphoneConnectionHelperBase headphoneConnectionHelper, ITelevisionSettings televisionSettings, ICurrentConsoleService currentConsoleService, IPreferenceResolver preferenceResolver)
			: base(localSettings, geoLocationService)
		{
			try
			{
				this.wolfAnalytics = wolfAnalytics;
				this.headphoneConnectionHelper = headphoneConnectionHelper;
				LogoResourceName = "ifit_logo_club_selection";
				LoginIconResourceName = "ic_club_user";
				GuestIconResourceName = "ic_club_guest";
				BackgroundImageResourceName = "club_account_selection_bg";
				TagLine = Wolf.Core.Resources.AppStrings.account_selection_tagline;
				MyAccountString = Wolf.Core.Resources.AppStrings.my_account.ToUpper();
				WorkoutString = Wolf.Core.Resources.AppStrings.work_out.ToUpper();
				LoginString = Wolf.Core.Resources.AppStrings.onboarding_login.ToUpper();
				StartString = Wolf.Core.Resources.AppStrings.start.ToUpper();
				clubLocalSettings?.ResetGuestSettings();
				preferenceResolver?.ResetIsMetric();
				preferenceResolver?.ResetGuestWeight();
				televisionSettings?.ResetTelevisionUrl();
				minIncline = (currentConsoleService?.Console?.ConsoleInfo?.MinIncline).GetValueOrDefault();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			ClearCookies();
			await headphoneConnectionHelper.Start().ConfigureAwait(continueOnCapturedContext: false);
			await headphoneConnectionHelper.UnbondWithAllDevices().ConfigureAwait(continueOnCapturedContext: false);
			headphoneConnectionHelper.Stop();
			await wolfAnalytics.StartClubSession().ConfigureAwait(continueOnCapturedContext: false);
			ResetIncline();
		}

		private void ResetIncline()
		{
			Log.Trace("ClubUnitAccountSelection", "Running ResetIncline");
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.Console?.ConsoleInfo?.CanSetIncline == true)
			{
				double mostRecentGrade = facadeFactoryDependencies.GradeFacade.GetMostRecentGrade();
				if (!mostRecentGrade.AlmostEqual(minIncline))
				{
					facadeFactoryDependencies.GradeFacade.SetGrade(minIncline);
					CreateInclineChangedSub();
				}
				else
				{
					CleanUpAndSetZeroIncline();
				}
			}
		}

		private void CreateInclineChangedSub()
		{
			actualInclineChangeSub?.Dispose();
			actualInclineChangeSub = null;
			actualInclineChangeSub = facadeFactoryDependencies.ActualInclineFacade.ObserveActualInclineChanges().Subscribe(ActualInclineChanged);
			currentConsoleService?.Console?.SetSubscribed(subscribed: true, FitnessValue.ActualIncline);
		}

		private void DoLoginAsGuest()
		{
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.IsBuiltinClub && Mvx.TryResolve<IIdleLogoutService>(out var service))
			{
				service.SetActive(active: false);
			}
			NavigateToDashboardViewModel();
		}

		private void DoLoginAsUser()
		{
			Log.Debug("ClubUnitAccountSelection", "Log in button pressed.");
			SafeShowDialog<ClubUnitLoginDialogViewModel>(trackingService, previousMatters: true);
		}

		protected override void DoGoToJoin()
		{
			SafeShowDialog<ClubRequestInformationDialogViewModel>(trackingService, previousMatters: true);
		}

		private void ActualInclineChanged(FitnessValueChange<double> metricChange)
		{
			if (metricChange.Current.AlmostEqual(minIncline))
			{
				CleanUpAndSetZeroIncline();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			CleanUpAndSetZeroIncline();
			UnregisterChangeHandlers();
		}

		private void CleanUpAndSetZeroIncline()
		{
			Log.Trace("ClubUnitAccountSelection", "Running CleanUpAndSetZeroIncline");
			currentConsoleService?.Console?.SetSubscribed(subscribed: false, FitnessValue.ActualIncline);
			actualInclineChangeSub?.Dispose();
			actualInclineChangeSub = null;
			facadeFactoryDependencies.GradeFacade.SetGrade(0.0);
		}

		internal static void SafeShowDialog<T>(IWolfTrackingService trackingService, bool previousMatters = false) where T : BaseViewModel
		{
			if (Mvx.TryResolve<IDialogPresenter>(out var service) && previousMatters)
			{
				foreach (Type preLoginDialogType in PreLoginDialogTypes)
				{
					if (service.IsDialogShown(preLoginDialogType.FullName))
					{
						Log.Debug("ClubUnitAccountSelection", "Not showing " + typeof(T).Name + " because " + preLoginDialogType.Name + " is showing or recently shown.");
						return;
					}
				}
			}
			if (trackingService.LatestViewModel != typeof(T))
			{
				BaseViewModel.ShowDialogViewModel<T>();
				return;
			}
			Log.Debug("ClubUnitAccountSelection", "Not showing " + typeof(T).Name + " because localSettings.LatestViewModel = " + trackingService.LatestViewModel.Name + ".");
		}

