	public class ClubUnitLoginDialogViewModel : ClubUnitPreloginBaseDialogViewModel
	{
		public INC<string> Username = new NC<string>(string.Empty);

		public INC<string> Password = new NC<string>(string.Empty);

		public INC<string> PasswordError = new NC<string>();

		private readonly IIfitLoginService loginService;

		private readonly IUserAvatarImage userAvatar;

		public string UsernameHint => Wolf.Core.Resources.AppStrings.username_hint;

		public string PasswordHint => Wolf.Core.Resources.AppStrings.ifit_login_page_password_hint;

		public string SignInButtonTitle => Wolf.Core.Resources.AppStrings.login_activity_primary_text.ToUpper();

		public ICommand SignIn => new MvxAsyncCommand(DoSignIn);

		public ICommand ForgetPassword => new MvxCommand(DoForgetPassword);

		[DependsOn(new string[] { "Username", "Password", "PasswordError" })]
		public bool SignInButtonEnabled
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(Username.Value) && !string.IsNullOrWhiteSpace(Password.Value) && PasswordError.Value != Wolf.Core.Resources.AppStrings.invalid_login)
				{
					return PasswordError.Value != Wolf.Core.Resources.AppStrings.ifit_login_page_password_error;
				}
				return false;
			}
		}

		public ClubUnitLoginDialogViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IIfitLoginService loginService, IUserAvatarImage userAvatar)
			: base(localSettings, ifitApi)
		{
			try
			{
				this.loginService = loginService;
				this.userAvatar = userAvatar;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task DoSignIn()
		{
			Loading.Value = true;
			wifiService?.RefreshConnectivityState();
			IConnectivity obj = connectivity;
			LoginResult result;
			if (obj == null || !obj.IsConnected)
			{
				result = LoginResult.NoInternetConnection;
			}
			else
			{
				try
				{
					result = await loginService.Authenticate(Username.Value.ToLower(), Password.Value).TimeoutAfter(LoginIfitViewModel.LoginTimeout).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (TimeoutException exception)
				{
					Log.Error("Api", "Authentication Timed Out", exception);
					result = LoginResult.TimeOut;
				}
				catch (Exception exception2)
				{
					Log.Error("Api", "General Exception Occured", exception2);
					result = LoginResult.UnknownFailure;
				}
			}
			await HandleResult(result).ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task HandleResult(LoginResult result)
		{
			switch (result)
			{
			case LoginResult.Success:
				await FetchUserInformationAndNavigateToDashboard().ConfigureAwait(continueOnCapturedContext: false);
				break;
			case LoginResult.UnknownFailure:
			case LoginResult.TimeOut:
				PasswordError.Value = Wolf.Core.Resources.AppStrings.error_logging_in;
				break;
			case LoginResult.InvalidToken:
				PasswordError.Value = Wolf.Core.Resources.AppStrings.authentication_invalid_token;
				break;
			case LoginResult.AlreadyLoggedIn:
				GoToDashboard();
				break;
			case LoginResult.NoInternetConnection:
				PasswordError.Value = Wolf.Core.Resources.AppStrings.wifi_not_found;
				break;
			case LoginResult.InvalidPassword:
				PasswordError.Value = Wolf.Core.Resources.AppStrings.ifit_login_page_password_error;
				break;
			case LoginResult.SubscriptionTypeNotSupported:
				PasswordError.Value = Wolf.Core.Resources.AppStrings.login_error_subscription_type_not_supported_title;
				break;
			default:
				PasswordError.Value = Wolf.Core.Resources.AppStrings.error_logging_in;
				break;
			}
			if (result != LoginResult.Success)
			{
				Log.Warn("Api", "ClubUnitLoginDialogViewModel user unable to login : " + result);
			}
			Loading.Value = false;
		}

		private async Task FetchUserInformationAndNavigateToDashboard()
		{
			User user;
			try
			{
				user = await User.GetMe(ifitApi, populate: true, force: true).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Failure retrieving user information", ex.GetBaseException());
				user = null;
			}
			if (user == null)
			{
				PasswordError.Value = Wolf.Core.Resources.AppStrings.error_logging_in;
				return;
			}
			if (user.Premium != true)
			{
				PasswordError.Value = Wolf.Core.Resources.AppStrings.club_subscription_type_not_eligible;
				Log.Warn("Api", string.Format("{0} user ineligible subscription type: {1}", "ClubUnitLoginDialogViewModel", user.SubscriptionType));
				try
				{
					await ifitApi.Logout(logoutAllUsers: true).ConfigureAwait(continueOnCapturedContext: false);
					return;
				}
				catch (Exception exception)
				{
					Log.Error("Api", "Failure logging out non-club-eligible account", exception);
					return;
				}
			}
			Task.Run(() => userAvatar.GenerateUserAvatarForUser(ifitApi.CurrentlyAuthenticatedUser));
			GoToDashboard();
		}

		private void GoToDashboard()
		{
			DoClose();
			NavigateToDashboardViewModel();
		}

		private void DoForgetPassword()
		{
			ClubUnitAccountSelectionViewModel.SafeShowDialog<ClubUnitForgotPasswordDialogViewModel>(trackingService);
			DoClose();
		}

		[DependsOn(new string[] { "Username", "Password" })]
