	public abstract class WifiStateAndPingViewModel : BaseViewModel
	{
		private IDisposable networkDisconnectedSub;

		private IDisposable monitorReconnectionSub;

		private readonly IGeoLocationService geoLocationService;

		private readonly List<WifiNetworkState> ConnectingWifiNetworkStates = new List<WifiNetworkState>
		{
			WifiNetworkState.Connected,
			WifiNetworkState.Connecting,
			WifiNetworkState.ObtainingIpaddr,
			WifiNetworkState.Authenticating,
			WifiNetworkState.CaptivePortalCheck
		};

		public new readonly INC<bool> IsLoading = new NC<bool>(value: false);

		public ICommand GoToJoin => new MvxCommand(DoGoToJoin);

		protected WifiStateAndPingViewModel(ILocalSettings localSettings, IGeoLocationService geoLocationService)
			: base(localSettings)
		{
			try
			{
				this.geoLocationService = geoLocationService;
				networkDisconnectedSub = wifiService.WhenNetworkStateChanged.Where((WifiNetworkState state) => state == WifiNetworkState.Disconnected).Subscribe(ShowDialogIfNotConnectingInTenSeconds);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected bool CheckWifiAndUpdateUI()
		{
			IsLoading.Value = true;
			bool flag = CheckWifiState();
			if (!flag)
			{
				IsLoading.Value = false;
			}
			return flag;
		}

		public virtual bool CheckWifiState()
		{
			wifiService.RefreshConnectivityState();
			if (wifiService.NetworkState != WifiNetworkState.Connected)
			{
				SafelyShowDefaultNoWifiDialog();
				return false;
			}
			return true;
		}

		public void ShowDialogIfNotConnectingInTenSeconds(WifiNetworkState state)
		{
			DisposeMonitorSub();
			monitorReconnectionSub = (from x in wifiService.WhenNetworkStateChanged.Timeout(TimeSpan.FromSeconds(10.0))
				where ConnectingWifiNetworkStates.Contains(x)
				select x).Take(1).Subscribe(delegate
			{
			}, delegate
			{
				CheckNetworkState();
				DisposeMonitorSub();
			}, DisposeMonitorSub);
		}

		public virtual bool CheckNetworkState()
		{
			wifiService.RefreshConnectivityState();
			if (!connectivity.IsConnected)
			{
				SafelyShowDefaultNoWifiDialog();
				return false;
			}
			return true;
		}

		private void SafelyShowDefaultNoWifiDialog(bool showNoInternetVersion = false)
		{
			if (!Mvx.TryResolve<IDialogPresenter>(out var presenter) || !Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				return;
			}
			service.RequestMainThreadAction(delegate
			{
				if (presenter.CurrentMainViewModel is BaseViewModel)
				{
					NoWifiDialogViewModel noWifiDialogViewModel = presenter.CurrentDialogViewModel<NoWifiDialogViewModel>();
					if (noWifiDialogViewModel == null)
					{
						ShowDefaultNoWifiDialog(showNoInternetVersion);
					}
				}
			});
		}

		private void ShowDefaultNoWifiDialog(bool showNoInternetVersion)
		{
			if (showNoInternetVersion)
			{
				ShowNoInternetConnectionDialog(new NoWifiDialogViewModel.DisplayData
				{
					Title = Wolf.Core.Resources.AppStrings.default_no_internet_connection_title,
					Description = Wolf.Core.Resources.AppStrings.default_no_internet_connection_description,
					OkButtonText = Wolf.Core.Resources.AppStrings.default_no_wifi_ok,
					CancelButtonText = string.Empty,
					TurnOnWifi = false,
					ShowCentered = true
				});
			}
			else
			{
				ShowNoInternetConnectionDialog(new NoWifiDialogViewModel.DisplayData
				{
					Title = Wolf.Core.Resources.AppStrings.default_no_wifi_title,
					Description = Wolf.Core.Resources.AppStrings.default_no_wifi_description,
					CancelButtonText = Wolf.Core.Resources.AppStrings.default_no_wifi_cancel,
					OkButtonText = Wolf.Core.Resources.AppStrings.default_no_wifi_turn_on,
					ShowCentered = true
				});
			}
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			DisposeNetworkSub();
			DisposeMonitorSub();
		}

		public override void Dispose()
		{
			DisposeNetworkSub();
			DisposeMonitorSub();
			base.Dispose();
			UnregisterChangeHandlers();
		}

		private void DisposeNetworkSub()
		{
			networkDisconnectedSub?.Dispose();
			networkDisconnectedSub = null;
		}

		private void DisposeMonitorSub()
		{
			monitorReconnectionSub?.Dispose();
			monitorReconnectionSub = null;
		}

		protected virtual void DoGoToJoin()
		{
		}

		protected void NavigateToRegistration(Action navigationAction)
		{
			if (CheckNetworkState())
			{
				if (geoLocationService.IsLocatedInUs)
				{
					navigationAction();
				}
				else
				{
					ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.prelogin_non_us_dialog_title, Wolf.Core.Resources.AppStrings.prelogin_non_us_dialog_message, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok, (Action)null, (Action)null, true, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
				}
			}
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
		private void OnPropertyChanged(object sender, PropertyChangedEventArgs args)
		{
			string propertyName = args.PropertyName;
		}

