	public class ForgotPasswordViewModel : BaseViewModel
	{
		private readonly IIfitApiService iFitApi;

		private CancellationTokenSource forgotPasswordCTS;

		public readonly INC<bool> ApiBusy = new NC<bool>();

		public readonly INC<string> EmailAddress = new NC<string>();

		public readonly INC<bool?> Result = new NC<bool?>();

		[DependsOn(new string[] { "Result" })]
		public bool HasError
		{
			get
			{
				if (Result.Value.HasValue)
				{
					return !Result.Value.Value;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "EmailAddress", "ApiBusy" })]
		public bool NextEnabled
		{
			get
			{
				if (!ApiBusy.Value && !string.IsNullOrWhiteSpace(EmailAddress.Value))
				{
					return EmailAddress.Value.IsValidEmail();
				}
				return false;
			}
		}

		public ICommand SendEmail => new MvxAsyncCommand(DoSendEmail);

		public ForgotPasswordViewModel(ILocalSettings localSettings, IIfitApiService apiService)
			: base(localSettings)
		{
			try
			{
				iFitApi = apiService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override void DoClose()
		{
			forgotPasswordCTS?.Cancel();
			forgotPasswordCTS?.Dispose();
			forgotPasswordCTS = null;
			base.DoClose();
		}

		private async Task DoSendEmail()
		{
			if (string.IsNullOrWhiteSpace(EmailAddress?.Value) || ApiBusy.Value)
			{
				return;
			}
			ApiBusy.Value = true;
			Result.Value = null;
			forgotPasswordCTS?.Cancel();
			CancellationTokenSource newCTS = (forgotPasswordCTS = new CancellationTokenSource());
			bool success = false;
			try
			{
				success = await User.ForgotPassword(iFitApi, EmailAddress.Value);
			}
			catch (Exception ex)
			{
				success = false;
				Log.Trace("Api", ex.ToString());
			}
			finally
			{
				ApiBusy.Value = false;
				if (newCTS != null && !newCTS.IsCancellationRequested)
				{
					Result.Value = success;
					if (success)
					{
						PresentSuccess();
					}
					else
					{
						PresentFailure();
					}
				}
			}
		}

		private void PresentSuccess()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.success, Wolf.Core.Resources.AppStrings.login_activity_forgot_password_success, DoClose, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper());
		}

		private void PresentFailure()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.login_activity_forgot_password_failure, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), (Action)null, (Action)null, true, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
		}

