	public class LoginIfitViewModel : WifiStateAndPingViewModel
	{
		public class NavObject
		{
			public string UserName { get; set; }
		}

		public static readonly TimeSpan LoginTimeout = TimeSpan.FromSeconds(10.0);

		private readonly IIfitApiService ifitApi;

		private readonly IIfitLoginService ifitLogin;

		private readonly IIfitUserExistenceService userExistence;

		private readonly IUserAvatarImage userAvatar;

		private readonly ITimeZoneService timeZoneService;

		public readonly INC<bool> PasswordIsHidden = new NC<bool>(value: true);

		public readonly INC<string> Email = new NC<string>();

		public readonly INC<string> Password = new NC<string>();

		public readonly INC<bool> EmailError = new NC<bool>(value: false);

		public readonly INC<bool> PasswordError = new NC<bool>(value: false);

		public readonly INC<string> ErrorMessage = new NC<string>();

		public readonly INC<bool> IsSuccessfulLogin = new NC<bool>();

		public readonly INC<bool> EmailFormatValid = new NC<bool>();

		public readonly INC<bool> NeedsThirdPartyLinking = new NC<bool>();

		public IThirdPartyLoginService ThirdPartyLoginService { get; private set; }

		[DependsOn(new string[] { "IsSuccessfulLogin", "IsLoading" })]
		public bool ShowLoadingOverlay
		{
			get
			{
				if (!IsLoading.Value)
				{
					return IsSuccessfulLogin.Value;
				}
				return true;
			}
		}

		[DependsOn(new string[] { "LoginButtonEnabled" })]
		public IMvxAsyncCommand LoginToIfit => new MvxAsyncCommand(DoLoginToIfit, () => LoginButtonEnabled);

		public IMvxAsyncCommand FacebookLoginToIFit => new MvxAsyncCommand(DoFacebookLoginToIfit);

		public ICommand ShowForgotPasswordLink => new MvxCommand(DoShowForgotPassword);

		public ICommand TogglePasswordVisibility => new MvxCommand(DoTogglePasswordVisibility);

		public ICommand CheckEmailFormat => new MvxCommand(DoCheckEmailFormat);

		[DependsOn(new string[] { "EmailError", "Password", "IsLoading" })]
		public bool LoginButtonEnabled
		{
			get
			{
				if (!EmailError.Value && !string.IsNullOrWhiteSpace(Password.Value))
				{
					return !IsLoading.Value;
				}
				return false;
			}
		}

		public bool IsBuiltIn => deviceInfo.IsBuiltIn;

		public LoginIfitViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IIfitLoginService ifitLogin, IIfitUserExistenceService userExistence, IThirdPartyLoginService thirdPartyLoginService, IUserAvatarImage userAvatar, IGeoLocationService geoLocationService, ITimeZoneService timeZoneService)
			: base(localSettings, geoLocationService)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.ifitLogin = ifitLogin;
				this.userExistence = userExistence;
				this.userAvatar = userAvatar;
				this.timeZoneService = timeZoneService;
				ThirdPartyLoginService = thirdPartyLoginService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init(NavObject nav)
		{
			if (!string.IsNullOrEmpty(nav.UserName))
			{
				Email.Value = nav.UserName;
				DoCheckEmailFormat();
			}
		}

		private void DoShowForgotPassword()
		{
			ShowLoginViewModel(null, ShireViewParams.ChildView<ForgotPasswordViewModel>());
		}

		private async Task DoLoginToIfit()
		{
			if (CheckWifiAndUpdateUI() && CheckEmailAndUpdateUI())
			{
				await LoginToIfitAsync();
			}
		}

		private void DoCheckEmailFormat()
		{
			if (string.IsNullOrEmpty(Email.Value))
			{
				EmailFormatValid.Value = false;
			}
			else
			{
				EmailFormatValid.Value = userExistence.CheckEmailFormat(Email.Value) || userExistence.CheckUsernameFormat(Email.Value);
			}
		}

		private bool CheckEmailAndUpdateUI()
		{
			DoCheckEmailFormat();
			EmailError.Value = !EmailFormatValid.Value;
			IsLoading.Value = EmailFormatValid.Value;
			return EmailFormatValid.Value;
		}

		[DependsOn(new string[] { "Email", "Password" })]
		private void ClearErrors()
		{
			EmailError.Value = false;
			PasswordError.Value = false;
		}

		private async Task LoginToIfitAsync()
		{
			LoginResult result;
			try
			{
				result = await ifitLogin.Authenticate(Email.Value.ToLower(), Password.Value).TimeoutAfter(LoginTimeout).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (TimeoutException exception)
			{
				Log.Error("Api", "Authentication Timed Out", exception);
				result = LoginResult.TimeOut;
			}
			await HandleLoginResults(result).ConfigureAwait(continueOnCapturedContext: false);
			IsLoading.Value = false;
		}

		private void LinkFacebookToExistingIfitAccount()
		{
			NeedsThirdPartyLinking.Value = true;
		}

		private async Task JoinIfitFromFacebook()
		{
			if (!NeedsThirdPartyLinking.Value)
			{
				IsLoading.Value = true;
				User user = new User();
				try
				{
					user = await ThirdPartyLoginService.GetUserInfoFromFacebook(user);
				}
				catch (Exception exception)
				{
					Log.Error("Api", "Error when getting user from Facebook", exception);
				}
				InvokeOnMainThread(delegate
				{
					ShowLoginViewModel(JoinIfitViewModel.CreateParamatersObject(user), ShireViewParams.ChildView<JoinUserDetailsViewModel>());
					IsLoading.Value = false;
				});
			}
		}

		private async Task HandleLoginResults(LoginResult result)
		{
			switch (result)
			{
			case LoginResult.Success:
				IsSuccessfulLogin.Value = true;
				await NavigateBasedOnUserStatus();
				break;
			case LoginResult.UnknownFailure:
			case LoginResult.TimeOut:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.error_logging_in;
				ShowLoginViewModel();
				break;
			case LoginResult.FacebookFailure:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.error_fb_logging_in;
				ShowLoginViewModel();
				break;
			case LoginResult.NeedsThirdPartyAssociation:
				InvokeOnMainThread(delegate
				{
					if (Mvx.TryResolve<IDialogPresenter>(out var service))
					{
						ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.onboarding_already_member, Wolf.Core.Resources.AppStrings.already_have_ifit_account, delegate
						{
							LinkFacebookToExistingIfitAccount();
							return (Task<object>)null;
						}, cancellableOperation: false, null, Wolf.Core.Resources.AppStrings.no, Wolf.Core.Resources.AppStrings.yes, OnConfirmActionTiming.BeforeClose, delegate
						{
							Task.Run((Func<Task>)JoinIfitFromFacebook);
						});
						service.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, arbitraryData);
					}
				});
				break;
			case LoginResult.InvalidToken:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.authentication_invalid_token;
				break;
			case LoginResult.AlreadyLoggedIn:
				NavigateToDashboardViewModel();
				break;
			case LoginResult.NoInternetConnection:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.wifi_not_found;
				break;
			case LoginResult.InvalidPassword:
				PasswordError.Value = true;
				break;
			case LoginResult.EmailAvailable:
			case LoginResult.UsernameAvailable:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.invalid_login;
				break;
			}
			if (result != LoginResult.Success)
			{
				Log.Trace("Api", "LoginIfitViewModel user unable to login: " + result);
			}
		}

		private async Task<bool> SwitchToLoggedInUser(string user)
		{
			User user2 = (await ifitApi.GetAuthenticatedUsers()).Find((User x) => x.Username.Equals(user) || x.Email.Equals(user));
			if (user2 == null)
			{
				return false;
			}
			try
			{
				await ifitApi.SwitchUser(user2.Id);
				return true;
			}
			catch (Exception)
			{
				return false;
			}
		}

		private void DoTogglePasswordVisibility()
		{
			PasswordIsHidden.Value = !PasswordIsHidden.Value;
		}

		private async Task DoFacebookLoginToIfit()
		{
			if (CheckWifiAndUpdateUI())
			{
				await DoThirdPartyLogin(ThirdPartyLoginService.LoginWithFacebook).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task DoThirdPartyLogin(Func<Task<LoginResult>> login)
		{
			if (!connectivity.IsConnected)
			{
				ShowLoginViewModel(null, ShireViewParams.DialogView<NoWifiDialogViewModel>());
				return;
			}
			INC<bool> emailError = EmailError;
			bool value = (PasswordError.Value = false);
			emailError.Value = value;
			IsLoading.Value = true;
			await HandleLoginResults(await login());
			IsLoading.Value = false;
		}

		private async Task NavigateBasedOnUserStatus()
		{
			IsSuccessfulLogin.Value = true;
			User user = null;
			try
			{
				user = await User.GetMe(ifitApi);
				await SetUserTimezone(user);
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Error retrieving user status", ex.GetBaseException());
			}
			Task.Run(() => userAvatar.GenerateUserAvatarForUser(ifitApi.CurrentlyAuthenticatedUser));
			if (NeedsThirdPartyLinking.Value)
			{
				try
				{
					User user2 = user;
					user2.Facebook = (await ThirdPartyLoginService.GetUserInfoFromFacebook(user)).Facebook;
					await user.LinkFacebookAccount(ifitApi);
				}
				catch (Exception exception)
				{
					Log.Error("Api", "Error linking User's Third Party App", exception);
				}
			}
			if (user?.Premium == true || !deviceInfo.IsBuiltIn)
			{
				ShowBLEOnboardingOrSkip();
			}
			else
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ifit_subscription, Wolf.Core.Resources.AppStrings.membership_activation_message);
			}
			DoClose();
		}

		private async Task SetUserTimezone(User user)
		{
			if (deviceInfo.IsBuiltIn)
			{
				await timeZoneService.SetTimeZoneAsync(new AvailableTimeZone(TimeZoneTypes.Custom, user.Timezone, user.Timezone, 0));
			}
		}

		public override void Dispose()
		{
			ThirdPartyLoginService?.Dispose();
			ThirdPartyLoginService = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

