{
	public class JoinIfitViewModel : WifiStateAndPingViewModel
	{
		public static Dictionary<LoginProvider, string> CantJoinMessage = new Dictionary<LoginProvider, string> { 
		{
			LoginProvider.facebook,
			Wolf.Core.Resources.AppStrings.unable_to_join_via_facebook
		} };

		public static Dictionary<LoginProvider, string> AlreadyInUseMessage = new Dictionary<LoginProvider, string> { 
		{
			LoginProvider.facebook,
			Wolf.Core.Resources.AppStrings.cant_join_facebook_account_already_in_use
		} };

		private LoginProvider provider;

		private readonly IIfitUserExistenceService userExistence;

		private User _user = new User();

		public readonly INC<string> EmailText = new NC<string>();

		public readonly INC<string> ErrorMessage = new NC<string>();

		public readonly INC<bool> EmailValid = new NC<bool>();

		public readonly INC<bool> EmailError = new NC<bool>();

		private User user
		{
			get
			{
				return _user;
			}
			set
			{
				_user = value;
				EmailText.Value = _user?.Email;
			}
		}

		public ICommand TryContinueToNext => new MvxAsyncCommand(DoTryContinueToNext);

		public IMvxAsyncCommand FacebookJoin => new MvxAsyncCommand(DoJoinViaFacebook);

		public IThirdPartyLoginService ThirdPartyLoginService { get; private set; }

		public bool IsBuiltIn => deviceInfo.IsBuiltIn;

		public JoinIfitViewModel(ILocalSettings localSettings, IIfitUserExistenceService userExistence, IThirdPartyLoginService thirdPartyLoginService, IGeoLocationService geoLocationService)
			: base(localSettings, geoLocationService)
		{
			try
			{
				this.userExistence = userExistence;
				ThirdPartyLoginService = thirdPartyLoginService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task DoCheckEmailValid()
		{
			if (CheckWifiAndUpdateUI())
			{
				EmailValid.Value = false;
				if (userExistence.CheckEmailFormat(EmailText.Value))
				{
					INC<bool> emailValid = EmailValid;
					emailValid.Value = await DoCheckEmailAvailability() == LoginResult.EmailAvailable;
				}
				else
				{
					ErrorMessage.Value = Wolf.Core.Resources.AppStrings.invalid_email_address;
					EmailError.Value = !EmailValid.Value;
				}
				IsLoading.Value = false;
			}
		}

		private async Task DoJoinViaFacebook()
		{
			if (CheckWifiAndUpdateUI())
			{
				provider = LoginProvider.facebook;
				await DoThirdPartyJoin(ThirdPartyLoginService.GetUserInfoFromFacebook);
			}
		}

		private async Task DoThirdPartyJoin(Func<User, Task<User>> join)
		{
			if (!connectivity.IsConnected)
			{
				ShowLoginViewModel(null, ShireViewParams.DialogView<NoWifiDialogViewModel>());
				return;
			}
			try
			{
				EmailError.Value = false;
				IsLoading.Value = true;
				user = await join(user);
				ShowLoginViewModel(CreateParamatersObject(user), ShireViewParams.ChildView<JoinUserDetailsViewModel>());
			}
			catch (ArgumentNullException ex)
			{
				Log.Error("Api", "Unable to join via " + provider, ex.GetBaseException());
				ErrorMessage.Value = CantJoinMessage[provider];
			}
			catch (Exception ex2)
			{
				Log.Error("Api", "Unable to join via " + provider, ex2.GetBaseException());
				ErrorMessage.Value = AlreadyInUseMessage[provider];
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		private async Task<LoginResult> DoCheckEmailAvailability()
		{
			user.Email = EmailText.Value;
			LoginResult loginResult = await userExistence.CheckEmailUsernameAvailability(user.Email);
			bool flag = loginResult != LoginResult.NoInternetConnection;
			switch (loginResult)
			{
			case LoginResult.EmailInUse:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.email_in_use;
				break;
			case LoginResult.NoInternetConnection:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.no_network_connectivity;
				break;
			case LoginResult.InvalidUsername:
			case LoginResult.UsernameAvailable:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.invalid_email_address;
				break;
			default:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_to_join;
				break;
			case LoginResult.EmailAvailable:
				break;
			}
			EmailValid.Value = loginResult == LoginResult.EmailAvailable;
			EmailError.Value = !EmailValid.Value && flag;
			return loginResult;
		}

		private async Task DoTryContinueToNext()
		{
			if (CheckWifiAndUpdateUI())
			{
				await DoCheckEmailValid();
				if (EmailValid.Value)
				{
					ShowLoginViewModel(CreateParamatersObject(user), ShireViewParams.ChildView<JoinUserDetailsViewModel>());
				}
			}
		}

		public static JoinUserDetailsViewModel.Parameters CreateParamatersObject(User user)
		{
			return new JoinUserDetailsViewModel.Parameters
			{
				Email = user.Email,
				Username = user.Username,
				Firstname = user.Firstname,
				Lastname = user.Lastname,
				Birthday = user.Birthday.ToString(),
				Gender = user.Gender,
				Facebook = user.Facebook
			};
		}

		public override void Dispose()
		{
			ThirdPartyLoginService.Dispose();
			ThirdPartyLoginService = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

