		[DependsOn(new string[] { "Birthday" })]
		public bool BirthdayIsValid => Birthday.Value.HasValue & (Birthday.Value <= DateTime.Today.AddYears(-13));

		[DependsOn(new string[] { "Password" })]
		public bool PasswordIsValid
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(Password.Value))
				{
					return !PasswordTooShort;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "Password" })]
		public bool PasswordTooShort
		{
			get
			{
				if (Password.Value.Length > 0)
				{
					return Password.Value.Length < 8;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "Email" })]
		public bool EmailValid
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(Email.Value))
				{
					return Email.Value.IsValidEmail();
				}
				return false;
			}
		}

		[DependsOn(new string[] { "Email" })]
		public bool EmailError
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(Email.Value))
				{
					return !Email.Value.IsValidEmail();
				}
				return false;
			}
		}

		[DependsOn(new string[] { "ActivationCode", "HasActivationCode", "ActivationCodeError" })]
		public bool ActivationCodeValid
		{
			get
			{
				if (!ActivationCodeError.Value && HasActivationCode.Value && !string.IsNullOrWhiteSpace(ActivationCode.Value))
				{
					return ActivationCode.Value.IsValidActivationCode();
				}
				return false;
			}
		}

		[DependsOn(new string[] { "HasActivationCode", "ActivationCodeValid", "EmailValid", "PasswordIsValid", "FullNameIsValid", "BirthdayIsValid", "IsLoading" })]
		public bool NextButtonEnabled
		{
			get
			{
				if (EmailValid && PasswordIsValid && FullNameIsValid.Value && BirthdayIsValid && !IsLoading.Value)
				{
					if (HasActivationCode.Value)
					{
						return ActivationCodeValid;
					}
					return true;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "FirstName", "LastName" })]
		public void FullNameValid()
		{
			if (string.IsNullOrEmpty(FirstName.Value) || string.IsNullOrWhiteSpace(LastName.Value))
			{
				FullNameIsValid.Value = false;
			}
			else
			{
				FullNameIsValid.Value = HumanNameConverter.IsValidFirstLast(FirstName.Value.Trim(), LastName.Value.Trim());
			}
