		private async Task DoJoinViaProvider()
		{
			_ = 1;
			try
			{
				IsLoading.Value = true;
				await ValidateActivationCode();
				if (!ActivationCodeError.Value)
				{
					await CreateOrUpdateUser();
				}
			}
			catch
			{
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_to_join;
			}
			finally
			{
				IsLoading.Value = false;
			}
		}

		private async Task HandleJoinUserDetailsResult(LoginResult result)
		{
			switch (result)
			{
			case LoginResult.Success:
				userHasBeenCreated = true;
				preferenceResolver.SetIsMetric(preferenceResolver.IsMetric);
				await NavigateBasedOnJoinResult();
				break;
			case LoginResult.EmailInUse:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.email_in_use;
				break;
			case LoginResult.UnknownFailure:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_to_join;
				break;
			case LoginResult.FacebookFailure:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_to_join_via_facebook;
				break;
			case LoginResult.InvalidToken:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_to_join_via_ifit;
				break;
			case LoginResult.InvalidPassword:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.ifit_login_page_password_error;
				break;
			case LoginResult.UnableToCreateUser:
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.ifit_login_page_unable_to_create_user;
				break;
			case LoginResult.GoogleFailure:
			case LoginResult.NeedsThirdPartyAssociation:
			case LoginResult.AlreadyLoggedIn:
			case LoginResult.NoInternetConnection:
			case LoginResult.TimeOut:
			case LoginResult.InvalidUsername:
				break;
			}
		}

		private async Task CreateOrUpdateUser()
		{
			_ = 3;
			try
			{
				if (userHasBeenCreated)
				{
					user = await user.Update(ifitApi);
				}
				else
				{
					Tuple<User, LoginResult> tuple = await ifitJoin.CreateAndLoginUser(user);
					user = tuple.Item1;
					await HandleJoinUserDetailsResult(tuple.Item2);
				}
				await timeZoneService.SetTimeZoneAsync(new AvailableTimeZone(TimeZoneTypes.Custom, user.Timezone, user.Timezone, 0));
			}
			catch (Exception exception)
			{
				Log.Error("JoinUserDetails", "Problems In `JoinUserDetailViewModel.CreateOrUpdateUser`", exception);
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_to_join;
			}
		}

		private async Task ValidateActivationCode()
		{
			if (!HasActivationCode.Value)
			{
				return;
			}
			PromoCode promoCode = null;
			try
			{
				promoCode = await PromoCode.GetPromoCode(ifitApi, ActivationCode.Value, force: true);
				if (promoCode == null || !promoCode.IsValid)
				{
					Log.Trace("JoinUserDetails", $"Promo code had invalid dates {promoCode?.StartDate} - {promoCode?.EndDate} or did not contain any applicable items or was null");
					ActivationCodeError.Value = true;
					return;
				}
				ActivationCodeError.Value = false;
			}
			catch (Exception ex)
			{
				Log.Error("JoinUserDetails", "Error getting promo code", ex.GetBaseException());
				ActivationCodeError.Value = true;
			}
			if (promoCode?.PercentDiscount == 100)
			{
				storeItemPromoCode = promoCode;
				membershipSettings.ActivationCode = ActivationCode.Value;
			}
		}

		private async Task SetChosenStoreItem()
		{
			if (storeItemPromoCode == null)
			{
				Log.Trace("JoinUserDetails", "SetChosenStoreItem - No promo code (expected if user never filled it out), not pulling StoreItem");
				return;
			}
			string storeItemId = string.Empty;
			try
			{
				storeItemId = storeItemPromoCode.Items.FirstOrDefault();
				StoreItem storeItem = await StoreItem.GetItem(ifitApi, storeItemId);
				if (storeItem.Id == storeItemId)
				{
					membershipSettings.ChosenStoreItem = storeItem;
					Log.Trace("JoinUserDetails", "SetChosenStoreItem - StoreItem(" + storeItem?.Id + ") successfully obtained and assigned as IMembershipSettings.ChosenStoreItem");
					return;
				}
				Log.Error("JoinUserDetails", "SetChosenStoreItem - StoreItem(" + storeItem?.Id + ") did not match PromoCode storeItemId(" + storeItemId + "), this is highly unexpected");
			}
			catch (Exception exception)
			{
				Log.Error("JoinUserDetails", "SetChosenStoreItem - Unable to get StoreItem for promoCode(" + storeItemPromoCode?.Code + ") - storeItemId(" + storeItemId + ")", exception);
			}
		}

		private async Task NavigateBasedOnJoinResult()
		{
			if (storeItemPromoCode?.BypassBilling ?? false)
			{
				await PerformNonBillingPromoOrder();
			}
			else if (membershipSettings.ChosenStoreItem != null)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ifit_subscription, Wolf.Core.Resources.AppStrings.membership_activation_message);
			}
			else
			{
				ActivationCodeError.Value = true;
			}
		}

		private async Task PerformNonBillingPromoOrder()
		{
			_ = 1;
			try
			{
				Order.Cart cart = new Order.Cart
				{
					Items = new List<Order.Item>
					{
						new Order.Item
						{
							Id = storeItemPromoCode.Items[0],
							Quantity = 1
						}
					},
					PromoCode = storeItemPromoCode.Code
				};
				if (!(await (await Order.Create(ifitApi, cart)).Charge(ifitApi)).OrderCharged)
				{
					ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_place_order;
					return;
				}
				membershipSettings.Reset();
				NavigateToDashboardViewModel();
			}
			catch (Exception ex)
			{
				Log.Error("JoinUserDetails", ex.ToString());
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.unable_place_order;
			}
		}

