			: base(localSettings, featureFlagManager, ifitApi, iFitGatewayApi, settingsRouter, wolfSharingService, dialogPresenter, postWorkoutInteractor, failedUploadMonitor, appReviewService, webViewUrlParameterService, webviewSettings, currentConsoleService, idleLogoutService, bleConsoleService, bleRadioStatusService, analytics)
