		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("ModalClosed", base.DoFinish);
		}

		public new Task Init(LogScreenNavObject nav)
		{
			string resourceName = "Wolf.Core.Source.ViewModels.PostWorkout.Content.OfflinePostWorkoutWebview.html";
			string webviewHtml = EmbeddedResourceUtil.ReadEmbeddedResourceText(typeof(OfflinePostWorkoutWebviewViewModel), resourceName);
			_webviewHtml = webviewHtml;
			return Task.FromResult(0);
		}

		public void AddMetric(List<MetricModel> metrics, string type, StatInfoLabelType statType, bool fromLeft = false)
		{
			LogScreenStatModel logScreenStatModel = SummaryStats.Value.FirstOrDefault((LogScreenStatModel x) => x.StatType == statType);
			if (logScreenStatModel != null)
			{
				string value = (fromLeft ? logScreenStatModel.LeftValue : logScreenStatModel.MainValue);
				string text = (fromLeft ? logScreenStatModel.LeftUnits : logScreenStatModel.MainUnits);
				if (!string.IsNullOrWhiteSpace(value))
				{
					metrics.Add(new MetricModel(type, value, string.IsNullOrWhiteSpace(text) ? null : text?.ToLower()));
				}
			}
		}

		public override Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			IDictionary<string, string> dictionary = new Dictionary<string, string>();
			dictionary["title"] = base.RequestedWorkout.Title;
			dictionary["overview"] = base.RequestedWorkout.Description;
			dictionary["metrics"] = JsonConvert.SerializeObject(GetMetricsList(), Formatting.None, new JsonSerializerSettings
			{
				NullValueHandling = NullValueHandling.Ignore
			});
			return Task.FromResult(dictionary);
		}

		protected override List<StatInfoLabelType> GetConfigFor(ActivityLog log)
		{
			return SummaryStatConfiguration.GetConfigFor(log.Stats);
		}

		private List<MetricModel> GetMetricsList()
		{
			List<MetricModel> list = new List<MetricModel>();
			AddMetric(list, "distance", StatInfoLabelType.Distance);
			AddMetric(list, "calories", StatInfoLabelType.Calories);
			AddMetric(list, "cadence", StatInfoLabelType.Cadence);
			AddMetric(list, "incline", StatInfoLabelType.Incline);
			AddMetric(list, "max-incline", StatInfoLabelType.Incline, fromLeft: true);
			AddMetric(list, "pace", StatInfoLabelType.Pace);
			AddMetric(list, "speed", StatInfoLabelType.Speed);
			AddMetric(list, "max-speed", StatInfoLabelType.Speed, fromLeft: true);
			AddMetric(list, "time", StatInfoLabelType.Time);
			AddMetric(list, "heart-rate", StatInfoLabelType.HeartRate);
			AddMetric(list, "max-heart-rate", StatInfoLabelType.HeartRate, fromLeft: true);
			AddMetric(list, "watts", StatInfoLabelType.Watts);
			AddMetric(list, "elevation-gain", StatInfoLabelType.Elevation);
			AddMetric(list, "elevation-loss", StatInfoLabelType.Elevation, fromLeft: true);
			AddMetric(list, "max-grade", StatInfoLabelType.Grade);
			AddMetric(list, "strokes-per-minute", StatInfoLabelType.StrokesPerMin);
			AddMetric(list, "500-split", StatInfoLabelType.FiveHundred);
			AddMetric(list, "resistance", StatInfoLabelType.Resistance);
			AddMetric(list, "max-resistance", StatInfoLabelType.Resistance, fromLeft: true);
			AddMetric(list, "fit-score", StatInfoLabelType.XScore);
			Workout requestedWorkout = base.RequestedWorkout;
			if (requestedWorkout != null)
			{
				Workout.DifficultyGroup difficulty = requestedWorkout.Difficulty;
				if (difficulty != null)
				{
					_ = difficulty.Score;
					if (true)
					{
						AddMetric(list, "intensity", base.RequestedWorkout.Difficulty.Score.ToString());
					}
				}
			}
			AddMetric(list, "total-reps", StatInfoLabelType.TotalReps);
			return list;
		}

		private void AddMetric(List<MetricModel> metrics, string type, string value, string units = null)
		{
			metrics.Add(new MetricModel(type, value, units));
		}

		public Task<string> GetData(Uri uri)
		{
			string empty = string.Empty;
			return Task.FromResult(uri.Host switch
			{
				"title" => base.RequestedWorkout.Title, 
				"overview" => base.RequestedWorkout.Description, 
				"metrics" => System.Text.Json.JsonSerializer.Serialize(GetMetricsList()), 
				_ => throw new KeyNotSupportedException("OfflinePostWorkout didn't recognize key " + uri.OriginalString), 
			});
		}

		public string[] GetAllSupportedKeys()
		{
			return new string[3] { "title", "overview", "metrics" };
		}

		public override void Dispose()
		{
			webViewDataService.UnregisterProvider(this);
			((BaseLogScreenViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

