		public async Task Init(BaseLogScreenViewModel.LogScreenNavObject nav)
		{
			WebviewUrl.Value = BaseWorkoutWebviewViewModel.GenerateUrl(featureFlagManager, Route);
			navObject = nav;
			activityLogId = nav.ActivityLogId;
			base.JustCompletedWorkout = nav.PostWorkout;
			ShouldShowBackground.Value = base.JustCompletedWorkout;
			postWorkoutInteractor.Initialize(nav, this);
			if (!base.JustCompletedWorkout)
			{
				await Initialize(await GetWorkoutId(), WorkoutSource.Summary);
			}
			if (base.JustCompletedWorkout && localSettings.IsRoboRunMode)
			{
				FinishAndNavigateAway();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			postWorkoutInteractor.DisableStartKey();
			postWorkoutInteractor.CheckAndShowSafetyKeyDialog();
			postWorkoutInteractor.CheckAndShowConsoleErrorDialog();
			if (base.JustCompletedWorkout)
			{
				Workout requestedWorkout = workoutSettings.WorkoutContainer?.Workout;
				MetricStats runningStats = workoutSettings.WorkoutContainer?.Stats?.RunningStats;
				WorkoutRunnerContext workoutRunnerContext = workoutSettings.WorkoutContainer?.WorkoutRunner?.RunContext ?? WorkoutRunnerContext.DefaultOnDemandContext;
				string programId = workoutSettings.WorkoutContainer?.ProgramId;
				string challengeId = workoutSettings.WorkoutContainer?.ChallengeId;
				uploadedActivityLog = (await postWorkoutInteractor.PopulateActivityLog(activityLogId, requestedWorkout?.Id, programId, challengeId, runningStats, workoutRunnerContext)).ActivityLog;
				activityLogId = uploadedActivityLog?.Id;
				if (uploadedActivityLog != null)
				{
					base.WorkoutId = uploadedActivityLog.WorkoutId;
				}
				appReviewService.RequestReview();
				await UploadMaxHeartRateIfNecessary(requestedWorkout);
				await UploadPulseMetricsIfNecessary();
			}
			if (base.WebViewIsPreloaded)
			{
				base.WebviewHolder.InitializeWithUpdatedConfigs(GetAdditionalConfig);
			}
			CheckForNativeMessagesReceivedBeforeViewModelShown();
			await dashboardWebviewCalls.Preload();
		}

		private void CheckForNativeMessagesReceivedBeforeViewModelShown()
		{
			if (Bridge.NativeMessagesReceivedBeforeViewModelShown.Any((DelayedMethodCall x) => x.MethodName == "TimeToInteractive"))
			{
				OnTimeToInteractive(null);
			}
			Bridge.NativeMessagesReceivedBeforeViewModelShown.Clear();
		}

		private async Task UploadMaxHeartRateIfNecessary(Workout requestedWorkout)
		{
			_ = 3;
			try
			{
				if (requestedWorkout != null)
				{
					WorkoutIsHeartrateTest = HRTrainingService.IsHRTestWorkoutId(requestedWorkout.Id);
				}
				MetricStats metricStats = workoutSettings.WorkoutContainer?.Stats?.RunningStats;
				int valueOrDefault = (metricStats?.PulseChanges?.Count).GetValueOrDefault();
				if (!base.JustCompletedWorkout || valueOrDefault == 0)
				{
					return;
				}
				int num = ((metricStats != null) ? (await metricStats.GetMaxHeartRate()) : 0);
				int maximumHeartRate = num;
				if (maximumHeartRate != 0)
				{
					User user = await User.GetMe(IfitApi);
					await user.GetHeartRateSettings(IfitApi);
					if (WorkoutIsHeartrateTest)
					{
						Log.Trace("Workout", $"Saving new maximum heart rate {maximumHeartRate}");
						user.HeartRateSettings.MaxHeartRate = maximumHeartRate;
						await user.UpdateHeartRateSettings(IfitApi);
					}
				}
			}
			catch (Exception ex)
			{
				Log.Error("Workout", $"Unable to upload max heart rate: {ex}", ex);
			}
		}

		private async Task UploadPulseMetricsIfNecessary()
		{
			try
			{
				if (WorkoutFeatureService.IsSmartAdjustAvailable(currentConsoleService?.ActiveConsole?.ConsoleInfo?.MachineType))
				{
					IInWorkoutMetricsManager inWorkoutMetricsManager = workoutSettings?.WorkoutContainer?.Stats?.RunningStats?.InWorkoutMetrics;
					if (inWorkoutMetricsManager != null)
					{
						await inWorkoutMetricsManager.Post(IfitApi);
					}
				}
			}
			catch (Exception ex)
			{
				Log.Error("Workout", $"Unable to upload pulse metrics: {ex}", ex);
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("WorkoutCompleted", FinishAndNavigateAway);
			bridge.Expose("AppFailed", OnAppFailed);
			bridge.ExposeTask("OpenConnectedAppWorkout", OpenConnectedAppWorkoutAsync);
		}

		public override void ClosePrePostWebView()
		{
			if (!base.JustCompletedWorkout)
			{
				ChangePresentation(new CloseFullScreenModalPresentationHint(this));
			}
			FinishAndNavigateAway();
		}

		private void OnAppFailed()
		{
			appHasFailed = true;
			ShowNoWifiLogScreen(navObject);
			DoClose();
		}

		private async Task OpenConnectedAppWorkoutAsync(IDictionary<string, string> parameters)
		{
			try
			{
				ConnectedApp connectedApp = ConnectedAppsUtil.ToConnectedApp(parameters["origin"]);
				string connectedAppWorkoutId = parameters["originId"];
				IConnectedAppWorkoutsService workoutsService = connectedAppsCollection[connectedApp].WorkoutsService;
				if (workoutsService != null)
				{
					await workoutsService.OpenConnectedAppWorkoutAsync(connectedAppWorkoutId).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception ex)
			{
				Log.Error(LogTag, $"Error during the opening of the connected app workout: {ex}", ex);
			}
		}

		protected async Task<string> GetWorkoutId()
		{
			try
			{
				ActivityLog activityLog = await ActivityLog.Get(IfitApi, activityLogId);
				string workoutId = activityLog.WorkoutId;
				activityLog.Dispose();
				return workoutId;
			}
			catch (Exception ex)
			{
				Log.Trace(LogTag, "Error loading activity log from api", ex.GetBaseException());
			}
			return null;
		}

		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			IDictionary<string, string> dictionary = (await base.GetAdditionalConfig()) ?? new Dictionary<string, string>();
			dictionary["workoutId"] = base.WorkoutId;
			dictionary["enableSocialSharing"] = featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfWorkoutsWebviewSocialSharingEnabled).ToString();
			dictionary["achievementStats"] = JsonConvert.SerializeObject(achievementStatsService.AchievementStats);
			return dictionary;
		}

		protected override void OnTimeToInteractive(IDictionary<string, string> obj)
		{
			base.OnTimeToInteractive(obj);
			Task.Run((Func<Task>)LogWebviewLoadTime);
		}

		private async Task LogWebviewLoadTime()
		{
			TimedEvent ev = await EventService.Instance.FetchEvent("PostWorkout WebView Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (ev == null)
			{
				Log.Trace("WebView", "PostWorkoutWebviewLoadTime Event is null in PostWorkoutWebviewViewModel");
				return;
			}
			if (!ev.Properties.ContainsKey("activityLogId"))
			{
				ev.Properties["activityLogId"] = activityLogId;
			}
			if (!ev.Properties.ContainsKey("activityLogDurationSeconds"))
			{
				ActivityLog activityLog = await activityLogRepository.FetchActivityLog(activityLogId);
				ev.Properties["activityLogDurationSeconds"] = TimeSpan.FromMilliseconds(activityLog?.Duration ?? 0).TotalSeconds;
			}
			await BaseWebViewViewModel.LogEventKey(ev.Key);
		}

		protected override void OnNavigateToPreparingWorkoutViewModel()
		{
			base.OnNavigateToPreparingWorkoutViewModel();
			Log.Trace("Workout", "PostWorkoutWebviewViewModel setting isStartingNewWorkout to true");
			isStartingNewWorkout = true;
		}

		public void FinishAndNavigateAway()
		{
			if (hasNavigatedAway)
			{
				return;
			}
			hasNavigatedAway = true;
			if (base.JustCompletedWorkout)
			{
				string text = MainToolbarViewModel.GetWallEUrlWhenNeed(featureFlagManager, FeatureFlags.WallEDashboardUrl, FeatureFlags.WolfDashboardWebviewUrl);
				if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service))
				{
					text = service.GenerateWebViewUrlWithParameters(text);
				}
				postWorkoutInteractor.NavigateAway(uploadedActivityLog?.Duration ?? 0, base.LogOut.Execute, NavigateToDashboardViewModel, base.ShowViewModel<DashboardViewModel>);
				webviewHolderFactory.WebviewHolderStore.FlushAllExcluding(text);
			}
			else
			{
				base.WebviewHolderFactory.WebviewHolderStore.Flush(Url);
				DoClose();
			}
		}

		public override void NavigateToDashboardViewModel(object parameterValuesObject = null, bool clearStack = true)
		{
			if (isStartingNewWorkout)
			{
				Log.Trace("Workout", "PostWorkoutWebviewViewModel skipping navigation to DashboardViewModel because of starting a workout");
			}
			else
			{
				base.NavigateToDashboardViewModel(parameterValuesObject, clearStack);
			}
		}

		protected override void InternetGainedOrLost(RefreshCause cause)
		{
			base.InternetGainedOrLost(cause);
			if (!hasFailedAlready && !hasNavigatedAway && cause == RefreshCause.LostInternet)
			{
				ShowNoWifiLogScreen(new BaseLogScreenViewModel.LogScreenNavObject
				{
					ActivityLogId = activityLogId,
					PostWorkout = base.JustCompletedWorkout
				});
			}
		}

		public void ShowNoWifiLogScreen(BaseLogScreenViewModel.LogScreenNavObject navObject)
		{
			if (base.JustCompletedWorkout)
			{
				ShowViewModel<NoWifiLogScreenViewModel>(navObject);
			}
			else
			{
				ShowViewModel<EmbeddedNoWifiDashboardViewModel>();
			}
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				base.Dispose();
				if (!appHasFailed && base.JustCompletedWorkout)
				{
					postWorkoutInteractor.CleanWorkout();
					achievementStatsService.ClearAchievementStats();
				}
				uploadedActivityLog?.Dispose();
				uploadedActivityLog = null;
				UnregisterChangeHandlers();
			}
		}

		public static async Task PreloadWebview(string activityLogId, Workout.WorkoutContext workoutContext)
		{
			if (!string.IsNullOrWhiteSpace(activityLogId) && Mvx.TryResolve<IFeatureFlagManager>(out var service) && service.IsFeatureEnabled(FeatureFlags.WolfUsePostworkoutWebview) && Mvx.TryResolve<ILocalSettings>(out var localSettings) && Mvx.TryResolve<IIfitApiService>(out var ifitApi) && Mvx.TryResolve<IDeviceInformation>(out var deviceInfo) && Mvx.TryResolve<IWebViewConfigService>(out var webViewConfigService) && Mvx.TryResolve<IWebviewHolderFactory>(out var service2))
			{
				string url = BaseWorkoutWebviewViewModel.GenerateUrl(service, "post");
				if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service3))
				{
					url = service3.GenerateWebViewUrlWithParameters(url);
				}
				bool leaderBoardEnabled = service.IsLeaderboardFeatureEnabledForWorkout(workoutContext);
				service2.WebviewHolderStore.PreloadWebView(url, 600, WebviewHolderType.Default, async delegate
				{
					IDictionary<string, string> dictionary = await BaseWorkoutWebviewViewModel.GetInitializeAppConfig(localSettings, ifitApi, webViewConfigService, activityLogId, workoutContext, deviceInfo.IsTablet, shouldDisplayRepeat: false, leaderBoardEnabled, WorkoutSource.NA.ToString());
					dictionary[JavascriptBridge.MethodToSetConfigs] = "InitializeApp";
					return dictionary;
