		}

		public override void DoShowNoWifiScreen()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.default_lost_wifi_title, Wolf.Core.Resources.AppStrings.default_lost_wifi_message, OnDialogConfirm, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.okay_title, null, null, dismissible: false);
		}

		protected override void InjectCustomBehaviorParameters(IDictionary<string, string> parameters)
		{
			if (parameters.ContainsKey("ActivityLogId"))
			{
				throw new ArgumentException("ActivityLogId was passed from WebView and injected from native. Please decide which place it should come of and pass once.");
			}
			parameters.Add("ActivityLogId", activityLogId);
		}

		protected override void DoClose()
		{
			ClosePrePostWebView();
		}

		private void OnDialogConfirm()
		{
			ShowNoWifiLogScreen(new BaseLogScreenViewModel.LogScreenNavObject
			{
				PostWorkout = true
			});
		}

		public virtual IPostWorkoutInteractor GetPostWorkoutInteractor()
		{
			return postWorkoutInteractor;
		}

		public override void OnWebviewErrorLoading(object sender, EventArgs e)
		{
			if (!hasFailedAlready && !hasNavigatedAway)
