		public static Task<IDictionary<string, string>> GetWebViewConfigs()
		{
			IDictionary<string, string> dictionary = new Dictionary<string, string>();
			if (Mvx.TryResolve<IIfitApiService>(out var service))
			{
				IWolfEnvironment wolfEnvironment = service.Environment as IWolfEnvironment;
				dictionary[JavascriptBridge.MethodToSetConfigs] = "SetInitialConfigValues";
				dictionary["clientId"] = wolfEnvironment.OnboardingClientId;
				dictionary["clientSecret"] = wolfEnvironment.OnboardingClientSecret;
