				if (Mvx.TryResolve<ILocalSettings>(out var service2))
				{
					if (service2.InDebugMode)
					{
						dictionary["baseUrl"] = wolfEnvironment.DebugEndpoint;
						dictionary["moesifAppId"] = wolfEnvironment.MoesifApplicationId;
					}
					else
					{
						dictionary["baseUrl"] = wolfEnvironment.Endpoint;
					}
				}
				if (Mvx.TryResolve<IWolfTrackingService>(out var service3))
				{
					dictionary["isFirstTime"] = service3.IsFirstTime.ToString();
				}
				if (Mvx.TryResolve<IFacebookIdService>(out var service4))
				{
					dictionary["facebookAppId"] = service4.FacebookAppId;
				}
				dictionary["mediaType"] = Wolf.Core.Resources.AppStrings.tablet;
				if (Mvx.TryResolve<IDeviceInformation>(out var service5))
				{
					if (!service5.IsTablet)
					{
						dictionary["mediaType"] = Wolf.Core.Resources.AppStrings.phone;
					}
					dictionary["isBuiltIn"] = service5.IsBuiltIn.ToString();
				}
			}
			else
			{
				Log.Error("Onboarding", "Failed to resolve apiService in OnboardingViewModel constructor.");
			}
			return Task.FromResult(dictionary);
		}

