		public BleOnboardingWebViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IIfitApiService apiService, IThirdPartyLoginService thirdPartyLoginService, IDashboardWebviewCalls dashboardWebviewCalls, IFailedUploadMonitor failedUploadMonitor, IWolfAnalytics wolfAnalytics, IBleOnboardingScanningService bleOnboardingScanningService, IBleOnboardingConnectingService bleOnboardingConnectingService, IBleDeviceSupplementaryDataService bleDeviceSupplementaryDataService, IHardwareInfo hardwareInfo, IInAppPurchaseService iapService, ISecondaryUsersService secondaryUsersService, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, IWebViewDataService webViewDataService, IDemoModeService demoModeService = null)
			: base(localSettings, featureFlagManager, apiService, thirdPartyLoginService, dashboardWebviewCalls, failedUploadMonitor, wolfAnalytics, secondaryUsersService, webViewUrlParameterService, webviewSettings, webViewDataService, demoModeService)
		{
			try
			{
				this.bleOnboardingScanningService = bleOnboardingScanningService;
				this.bleOnboardingConnectingService = bleOnboardingConnectingService;
				this.bleDeviceSupplementaryDataService = bleDeviceSupplementaryDataService;
				this.hardwareInfo = hardwareInfo;
				this.iapService = iapService;
				this.wolfAnalytics = wolfAnalytics;
				purchaseSyncedSub = iapService.OnPurchaseSynced.Subscribe(HandlePurchaseSynced);
				purchaseSyncErrorSub = iapService.OnPurchaseSyncError.Subscribe(HandlePurchaseSyncError);
