			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObject nav)
		{
			Init((OnboardingWebViewModel.NavObject)nav);
			this.nav = nav;
			bleOnboardingScanningService.IsNewPairing = nav?.NewPairing ?? false;
			if (nav != null && nav.NewPairing)
			{
				return;
			}
			NonConnectedMockDevice obj = bleOnboardingConnectingService.CurrentDevice as NonConnectedMockDevice;
			if (obj == null || obj.Type != MockType.Strength)
			{
				Log.Trace("Onboarding", $"Connecting to {MockType.Strength} non-connected device.");
				NonConnectedMockDevice nonConnectedDevice = MockDeviceUtil.GetNonConnectedMockDevice(MockType.Strength);
				Task.Run(async delegate
				{
					await Connect(nonConnectedDevice);
				});
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.ExposeTask("getSubscriptionStatus", HandleGetSubscriptionStatus);
			bridge.ExposeTask("startPayment", HandleStartPayment);
			bridge.Expose("getHelp", HandleUserWantsHelp);
			bridge.ExposeTask("userWantsPair", HandleUserWantsPairRequest);
			bridge.ExposeTask("pairDevice", HandlePairDeviceRequest);
		}

