		private void SetSubscriptionStatus(SubscriptionStatus subscriptionStatus)
		{
			Bridge.Call("setSubscriptionStatus", new Dictionary<string, string> { ["subscriptionStatus"] = $"{subscriptionStatus}" });
		}

		private void SetSubscriptionStatus(string error)
		{
			Bridge.Call("setSubscriptionStatus", new Dictionary<string, string> { ["error"] = error });
			Log.Error("Onboarding", "SetSubscriptionStatus: " + error);
		}

		private async Task HandleStartPayment(IDictionary<string, string> obj)
		{
			try
			{
				if (!(await iapService.OpenConnection()))
				{
					HandlePurchaseError(Wolf.Core.Resources.AppStrings.onboarding_payment_billing_connection_error, "Could not connect to IAP store");
					return;
				}
			}
			catch (InAppPurchaseException ex)
			{
				HandlePurchaseError(ex.UserError, ex.Message);
				return;
			}
			await iapService.MakePayment(obj, HandlePurchaseError, HandlePurchaseException);
		}

		private async Task HandleUserWantsPairRequest(IDictionary<string, string> parameters)
		{
			if (parameters.GetValueSafely("value").IsNullOrWhitespace())
			{
				return;
			}
			if (parameters.IsValueFalse("value"))
			{
				StopScan();
				return;
			}
			await bleConsoleService.Disconnect(forgetDevice: true);
			currentConsoleService.ForgetLastConnectedBleMachine();
			whenUserWantsPair.OnNext(value: true);
			RequestEnableBluetooth(notifyIfCannotEnable: true);
			if (DeviceInfo.Platform != DevicePlatform.Android)
			{
				await ClearAndStartScan();
			}
		}

		private void NotifyDeviceAdded(List<IBleDevice> devices)
		{
			var value = devices?.Select(delegate(IBleDevice x)
			{
				string id = x?.PairKey;
				string type = new BleDeviceNameConverter(bleDeviceSupplementaryDataService).ConvertName(x);
				return new
				{
					id = id,
					type = type,
					state = x?.State switch
					{
						Sindarin.Core.Ble.Connection.DeviceState.Connected => "connected", 
						Sindarin.Core.Ble.Connection.DeviceState.Connecting => "connecting", 
						_ => "notConnected", 
					}
				};
			});
			Dictionary<string, string> payload = new Dictionary<string, string> { ["value"] = JsonConvert.SerializeObject(value) };
			InvokeOnMainThread(delegate
			{
				Bridge.Call("setPairOptions", payload);
			});
		}

		private async Task OnShouldAutomaticallyConnectToDevice(IBleDevice device)
		{
			StopScan();
			InvokeOnMainThread(delegate
			{
				Bridge.Call("nativeIsAutoPairing");
			});
			await Connect(device).ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task HandlePairDeviceRequest(IDictionary<string, string> parameters)
		{
			string pairKey = parameters.GetValueSafely("id");
			if (pairKey.IsNullOrWhitespace() && (bleConsoleService?.IsConnectedToConsole ?? false))
			{
				await Disconnect();
				return;
			}
			IBleDevice bleDevice = await bleOnboardingScanningService.GetDeviceWithPairKey(pairKey);
			if (bleDevice == null)
			{
				Log.Error(LogTag, "Webview requests to pair device but we can't find device with pair key " + pairKey);
				NotifyConnectFailed(pairKey, "We couldn't find the requested device");
			}
			else
			{
				Log.Trace(LogTag, "Connecting to device with pair key " + pairKey);
				await Connect(bleDevice).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task Connect(IBleDevice device)
		{
			StopScan();
			try
			{
				NotifyConnectSucceeded((await bleOnboardingConnectingService.Connect(device, CancellationToken.None)).PairKey);
			}
			catch (BleOnboardingConnectFailedException ex)
			{
				HandleConnectFailed(device.PairKey, ex.Message);
			}
			catch (OperationCanceledException)
			{
				Log.Trace(LogTag, "Connect was canceled via cancellation token");
			}
		}

		private async Task Disconnect()
		{
			Log.Trace(LogTag, "pairDevice - null id, calling Disconnect");
			await bleOnboardingConnectingService.Disconnect();
			NotifyConnectSucceeded(null);
		}

		private void HandleConnectFailed(string pairKey, string error)
		{
			NotifyConnectFailed(pairKey, error);
		}

		private void NotifyConnectSucceeded(string pairKey)
		{
			Dictionary<string, string> payload = new Dictionary<string, string>
			{
				["methodName"] = "pairDeviceResult",
				["id"] = pairKey,
				["success"] = "true",
				["deviceType"] = bleOnboardingConnectingService.GetCurrentConsoleType()
			};
			NotifyConnectFinished(payload);
		}

		private void NotifyConnectFailed(string pairKey, string error)
		{
			Dictionary<string, string> payload = new Dictionary<string, string>
			{
				["methodName"] = "pairDeviceResult",
				["id"] = pairKey,
				["success"] = "false",
				["error"] = error
			};
			NotifyConnectFinished(payload);
		}

		private void NotifyConnectFinished(IDictionary<string, string> payload)
		{
			InvokeOnMainThread(delegate
			{
				Bridge.Call("pairDeviceResult", payload);
			});
		}

		private void HandleUserWantsHelp(IDictionary<string, string> parameters)
		{
			StopScan();
			TryAgainDialogInitializationData arbitraryData = new TryAgainDialogInitializationData
			{
				CanClose = true,
				IsOnboarding = (nav == null || !nav.NewPairing),
				OnDismiss = async delegate
				{
					await StartScan();
				},
				CloseOnDismiss = true,
				Error1 = TryAgainErrors.BleSettings,
				Error2 = TryAgainErrors.BluetoothSupport2,
				Error3 = TryAgainErrors.BluetoothSupport3,
				Error4 = TryAgainErrors.BleActivationInstructions,
				Error5 = TryAgainErrors.EquipmentRecovery,
				ErrorText = string.Empty,
				Retry = async delegate
				{
					await ClearAndStartScan();
				}
			};
			BaseViewModel.ShowDialogViewModel<TryAgainViewModel>(arbitraryData);
		}

		private async Task StartScan()
		{
			RegisterScanSubscribers();
			await bleOnboardingScanningService.StartScan();
		}

		private async Task ClearAndStartScan()
		{
			RegisterScanSubscribers();
			await bleOnboardingScanningService.ClearAndStartScan();
		}

		private void StopScan()
		{
			DisposeScanSubscribers();
			bleOnboardingScanningService.StopScan();
		}

		protected override async void OnboardingCompleted(IDictionary<string, string> obj)
		{
			StopScan();
			if (nav?.NewPairing == true)
			{
				DoClose();
				FlushNonPreloadedWebviews();
				return;
			}
			if (!base.ApiService.HasLoggedInUser)
			{
				try
				{
					await whenPostLogin.AsObservable().Take(1).Timeout(TimeSpan.FromSeconds(10.0))
						.ToTask();
				}
				catch (Exception exception)
				{
					Log.Trace("Onboarding", "Error logging user in Native:", exception);
				}
			}
			if (base.ApiService.HasLoggedInUser)
			{
				base.OnboardingCompleted(obj);
				FlushNonPreloadedWebviews();
			}
		}

		protected override Task PostLoginSuccess()
		{
			whenPostLogin.OnNext(value: true);
			return Task.FromResult(result: true);
		}

		private void OnLoginFailureReload()
		{
			whenPostLogin.OnNext(value: false);
			Bridge.Call("goToLogin");
		}

		public override async Task<IDictionary<string, string>> GetConfigs()
		{
			IDictionary<string, string> dictionary = await base.GetConfigs();
			if (nav?.NewPairing == true)
			{
				dictionary["userWantsNewPair"] = WebviewParamValues.WebviewParamValue(b: true);
			}
			return dictionary;
		}

		private void DoBackPressed()
		{
			Bridge.Call("userPressedBackButton");
		}

		private void HandlePurchaseError(string messageForUser, string messageForLogs, bool _ = false)
		{
			try
			{
				iapService.CloseConnection();
			}
			catch (Exception exception)
			{
				Log.Error("Onboarding", "Error closing IAP Service connection", exception);
			}
			Bridge.Call("paymentFinished", new Dictionary<string, string> { ["error"] = messageForUser ?? Wolf.Core.Resources.AppStrings.onboarding_payment_incomplete });
			Log.Error("Onboarding", string.Format(Wolf.Core.Resources.AppStrings.onboarding_payment_purchasing_sub_error, messageForLogs));
		}

		private Task HandlePurchaseException(InAppBillingPurchaseException exception)
		{
			if (exception.PurchaseError != PurchaseError.UserCancelled)
			{
				wolfAnalytics.HandledInAppBillingPurchaseException(exception);
			}
			switch (exception.PurchaseError)
			{
			case PurchaseError.UserCancelled:
				HandlePurchaseError(Wolf.Core.Resources.AppStrings.onboarding_payment_cancelled, "User cancelled purchase");
				break;
			case PurchaseError.BillingUnavailable:
			case PurchaseError.AppStoreUnavailable:
				HandlePurchaseError(Wolf.Core.Resources.AppStrings.onboarding_payment_connecting_to_store_error, $"Error purchasing subscription: {exception}");
				break;
			case PurchaseError.PaymentNotAllowed:
				HandlePurchaseError(Wolf.Core.Resources.AppStrings.onboarding_payment_not_allowed, $"Payment is not allowed on this device: {exception}");
				break;
			default:
				HandlePurchaseError(Wolf.Core.Resources.AppStrings.onboarding_payment_incomplete, $"Error purchasing subscription: {exception}");
				break;
			}
			return Task.CompletedTask;
		}

		private void HandlePurchaseSynced(bool _)
		{
			Bridge.Call("paymentFinished");
		}

		private void HandlePurchaseSyncError(InAppPurchaseException ex)
		{
			HandlePurchaseError(ex.UserError, ex.Message);
		}

		protected override Auth0InitializationData Auth0InitializationData(IWolfEnvironment environment, string auth0Config)
		{
			Auth0InitializationData auth0InitializationData = base.Auth0InitializationData(environment, auth0Config);
			string text = (hardwareInfo.IsAndroid ? "android" : "ios");
			auth0InitializationData.RedirectUri = PackageName + "://" + environment?.Auth0Configs[auth0Config].domain + "/" + text + "/" + PackageName + "/";
			auth0InitializationData.RedirectUri += (auth0Config.Equals("PlanetFitness") ? "pigeon" : "callback");
			return auth0InitializationData;
		}

		public override Task<string> GetData(Uri uri)
		{
			string result;
			try
			{
				Task<string> task = base.GetData(uri);
				task.Wait();
				result = task.Result;
			}
			catch (KeyNotSupportedException ex)
			{
				string host = uri.Host;
				if (!(host == "new-pairing"))
				{
					throw ex;
				}
				string text = (nav?.NewPairing ?? false).WebviewParamValue();
				result = text;
			}
			return Task.FromResult(result);
		}

		public override string[] GetAllSupportedKeys()
		{
			string[] allSupportedKeys = base.GetAllSupportedKeys();
			return allSupportedKeys.Concat(new string[1] { "new-pairing" }).ToArray();
		}

		private void RegisterScanSubscribers()
		{
			DisposeScanSubscribers();
			deviceAddedSub = bleOnboardingScanningService.WhenDeviceAdded?.Subscribe(NotifyDeviceAdded);
			shouldConnectSub = bleOnboardingScanningService.WhenShouldConnectToDevice?.SubscribeAsync(OnShouldAutomaticallyConnectToDevice);
		}

		private void DisposeScanSubscribers()
		{
			deviceAddedSub?.Dispose();
			deviceAddedSub = null;
			shouldConnectSub?.Dispose();
			shouldConnectSub = null;
		}

		public override void Dispose()
		{
			base.Dispose();
			deviceAddedSub?.Dispose();
			deviceAddedSub = null;
			purchaseSyncedSub?.Dispose();
			purchaseSyncedSub = null;
			purchaseSyncErrorSub?.Dispose();
			purchaseSyncErrorSub = null;
			shouldConnectSub?.Dispose();
			shouldConnectSub = null;
			IBleOnboardingScanningService obj = bleOnboardingScanningService;
			if (obj != null)
			{
				obj.Dispose();
				UnregisterChangeHandlers();
			}
		}

