	public abstract class OnboardingAuthViewModel : BaseOnboardingViewModel, IWebViewDataProvider
	{
		public const string SetAuthCredentialsMethodName = "SetAuthCredentials";

		public const string GetFacebookProfileInfoMethodName = "GetFacebookProfileInfo";

		public const string SetFacebookProfileInfoMethodName = "SetFacebookProfileInfo";

		public const string CancelFacebookProfileInfoMethodName = "CancelFacebookProfileInfo";

		public const string LoginWithPlanetFitnessMethodName = "LoginWithPlanetFitness";

		public const string SetPlanetFitnessResponseMethodName = "PFLoginResponse";

		public const string CancelPlanetFitnessMethodName = "PFLoginResponse";

		public const string LoginWithAppleMethodName = "LoginWithApple";

		public const string SetAppleResponseMethodName = "AppleLoginResponse";

		public const string CancelAppleMethodName = "AppleLoginResponse";

		public const string LoginWithAuth0MethodName = "LoginWithAuth0";

		public const string SetAuth0ResponseMethodName = "Auth0LoginResponse";

		public const string CancelAuth0MethodName = "Auth0LoginResponse";

		public const string CockatooBaseConfigName = "cockatooBaseUrl";

		public const string SignInWithAppleEnabledConfigName = "signInWithAppleEnabled";

		public const string StrengthMirrorDeviceSerial = "strength-mirror-device-serial-number";

		public const string CockatooGatewayPath = "cockatoo/";

		private readonly IWebViewDataService webViewDataService;

		private readonly IDemoModeService demoModeService;

		public const string LoginActiveKeyString = "login-active";

		public const string LoginSuccessfulKeyString = "login-successful";

		public const string LoginWithAppleEnabledKeyString = "login-with-apple-enabled";

		public const string IsInDemoModeKeyString = "is-in-demo-mode";

		private IWolfAnalytics WolfAnalytics { get; }

		public IThirdPartyLoginService ThirdPartyLoginService { get; private set; }

		protected bool LoginActive { get; set; }

		protected bool LoginSuccessful { get; set; }

		protected virtual Action OnLoginFailure => DoClose;

		protected virtual double TimeoutSeconds => TimeSpan.FromMinutes(5.0).TotalSeconds;

		protected override bool ShouldDemoModeScreensaverShow => true;

		public string Scheme => "onboarding";

		protected OnboardingAuthViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IIfitApiService apiService, IThirdPartyLoginService thirdPartyLoginService, IDashboardWebviewCalls dashboardWebviewCalls, IFailedUploadMonitor failedUploadMonitor, IWolfAnalytics analytics, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, IWebViewDataService webViewDataService, IDemoModeService demoModeService = null)
			: base(localSettings, featureFlagManager, apiService, dashboardWebviewCalls, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				this.webViewDataService = webViewDataService;
				webViewDataService.RegisterProvider(this);
				ThirdPartyLoginService = thirdPartyLoginService;
				WolfAnalytics = analytics;
				this.demoModeService = demoModeService;
