		public override Task OnViewShown()
		{
			LoginActive = false;
			LoginSuccessful = false;
			return base.OnViewShown();
		}

		public override void Dispose()
		{
			webViewDataService.UnregisterProvider(this);
			ThirdPartyLoginService?.Dispose();
			ThirdPartyLoginService = null;
			((BaseWebViewViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.ExposeTask("SetAuthCredentials", HandleSetAuthCredentials);
			bridge.ExposeTask("GetFacebookProfileInfo", HandleGetFacebookProfileInfo);
			bridge.ExposeTask("LoginWithPlanetFitness", HandleLoginWithPlanetFitness);
			bridge.ExposeTask("LoginWithApple", HandleLoginWithApple);
			bridge.ExposeTask("LoginWithAuth0", HandleLoginWithAuth0);
		}

		public override async Task<IDictionary<string, string>> GetConfigs()
		{
			IDictionary<string, string> dictionary = await base.GetConfigs();
			if (base.ApiService != null)
			{
				dictionary["cockatooBaseUrl"] = base.ApiService.Environment.BaseGatewayAPIUrl + "cockatoo/";
			}
			if (ThirdPartyLoginService != null)
			{
				dictionary["signInWithAppleEnabled"] = ThirdPartyLoginService.IsLoginWithAppleEnabled.WebviewParamValue();
			}
			if (base.IsStrengthMirror)
			{
				dictionary["strength-mirror-device-serial-number"] = deviceInfo.StrengthMirrorSerialNumber;
			}
			return dictionary;
		}

		protected async Task HandleSetAuthCredentials(IDictionary<string, string> parameters)
		{
			if (LoginActive)
			{
				return;
			}
			LoginActive = true;
			if (LoginSuccessful)
			{
				return;
			}
			AuthToken token = new AuthToken
			{
				TokenType = "Bearer",
				AccessToken = parameters["bearerToken"],
				RefreshToken = parameters["refreshToken"],
				ExpiresIn = int.Parse(parameters["expiresIn"])
			};
			try
			{
				Log.Trace("Onboarding", "User logged in, adding user to API service");
				if (WolfAnalytics != null)
				{
					IWolfAnalytics wolfAnalytics = WolfAnalytics;
					ICurrentConsoleService obj = currentConsoleService;
					wolfAnalytics.ShouldIdentifyAnonymousUser = obj == null || obj.Console?.ConsoleInfo?.IsClubUnit != true;
				}
				LoginResult loginResult = await base.ApiService.LoginWithIfitToken(token);
				if (loginResult == LoginResult.Success)
				{
					await SetTimeZoneInfo();
					LoginActive = false;
					if ((await featureFlagManager.UserSynced.FirstAsync((LaunchDarklySyncState result) => result.Status != LaunchDarklySyncStatus.InProgress)).Status == LaunchDarklySyncStatus.Broken)
					{
						PostLoginFailure(LoginResult.TimeOut);
						return;
					}
					if (personalTrainingSettings != null)
					{
						await personalTrainingSettings.RefreshUserSettings();
					}
					await PostLoginSuccess();
				}
				else
				{
					PostLoginFailure(loginResult);
				}
			}
			catch (ApiException ex) when (ex.StatusCode == HttpStatusCode.ServiceUnavailable)
			{
				Log.Error("Onboarding", "Refit exception during login: " + ex.Message, ex);
				PostLoginFailure(LoginResult.UnknownFailure, null, Wolf.Core.Resources.AppStrings.onboarding_server_over_capacity_error);
			}
			catch (TimeoutException exception)
			{
				Log.Error("Onboarding", "Timeout exception during login", exception);
				PostLoginFailure(LoginResult.TimeOut);
			}
			catch (Exception exception2)
			{
				Log.Error("Onboarding", "HandleSetAuthCredentials - error logging in", exception2);
				PostLoginFailure(LoginResult.UnknownFailure);
			}
		}

		private async Task HandleGetFacebookProfileInfo(IDictionary<string, string> obj)
		{
			_ = 1;
			try
			{
				if (!(await ThirdPartyLoginService.GenerateAndCacheFacebookAccessToken()))
				{
					Log.Error("Onboarding", "Unable to get Facebook Access token.");
					CancelFacebookProfileInfo();
					return;
				}
				User user = await ThirdPartyLoginService.GetUserInfoFromFacebook(new User());
				if (string.IsNullOrWhiteSpace(user?.Facebook) || string.IsNullOrWhiteSpace(user?.FacebookId))
				{
					Log.Error("Onboarding", "Error getting Facebook user information, facebook accessToken or userId null or empty.");
					CancelFacebookProfileInfo();
				}
				else
				{
					SetFacebookProfileInfo(user);
				}
			}
			catch (Exception ex)
			{
				Log.Error("Onboarding", $"Exception thrown getting Facebook user information: {ex.GetBaseException()}");
				CancelFacebookProfileInfo();
			}
		}

		private void SetFacebookProfileInfo(User user)
		{
			if (user == null)
			{
				CancelFacebookProfileInfo();
				return;
			}
			Bridge.Call("SetFacebookProfileInfo", new Dictionary<string, string>
			{
				["birthday"] = user.Birthday?.ToString("d") ?? string.Empty,
				["email"] = user.Email ?? string.Empty,
				["name"] = user.FullName,
				["gender"] = user.Gender?.ToLower() ?? string.Empty,
				["id"] = user.FacebookId,
				["accessToken"] = user.Facebook
			});
		}

		private void CancelFacebookProfileInfo()
		{
			Bridge.Call("CancelFacebookProfileInfo", new Dictionary<string, string>());
		}

		private async Task HandleLoginWithPlanetFitness(IDictionary<string, string> obj)
		{
			await HandleLoginWithAuth0(obj, "PlanetFitness");
		}

		private async Task HandleLoginWithApple(IDictionary<string, string> obj)
		{
			try
			{
				AppleResponse appleResponse = await ThirdPartyLoginService.LoginWithApple();
				if (string.IsNullOrWhiteSpace(appleResponse?.User))
				{
					Log.Error("Onboarding", "Failed to get Apple user identifier: " + (appleResponse?.Error ?? "No response error"));
					CancelLoginWithApple(appleResponse);
				}
				else
				{
					SetLoginWithAppleResponse(appleResponse);
				}
			}
			catch (Exception exception)
			{
				Log.Error("Onboarding", "HandleLoginWithApple", exception);
				CancelLoginWithApple("Authorization failed");
			}
		}

		private void SetLoginWithAppleResponse(AppleResponse response)
		{
			if (response == null)
			{
				CancelLoginWithApple();
				return;
			}
			string value = JsonConvert.SerializeObject(response);
			Bridge.Call("AppleLoginResponse", JsonConvert.DeserializeObject<Dictionary<string, string>>(value));
		}

		private void CancelLoginWithApple(string error)
		{
			CancelLoginWithApple(new AppleResponse
			{
				Error = error
			});
		}

		private void CancelLoginWithApple(AppleResponse response = null)
		{
			if (response == null)
			{
				response = new AppleResponse
				{
					Error = "Unexpected error"
				};
			}
			string value = JsonConvert.SerializeObject(response);
			Bridge.Call("AppleLoginResponse", JsonConvert.DeserializeObject<Dictionary<string, string>>(value));
		}

		protected virtual Auth0InitializationData Auth0InitializationData(string auth0Config)
		{
			IWolfEnvironment environment = base.ApiService.Environment as IWolfEnvironment;
			return Auth0InitializationData(environment, auth0Config);
		}

		protected virtual Auth0InitializationData Auth0InitializationData(IWolfEnvironment environment, string auth0Config)
		{
			Auth0Config auth0Config2 = environment?.Auth0Configs[auth0Config];
			if (auth0Config2 == null)
			{
				return null;
			}
			Auth0InitializationData auth0InitializationData = new Auth0InitializationData(auth0Config2.domain, auth0Config2.clientId, auth0Config2.scope);
			if (!auth0Config2.audience.IsNullOrEmpty() && !auth0Config2.selectedTab.IsNullOrEmpty())
			{
				auth0InitializationData.ExtraParameters = new { auth0Config2.audience, auth0Config2.selectedTab };
			}
			if (!auth0Config2.audience.IsNullOrEmpty())
			{
				auth0InitializationData.ExtraParameters = new { auth0Config2.audience };
			}
			if (!auth0Config2.selectedTab.IsNullOrEmpty())
			{
				auth0InitializationData.ExtraParameters = new { auth0Config2.selectedTab };
			}
			return auth0InitializationData;
		}

		private async Task HandleLoginWithAuth0(IDictionary<string, string> obj)
		{
			if (!obj.ContainsKey("signUp") || !(obj["signUp"] == "true"))
			{
				await HandleLoginWithAuth0(obj, "Auth0Login");
			}
			else
			{
				await HandleLoginWithAuth0(obj, "Auth0SignUp");
			}
		}

		private async Task HandleLoginWithAuth0(IDictionary<string, string> obj, string auth0Config)
		{
			try
			{
				Auth0Response auth0Response = await ThirdPartyLoginService.LoginWithAuth0(Auth0InitializationData(auth0Config));
				if (string.IsNullOrWhiteSpace(auth0Response?.AccessToken))
				{
					Log.Error("Onboarding", "Failed to get " + auth0Config + " access token.");
					CancelAuth0(auth0Config, "Failed to get access token");
				}
				else
				{
					SetAuth0Response(auth0Config, auth0Response);
				}
			}
			catch (Exception exception)
			{
				Log.Error("Onboarding", "HandleLoginWithAuth0: " + auth0Config, exception);
				CancelAuth0(auth0Config, "Login failed");
			}
		}

		private void SetAuth0Response(string auth0Config, Auth0Response response)
		{
			if (response == null)
			{
				CancelAuth0(auth0Config, "Unexpected response");
				return;
			}
			string methodName = ((auth0Config == "PlanetFitness") ? "PFLoginResponse" : "Auth0LoginResponse");
			string value = JsonConvert.SerializeObject(response);
			Bridge.Call(methodName, JsonConvert.DeserializeObject<Dictionary<string, string>>(value));
		}

		private void CancelAuth0(string auth0Config, string error = null)
		{
			CancelAuth0(auth0Config, new Auth0Response
			{
				Error = error
			});
		}

		private void CancelAuth0(string auth0Config, Auth0Response response)
		{
			string value = JsonConvert.SerializeObject(response);
			string methodName = ((auth0Config == "PlanetFitness") ? "PFLoginResponse" : "Auth0LoginResponse");
			Bridge.Call(methodName, JsonConvert.DeserializeObject<Dictionary<string, string>>(value));
		}

		public virtual Task<string> GetData(Uri uri)
		{
			return Task.FromResult(uri.Host switch
			{
				"login-active" => LoginActive.WebviewParamValue(), 
				"login-successful" => LoginSuccessful.WebviewParamValue(), 
				"login-with-apple-enabled" => (ThirdPartyLoginService?.IsLoginWithAppleEnabled ?? false).WebviewParamValue(), 
				"is-in-demo-mode" => (demoModeService?.IsInDemoMode ?? false).WebviewParamValue(), 
				_ => throw new KeyNotSupportedException("Onboarding did not recognize key " + uri.OriginalString), 
			});
		}

		public virtual string[] GetAllSupportedKeys()
		{
			return new string[4] { "login-active", "login-successful", "login-with-apple-enabled", "is-in-demo-mode" };
		}

		private async Task SetTimeZoneInfo()
		{
			if (Mvx.TryResolve<ITimeZoneService>(out var timeZoneService))
			{
				User user = await User.GetMe(base.ApiService);
				if (deviceInfo.IsBuiltIn)
				{
					await timeZoneService.SetTimeZoneAsync(new AvailableTimeZone(TimeZoneTypes.Custom, user.Timezone, user.Timezone, 0));
				}
			}
		}

		protected void FlushNonPreloadedWebviews()
		{
			webviewHolderFactory.WebviewHolderStore.FlushAllExcluding(MainToolbarViewModel.GetWallEUrlWhenNeed(featureFlagManager, FeatureFlags.WallEDashboardUrl, FeatureFlags.WolfDashboardWebviewUrl), featureFlagManager.GetString(FeatureFlags.WolfWorkoutsWebviewUrl), FeatureFlags.WolfWorkoutWebViewDefaultUrl, FeatureFlags.WolfWorkoutWebViewDefaultUrlTest, FeatureFlags.WolfWorkoutWebViewDefaultUrlDev);
		}

		protected abstract Task PostLoginSuccess();

		protected void PostLoginFailure(LoginResult loginResult, string title = null, string message = null, string confirmText = null)
		{
			title = (string.IsNullOrWhiteSpace(title) ? Wolf.Core.Resources.AppStrings.onboarding_login_error : title);
			message = (string.IsNullOrWhiteSpace(message) ? Wolf.Core.Resources.AppStrings.onboarding_try_again : message);
			confirmText = (string.IsNullOrWhiteSpace(confirmText) ? Wolf.Core.Resources.AppStrings.ok : confirmText);
			if (loginResult == LoginResult.SubscriptionTypeNotSupported)
			{
				title = Wolf.Core.Resources.AppStrings.login_error_subscription_type_not_supported_title;
				message = Wolf.Core.Resources.AppStrings.login_error_subscription_type_not_supported_body;
			}
			ShowSimpleConfirmationDialog(title, message, (Func<CancellationToken, Task<object>>)null, string.Empty, confirmText, OnLoginFailure, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false, true);
			LoginActive = false;
		}

