	public class OnboardingPaymentViewModel : BaseOnboardingViewModel
	{
		public new class NavObject
		{
			public bool HasFreeTrial { get; set; }

			public bool GoToWallOnClose { get; set; } = true;
		}

		private SemaphoreSlim processingPurchaseRequest = new SemaphoreSlim(1);

		private NavObject userInfo;

		private bool goToWallOnClose = true;

		private readonly IInAppPurchaseService iapService;

		private IDisposable purchaseSyncSubscription;

		private IDisposable syncErrorSubscription;

		private readonly IWolfAnalytics wolfAnalytics;

		private static readonly string PurchaseErrorUserMessage = Wolf.Core.Resources.AppStrings.onboarding_payment_incomplete;

		private const string PagePayment = "plan-selection";

		public readonly INC<bool> IsProcessing = new NC<bool>();

		public static string WebViewUrl => BaseOnboardingViewModel.BaseUrl + "#" + "plan-selection";

		protected override string Url => WebViewUrl;

		public override bool DisableWebViewScrollingExceptWhenKeyboardIsShowing => false;

		public new static async Task<IDictionary<string, string>> GetWebViewConfigs()
		{
			IDictionary<string, string> dictionary = await BaseOnboardingViewModel.GetWebViewConfigs();
			if (Mvx.TryResolve<IInAppPurchaseService>(out var service))
			{
				foreach (KeyValuePair<string, string> item in service.PricingInfo)
				{
					if (item.Key != null)
					{
						dictionary.Remove(item.Key);
						dictionary.Add(item);
					}
					else
					{
						Log.Error("Onboarding", $"The key value pair {item} had a null key");
					}
				}
			}
			return dictionary;
		}

		public OnboardingPaymentViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IIfitApiService apiService, IInAppPurchaseService iapService, IWolfAnalytics wolfAnalytics, IDashboardWebviewCalls dashboardWebviewCalls, IFailedUploadMonitor failedUploadMonitor, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings)
			: base(localSettings, featureFlagManager, apiService, dashboardWebviewCalls, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				webviewPath = "plan-selection";
				this.iapService = iapService;
				this.wolfAnalytics = wolfAnalytics;
				purchaseSyncSubscription = iapService.OnPurchaseSynced.SubscribeAsync(ContinueFromSuccessfulPayment);
				syncErrorSubscription = iapService.OnPurchaseSyncError.Subscribe(HandleFailedPurchaseSync);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObject nav)
		{
			userInfo = nav;
			goToWallOnClose = nav.GoToWallOnClose;
		}

		protected override void DoClose()
		{
			purchaseSyncSubscription?.Dispose();
			purchaseSyncSubscription = null;
			syncErrorSubscription?.Dispose();
			syncErrorSubscription = null;
			processingPurchaseRequest?.Dispose();
			processingPurchaseRequest = null;
			if (goToWallOnClose)
			{
				ShowOnboardingWallViewModel();
			}
			base.DoClose();
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			IsProcessing.Value = false;
			Bridge = bridge;
			Bridge.Expose("MakePayment", HandleMakePayment);
		}

		protected virtual void ShowBillingError(string messageForUser, string messageForLogs, bool goToWall = false)
		{
			Action action = delegate
			{
				goToWallOnClose = goToWall;
				DoClose();
			};
			ShowError(messageForUser, messageForLogs, goToWall ? action : null);
		}

		private void HandleFailedPurchaseSync(InAppPurchaseException ex)
		{
			ShowError(ex.UserError, ex.Message, onConfirm);
			async void onConfirm()
			{
				await (base.ApiService?.Logout());
				goToWallOnClose = true;
				DoClose();
			}
		}

		private void ShowError(string messageForUser, string messageForLogs, Action onConfirm = null)
		{
			IsProcessing.Value = false;
			Log.Error("Onboarding", string.Format(Wolf.Core.Resources.AppStrings.onboarding_payment_purchasing_sub_error, messageForLogs));
			try
			{
				iapService?.CloseConnection();
			}
			catch (Exception exception)
			{
				Log.Error("Onboarding", "Could not close IAP Service connection", exception);
			}
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.onboarding_payment_notice, messageForUser, confirmAction, string.Empty, Wolf.Core.Resources.AppStrings.ok, null, null, dismissible: false, cancellable: false);
			void confirmAction()
			{
				processingPurchaseRequest?.Release();
				onConfirm?.Invoke();
			}
		}

		private void HandleMakePayment(IDictionary<string, string> obj)
		{
			SemaphoreSlim semaphoreSlim = processingPurchaseRequest;
			if (semaphoreSlim == null || !semaphoreSlim.Wait(0))
			{
				return;
			}
			Task.Run(async delegate
			{
				IsProcessing.Value = true;
				try
				{
					if (!(await iapService.OpenConnection()))
					{
						ShowBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_billing_connection_error, "Could not connect to IAP store");
						return;
					}
				}
				catch (InAppPurchaseException ex)
				{
					ShowBillingError(ex.UserError, ex.Message, ex.IsFatalError);
					return;
				}
				if (await iapService.MakePayment(obj, ShowBillingError, HandleBillingPurchaseException))
				{
					if (userInfo.HasFreeTrial)
					{
						analytics?.TrialStarted();
					}
					else
					{
						analytics?.PaymentStarted();
					}
				}
			});
		}

		protected virtual async Task HandleBillingPurchaseException(InAppBillingPurchaseException exception)
		{
			if (exception.PurchaseError != PurchaseError.UserCancelled)
			{
				wolfAnalytics.HandledInAppBillingPurchaseException(exception);
				Log.Error("Onboarding", $"InAppBillingPurchaseException making purchase, purchase error: {exception.PurchaseError}", exception);
			}
			switch (exception.PurchaseError)
			{
			case PurchaseError.UserCancelled:
				Log.Trace("Onboarding", "User cancelled purchase");
				await iapService.CloseConnection();
				IsProcessing.Value = false;
				try
				{
					if (processingPurchaseRequest == null)
					{
						Log.Trace("Onboarding", "User Left OnboardingPaymentViewModel And Then Cancelled Purchase");
					}
					processingPurchaseRequest?.Release();
					break;
				}
				catch (ObjectDisposedException)
				{
					Log.Trace("Onboarding", "processingPurchaseRequest was already disposed of when handling purchase exception.");
					break;
				}
			case PurchaseError.BillingUnavailable:
			case PurchaseError.AppStoreUnavailable:
				ShowBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_connecting_to_store_error, $"Error purchasing subscription: {exception}");
				break;
			case PurchaseError.PaymentNotAllowed:
				ShowBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_not_allowed, $"Payment is not allowed on this device: {exception}");
				break;
			default:
				ShowBillingError(PurchaseErrorUserMessage, $"Error purchasing subscription: {exception}");
				break;
			}
		}

		private async Task ContinueFromSuccessfulPayment(bool _)
		{
			Log.Trace("Onboarding", "Refreshing user and token after successful payment");
			try
			{
				User user = await base.ApiService.RefreshCurrentlyAuthenticatedUser();
				Log.Trace("Onboarding", $"User subscription {user.SubscriptionType} - PF: {user.IsPlanetFitnessUser}");
			}
			catch (Exception exception)
			{
				Log.Error("Onboarding", "Exception thrown refreshing user data", exception);
			}
			await base.ApiService.RefreshToken();
			Log.Trace("Onboarding", "Cleaning webview store");
			InvokeOnMainThread(delegate
			{
				webviewHolderFactory.WebviewHolderStore.FlushAll();
				webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
			});
			Log.Trace("Onboarding", "IAP> Continuing on from Payment ViewModel.");
			goToWallOnClose = false;
			IsProcessing.Value = false;
			if (!trackingService.HasCompletedOnboarding(base.ApiService.CurrentlyAuthenticatedUserId))
			{
				ShowViewModel<OnboardingPersonalizationViewModel>();
			}
			else
			{
				NavigateToFirstViewModel();
			}
		}

