	public class OnboardingPersonalizationViewModel : BaseOnboardingViewModel
	{
		private const string PageProfile = "wolf-user-profile";

		private bool isNavigatingAway;

		private readonly IBranchService branchService;

		public static string WebViewUrl => BaseOnboardingViewModel.BaseUrl + "#" + "wolf-user-profile";

		protected override string Url => WebViewUrl;

		public OnboardingPersonalizationViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IIfitApiService apiService, IDashboardWebviewCalls dashboardWebviewCalls, IFailedUploadMonitor failedUploadMonitor, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, IBranchService branchService = null)
			: base(localSettings, featureFlagManager, apiService, dashboardWebviewCalls, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				this.branchService = branchService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			ResetDemoMode();
			if (localSettings.IsRoboRunMode)
			{
				HandleOnboardingCompleted();
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("OnboardingCompleted", HandleOnboardingCompleted);
		}

		protected void HandleOnboardingCompleted()
		{
			if (isNavigatingAway)
			{
				return;
			}
			isNavigatingAway = true;
			if (!trackingService.HasCompletedOnboarding(base.ApiService.CurrentlyAuthenticatedUserId))
			{
				trackingService.SetCompletedOnboarding(base.ApiService.CurrentlyAuthenticatedUserId);
				analytics?.TutorialCompleted();
			}
			if (!Mvx.TryResolve<IBleConsoleService>(out var service) || service.ConnectionState == ConsoleConnectionState.Connected)
			{
				InvokeOnMainThread(delegate
				{
					webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
					NavigateToFirstViewModel();
				});
			}
			else
			{
				InvokeOnMainThread(delegate
				{
					ShowBlePairFilterView();
				});
			}
		}

