	public class OnBoardingSetupViewModel : BaseViewModel
	{
		public enum ViewState
		{
			Language,
			Wifi,
			Units,
			Update
		}

		private const int UpdateDelayTimeMs = 2000;

		private bool navigatingAway;

		public readonly INC<string> Title = new NC<string>();

		public readonly INC<string> NextButtonTitle = new NC<string>();

		public readonly INC<bool> IsWifiComplete = new NC<bool>();

		public readonly INC<bool> IsUnitsComplete = new NC<bool>();

		public readonly INC<bool> SkipWifiVisible = new NC<bool>(value: false);

		private ViewState currentView = ViewState.Wifi;

		protected bool hasSkippedWifi;

		private readonly ICheckUpdateService updateCheck;

		private readonly ILaunchUpdate launchUpdate;

		private readonly ISettingsRouter settingsRouter;

		private readonly ISecondaryUsersService secondaryUsersService;

		private readonly IMvxMainThreadDispatcher dispatcher;

		private readonly ISetUnitsService setUnitsService;

		private bool updateChecked;

		public ViewState CurrentView
		{
			get
			{
				return currentView;
			}
			set
			{
				currentView = value;
				OnCurrentViewChanged();
			}
		}

		public bool ShowUnitsConfiguration { get; private set; }

		protected override bool ShouldDemoModeScreensaverShow => !updateChecked;

		protected virtual int UpdateAttemptDurationSeconds => 30;

		protected Task CheckAndLaunchUpdateTask { get; private set; }

		public ICommand SkipWifiButton => new MvxCommand(DoSkipWifi);

		public OnBoardingSetupViewModel(ILocalSettings localSettings, ICheckUpdateService updateCheck, ILaunchUpdate launchUpdate, ISettingsRouter settingsRouter, ISecondaryUsersService secondaryUsersService, ISetUnitsService setUnitsService, ICurrentConsoleService currentConsoleService)
			: base(localSettings)
		{
			try
			{
				this.updateCheck = updateCheck;
				this.launchUpdate = launchUpdate;
				this.settingsRouter = settingsRouter;
				this.secondaryUsersService = secondaryUsersService;
				this.setUnitsService = setUnitsService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			ConsoleType? consoleType = currentConsoleService?.Console?.ConsoleInfo?.MachineType;
			ShowUnitsConfiguration = !consoleType.HasValue || !consoleType.Value.IsRower();
			if (!ShowUnitsConfiguration)
			{
				bool isClubOwner = currentConsoleService?.IsBuiltinClub ?? false;
				await setUnitsService.SetUnits(isMetric: true, isClubOwner);
			}
			if (base.localSettings != null && deviceInfo.IsBuiltIn && currentConsoleService != null && !currentConsoleService.IsBuiltinClub)
			{
				ILocalSettings localSettings = base.localSettings;
				localSettings.IsAllAuthenticatedUsersLinked = await secondaryUsersService.IsAllAuthenticatedUsersLinked();
			}
		}

		private void OnCurrentViewChanged()
		{
			if (deviceInfo.IsStrengthMirror && Mvx.TryResolve<ITouchMonitor>(out var service))
			{
				service.UpdateLastObservedTouch();
			}
			switch (CurrentView)
			{
			case ViewState.Language:
				SkipWifiVisible.Value = false;
				break;
			case ViewState.Wifi:
				NextButtonTitle.Value = Wolf.Core.Resources.AppStrings.onboarding_wifi_next.ToUpper();
				SkipWifiVisible.Value = ShouldAllowSkipWifi();
				break;
			case ViewState.Units:
				SkipWifiVisible.Value = false;
				break;
			case ViewState.Update:
				SkipWifiVisible.Value = false;
				if (!hasSkippedWifi)
				{
					CheckAndLaunchUpdateTask = CheckAndLaunchUpdate();
				}
				break;
			}
		}

		protected void SkipAndOrFinish()
		{
			if (!navigatingAway)
			{
				navigatingAway = true;
				CompleteFirstRunSetup();
				Close(this);
			}
		}

		private void DoSkipWifi()
		{
			if (ShouldAllowSkipWifi())
			{
				hasSkippedWifi = true;
				if (currentConsoleService.IsBuiltinClub)
				{
					ShowViewModel<ClubUnitAccountSelectionViewModel>();
				}
				else
				{
					NavigateToDashboardViewModel();
				}
				Close(this);
			}
		}

		public virtual async Task CheckAndLaunchUpdate()
		{
			if (!connectivity.IsConnected)
			{
				Log.Info("UpdateCheck", "Not checking for update(s) when no internet connection available");
			}
			else
			{
				if (updateChecked)
				{
					return;
				}
				updateChecked = true;
				Task<CheckUpdateState> updateCheckTask = updateCheck.CheckForUpdate();
				Task task = Task.Delay(2000);
				Task<Task> task2 = Task.WhenAny(updateCheckTask, Task.Delay(TimeSpan.FromSeconds(UpdateAttemptDurationSeconds)));
				await Task.WhenAll(task2, task);
				if (updateCheckTask.IsFaulted || updateCheckTask.IsCanceled)
				{
					HandleUpdateCheckFailure(updateCheckTask.Exception?.GetBaseException());
					return;
				}
				if (updateCheckTask.Result == CheckUpdateState.UpdateAvailable)
				{
					Task.Run(delegate
					{
						trackingService.FirstRun = false;
						launchUpdate.UpdateConnectedMachine();
					});
				}
				SkipAndOrFinish();
			}
		}

		protected virtual void HandleUpdateCheckFailure(Exception error)
		{
			if (error != null)
			{
				Log.Error("UpdateCheck", "Exception occurred while performing update check.", error);
			}
			else
			{
				Log.Error("UpdateCheck", "Onboarding update check failed.");
			}
			bool shouldAllowSkippingUpdateCheck = ShouldAllowSkippingUpdateCheck();
			Log.Trace("UpdateCheck", string.Format("{0}: {1}", "shouldAllowSkippingUpdateCheck", shouldAllowSkippingUpdateCheck), error);
			string text = Wolf.Core.Resources.AppStrings.onboarding_update_failure_message;
			if (shouldAllowSkippingUpdateCheck)
			{
				text += "\n\nCheck to make sure that Eru is properly installed on this device as well. If you're on an emulator, you'll just need to skip this.";
			}
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, text, AfterUpdateCheckFailureDialog, cancellableOperation: false, null, shouldAllowSkippingUpdateCheck ? Wolf.Core.Resources.AppStrings.wifi_skip.ToUpper() : string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), null, delegate
			{
				if (shouldAllowSkippingUpdateCheck)
				{
					SkipAndOrFinish();
				}
				else
				{
					AfterUpdateCheckFailureDialog();
				}
			}, dismissible: false);
		}

		protected virtual void AfterUpdateCheckFailureDialog()
		{
			if (!navigatingAway)
			{
				navigatingAway = true;
				GoToViewModelAndClearNavStack<WelcomeViewModel>();
				Close(this);
			}
		}

		protected virtual bool ShouldAllowSkippingUpdateCheck()
		{
			return false;
		}

		private bool ShouldAllowSkipWifi()
		{
			if (deviceInfo.IsStrengthMirror)
			{
				return false;
			}
			return true;
		}

