					{
						IIfitApiService apiService = base.ApiService;
						if (apiService != null && !apiService.HasLoggedInUser)
						{
							NavObject navObject = nav;
							if (navObject == null)
							{
								return true;
							}
							return !navObject.GoToSummary;
						}
					}
				}
				return false;
			}
		}

