		private void CheckForConnection()
		{
			wifiService.RefreshConnectivityState();
			if (wifiService.NetworkState != WifiNetworkState.Connected)
			{
				bool dismissible = base.LoginSuccessful || !base.IsStrengthMirror;
				ShowNoInternetConnectionDialog(new NoWifiDialogViewModel.DisplayData
				{
					Title = Wolf.Core.Resources.AppStrings.default_no_wifi_title,
					Description = Wolf.Core.Resources.AppStrings.default_no_wifi_description,
					CancelButtonText = Wolf.Core.Resources.AppStrings.default_no_wifi_cancel,
					OkButtonText = Wolf.Core.Resources.AppStrings.default_no_wifi_turn_on,
					ShowCentered = true,
					Dismissible = dismissible
				});
				connectivity.ConnectivityChanged -= ConnectivityChanged;
				connectivity.ConnectivityChanged += ConnectivityChanged;
			}
		}

		protected void ConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			if (connectivity.IsConnected)
			{
				Reload();
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("NavigateToPage", NavigateToPage);
			bridge.Expose("NavigateToPayment", NavigateToPayment);
			bridge.Expose("OnboardingCompleted", OnboardingCompleted);
			bridge.Expose("ShowPrivacyPolicy", ShowPrivacyPolicy);
			bridge.Expose("ShowSecretSettings", ShowSecretSettings);
			bridge.Expose("ShowTermsOfUse", ShowTermsOfUse);
			bridge.Expose("cancelLogin", CancelLogin);
			bridge.Expose("ShowTermsOfMembership", ShowTermsOfMembership);
		}

		public override async Task<IDictionary<string, string>> GetConfigs()
		{
			IDictionary<string, string> configs = await base.GetConfigs();
			if (data != null)
			{
				data.ForEach(delegate(KeyValuePair<string, string> x)
				{
					if (x.Value != null)
					{
						configs[x.Key] = x.Value;
					}
				});
			}
			if (nav?.GoToPayment ?? false)
			{
				configs["goToPayment"] = WebviewParamValues.WebviewParamValue(b: true);
			}
			if (nav?.GoToSummary ?? false)
			{
				configs["goToSummary"] = WebviewParamValues.WebviewParamValue(b: true);
			}
			if (nav?.ShowLogin ?? false)
			{
				configs["isSecondaryUser"] = WebviewParamValues.WebviewParamValue(b: true);
			}
			if (!string.IsNullOrEmpty(nav?.NavigatedFrom))
			{
				configs["navigatedFrom"] = nav.NavigatedFrom;
			}
			if (!(base.ApiService?.HasLoggedInUser ?? false))
			{
				configs.Remove("token");
			}
			else
			{
				IDictionary<string, string> dictionary = configs;
				dictionary.Add("bearerToken", await base.ApiService.GetToken());
			}
			return configs;
		}

