		{
			return new NavObject
			{
				Data = obj
			};
		}

		protected void Reload()
		{
			ShowViewModel<OnboardingWebViewModel>(nav);
			Close(this);
		}

		protected virtual void OnboardingCompleted(IDictionary<string, string> obj)
		{
			trackingService.SetCompletedOnboarding(base.ApiService.CurrentlyAuthenticatedUserId);
			analytics?.TutorialCompleted();
			InvokeOnMainThread(delegate
			{
				webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
				webviewHolderFactory.WebviewHolderStore.FlushAll();
			});
			Task.Run((Func<Task>)CheckSecondaryUsersAndNavigate);
		}

		protected async Task CheckSecondaryUsersAndNavigate()
		{
			if (deviceInfo.IsBuiltIn && !currentConsoleService.IsBuiltinClub)
			{
				ILocalSettings localSettings = base.localSettings;
				localSettings.IsAllAuthenticatedUsersLinked = await secondaryUsersService.IsAllAuthenticatedUsersLinked();
			}
			NavigateToFirstViewModel();
		}

		protected override Task PostLoginSuccess()
		{
			webviewHolderFactory.WebviewHolderStore.FlushAll();
			return Task.CompletedTask;
		}

		public override Task<string> GetData(Uri uri)
		{
			string result;
			try
			{
				Task<string> task = base.GetData(uri);
				task.Wait();
				result = task.Result;
			}
			catch (KeyNotSupportedException ex)
			{
				result = uri.Host switch
				{
					"go-to-payment" => (nav?.GoToPayment ?? false).WebviewParamValue(), 
					"go-to-summary" => (nav?.GoToSummary ?? false).WebviewParamValue(), 
					"show-login" => (nav?.ShowLogin ?? false).WebviewParamValue(), 
					"navigated-from" => nav?.NavigatedFrom.ToLowerInvariant(), 
					_ => throw ex, 
				};
			}
			return Task.FromResult(result);
		}

		public override string[] GetAllSupportedKeys()
		{
			string[] allSupportedKeys = base.GetAllSupportedKeys();
			return allSupportedKeys.Concat(new string[4] { "go-to-payment", "go-to-summary", "show-login", "navigated-from" }).ToArray();
		}

