	public class WelcomeViewModel : BaseViewModel
	{
		private const string Tag = "Welcome";

		private const int SecretSettingsTapTimes = 4;

		private const int SecretSettingsTapTime = 5;

		private int secretSettingsTapCount;

		private DateTime startTime = DateTime.Now;

		private readonly IGeoLocationService geoLocationService;

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly IDemoModeService demoModeService;

		private readonly ILockScreenHandler lockScreenHandler;

		public readonly INC<bool> ShouldShowEnableRetailDemoModeButton = new NC<bool>();

		public readonly INC<ConsoleType> ConsoleType = new NC<ConsoleType>();

		protected override bool ShouldDemoModeScreensaverShow => true;

		protected override TimeSpan DemoModeScreensaverInactivityTimeout => TimeSpan.FromSeconds(60.0);

		public MvxCommand GoToNext => new MvxCommand(DoGoToNext);

		public MvxCommand DoGoToSecretSettings => new MvxCommand(GoToSecretSettings);

		public MvxCommand DoEnableDemoMode => new MvxCommand(delegate
		{
			BaseViewModel.ShowDialogViewModel<PinCodeDemoModeViewModel>();
		});

		public WelcomeViewModel(ILocalSettings localSettings, IGeoLocationService geoLocationService, IWolfAnalytics wolfAnalytics, IDemoModeService demoModeService = null, ILockScreenHandler lockScreenHandler = null)
			: base(localSettings)
		{
			try
			{
				this.geoLocationService = geoLocationService;
				this.wolfAnalytics = wolfAnalytics;
				this.demoModeService = demoModeService;
				this.lockScreenHandler = lockScreenHandler;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init()
		{
			Log.Trace("Welcome", "Startup completed, initializing WelcomeViewModel");
			Log.Trace("Welcome", "Built in status: " + deviceInfo.IsBuiltIn);
			Log.Trace("Welcome", "First run: " + trackingService.FirstRun);
			ConsoleType.Value = currentConsoleService.ConsoleType;
			bool flag = deviceInfo.IsBuiltIn || base.IsStrengthMirror;
			if (flag)
			{
				geoLocationService.PreFetchIsLocatedInUs();
			}
			if (!flag || !trackingService.FirstRun)
			{
				Log.Trace("Welcome", "Not first run or not built in (or a strength mirror unit), skipping Welcome screen");
				ShowViewModel<LaunchScreenViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ClearStackToRequested(), (MvxRequestedBy)null);
				DoClose();
				return;
			}
			Log.Trace("Welcome", "First run not completed, continuing with Welcome screen");
			wifiService.TurnWifiOn();
			if (flag)
			{
				IDemoModeService obj = demoModeService;
				if (obj != null && obj.CanEnterDemoMode())
				{
					ShouldShowEnableRetailDemoModeButton.Value = true;
					SendAnalytics();
				}
			}
		}

		private void SendAnalytics()
		{
			Dictionary<string, object> properties = new Dictionary<string, object> { { "demoModeAvailable", true } };
			wolfAnalytics.OnRetailDemoModeAvailabilityEvent(properties);
		}

		public override void OnAfterViewShown()
		{
			base.OnAfterViewShown();
			lockScreenHandler?.NavigateToLockScreen();
		}

		private void GoToSecretSettings()
		{
			if (DateTime.Now - startTime > TimeSpan.FromSeconds(5.0))
			{
				startTime = DateTime.Now;
				secretSettingsTapCount = 1;
				return;
			}
			secretSettingsTapCount++;
			if (secretSettingsTapCount > 4)
			{
				secretSettingsTapCount = 0;
				ShowViewModel<SecretSettingsViewModel>();
			}
		}

		public void DoGoToNext()
		{
			if (!connectivity.IsConnected)
			{
				ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<WifiSelectionViewModel>(), (MvxRequestedBy)null);
			}
			else if (featureFlagManager.IsFeatureEnabled(FeatureFlags.UseLocalizedStrings) && deviceInfo.IsBuiltIn)
			{
				ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<LanguageSelectionViewModel>(), (MvxRequestedBy)null);
			}
			else
			{
				ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<EmbeddedUpdateCheckViewModel>(), (MvxRequestedBy)null);
			}
			Close(this);
		}

