namespace Wolf.Core.ViewModels.Onboarding.Wifi
{
	public class WifiSelectionViewModel : BaseViewModel
	{
		protected const int InternetErrorDialogPresentDelayMs = 1000;

		protected const int WifiManagerChangeDelayMs = 500;

		protected const int PingTestRetries = 3;

		public readonly INC<List<WifiNetworkInfo>> Networks = new NC<List<WifiNetworkInfo>>();

		public readonly INC<bool> IsScanning = new NC<bool>();

		public readonly INC<bool> IsConnecting = new NC<bool>();

		public readonly INC<string> WifiConnectError = new NC<string>();

		private readonly bool showUnitsConfiguration;

		private bool hasStartedInternetPingCheck;

		private bool navigatingAway;

		private IDisposable wifiStateChanged;

		private readonly IGeoLocationService geoLocationService;

		private readonly ICrashReporter crashReporter;

		protected string DesiredNetworkSsid { get; set; }

		protected Task ScanTask { get; private set; }

		[DependsOn(new string[] { "IsScanning", "IsConnecting" })]
		public bool IsLoadingIndicatorVisible
		{
			get
			{
				if (!IsScanning.Value)
				{
					return IsConnecting.Value;
				}
				return true;
			}
		}

		[DependsOn(new string[] { "IsLoadingIndicatorVisible" })]
		public bool IsNotLoadingIndicatorVisible => !IsLoadingIndicatorVisible;

		public bool HasSkippedWifi { get; set; }

		public ICommand StartScan => new MvxCommand(DoStartScan);

		public ICommand Connect => new MvxAsyncCommand<WifiNetworkInfo>(DoConnect);

		protected virtual bool ShouldCheckPingAfterWifiConnection => true;

		protected virtual bool ShouldDelayBetweenWifiManagerCalls => true;

		public WifiSelectionViewModel(ILocalSettings localSettings, IGeoLocationService geoLocationService, ICrashReporter crashReporter, ICurrentConsoleService currentConsoleService)
			: base(localSettings)
		{
			try
			{
				this.geoLocationService = geoLocationService;
				this.crashReporter = crashReporter;
				wifiStateChanged = wifiService.WhenNetworkStateChanged.Subscribe(ChangeWifiState);
				ConsoleType? consoleType = currentConsoleService?.CurrentConsoleType;
				showUnitsConfiguration = !consoleType.HasValue || !consoleType.Value.IsRower();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			await Scan();
			if (connectivity.IsConnected)
			{
				Log.Trace("Wifi", "Already connected to the internet, skipping WifiSelectionViewModel");
				await ShowNextOnboardingViewModel();
			}
		}

		private void ChangeWifiState(WifiNetworkState wifiState)
		{
			if (connectivity.IsConnected && (DesiredNetworkSsid == null || wifiService.ActiveNetworkInfo.Ssid.Replace("\"", "") == DesiredNetworkSsid))
			{
				IsConnecting.Value = true;
				Log.Trace("Wifi", "Wifi connected with internet");
				wifiStateChanged?.Dispose();
				wifiStateChanged = null;
				Task.Run((Func<Task>)CheckForInternetThenShowNextOnboardingViewModel);
			}
		}

		private void DoStartScan()
		{
			ScanTask = Task.Run((Func<Task>)Scan);
		}

		public async Task Scan()
		{
			IsScanning.Value = true;
			wifiService.TurnWifiOn();
			try
			{
				List<WifiNetworkInfo> list = await wifiService.GetNetworks();
				list.Add(new WifiNetworkInfo
				{
					Ssid = Wolf.Core.Resources.AppStrings.wifi_other,
					Rssi = -2
				});
				Networks.Value = list;
				if (wifiService.ActiveNetworkInfo != null && wifiService.ActiveNetworkInfo.Rssi != -1 && connectivity != null && connectivity.IsConnected)
				{
					await CheckForInternetThenShowNextOnboardingViewModel();
				}
			}
			catch (TimeoutException)
			{
				Log.Trace("Wifi", "WifiService timed out scanning for networks");
			}
			IsScanning.Value = false;
		}

		private void DoGoToOther()
		{
			ShowViewModel<SettingsOtherWifiDialogViewModel>(new WifiNetworkInfo());
		}

		public async Task DoConnect(WifiNetworkInfo wifi)
		{
			if (wifi.WifiRssiLevel == WifiNetworkInfo.RssiLevel.NA)
			{
				DoGoToOther();
				return;
			}
			DesiredNetworkSsid = wifi.Ssid;
			Log.Trace("Wifi", "Attempting to connect to wifi network: " + wifi.Ssid);
			if (wifi == wifiService.ActiveNetworkInfo)
			{
				await CheckForInternetThenShowNextOnboardingViewModel();
				return;
			}
			try
			{
				switch (wifi.Auth)
				{
				case WifiNetworkInfo.AuthType.None:
				{
					IsConnecting.Value = true;
					WifiConnectionResults wifiConnectionResults = await wifiService.ConnectToNetwork(wifi).ConfigureAwait(continueOnCapturedContext: false);
					if (wifiConnectionResults != WifiConnectionResults.Success && wifi.Security == WifiNetworkInfo.SecurityType.WpaWpa2)
					{
						Log.Trace("Wifi", "Connection failed over WPA/WPA2, attempting to connect over WEP");
						wifi.Security = WifiNetworkInfo.SecurityType.Wep;
						IsConnecting.Value = true;
						wifiConnectionResults = await wifiService.ConnectToNetwork(wifi).ConfigureAwait(continueOnCapturedContext: false);
					}
					if (wifiConnectionResults == WifiConnectionResults.AuthenticationError)
					{
						throw new WifiException(Wolf.Core.Resources.AppStrings.authentication_invalid_user_pass);
					}
					if (WifiConnectionResults.TimeoutError == wifiConnectionResults && Mvx.TryResolve<IWolfAnalytics>(out var service))
					{
						service.HandledWifiTimeoutError(new WifiException(Wolf.Core.Resources.AppStrings.wifi_connect_error));
						throw new WifiException(Wolf.Core.Resources.AppStrings.wifi_connect_error);
					}
					if (wifiConnectionResults != WifiConnectionResults.Success)
					{
						throw new NotSupportedException(Wolf.Core.Resources.AppStrings.wifi_connect_error);
					}
					await CheckForInternetThenShowNextOnboardingViewModel();
					break;
				}
				case WifiNetworkInfo.AuthType.Pass:
				case WifiNetworkInfo.AuthType.IdentityPass:
					ShowViewModel<SettingsOtherWifiDialogViewModel>(wifi);
					break;
				default:
					throw new NotSupportedException(Wolf.Core.Resources.AppStrings.wifi_connect_error_security_type);
				}
			}
			catch (Exception ex)
			{
				Log.Error("Wifi", ex.GetType().Name + " occurred connecting to network " + wifi?.Ssid + ": " + ex.Message);
				WifiConnectError.Value = ex.Message;
				IsConnecting.Value = false;
				if (!(ex is WifiException))
				{
					await crashReporter.ReportError(ex.Message, ex, new Dictionary<string, object> { { "WifiNetworkInfo", wifi } });
				}
			}
		}

		protected async Task CheckForInternetThenShowNextOnboardingViewModel()
		{
			if (isDisposed || navigatingAway || hasStartedInternetPingCheck)
			{
				return;
			}
			hasStartedInternetPingCheck = true;
			wifiService.RefreshConnectivityState();
			await DelayForWifiManagerOperationsIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
			Log.Trace("Wifi", string.Format("{0}: {1}", "ShouldCheckPingAfterWifiConnection", ShouldCheckPingAfterWifiConnection));
			if (ShouldCheckPingAfterWifiConnection)
			{
				bool flag = await CheckIsRemoteInternetReachable().ConfigureAwait(continueOnCapturedContext: false);
				Log.Trace("Wifi", string.Format("{0}: {1}", "isRemoteReachable", flag));
				if (!flag)
				{
					Task.Run((Func<Task>)InternetReachableCheckFailed);
					return;
				}
			}
			Log.Trace("Wifi", "Going to next onboarding VM...");
			await ShowNextOnboardingViewModel().ConfigureAwait(continueOnCapturedContext: false);
		}

		protected virtual async Task InternetReachableCheckFailed()
		{
			IsConnecting.Value = true;
			await DelayForWifiManagerOperationsIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
			if (!isDisposed)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.default_no_wifi_title, Wolf.Core.Resources.AppStrings.onboarding_internet_check_error_message, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)OnInternetUnreachableFailureDialogClosed, (Action)null, false, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
			}
		}

		protected virtual void OnInternetUnreachableFailureDialogClosed()
		{
			Task.Run((Func<Task>)ForgetConnectionAndGoToWelcomeScreen);
		}

		private async Task ForgetConnectionAndGoToWelcomeScreen()
		{
			if (!navigatingAway)
			{
				navigatingAway = true;
				wifiService.DisableConfiguredNetworks();
				await DelayForWifiManagerOperationsIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
				wifiService.RemoveConfiguredNetworks();
				await DelayForWifiManagerOperationsIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
				wifiService.SaveConfiguration();
				await DelayForWifiManagerOperationsIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
				wifiService.TurnWifiOff();
				await DelayForWifiManagerOperationsIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
				GoToViewModelAndClearNavStack<WelcomeViewModel>();
				DoClose();
			}
		}

		protected virtual async Task ShowNextOnboardingViewModel()
		{
			await Task.WhenAll(new List<Task> { geoLocationService.PreFetchIsLocatedInUs() });
			IsConnecting.Value = false;
			if (!HasSkippedWifi && !navigatingAway)
			{
				navigatingAway = true;
				if (featureFlagManager.IsFeatureEnabled(FeatureFlags.UseLocalizedStrings) && deviceInfo.IsBuiltIn)
				{
					ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<LanguageSelectionViewModel>(), (MvxRequestedBy)null);
					Close(this);
				}
				else
				{
					ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<EmbeddedUpdateCheckViewModel>(), (MvxRequestedBy)null);
				}
			}
		}

		private async Task<bool> CheckIsRemoteInternetReachable()
		{
			try
			{
				Log.Trace("Wifi", "Running a ping check...");
				Guid pingCheckGuid = Guid.NewGuid();
				Log.Trace("Wifi", $"Ping check GUID started: {pingCheckGuid}");
				bool connectionSucceeded = false;
				for (int i = 0; i < 3; i++)
				{
					if (await RemoteInternetTest().ConfigureAwait(continueOnCapturedContext: false))
					{
						connectionSucceeded = true;
						break;
					}
				}
				Log.Trace("Wifi", $"Ping check GUID finished: {pingCheckGuid}");
				Log.Trace("Wifi", $"Ping success: {connectionSucceeded}");
				return connectionSucceeded;
			}
			catch (Exception exception)
			{
				Log.Error("Wifi", "Error checking internet connection in CheckIsRemoteInternetReachable", exception);
			}
			return false;
		}

		protected virtual async Task<bool> RemoteInternetTest()
		{
			return await wifiService.PingSucceeds().ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task DelayForWifiManagerOperationsIfNecessary()
		{
			if (ShouldDelayBetweenWifiManagerCalls)
			{
				await Task.Delay(500).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public override void Dispose()
		{
			wifiStateChanged?.Dispose();
			wifiStateChanged = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

