namespace Wolf.Core.ViewModels.Onboarding.FirmwareUpdate
{
	public class OnboardingFirmwareUpdateViewModel : BaseVideoViewModel
	{
		public class NavObject : ShowViewModelParameters
		{
			public bool IsDfuRecovery { get; set; }
		}

		public const string TabletVideoSlug = "firmware-update-video-tablet";

		public const string PhoneVideoSlug = "firmware-update-video-phone";

		public readonly INC<string> StatusText = new NC<string>();

		public readonly INC<string> MessageText = new NC<string>();

		public readonly INC<string> ErrorMessage = new NC<string>();

		public readonly INC<int> Progress = new NC<int>(0);

		public readonly INC<bool> PreparingVisible = new NC<bool>(value: false);

		public readonly INC<bool> UploadingVisible = new NC<bool>(value: false);

		public readonly INC<bool> CompleteVisible = new NC<bool>(value: false);

		private IDisposable stateChangeSub;

		private IDisposable progressSub;

		private readonly IUpdater updater;

		private readonly ICheckUpdateService checker;

		private readonly ILaunchUpdate updateLauncher;

		private new readonly IBleConsoleService bleConsoleService;

		private new readonly IIfitApiService apiService;

		private bool updateCompleted;

		private string email;

		private bool isActivationFlow;

		private bool isDfuRecovery;

		public override string VideoSlug
		{
			get
			{
				if (!IsTablet)
				{
					return "firmware-update-video-phone";
				}
				return "firmware-update-video-tablet";
			}
		}

		public override bool CanShowLoading => false;

		public override bool LoopVideo => true;

		[DependsOn(new string[] { "PreparingVisible", "CompleteVisible" })]
		public bool ShowUpdateIndicator
		{
			get
			{
				if (!PreparingVisible.Value)
				{
					return CompleteVisible.Value;
				}
				return true;
			}
		}

		public ICommand RetryCommand => new MvxAsyncCommand(StartFirmwareUpdate);

		public virtual void Init(NavObject nav)
		{
			email = nav.Email;
			isActivationFlow = nav.IsActivationFlow;
			isDfuRecovery = nav.IsDfuRecovery;
		}

		public OnboardingFirmwareUpdateViewModel(ILocalSettings localSettings, IVideoService videoService, IUpdater updater, ICheckUpdateService checker, ILaunchUpdate updateLauncher, IBleConsoleService bleConsoleService, IIfitApiService apiService)
			: base(localSettings, videoService, apiService)
		{
			try
			{
				this.updater = updater;
				this.checker = checker;
				this.updateLauncher = updateLauncher;
				this.bleConsoleService = bleConsoleService;
				this.apiService = apiService;
				MessageText.Value = string.Format(Wolf.Core.Resources.AppStrings.firmware_message, IsTablet ? "\n" : " ");
				PreparingUpdate(Wolf.Core.Resources.AppStrings.firmware_preparing);
				progressSub = updater.WhenProgressChanged.Subscribe(delegate(int x)
				{
					Progress.Value = x;
					StatusText.Value = string.Format(Wolf.Core.Resources.AppStrings.firmware_update_updating_firmware_percent, x);
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init()
		{
			if (bleConsoleService.CurrentDevice is MockDevice)
			{
				ShowUpdateCompleted();
				NavigateToNext();
			}
			else
			{
				Task.Run((Func<Task>)StartFirmwareUpdate);
			}
		}

		public override void Dispose()
		{
			stateChangeSub?.Dispose();
			progressSub?.Dispose();
			base.Dispose();
			UnregisterChangeHandlers();
		}

		protected override void NavigateToNext()
		{
			base.NavigateToNext();
			if (apiService?.CurrentlyAuthenticatedUser?.Premium == true)
			{
				NavigateToDashboardViewModel();
			}
			else
			{
				ShowViewModel<OnboardingPreVideoViewModel>(new ShowViewModelParameters
				{
					Email = email,
					IsActivationFlow = isActivationFlow
				});
			}
			DoClose();
		}

		private async Task StartFirmwareUpdate()
		{
			switch (await checker.CheckForUpdate())
			{
			case CheckUpdateState.UpToDate:
				NavigateToNext();
				break;
			case CheckUpdateState.UpdateAvailable:
				if (localSettings.ShowAutomaticUpdate)
				{
					InitiateUpdate();
				}
				else
				{
					NavigateToNext();
				}
				break;
			case CheckUpdateState.NoMachine:
				if (isDfuRecovery)
				{
					InitiateUpdate();
				}
				else
				{
					OnError(Wolf.Core.Resources.AppStrings.no_machine_connected);
				}
				break;
			case CheckUpdateState.NoNetwork:
				OnError(Wolf.Core.Resources.AppStrings.no_internet_firmware);
				break;
			case CheckUpdateState.Error:
				OnError(Wolf.Core.Resources.AppStrings.firmware_update_unable_to_update);
				break;
			case CheckUpdateState.Checking:
				break;
			}
		}

		private void OnUpdateStateChanged(UpdateState state)
		{
			switch (state)
			{
			case UpdateState.Transfering:
				TransferingUpdate(Wolf.Core.Resources.AppStrings.firmware_update_transferring);
				break;
			case UpdateState.Failed:
				OnUpdateFailed();
				break;
			case UpdateState.Done:
				UpdateCompleteAsync();
				break;
			case UpdateState.TransferComplete:
				PreparingUpdate(Wolf.Core.Resources.AppStrings.firmware_preparing);
				break;
			case UpdateState.ActivateAndReset:
				PreparingUpdate(Wolf.Core.Resources.AppStrings.firmware_update_activate_and_reset);
				break;
			case UpdateState.DisconnectedBeforeComplete:
				PreparingUpdate(Wolf.Core.Resources.AppStrings.firmware_scanning_equipment);
				break;
			default:
				PreparingUpdate(Wolf.Core.Resources.AppStrings.firmware_preparing);
				break;
			}
		}

		private void PreparingUpdate(string message)
		{
			StatusText.Value = message;
			PreparingVisible.Value = true;
			UploadingVisible.Value = false;
			CompleteVisible.Value = false;
		}

		private void TransferingUpdate(string message)
		{
			StatusText.Value = message;
			PreparingVisible.Value = false;
			UploadingVisible.Value = true;
			CompleteVisible.Value = false;
		}

		private void OnError(string message)
		{
			ErrorMessage.Value = message;
			ShowErrorDialog();
		}

		private void OnUpdateFailed()
		{
			stateChangeSub?.Dispose();
			ShowErrorDialog();
		}

		private void ShowErrorDialog()
		{
			TryAgainDialogInitializationData arbitraryData = new TryAgainDialogInitializationData
			{
				OnDismiss = NavigateToNext,
				CanClose = true,
				IsOnboarding = true,
				ErrorText = Wolf.Core.Resources.AppStrings.firmware_update_error,
				Error1 = TryAgainErrors.FirmewareWifi,
				Error2 = TryAgainErrors.FirmwareRestart,
				Error3 = TryAgainErrors.None,
				Error4 = TryAgainErrors.None,
				Error5 = TryAgainErrors.None,
				Retry = RetryUpdate
			};
			BaseViewModel.ShowDialogViewModel<TryAgainViewModel>(arbitraryData);
		}

		private void RetryUpdate()
		{
			DoClose();
		}

		private void InitiateUpdate()
		{
			stateChangeSub?.Dispose();
			stateChangeSub = updater.WhenUpdateStateChanged.Subscribe(OnUpdateStateChanged);
			Timers.UpdateFirmwareTimer.Start();
			updateLauncher.UpdateConnectedMachine();
		}

		private async Task UpdateCompleteAsync()
		{
			if (updateCompleted)
			{
				Log.Trace("Updating", "Firmware update already completed");
				return;
			}
			Log.Trace("Updating", "Firmware update completed");
			updateCompleted = true;
			Timers.UpdateFirmwareTimer.End("Done updating firmware");
			await Task.Delay(TimeSpan.FromSeconds(2.0));
			await bleConsoleService.ConnectToCachedConsole();
			ShowUpdateCompleted();
			await Task.Delay(TimeSpan.FromSeconds(1.0));
			NavigateToNext();
		}

		private void ShowUpdateCompleted()
		{
			PreparingVisible.Value = false;
			UploadingVisible.Value = false;
			CompleteVisible.Value = true;
			StatusText.Value = Wolf.Core.Resources.AppStrings.firmware_update_done;
		}

		private void RestartFirmwareUpdate()
		{
			PreparingUpdate(Wolf.Core.Resources.AppStrings.firmware_preparing);
			Progress.Value = 0;
			if (bleConsoleService.ConnectionState == ConsoleConnectionState.Connected)
			{
				Task.Run((Func<Task>)StartFirmwareUpdate);
				return;
			}
			ShowBleScanningDialog(showSafely: true, new BleDialogInitializationData
			{
				CanClose = false,
				IsOnboarding = true,
				OnFinished = delegate
				{
					Task.Run((Func<Task>)StartFirmwareUpdate);
				}
			});
		}

