namespace Wolf.Core.ViewModels.Onboarding.Measurements
{
	public class MeasurementSelectionViewModel : BaseViewModel
	{
		public readonly INC<bool> IsMetric = new NC<bool>();

		private readonly ISettingsRouter settingsRouter;

		private readonly ISetUnitsService setUnitsService;

		public IMvxCommand SelectMetricCommand => new MvxAsyncCommand(SelectMetric);

		public IMvxCommand SelectUSStandardCommand => new MvxAsyncCommand(SelectUSStandard);

		public IMvxCommand NextComamnd => new MvxCommand(DoNext);

		public MeasurementSelectionViewModel(ILocalSettings localSettings, ISettingsRouter settingsRouter, ISetUnitsService setUnitsService)
			: base(localSettings)
		{
			try
			{
				this.settingsRouter = settingsRouter;
				this.setUnitsService = setUnitsService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			bool valueOrDefault = currentConsoleService.Console?.ConsoleInfo?.IsClub == true;
			INC<bool> isMetric = IsMetric;
			isMetric.Value = await settingsRouter.GetIsMetric(valueOrDefault).ConfigureAwait(continueOnCapturedContext: false);
			await base.OnViewShown().ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task SelectMetric()
		{
			IsMetric.Value = true;
			bool valueOrDefault = currentConsoleService.Console?.ConsoleInfo?.IsClub == true;
			await setUnitsService.SetUnits(isMetric: true, valueOrDefault);
		}

		private async Task SelectUSStandard()
		{
			IsMetric.Value = false;
			bool valueOrDefault = currentConsoleService.Console?.ConsoleInfo?.IsClub == true;
			await setUnitsService.SetUnits(isMetric: false, valueOrDefault);
		}

