	public class AccountsContentViewModel : BaseContentViewModel
	{
		public class IsActiveToRightImageValueConverter : MvxValueConverter<bool, UserViewRightImageType>
		{
			protected override UserViewRightImageType Convert(bool value, Type targetType, object parameter, CultureInfo culture)
			{
				if (!value)
				{
					return UserViewRightImageType.Switch;
				}
				return UserViewRightImageType.Check;
			}
		}

		public readonly INC<int> UserCount = new NC<int>(1);

		public readonly INC<bool> IsFamilyPlan = new NC<bool>();

		public ICommand AddAccountClicked => new MvxCommand(DoShowAddUser);

		public ICommand NavManageAccounts => new MvxCommand(DoNavManageAccounts);

		public AccountsContentViewModel(ILocalSettings localSettings, IIfitApiService api, IDialogPresenter dialogPresenter, IFailedUploadMonitor failedUploadMonitor)
			: base(localSettings, api, dialogPresenter, failedUploadMonitor)
		{
			try
			{
				LoggedInUser.Value = api.CurrentlyAuthenticatedUser;
				PopulateUserList(api.AuthenticatedUsers);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void PopulateUserList(List<User> authenticatedUsers)
		{
			List<User> list = authenticatedUsers.Where((User x) => x.Id != api.CurrentlyAuthenticatedUserId).DistinctBy((User x) => x.Id).OrderBy((User x) => x.Firstname, StringComparer.CurrentCultureIgnoreCase)
				.ToList();
			list.Insert(0, api.CurrentlyAuthenticatedUser);
			foreach (User item in list)
			{
				Users.Add(new UserAccountMenuItemModel(localSettings, api, item, UserViewRightImageType.None, DoSwitchUserAsync));
			}
			UserCount.Value = Users.Count;
			IsFamilyPlan.Value = api.CurrentlyAuthenticatedUser.SubscriptionType == User.SubscriptionTypes.CoachPlus;
		}

		protected async Task DoSwitchUserAsync(User toUser)
		{
			if (toUser == null)
			{
				return;
			}
			if (toUser.Equals(LoggedInUser.Value))
			{
				ShowViewModel<MyProfileViewModel>();
				return;
			}
			ClearDialogs();
			webviewHolderFactory.WebviewHolderStore.FlushAll();
			try
			{
				await api.SwitchUser(toUser.Id);
				ClearCookies();
				DoClose();
				HardResetNavigation();
			}
			catch (Exception)
			{
				ShowLoginViewModel(new PreLoginNavObject
				{
					UserName = toUser.Username
				});
			}
		}

		protected void DoShowAddUser()
		{
			ClearDialogs();
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.ShowCommonOnboardingWebFlow))
			{
				ShowLoginViewModel(new OnboardingWebViewModel.NavObject
				{
					ShowLogin = true
				}, null, clearStack: false);
			}
			else
			{
				ShowLoginViewModel(new PreLoginNavObject
				{
					AllowCancel = true,
					ShowLogin = true
				}, null, clearStack: false);
			}
		}

		private void DoNavManageAccounts()
		{
			ShowViewModel<ManageAccountsViewModel>();
			DoClose();
		}

