	public abstract class BaseContentViewModel : UserAccountViewModel
	{
		public class NavigationObject
		{
			public bool AnimateTransition { get; set; }
		}

		public IMvxCommand LogInOrLogOut => new MvxCommand(DoLogInOrLogOut);

		public bool IsBuiltIn => deviceInfo?.IsBuiltIn ?? false;

		public bool AnimateTransition { get; set; }

		protected BaseContentViewModel(ILocalSettings localSettings, IIfitApiService api, IDialogPresenter dialogPresenter, IFailedUploadMonitor failedUploadMonitor)
		{
			try
			{
				base..ctor(localSettings, api, dialogPresenter, failedUploadMonitor);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavigationObject navigationObject)
		{
			if (navigationObject != null)
			{
				AnimateTransition = navigationObject.AnimateTransition;
			}
		}

		private void DoLogInOrLogOut()
		{
			if (base.HasLoggedInUser)
			{
				BaseViewModel baseViewModel = dialogPresenter?.CurrentMainViewModel as BaseViewModel;
				DoClose();
				baseViewModel?.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.profile_logout_confirmation_title, Wolf.Core.Resources.AppStrings.profile_logout_confirmation_description, LogoutFunc, Wolf.Core.Resources.AppStrings.profile_logout_cancel_button.ToUpper(), Wolf.Core.Resources.AppStrings.yes.ToUpper());
				return;
			}
			DoClose();
			if (!connectivity.IsConnected && deviceInfo.IsBuiltIn)
			{
				ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<WifiSelectionViewModel>(), (MvxRequestedBy)null);
			}
			else
			{
				ShowLoginViewModel(null, ShireViewParams.ChildView<LoginIfitViewModel>());
			}
		}

		private async Task<object> LogoutFunc(CancellationToken arg)
		{
			ClearCookies();
			Log.Trace("Settings", "Logout confirmation received");
			if (!api.HasLoggedInUser)
			{
				LoggedInUser.Value = null;
			}
			await DoLogOut();
			ClearDialogs();
			return 0;
		}

