		private readonly IDisposable connectedAccessoriesCountChangedSub;

		private readonly IWolfAnalytics analytics;

		private readonly INeedsRefreshService refreshService;

		private readonly IStartManualWorkoutService startManualWorkoutService;

		private readonly ILockPinService lockPinService;

		private readonly ILockScreenHandler lockScreenHandler;

		private readonly IConnectedBluetoothAccessories connectedBluetoothAccessories;

		private readonly ISendBroadcastService sendBroadcastService;

		private bool navigationInProgress;

		public readonly INC<bool> ShowUpgradeButton = new NC<bool>();

		public readonly INC<int> BluetoothAccessoriesCount = new NC<int>();

		public ICommand AppearanceButtonClicked => new MvxCommand(delegate
		{
			BeginNavigateAway(OnAppearanceButtonClicked);
		});

		public ICommand BluetoothAccessoriesButtonClicked => new MvxCommand(OnBluetoothAccessoriesClicked);

		public ICommand BleWifiButtonClicked => new MvxCommand(delegate
		{
