		});

		public ICommand SettingsButtonClicked => new MvxCommand(delegate
		{
			BeginNavigateAway(OnSettingsButtonClicked);
		});

		public ICommand FeedbackButtonClicked => new MvxCommand(delegate
		{
			BeginNavigateAway(OnFeedbackButtonClicked);
		});

		public ICommand LockScreenButtonClicked => new MvxCommand(OnLockScreenButtonClicked);

		public ICommand WhatsNewButtonClicked => new MvxCommand(OnWhatsNewButtonClicked);

		public ICommand HelpButtonClicked => new MvxCommand(delegate
		{
			BeginNavigateAway(OnHelpButtonClicked);
		});

		public ICommand ShowProfile => new MvxCommand(OnShowProfile);

		public ICommand UpdateToiFIT2 => new MvxCommand(OnUpdateToiFIT2);

		public ICommand StartManualWorkout => new MvxAsyncCommand(OnStartManualWorkout);

		public ICommand InviteUsersClickedCommand => new MvxCommand(delegate
		{
			BeginNavigateAway(OnInviteUsersClicked);
		});

		public ICommand SwitchProfileClickedCommand => new MvxCommand(delegate
		{
			BeginNavigateAway(OnSwitchProfileClicked);
		});

		public ICommand MembershipClickedCommand => new MvxCommand(delegate
		{
			BeginNavigateAway(OnMembershipClicked);
		});

		public ICommand ShopAccessoriesClicked => new MvxCommand(OnShopAccessoriesButtonClicked);

		public bool IsShowingWifiButton
		{
			get
			{
				if (!base.IsBuiltIn)
				{
					return base.IsStrengthMirror;
				}
				return true;
			}
		}

		public bool ShowLockScreenButton => lockScreenHandler.CanShowLockScreen;

		public bool ShowAppearanceButton
		{
			get
			{
				if (IsTablet)
				{
					IFeatureFlagManager obj = featureFlagManager;
					if (obj != null && obj.IsFeatureEnabled(FeatureFlags.WolfColorSchemeFeature) && !deviceInfo.IsStrengthMirror)
					{
						return !deviceInfo.UseHeadlessBikeTheme;
					}
				}
				return false;
			}
		}

		public bool ShowShopSection => featureFlagManager.IsFeatureEnabled(FeatureFlags.ShowShopSectionInNavigationDrawer);

		public bool ShowUpdateiFIT2 => featureFlagManager.IsFeatureEnabled(FeatureFlags.ValinorEnabled);

		[DependsOn(new string[] { "HasLoggedInUser" })]
		public bool HasLoggedInUserNonClub
		{
			get
			{
				if (base.HasLoggedInUser)
				{
					return !currentConsoleService.IsBuiltinClub;
				}
				return false;
			}
		}

		public bool IsWhatsNewItemVisible => featureFlagManager.IsFeatureEnabled(FeatureFlags.FeatureAnnouncementsEnabled);

		[DependsOn(new string[] { "LoggedInUser" })]
		public bool IsBuiltInCoachPlusUser
		{
			get
			{
				if (deviceInfo.IsBuiltIn && !currentConsoleService.IsBuiltinClub)
				{
					User value = LoggedInUser.Value;
					if (value == null)
					{
						return false;
					}
					return value.SubscriptionType == User.SubscriptionTypes.CoachPlus;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "LoggedInUser" })]
		public bool ShowMembership
		{
			get
			{
				if (base.HasLoggedInUser)
				{
					if (deviceInfo.IsBuiltIn)
					{
						return !currentConsoleService.IsBuiltinClub;
					}
					return true;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "HasLoggedInUserNonClub" })]
		public bool IsOtherAccountsVisible
		{
			get
			{
				if (HasLoggedInUserNonClub && !IsSwitchProfileVisible)
				{
					return IsTablet;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "LoggedInUser" })]
		public bool IsSwitchProfileVisible
		{
			get
			{
				if (ShouldShowAccountSelection())
				{
					if (!localSettings.IsAllAuthenticatedUsersLinked)
					{
						User value = LoggedInUser.Value;
						if (value != null && value.IsSecondary)
						{
							return api.AuthenticatedUsers.All((User user) => user.SubscriptionType != User.SubscriptionTypes.Premium);
						}
						return false;
					}
					return true;
				}
				return false;
			}
		}

		public bool ShowBluetoothAccessoriesButton => base.IsBuiltIn;

		[DependsOn(new string[] { "BluetoothAccessoriesCount" })]
		public string BluetoothAccessoriesCountText
		{
			get
			{
				if (BluetoothAccessoriesCount.Value <= 0)
				{
					return string.Empty;
				}
				return BluetoothAccessoriesCount.Value.ToString();
			}
		}

		[DependsOn(new string[] { "BluetoothAccessoriesCount" })]
		public bool ShowBluetoothAccessoriesBadge
		{
			get
			{
				if (BluetoothAccessoriesCount.Value > 0)
				{
					return ShowBluetoothAccessoriesButton;
				}
				return false;
			}
		}

		public NavigationContentViewModel(ILocalSettings localSettings, IIfitApiService api, IDialogPresenter dialogPresenter, IFailedUploadMonitor failedUploadMonitor, INeedsRefreshService refreshService, IWolfAnalytics analytics, IStartManualWorkoutService startManualWorkoutService, ICurrentConsoleService currentConsoleService, ILockPinService lockPinService, ILockScreenHandler lockScreenHandler, IConnectedBluetoothAccessories connectedBluetoothAccessories, ISendBroadcastService sendBroadcastService)
			: base(localSettings, api, dialogPresenter, failedUploadMonitor)
		{
			try
			{
				NavigationContentViewModel navigationContentViewModel = this;
				this.refreshService = refreshService;
				this.analytics = analytics;
				this.startManualWorkoutService = startManualWorkoutService;
				this.lockPinService = lockPinService;
				this.lockScreenHandler = lockScreenHandler;
				this.connectedBluetoothAccessories = connectedBluetoothAccessories;
				this.sendBroadcastService = sendBroadcastService;
				needsRefreshSubscription = refreshService.WhenNeedsRefresh.Where((IRefreshPayload payload) => payload.Cause == RefreshCause.AuthenticatedUserChanged || payload.Cause == RefreshCause.TokenRefreshed).SubscribeWithErrorLogging(delegate
				{
					navigationContentViewModel.LoggedInUser.Value = api.CurrentlyAuthenticatedUser;
				});
				BluetoothAccessoriesCount.Value = connectedBluetoothAccessories.DeviceCount;
				connectedAccessoriesCountChangedSub = connectedBluetoothAccessories.WhenDeviceCountChanged.SubscribeWithErrorLogging(delegate(int deviceCount)
				{
					navigationContentViewModel.BluetoothAccessoriesCount.Value = deviceCount;
				});
				User currentlyAuthenticatedUser = api.CurrentlyAuthenticatedUser;
				int num;
				if (currentlyAuthenticatedUser != null && currentlyAuthenticatedUser.SubscriptionType == User.SubscriptionTypes.Free)
				{
					User currentlyAuthenticatedUser2 = api.CurrentlyAuthenticatedUser;
					num = ((currentlyAuthenticatedUser2 != null && !currentlyAuthenticatedUser2.IsSecondary) ? 1 : 0);
				}
				else
				{
					num = 0;
				}
				bool flag = (byte)num != 0;
				ShowUpgradeButton.Value = flag && deviceInfo.IsBuiltIn;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void OnShopAccessoriesButtonClicked()
		{
			string text = featureFlagManager.GetString(FeatureFlags.ShopIFITWebviewUrl);
			if (string.IsNullOrEmpty(text))
			{
				text = "https://shop.ifit.com";
			}
			if (base.IsBuiltIn)
			{
				DoClose();
				ShopQRCodeArbitraryData arbitraryData = new ShopQRCodeArbitraryData(text);
				BaseViewModel.ShowDialogViewModel<ShopQRCodeViewModel>(arbitraryData);
			}
			else
			{
				Browser.OpenAsync(text, BrowserLaunchMode.SystemPreferred);
			}
		}

		public override Task OnViewShown()
		{
			navigationInProgress = false;
			return base.OnViewShown();
		}

		public override void Dispose()
		{
			needsRefreshSubscription?.Dispose();
			needsRefreshSubscription = null;
			connectedBluetoothAccessories.Dispose();
			connectedAccessoriesCountChangedSub.Dispose();
			((UserAccountViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

