		{
			DoClose();
			lockScreenHandler.NavigateToLockScreen();
		}

		private void BeginNavigateAway(Action continuation)
		{
			if (!navigationInProgress)
			{
				navigationInProgress = true;
				DoClose();
				continuation();
			}
		}

