				BluetoothDevicePickerViewModel.Show(BluetoothDevicePickerViewModel.OverlaySource.FromNone);
			}
		}

		private void OnBleWifiButtonClicked()
		{
			IBleRadioStatusService service;
			if (IsShowingWifiButton)
			{
				ShowViewModel<SettingsWifiViewModel>();
			}
			else if (Mvx.TryResolve<IBleRadioStatusService>(out service) && service.CheckAndRequestBluetooth(notifyIfCannotEnable: true, BaseViewModel.GetCaller("OnBleWifiButtonClicked")))
			{
				BleDialogInitializationData initData = new BleDialogInitializationData
				{
					CanClose = true,
					CloseOnDismiss = true,
					OnFinished = delegate
					{
						navigationInProgress = false;
					},
					OnDismiss = delegate
					{
						navigationInProgress = false;
					}
				};
				ShowBleScanningDialog(showSafely: true, initData);
			}
			else
			{
				navigationInProgress = false;
			}
		}

		private void OnFeedbackButtonClicked()
		{
			ShowViewModel<FeedbackViewModel>();
		}

		private void OnHelpButtonClicked()
		{
			ShowViewModel<CloseableWebViewViewModel>(new CloseableWebViewViewModel.NavObject
			{
				LogTag = "WebView",
				Url = featureFlagManager.GetString(FeatureFlags.WolfHelpWebViewUrl)
			});
		}

		private void OnSwitchProfileClicked()
		{
			analytics.SwitchProfileClicked();
			ShowViewModel<AccountSelectionViewModel>();
		}

		private void OnInviteUsersClicked()
		{
			ShowViewModel<ManageAccountsViewModel>();
		}

		private void OnMembershipClicked()
		{
			ShowViewModel<MyMembershipViewModel>();
		}

