		{
			get
			{
				if (!HasLoggedInUser)
				{
					return !base.IsStrengthMirror;
				}
				return false;
			}
		}

		protected UserAccountViewModel(ILocalSettings localSettings, IIfitApiService api, IDialogPresenter dialogPresenter, IFailedUploadMonitor failedUploadMonitor)
			: base(localSettings, failedUploadMonitor)
		{
			try
			{
				this.api = api;
				this.dialogPresenter = dialogPresenter;
				LoggedInUser.Value = api.CurrentlyAuthenticatedUser;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected void OnOtherAccountsClicked()
		{
			if (dialogPresenter.CurrentMainViewModel != null)
			{
				DoClose();
				OnOtherAccountsClicked(dialogPresenter.CurrentMainViewModel.GetType());
			}
		}

		protected void OnOtherAccountsClicked(Type parentType)
		{
			if (BaseViewModel.CurrentContentView == ContentView.Navigation)
			{
				ShowViewModel(parentType, new BaseContentViewModel.NavigationObject
				{
					AnimateTransition = true
				}, ShireViewParams.ChangeDialogContent<NavigationDrawerViewModel, AccountsContentViewModel>());
				BaseViewModel.CurrentContentView = ContentView.Accounts;
			}
			else
			{
				ShowViewModel(parentType, new BaseContentViewModel.NavigationObject
				{
					AnimateTransition = true
				}, ShireViewParams.ChangeDialogContent<NavigationDrawerViewModel, NavigationContentViewModel>());
				BaseViewModel.CurrentContentView = ContentView.Navigation;
			}
			DoClose();
		}

		public override void Dispose()
		{
			base.Dispose();
			secondaryServiceSubscription?.Dispose();
			secondaryServiceSubscription = null;
			if (Users == null)
			{
				return;
			}
			foreach (UserAccountMenuItemModel user in Users)
			{
				user?.Dispose();
			}
			Users?.Clear();
			Users = null;
			UnregisterChangeHandlers();
		}

		protected virtual Task HandleSecondaryServiceResult(SecondaryOperationResult result)
		{
			return Task.Run(delegate
			{
				switch (result)
				{
				case SecondaryOperationResult.InviteSent:
					ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_invite_success;
					break;
				case SecondaryOperationResult.ErrorSendingInvite:
					ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_invite_error;
					break;
				case SecondaryOperationResult.SecondaryRemoved:
					ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_remove_user_success;
					break;
				case SecondaryOperationResult.ErrorRemovingSecondary:
					ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_remove_user_failed;
					break;
				case SecondaryOperationResult.ErrorInviteAlreadyLinked:
					ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_invite_already_premium;
					break;
				case SecondaryOperationResult.ErrorInviteInvalidEmailAddress:
					ToastMessage.Value = Wolf.Core.Resources.AppStrings.settings_invite_invalid_email;
					break;
				}
			});
		}

