	public abstract class BaseLogScreenViewModel : BaseFavoritableWorkoutViewModel, IPostWorkoutViewPresenter, IShowSimpleConfirmationDialog
	{
		public class LogScreenNavObject
		{
			public const string LogCategoryWorkout = "workout";

			public string ActivityLogId { get; set; }

			public bool FromFeed { get; set; }

			public bool FromWolf { get; set; }

			public bool PostWorkout { get; set; }

			public string LogCategory { get; set; }

			public Guid UploadLogItemId { get; set; }

			public UploadResult UploadResult { get; set; }

			public ErrorCode UploadErrorCode { get; set; }
		}

		protected ActivityLog ActivityLog;

		protected readonly ISettingsRouter settingsRouter;

		protected new readonly IDialogPresenter dialogPresenter;

		private new readonly IBleConsoleService bleConsoleService;

		private readonly IBleRadioStatusService bleRadioStatusService;

		protected readonly IPostWorkoutInteractor PostWorkoutInteractor;

		private readonly IWorkoutApiService workoutApiService;

		private readonly IAppReviewService appReviewService;

		private readonly IIdleLogoutService logoutService;

		public readonly INC<IList<LogScreenStatModel>> SummaryStats = new NC<IList<LogScreenStatModel>>();

		public readonly INC<bool> Loading = new NC<bool>(value: true);

		public readonly INC<string> FinishButtonText = new NC<string>("");

		public readonly INC<bool> IsPostWorkout = new NC<bool>(value: true);

		public readonly INC<bool> IsMetric = new NC<bool>();

		public readonly INC<string> WorkoutTitle = new NC<string>();

		public readonly INC<bool> ShowDeleteBtn = new NC<bool>(value: false);

		public readonly INC<string> ErrorMessage = new NC<string>();

		public readonly BooleanCycle ShowRepeatWorkoutButton = new BooleanCycle();

		public readonly INC<bool> IsNonWorkoutLog = new NC<bool>(value: false);

		public readonly INC<bool> HadErrorLoading = new NC<bool>(value: false);

		private readonly Subject<object> whenRepeatedWorkoutStarts = new Subject<object>();

		protected bool HasFailedAlready
		{
			get
			{
				return PostWorkoutInteractor.HasFailedAlready;
			}
			set
			{
				PostWorkoutInteractor.HasFailedAlready = value;
			}
		}

		protected bool HasNavigatedAway
		{
			get
			{
				return PostWorkoutInteractor.HasNavigatedAway;
			}
			private set
			{
				PostWorkoutInteractor.HasNavigatedAway = value;
			}
		}

		protected string ActivityLogId { get; set; }

		protected bool ActivityIsWolfWorkout { get; private set; }

		protected bool WorkoutIsHeartrateTest { get; private set; }

		protected bool HasLoggedInUser => ifitApi?.HasLoggedInUser ?? false;

		protected override string WorkoutId => base.RequestedWorkout?.Id;

		public ICommand DeleteWorkout => new MvxCommand(DoDelete);

		public ICommand FinishWorkout => new MvxCommand(DoFinish);

		public ICommand RepeatWorkout => new MvxAsyncCommand(DoRepeat);

		public bool IsManualWorkout
		{
			get
			{
				if (base.RequestedWorkout != null)
				{
					return string.IsNullOrEmpty(base.RequestedWorkout?.Title);
				}
				return false;
			}
		}

		[DependsOn(new string[] { "Loading", "IsNonWorkoutLog", "CloudEnabled" })]
		public bool ShowFavoriteBtn
		{
			get
			{
				if (!Loading.Value && HasLoggedInUser && base.CloudEnabled && (!IsNonWorkoutLog.Value || IsManualWorkout))
				{
					return !HadErrorLoading.Value;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "Loading", "IsNonWorkoutLog", "IsPostWorkout" })]
		public bool ShowTrashCan
		{
			get
			{
				if (!Loading.Value && (IsNonWorkoutLog.Value || IsPostWorkout.Value || IsManualWorkout))
				{
					return !HadErrorLoading.Value;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "Loading", "IsNonWorkoutLog", "IsPostWorkout" })]
		public bool ShowHamburger
		{
			get
			{
				if (!Loading.Value && !IsNonWorkoutLog.Value && !IsPostWorkout.Value && !IsManualWorkout)
				{
					return !HadErrorLoading.Value;
				}
				return false;
			}
		}

		protected double WorkoutDistance { get; private set; }

		public IWolfSharingService WolfSharingService { get; private set; }

		public IObservable<object> WhenRepeatedWorkoutStarts => whenRepeatedWorkoutStarts;

		protected BaseLogScreenViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, ISettingsRouter settingsRouter, IWolfSharingService wolfSharingService, IDialogPresenter dialogPresenter, IPostWorkoutInteractor postWorkoutInteractor, IFailedUploadMonitor failedUploadMonitor, IAppReviewService appReviewService, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService, IIdleLogoutService logoutService = null, IBleConsoleService bleConsoleService = null, IBleRadioStatusService bleRadioStatusService = null, IWolfAnalytics analytics = null, IWorkoutApiService workoutApiService = null)
			: base(localSettings, featureFlagManager, ifitApi, iFitGatewayApi, failedUploadMonitor, webViewUrlParameterService, webviewSettings, currentConsoleService)
		{
			try
			{
				this.bleConsoleService = bleConsoleService;
				this.bleRadioStatusService = bleRadioStatusService;
				WolfSharingService = wolfSharingService;
				this.settingsRouter = settingsRouter;
				this.dialogPresenter = dialogPresenter;
				PostWorkoutInteractor = postWorkoutInteractor;
				this.workoutApiService = workoutApiService;
				this.appReviewService = appReviewService;
				this.logoutService = logoutService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(LogScreenNavObject nav)
		{
			ActivityLogId = nav?.ActivityLogId;
			IsPostWorkout.Value = nav?.PostWorkout ?? false;
			ActivityIsWolfWorkout = nav?.FromWolf ?? false;
			PostWorkoutInteractor.Initialize(nav, this);
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			PostWorkoutInteractor.DisableStartKey();
			PostWorkoutInteractor.CheckAndShowSafetyKeyDialog();
			PostWorkoutInteractor.CheckAndShowConsoleErrorDialog();
			if (base.viewShownCount > 1)
			{
				return;
			}
			Loading.Value = true;
			InitializeFinishButtonText(ActivityLogId);
			await InitializeIsMetric();
			base.RequestedWorkout = workoutSettings.WorkoutContainer?.Workout;
			MetricStats runningStats = workoutSettings.WorkoutContainer?.Stats?.RunningStats;
			ActivityLog = await PopulateActivityLog(runningStats);
			InitializeWorkoutDistance(runningStats);
			if (!IsTabletWithNoWifi && !HasFailedAlready && base.RequestedWorkout == null && ActivityIsWolfWorkout && !HasNavigatedAway)
			{
				Log.Trace("Workout", "No workout in log screen, workout container empty: " + (workoutSettings.WorkoutContainer == null));
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.log_screen_load_error;
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, ErrorMessage.Value, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), (Action)DoFinish, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false, true);
				return;
			}
			InitializeWorkoutTitle(base.RequestedWorkout);
			InitializeRepeatWorkoutButton(base.RequestedWorkout);
			await UploadMaxHeartRateIfNecessary();
			try
			{
				await CheckIfFavorite();
			}
			catch (NullReferenceException)
			{
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Exception in CheckIfFavorite for workout '" + (WorkoutId ?? "null") + "'", exception);
			}
			SetDeleteButton();
			appReviewService.RequestReview();
			Loading.Value = false;
			if (currentConsoleService.IsBuiltinClub)
			{
				logoutService?.SetActive(active: true);
			}
		}

		private async Task UploadMaxHeartRateIfNecessary()
		{
			_ = 3;
			try
			{
				if (base.RequestedWorkout != null)
				{
					WorkoutIsHeartrateTest = HRTrainingService.IsHRTestWorkoutId(base.RequestedWorkout.Id);
				}
				MetricStats metricStats = workoutSettings.WorkoutContainer?.Stats?.RunningStats;
				int valueOrDefault = (metricStats?.PulseChanges?.Count).GetValueOrDefault();
				if (WorkoutIsHeartrateTest && (IsPostWorkout?.Value ?? false) && valueOrDefault > 0)
				{
					int num = ((metricStats != null) ? (await metricStats.GetMaxHeartRate()) : 0);
					int maximumHeartRate = num;
					if (maximumHeartRate != 0)
					{
						Log.Trace("Workout", $"Saving new maximum heart rate {maximumHeartRate}");
						User user = await User.GetMe(ifitApi);
						await user.GetHeartRateSettings(ifitApi);
						user.HeartRateSettings.MaxHeartRate = maximumHeartRate;
						await user.UpdateHeartRateSettings(ifitApi);
					}
				}
			}
			catch (Exception exception)
			{
				Log.Error("BaseLogScreenViewModel", "Exception thrown UploadMaxHeartRateIfNecessary", exception);
			}
		}

		protected virtual void SetDeleteButton()
		{
			if (ActivityLog == null)
			{
				ShowDeleteBtn.Value = false;
			}
			else
			{
				ShowDeleteBtn.Value = HasLoggedInUser;
			}
		}

		private void InitializeWorkoutDistance(MetricStats runningStats)
		{
			double num = ((runningStats != null && runningStats.DistanceChanges.IsNullOrEmpty()) ? 0.0 : (runningStats?.DistanceChanges.Last.Value ?? 0.0));
			WorkoutDistance = ActivityLog?.Summary?.TotalMeters ?? num;
		}

		protected virtual void InitializeRepeatWorkoutButton(Workout workout)
		{
			ShowRepeatWorkoutButton.Value = !BaseFavoritableWorkoutViewModel.IsConsideredManualWorkout(workout);
		}

		protected void InitializeWorkoutTitle(Workout workout)
		{
			WorkoutTitle.Value = workout?.Title ?? "";
		}

		protected async Task InitializeIsMetric()
		{
			INC<bool> isMetric = IsMetric;
			isMetric.Value = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
		}

		protected void InitializeFinishButtonText(string logId)
		{
			FinishButtonText.Value = Wolf.Core.Resources.AppStrings.finish;
		}

		protected virtual async Task<ActivityLog> PopulateActivityLog(MetricStats runningStats)
		{
			if (HasFailedAlready)
			{
				return null;
			}
			WorkoutRunnerContext workoutRunnerContext = workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext ?? WorkoutRunnerContext.DefaultOnDemandContext;
			string programId = workoutSettings?.WorkoutContainer?.ProgramId;
			string challengeId = workoutSettings?.WorkoutContainer?.ChallengeId;
			ActivityLogPopulateResult log = await PostWorkoutInteractor.PopulateActivityLog(ActivityLogId, WorkoutId, programId, challengeId, runningStats, workoutRunnerContext).ConfigureAwait(continueOnCapturedContext: false);
			if (log?.ActivityLog == null)
			{
				return null;
			}
			if (IsTabletWithNoWifi || !HasLoggedInUser)
			{
				await InitializeStatsFromLog(log.ActivityLog).ConfigureAwait(continueOnCapturedContext: false);
			}
			if (!log.PopulatedFromApi)
			{
				return log.ActivityLog;
			}
			try
			{
				base.RequestedWorkout = await workoutApiService.Get(log.ActivityLog.WorkoutId).ConfigureAwait(continueOnCapturedContext: false);
				base.RequestedWorkout.RoundInclineControls();
			}
			catch (Exception ex)
			{
				Log.Trace("Workout", $"Error loading workout from api - {ex.GetBaseException()}");
				return null;
			}
			return log.ActivityLog;
		}

		public override void Dispose()
		{
			base.Dispose();
			ActivityLog?.Dispose();
			ActivityLog = null;
			UnregisterChangeHandlers();
		}

		protected async Task InitializeStatsFromLog(ActivityLog log)
		{
			bool isMetric = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
			List<LogScreenStatModel> list = GetConfigFor(log)?.Select((StatInfoLabelType x) => LogScreenStatModelHelper.Create(x, log, isMetric))?.ExcludingNulls()?.ToList();
			list?.RemoveAll((LogScreenStatModel x) => x.StatType == StatInfoLabelType.Distance && double.TryParse(x.MainValue, out var result) && result == 0.0);
			SummaryStats.Value = list;
		}

		protected virtual List<StatInfoLabelType> GetConfigFor(ActivityLog log)
		{
			return SummaryStatConfiguration.GetConfigFor(log.Stats);
		}

		protected virtual void DisplayLogLoadErrorMessage()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.error_ifit_loading_log, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), (Action)DoClose, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false, true);
		}

		protected virtual void DisplayLogLoadErrorWorkoutSavedMessage()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.error_log_upload_success_error_loading_view, delegate
			{
				DoFinish();
			}, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), null, null, dismissible: false);
		}

		private void DoDelete()
		{
			if (!HasLoggedInUser)
			{
				DoFinish();
				return;
			}
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.delete_workout_confirmation_title, Wolf.Core.Resources.AppStrings.delete_workout_confirmation_text, async delegate
			{
				await DeleteLogFromApi();
				return (object)null;
			}, Wolf.Core.Resources.AppStrings.delete_workout_cancel_button.ToUpper(), Wolf.Core.Resources.AppStrings.delete_workout_confirm_button.ToUpper());
		}

		protected async Task DeleteLogFromApi()
		{
			Loading.Value = true;
			if (!IsNonWorkoutLog.Value)
			{
				await PostWorkoutInteractor.DeleteActivityLog(ActivityLogId);
			}
			else
			{
				await DeleteUserLog();
			}
		}

		private async Task DeleteUserLog()
		{
			bool flag;
			try
			{
				if (await UserLog.Delete(ifitApi, ActivityLogId))
				{
					flag = true;
				}
				else
				{
					flag = false;
					Log.Trace(LogTag, "Could not delete user log " + ActivityLogId);
				}
			}
			catch (Exception ex)
			{
				flag = false;
				Log.Trace("Workout", "Could not delete activity log " + ActivityLogId + " - " + ex.Message);
			}
			if (!HasNavigatedAway)
			{
				if (flag)
				{
					DoFinish();
				}
				else
				{
					ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.delete_workout_save_error, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), (Action)DoFinish, (Action)null, false, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
				}
			}
		}

		public void DoFinish()
		{
			if (HasNavigatedAway)
			{
				return;
			}
			HasNavigatedAway = true;
			if (IsPostWorkout.Value)
			{
				PostWorkoutInteractor.NavigateAway(ActivityLog?.Duration ?? 0, delegate
				{
					DoLogOut();
				}, NavigateToDashboardViewModel, base.ShowViewModel<DashboardViewModel>);
			}
			else
			{
				DoClose();
			}
		}

		protected virtual async Task DoRepeat()
		{
			if (await ShowErrorIfWorkoutIncompatible(displayBlePairFilter: true))
			{
				return;
			}
			if (!deviceInfo.IsBuiltIn && !base.RequestedWorkout.IsStrengthWorkout())
			{
				if (currentConsoleService.Console?.ConsoleInfo != null)
				{
					IBleConsoleService obj = bleConsoleService;
					if (obj != null && obj.ConnectionState == ConsoleConnectionState.Connected)
					{
						goto IL_00ff;
					}
				}
				if (bleRadioStatusService.CheckAndRequestBluetooth(notifyIfCannotEnable: true, GetType().Name))
				{
					ShowBleScanningDialog();
				}
				return;
			}
			goto IL_00ff;
			IL_00ff:
			if (base.RequestedWorkout != null && !BaseFavoritableWorkoutViewModel.IsConsideredManualWorkout(base.RequestedWorkout) && base.StartWorkoutService != null)
			{
				Task<StateChange> task = (from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
					where x.Current == ConsoleState.Idle
					select x).Take(1).ToTask();
				if (facadeFactoryDependencies.ConsoleStateFacade.GetMostRecentConsoleState() != ConsoleState.Idle)
				{
					await task.ConfigureAwait(continueOnCapturedContext: false);
				}
				AnalyticsSource analyticsSource = new AnalyticsSource(WorkoutSource.Summary);
				if (await base.StartWorkoutService.DoStartWorkout(base.RequestedWorkout, WorkoutRunnerContext.DefaultOnDemandContext, WaitForConsoleReady, analyticsSource))
				{
					whenRepeatedWorkoutStarts.OnNext(null);
					DoClose();
				}
			}
		}

		protected override void DoClose()
		{
			PostWorkoutInteractor.CleanWorkout();
			base.DoClose();
		}

		public void FinishAndNavigateAway()
		{
			DoFinish();
		}

