	public class LogScreenViewModel : BaseLogScreenViewModel
	{
		public const string NativeMethodLoadedSuccessfully = "logViewLoaded";

		public const string NativeParamStatus = "status";

		public const string NativeParamStatusFailure = "failure";

		public const string NativeParamMessage = "message";

		private const string Tag = "LogScreen";

		private bool webviewFinished;

		private bool sharingNow;

		private readonly string[] nonWorkoutTypes = new string[4] { "weight-log", "manual-activity-log", "calories-consumed", "wearable-log" };

		private readonly RateWorkoutViewModel _rateWorkout;

		public readonly INC<bool> ShowToolbar = new NC<bool>(value: false);

		public readonly BooleanCycle ShowShareContainer = new BooleanCycle();

		private System.Threading.Timer webviewTimer;

		protected bool hasWebviewResponded;

		protected virtual TimeSpan WebviewTimeDelta => TimeSpan.FromMilliseconds(10000.0);

		public RateWorkoutViewModel RateWorkoutModel => _rateWorkout;

		public ICommand FacebookShareWorkout => new MvxAsyncCommand(DoFacebookShare);

		public ICommand TwitterShareWorkout => new MvxAsyncCommand(DoTwitterShare);

		public ICommand CloseShareWorkout => new MvxCommand(ShowShareContainer.SwitchValue);

		public ICommand ShareWorkout => new MvxCommand(ShowShareContainer.SwitchValue);

		protected override string Url => featureFlagManager.GetString(FeatureFlags.WolfLogSummaryWebviewUrl);

		protected override bool ShouldPerformAdditionalHostCheck => true;

		public override string LogTag => "LogScreen";

		public LogScreenViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, ISettingsRouter settingsRouter, IWolfSharingService wolfSharingService, IDialogPresenter dialogPresenter, IFeatureFlagManager featureFlagManager, IPostWorkoutInteractor postWorkoutInteractor, IFailedUploadMonitor failedUploadMonitor, IAppReviewService appReviewService, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService, IIdleLogoutService logoutService = null, IBleConsoleService bleConsoleService = null, IBleRadioStatusService bleRadioStatusService = null, IWolfAnalytics analytics = null, IWorkoutApiService workoutApiService = null)
			: base(localSettings, featureFlagManager, ifitApi, iFitGatewayApi, settingsRouter, wolfSharingService, dialogPresenter, postWorkoutInteractor, failedUploadMonitor, appReviewService, webViewUrlParameterService, webviewSettings, currentConsoleService, logoutService, bleConsoleService, bleRadioStatusService, analytics, workoutApiService)
		{
			try
			{
				webviewFinished = false;
				_rateWorkout = new RateWorkoutViewModel(localSettings, ifitApi, analytics);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			if (_rateWorkout != null)
			{
				_rateWorkout.Dispose();
			}
			DisposeTimer();
			base.Dispose();
			UnregisterChangeHandlers();
		}

		public override async Task OnViewShown()
		{
			hasWebviewResponded = false;
			if (base.viewShownCount == 0)
			{
				webviewTimer = new System.Threading.Timer(delegate
				{
					WebviewNonResponsive();
				}, null, (int)WebviewTimeDelta.TotalMilliseconds, -1);
			}
			await base.OnViewShown();
			sharingNow = false;
			_rateWorkout.WorkoutId = WorkoutId;
			await _rateWorkout.UpdateRatingFromApi();
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.ExposeTask("logViewPostWorkoutUserRating", OnRateWorkout);
			bridge.ExposeTask("logViewShareWorkout", OnShareWorkout);
			bridge.Expose("logType", OnLogType);
			bridge.Expose("logViewLoadingError", OnLogViewLoadingError);
			bridge.Expose("logViewLoaded", OnLogViewLoadedSuccessfully);
		}

		public override void OnWebviewFinishedNavigating(object sender, EventArgs e)
		{
			webviewFinished = true;
			InvokeOnMainThread(async delegate
			{
				Dictionary<string, string> dictionary = (await (webViewConfigService?.GetBaseConfigsExcluding())) ?? new Dictionary<string, string>();
				IWolfEnvironment wolfEnvironment = ifitApi.Environment as IWolfEnvironment;
				dictionary["clientId"] = wolfEnvironment.LogScreenClientId;
				dictionary["clientSecret"] = wolfEnvironment.LogScreenClientSecret;
				dictionary["baseIfitAPIUrl"] = wolfEnvironment.Endpoint;
				Bridge.Call("logViewSetupApp", dictionary);
				SendLogIdToJS();
			});
		}

		public override void OnWebviewErrorLoading(object sender, EventArgs e)
		{
			HadErrorLoading.Value = true;
			IsNonWorkoutLog.Value = false;
			if (!base.HasFailedAlready && !base.HasNavigatedAway)
			{
				Log.Error("WebView", "Error while loading log screen webview.");
				DisposeTimer();
				DisplayLogLoadErrorMessage();
				base.HasFailedAlready = true;
			}
		}

		private void DisposeTimer()
		{
			webviewTimer?.DisposeAsync();
			webviewTimer = null;
		}

		private void SendLogIdToJS()
		{
			if (webviewFinished && !string.IsNullOrEmpty(base.ActivityLogId))
			{
				InvokeOnMainThread(delegate
				{
					Bridge.Call("logViewSetLog", new Dictionary<string, string> { ["id"] = base.ActivityLogId });
				});
			}
		}

		protected Task DoFacebookShare()
		{
			return DoSocialShare();
		}

		protected Task DoTwitterShare()
		{
			return DoSocialShare();
		}

		private async Task DoSocialShare()
		{
			_ = 1;
			try
			{
				if (await VerifyOrRequestSharePermission())
				{
					bool flag = !sharingNow;
					sharingNow = false;
					if (flag)
					{
						await ShareViaProvider();
					}
				}
			}
			catch (Exception ex)
			{
				ReportSharingException(ex);
			}
		}

		private void ReportSharingException(Exception ex)
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.share_error, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, true, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
			Log.Error("LogScreen", $"Sharing Exception {ex}", ex);
		}

		protected virtual async Task<bool> VerifyOrRequestSharePermission()
		{
			User me = await User.GetMe(ifitApi);
			if (me.Settings.PrivateProfile != true)
			{
				return true;
			}
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.share_workout_requires_public_profile_title, Wolf.Core.Resources.AppStrings.share_workout_requires_public_profile, delegate
			{
				tcs.TrySetResult(result: true);
				return (Task<object>)null;
			}, cancellableOperation: false, delegate
			{
				tcs.TrySetResult(result: false);
			}, Wolf.Core.Resources.AppStrings.no.ToUpper(), Wolf.Core.Resources.AppStrings.yes.ToUpper(), OnConfirmActionTiming.BeforeClose);
			dialogPresenter?.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, arbitraryData);
			bool result = await tcs.Task;
			if (result)
			{
				me.Settings.PrivateProfile = false;
				await me.UpdateSettings(ifitApi);
			}
			return result;
		}

		private Task ShareViaProvider()
		{
			IConnectivity obj = connectivity;
			if (obj != null && !obj.IsConnected)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.wifi_not_found, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, true, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
			}
			else if (base.RequestedWorkout == null)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.share_error, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, true, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
			}
			return Task.CompletedTask;
		}

		protected async Task OnShareWorkout(IDictionary<string, string> parameters)
		{
			try
			{
				if (parameters.ContainsKey("provider"))
				{
					await ShareViaProvider();
					return;
				}
				throw new Exception("The \"provider\" key is missing from the logViewShareWorkout call");
			}
			catch (Exception ex)
			{
				Log.Error(LogTag, "Error sharing workout: " + ex.Message, ex);
			}
		}

		protected Task OnRateWorkout(IDictionary<string, string> parameters)
		{
			int starRating = Convert.ToInt32(parameters.ContainsKey("rating") ? parameters["rating"] : "0");
			return _rateWorkout.DoSetPopupRatingAsync(starRating);
		}

		protected void OnLogType(IDictionary<string, string> parameters)
		{
			ShowToolbar.Value = true;
			string value = (parameters.ContainsKey("logType") ? parameters["logType"] : string.Empty);
			IsNonWorkoutLog.Value = Enumerable.Contains(nonWorkoutTypes, value);
		}

		protected void OnLogViewLoadingError(IDictionary<string, string> parameters)
		{
			OnWebviewErrorLoading(null, null);
			string text = (parameters.ContainsKey("error") ? parameters["error"] : string.Empty);
			Log.Error(LogTag, "Error loading log view: " + text);
		}

		protected void WebviewNonResponsive()
		{
			if (!hasWebviewResponded)
			{
				Log.Error(LogTag, "WebviewNonResponsive event has been triggered, and the logViewLoaded callback was never called.");
				ShowNoWifiLogScreen(new LogScreenNavObject
				{
					ActivityLogId = base.ActivityLogId,
					PostWorkout = IsPostWorkout.Value
				});
				DoClose();
			}
		}

		protected void OnLogViewLoadedSuccessfully(IDictionary<string, string> parameters)
		{
			parameters.TryGetValue("status", out var value);
			if (value == "failure")
			{
				hasWebviewResponded = false;
				parameters.TryGetValue("message", out var value2);
				Log.Error(LogTag, "View loaded successfully with data error " + value2);
			}
			else
			{
				hasWebviewResponded = true;
			}
		}

