		protected override async Task<ActivityLog> PopulateActivityLog(MetricStats runningStats)
		{
			Log.Trace(LogTag, "Attempting offline population of activity log.");
			if (!Mvx.TryResolve<IActivityLogRepository>(out var service))
			{
				Log.Warn(LogTag, "Could not resolve an IActivityLogRepository. Can not display stats.");
				return null;
			}
			WorkoutRunnerContext workoutRunnerContext = workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext ?? WorkoutRunnerContext.DefaultOnDemandContext;
			string programId = workoutSettings?.WorkoutContainer?.ProgramId;
			string challengeId = workoutSettings?.WorkoutContainer?.ChallengeId;
			ActivityLogPopulateResult log = await service.PopulateActivityLog(null, WorkoutId, programId, challengeId, runningStats, workoutRunnerContext);
			if (log?.ActivityLog == null)
			{
				DisplayLogLoadErrorMessage();
				return null;
			}
			await InitializeStatsFromLog(log.ActivityLog).ConfigureAwait(continueOnCapturedContext: false);
			return log.ActivityLog;
		}

