namespace Wolf.Core.ViewModels.Login
{
	public class FirstBleContainerViewModel : BaseBleViewModel, IHasUserInfo
	{
		private readonly IMvxWebBrowserTask browserTask;

		private readonly IIfitApiService api;

		private User _currentUser;

		public ICommand Skip => new MvxCommand(DoSkip);

		public ICommand OpenSupportSite => new MvxCommand(DoOpenSupportSite);

		public User CurrentUser
		{
			get
			{
				return _currentUser;
			}
			private set
			{
				_currentUser = value;
				RaisePropertyChanged("CurrentUser");
			}
		}

		public FirstBleContainerViewModel(ILocalSettings localSettings, IMvxWebBrowserTask browserTask, IIfitApiService api, IBleRadioStatusService bleRadioStatusService, ICurrentConsoleService currentConsoleService, IBleConsoleService bleConsoleService = null)
			: base(localSettings, bleRadioStatusService, bleConsoleService)
		{
			try
			{
				this.browserTask = browserTask;
				this.api = api;
				base.ParentType = GetType();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			bleRadioStatusService?.CheckAndRequestBluetooth(notifyIfCannotEnable: true, GetType().Name);
			if (!IsBleConsoleServiceNull("OnViewShown"))
			{
				ShowBleScanningDialog(showSafely: true, new BleDialogInitializationData
				{
					CanClose = true,
					IsOnboarding = true,
					OnFinished = CloseAndShowDashboard,
					OnDismiss = DoSkip
				});
			}
		}

		public override void Start()
		{
			base.Start();
			Task.Run((Func<Task>)LoadUserData);
		}

		private async Task LoadUserData()
		{
			try
			{
				CurrentUser = await User.GetMe(api);
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Error retrieving user status", exception);
			}
		}

		private void DoSkip()
		{
			if (!IsBleConsoleServiceNull("DoSkip"))
			{
				if (currentConsoleService?.Console != null)
				{
					CloseAndShowDashboard();
				}
				else
				{
					ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ble_dialog_skip_title, Wolf.Core.Resources.AppStrings.ble_dialog_skip_description, CloseAndShowDashboard, Wolf.Core.Resources.AppStrings.no_connect.ToUpper(), Wolf.Core.Resources.AppStrings.yes_skip.ToUpper());
				}
			}
