namespace Wolf.Core.ViewModels.LockScreen
{
	public class LockScreenDialogViewModel : BaseSwappingBackgroundViewModel
	{
		private int pinNumberIndex;

		private string[] pinNumberArray = new string[4];

		private bool forceLoggedInUserToDashboard;

		private readonly IDisposable consoleStateSub;

		private readonly IIfitApiService api;

		private readonly ILockPinService lockPinService;

		private readonly ILockScreenHandler lockScreenHandler;

		public readonly INC<int> PauseTimeoutSecondsRemaining = new NC<int>();

		public readonly INC<int> CurrentImageIndex = new NC<int>();

		public readonly INC<int> CurrentPositionIndex = new NC<int>(0);

		public readonly INC<bool> PinNumber1Entered = new NC<bool>();

		public readonly INC<bool> PinNumber2Entered = new NC<bool>();

		public readonly INC<bool> PinNumber3Entered = new NC<bool>();

		public readonly INC<bool> PinNumber4Entered = new NC<bool>();

		public readonly INC<bool> LockPinDoesntMatch = new NC<bool>();

		private IDisposable updatePauseTimeRemainingSub;

		private IDisposable updateStateChangedSub;

		private string LockPinNumber => string.Concat(pinNumberArray).Trim();

		private bool CanCheckPinNumberMatch => LockPinNumber.Length == 4;

		protected override int SecondsBetweenPositionMoves => 60;

		protected override int SecondsBetweenImageChanges => 120;

		protected override int NumPositions => 5;

		public override bool ShouldInterceptConsoleStartButton => true;

		[DependsOn(new string[] { "PauseTimeoutSecondsRemaining" })]
		public string PauseTimeoutRemainingText => ValueFormatters.SecondsFormatter.Format(Math.Max(PauseTimeoutSecondsRemaining.Value, 0));

		[DependsOn(new string[] { "PauseTimeoutSecondsRemaining" })]
		public bool PauseTimeoutVisible
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj != null && obj.IsInWorkout)
				{
					return PauseTimeoutSecondsRemaining.Value >= 1;
				}
				return false;
			}
		}

		public IMvxCommand ClickNumber { get; }

		public IMvxCommand ClickDelete { get; }

		public IMvxCommand ForgotLockPin { get; }

		public override object ArbitraryData
		{
			get
			{
				return base.ArbitraryData;
			}
			set
			{
				base.ArbitraryData = value;
				UpdateFromArbitraryData();
			}
		}

		public LockScreenDialogViewModel(ILocalSettings localSettings, IIfitApiService api, ILockPinService lockPinService, ILockScreenHandler lockScreenHandler)
			: base(localSettings)
		{
			try
			{
				this.api = api;
				this.lockPinService = lockPinService;
				this.lockScreenHandler = lockScreenHandler;
				CurrentImageIndex.Value = StartingIndex;
				ClickNumber = new MvxAsyncCommand<string>(DoPressNumber);
				ClickDelete = new MvxCommand(DoPressDelete);
				ForgotLockPin = new MvxAsyncCommand(DoForgotLockPin);
				PauseTimeoutSecondsRemaining.Value = (currentConsoleService?.Console?.PauseTimeoutSecondsRemaining).GetValueOrDefault();
				updatePauseTimeRemainingSub?.Dispose();
				updatePauseTimeRemainingSub = currentConsoleService?.Console?.WhenPausedTimeRemainingChanged.SubscribeWithErrorLogging(UpdatePauseTimeRemaining);
				updateStateChangedSub?.Dispose();
				updateStateChangedSub = currentConsoleService?.Console?.WhenStateChanged.Where((StateChange x) => x.ChangedFromState(ConsoleState.Paused)).SubscribeWithErrorLogging(UpdateStateChanged);
				consoleStateSub = currentConsoleService?.Console?.WhenStateChanged.Subscribe(ConsoleStateChanged);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			updatePauseTimeRemainingSub?.Dispose();
			updatePauseTimeRemainingSub = null;
			updateStateChangedSub?.Dispose();
			updateStateChangedSub = null;
			IDisposable disposable = consoleStateSub;
			if (disposable != null)
			{
				disposable.Dispose();
				UnregisterChangeHandlers();
			}
		}

		protected override void NextPosition()
		{
			int value = CurrentPositionIndex.Value;
			value++;
			if (value == NumPositions)
			{
				value = 0;
			}
			CurrentPositionIndex.Value = value;
		}

		protected override void NextImage()
		{
			int value = CurrentImageIndex.Value;
			value++;
			if (value == base.NumImages)
			{
				value = 0;
			}
			CurrentImageIndex.Value = value;
		}

		private void ConsoleStateChanged(StateChange state)
		{
			if (state.ChangedToState(ConsoleState.SafetyKeyRemoved))
			{
				lockScreenHandler.UnlockScreen(continueWorkout: true).ConfigureAwait(continueOnCapturedContext: false);
				DoClose();
			}
		}

		private void UpdatePinNumberProperties()
		{
			PinNumber1Entered.Value = !string.IsNullOrWhiteSpace(pinNumberArray[0]);
			PinNumber2Entered.Value = !string.IsNullOrWhiteSpace(pinNumberArray[1]);
			PinNumber3Entered.Value = !string.IsNullOrWhiteSpace(pinNumberArray[2]);
			PinNumber4Entered.Value = !string.IsNullOrWhiteSpace(pinNumberArray[3]);
		}

		private void ClearPinNumberProperties()
		{
			pinNumberIndex = 0;
			Array.Clear(pinNumberArray, 0, pinNumberArray.Length);
			UpdatePinNumberProperties();
		}

		private async Task DoPressNumber(string number)
		{
			if (pinNumberIndex <= pinNumberArray.Length - 1)
			{
				pinNumberArray[pinNumberIndex] = number;
				UpdatePinNumberProperties();
				pinNumberIndex++;
				LockPinDoesntMatch.Value = false;
				await DoCheckPinNumberMatch().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private void DoPressDelete()
		{
			if (pinNumberIndex != 0)
			{
				Array.Clear(pinNumberArray, pinNumberIndex - 1, 1);
				UpdatePinNumberProperties();
				pinNumberIndex--;
				LockPinDoesntMatch.Value = false;
			}
		}

		private async Task DoCheckPinNumberMatch()
		{
			if (CanCheckPinNumberMatch)
			{
				await Task.Delay(300);
				if (!PinNumberConfirmationMatch())
				{
					LockPinDoesntMatchState();
				}
				else if (NoWifi)
				{
					await lockScreenHandler.UnlockScreen(currentConsoleService?.IsInWorkout ?? false).ConfigureAwait(continueOnCapturedContext: false);
					DoClose();
					ShowViewModel<EmbeddedNoWifiDashboardViewModel>();
				}
				else
				{
					await DoDismiss().ConfigureAwait(continueOnCapturedContext: false);
				}
			}
		}

		private async Task DoForgotLockPin()
		{
			if (NoWifi)
			{
				await lockScreenHandler.UnlockScreen(currentConsoleService?.IsInWorkout ?? false).ConfigureAwait(continueOnCapturedContext: false);
				lockScreenHandler.LockWhenFinishProcess = true;
				DoClose();
				ShowViewModel<MobileNoWifiViewModel>();
			}
			else if (!api.HasLoggedInUser)
			{
				await lockScreenHandler.UnlockScreen(currentConsoleService?.IsInWorkout ?? false).ConfigureAwait(continueOnCapturedContext: false);
				ShowLoginViewModel(null, ShireViewParams.ChildView<ForgotPasswordViewModel>());
			}
			else
			{
				ShowViewModel<AccountSelectionVerifyPasswordViewModel>();
			}
		}

		private bool PinNumberConfirmationMatch()
		{
			string lockPinNumber = lockPinService.GetLockPinNumber();
			if (CanCheckPinNumberMatch && !string.IsNullOrEmpty(lockPinNumber))
			{
				return lockPinNumber == LockPinNumber;
			}
			return false;
		}

		private void LockPinDoesntMatchState()
		{
			LockPinDoesntMatch.Value = true;
			ClearPinNumberProperties();
		}

		private async Task DoDismiss()
		{
			bool isInWorkout = currentConsoleService?.IsInWorkout ?? false;
			await lockScreenHandler.UnlockScreen(isInWorkout).ConfigureAwait(continueOnCapturedContext: false);
			if (isInWorkout)
			{
				DoClose();
			}
			else if (forceLoggedInUserToDashboard)
			{
				DoClose();
				NavigateToDashboardViewModel();
			}
			else if (base.IsAccountSelectionAvailable && !(dialogPresenter.CurrentMainViewModel is AccountSelectionViewModel))
			{
				lockScreenHandler.NavigateFrom = typeof(AccountSelectionViewModel);
				NavigateToAccountSelectionViewModel();
			}
			else
			{
				DoClose();
				NavigateToDashboardViewModel();
			}
		}

		private void UpdatePauseTimeRemaining(int remaining)
		{
			PauseTimeoutSecondsRemaining.Value = remaining;
		}

		private void UpdateStateChanged(StateChange change)
		{
			UpdatePauseTimeRemaining(0);
		}

		private void UpdateFromArbitraryData()
		{
			if (ArbitraryData is bool flag)
			{
				forceLoggedInUserToDashboard = flag;
			}
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
