namespace Wolf.Core.ViewModels.Live
{
	public class LiveScheduleViewModel : MainToolbarViewModel
	{
		public new class NavObject : BaseWebViewViewModel.NavObject
		{
			public string InitialModality { get; set; }

			public new string DeepLink { get; set; }
		}

		public const string WebSetupTokenKey = "token";

		public const string WebSetupUserIdKey = "userId";

		public const string WebSetupBaseGatewayKey = "baseGatewayAPIUrl";

		public const string WebSetupSoftwareNum = "softwareNumber";

		public const string WebSetupDeviceType = "deviceType";

		public const string WebSetupClientId = "clientId";

		public const string WebSetupClientSecret = "clientSecret";

		public const string LiveScheduleIdKey = "scheduleId";

		public const string LiveWorkoutIdKey = "workoutId";

		public const string NativeMethodJoinLiveWorkout = "JoinLiveWorkout";

		public const string NativeMethodScheduleSelected = "ScheduleSelected";

		public const string NativeMethodNavigateToLibrary = "NavigateToLibrary";

		private readonly IBleRadioStatusService bleRadioService;

		private readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		private new readonly IBleConsoleService bleConsoleService;

		private readonly IPreWorkoutNavigator preWorkoutNavigator;

		private readonly IWolfAnalytics wolfAnalytics;

		private bool workoutSelected;

		private bool isNavigatingToPreWorkout;

		private bool startedLiveWorkout;

		private bool isHiddenAlready;

		private IDisposable startedWorkoutSub;

		public override int WebviewTTL => 900;

		public override string LogTag => "LiveSchedule";

		public bool HideAnimationEnabled
		{
			get
			{
				if (isNavigatingToPreWorkout)
				{
					IPreWorkoutNavigator obj = preWorkoutNavigator;
					if (obj == null)
					{
						return false;
					}
					return !obj.IsPreWorkoutWebviewEnabled;
				}
				return true;
			}
		}

		protected override string Url
		{
			get
			{
				if (!base.ShouldHermesOverride)
				{
					return MainToolbarViewModel.GetWallEUrlWhenNeed(base.FeatureFlagManager, FeatureFlags.WallELiveUrl, FeatureFlags.LiveScheduleWebViewUrl);
				}
				return base.HermesUrl;
			}
		}

		public LiveScheduleViewModel(ILocalSettings settings, IFeatureFlagManager featureFlagManager, IIfitApiService ifitApi, IBleRadioStatusService bleRadioService, IMvxMainThreadDispatcher mainThreadDispatcher, IFailedUploadMonitor failedUploadMonitor, IPreWorkoutNavigator preWorkoutNavigator, IWolfAnalytics wolfAnalytics, IModalityChangeService modalityChangeService, IWebViewUrlParameterService webViewUrlParameterService, IUpgradeService upgradeService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService, IBleConsoleService bleConsoleService = null)
			: base(settings, featureFlagManager, ToolbarMode.Live, ifitApi, failedUploadMonitor, modalityChangeService, webViewUrlParameterService, upgradeService, webviewSettings, currentConsoleService)
		{
			try
			{
				this.bleRadioService = bleRadioService;
				this.mainThreadDispatcher = mainThreadDispatcher;
				this.bleConsoleService = bleConsoleService;
				this.preWorkoutNavigator = preWorkoutNavigator;
				this.wolfAnalytics = wolfAnalytics;
				analyticsSource = new AnalyticsSource(WorkoutSource.Live, -1);
				startedWorkoutSub = base.StartWorkoutService.WhenWorkoutStarted.Subscribe(delegate(StartingWorkoutParams workoutParams)
				{
					if (workoutParams.RunningContext != WorkoutRunnerContext.DefaultOnDemandContext)
					{
						startedLiveWorkout = true;
					}
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObject nav)
		{
			base.InitialModality = nav?.InitialModality;
			base.DeepLink = nav?.DeepLink;
			SetIsLoadingOnMainThread(isLoading: true);
		}

		public override void WebviewInitialization()
		{
			base.WebviewInitialization();
			SetIsLoadingOnMainThread(isLoading: false);
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown().ConfigureAwait(continueOnCapturedContext: false);
			if (!IsLiveEnabled.Value)
			{
				NavigateToDashboardViewModel();
			}
			SetIsLoadingOnMainThread(isLoading: true);
			PreloadWebView(ifitApi);
			workoutSelected = false;
			isNavigatingToPreWorkout = false;
			SetIsLoadingOnMainThread(isLoading: false);
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			if (!startedLiveWorkout && !isHiddenAlready)
			{
				isHiddenAlready = true;
				Task.Run(async delegate
				{
					await wolfAnalytics.NavigatedAwayFromLive();
				});
			}
		}

		public override void Dispose()
		{
			startedWorkoutSub?.Dispose();
			startedWorkoutSub = null;
			base.WebviewHolderFactory.WebviewHolderStore.Flush(Url);
			base.Dispose();
			UnregisterChangeHandlers();
		}

		public override void UpdateFeatureFlags()
		{
			base.UpdateFeatureFlags();
			ViewModelHasHeaderShadow.Value = base.GetIsNativeModalitySelectorVisible;
		}

		private void SetIsLoadingOnMainThread(bool isLoading)
		{
			mainThreadDispatcher.RequestMainThreadAction(delegate
			{
				IsLoading.Value = isLoading;
			});
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.ExposeTask("ScheduleSelected", ScheduleSelected);
			bridge.Expose("NavigateToLibrary", OnLibraryButtonClicked);
		}

		private async Task ScheduleSelected(IDictionary<string, string> scheduleInfo)
		{
			if (!workoutSelected)
			{
				workoutSelected = true;
				isNavigatingToPreWorkout = true;
				scheduleInfo.TryGetValue("scheduleId", out var scheduleId);
				Log.Trace(LogTag, "Live workout selected showing pre workout, schedule id: " + scheduleId);
				LiveWorkouts.WorkoutInfo workoutInfo = await GetLiveWorkoutInfo(scheduleId).ConfigureAwait(continueOnCapturedContext: false);
				if (workoutInfo == null)
				{
					ShowError(Wolf.Core.Resources.AppStrings.live_schedule_load_error, ErrorCode.WebViewLiveWorkoutScheduleIsNullError);
					isNavigatingToPreWorkout = false;
					return;
				}
				ShowViewModel<PreWorkoutViewModel>(new PreWorkoutViewModel.NavObject
				{
					WorkoutId = workoutInfo?.WorkoutId,
					WorkoutSource = WorkoutSource.Live,
					ScheduleId = scheduleId,
					WorkoutContext = workoutInfo.Context,
					DashboardIndex = -1
				});
			}
		}

		private async Task<LiveWorkouts.WorkoutInfo> GetLiveWorkoutInfo(string scheduleId)
		{
			LiveWorkouts.WorkoutInfo liveWorkout = null;
			try
			{
				liveWorkout = await LiveWorkouts.GetWorkout(ifitApi, scheduleId, populateObjects: true).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error getting actual workout Id from live schedule Id: " + scheduleId, exception);
			}
			return liveWorkout;
		}

		private void ShowError(string error, ErrorCode errorCode, bool closeAfterDismiss = false)
		{
			if (isDisposed)
			{
				return;
			}
			ClearFlags();
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, error, (Func<CancellationToken, Task<object>>)null, false, (Action<Task<object>>)delegate
			{
				if (closeAfterDismiss)
				{
					DoClose();
				}
			}, (string)null, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, false, false, "", (TaskCompletionSource<object>)null, errorCode.HumanReadable(), true);
		}

		private void ClearFlags()
		{
			workoutSelected = false;
			SetIsLoadingOnMainThread(isLoading: false);
		}

		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			return new Dictionary<string, string>
			{
				[JavascriptBridge.MethodToSetConfigs] = WebviewMethodOldInitializeWebview,
				["clientId"] = ifitApi?.Environment?.ClientId ?? string.Empty,
				["clientSecret"] = ifitApi?.Environment?.ClientSecret ?? string.Empty,
				["deviceType"] = (deviceInfo.IsTablet ? "tablet" : "phone")
			};
		}

		public void PreloadWebView(IIfitApiService ifitApi)
		{
			if (ifitApi.HasLoggedInUser && Mvx.TryResolve<IWebviewHolderFactory>(out var webViewStore) && Mvx.TryResolve<IFeatureFlagManager>(out var service))
			{
				string webviewUrl = service.GetString(FeatureFlags.LiveScheduleWebViewUrl);
				Task.Run(async delegate
				{
					webViewStore.WebviewHolderStore.PreloadWebView(webviewUrl, WebviewTTL, WebviewHolderType.Default, GetAdditionalConfig);
				});
			}
		}

		public static string GetWebViewUrl(IFeatureFlagManager ffm)
		{
			return ffm.GetString(FeatureFlags.LiveScheduleWebViewUrl);
		}

		public override Task RefreshAfterModalityChange()
		{
			SetIsLoadingOnMainThread(isLoading: true);
			Log.Trace(LogTag, "LiveScheduleVM: RefreshAfterModalityChange requesting webview refresh");
			RequestWebviewRefresh();
			WebviewInitialization();
			return Task.CompletedTask;
		}

		public override bool BeforeBehaviorRun(string name, IDictionary<string, string> parameters)
		{
			if (name != "JoinLiveWorkout")
			{
				return true;
			}
			if (workoutSelected)
			{
				return false;
			}
			workoutSelected = true;
			return true;
		}

		public override void AfterBehaviorRun(string name, IDictionary<string, string> parameters)
		{
			base.AfterBehaviorRun(name, parameters);
			if (name != "JoinLiveWorkout")
			{
				workoutSelected = false;
			}
		}

