			public static NavObject CreateSearch(LibrarySearchParams searchParams)
			{
				List<string> list = new List<string>();
				if (!string.IsNullOrWhiteSpace(searchParams.Category))
				{
					list.Add("categories=" + searchParams.Category);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.TrainerId))
				{
					list.Add("trainerIds=" + searchParams.TrainerId);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.Continent))
				{
					list.Add("continents=" + searchParams.Continent);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.TargetArea))
				{
					list.Add("targetAreas=" + searchParams.TargetArea);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.LocationType))
				{
					list.Add("locationTypes=" + searchParams.LocationType);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.RequiredEquipment))
				{
					list.Add("requiredEquipment=" + searchParams.RequiredEquipment);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.Duration))
				{
					list.Add("timeRanges=" + searchParams.Duration);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.Intensity))
				{
					list.Add("difficultyScores=" + searchParams.Intensity);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.Language))
				{
					list.Add("languages=" + searchParams.Language);
				}
				if (!string.IsNullOrWhiteSpace(searchParams.Completed))
				{
					list.Add("hasCompleted=" + searchParams.Completed);
				}
				string text = string.Join("&", list);
				return new NavObject
				{
					EntryPoint = "/search?" + text
				};
