				this.wolfAnalytics = wolfAnalytics;
				this.webViewDataService = webViewDataService;
				webViewDataService.RegisterProvider(this);
				ToolbarItems.Value = GetToolbarItems("hamburger");
				backClickedSub = _whenBackClicked.SampleFirst(TimeSpan.FromMilliseconds(500.0)).Subscribe(delegate
