		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (webViewIsInitialized)
			{
				string text = entryPoint;
				if (text == null || !text.Contains("favorites"))
				{
					Bridge.Call("RefreshFavorites");
				}
			}
			if (webviewSettings.ReloadLibraryData)
			{
				webviewSettings.ReloadLibraryData = false;
				Log.Trace(LogTag, "OnViewShown - Reloading library");
				WebviewInitialization();
			}
		}

		public override void UpdateFeatureFlags()
		{
			base.UpdateFeatureFlags();
			ViewModelHasHeaderShadow.Value = base.GetIsNativeModalitySelectorVisible;
		}

		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			Dictionary<string, string> setupParams = new Dictionary<string, string>();
			IWolfEnvironment wolfEnvironment = ifitApi.Environment as IWolfEnvironment;
			string libraryClientId = wolfEnvironment?.LibraryClientId;
			string libraryClientSecret = wolfEnvironment?.LibraryClientSecret;
			string token = await ifitApi.GetToken();
			bool b = await preferenceResolver.GetIsMetric();
			setupParams["clientId"] = libraryClientId;
			setupParams["clientSecret"] = libraryClientSecret;
			setupParams["token"] = token;
			setupParams["baseGatewayAPIUrl"] = ifitApi.Environment.BaseGatewayAPIUrl;
			setupParams["verbose"] = WebviewParamValues.WebviewParamValue(b: false);
			setupParams["useMetricUnits"] = b.WebviewParamValue();
			setupParams[JavascriptBridge.MethodToSetConfigs] = WebviewMethodOldInitializeWebview;
			if (entryPoint.IsNotNullOrWhiteSpace())
			{
				setupParams["entryPoint"] = Uri.UnescapeDataString(entryPoint);
			}
			return setupParams;
		}

