			base.InjectCustomBehaviorParameters(parameters);
		}

		public void Init(NavObject nav)
		{
			entryPoint = nav?.EntryPoint;
			justCompletedWorkout = nav?.JustCompletedWorkout ?? false;
			base.InitialModality = nav?.InitialModality;
			base.DeepLink = nav?.DeepLink;
			SetDefaultToolbarMode(nav?.DefaultToolbarMode ?? ToolbarMode.Library);
			OnUrlsUpdated(null);
		}

		public void RefreshView(IDictionary<string, string> args)
		{
			NavObject nav = JsonConvert.DeserializeObject<NavObject>(JsonConvert.SerializeObject(args));
			Refresh(nav);
		}

		public void Refresh(NavObject nav)
		{
			NavigateWebView(nav?.EntryPoint);
		}

		private void NavigateWebView(string fragment = null)
		{
			bool b = fragment?.IsNullOrEmpty() ?? true;
			Dictionary<string, string> parameters = new Dictionary<string, string>
			{
				{ "entryPoint", fragment },
				{
					"clearBackStack",
					b.WebviewParamValue()
				}
			};
			Bridge.Call("Navigate", parameters);
		}

		protected ToolbarItemType GetToolbarItems(string buttonStyle)
		{
			ToolbarItemType toolbarItemType = ((!(buttonStyle == "hamburger")) ? ToolbarItemType.Back : ToolbarItemType.Hamburger);
			toolbarItemType |= ToolbarItemType.Title;
			if (base.IsStrengthMirror)
			{
				toolbarItemType |= ToolbarItemType.Logo;
			}
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.UseAthenaeumWebViewFilter))
			{
				toolbarItemType |= ToolbarItemType.Search;
			}
			return toolbarItemType;
		}

		protected override void SetupHeaderToolbar()
		{
			if (base.viewShownCount != 1)
			{
				return;
			}
			string text = entryPoint;
			string value;
			if (text != null && text.Contains("favorites"))
			{
				value = Wolf.Core.Resources.AppStrings.favorites;
			}
			else
			{
				string text2 = entryPoint;
				if (text2 != null && text2.Contains("trainer"))
				{
					value = Wolf.Core.Resources.AppStrings.trainer;
				}
				else
				{
					string text3 = entryPoint;
					value = ((text3 == null || !text3.Contains("challenges")) ? Wolf.Core.Resources.AppStrings.library : Wolf.Core.Resources.AppStrings.challenges);
				}
			}
			HeaderToolbarText.Value = value;
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				webViewDataService.UnregisterProvider(this);
				backClickedSub?.Dispose();
				backClickedSub = null;
				base.WebviewHolder = null;
				base.Dispose();
				UnregisterChangeHandlers();
			}
		}

		protected override void OnLibraryButtonClicked()
		{
			if (Mode.Value == ToolbarMode.Challenges)
			{
				base.OnLibraryButtonClicked();
			}
			else if (webViewIsInitialized)
			{
				NavigateWebView();
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			Bridge.Expose("WorkoutSelected", OnWorkoutSelected);
			Bridge.Expose("SetToolbarTitle", OnSetToolbarTitle);
			Bridge.Expose("TrackingEvent", OnTrackingEvent);
		}

		protected override void OnTimeToInteractive(IDictionary<string, string> args)
		{
			base.OnTimeToInteractive(args);
			Task.Run(async delegate
			{
				await LogLibraryLoadTime();
			});
		}

		private async Task LogLibraryLoadTime()
		{
			TimedEvent timedEvent = await EventService.Instance.FetchEvent("Library Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null)
			{
				if (!timedEvent.Properties.ContainsKey("destination"))
				{
					timedEvent.Properties["destination"] = "webview";
				}
				await BaseWebViewViewModel.LogEventKey(timedEvent.Key);
			}
		}

		public override void OnWebviewIsReady(object sender, IDictionary<string, string> initializationParameters)
		{
			base.OnWebviewIsReady(sender, initializationParameters);
			if (!webViewIsInitialized)
			{
				FinalizeWebview();
			}
		}

		public void FinalizeWebview()
		{
			webViewIsInitialized = true;
			if (entryPoint.IsNullOrWhitespace())
			{
				Bridge.Call("RefreshFavorites");
			}
		}

		private void OnWorkoutSelected(IDictionary<string, string> args)
		{
			if (!args.TryGetValue("workoutId", out var value))
			{
				ShowLoadError();
				return;
			}
			args.TryGetValue("programId", out var value2);
			ShowViewModel<PreWorkoutViewModel>(new PreWorkoutViewModel.NavObject
			{
				WorkoutId = value,
				ProgramId = value2,
				WorkoutSource = AnalyticsWorkoutSource,
				DashboardIndex = -1,
				ReferralSource = ReferralSourceTag
			});
		}

		private void OnSetToolbarTitle(IDictionary<string, string> obj)
		{
			if (obj.TryGetValue("title", out var value))
			{
				HeaderToolbarText.Value = value;
			}
			if (obj.TryGetValue("buttonStyle", out var value2))
			{
				ToolbarItems.Value = GetToolbarItems(value2);
			}
			if (obj.TryGetValue("searchIsVisible", out var value3))
			{
				bool.TryParse(value3, out var result);
				ToolbarShowSearchIcon(result);
			}
			if (obj.TryGetValue("registerButtonIsVisible", out var value4))
			{
				bool.TryParse(value4, out var result2);
				obj.TryGetValue("registerButtonText", out var value5);
				ToolbarShowRightTextButton(result2, value5);
			}
			if (obj.TryGetValue("showHeaderShadow", out var value6) && bool.TryParse(value6, out var result3))
			{
				ShowHeaderShadow.Value = result3;
			}
			if (obj.TryGetValue("showFooterShadow", out var value7) && bool.TryParse(value7, out var result4))
			{
				ShowFooterShadow.Value = result4;
			}
		}

		private void OnTrackingEvent(IDictionary<string, string> args)
		{
			wolfAnalytics.WebviewEvent(args);
		}

		private void OnUpgradeRequest()
		{
			webViewBehaviorsService.RunBehavior("upgrade", null, this);
		}

		private void DoBackClicked()
		{
			if (base.WebviewControlsBackNav)
			{
				Bridge.Call("BackClicked");
			}
			else
			{
				DoClose();
			}
		}

		private void DoSearchClicked()
		{
			Bridge.Call("SearchClicked");
		}

		private new void OnHamburgerButtonClicked()
		{
			if (ToolbarItems.Value.HasFlag(ToolbarItemType.Hamburger))
			{
				base.HamburgerButtonClicked.SafeExecute();
			}
			else
			{
				_whenBackClicked.OnNext(null);
			}
		}

		private void ToolbarShowSearchIcon(bool searchIsVisible)
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.UseAthenaeumWebViewFilter))
			{
				ToolbarItemType value = ToolbarItems.Value;
				value = ((!searchIsVisible) ? (value & ~ToolbarItemType.Search) : (value | ToolbarItemType.Search));
				ToolbarItems.Value = value;
			}
		}

		private void ToolbarShowRightTextButton(bool buttonIsVisible, string buttonText)
		{
			ToolbarItemType value = ToolbarItems.Value;
			if (base.IsBuiltIn && buttonIsVisible && buttonText.IsNotNullOrWhiteSpace())
			{
				value |= ToolbarItemType.RightText;
				RightButtonText.Value = buttonText;
			}
			else
			{
				value &= ~ToolbarItemType.RightText;
			}
			ToolbarItems.Value = value;
		}

		protected void ShowLoadError()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.library_load_error);
		}

		protected override async Task HandleNeedsRefresh(IRefreshPayload payload)
		{
			await base.HandleNeedsRefresh(payload);
			RefreshCause cause = payload.Cause;
			if (cause == RefreshCause.Favorites)
			{
				Bridge.Call("RefreshFavorites");
			}
		}

		public static string GetWebViewUrl(IFeatureFlagManager ffm, string entryPoint)
		{
			string text = MainToolbarViewModel.GetWallEUrlWhenNeed(ffm, FeatureFlags.WallELibraryUrl, FeatureFlags.WolfAthenaeumWebViewUrl);
			if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service))
			{
				text = service.GenerateWebViewUrlWithParameters(text);
			}
			if (entryPoint.IsNotNullOrWhiteSpace())
			{
				text = $"{TrimFragmentSeparator(text)}{'#'}{'/'}{TrimStartingPath(entryPoint)}";
			}
			if (!Uri.IsWellFormedUriString(text, UriKind.Absolute))
			{
				return string.Empty;
			}
			return text;
		}

		private static string TrimFragmentSeparator(string baseUrl)
		{
			string text = baseUrl;
			if (text != null)
			{
				int num = text.IndexOf('#');
				if (num >= 0)
				{
					text = text.Substring(0, num);
				}
			}
			return text?.TrimEnd('/');
		}

		private static string TrimStartingPath(string fragment)
		{
			return fragment?.TrimStart('/');
		}

		public override async Task RefreshAfterModalityChange()
		{
