namespace Wolf.Core.ViewModels.LaunchScreen
{
	public class LaunchScreenViewModel : BaseViewModel
	{
		private const string Tag = "LaunchScreen";

		private const int LDFlagSyncTimeoutSeconds = 15;

		private const int LDFlagSyncCheckMs = 500;

		private ErrorCode currentLDStatus = ErrorCode.None;

		private const int LinkServiceTimeoutSeconds = 10;

		private bool startedNavigation;

		private bool shouldAutoClose = true;

		private string externalUriString;

		private new readonly IConnectivity connectivity;

		private readonly IIfitApiService ifitApi;

		private new readonly IBleConsoleService bleConsoleService;

		private readonly IUserAvatarImage userAvatar;

		private readonly ISecondaryUsersService secondaryUsersService;

		private readonly IFitnessConsoleRegisterService fitnessConsoleRegisterService;

		private readonly IDeviceInformation deviceInformation;

		private bool shouldBleShowWall;

		private bool forceLoggedInUserToDashboard;

		public readonly BooleanCycle InitializationComplete = new BooleanCycle();

		private bool softPaywallEnabled => featureFlagManager.IsFeatureEnabled(FeatureFlags.SoftPaywallEnabled);

		private bool IsBuiltIn => deviceInfo?.IsBuiltIn ?? false;

		public LaunchScreenViewModel(ILocalSettings localSettings, IConnectivity connectivity, IIfitApiService ifitApi, IUserAvatarImage userAvatar, IFitnessConsoleRegisterService fitnessConsoleRegisterService, ISecondaryUsersService secondaryUsersService, IDeviceInformation deviceInformation)
			: base(localSettings)
		{
			try
			{
				this.connectivity = connectivity;
				this.ifitApi = ifitApi;
				this.userAvatar = userAvatar;
				this.secondaryUsersService = secondaryUsersService;
				this.fitnessConsoleRegisterService = fitnessConsoleRegisterService;
				this.deviceInformation = deviceInformation;
				Mvx.TryResolve<IBleConsoleService>(out bleConsoleService);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(LoginViewModelOverride.NavObject nav)
		{
			shouldBleShowWall = nav.ShouldBleShowWall;
			forceLoggedInUserToDashboard = nav.ForceLoggedInUserToDashboard;
			if (shouldBleShowWall)
			{
				Log.Trace("LaunchScreen", "LaunchScreenViewModel: Custom destination = wall");
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (localSettings.WipeWorkouts)
			{
				Log.Trace("LaunchScreen", "Wiping workouts");
				await ifitApi.Cache.InvalidateAllObjects<Workout>().ToTask().ConfigureAwait(continueOnCapturedContext: false);
				localSettings.WipeWorkouts = false;
			}
			IAppLinking linkService = null;
			try
			{
				if (!InitializationComplete.Value)
				{
					linkService = Mvx.Resolve<IAppLinking>();
					linkService?.Init("ifitcardio", (string arg) => true);
				}
			}
			catch (Exception exception)
			{
				Log.Error("LaunchScreen", "Exception getting IAppLinking implementation.", exception);
			}
			if (Mvx.TryResolve<IDemoModeService>(out var service) && service.IsInDemoMode)
			{
				InitializationComplete.SetTrue();
				return;
			}
			await WaitForLDSyncIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
			if (linkService != null && !deviceInformation.IsBuiltIn)
			{
				Log.Trace("LaunchScreen", "Awaiting app link service initialization");
				Task<string> task = linkService.WaitForInitializationComplete();
				try
				{
					await Task.WhenAll<string>(task).TimeoutAfter(TimeSpan.FromSeconds(10.0));
				}
				catch (OperationCanceledException)
				{
					Log.Error("LaunchScreen", "Unable to wait for application link service initialization due to cancellation.");
				}
				catch (TimeoutException)
				{
					Log.Error("LaunchScreen", "Timeout occurred while waiting for link service initialization.");
				}
			}
			InitializationComplete.SetTrue();
		}

		public override void OnAfterViewShown()
		{
			if (Mvx.TryResolve<IApplicationRestarter>(out var service))
			{
				service.RestartAppIfWaiting();
			}
			base.OnAfterViewShown();
		}

		private async Task WaitForLDSyncIfNecessary()
		{
			Log.Trace("FeatureFlags", "Waiting for LDSync on LaunchScreenViewModel.");
			if (!connectivity.IsConnected)
			{
				Log.Error("FeatureFlags", "User's device was not connected to Internet during LaunchScreenViewModel.");
				currentLDStatus = ErrorCode.WifiNoInternet;
				return;
			}
			LaunchDarklySyncState launchDarklySyncState = await featureFlagManager.UserSynced.FirstAsync((LaunchDarklySyncState result) => result.Status != LaunchDarklySyncStatus.InProgress);
			switch (launchDarklySyncState.Status)
			{
			case LaunchDarklySyncStatus.Synced:
				Log.Error("FeatureFlags", "Successfully waited for LD flags to sync.");
				currentLDStatus = ErrorCode.None;
				break;
			case LaunchDarklySyncStatus.Broken:
				if (launchDarklySyncState.Error is TimeoutException)
				{
					Log.Error("FeatureFlags", "Timed out waiting for LD flags to sync.", launchDarklySyncState.Error);
					currentLDStatus = ErrorCode.LaunchDarklyFailureTimeout;
				}
				else
				{
					Log.Error("FeatureFlags", "Error occurred waiting for LD flags to sync.", launchDarklySyncState.Error);
					currentLDStatus = ErrorCode.LaunchDarklyFailureOther;
				}
				break;
			}
		}

		public async Task NavigateToNextScreen(string externalUriString = null)
		{
			if (startedNavigation)
			{
				return;
			}
			this.externalUriString = externalUriString;
			startedNavigation = true;
			if (Mvx.TryResolve<IDemoModeService>(out var service) && service.IsInDemoMode)
			{
				service.ResumeDemoMode();
				return;
			}
			await DetermineNextNavigation();
			if (shouldAutoClose)
			{
				DoClose();
			}
			appLinking.MarkApplicationReadyForLink();
		}

		private async Task DetermineNextNavigation()
		{
			if (Mvx.TryResolve<ILockScreenHandler>(out var service) && service.CanShowLockScreen && service.NavigateFrom != typeof(AccountSelectionViewModel))
			{
				shouldAutoClose = false;
				service.NavigateToLockScreen(typeof(LaunchScreenViewModel));
				return;
			}
			Log.Trace("LaunchScreen", $"Has logged in user: {ifitApi.HasLoggedInUser}");
			bool flag = await wifiService.PingSucceeds();
			if (currentLDStatus != ErrorCode.None || !flag)
			{
				Log.Error("LaunchScreen", $"Navigating to NoWifi Dashboard because LD status is {currentLDStatus}");
				NoWifiScreenNavObject parameterValuesObject = new NoWifiScreenNavObject
				{
					ErrorCode = currentLDStatus
				};
				ShowViewModel<EmbeddedNoWifiDashboardViewModel>(parameterValuesObject);
				return;
			}
			if ((ifitApi.HasLoggedInUser && !currentConsoleService.IsBuiltinClub) || ((currentConsoleService.Console?.Initialized ?? false) && currentConsoleService.Console.LatestBasicInfo.IsInRecoverableWorkout()))
			{
				await HandleLoggedInUser();
				if (ShouldHandleDeepLink())
				{
					await HandleDeepLink();
				}
				return;
			}
			if (ifitApi.HasLoggedInUser)
			{
				await DoLogOut(skipNavigation: false, showLaunchScreen: false);
			}
			LoginViewModelOverride.NavObject parameterValuesObject2 = new LoginViewModelOverride.NavObject
			{
				ShouldBleShowWall = shouldBleShowWall
			};
			ShowLoginViewModel(parameterValuesObject2);
		}

		private async Task<bool> IsLoggingOutDueToFailedUserUpdate()
		{
			if (ifitApi.Token == null || ifitApi.Token.IsExpired)
			{
				Log.Trace("Api", "Failed to update user and our token is expired, so we're logging the user out");
				await ifitApi.Logout(logoutAllUsers: true);
				ShowLoginViewModel();
				return true;
			}
			Log.Trace("Api", "Failed to update user, but our token isn't expired");
			return false;
		}

		private bool ShouldHandleDeepLink()
		{
			Uri result;
			return Uri.TryCreate(externalUriString, UriKind.Absolute, out result);
		}

		private Task HandleDeepLink()
		{
			if (Mvx.TryResolve<IAppLinking>(out var service))
			{
				service.HandleExternalLinkRequest(externalUriString);
			}
			return Task.FromResult(0);
		}

		protected async Task HandleLoggedInUser()
		{
			User currentUser = ifitApi.CurrentlyAuthenticatedUser;
			Task.Run(() => userAvatar.GenerateUserAvatarForUser(ifitApi.CurrentlyAuthenticatedUser));
			try
			{
				currentUser = await GetCurrentUser();
				if (personalTrainingSettings != null)
				{
					await personalTrainingSettings.RefreshUserSettings();
				}
			}
			catch (iFit.Api.Support.ConnectivityException arg)
			{
				Log.Trace("LaunchScreen", $"Exception getting user details {arg}");
				if (await IsLoggingOutDueToFailedUserUpdate())
				{
					return;
				}
				Log.Trace("LaunchScreen", "Using cached user");
			}
			catch (ApiException arg2)
			{
				Log.Trace("LaunchScreen", $"Exception getting user details {arg2}");
				await ifitApi.Logout(logoutAllUsers: true);
				ShowLoginViewModel();
				return;
			}
			bool isBuiltInOrStrengthMirror = IsBuiltIn || base.IsStrengthMirror;
			if (deviceInfo.IsBuiltIn && !currentConsoleService.IsBuiltinClub)
			{
				ILocalSettings localSettings = base.localSettings;
				localSettings.IsAllAuthenticatedUsersLinked = await secondaryUsersService.IsAllAuthenticatedUsersLinked();
			}
			User user = currentUser;
			if (((user == null) ? ((bool?)null) : (!user.Premium)) ?? true)
			{
				if (isBuiltInOrStrengthMirror || softPaywallEnabled)
				{
					ShowFirstViewModel();
				}
				else
				{
					ShowMarketingViewModel("LaunchScreen", ifitApi.CurrentlyAuthenticatedUser?.Email);
				}
			}
			else if (!isBuiltInOrStrengthMirror && (!currentUser.BirthdayIsValid || !trackingService.HasCompletedOnboarding(currentUser.Id)))
			{
				ShowPersonalizationViewModel();
			}
			else if (!base.localSettings.DashboardShownOnce)
			{
				shouldAutoClose = false;
				PresentNextViewToLoggedInUser(externalUriString);
			}
			else
			{
				ShowFirstViewModel();
			}
		}

		private void PresentNextViewToLoggedInUser(string deepLinkUriString = null)
		{
			if (externalUriString != null && deepLinkUriString != null)
			{
				if (!Mvx.TryResolve<IAppLinking>(out var service) || !service.OpenLinkUrl(deepLinkUriString))
				{
					Log.Trace("LaunchScreen", "Unable to resolve IAppLinking service when loading deep link URL: " + deepLinkUriString + ". Loading Dashboard instead.");
					ShowFirstViewModel();
				}
			}
			else
			{
				ShowFirstViewModel();
			}
		}

		private void ShowFirstViewModel()
		{
			Task.Run(async delegate
			{
				await EventService.Instance.LogAsync("Launch Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			});
			if (AttemptNavigateToPendingDeepLink())
			{
				externalUriString = null;
				return;
			}
			Dictionary<string, object> properties = new Dictionary<string, object> { 
			{
				"isBoltEnabled",
				featureFlagManager.IsFeatureEnabled(FeatureFlags.BoltEnabled) && featureFlagManager.IsFeatureEnabled(FeatureFlags.BoltEnabledDashboard)
			} };
			Task.Run(async () => await EventService.Instance.CreateAsync("Dashboard WebView Screen Time", properties).ConfigureAwait(continueOnCapturedContext: false));
			if (!forceLoggedInUserToDashboard)
			{
				IFitnessConsole console = currentConsoleService.Console;
				if (console == null || !console.Initialized || !currentConsoleService.Console.LatestBasicInfo.IsInRecoverableWorkout())
				{
					if (localSettings.IsAllAuthenticatedUsersLinked && ShouldShowAccountSelection())
					{
						NavigateToAccountSelectionViewModel();
					}
					else
					{
						NavigateToDashboardViewModel();
					}
					return;
				}
			}
			NavigateToDashboardViewModel();
		}

		protected async Task<User> GetCurrentUser()
		{
			User currentUser = ifitApi.CurrentlyAuthenticatedUser;
			if (currentUser?.Premium == true)
			{
				DateTime utcNow = DateTime.UtcNow;
				DateTime? expiration = currentUser.Expiration;
				if (utcNow < expiration)
				{
					Task.Run(async delegate
					{
						await RefreshUser();
					}).ConfigureAwait(continueOnCapturedContext: false);
					return currentUser;
				}
			}
			if (connectivity.IsConnected)
			{
				currentUser = await ifitApi.RefreshCurrentlyAuthenticatedUser();
			}
			bool isPremium = currentUser?.Premium == true;
			if (!isPremium)
			{
				try
				{
					isPremium = await RenewalStatus.CheckStatus(ifitApi);
				}
				catch (ApiException)
				{
				}
				catch (OperationCanceledException ex2)
				{
					throw new iFit.Api.Support.ConnectivityException(ex2.Message, ex2);
				}
				if (isPremium)
				{
					currentUser = await ifitApi.RefreshCurrentlyAuthenticatedUser();
				}
			}
			return currentUser;
		}

		private async Task RefreshUser()
		{
			try
			{
				await ifitApi.RefreshCurrentlyAuthenticatedUser();
			}
			catch (Exception arg)
			{
				Log.Trace("LaunchScreen", $"Exception refreshing user {arg}");
			}
		}

