	public class ActivePulseSideRailDialogViewModel : MaxWorkoutTimeWarningViewModel
	{
		private const string timeFormat = "m\\:ss";

		private readonly IHRTrainingService hrTrainingService;

		private const int countdownSeconds = 30;

		private IDisposable whenTimeChangedSub;

		private TimeSpan timeLeftUntilPause = TimeSpan.FromSeconds(30.0);

		public INC<string> TimerString = new NC<string>();

		public ICommand ContinueWithSmartAdjust => new MvxCommand(DoContinueWithSmartAdjust);

		public ICommand ContinueWithActivePulse => new MvxCommand(DoContinueWithActivePulse);

		public override string Title => Wolf.Core.Resources.AppStrings.pause_workout_question;

		public override string Subtitle => Wolf.Core.Resources.AppStrings.activepulse_side_rail_explanation;

		public string TurnOffActivePulseText => Wolf.Core.Resources.AppStrings.activepulse_turn_off.ToUpper();

		public string ContinueWithActivePulseButtonText => Wolf.Core.Resources.AppStrings.activepulse_continue.ToUpper();

		public ActivePulseSideRailDialogViewModel(ILocalSettings localSettings, IHRTrainingService hrTrainingService, ICurrentConsoleService currentConsoleService)
			: base(localSettings, currentConsoleService)
		{
			try
			{
				this.hrTrainingService = hrTrainingService;
				whenTimeChangedSub = facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().SubscribeWithErrorLogging(OnTimeTimeChanged);
				TimerString.Value = TimeSpan.FromSeconds(30.0).ToString("m\\:ss");
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void OnTimeTimeChanged(FitnessValueChange<int> metricChange)
		{
			timeLeftUntilPause = timeLeftUntilPause.Subtract(TimeSpan.FromSeconds(1.0));
			TimerString.Value = timeLeftUntilPause.ToString("m\\:ss");
			if (timeLeftUntilPause.Equals(TimeSpan.Zero))
			{
				DoContinueWithSmartAdjust();
			}
		}

		private void DoContinueWithActivePulse()
		{
			hrTrainingService.SiderailContinue();
			CleanUp();
			Close(this);
		}

		private void DoContinueWithSmartAdjust()
		{
			CleanUp();
			Close(this);
		}

		public override void Dispose()
		{
			base.Dispose();
			CleanUp();
			UnregisterChangeHandlers();
		}

		private void CleanUp()
		{
			whenTimeChangedSub?.Dispose();
			whenTimeChangedSub = null;
		}

