		public IObservable<WidgetType> HRWidgetTypeChanged => _hrWidgetModeChanged;

		public MvxCommand InfoClicked => new MvxCommand(DoOpenInfo);

		public MvxCommand PagerContainerClicked => new MvxCommand(DoAdvancePage);

		public HRZoneWidgetContainerViewModel(ILocalSettings localSettings, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService, IDeveloperSettings developerSettings, IHRZoneUpdatingAnalyticsService hrZoneUpdatingAnalyticsService)
			: base(localSettings, hrTrainingService, workoutFeatureService, hrZoneUpdatingAnalyticsService)
		{
			try
			{
				if (developerSettings.ShowHRDebugInfo)
				{
					Pages.Add(typeof(HRZoneDebugViewModel));
					ActivePulseOffPages.Add(typeof(HRZoneDebugViewModel));
				}
				pagesCurrentPageSub = Pages.CurrentPage.ToObservable().Subscribe(UpdateVisibility);
				apOffPagesCurrentPageSub = ActivePulseOffPages.CurrentPage.ToObservable().Subscribe(UpdateVisibility);
				activePulseEnabled = personalTrainingSettings.ActivePulseEnabled;
				activePulseEnabledChangedSub = personalTrainingSettings.WhenActivePulseEnabledChanged.Subscribe(ActivePulseEnabledChanged);
				activePulseOn = workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse);
				scalingModeChangedSub = workoutFeatureService.WhenScalingModeChanged.Subscribe(ScalingModeChanged);
				UpdateVisibility(0);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override void OnCountdownUpdated(TimeSpan remainingTime)
		{
			if (IsCountingDown.Value)
			{
				if (activePulseOn)
				{
					PulseStatusMessage.Value = string.Format(Wolf.Core.Resources.AppStrings.hr_widget_workout_starts_in, remainingTime.ToString("m\\:ss"));
				}
				else
				{
					UpdateStatusMessageAndIcon(null);
				}
			}
			UpdateVisibility(0);
		}

		private void ScalingModeChanged(ScalingMode scalingMode)
		{
			activePulseOn = workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse);
			if (!activePulseOn)
			{
				UpdateStatusMessageAndIcon(null);
			}
			UpdateVisibility(0);
		}

		private void ActivePulseEnabledChanged(bool apEnabled)
		{
			if (activePulseEnabled != apEnabled)
			{
				activePulseEnabled = apEnabled;
				Pages.CurrentPage.Value = 0;
				ActivePulseOffPages.CurrentPage.Value = 0;
			}
			UpdateVisibility(0);
		}

		private void UpdateVisibility(int ignored)
		{
			if (!activePulseEnabled || !activePulseOn)
			{
				ShowActivePulseOffPages.Value = true;
				ShowPages.Value = false;
				SelectedPage.Value = ActivePulseOffPages.CurrentPage.Value;
				PageCount.Value = ActivePulseOffPages.Count;
				ShowFlipper.Value = true;
				StatusMessageVisible.Value = SelectedPage.Value != 0;
				ShowWarmupScreen.Value = false;
			}
			else if (!IsCountingDown.Value)
			{
				ShowPages.Value = true;
				ShowActivePulseOffPages.Value = false;
				SelectedPage.Value = Pages.CurrentPage.Value;
				PageCount.Value = Pages.Count;
				ShowFlipper.Value = true;
				StatusMessageVisible.Value = SelectedPage.Value != 0;
				ShowWarmupScreen.Value = false;
			}
			else
			{
				ShowPages.Value = false;
				ShowActivePulseOffPages.Value = false;
				ShowFlipper.Value = false;
				StatusMessageVisible.Value = true;
				ShowWarmupScreen.Value = true;
			}
		}

		private void DoOpenInfo()
		{
			_hrWidgetModeChanged.OnNext(WidgetType.HRMyZones);
		}

		private void DoAdvancePage()
		{
			if (ShowPages.Value)
			{
				Pages.GoToNextPage();
			}
			else if (ShowActivePulseOffPages.Value)
			{
				ActivePulseOffPages.GoToNextPage();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			pagesCurrentPageSub?.Dispose();
			pagesCurrentPageSub = null;
			apOffPagesCurrentPageSub?.Dispose();
			apOffPagesCurrentPageSub = null;
			activePulseEnabledChangedSub?.Dispose();
			activePulseEnabledChangedSub = null;
			scalingModeChangedSub?.Dispose();
			scalingModeChangedSub = null;
			UnregisterChangeHandlers();
		}

		protected override Task OnHRDataUpdated(HRZoneUpdate zoneUpdate)
		{
			return Task.FromResult(result: true);
		}

