		};

		private IWorkoutContainer workoutContainer;

		public readonly INCList<InWorkoutHeaderHudType> HeaderPages = new NCList<InWorkoutHeaderHudType>();

		[DependsOn(new string[] { "HeaderPages" })]
		public bool ShouldShowChartsPagerButton
		{
			get
			{
				INCList<InWorkoutHeaderHudType> headerPages = HeaderPages;
				if (headerPages == null)
				{
					return false;
				}
				return headerPages.Value?.Contains(InWorkoutHeaderHudType.Charts) == true;
			}
		}

		public bool IsInStrengthWorkout
		{
			get
			{
				IWorkoutContainer obj = workoutSettings.WorkoutContainer;
				if (obj == null)
				{
					return false;
				}
				return obj.Workout?.IsStrengthWorkout() == true;
			}
		}

		public InWorkoutHeaderViewModel(ILocalSettings localSettings)
			: base(localSettings)
		{
			try
			{
				List<InWorkoutHeaderHudType> list = new List<InWorkoutHeaderHudType> { InWorkoutHeaderHudType.Stats };
				if (!IsInStrengthWorkout)
				{
					list.Add(InWorkoutHeaderHudType.Charts);
				}
				HeaderPages.Value = list;
				workoutContainer = workoutSettings?.WorkoutContainer;
				IWorkoutContainer obj = workoutContainer;
				if (obj != null && obj.IsRecoveryWorkout)
				{
					IFitnessConsole console = workoutContainer.Console;
					if (console != null)
					{
						_ = console.LatestBasicInfo?.CurrentState == ConsoleState.CoolDown;
					}
					else
						_ = 0;
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			workoutContainer = null;
			UnregisterChangeHandlers();
		}

