		private bool ClosedCaptionsFeatureEnabled
		{
			get
			{
				IFeatureFlagManager obj = featureFlagManager;
				if (obj != null && obj.IsFeatureEnabled(FeatureFlags.ClosedCaptioningEnabled))
				{
					if (base.IsStrengthMirror)
					{
						return featureFlagManager.IsFeatureEnabled(FeatureFlags.ClosedCaptioningMirrorEnabled);
					}
					return true;
				}
				return false;
			}
		}

		public bool LeaderboardFlagEnabled
		{
