		public VolumeType WorkoutPauseVolumeType
		{
			get
			{
				IDeviceInformation deviceInformation = deviceInfo;
				if (deviceInformation == null || !deviceInformation.IsBuiltIn)
				{
					return VolumeType.Master;
				}
				return VolumeType.System;
			}
		}

		public bool UseVideoBackgroundService
		{
			get
			{
				if (!deviceInfo.IsBuiltIn && !deviceInfo.IsStrengthMirror && IsVideoWorkout)
				{
					return WorkoutMode.Value != ConsoleState.CoolDown;
				}
				return false;
			}
		}

		public float LastSystemVolume
		{
			get
			{
				if (base.IsStrengthMirror && !IsBuiltinWithHeadphonesConnected)
				{
					return mediaSettings.StrengthMirrorSystemVolume;
				}
				float result = (float)((deviceInfo.IsBuiltIn ? currentConsoleService.PhysicalConsole : currentConsoleService.ActiveConsole)?.LatestBasicInfo?.Volume ?? 0) / 100f;
				if (!IsBuiltinWithHeadphonesConnected)
				{
					return result;
				}
				return Math.Max(LastTrainerVolume, LastMusicVolume);
			}
		}

		private bool IsBuiltinWithHeadphonesConnected
		{
			get
			{
				if (deviceInfo.IsBuiltIn)
				{
					return headphoneConnectionHelper.IsConnected();
				}
				return false;
			}
		}

