		[DependsOn(new string[] { "IsRunningState", "IsClosedCaptionsOn" })]
		public bool IsClosedCaptionsVisible
		{
			get
			{
				if (IsRunningState && IsClosedCaptionsOn.Value && !IsManualWorkout && !IsMapWorkout && ClosedCaptionsFeatureEnabled && ClosedCaptionsPreferredLanguageAvailable.Value)
				{
					return !IsLiveWorkout;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsClosedCaptionsVisible" })]
		public bool IsClosedCaptionsToggled
		{
			get
			{
				return IsClosedCaptionsVisible;
			}
			set
			{
				if (IsClosedCaptionsVisible != value)
				{
					closedCaptionsSettings.ToggleClosedCaptions().SafeFireAndForget(continueOnCapturedContext: false, delegate(Exception ex)
					{
						Log.Trace(LogTag, ex.Message);
					});
				}
			}
		}

