		public bool ActivePulseEnabled
		{
			get
			{
				return _activePulseEnabled;
			}
			set
			{
				if (_activePulseEnabled != value)
				{
					_activePulseEnabled = value;
					RaisePropertyChanged("ActivePulseEnabled");
					workoutFeatureService.TurnMode(ScalingMode.ActivePulse, _activePulseEnabled);
					analytics.InWorkoutWidgetInteraction(workoutSettings?.WorkoutContainer?.Workout, "Tap", _activePulseEnabled, "Active Pulse");
				}
			}
		}

		public bool TrainingModeEnabled
		{
			get
			{
				return _trainingModeEnabled;
			}
			set
			{
				if (_trainingModeEnabled != value)
				{
					_trainingModeEnabled = value;
					RaisePropertyChanged("TrainingModeEnabled");
					workoutFeatureService.TurnMode(ScalingMode.SmartAdjust, _trainingModeEnabled);
					analytics.InWorkoutWidgetInteraction(workoutSettings?.WorkoutContainer?.Workout, "Tap", _trainingModeEnabled, "Smart Adjust");
				}
			}
		}

