		public bool FabButtonVisible
		{
			get
			{
				if (IsRunningState && !IsStrengthWorkout && !IsInFullscreenMode.Value && !InRetailDemo)
				{
					return !deviceInfo.UseHeadlessBikeTheme;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "WorkoutMode", "IsRunningState" })]
		public bool HeaderPageSwipeEnabled
		{
			get
			{
				if ((IsRunningState || WorkoutMode.Value == ConsoleState.WarmUp || WorkoutMode.Value == ConsoleState.CoolDown) && !IsStrengthWorkout)
				{
					IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
					if (workoutContainer == null)
					{
						return true;
					}
					return !workoutContainer.IsInEquipmentlessWorkout;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsRunningState" })]
		public bool HudDropDownEnabled
		{
			get
			{
				if (HeaderPageSwipeEnabled && WorkoutMode.Value != ConsoleState.WarmUp && WorkoutMode.Value != ConsoleState.CoolDown && IsRunningState && !IsStrengthWorkout)
				{
					return !InRetailDemo;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsRunningState", "WorkoutEntered", "CooldownEntered" })]
		public bool GoToCooldownButtonVisible
		{
			get
			{
				if (InRetailDemo || !IsRunningState)
				{
					if (IsLiveWorkout && WorkoutEntered.Value)
					{
						return !CooldownEntered.Value;
					}
					return false;
				}
				return true;
			}
		}

		[DependsOn(new string[] { "IsRunningState", "WorkoutEntered", "CooldownEntered", "IsManualWorkout", "IsMapWorkout", "IsLiveWorkout" })]
		public bool ClosedCaptionsButtonVisible
		{
			get
			{
				if ((IsRunningState || (IsLiveWorkout && WorkoutEntered.Value && !CooldownEntered.Value)) && !IsManualWorkout && !IsMapWorkout && ClosedCaptionsFeatureEnabled)
				{
					return !IsLiveWorkout;
				}
				return false;
			}
		}

