		public bool ShouldAutomaticallyShowHeartRateWidget
		{
			get
			{
				if (HRWidgetEnabled)
				{
					IWorkoutSettings obj = workoutSettings;
					if (obj != null && obj.PreferredLeftWorkoutWidget == WidgetType.HRTarget)
					{
						IWorkoutSettings obj2 = workoutSettings;
						if (obj2 == null)
						{
							return false;
						}
						return !obj2.HideHrWidgetUntilHrm;
					}
				}
				return false;
			}
		}

