		private async void OnClosedCaptionSettingsFetchException(Exception ex)
		{
			if (ex.GetType() == typeof(iFit.Api.Support.ConnectivityException))
			{
				Log.Error("Workout", "An error occurred starting the workout", ex);
				workoutPathoutService.FinishAsync("failedToStart");
				ErrorStartingWorkout.Value = true;
				await NavigateAway(showError: true);
			}
		}

		private async Task InitClosedCaptionSettings(IClosedCaptionsSettings closedCaptionsSettings)
		{
			if (deviceInfo.IsBuiltIn)
			{
				IWorkoutSettings obj = workoutSettings;
				if (obj != null && obj.WorkoutContainer?.Workout.HasFilter(Workout.WorkoutFilter.IsManual) == true)
				{
					return;
				}
			}
			INC<string> closedCaptionsPreferredLanguageName = ClosedCaptionsPreferredLanguageName;
			closedCaptionsPreferredLanguageName.Value = (await closedCaptionsSettings.GetPreferredLanguage()).Name;
			INC<bool> isClosedCaptionsOn = IsClosedCaptionsOn;
			isClosedCaptionsOn.Value = await closedCaptionsSettings.GetIsClosedCaptionsOn();
		}

