		private void SetPulseText()
		{
			IConsoleInfo consoleInfo = currentConsoleService?.ActiveConsole?.ConsoleInfo;
			string arg = "";
			string newValue = "";
			if (consoleInfo != null)
			{
				if (consoleInfo.CanSetKph && consoleInfo.CanSetIncline)
				{
					newValue = Wolf.Core.Resources.AppStrings.inworkout_settings_speed_or_incline;
					arg = Wolf.Core.Resources.AppStrings.inworkout_settings_speed_and_incline;
				}
				else if (consoleInfo.CanSetKph)
				{
					newValue = (arg = Wolf.Core.Resources.AppStrings.inworkout_settings_speed);
				}
				else if (consoleInfo.CanSetResistance || consoleInfo.CanSetGear)
				{
					newValue = (arg = Wolf.Core.Resources.AppStrings.inworkout_settings_resistance);
				}
				SmartAdjustToggleText.Value = Wolf.Core.Resources.AppStrings.training_mode_subtitle.Replace("{0}", newValue);
				ActivePulseToggleText.Value = string.Format(Wolf.Core.Resources.AppStrings.activepulse_subtitle, arg);
			}
		}

