		private void SetupCaptionMonitoring()
		{
			if (IsLiveWorkout)
			{
				videoCaptionStatusSub = captionMonitoringService.WhenVideoCaptionStatusChanged.SubscribeAsync(HandleVideoCaptionStatusChange, async delegate(Exception ex)
				{
					Log.Error("Workout", "Live: caption error", ex);
					if (ex is LiveWorkoutTranslatorService.LiveWorkoutTranslatorServiceCoolDownStateException)
					{
						await GracefullyEndLiveWorkout().ConfigureAwait(continueOnCapturedContext: false);
						ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.live_workout_already_ended_title, Wolf.Core.Resources.AppStrings.live_workout_already_ended_message, (Func<CancellationToken, Task<object>>)null, (string)null, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false, true);
					}
				});
				captionMonitoringService.NoLongerFollowingWorkout = NoLongerFollowingWorkout;
				captionMonitoringService.StartMonitoringCaptions();
			}
			else
			{
				closedCaptionsMonitoringService.StartMonitoringCaptions();
				closedCaptionReceivedSub = closedCaptionsMonitoringService.WeakSubscribe<IClosedCaptionsMonitoringService, string>("ClosedCaptionReceived", OnClosedCaptionReceived);
				closedCaptionsMonitoredLanguageSub = closedCaptionsMonitoringService.WeakSubscribe<IClosedCaptionsMonitoringService, ClosedCaptionLanguage>("LanguageChanged", OnClosedCaptionMonitoredLanguageChanged);
			}
		}

