		[DependsOn(new string[] { "FollowWorkoutButtonVisible" })]
		private void FollowWorkoutButtonVisibilityChanged()
		{
			if (currentFollowWorkoutButtonVisible.HasValue && currentFollowWorkoutButtonVisible != FollowWorkoutButtonVisible && FollowWorkoutButtonVisible)
			{
				if (currentIsRunningState != IsRunningState)
				{
					Log.Trace("Workout", $"Follow workout button appeared because IsRunningState changed from {currentIsRunningState} to {IsRunningState}");
				}
				if (currentNoLongerFollowingWorkout != NoLongerFollowingWorkout.Value)
				{
					Log.Trace("Workout", $"Follow workout button appeared because NoLongerFollowingWorkout changed from {currentNoLongerFollowingWorkout} to {NoLongerFollowingWorkout.Value}");
				}
				if (currentNavContainerOpen != NavContainerOpen.Value)
				{
					Log.Trace("Workout", $"Follow workout button appeared because NavContainerOpen changed from {currentNavContainerOpen} to {NavContainerOpen.Value}");
				}
			}
			currentFollowWorkoutButtonVisible = FollowWorkoutButtonVisible;
			currentIsRunningState = IsRunningState;
			currentNoLongerFollowingWorkout = NoLongerFollowingWorkout.Value;
			currentNavContainerOpen = NavContainerOpen.Value;
		}

		[DependsOn(new string[] { "WorkoutMode", "NoLongerFollowingWorkout" })]
		private void TrackFollowDuration()
		{
			switch (WorkoutMode.Value)
			{
			case ConsoleState.Paused:
			case ConsoleState.PauseOverride:
				inWorkoutMetricsManager?.StartRecordingMetricTime(InWorkoutMetric.WorkoutPaused);
				if (!IsInFullscreenMode.Value)
				{
					inWorkoutFlipperMetricsManager.PauseRecordingAllMetrics(DateTime.UtcNow);
				}
				break;
			case ConsoleState.Workout:
			case ConsoleState.Resume:
				inWorkoutMetricsManager?.StopRecordingMetricTime(InWorkoutMetric.WorkoutPaused, DateTime.UtcNow);
				if (!IsInFullscreenMode.Value)
				{
					inWorkoutFlipperMetricsManager.StartOrResumeRecordingAllMetrics();
				}
				break;
			}
		}

		private bool ShouldEnableLeaderboard()
		{
			if (ifitApi?.CurrentlyAuthenticatedUser?.Premium != true)
			{
				return false;
			}
			Workout workout = workoutSettings?.WorkoutContainer?.Workout;
			if (workout != null && workout.ShouldUseEquipmentlessConsole())
			{
				return false;
			}
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.ActiveConsole.IsNonconnectedConsole())
			{
				return false;
			}
			ICurrentConsoleService obj2 = currentConsoleService;
			if (obj2 != null && obj2.IsBuiltinClub)
			{
				return false;
			}
			if (competitionsService.IsUsingNativeCompetitionService)
			{
				IsUsingNativeCompetitionService.Value = competitionsService.IsUsingNativeCompetitionService;
				return true;
			}
			if (workout != null && !workout.IsManual() && LeaderboardFlagEnabled && LeaderboardDataUploadEnabled && (workout.Target == Workout.TargetType.Meters || workout.Target == Workout.TargetType.Seconds))
			{
				return !InRetailDemo;
			}
			return false;
		}

		private void ScalingModeChanged(ScalingMode mode)
		{
			ActivePulseEnabled = workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse);
			TrainingModeEnabled = workoutFeatureService.IsScalingModeEnabled(ScalingMode.SmartAdjust);
			if (ActivePulseEnabled)
			{
				if (HRBadgeState.Value != Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Found)
				{
					UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.ActivePulseOn);
				}
			}
			else if (HRBadgeState.Value != Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Disconnected)
			{
				UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.None);
			}
		}

