		private void InitializeWidgetsForRunning(bool tryToShowHRWidget = false)
		{
			if (WorkoutEntered.Value && !initialWidgetSetupDone && !IsInFullscreenMode.Value)
			{
				if (LeaderboardAvailable && ShouldAutomaticallyShowLeaderboard && !CooldownEntered.Value)
				{
					widgetManager.ToggleLeaderboardWidget();
				}
				if (tryToShowHRWidget && ShouldAutomaticallyShowHeartRateWidget)
				{
					widgetManager.ToggleHRWidget();
				}
				initialWidgetSetupDone = true;
			}
		}

