		private void HandleVideoBufferStatusChange(VideoBufferMonitoringService.VideoBufferingStatus status)
		{
			if (status.IsBuffering && !poorInternetDialogShown && pingCheckTask == null && hardwareInfo.IsAndroid)
			{
				pingCheckTask = Task.Run(async delegate
				{
					double num = ((double?)workoutRunner?.Console?.LatestBasicInfo?.RunningTime) ?? 22.0;
					if (num < 21.0)
					{
						await Task.Delay(TimeSpan.FromSeconds(21.0 - num));
					}
					if (await wifiService.IsConnectionPoorOrLost() && !poorInternetDialogShown)
					{
						poorInternetDialogShown = true;
						ShowPoorInternetConnectionDialog();
					}
					pingCheckTask = null;
				});
			}
			suppressBufferMessage = false;
		}

		private async Task HandleVideoCaptionStatusChange(VideoCaptionStatus status)
		{
			if (!status.CaptionsAreInTrouble && !status.CaptionsAreMalformed)
			{
				streamFailActivated = false;
				streamFailsafeAttempted = false;
				streamRestartAttempted = false;
				return;
			}
			if (status.CaptionsAreMalformed && !NoLongerFollowingWorkout.Value && !streamFailActivated)
			{
				streamFailActivated = true;
				Log.Error("Video", "Captions are malformed. Giving up and showing the user an error.");
				SendLiveWorkoutDisconnectedAnalytics(status);
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.live_control_failure_title, Wolf.Core.Resources.AppStrings.live_control_failure_message, delegate
				{
					InvokeOnMainThread(delegate
					{
						NoLongerFollowingWorkout.Value = true;
					});
				}, Wolf.Core.Resources.AppStrings.save_workout.ToUpper(), Wolf.Core.Resources.AppStrings.dialog_continue.ToUpper(), null, async delegate
				{
					await GracefullyEndLiveWorkout().ConfigureAwait(continueOnCapturedContext: false);
				}, dismissible: false);
			}
			else if (status.SecondsSinceLastCaption > 180 && !streamFailActivated)
			{
				streamFailActivated = true;
				Log.Error("Video", $"No captions recevied for at least {180} seconds. Giving up and ending workout.");
				await SendLiveWorkoutDisconnectedAnalytics(status);
				await GracefullyEndLiveWorkout().ConfigureAwait(continueOnCapturedContext: false);
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.live_connection_failure_title, Wolf.Core.Resources.AppStrings.live_connection_failure_message, (Func<CancellationToken, Task<object>>)null, (string)null, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, false, false, "", (TaskCompletionSource<object>)null, (string)null, false, true);
			}
			else if (status.SecondsSinceLastCaption > 60 && !streamFailsafeAttempted)
			{
				streamFailsafeAttempted = true;
				IFitnessConsole fitnessConsole = workoutRunner?.Console;
				if (fitnessConsole != null && fitnessConsole.ConsoleInfo.MachineType.IsBeltBasedMachine())
				{
					Log.Error("Video", $"No captions received for at least {60} seconds. Setting speed and incline to minimums.");
					facadeFactoryDependencies.KphFacade.SetKph(1.6);
					facadeFactoryDependencies.GradeFacade.SetGrade(0.0);
				}
			}
			if (status.SecondsSinceLastCaption > 30 && !streamRestartAttempted)
			{
				streamRestartAttempted = true;
				Log.Error("Video", $"No captions received for at least {30} seconds. Attempting to reset stream.");
				ICombinedAudioVideoPlayer player = VideoService.PreBufferedVideoPlayer;
				string audioUri = workoutRunner?.Workout?.GetWorkoutMetadataAudioUrl();
				await player.StartLoadStream(workoutRunner?.RunContext?.ScheduleInfo?.LiveStreamUrl, VideoService.GetSelectedPlaybackType(), audioUri);
				player.Play();
			}
		}

		private async Task SendLiveWorkoutDisconnectedAnalytics(VideoCaptionStatus status)
		{
			Dictionary<string, object> analyticsProperties = await MediaAnalyticsExtensions.GetLiveWorkoutDisconnectedProperties(workoutRunner?.RunContext?.ScheduleInfo, status, VideoService);
			if (Mvx.TryResolve<IMediaAnalyticsService>(out var service))
			{
				MediaAnalyticsData extraAnalyticsData = await service.SetLiveWorkoutKickout();
				List<string> tag = new List<string> { "LiveWorkoutDisconnected" };
				string message = "Live workout disconnected";
				Exception exception = new Exception("Live workout disconnected, no crash");
				await Task.WhenAll(analytics.LiveWorkoutDisconnected(analyticsProperties, extraAnalyticsData), workoutPathoutService.FinishAsync("stoppedGettingControls", analyticsProperties), crashReporter?.ReportError(tag, message, exception, includeLogFiles: true, isManualLog: true));
			}
			else
			{
				Log.Error("Workout", "Could not resolve IMediaAnalyticsService");
				await Task.WhenAll(analytics.LiveWorkoutDisconnected(analyticsProperties), workoutPathoutService.FinishAsync("stoppedGettingControls", analyticsProperties));
			}
		}

		private void HandleFullScreenChange(bool isFullScreen)
		{
