		public async Task Init()
		{
			if (currentConsoleService?.ActiveConsole == null)
			{
				Log.Trace("Workout", "Abandoning InWorkoutViewModel Init since Console is null");
				return;
			}
			await Task.Run(async delegate
			{
				inAppNotificationService?.CreateHelpersForNewWorkout();
				IInAppNotificationService notificationService = inAppNotificationService;
				IWorkoutFeatureService obj = workoutFeatureService;
				IWorkoutRunner runner = workoutRunner;
				IWorkoutSettings obj2 = workoutSettings;
				FollowMessageViewModel = new FollowMessageViewModel(notificationService, obj, runner, obj2 != null && obj2.WorkoutContainer?.Workout?.IsVideoWorkout() == true);
				consoleStateChangedSub = currentConsoleService?.ActiveConsole.WhenStateChanged.SubscribeAsyncWithErrorLogging(OnConsoleStateChange);
				IWorkoutContainer container = workoutSettings?.WorkoutContainer;
				LeftSliderModel = container?.ConsoleConfiguration?.LeftSlider;
				RightSliderModel = container?.ConsoleConfiguration?.RightSlider;
				UseResumablePauseScreen.Value = container?.ConsoleConfiguration?.CanResumeWithButton == true || (currentConsoleService.ActiveConsole?.IsNonconnectedConsole() ?? false);
				if (LeftSliderModel != null)
				{
					LeftSliderModel.WorkoutChangeLevel = container?.WorkoutChangeLevel;
				}
				if (RightSliderModel != null)
				{
					RightSliderModel.WorkoutChangeLevel = container?.WorkoutChangeLevel;
				}
				await Task.Run(async delegate
				{
					SelectWarmUpPages(await Task.FromResult(workoutSettings.WorkoutContainer?.ConsoleConfiguration).ConfigureAwait(continueOnCapturedContext: false));
				});
				WorkoutMode.Value = ConsoleState.WarmUp;
				if (currentConsoleService?.ActiveConsole != null)
				{
					currentConsoleService.ActiveConsole.PauseOverrideEnabled = false;
				}
				EnableFullScreenStrengthWorkout();
				whenWorkoutEndingSub = currentConsoleService?.ActiveConsole?.WhenWorkoutEnding.Take(1).SubscribeWithErrorLogging(delegate
				{
					Log.Trace("Workout", "whenWorkoutEndingSub called. Setting IsWorkoutEnding.Value = true");
					IsWorkoutEnding.Value = true;
				});
				IDeviceInformation deviceInformation = deviceInfo;
				if (deviceInformation != null && !deviceInformation.IsBuiltIn && !currentConsoleService.ActiveConsole.IsNonconnectedConsole() && !currentConsoleService.ActiveConsole.IsEquipmentlessConsole())
				{
					whenBleRadioDisabledByUser = bleRadioStatusService.WhenBluetoothRadioEnabledChanged.Where((bool isEnabled) => !isEnabled).SubscribeAsyncWithErrorLogging(async delegate
					{
						shouldKeepRecoveryWorkoutCache = true;
						await Task.WhenAll(workoutPathoutService.FinishAsync("bleRadioDisabledException"), NavigateAway(showError: false, "whenBleRadioDisabledByUser"));
					});
				}
				whenTimeChangedSub = facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().SubscribeWithErrorLogging(async delegate(FitnessValueChange<int> x)
				{
					await OnConsoleTimeChanged(x);
				});
				userOverrideDecoratorChangedSub = container?.WorkoutRunner.WhenOverrideDecoratorChanged.SubscribeWithErrorLogging(OverrideDecoratorsChanged);
				if (container != null)
				{
					ConsoleState currentState = container.Console.LatestBasicInfo.CurrentState;
					if (currentState.IsRunningState() || currentState == ConsoleState.CoolDown)
					{
						container.Console.ChangeManager.RetriggerCurrentStateChange();
					}
					else if (currentState == ConsoleState.Paused)
					{
						UpdateWorkoutMode(new StateChange(ConsoleState.Unknown, ConsoleState.Paused));
					}
				}
				SetupBLERecoveryIfBLE();
				InitPreBufferedVideoPlayer(container);
				bool valueOrDefault = container?.Workout?.IsVideoWorkout() == true;
				bool valueOrDefault2 = container?.Workout?.IsGoogleMap == true;
				if (deviceInfo.IsBuiltIn && (valueOrDefault || valueOrDefault2))
				{
					volumeMetricSub = facadeFactoryDependencies.VolumeFacade.ObserveVolumeChanges().SubscribeWithErrorLogging(WhenConsoleVolumeChanged);
				}
				audioServiceInitializedSub?.Dispose();
				audioServiceInitializedSub = MusicService.WhenAudioServiceInitialized.Subscribe(delegate
				{
					feedFmStationChangeSub = WorkoutAudioService.WhenStationChanged.Subscribe(delegate
					{
						HandleAudioServiceInitialized();
					});
				});
				if (mockLiveWorkoutService?.IsMockedLiveWorkoutSet ?? false)
				{
					mockLiveWorkoutService.BeginMockedLiveWorkoutCaptions(captionMonitoringService);
				}
				await InitializeFeedFm().ConfigureAwait(continueOnCapturedContext: false);
			});
			await Task.Run(delegate
			{
				OverrideDecoratorsChanged(null);
			});
		}

		private async Task InitializeFeedFm()
		{
			if (MusicService != null)
			{
				INC<bool> trainerSelectStationEnabled = TrainerSelectStationEnabled;
				int value;
				if ((feedFmAvailabilityService?.IsFeedFmTrainerSelectFeatureEnabledForDevice() ?? false) && feedFmAvailabilityService.IsFeedFmFeatureEnabledForWorkout(WorkoutContainer?.Workout) && IsLiveWorkout)
				{
					IMusicService musicService = MusicService;
					value = ((musicService != null && musicService.FeedFmStations?.TrainerSelectStationSet == true) ? 1 : 0);
				}
				else
				{
					value = 0;
				}
				trainerSelectStationEnabled.Value = (byte)value != 0;
				if (!(workoutRunner is LiveWorkoutRunner liveWorkoutRunner))
				{
					await InitializeFeedFmForOnDemand().ConfigureAwait(continueOnCapturedContext: false);
				}
				else
				{
					InitializeFeedFmForScheduledWorkout(liveWorkoutRunner);
				}
			}
		}

		private async Task InitializeFeedFmForOnDemand()
		{
			bool upFeedFmAudioServiceIfAvailable = await MediaService.ShouldMusicStartAutomaticallyAsync().ConfigureAwait(continueOnCapturedContext: false);
			MusicService.SetUpFeedFmAudioServiceIfAvailable(upFeedFmAudioServiceIfAvailable);
			if (MusicService.WorkoutUsingBlankFeedFmMix())
			{
				MusicService.FeedFm.Pause(PauseMusicType.PausedDisabled);
			}
		}

		private void InitializeFeedFmForScheduledWorkout(LiveWorkoutRunner liveWorkoutRunner)
		{
			whenFeedFmStationsInitialized?.Dispose();
			whenFeedFmStationsInitialized = MusicService.WhenFeedFmStationsInitialized.Subscribe(delegate
			{
				TrainerSelectStationEnabled.Value = TrainerSelectStationEnabled.Value && MusicService.CurrentStationIsTrainerSelect;
			});
			liveWorkoutFeedFmPlaybackNeedsUpdate = true;
			liveWorkoutRunnerStateUpdateSub?.Dispose();
			liveWorkoutRunnerStateUpdateSub = liveWorkoutRunner.WhenLiveWorkoutModeChanged.Subscribe(delegate(LiveWorkoutState state)
			{
				if (liveWorkoutFeedFmPlaybackNeedsUpdate)
				{
					liveWorkoutFeedFmPlaybackNeedsUpdate = false;
					liveWorkoutRunnerStateUpdateSub?.Dispose();
					liveWorkoutRunnerStateUpdateSub = null;
					if (state != LiveWorkoutState.Cooldown)
					{
						if (!TrainerSelectStationEnabled.Value)
						{
							MusicService.SetUpFeedFmAudioServiceIfAvailable(state == LiveWorkoutState.InWorkout);
							feedFmScheduledFeedFmPlaybackReadySub?.Dispose();
							feedFmScheduledFeedFmPlaybackReadySub = MusicService.OnFeedFmInstantPlaybackReady.Take(1).SubscribeWithErrorLogging(delegate
							{
								feedFmScheduledFeedFmPlaybackReadySub?.Dispose();
								feedFmScheduledFeedFmPlaybackReadySub = null;
								MusicService?.PlayAudioServicePlayerIfEnabled();
							});
						}
						else if (state == LiveWorkoutState.Warmup)
						{
							QueueScheduledFeedFmPlaybackAt(liveWorkoutRunner, -FeedFmLiveWorkoutStationLoadBufferSeconds);
						}
						else
						{
							liveWorkoutRunnerTimeUpdateSub?.Dispose();
							liveWorkoutRunnerTimeUpdateSub = liveWorkoutRunner.WhenLiveWorkoutTimeUpdated.Subscribe(delegate(LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate timeUpdate)
							{
								if (!(timeUpdate.CurrentTime <= 0.0) && IsRunningState)
								{
									liveWorkoutRunnerTimeUpdateSub?.Dispose();
									liveWorkoutRunnerTimeUpdateSub = null;
									QueueScheduledFeedFmPlaybackAt(liveWorkoutRunner, Convert.ToSingle(timeUpdate.CurrentTime));
								}
							});
						}
					}
				}
			});
		}

		private void QueueScheduledFeedFmPlaybackAt(LiveWorkoutRunner liveWorkoutRunner, float latestCaptionTime)
		{
			float scheduleTime = latestCaptionTime + (float)FeedFmLiveWorkoutStationLoadBufferSeconds;
			MusicService.SetInitialTssStartTime(scheduleTime);
			feedFmScheduledFeedFmPlaybackReadySub?.Dispose();
			feedFmScheduledFeedFmPlaybackReadySub = MusicService.OnFeedFmInstantPlaybackReady.Take(1).SubscribeWithErrorLogging(delegate
			{
				feedFmScheduledFeedFmPlaybackReadySub?.Dispose();
				feedFmScheduledFeedFmPlaybackReadySub = null;
				HandleScheduledFeedFmPlaybackReady(liveWorkoutRunner, scheduleTime);
			});
			MusicService.SetUpFeedFmAudioServiceIfAvailable(shouldStartFeedFmServiceAutomatically: false);
		}

		private void HandleScheduledFeedFmPlaybackReady(LiveWorkoutRunner liveWorkoutRunner, float scheduledSeconds)
		{
			liveWorkoutRunner?.WhenLiveWorkoutTimeUpdated.Where((LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate x) => x.CurrentTime >= (double)scheduledSeconds).Take(1).Subscribe(delegate
			{
				Log.Trace("Audio", $"Reached Feed.fm playback scheduled time of: {scheduledSeconds}");
				MusicService?.PlayAudioServicePlayerIfEnabled();
			});
		}

