		private void SetupBLERecoveryIfBLE()
		{
			if (deviceInfo.IsBuiltIn)
			{
				return;
			}
			IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
			if (workoutContainer != null && workoutContainer.Workout?.ShouldUseEquipmentlessConsole() == true)
			{
				return;
			}
			IWorkoutContainer workoutContainer2 = workoutSettings.WorkoutContainer;
			if (workoutContainer2 != null && workoutContainer2.Console?.ConnectionType == Sindarin.Core.Connection.ConnectionType.BLE)
			{
				tickSub = Observable.Interval(TimeSpan.FromSeconds(1.0), intervalScheduler).SubscribeWithErrorLogging(async delegate
				{
					await OnTimerTick();
				});
			}
		}

		private async Task OnTimerTick()
		{
			if (WorkoutMode.Value != ConsoleState.WarmUp && WorkoutMode.Value != ConsoleState.Workout && WorkoutMode.Value != ConsoleState.PauseOverride && WorkoutMode.Value != ConsoleState.CoolDown)
			{
				timeSinceLastConsoleUpdate = 0;
				return;
			}
			totalTicks++;
			timeSinceLastConsoleUpdate++;
			if (Reconnecting.Value)
			{
				BLEDisconnectTimeoutSecondsRemaining.Value--;
				if (BLEDisconnectTimeoutSecondsRemaining.Value <= 0)
				{
					try
					{
						await workoutPathoutService.FinishAsync("timeoutBLEDisconnect");
						await NavigateAway(showError: true, "OnTimerTick");
					}
					catch (Exception exception)
					{
						Log.Error("Workout", "OnTimerTick Exception", exception);
					}
				}
			}
			else if (timeSinceLastConsoleUpdate > 3 && totalTicks > 15)
			{
				OnConsoleTimeout();
			}
		}

		private void OnConsoleTimeout()
		{
			if (!Reconnecting.Value)
			{
				Reconnecting.Value = true;
				ReconnectingText.Value = Wolf.Core.Resources.AppStrings.in_workout_ble_lost;
				EndWorkoutVisible.Value = true;
				BLEDisconnectTimeoutSecondsRemaining.Value = BleReconnectTimeoutSeconds;
				recoveryTimeoutSub?.Dispose();
				recoveryTimeoutSub = Observable.Timer(TimeSpan.FromSeconds(30.0)).SubscribeWithErrorLogging(RecoveryStillInProgress);
			}
		}

		private void OnConsoleUpdate()
		{
			if (Reconnecting.Value)
			{
				Reconnecting.Value = false;
				recoveryTimeoutSub?.Dispose();
				recoveryTimeoutSub = null;
			}
		}

		private void RecoveryStillInProgress(long timeout)
		{
			recoveryTimeoutSub?.Dispose();
			recoveryTimeoutSub = null;
			ReconnectingText.Value = Wolf.Core.Resources.AppStrings.in_workout_ble_still_lost;
		}

