		private void ScanForHeartRateMonitor()
		{
			heartRateScanSub?.Dispose();
			heartRateUpdateSub?.Dispose();
			IHeartRateHelper helper = heartRateService.HeartRate;
			hrTrainingService.IsUsingMockDevice = workoutSettings.WorkoutContainer?.Console is MockFitnessConsoleBase || heartRateService.Mock;
			if (!helper.IsConnected)
			{
				ConnectedToHeartRateMonitor.Value = false;
				workoutFeatureService.HeartRateMonitorConnected = false;
			}
			heartRateScanSub = helper.WhenConnectionChanged.Where((bool connected) => connected).Take(1).SubscribeWithErrorLogging(delegate
			{
				heartRateUpdateSub = helper.WhenStrapHeartRateUpdated.Where((int y) => y > 0).SubscribeWithErrorLogging(delegate
				{
					if (!ConnectedToHeartRateMonitor.Value)
					{
						UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Found);
						ShowHrWidgetIfNeedBe();
						ConnectedToHeartRateMonitor.Value = true;
						workoutFeatureService.HeartRateMonitorConnected = true;
						inWorkoutMetricsManager.IncrementMetricBy1(InWorkoutMetric.HeartRateMonitorConnected);
					}
				});
			});
			if (heartRateDisconnectedSub == null)
			{
				heartRateDisconnectedSub = helper.WhenConnectionChanged.Where((bool connected) => !connected).Subscribe(delegate
				{
					UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Disconnected);
					ConnectedToHeartRateMonitor.Value = false;
					workoutFeatureService.HeartRateMonitorConnected = false;
				});
			}
			if (!localSettings.IsAutomatedTestingMode)
			{
				if (!deviceInfo.IsBuiltIn)
				{
					helper.ForceHeartRateDisconnect();
					helper.ScanAndConnectToHeartRateDevice(delayScan: true);
				}
				UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Searching);
				if (deviceInfo.IsBuiltIn && !dialogPresenter.IsDialogShown<BluetoothDevicePickerViewModel>())
				{
					helper.ScanAndConnectToHeartRateDevice();
				}
			}
		}

		protected void ShowHrWidgetIfNeedBe()
		{
			if (workoutFeatureService.IsActivePulseAvailableInWorkout() && workoutSettings.HideHrWidgetUntilHrm)
			{
				if (!widgetManager.HRWidgetVisible)
				{
					widgetManager.ToggleHRWidget();
				}
				workoutSettings.HideHrWidgetUntilHrm = false;
			}
		}

		private void UpdateHRBadgeState(HRBadgeState newBadgeState)
		{
			if (!personalTrainingSettings.ActivePulseEnabled)
			{
				newBadgeState = Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.None;
			}
			HRBadgeLightText.Value = LightTextForHRBadgeState(newBadgeState);
			HRBadgeBoldText.Value = BoldTextForHRBadgeState(newBadgeState);
			HRBadgeState.Value = newBadgeState;
			switch (newBadgeState)
			{
			case Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Searching:
				searchingSub = Observable.Timer(SearchingTime).SubscribeWithErrorLogging(delegate
				{
					if (!isDisposed)
					{
						if (HRBadgeState.Value == Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Searching)
						{
							UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.NotFound);
						}
						searchingSub?.Dispose();
						searchingSub = null;
					}
				});
				break;
			case Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Found:
				foundSub = Observable.Timer(FoundTime).SubscribeWithErrorLogging(delegate
				{
					if (!isDisposed)
					{
						if (workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse))
						{
							UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.ActivePulseOn);
						}
						else
						{
							UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.None);
							InvokeOnMainThread(delegate
							{
								widgetManager?.ShowHeartRateWidget.SafeExecute();
							});
						}
						foundSub?.Dispose();
						foundSub = null;
					}
				});
				break;
			case Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.NotFound:
				notFoundSub = Observable.Timer(NotFoundTime).SubscribeWithErrorLogging(delegate
				{
					if (!isDisposed)
					{
						if (HRBadgeState.Value == Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.NotFound)
						{
							UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.None);
						}
						if (personalTrainingSettings.ActivePulseEnabled)
						{
							IWorkoutSettings obj = workoutSettings;
							if (obj != null && !obj.HideHrWidgetUntilHrm)
							{
								InvokeOnMainThread(delegate
								{
									widgetManager?.ShowHeartRateWidget.SafeExecute();
								});
							}
						}
						notFoundSub?.Dispose();
						notFoundSub = null;
					}
				});
				break;
			case Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Disconnected:
				disconnectSub = Observable.Timer(DisconnectTime).SubscribeWithErrorLogging(delegate
				{
					if (!isDisposed)
					{
						if (HRBadgeState.Value == Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Disconnected)
						{
							UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.None);
						}
						disconnectSub?.Dispose();
						disconnectSub = null;
					}
				});
				break;
			}
		}

		protected string LightTextForHRBadgeState(HRBadgeState badgeState)
		{
			if (badgeState != Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.ActivePulseOn)
			{
				return "";
			}
			return Wolf.Core.Resources.AppStrings.activepulse_on;
		}

		protected string BoldTextForHRBadgeState(HRBadgeState badgeState)
		{
			return badgeState switch
			{
				Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.ActivePulseOn => Wolf.Core.Resources.AppStrings.activepulse_no_space.ToUpperInvariant(), 
				Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Disconnected => Wolf.Core.Resources.AppStrings.hr_strap_disconnected.ToUpperInvariant(), 
				Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Searching => Wolf.Core.Resources.AppStrings.hr_strap_searching.ToUpperInvariant(), 
				Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.Found => Wolf.Core.Resources.AppStrings.hr_strap_found.ToUpperInvariant(), 
				Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.NotFound => Wolf.Core.Resources.AppStrings.hr_strap_not_found.ToUpperInvariant(), 
				_ => "", 
			};
		}

		private async Task OnConsoleTimeChanged(FitnessValueChange<int> metricChange)
		{
			timeSinceLastConsoleUpdate = 0;
			OnConsoleUpdate();
			if (!base.IsBuiltInClubUnit)
			{
				return;
			}
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			if (activeConsole == null || activeConsole.LatestBasicInfo?.CurrentState != ConsoleState.Workout)
			{
				return;
			}
			double totalSeconds = TimeSpan.FromMinutes(clubLocalSettings.ClubMaxWorkoutTimeMinutes).TotalSeconds;
			IWorkoutRunner obj = workoutRunner;
			bool? obj2;
			if (obj == null)
			{
				obj2 = null;
			}
			else
			{
				Workout workout = obj.Workout;
				obj2 = ((workout != null) ? new bool?(!workout.IsManual()) : ((bool?)null));
			}
			if (obj2 ?? true)
			{
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				int num;
				if (workoutContainer != null && workoutContainer.Workout?.Target == Workout.TargetType.Seconds)
				{
					IWorkoutContainer workoutContainer2 = workoutSettings.WorkoutContainer;
					num = ((workoutContainer2 != null && workoutContainer2.Workout?.TargetValue <= totalSeconds) ? 1 : 0);
				}
				else
				{
					num = 0;
				}
				if (num != 0)
				{
					return;
				}
			}
			int current = metricChange.Current;
			double num2 = totalSeconds - (double)current;
			if (num2 <= 0.0)
			{
				IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
				await workoutFacade.EndWorkoutAsync();
			}
			else
			{
				if (!clubUnitSecondsRemainingToShowWarnings.Any() || !(num2 < clubUnitSecondsRemainingToShowWarnings.First()))
				{
					return;
				}
				if (clubUnitSecondsRemainingToShowWarnings.Count == 2)
				{
					BaseViewModel.ShowDialogViewModel<MaxWorkoutFiveMinuteWarningViewModel>();
				}
				else
				{
					if (Mvx.TryResolve<IDialogPresenter>(out var service) && service.IsDialogShown<MaxWorkoutFiveMinuteWarningViewModel>())
					{
						service.CurrentDialogViewModel<MaxWorkoutFiveMinuteWarningViewModel>().CloseViewModel.Execute();
					}
					BaseViewModel.ShowDialogViewModel<MaxWorkoutOneMinuteWarningViewModel>();
				}
				clubUnitSecondsRemainingToShowWarnings.RemoveAt(0);
			}
		}

