		private async Task DoGoToCooldownSafely(bool activityCompleted)
		{
			ShowActivePulseToggle.Value = false;
			ShowSmartAdjustToggle.Value = false;
			wasInVideoMusicRegion = MusicService.InsideVideoMusicRegion || MusicService.WorkoutRegions.IsEntirelyWithinMusicRegion;
			try
			{
				await cooldownSemaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				await DoGoToCooldown(activityCompleted).ConfigureAwait(continueOnCapturedContext: false);
				StopRecordingInWorkoutMetrics();
			}
			finally
			{
				cooldownSemaphore.Release();
			}
			async Task DoGoToCooldown(bool completed)
			{
				Log.Trace("Workout", $"DoGoToCooldown - Completed {completed}");
				bool navigateAway = false;
				DateTime utcNow = DateTime.UtcNow;
				if (cooldownStartedDate.HasValue)
				{
					DateTime value = utcNow;
					DateTime? dateTime = cooldownStartedDate;
					if (!(value - dateTime > TimeSpan.FromSeconds(5.0)))
					{
						Log.Trace("Workout", $"Cooldown already started {(utcNow - cooldownStartedDate.Value).TotalSeconds} seconds ago, start prevented");
						goto IL_02e5;
					}
				}
				Log.Trace("Workout", "DoGoToCooldown Resetting cooldownStartedDate");
				cooldownStartedDate = DateTime.UtcNow;
				captionMonitoringService?.StopMonitoringCaptions();
				videoPlaybackCompletedSub?.Dispose();
				videoPlaybackCompletedSub = null;
				try
				{
					if (currentConsoleService.ActiveConsole != null)
					{
						currentConsoleService.ActiveConsole.PauseOverrideEnabled = false;
						Log.Trace("Workout", "DoGoToCooldown set PauseOverridEnabled = false");
					}
					bool flag = false;
					if (workoutSettings?.WorkoutContainer?.WorkoutRunner != null)
					{
						flag = await FinishWorkoutAsync(completed);
					}
					if (!flag)
					{
						Log.Trace("Workout", "Tried to finish a workout but the console must have triggered the cooldown already or is in the wrong state.");
					}
					Log.Trace("Workout", "DoGoToCooldown finished workout");
				}
				catch (Exception exception)
				{
					Log.Error("Workout", "Received error while going to cooldown", exception);
					if (workoutRunner != null)
					{
						await workoutRunner.StopAsync();
					}
					navigateAway = true;
				}
				goto IL_02e5;
				IL_02e5:
				if (navigateAway)
				{
					await NavigateAway(showError: false, "DoGoToCooldown").ConfigureAwait(continueOnCapturedContext: false);
				}
				if (IsFeedFmEnabledInSettings && wasInVideoMusicRegion)
				{
					MusicService.ShowFeedFmNotification();
				}
			}
		}

