		private void DoPauseButtonTapped()
		{
			ILockScreenHandler obj = lockScreenHandler;
			if (obj != null && obj.IsScreenLocked)
			{
				Log.Trace("Workout", "Ignore pause button tapped, console is pinlocked");
				return;
			}
			Log.Trace("Workout", "Pause button tapped");
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			bool flag = activeConsole != null && activeConsole.LatestBasicInfo?.CurrentState == ConsoleState.PauseOverride;
			Log.Trace("Workout", $"...wasInPauseOverride: {flag}");
			userInitiatedPause = true;
			if (currentConsoleService?.ActiveConsole != null)
			{
				Log.Trace("Workout", "...setting Console.PauseOverrideEnabled = false");
				currentConsoleService.ActiveConsole.PauseOverrideEnabled = false;
			}
			Log.Trace("Workout", "...Pausing WorkoutRunner");
			workoutRunner?.Pause();
			Log.Trace("Workout", "...WorkoutRunner paused");
			suppressBufferMessage = (videoBufferService?.CheckBufferPercentage() ?? 0.0) >= 26.0;
			Log.Trace("Workout", $"...suppressBufferMessage: {suppressBufferMessage}");
			if (flag)
			{
				IFitnessConsole activeConsole2 = currentConsoleService.ActiveConsole;
				if (activeConsole2 != null && activeConsole2.LatestBasicInfo?.CurrentState == ConsoleState.Paused)
				{
					Log.Trace("Workout", "...Doing video pause stuff");
					UpdateWorkoutMode(new StateChange(ConsoleState.PauseOverride, ConsoleState.Paused));
					Log.Trace("Workout", "...UpdateWorkoutMode complete");
					VideoService?.PreBufferedVideoPlayer?.Pause();
					Log.Trace("Workout", "...Done with video pause stuff");
				}
			}
			captionMonitoringService?.StopMonitoringCaptions();
			Log.Trace("Workout", "...Done processing pause button");
		}

		private void DoResumeButtonTapped()
		{
			ILockScreenHandler obj = lockScreenHandler;
			if (obj != null && obj.IsScreenLocked)
			{
				Log.Trace("Workout", "Ignore resume button tapped, console is pinlocked");
				return;
			}
			if (WorkoutMode.Value == ConsoleState.Workout)
			{
				Log.Trace("Workout", "Ignore button tapped, WorkoutMode is Workout");
				return;
			}
			Log.Trace("Workout", "Resume button tapped");
			if (retryResumeSub == null)
			{
				retryResumeSub = Observable.Interval(TimeSpan.FromSeconds(3.0)).SubscribeWithErrorLogging(delegate
				{
					ICurrentConsoleService obj2 = currentConsoleService;
					if (obj2 != null && obj2.IsInWorkout)
					{
						OnConsoleTimeout();
						workoutRunner?.Resume();
					}
					else
					{
						retryResumeSub?.Dispose();
						retryResumeSub = null;
					}
				});
			}
			workoutRunner?.Resume();
		}

		private async Task DoStopButtonTapped()
		{
			if (lockScreenHandler?.IsScreenLocked ?? false)
			{
				Log.Trace("Workout", "Ignore button stop tapped, console is pinlocked");
				return;
			}
			Log.Trace("Workout", "Stop button tapped");
			StopRecordingInWorkoutMetrics();
			Log.Trace("Workout", "Metrics recording stopped");
			SendWorkoutEndedEarlyAnalytics();
			Log.Trace("Workout", "Ended early workout analytics sent");
			Task.Run((Func<Task>)CreatePostWorkoutWebviewLoadTimeEvent);
			Log.Trace("Workout", "Current console state: " + ((currentConsoleService.ActiveConsole?.LatestBasicInfo?.CurrentState)?.ToString() ?? "<null>"));
			if (workoutSettings.WorkoutContainer?.Workout == null || currentConsoleService.ActiveConsole == null || currentConsoleService.ActiveConsole.LatestBasicInfo.IsInState(ConsoleState.Idle, ConsoleState.WorkoutResults))
			{
				Log.Trace("Workout", "Console either null, or already in results or idle. Ending workout.");
				Task.Run(async delegate
				{
					await NavigateAway(showError: false, "DoStopButtonTapped").ConfigureAwait(continueOnCapturedContext: false);
				});
				return;
			}
			if (retryStopSub == null)
			{
				retryStopSub = Observable.Interval(TimeSpan.FromSeconds(3.0)).SubscribeWithErrorLogging(delegate
				{
					ICurrentConsoleService obj = currentConsoleService;
					if (obj != null && obj.IsInWorkout)
					{
						OnConsoleTimeout();
						workoutRunner?.StopAsync();
					}
					else
					{
						retryStopSub?.Dispose();
						retryStopSub = null;
					}
				});
			}
			if (workoutRunner != null)
			{
				await workoutRunner.StopAsync();
			}
			inAppNotificationService?.DismissAll();
			string activityLogId = workoutRunner?.WolfGeneratedId;
			if (MediaService.Music.FeedFm != null)
			{
				AudioPlayerAction volumeState = (mediaSettings.MusicVolumeMuted ? AudioPlayerAction.MusicMuted : AudioPlayerAction.MusicUnMuted);
				feedFmAnalyticsService.SetInWorkoutMusicState(startingWorkout: false, MediaService.Music.FeedFm.ActiveState, volumeState);
			}
			FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics data = feedFmAnalyticsService?.BundleFeedFmAnalytics(activityLogId);
			if (WorkoutContainer?.Workout != null)
			{
				await analytics.FeedFmPostWorkoutData(data, WorkoutContainer.Workout).ConfigureAwait(continueOnCapturedContext: false);
			}
			else
			{
				Log.Trace("Workout", $"FeedFmPostWorkoutData not sending because WorkoutContainer is {WorkoutContainer} and Workout is {WorkoutContainer?.Workout}");
			}
			feedFmAnalyticsService?.Reset();
		}

		private void SendWorkoutEndedEarlyAnalytics()
		{
			Log.Trace("Workout", "Sending ended early workout analytics");
			analytics.WebViewMayBeShownSoon();
			if (workoutSettings?.WorkoutContainer?.Workout == null)
			{
				Log.Trace("Workout", "WorkoutContainer is null");
				Log.Trace("Workout", "Trying send analytics");
				SendWorkoutPathoutAnalytics("userEndedEarly").ConfigureAwait(continueOnCapturedContext: false);
				return;
			}
			double valueOrDefault = (workoutSettings?.WorkoutContainer?.Stats?.RunningStats?.DistanceChanges?.Last?.Value).GetValueOrDefault();
			IWorkoutSettings obj = workoutSettings;
			double valueOrDefault2 = ((obj == null) ? ((double?)null) : (obj.WorkoutContainer?.Stats?.RunningStats?.TimeSeconds?.Last?.Value * 1000.0)).GetValueOrDefault();
			bool flag = valueOrDefault2 < (double)workoutSettings.MinimumWorkoutDuration;
			bool flag2 = valueOrDefault < workoutSettings.MinimumWorkoutDistance;
			string pathoutReason = (((workoutSettings.WorkoutContainer.Workout.Type == Workout.WorkoutType.Strength) ? flag : (flag || flag2)) ? "userEndedBeforeThresholds" : "userEndedEarly");
			Log.Trace("Workout", "Trying send analytics");
			SendWorkoutPathoutAnalytics(pathoutReason).ConfigureAwait(continueOnCapturedContext: false);
		}

