		public virtual async Task NavigateAway(bool showError = false, string navigatingFrom = "")
		{
			if (!string.IsNullOrWhiteSpace(navigatingFrom))
			{
				Log.Trace("Workout", "NavigateAway triggered from " + navigatingFrom);
			}
			if (navigatedAway)
			{
				return;
			}
			navigatedAway = true;
			if (!shouldKeepRecoveryWorkoutCache)
			{
				await ClearRecoveryInfo().ConfigureAwait(continueOnCapturedContext: false);
			}
			CleanUp();
			if (!WorkoutEntered.Value || InRetailDemo)
			{
				workoutSettings?.ClearAndDisposeWorkoutContainer();
				if (InRetailDemo)
				{
					ExitRetailDemoWorkout();
				}
				else
				{
					this.OnWorkoutFinished?.Invoke(this, EventArgs.Empty);
					NavigateToDashboardViewModel();
				}
				DoClose();
			}
			else
			{
				UploadingLogsAndCleaningWorkout.Value = true;
				if (IsClubBle)
				{
					analytics.EnsureClubConsole(currentConsoleService?.ActiveConsole?.ConsoleInfo);
				}
				UploadResult result = await inWorkoutLogUploadInteractor.UploadAndNavigateAway(this, showError, this.OnWorkoutFinished);
				IWorkoutContainer container = workoutSettings?.WorkoutContainer;
				await SendInWorkoutDataToAnalytics(container).ConfigureAwait(continueOnCapturedContext: false);
				if (!showError && analytics != null && container?.Workout != null && container?.Stats != null && !container.Workout.IsGoogleMap)
				{
					leaderboardAnalytics?.LogLeaderboardAnalytics(container.Workout, container.Stats, workoutSettings.PreferredRightWorkoutWidget, competitionsService.GetRank());
				}
				ErrorRunningWorkout.Value |= showError;
				if (result == UploadResult.Success)
				{
					this.OnWorkoutFinished?.Invoke(this, EventArgs.Empty);
				}
			}
			if (localSettings != null && !deviceInfo.IsBuiltIn)
			{
				heartRateService.HeartRate.ForceHeartRateDisconnect();
			}
			ErrorRunningWorkout.Value |= showError;
		}

