		private void StoreUserMusicPreferences()
		{
			string text = ifitApi?.CurrentlyAuthenticatedUserId;
			if (text == null)
			{
				return;
			}
			string lastStationUserSelected = persistentMusicSettings.LastStationUserSelected;
			Dictionary<string, List<string>> dictionary = persistentMusicSettings.UserPreferredStations;
			if (lastStationUserSelected == null)
			{
				return;
			}
			if (dictionary != null && dictionary.ContainsKey(text))
			{
				if (dictionary[text].Contains(lastStationUserSelected))
				{
					dictionary[text].RemoveAt(dictionary[text].IndexOf(lastStationUserSelected));
				}
				dictionary[text].Insert(0, lastStationUserSelected);
			}
			else
			{
				if (dictionary == null)
				{
					dictionary = new Dictionary<string, List<string>>();
				}
				dictionary[text] = new List<string> { lastStationUserSelected };
			}
			persistentMusicSettings.UserPreferredStations = dictionary;
			persistentMusicSettings.LastStationUserSelected = null;
		}

		private async Task SendInWorkoutDataToAnalytics(IWorkoutContainer container)
		{
			if (container?.Workout == null)
			{
				Log.Trace("WolfAnalytics", "Unable to send in workout data to analytics, workout was null");
				return;
			}
			Workout workout = container.Workout;
			List<Task> list = new List<Task>
			{
				SendDataToAnalytics(analytics.FollowTrainerStats, inWorkoutMetricsManager.ToAnalyticsData()),
				SendDataToAnalytics(analytics.HrmConnectedInWorkout, inWorkoutMetricsManager.HrmConnectedToAnalytics()),
				SendDataToAnalytics(analytics.FlipperMetrics, inWorkoutFlipperMetricsManager.FlipperMetricsToAnalytics()),
				SendDataToAnalytics(analytics.InWorkoutNumberOfControlChanges, inWorkoutMetricsManager.ControlChangeMetricsToAnalytics())
			};
			if (workoutFeatureService.IsSmartAdjustAvailableInWorkout())
			{
				list.AddRange(new Task[3]
				{
					SendDataToAnalytics(analytics.PulsePercentageMetrics, inWorkoutMetricsManager.PulsePercentageMetricsToAnalytics()),
					SendDataToAnalytics(analytics.PulseControlMetrics, inWorkoutMetricsManager.PulseControlMetricsToAnalytics()),
					SendDataToAnalytics(analytics.PulseCorrectZoneMetrics, inWorkoutMetricsManager.PulseCorrectZoneMetricsToAnalytics(featureFlagManager.GetString(FeatureFlags.ActivePulseModel)))
				});
			}
			await Task.WhenAll(list);
			Task SendDataToAnalytics(Func<Dictionary<string, object>, Workout, Task> analyticsCall, Dictionary<string, object> data)
			{
				return analyticsCall(data, workout);
			}
		}

