		private void CleanUp()
		{
			if (feedFmAvailabilityService != null && feedFmAvailabilityService.ShouldShowStationChanger())
			{
				StoreUserMusicPreferences();
			}
			if (IsVideoWorkout)
			{
				VideoService?.PreBufferedVideoPlayer?.ApplicationPaused();
			}
			WorkoutAudioService?.Stop();
			if (MediaService?.Music?.VolumeScreenAvailable != null)
			{
				MediaService.Music.VolumeScreenAvailable.Changed -= VolumeScreenAvailableOnChanged;
			}
			MusicService?.ClearFeedFmMix();
			MediaService?.Cleanup();
			heartRateService?.HeartRate?.StopScanning();
			CleanUpSubscribers();
			AutomaticWebviewReloader?.Dispose();
			AutomaticWebviewReloader = null;
			if (captionMonitoringService != null)
			{
				captionMonitoringService.NoLongerFollowingWorkout = null;
				captionMonitoringService.Dispose();
				captionMonitoringService = null;
			}
			closedCaptionsMonitoringService?.Dispose();
			closedCaptionsMonitoringService = null;
			widgetManager?.Dispose();
			widgetManager = null;
			activePulseChangeSub?.Dispose();
			activePulseChangeSub = null;
			activePulseSideRailSub?.Dispose();
			activePulseSideRailSub = null;
			whenWhenShowDebugPulseMoreInfoSub?.Dispose();
			whenWhenShowDebugPulseMoreInfoSub = null;
			ConstantWattsModel?.Dispose();
			ConstantWattsModel = null;
			FollowMessageViewModel?.Dispose();
