		private async Task OnConsoleStateChange(StateChange change)
		{
			UpdateWorkoutMode(change);
			CheckPagesVisible(change);
			if (change.Current == ConsoleState.Idle && change.Old == ConsoleState.Paused && workoutPathoutService.IsWorkoutRunning)
			{
				SendWorkoutPathoutAnalytics("pauseScreenTimeout");
			}
			if (change.Current == ConsoleState.Idle && change.Old == ConsoleState.WorkoutResults)
			{
				await NavigateAway(showError: false, "whenIdleFromResults");
			}
			else if (change.Current == ConsoleState.WorkoutResults && change.Old == ConsoleState.Idle)
			{
				await NavigateAway(showError: true, "whenResultsError");
			}
			else if (change.Current == ConsoleState.WorkoutResults && change.Old != ConsoleState.Idle)
			{
				await NavigateAway(showError: false, "whenResults");
			}
			else if (change.Current == ConsoleState.Idle)
			{
				await NavigateAway(showError: false, "whenIdle");
			}
			else if (change.Current == ConsoleState.WarmUp)
			{
				EnterWarmup();
			}
			else if (change.Current == ConsoleState.Workout)
			{
				EnterRunning();
			}
			else if (change.Current == ConsoleState.CoolDown)
			{
				EnterCooldown();
			}
			else if (change.Current == ConsoleState.SafetyKeyRemoved)
			{
				if (IsLiveWorkout)
				{
					captionMonitoringService?.StopMonitoringCaptions();
				}
				dialogPresenter.CurrentDialogViewModel<InWorkoutAudioSettingsViewModel>()?.CloseViewModel.Execute();
				dialogPresenter.CurrentDialogViewModel<InWorkoutMusicControlsViewModel>()?.CloseViewModel.Execute();
				dialogPresenter.CurrentDialogViewModel<InWorkoutHeadphonePickerViewModel>()?.CloseViewModel.Execute();
				dialogPresenter.CurrentDialogViewModel<BluetoothDevicePickerViewModel>()?.CloseViewModel.Execute();
			}
		}

		private async Task EnterWarmup()
		{
			if (!navigatedAway && !WarmupEntered.Value)
			{
				SelectWarmUpPages(await Task.FromResult(workoutSettings?.WorkoutContainer?.ConsoleConfiguration));
				currentConsoleService.ActiveConsole.StartKeyEnabled = false;
				VolumeVisible.Value &= !IsVideoWorkout;
				WarmupEntered.Value = true;
			}
		}

		private async Task EnterRunning()
		{
			if (navigatedAway || WorkoutEntered.Value)
			{
				return;
			}
			if (VideoService?.PreBufferedVideoPlayer != null)
			{
				VideoService.PreBufferedVideoPlayer.AudioSourceConnectedOption = AudioSourceChangeOption.Play;
				VideoService.PreBufferedVideoPlayer.AudioSourceDisconnectedOption = AudioSourceChangeOption.Play;
			}
			if (inAppNotificationService != null)
			{
				inAppNotificationService.SuppressAll = false;
			}
			HeaderViewContainerVisible.Value = true;
			SelectWorkoutPages();
			List<InWorkoutHeaderHudType> list = new List<InWorkoutHeaderHudType>();
			IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
			if (workoutContainer == null || !workoutContainer.IsInEquipmentlessWorkout)
			{
				list.Add(InWorkoutHeaderHudType.Stats);
			}
			if (IsTablet)
			{
				IWorkoutContainer workoutContainer2 = workoutSettings.WorkoutContainer;
				if (workoutContainer2 == null || !workoutContainer2.IsInEquipmentlessWorkout)
				{
					list.Add(InWorkoutHeaderHudType.Charts);
				}
			}
			HudScreenTypes.Value = list;
			await workoutPathoutService.StartAsync(workoutSettings.WorkoutContainer?.Workout);
			if (IsVideoWorkout)
			{
				MonitorVideoBuffering();
				VolumeVisible.Value = true;
			}
			if (!base.IsBuiltInClubUnit)
			{
				ScanForHeartRateMonitor();
			}
			if (!WorkoutEntered.Value)
			{
				UpdateNonconnectedSpeedIfNecessary();
			}
			WorkoutEntered.Value = true;
			InvokeOnMainThread(delegate
			{
				InitializeWidgetsForRunning();
			});
			if (workoutFeatureService.IsSmartAdjustAvailableInWorkout() && personalTrainingSettings.SmartAdjustEnabled)
			{
				CoachingMessageNotificationData notification = new CoachingMessageNotificationData(HowlSmartAdjustType.StartOfWarmup, TimeSpan.FromSeconds(12.0));
				inAppNotificationService.Post(notification, ignoreSuppressed: true);
			}
		}

