		}

		private async Task EnterCooldown()
		{
			if (navigatedAway || CooldownEntered.Value)
			{
				return;
			}
			analytics.WebViewMayBeShownSoon();
			await SendWorkoutPathoutAnalytics("completed");
			if (InRetailDemo)
			{
				HeaderViewContainerVisible.Value = false;
				Log.Trace(LogTag, string.Format("{0} is {1}, calling {2} instead of entering Cooldown...", "InRetailDemo", InRetailDemo, "DoStopButtonTapped"));
				DoStopButtonTapped();
				return;
			}
			if (inAppNotificationService != null)
			{
				inAppNotificationService.SuppressAll = true;
				inAppNotificationService.DismissAll();
			}
			Log.Trace("Workout", "Starting EnteredCooldown");
			if (NavContainerOpen.Value)
			{
				Log.Trace("Workout", "EnteredCooldown Closing fabbar");
				CloseNavMenu.Execute(null);
			}
			if (HudIsVisible.Value)
			{
				HudIsVisible.SetFalse();
				HudFullscreenChange(isHudDown: false);
			}
			SelectCoolDownPages();
			InvokeOnMainThread(delegate
			{
				UpdateHRBadgeState(Wolf.Core.ViewModels.InWorkout.Widgets.HRBadgeState.None);
			});
			WorkoutEntered.Value = true;
			CooldownEntered.Value = true;
			inWorkoutLogUploadInteractor.BeginBackgroundUpload();
			Log.Trace("Workout", "EnteredCooldown finished");
		}

		private void UpdateWorkoutMode(StateChange change)
		{
			Log.Trace("Workout", $"UpdateWorkoutMode from: {change.Old} to: {change.Current}");
			retryResumeSub?.Dispose();
			retryResumeSub = null;
			retryStopSub?.Dispose();
			retryStopSub = null;
			consoleState = change.Current;
			ConsoleStateChanged?.Invoke(this, new ConsoleStateEventArgs(change.Current));
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			WorkoutMode.Value = change.Current;
			activeConsole.PauseOverrideEnabled = PauseOverrideSupported && change.Current == ConsoleState.Workout;
			if (userInitiatedPause && WorkoutMode.Value != ConsoleState.Paused && WorkoutMode.Value != ConsoleState.PauseOverride)
			{
				userInitiatedPause = false;
			}
			if (PauseOverrideSupported && change.Old == ConsoleState.Workout && (WorkoutMode.Value == ConsoleState.Paused || WorkoutMode.Value == ConsoleState.PauseOverride) && !userInitiatedPause)
			{
				Log.Trace("Workout", $"Workout paused, but running video workout on a {activeConsole.ConsoleInfo.MachineType} machine, so auto-resuming.");
				IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
				workoutFacade.ResumeWorkout();
			}
			else
			{
				Log.Trace("Workout", "Workout state changed, not auto-resuming");
				PauseTimeoutSecondsRemaining.Value = activeConsole.PauseTimeoutSecondsRemaining;
				updatePauseTimeRemainingSub?.Dispose();
				updatePauseTimeRemainingSub = activeConsole.WhenPausedTimeRemainingChanged.SubscribeWithErrorLogging(UpdatePauseTimeRemaining);
				if (appLifecycleService != null)
				{
					appLifecycleService.AppStateChanged -= CheckForPauseTimeoutOnForeground;
					appLifecycleService.AppStateChanged += CheckForPauseTimeoutOnForeground;
				}
			}
			if ((change.Old != ConsoleState.PauseOverride && change.Old != ConsoleState.Workout) || (change.Current != ConsoleState.PauseOverride && change.Current != ConsoleState.Workout))
			{
				InvokeOnMainThread(delegate
				{
					MediaService.HandleAudioServicePlaybackChanges(change.Current);
				});
			}
			switch (change.Current)
			{
			case ConsoleState.WarmUp:
				captionMonitoringService?.StartMonitoringCaptions();
				break;
			case ConsoleState.Workout:
			case ConsoleState.PauseOverride:
				captionMonitoringService?.StartMonitoringCaptions();
				if (VideoService?.PreBufferedVideoPlayer != null)
				{
					VideoService.PreBufferedVideoPlayer.AudioSourceConnectedOption = AudioSourceChangeOption.Play;
					VideoService.PreBufferedVideoPlayer.AudioSourceDisconnectedOption = AudioSourceChangeOption.Play;
				}
				break;
			case ConsoleState.CoolDown:
				captionMonitoringService?.StopMonitoringCaptions();
				VideoService?.PreBufferedVideoPlayer?.Stop(PlayerType.Video);
				break;
			case ConsoleState.Paused:
				if (VideoService?.PreBufferedVideoPlayer != null)
				{
					VideoService.PreBufferedVideoPlayer.AudioSourceConnectedOption = AudioSourceChangeOption.Pause;
					VideoService.PreBufferedVideoPlayer.AudioSourceDisconnectedOption = AudioSourceChangeOption.Pause;
				}
				break;
			case ConsoleState.WorkoutResults:
			case ConsoleState.SafetyKeyRemoved:
			case ConsoleState.Resume:
				break;
			}
		}

		private async Task SendWorkoutPathoutAnalytics(string pathoutReason)
		{
			await workoutPathoutService.FinishAsync(pathoutReason).ConfigureAwait(continueOnCapturedContext: false);
