		private void UpdatePauseTimeRemaining(int remaining)
		{
			PauseTimeoutSecondsRemaining.Value = remaining;
		}

		private void CheckForPauseTimeoutOnForeground(object obj, AppStateEventArgs state)
		{
			if (state.CurrentState == AppLifecycleService.AppState.Foreground && (WorkoutMode.Value == ConsoleState.Paused || WorkoutMode.Value == ConsoleState.PauseOverride) && PauseTimeoutSecondsRemaining.Value <= 0)
			{
				Log.Trace(LogTag, "Pause timed out while backgrounded but didn't stop workout. Stopping now.");
				SendWorkoutPathoutAnalytics("pauseScreenTimeoutInBackground");
				DoStopButtonTapped();
			}
		}

