		{
			videoPlaybackCompletedSub?.Dispose();
			videoPlaybackCompletedSub = VideoService?.PreBufferedVideoPlayer?.VideoPlaybackCompleted?.SubscribeAsyncWithErrorLogging(async delegate(bool completed)
			{
