		private async Task VideoPlaybackCompleted(bool completed)
		{
			Log.Trace("Video", $"Video playback completed: {completed}");
			videoPlaybackCompletedSub?.Dispose();
			videoPlaybackCompletedSub = null;
			if (!CooldownEntered.Value && !IsLiveWorkout)
			{
				Log.Trace("Workout", "DoGoToCooldown from video playback");
				await DoGoToCooldownSafely(completed).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private void OverrideDecoratorsChanged(object x)
		{
			Workout workout = workoutSettings?.WorkoutContainer?.Workout;
			if (string.IsNullOrWhiteSpace(workout?.Id) || workout.IsManual())
			{
				NoLongerFollowingWorkout.Value = false;
				return;
			}
			IWorkoutRunner obj = workoutRunner;
			bool flag = obj != null && obj.Decorators?.OfType<UserOverrideDecorator>()?.Any((UserOverrideDecorator d) => d.Enabled) == true;
			if (NoLongerFollowingWorkout.Value != flag)
			{
				NoLongerFollowingWorkout.Value = flag;
			}
			FollowMessageViewModel?.CheckDecorators(flag);
		}

		private void WhenConsoleVolumeChanged(FitnessValueChange<int> metricChange)
		{
			if (isUserSlidingSystemVolume || workoutSettings?.WorkoutContainer?.InWorkoutSystemVolumeInteractor?.IsProcessingVolumeChanges == true)
			{
				return;
			}
			ConsoleState valueOrDefault = (currentConsoleService?.ActiveConsole?.LatestBasicInfo?.CurrentState).GetValueOrDefault();
			if (valueOrDefault.IsRunningState() || valueOrDefault == ConsoleState.WarmUp || valueOrDefault == ConsoleState.CoolDown)
			{
				if (IsBuiltinWithHeadphonesConnected)
				{
					int trainerAndMusicVolumes = Convert.ToInt32(metricChange.Current);
					SetTrainerAndMusicVolumes(trainerAndMusicVolumes);
				}
				else if (InRetailDemo)
				{
					DoUpdateTrainerVolume((float)metricChange.Current / 100f);
				}
				int num = metricChange.Current.RoundToNearest(10.0);
				SystemVolume.Value = Convert.ToSingle((double)num / 100.0);
				DoShowMusicControls();
				feedFmAnalyticsService.HandleVolumeChange(Convert.ToInt32(metricChange.Current), VolumeChangeLocation.Hardware, VolumeChangeType.Master, VolumeChangeSource.Dashboard);
			}
		}

