		public void DoShowMusicControls(int autoDismissDuration, bool isFromFeedFmWidget = false)
		{
			CanClickMusicControls.Value = false;
			if (!VolumeScreenCurrentlyUp && Mvx.TryResolve<IDialogPresenter>(out var service) && !callingDoShowMusicControls)
			{
				callingDoShowMusicControls = true;
				if (InRetailDemo)
				{
					autoDismissDuration = 3;
				}
				if (feedFmAvailabilityService.ShouldUseStationChangeViewModels() && IsUsingFeedFmService)
				{
					audioSettingsViewShown?.Dispose();
					audioSettingsViewShown = mvxMessenger?.SubscribeOnThreadPoolThread<InWorkoutAudioSettingsViewModel.AudioSettingsViewLoaded>(async delegate
					{
						Task.Run((Func<Task>)OnMusicControlsShown).ConfigureAwait(continueOnCapturedContext: false);
						audioSettingsViewShown.Dispose();
					});
					CloseHud.Execute(null);
					service?.ShowDialog<InWorkoutAudioSettingsViewModel>(null, showSafely: true, new MusicControlsInitializationData
					{
						OnDismiss = delegate
						{
							callingDoShowMusicControls = false;
							MusicOverlayShowing.Value = false;
							CanClickMusicControls.Value = true;
							mvxMessenger?.Publish(new FeedFmNotificationViewModel.FeedFmNotificationDismissed(this));
							_updateNotificationVisibility.OnNext(value: true);
						},
						SecondsToKeepAliveAfterInteraction = TimeSpan.FromSeconds(autoDismissDuration),
						PreferredTab = ((!isFromFeedFmWidget) ? AudioSettingsTab.VolumeMixer : AudioSettingsTab.FeedFm)
					});
				}
				else
				{
					PauseScreenShown.Value = false;
					service?.ShowDialog<InWorkoutMusicControlsViewModel>(null, showSafely: true, new MusicControlsInitializationData
					{
						OnAppear = delegate
						{
							MusicOverlayShowing.Value = true;
						},
						OnDismiss = delegate
						{
							MusicOverlayShowing.Value = false;
							callingDoShowMusicControls = false;
							CanClickMusicControls.Value = true;
							mvxMessenger?.Publish(new FeedFmNotificationViewModel.FeedFmNotificationDismissed(this));
							_updateNotificationVisibility.OnNext(value: true);
						},
						SecondsToKeepAliveAfterInteraction = TimeSpan.FromSeconds(autoDismissDuration)
					}, animated: false);
				}
				_updateNotificationVisibility.OnNext(value: false);
				FeedFmAnalytics.AudioSettingsEntryPoint entryPoint = ((!isFromFeedFmWidget) ? FeedFmAnalytics.AudioSettingsEntryPoint.AudioSettingsButton : FeedFmAnalytics.AudioSettingsEntryPoint.PauseOverlayWidget);
				feedFmAnalyticsService.AddAudioSettingsEntryPoint(entryPoint);
			}
			else
			{
				CanClickMusicControls.Value = true;
			}
			async Task OnMusicControlsShown()
			{
				if (callingDoShowMusicControls)
				{
					MusicOverlayShowing.Value = true;
					await Task.Run(async delegate
					{
						await Task.Delay(500);
						PauseScreenShown.Value = false;
					}).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
		}

