		private void SetupNotifyTrackPlayingSub()
		{
			LastReportedTrackId = null;
			notifyTrackPlayingSub?.Dispose();
			notifyTrackPlayingSub = Observable.Timer(TimeSpan.Zero, NotifyTrackPlayingInterval).SubscribeAsyncWithErrorLogging(async delegate
			{
				await DoNotifyTracks().ConfigureAwait(continueOnCapturedContext: false);
			});
		}

		private async Task<string> GetCurrentPopMusicTrackId(WorkoutPopMusicInfoService popMusicInfoService)
		{
			MixTrack currentMixTrack = null;
			try
			{
				currentMixTrack = await popMusicInfoService.MixTrackAtTime((int)VideoService.PreBufferedVideoPlayer.AudioPosition).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception arg)
			{
				Log.Error("Workout", $"Could not get current mix track: {arg}");
			}
			return currentMixTrack?.Track?.Id;
		}

		protected virtual async Task DoNotifyTracks()
		{
			if (!MediaService.Music.WorkoutHasLegacyPopMusic || !(currentConsoleService?.ActiveConsole?.LatestBasicInfo?.CurrentState).HasValue || !validConsoleStatesForMusic.Contains(currentConsoleService.ActiveConsole.LatestBasicInfo.CurrentState))
			{
				return;
			}
			IWorkoutMusicInfoService musicInfoService = workoutSettings.WorkoutContainer.MusicInfoService;
			WorkoutPopMusicInfoService popMusicInfoService = musicInfoService as WorkoutPopMusicInfoService;
			if (popMusicInfoService == null || isCheckingForNotifyTracks)
			{
				return;
			}
			isCheckingForNotifyTracks = true;
			if (!HasNotifiedMixPlayed)
			{
				try
				{
					await popMusicInfoService.NotifyMixPlayed().ConfigureAwait(continueOnCapturedContext: false);
					HasNotifiedMixPlayed = true;
				}
				catch (Exception arg)
				{
					Log.Error("Workout", $"Could not report mix played: {arg}");
				}
			}
			InvokeOnMainThread(async delegate
			{
				string currentTrackId = await GetCurrentPopMusicTrackId(popMusicInfoService);
				if (currentTrackId != null && currentTrackId != LastReportedTrackId)
				{
					try
					{
						await popMusicInfoService.NotifyTrackPlayed(currentTrackId);
						LastReportedTrackId = currentTrackId;
					}
					catch (Exception arg2)
					{
						Log.Error("Workout", string.Format("Could not report current track Id ({0}): {1}", currentTrackId ?? "null", arg2));
					}
				}
				isCheckingForNotifyTracks = false;
			});
		}

		private async Task DoSetMockHeartRate()
		{
			int result = DefaultMockHeartRate;
			int.TryParse(MockHrText, out result);
			if (heartRateService.HeartRate is MockHeartRateHelper mockHeartRateHelper)
			{
				mockHeartRateHelper.HeartRateBase = result;
				if (!mockHeartRateHelper.IsRunning)
				{
					await mockHeartRateHelper.ScanAndConnectToHeartRateDevice();
				}
			}
		}

		private void DoStopHeartRateHelper()
		{
			heartRateService.HeartRate.ForceHeartRateDisconnect();
		}

		public void SelectWarmUpPages(IConsoleConfiguration config)
		{
			if (InRetailDemo)
			{
				Pages.Value = new List<Type> { typeof(InWorkoutRetailDemoLoadingVideoViewModel) };
			}
			else if (config == null)
			{
				Log.Error("Workout", "Tried to activate warmup pages, but configuration was null");
			}
			else if (config.MainWarmupPages.IsNullOrEmpty())
			{
				Log.Trace("Workout", "Selecting workout pages instead of warmup pages");
				SelectWorkoutPages();
			}
			else if (!WarmupPagesSelected)
			{
				Log.Trace("Workout", $"Selecting warmup pages. MainWarmupPages count: {config.MainWarmupPages?.Count}");
				Pages.Value = config.MainWarmupPages;
			}
		}

		private void SelectWorkoutPages()
		{
			if (!WorkoutPagesSelected)
			{
				Log.Trace("Workout", "Selecting workout pages");
				Pages.Value = workoutSettings.WorkoutContainer?.ConsoleConfiguration?.MainWorkoutPages;
			}
		}

		private void SelectCoolDownPages()
		{
			if (InRetailDemo)
			{
				Pages.Value = new List<Type>();
				return;
			}
			IConsoleConfiguration consoleConfiguration = workoutSettings.WorkoutContainer?.ConsoleConfiguration;
			if (consoleConfiguration == null)
			{
				Log.Error("Workout", "Tried to activate cooldown pages, but configuration was null");
			}
			else if (consoleConfiguration.MainCooldownPages.IsNullOrEmpty())
			{
				Pages.Value = new List<Type> { typeof(InWorkoutWarmCoolViewModel) };
			}
			else if (!CooldownPagesSelected)
			{
				Log.Trace("Workout", "Selecting cooldown pages");
				Pages.Value = consoleConfiguration?.MainCooldownPages;
			}
		}

		private void LogWorkoutDetails()
		{
			if (localSettings != null)
			{
				if (workoutSettings?.WorkoutContainer != null)
				{
					if (workoutSettings?.WorkoutContainer?.Workout != null)
					{
						Workout workout = workoutSettings.WorkoutContainer.Workout;
						Log.Trace("Workout", $"Workout.Type: {workout.Type}; " + "Workout.ID: " + workout.Id + "; Workout.VideoID: " + workout.VideoId + "; " + $"Workout.WorkoutFilters: {workout.WorkoutFilters}" + $"Workout.IsLiveWorkout: {workout.IsLiveWorkout}; " + $"Workout.IsGoogleMap: {workout.IsGoogleMap};");
					}
					else
					{
						Log.Trace("Workout", "Can not log workout details because Workout is null");
					}
				}
				else
				{
					Log.Trace("Workout", "Can not log workout details because WorkoutContainer is null");
				}
			}
			else
			{
				Log.Trace("Workout", "Can not log workout details because localSettings is null");
			}
		}

		private void InitPreBufferedVideoPlayer(IWorkoutContainer container)
		{
			if (VideoService?.PreBufferedVideoPlayer == null || container == null || container.Workout?.IsVideoWorkout() != true)
			{
				return;
			}
			musicTracksInfoSub?.Dispose();
			musicTracksInfoSub = workoutSettings.WorkoutContainer?.MusicInfoService?.WhenMusicInfoChanged?.Subscribe(delegate(IList<MusicTrack> tracks)
			{
				if (tracks.CountSafe() > 0)
				{
					VideoService.PreBufferedVideoPlayer.AudioVolume = mediaSettings.MusicVolume;
					musicTracksInfoSub?.Dispose();
				}
			}, delegate(Exception ex)
			{
				Log.Error("Workout", "Error with subscription for MusicInfoService in $InWorkoutViewModel", ex);
			});
			MediaService.UpdatePlayerVolumesFromSettings();
			if (currentConsoleService.ActiveConsole is IEquipmentlessConsole equipmentlessConsole)
			{
				equipmentlessConsole.HeartRateHelper = heartRateService.HeartRate;
			}
		}

		public void DoRefreshFeedFmAudioTrack()
		{
			AudioTrack.Value = MusicService?.FeedFm?.ActiveTrack ?? MusicService?.FeedFm?.PlayHistory?.LastOrDefault();
		}

		private void DoUpdateVolume(float newVolume)
		{
			switch (WorkoutPauseVolumeType)
			{
			case VolumeType.System:
				SystemVolumeFromSlider.Value = newVolume;
				break;
			case VolumeType.Master:
				DoUpdateMasterVolume(newVolume);
				break;
			}
		}

		private void DoUpdateTrainerVolume(float newVolume)
		{
			newVolume = newVolume.Clamp(0f, 1f);
			MediaService.SetVideoVolume(newVolume);
		}

		private void DoUpdateMusicVolume(float newVolume)
		{
			bool musicVolumeMuted = mediaSettings.MusicVolumeMuted;
			newVolume = newVolume.Clamp(0f, 1f);
			MediaService.SetMusicVolume(newVolume);
			AudioPlayerType player = ((!IsUsingFeedFmService) ? AudioPlayerType.Stock : AudioPlayerType.FeedFm);
			int volume = (int)(newVolume * 100f).Clamp(0f, 100f);
			if (!musicVolumeMuted && mediaSettings.MusicVolumeMuted)
			{
				analytics.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.MusicMuted, player, volume, workoutRunner.WolfGeneratedId);
			}
			else if (musicVolumeMuted && !mediaSettings.MusicVolumeMuted)
			{
				analytics.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.MusicUnMuted, player, volume, workoutRunner.WolfGeneratedId);
			}
		}

		private void DoUpdateMasterVolume(float newVolume)
		{
			newVolume = newVolume.Clamp(0f, 1f);
			if (masterVolumeMixerService != null)
			{
				masterVolumeMixerService.ScaleVolumeLevels(newVolume);
				DoUpdateTrainerVolume(mediaSettings.TrainerVolume);
				DoUpdateMusicVolume(mediaSettings.MusicVolume);
			}
		}

		public void SystemVolumeReleased()
		{
			isUserSlidingSystemVolume = false;
			UpdateSystemVolume(force: true);
		}

		public void SystemVolumeSlidingStarted()
		{
			isUserSlidingSystemVolume = true;
		}

		[DependsOn(new string[] { "SystemVolumeFromSlider" })]
		protected void SystemVolumeFromSliderChanged()
		{
			if (isUserSlidingSystemVolume)
			{
				float lastSystemVolume = LastSystemVolume;
				SystemVolume.Value = SystemVolumeFromSlider.Value;
				int currentSystemVolume = SystemVolumeHelper.MapVolume(SystemVolume.Value);
				int previousSystemVolume = SystemVolumeHelper.MapVolume(lastSystemVolume);
				platformMediaVolumeService.IncreaseVolumeIfNeeded(deviceInfo.IsBuiltIn, headphoneConnectionHelper.IsConnected(), previousSystemVolume, currentSystemVolume);
				UpdateSystemVolume();
			}
		}

		private void UpdateSystemVolume(bool force = false)
		{
			int num = SystemVolumeHelper.MapVolume(SystemVolume.Value);
			if (IsBuiltinWithHeadphonesConnected)
			{
				SetTrainerAndMusicVolumes(num);
			}
			SystemVolumeHelper.UpdateVolumeLevel(currentConsoleService, deviceInfo, workoutSettings, num, force);
			feedFmAnalyticsService.HandleVolumeChange(num, VolumeChangeLocation.Slider, VolumeChangeType.Master, VolumeChangeSource.Pause);
		}

		private void SetTrainerAndMusicVolumes(int mappedVolume)
		{
			float num = mediaSettings.MusicVolume * 100f;
			float num2 = mediaSettings.TrainerVolume * 100f;
			float volume;
			float volume2;
			if (num.AlmostEqual(0f) && num2.AlmostEqual(0f))
			{
				volume = (volume2 = InWorkoutMusicControlsViewModel.GetRoundedMusicTrainerVolumeFraction(mappedVolume).Clamp(0f, 1f));
			}
			else
			{
				volume = InWorkoutMusicControlsViewModel.GetMusicTrainerVolumeFraction(mappedVolume, num, num2).Clamp(0f, 1f);
				volume2 = InWorkoutMusicControlsViewModel.GetMusicTrainerVolumeFraction(mappedVolume, num2, num).Clamp(0f, 1f);
			}
			MediaService?.SetMusicVolume(volume);
			MediaService?.SetVideoVolume(volume2);
		}

		private void DoCommitVolumeChange()
		{
			INC<bool> volumeScreenAvailable = VolumeScreenAvailable;
			if (volumeScreenAvailable != null)
			{
				_ = volumeScreenAvailable.Value;
				if (0 == 0 && VolumeScreenAvailable.Value)
				{
					masterVolumeMixerService?.CommitVolumeLevels();
				}
			}
		}

		private void UpdateNonconnectedSpeedIfNecessary()
		{
			if (!isDisposed && !navigatedAway)
			{
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				if (workoutContainer != null && workoutContainer.Workout?.IsGoogleMap == true && activeConsole != null && activeConsole.IsNonconnectedConsole() && activeConsole != null && activeConsole.ConsoleInfo?.MachineType.IsBeltBasedMachine() == true)
				{
					facadeFactoryDependencies.KphFacade.SetKph(8.0);
				}
			}
		}

		public void FinishAndNavigateAway()
		{
			webviewHolderFactory.WebviewHolderStore.FlushAll();
			inWorkoutLogUploadInteractor.NavigateAway(base.LogOut.Execute, NavigateToDashboardViewModel, base.ShowViewModel<DashboardViewModel>);
			DoClose();
		}

		public void ShowPreviousOverlayScreen(BluetoothDevicePickerViewModel.OverlaySource state)
		{
			switch (state)
			{
			case BluetoothDevicePickerViewModel.OverlaySource.FromMusic:
				DoShowMusicControls();
				break;
			case BluetoothDevicePickerViewModel.OverlaySource.FromPause:
				PauseScreenShown.Value = true;
				break;
			default:
				throw new ArgumentOutOfRangeException("state", state, null);
			case BluetoothDevicePickerViewModel.OverlaySource.FromWarmCool:
			case BluetoothDevicePickerViewModel.OverlaySource.FromNone:
				break;
			}
		}

		private string GetCooldownButtonText()
		{
			string result = (IsTablet ? Wolf.Core.Resources.AppStrings.go_to_cool_down : Wolf.Core.Resources.AppStrings.cool_down);
			IWorkoutRunner workoutRunner = this.workoutRunner;
			if (workoutRunner != null && workoutRunner.CoolDown == null)
			{
				result = Wolf.Core.Resources.AppStrings.in_workout_ble_end_workout;
			}
			return result;
		}

