	public class LeaderboardParticipantItemViewModel : MvxViewModel
	{
		public readonly INC<User> User = new NC<User>();

		public readonly INC<string> Guid = new NC<string>();

		public readonly INC<string> Name = new NC<string>();

		public readonly INC<string> Subtitle = new NC<string>();

		public readonly INC<string> Rank = new NC<string>();

		public readonly INC<bool> ShowTrainerIcon = new NC<bool>();

		public readonly INC<bool> ShowFirstPlaceIcon = new NC<bool>();

		public readonly INC<bool> ShowRanking = new NC<bool>();

		public readonly INC<string> Value = new NC<string>();

		public readonly INC<double> ProgressPercent = new NC<double>();

		public readonly INC<double> ProgressOpacity = new NC<double>();

		public readonly INC<bool> IsMetric = new NC<bool>();

		public LeaderboardParticipantItemViewModel(CompetitionParticipant participant, bool isMetric)
		{
			var (firstname, lastname) = HumanNameConverter.ConvertFullNameToFirstLastName(participant.Name);
			User.Value = new User
			{
				Id = participant.UserId,
				Firstname = firstname,
				Lastname = lastname
			};
			Guid.Value = participant.Guid;
			if (participant.AvatarUrl != null && !participant.AvatarUrl.Contains("default"))
			{
				User.Value.ImageUrl = participant.AvatarUrl;
			}
			Name.Value = participant.Name;
			switch (participant.Type)
			{
			case ParticipantType.You:
				Subtitle.Value = Wolf.Core.Resources.AppStrings.leaderboard_participant_you.ToLower(CultureInfo.CurrentUICulture);
				break;
			case ParticipantType.Trainer:
				ShowTrainerIcon.Value = true;
				Subtitle.Value = Wolf.Core.Resources.AppStrings.trainer;
				break;
			case ParticipantType.Other:
				Subtitle.Value = ((string.IsNullOrWhiteSpace(participant.Gender) || participant.Age <= 0) ? string.Empty : string.Format(Wolf.Core.Resources.AppStrings.leaderboard_demographics, participant.Gender, RoundAgeTo10s(participant.Age)));
				break;
			}
			IsMetric.Value = isMetric;
			Update(participant);
		}

		public void Update(CompetitionParticipant participant)
		{
			Rank.Value = participant.Rank.ToString();
			ShowFirstPlaceIcon.Value = participant.Rank == 1;
			ShowRanking.Value = participant.Rank != 0;
			Value.Value = (IsMetric.Value ? UnitUtil.EnsureKilometers(DistanceUnit.M, participant.Value, 2).ToString($"F{2}") : UnitUtil.EnsureMiles(DistanceUnit.M, participant.Value, 2).ToString($"F{2}"));
			ProgressOpacity.Value = participant.ProgressOpacity;
			ProgressPercent.Value = participant.ProgressPercent;
		}

		private int RoundAgeTo10s(double age)
		{
			return (int)(Math.Floor(age / 10.0) * 10.0);
		}
	}
	public class NativeLeaderboardViewModel : BaseViewModel
	{
		public readonly INC<string> HeaderText = new NC<string>();

		public readonly INC<bool> ShouldShowHeaderBlock = new NC<bool>();

		public readonly INC<bool> ShouldShowRankingBlock = new NC<bool>();

		public readonly INC<string> RankingTitleText = new NC<string>();

		public readonly INC<string> CurrentRank = new NC<string>();

		public readonly INC<string> CurrentRankOutOfText = new NC<string>();

		public readonly INC<string> InTheLeadText = new NC<string>();

		public readonly INC<bool> ShouldShowInTheLeadText = new NC<bool>();

		public readonly INC<bool> ShouldShowStatHeaderBlock = new NC<bool>();

		public readonly INC<string> StatRankHeaderText = new NC<string>();

		public readonly INC<bool> ShouldShowStatRankHeaderText = new NC<bool>();

		public readonly INC<string> StatTypeHeaderText = new NC<string>();

		public readonly INC<string> MapWorkoutText = new NC<string>();

		public readonly INC<bool> IsMetric = new NC<bool>();

		public readonly INC<bool> IsMapWorkout = new NC<bool>();

		private readonly INativeCompetitionService competitionService;

		private new readonly IWorkoutSettings workoutSettings;

		private IDisposable competitionUpdatedSub;

		public readonly MvxObservableCollection<LeaderboardParticipantItemViewModel> Participants = new MvxObservableCollection<LeaderboardParticipantItemViewModel>();

		public NativeLeaderboardViewModel(ILocalSettings localSettings, INativeCompetitionService competitionService, IWorkoutSettings workoutSettings)
			: base(localSettings)
		{
			try
			{
				this.competitionService = competitionService;
				this.workoutSettings = workoutSettings;
				IsMetric.Value = workoutSettings?.WorkoutContainer?.IsMetric == true;
				HeaderText.Value = Wolf.Core.Resources.AppStrings.leaderboard;
				ShouldShowHeaderBlock.Value = true;
				ShouldShowRankingBlock.Value = false;
				RankingTitleText.Value = Wolf.Core.Resources.AppStrings.leaderboard_native_current_ranking;
				CurrentRank.Value = string.Empty;
				CurrentRankOutOfText.Value = string.Empty;
				InTheLeadText.Value = Wolf.Core.Resources.AppStrings.leaderboard_native_leader;
				ShouldShowInTheLeadText.Value = false;
				ShouldShowStatHeaderBlock.Value = false;
				IsMapWorkout.Value = false;
				StatRankHeaderText.Value = Wolf.Core.Resources.AppStrings.leaderboard_native_rank;
				StatTypeHeaderText.Value = (IsMetric.Value ? Wolf.Core.Resources.AppStrings.km : Wolf.Core.Resources.AppStrings.leaderboard_native_miles);
				MapWorkoutText.Value = Wolf.Core.Resources.AppStrings.leaderboard_native_mapworkout;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			competitionUpdatedSub?.Dispose();
			competitionUpdatedSub = null;
			if (!IsMapWorkout.Value)
			{
				competitionUpdatedSub = competitionService.ParticipantsUpdated.SubscribeWithErrorLogging(OnNext);
			}
			IsMapWorkout.Value = competitionService.IsGoogleMap;
			return base.OnViewShown();
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			competitionUpdatedSub?.Dispose();
			competitionUpdatedSub = null;
		}

		private void OnNext(bool obj)
		{
			try
			{
				List<CompetitionParticipant> participants = competitionService.Participants;
				UpdateRankingBlock(participants);
				UpdateStatHeaderBlock(participants);
				UpdateParticipants(participants);
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "NativeLeaderboardViewModel", exception);
			}
		}

		private void UpdateStatHeaderBlock(List<CompetitionParticipant> list)
		{
			ShouldShowStatHeaderBlock.Value = list.Count > 0;
			ShouldShowStatRankHeaderText.Value = list.Count > 2;
		}

		private void UpdateParticipants(List<CompetitionParticipant> list)
		{
			List<LeaderboardParticipantItemViewModel> list2 = new List<LeaderboardParticipantItemViewModel>();
			foreach (CompetitionParticipant person in list)
			{
				LeaderboardParticipantItemViewModel leaderboardParticipantItemViewModel = Participants.FirstOrDefault((LeaderboardParticipantItemViewModel x) => x.Guid.Value.Equals(person.Guid));
				if (leaderboardParticipantItemViewModel == null)
				{
					list2.Add(new LeaderboardParticipantItemViewModel(person, IsMetric.Value));
				}
				else
				{
					leaderboardParticipantItemViewModel.Update(person);
				}
			}
			if (list2.Count > 0)
			{
				Participants.AddRange(list2);
			}
		}

		private void UpdateRankingBlock(List<CompetitionParticipant> list)
		{
			ShouldShowRankingBlock.Value = list.Count > 2;
			if (ShouldShowRankingBlock.Value)
			{
				CompetitionParticipant competitionParticipant = list.FirstOrDefault((CompetitionParticipant x) => x.Type == ParticipantType.You);
				if (competitionParticipant != null)
				{
					ShouldShowInTheLeadText.Value = competitionParticipant.Rank == 1;
					CurrentRank.Value = competitionParticipant.Rank.ToString();
					CurrentRankOutOfText.Value = $"/ {list.Count - 1}";
				}
			}
		}

