	public class MaxWorkoutOneMinuteWarningViewModel : MaxWorkoutTimeWarningViewModel
	{
		public string OkString = Wolf.Core.Resources.AppStrings.okay_title.ToUpper();

		public INC<string> TimerString = new NC<string>();

		private IDisposable whenTimeChangedSub;

		private const string timeFormat = "m\\:ss";

		public MaxWorkoutOneMinuteWarningViewModel(ILocalSettings localSettings, ICurrentConsoleService currentConsoleService)
			: base(localSettings, currentConsoleService)
		{
			try
			{
				whenTimeChangedSub = facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().SubscribeWithErrorLogging(OnTimeTimeChanged);
				Subtitle = Wolf.Core.Resources.AppStrings.club_workout_warning_subtitle_1min;
				TimerString.Value = TimeSpan.FromMinutes(1.0).ToString("m\\:ss");
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void OnTimeTimeChanged(FitnessValueChange<int> metricChange)
		{
			double totalSeconds = TimeSpan.FromMinutes(clubLocalSettings.ClubMaxWorkoutTimeMinutes).TotalSeconds;
			int current = metricChange.Current;
			double val = Math.Floor(totalSeconds - (double)current);
			val = Math.Max(0.0, val);
			TimerString.Value = TimeSpan.FromSeconds(val).ToString("m\\:ss");
		}

		public override void Dispose()
		{
			base.Dispose();
			whenTimeChangedSub?.Dispose();
			whenTimeChangedSub = null;
			UnregisterChangeHandlers();
		}

