	public abstract class MaxWorkoutTimeWarningViewModel : ClubTabletFullScreenDialogViewModel
	{
		private IDisposable doneRunningSubscription;

		public ICommand Continue => new MvxCommand(DoContinue);

		public ICommand Cooldown => new MvxCommand(DoCooldown);

