		public virtual string Subtitle { get; protected set; }

		public string CooldownButtonText
		{
			get
			{
				if (workoutSettings?.WorkoutContainer?.WorkoutRunner?.CoolDown == null)
				{
					return Wolf.Core.Resources.AppStrings.in_workout_ble_end_workout;
				}
				return Wolf.Core.Resources.AppStrings.club_workout_warning_cool_down.ToUpper();
			}
		}

		public MaxWorkoutTimeWarningViewModel(ILocalSettings localSettings, ICurrentConsoleService currentConsoleService)
			: base(localSettings)
		{
			try
			{
				doneRunningSubscription = currentConsoleService.ActiveConsole?.WhenStateChanged.Where((StateChange change) => change.Current != ConsoleState.Workout).SubscribeWithErrorLogging(delegate
				{
					Close(this);
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			((BaseViewModel)this).Dispose();
			doneRunningSubscription?.Dispose();
			doneRunningSubscription = null;
			UnregisterChangeHandlers();
		}

		private void DoContinue()
		{
			Close(this);
		}

		private void DoCooldown()
		{
			Close(this);
			workoutSettings.WorkoutContainer?.WorkoutRunner?.FinishWorkout(completed: false);
		}

