				this.retailDemoLocalWorkoutService = retailDemoLocalWorkoutService;
				this.closedCaptionsSettings = closedCaptionsSettings;
				this.mockLiveWorkoutService = mockLiveWorkoutService;
				this.feedFmMuteDisablingService = feedFmMuteDisablingService;
