		private async Task PopulatePreferredLanguage()
		{
			if (!deviceInfo.IsBuiltIn || workoutId != null || programId != null)
			{
				await closedCaptionsSettings.GetPreferredLanguage();
			}
		}

		private async void OnGetPrefferedLanguageException(Exception ex)
		{
			if (ex.GetType() == typeof(iFit.Api.Support.ConnectivityException))
			{
				await OnError(Wolf.Core.Resources.AppStrings.start_workout_error, ErrorCode.StartingWorkoutFetchUserSettingsFailed, shouldUploadToAnalytics: true, workoutId).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public async Task Init(NavObject nav)
		{
			cachedNavObj = nav;
			workoutId = nav?.WorkoutId;
			programId = nav?.ProgramId;
			challengeId = nav?.ChallengeId;
			RunningContext = JsonConvert.DeserializeObject<WorkoutRunnerContext>(nav?.RunningContext);
			SetUpMockLiveWorkoutIfNecessary();
			analyticsSource = new AnalyticsSource(nav?.WorkoutSource ?? WorkoutSource.NA, nav?.DashboardIndex ?? (-1));
			if (currentConsoleService.Console is StrengthWorkoutEquipmentlessConsole)
			{
				currentConsoleService.Console.SetValue(FitnessValue.WorkoutMode, ConsoleState.WorkoutResults);
			}
			trackingService.IsLoadingWorkout = true;
			if (localSettings != null)
			{
				enteredPaused = currentConsoleService.ActiveConsole?.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Paused).Subscribe(delegate
				{
					EnteredPauseStateCancelling();
				});
				enteredIdle = currentConsoleService.ActiveConsole?.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Idle).Subscribe(delegate
				{
					EnteredIdleStateCancelling();
				});
			}
			necessaryToPromptForStartButtonPress = IsNecessaryToPromptForStartButtonPress();
			if (!featureFlagManager.GetBool(FeatureFlags.VideoHlsEnabled) && workoutSettings.VideoQuality == VideoQuality.Auto)
			{
				workoutVideoSpeedTestTask = workoutVideoSpeedTest.DetermineVideoQuality(speedTestCts.Token);
			}
			PopulatePreferredLanguage().SafeFireAndForget(continueOnCapturedContext: false, OnGetPrefferedLanguageException);
			mediaService.AdditionalInitializationForWorkout();
			if (feedFmMuteDisablingService?.IsEnabled ?? false)
			{
				feedFmMuteDisablingService.StartupFeedFmDisablingCheck();
			}
			skipLiabilityAcceptance = await CanSkipLiabilityAcceptance();
		}

		private void SetUpMockLiveWorkoutIfNecessary()
		{
			if (ShouldWorkoutSetUpAsMockLiveWorkout())
			{
				Log.Trace("Workout", "ShouldWorkoutSetUpAsMockLiveWorkout is true, setting up new workout runner context.");
				RunningContext = CreateMockLiveWorkoutRunnerContext();
			}
		}

		private bool ShouldWorkoutSetUpAsMockLiveWorkout()
		{
			WorkoutRunnerContext runningContext = RunningContext;
			if (runningContext != null && runningContext.Context == Workout.WorkoutContext.OnDemand && workoutId.HasValue())
			{
				return mockLiveWorkoutService?.IsMockedLiveWorkoutSet ?? false;
			}
			return false;
		}

		private WorkoutRunnerContext CreateMockLiveWorkoutRunnerContext()
		{
			return new WorkoutRunnerContext(Workout.WorkoutContext.ScheduledPre, new LiveWorkouts.WorkoutInfo
			{
				Id = mockLiveWorkoutService.MockedLiveWorkoutScheduleId,
				LiveStreamUrl = mockLiveWorkoutService.MockedLiveWorkoutStreamUrl,
				WorkoutId = workoutId,
				IsRerun = true
			});
		}

		private async Task<bool> CanSkipLiabilityAcceptance()
		{
			User user = await User.GetMe(ifitApi);
			int result;
			if (user != null && user.WarningAccepted.HasValue)
			{
				DateTime now = DateTime.Now;
				DateTime? obj = user?.WarningAccepted?.AddYears(1);
				result = ((now <= obj) ? 1 : 0);
			}
			else
			{
				result = 0;
			}
			return (byte)result != 0;
		}

		public override async Task OnViewShown()
		{
			try
			{
				await base.OnViewShown();
				if (base.viewShownCount > 1)
				{
					return;
				}
				if (cachedNavObj?.IsForegrounding ?? false)
				{
					await Task.Delay(8000);
				}
				CheckWorkoutCancelledByUser();
				await Task.Run(async delegate
				{
					await DoInitialWorkoutPrep();
				});
			}
			catch (Exception e)
			{
				await HandleExceptionDuringPrep(e, ErrorCode.ExceptionThrownInInitialWorkoutPrep);
			}
		}

		protected async Task DoInitialWorkoutPrep()
		{
			isMetric = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
			workoutVideo = null;
			mediaService?.Music?.ClearFeedFmMix();
			CheckWorkoutCancelledByUser();
			if (currentConsoleService.ActiveConsole != null)
			{
				currentConsoleService.ActiveConsole.StartKeyEnabled = true;
				if (currentConsoleService.ActiveConsole.ConsoleInfo?.MachineType.IsAerobicMachine() ?? false)
				{
					facadeFactoryDependencies.IdleModeLockoutFacade.SetIdleModeLockout(idleModeLockout: false);
				}
			}
			PreparingWorkoutViewModel preparingWorkoutViewModel = this;
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			preparingWorkoutViewModel.recovering = activeConsole != null && activeConsole.LatestBasicInfo?.IsInRecoverableWorkout() == true;
			IFitnessConsole activeConsole2 = currentConsoleService.ActiveConsole;
			bool flag = activeConsole2 != null && activeConsole2.ConsoleInfo?.SystemUnits == true;
			if (workoutId == null && recovering)
			{
				if (isMetric != flag)
				{
					isMetric = flag;
					await setUnitsService.SetUnits(flag);
				}
				CheckWorkoutCancelledByUser();
				WorkoutRecoveryInfo workoutRecoveryInfo = await recoveryStateManager.GetRecoveryInfo(currentConsoleService.ActiveConsole, ifitApi, featureFlagManager, setter, isMetric).ConfigureAwait(continueOnCapturedContext: false);
				if (workoutRecoveryInfo != null)
				{
					currentConsoleService.ActiveConsole?.ReinitializeFitnessValues(workoutRecoveryInfo.AddedTime, workoutRecoveryInfo.PausedTime);
					workoutId = workoutRecoveryInfo.WorkoutId;
					RunningContext = workoutRecoveryInfo.RunContext;
				}
				CheckWorkoutCancelledByUser();
			}
			else if (!deviceInfo.IsBuiltIn && isMetric != flag && !(currentConsoleService.Console is MockFitnessConsoleBase))
			{
				if (ShouldPromptUserForUnitSettingAgreement(currentConsoleService.ActiveConsole))
				{
					Log.Trace("Workout", $"System units out of sync between user and console. User Metric: {isMetric}, Console Metric: {flag}. Prompting to update.");
					bool flag2 = await PromptUserForUnitSettingAgreement().ConfigureAwait(continueOnCapturedContext: false);
					Log.Trace("Workout", "User has chosen " + (flag2 ? "Metric" : "Standard") + ".");
					isMetric = flag2;
					await setUnitsService.SetUnits(flag2);
					CheckWorkoutCancelledByUser();
				}
				else
				{
					Log.Trace("Workout", "System units out of sync between user and console, but console does not need user confirmation to update.");
					Log.Trace("Workout", $"Setting console's metric value to match user's: {isMetric}");
				}
			}
			if (string.IsNullOrEmpty(workoutId))
			{
				PreparingWorkoutViewModel preparingWorkoutViewModel2 = this;
				bool num = isMetric;
				double? runningTime = currentConsoleService.ActiveConsole?.LatestBasicInfo?.RunningTime;
				preparingWorkoutViewModel2.PreparedWorkout = Workout.ManualWorkout(num, null, runningTime);
			}
			else
			{
				try
				{
					IConsoleInfo consoleInfo = currentConsoleService.ActiveConsole?.ConsoleInfo;
					PreparedWorkout = await GetWorkout().ConfigureAwait(continueOnCapturedContext: false);
					if (PreparedWorkout == null)
					{
						await OnError(Wolf.Core.Resources.AppStrings.start_workout_error, ErrorCode.GetWorkoutFailed, shouldUploadToAnalytics: true, workoutId).ConfigureAwait(continueOnCapturedContext: false);
						return;
					}
					if (!PreparedWorkout.ShouldUseEquipmentlessConsole())
					{
						PreparedWorkout.RoundInclineControls();
						if (consoleInfo?.MachineType.IsAerobicMachine() ?? false)
						{
							PreparedWorkout.Controls = PreparedWorkout.ConvertRelativeResistanceControlsToResistance(consoleInfo);
						}
					}
					CheckWorkoutCancelledByUser();
				}
				catch (Exception)
				{
					Log.Trace("Workout", "Exception when getting workout");
					throw;
				}
			}
			if (mediaService?.Music != null)
			{
				await SetupFeedFmOrStockWorkoutMusic().ConfigureAwait(continueOnCapturedContext: false);
			}
			CheckWorkoutCancelledByUser();
			if (recovering || PreparedWorkout != null)
			{
				if ((PreparedWorkout?.IsVideoWorkout() ?? false) && currentConsoleService.ActiveConsole != null)
				{
					try
					{
						await LoadVideo().ConfigureAwait(continueOnCapturedContext: false);
						Task.Run(async delegate
						{
							await SendLoadTimeAnalytics().ConfigureAwait(continueOnCapturedContext: false);
						});
						ConsoleType? consoleType = currentConsoleService.ActiveConsole.ConsoleInfo?.MachineType;
						string consoleType2 = (consoleType.HasValue ? consoleType.ToString().ToLower() : string.Empty);
						if (!InRetailDemo)
						{
							await howlService.Retrieve(PreparedWorkout.WorkoutNotificationFilters, consoleType2, changeLanguageService.CurrentLanguageTwoLetterISOCode).ConfigureAwait(continueOnCapturedContext: false);
						}
					}
					catch (Exception e)
					{
						await HandleExceptionDuringPrep(e, ErrorCode.ExceptionThrownLoadingVideoWorkout);
						return;
					}
				}
				else
				{
					WorkoutRunnerContext runningContext = RunningContext;
					if (runningContext == null || runningContext.Context != Workout.WorkoutContext.OnDemand)
					{
						Log.Trace("Workout", "Oops. Tried to run a non-video workout as a live workout");
						await OnError(Wolf.Core.Resources.AppStrings.start_workout_error, ErrorCode.NonVideoNonLiveWorkoutWasAccidentallyScheduleAsLive, shouldUploadToAnalytics: true, workoutId).ConfigureAwait(continueOnCapturedContext: false);
						if (recovering)
						{
							Log.Trace("Workout", "The failed workout was a recoverable workout");
						}
						return;
					}
					Task.Run(async delegate
					{
						await SendLoadTimeAnalytics().ConfigureAwait(continueOnCapturedContext: false);
					});
					if (!skipLiabilityAcceptance)
					{
						await PromptForStartButtonPressBeforeWorkout().ConfigureAwait(continueOnCapturedContext: false);
					}
				}
			}
			if (skipLiabilityAcceptance)
			{
				await PromptForStartButtonPressBeforeWorkout();
			}
		}

		private async Task<Workout> GetWorkout(bool forceIfCached = false)
		{
			if (InRetailDemo)
			{
				Workout workoutForConsoleType = retailDemoLocalWorkoutService.GetWorkoutForConsoleType(currentConsoleService.PhysicalConsole.ConsoleInfo.MachineType);
				if (workoutForConsoleType != null)
				{
					return workoutForConsoleType;
				}
			}
			return await workoutApiService.Get(workoutId, forceIfCached).ConfigureAwait(continueOnCapturedContext: false);
		}

		protected virtual async Task<bool> PromptUserForUnitSettingAgreement()
		{
			bool shouldUseMetric = false;
			await Task.Delay(1000).ConfigureAwait(continueOnCapturedContext: false);
			await this.ShowSimpleConfirmationDialogAsync(Wolf.Core.Resources.AppStrings.conflicting_system_units.ToUpper(), Wolf.Core.Resources.AppStrings.conflicting_system_units_msg, delegate
			{
				shouldUseMetric = true;
			}, cancellableOperation: false, null, Wolf.Core.Resources.AppStrings.settings_unit_standard.ToUpper(), Wolf.Core.Resources.AppStrings.settings_unit_metric.ToUpper(), null, null, dismissible: false).ConfigureAwait(continueOnCapturedContext: false);
			return shouldUseMetric;
		}

		private static bool ShouldPromptUserForUnitSettingAgreement(IFitnessConsole console)
		{
			if (!(console is MockFitnessConsoleBase) && !console.IsNonconnectedConsole())
			{
				return !(console is IEquipmentlessConsole);
			}
			return false;
		}

		private async Task<bool> CheckIfPremiumUser()
		{
			try
			{
				User user = await ifitApi.RefreshCurrentlyAuthenticatedUser().ConfigureAwait(continueOnCapturedContext: false);
				if (user == null)
				{
					Log.Error("Api", "CheckIfPremiumUser called, but calling RefreshCurrentlyAuthenticatedUser returned null.");
				}
				return user != null && user.Premium == true;
			}
			catch (Exception exception)
			{
				Log.Error("Api", "CheckIfPremiumUser called, but calling RefreshCurrentlyAuthenticatedUser threw an exception.", exception);
			}
			return false;
		}

		private async Task SetupFeedFmOrStockWorkoutMusic()
		{
			if (InRetailDemo)
			{
				return;
			}
			bool isConnectedToInternet = await IsConnectedToInternet().ConfigureAwait(continueOnCapturedContext: false);
			Log.Trace("Audio", string.Format("{0}: {1}", "isConnectedToInternet", isConnectedToInternet));
			CheckWorkoutCancelledByUser();
			bool feedFmFeatureEnabled = feedFmAvailabilityService.IsFeedFmFeatureEnabledForWorkout(PreparedWorkout);
			Log.Trace("Audio", string.Format("{0}: {1}", "feedFmFeatureEnabled", feedFmFeatureEnabled));
			bool flag = await CheckIfPremiumUser().ConfigureAwait(continueOnCapturedContext: false);
			Log.Trace("Audio", string.Format("{0}: {1}", "premiumUser", flag));
			if (!(isConnectedToInternet && feedFmFeatureEnabled && flag))
			{
				Log.Trace("Audio", "canUseFeedFmMix is false, not calling SetFeedFmStationsForWorkoutIfAvailable");
				if (isConnectedToInternet && mediaService.Music.FeedFmStations == null && (PreparedWorkout?.IsVideoWorkout() ?? false))
				{
					Log.Trace("Audio", "Did not load FeedFM mix. Attempting to fetch legacy mix from API.");
					await mediaService.Music.FetchLegacyMix(workoutId).ConfigureAwait(continueOnCapturedContext: false);
					try
					{
						Log.Trace("Audio", "LegacyMix: " + ((mediaService.Music.LegacyMix == null) ? "null" : JsonConvert.SerializeObject(mediaService.Music.LegacyMix)));
						return;
					}
					catch (Exception ex)
					{
						Log.Error("Audio", "Tried to serialize LegacyMix while logging error, but " + ex.GetType().Name + " occurred.", ex);
						return;
					}
				}
				try
				{
					Log.Trace("Audio", "FetchLegacyMix not called.");
					Log.Trace("Audio", string.Format("{0}: {1}", "isConnectedToInternet", isConnectedToInternet));
					Log.Trace("Audio", "FeedFmStations: " + ((mediaService.Music.FeedFmStations == null) ? "null" : JsonConvert.SerializeObject(mediaService.Music.FeedFmStations)));
					Log.Trace("Audio", string.Format("{0}.IsVideoWorkout(): {1}", "PreparedWorkout", PreparedWorkout?.IsVideoWorkout() ?? false));
					return;
				}
				catch (Exception ex2)
				{
					Log.Error("Audio", ex2.GetType().Name + " occurred in DoInitialWorkoutPrep.", ex2);
					return;
				}
			}
			await mediaService.Music.SetFeedFmStationsForWorkoutIfAvailable(PreparedWorkout, RunningContext).ConfigureAwait(continueOnCapturedContext: false);
			if (mediaService.Music.FeedFmStations == null)
			{
				Log.Error("Audio", "SetFeedFmStationsForWorkoutIfAvailable returned null.");
			}
		}

		private async Task<bool> IsConnectedToInternet()
		{
			Log.Trace("Workout", "Calling TestIsInternetConnectedAndReachable to check for internet connectivity...");
			bool isConnectedToInternet = false;
			try
			{
				isConnectedToInternet = await TestIsInternetConnectedAndReachable().ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				Log.Error("Workout", ex.GetType().Name + " occurred while calling TestIsInternetConnectedAndReachable", ex);
			}
			Log.Trace("Workout", string.Format("{0}: {1}", "isConnectedToInternet", isConnectedToInternet));
			return isConnectedToInternet;
		}

		private async Task LoadVideo()
		{
			if (RunningContext == null)
			{
				throw new BaseWorkoutRunner.WorkoutStateException("Tried to load video without a WorkoutRunnerContext");
			}
			if (currentConsoleService.ActiveConsole != null)
			{
				currentConsoleService.ActiveConsole.PauseOverrideEnabled = true;
			}
			bool bufferVideo = true;
			WorkoutStationModel feedFmStations = mediaService.Music.FeedFmStations;
			string audioUrl = ((feedFmStations != null && feedFmStations.PrimarySpecialtyStation()?.IsFeedFm == true) ? null : (mediaService.Music.LegacyMix?.StreamUrl ?? PreparedWorkout?.GetWorkoutMetadataAudioUrl()));
			if ((developerSettings.IsOfflineVideoStorageEnabled || InRetailDemo) && RunningContext.Context == Workout.WorkoutContext.OnDemand)
			{
				bufferVideo = false;
				string cachedVideoPath;
				if (InRetailDemo)
				{
					cachedVideoPath = retailDemoLocalWorkoutService.GetWorkoutVideoFilePathForConsoleType(currentConsoleService.PhysicalConsole.ConsoleInfo.MachineType);
				}
				else
				{
					ShowVideoDownloadProgress.Value = true;
					whenVideoDownloadProgressChanged = videoDownloader.WhenDownloadProgressChanged.Subscribe(delegate(IDownloadUpdate x)
					{
						VideoDownloadProgress.Value = string.Format(Wolf.Core.Resources.AppStrings.downloading_video_percent, x.TotalPercentComplete);
						if (Mvx.TryResolve<ITouchMonitor>(out var service))
						{
							service.UpdateLastObservedTouch();
						}
					});
					cachedVideoPath = await videoDownloader.DownloadOrRetrieveCachedVodVideoPath(PreparedWorkout?.Id).ConfigureAwait(continueOnCapturedContext: false);
				}
				if (string.IsNullOrWhiteSpace(cachedVideoPath))
				{
					bufferVideo = true;
					ShowVideoDownloadProgress.Value = false;
				}
				else
				{
					if (InRetailDemo)
					{
						await Task.Delay(1000).ConfigureAwait(continueOnCapturedContext: false);
					}
					await videoService.LoadFromDirectSource(cachedVideoPath, audioUrl).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			CheckWorkoutCancelledByUser();
			ShowVideoDownloadProgress.Value = false;
			if (bufferVideo)
			{
				videoQualitySettings.ClearQualitySettings();
				try
				{
					if (!featureFlagManager.GetBool(FeatureFlags.VideoHlsEnabled) && base.workoutSettings.VideoQuality == VideoQuality.Auto)
					{
						Log.Info("Workout", "Waiting for result from workout video speed test");
						IWorkoutSettings workoutSettings = base.workoutSettings;
						workoutSettings.OptimizedVideoQuality = await workoutVideoSpeedTestTask;
						Log.Info("Workout", $"Optimized video quality is {base.workoutSettings.OptimizedVideoQuality}");
					}
				}
				catch (OperationCanceledException)
				{
				}
				if (RunningContext.Context != Workout.WorkoutContext.OnDemand)
				{
					await videoService.StartPrebufferingLiveVideo(RunningContext.ScheduleInfo.LiveStreamUrl, audioUrl).ConfigureAwait(continueOnCapturedContext: false);
				}
				else
				{
					string text = await (Mvx.Resolve<ITelevisionTunerService>()?.GetStreamUri()).ConfigureAwait(continueOnCapturedContext: false);
					if (text != null)
					{
						videoService.ShowCaptions = true;
						await videoService.StartPrebufferingLiveVideo(text).ConfigureAwait(continueOnCapturedContext: false);
					}
					else
					{
						videoService.ShowCaptions = false;
						workoutVideo = await WorkoutVideo.GetWorkoutVideo(ifitApi, PreparedWorkout?.Id, RunningContext.Context).ConfigureAwait(continueOnCapturedContext: false);
						if (workoutVideo != null)
						{
							await videoService.StartPrebufferingVodVideo(workoutVideo?.Sources?.HlsSource?.SourceUrl, audioUrl).ConfigureAwait(continueOnCapturedContext: false);
						}
						else
						{
							Log.Error("Workout", "Workout video was not loaded.");
						}
					}
				}
				CheckWorkoutCancelledByUser();
				videoSyncService.VideoSessionStarted();
			}
			if (!skipLiabilityAcceptance)
			{
				ShowVideoLayout.Value = true;
				ShowVideoLegalText.Value = true;
				ShowVideoLoadingText.Value = false;
				ShowNonVideoLayout.Value = false;
				ShowCancellingLayout.Value = false;
			}
			if (InRetailDemo)
			{
				demoModeLegalDisclaimerAutoCancelTimerSub?.Dispose();
				Log.Trace("Workout", string.Format("{0} is {1}, creating legal disclaimer idle timeout subscriber.", "InRetailDemo", InRetailDemo));
				demoModeLegalDisclaimerAutoCancelTimerSub = Observable.Timer(TimeSpan.FromMinutes(2.0)).Take(1).SubscribeWithErrorLogging(delegate
				{
					HandleDemoModeAutoCancelTimeout();
				});
			}
		}

		private void HandleDemoModeAutoCancelTimeout()
		{
			demoModeLegalDisclaimerAutoCancelTimerSub?.Dispose();
			demoModeLegalDisclaimerAutoCancelTimerSub = null;
			if (!isDisposed && !isPrepComplete && ShowVideoLegalText.Value)
			{
				Log.Trace("Workout", "Legal disclaimer idle timeout occurred. Auto-cancelling workout...");
				GoBack.Execute(null);
			}
		}

		private async Task SendLoadTimeAnalytics()
		{
			TimedEvent timedEvent = await EventService.Instance.FetchEvent("Start Workout To Accept Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null)
			{
				EventService.Instance.AddWorkoutProperties(timedEvent, PreparedWorkout);
				await EventService.Instance.LogAsync(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		protected override void OnViewHidden()
		{
			trackingService.IsLoadingWorkout = false;
			base.OnViewHidden();
		}

		protected async Task OnAcceptLegalButtonPressed()
		{
			demoModeLegalDisclaimerAutoCancelTimerSub?.Dispose();
			demoModeLegalDisclaimerAutoCancelTimerSub = null;
			try
			{
				await Task.Run(async delegate
				{
					try
					{
						await UpdateWarningAccepted();
					}
					catch (Exception ex)
					{
						Log.Error("Workout", "An error occured attempting UpdateWarningAccepted: " + ex.Message);
					}
					await PromptForStartButtonPressBeforeWorkout();
				});
			}
			catch (Exception e)
			{
				await HandleExceptionDuringPrep(e, ErrorCode.ExceptionThrownOnStartButtonPrompt);
			}
		}

		private async Task PromptForStartButtonPressBeforeWorkout()
		{
			IWifiService obj = wifiService;
			bool flag = obj == null || obj.NetworkState != WifiNetworkState.Connected || (featureFlagManager?.IsFeatureEnabled(FeatureFlags.RestrictUnsafeTreadmillWorkouts) ?? true);
			if (necessaryToPromptForStartButtonPress && currentConsoleService.ActiveConsole.ChangeManager == null)
			{
				Log.Error("Workout", "WhenKeyCodeObserved observable in console's change manager is null.");
				if (flag)
				{
