		private async Task OnConsoleStartKeyPressed()
		{
			startKeyCodeSub?.Dispose();
			startKeyCodeSub = null;
			ShowPressStartButton.Value = false;
			if (!(await CheckForAndShowConnectionError().ConfigureAwait(continueOnCapturedContext: false)))
			{
				CheckWorkoutCancelledByUser();
				if (isAwaitingStartButtonPrompt && !isCancelled)
				{
					isAwaitingStartButtonPrompt = false;
					Log.Trace("Workout", "Workout starting. User pressed the treadmill start button.");
					await StartWorkout();
				}
			}
		}

		private async Task<bool> CheckForAndShowConnectionError()
		{
			if (PreparedWorkout.IsManual() || InRetailDemo)
			{
				return false;
			}
			if (!connectivity.IsConnected)
			{
				Log.Trace("Workout", "Failed to start workout, no internet.");
				await OnError(Wolf.Core.Resources.AppStrings.internet_connection_error_try_again, ErrorCode.NoInternetConnectionWhileStartingWorkout, shouldUploadToAnalytics: false).ConfigureAwait(continueOnCapturedContext: false);
				return true;
			}
			return false;
		}

		private bool IsNecessaryToPromptForStartButtonPress()
		{
			return !deviceInfo.IsBuiltIn && currentConsoleService.ActiveConsole?.ConsoleInfo != null && currentConsoleService.ActiveConsole.ConsoleInfo.MachineType.IsBeltBasedMachine() && !currentConsoleService.ActiveConsole.IsMock() && !workoutSettings.OverrideRequireStart && !equipmentlessConsoleService.EquipmentlessConsoleOverrideEnabled;
		}

