		private async void OnPrepComplete(MvxBundle presentationBundle)
		{
			ShowViewModel<InWorkoutViewModel>((IMvxBundle)null, (IMvxBundle)presentationBundle, (MvxRequestedBy)null);
			await Task.Run(delegate
			{
				DoClose();
			});
		}

		private void DisconnectIfBleMachine()
		{
			if (!deviceInfo.IsBuiltIn && Mvx.TryResolve<IBleConsoleService>(out var service))
			{
				Log.Error("Ble", "Disconnecting BLE device after workout start timeout");
				service?.DisconnectImmediate(forgetDevice: false);
			}
		}

		private void CheckWorkoutCancelledByUser()
		{
			if (isCancellingByBackButton)
			{
				throw new TaskCanceledException("Workout cancelled by user pressing back button");
			}
			if (isCancellingByBackgrounding)
			{
				throw new TaskCanceledException("Workout cancelled by user backgrounding app");
			}
		}

		private async Task HandleExceptionDuringPrep(Exception e, ErrorCode errorCode)
		{
			string text = "Exception while preparing workout: " + e.Message;
			string start_workout_error = Wolf.Core.Resources.AppStrings.start_workout_error;
			if (isCancellingByBackButton || isCancellingByBackgrounding)
			{
				Log.Trace("Workout", text);
				return;
			}
			Log.Fatal("Workout", "Unknown error starting workout", e);
			await OnError(start_workout_error, errorCode, shouldUploadToAnalytics: true, workoutId, e).ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task DoBackClose()
		{
			lock (loadingCancelledLock)
			{
				if (isCancelled || isPrepComplete)
				{
					Log.Trace("Workout", "Ignoring back button press. Workout already cancelled or prep is complete");
					return;
				}
				isCancellingByBackButton = true;
			}
			Log.Trace("Workout", "Back button pressed to cancel workout");
			await CleanUpWorkoutAndVideo();
			await WaitForConsoleStoppingBeforeClosing();
			deviceInfo.UseHeadlessBikeTheme = false;
		}

		private async Task WaitForConsoleStoppingBeforeClosing()
		{
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			ConsoleState currentState = activeConsole?.LatestBasicInfo?.CurrentState ?? ConsoleState.Idle;
			if (activeConsole == null || activeConsole is IEquipmentlessConsole || currentState == ConsoleState.Idle || currentState == ConsoleState.WorkoutResults || (deviceInfo.IsStrengthMirror && (!deviceInfo.IsHeadlessBikeVault || !currentConsoleService.IsAttachedConsoleActive)))
			{
				videoSyncService?.VideoSessionCleanup();
				CloseToDashboard();
				return;
			}
			if (currentState == ConsoleState.Paused)
			{
				videoSyncService?.VideoSessionStopped();
				await ConsoleStateAwaiterFactory.Builder().FromCurrentState(ConsoleState.Idle).AfterConsoleCommand(async delegate
				{
					IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
					await workoutFacade.EndWorkoutAsync();
				})
					.WithSkipCondition(currentState != ConsoleState.Idle && currentState != ConsoleState.WorkoutResults)
					.Run()
					.ConfigureAwait(continueOnCapturedContext: false);
				CloseToDashboard();
				return;
			}
			videoSyncService?.VideoSessionStopped();
			await ConsoleStateAwaiterFactory.Builder().FromCurrentState(ConsoleState.Paused).AfterConsoleCommand(delegate
			{
				IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
				workoutFacade.PauseWorkout();
			})
				.WithSkipCondition(currentState != ConsoleState.Paused)
				.Run()
				.ConfigureAwait(continueOnCapturedContext: false);
			await ConsoleStateAwaiterFactory.Builder().FromCurrentState(ConsoleState.Idle).AfterConsoleCommand(async delegate
			{
				IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
				await workoutFacade.EndWorkoutAsync();
			})
				.WithSkipCondition(currentState != ConsoleState.Idle && currentState != ConsoleState.WorkoutResults)
				.Run()
				.ConfigureAwait(continueOnCapturedContext: false);
			CloseToDashboard();
		}

		private void EnteredPauseStateCancelling()
		{
			if (!isDisposed)
			{
				Log.Trace("Workout", "PreparingWorkoutViewModel was paused, stopping workout.");
				if (isCancellingByBackButton && Mvx.TryResolve<IWolfAnalytics>(out var service))
				{
					service.EndedWorkoutWithLoadingWorkoutBackButton();
				}
				SetupUIcancelling();
				IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
				workoutFacade.EndWorkoutAsync();
			}
		}

		private void EnteredIdleStateCancelling()
		{
			CloseToDashboard();
		}

		private void SetupUIcancelling()
		{
			ShowVideoLayout.Value = false;
			ShowVideoLegalText.Value = false;
			ShowVideoLoadingText.Value = false;
			ShowNonVideoLayout.Value = false;
			ShowCancellingLayout.Value = true;
		}

		private async Task OnError(string error, ErrorCode errorCode, bool shouldUploadToAnalytics, string workoutId = null, Exception exception = null)
		{
			bool flag = false;
			lock (loadingCancelledLock)
			{
				if (isCancellingByBackButton || isCancellingByBackgrounding)
				{
					Log.Trace("Workout", "Ignoring error, workout already cancelled");
					return;
				}
				isCancellingByError = true;
				flag = isPrepComplete;
				isPrepComplete = false;
				DisposePausedAndIdleListeners();
			}
			IFitnessConsole console = currentConsoleService.ActiveConsole;
			if (flag)
			{
				if (console == null || console.LatestBasicInfo.CurrentState != ConsoleState.Paused)
				{
					if (console != null && console.LatestBasicInfo.CurrentState == ConsoleState.Idle)
					{
						Log.Trace("Workout", $"Error occurred in final workout prep stages. Waiting {3} seconds " + $"to allow console state to change from {console?.LatestBasicInfo?.CurrentState} before cancelling");
						await Task.Delay(TimeSpan.FromSeconds(3.0));
					}
					Log.Trace("Workout", $"Continuing OnError() call to pause workout... Current console state = {console?.LatestBasicInfo.CurrentState}");
					if (console?.LatestBasicInfo != null && console.LatestBasicInfo.CurrentState != ConsoleState.Idle && console.LatestBasicInfo.CurrentState != ConsoleState.Paused)
					{
						IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
						workoutFacade.PauseWorkout();
					}
				}
			}
			await CleanUpWorkoutAndVideo();
			if (shouldUploadToAnalytics)
			{
				await wolfAnalytics.FailedToStartWorkout(errorCode, workoutId, exception);
			}
			lock (loadingCancelledLock)
			{
				if (isCancellingByBackgrounding)
				{
					Log.Trace("Workout", "App backgrounded before error message shown, will try again when foregrounded.");
					return;
				}
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, error, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok, (Action)CloseToDashboard, (Action)null, false, true, "", (TaskCompletionSource<object>)null, errorCode.HumanReadable(), true, true);
				errorDialogShown = true;
			}
		}

		private async Task CleanUpWorkoutAndVideo()
		{
			SetupUIcancelling();
			DisposeWorkoutStarted();
			speedTestCts?.Cancel();
			videoService?.Cleanup();
			videoSyncService?.VideoSessionStopped();
			workoutVideoSpeedTestResultSub?.Dispose();
			workoutVideoSpeedTestResultSub = null;
			base.StartWorkoutService.CancelWorkoutPreparations();
			mediaService?.Music?.ClearFeedFmMix();
			mockLiveWorkoutService?.ClearMockedLiveWorkoutSettings();
			startKeyCodeSub?.Dispose();
			startKeyCodeSub = null;
			PreparedWorkout?.Dispose();
			PreparedWorkout = null;
			await CleanUpWorkoutContainer();
			equipmentlessConsoleService?.CleanUpConsole();
			await recoveryStateManager.ClearRecoveryInfo();
		}

		private async Task CleanUpWorkoutContainer()
		{
			if (localSettings == null)
			{
				return;
			}
			try
			{
				if (workoutSettings.WorkoutContainer?.WorkoutRunner != null)
				{
					await workoutSettings.WorkoutContainer.WorkoutRunner.FinishWorkout(completed: false).ConfigureAwait(continueOnCapturedContext: false);
				}
				IWorkoutRunner workoutRunner = workoutSettings.WorkoutContainer?.WorkoutRunner;
				if (workoutRunner != null)
				{
					await workoutRunner.StopAsync();
				}
			}
			catch (Exception arg)
			{
				Log.Error("Workout", $"Exception occurred while cleaning up workout runner: {arg}");
			}
			workoutSettings.ClearAndDisposeWorkoutContainer();
		}

		public void OnAppBackgrounded()
		{
			lock (loadingCancelledLock)
			{
				if (isCancellingByBackgrounding)
				{
					Log.Trace("Workout", "Received app backgrounded event notification multiple times. Ignoring this time.");
					return;
				}
				if (isCancellingByBackButton)
				{
					Log.Trace("Workout", "App backgrounded but user already cancelled workout. Ignoring backgrounding");
					return;
				}
				if (isPrepComplete)
				{
					Log.Trace("Workout", "App backgrounded but workout prep already completed. Ignoring backgrounding.");
					return;
				}
				isCancellingByBackgrounding = true;
				if (isCancellingByError)
				{
					Log.Trace("Workout", "App backgrounded but error occurred during prep. Ignoring backgrounding.");
					return;
				}
				PreparedWorkout?.Dispose();
				PreparedWorkout = null;
				Log.Trace("Workout", "User backgrounded app while preparing workout. Stopping workout preparations for " + workoutId);
			}
			videoService?.Cleanup();
			videoSyncService?.VideoSessionStopped();
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
			ConsoleState? consoleState = activeConsole?.LatestBasicInfo?.CurrentState;
			if (consoleState == ConsoleState.Paused)
			{
				workoutFacade.EndWorkoutAsync();
			}
			else if (consoleState == ConsoleState.WarmUp)
			{
				workoutFacade.PauseWorkout();
			}
			DisposeWorkoutStarted();
		}

		public async Task<bool> OnAppForegrounded()
		{
			Task task = null;
			lock (loadingCancelledLock)
			{
				if (isPrepComplete)
				{
					Log.Warn("Workout", "App foregrounded on preparing workout but prep is already complete, not restarting prep.");
					return false;
				}
				if (isCancellingByBackButton)
				{
					Log.Trace("Workout", "App foregrounded on preparing workout but prep is already cancelled by back button, not restarting prep.");
					return false;
				}
				if (isCancellingByError)
				{
					Log.Trace("Workout", "App foregrounded on preparing workout but error occurred during prep, not restarting prep");
					if (errorDialogShown)
					{
						return false;
					}
					isCancellingByBackgrounding = false;
					task = Task.Run(async delegate
					{
						await OnError(Wolf.Core.Resources.AppStrings.start_workout_error, ErrorCode.AppWasBackgroundedAsErrorOccurred, shouldUploadToAnalytics: true, workoutId);
					});
				}
			}
			if (task != null)
			{
				await task;
				return false;
			}
			if (cachedNavObj != null)
			{
				Log.Trace("Workout", "App foregrounded on preparing workout. Restarting workout preparations for " + workoutId);
				cachedNavObj.IsForegrounding = true;
				ShowViewModel<PreparingWorkoutViewModel>(cachedNavObj);
				return true;
			}
			Log.Error("Workout", "App foregrounded on preparing workout but no cached navigation object, unable to continue prep.");
			await OnError(Wolf.Core.Resources.AppStrings.start_workout_error, ErrorCode.NoCachedNavigationObject, shouldUploadToAnalytics: true, workoutId);
			return false;
		}

		private void DisposeWorkoutStarted()
		{
			workoutStarted?.Dispose();
			workoutStarted = null;
			startKeyCodeSub?.Dispose();
			startKeyCodeSub = null;
		}

		private void DisposePausedAndIdleListeners()
		{
			Log.Trace("Workout", "Cleaning up PreparingWorkoutViewModel for " + (workoutId ?? "<null workout id>"));
			whenVideoDownloadProgressChanged?.Dispose();
			whenVideoDownloadProgressChanged = null;
			enteredPaused?.Dispose();
			enteredPaused = null;
			enteredIdle?.Dispose();
			enteredIdle = null;
			demoModeLegalDisclaimerAutoCancelTimerSub?.Dispose();
			demoModeLegalDisclaimerAutoCancelTimerSub = null;
		}

		private void CleanUp()
		{
			whenVideoDownloadProgressChanged?.Dispose();
			whenVideoDownloadProgressChanged = null;
			DisposePausedAndIdleListeners();
			DisposeWorkoutStarted();
		}

		protected override void DoClose()
		{
			Log.Trace("Workout", "Calling DoClose in PreparingWorkoutViewModel for " + (workoutId ?? "<null workout id>"));
			if (hasClosed)
			{
				Log.Trace("Workout", "PreparingWorkoutViewModel has already been closed, exiting");
				return;
			}
			hasClosed = true;
			CleanUp();
			base.DoClose();
		}

		private void CloseToDashboard()
		{
			if (!isGoingBackToDashboard)
			{
				isGoingBackToDashboard = true;
				if (InRetailDemo)
				{
					GoToRetailDemoModeScreensaverIfInDemoMode(showScreensaver: false);
					DoClose();
				}
				else
				{
					NavigateToDashboardViewModel();
				}
			}
		}

