	public class FullScreenGesture : WidgetGesture
	{
		private bool enterFullScreen;

		private new WidgetManager widgetManager;

		public FullScreenGesture(List<IWidgetAnimator> animators, PointF start, WidgetManager widgetManager, bool enterFullScreen)
			: base(animators, ScreenArea.Middle, start, widgetManager)
		{
			this.widgetManager = widgetManager;
			this.enterFullScreen = enterFullScreen;
		}

		protected override SwipeDirection DetermineValidSwipeDirection()
		{
			if (enterFullScreen)
			{
				return SwipeDirection.Up;
			}
			return SwipeDirection.Down;
		}

		protected override void CompleteOrCancelGesture(bool completeGesture)
		{
			if (completeGesture)
			{
				widgetManager.ToggleFullScreen.Execute(null);
				return;
			}
			foreach (IWidgetAnimator widget in base.widgets)
			{
				widget.CancelMove();
			}
		}
	}
