	public enum SwipeDirection
	{
		NotFarEnough,
		Left,
		Right,
		Both,
		Up,
		Down,
		None
	}
	public class WidgetGesture
	{
		protected List<IWidgetAnimator> widgets { get; }

		private ScreenArea area { get; set; }

		private PointF start { get; set; }

		private SwipeDirection validSwipeDirection { get; set; }

		private SwipeDirection initialSwipeDirection { get; set; }

		protected WidgetManager widgetManager { get; set; }

		public WidgetGesture(List<IWidgetAnimator> animators, ScreenArea area, PointF start, WidgetManager widgetManager)
		{
			widgets = animators;
			this.area = area;
			this.start = start;
			this.widgetManager = widgetManager;
			initialSwipeDirection = SwipeDirection.NotFarEnough;
			validSwipeDirection = SwipeDirection.NotFarEnough;
		}

		protected virtual SwipeDirection DetermineValidSwipeDirection()
		{
			SwipeDirection result = SwipeDirection.None;
			if (widgets.Count == 1)
			{
				IWidgetAnimator widgetAnimator = widgets[0];
				if (widgetAnimator.State == WidgetState.On)
				{
					if (area == ScreenArea.LeftSide)
					{
						result = SwipeDirection.Left;
					}
					else if (area == ScreenArea.RightSide)
					{
						result = SwipeDirection.Right;
					}
				}
				else if (area == ScreenArea.LeftSide)
				{
					result = SwipeDirection.Right;
				}
				else if (area == ScreenArea.RightSide)
				{
					result = SwipeDirection.Left;
				}
			}
			else if (widgets.Count > 1)
			{
				if (area == ScreenArea.LeftSide)
				{
					result = SwipeDirection.Left;
				}
				else if (area == ScreenArea.RightSide)
				{
					result = SwipeDirection.Right;
				}
				foreach (IWidgetAnimator widget in widgets)
				{
					if (widget.CanSwipeOn && widget.State == WidgetState.Off)
					{
						result = SwipeDirection.Both;
					}
				}
			}
			return result;
		}

		public static SwipeDirection GetSwipeDirection(PointF start, PointF newPoint)
		{
			int num = 5;
			float num2 = newPoint.X - start.X;
			float num3 = newPoint.Y - start.Y;
			double num4 = Math.Sqrt(num2 * num2 + num3 * num3);
			if (num4 < (double)num)
			{
				return SwipeDirection.NotFarEnough;
			}
			float num5 = Math.Abs(num2);
			float num6 = Math.Abs(num3);
			if (num5 > num6)
			{
				if (num2 > 0f)
				{
					return SwipeDirection.Right;
				}
				return SwipeDirection.Left;
			}
			if (num3 > 0f)
			{
				return SwipeDirection.Down;
			}
			return SwipeDirection.Up;
		}

		private void ValidateInitialSwipeDirection(PointF newLocation)
		{
			initialSwipeDirection = GetSwipeDirection(start, newLocation);
			if (initialSwipeDirection != SwipeDirection.NotFarEnough)
			{
				if (validSwipeDirection == initialSwipeDirection || (validSwipeDirection == SwipeDirection.Both && (initialSwipeDirection == SwipeDirection.Left || initialSwipeDirection == SwipeDirection.Right)))
				{
					validSwipeDirection = initialSwipeDirection;
				}
				else
				{
					validSwipeDirection = SwipeDirection.None;
				}
			}
		}

		protected bool IsSwipeDirectionValid()
		{
			if (initialSwipeDirection != SwipeDirection.NotFarEnough)
			{
				return validSwipeDirection != SwipeDirection.None;
			}
			return false;
		}

		public bool GestureChanged(PointF newLocation)
		{
			if (validSwipeDirection == SwipeDirection.NotFarEnough)
			{
				validSwipeDirection = DetermineValidSwipeDirection();
			}
			if (initialSwipeDirection == SwipeDirection.NotFarEnough)
			{
				ValidateInitialSwipeDirection(newLocation);
			}
			if (!IsSwipeDirectionValid())
			{
				return false;
			}
			if (GetSwipeDirection(start, newLocation) == validSwipeDirection)
			{
				float offset = Math.Abs(newLocation.X - start.X);
				if (validSwipeDirection == SwipeDirection.Up || validSwipeDirection == SwipeDirection.Down)
				{
					offset = Math.Abs(newLocation.Y - start.Y);
				}
				foreach (IWidgetAnimator widget in widgets)
				{
					widget.DragTo(offset);
				}
				return true;
			}
			return false;
		}

		public void GestureEnded(PointF endLocation)
		{
			if (IsSwipeDirectionValid() && (area != ScreenArea.RightSide || validSwipeDirection != SwipeDirection.Left || !widgetManager.IsFullScreen.Value))
			{
				bool flag = GetSwipeDirection(start, endLocation) == validSwipeDirection;
				float num = Math.Abs(endLocation.X - start.X);
				if (validSwipeDirection == SwipeDirection.Up || validSwipeDirection == SwipeDirection.Down)
				{
					num = Math.Abs(endLocation.Y - start.Y);
				}
				bool completeGesture = flag && num > 50f;
				CompleteOrCancelGesture(completeGesture);
			}
		}

		protected virtual void CompleteOrCancelGesture(bool completeGesture)
		{
			foreach (IWidgetAnimator widget in widgets)
			{
				if (completeGesture)
				{
					widget.CompleteMove();
				}
				else
				{
					widget.CancelMove();
				}
			}
		}
	}
	public enum ScreenArea
	{
		LeftSide,
		RightSide,
		Middle,
		Header,
		None
	}
	public class WidgetManager : IDisposable
	{
		private readonly Dictionary<WidgetType, IWidgetAnimator> widgetAnimators = new Dictionary<WidgetType, IWidgetAnimator>();

		private readonly List<IWidgetAnimator> notificationAnimators = new List<IWidgetAnimator>();

		private IWidgetAnimator savedWidgetFromHide;

		private IDisposable subLeaderboardOnVisible;

		private IDisposable subHRTargetOnVisible;

		private IDisposable subHRMyZonesOnVisible;

		private IDisposable subLeftSliderVisible;

		private IDisposable subRightSliderVisible;

		private IDisposable subConstantWattsOnVisible;

		private IDisposable subOnStateChange;

		private const float SwipeExtraArea = 104f;

		private bool inCooldown;

		private ConsoleState consoleState;

		public readonly INC<bool> IsFullScreen = new NC<bool>(value: false);

		public readonly INC<bool> CanToggleWorkoutControls = new NC<bool>(value: true);

		public readonly INC<bool> WorkoutControlsVisible = new NC<bool>(value: false);

		public readonly INC<bool> IsHRWidgetVisible = new NC<bool>(value: false);

		public readonly INC<bool> IsLeaderboardVisible = new NC<bool>(value: false);

		public readonly INC<bool> IsConstantWattsVisible = new NC<bool>(value: false);

		public readonly INC<WidgetType> LastVisibleRightWidgetBeforeEnteringFullscreen = new NC<WidgetType>(WidgetType.RightSlider);

		private readonly ILeaderboardAnalyticTracker leaderboardAnalytics;

		private readonly ILocalSettings localSettings;

		private readonly IInAppNotificationService inAppNotificationService;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IWolfAnalytics analytics;

		private readonly IWorkoutChangeLevel workoutChangeLevel;

		private readonly Subject<bool> _leftSideWidgetVisible = new Subject<bool>();

		private IWidgetAnimator ActiveHRWidget { get; set; }

		public ICommand ToggleFullScreen => new MvxCommand(DoToggleFullScreen);

		public ICommand ToggleWorkoutControls => new MvxCommand(DoToggleWorkoutControls);

		public ICommand ShowHeartRateWidget => new MvxCommand(DoShowHeartRateWidget);

		public IObservable<bool> LeftSideWidgetVisible => _leftSideWidgetVisible;

		public bool PauseNotificationsOnHRToggle { get; set; }

		public bool HRWidgetVisible
		{
			get
			{
				if (ActiveHRWidget == null)
				{
					return false;
				}
				return ActiveHRWidget.Visible;
			}
		}

		public bool LeaderboardVisible
		{
			get
			{
				widgetAnimators.TryGetValue(WidgetType.Leaderboard, out var value);
				return value?.Visible ?? false;
			}
		}

		private bool AreWorkoutControlsVisible
		{
			get
			{
				widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var value);
				widgetAnimators.TryGetValue(WidgetType.RightSlider, out var value2);
				if (value != null && value.Visible)
				{
					return true;
				}
				if (value2 != null && value2.Visible)
				{
					return true;
				}
				return false;
			}
		}

		public WidgetManager(ILeaderboardAnalyticTracker leaderboardAnalytics, ILocalSettings localSettings, IInAppNotificationService inAppNotificationService, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IWolfAnalytics analytics, IWorkoutChangeLevel workoutChangeLevel)
		{
			this.leaderboardAnalytics = leaderboardAnalytics;
			this.localSettings = localSettings;
			this.inAppNotificationService = inAppNotificationService;
			this.workoutSettings = workoutSettings;
			this.analytics = analytics;
			this.workoutChangeLevel = workoutChangeLevel;
			subOnStateChange = currentConsoleService.ActiveConsole?.WhenStateChanged.Subscribe(OnStateChange);
			INC<bool> canToggleWorkoutControls = CanToggleWorkoutControls;
			int value;
			if (!IsFullScreen.Value)
			{
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				value = ((workoutContainer == null || !workoutContainer.IsInEquipmentlessWorkout) ? 1 : 0);
			}
			else
			{
				value = 0;
			}
			canToggleWorkoutControls.Value = (byte)value != 0;
		}

		public void RestoreLeftSideWidget()
		{
			if (inCooldown || savedWidgetFromHide == null)
			{
				return;
			}
			if (IsFullScreen.Value)
			{
				savedWidgetFromHide.MoveTo(WidgetState.OffDuringFullScreen);
				return;
			}
			widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var value);
			if ((value == null || value.State != WidgetState.On) && (ActiveHRWidget == null || ActiveHRWidget.State != WidgetState.On) && (ActiveHRWidget == null || !ActiveHRWidget.Visible))
			{
				savedWidgetFromHide.MoveTo(WidgetState.On);
				savedWidgetFromHide = null;
			}
		}

		public void HideLeftSideWidget()
		{
			if (!inCooldown)
			{
				if (widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var value) && value.State == WidgetState.On)
				{
					savedWidgetFromHide = value;
					savedWidgetFromHide.MoveTo(WidgetState.Off);
				}
				else if (ActiveHRWidget != null && ActiveHRWidget.State == WidgetState.On)
				{
					savedWidgetFromHide = ActiveHRWidget;
					savedWidgetFromHide.MoveTo(WidgetState.Off);
				}
			}
		}

		public bool Contains(WidgetType type)
		{
			return widgetAnimators?.ContainsKey(type) ?? false;
		}

		public void Add(WidgetType type, IWidgetAnimator animator)
		{
			if (type == WidgetType.Notification)
			{
				notificationAnimators.Add(animator);
			}
			else if (widgetAnimators.ContainsKey(type))
			{
				widgetAnimators[type] = animator;
			}
			else
			{
				widgetAnimators.Add(type, animator);
			}
			switch (type)
			{
			case WidgetType.Leaderboard:
				subLeaderboardOnVisible?.Dispose();
				subLeaderboardOnVisible = animator.OnVisible.Subscribe(OnLeaderboardVisibilityChange);
				break;
			case WidgetType.HRTarget:
				ActiveHRWidget = GetAnimatorForType(WidgetType.HRTarget);
				subHRTargetOnVisible?.Dispose();
				subHRTargetOnVisible = animator.OnVisible.Subscribe(OnHRVisibilityChange);
				break;
			case WidgetType.HRMyZones:
				subHRMyZonesOnVisible?.Dispose();
				subHRMyZonesOnVisible = animator.OnVisible.Subscribe(OnHRVisibilityChange);
				break;
			case WidgetType.LeftSlider:
				subLeftSliderVisible?.Dispose();
				subLeftSliderVisible = animator.OnVisible.Subscribe(OnLeftSliderVisibilityChange);
				break;
			case WidgetType.RightSlider:
				WorkoutControlsVisible.Value = AreWorkoutControlsVisible;
				subRightSliderVisible?.Dispose();
				subRightSliderVisible = animator.OnVisible.Subscribe(OnRightSliderVisibilityChange);
				break;
			case WidgetType.ConstantWatts:
				subConstantWattsOnVisible?.Dispose();
				subConstantWattsOnVisible = animator.OnVisible.Subscribe(OnConstantWattsVisibilityChange);
				break;
			}
		}

		public void OnStateChange(StateChange stateChange)
		{
			consoleState = stateChange.Current;
			if (consoleState == ConsoleState.CoolDown || consoleState == ConsoleState.WorkoutResults)
			{
				DestroyWidgetsForCooldown();
			}
			if ((consoleState == ConsoleState.WarmUp || consoleState == ConsoleState.Workout || consoleState == ConsoleState.CoolDown) && AreWorkoutControlsVisible)
			{
				workoutChangeLevel?.UserToggledSoftwareControls(isVisible: true);
			}
		}

		public void DestroyWidgetsForCooldown()
		{
			inCooldown = true;
			ActiveHRWidget = null;
			savedWidgetFromHide = null;
			if (consoleState == ConsoleState.WorkoutResults)
			{
				inAppNotificationService.DismissAll();
			}
			widgetAnimators.TryGetValue(WidgetType.Leaderboard, out var value);
			if (value != null)
			{
				subLeaderboardOnVisible?.Dispose();
				subLeaderboardOnVisible = null;
				value.MoveTo(WidgetState.OffAndDestroy);
				widgetAnimators.Remove(WidgetType.Leaderboard);
			}
			widgetAnimators.TryGetValue(WidgetType.ConstantWatts, out var value2);
			if (value2 != null)
			{
				subConstantWattsOnVisible?.Dispose();
				subConstantWattsOnVisible = null;
				value2.MoveTo(WidgetState.OffAndDestroy);
				widgetAnimators.Remove(WidgetType.ConstantWatts);
			}
			widgetAnimators.TryGetValue(WidgetType.HRTarget, out var value3);
			if (value3 != null)
			{
				subHRTargetOnVisible?.Dispose();
				subHRTargetOnVisible = null;
				value3.MoveTo(WidgetState.OffAndDestroy);
				widgetAnimators.Remove(WidgetType.HRTarget);
			}
			widgetAnimators.TryGetValue(WidgetType.HRMyZones, out var value4);
			if (value4 != null)
			{
				subHRMyZonesOnVisible?.Dispose();
				subHRMyZonesOnVisible = null;
				value4.MoveTo(WidgetState.OffAndDestroy);
				widgetAnimators.Remove(WidgetType.HRMyZones);
			}
			if (workoutSettings.ShowSliders && !IsFullScreen.Value)
			{
				widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var value5);
				widgetAnimators.TryGetValue(WidgetType.RightSlider, out var value6);
				if (value5 != null && !value5.Visible && consoleState != ConsoleState.WorkoutResults)
				{
