		public void Remove(IWidgetAnimator animator)
		{
			List<IWidgetAnimator> list = notificationAnimators;
			if (list != null && list.Contains(animator))
			{
				notificationAnimators.Remove(animator);
			}
			Dictionary<WidgetType, IWidgetAnimator> dictionary = widgetAnimators;
			if (dictionary != null && dictionary.Any((KeyValuePair<WidgetType, IWidgetAnimator> kvp) => kvp.Value == animator))
			{
				WidgetType key = widgetAnimators.First((KeyValuePair<WidgetType, IWidgetAnimator> kvp) => kvp.Value == animator).Key;
				widgetAnimators.Remove(key);
			}
		}

		public void SetActiveHRwidget(WidgetType widgetType)
		{
			IWidgetAnimator animatorForType = GetAnimatorForType(WidgetType.HRMyZones);
			IWidgetAnimator animatorForType2 = GetAnimatorForType(WidgetType.HRTarget);
			switch (widgetType)
			{
			case WidgetType.HRMyZones:
				ActiveHRWidget = animatorForType;
				if (animatorForType2.Visible)
				{
					animatorForType2.MoveTo(WidgetState.Off);
					animatorForType.MoveTo(WidgetState.On);
				}
				break;
			case WidgetType.HRTarget:
				ActiveHRWidget = animatorForType2;
				if (animatorForType.Visible)
				{
					animatorForType2.MoveTo(WidgetState.On);
					animatorForType.MoveTo(WidgetState.Off);
				}
				break;
			}
		}

		private void DoToggleWorkoutControls()
		{
			IWidgetAnimator animatorForType = GetAnimatorForType(WidgetType.LeftSlider);
			IWidgetAnimator animatorForType2 = GetAnimatorForType(WidgetType.RightSlider);
			if (animatorForType == null && animatorForType2 == null)
			{
				return;
			}
			WidgetState widgetState = WidgetState.Off;
			if ((animatorForType == null || !animatorForType.Visible) && (animatorForType2 == null || !animatorForType2.Visible))
			{
				widgetState = WidgetState.On;
			}
			if (widgetState == WidgetState.On)
			{
				if (IsFullScreen.Value)
				{
					Log.Trace("Workout", "Not animating workout controls on in fullscreen");
					return;
				}
				IEnumerable<KeyValuePair<WidgetType, IWidgetAnimator>> enumerable = widgetAnimators.Where((KeyValuePair<WidgetType, IWidgetAnimator> x) => x.Key != WidgetType.LeftSlider && x.Key != WidgetType.RightSlider && x.Value.State == WidgetState.On && (x.Value.Location == WidgetLocation.Left || x.Value.Location == WidgetLocation.Right));
				foreach (KeyValuePair<WidgetType, IWidgetAnimator> item in enumerable)
				{
					item.Value.MoveTo(WidgetState.Off);
				}
			}
			animatorForType?.MoveTo(widgetState);
			animatorForType2?.MoveTo(widgetState);
			WorkoutControlsVisible.Value = widgetState == WidgetState.On;
			workoutSettings.ShowSliders = WorkoutControlsVisible.Value;
			analytics.InWorkoutWidgetInteraction(workoutSettings.WorkoutContainer.Workout, "Tap", widgetState == WidgetState.On, "Workout Controls");
		}

