		public void ToggleHRWidget()
		{
			if (ActiveHRWidget == null)
			{
				return;
			}
			if (IsFullScreen.Value)
			{
				savedWidgetFromHide = ActiveHRWidget;
				savedWidgetFromHide.MoveTo(WidgetState.OffDuringFullScreen);
				return;
			}
			WidgetState widgetState = WidgetState.Off;
			if (!ActiveHRWidget.Visible)
			{
				widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var value);
				if (value != null && value.Visible)
				{
					value?.MoveTo(WidgetState.Off);
				}
				widgetState = WidgetState.On;
			}
			ActiveHRWidget.MoveTo(widgetState);
			analytics.InWorkoutWidgetInteraction(workoutSettings.WorkoutContainer.Workout, "Tap", widgetState == WidgetState.On, "HR Widget");
		}

		private IWidgetAnimator GetAnimatorForType(WidgetType type)
		{
			if (widgetAnimators == null)
			{
				Log.Error("Workout", "widgetAnimators is null.");
				return null;
			}
			if (!widgetAnimators.ContainsKey(type))
			{
				Log.Error("Workout", string.Format("{0} does not contain key: {1}", "widgetAnimators", type));
				return null;
			}
			return widgetAnimators[type];
		}

		public void ToggleLeaderboardWidget()
		{
			IWidgetAnimator animatorForType = GetAnimatorForType(WidgetType.Leaderboard);
			if (animatorForType == null)
			{
				Log.Error("Workout", "WidgetManager.ToggleLeaderboardWidget called, but could not get animator.");
				return;
			}
			WidgetType oldMode = WidgetType.None;
			WidgetType newMode = WidgetType.None;
			if (!animatorForType.Visible)
			{
				widgetAnimators.TryGetValue(WidgetType.RightSlider, out var value);
				if (value != null && value.Visible)
				{
					value?.MoveTo(WidgetState.Off);
					oldMode = WidgetType.RightSlider;
				}
				animatorForType.MoveTo(WidgetState.On);
				newMode = WidgetType.Leaderboard;
			}
			else
			{
				animatorForType.MoveTo(WidgetState.OffAndUnload);
				oldMode = WidgetType.Leaderboard;
			}
			leaderboardAnalytics?.TrackLeaderboardAnalytics(oldMode, newMode);
		}

