		private void DoToggleFullScreen()
		{
			IsFullScreen.Value = !IsFullScreen.Value;
			INC<bool> canToggleWorkoutControls = CanToggleWorkoutControls;
			int value;
			if (!IsFullScreen.Value)
			{
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				value = ((workoutContainer == null || !workoutContainer.IsInEquipmentlessWorkout) ? 1 : 0);
			}
			else
			{
				value = 0;
			}
			canToggleWorkoutControls.Value = (byte)value != 0;
			if (IsFullScreen.Value)
			{
				LastVisibleRightWidgetBeforeEnteringFullscreen.Value = (IsLeaderboardVisible.Value ? WidgetType.Leaderboard : WidgetType.RightSlider);
				List<IWidgetAnimator> list = new List<IWidgetAnimator>();
				list.AddRange(widgetAnimators.Values.Where((IWidgetAnimator x) => (x.State == WidgetState.On && !x.AnimationInProgressToState.IsOff()) || x.AnimationInProgressToState == WidgetState.On));
				{
