		public WidgetGesture StartPossibleWidgetGesture(SwipeDirection direction, PointF start, float screenWidth, float screenHeight, float headerHeight)
		{
			IWidgetAnimator widgetAnimator = CheckNotificationsForHit(start);
			if (widgetAnimator != null && !widgetAnimator.GesturesEnabled)
			{
				return null;
			}
			WidgetGesture widgetGesture = SetupGestureForNotificationOnly(start);
			if (widgetGesture != null)
			{
				return widgetGesture;
			}
			if (IsFullScreen.Value)
			{
				return SetupExitFullScreenGesture(start);
			}
			if (start.Y <= headerHeight)
			{
				return SetupGestureForHeader(start);
			}
			if (!IsWidgetHit(start) && (direction == SwipeDirection.Up || direction == SwipeDirection.Down))
			{
				return SetupEnterFullScreenGesture(start);
			}
			float num = screenWidth / 2f - 52f;
			float num2 = screenWidth / 2f + 52f;
			if (start.X <= num)
			{
				return SetupGestureForLeftSide(start);
			}
			if (start.X >= num2)
			{
				return SetupGestureForRightSide(start);
			}
			return null;
		}

		private WidgetGesture SetupGestureForRightSide(PointF start)
		{
			List<IWidgetAnimator> list = new List<IWidgetAnimator>();
			if (consoleState == ConsoleState.Workout)
			{
				widgetAnimators.TryGetValue(WidgetType.Leaderboard, out var value);
				if (value != null)
				{
					if (value.IsTouchSuppressed(start))
					{
						return null;
					}
					list.Add(value);
				}
				widgetAnimators.TryGetValue(WidgetType.ConstantWatts, out var value2);
				if (value2 != null)
				{
					if (value2.IsTouchSuppressed(start))
					{
						return null;
					}
					list.Add(value2);
				}
			}
			widgetAnimators.TryGetValue(WidgetType.RightSlider, out var rightSlider);
			widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var value3);
			if (rightSlider != null && (rightSlider.State == WidgetState.On || (value3 != null && value3.State == WidgetState.On)) && list.All((IWidgetAnimator widget) => widget.State != rightSlider.State))
			{
				list.Add(rightSlider);
			}
			return new WidgetGesture(list, ScreenArea.RightSide, start, this);
		}

		private WidgetGesture SetupGestureForLeftSide(PointF start)
		{
			List<IWidgetAnimator> list = new List<IWidgetAnimator>();
			if (ActiveHRWidget != null && consoleState == ConsoleState.Workout)
			{
				list.Add(ActiveHRWidget);
			}
			widgetAnimators.TryGetValue(WidgetType.RightSlider, out var value);
			widgetAnimators.TryGetValue(WidgetType.LeftSlider, out var leftSlider);
			if (leftSlider != null && (leftSlider.State == WidgetState.On || (value != null && value.State == WidgetState.On)) && list.All((IWidgetAnimator widget) => widget.State != leftSlider.State))
			{
				list.Add(leftSlider);
			}
			return new WidgetGesture(list, ScreenArea.LeftSide, start, this);
		}

		private WidgetGesture SetupEnterFullScreenGesture(PointF start)
		{
			List<IWidgetAnimator> list = new List<IWidgetAnimator>();
			list.AddRange(widgetAnimators.Values.Where((IWidgetAnimator x) => (x.State == WidgetState.On && !x.AnimationInProgressToState.IsOff()) || x.AnimationInProgressToState == WidgetState.On));
			return new FullScreenGesture(list, start, this, enterFullScreen: true);
		}

		private WidgetGesture SetupExitFullScreenGesture(PointF start)
		{
			List<IWidgetAnimator> list = new List<IWidgetAnimator>();
			list.AddRange(widgetAnimators.Values.Where((IWidgetAnimator x) => x.State == WidgetState.OffDuringFullScreen));
			return new FullScreenGesture(list, start, this, enterFullScreen: false);
		}

		private WidgetGesture SetupGestureForHeader(PointF start)
		{
			return new WidgetGesture(new List<IWidgetAnimator>(), ScreenArea.Header, start, this);
		}

		private WidgetGesture SetupGestureForNotificationOnly(PointF start)
		{
			List<IWidgetAnimator> list = new List<IWidgetAnimator>();
			IWidgetAnimator widgetAnimator = CheckNotificationsForHit(start);
			if (widgetAnimator != null)
			{
				list.Add(widgetAnimator);
				return new WidgetGesture(list, ScreenArea.LeftSide, start, this);
			}
			return null;
		}

		private IWidgetAnimator CheckNotificationsForHit(PointF start)
		{
			foreach (IWidgetAnimator notificationAnimator in notificationAnimators)
			{
				if (notificationAnimator.ViewContains(start))
				{
					return notificationAnimator;
				}
			}
			return null;
		}

		private bool IsWidgetHit(PointF pt)
		{
			return widgetAnimators.Values.Any((IWidgetAnimator x) => x.ViewContains(pt));
		}

		public void HudStateChange(bool hudIsDown)
		{
			if (hudIsDown)
			{
				inAppNotificationService.DismissAll(typeof(CoachingMessageNotificationData));
				inAppNotificationService.Suppress(typeof(CoachingMessageNotificationData));
			}
			else
			{
				inAppNotificationService.Unsuppress(typeof(CoachingMessageNotificationData));
			}
		}

		public void Dispose()
		{
			subHRTargetOnVisible?.Dispose();
			subHRTargetOnVisible = null;
			subLeaderboardOnVisible?.Dispose();
			subLeaderboardOnVisible = null;
			subHRMyZonesOnVisible?.Dispose();
			subHRMyZonesOnVisible = null;
			subLeftSliderVisible?.Dispose();
			subLeftSliderVisible = null;
			subRightSliderVisible?.Dispose();
			subRightSliderVisible = null;
			subConstantWattsOnVisible?.Dispose();
			subConstantWattsOnVisible = null;
			subOnStateChange?.Dispose();
			subOnStateChange = null;
			savedWidgetFromHide = null;
			ActiveHRWidget = null;
			widgetAnimators.ForEach(delegate(KeyValuePair<WidgetType, IWidgetAnimator> x)
			{
				x.Value.Dispose();
			});
			widgetAnimators.Clear();
		}
	}
	public enum WidgetType
	{
		None,
		LeftSlider,
		RightSlider,
		HRTarget,
		HRMyZones,
		Leaderboard,
		Notification,
		Header,
		StatsHeader,
		ChartsHeader,
		FAB,
		HRBadge,
		CenterNotifications,
		ConstantWatts,
		ClosedCaptions
	}
	public static class WidgetTypeExtesions
	{
		public static bool IsWidgetOnRight(this WidgetType widgetType)
		{
			if (widgetType == WidgetType.RightSlider || widgetType == WidgetType.Leaderboard || widgetType == WidgetType.ConstantWatts)
			{
				return true;
			}
			return false;
		}

		public static bool IsValidConsoleState(this WidgetType widgetType, ConsoleState consoleState)
		{
			if (widgetType == WidgetType.Leaderboard || widgetType == WidgetType.ConstantWatts)
			{
				return consoleState == ConsoleState.Workout;
			}
			return true;
		}
	}
