	public class GuestWeightLogModalViewModel : WarmCoolModalViewModel
	{
		private const int RoundingDigits = 2;

		public readonly ImprovedObservableCollection<string> WeightUnitOfMeasure = new ImprovedObservableCollection<string>();

		public readonly INC<int> SelectedWeight = new NC<int>();

		public readonly INC<string> SelectedUnitOfMeasure = new NC<string>();

		private readonly ISettingsRouter settingsRouter;

		public string ButtonText = Wolf.Core.Resources.AppStrings.club_guest_enter_weight_button_text.ToUpper();

		public static int MinWeightKg => (int)Math.Ceiling(45.36);

		public static int MinWeightLbs => (int)Math.Ceiling(UnitUtil.EnsureLbs(WeightUnit.Kg, 45.36, 2));

		public MvxCommand<int> ValueChanged => new MvxCommand<int>(OnValueChanged);

		public string HeaderText => Wolf.Core.Resources.AppStrings.club_guest_enter_weight_header_text;

		private bool SelectedUnitOfMeasureIsMetric => SelectedUnitOfMeasure?.Value == Wolf.Core.Resources.AppStrings.kg;

		public MvxAsyncCommand SaveWeight => new MvxAsyncCommand(SaveUserWeight);

		[DependsOn(new string[] { "SelectedUnitOfMeasure" })]
		public int WeightMinValue
		{
			get
			{
				if (!SelectedUnitOfMeasureIsMetric)
				{
					return MinWeightLbs;
				}
				return MinWeightKg;
			}
		}

		[DependsOn(new string[] { "SelectedUnitOfMeasure" })]
		public int WeightMaxValue
		{
			get
			{
				double num = currentConsoleService.ActiveConsole?.ConsoleInfo?.MaxWeight ?? 136.078;
				num = (SelectedUnitOfMeasureIsMetric ? num : UnitUtil.EnsureLbs(WeightUnit.Kg, num, 2));
				int num2 = (SelectedUnitOfMeasureIsMetric ? 240 : 530);
				return (int)Math.Min(num, num2);
			}
		}

		public GuestWeightLogModalViewModel(ILocalSettings localSettings, ISettingsRouter settingsRouter, IInWorkoutWarmCoolUiService inWorkoutWarmCoolUiService)
			: base(localSettings, inWorkoutWarmCoolUiService)
		{
			try
			{
				WeightUnitOfMeasure.AddRange(new string[2]
				{
					Wolf.Core.Resources.AppStrings.kg,
					Wolf.Core.Resources.AppStrings.lbs
				});
				this.settingsRouter = settingsRouter;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			Task<double> userWeightTask = settingsRouter.GetWeightKgs();
			Task<bool> isMetricTask = settingsRouter.GetIsMetric();
			await Task.WhenAll(userWeightTask, isMetricTask);
			double userWeight = await userWeightTask;
			bool flag = await isMetricTask;
			SelectedUnitOfMeasure.Value = (flag ? Wolf.Core.Resources.AppStrings.kg : Wolf.Core.Resources.AppStrings.lbs);
			if (!flag)
			{
				userWeight = UnitUtil.EnsureLbs(WeightUnit.Kg, userWeight, 2);
			}
			SelectedWeight.Value = Convert.ToInt32(userWeight);
		}

		[DependsOn(new string[] { "SelectedUnitOfMeasure" })]
		private void UpdateValues()
		{
			double num = 0.0;
			num = ((!SelectedUnitOfMeasureIsMetric) ? UnitUtil.EnsureLbs(WeightUnit.Kg, SelectedWeight.Value, 2) : UnitUtil.EnsureKgs(WeightUnit.Lb, SelectedWeight.Value, 2));
			num = Math.Round(num);
			num = num.Clamp(WeightMinValue, WeightMaxValue);
			SelectedWeight.Value = Convert.ToInt32(num);
		}

		private void OnValueChanged(int value)
		{
			SelectedWeight.Value = value;
		}

		private async Task SaveUserWeight()
		{
			bool flag = SelectedUnitOfMeasure.Value != Wolf.Core.Resources.AppStrings.lbs;
			double num = SelectedWeight.Value;
			if (!flag)
			{
				num = UnitUtil.EnsureKgs(WeightUnit.Lb, num, 2);
			}
			preferenceResolver.IsMetric = flag;
			preferenceResolver.GuestWeight = num;
			if (workoutSettings.WorkoutContainer?.WorkoutRunner?.Console != null)
			{
				await SetConsoleWeight(num).ConfigureAwait(continueOnCapturedContext: false);
			}
			inWorkoutWarmCoolUiService?.CloseChildModals(Modal.None);
		}

		private async Task SetConsoleWeight(double weightKgs)
		{
			_ = 1;
			try
			{
				IFitnessConsole fitnessConsole = workoutSettings.WorkoutContainer?.WorkoutRunner?.Console;
				if (fitnessConsole != null)
				{
					IWeightFacade weightFacade = facadeFactoryDependencies.WeightFacade;
					bool success = await weightFacade.SetWeightAsync(weightKgs).ConfigureAwait(continueOnCapturedContext: false);
					double num = await weightFacade.GetWeightAsync().ConfigureAwait(continueOnCapturedContext: false);
					if (!num.AlmostEqual(weightKgs) || !success)
					{
						Log.Error("Connection", $"Setting weight to console was unsuccessful - weightKgs {weightKgs} - ConsoleWeight {num} - Success {success}");
					}
					else
					{
						Log.Trace("Connection", "Setting weight to console was successful");
					}
				}
			}
			catch (Exception exception)
			{
				Log.Error("Connection", "GuestWeightLogModalViewModel - Failed to set weight to console", exception);
			}
		}

