		Satellite,
		Cycle
	}
	public class InWorkoutMapViewModel : InWorkoutPageViewModel
	{
		private const int MapCycleDelaySec = 15;

		private int currentMapCycleIndex;

		private List<MapView> enabledCycleMapViews;

		protected IMvxMainThreadDispatcher mainThreadDispatcher;

		public readonly IStreetViewService StreetViewService;

		private IDisposable mapCycleTimerSubscription;

		private IDisposable streetViewNotAvailable;

		private IDisposable streetViewAvailable;

		private IDisposable streetViewImageErrorOccurred;

		private IDisposable wifiStateSub;

		private IDisposable workoutResumedSub;

		private bool badConnectionDialogShown;

		private DateTime lastSuccessfulImage = DateTime.MinValue;

		public readonly INC<MapView> CurrentMapView = new NC<MapView>(MapView.StreetView);

		public readonly INC<MapViewOption> CurrentMapViewOption = new NC<MapViewOption>(MapViewOption.StreetView);

		public readonly INC<bool> IsWaitingForStreetView = new NC<bool>(value: true);

		public readonly INC<bool> IsStreetViewImageryAvailable = new NC<bool>(value: false);

		private IFitnessConsole CurrentConsole => currentConsoleService?.ActiveConsole;

		public List<iFit.Api.Google.LatLng> Route { get; set; }

		public List<IUserPositionUpdate> UserUpdates { get; set; }

		public ICommand DisplayStreetView => new MvxCommand(DoDisplayStreetViewMapView);

		public ICommand DisplayMapView => new MvxCommand(DoDisplayMapMapView);

		public ICommand DisplaySatelliteView => new MvxCommand(DoDisplaySatelliteMapView);

		public ICommand CycleMapViews => new MvxCommand(DoCycleMapViews);

		[DependsOn(new string[] { "CurrentMapView", "IsWaitingForStreetView", "IsStreetViewImageryAvailable" })]
		public bool ShowStreetViewImagery
		{
			get
			{
				if (!IsWaitingForStreetView.Value && IsStreetViewImageryAvailable.Value)
				{
					return CurrentMapView.Value == MapView.StreetView;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "CurrentMapView", "IsStreetViewImageryAvailable", "IsWaitingForStreetView" })]
		public bool ShowStreetViewImageryNotAvailable
		{
			get
			{
				if (CurrentMapView.Value == MapView.StreetView)
				{
					if (!IsWaitingForStreetView.Value)
					{
						return !IsStreetViewImageryAvailable.Value;
					}
					return true;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsStreetViewImageryAvailable", "IsWaitingForStreetView" })]
		public string StreetViewImageryNotAvailableText
		{
			get
			{
				if (!IsStreetViewImageryAvailable.Value && !IsWaitingForStreetView.Value)
				{
					return Wolf.Core.Resources.AppStrings.no_street_view;
				}
				return Wolf.Core.Resources.AppStrings.street_view_loading;
			}
		}

		public InWorkoutMapViewModel(ILocalSettings localSettings, IMvxMainThreadDispatcher dispatcher)
			: base(localSettings)
		{
			try
			{
				mainThreadDispatcher = dispatcher;
				Route = (workoutSettings.WorkoutContainer.Workout.Geo?.Path)?.LatLngs.Select((iFit.Api.DataObjects.LatLng x) => x.ToGoogleLatLng()).ToList();
				UserUpdates = workoutSettings.WorkoutContainer.ConsoleConfiguration.UserUpdates;
				StreetViewService = workoutSettings.WorkoutContainer.ConsoleConfiguration.StreetView;
				streetViewAvailable = StreetViewService.WhenImageAvailableAtCurrentDistance.SubscribeWithErrorLogging(delegate
				{
					mainThreadDispatcher.RequestMainThreadAction(delegate
					{
						lastSuccessfulImage = DateTime.Now;
						IsWaitingForStreetView.Value = false;
						IsStreetViewImageryAvailable.Value = true;
					});
				});
				streetViewNotAvailable = StreetViewService.WhenImageNotAvailableAtCurrentDistance.SubscribeWithErrorLogging(delegate(bool x)
				{
					mainThreadDispatcher.RequestMainThreadAction(delegate
					{
						IsWaitingForStreetView.Value = false;
						IsStreetViewImageryAvailable.Value = x;
					});
				});
				wifiStateSub = wifiService.WhenNetworkStateChanged.SubscribeAsyncWithErrorLogging(async delegate(WifiNetworkState state)
				{
					bool flag = state == WifiNetworkState.Disconnected;
					bool flag2 = flag;
					if (flag2)
					{
						flag2 = !(await wifiService.PingSucceeds());
					}
					if (flag2)
					{
						ShowBadConnectionDialog();
					}
				});
				streetViewImageErrorOccurred = StreetViewService.WhenErrorOccurredLoadingImage.SubscribeAsyncWithErrorLogging(async delegate(Exception x)
				{
					await HandleErrorLoadingImage(x);
				});
				workoutResumedSub = CurrentConsole?.WhenStateChanged?.Where((StateChange x) => x.ChangedFromState(ConsoleState.Paused) && x.Current.IsRunningState()).SubscribeWithErrorLogging(delegate
				{
					MapCycleTimerUpdate();
				});
				InitMapView();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task HandleErrorLoadingImage(Exception ex)
		{
			if (await wifiService.IsConnectionPoor())
			{
				ShowBadConnectionDialog();
			}
		}

		private void ShowBadConnectionDialog()
		{
			if (badConnectionDialogShown)
			{
				return;
			}
			mainThreadDispatcher.RequestMainThreadAction(delegate
			{
				badConnectionDialogShown = true;
				DateTime dialogShownTime = DateTime.Now;
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.streetview_bad_connection_title, Wolf.Core.Resources.AppStrings.streetview_bad_connection_message, async delegate
				{
					if (lastSuccessfulImage < dialogShownTime)
					{
						IWorkoutRunner workoutRunner = workoutSettings?.WorkoutContainer.WorkoutRunner;
						if (workoutRunner != null)
						{
							await workoutRunner.StopAsync();
						}
					}
				}, Wolf.Core.Resources.AppStrings.streetview_bad_connection_continue_workout, Wolf.Core.Resources.AppStrings.streetview_bad_connection_end_workout);
			});
		}

		protected virtual void InitMapView()
		{
			enabledCycleMapViews = new List<MapView>
			{
				MapView.StreetView,
				MapView.Map,
				MapView.Satellite
			};
			if ((localSettings.MapCycleViews & MapView.Map) == 0)
			{
				enabledCycleMapViews.Remove(MapView.Map);
			}
			if ((localSettings.MapCycleViews & MapView.Satellite) == 0)
			{
				enabledCycleMapViews.Remove(MapView.Satellite);
			}
			if (enabledCycleMapViews.Count > 1 && (localSettings.MapCycleViews & MapView.StreetView) == 0)
			{
				enabledCycleMapViews.Remove(MapView.StreetView);
			}
			IsWaitingForStreetView.Value = true;
			CurrentMapViewOption.Value = localSettings.MapViewOption;
			switch (CurrentMapViewOption.Value)
			{
			case MapViewOption.StreetView:
				DoDisplayStreetViewMapView();
				break;
			case MapViewOption.Map:
				DoDisplayMapMapView();
				break;
			case MapViewOption.Satellite:
				DoDisplaySatelliteMapView();
				break;
			case MapViewOption.Cycle:
				DoCycleMapViews();
				break;
			}
		}

		public override void Dispose()
		{
			((BaseViewModel)this).Dispose();
			CleanUp();
			UnregisterChangeHandlers();
		}

		private void CleanUp()
		{
			mapCycleTimerSubscription?.Dispose();
			mapCycleTimerSubscription = null;
			streetViewNotAvailable?.Dispose();
			streetViewNotAvailable = null;
			streetViewAvailable?.Dispose();
			streetViewAvailable = null;
			streetViewImageErrorOccurred?.Dispose();
			streetViewImageErrorOccurred = null;
			wifiStateSub?.Dispose();
			wifiStateSub = null;
			workoutResumedSub?.Dispose();
			workoutResumedSub = null;
		}

		private void DoDisplayStreetViewMapView()
		{
			DoDisplayMapView(MapViewOption.StreetView, MapView.StreetView);
		}

		private void DoDisplayMapMapView()
		{
			DoDisplayMapView(MapViewOption.Map, MapView.Map);
		}

		private void DoDisplaySatelliteMapView()
		{
			DoDisplayMapView(MapViewOption.Satellite, MapView.Satellite);
		}

		private void DoDisplayMapView(MapViewOption mapViewOption, MapView mapView)
		{
			CurrentMapViewOption.Value = mapViewOption;
			localSettings.MapViewOption = CurrentMapViewOption.Value;
			CurrentMapView.Value = mapView;
			MapCycleTimerUpdate();
		}

		private void DoCycleMapViews()
		{
			CurrentMapViewOption.Value = MapViewOption.Cycle;
			localSettings.MapViewOption = CurrentMapViewOption.Value;
			currentMapCycleIndex = -1;
			MapCycleTimerUpdate();
		}

		private void MapCycleTimerUpdate()
		{
			mapCycleTimerSubscription?.Dispose();
			mapCycleTimerSubscription = null;
			if (CurrentMapViewOption.Value == MapViewOption.Cycle)
			{
				IFitnessConsole currentConsole = CurrentConsole;
				if (currentConsole == null || currentConsole.LatestBasicInfo?.CurrentState != ConsoleState.Paused)
				{
					currentMapCycleIndex = (currentMapCycleIndex + 1) % enabledCycleMapViews.Count;
					CurrentMapView.Value = enabledCycleMapViews[currentMapCycleIndex];
					StartMapCycleTimer();
				}
			}
		}

		private void StartMapCycleTimer()
		{
			mapCycleTimerSubscription?.Dispose();
			mapCycleTimerSubscription = GetMapCycleChangeObservable().SubscribeWithErrorLogging(delegate
			{
				MapCycleTimerUpdate();
			});
		}

		protected virtual IObservable<long> GetMapCycleChangeObservable()
		{
			return Observable.Timer(TimeSpan.FromSeconds(15.0));
		}

