	public class InWorkoutRetailDemoLoadingVideoViewModel : InWorkoutPageViewModel
	{
		private const int DelaySecondsBeforeTransition = 3;

		private IDisposable videoBufferStatusSub;

		protected IVideoBufferMonitoringService VideoBufferService { get; private set; }

		protected IVideoService VideoService { get; private set; }

		private IWorkoutRunner WorkoutRunner => workoutSettings?.WorkoutContainer?.WorkoutRunner;

		private bool IsConsoleInWarmup
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.Console.LatestBasicInfo?.IsInState(ConsoleState.WarmUp) == true;
			}
		}

		private bool IsSafetyKeyRemoved
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.Console.LatestBasicInfo?.IsInState(ConsoleState.SafetyKeyRemoved) == true;
			}
		}

		public InWorkoutRetailDemoLoadingVideoViewModel(ILocalSettings localSettings, IVideoBufferMonitoringService videoBufferService, IVideoService videoService = null)
			: base(localSettings)
		{
			try
			{
				VideoService = videoService;
				IWorkoutContainer workoutContainer = workoutSettings?.WorkoutContainer;
				if (workoutContainer == null)
				{
					Log.Error("Workout", "WorkoutContainer null while constructing InWorkoutWarmCoolViewModel");
					return;
				}
				if (workoutContainer.Console == null)
				{
					Log.Error("Workout", "WorkoutContainer's Console null while constructing InWorkoutWarmCoolViewModel");
					return;
				}
				Workout workout = workoutContainer.Workout;
				if (workout != null && workout.IsVideoWorkout() && IsConsoleInWarmup)
				{
					if (videoBufferService != null)
					{
						videoBufferStatusSub = videoBufferService.WhenVideoBufferStatusChanged.SubscribeWithErrorLogging(HandleVideoBufferStatusChange);
						VideoBufferService = videoBufferService;
						videoBufferService.StartVideoBufferMonitoring(videoService.PreBufferedVideoPlayer?.CurrentSettingsInfo);
					}
				}
				else
				{
					videoBufferService?.Dispose();
					Task.Run((Func<Task>)SkipToWorkoutWithDelay);
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void HandleVideoBufferStatusChange(VideoBufferMonitoringService.VideoBufferingStatus status)
		{
			if (status.BufferPercentage >= 100)
			{
				videoBufferStatusSub?.Dispose();
				videoBufferStatusSub = null;
				Task.Run((Func<Task>)SkipToWorkoutWithDelay);
			}
		}

		private async Task SkipToWorkoutWithDelay()
		{
			if (IsConsoleInWarmup || IsSafetyKeyRemoved)
			{
				await Task.Delay(TimeSpan.FromSeconds(3.0));
				await WaitForSafetyKey();
				await WorkoutRunner.FinishWarmUp().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task WaitForSafetyKey()
		{
			while (IsSafetyKeyRemoved)
			{
				await Task.Delay(100);
			}
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				videoBufferStatusSub?.Dispose();
				videoBufferStatusSub = null;
				VideoBufferService = null;
				((BaseViewModel)this).Dispose();
				isDisposed = true;
				UnregisterChangeHandlers();
			}
		}

