	public class InWorkoutTrackViewModel : InWorkoutPageViewModel
	{
		private const double MetersInTrack = 400.0;

		private const double MilesInTrack = 0.25;

		private const double AnimationTolerance = 0.0001;

		private const double InterpolationMs = 33.0;

		private const double maxMetersDifference = 500.0;

		private const double maxTimeDifference = 60.0;

		private IDisposable distanceChanged;

		private IDisposable lapTimeChanged;

		private int previousLap = 1;

		private double previousCompletedPercent;

		private double previousDrawnPercent;

		private double lastLapFinishedSeconds;

		private double lastTick;

		private bool isMetric;

		private double lastMeters;

		public readonly INC<double> DrawnPercent = new NC<double>(0.0);

		public readonly INC<string> LapTimeText = new NC<string>("00:00:00");

		public readonly INC<string> LapCountText = new NC<string>("1");

		public readonly INC<string> LapDistanceValueText = new NC<string>(string.Empty);

		public readonly INC<string> LapDistanceLabelText = new NC<string>(Wolf.Core.Resources.AppStrings.track_length.ToUpper());

		public readonly INC<bool> Visible = new NC<bool>(Mvx.Resolve<IHardwareInfo>().IsAndroid);

		public ValueInterpolator<double> TrackInterpolator { get; set; }

		public InWorkoutTrackViewModel(ILocalSettings localSettings, IPreferenceResolver preferenceResolver)
			: base(localSettings)
		{
			try
			{
				SetupDistanceAndTimeSubscriptions();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			isMetric = preferenceResolver.IsMetric;
			bool valueOrDefault = currentConsoleService.ActiveConsole?.ConsoleInfo?.MachineType.IsRower() == true;
			LapDistanceValueText.Value = ((isMetric || valueOrDefault) ? $"{400.0} {Wolf.Core.Resources.AppStrings.meters_label_full}" : Wolf.Core.Resources.AppStrings.quarter_mile).ToUpper();
			await base.OnViewShown().ConfigureAwait(continueOnCapturedContext: false);
		}

		protected void SetupDistanceAndTimeSubscriptions()
		{
			distanceChanged?.Dispose();
			distanceChanged = null;
			distanceChanged = facadeFactoryDependencies.CurrentDistanceFacade.ObserveMeterChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<double> x)
			{
				SetMeters(x.Current);
			});
			lapTimeChanged?.Dispose();
			lapTimeChanged = null;
			lapTimeChanged = facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<int> x)
			{
				UpdateLapTime(x.Current);
			});
		}

		private void UpdateLapTime(double currentTime)
		{
			UpdateLabelsVisible();
			double num = ((currentTime > 0.0) ? currentTime : 0.0);
			if (currentTime < lastTick || currentTime - lastTick > 60.0)
			{
				lastTick = currentTime;
				return;
			}
			lastTick = num;
			LapTimeText.Value = TimeSpan.FromSeconds(num - lastLapFinishedSeconds).ToString("c");
		}

		private void UpdateLabelsVisible()
		{
			if (Mvx.Resolve<IHardwareInfo>().IsAndroid)
			{
				if (Visible.Value == workoutSettings.FabOpen)
				{
					Visible.Value = !workoutSettings.FabOpen;
				}
			}
			else if (Visible.Value != workoutSettings.FabOpen)
			{
				Visible.Value = workoutSettings.FabOpen;
			}
		}

		private void UpdateLapCount(double meters)
		{
			int num = 1;
			if (meters > 0.0)
			{
				double distance = GetDistance(meters);
				double num2 = (isMetric ? 400.0 : 0.25);
				num = (int)Math.Floor(distance / num2) + 1;
				if (num > previousLap)
				{
					lastLapFinishedSeconds = lastTick;
					previousLap = num;
				}
			}
			LapCountText.Value = num.ToString();
		}

		private void SetMeters(double meters)
		{
			Log.Trace("Workout", $"SetMeters {meters}");
			if (meters < lastMeters || meters - lastMeters > 500.0)
			{
				lastMeters = meters;
				return;
			}
			lastMeters = meters;
			double percentOfTrackToDraw = GetPercentOfTrackToDraw(meters);
			UpdateLapCount(meters);
			if (isDisposed)
			{
				return;
			}
			if (TrackInterpolator == null)
			{
				SetUpTrackInterpolator(percentOfTrackToDraw);
				return;
			}
			if (percentOfTrackToDraw < previousDrawnPercent)
			{
				TrackInterpolator.SetValue = 0.0001;
			}
			if (!isDisposed && TrackInterpolator != null)
			{
				previousDrawnPercent = percentOfTrackToDraw;
				TrackInterpolator.SetValue = percentOfTrackToDraw;
			}
		}

		private void SetUpTrackInterpolator(double percent)
		{
			DrawnPercent.Value = percent;
			TrackInterpolator = new EasingDoubleInterpolator(TimeSpan.FromMilliseconds(33.0), 20.0, InterpolatorMode.InterpolateUpward, 0.0001, percent);
			TrackInterpolator.InterpolatedValueChanged += HandleTrackInterpolatorChanged;
			TrackInterpolator.Start();
		}

		private double GetPercentOfTrackToDraw(double meters)
		{
			double percentOfLapComplete = GetPercentOfLapComplete(meters);
			bool flag = percentOfLapComplete < 0.33 && previousCompletedPercent > 0.66;
			previousCompletedPercent = percentOfLapComplete;
			if (!flag)
			{
				return percentOfLapComplete;
			}
			return 1.0;
		}

		private double GetPercentOfLapComplete(double meters)
		{
			double distance = GetDistance(meters);
			if (distance <= 0.0)
			{
				return 0.0;
			}
			double num = (isMetric ? 400.0 : 0.25);
			return distance % num / num;
		}

		private double GetDistance(double meters)
		{
			if (!isMetric)
			{
				return UnitUtil.EnsureMiles(DistanceUnit.M, meters, 3);
			}
			return meters;
		}

		private void HandleTrackInterpolatorChanged(object sender, double newValue)
		{
			try
			{
				if (TrackInterpolator != null)
				{
					TrackInterpolator.Paused = true;
					DrawnPercent.Value = newValue * 1.01;
					TrackInterpolator.Paused = false;
				}
			}
			catch (NullReferenceException)
			{
			}
		}

		public override void Dispose()
		{
			distanceChanged?.Dispose();
			distanceChanged = null;
			lapTimeChanged?.Dispose();
			lapTimeChanged = null;
			TrackInterpolator?.Stop();
			TrackInterpolator = null;
			((BaseViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

