	public enum Modal
	{
		None,
		Weight
	}
	public interface IInWorkoutWarmCoolUiService : IDisposable
	{
		Modal CurrentModal { get; }

		IObservable<Unit> WhenCloseModals { get; }

		IObservable<Modal> WhenModalChanged { get; }

		bool CloseChildModals(Modal newModal);
	}
	public class InWorkoutWarmCoolUiService : IInWorkoutWarmCoolUiService, IDisposable
	{
		private Subject<Unit> _whenCloseModals = new Subject<Unit>();

		private Subject<Modal> _whenModalChanged = new Subject<Modal>();

		private Modal _currentModal;

		public IObservable<Unit> WhenCloseModals => _whenCloseModals;

		public IObservable<Modal> WhenModalChanged => _whenModalChanged;

		public Modal CurrentModal
		{
			get
			{
				return _currentModal;
			}
			set
			{
				if (_currentModal != value)
				{
					_currentModal = value;
					_whenModalChanged.OnNext(_currentModal);
				}
			}
		}

		public bool CloseChildModals(Modal newModal)
		{
			_whenCloseModals.OnNext(Unit.Default);
			if (newModal != Modal.None && newModal == CurrentModal)
			{
				CurrentModal = Modal.None;
				return false;
			}
			if (newModal == Modal.None && CurrentModal != Modal.None)
			{
				CurrentModal = newModal;
				return false;
			}
			CurrentModal = newModal;
			return true;
		}

		public void Dispose()
		{
			_whenCloseModals?.Dispose();
			_whenCloseModals = null;
			_whenModalChanged?.Dispose();
			_whenModalChanged = null;
		}
	}
