		private bool IsBuiltInBluetoothFeatureEnabled
		{
			get
			{
				if (deviceInfo.IsBuiltIn)
				{
					return featureFlagManager?.IsFeatureEnabled(FeatureFlags.EmbeddedBluetoothHeadphoneFeature) ?? false;
				}
				return false;
			}
		}

		private IWorkoutRunner WorkoutRunner => workoutSettings?.WorkoutContainer?.WorkoutRunner;

		private bool IsVideoWorkout => workoutSettings.WorkoutContainer?.Workout.IsVideoWorkout() ?? false;

		private bool IsLiveWorkout
		{
			get
			{
				IWorkoutRunner workoutRunner = WorkoutRunner;
				if (workoutRunner != null)
				{
					WorkoutRunnerContext runContext = workoutRunner.RunContext;
					if (runContext != null)
					{
						_ = runContext.Context;
						if (true)
						{
							return WorkoutRunner.RunContext.Context != Workout.WorkoutContext.OnDemand;
						}
					}
				}
				return false;
			}
		}

		protected bool IsAudioPossible
		{
			get
			{
				if (!mediaService.Music.WorkoutHasMusic && !IsVideoWorkout && !IsLiveWorkout)
				{
					ITelevisionTunerService obj = televisionTunerService;
					if (obj == null)
					{
						return false;
					}
					return obj.IsAvailable == true;
				}
				return true;
			}
		}

		[DependsOn(new string[] { "IsWarmup" })]
		public bool ShowPlaybackQualityInfo
		{
			get
			{
				if (IsWarmup.Value && !featureFlagManager.IsFeatureEnabled(FeatureFlags.VideoHlsEnabled))
				{
					return IsVideoWorkout;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsWarmup" })]
		public string HeaderText
		{
			get
			{
				if (!IsWarmup.Value)
				{
					return Wolf.Core.Resources.AppStrings.cooldown_great_work;
				}
				return Wolf.Core.Resources.AppStrings.workout_begins_in;
			}
		}

		[DependsOn(new string[] { "IsWarmup" })]
		public string SkipButtonText
		{
			get
			{
				if (!IsWarmup.Value)
				{
					return Wolf.Core.Resources.AppStrings.end_cool_down;
				}
				return Wolf.Core.Resources.AppStrings.skip_warm_up;
			}
		}

		[DependsOn(new string[] { "TimeRemaining" })]
		public string TimeRemainingToDisplay
		{
			get
			{
				double val = Math.Ceiling(TimeRemaining.Value);
				return StatInfoLabelType.Time.GetFormattedValue(Math.Max(val, 0.0));
			}
		}

		[DependsOn(new string[] { "ShowBufferingText", "WasBadConnectionDetected" })]
		public string BufferingText
		{
			get
			{
				if (WasBadConnectionDetected.Value)
				{
					return Wolf.Core.Resources.AppStrings.buffering_video_bad_connection;
				}
				if (!ShowBufferingText.Value)
				{
					return null;
				}
				return Wolf.Core.Resources.AppStrings.buffering_video_warmup;
			}
		}

		[DependsOn(new string[] { "ShowBufferingText", "WasBadConnectionDetected" })]
		public bool IsBuffering
		{
			get
			{
				if (!ShowBufferingText.Value)
				{
					return WasBadConnectionDetected.Value;
				}
				return true;
			}
		}

		public IFitnessConsole Console => currentConsoleService?.ActiveConsole;

		private double CooldownSeconds => workoutSettings?.WorkoutContainer?.WorkoutRunner?.CoolDown?.TargetValue ?? 600.0;

		private bool IsConsoleInWarmup
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.ActiveConsole.LatestBasicInfo?.IsInState(ConsoleState.WarmUp) == true;
			}
		}

		private IMediaService MediaService => Mvx.Resolve<IMediaService>();

