		public InWorkoutWarmCoolViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IInWorkoutWarmCoolUiService inWorkoutWarmCoolUiService, IOverlayNotifier overlayNotifier, IInAppNotificationService inAppNotificationService, IWorkoutFeatureService workoutFeatureService, IMediaService mediaService, IMediaSettings mediaSettings, IConnectedBluetoothAccessories connectedBluetoothAccessories, IVideoPlayerErrorHandler videoPlayerErrorHandler, IVideoBufferMonitoringService videoBufferService = null, IFeedFmAnalyticsService feedFmAnalyticsService = null, ITelevisionTunerService televisionTunerService = null)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.inWorkoutWarmCoolUiService = inWorkoutWarmCoolUiService;
				this.inAppNotificationService = inAppNotificationService;
				this.workoutFeatureService = workoutFeatureService;
				this.mediaService = mediaService;
				this.mediaSettings = mediaSettings;
				this.videoPlayerErrorHandler = videoPlayerErrorHandler;
				VideoBufferService = videoBufferService;
				this.feedFmAnalyticsService = feedFmAnalyticsService;
				this.televisionTunerService = televisionTunerService;
				this.connectedBluetoothAccessories = connectedBluetoothAccessories;
				BindingCtsToken = bindingCts.Token;
				inAppNotificationService.SuppressAll = true;
				inAppNotificationService.DismissAll();
				IsBuiltIn.Value = deviceInfo?.IsBuiltIn ?? false;
				IsModalVisible.Value = inWorkoutWarmCoolUiService.CurrentModal != Modal.None;
				modalChangedSub = inWorkoutWarmCoolUiService.WhenModalChanged.Subscribe(delegate(Modal modal)
				{
					IsModalVisible.Value = modal != Modal.None;
				});
				IWorkoutContainer workoutContainer = workoutSettings?.WorkoutContainer;
				if (workoutContainer == null)
				{
					Log.Error("Workout", "WorkoutContainer null while constructing InWorkoutWarmCoolViewModel");
					return;
				}
				if (workoutContainer.Console == null)
				{
					Log.Error("Workout", "WorkoutContainer's Console null while constructing InWorkoutWarmCoolViewModel");
					return;
				}
				timeUpdatedSub = facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().Where(TimeUpdateSubWhere)?.Select((FitnessValueChange<int> x) => x.Current)?.Subscribe(UpdateTimeRemaining, delegate(Exception ex)
				{
					Log.Error("Workout", "Error in timeUpdatedSub", ex);
				});
				stateSub = (from x in workoutContainer.Console.WhenStateChanged?.Where((StateChange x) => x.Old != ConsoleState.Paused && x.Old != ConsoleState.PauseOverride)
					select x.Current)?.Subscribe(WarmCoolStateChange, delegate(Exception ex)
				{
					Log.Error("Workout", "Error in stateSub", ex);
				});
				WarmCoolStateChange(workoutContainer.Console.LatestBasicInfo?.CurrentState ?? ConsoleState.Unknown);
				bool flag = workoutContainer.Workout?.IsVideoWorkout() ?? false;
				CanSkip.Value = !flag || !IsConsoleInWarmup;
				Log.Trace("Workout", CanSkip.Value ? $"Can skip {workoutContainer.Console.LatestBasicInfo?.CurrentState} in InWorkoutWarmCoolViewModel" : $"Can't skip {workoutContainer.Console.LatestBasicInfo?.CurrentState} because isVideoWorkout = {flag} and IsConsoleInWarmup = {IsConsoleInWarmup}");
				if (flag && IsConsoleInWarmup && VideoBufferService != null)
				{
					ShowBufferingText.Value = true;
					videoBufferStatusSub = VideoBufferService.WhenVideoBufferStatusChanged?.SubscribeWithErrorLogging(HandleVideoBufferStatusChange);
					VideoBufferService.StartVideoBufferMonitoring();
				}
				else
				{
					VideoBufferService?.Dispose();
				}
				BluetoothButtonViewModel = new BluetoothAccessoriesButtonViewModel(localSettings, connectedBluetoothAccessories);
				UpdateHeadphonesButtonVisible(overlayNotifier.AnyOverlayShowing);
				showingAnyOverlaySub = overlayNotifier.OnAnyOverlayShowing.SubscribeWithErrorLogging(UpdateHeadphonesButtonVisible);
				ShowWeightButton.Value = IsWarmup.Value && currentConsoleService.IsBuiltinClub && !ifitApi.HasLoggedInUser;
				PlaybackQualityInfo.Value = ((workoutSettings.VideoQuality == VideoQuality.Auto) ? Wolf.Core.Resources.AppStrings.inworkout_playback_quality_info_automatic : Wolf.Core.Resources.AppStrings.inworkout_playback_quality_info);
				PlaybackQualityInfoBolded.Value = Wolf.Core.Resources.AppStrings.inworkout_playback_quality_info_bolded;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			videoErrorSub?.Dispose();
			videoErrorSub = VideoPlayer?.VideoErrorOccured?.SubscribeAsyncWithErrorLogging((Exception ex) => videoPlayerErrorHandler.HandleVideoPlayerError(ex));
		}

		private void UpdateHeadphonesButtonVisible(bool anyOverlayVisible)
		{
			ShowBluetoothAccessoryButton.Value = IsBuiltInBluetoothFeatureEnabled && IsAudioPossible && !anyOverlayVisible;
		}

		public void StartupNotification()
		{
			if (workoutFeatureService.IsSmartAdjustAvailableInWorkout() && personalTrainingSettings.SmartAdjustEnabled && !IsConsoleInWarmup)
			{
				CoachingMessageNotificationData coachingMessageNotificationData = new CoachingMessageNotificationData(HowlSmartAdjustType.EndOfCooldown, TimeSpan.FromDays(1.0));
				notificationGuid = coachingMessageNotificationData.Id;
				inAppNotificationService.Post(coachingMessageNotificationData, ignoreSuppressed: true);
			}
		}

		private void HandleVideoBufferStatusChange(VideoBufferMonitoringService.VideoBufferingStatus status)
		{
			Log.Trace("Video", $"VideoBufferStatusChange: {status}");
			if (status.VideoFailedToLoad)
			{
				VideoFailedToLoad();
				return;
			}
			InvokeOnMainThread(delegate
			{
				BufferFullFraction.Value = (float)status.BufferPercentage / 100f;
				WasBadConnectionDetected.Value = IsConsoleInWarmup && status.BadConnection;
				ShowBufferingText.Value = !status.AllowSkip;
				CanSkip.Value = !IsConsoleInWarmup || status.AllowSkip;
			});
		}

		private bool TimeUpdateSubWhere(FitnessValueChange<int> change)
		{
			ConsoleState? consoleState = workoutSettings?.WorkoutContainer?.Console?.LatestBasicInfo?.CurrentState;
			if (consoleState != ConsoleState.WarmUp)
			{
				return consoleState == ConsoleState.CoolDown;
			}
			return true;
		}

		private void UpdateTimeRemaining(int current)
		{
			if (workoutSettings?.WorkoutContainer?.Console?.LatestBasicInfo?.IsInState(ConsoleState.SafetyKeyRemoved, ConsoleState.Demo, ConsoleState.Error) != true)
			{
				TimeRemaining.Value = current;
			}
		}

		private void VideoFailedToLoad()
		{
			videoBufferStatusSub?.Dispose();
			Log.Error("Video", "Video failed to load, abort workout");
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.video_load_failed, (Func<CancellationToken, Task<object>>)null, string.Empty, Wolf.Core.Resources.AppStrings.ok, (Action)async delegate
			{
				await (workoutSettings?.WorkoutContainer?.WorkoutRunner?.StopAsync());
			}, (Action)null, false, true, "", (TaskCompletionSource<object>)null, (string)null, false, true);
		}

		private void DoShowWeightDialog()
		{
			IInWorkoutWarmCoolUiService obj = inWorkoutWarmCoolUiService;
			if (obj == null || obj.CloseChildModals(Modal.Weight))
			{
				ShowViewModel<InWorkoutViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<GuestWeightLogModalViewModel>(), (MvxRequestedBy)null);
			}
		}

		private void DoShowHeadphonePicker()
		{
			if (base.IsBuiltInClubUnit)
			{
				InWorkoutHeadphonePickerViewModel.Show(InWorkoutHeadphonePickerViewModel.OverlaySource.FromNone);
			}
			else
			{
				BluetoothDevicePickerViewModel.Show(BluetoothDevicePickerViewModel.OverlaySource.FromWarmCool);
