		}

		public bool ShouldShowPauseOverlay()
		{
			return inWorkoutWarmCoolUiService?.CloseChildModals(Modal.None) ?? true;
		}

		private void WarmCoolStateChange(ConsoleState state)
		{
			if (state != ConsoleState.WarmUp && state != ConsoleState.CoolDown)
			{
				if (state != ConsoleState.Workout)
				{
					DismissNotifications();
				}
				inWorkoutWarmCoolUiService?.CloseChildModals(Modal.None);
				return;
			}
			IsWarmup.Value = state == ConsoleState.WarmUp;
			if (TimeRemaining.Value == 0.0)
			{
				if (IsWarmup.Value)
				{
					TimeRemaining.Value = workoutSettings.WorkoutContainer?.WorkoutRunner?.WarmUp?.TargetValue ?? ((double)workoutSettings.WarmUpSeconds);
				}
				else
				{
					TimeRemaining.Value = CooldownSeconds;
				}
			}
			if (!IsWarmup.Value)
			{
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				if (workoutContainer != null && workoutContainer.Workout?.IsVideoWorkout() == true)
				{
					VideoBufferService?.CleanUp();
					CanSkip.Value = true;
					WasBadConnectionDetected.Value = false;
					ShowBufferingText.Value = false;
					Log.Trace("Workout", $"Can skip {state} in WarmCoolStateChange");
				}
			}
		}

		private async Task DoSkip()
		{
			Log.Trace("Workout", $"Skipping workout state {currentConsoleService?.Console?.LatestBasicInfo?.CurrentState}");
			inWorkoutWarmCoolUiService?.CloseChildModals(Modal.None);
			if (!CanSkip.Value)
			{
				Log.Trace("Workout", "Can't skip; aborting");
				return;
			}
			if (workoutSettings.WorkoutContainer?.WorkoutRunner != null)
			{
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				if (activeConsole != null && activeConsole.LatestBasicInfo?.CurrentState == ConsoleState.WarmUp)
				{
					await workoutSettings.WorkoutContainer.WorkoutRunner.FinishWarmUp().ConfigureAwait(continueOnCapturedContext: false);
					mediaService.Music.HandleUserSkipRequest(IsWarmup.Value, mediaService.Music.MusicShouldBeDisabledInMainWorkout, mediaSettings.TrainerVolume);
				}
			}
			IFitnessConsole activeConsole2 = currentConsoleService.ActiveConsole;
			if (activeConsole2 != null && activeConsole2.LatestBasicInfo?.CurrentState == ConsoleState.CoolDown)
			{
				mediaService.Music.FeedFm?.Pause();
				Task.Run((Func<Task>)CreatePostWorkoutWebviewLoadTimeEvent);
				Task task = workoutSettings.WorkoutContainer?.WorkoutRunner?.StopAsync();
				if (task != null)
				{
					await task;
				}
				inAppNotificationService.DismissAll();
				inAppNotificationService.SuppressAll = true;
				if (Mvx.TryResolve<IWolfAnalytics>(out var service) && mediaService.Music.FeedFm != null)
				{
					string activityLogId = workoutSettings?.WorkoutContainer?.WorkoutRunner?.WolfGeneratedId ?? "Activity Log Id was unavailable";
					AudioPlayerAction volumeState = (mediaSettings.MusicVolumeMuted ? AudioPlayerAction.MusicMuted : AudioPlayerAction.MusicUnMuted);
					feedFmAnalyticsService.SetInWorkoutMusicState(startingWorkout: false, mediaService.Music.FeedFm.ActiveState, volumeState);
					FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics data = feedFmAnalyticsService.BundleFeedFmAnalytics(activityLogId);
					await service.FeedFmPostWorkoutData(data, WorkoutRunner.Workout);
					feedFmAnalyticsService.Reset();
				}
			}
			Log.Trace("Workout", "Done skipping");
		}

		private async Task CreatePostWorkoutWebviewLoadTimeEvent()
		{
			TimedEvent timedEvent = await EventService.Instance.CreateAsync("PostWorkout WebView Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null)
			{
				EventService.Instance.AddWorkoutProperties(timedEvent, workoutSettings.WorkoutContainer.Workout);
				if (!timedEvent.Properties.ContainsKey("withCoolDown"))
				{
					timedEvent.Properties["withCoolDown"] = true;
				}
			}
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				((BaseViewModel)this).Dispose();
				bindingCts.Cancel();
				bindingCts.Dispose();
				modalChangedSub?.Dispose();
				modalChangedSub = null;
				timeUpdatedSub?.Dispose();
				timeUpdatedSub = null;
				stateSub?.Dispose();
				stateSub = null;
				videoErrorSub?.Dispose();
				videoErrorSub = null;
				videoBufferStatusSub?.Dispose();
				videoBufferStatusSub = null;
				BluetoothButtonViewModel.Dispose();
				connectedBluetoothAccessories.Dispose();
				showingAnyOverlaySub?.Dispose();
				showingAnyOverlaySub = null;
				if (inAppNotificationService != null)
				{
					inAppNotificationService.SuppressAll = false;
				}
				((BaseViewModel)this).Dispose();
				isDisposed = true;
				UnregisterChangeHandlers();
			}
		}

		private void DismissNotifications()
		{
			IInAppNotificationService obj = inAppNotificationService;
			if (obj != null && obj.Exists(notificationGuid))
			{
				inAppNotificationService.Dismiss(typeof(CoachingMessageNotificationData));
			}
		}

