namespace Wolf.Core.ViewModels.InWorkout.Notifications
{
	public abstract class BaseNotificationPresenterModel : INotificationPresenter, IDisposable
	{
		protected readonly IInAppNotificationService notificationService;

		private IDisposable notificationSubscription;

		public abstract Action<NotificationData> OnShow { get; set; }

		public abstract Action<NotificationData> OnDismiss { get; set; }

		public abstract Type NotificationDataType { get; }

		public bool IsRunning => notificationService.Exists(NotificationDataType);

		protected BaseNotificationPresenterModel(IInAppNotificationService inAppNotificationService)
		{
			notificationService = inAppNotificationService;
			notificationSubscription = notificationService.NotificationChanges.Subscribe(OnNotification);
		}

		protected virtual void OnNotification((NotificationChangeType type, NotificationData data) notification)
		{
			if (!(NotificationDataType != notification.data.GetType()))
			{
				switch (notification.type)
				{
				case NotificationChangeType.Add:
					OnShow(notification.data);
					break;
				case NotificationChangeType.Remove:
					OnDismiss(notification.data);
					break;
				}
			}
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				OnShow = null;
				OnDismiss = null;
				notificationSubscription?.Dispose();
				notificationSubscription = null;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
	public class CoachingNotificationsPresenterModel : BaseNotificationPresenterModel
	{
		public override Action<NotificationData> OnShow { get; set; }

		public override Action<NotificationData> OnDismiss { get; set; }

		public override Type NotificationDataType => typeof(CoachingMessageNotificationData);

		public IFollowMessageViewModel FollowMessageViewModel { get; set; }

		public CoachingNotificationsPresenterModel(IInAppNotificationService inAppNotificationService)
			: base(inAppNotificationService)
		{
		}

		protected override void OnNotification((NotificationChangeType type, NotificationData data) notification)
		{
			base.OnNotification(notification);
			if (notification.type == NotificationChangeType.Add && notification.data is FollowNotificationData)
			{
				OnShowFollowMessage(notification.data.Id);
			}
			if (notification.type == NotificationChangeType.Remove && notification.data is FollowNotificationData)
			{
				OnDismissFollowMessage();
			}
		}

		private void OnShowFollowMessage(string guid)
		{
			FollowMessageViewModel.ShowMessage(guid);
		}

		private void OnDismissFollowMessage()
		{
			FollowMessageViewModel.DismissMessage();
		}

		protected override void Dispose(bool disposing)
		{
			if (disposing)
			{
				FollowMessageViewModel?.DismissMessage();
				FollowMessageViewModel = null;
			}
			base.Dispose(disposing);
		}
	}
	public enum CoachingNotificationArrow
	{
		None,
		Up,
		Down
	}
	public class CoachingNotificationViewModel : NotificationViewModel<CoachingMessageNotificationData>
	{
		public INC<bool> IsAlertNotification = new NC<bool>(value: false);

		public INC<string> TrainerImageUrl = new NC<string>();

		public INC<string> HeaderTitle = new NC<string>();

		public INC<string> Message = new NC<string>();

		public INC<string> ActionMessage = new NC<string>();

		public INC<bool> IsActionVisible = new NC<bool>();

		public INC<string> NotificationType = new NC<string>();

		public INC<HowlTriggerType> TriggerType = new NC<HowlTriggerType>(HowlTriggerType.ActivePulse);

		public INC<CoachingNotificationArrow> Arrow = new NC<CoachingNotificationArrow>(CoachingNotificationArrow.None);

		public INC<bool> IsArrowVisible = new NC<bool>();

		private readonly ILocalSettings localSettings;

		private readonly IIfitApiService ifitApi;

		private readonly IWorkoutSettings workoutSettings;

		public ICommand ActionSelected => new MvxCommand(DoActionSelected);

		public bool IsSystemNotification => base.Data?.IsSystemNotification ?? false;

		public CoachingNotificationViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IInAppNotificationService notificationService, IHowlService howlService, IWorkoutSettings workoutSettings)
			: base(notificationService, howlService)
		{
			try
			{
				this.localSettings = localSettings;
				this.ifitApi = ifitApi;
				this.workoutSettings = workoutSettings;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task Init(string guid)
		{
			await base.Init(guid).ConfigureAwait(continueOnCapturedContext: false);
			await InitializeRequiredData().ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task ReloadNotificationContent(string guid)
		{
			ReloadData(guid);
			await InitializeRequiredData().ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task InitializeRequiredData()
		{
			ConfiguredTaskAwaitable configuredTaskAwaitable = InitTrainer().ConfigureAwait(continueOnCapturedContext: false);
			InitCoachMessage();
			InitArrow();
			await configuredTaskAwaitable;
		}

		private async Task InitTrainer()
		{
			if (base.Data?.IsSystemNotification ?? false)
			{
				HeaderTitle.Value = Wolf.Core.Resources.AppStrings.notification_ifit_settings;
				return;
			}
			try
			{
				HeaderTitle.Value = Wolf.Core.Resources.AppStrings.notification_ifit_coach;
				if (workoutSettings.WorkoutContainer?.Workout == null)
				{
					return;
				}
				Workout workout = workoutSettings.WorkoutContainer?.Workout;
				if (workout?.Metadata?.TrainerId != null && TrainerImageUrl.Value == null)
				{
					try
					{
						Workout.VideoWorkoutMetadata metadata = workout.Metadata;
						Trainer trainer = workout.Metadata.Trainer;
						Trainer trainer2 = trainer;
						if (trainer2 == null)
						{
							trainer2 = await Trainer.Get(ifitApi, workout.Metadata.TrainerId).ConfigureAwait(continueOnCapturedContext: false);
						}
						metadata.Trainer = trainer2;
					}
					catch (Exception ex)
					{
						Log.Error("Workout", $"Workout Id: {workout.Id} TrainerId: {workout.Metadata.TrainerId} Unable to get trainer information: {ex}", ex);
					}
				}
				if (workout?.Metadata?.Trainer != null)
				{
					TrainerImageUrl.Value = workout.Metadata.Trainer.ProfileImageThumbnailUrl;
					HeaderTitle.Value = workout.Metadata.Trainer.FirstName + " " + workout.Metadata.Trainer.LastName;
				}
			}
			catch (Exception ex2)
			{
				Log.Error("Workout", "Initialize trainer message error: " + ex2.Message, ex2);
			}
		}

		private void InitCoachMessage()
		{
			if (base.Data == null)
			{
				return;
			}
			try
			{
				(string, string) tuple = base.Data.Message(howlService);
				Message.Value = tuple.Item1;
				ActionMessage.Value = tuple.Item2.ToUpper();
				IsActionVisible.Value = !string.IsNullOrEmpty(tuple.Item2);
				CoachingMessageNotificationData data = base.Data;
				if (data != null && data.TriggerType == HowlTriggerType.ActivePulse)
				{
					TriggerType.Value = HowlTriggerType.ActivePulse;
					NotificationType.Value = Wolf.Core.Resources.AppStrings.activepulse;
					return;
				}
				CoachingMessageNotificationData data2 = base.Data;
				if (data2 != null && data2.TriggerType == HowlTriggerType.SmartAdjust)
				{
					TriggerType.Value = HowlTriggerType.SmartAdjust;
					NotificationType.Value = Wolf.Core.Resources.AppStrings.training_mode;
				}
			}
			catch (Exception ex)
			{
				Log.Error("Workout", "Initialize coach message error: " + ex.Message, ex);
			}
		}

		private void InitArrow()
		{
			if (base.Data != null)
			{
				Arrow.Value = (base.Data.RequiresArrowDown ? CoachingNotificationArrow.Down : (base.Data.RequiresArrowUp ? CoachingNotificationArrow.Up : CoachingNotificationArrow.None));
				IsArrowVisible.Value = Arrow.Value != CoachingNotificationArrow.None;
			}
		}

		private void DoActionSelected()
		{
			if (base.Data != null && IsActionVisible.Value)
			{
				base.Data.ActionHappened = true;
			}
			DismissNotification();
		}

