	public interface IFollowMessageViewModel
	{
		void ShowMessage(string guid);

		void DismissMessage();
	}
	public class FollowMessageViewModel : ShireBaseViewModel, IFollowMessageViewModel
	{
		private IDisposable scalingModeChangedSub;

		public INC<FollowNotificationData.FollowNotificationType> NotificationType = new NC<FollowNotificationData.FollowNotificationType>(FollowNotificationData.FollowNotificationType.Workout);

		public INC<string> Message = new NC<string>();

		public INC<bool> IsMessageVisible = new NC<bool>();

		private readonly IInAppNotificationService notificationService;

		private readonly IWorkoutFeatureService workoutFeatureService;

		private readonly IWorkoutRunner runner;

		private FollowNotificationData data;

		private readonly bool isVideoWorkout;

		private bool notFollowingWorkout;

		private string followWorkoutGuid;

		private IDisposable notificationSub;

		public ICommand ActionSelected => new MvxCommand(DoActionSelected);

		public FollowMessageViewModel(IInAppNotificationService notificationService, IWorkoutFeatureService workoutFeatureService, IWorkoutRunner runner, bool isVideoWorkout)
		{
			try
			{
				this.isVideoWorkout = isVideoWorkout;
				this.notificationService = notificationService;
				this.workoutFeatureService = workoutFeatureService;
				this.runner = runner;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void ShowMessage(string guid)
		{
			data = notificationService.Get<FollowNotificationData>(guid);
			NotificationType.Value = data.NotificationType;
			DetermineMessage();
			if (NotificationType.Value == FollowNotificationData.FollowNotificationType.TurnOnTrainingMode)
			{
				ListenForModeChangesToDismiss();
			}
			IsMessageVisible.Value = true;
		}

		public void DismissMessage()
		{
			IsMessageVisible.Value = false;
		}

		private void ListenForModeChangesToDismiss()
		{
			scalingModeChangedSub?.Dispose();
			scalingModeChangedSub = workoutFeatureService.WhenScalingModeChanged.Subscribe(ScalingModeChanged);
		}

		private void ScalingModeChanged(ScalingMode newScalingMode)
		{
			if (newScalingMode != ScalingMode.Manual)
			{
				scalingModeChangedSub?.Dispose();
				scalingModeChangedSub = null;
				DismissMessage();
				DoActionSelected();
			}
		}

		private void DetermineMessage()
		{
			switch (NotificationType.Value)
			{
			case FollowNotificationData.FollowNotificationType.Gear:
				Message.Value = Wolf.Core.Resources.AppStrings.notification_follow_gear;
				break;
			case FollowNotificationData.FollowNotificationType.Incline:
				Message.Value = Wolf.Core.Resources.AppStrings.notification_follow_incline;
				break;
			case FollowNotificationData.FollowNotificationType.Resistance:
				Message.Value = Wolf.Core.Resources.AppStrings.notification_follow_resistance;
				break;
			case FollowNotificationData.FollowNotificationType.Speed:
				Message.Value = Wolf.Core.Resources.AppStrings.notification_follow_speed;
				break;
			case FollowNotificationData.FollowNotificationType.Workout:
				Message.Value = Wolf.Core.Resources.AppStrings.notification_follow_workout;
				break;
			case FollowNotificationData.FollowNotificationType.TurnOnTrainingMode:
				Message.Value = Wolf.Core.Resources.AppStrings.turn_on_training_mode;
				break;
			case FollowNotificationData.FollowNotificationType.Legacy:
				Message.Value = LegacyMessage();
				break;
			}
		}

		private void DoActionSelected()
		{
			if (data != null)
			{
				data.ActionHappened = true;
				notificationService.Dismiss(data.Id);
			}
		}

		private string LegacyMessage()
		{
			if (!isVideoWorkout)
			{
				return Wolf.Core.Resources.AppStrings.follow_workout;
			}
			return Wolf.Core.Resources.AppStrings.follow_trainer;
		}

		public void CheckDecorators(bool userOverriding)
		{
			if (!workoutFeatureService.IsSmartAdjustAvailableInWorkout() || workoutFeatureService.ScalingMode == ScalingMode.Manual)
			{
				if (userOverriding && !notFollowingWorkout)
				{
					notFollowingWorkout = true;
					PostFollowWorkoutNotification();
				}
				else if (notFollowingWorkout && !userOverriding)
				{
					notFollowingWorkout = false;
				}
			}
		}

		private void PostFollowWorkoutNotification()
		{
			FollowNotificationData.FollowNotificationType notificationType = FollowNotificationData.FollowNotificationType.Legacy;
			if (workoutFeatureService.IsSmartAdjustAvailableInWorkout() && workoutFeatureService.SavedScalingMode != ScalingMode.Legacy)
			{
				notificationType = FollowNotificationData.FollowNotificationType.TurnOnTrainingMode;
			}
			FollowNotificationData followNotificationData = new FollowNotificationData(notificationType);
			followWorkoutGuid = followNotificationData.Id;
			notificationService?.Post(followNotificationData);
			notificationSub?.Dispose();
			notificationSub = notificationService?.NotificationChanges.Subscribe(LookForFollowWorkoutDismissed);
		}

		private void LookForFollowWorkoutDismissed((NotificationChangeType type, NotificationData data) obj)
		{
			if (obj.type == NotificationChangeType.Remove && obj.data.Id.Equals(followWorkoutGuid))
			{
				followWorkoutGuid = null;
				notificationSub?.Dispose();
				notificationSub = null;
				runner.DisableUserOverrides(resetValues: true);
				if (obj.data is FollowNotificationData { NotificationType: FollowNotificationData.FollowNotificationType.Legacy })
				{
					workoutFeatureService.TurnMode(ScalingMode.Manual, on: false);
				}
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			scalingModeChangedSub?.Dispose();
			scalingModeChangedSub = null;
			notificationSub?.Dispose();
			notificationSub = null;
			UnregisterChangeHandlers();
		}

