			: base(localSettings)
		{
			try
			{
				this.workoutFeatureService = workoutFeatureService;
				scalingModeChangedSub = workoutFeatureService.WhenScalingModeChanged.Subscribe(ScalingModeChanged);
				activePulseChangedSub = personalTrainingSettings.WhenActivePulseEnabledChanged.Subscribe(ActivePulseEnabledChanged);
				RefreshFlags();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void ActivePulseEnabledChanged(bool activePulseEnabled)
		{
			RefreshFlags();
		}

		private void ScalingModeChanged(ScalingMode mode)
		{
			RefreshFlags();
		}

		private void RefreshFlags()
		{
			ActivePulseEnabledButOff.Value = personalTrainingSettings.ActivePulseEnabled && workoutFeatureService.IsScalingModeEnabled(ScalingMode.SmartAdjust) && !workoutFeatureService.HeartRateMonitorConnected;
			ActivePulseDisabled.Value = !ActivePulseEnabledButOff.Value;
		}

		private void DoEnableActivePulse()
		{
			personalTrainingSettings.ActivePulseEnabled = true;
			workoutFeatureService.TurnMode(ScalingMode.ActivePulse, on: true);
			RefreshFlags();
		}

		public override void Dispose()
		{
			base.Dispose();
			scalingModeChangedSub?.Dispose();
			scalingModeChangedSub = null;
			activePulseChangedSub?.Dispose();
			activePulseChangedSub = null;
			UnregisterChangeHandlers();
		}

