	public class HRZoneDebugViewModel : HRZoneUpdatingBaseViewModel
	{
		private IDisposable workoutLevelChangedSub;

		private CancellationTokenSource zeroHRCts;

		public INC<string> ScalingText = new NC<string>();

		public INC<string> CurrentScaleText = new NC<string>();

		public INC<string> ZeroHRWarningText = new NC<string>();

		public INC<string> ReasonText = new NC<string>();

		public HRZoneDebugViewModel(ILocalSettings settings, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService, IDeveloperSettings developerSettings, IHRZoneUpdatingAnalyticsService hrZoneUpdatingAnalyticsService)
			: base(settings, hrTrainingService, workoutFeatureService, hrZoneUpdatingAnalyticsService)
		{
			try
			{
				if (developerSettings != null && developerSettings.ShowHRDebugInfo)
				{
					workoutLevelChangedSub = workoutSettings?.WorkoutContainer?.WorkoutRunner?.HRTrainingService?.WhenSuggestedLevelChanged?.Subscribe(OnWorkoutLevelChanged);
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void OnWorkoutLevelChanged(WorkoutLevelUpdate levelUpdate)
		{
			if (levelUpdate == null)
			{
				return;
			}
			ScalingText.Value = $"Scaling: {levelUpdate.Change}";
			StringBuilder stringBuilder = new StringBuilder("Reason: |");
			foreach (KeyValuePair<string, object> item in levelUpdate.ReasonForChange)
			{
				stringBuilder.Append(item.Key);
				stringBuilder.Append(" : ");
				stringBuilder.Append(item.Value?.ToString() ?? "no value");
				stringBuilder.Append("| |");
			}
			ReasonText.Value = stringBuilder.ToString();
		}

		public override void Dispose()
		{
			base.Dispose();
			workoutLevelChangedSub?.Dispose();
			workoutLevelChangedSub = null;
			UnregisterChangeHandlers();
		}

		protected override async Task OnHRDataUpdated(HRZoneUpdate zoneUpdate)
		{
			CurrentScaleText.Value = "Curr Scale: " + (zoneUpdate?.CurrScale.ToString() ?? "Error");
			if (zoneUpdate == null || zoneUpdate.CurrentBpm > 0)
			{
				return;
			}
			zeroHRCts?.Cancel();
			zeroHRCts = new CancellationTokenSource();
			ZeroHRWarningText.Value = $"Zero HR at {zoneUpdate.CurrentAt.Minutes}:{zoneUpdate.CurrentAt.Seconds}";
			try
			{
				await Task.Delay(TimeSpan.FromSeconds(10.0), zeroHRCts.Token);
				ZeroHRWarningText.Value = string.Empty;
			}
			catch (OperationCanceledException)
			{
			}
		}

