	public class HRZoneLineChartViewModel : HRZoneUpdatingBaseViewModel
	{
		protected const int TrailingHRTime = 90;

		protected const int LeadingHRTime = 90;

		private readonly IIfitApiService api;

		private readonly IVideoService videoService;

		private IDisposable hrUpdatedSub;

		private IDisposable timeUpdatedSub;

		private IDisposable maxHeartRateChangedSub;

		private IDisposable chartSub;

		protected int minimumZ1Bpm;

		public readonly INC<bool> ViewModelInitialized = new NC<bool>();

		public readonly INC<Tuple<double, double>> HRCurrent = new NC<Tuple<double, double>>();

		public readonly INC<int> ChartMinTime = new NC<int>();

		public readonly INC<int> ChartMaxTime = new NC<int>();

		public readonly INC<int> MaxHeartRate = new NC<int>();

		public IReadOnlyList<UserHeartRateZone> UserHRZones = new List<UserHeartRateZone>();

		public InWorkoutChartDataProvider ChartData => workoutSettings?.WorkoutContainer?.ChartData;

		public int NumberOfZones => base.HrTrainingService?.ZoneCount ?? 5;

		public ChartDataCollection HRCurrentMetric { get; set; }

		public ChartMetricModel HRPredictedMetricModel { get; private set; }

		public HRZoneLineChartViewModel(ILocalSettings settings, IIfitApiService api, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService, IVideoService videoService, IHRZoneUpdatingAnalyticsService hrZoneUpdatingAnalyticsService, IHeartRateService heartRateService)
			: base(settings, hrTrainingService, workoutFeatureService, hrZoneUpdatingAnalyticsService)
		{
			try
			{
				this.api = api;
				this.videoService = videoService;
				MaxHeartRate.Value = heartRateService.HeartRate.MaxHeartRate;
				maxHeartRateChangedSub = heartRateService.HeartRate.MaxHeartRateChanged.Subscribe(delegate(int x)
				{
					if (x > MaxHeartRate.Value)
					{
						MaxHeartRate.Value = x;
					}
				});
				HRCurrent.Value = new Tuple<double, double>(0.0, 0.0);
				ChartMinTime.Value = 0;
				ChartMaxTime.Value = 180;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			try
			{
				UserHeartRateSettings userHeartRateSettings = await (await User.GetMe(api)).GetHeartRateSettings(api, force: true);
				userHeartRateSettings?.Zones?.Sort((UserHeartRateZone x, UserHeartRateZone y) => x.MinBpm.CompareTo(y.MinBpm));
				UserHRZones = userHeartRateSettings.Zones;
				minimumZ1Bpm = UserHRZones.First((UserHeartRateZone z) => z.ZoneNumber == 1).MinBpm - 1;
			}
			catch (Exception ex)
			{
				Log.Error("HRZoneLineChartViewModel", "ERROR getting user HR settings: " + ex.Message);
			}
			if (HRCurrentMetric == null)
			{
				HRCurrentMetric = new ChartDataCollection();
			}
			else
			{
				HRCurrentMetric.Clear();
			}
			HistoricDataIntoCurrent();
			if (ChartData != null)
			{
				int num = Array.FindIndex(ChartData.CurrentMetrics, (ChartMetricModel x) => x.DataConfig.Metric == ChartMetricConfiguration.MetricType.HeartRate);
				if (num > -1)
				{
					RegisterCurrentValue(HRCurrent, ChartData.CurrentMetrics[num]);
					HRPredictedMetricModel = ChartData.HRWidgetPredictedModel;
				}
			}
			timeUpdatedSub?.Dispose();
			timeUpdatedSub = videoService.PreBufferedVideoPlayer?.WhenVideoPositionSecondsChanged.Subscribe(OnTimeChanged);
			ViewModelInitialized.Value = true;
		}

		protected void RegisterCurrentValue(INC<Tuple<double, double>> current, ChartMetricModel model)
		{
			chartSub?.Dispose();
			chartSub = model.ChartData.ObservableEvent().Subscribe(delegate
			{
				IncomingHrData(model);
			});
		}

		private void IncomingHrData(ChartMetricModel model)
		{
			if (model.DataProvider is HistoricalStatChartDataProvider { IsDataBinned: not false } historicalStatChartDataProvider)
			{
				AddToCurrentMetric(historicalStatChartDataProvider.BinnedData?.LastOrDefault());
			}
			else
			{
				AddToCurrentMetric(model?.DataProvider?.ProviderData?.LastOrDefault());
			}
		}

		private void AddToCurrentMetric(Tuple<double, double> value)
		{
			try
			{
				if (value != null)
				{
					double item = value.Item1;
					double item2 = value.Item2;
					item2 = Math.Max(item2, minimumZ1Bpm);
					HRCurrentMetric.Add(new Tuple<double, double>(item, item2));
					double key = item - 90.0;
					HRCurrentMetric.RemoveDataBeforeKey(key);
				}
			}
			catch (Exception exception)
			{
				Log.Error("HRZoneLineChartViewModel", "Exception when adding HR data to current metric", exception);
			}
		}

		protected void OnTimeChanged(double current)
		{
			ChartMinTime.Value = (int)current - 90;
			ChartMaxTime.Value = (int)current + 90;
		}

		private void HistoricDataIntoCurrent()
		{
			if (ChartData == null)
			{
				return;
			}
			int num = Array.FindIndex(ChartData.CurrentMetrics, (ChartMetricModel x) => x.DataConfig.Metric == ChartMetricConfiguration.MetricType.HeartRate);
			if (num > -1 && ChartData.CurrentMetrics[num].DataProvider is HistoricalStatChartDataProvider historicalStatChartDataProvider)
			{
				for (int num2 = 0; num2 < historicalStatChartDataProvider.BinnedData.Count; num2++)
				{
					AddToCurrentMetric(historicalStatChartDataProvider.BinnedData[num2]);
				}
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			hrUpdatedSub?.Dispose();
			hrUpdatedSub = null;
			chartSub?.Dispose();
			chartSub = null;
			timeUpdatedSub?.Dispose();
			timeUpdatedSub = null;
			maxHeartRateChangedSub?.Dispose();
			maxHeartRateChangedSub = null;
			UnregisterChangeHandlers();
		}

		protected override Task OnHRDataUpdated(HRZoneUpdate zoneUpdate)
		{
			return Task.FromResult(result: true);
		}

