	public class HRZoneMyZonesViewModel : BaseViewModel, IHRWidgetModeNotifier
	{
		private readonly IIfitApiService api;

		private Subject<WidgetType> _hrWidgetModeChanged = new Subject<WidgetType>();

		public INC<UserHRZoneUIAdapter> Zone5 = new NC<UserHRZoneUIAdapter>();

		public INC<UserHRZoneUIAdapter> Zone4 = new NC<UserHRZoneUIAdapter>();

		public INC<UserHRZoneUIAdapter> Zone3 = new NC<UserHRZoneUIAdapter>();

		public INC<UserHRZoneUIAdapter> Zone2 = new NC<UserHRZoneUIAdapter>();

		public INC<UserHRZoneUIAdapter> Zone1 = new NC<UserHRZoneUIAdapter>();

		public INC<User> LoggedInUser = new NC<User>();

		public IObservable<WidgetType> HRWidgetTypeChanged => _hrWidgetModeChanged;

		public string TitleString => Wolf.Core.Resources.AppStrings.activepulse_training;

		public string DescriptionString => Wolf.Core.Resources.AppStrings.my_hr_zone_description;

		public ICommand Exit => new MvxCommand(DoExit);

		public HRZoneMyZonesViewModel(ILocalSettings localSettings, IIfitApiService api)
			: base(localSettings)
		{
			try
			{
				this.api = api;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			LoggedInUser.Value = api.CurrentlyAuthenticatedUser;
			try
			{
				UserHeartRateSettings userHeartRateSettings = await (await User.GetMe(api)).GetHeartRateSettings(api, force: true);
				Zone5.Value = (from x in userHeartRateSettings.Zones
					where x.ZoneNumber == 5
					select new UserHRZoneUIAdapter(x)).FirstOrDefault();
				Zone4.Value = (from x in userHeartRateSettings.Zones
					where x.ZoneNumber == 4
					select new UserHRZoneUIAdapter(x)).FirstOrDefault();
				Zone3.Value = (from x in userHeartRateSettings.Zones
					where x.ZoneNumber == 3
					select new UserHRZoneUIAdapter(x)).FirstOrDefault();
				Zone2.Value = (from x in userHeartRateSettings.Zones
					where x.ZoneNumber == 2
					select new UserHRZoneUIAdapter(x)).FirstOrDefault();
				Zone1.Value = (from x in userHeartRateSettings.Zones
					where x.ZoneNumber == 1
					select new UserHRZoneUIAdapter(x)).FirstOrDefault();
			}
			catch (Exception ex) when (!(ex is iFit.Api.Support.ConnectivityException))
			{
				Log.Error("HRZoneMyZonesViewModel", "Failed to retrieve HR zones", ex);
			}
		}

		private void DoExit()
		{
			_hrWidgetModeChanged.OnNext(WidgetType.HRTarget);
		}

