	public abstract class HRZoneTargetBaseViewModel : HRZoneUpdatingBaseViewModel
	{
		protected const string ValuePlaceHolder = "--";

		protected string PercentOrBlank;

		public readonly SplatColor DefaultLeftBGColor;

		public readonly INC<string> CurrentLabelText;

		public readonly INC<string> CurrentValueText;

		public readonly INC<string> TargetLabelText;

		public readonly INC<string> TargetValueText;

		protected abstract string TargetLabelTextToUse { get; }

		protected HRZoneTargetBaseViewModel(ILocalSettings localSettings, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService, IIfitApiService api, IHRZoneUpdatingAnalyticsService hrZoneUpdatingAnalyticsService)
		{
			try
			{
				PercentOrBlank = "";
				DefaultLeftBGColor = Colors.HRZoneDefaultWidgetBackground;
				CurrentLabelText = new NC<string>(string.Empty);
				CurrentValueText = new NC<string>("--");
				TargetLabelText = new NC<string>(string.Empty);
				TargetValueText = new NC<string>("--");
				base..ctor(localSettings, hrTrainingService, workoutFeatureService, hrZoneUpdatingAnalyticsService);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected abstract string GetBpmValueForDisplay(int bpm, int restingHR, int hrReserve);

		protected override Task OnHRDataUpdated(HRZoneUpdate zoneUpdate)
		{
			if (zoneUpdate == null)
			{
				return Task.FromResult(0);
			}
			UpdateCurrentValues(zoneUpdate);
			if (!IsCountingDown.Value && zoneUpdate.TargetZone != null)
			{
				UpdateTargetValues(zoneUpdate);
			}
			return Task.FromResult(0);
		}

		private void UpdateCurrentValues(HRZoneUpdate zoneUpdate)
		{
			CurrentValueText.Value = ((zoneUpdate.CurrentBpm == 0) ? "--" : GetBpmValueForDisplay(zoneUpdate.CurrentBpm, zoneUpdate.RestingHR, zoneUpdate.HRReserve));
		}

		private void UpdateTargetValues(HRZoneUpdate zoneUpdate)
		{
			if (zoneUpdate.HasAchievedCurrentZone)
			{
				TargetLabelText.Value = Wolf.Core.Resources.AppStrings.target_bpm.ToUpper();
			}
			else
			{
				TargetLabelText.Value = Wolf.Core.Resources.AppStrings.expected_bpm.ToUpper();
			}
			string bpmValueForDisplay = GetBpmValueForDisplay(zoneUpdate.BpmRange[0], zoneUpdate.RestingHR, zoneUpdate.HRReserve);
			string bpmValueForDisplay2 = GetBpmValueForDisplay(zoneUpdate.BpmRange[1], zoneUpdate.RestingHR, zoneUpdate.HRReserve);
			TargetValueText.Value = bpmValueForDisplay + "-" + bpmValueForDisplay2 + PercentOrBlank;
		}

