	public abstract class HRZoneUpdatingBaseViewModel : BaseViewModel
	{
		public enum CenterImage
		{
			None,
			Up,
			TrendingUp,
			Check,
			TrendingDown,
			Down,
			Heart
		}

		public enum MessageImage
		{
			Heart,
			Clock
		}

		private IDisposable hrUpdatedSub;

		private IDisposable countdownTimeSub;

		private readonly IHRZoneUpdatingAnalyticsService hrZoneUpdatingAnalyticsService;

		private HRZoneUpdatingBaseViewModelMetrics metrics;

		protected readonly IWorkoutFeatureService workoutFeatureService;

		public readonly INC<bool> IsCountingDown = new NC<bool>(value: true);

		public readonly INC<CenterImage> CenterIcon = new NC<CenterImage>(CenterImage.Heart);

		public readonly INC<bool> InTargetZone = new NC<bool>(value: true);

		public readonly INC<int> CurrentTargetZoneNum = new NC<int>();

		public readonly INC<SplatColor> TargetZoneColor = new NC<SplatColor>(new UserHeartRateZone(0, 0, 0).GetColorForTargetWidget());

		public readonly INC<string> TargetZoneText = new NC<string>(string.Format(Wolf.Core.Resources.AppStrings.zone_num, string.Empty).ToUpper());

		public readonly INC<string> PulseStatusMessage = new NC<string>(Wolf.Core.Resources.AppStrings.hr_widget_state_calibrating);

		public readonly INC<MessageImage> StatusMessageImage = new NC<MessageImage>(MessageImage.Clock);

		public readonly INC<WorkoutScaleState> ScaleState = new NC<WorkoutScaleState>(WorkoutScaleState.WarmingUp);

		public readonly INC<string> ActualBpm = new NC<string>(Wolf.Core.Resources.AppStrings.hr_widget_actual_bpm.ToUpper());

		public readonly INC<string> ProjectedBpm = new NC<string>(Wolf.Core.Resources.AppStrings.hr_widget_projected_bpm.ToUpper());

		protected virtual TimeSpan CountdownPeriod => HRTrainingService.CountdownPeriod;

		public IHRTrainingService HrTrainingService { get; set; }

		public IMvxCommand MoreInfo => new MvxCommand(DoMoreInfo);

		protected HRZoneUpdatingBaseViewModel(ILocalSettings localSettings, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService, IHRZoneUpdatingAnalyticsService hrZoneUpdatingAnalyticsService)
			: base(localSettings)
		{
			try
			{
				HrTrainingService = hrTrainingService;
				this.workoutFeatureService = workoutFeatureService;
				this.hrZoneUpdatingAnalyticsService = hrZoneUpdatingAnalyticsService;
				hrUpdatedSub = hrTrainingService.WhenHRZoneDataChanged?.Where((HRZoneUpdate x) => x != null)?.SubscribeAsyncWithErrorLogging(HRDataUpdated);
				if (workoutFeatureService.IsActivePulseAvailableInWorkout())
				{
					IFitnessConsole console = workoutSettings?.WorkoutContainer?.Console;
					countdownTimeSub = facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().Where((Func<FitnessValueChange<int>, bool>)delegate
					{
						IFitnessConsole fitnessConsole = console;
						return fitnessConsole != null && fitnessConsole.LatestBasicInfo?.CurrentState == ConsoleState.Workout;
					}).SubscribeAsync(OnConsoleTimeChanged);
				}
				hrZoneUpdatingAnalyticsService?.SetInWorkoutMetricsManager(workoutSettings?.WorkoutContainer?.Stats.RunningStats.InWorkoutMetrics);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private Task HRDataUpdated(HRZoneUpdate zoneUpdate)
		{
			if (zoneUpdate == null || zoneUpdate.TargetZone == null)
			{
				return Task.FromResult(result: true);
			}
			UpdateTargetZone(zoneUpdate);
			UpdateStatusMessageAndIcon(zoneUpdate);
			return OnHRDataUpdated(zoneUpdate);
		}

		private void UpdateTargetZone(HRZoneUpdate zoneUpdate)
		{
			CurrentTargetZoneNum.Value = zoneUpdate.TargetZone.ZoneNumber;
			TargetZoneColor.Value = zoneUpdate.TargetZone.GetColorForTargetWidget();
			InTargetZone.Value = zoneUpdate.CurrentBpmMatchesTargetZone;
			TargetZoneText.Value = string.Format(Wolf.Core.Resources.AppStrings.zone_num, zoneUpdate.TargetZone.ZoneNumber).ToUpper();
			hrZoneUpdatingAnalyticsService?.UpdateHRZoneMetrics(CurrentTargetZoneNum.Value, InTargetZone.Value);
			TargetZoneText.Value = string.Format(Wolf.Core.Resources.AppStrings.zone_num, CurrentTargetZoneNum.Value).ToUpper();
			if (metrics == null)
			{
				metrics = new HRZoneUpdatingBaseViewModelMetrics(workoutFeatureService, workoutSettings?.WorkoutContainer?.Stats.RunningStats.InWorkoutMetrics);
			}
			metrics.UpdateHRZoneMetrics(CurrentTargetZoneNum.Value, InTargetZone.Value);
		}

		protected void UpdateStatusMessageAndIcon(HRZoneUpdate zoneUpdate)
		{
			if (!personalTrainingSettings.ActivePulseEnabled || !workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse))
			{
				ScaleState.Value = WorkoutScaleState.Disabled;
				CenterIcon.Value = CenterImage.Heart;
			}
			else if (IsCountingDown.Value)
			{
				ScaleState.Value = WorkoutScaleState.WarmingUp;
			}
			else if (zoneUpdate.ScaleState == WorkoutScaleState.ScalingDown && !zoneUpdate.SuppressNotificationOnUpdate)
			{
				ScaleState.Value = WorkoutScaleState.ScalingDown;
				CenterIcon.Value = CenterImage.Down;
			}
			else if (zoneUpdate.ScaleState == WorkoutScaleState.ScalingUp && !zoneUpdate.SuppressNotificationOnUpdate)
			{
				ScaleState.Value = WorkoutScaleState.ScalingUp;
				CenterIcon.Value = CenterImage.Up;
			}
			else if (zoneUpdate.CurrentBpmMatchesTargetZone)
			{
				ScaleState.Value = WorkoutScaleState.OnTarget;
				CenterIcon.Value = CenterImage.Check;
			}
			else if (zoneUpdate.ScaleState == WorkoutScaleState.TrendingDown)
			{
				ScaleState.Value = WorkoutScaleState.TrendingDown;
				CenterIcon.Value = CenterImage.TrendingDown;
			}
			else if (zoneUpdate.ScaleState == WorkoutScaleState.TrendingUp)
			{
				ScaleState.Value = WorkoutScaleState.TrendingUp;
				CenterIcon.Value = CenterImage.TrendingUp;
			}
			else
			{
				ScaleState.Value = WorkoutScaleState.Monitoring;
				CenterIcon.Value = CenterImage.Heart;
			}
			StatusMessageImage.Value = MessageImage.Heart;
			switch (ScaleState.Value)
			{
			case WorkoutScaleState.Disabled:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.activepulse_off;
				break;
			case WorkoutScaleState.OnTarget:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.hr_widget_state_on_target;
				break;
			case WorkoutScaleState.TrendingUp:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.hr_widget_state_trending_up;
				break;
			case WorkoutScaleState.TrendingDown:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.hr_widget_state_trending_down;
				break;
			case WorkoutScaleState.ScalingUp:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.hr_widget_state_scale_up;
				break;
			case WorkoutScaleState.ScalingDown:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.hr_widget_state_scale_down;
				break;
			case WorkoutScaleState.Monitoring:
				PulseStatusMessage.Value = Wolf.Core.Resources.AppStrings.hr_widget_state_monitoring;
				break;
			case WorkoutScaleState.WarmingUp:
				StatusMessageImage.Value = MessageImage.Clock;
				break;
			}
		}

		protected abstract Task OnHRDataUpdated(HRZoneUpdate zoneUpdate);

		protected virtual void OnCountdownUpdated(TimeSpan remainingTime)
		{
		}

		private async Task OnConsoleTimeChanged(FitnessValueChange<int> metricChange)
		{
			await UpdateForCurrentTime(metricChange.Current);
		}

		protected async Task UpdateForCurrentTime(double currentTimeSeconds)
		{
			TimeSpan currAt = TimeSpan.FromSeconds(currentTimeSeconds);
			if (currAt < CountdownPeriod)
			{
				IsCountingDown.Value = true;
				OnCountdownUpdated(CountdownPeriod - currAt);
			}
			else if (countdownTimeSub != null)
			{
				countdownTimeSub?.Dispose();
				countdownTimeSub = null;
				HRZoneUpdate zoneUpdate = await (HrTrainingService.WhenHRZoneDataChanged?.FirstOrDefaultAsync());
				IsCountingDown.Value = false;
				OnCountdownUpdated(CountdownPeriod - currAt);
				await HRDataUpdated(zoneUpdate).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private void DoMoreInfo()
		{
			workoutFeatureService.ShowDebugPulseChangeLevelView = !workoutFeatureService.ShowDebugPulseChangeLevelView;
		}

		public override void Dispose()
		{
			base.Dispose();
			hrUpdatedSub?.Dispose();
			hrUpdatedSub = null;
			countdownTimeSub?.Dispose();
			countdownTimeSub = null;
			UnregisterChangeHandlers();
		}

