	public class HRZoneUpdatingBaseViewModelMetrics
	{
		private readonly IInWorkoutMetricsManager inWorkoutMetrics;

		private readonly IWorkoutFeatureService workoutFeatureService;

		private int prevCurrentTargetZoneNum;

		private bool prevInTargetZone;

		private bool prevActivePulse;

		public HRZoneUpdatingBaseViewModelMetrics(IWorkoutFeatureService workoutFeatureService, IInWorkoutMetricsManager inWorkoutMetrics)
		{
			this.workoutFeatureService = workoutFeatureService;
			this.inWorkoutMetrics = inWorkoutMetrics;
		}

		public void UpdateHRZoneMetrics(int currentTargetZoneNum, bool inTargetZone)
		{
			if (inWorkoutMetrics != null && !DidNothingChangeToRecordMetrics(currentTargetZoneNum, inTargetZone))
			{
				StopRecordingPreviousZoneIfNeedBe(currentTargetZoneNum);
				StartStopCurrentZone(currentTargetZoneNum, inTargetZone);
				SaveCurrentValues(currentTargetZoneNum, inTargetZone);
			}
		}

		private void SaveCurrentValues(int currentTargetZoneNum, bool inTargetZone)
		{
			prevCurrentTargetZoneNum = currentTargetZoneNum;
			prevInTargetZone = inTargetZone;
			prevActivePulse = workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse);
		}

		private bool DidNothingChangeToRecordMetrics(int currentTargetZoneNum, bool inTargetZone)
		{
			bool flag = workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse);
			if (prevActivePulse == flag && prevCurrentTargetZoneNum == currentTargetZoneNum)
			{
				return prevInTargetZone == inTargetZone;
			}
			return false;
		}

		private void StartStopCurrentZone(int currentTargetZoneNum, bool inTargetZone)
		{
			bool flag = workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse);
			InWorkoutMetric metric = currentTargetZoneNum.HRZoneToMetric();
			if (inTargetZone && flag)
			{
				inWorkoutMetrics.StartRecordingMetricTime(metric);
			}
			else
			{
				inWorkoutMetrics.StopRecordingMetricTime(metric, DateTime.UtcNow);
			}
		}

		private void StopRecordingPreviousZoneIfNeedBe(int currentTargetZoneNum)
		{
			if (prevCurrentTargetZoneNum != currentTargetZoneNum && prevCurrentTargetZoneNum > 0)
			{
				InWorkoutMetric metric = prevCurrentTargetZoneNum.HRZoneToMetric();
				inWorkoutMetrics.StopRecordingMetricTime(metric, DateTime.UtcNow);
			}
		}
	}
	public static class HRZoneExtensions
	{
		public static SplatColor GetColorForTargetWidget(this UserHeartRateZone zone)
		{
			return zone?.ZoneNumber switch
			{
				1 => Colors.HRZone1WidgetBackground, 
				2 => Colors.HRZone2WidgetBackground, 
				3 => Colors.HRZone3WidgetBackground, 
				4 => Colors.HRZone4WidgetBackground, 
				5 => Colors.HRZone5WidgetBackground, 
				_ => Colors.HRZone1WidgetBackground, 
			};
		}

		public static InWorkoutMetric HRZoneToMetric(this int hrZone)
		{
			return hrZone switch
			{
				1 => InWorkoutMetric.TimeInTargetZoneOne, 
				2 => InWorkoutMetric.TimeInTargetZoneTwo, 
				3 => InWorkoutMetric.TimeInTargetZoneThree, 
				4 => InWorkoutMetric.TimeInTargetZoneFour, 
				5 => InWorkoutMetric.TimeInTargetZoneFive, 
				_ => InWorkoutMetric.NotInitialized, 
			};
		}

		public static InWorkoutMetric WorkoutInZoneMetric(this int zoneNum)
		{
			return zoneNum switch
			{
				1 => InWorkoutMetric.TimeWorkoutInZoneOne, 
				2 => InWorkoutMetric.TimeWorkoutInZoneTwo, 
				3 => InWorkoutMetric.TimeWorkoutInZoneThree, 
				4 => InWorkoutMetric.TimeWorkoutInZoneFour, 
				5 => InWorkoutMetric.TimeWorkoutInZoneFive, 
				_ => InWorkoutMetric.NotInitialized, 
			};
		}

		public static InWorkoutMetric WorkoutEnteredZoneMetric(this int zoneNum)
		{
			return zoneNum switch
			{
				1 => InWorkoutMetric.EnteredZoneOne, 
				2 => InWorkoutMetric.EnteredZoneTwo, 
				3 => InWorkoutMetric.EnteredZoneThree, 
				4 => InWorkoutMetric.EnteredZoneFour, 
				5 => InWorkoutMetric.EnteredZoneFive, 
				_ => InWorkoutMetric.NotInitialized, 
			};
		}
	}
