	public static class HeadphonePickerItemViewModelExtensions
	{
		public static void SortDevices(this ImprovedObservableCollection<HeadphonePickerItemViewModel> devices)
		{
			HeadphonePickerItemViewModel[] collection = devices.Where((HeadphonePickerItemViewModel d) => d.State.Value == HeadphoneDeviceState.Connected).Take(1).ToArray();
			HeadphonePickerItemViewModel[] collection2 = devices.Where((HeadphonePickerItemViewModel d) => d.State.Value == HeadphoneDeviceState.Connecting).Take(1).ToArray();
			HeadphonePickerItemViewModel[] collection3 = (from d in devices
				where d.State.Value == HeadphoneDeviceState.Disconnected
				orderby d.Device.Value.Rssi descending
				select d).ToArray();
			List<HeadphonePickerItemViewModel> list = new List<HeadphonePickerItemViewModel>();
			list.AddRange(collection);
			list.AddRange(collection2);
			list.AddRange(collection3);
			if (!devices.SequenceEqual(list))
			{
				devices.ReplaceItems(list);
			}
			list.Clear();
		}
	}
	public class HeadphonePickerViewModel : BaseViewModel
	{
		public static readonly TimeSpan MinimumFoundDeviceUpdateInterval = TimeSpan.FromSeconds(2.0);

		public readonly ImprovedObservableCollection<HeadphonePickerItemViewModel> Devices = new ImprovedObservableCollection<HeadphonePickerItemViewModel>();

		protected readonly HeadphoneConnectionHelperBase ConnectionHelper;

		private readonly IList<IHeadphone> foundDevices = new List<IHeadphone>();

		private DateTime lastFoundDeviceUpdate;

		private readonly ISet<Guid> headphonesFoundInLatestScan;

		private IDisposable deviceFoundSub;

		private IDisposable addFoundDevicesTimerSub;

		public string HeaderText
		{
			get
			{
				if (!currentConsoleService.IsCurrentConsoleClub)
				{
					return Wolf.Core.Resources.AppStrings.bluetooth_device_picker_title;
				}
				return Wolf.Core.Resources.AppStrings.headphones_picker_title;
			}
		}

		public string InstructionsText
		{
			get
			{
				if (!currentConsoleService.IsCurrentConsoleClub)
				{
					return Wolf.Core.Resources.AppStrings.bluetooth_device_picker_instructions;
				}
				return Wolf.Core.Resources.AppStrings.headphones_picker_instructions;
			}
		}

		public string LoadingText => Wolf.Core.Resources.AppStrings.headphones_picker_loading_text;

		public MvxAsyncCommand<HeadphonePickerItemViewModel> HandleConnection => new MvxAsyncCommand<HeadphonePickerItemViewModel>(DoHandleConnection);

		public HeadphonePickerViewModel(ILocalSettings localSettings, HeadphoneConnectionHelperBase connectionHelper, ICurrentConsoleService currentConsoleService)
			: base(localSettings)
		{
			try
			{
				ConnectionHelper = connectionHelper;
				headphonesFoundInLatestScan = new HashSet<Guid>();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (deviceFoundSub == null)
			{
				deviceFoundSub = ConnectionHelper.OnDeviceFound.SubscribeWithErrorLogging(AddFoundDevice);
			}
			ConnectionHelper.ScanEnded -= OnScanEnded;
			ConnectionHelper.ScanEnded += OnScanEnded;
			await ConnectionHelper.Start().ConfigureAwait(continueOnCapturedContext: false);
			Log.Trace("Headphone", "HeadphonePickerViewModel starting scan.");
			BeginScan();
		}

		private void AddFoundDevice(IHeadphone device)
		{
			lock (headphonesFoundInLatestScan)
			{
				headphonesFoundInLatestScan.Add(device.Id);
			}
			TimeSpan timeSpan = DateTime.UtcNow - lastFoundDeviceUpdate;
			if (timeSpan > MinimumFoundDeviceUpdateInterval)
			{
				lastFoundDeviceUpdate = DateTime.UtcNow;
				UpdateDevice(device);
				return;
			}
			foundDevices.Add(device);
			if (addFoundDevicesTimerSub == null)
			{
				DateTime dateTime = lastFoundDeviceUpdate + MinimumFoundDeviceUpdateInterval;
				addFoundDevicesTimerSub = Observable.Timer(dateTime).Subscribe(delegate
				{
					AddFoundDevicesAndDisposeTimerOnMainThread();
				});
			}
		}

		private void UpdateDevice(IHeadphone device)
		{
			InvokeOnMainThread(delegate
			{
				if (device != null)
				{
					AddDevice(device);
					Devices.SortDevices();
				}
			});
		}

		private void AddDevice(IHeadphone device)
		{
			HeadphonePickerItemViewModel headphonePickerItemViewModel = Devices.FirstOrDefault((HeadphonePickerItemViewModel x) => x.Device.Value.Id == device.Id);
			if (headphonePickerItemViewModel == null)
			{
				HeadphonePickerItemViewModel headphonePickerItemViewModel2 = new HeadphonePickerItemViewModel(localSettings, ConnectionHelper, device);
				Devices.Add(headphonePickerItemViewModel2);
				headphonePickerItemViewModel2.State.Changed -= SortDevices;
				headphonePickerItemViewModel2.State.Changed += SortDevices;
			}
		}

		private void SortDevices(object sender, EventArgs e)
		{
			Devices.SortDevices();
		}

		private void AddFoundDevicesAndDisposeTimerOnMainThread()
		{
			InvokeOnMainThread(delegate
			{
				while (foundDevices.Any())
				{
					IHeadphone device = foundDevices[0];
					foundDevices.RemoveAt(0);
					AddDevice(device);
				}
				Devices.SortDevices();
				addFoundDevicesTimerSub?.Dispose();
				addFoundDevicesTimerSub = null;
				lastFoundDeviceUpdate = DateTime.UtcNow;
			});
		}

		private void OnScanEnded(object sender, EventArgs args)
		{
			InvokeOnMainThread(delegate
			{
				lock (headphonesFoundInLatestScan)
				{
					foreach (HeadphonePickerItemViewModel item in Devices.Where(IsDisconnectedAndNotInLatestScan).ToList())
					{
						item.State.Changed -= SortDevices;
						Devices.Remove(item);
						item.Dispose();
					}
					headphonesFoundInLatestScan.Clear();
				}
			});
		}

		private bool IsDisconnectedAndNotInLatestScan(HeadphonePickerItemViewModel item)
		{
			if (item.State.Value != HeadphoneDeviceState.Disconnected)
			{
				return false;
			}
			IHeadphone value = item.Device.Value;
			if (value == null)
			{
				return true;
			}
			if (ConnectionHelper.GetCurrentBondState(value) == BondState.Unbonded)
			{
				return !headphonesFoundInLatestScan.Contains(value.Id);
			}
			return false;
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				CleanUp();
				base.Dispose();
				UnregisterChangeHandlers();
			}
		}

		private void CleanUp()
		{
			deviceFoundSub?.Dispose();
			deviceFoundSub = null;
			addFoundDevicesTimerSub?.Dispose();
			addFoundDevicesTimerSub = null;
			foundDevices.Clear();
			ConnectionHelper.EndScan();
			ConnectionHelper.Stop();
			Devices.ExcludingNulls().DoForEach(delegate(HeadphonePickerItemViewModel d)
			{
				d.State.Changed -= SortDevices;
				d.Dispose();
			});
			InvokeOnMainThread(Devices.Clear);
		}

		private async Task DoHandleConnection(HeadphonePickerItemViewModel model)
		{
			IHeadphone value = model.Device.Value;
			HeadphoneDeviceState state = ConnectionHelper.GetState(value);
			switch (state)
			{
			case HeadphoneDeviceState.Disconnected:
			case HeadphoneDeviceState.Connecting:
				Log.Trace("Ble", "Connecting to device " + value?.Name);
				ConnectionHelper.EndScan();
				await ConnectionHelper.BondWithDevice(value).ConfigureAwait(continueOnCapturedContext: true);
				if (deviceFoundSub != null)
				{
					BeginScan();
				}
				break;
			case HeadphoneDeviceState.Connected:
				Log.Trace("Ble", "Disconnecting from device " + value?.Name);
				await ConnectionHelper.UnbondWithDevice(value).ConfigureAwait(continueOnCapturedContext: true);
				break;
			default:
				Log.Error("Ble", $"Unknown headphone state {state}");
				break;
			}
		}

		private void BeginScan()
		{
			ConnectionHelper.BeginScan();
		}

