	public class ChartsHeaderPageViewModel : BaseHeaderPageViewModel
	{
		private readonly List<IDisposable> Observables = new List<IDisposable>();

		public readonly INC<bool> IsMetric = new NC<bool>();

		public readonly INC<float> ChartMax = new NC<float>();

		public readonly INC<float> ChartMin = new NC<float>();

		public readonly INC<bool> ViewModelInitialized = new NC<bool>();

		public readonly INC<Tuple<double, double>> Current1 = new NC<Tuple<double, double>>();

		public readonly INC<Tuple<double, double>> Current2 = new NC<Tuple<double, double>>();

		public readonly INC<Tuple<double, double>> Current3 = new NC<Tuple<double, double>>();

		public readonly INC<Tuple<double, double>> Current4 = new NC<Tuple<double, double>>();

		public readonly INC<Tuple<double, double>> Current5 = new NC<Tuple<double, double>>();

		private readonly ISettingsRouter settingsRouter;

		public override InWorkoutHeaderHudType PageType => InWorkoutHeaderHudType.Charts;

		public InWorkoutChartDataProvider ChartData => workoutSettings.WorkoutContainer?.ChartData;

		public Theme CurrentTheme => themeService.AppTheme;

		public IChartLabelUtil XAxisFormatter => ChartData.XAxisFormatter;

		public bool HasInclineMetric
		{
			get
			{
				if (!HasMetricType(ChartMetricConfiguration.MetricType.Incline))
				{
					return HasMetricType(ChartMetricConfiguration.MetricType.PredictedIncline);
				}
				return true;
			}
		}

		public bool HasResistanceMetric
		{
			get
			{
				if (!HasMetricType(ChartMetricConfiguration.MetricType.Resistance))
				{
					return HasMetricType(ChartMetricConfiguration.MetricType.PredictedResistance);
				}
				return true;
			}
		}

		public bool HasGearMetric
		{
			get
			{
				if (!HasMetricType(ChartMetricConfiguration.MetricType.Gear))
				{
					return HasMetricType(ChartMetricConfiguration.MetricType.PredictedGear);
				}
				return true;
			}
		}

