			}
		}

		public override void Dispose()
		{
			foreach (IDisposable observable in Observables)
			{
				observable.Dispose();
			}
			Observables.Clear();
			((BaseViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (base.viewShownCount > 1)
			{
				Log.Debug("Charting", $"Early out from ChartsHeaderPageViewModel.OnViewShown because viewShownCount is {base.viewShownCount}");
			}
		}

		private bool HasMetricType(ChartMetricConfiguration.MetricType metricType)
		{
			ChartMetricConfiguration metric1Config = Metric1Config;
			if (metric1Config == null || metric1Config.Metric != metricType)
			{
				ChartMetricConfiguration metric2Config = Metric2Config;
				if (metric2Config == null || metric2Config.Metric != metricType)
				{
					ChartMetricConfiguration metric3Config = Metric3Config;
					if (metric3Config == null || metric3Config.Metric != metricType)
					{
						ChartMetricConfiguration metric4Config = Metric4Config;
						if (metric4Config == null || metric4Config.Metric != metricType)
						{
							ChartMetricConfiguration metric5Config = Metric5Config;
							if (metric5Config == null)
							{
								return false;
							}
							return metric5Config.Metric == metricType;
						}
					}
				}
			}
			return true;
		}

		public async Task OnShownAsync()
		{
			Log.Debug("Charting", "ChartsHeader initializing");
			INC<bool> isMetric = IsMetric;
			isMetric.Value = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				IConsoleInfo consoleInfo = currentConsoleService.ActiveConsole.ConsoleInfo;
				double val = (IsMetric.Value ? consoleInfo.MaxKph : UnitUtil.EnsureMph(SpeedUnit.Kph, consoleInfo.MaxKph));
				double maxResistanceLevel = consoleInfo.MaxResistanceLevel;
				double maxIncline = consoleInfo.MaxIncline;
				double minIncline = consoleInfo.MinIncline;
				int maxGear = consoleInfo.MaxGear;
				int minGear = consoleInfo.MinGear;
				ChartMax.Value = (float)Math.Max(Math.Max(Math.Max(maxGear, val), maxResistanceLevel), maxIncline) + 1f;
				ChartMin.Value = (float)Math.Min(Math.Min(0, minGear), minIncline) - 1f;
			}
			catch (NullReferenceException exception)
			{
				ICurrentConsoleService obj = currentConsoleService;
				int num;
				if (obj == null)
				{
					num = 1;
				}
				else
				{
					IFitnessConsole activeConsole = obj.ActiveConsole;
					if (activeConsole == null)
					{
						num = 1;
					}
					else
					{
						IConsoleInfo consoleInfo2 = activeConsole.ConsoleInfo;
						if (consoleInfo2 == null)
						{
							num = 1;
						}
						else
						{
							_ = consoleInfo2.MaxIncline;
							num = 0;
						}
					}
				}
				if (num != 0)
				{
					Log.Error("Charting", "Null value for ConsoleInfo Incline");
				}
				else
				{
					Log.Error("Charting", "Null value for ChartData");
				}
				Log.Error("Charting", "Null reference when trying to calculate elevation scaler", exception);
			}
			Current1.Value = new Tuple<double, double>(0.0, 0.0);
			Current2.Value = new Tuple<double, double>(0.0, 0.0);
			Current3.Value = new Tuple<double, double>(0.0, 0.0);
			Current4.Value = new Tuple<double, double>(0.0, 0.0);
			Current5.Value = new Tuple<double, double>(0.0, 0.0);
			if (ChartData != null)
			{
				if (currentConsoleService.ActiveConsole.ConsoleInfo.MachineType.IsBeltBasedMachine())
				{
					AssignMetricModel(ChartMetricConfiguration.MetricType.Speed);
					AssignMetricModel(ChartMetricConfiguration.MetricType.PredictedSpeed);
					InWorkoutChartDataProvider chartData = ChartData;
					if (chartData != null && chartData.SupportsIncline?.Value == true)
					{
						AssignMetricModel(ChartMetricConfiguration.MetricType.Incline);
						AssignMetricModel(ChartMetricConfiguration.MetricType.PredictedIncline);
					}
				}
				else
				{
					InWorkoutChartDataProvider chartData2 = ChartData;
					if (chartData2 != null && chartData2.SupportsSpeed?.Value == true)
					{
						AssignMetricModel(ChartMetricConfiguration.MetricType.Speed);
					}
					InWorkoutChartDataProvider chartData3 = ChartData;
					if (chartData3 != null && chartData3.SupportsIncline?.Value == true)
					{
						AssignMetricModel(ChartMetricConfiguration.MetricType.Incline);
						AssignMetricModel(ChartMetricConfiguration.MetricType.PredictedIncline);
					}
					InWorkoutChartDataProvider chartData4 = ChartData;
					if (chartData4 != null && chartData4.SupportsResistance?.Value == true)
					{
						AssignMetricModel(ChartMetricConfiguration.MetricType.Resistance);
						AssignMetricModel(ChartMetricConfiguration.MetricType.PredictedResistance);
					}
					InWorkoutChartDataProvider chartData5 = ChartData;
					if (chartData5 != null && chartData5.SupportsGear?.Value == true)
					{
						AssignMetricModel(ChartMetricConfiguration.MetricType.Gear);
						AssignMetricModel(ChartMetricConfiguration.MetricType.PredictedGear);
					}
				}
			}
			ViewModelInitialized.Value = true;
			Log.Debug("Charting", "ChartsHeader finished initializing");
		}

		private void AssignMetricModel(ChartMetricConfiguration.MetricType metricType)
		{
			ChartMetricModel chartMetricModel = ChartData.MetricModels.FirstOrDefault((ChartMetricModel cmm) => cmm != null && cmm.DataConfig.Metric == metricType);
			if (chartMetricModel == null)
			{
				return;
			}
			ChartDataCollection metric;
			bool currentEnabled;
			if (!Metric1Enabled)
			{
				SetMetricFields(chartMetricModel, Current1, out metric, out var metricConfig, out currentEnabled);
				Metric1 = metric;
				Metric1Enabled = metric != null;
				Metric1Config = metricConfig;
				Current1Enabled = currentEnabled;
				ChartMetricConfiguration metric1Config = Metric1Config;
				if (metric1Config != null && metric1Config.Scaler == ChartScalerType.Speed)
				{
					Metric1Scaler = new SpeedScaler(IsMetric.Value);
				}
			}
			else if (!Metric2Enabled)
			{
				SetMetricFields(chartMetricModel, Current2, out metric, out var metricConfig2, out currentEnabled);
				Metric2 = metric;
				Metric2Enabled = metric != null;
				Metric2Config = metricConfig2;
				Current2Enabled = currentEnabled;
				ChartMetricConfiguration metric2Config = Metric2Config;
				if (metric2Config != null && metric2Config.Scaler == ChartScalerType.Speed)
				{
					Metric2Scaler = Metric1Scaler;
				}
			}
			else if (!Metric3Enabled)
			{
				SetMetricFields(chartMetricModel, Current3, out metric, out var metricConfig3, out currentEnabled);
				Metric3 = metric;
				Metric3Enabled = metric != null;
				Metric3Config = metricConfig3;
				Current3Enabled = currentEnabled;
			}
			else if (!Metric4Enabled)
			{
				SetMetricFields(chartMetricModel, Current4, out metric, out var metricConfig4, out currentEnabled);
				Metric4 = metric;
				Metric4Enabled = metric != null;
				Metric4Config = metricConfig4;
				Current4Enabled = currentEnabled;
			}
			else if (!Metric5Enabled)
			{
				SetMetricFields(chartMetricModel, Current5, out metric, out var metricConfig5, out currentEnabled);
				Metric5 = metric;
				Metric5Enabled = metric != null;
				Metric5Config = metricConfig5;
				Current5Enabled = currentEnabled;
			}
		}

		private void SetMetricFields(ChartMetricModel metricModel, INC<Tuple<double, double>> current, out ChartDataCollection metric, out ChartMetricConfiguration metricConfig, out bool currentEnabled)
		{
			ChartMetricConfiguration dataConfig = metricModel.DataConfig;
			bool flag = !dataConfig.IsGoalBased;
			double targetValue = workoutSettings.WorkoutContainer.Workout.TargetValue;
			if ((dataConfig.IsGoalBased && !metricModel.ChartData.Any((Tuple<double, double> t) => t != null && t.Item1 > 0.0 && t != null && t.Item1 < targetValue)) || (flag && current == null))
			{
				metric = null;
				metricConfig = null;
				currentEnabled = false;
				return;
			}
			metric = metricModel.ChartData;
			metricConfig = dataConfig;
			currentEnabled = flag;
			if (flag && current != null)
			{
				RegisterCurrentValue(metric, current, metricModel);
			}
		}

		private void RegisterCurrentValue(ChartDataCollection chartData, INC<Tuple<double, double>> current, ChartMetricModel model)
		{
			Observables.Add(chartData.ObservableEvent().Subscribe(delegate
			{
				current.Value = model.DataProvider.ProviderData.LastOrDefault() ?? current.Value;
			}));
		}

