	public class MusicHeaderPageViewModel : BaseHeaderPageViewModel
	{
		private const string Tag = "Music";

		public readonly IMetric MainMetric;

		public readonly IMetric TopSubMetric;

		public readonly IMetric BottomSubMetric;

		public readonly INC<bool> PrevButtonEnabled = new NC<bool>();

		public readonly INC<bool> NextButtonEnabled = new NC<bool>();

		public readonly INC<AvailabilityStatus> MusicAvailability = new NC<AvailabilityStatus>(AvailabilityStatus.Unavailable);

		public readonly INC<bool> IsLoadingArtwork = new NC<bool>();

		public readonly INC<bool> IsPlayingMusic = new NC<bool>();

		public readonly INC<IBitmap> SongArtwork = new NC<IBitmap>();

		public readonly INC<string> SongTitle = new NC<string>();

		public readonly INC<string> SongPlaylist = new NC<string>();

		public override InWorkoutHeaderHudType PageType => InWorkoutHeaderHudType.Music;

		[DependsOn(new string[] { "MusicAvailability" })]
		public bool IsMusicLoading => MusicAvailability.Value == AvailabilityStatus.Loading;

		public ICommand PrevTrack => new MvxCommand(DoPrevTrack);

		public ICommand NextTrack => new MvxCommand(DoNextTrack);

		public ICommand PausePlay => new MvxCommand(DoPausePlay);

		public MusicHeaderPageViewModel(ILocalSettings localSettings, IWorkoutSettings workoutSettings)
			: base(localSettings)
		{
			try
			{
				MainMetric = workoutSettings.WorkoutContainer.ConsoleConfiguration.MusicHeaderMetric1;
				TopSubMetric = workoutSettings.WorkoutContainer.ConsoleConfiguration.MusicHeaderMetric2;
				BottomSubMetric = workoutSettings.WorkoutContainer.ConsoleConfiguration.MusicHeaderMetric3;
				SongTitle.Value = "Song title";
				SongPlaylist.Value = "Playlist title";
				DoPrevTrack();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void DoPrevTrack()
		{
			PrevButtonEnabled.Value = false;
			NextButtonEnabled.Value = true;
			IsPlayingMusic.Value = false;
			SetTestingArtwork("https://upload.wikimedia.org/wikipedia/en/4/42/Beatles_-_Abbey_Road.jpg");
			MusicAvailability.Value = AvailabilityStatus.Loading;
		}

		private async void DoNextTrack()
		{
			await Task.Run((Func<Task>)DoNextTrackAsync);
		}

		private async Task DoNextTrackAsync()
		{
			PrevButtonEnabled.Value = true;
			NextButtonEnabled.Value = false;
			IsPlayingMusic.Value = false;
			await SetTestingArtwork("https://upload.wikimedia.org/wikipedia/en/5/50/Sgt._Pepper's_Lonely_Hearts_Club_Band.jpg");
			MusicAvailability.Value = AvailabilityStatus.Loading;
			await Task.Delay(3000);
			MusicAvailability.Value = AvailabilityStatus.Available;
		}

		private void DoPausePlay()
		{
			IsPlayingMusic.Value = !IsPlayingMusic.Value;
		}

		private async Task SetTestingArtwork(string url)
		{
			IBitmap bitmap = null;
			SongArtwork.Value = bitmap;
			IsLoadingArtwork.Value = true;
			await Task.Delay(1000);
			try
			{
				HttpWebRequest httpWebRequest = WebRequest.CreateHttp(url);
				using WebResponse response = await Task.Factory.FromAsync(httpWebRequest.BeginGetResponse, httpWebRequest.EndGetResponse, null);
				using Stream stream = response.GetResponseStream();
				bitmap = await BitmapLoader.Current.Load(stream, null, null);
			}
			catch (Exception ex)
			{
				Log.Error("Music", ex.ToString());
			}
			finally
			{
				SongArtwork.Value = bitmap;
				IsLoadingArtwork.Value = false;
			}
		}

