	public class StatsHeaderPageViewModel : BaseHeaderPageViewModel
	{
		private readonly IInWorkoutFlipperMetricsManager inWorkoutFlipperMetricsManager;

		private IDisposable heartRateInitializedSub;

		private IDisposable heartRateValueSub;

		private IDisposable consoleHeartRateValueSub;

		private IDisposable heartRateDisconnectSub;

		private IDisposable consoleStateSub;

		private bool isHeartRateMonitorConnected;

		private bool hasReceivedPulse;

		public readonly ObservableCollection<IMetric> FlipperGroup1Metrics = new ObservableCollection<IMetric>();

		public readonly ObservableCollection<IMetric> FlipperGroup2Metrics = new ObservableCollection<IMetric>();

		public readonly ObservableCollection<IMetric> FlipperGroup3Metrics = new ObservableCollection<IMetric>();

		public readonly ObservableCollection<IMetric> FlipperGroup4Metrics = new ObservableCollection<IMetric>();

		public readonly ObservableCollection<IMetric> FlipperGroup5Metrics = new ObservableCollection<IMetric>();

		public readonly INC<bool> ConnectedToHeartRateMonitor = new NC<bool>();

		public readonly INC<bool> IsInCoolDown = new NC<bool>();

		public override InWorkoutHeaderHudType PageType => InWorkoutHeaderHudType.Stats;

		public ICommand UpdateVisibleFlipperCommand => new MvxCommand<(IMetric, IMetric)>(UpdateVisibleFlipper);

		public StatsHeaderPageViewModel(ILocalSettings localSettings, IWorkoutSettings workoutSettings, IHeartRateService heartRateService, IInWorkoutFlipperMetricsManager inWorkoutFlipperMetricsManager)
			: base(localSettings)
		{
			try
			{
				this.inWorkoutFlipperMetricsManager = inWorkoutFlipperMetricsManager;
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				if (workoutContainer != null && workoutContainer?.Console != null)
				{
					IConsoleConfiguration consoleConfiguration = workoutContainer.ConsoleConfiguration;
					Pulse pulse = workoutContainer?.Console?.LatestBasicInfo?.CurrentPulse;
					Pulse.Source source = pulse?.PulseSource ?? Pulse.Source.None;
					ConnectedToHeartRateMonitor.Value = pulse != null && pulse.UserPulse > 0 && source != Pulse.Source.None;
					consoleConfiguration.FlipperGroup1.DoForEach(delegate(IMetric metric)
					{
						FlipperGroup1Metrics.Add(metric);
					}, ignoreNulls: true);
					consoleConfiguration.FlipperGroup2.DoForEach(delegate(IMetric metric)
					{
						FlipperGroup2Metrics.Add(metric);
					}, ignoreNulls: true);
					consoleConfiguration.FlipperGroup3.DoForEach(delegate(IMetric metric)
					{
						FlipperGroup3Metrics.Add(metric);
					}, ignoreNulls: true);
					consoleConfiguration.FlipperGroup4.DoForEach(delegate(IMetric metric)
					{
						FlipperGroup4Metrics.Add(metric);
					}, ignoreNulls: true);
					consoleConfiguration.FlipperGroup5.DoForEach(delegate(IMetric metric)
					{
						FlipperGroup5Metrics.Add(metric);
					}, ignoreNulls: true);
					SetUpHeartRate(workoutContainer, heartRateService.HeartRate);
					SetupVisibleMetrics();
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void SetUpHeartRate(IWorkoutContainer container, IHeartRateHelper helper)
		{
			consoleHeartRateValueSub = facadeFactoryDependencies.PulseFacade.ObservePulseChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<Pulse> x)
			{
				Pulse.Source pulseSource = x.Current.PulseSource;
				if (pulseSource != Pulse.Source.None && x.Current.UserPulse > 0)
				{
					ConnectedToHeartRateMonitor.Value = true;
				}
				else if (pulseSource == Pulse.Source.None || x.Current.UserPulse <= 0)
				{
					ConnectedToHeartRateMonitor.Value = false;
				}
			});
			heartRateInitializedSub = helper.WhenConnectionChanged.SubscribeWithErrorLogging(delegate(bool connected)
			{
				if (!connected || !ConnectedToHeartRateMonitor.Value)
				{
					isHeartRateMonitorConnected = connected;
					ConnectedToHeartRateMonitor.Value = hasReceivedPulse && connected;
				}
			});
			heartRateValueSub = helper.WhenStrapHeartRateUpdated.SubscribeWithErrorLogging(delegate(int x)
			{
				Pulse.Source? source = container?.Console?.LatestBasicInfo?.CurrentPulse?.PulseSource;
				hasReceivedPulse = x > 0;
				if (hasReceivedPulse != ConnectedToHeartRateMonitor.Value && source != Pulse.Source.None)
				{
					ConnectedToHeartRateMonitor.Value = isHeartRateMonitorConnected && hasReceivedPulse;
				}
			});
			consoleStateSub = container.Console.WhenStateChanged.Where((StateChange s) => s.Current == ConsoleState.CoolDown).SubscribeWithErrorLogging(delegate
			{
				IsInCoolDown.Value = true;
			});
		}

		private void SetupVisibleMetrics()
		{
			if (!IsInCoolDown.Value && workoutSettings?.WorkoutContainer?.WorkoutRunner?.HasStartedCoolDown != true)
			{
				List<IMetric> list = new List<IMetric>();
				Func<IMetric, bool> predicate = (IMetric x) => !(x is HeartRateMetricBase) || ConnectedToHeartRateMonitor.Value;
				list.AddIfNotNull(FlipperGroup1Metrics.FirstOrDefault(predicate));
				list.AddIfNotNull(FlipperGroup2Metrics.FirstOrDefault(predicate));
				list.AddIfNotNull(FlipperGroup3Metrics.FirstOrDefault(predicate));
				list.AddIfNotNull(FlipperGroup4Metrics.FirstOrDefault(predicate));
				list.AddIfNotNull(FlipperGroup5Metrics.FirstOrDefault(predicate));
				inWorkoutFlipperMetricsManager.InitializeVisibleMetrics(list);
			}
		}

		private void UpdateVisibleFlipper((IMetric oldMetric, IMetric newMetric) metricsTuple)
		{
			if (metricsTuple.oldMetric != metricsTuple.newMetric && !IsInCoolDown.Value && workoutSettings?.WorkoutContainer?.WorkoutRunner?.HasStartedCoolDown != true)
			{
				inWorkoutFlipperMetricsManager.UpdateVisibleMetric(metricsTuple.oldMetric, metricsTuple.newMetric);
			}
		}

		public override void Dispose()
		{
			((BaseViewModel)this).Dispose();
			FlipperGroup1Metrics?.Clear();
			FlipperGroup2Metrics?.Clear();
			FlipperGroup3Metrics?.Clear();
			FlipperGroup4Metrics?.Clear();
			FlipperGroup5Metrics?.Clear();
			consoleHeartRateValueSub?.Dispose();
			consoleHeartRateValueSub = null;
			heartRateInitializedSub?.Dispose();
			heartRateInitializedSub = null;
			heartRateValueSub?.Dispose();
			heartRateValueSub = null;
			heartRateDisconnectSub?.Dispose();
			heartRateDisconnectSub = null;
			consoleStateSub?.Dispose();
			consoleStateSub = null;
			UnregisterChangeHandlers();
		}

		[GeneratedCode("Processed by DependsOn.Fody", "1.0")]
