namespace Wolf.Core.ViewModels.InWorkout.Debug
{
	public class DebugPulseChangeLevelViewModel : BaseViewModel
	{
		private readonly IWorkoutFeatureService workoutFeatureService;

		private readonly IActivePulseService activePulseService;

		private readonly string payloadAnalysisData = "analysisData";

		private readonly string payloadMessage = "message";

		private IDisposable SubDebugScaleLevels;

		private IDisposable workoutLevelChangedSub;

		public readonly INC<string> ScaleLevels1 = new NC<string>();

		public readonly INC<string> ScaleLevels2 = new NC<string>();

		public readonly INC<string> MaxText = new NC<string>();

		public ICommand ScaleUp => new MvxCommand(DoScaleUp);

		public ICommand ScaleDown => new MvxCommand(DoScaleDown);

		public ICommand CloseDebugView => new MvxCommand(DoCloseDebugView);

		public ICommand Plus2 => new MvxCommand(DoPlus2);

		public ICommand Plus1 => new MvxCommand(DoPlus1);

		public ICommand Minus2 => new MvxCommand(DoMinus2);

		public ICommand Minus1 => new MvxCommand(DoMinus1);

		public ICommand SiderailTrigger => new MvxCommand(DoSiderailTrigger);

		public DebugPulseChangeLevelViewModel(ILocalSettings localSettings, IWorkoutFeatureService workoutFeatureService, IActivePulseService activePulseService)
			: base(localSettings)
		{
			try
			{
				this.workoutFeatureService = workoutFeatureService;
				this.activePulseService = activePulseService;
				if (workoutSettings.WorkoutContainer?.WorkoutRunner?.ControlAdapter is IScalingControlAdapter scalingControlAdapter)
				{
					scalingControlAdapter.EnableScalingDebug = true;
					SubDebugScaleLevels = scalingControlAdapter.DebugScaleLevels.Subscribe(delegate((FitnessValue metric, string msg) x)
					{
						if (x.metric == FitnessValue.Kph || x.metric == FitnessValue.Resistance || x.metric == FitnessValue.Gear)
						{
							ScaleLevels1.Value = x.msg;
						}
						else if (x.metric == FitnessValue.Grade)
						{
							ScaleLevels2.Value = x.msg;
						}
						else if (x.metric == FitnessValue.MaxRpm)
						{
							MaxText.Value = x.msg;
						}
					});
				}
				ScaleLevels1.Value = "";
				ScaleLevels2.Value = "";
				MaxText.Value = "";
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void DoScaleUp()
		{
			((WorkoutChangeLevel)workoutSettings.WorkoutContainer.WorkoutChangeLevel).ScaleUp();
		}

		private void DoScaleDown()
		{
			((WorkoutChangeLevel)workoutSettings.WorkoutContainer.WorkoutChangeLevel).ScaleDown();
		}

		private void DoCloseDebugView()
		{
			workoutFeatureService.ShowDebugPulseChangeLevelView = false;
		}

		private void DoPlus2()
		{
			activePulseService.InjectScale(ActivePulseService.InjectScaleLevel.Plus2);
		}

		private void DoPlus1()
		{
			activePulseService.InjectScale(ActivePulseService.InjectScaleLevel.Plus1);
		}

		private void DoMinus2()
		{
			activePulseService.InjectScale(ActivePulseService.InjectScaleLevel.Minus2);
		}

		private void DoMinus1()
		{
			activePulseService.InjectScale(ActivePulseService.InjectScaleLevel.Minus1);
		}

		private void DoSiderailTrigger()
		{
			activePulseService.InjectTriggerPause();
		}

		public override void Dispose()
		{
			base.Dispose();
			if (workoutSettings.WorkoutContainer?.WorkoutRunner?.ControlAdapter is IScalingControlAdapter scalingControlAdapter)
			{
				scalingControlAdapter.EnableScalingDebug = false;
			}
			SubDebugScaleLevels?.Dispose();
			SubDebugScaleLevels = null;
			workoutLevelChangedSub?.Dispose();
			workoutLevelChangedSub = null;
			UnregisterChangeHandlers();
		}

