namespace Wolf.Core.ViewModels.GoogleMapsWebView
{
	public class GoogleMapsWebViewViewModel : BaseWebViewViewModel
	{
		private const int GoogleMapsWebViewTTL = 0;

		private readonly IGoogleMapsWebViewBridgeService bridgeService;

		private bool initialLoad = true;

		private readonly Subject<object> _whenWebViewPreLoadFinished = new Subject<object>();

		public override int WebviewTTL => 0;

		public override string LogTag => "GoogleMapsWebView";

		protected override string Url => featureFlagManager.GetString(FeatureFlags.AtlasWebViewUrl);

		public IObservable<object> WhenWebViewPreLoadFinished => _whenWebViewPreLoadFinished;

		public GoogleMapsWebViewViewModel(IGoogleMapsWebViewBridgeService bridgeService, ILocalSettings settings, IFeatureFlagManager featureFlagManager, IFailedUploadMonitor failedUploadMonitor, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings)
			: base(settings, featureFlagManager, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				this.bridgeService = bridgeService;
				PreloadWebView();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridgeService.SetBridge(Bridge);
		}

		public override void OnWebviewFinishedNavigating(object sender, EventArgs e)
		{
			if (!initialLoad)
			{
				return;
			}
			initialLoad = false;
			try
			{
				bridgeService?.SetWebViewLoaded(isLoaded: true);
				Bridge.Call("setupApp", ConfigsForWebView());
				_whenWebViewPreLoadFinished.OnNext(null);
			}
			catch (Exception)
			{
				initialLoad = true;
				Log.Error(LogTag, "Google Maps WebView could not navigate.");
			}
		}

		private static Dictionary<string, string> ConfigsForWebView()
		{
			return new Dictionary<string, string> { [JavascriptBridge.MethodToSetConfigs] = "setupApp" };
		}

		public static Task<IDictionary<string, string>> GetAdditionalConfigs()
		{
			return Task.FromResult((IDictionary<string, string>)ConfigsForWebView());
		}

		public static void PreloadWebView()
		{
			IWebviewHolderFactory webviewHolderFactory = Mvx.Resolve<IWebviewHolderFactory>();
			IMvxMainThreadDispatcher mvxMainThreadDispatcher = Mvx.Resolve<IMvxMainThreadDispatcher>();
			IFeatureFlagManager featureFlagManager = Mvx.Resolve<IFeatureFlagManager>();
			string webviewUrl = featureFlagManager.GetString(FeatureFlags.AtlasWebViewUrl);
			Dictionary<string, string> dictionary = ConfigsForWebView();
			mvxMainThreadDispatcher.RequestMainThreadAction(delegate
			{
				webviewHolderFactory.WebviewHolderStore.PreloadWebView(webviewUrl, 0, WebviewHolderType.Default, GetAdditionalConfigs);
			});
		}

