namespace Wolf.Core.ViewModels.ForcedUpdate
{
	public class ForcedUpdateViewModel : BaseViewModel
	{
		private readonly ICheckUpdateService checkUpdateService;

		private readonly ILaunchUpdate launchUpdateService;

		public ForcedUpdateViewModel(ILocalSettings localSettings, ICheckUpdateService checkUpdateService, ILaunchUpdate launchUpdateService, IBleConsoleService bleConsoleService)
			: base(localSettings)
		{
			try
			{
				this.checkUpdateService = checkUpdateService;
				this.launchUpdateService = launchUpdateService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (base.viewShownCount > 1)
			{
				NavigateToNextPage();
				return;
			}
			CheckUpdateState checkUpdateState = await checkUpdateService.CheckForUpdate();
			NavigateToNextPage();
			if (checkUpdateState == CheckUpdateState.UpdateAvailable)
			{
				await Task.Delay(TimeSpan.FromMilliseconds(1000.0));
				launchUpdateService.UpdateConnectedMachine();
			}
		}

		private void NavigateToNextPage()
		{
			if (bleConsoleService.IsEquipmentRegistered ?? true)
			{
				ShowLoginViewModel();
			}
			DoClose();
		}

