	public class FeedViewModel : MainToolbarViewModel
	{
		private const string Tag = "Feed";

		private const string WebViewSetupFunc = "InitializeApp";

		public const int FeedWebviewTTL = 14400;

		private const string WebMethodGetDateInView = "getDateInView";

		private const string WebMethodRefreshFeed = "refreshFeed";

		private const string NativeMethodMonthUpdate = "MonthUpdate";

		private const string NativeMethodFeedItemSelected = "FeedItemSelected";

		private const string MonthUpdateMonthKey = "month";

		private const string OnFeedItemSelectedAppDeepLinkKey = "appDeepLink";

		private const string OnFeedItemSelectedAppNameKey = "appName";

		private const string OnFeedItemSelectedFeedItemIdKey = "feedItemId";

		private const string OnFeedItemSelectedIsHistoricalKey = "isHistorical";

		private bool initialLoad = true;

		private bool feedItemSelected;

		private MvxSubscriptionToken messageTokenActivityLogDeleted;

		private PostWorkoutWebviewViewModel.ActivityLogDeletedMethodCallMessage previousActivityLogDeletedMethodCallMessage;

		private MvxSubscriptionToken messageTokenModalClosed;

		private BasePrePostWorkoutWebviewViewModel.ModalClosedMethodCallMessage previousModalClosedMethodCallMessage;

		private ILocalSettings settings;

		protected override string Url
		{
			get
			{
				if (!base.ShouldHermesOverride)
				{
					return featureFlagManager.GetString(FeatureFlags.PersonalFeedWebViewUrl);
				}
				return base.HermesUrl;
			}
		}

		public override string LogTag => "Feed";

		public override int WebviewTTL => 14400;

		public FeedViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IFeatureFlagManager featureFlagManager, IFailedUploadMonitor failedUploadMonitor, IMvxMessenger messenger, IModalityChangeService modalityChangeService, IWebViewUrlParameterService webViewUrlParameterService, IUpgradeService upgradeService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService)
			: base(localSettings, featureFlagManager, ToolbarMode.CalendarOrFeed, ifitApi, failedUploadMonitor, modalityChangeService, webViewUrlParameterService, upgradeService, webviewSettings, currentConsoleService)
		{
			try
			{
				settings = localSettings;
				HeaderToolbarText.Value = Wolf.Core.Resources.AppStrings.Calendar;
				messageTokenActivityLogDeleted = messenger?.Subscribe(delegate(PostWorkoutWebviewViewModel.ActivityLogDeletedMethodCallMessage x)
				{
					previousActivityLogDeletedMethodCallMessage = x;
				});
				messageTokenModalClosed = messenger?.Subscribe(delegate(BasePrePostWorkoutWebviewViewModel.ModalClosedMethodCallMessage x)
				{
					previousModalClosedMethodCallMessage = x;
				});
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			Bridge.Call("getDateInView", new Dictionary<string, string>());
			if (webviewSettings.ReloadFeedData)
			{
				webviewSettings.ReloadFeedData = false;
				InitiateRefreshFeedCall();
			}
			feedItemSelected = false;
		}

		private void InitiateRefreshFeedCall()
		{
			BaseWebViewMethodCallMessage baseWebViewMethodCallMessage = previousActivityLogDeletedMethodCallMessage;
			baseWebViewMethodCallMessage = baseWebViewMethodCallMessage ?? previousModalClosedMethodCallMessage;
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			dictionary.Add("previousJSCalls", JsonConvert.SerializeObject(BaseWebViewViewModel.GeneratePreviousJsCallsDictionary(baseWebViewMethodCallMessage)));
			Dictionary<string, string> parameters = dictionary;
			Bridge.Call("refreshFeed", parameters);
			previousActivityLogDeletedMethodCallMessage?.Dispose();
			previousActivityLogDeletedMethodCallMessage = null;
			previousModalClosedMethodCallMessage?.Dispose();
			previousModalClosedMethodCallMessage = null;
		}

		private void MonthUpdate(IDictionary<string, string> parameters)
		{
			HeaderToolbarText.Value = (parameters.ContainsKey("month") ? parameters["month"] : Wolf.Core.Resources.AppStrings.Calendar);
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			base.BuildBridge(bridge);
			bridge.Expose("FeedItemSelected", OnFeedItemSelected);
			bridge.Expose("MonthUpdate", MonthUpdate);
		}

		private void OnFeedItemSelected(IDictionary<string, string> methodParams)
		{
			if (!feedItemSelected)
			{
				feedItemSelected = true;
				IAppLinking service;
				if (methodParams["isHistorical"].ToLower() == "false" && methodParams["appDeepLink"].StartsWith("ifitcardio"))
				{
					OpenPreWorkoutViewModel(methodParams["feedItemId"]);
				}
				else if (!Mvx.TryResolve<IAppLinking>(out service))
				{
					OnIAppLinkingFailedToResolve(methodParams);
				}
				else if (methodParams.ContainsKey("appDeepLink"))
				{
					DispatchDeepLink(methodParams);
				}
				else
				{
					DispatchLocalLink(methodParams, service);
				}
			}
		}

		private void OpenPreWorkoutViewModel(string id)
		{
			PreWorkoutViewModel.NavObject parameterValuesObject = new PreWorkoutViewModel.NavObject
			{
				WorkoutId = id,
				WorkoutSource = WorkoutSource.Calendar,
				DashboardIndex = -1
			};
			ShowViewModel<PreWorkoutViewModel>(parameterValuesObject);
		}

		private void OnIAppLinkingFailedToResolve(IDictionary<string, string> methodParams)
		{
			StringBuilder sb = new StringBuilder();
			methodParams.ForEach(delegate(KeyValuePair<string, string> x)
			{
				sb.AppendLine("\tKey - " + x.Key + ": Value - " + x.Value);
			});
			Log.Trace("MvxTrace", "Failed to resolve IAppLinking when processing NativeMethodFeedItemSelected for method parameters:\n" + sb.ToString());
		}

		private void DispatchDeepLink(IDictionary<string, string> methodParams)
		{
			string empty = string.Empty;
			empty = methodParams["appDeepLink"];
			string text = empty.Substring(empty.IndexOf('?') + 1);
			string[] source = text.Split('&');
			Dictionary<string, string> dictionary = (from o in source
				select o.Split('=') into items
				where items.Count() == 2
				select items).ToDictionary((string[] pair) => Uri.UnescapeDataString(pair[0]), (string[] pair) => Uri.UnescapeDataString(pair[1]));
			string text2 = (empty.ToLowerInvariant().StartsWith("ifitcardio", StringComparison.Ordinal) ? "true" : "false");
			dictionary.TryGetValue("category", out var value);
			BaseLogScreenViewModel.LogScreenNavObject parameterValuesObject = new BaseLogScreenViewModel.LogScreenNavObject
			{
				ActivityLogId = dictionary["id"],
				FromFeed = true,
				FromWolf = (text2 == "true"),
				LogCategory = value,
				PostWorkout = false
			};
			Log.Trace("MvxTrace", "Feed WebView selected an item to open via \"" + empty + "\".");
			if (!ShowLogScreen(parameterValuesObject))
			{
				ShowSimpleInternetErrorDialog();
			}
		}

		private void DispatchLocalLink(IDictionary<string, string> methodParams, IAppLinking linkService)
		{
			try
			{
				string empty = string.Empty;
				string empty2 = string.Empty;
				if (methodParams.TryGetValue("feedItemId", out var value))
				{
					string text = methodParams["appName"];
					Log.Trace("MvxTrace", "Feed WebView selected legacy version feed item " + value + ".");
					bool flag = text == "Cardio App";
					empty = string.Format("{0}://{1}?id={2}&isFeed=true&iswolf={3}", "ifitcardio", "applink", value, flag);
					linkService?.OpenLinkUrl(empty, string.IsNullOrEmpty(empty2) ? "https://www.ifit.com" : empty2);
				}
			}
			catch (Exception)
			{
				Log.Error("WebView", "Feed WebView error when tapping a feed item. Likely bad parameters.");
			}
		}

		protected override void SetupHeaderToolbar()
		{
			if (base.viewShownCount < 1)
			{
				HeaderToolbarText.Value = Wolf.Core.Resources.AppStrings.Calendar;
			}
		}

		public static string GetWebViewUrl(IFeatureFlagManager ffm)
		{
			string text = ffm.GetString(FeatureFlags.PersonalFeedWebViewUrl);
			if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service))
			{
				text = service.GenerateWebViewUrlWithParameters(text);
			}
			return text;
		}

