			return new Dictionary<string, string>
			{
				["whichApp"] = "ifitcardio",
				[JavascriptBridge.MethodToSetConfigs] = "InitializeApp"
			};
		}

		public override Task RefreshAfterModalityChange()
		{
			Log.Trace(LogTag, "Feed does not need to reinitialize after modality change.");
			return Task.CompletedTask;
		}

