namespace Wolf.Core.ViewModels.Favorites
{
	public abstract class BaseFavoritableWorkoutViewModel : BaseWebViewViewModel
	{
		private const string PlaceholderVideoBannerImg = "https://s3.amazonaws.com/ifit-wolf/misc/video-banner.png";

		protected readonly IIfitApiService ifitApi;

		protected readonly IIFitGatewayApiService iFitGatewayApi;

		public readonly INC<bool> IsDownloadingBannerImage = new NC<bool>();

		public readonly INC<bool> IsFavorite = new NC<bool>();

		public readonly INC<bool> IsFavoriteUpdating = new NC<bool>();

		public readonly INC<int?> StreetViewImageWidth = new NC<int?>();

		public readonly INC<int?> StreetViewImageHeight = new NC<int?>();

		public readonly INC<byte[]> BannerImage = new NC<byte[]>();

		public readonly INC<bool?> IsMapWorkout = new NC<bool?>();

		public readonly INC<string> VideoStreamUrl = new NC<string>();

		public readonly INC<Workout.VideoWorkoutMetadata> VideoWorkoutMetadata = new NC<Workout.VideoWorkoutMetadata>();

		public readonly INC<Trainer> VideoWorkoutTrainer = new NC<Trainer>();

		private Subject<object> _whenIncompatibleWorkoutErrorDisplays = new Subject<object>();

		protected abstract string WorkoutId { get; }

		public bool CloudEnabled => connectivity.IsConnected;

		public bool HasVideoTrainer => false;

		public bool IsVideoWorkout => base.RequestedWorkout?.IsVideoWorkout() ?? false;

		public IMvxAsyncCommand FavoriteButtonTap => new MvxAsyncCommand(DoFavoriteButtonTapped);

		public IObservable<object> WhenIncompatibleWorkoutErrorDisplays => _whenIncompatibleWorkoutErrorDisplays?.AsObservable();

		protected override bool AllowConsoleTypeChangeToResetNavigation => true;

		protected BaseFavoritableWorkoutViewModel(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, IFailedUploadMonitor failedUploadMonitor, IWebViewUrlParameterService webViewUrlParameterService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService)
			: base(localSettings, featureFlagManager, failedUploadMonitor, webViewUrlParameterService, webviewSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.iFitGatewayApi = iFitGatewayApi;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			Log.Trace("Workout", "Disposing requested workout in favoritable VM");
			BannerImage.Value = null;
			_whenIncompatibleWorkoutErrorDisplays?.Dispose();
			_whenIncompatibleWorkoutErrorDisplays = null;
			UnregisterChangeHandlers();
		}

		protected virtual async Task<byte[]> LoadStreetViewImage(double meters = 0.0)
		{
			if (base.RequestedWorkout == null)
			{
				return null;
			}
			Workout requestedWorkout = base.RequestedWorkout;
			if ((requestedWorkout != null && !requestedWorkout.IsGoogleMap) || base.RequestedWorkout.Id == null)
			{
				return null;
			}
			if (!StreetViewImageWidth.Value.HasValue || !StreetViewImageHeight.Value.HasValue)
			{
				return null;
			}
			if (!connectivity.IsConnected)
			{
				return null;
			}
			using StreetViewService streetView = new StreetViewService(ifitApi, iFitGatewayApi, currentConsoleService.ActiveConsole, base.RequestedWorkout.Id, StreetViewImageWidth.Value.Value, StreetViewImageHeight.Value.Value);
			await streetView.Initialize();
			return await streetView.GetImageForDistance(meters, isLandscape: false, QualityMode.FullQuality);
		}

		protected virtual async Task CheckIfFavorite()
		{
			IsFavoriteUpdating.Value = true;
			List<Workout> favorites = null;
			object obj = null;
			try
			{
				try
				{
					favorites = await Favorite.Get<Workout>(ifitApi, Favorite.Model.Workouts, 1, 99, "", force: true);
				}
				catch (Exception ex)
				{
					Exception baseException = ex.GetBaseException();
					Log.Error("Api", "Error fetching favorites: (Workout " + WorkoutId + ") " + baseException.Message + " " + baseException.StackTrace);
				}
			}
			catch (object obj2)
			{
				obj = obj2;
			}
			if (base.RequestedWorkout != null)
			{
				string workoutIdToCheck = await base.RequestedWorkout.DetermineWorkoutIdToUse(ifitApi);
				IsFavorite.Value = favorites?.Any((Workout w) => w.Id == workoutIdToCheck) ?? false;
				IsFavoriteUpdating.Value = false;
			}
			if (favorites != null)
			{
				foreach (Workout item in favorites)
				{
					item.Dispose();
				}
			}
			object obj3 = obj;
			if (obj3 != null)
			{
				if (!(obj3 is Exception source))
				{
					throw obj3;
				}
				ExceptionDispatchInfo.Capture(source).Throw();
			}
		}

		protected async Task DoFavoriteButtonTapped()
		{
			if (IsFavorite.Value)
			{
				await Task.Run((Func<Task>)StartRemoveFavorite);
			}
			else
			{
				await Task.Run((Func<Task>)StartAddFavorite);
			}
		}

		protected async Task StartAddFavorite()
		{
			if (string.IsNullOrWhiteSpace(WorkoutId))
			{
				return;
			}
			IsFavoriteUpdating.Value = true;
			string workoutIdToFavorite = null;
			try
			{
				workoutIdToFavorite = await base.RequestedWorkout.DetermineWorkoutIdToUse(ifitApi);
				await Favorite.Create(ifitApi, workoutIdToFavorite);
				IsFavorite.Value = true;
			}
			catch (Exception ex)
			{
				Exception baseException = ex.GetBaseException();
				Log.Error("Api", "Error adding favorite: (Workout " + workoutIdToFavorite + ") " + baseException.Message + " " + baseException.StackTrace);
			}
			finally
			{
				IsFavoriteUpdating.Value = false;
			}
		}

		protected async Task StartRemoveFavorite()
		{
			if (string.IsNullOrWhiteSpace(WorkoutId))
			{
				return;
			}
			IsFavoriteUpdating.Value = true;
			string workoutIdToUnfavorite = null;
			try
			{
				workoutIdToUnfavorite = await base.RequestedWorkout.DetermineWorkoutIdToUse(ifitApi);
				if (await Favorite.Delete(ifitApi, workoutIdToUnfavorite))
				{
					IsFavorite.Value = false;
				}
				else
				{
					Log.Error("Api", "Error removing favorite (Workout " + workoutIdToUnfavorite + "). API request failed.");
				}
			}
			catch (Exception ex)
			{
				Exception baseException = ex.GetBaseException();
				Log.Error("Api", "Error removing favorite: (Workout " + workoutIdToUnfavorite + ") " + baseException.Message + " " + baseException.StackTrace);
			}
			finally
			{
				IsFavoriteUpdating.Value = false;
			}
		}

		protected async Task GetVideoTrainer(string trainerId)
		{
			if (string.IsNullOrWhiteSpace(trainerId))
			{
				return;
			}
			try
			{
				Trainer trainer = await Trainer.Get(ifitApi, trainerId);
				if (trainer != null)
				{
					VideoWorkoutTrainer.Value = trainer;
				}
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Error retrieving Trainer data for workout id " + (WorkoutId ?? "<null>"), ex.GetBaseException());
			}
		}

		protected async Task TrySetVideoWorkoutHeaderImage()
		{
			if (base.RequestedWorkout?.IsVideoWorkout() == true && BannerImage.Value == null)
			{
				string url = "https://s3.amazonaws.com/ifit-wolf/misc/video-banner.png";
				if (!string.IsNullOrEmpty(base.RequestedWorkout?.CoverImageUri))
				{
					url = ImageUtil.GetResizedUrl(base.RequestedWorkout.CoverImageUri, 1024, 576);
				}
				await DownloadBannerImage(url);
			}
		}

		protected async Task DownloadBannerImage(string url)
		{
			if (string.IsNullOrEmpty(url))
			{
				return;
			}
			try
			{
				IsDownloadingBannerImage.Value = true;
				byte[] array = await ImageDownloader.DownloadImage(url);
				if (BannerImage.Value == null || (array != null && !Enumerable.SequenceEqual(BannerImage.Value, array)))
				{
					BannerImage.Value = array;
				}
			}
			catch (Exception ex)
			{
				try
				{
					if (!url.Equals("https://s3.amazonaws.com/ifit-wolf/misc/video-banner.png"))
					{
						Log.Error("Api", "Error retrieving video banner image for workout id " + (WorkoutId ?? "<null>"), ex.GetBaseException());
						IsDownloadingBannerImage.Value = true;
						byte[] array2 = await ImageDownloader.DownloadImage("https://s3.amazonaws.com/ifit-wolf/misc/video-banner.png");
						if (BannerImage.Value == null || (array2 != null && !Enumerable.SequenceEqual(BannerImage.Value, array2)))
						{
							BannerImage.Value = array2;
						}
					}
				}
				catch (Exception ex2)
				{
					Log.Error("Api", "Error retrieving placeholder video banner image for workout id " + (WorkoutId ?? "<null>"), ex2.GetBaseException());
				}
			}
			finally
			{
				IsDownloadingBannerImage.Value = false;
			}
		}

		[Obsolete("See WorkoutExtensions.ShouldTreatWorkoutAsManual")]
		protected static bool IsConsideredManualWorkout(Workout workout)
		{
			if (string.IsNullOrWhiteSpace(workout?.Id))
			{
				return true;
			}
			if ((workout.Controls?.Count).GetValueOrDefault() == 0 && !workout.IsGoogleMap && workout.TargetValue.Equals(0.0) && workout.Metadata == null && workout.Title == null)
			{
				return !workout.HasFilter(Workout.WorkoutFilter.IsVideo);
			}
			return false;
		}

		protected async Task<bool> ShowErrorIfWorkoutIncompatible(bool displayBlePairFilter = false, bool closeScreen = false)
		{
			if (base.RequestedWorkout != null)
			{
				Workout requestedWorkout = base.RequestedWorkout;
				if ((requestedWorkout == null || requestedWorkout.IsVideoWorkout()) && !base.RequestedWorkout.ShouldUseEquipmentlessConsole())
				{
					bool flag = ((!(deviceInfo?.IsHeadlessBikeVault ?? false) || !(currentConsoleService?.IsAttachedConsoleActive ?? false)) ? currentConsoleService.ActiveConsole.CanDoWorkout(base.RequestedWorkout, deviceInfo.IsStrengthMirror) : currentConsoleService.ActiveConsole.CanDoWorkout(base.RequestedWorkout));
					if (!flag || (currentConsoleService.ActiveConsole?.IsNonconnectedConsole() ?? false))
					{
						if (!deviceInfo.IsBuiltIn && displayBlePairFilter && Mvx.TryResolve<IMvxMessenger>(out var service))
						{
							bool returnValue = false;
							await DisplayBlePairFilterVM(service, delegate
							{
								if (!currentConsoleService.ActiveConsole.CanDoWorkout(base.RequestedWorkout, deviceInfo.IsStrengthMirror))
								{
									this.OnIncompatibleWorkout(closeScreen);
									_whenIncompatibleWorkoutErrorDisplays?.OnNext(null);
								}
								this.OnIncompatibleWorkout(closeScreen);
								_whenIncompatibleWorkoutErrorDisplays?.OnNext(null);
							}, delegate
							{
								returnValue = true;
							});
							return returnValue;
						}
						this.OnIncompatibleWorkout(closeScreen);
						_whenIncompatibleWorkoutErrorDisplays?.OnNext(null);
						return true;
					}
					return false;
				}
			}
			return false;
		}

