		[DependsOn(new string[] { "WorkoutControls" })]
		public double AverageGrade
		{
			get
			{
				if (WorkoutControls.Value == null || WorkoutControls.Value.Count == 0)
				{
					return 0.0;
				}
				return WorkoutControls.Value.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline && !double.IsNaN(x.Value)).Average((Workout.Control x) => x.Value);
			}
		}

		[DependsOn(new string[] { "RoutePoints", "WorkoutSpeed", "WorkoutControls" })]
		public double CaloriesBurned => CalorieFormulas.Running(weightInKgs, SecondsToComplete, MetersPerSecond, AverageGrade);

		[DependsOn(new string[] { "RoutePoints" })]
		public bool CloseLoopEnabled
		{
			get
			{
				if (RoutePoints.Value.CountSafe() >= 2)
				{
					return RoutePoints.Value.First().IsAtLeastXMetersAway(RoutePoints.Value.Last(), 1.5);
				}
				return false;
			}
		}

		[DependsOn(new string[] { "RoutePoints", "ForcedToolboxMode", "SearchResults" })]
		public ToolBoxMode CurrentToolBoxMode
		{
			get
			{
				if (ForcedToolboxMode.Value.HasValue)
				{
					if (ForcedToolboxMode.Value.Value == ToolBoxMode.Small)
					{
						if (SearchResults.Value.CountSafe() <= 0)
						{
							return ToolBoxMode.Small;
						}
						return ToolBoxMode.SmallSearch;
					}
					if (RoutePoints.Value.CountSafe() >= 2)
					{
						ForceUncheckToolsIfNeeded();
						return ToolBoxMode.Sidebar;
					}
					if (IsMapToolsHidden.Value)
					{
						return ToolBoxMode.Small;
					}
					return ToolBoxMode.Large;
				}
				if (RoutePoints.Value.CountSafe() == 0)
				{
					if (SearchResults.Value.CountSafe() <= 0)
					{
						return ToolBoxMode.Small;
					}
					return ToolBoxMode.SmallSearch;
				}
				if (RoutePoints.Value.CountSafe() == 1)
				{
					if (IsMapToolsHidden.Value)
					{
						return ToolBoxMode.SmallSearch;
					}
					return ToolBoxMode.Large;
				}
				ForceUncheckToolsIfNeeded();
				return ToolBoxMode.Sidebar;
			}
		}

