		public DrawMapViewModel(ILocalSettings localSettings, IGoogleApiService googleApi, IIFitGatewayApiService iFitGatewayApi, IElevationGainWorkoutControlService elevationGainWorkoutControlService, ISettingsRouter settingsRouter, IMvxMainThreadDispatcher dispatch, IThemeService themeService, IFeatureFlagManager featureFlagManager, IIfitApiService ifitApi, IFailedUploadMonitor failedUploadMonitor, IModalityChangeService modalityChangeService, IWebViewUrlParameterService webViewUrlParameterService, IUpgradeService upgradeService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService)
			: base(localSettings, featureFlagManager, ToolbarMode.DrawMap, ifitApi, failedUploadMonitor, modalityChangeService, webViewUrlParameterService, upgradeService, webviewSettings, currentConsoleService)
		{
			try
			{
				this.googleApi = googleApi;
				this.iFitGatewayApi = iFitGatewayApi;
				this.elevationGainWorkoutControlService = elevationGainWorkoutControlService;
				this.settingsRouter = settingsRouter;
				this.dispatch = dispatch;
				this.themeService = themeService;
				ShowCurrentLocationFab = !deviceInfo.IsBuiltIn;
				ViewMode.Value = ((!themeService.IsCurrentThemeDarkVariant()) ? MapType.Normal : MapType.Satellite);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

