		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
			await Task.Run(async delegate
			{
				SaveScreenShown.SetFalse();
				INC<bool> isMetric = IsMetric;
				isMetric.Value = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
				weightInKgs = await settingsRouter.GetWeightKgs().ConfigureAwait(continueOnCapturedContext: false);
				ConsoleType currentConsoleType = currentConsoleService.GetCurrentConsoleType(ConsoleType.Treadmill);
				WorkoutSpeed.Value = currentConsoleType.EstimateWorkoutSpeed(IsMetric.Value);
				if (RouteElevationPoints.Value.Count <= 0)
				{
					Tuple<iFit.Api.Google.LatLng, string> randomFamousLocation = GetRandomFamousLocation();
					MapCenter.Value = randomFamousLocation.Item1;
					SearchText.Value = randomFamousLocation.Item2;
				}
				SetMinMaxSpeedsAndIncline();
			});
		}

		private Tuple<iFit.Api.Google.LatLng, string> GetRandomFamousLocation()
		{
			return famousLocations[new Random().Next(0, famousLocations.Count)];
		}

		private void OnLocationFound(Location location)
		{
			localSettings.CurrentLocation = new iFit.Api.Google.LatLng(location.Latitude, location.Longitude);
			SetMapLocation();
		}

		private void OnLocationError()
		{
			MsgToUser.Value = Wolf.Core.Resources.AppStrings.no_location;
		}

		private void OnGPSUnavailable()
		{
			MsgToUser.Value = Wolf.Core.Resources.AppStrings.no_gps;
			LocationNotAuthorizedError.Value = true;
		}

		private void SetMinMaxSpeedsAndIncline()
		{
			bool flag = currentConsoleService?.ActiveConsole?.ConsoleInfo == null;
			if (IsMetric.Value)
			{
				minimumSpeed = (flag ? 2.0 : currentConsoleService.ActiveConsole.ConsoleInfo.MinKph);
				maximumSpeed = (flag ? 20.0 : currentConsoleService.ActiveConsole.ConsoleInfo.MaxKph);
			}
			else
			{
				minimumSpeed = (flag ? 1.0 : UnitUtil.EnsureMph(SpeedUnit.Kph, currentConsoleService.ActiveConsole.ConsoleInfo.MinKph));
				maximumSpeed = (flag ? 12.0 : UnitUtil.EnsureMph(SpeedUnit.Kph, currentConsoleService.ActiveConsole.ConsoleInfo.MaxKph));
			}
			double num = 2.0;
			minimumSpeed = Math.Ceiling(minimumSpeed * num) / num;
			maximumSpeed = Math.Round(maximumSpeed);
			if (minimumSpeed < 1.0)
			{
				minimumSpeed = 1.0;
			}
			if (!flag)
			{
				double valueOrDefault = (currentConsoleService?.ActiveConsole?.ConsoleInfo?.MaxIncline).GetValueOrDefault();
				double num2 = (currentConsoleService?.ActiveConsole?.ConsoleInfo?.MinIncline).GetValueOrDefault();
				if (num2 > valueOrDefault)
				{
					num2 = valueOrDefault;
				}
				MaxIncline = valueOrDefault;
				MinIncline = num2;
				RaisePropertyChanged("MaxIncline");
				RaisePropertyChanged("MinIncline");
			}
		}

		private async Task FindUserCurrentLocation()
		{
			if (!Mvx.TryResolve<IPermissionsService>(out var service) || service.HasPermissions(new PermissionType[2]
			{
				PermissionType.AccessCoarseLocation,
				PermissionType.AccessFineLocation
			}) || localSettings.IsRoboRunMode)
			{
				await ContinueFindUserCurrentLocation();
			}
			else
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.permissions_title, Wolf.Core.Resources.AppStrings.permission_location_current_explanation, RequestBLEService, Wolf.Core.Resources.AppStrings.cancel_title.ToUpper(), Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), delegate
				{
				}, null, dismissible: true, cancellable: true, "", null, null, isWarning: false, showSafely: false);
			}
		}

		private void RequestBLEService()
		{
			_askLocation.Raise(null);
		}

		public async Task ContinueFindUserCurrentLocation()
		{
			FABMenuIsOpen.Value = false;
			if (localSettings.CurrentLocation != null && !localSettings.CurrentLocation.IsUnknown)
			{
				SetMapLocation();
			}
			LocationNotAuthorizedError.Value = false;
			try
			{
				GeolocationRequest request = new GeolocationRequest(GeolocationAccuracy.Medium);
				Location location = await Geolocation.GetLocationAsync(request);
				if (location == null)
				{
					OnLocationError();
				}
				else
				{
					OnLocationFound(location);
				}
			}
			catch (Exception ex)
			{
				if (ex is FeatureNotSupportedException || ex is FeatureNotEnabledException || ex is PermissionException)
				{
					OnGPSUnavailable();
				}
				else
				{
					OnLocationError();
				}
			}
		}

		private async Task SetMapLocation()
		{
			MapCenter.Value = localSettings.CurrentLocation;
			DoClearSearchText();
			List<Geocode.GeocodeResults> list = (await Geocode.ReverseGet(googleApi, MapCenter.Value.ToString()))?.Results;
			if (list != null)
			{
				Geocode.GeocodeResults geocodeResults = list.FirstOrDefault();
				SearchText.Value = geocodeResults.FormattedAddress;
			}
		}

		private void DoToggleViewMode(MapType viewMode)
		{
			ViewMode.Value = viewMode;
			FABMenuIsOpen.Value = false;
		}

		private void DoMapBuilderToolsButtonTap()
		{
			if (RoutePoints.Value.CountSafe() < 2)
			{
				IsMapToolsHidden.SwitchValue();
				_updateMapToolsTintColor.Raise(null);
			}
			ForceEndEditing.SetTrue();
			ForcedToolboxMode.Value = ToolBoxMode.Large;
		}

		private void ForceUncheckToolsIfNeeded()
		{
			if (!IsMapToolsHidden.Value)
			{
				IsMapToolsHidden.Value = true;
				_updateMapToolsTintColor.Raise(null);
			}
		}

		private void DoClearSearchText()
		{
			SearchText.Value = "";
		}

		private async Task DoSearchCurrentText()
		{
			await Task.Run((Func<Task>)DoSearchCurrentTextAsync);
		}

		private async Task DoSearchCurrentTextAsync()
		{
			if (CurrentTextSearching.Value)
			{
				return;
			}
			CurrentTextSearching.Value = true;
			List<PlaceAutoComplete.Prediction> source = await GetPlacesPredictions(SearchText.Value);
			try
			{
				await DoCenterMapAtSearchResultAsync(source.First());
			}
			catch (Exception ex)
			{
				Log.Trace("DrawMap", "Exception thrown centering map on search result " + ex.Message);
			}
			finally
			{
				OnSearchBoxBlur();
				CurrentTextSearching.Value = false;
			}
		}

		[DependsOn(new string[] { "SearchText" })]
		private async void HandleSearchTextChanged()
		{
			if (!disregardSearchTextUpdate)
			{
				await Task.Run((Func<Task>)PerformPlacesSearch);
			}
			disregardSearchTextUpdate = false;
		}

		private void NotifyUser(string msg, bool shouldNotify = true)
		{
			if (shouldNotify)
			{
				MsgToUser.Value = msg;
			}
		}

		private async Task<List<PlaceAutoComplete.Prediction>> GetPlacesPredictions(string search, bool shouldNotifyUser = true)
		{
			if (string.IsNullOrWhiteSpace(SearchText.Value))
			{
				NotifyUser(Wolf.Core.Resources.AppStrings.drawmap_no_results_toast, shouldNotifyUser);
				return null;
			}
			try
			{
				PlaceAutoComplete placeAutoComplete = await PlaceAutoComplete.Get(googleApi, search);
				switch (placeAutoComplete.Status)
				{
				case BaseGoogleDataObject.ResponseStatusType.Ok:
					return placeAutoComplete.Predictions;
				case BaseGoogleDataObject.ResponseStatusType.ZeroResults:
					NotifyUser(Wolf.Core.Resources.AppStrings.no_location, shouldNotifyUser);
					return null;
				default:
					NotifyUser(Wolf.Core.Resources.AppStrings.no_location, shouldNotifyUser);
					Log.Trace("DrawMap", "Searching for " + search + " returned with status " + placeAutoComplete.Status);
					return null;
				}
			}
			catch (Exception ex)
			{
				NotifyUser(Wolf.Core.Resources.AppStrings.no_location, shouldNotifyUser);
				Log.Trace("DrawMap", "Searching for " + search + " threw exception " + ex.Message + " StackTrace: " + ex.StackTrace);
				return null;
			}
		}

		private async Task<bool> AdditionalInputWasGiven(CancellationToken token)
		{
			await Task.Delay(500);
			return token.IsCancellationRequested;
		}

		private async Task PerformPlacesSearch()
		{
			SearchResults.Value = new List<PlaceAutoComplete.Prediction>();
			if (placesCancelationTokenSource != null)
			{
				placesCancelationTokenSource.Cancel();
			}
			placesCancelationTokenSource = new CancellationTokenSource();
			if (!(await AdditionalInputWasGiven(placesCancelationTokenSource.Token)))
			{
				List<PlaceAutoComplete.Prediction> list = await GetPlacesPredictions(SearchText.Value, shouldNotifyUser: false);
				if (list != null)
				{
					SearchResults.Value = list;
				}
			}
		}

		private void DoSearchButtonTap()
		{
			ForceUncheckToolsIfNeeded();
			ForcedToolboxMode.Value = ToolBoxMode.Small;
		}

		private void OnSearchBoxFocused()
		{
			SearchInputFieldFocused.Value = true;
			SearchText.Value = SearchText.Value;
		}

		private void OnSearchBoxBlur()
		{
			SearchInputFieldFocused.Value = false;
			SearchResults.Value = new List<PlaceAutoComplete.Prediction>();
		}

		private void DoSpeedDecrementButtonTap()
		{
			if (!(WorkoutSpeed.Value <= minimumSpeed))
			{
				double num = WorkoutSpeed.Value - 0.5;
				if (num < minimumSpeed)
				{
					num = minimumSpeed;
				}
				WorkoutSpeed.Value = Math.Round(num, 1);
				UpdateWorkoutControls();
			}
		}

		private void DoSpeedIncrementButtonTap()
		{
			if (!(WorkoutSpeed.Value >= maximumSpeed))
			{
				double num = WorkoutSpeed.Value + 0.5;
				if (num > maximumSpeed)
				{
					num = maximumSpeed;
				}
				WorkoutSpeed.Value = Math.Round(num, 1);
				UpdateWorkoutControls();
			}
		}

		[DependsOn(new string[] { "RoutePoints" })]
		private async Task RouteUpdated()
		{
			await Task.Run(async delegate
			{
				Task item = UpdateWorkoutControls();
				Task item2 = BeginStreetViewImageFetch();
				Task item3 = UpdateWorkoutTitle();
				await Task.WhenAll(new List<Task> { item, item2, item3 });
			});
		}

		private async Task UpdateWorkoutTitle()
		{
			iFit.Api.Google.LatLng latLng = RoutePoints.Value.FirstOrDefault();
			if (latLng != null)
			{
				try
				{
					workoutTitle = (await Geocode.ReverseGet(googleApi, latLng.ToString()))?.Results[0].ToWorkoutTitle();
					return;
				}
				catch (Exception ex)
				{
					Log.Trace("DrawMap", $"Error getting reverse Geocode on draw map - {ex.GetBaseException()}");
					workoutTitle = "";
					return;
				}
			}
			workoutTitle = "";
		}

		private async Task BeginStreetViewImageFetch()
		{
			StreetViewImageAtLastPoint.Value = null;
			if (StreetViewImageWidth < 1 || StreetViewImageHeight < 1)
			{
				Log.Trace("DrawMap", "StreetViewImageWidth or StreetViewImageHeight is not set, so the street view image request is cancelled.");
				StreetViewImageLoading.Value = false;
				return;
			}
			StreetViewImageLoading.Value = true;
			IList<iFit.Api.Google.LatLng> value = RoutePoints.Value;
			int count = value.Count;
			if (count == 0)
			{
				StreetViewImageLoading.Value = false;
				return;
			}
			iFit.Api.Google.LatLng latLng = value[count - 1];
			double heading;
			if (count == 1)
			{
				heading = 180.0;
			}
			else
			{
				iFit.Api.Google.LatLng start = value[count - 2];
				heading = start.GetHeadingDegrees(latLng);
			}
			StreetViewPoints.Point point = new StreetViewPoints.Point
			{
				Lat = latLng.Lat,
				Lng = latLng.Lng,
				Heading = heading
			};
			byte[] array;
			try
			{
				array = await point.GetImage(iFitGatewayApi, StreetViewImageWidth, StreetViewImageHeight);
			}
			catch (Exception exception)
			{
				Log.Error("DrawMap", $"Error downloading street view image for ({point.Lat},{point.Lng})", exception);
				array = null;
			}
			if (array == null || array.Length < 1)
			{
				StreetViewImageAtLastPoint.Value = null;
				StreetViewImageLoading.Value = false;
				return;
			}
			int num = StreetViewImageWidth * StreetViewImageHeight;
			int num2 = (int)Math.Ceiling(0.016 * (double)num + 4096.0);
			bool flag = array.Length < num2;
			StreetViewImageAtLastPoint.Value = (flag ? null : array);
			StreetViewImageLoading.Value = false;
		}

		private async Task UpdateWorkoutControls()
		{
			if (RoutePoints.Value.Count >= 2)
			{
				WorkoutMetricsError.Value = false;
				WorkoutMetricsLoading.Value = true;
				if (!IsMetric.Value)
				{
					UnitUtil.EnsureMps(SpeedUnit.Mph, WorkoutSpeed.Value);
				}
				else
				{
					UnitUtil.EnsureMps(SpeedUnit.Kph, WorkoutSpeed.Value);
				}
				ElevationGainWorkoutControlResult elevationGainWorkoutControlResult = await elevationGainWorkoutControlService.CalculateElevationGainAndWorkoutControls(RoutePoints.Value.ToList(), IsMetric.Value);
				WorkoutMetricsError.Value = elevationGainWorkoutControlResult == null;
				if (elevationGainWorkoutControlResult != null)
				{
					Workout workout = new Workout
					{
						Controls = elevationGainWorkoutControlResult.WorkoutControls.ToList()
					};
					workout.RoundInclineControls();
					WorkoutControls.Value = workout.Controls;
					VerticalGain.Value = elevationGainWorkoutControlResult.ElevationGain;
					RouteElevationPoints.Value = CalculateInclineChartPoints(elevationGainWorkoutControlResult.ElevationResults);
				}
				WorkoutMetricsLoading.Value = false;
			}
		}

		private IList<Tuple<double, double>> CalculateInclineChartPoints(IList<Elevations.ElevationResults> elevations)
		{
			List<Tuple<double, double>> list = new List<Tuple<double, double>>();
			if (elevations != null && elevations.Count > 0)
			{
				list.Add(new Tuple<double, double>(0.0, elevations.First().Elevation));
				double num = 0.0;
				for (int i = 1; i < elevations.Count; i++)
				{
					Elevations.ElevationResults elevationResults = elevations[i - 1];
					Elevations.ElevationResults elevationResults2 = elevations[i];
					num += elevationResults2.Location.GetDistanceTo(elevationResults.Location);
					list.Add(new Tuple<double, double>(num, elevationResults2.Elevation));
				}
			}
			return list;
		}

		private void DoSaveWorkoutButtonTap()
		{
			Workout workout = new Workout
			{
				Controls = WorkoutControls.Value.ToList()
			};
			workout.RoundInclineControls();
			string jsonControls = JsonConvert.SerializeObject(workout.Controls);
			string jsonLatLng = JsonConvert.SerializeObject(RoutePoints.Value);
			SaveDrawMapViewModel.NavObject parameterValuesObject = new SaveDrawMapViewModel.NavObject
			{
				WorkoutTitle = workoutTitle,
				JsonControls = jsonControls,
				JsonLatLng = jsonLatLng
			};
			ShowViewModel<DrawMapViewModel>(parameterValuesObject, ShireViewParams.ChildView<SaveDrawMapViewModel>());
			SaveScreenShown.SetTrue();
		}

		private async Task DoCenterMapAtSearchResult(object item)
		{
			PlaceAutoComplete.Prediction selectedAutocomplete = item as PlaceAutoComplete.Prediction;
			await Task.Run(() => DoCenterMapAtSearchResultAsync(selectedAutocomplete));
			ForcedToolboxMode.Value = null;
		}

		private async Task DoCenterMapAtSearchResultAsync(PlaceAutoComplete.Prediction prediction)
		{
			disregardSearchTextUpdate = true;
			SearchText.Value = prediction.Description;
			SearchInputFieldFocused.Value = false;
			SearchResults.Value = new List<PlaceAutoComplete.Prediction>();
			iFit.Api.Google.LatLng latLng = await GetLatLngForPlaceId(prediction.PlaceId);
			if (latLng != null)
			{
				MapCenter.Value = latLng;
			}
		}

		private async Task<iFit.Api.Google.LatLng> GetLatLngForPlaceId(string placeId)
		{
			iFit.Api.Google.LatLng location = null;
			try
			{
				location = ((await Geocode.ReverseGetByPlaceId(googleApi, placeId))?.Results.FirstOrDefault())?.Geometry?.Location;
			}
			catch (Exception ex)
			{
				Log.Trace("DrawMap", "Exception thrown when getting reversed GeoCode by PlaceID " + ex.Message);
			}
			return location;
		}

		public override Task RefreshAfterModalityChange()
		{
			Log.Trace(LogTag, "RefreshAfterModalityChange is not implemented for DrawMap!!");
			return Task.CompletedTask;
		}

