	public class SaveDrawMapViewModel : BaseViewModel
	{
		public class NavObject
		{
			public string WorkoutTitle { get; set; }

			public string JsonControls { get; set; }

			public string JsonLatLng { get; set; }
		}

		private List<Workout.Control> workoutControls;

		private List<iFit.Api.Google.LatLng> workoutCoordinates;

		private readonly IElevationGainWorkoutControlService elevationGainWorkoutControlService;

		private readonly IWolfAnalytics analytics;

		private readonly ISettingsRouter settingsRouter;

		private readonly IWorkoutApiService workoutApiService;

		public const int MaxWorkoutDescriptionLength = 1500;

		public readonly INC<string> WorkoutTitle = new NC<string>();

		public readonly INC<string> WorkoutDescription = new NC<string>();

		public readonly INC<bool> IsSaving = new NC<bool>();

		public readonly INC<bool> SaveError = new NC<bool>();

		public readonly INC<bool> SaveSuccessful = new NC<bool>();

		[DependsOn(new string[] { "IsSaving", "SaveSuccessful" })]
		public bool ShowActivityIndicator
		{
			get
			{
				if (!IsSaving.Value)
				{
					return SaveSuccessful.Value;
				}
				return true;
			}
		}

		[DependsOn(new string[] { "WorkoutTitle", "IsSaving" })]
		public bool SaveButtonEnabled
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(WorkoutTitle.Value))
				{
					return !IsSaving.Value;
				}
				return false;
			}
		}

		[DependsOn(new string[] { "IsSaving" })]
		public ToolbarItemType ToolbarItems
		{
			get
			{
				if (!IsSaving.Value)
				{
					return ToolbarItemType.Back;
				}
				return ToolbarItemType.None;
			}
		}

		public IMvxAsyncCommand SaveWorkout => new MvxAsyncCommand(DoSaveWorkoutAsync);

		public ICommand BackPressed => new MvxCommand(DoClose);

		public MvxCommand CheckWorkoutDescriptionLength => new MvxCommand(DoCheckWorkoutDescriptionLength);

		public SaveDrawMapViewModel(ILocalSettings settings, IWolfAnalytics analytics, IElevationGainWorkoutControlService elevationGainWorkoutControlService, ISettingsRouter settingsRouter, IWorkoutApiService workoutApiService, ICurrentConsoleService currentConsoleService)
			: base(settings)
		{
			try
			{
				this.analytics = analytics;
				this.elevationGainWorkoutControlService = elevationGainWorkoutControlService;
				this.settingsRouter = settingsRouter;
				this.workoutApiService = workoutApiService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObject nav)
		{
			WorkoutTitle.Value = nav.WorkoutTitle;
			if (!string.IsNullOrWhiteSpace(nav.JsonControls))
			{
				workoutControls = JsonConvert.DeserializeObject<List<Workout.Control>>(nav.JsonControls);
			}
			if (!string.IsNullOrWhiteSpace(nav.JsonLatLng))
			{
				workoutCoordinates = JsonConvert.DeserializeObject<List<iFit.Api.Google.LatLng>>(nav.JsonLatLng);
			}
		}

		[DependsOn(new string[] { "WorkoutDescription" })]
		private void DoCheckWorkoutDescriptionLength()
		{
			if (WorkoutDescription.Value.Length > 1500)
			{
				WorkoutDescription.Value = WorkoutDescription.Value.Substring(0, 1500);
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RegisterForStartButton();
		}

		private async Task DoSaveWorkoutAsync()
		{
			IsSaving.Value = true;
			if (workoutControls.CountSafe() == 0)
			{
				ElevationGainWorkoutControlResult elevationGainWorkoutControlResult = null;
				if (workoutCoordinates.CountSafe() != 0)
				{
					bool isMetric = await settingsRouter.GetIsMetric().ConfigureAwait(continueOnCapturedContext: false);
					elevationGainWorkoutControlResult = await elevationGainWorkoutControlService.CalculateElevationGainAndWorkoutControls(workoutCoordinates, isMetric);
				}
				if (elevationGainWorkoutControlResult == null)
				{
					SaveError.Value = true;
					IsSaving.Value = false;
					return;
				}
				workoutControls = elevationGainWorkoutControlResult.WorkoutControls.ToList();
			}
			ConsoleType type = currentConsoleService.LastKnownConsoleType;
			IConsoleInfo consoleInfo = currentConsoleService.ActiveConsole?.ConsoleInfo;
			if (consoleInfo != null)
			{
				type = consoleInfo.MachineType;
			}
			Workout.WorkoutType type2 = Workout.WorkoutType.Run;
			if (type.IsBike())
			{
				type2 = Workout.WorkoutType.Cycle;
			}
			else if (type.IsRower())
			{
				type2 = Workout.WorkoutType.Row;
			}
			Workout workout = new Workout
			{
				Title = WorkoutTitle.Value,
				Description = WorkoutDescription.Value,
				Type = type2,
				Controls = workoutControls,
				Created = DateTime.Now,
				Target = Workout.TargetType.Meters,
				TargetValue = workoutControls.Last().At,
				Geo = new Workout.GeoSet
				{
					Path = new Workout.Path
					{
						Coordinates = workoutCoordinates?.Select((iFit.Api.Google.LatLng x) => new List<double> { x.Lng, x.Lat }).ToList()
					}
				}
			};
			string savedWorkoutId = null;
			try
			{
				savedWorkoutId = await workoutApiService.Create(workout).ConfigureAwait(continueOnCapturedContext: false);
				SaveSuccessful.Value = true;
			}
			catch (Exception ex)
			{
				Exception ex2 = ex;
				StringBuilder stringBuilder = new StringBuilder();
				stringBuilder.AppendLine(ex.Message);
				while (ex2.InnerException != null)
				{
					stringBuilder.AppendLine(ex2.InnerException.Message);
					ex2 = ex2.InnerException;
				}
				Log.Error("DrawMap", $"Exception thrown while saving draw map workout - {stringBuilder}");
				SaveError.Value = true;
			}
			finally
			{
				workout.Dispose();
			}
			if (!SaveError.Value)
			{
				await SavedMapWorkout(savedWorkoutId);
			}
			else
			{
				IsSaving.Value = false;
			}
		}

		protected async Task SavedMapWorkout(string savedWorkoutId)
		{
			await (analytics?.SavedDrawMap());
			PreWorkoutViewModel.NavObject parameterValuesObject = new PreWorkoutViewModel.NavObject
			{
				WorkoutId = savedWorkoutId,
				WorkoutSource = WorkoutSource.DrawMap,
				DashboardIndex = -1
			};
			NavigateToDashboardViewModel(parameterValuesObject);
		}

