	public class FanVolumeDialogViewModel : BaseViewModel
	{
		private readonly IFanVolumeHandler fanHandler;

		private IDisposable updateSub;

		private IDisposable timeSub;

		private TimeSpan remainingTime;

		public readonly INC<int> FanLevel = new NC<int>();

		public readonly INC<int> VolumeLevel = new NC<int>();

		public readonly INC<bool> IsFanMode = new NC<bool>();

		public TimeSpan DisplayTime { get; } = TimeSpan.FromSeconds(5.0);

		public TimeSpan DecrementIntervalLength { get; } = TimeSpan.FromSeconds(1.0);

		[DependsOn(new string[] { "IsFanMode" })]
		public bool IsVolumeMode => !IsFanMode.Value;

		[DependsOn(new string[] { "IsFanMode", "FanLevel" })]
		public bool FanIsAuto
		{
			get
			{
				if (IsFanMode.Value)
				{
					return FanLevel.Value == 4;
				}
				return false;
			}
		}

		public FanVolumeDialogViewModel(ILocalSettings localSettings, IFanVolumeHandler fanHandler)
			: base(localSettings)
		{
			try
			{
				this.fanHandler = fanHandler;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			if (ArbitraryData is FanVolumeUpdate update)
			{
				PerformUpdate(update);
			}
			updateSub?.Dispose();
			updateSub = fanHandler.WhenFanOrVolumeChange.Subscribe(PerformUpdate);
			timeSub?.Dispose();
			timeSub = Observable.Interval(DecrementIntervalLength, intervalScheduler).Subscribe(Decrement);
			return base.OnViewShown();
		}

		private void Decrement(long x)
		{
			remainingTime -= DecrementIntervalLength;
			if (remainingTime.TotalMilliseconds <= 0.0)
			{
				Finished();
			}
		}

		private void PerformUpdate(FanVolumeUpdate update)
		{
			if (update == null || update.IsUnknownFanUpdate || IsVolumeUpdateOnRetailDemoModeVideoView(update))
			{
				Finished();
				return;
			}
			if (update.IsFanUpdate)
			{
				IsFanMode.Value = true;
				FanLevel.Value = update.UpdateValue;
			}
			else
			{
				IsFanMode.Value = false;
				VolumeLevel.Value = update.UpdateValue;
			}
			remainingTime = DisplayTime;
		}

		private bool IsVolumeUpdateOnRetailDemoModeVideoView(FanVolumeUpdate update)
		{
			string text = dialogPresenter?.CurrentMainViewModel?.GetType().Name ?? string.Empty;
			if (text == "RetailDemoModeVideoViewModel")
			{
				return !update.IsFanUpdate;
			}
			return false;
		}

		private void Finished()
		{
			updateSub?.Dispose();
			timeSub?.Dispose();
			DoClose();
		}

