	public abstract class AutoUpdateDialogViewModel : BaseBleDialogViewModel
	{
		protected virtual bool ShouldDisplayUpdate => true;

		protected IDisposable UpdatingSub { get; private set; }

		protected AutoUpdateDialogViewModel(ILocalSettings localSettings)
			: base(localSettings)
		{
			try
			{
				SubscribeToUpdate();
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override void OnViewHidden()
		{
			DisposeUpdateSub();
			base.OnViewHidden();
		}

		public override void Dispose()
		{
			DisposeUpdateSub();
			((BaseViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

		private void DisposeUpdateSub()
		{
			UpdatingSub?.Dispose();
			UpdatingSub = null;
		}

		public void SubscribeToUpdate()
		{
			if (!deviceInfo.IsBuiltIn && Mvx.TryResolve<IUpdater>(out var service))
			{
				Log.Trace("Updating", "BaseViewModel.OnViewShown: subscribed to ShowUpdateProgressDialog " + GetType().Name);
				DisposeUpdateSub();
				UpdatingSub = service.WhenIsUpdatingChanged.Where((bool x) => x && ShouldDisplayUpdate).Take(1).Subscribe(ShowUpdateProgressDialog);
			}
		}

		protected virtual void ShowUpdateProgressDialog(bool _)
		{
			ShowViewModel<SettingsUpdateViewModel>();
		}

