	public class FullNameDialogViewModel : BaseViewModel
	{
		public class NavObj
		{
			public string First { get; set; }

			public string Last { get; set; }
		}

		private IIfitApiService ifitApi;

		public readonly INC<bool> IsSaving = new NC<bool>();

		public readonly INC<string> FirstName = new NC<string>();

		public readonly INC<string> LastName = new NC<string>();

		public readonly INC<string> ErrorMessage = new NC<string>();

		public ICommand SaveIt => new MvxAsyncCommand(DoSaveIt);

		[DependsOn(new string[] { "FirstName", "LastName" })]
		public bool CanSave => HumanNameConverter.IsValidFirstLast(FirstName.Value.Trim(), LastName.Value.Trim());

		public FullNameDialogViewModel(ILocalSettings localSettings, IIfitApiService ifitApi)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObj data)
		{
			if (data != null)
			{
				FirstName.Value = data.First;
				LastName.Value = data.Last;
			}
		}

		private async Task DoSaveIt()
		{
			try
			{
				IsSaving.Value = true;
				FirstName.Value = FirstName.Value.Trim();
				LastName.Value = LastName.Value.Trim();
				User user = await User.GetMe(ifitApi);
				user.Firstname = FirstName.Value;
				user.Lastname = LastName.Value;
				FullNameMessage message = new FullNameMessage(this, user.Firstname, user.Lastname);
				IMvxMessenger mvxMessenger = Mvx.Resolve<IMvxMessenger>();
				mvxMessenger.Publish(message);
				DoClose();
			}
