	public class LockPinDialogViewModel : BaseDialogViewModel
	{
		private readonly ILockPinService lockPinService;

		private int pinNumberIndex;

		private string[] pinNumberArray = new string[4];

		private bool changingLockPin;

		public readonly INC<string> Title = new NC<string>();

		public readonly INC<string> SubTitle = new NC<string>();

		public readonly INC<string> ButtonConfirmText = new NC<string>();

		public readonly INC<string> LockPinNumberConfirmation = new NC<string>();

		public readonly INC<bool> IsConfirming = new NC<bool>();

		public readonly INC<string> PinNumber1 = new NC<string>();

		public readonly INC<string> PinNumber2 = new NC<string>();

		public readonly INC<string> PinNumber3 = new NC<string>();

		public readonly INC<string> PinNumber4 = new NC<string>();

		public readonly INC<bool> LockPinDoesntMatch = new NC<bool>();

		public readonly INC<bool> ButtonConfirmEnabled = new NC<bool>();

		public readonly INC<string> ErrorMessage = new NC<string>();

		private string LockPinNumber => string.Concat(pinNumberArray).Trim();

		private LockPinDialogArbitraryData Data => ArbitraryData as LockPinDialogArbitraryData;

		public IMvxCommand ClickNumber { get; }

		public IMvxCommand ClickDelete { get; }

		public IMvxCommand ClickConfirm { get; }

		public IMvxCommand ClickCancel { get; }

		public IMvxCommand ClickBack { get; }

		public LockPinDialogViewModel(ILocalSettings localSettings, ILockPinService lockPinService)
			: base(localSettings)
		{
			try
			{
				this.lockPinService = lockPinService;
				ClickNumber = new MvxCommand<string>(DoPressNumber);
				ClickDelete = new MvxCommand(DoPressDelete);
				ClickConfirm = new MvxCommand(DoPressConfirm);
				ClickCancel = new MvxCommand(DoClose);
				ClickBack = new MvxCommand(SetUpLockPinState);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			changingLockPin = Data != null && Data.ChangingLockPin;
			SetUpLockPinState();
			return base.OnViewShown();
		}

		private void DoPressNumber(string number)
		{
			if (pinNumberIndex <= pinNumberArray.Length - 1)
			{
				pinNumberArray[pinNumberIndex] = number;
				UpdatePinNumberProperties();
				pinNumberIndex++;
				LockPinDoesntMatch.Value = false;
			}
		}

		private void DoPressDelete()
		{
			if (pinNumberIndex != 0)
			{
				Array.Clear(pinNumberArray, pinNumberIndex - 1, 1);
				UpdatePinNumberProperties();
				pinNumberIndex--;
				LockPinDoesntMatch.Value = false;
			}
		}

		private void DoPressConfirm()
		{
			try
			{
				if (IsConfirming.Value)
				{
					if (!PinNumberConfirmationMatch())
					{
						LockPinDoesntMatchState();
						return;
					}
					lockPinService.SaveLockPinNumber(LockPinNumber);
					DoClose();
					InformationDialogViewModel.InformationDisplayData arbitraryData = new InformationDialogViewModel.InformationDisplayData
					{
						Message = (changingLockPin ? Wolf.Core.Resources.AppStrings.lock_pin_dialog_new_lock_pin_saved : Wolf.Core.Resources.AppStrings.lock_pin_dialog_lock_pin_active),
						OnConfirm = delegate
						{
							NavigateToDashboardViewModel();
							ShowViewModel<SettingsViewModel>();
							if (Data?.FromViewModel == typeof(LockPinSettingsViewModel))
							{
								ShowViewModel<LockPinSettingsViewModel>();
							}
						}
					};
					BaseDialogViewModel.ShowDialogViewModel<InformationDialogViewModel>(arbitraryData);
				}
				else
				{
					InConfirmationLockPinState(LockPinNumber);
				}
			}
			catch (Exception ex)
			{
				Log.Error("Settings", "Error saving from lock pin dialog", ex.GetBaseException());
				ErrorMessage.Value = Wolf.Core.Resources.AppStrings.save_error;
			}
		}

		private void UpdatePinNumberProperties()
		{
			PinNumber1.Value = pinNumberArray[0];
			PinNumber2.Value = pinNumberArray[1];
			PinNumber3.Value = pinNumberArray[2];
			PinNumber4.Value = pinNumberArray[3];
			ButtonConfirmEnabled.Value = LockPinNumber.Length == 4;
		}

		private void ClearPinNumberProperties()
		{
			pinNumberIndex = 0;
			Array.Clear(pinNumberArray, 0, pinNumberArray.Length);
			UpdatePinNumberProperties();
		}

		private bool PinNumberConfirmationMatch()
		{
			if (LockPinNumberConfirmation != null && LockPinNumber.Length == 4)
			{
				return LockPinNumberConfirmation.Value == string.Concat(pinNumberArray);
			}
			return false;
		}

		private void SetUpLockPinState()
		{
			Title.Value = (changingLockPin ? Wolf.Core.Resources.AppStrings.lock_pin_dialog_create_new_pin_title : Wolf.Core.Resources.AppStrings.lock_pin_dialog_create_pin_title);
			SubTitle.Value = Wolf.Core.Resources.AppStrings.lock_pin_dialog_pin_do_not_match;
			ButtonConfirmText.Value = Wolf.Core.Resources.AppStrings.set_up_pin_button_text;
			LockPinNumberConfirmation.Value = string.Empty;
			IsConfirming.Value = false;
			LockPinDoesntMatch.Value = false;
			ClearPinNumberProperties();
		}

		private void InConfirmationLockPinState(string lockPinNumberConfirmation)
		{
			Title.Value = (changingLockPin ? Wolf.Core.Resources.AppStrings.lock_pin_dialog_confirm_new_lock_pin_title : Wolf.Core.Resources.AppStrings.lock_pin_dialog_confirm_lock_pin_title);
			SubTitle.Value = string.Empty;
			ButtonConfirmText.Value = Wolf.Core.Resources.AppStrings.confirm_pin_button_text;
			LockPinNumberConfirmation.Value = lockPinNumberConfirmation;
			IsConfirming.Value = true;
			LockPinDoesntMatch.Value = false;
			ClearPinNumberProperties();
		}

		private void LockPinDoesntMatchState()
		{
			SubTitle.Value = Wolf.Core.Resources.AppStrings.lock_pin_dialog_pin_do_not_match;
			LockPinDoesntMatch.Value = true;
			ClearPinNumberProperties();
		}

