	public class NoWifiDialogViewModel : BaseViewModel
	{
		public class DisplayData
		{
			public string Title { get; set; }

			public string Description { get; set; }

			public string CancelButtonText { get; set; }

			public string OkButtonText { get; set; }

			public bool ShowCentered { get; set; }

			public bool TurnOnWifi { get; set; } = true;

			public Action AfterConnected { get; set; }

			public bool Dismissible { get; set; } = true;

			public DisplayData()
			{
				ShowCentered = true;
				TurnOnWifi = true;
			}
		}

		public readonly INC<string> OkButtonDisplayString = new NC<string>();

		public readonly INC<string> TitleDisplayString = new NC<string>();

		public readonly INC<string> DescriptionDisplayString = new NC<string>();

		public readonly INC<bool> ShowCancelButton = new NC<bool>();

		public readonly INC<bool> IsConnecting = new NC<bool>();

		public readonly INC<string> MessageToUser = new NC<string>();

		private IAppLauncherService appLauncher;

		private readonly IHardwareInfo hardwareInfo;

		private DisplayData Data => ArbitraryData as DisplayData;

		public string CancelButtonText => Data?.CancelButtonText ?? Wolf.Core.Resources.AppStrings.default_no_wifi_ignore;

		private string TurnOnString => Data?.OkButtonText ?? Wolf.Core.Resources.AppStrings.default_no_wifi_turn_on;

		private string OkButtonText => Wolf.Core.Resources.AppStrings.default_no_wifi_go_to_settings;

		public bool ShowCentered => Data?.ShowCentered ?? false;

		public bool Dismissible => Data?.Dismissible ?? true;

		public ICommand OkTapped => new MvxCommand(DoOkTapped);

		public IMvxCommand WifiDashboardViewModel => new MvxCommand(ShowWifiDashboard);

		protected bool ShowingSettingsMode
		{
			get
			{
				if (wifiService.IsWifiEnabled)
				{
					return !connectivity.IsConnected;
				}
				return false;
			}
		}

		public NoWifiDialogViewModel(ILocalSettings localSettings, IAppLauncherService appLauncher, IHardwareInfo hardwareInfo)
			: base(localSettings)
		{
			try
			{
				this.appLauncher = appLauncher;
				this.hardwareInfo = hardwareInfo;
				ShowCancelButton.Value = true;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			if (connectivity.IsConnected)
			{
				Close(this);
			}
			connectivity.ConnectivityChanged -= ConnectivityChanged;
			connectivity.ConnectivityChanged += ConnectivityChanged;
			OkButtonDisplayString.Value = TurnOnString;
			TitleDisplayString.Value = TextForTitle();
			DescriptionDisplayString.Value = TextForDescription();
			UpdateDialog();
			return base.OnViewShown();
		}

		private void UpdateDialog(bool force = false)
		{
			if (ShowingSettingsMode || force)
			{
				IsConnecting.Value = false;
				OkButtonDisplayString.Value = Wolf.Core.Resources.AppStrings.default_no_wifi_go_to_settings;
				TitleDisplayString.Value = TextForTitle();
				DescriptionDisplayString.Value = TextForDescription();
				ShowCancelButton.Value = false;
			}
		}

		private string TextForTitle()
		{
			if (!ShowingSettingsMode && Data?.Title != null)
			{
				return Data.Title;
			}
			return Wolf.Core.Resources.AppStrings.default_no_wifi_title;
		}

		private string TextForDescription()
		{
			if (!ShowingSettingsMode && Data?.Description != null)
			{
				return Data.Description;
			}
			return Wolf.Core.Resources.AppStrings.default_no_wifi_description;
		}

		private void DoOkTapped()
		{
			if (ShowingSettingsMode)
			{
				GoToSettings();
				return;
			}
			DisplayData data = Data;
			if (data != null && data.TurnOnWifi)
			{
				TurnOnWifi();
			}
			else
			{
				DoClose();
			}
		}

		private void ShowWifiDashboard()
		{
			if (!deviceInfo.IsStrengthMirror)
			{
				ShowViewModel<SettingsWifiViewModel>();
			}
		}

		private void GoToSettings()
		{
			if (deviceInfo.IsBuiltIn)
			{
				wifiService.TurnWifiOn();
				ShowViewModel<SettingsWifiViewModel>();
			}
			else
			{
				appLauncher.LaunchApp(LaunchableApp.WifiSettings);
			}
			DoClose();
		}

		private void TurnOnWifi()
		{
			try
			{
				if (hardwareInfo.IsAndroid)
				{
					IsConnecting.Value = true;
					wifiService.TurnWifiOn();
				}
				else
				{
					appLauncher.LaunchApp(LaunchableApp.WifiSettings);
				}
			}
			catch (Exception e)
			{
				HandleConnectionError(e);
			}
		}

		private void HandleConnectionError(Exception e)
		{
			if (!(e is TimeoutException))
			{
				Log.Trace("Wifi", $"Failed due to timeout.  Exception: {e.GetBaseException()}");
			}
			UpdateDialog(force: true);
		}

		protected void ConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			if (connectivity.IsConnected)
			{
				MessageToUser.Value = Wolf.Core.Resources.AppStrings.wifi_connected_toast;
				DoClose();
				Data?.AfterConnected?.Invoke();
			}
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			connectivity.ConnectivityChanged -= ConnectivityChanged;
		}

