	public class PasswordUpdateDialogViewModel : BaseViewModel
	{
		private readonly IIfitApiService ifitApi;

		private new readonly IDialogPresenter dialogPresenter;

		public readonly INC<bool> ViewModelInitialized = new NC<bool>();

		public readonly BooleanCycle ActivityIndicatorVisible = new BooleanCycle();

		public readonly INC<string> TitleText = new NC<string>();

		public readonly INC<string> FirstLabelText = new NC<string>();

		public readonly INC<string> SecondLabelText = new NC<string>();

		public readonly INC<string> ThirdLabelText = new NC<string>();

		public readonly INC<bool> FirstFieldSecure = new NC<bool>(value: true);

		public readonly INC<bool> SecondFieldSecure = new NC<bool>(value: true);

		public readonly INC<bool> ThirdFieldSecure = new NC<bool>(value: true);

		public readonly INC<bool> ConfirmButtonEnabled = new NC<bool>();

		public readonly INC<string> FirstFieldInput = new NC<string>();

		public readonly INC<string> SecondFieldInput = new NC<string>();

		public readonly INC<string> ThirdFieldInput = new NC<string>();

		public readonly INC<string> CancelButtonText = new NC<string>();

		public readonly INC<string> ConfirmButtonText = new NC<string>();

		public ICommand CancelOrGoBack => new MvxCommand(DoClose);

		public ICommand EnableOrDisableConfirmButton => new MvxCommand(DoEnableOrDisableConfirmButton);

		public ICommand Confirm => new MvxAsyncCommand(DoConfirm);

		public ICommand FirstFieldSecureToggle => new MvxCommand(DoToggleFirstFieldSecure);

		public ICommand SecondFieldSecureToggle => new MvxCommand(DoToggleSecondFieldSecure);

		public ICommand ThirdFieldSecureToggle => new MvxCommand(DoToggleThirdFieldSecure);

		public PasswordUpdateDialogViewModel(ILocalSettings localSettings, IIfitApiService ifitApi, IDialogPresenter dialogPresenter)
			: base(localSettings)
		{
			try
			{
				this.ifitApi = ifitApi;
				this.dialogPresenter = dialogPresenter;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			InitializeDialog();
			ViewModelInitialized.Value = true;
			return base.OnViewShown();
		}

		private void InitializeDialog()
		{
			TitleText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_password_dialog_maintext;
			FirstLabelText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_reset_password_dialog_subtext;
			FirstFieldInput.Value = string.Empty;
			SecondLabelText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_password_dialog_subtext;
			SecondFieldInput.Value = string.Empty;
			ThirdLabelText.Value = Wolf.Core.Resources.AppStrings.settings_myprofile_password_dialog_placeholder;
			ThirdFieldInput.Value = string.Empty;
			ConfirmButtonText.Value = Wolf.Core.Resources.AppStrings.settings_dialog_Save;
			ConfirmButtonEnabled.Value = false;
			CancelButtonText.Value = Wolf.Core.Resources.AppStrings.settings_dialog_cancel;
		}

		private async Task DoConfirm()
		{
			ActivityIndicatorVisible.Value = true;
			await CheckIfInputTextsEqual();
		}

		private async Task ShowNewDialog(string message, bool isSuccess = false)
		{
			DoClose();
			await Task.Delay(1000);
			ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(isSuccess ? Wolf.Core.Resources.AppStrings.success : Wolf.Core.Resources.AppStrings.error, message, null, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), OnConfirmActionTiming.AfterClose);
			dialogPresenter.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, arbitraryData);
		}

		private void DoToggleFirstFieldSecure()
		{
			FirstFieldSecure.Value = !FirstFieldSecure.Value;
		}

		private void DoToggleSecondFieldSecure()
		{
			SecondFieldSecure.Value = !SecondFieldSecure.Value;
		}

		private void DoToggleThirdFieldSecure()
		{
			ThirdFieldSecure.Value = !ThirdFieldSecure.Value;
		}

		private void DoEnableOrDisableConfirmButton()
		{
			ConfirmButtonEnabled.Value = AreValidPasswords();
		}

		private async Task CheckIfInputTextsEqual()
		{
			if (string.Equals(SecondFieldInput.Value, ThirdFieldInput.Value))
			{
				if (AreValidPasswords())
				{
					await UpdateUserPassword();
				}
				else
				{
					await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_myprofile_password_dialog_short);
				}
			}
			else
			{
				await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_myprofile_password_dialog_nomatch);
			}
		}

		private bool IsValidPassword(string password)
		{
			if (password == null)
			{
				return false;
			}
			return password.Length >= 8;
		}

		private bool AreValidPasswords()
		{
			if (IsValidPassword(FirstFieldInput.Value) && IsValidPassword(SecondFieldInput.Value))
			{
				return IsValidPassword(ThirdFieldInput.Value);
			}
			return false;
		}

		private async Task UpdateUserPassword()
		{
			User user;
			try
			{
				user = await User.GetMe(ifitApi);
			}
			catch (Exception ex)
			{
				Log.Error("Settings", ex.Message);
				await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_login_sync_error);
				return;
			}
			if (user == null)
			{
				await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_login_sync_error);
				return;
			}
			UserPasswordChange passwordChange = new UserPasswordChange
			{
				OldPassword = FirstFieldInput.Value,
				NewPassword = SecondFieldInput.Value
			};
			bool success;
			try
			{
				success = await user.ChangePassword(ifitApi, passwordChange);
			}
			catch (Exception ex2)
			{
				success = false;
				Log.Error("Settings", ex2.Message);
				if (ex2 is ApiException)
				{
					if (((ApiException)ex2).StatusCode == HttpStatusCode.BadRequest)
					{
						await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_myprofile_invalid_password);
					}
					else
					{
						await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_myprofile_password_error);
					}
					return;
				}
				if (ex2 is iFit.Api.Support.ConnectivityException)
				{
					await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_myprofile_password_nowifi);
					return;
				}
			}
			if (success)
			{
				await ShowNewDialog(Wolf.Core.Resources.AppStrings.password_was_updated, isSuccess: true);
			}
			else
			{
				await ShowNewDialog(Wolf.Core.Resources.AppStrings.settings_myprofile_password_error);
			}
		}

