	public class RestartDialogViewModel : BaseViewModel
	{
		public class NavObject
		{
			public string FatalityExceptionType { get; set; }

			public string DisplayMessage { get; set; }
		}

		public readonly INC<string> DisplayMessage = new NC<string>();

		private readonly IDisposable recoverSub;

		private string fatalityExceptionType;

		public RestartDialogViewModel(ILocalSettings settings, IFatalityHandler fatality)
			: base(settings)
		{
			try
			{
				recoverSub = fatality.WhenFatalityRecovered.Where((FatalRecovery x) => x.ExceptionTypeToRecover.ToString() == fatalityExceptionType).Subscribe(FinishHim);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NavObject nav)
		{
			DisplayMessage.Value = nav.DisplayMessage;
			fatalityExceptionType = nav.FatalityExceptionType;
		}

		private void FinishHim(FatalRecovery _)
		{
			DoClose();
		}

		public override Task OnViewShown()
		{
			trackingService.IsRestartDialogShowing = true;
			return base.OnViewShown();
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			trackingService.IsRestartDialogShowing = false;
		}

		public override void Dispose()
		{
			recoverSub?.Dispose();
			base.Dispose();
			UnregisterChangeHandlers();
		}

