	public static class TryAgainErrors
	{
		private const string LegacyAndroidUrl = "https://play.google.com/store/apps/details?id=com.ifit.standalone";

		private const string LegacyiOSUrl = "https://itunes.apple.com/us/app/ifit-bluetooth-tablet-app/id1108588956?mt=8";

		private const string FirmwareSupportUrl = "http://ifit.io/wolf-tablet-firmware-support";

		private const string BluetoothSupportUrl = "http://ifit.io/JJCq";

		private static IHardwareInfo hardwareInfo;

		private static string LegacyAppUrl
		{
			get
			{
				if (!IsAndroid)
				{
					return "https://itunes.apple.com/us/app/ifit-bluetooth-tablet-app/id1108588956?mt=8";
				}
				return "https://play.google.com/store/apps/details?id=com.ifit.standalone";
			}
		}

		public static string BleErrorTip1
		{
			get
			{
				string format = (IsAndroid ? Wolf.Core.Resources.AppStrings.ble_dialog_error_tip1 : Wolf.Core.Resources.AppStrings.ble_dialog_error_tip1_ios);
				if (!Mvx.TryResolve<IDeviceInformation>(out var service))
				{
					return string.Format(format, Wolf.Core.Resources.AppStrings.tablet);
				}
				return string.Format(format, service.IsTablet ? Wolf.Core.Resources.AppStrings.tablet : Wolf.Core.Resources.AppStrings.phone);
			}
		}

		private static string BleErrorTipLink1
		{
			get
			{
				if (!IsAndroid)
				{
					return string.Empty;
				}
				return Wolf.Core.Resources.AppStrings.ble_dialog_error_view_ble_settings;
			}
		}

		public static bool IsAndroid
		{
			get
			{
				if (hardwareInfo == null)
				{
					Mvx.TryResolve<IHardwareInfo>(out hardwareInfo);
				}
				return hardwareInfo?.IsAndroid ?? false;
			}
		}

		public static TryAgainError None => new TryAgainError(string.Empty, GoToNothing);

		public static TryAgainError LegacyApp => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_invalid_software_number_error_tip1, Wolf.Core.Resources.AppStrings.ble_dialog_invalid_software_number_error_tip_link1, GoToLegacyApp);

		public static TryAgainError FirmwareSupport => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_invalid_software_number_error_tip2, Wolf.Core.Resources.AppStrings.ble_dialog_invalid_software_number_error_tip_link2, GoToFirmwareSupport);

		public static TryAgainError FirmewareWifi => new TryAgainError(Wolf.Core.Resources.AppStrings.firmware_update_wifi_tip1, GoToNothing);

		public static TryAgainError FirmwareRestart => new TryAgainError(Wolf.Core.Resources.AppStrings.firmware_update_restart_tip2, GoToNothing);

		public static TryAgainError EmptyBluetoothSupport1 => new TryAgainError(BleErrorTip1, GoToNothing);

		public static TryAgainError EmptyBluetoothSupport2 => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_error_tip2, GoToNothing);

		public static TryAgainError EmptyBluetoothSupport3 => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_error_tip3, GoToNothing);

		public static TryAgainError BluetoothSupport1 => new TryAgainError(BleErrorTip1, GoToBluetoothSupport);

		public static TryAgainError BluetoothSupport2 => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_error_tip2, GoToBluetoothSupport);

		public static TryAgainError BluetoothSupport3 => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_error_tip3, GoToBluetoothSupport);

		public static TryAgainError BleActivationInstructions => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_error_tip4, Wolf.Core.Resources.AppStrings.ble_dialog_error_view_manually_activate.ToUpper(), GoToBleActivationInstructions);

		public static TryAgainError BleSettings => new TryAgainError(BleErrorTip1, BleErrorTipLink1, GoToBleSettings);

		public static TryAgainError EquipmentRecovery => new TryAgainError(Wolf.Core.Resources.AppStrings.ble_dialog_error_tip5, Wolf.Core.Resources.AppStrings.ble_dialog_error_tip5_link.ToUpper(), GoToEquipmentRecovery);

		private static void GoToNothing()
		{
		}

		private static void GoToUrl(string url)
		{
			if (Mvx.TryResolve<IMvxWebBrowserTask>(out var service))
			{
				service.ShowWebPage(url);
			}
		}

		private static void GoToLegacyApp()
		{
			GoToUrl(LegacyAppUrl);
		}

		private static void GoToFirmwareSupport()
		{
			GoToUrl("http://ifit.io/wolf-tablet-firmware-support");
		}

		private static void GoToBluetoothSupport()
		{
			GoToUrl("http://ifit.io/JJCq");
		}

		private static void GoToBleActivationInstructions()
		{
			BaseBleDialogViewModel.ShowDialogViewModel<BleActivateInstructionStepsViewModel>();
		}

		private static void GoToBleSettings()
		{
			if (Mvx.TryResolve<IAppLauncherService>(out var service))
			{
				service?.LaunchApp(LaunchableApp.BleSettings);
			}
		}

		private static void GoToEquipmentRecovery()
		{
			Log.Trace("Updating", "Scanning for updateable equipment");
			if (Mvx.TryResolve<IDfuConnectionService>(out var service))
			{
				service.ScanForRecoverableDevices(null, showNoRecoverableDialog: true, showScanningDialog: true);
			}
		}
	}
