		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			bool flag = ArbitraryData?.ErrorText == null;
			ErrorText.Value = ArbitraryData?.ErrorText ?? Wolf.Core.Resources.AppStrings.ble_dialog_error_text;
			ErrorSubText.Value = ArbitraryData?.ErrorSubText ?? Wolf.Core.Resources.AppStrings.ble_dialog_error_subtext;
			ButtonText.Value = ArbitraryData?.ButtonText?.ToUpper() ?? Wolf.Core.Resources.AppStrings.ble_dialog_equipment_not_found_try_again.ToUpper();
			if (flag)
			{
				SetupError(ErrorTip1, ErrorTipLink1, out firstLinkClicked, ArbitraryData?.Error1 ?? TryAgainErrors.EmptyBluetoothSupport1, TryAgainErrors.BleErrorTip1);
				SetupError(ErrorTip2, ErrorTipLink2, out secondLinkClicked, ArbitraryData?.Error2 ?? TryAgainErrors.EmptyBluetoothSupport2, Wolf.Core.Resources.AppStrings.ble_dialog_error_tip2);
				SetupError(ErrorTip3, ErrorTipLink3, out thirdLinkClicked, ArbitraryData?.Error3 ?? TryAgainErrors.EmptyBluetoothSupport3, Wolf.Core.Resources.AppStrings.ble_dialog_error_tip3);
				SetupError(ErrorTip4, ErrorTipLink4, out fourthLinkClicked, ArbitraryData?.Error4 ?? TryAgainErrors.None);
				SetupError(ErrorTip5, ErrorTipLink5, out fifthLinkClicked, ArbitraryData?.Error5 ?? TryAgainErrors.None);
			}
			else
			{
				SetupError(ErrorTip1, ErrorTipLink1, out firstLinkClicked, ArbitraryData?.Error1 ?? TryAgainErrors.EmptyBluetoothSupport1);
				SetupError(ErrorTip2, ErrorTipLink2, out secondLinkClicked, ArbitraryData?.Error2 ?? TryAgainErrors.EmptyBluetoothSupport2);
				SetupError(ErrorTip3, ErrorTipLink3, out thirdLinkClicked, ArbitraryData?.Error3 ?? TryAgainErrors.EmptyBluetoothSupport3);
				SetupError(ErrorTip4, ErrorTipLink4, out fourthLinkClicked, ArbitraryData?.Error4 ?? TryAgainErrors.None);
				SetupError(ErrorTip5, ErrorTipLink5, out fifthLinkClicked, ArbitraryData?.Error5 ?? TryAgainErrors.None);
			}
			CanClose.Value = ArbitraryData?.CanClose ?? false;
			IsOnboarding.Value = ArbitraryData?.IsOnboarding ?? false;
			ViewModelInitialized.Value = true;
		}

		private void SetupError(INC<string> tip, INC<string> tipLink, out ICommand clickCommand, TryAgainError error)
		{
			tip.Value = error.Tip;
			tipLink.Value = error.TipLink;
			clickCommand = new MvxCommand(error.ClickAction);
		}

		private void SetupError(INC<string> tip, INC<string> tipLink, out ICommand clickCommand, TryAgainError error, string erroTipValue)
		{
			tip.Value = erroTipValue;
			tipLink.Value = error.TipLink;
			clickCommand = new MvxCommand(error.ClickAction);
		}

		private void RetryAndClose()
		{
			_whenRetryButtonTapped.OnNext(null);
			DoClose();
			ArbitraryData?.Retry?.Invoke();
		}

		protected override void ShowUpdateProgressDialog(bool _)
		{
			if (IsOnboarding.Value)
			{
				ShowViewModel<OnboardingFirmwareUpdateViewModel>(new OnboardingFirmwareUpdateViewModel.NavObject
				{
					IsDfuRecovery = true
				});
			}
			else
			{
				base.ShowUpdateProgressDialog(_);
			}
		}

