namespace Wolf.Core.ViewModels.Dialogs.SimpleConfirmation
{
	public class ConfirmationInitializationData
	{
		public bool CancellableOperation { get; private set; }

		public string CancelButtonText { get; private set; }

		public string ConfirmButtonText { get; private set; }

		public string Title { get; private set; }

		public string Message { get; private set; }

		public Func<CancellationToken, Task<object>> OnConfirm { get; private set; }

		public Action<Task<object>> OnFinished { get; private set; }

		public OnConfirmActionTiming Timing { get; private set; }

		public Action OnClose { get; private set; }

		public Action OnCancel { get; private set; }

		public string DialogTag { get; private set; }

		public TaskCompletionSource<object> TCS { get; set; }

		public bool Dismissible { get; private set; }

		public bool Cancellable { get; private set; }

		public string Subtitle { get; private set; }

		public bool IsWarning { get; private set; }

		public ConfirmationInitializationData(string title, string message, string cancelButtonText, string confirmButtonText, Action onConfirm, Action onCancel)
			: this(title, message, async delegate
			{
				await Task.Run(delegate
				{
					onConfirm?.Invoke();
				});
				return (object)null;
			}, cancellableOperation: true, delegate
			{
			}, cancelButtonText, confirmButtonText, OnConfirmActionTiming.BeforeClose, null, onCancel)
		{
		}

		public ConfirmationInitializationData(string title, string message, Func<CancellationToken, Task<object>> onConfirm, bool cancellableOperation, Action<Task<object>> onFinished, string cancelButtonText, string confirmButtonText, OnConfirmActionTiming timing, Action onClose = null, Action onCancel = null, bool dismissible = true, bool cancellable = true, string dialogTag = "", TaskCompletionSource<object> tcs = null, string subtitle = null, bool isWarning = false)
		{
			CancellableOperation = cancellableOperation;
			CancelButtonText = cancelButtonText ?? Wolf.Core.Resources.AppStrings.cancel.ToUpper();
			ConfirmButtonText = confirmButtonText ?? Wolf.Core.Resources.AppStrings.yes.ToUpper();
			Title = title ?? string.Empty;
			Message = message ?? string.Empty;
			OnConfirm = onConfirm;
			OnFinished = onFinished;
			Timing = timing;
			OnClose = onClose;
			OnCancel = onCancel;
			Dismissible = dismissible;
			Cancellable = cancellable;
			DialogTag = dialogTag;
			TCS = tcs;
			Subtitle = subtitle;
			IsWarning = isWarning;
		}

		public ConfirmationInitializationData(string title, string message, string closeButtonText, bool dismissible, bool cancellable, string dialogTag = "", TaskCompletionSource<object> tcs = null)
			: this(title, message, null, string.Empty, closeButtonText, null, null, dismissible, cancellable, dialogTag, tcs)
		{
		}

		public ConfirmationInitializationData(string title, string message, Func<CancellationToken, Task<object>> onConfirm, string cancelButtonText = null, string confirmButtonText = null, Action onClose = null, Action onCancel = null, bool dismissible = true, bool cancellable = true, string dialogTag = "", TaskCompletionSource<object> tcs = null)
			: this(title, message, onConfirm, cancellableOperation: false, null, cancelButtonText, confirmButtonText, OnConfirmActionTiming.AfterClose, onClose, onCancel, dismissible, cancellable, dialogTag, tcs)
		{
		}
	}
	public enum OnConfirmActionTiming
	{
		BeforeClose = 1,
		AfterClose
	}
	public class SimpleConfirmationDialogViewModel : BaseDialogViewModel
	{
		private readonly IWolfAnalytics wolfAnalytics;

		private bool doNotSetResult;

		private bool cancellableOperation;

		private bool dismissible;

		private bool didConfirm;

		private CancellationTokenSource cancellationTokenSource;

		private Func<CancellationToken, Task<object>> onConfirmFunc;

		private OnConfirmActionTiming onConfirmActionTiming;

		private Action<Task<object>> onFinished;

		private Action onClose;

		private Action onCancel;

		public readonly BooleanCycle ActivityIndicatorVisible = new BooleanCycle();

		public readonly BooleanCycle ActivityCancelButtonVisible = new BooleanCycle();

		public readonly INC<string> CancelButtonText = new NC<string>();

		public readonly INC<string> ConfirmButtonText = new NC<string>();

		public readonly BooleanCycle Dismissible = new BooleanCycle(value: true);

		public readonly BooleanCycle Cancellable = new BooleanCycle(value: true);

		public readonly INC<string> MessageText = new NC<string>();

		public readonly INC<string> TitleText = new NC<string>();

		public readonly INC<string> SubtitleText = new NC<string>();

		public readonly BooleanCycle SubtitleVisible = new BooleanCycle();

		public readonly BooleanCycle IsWarning = new BooleanCycle();

		public override object ArbitraryData
		{
			get
			{
				return base.ArbitraryData;
			}
			set
			{
				base.ArbitraryData = value;
				UpdateFromArbitraryData();
			}
		}

		public ConfirmationInitializationData InitializationData => ArbitraryData as ConfirmationInitializationData;

		public TaskCompletionSource<object> TCS { get; private set; }

		public ICommand CancelOperation => new MvxCommand(DoCancelOperation);

		public ICommand Confirm => new MvxAsyncCommand(DoConfirm);

		public SimpleConfirmationDialogViewModel(ILocalSettings settings, IWolfAnalytics wolfAnalytics)
			: base(settings)
		{
			try
			{
				this.wolfAnalytics = wolfAnalytics;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			Dismissible.Value = dismissible;
			return base.OnViewShown();
		}

		private void UpdateFromArbitraryData()
		{
			if (ArbitraryData is ConfirmationInitializationData confirmationInitializationData)
			{
				TitleText.Value = confirmationInitializationData.Title;
				MessageText.Value = confirmationInitializationData.Message;
				cancellableOperation = confirmationInitializationData.CancellableOperation;
				CancelButtonText.Value = confirmationInitializationData.CancelButtonText;
				ConfirmButtonText.Value = confirmationInitializationData.ConfirmButtonText;
				onConfirmFunc = confirmationInitializationData.OnConfirm;
				onConfirmActionTiming = confirmationInitializationData.Timing;
				onFinished = confirmationInitializationData.OnFinished;
				onClose = confirmationInitializationData.OnClose;
				onCancel = confirmationInitializationData.OnCancel;
				dismissible = confirmationInitializationData.Dismissible;
				Cancellable.Value = confirmationInitializationData.Cancellable;
				TCS = confirmationInitializationData.TCS;
				SubtitleText.Value = confirmationInitializationData?.Subtitle;
				SubtitleVisible.Value = !string.IsNullOrWhiteSpace(SubtitleText.Value);
				IsWarning.Value = confirmationInitializationData.IsWarning;
				StringBuilder stringBuilder = new StringBuilder();
				stringBuilder.Append("Showed SimpleConfirmationDialog: ");
				stringBuilder.Append(confirmationInitializationData.Title ?? "no title");
				if (!string.IsNullOrEmpty(confirmationInitializationData.Message))
				{
					stringBuilder.Append(" / " + confirmationInitializationData.Message);
				}
				if (!string.IsNullOrEmpty(confirmationInitializationData.Subtitle))
				{
					stringBuilder.Append(" / " + confirmationInitializationData.Subtitle);
					wolfAnalytics.ErrorCodeDisplayed(confirmationInitializationData.Title, confirmationInitializationData.Message, confirmationInitializationData.Subtitle);
				}
				Log.Trace("Navigation", stringBuilder.ToString());
			}
		}

		private async Task DoConfirm()
		{
			Log.Trace("Navigation", "User tapped confirm button: " + (ConfirmButtonText.Value ?? "null string") + " (" + TitleText.Value + ")");
			cancellationTokenSource = new CancellationTokenSource();
			CancellationToken token = cancellationTokenSource.Token;
			Task<object> task = null;
			Cancellable.Value = true;
			didConfirm = true;
			if (onConfirmActionTiming == OnConfirmActionTiming.BeforeClose)
			{
				ActivityIndicatorVisible.SetTrue();
				ActivityCancelButtonVisible.Value = cancellableOperation;
				if (onConfirmFunc != null)
				{
					task = Task.Run(() => onConfirmFunc(token), token);
					try
					{
						await task;
					}
					catch
					{
					}
				}
				ActivityCancelButtonVisible.SetFalse();
				onFinished?.Invoke(task);
				TCS?.TrySetResult(task);
				doNotSetResult = true;
				DoClose();
				return;
			}
			doNotSetResult = true;
			DoClose();
			if (onConfirmFunc != null)
			{
				task = Task.Run(() => onConfirmFunc(token), token);
			}
			onFinished?.Invoke(task);
			TCS?.TrySetResult(task);
		}

		private void DoCancelOperation()
		{
			if (cancellableOperation)
			{
				cancellationTokenSource?.Cancel();
			}
		}

		protected override void DoClose()
		{
			Log.Trace("Navigation", "Dialog closed by user: " + TitleText.Value + ".");
			if (Cancellable.Value)
			{
				if (!didConfirm)
				{
					onCancel?.Invoke();
				}
				onClose?.Invoke();
				if (!doNotSetResult)
				{
					TCS?.TrySetResult(null);
				}
				base.DoClose();
			}
		}

