namespace Wolf.Core.ViewModels.Dialogs.Progress
{
	public class ProgressDialogResult
	{
		public bool Success { get; private set; }

		public Exception Error { get; private set; }

		private ProgressDialogResult(bool success, Exception error)
		{
			Success = success;
			Error = error;
		}

		public static ProgressDialogResult FromSuccess()
		{
			return new ProgressDialogResult(success: true, null);
		}

		public static ProgressDialogResult FromError(Exception error)
		{
			return new ProgressDialogResult(success: false, error);
		}
	}
	public class ProgressDialogViewModel : BaseDialogViewModel
	{
		public readonly INC<string> TitleText = new NC<string>();

		private new readonly IDialogPresenter dialogPresenter;

		private IDisposable observableSubscriber;

		public new ProgressInitializationData ArbitraryData
		{
			get
			{
				return base.ArbitraryData as ProgressInitializationData;
			}
			set
			{
				base.ArbitraryData = value;
			}
		}

		public ProgressDialogViewModel(ILocalSettings localSettings, IDialogPresenter dialogPresenter)
			: base(localSettings)
		{
			try
			{
				this.dialogPresenter = dialogPresenter;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override Task OnViewShown()
		{
			if (ArbitraryData != null)
			{
				TitleText.Value = ArbitraryData.Title;
				observableSubscriber?.Dispose();
				observableSubscriber = null;
				if (ArbitraryData.Observable != null)
				{
					if (ArbitraryData.Timeout.Ticks > 0)
					{
						observableSubscriber = ArbitraryData.Observable.Timeout(ArbitraryData.Timeout).Take(1).Subscribe(OnNext, OnError);
					}
					else
					{
						observableSubscriber = ArbitraryData.Observable.Take(1).Subscribe(OnNext, OnError);
					}
				}
			}
			return base.OnViewShown();
		}

		private void CloseThenInvoke(Action action)
		{
			observableSubscriber?.Dispose();
			observableSubscriber = null;
			DoClose();
			if (dialogPresenter != null)
			{
				WaitForClosureBefore(action);
			}
			else
			{
				action();
			}
		}

		private void OnNext(object obj)
		{
			CloseThenInvoke(delegate
			{
				ArbitraryData?.OnNext?.Invoke(obj);
				ArbitraryData?.TCS?.TrySetResult(ProgressDialogResult.FromSuccess());
			});
		}

		private void OnError(Exception e)
		{
			CloseThenInvoke(delegate
			{
				ArbitraryData?.OnError?.Invoke(e);
				ArbitraryData?.TCS?.TrySetResult(ProgressDialogResult.FromError(e));
			});
		}

		private void WaitForClosureBefore(Action action)
		{
			Task.Run(async delegate
			{
				bool dialogStillShown = true;
				int waitPeriodMs = 50;
				int remainingAttempts = 1000 / waitPeriodMs;
				while (dialogStillShown && remainingAttempts > 0)
				{
					InvokeOnMainThread(delegate
					{
						dialogStillShown = dialogPresenter.IsDialogShown<ProgressDialogViewModel>();
					});
					if (!dialogStillShown)
					{
						break;
					}
					remainingAttempts--;
					await Task.Delay(waitPeriodMs);
				}
				InvokeOnMainThread(action);
			});
		}

		public override void Dispose()
		{
			observableSubscriber?.Dispose();
			observableSubscriber = null;
			((BaseViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

