		public static bool CheckShouldRecoverForBuiltIn(IConsoleBasicInfo basicConsoleInfo, ICurrentConsoleService currentConsoleService)
		{
			bool flag = currentConsoleService.CurrentConsoleType?.IsAerobicMachine() ?? false;
			bool result = basicConsoleInfo.IsInRecoverableWorkout();
			bool result2 = basicConsoleInfo.IsInState(ConsoleState.CoolDown, ConsoleState.Workout) || (basicConsoleInfo.IsInState(ConsoleState.Paused, ConsoleState.PauseOverride) && basicConsoleInfo.RunningTime > 0);
			if (!flag)
			{
				return result;
			}
			return result2;
		}

