		public override async Task<IDictionary<string, string>> GetAdditionalConfig()
		{
			IDictionary<string, string> dictionary = await dashboardWebviewCalls.GetWebviewConfigPayload();
			dictionary["refreshType"] = refreshType.GetEnumMemberAttributeValue();
			return dictionary;
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			UpdateFeatureFlags();
			await feedbackService.CheckForUploadRequest().ConfigureAwait(continueOnCapturedContext: false);
			if (lockScreenHandler.IsScreenLocked)
			{
				IsLocked.Value = true;
				return;
			}
			IsLocked.Value = false;
			IsLoadingData.Value = false;
			IsNavigatingAway = false;
			IsManualButtonEnabled.Value = false;
			if (ShouldAllowManualWorkouts())
			{
				manualWorkoutsSub?.Dispose();
				manualWorkoutsSub = Observable.Interval(TimeSpan.FromMilliseconds(750.0)).Take(1).Subscribe(delegate
				{
					IsManualButtonEnabled.Value = true;
				});
			}
			PreLoadFeedAndLibraryWebviews();
			SetUpConsoleInitializedSub();
			if (currentConsoleService.IsBuiltinClub)
			{
				loggingOutSub?.Dispose();
				loggingOutSub = ifitApi.WhenLoggingOut.Subscribe(delegate
				{
					RemoveNeedsRefreshSub();
				});
			}
			Log.Trace(LogTag, $"OnViewShown() loadingData={IsLoadingData.Value}");
			IsLoadingData.Value = true;
			if (deviceInfo?.IsBuiltIn ?? false)
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj != null && obj.Console?.LatestBasicInfo?.IsInState(ConsoleState.SafetyKeyRemoved, ConsoleState.Demo) == true)
				{
					IDialogPresenter dialogPresenter = Mvx.Resolve<IDialogPresenter>();
					dialogPresenter.ShowDialog(typeof(SafetyKeyDialogViewModel).FullName, null, showSafely: true);
				}
			}
			if (currentConsoleService?.Console?.LatestBasicInfo == null)
			{
				consoleRecoverySub?.Dispose();
				consoleRecoverySub = currentConsoleService?.Console?.WhenStateChanged?.Take(1)?.Subscribe(delegate
				{
					DoCheckForInRecovery();
				}, delegate(Exception e)
				{
					Log.Error("Ble", $"Error observing WhenStateChanged event: {e}");
				});
				if (consoleRecoverySub == null)
				{
					consoleRecoverySub = currentConsoleService?.WhenConsoleChanged?.Take(1)?.Subscribe(delegate(IFitnessConsole console)
					{
						GetConsoleBeforeRecovery(console);
					}, delegate(Exception e)
					{
						Log.Error("Ble", $"Error observing WhenConsoleChanged event: {e}");
					});
				}
			}
			else if (DoCheckForInRecovery())
			{
				IsLoadingData.Value = false;
				return;
			}
			OnViewShownConditionalSetup();
			IsLoadingData.Value = false;
			dormantUpdateChecker.ShowUpdateDialogIfNeeded();
			if (currentConsoleService.IsBuiltinClub && Mvx.TryResolve<IIdleLogoutService>(out var service))
			{
				service.SetActive(active: true);
			}
			if (!base.WebviewHolder.IsReadyToCommunicate || HasCalledSetup)
			{
				await RefreshWebview().ConfigureAwait(continueOnCapturedContext: false);
			}
			else
			{
				TryInitialSetupWebview();
			}
			PromptUserToDeleteDemoModeAssets();
			Log.Trace(LogTag, $"OnViewShown done, loadingData={IsLoadingData.Value}");
			Log.Trace(LogTag, $"OnViewShown: IsTopBarVisible {base.IsTopBarVisible}");
		}

