		protected virtual void OnConsoleInitialized()
		{
			if (!consoleAlreadyInitialized)
			{
				consoleAlreadyInitialized = true;
				if (base.WebviewHolder.IsReadyToCommunicate)
				{
					TryInitialSetupWebview();
				}
			}
		}

		protected override async Task AddWebviewParams()
		{
			await base.AddWebviewParams();
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.BoltEnabled) || !featureFlagManager.IsFeatureEnabled(FeatureFlags.BoltEnabledDashboard))
			{
				return;
			}
			IDictionary<string, string> dictionary = await dashboardWebviewCalls.GetWebviewConfigPayload();
			if (dictionary["newData"].HasValue())
			{
				return;
			}
			HasCalledSetup = true;
			foreach (KeyValuePair<string, string> item in dictionary)
			{
				if (!item.Key.Equals("newData"))
				{
					base.WebViewQueryParams[item.Key] = item.Value;
				}
			}
			base.WebViewQueryParams["methodName"] = WebviewParamValues.SetUpApp;
		}

		protected override async Task HandleNeedsRefresh(IRefreshPayload payload)
		{
			await base.HandleNeedsRefresh(payload);
			switch (payload.Cause)
			{
			case RefreshCause.LostInternet:
			case RefreshCause.GainedInternet:
			case RefreshCause.ConsoleLost:
			case RefreshCause.AuthenticatedUserChanged:
				Log.Trace("DashboardViewModel", $"Got RefreshCause {payload.Cause}. Doing nothing.");
				break;
			case RefreshCause.EnvironmentChanged:
				HardResetNavigation();
				break;
			case RefreshCause.ConsoleConnected:
				await OnConsoleConnected().ConfigureAwait(continueOnCapturedContext: false);
				break;
			case RefreshCause.TokenRefreshed:
				ForceInitialSetupWebview();
				break;
			case RefreshCause.DayChanged:
				SetUpWebviewForDayChange();
				break;
			default:
				await RefreshWebview().ConfigureAwait(continueOnCapturedContext: false);
				break;
			}
		}

		protected void TryInitialSetupWebview()
		{
			if (!HasCalledSetup)
			{
				ForceInitialSetupWebview();
			}
		}

		protected void ForceInitialSetupWebview(RefreshType type = RefreshType.Unspecified)
		{
			HasCalledSetup = true;
			refreshType = type;
			WebviewInitialization();
		}

		protected async Task Refresh(RefreshType type)
		{
			if (await base.WebviewHolder.DidPayloadChange().ConfigureAwait(continueOnCapturedContext: false))
			{
				Log.Info("WebView", "Dashboard webview refresh called with new params - reinitializing");
				ForceInitialSetupWebview();
				return;
			}
			base.Dispatcher.RequestMainThreadAction(delegate
			{
				Bridge?.Call("refreshData", new Dictionary<string, string> { ["refreshType"] = type.GetEnumMemberAttributeValue() ?? string.Empty });
				Bridge?.Call("setOverlay", new Dictionary<string, string> { ["value"] = "false" });
			});
			webviewSettings.ReloadDashboard = false;
		}

