		private async Task ConnectAndRegisterConsole()
		{
			if (bleConsoleService != null)
			{
				await bleConsoleService.ConnectToCachedConsole();
			}
			if (Mvx.TryResolve<IFitnessConsoleRegisterService>(out var service))
			{
				await service.Register(currentConsoleService.Console, ifitApi);
			}
		}

		private void SetUpConsoleInitializedSub()
		{
			consoleInitializedSub?.Dispose();
			consoleInitializedSub = currentConsoleService?.Console?.WhenConsoleInitialized?.SubscribeWithErrorLogging(delegate
			{
				OnConsoleInitialized();
			});
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.Console?.Initialized == true)
			{
				consoleAlreadyInitialized = true;
			}
		}

		private void OnViewShownConditionalSetup()
		{
			if (localSettings != null)
			{
				localSettings.DashboardShownOnce = true;
				if (currentConsoleService.ActiveConsole != null)
				{
					currentConsoleService.ActiveConsole.StartKeyEnabled = true;
				}
			}
			if (shouldShowLogoutContinue)
			{
				if (Mvx.TryResolve<IDialogPresenter>(out var service))
				{
					service.ShowDialog<LogoutContinueDialogViewModel>();
				}
				shouldShowLogoutContinue = false;
			}
			if (promptForBleWhenShown)
			{
				ShowBleScanningDialog();
				promptForBleWhenShown = false;
			}
			if (!string.IsNullOrWhiteSpace(externalUrlToOpenWhenShown))
			{
				Log.Trace(LogTag, "Dashboard is showing an external URL: " + externalUrlToOpenWhenShown);
				browserService.OpenUrl(externalUrlToOpenWhenShown);
				externalUrlToOpenWhenShown = null;
			}
		}

		private bool DoCheckForInRecovery()
		{
			consoleRecoverySub?.Dispose();
			IBleConsoleService obj = bleConsoleService;
			if (obj != null && obj.ConnectionState == ConsoleConnectionState.Connected)
			{
				return CheckForInRecoverableWorkout();
			}
			if (deviceInfo.IsBuiltIn)
			{
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				if (activeConsole != null && activeConsole.Initialized && currentConsoleService.ActiveConsole.LatestBasicInfo.IsInRecoverableWorkout())
				{
					if (CheckShouldRecoverForBuiltIn(currentConsoleService.ActiveConsole.LatestBasicInfo, currentConsoleService))
					{
						return CheckForInRecoverableWorkout();
					}
					KillUnrecoverableWorkout();
				}
			}
			if (bleConsoleService != null && !deviceInfo.IsBuiltIn)
			{
				consoleRecoverySub?.Dispose();
				consoleRecoverySub = bleConsoleService.WhenConnectionStateChanged?.Where((ConsoleConnectionState x) => x == ConsoleConnectionState.Connected)?.Take(1)?.Timeout(TimeSpan.FromSeconds(10.0))?.SubscribeWithErrorLogging(delegate
				{
					CheckForInRecoverableWorkout();
				});
			}
			RegisterForStartButton();
			return false;
		}

		private void KillUnrecoverableWorkout()
		{
			stopWorkoutSub?.Dispose();
			stopWorkoutSub = Observable.Interval(TimeSpan.FromSeconds(5.0)).Take(3).SubscribeWithErrorLogging(delegate
			{
				Log.Trace("Workout", "Killing unrecoverable workout");
				if (Mvx.TryResolve<IWorkoutFacade>(out var service))
				{
					service.PauseWorkout();
					Task.Run((Func<Task>)service.EndWorkoutAsync);
				}
			});
			killedWorkoutDetectionSub?.Dispose();
			killedWorkoutDetectionSub = currentConsoleService.ActiveConsole?.WhenStateChanged?.Where((StateChange x) => x.ChangedToState(ConsoleState.WorkoutResults, ConsoleState.Idle))?.Take(1)?.Subscribe(delegate
			{
				stopWorkoutSub?.Dispose();
			}, delegate(Exception ex)
			{
				Log.Error(LogTag, $"Exception when trying to end workout: {ex.GetBaseException()}");
			});
		}

		private void GetConsoleBeforeRecovery(IFitnessConsole console)
		{
			consoleRecoverySub?.Dispose();
			if (console?.Initialized == true)
			{
				if (!DoCheckForInRecovery() && !consoleAlreadyInitialized)
				{
					OnConsoleInitialized();
				}
				return;
			}
			consoleRecoverySub?.Dispose();
			consoleRecoverySub = currentConsoleService.ActiveConsole?.WhenStateChanged?.Take(1)?.Subscribe(delegate
			{
				DoCheckForInRecovery();
			}, delegate(Exception e)
			{
				Log.Error("Ble", $"Error observing WhenStateChanged event: {e}");
			});
		}

		private async Task OnWorkoutTileTapped(TileTappedParams tappedParams)
		{
			await CreatePreworkoutWebviewLoadTimeEvent();
			if (tappedParams.IsNoWifiWorkout)
			{
				ShowViewModel<DashboardViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.DialogView<NoWifiDialogViewModel>(), (MvxRequestedBy)null);
			}
			else if (!(await CheckIfNotAvailableLoggedInAndBuiltIn(tappedParams)) && !IsNavigatingAway)
			{
				IsNavigatingAway = true;
				PreWorkoutViewModel.NavObject parameterValuesObject = new PreWorkoutViewModel.NavObject
				{
					WorkoutId = tappedParams.WorkoutId,
					ProgramId = tappedParams.ProgramId,
					WorkoutSource = WorkoutSource.Dashboard,
					DashboardIndex = tappedParams.DashboardIndex,
					ReferralSource = WorkoutSource.Dashboard.ToString()
				};
				ShowViewModel<PreWorkoutViewModel>(parameterValuesObject);
			}
		}

		private async Task StartProgram(TileTappedParams tappedParams)
		{
			if (!(await CheckIfNotAvailableLoggedInAndBuiltIn(tappedParams)) && !IsNavigatingAway)
			{
				IsNavigatingAway = true;
				DetailsViewModel.NavObject parameterValuesObject = new DetailsViewModel.NavObject
				{
					Id = tappedParams.ProgramId,
					UrlRouteName = "program",
					ReferralSource = WorkoutSource.Library.ToString()
				};
				ShowViewModel<DetailsViewModel>(parameterValuesObject);
			}
		}

		private async Task CreatePreworkoutWebviewLoadTimeEvent()
		{
			TimedEvent timedEvent = await EventService.Instance.CreateAsync("PreWorkout WebView Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null)
			{
				timedEvent.Properties["origin"] = "dashboard";
			}
		}

		private async Task OnLibraryTileTapped(TileTappedParams tappedParams, IDictionary<string, string> navigationParams = null)
		{
			if (!(await CheckIfNotAvailableLoggedInAndBuiltIn(tappedParams)) && !IsNavigatingAway)
			{
				IsNavigatingAway = true;
				await CreateLibraryLoadTimeEvent();
				if (!navigationParams.IsNullOrEmpty() && navigationParams.ContainsKey("entryPoint"))
				{
					LibraryAthenaeumViewModel.NavObject parameterValuesObject = new LibraryAthenaeumViewModel.NavObject
					{
						EntryPoint = navigationParams["entryPoint"]
					};
					ShowViewModel<LibraryAthenaeumViewModel>(parameterValuesObject);
				}
				else
				{
					ShowLibraryViewModel();
				}
			}
		}

		private async Task OnTrainerSelected(TileTappedParams tappedParams)
		{
			if (!(await CheckIfNotAvailableLoggedInAndBuiltIn(tappedParams)) && !IsNavigatingAway)
			{
				IsNavigatingAway = true;
				LibraryAthenaeumViewModel.NavObject parameterValuesObject = LibraryAthenaeumViewModel.NavObject.CreateTrainer(tappedParams.TrainerId);
				ShowViewModel<LibraryAthenaeumViewModel>(parameterValuesObject);
			}
		}

		private async Task CreateLibraryLoadTimeEvent()
		{
			TimedEvent timedEvent = await EventService.Instance.CreateAsync("Library Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null && !timedEvent.Properties.ContainsKey("origin"))
			{
				timedEvent.Properties["origin"] = "dashboard";
			}
		}

		private void CheckIfPremiumUserOrLoggedIn(Action action)
		{
			if (ifitApi.HasLoggedInUser)
			{
				action();
			}
			else if (!IsNavigatingAway)
			{
				IsNavigatingAway = true;
				ShowLoginViewModel(null, ShireViewParams.ChildView<JoinIfitViewModel>());
			}
		}

		private async Task<bool> CheckIfNotAvailableLoggedInAndBuiltIn(TileTappedParams tappedParams)
		{
			if (!tappedParams.IsAvailable && IsPremiumUser.Value == false)
			{
				await GetUserPremium(WebviewName);
				ForceInitialSetupWebview();
			}
			if (!tappedParams.IsAvailable && IsPremiumUser.Value == false)
			{
				if (IsNavigatingAway)
				{
					return true;
				}
				IsNavigatingAway = true;
				if (ifitApi.HasLoggedInUser)
				{
					if (deviceInfo?.IsBuiltIn ?? false)
					{
						ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ifit_subscription, Wolf.Core.Resources.AppStrings.membership_activation_message);
					}
					else
					{
						ShowMarketingViewModel(WebviewName);
					}
				}
				else
				{
					ShowLoginViewModel(null, ShireViewParams.ChildView<JoinIfitViewModel>());
				}
				return true;
			}
			return false;
		}

		private Task OnConsoleConnected()
		{
			if (currentConsoleService.ActiveConsole.IsNonconnectedConsole())
			{
				return Task.CompletedTask;
			}
			ForceInitialSetupWebview();
			return Task.CompletedTask;
		}

		public override void BuildBridge(IJavascriptBridge bridge)
		{
			if (connectivity?.IsConnected == true)
			{
				base.BuildBridge(bridge);
				bridge.ExposeTask("StartWorkout", OnWorkoutTileTapped);
				bridge.Expose("DrawMap", OnDrawMapTileTapped);
				bridge.Expose("Favorites", OnFavoritesTileTapped);
				bridge.ExposeTask("StartProgram", StartProgram);
				bridge.ExposeTask("Library", OnLibraryTileTapped);
				bridge.ExposeTask("Trainer", OnTrainerSelected);
				bridge.ExposeTask("RequestInitialization", RequestInitialization);
				bridge.Expose("HideLoadingAnimator", HideLoadingAnimator);
				bridge.Expose("HideModalitySelector", HideModalitySelector);
			}
		}

		public Task RequestInitialization(IDictionary<string, string> parameters)
		{
			Log.Trace("WebView", "The Dashboard webview reported it needs to be initialized, calling setupApp");
			ForceInitialSetupWebview();
			return Task.CompletedTask;
		}

		public void HideLoadingAnimator(IDictionary<string, string> parameters)
		{
			IsLoadingData.Value = false;
			TryInitialSetupWebview();
		}

		public void HideModalitySelector()
		{
			webviewHideModalitySelector = true;
			ShowModalitySelector.Value = featureFlagManager.IsFeatureEnabled(FeatureFlags.ShowModalitySelector) && !webviewHideModalitySelector;
		}

		public override async void OnWebviewStateChanged(object sender, WebViewState state)
		{
			base.OnWebviewStateChanged(sender, state);
			if (state == WebViewState.Loaded)
			{
				await OnWebViewLoaded().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public override void OnWebviewFinishedNavigating(object sender, EventArgs e)
		{
			TryInitialSetupWebview();
		}

		private async Task OnWebViewLoaded()
		{
			if (HasCalledSetup)
			{
				await RefreshWebview().ConfigureAwait(continueOnCapturedContext: false);
			}
			else
			{
				TryInitialSetupWebview();
			}
		}

		protected override void OnTimeToInteractive(IDictionary<string, string> args)
		{
			base.OnTimeToInteractive(args);
			Task.Run(async delegate
			{
				await BaseWebViewViewModel.LogEventKey("Dashboard WebView Screen Time");
			});
		}

		public virtual Task RefreshWebview()
		{
			WebviewHolder webviewHolder = base.WebviewHolder;
			if (webviewHolder == null || webviewHolder.WebView?.IsLoaded != true)
			{
				Log.Warn(LogTag, $"WebViewStoreObject is not loaded. Is WebViewStoreObject null? {base.WebviewHolder == null}. Is WebView null? {base.WebviewHolder?.WebView == null}");
				return Task.CompletedTask;
			}
			return Refresh(RefreshType.Unspecified);
		}

		private void SetUpWebviewForDayChange()
		{
			if (base.WebviewHolder.WebView.IsLoaded)
			{
				ForceInitialSetupWebview(RefreshType.Overnight);
			}
		}

		public override string GetUrlForViewSetup()
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.BoltEnabled) && featureFlagManager.IsFeatureEnabled(FeatureFlags.BoltEnabledDashboard))
			{
				return string.Empty;
			}
			return base.GetUrlForViewSetup();
		}

		public virtual void PreLoadFeedAndLibraryWebviews()
		{
			dashboardWebviewCalls.PreLoadFeedAndLibraryWebviews();
		}

		protected override void DoTryAgain()
		{
			base.DoTryAgain();
			webviewHolderFactory.WebviewHolderStore.Flush(Url);
			NavigateToDashboardViewModel();
		}

		public Task<string> GetData(Uri uri)
		{
			if (uri.Host == "refresh-type")
			{
				return Task.FromResult(refreshType.GetEnumMemberAttributeValue());
			}
			throw new KeyNotSupportedException("Dashboard didn't recognize key " + uri.OriginalString);
		}

		public string[] GetAllSupportedKeys()
		{
			return new string[1] { "refresh-type" };
		}

