	public interface IDashboardWebviewCalls
	{
		Task Preload();

		Task<IDictionary<string, string>> GetWebviewConfigPayload();

		void PreLoadFeedAndLibraryWebviews();
	}
	public class DashboardWebviewCalls : IDashboardWebviewCalls
	{
		public const int DashboardWebviewTTL = 14400;

		private const string WebviewMethodOldInitializeWebview = "setupApp";

		private readonly IIfitApiService ifitApi;

		private readonly IDataFetcher dataFetcher;

		private readonly IDeviceInformation deviceInfo;

		private readonly IConnectivity connectivityService;

		private readonly IWebviewHolderFactory webviewHolderFactory;

		private readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ICurrentConsoleService currentConsoleService;

		private bool isSettingUpWebview;

		private bool IsPhone => !IsTablet;

		private bool IsTablet => deviceInfo.IsTablet;

		private bool IsBuiltIn => deviceInfo.IsBuiltIn;

		private bool IsConnected => connectivityService.IsConnected;

		public DashboardWebviewCalls(IIfitApiService ifitApi, IDataFetcher dataFetcher, IDeviceInformation deviceInfo, IConnectivity connectivityService, IWebviewHolderFactory webviewHolderFactory, IMvxMainThreadDispatcher mainThreadDispatcher, IFeatureFlagManager featureFlagManager, ICurrentConsoleService currentConsoleService)
		{
			this.ifitApi = ifitApi;
			this.dataFetcher = dataFetcher;
			this.deviceInfo = deviceInfo;
			this.connectivityService = connectivityService;
			this.webviewHolderFactory = webviewHolderFactory;
			this.mainThreadDispatcher = mainThreadDispatcher;
			this.featureFlagManager = featureFlagManager;
			this.currentConsoleService = currentConsoleService;
		}

		public async Task Preload()
		{
			if (!IsBuiltIn || IsConnected)
			{
				string url = MainToolbarViewModel.GetWallEUrlWhenNeed(featureFlagManager, FeatureFlags.WallEDashboardUrl, FeatureFlags.WolfDashboardWebviewUrl);
				if (Mvx.TryResolve<IWebViewUrlParameterService>(out var service))
				{
					url = service.GenerateWebViewUrlWithParameters(url);
				}
				webviewHolderFactory.WebviewHolderStore.PreloadWebView(url, 14400, WebviewHolderType.Dashboard, GetWebviewConfigPayload);
			}
		}

		[Obsolete("The following preload call remains in order not to refactor dashboard all at once... Check the full comment.")]
		public void PreLoadFeedAndLibraryWebviews()
		{
			if (IsConnected)
			{
				if (IsPhone)
				{
					PreWorkoutWebviewViewModel.PreloadWebview();
				}
				dataFetcher.FetchConsoleWorkouts(deviceInfo.SoftwareNumber);
			}
		}

		public async Task<IDictionary<string, string>> GetWebviewConfigPayload()
		{
			User user = ifitApi.CurrentlyAuthenticatedUser;
			IWolfEnvironment environment = ifitApi.Environment as IWolfEnvironment;
			ConsoleType consoleType = currentConsoleService.Console?.ConsoleInfo?.MachineType ?? currentConsoleService.LastKnownConsoleType;
			Dictionary<string, string> configPayload = new Dictionary<string, string>();
			Dictionary<string, string> dictionary = configPayload;
			dictionary["bearerToken"] = await ifitApi.GetToken();
			configPayload["clientId"] = environment.DashboardClientId;
			configPayload["clientSecret"] = environment.DashboardClientSecret;
			configPayload["equipmentType"] = consoleType.GetWotdType().ToString().ToLower();
			configPayload["userType"] = UserTypeText(user);
			configPayload["deviceName"] = deviceInfo.DeviceName;
			configPayload[JavascriptBridge.MethodToSetConfigs] = "setupApp";
			return configPayload;
		}

		private string UserTypeText(User user)
		{
			string empty = string.Empty;
			if (user == null)
			{
				return "anonymous";
			}
			if (user.Premium == true)
			{
				return "premium";
			}
			return "free";
		}
	}
	public class TileTappedParams
	{
		private const string WorkoutIdKey = "workoutId";

		private const string ProgramIdKey = "programId";

		private const string TrainerIdKey = "trainerId";

		private const string DescriptionKey = "description";

		private const string DashboardIndexKey = "tileIndex";

		private const string IsAvailableKey = "isAvailable";

		private const string IsNoWifiWorkoutKey = "isNoWifiWorkout";

		public string WorkoutId { get; set; }

		public string ProgramId { get; set; }

		public string TrainerId { get; set; }

		public string Description { get; set; }

		public int DashboardIndex { get; set; }

		public bool IsAvailable { get; set; }

		public bool IsNoWifiWorkout { get; set; }

		public DashboardTileModel.TileType TileType { get; set; }

		public TileTappedParams()
		{
		}

		public TileTappedParams(IDictionary<string, string> tileParams, DashboardTileModel.TileType tileType)
		{
			WorkoutId = (tileParams.ContainsKey("workoutId") ? tileParams["workoutId"] : "");
			ProgramId = (tileParams.ContainsKey("programId") ? tileParams["programId"] : "");
			TrainerId = (tileParams.ContainsKey("trainerId") ? tileParams["trainerId"] : "");
			Description = (tileParams.ContainsKey("description") ? tileParams["description"] : "");
			DashboardIndex = (tileParams.ContainsKey("tileIndex") ? int.Parse(tileParams["tileIndex"]) : (-1));
			IsAvailable = tileParams.ContainsKey("isAvailable") && bool.Parse(tileParams["isAvailable"]);
			IsNoWifiWorkout = tileParams.ContainsKey("isNoWifiWorkout") && bool.Parse(tileParams["isNoWifiWorkout"]);
			TileType = tileType;
		}
	}
