namespace Wolf.Core.ViewModels.Dashboard.NoWifi
{
	public class EmbeddedNoWifiDashboardViewModel : MainToolbarViewModel
	{
		public readonly INC<bool> IsConnecting = new NC<bool>();

		public readonly INC<string> StatusText = new NC<string>();

		public readonly INC<string> ErrorCodeText = new NC<string>();

		private readonly INoWifiDashboardService noWifiDashboardService;

		private new readonly IDialogPresenter dialogPresenter;

		private readonly ILockScreenHandler lockScreenHandler;

		private IDisposable attemptingToConnectSub;

		private IDisposable successfullyConnectedSub;

		private IDisposable failedToConnectSub;

		private ErrorCode errorCode;

		private bool hasSuccessfullyConnected;

		public override string LogTag => "NoWifiDashboard";

		protected override string Url => MainToolbarViewModel.GetWallEUrlWhenNeed(featureFlagManager, FeatureFlags.WallEDashboardUrl, FeatureFlags.WolfDashboardWebviewUrl);

		public string InternetText
		{
			get
			{
				if (!ifitApi.HasLoggedInUser)
				{
					return Wolf.Core.Resources.AppStrings.internet_connection_error_embedded_not_logged_in;
				}
				return Wolf.Core.Resources.AppStrings.internet_connection_error_embedded_logged_in;
			}
		}

		public static string TryAgainText => Wolf.Core.Resources.AppStrings.internet_try_again;

		public static string CheckSettingsText => Shire.Core.Resources.AppStrings.internet_check_settings.ToUpper();

		public new IMvxAsyncCommand TryAgainClicked => new MvxAsyncCommand(DoTryAgainClicked);

		public IMvxCommand SettingsClicked => new MvxCommand(DoSettingClicked);

		private bool ShouldShowSafetyKey
		{
			get
			{
				IDeviceInformation deviceInformation = deviceInfo;
				if (deviceInformation != null && deviceInformation.IsBuiltIn)
				{
					ICurrentConsoleService obj = currentConsoleService;
					if (obj == null)
					{
						return false;
					}
					return obj.ActiveConsole?.LatestBasicInfo?.IsInState(ConsoleState.SafetyKeyRemoved, ConsoleState.Demo) == true;
				}
				return false;
			}
		}

		private bool ShouldShowConsoleError
		{
			get
			{
				IDeviceInformation deviceInformation = deviceInfo;
				if (deviceInformation != null && deviceInformation.IsBuiltIn)
				{
					ICurrentConsoleService obj = currentConsoleService;
					if (obj == null)
					{
						return false;
					}
					return obj.ActiveConsole?.LatestBasicInfo?.IsInState(ConsoleState.Error) == true;
				}
				return false;
			}
		}

		public EmbeddedNoWifiDashboardViewModel(INoWifiDashboardService noWifiDashboardService, IDialogPresenter dialogPresenter, ILocalSettings settings, IFeatureFlagManager featureFlagManager, IIfitApiService ifitApi, IFailedUploadMonitor failedUploadMonitor, IModalityChangeService modalityChangeService, IWebViewUrlParameterService webViewUrlParameterService, IUpgradeService upgradeService, IWebviewSettings webviewSettings, ICurrentConsoleService currentConsoleService, ILockScreenHandler lockScreenHandler)
			: base(settings, featureFlagManager, ToolbarMode.Dashboard, ifitApi, failedUploadMonitor, modalityChangeService, webViewUrlParameterService, upgradeService, webviewSettings, currentConsoleService)
		{
			try
			{
				this.noWifiDashboardService = noWifiDashboardService;
				this.dialogPresenter = dialogPresenter;
				this.lockScreenHandler = lockScreenHandler;
				Log.Trace(LogTag, $"Constructor: IsTopBarVisible {base.IsTopBarVisible}");
				base.ParentType = GetType();
				IsManualButtonEnabled.Value = false;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void Init(NoWifiScreenNavObject nav)
		{
			Log.Trace(LogTag, $"Before init: IsTopBarVisible {base.IsTopBarVisible}");
			errorCode = nav.ErrorCode;
			Log.Trace(LogTag, $"After init: IsTopBarVisible {base.IsTopBarVisible}");
		}

		public override async Task OnViewShown()
		{
			Log.Trace(LogTag, $"Before OnViewShown: IsTopBarVisible {base.IsTopBarVisible}");
			await base.OnViewShown();
			IsConnecting.Value = false;
			StatusText.Value = string.Empty;
			ErrorCodeText.Value = ((errorCode == (ErrorCode)0) ? ErrorCode.WifiNoInternet.HumanReadable() : errorCode.HumanReadable());
			if (ShouldShowSafetyKey)
			{
				dialogPresenter.ShowDialog<SafetyKeyDialogViewModel>(null, showSafely: true);
			}
			if (lockScreenHandler.IsScreenLocked)
			{
				lockScreenHandler.NavigateToLockScreen();
			}
			if (ShouldShowConsoleError)
			{
				dialogPresenter.ShowDialog<ConsoleErrorDialogViewModel>(null, showSafely: true);
			}
			noWifiDashboardService.ResetState();
			SetUpConnectionSubs();
			if ((currentConsoleService?.IsBuiltinClub ?? false) && Mvx.TryResolve<IIdleLogoutService>(out var service))
			{
				service.SetActive(active: true);
			}
			await analytics.ErrorCodeDisplayed("No Wifi Dashboard", InternetText, ErrorCodeText.Value);
			if (ShouldAllowManualWorkouts())
			{
				Observable.Interval(TimeSpan.FromMilliseconds(750.0)).Take(1).Subscribe(delegate
				{
					IsManualButtonEnabled.Value = true;
				});
			}
			Log.Trace(LogTag, "OnViewShown done");
			Log.Trace(LogTag, $"After OnViewShown: IsTopBarVisible {base.IsTopBarVisible}");
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			if (base.StartWorkoutService != null && !base.StartWorkoutService.StartingWorkout && currentConsoleService?.ActiveConsole != null)
			{
				currentConsoleService.ActiveConsole.StartKeyEnabled = false;
			}
		}

		public override void OnWebviewErrorLoading(object sender, EventArgs e)
		{
		}

		private void SetUpConnectionSubs()
		{
			attemptingToConnectSub = noWifiDashboardService?.WhenAttemptingToConnect.SubscribeWithErrorLogging(AttemptingToConnect);
			successfullyConnectedSub = noWifiDashboardService?.WhenSuccessfullyConnected.SubscribeWithErrorLogging(SuccessfullyConnected);
			failedToConnectSub = noWifiDashboardService?.WhenFailedToConnect.SubscribeWithErrorLogging(FailedToConnect);
		}

		private void AttemptingToConnect(string message)
		{
			Log.Trace("EmbeddedNoWifiDashboardViewModel", "Attempting to connect.");
			IsConnecting.Value = true;
			StatusText.Value = message;
		}

		private void SuccessfullyConnected(string message)
		{
			if (hasSuccessfullyConnected)
			{
				Log.Trace("EmbeddedNoWifiDashboardViewModel", "Successfully connected, but we've already successfully connected. Doing nothing.");
				return;
			}
			Log.Trace("EmbeddedNoWifiDashboardViewModel", "Successfully connected. Navigating to dashboard.");
			hasSuccessfullyConnected = true;
			StatusText.Value = message;
			ILockScreenHandler obj = lockScreenHandler;
			if (obj == null || !obj.NavigateToLockScreenWhenGainConnection(DoClose))
			{
				ShowViewModel<DashboardViewModel>();
				DoClose();
			}
		}

		private void FailedToConnect(string message)
		{
			Log.Trace("EmbeddedNoWifiDashboardViewModel", "Failed to connect.");
			IsConnecting.Value = false;
			StatusText.Value = message;
		}

		private async Task DoTryAgainClicked()
		{
			Log.Trace("EmbeddedNoWifiDashboardViewModel", "TryAgainClicked.");
			IsConnecting.Value = true;
			await Task.Delay(1500).ConfigureAwait(continueOnCapturedContext: false);
			await noWifiDashboardService.TryAgain().ConfigureAwait(continueOnCapturedContext: false);
		}

		private void DoSettingClicked()
		{
			wifiService.TurnWifiOn();
			ShowViewModel<SettingsWifiViewModel>();
		}

