namespace Wolf.Core.ViewModels.ConsoleError
{
	public class ConsoleErrorDialogViewModel : SimpleConfirmationDialogViewModel
	{
		private readonly IIdleLogoutService idleLogoutService;

		protected IDisposable timeoutSub;

		protected IDisposable consoleStateExitedSub;

		public ConsoleErrorDialogViewModel(ILocalSettings localSettings, IIdleLogoutService idleLogoutService, IWolfAnalytics wolfAnalytics)
			: base(localSettings, wolfAnalytics)
		{
			try
			{
				this.idleLogoutService = idleLogoutService;
				TitleText.Value = Wolf.Core.Resources.AppStrings.console_error_title;
				SubtitleText.Value = Wolf.Core.Resources.AppStrings.console_error_message.Replace("{timeRemaining}", ValueFormatters.SecondsFormatter.BlankValue);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			idleLogoutService?.SetActive(active: false);
			ConsoleState? consoleState = currentConsoleService?.Console?.LatestBasicInfo?.CurrentState;
			if (consoleState.HasValue && consoleState.Value != ConsoleState.Error)
			{
				ConsoleStateCleared();
				return;
			}
			consoleStateExitedSub?.Dispose();
			consoleStateExitedSub = currentConsoleService?.Console?.WhenStateChanged.Where((StateChange x) => !x.ChangedToState(ConsoleState.Error)).Take(1).Subscribe(delegate
			{
				ConsoleStateCleared();
			});
			Task<IConsoleError> task = currentConsoleService?.Console?.GetConsoleErrorAsync();
			if (task != null && await task is ITimedError timedError)
			{
				timeoutSub?.Dispose();
				timeoutSub = timedError.Timeout.Subscribe(delegate(TimeSpan timeout)
				{
					SubtitleText.Value = Wolf.Core.Resources.AppStrings.console_error_message.Replace("{timeRemaining}", ValueFormatters.SecondsFormatter.Format(timeout.TotalSeconds));
				}, HandleException);
			}
		}

		protected virtual void HandleException(Exception ex)
		{
			ShowViewModelThenClose<PowerCycleViewModel>();
		}

		protected virtual void ConsoleStateCleared()
		{
			DoClose();
		}

		protected override void DoClose()
		{
			idleLogoutService?.SetActive(active: true);
			base.DoClose();
		}

		public override void Dispose()
		{
			((BaseViewModel)this).Dispose();
			timeoutSub?.Dispose();
			timeoutSub = null;
			consoleStateExitedSub?.Dispose();
			consoleStateExitedSub = null;
			UnregisterChangeHandlers();
		}

