		{
			if (Mvx.TryResolve<IDialogPresenter>(out var service) && !service.IsDialogShown<BluetoothDevicePickerViewModel>())
			{
				service.ShowDialog<BluetoothDevicePickerViewModel>(null, showSafely: true, new BluetoothDevicePickerOptions(source));
