		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			if (deviceFoundSub == null)
			{
				deviceFoundSub = ConnectionHelper.OnDeviceFound.SubscribeWithErrorLogging(OnFoundHeadphoneDevice);
			}
			ConnectionHelper.ScanEnded -= OnScanEnded;
			ConnectionHelper.ScanEnded += OnScanEnded;
			await ConnectionHelper.Start().ConfigureAwait(continueOnCapturedContext: false);
			onFoundDeviceSub?.Dispose();
			onFoundDeviceSub = heartRateScanner.OnFoundDevice.Subscribe(OnFoundHeartRateDevice);
			heartRateHelper.ReconnectOnLostConnection = false;
			wasScanningForHRMOnViewShown = heartRateHelper.IsScanning;
			heartRateHelper.StopScanning();
			if (heartRateHelper.CurrentlyConnectedDevice != null)
			{
				OnFoundHeartRateDevice(heartRateHelper.CurrentlyConnectedDevice);
			}
			BeginScan();
		}

		private void BeginScan()
		{
			ConnectionHelper.BeginScan();
			heartRateScanner.BeginScanning(TimeSpan.MaxValue);
		}

		private void OnFoundHeadphoneDevice(IHeadphone device)
		{
			HeadphoneBasePickerItemViewModel headphoneBasePickerItemViewModel = new HeadphoneBasePickerItemViewModel(ConnectionHelper, device);
			foundDevices.OnNext(headphoneBasePickerItemViewModel);
			headphonesFoundInLatestScan.Add(headphoneBasePickerItemViewModel.Id);
		}

		private void OnFoundHeartRateDevice(IBleDevice device)
		{
			HeartRatePickerItemViewModel heartRatePickerItemViewModel = new HeartRatePickerItemViewModel(device);
			foundDevices.OnNext(heartRatePickerItemViewModel);
			hrmFoundInLatestScan.Add(heartRatePickerItemViewModel.Id);
		}

		private void DelayDeviceReceived(BasePickerItemViewModel viewModel)
		{
			InvokeOnMainThread(delegate
			{
				if (PickerViewModelExtensions.DoesDeviceExist(Devices, OtherAccessories, viewModel.Id))
				{
					viewModel.Dispose();
				}
				else
				{
					viewModel.State.Changed -= SortDevices;
					viewModel.State.Changed += SortDevices;
					if (viewModel.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected || viewModel.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
					{
						Devices.Add(viewModel);
					}
					else
					{
						OtherAccessories.Add(viewModel);
					}
				}
			});
		}

		private void OnScanEnded(object sender, EventArgs args)
		{
			RemoveDevices(headphonesFoundInLatestScan, typeof(HeadphoneBasePickerItemViewModel));
		}

		private void RemoveDevices(ConcurrentBag<Guid> scannedDevices, Type type)
		{
			InvokeOnMainThread(delegate
			{
				RemoveDevices(Devices, scannedDevices, type);
				RemoveDevices(OtherAccessories, scannedDevices, type);
			});
		}

		private void RemoveDevices(ImprovedObservableCollection<BasePickerItemViewModel> list, ConcurrentBag<Guid> scannedDevices, Type type)
		{
			List<BasePickerItemViewModel> list2 = list.NeedRemoved(scannedDevices, type);
			foreach (BasePickerItemViewModel item in list2)
			{
				item.State.Changed -= SortDevices;
				list.Remove(item);
				item.Dispose();
			}
			scannedDevices.Clear();
		}

		private async Task DoHandleConnection(BasePickerItemViewModel model)
		{
			if (!model.Enabled.Value)
			{
				return;
			}
			if (model is HeadphoneBasePickerItemViewModel)
			{
				await DoHeadphoneConnection(model);
				return;
			}
			if (!(model is IHeartRatePickerItemViewModel))
			{
				throw new Exception($"This view model type is not implemented: [{model.GetType()}]");
			}
			await DoHeartRateMonitorConnection(model);
		}

		private async Task DoHeadphoneConnection(BasePickerItemViewModel model)
		{
			IHeadphone device = ((HeadphoneBasePickerItemViewModel)model).Device;
			HeadphoneDeviceState state = ConnectionHelper.GetState(device);
			switch (state)
			{
			case HeadphoneDeviceState.Connecting:
				Log.Trace("Ble", "Already connecting to headphone device " + device?.Name);
				break;
			case HeadphoneDeviceState.Disconnected:
				Log.Trace("Ble", "Connecting to headphone device " + device?.Name);
				ConnectionHelper.EndScan();
				try
				{
					await ConnectionHelper.BondWithDevice(device).ConfigureAwait(continueOnCapturedContext: true);
					await persistentBluetoothDevices.SaveDevice(model.Id);
				}
				catch (Exception exception)
				{
					Log.Error("Ble", "Failed to bond with headphone device through the BluetoothDevicePickerViewModel", exception);
					wolfAnalytics.HandleConnectToHeadphoneError(exception);
				}
				if (deviceFoundSub != null)
				{
					BeginScan();
				}
				break;
			case HeadphoneDeviceState.Connected:
				Log.Trace("Ble", "Disconnecting from headphone device " + device?.Name);
				await persistentBluetoothDevices.DeleteDevice(model.Id);
				await ConnectionHelper.UnbondWithDevice(device).ConfigureAwait(continueOnCapturedContext: true);
				break;
			default:
				Log.Error("Ble", $"Unknown headphone state {state}");
				break;
			}
		}

		private async Task DoHeartRateMonitorConnection(BasePickerItemViewModel model)
		{
			IHeartRatePickerItemViewModel heartRatePickerItemViewModel = (IHeartRatePickerItemViewModel)model;
			if (model.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected)
			{
				Log.Trace("Ble", "Disconnecting to HRM device " + model.Name);
				await heartRatePickerItemViewModel.ForceDisconnect();
				await heartRateHelper.RemoveBond();
				heartRateHelper.ForceHeartRateDisconnect();
				await persistentBluetoothDevices.DeleteBondedHrm(model.Id);
				return;
			}
			if (model.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
			{
				Log.Trace("Ble", "Already connecting to HRM device " + model.Name);
				return;
			}
			Log.Trace("Ble", "Connecting to HRM device " + model.Name);
			IHeartRateConnection heartRateConnection = await heartRatePickerItemViewModel.CreateConnection();
			if (heartRateConnection != null && heartRateConnection.Initialized && heartRateConnection != null && heartRateConnection.Device?.State == Sindarin.Core.Ble.Connection.DeviceState.Connected)
			{
				heartRateHelper.Manage(heartRateConnection);
				await persistentBluetoothDevices.SaveBondedHrm(model.Id);
			}
			else
			{
				heartRateConnection?.Dispose();
			}
		}

		private void SortDevices(object sender, EventArgs e)
		{
			InvokeOnMainThread(delegate
			{
				OtherAccessories.MoveTo(Devices, (BasePickerItemViewModel x) => x.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected || x.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting);
				Devices.MoveTo(OtherAccessories, (BasePickerItemViewModel x) => x.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Disconnected || x.State.Value == Sindarin.Core.Ble.Connection.DeviceState.LostConnection);
				Devices.SortDevices();
				OtherAccessories.SortDevices();
				PickerViewModelExtensions.EnableDisableOthers(Devices, OtherAccessories);
			});
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				CleanUp();
				base.Dispose();
				UnregisterChangeHandlers();
			}
		}

		private void CleanUp()
		{
			deviceFoundSub?.Dispose();
			deviceFoundSub = null;
			foundDevices?.Dispose();
			addFoundDevicesTimerSub?.Dispose();
			addFoundDevicesTimerSub = null;
			ConnectionHelper.ScanEnded -= OnScanEnded;
			ConnectionHelper.EndScan();
			ConnectionHelper.Stop();
			Devices.ExcludingNulls().DoForEach(delegate(BasePickerItemViewModel d)
			{
				d.State.Changed -= SortDevices;
				d.Dispose();
			});
			OtherAccessories.ExcludingNulls().DoForEach(delegate(BasePickerItemViewModel d)
			{
				d.State.Changed -= SortDevices;
				d.Dispose();
			});
			onFoundDeviceSub?.Dispose();
			onFoundDeviceSub = null;
			heartRateScanner?.StopScanning();
			heartRateHelper.ReconnectOnLostConnection = true;
			if (wasScanningForHRMOnViewShown && !heartRateHelper.IsConnected)
			{
				heartRateHelper.ScanAndConnectToHeartRateDevice();
			}
			InvokeOnMainThread(delegate
			{
				Devices.Clear();
				OtherAccessories.Clear();
			});
		}

