	public static class PickerViewModelExtensions
	{
		public static List<BasePickerItemViewModel> NeedRemoved(this IEnumerable<BasePickerItemViewModel> list, IEnumerable<Guid> scannedDevices, Type type)
		{
			return list.Where((BasePickerItemViewModel x) => x.IsDisconnected && !scannedDevices.Contains(x.Id) && x.GetType() == type).ToList();
		}

		public static bool DoesDeviceExist(IEnumerable<BasePickerItemViewModel> list1, IEnumerable<BasePickerItemViewModel> list2, Guid id)
		{
			if (!list1.Any((BasePickerItemViewModel x) => x.Id == id))
			{
				return list2.Any((BasePickerItemViewModel x) => x.Id == id);
			}
			return true;
		}

		public static void MoveTo(this ImprovedObservableCollection<BasePickerItemViewModel> source, ImprovedObservableCollection<BasePickerItemViewModel> dest, Func<BasePickerItemViewModel, bool> comparison)
		{
			List<BasePickerItemViewModel> list = source.Where(comparison).ToList();
			foreach (BasePickerItemViewModel item in list)
			{
				source.Remove(item);
				dest.Add(item);
			}
		}

		public static void SortDevices(this ImprovedObservableCollection<BasePickerItemViewModel> devices)
		{
			List<BasePickerItemViewModel> list = devices.ToList();
			list.Sort(delegate(BasePickerItemViewModel a, BasePickerItemViewModel b)
			{
				if (a.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected)
				{
					if (b.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected)
					{
						return 0;
					}
					return -1;
				}
				if (b.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected)
				{
					return 1;
				}
				if (a.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
				{
					if (b.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
					{
						return 0;
					}
					return -1;
				}
				if (b.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
				{
					return 1;
				}
				if (a.Rssi > b.Rssi)
				{
					return -1;
				}
				return (a.Rssi < b.Rssi) ? 1 : 0;
			});
			devices.ReplaceItems(list);
		}

		public static void EnableDisableOthers(IEnumerable<BasePickerItemViewModel> devices, IEnumerable<BasePickerItemViewModel> others)
		{
			bool value = !devices.Any((BasePickerItemViewModel x) => x.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting) && !others.Any((BasePickerItemViewModel x) => x.State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting);
			foreach (BasePickerItemViewModel other in others)
			{
				other.Enabled.Value = value;
			}
			foreach (BasePickerItemViewModel device in devices)
			{
				device.Enabled.Value = true;
			}
		}
	}
}
namespace Wolf.Core.ViewModels.BluetoothDevicePicker.Picker.Model
{
	public enum PickerIconType
	{
		HeartRateConnected,
		HeartRateOthers,
		HeartRateDisabled,
		HeadphoneConnected,
		HeadphoneOthers,
		HeadphoneDisabled
	}
	public abstract class BasePickerItemViewModel : MvxViewModel, IDisposable, ICloneable
	{
		private bool isDisposed;

		public readonly INC<PickerIconType> Icon = new NC<PickerIconType>();

		public readonly INC<Sindarin.Core.Ble.Connection.DeviceState> State = new NC<Sindarin.Core.Ble.Connection.DeviceState>(Sindarin.Core.Ble.Connection.DeviceState.Disconnected);

		public readonly INC<bool> Enabled = new NC<bool>();

		public abstract Guid Id { get; }

		public abstract int Rssi { get; }

		public abstract string Name { get; }

		public abstract bool IsDisconnected { get; }

		protected BasePickerItemViewModel()
		{
			Enabled.Value = true;
			State.Changed -= OnStateChanged;
			State.Changed += OnStateChanged;
			Enabled.Changed -= OnStateChanged;
			Enabled.Changed += OnStateChanged;
		}

		public virtual void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					State.Changed -= OnStateChanged;
					Enabled.Changed -= OnStateChanged;
				}
				isDisposed = true;
			}
		}

		protected abstract void OnStateChanged(object obj, EventArgs args);

		public abstract object Clone();
	}
	public class HeadphoneBasePickerItemViewModel : BasePickerItemViewModel
	{
		private readonly HeadphoneConnectionHelperBase connectionHelper;

		private IDisposable stateChangedSub;

		private bool isDisposed;

		public IHeadphone Device { get; }

		public override Guid Id => Device.Id;

		public override int Rssi => Device.Rssi;

		public override string Name { get; }

		public override bool IsDisconnected
		{
			get
			{
				if (CurrentBondState == BondState.Unbonded)
				{
					return State.Value == Sindarin.Core.Ble.Connection.DeviceState.Disconnected;
				}
				return false;
			}
		}

		private BondState CurrentBondState => connectionHelper.GetCurrentBondState(Device);

		public HeadphoneBasePickerItemViewModel(HeadphoneConnectionHelperBase connectionHelper, IHeadphone device)
		{
			this.connectionHelper = connectionHelper;
			Device = device;
			Name = device.Name;
			UpdateState();
			UpdateIcon();
			stateChangedSub = connectionHelper.OnStateChanged.Where((Guid id) => id == Id).SubscribeWithErrorLogging(delegate
			{
				UpdateState();
			});
		}

		protected override void OnStateChanged(object obj, EventArgs args)
		{
			UpdateIcon();
		}

		private void UpdateIcon()
		{
			if (!Enabled.Value)
			{
				Icon.Value = PickerIconType.HeadphoneDisabled;
			}
			else if (State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected || State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
			{
				Icon.Value = PickerIconType.HeadphoneConnected;
			}
			else
			{
				Icon.Value = PickerIconType.HeadphoneOthers;
			}
		}

		private void UpdateState()
		{
			State.Value = connectionHelper.GetState(Device).ToDeviceState();
		}

		public override void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected override void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					stateChangedSub?.Dispose();
					stateChangedSub = null;
				}
				if (State.Value != Sindarin.Core.Ble.Connection.DeviceState.Connected && Device is IDisposable disposable)
				{
					disposable.Dispose();
				}
				base.Dispose(disposing);
				isDisposed = true;
			}
		}

		public override object Clone()
		{
			return new HeadphoneBasePickerItemViewModel(connectionHelper, Device);
		}
	}
	public interface IHeartRatePickerItemViewModel
	{
		IBleDevice Device { get; }

		Task<IHeartRateConnection> CreateConnection();

		Task ForceDisconnect();
	}
	public class HeartRatePickerItemViewModel : BasePickerItemViewModel, IHeartRatePickerItemViewModel
	{
		private IDisposable whenDeviceChangedSub;

		private readonly SemaphoreSlim deviceStateLock = new SemaphoreSlim(1, 1);

		public IBleDevice Device { get; private set; }

		public override Guid Id => Device.Id;

		public override int Rssi => Device.Rssi;

		public override string Name => Device.Name;

		public override bool IsDisconnected
		{
			get
			{
				if (Device.State != Sindarin.Core.Ble.Connection.DeviceState.Disconnected)
				{
					return Device.State == Sindarin.Core.Ble.Connection.DeviceState.LostConnection;
				}
				return true;
			}
		}

		protected virtual TimeSpan ConnectionTimeout => HeartRateHelper.DefaultConnectionInitTimeout;

		public HeartRatePickerItemViewModel(IBleDevice device)
		{
			Device = device;
			State.Value = Device.State;
			UpdateIcon();
			whenDeviceChangedSub = Device.WhenStateChanged.SubscribeAsync((Sindarin.Core.Ble.Connection.DeviceState _) => HandleDeviceStateChangedAsync());
		}

		protected override void OnStateChanged(object obj, EventArgs args)
		{
			UpdateIcon();
		}

		private void UpdateIcon()
		{
			InvokeOnMainThread(delegate
			{
				if (!Enabled.Value)
				{
					Icon.Value = PickerIconType.HeartRateDisabled;
				}
				else if (State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connected || State.Value == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
				{
					Icon.Value = PickerIconType.HeartRateConnected;
				}
				else
				{
					Icon.Value = PickerIconType.HeartRateOthers;
				}
			});
		}

		private async Task HandleDeviceStateChangedAsync()
		{
			await deviceStateLock.WaitAsync();
			try
			{
				if (Device.State == Sindarin.Core.Ble.Connection.DeviceState.Disconnected || Device.State == Sindarin.Core.Ble.Connection.DeviceState.LostConnection)
				{
					HandleDisconnect();
				}
				else
				{
					State.Value = Device.State;
				}
			}
			finally
			{
				deviceStateLock.Release();
			}
		}

		public Task<IHeartRateConnection> CreateConnection()
		{
			return CreateConnectionLocked();
		}

		private async Task<IHeartRateConnection> CreateConnectionLocked()
		{
			await deviceStateLock.WaitAsync();
			try
			{
				return await CreateConnectionAsyncInternal(1);
			}
			finally
			{
				deviceStateLock.Release();
			}
		}

		private async Task<IHeartRateConnection> CreateConnectionAsyncInternal(int retries = 0)
		{
			HandleDisconnect();
			State.Value = Sindarin.Core.Ble.Connection.DeviceState.Connecting;
			HeartRateConnection connection = new HeartRateConnection(Device, null);
			bool initialized = connection.Initialized;
			try
			{
				if (!initialized)
				{
					initialized = await connection.WhenInitialized.Timeout(ConnectionTimeout).Take(1).ToTask();
				}
			}
			catch (TimeoutException exception)
			{
				Log.Trace("HeartRatePickerItemViewModel", "Initializing heart rate connection timed out", exception);
			}
			if (!initialized)
			{
				connection.Dispose();
				if (retries > 0)
				{
					HeartRatePickerItemViewModel heartRatePickerItemViewModel = this;
					int num = retries - 1;
					retries = num;
					return await heartRatePickerItemViewModel.CreateConnectionAsyncInternal(num);
				}
				State.Value = Sindarin.Core.Ble.Connection.DeviceState.Disconnected;
				return null;
			}
			State.Value = Sindarin.Core.Ble.Connection.DeviceState.Connected;
			whenDeviceChangedSub?.Dispose();
			whenDeviceChangedSub = Device.WhenStateChanged.SubscribeAsyncWithErrorLogging((Sindarin.Core.Ble.Connection.DeviceState _) => HandleDeviceStateChangedAsync());
			Log.Trace("HeartRatePickerItemViewModel", $"Successfully created HRM connection (device id: {Device.Id})");
			return connection;
		}

		public Task ForceDisconnect()
		{
			return ForceDisconnectLocked();
		}

		private async Task ForceDisconnectLocked()
		{
			await deviceStateLock.WaitAsync();
			try
			{
				HandleDisconnect();
			}
			finally
			{
				deviceStateLock.Release();
			}
		}

		private void HandleDisconnect()
		{
			whenDeviceChangedSub?.Dispose();
			Device.Disconnect();
			Device.Dispose();
			Device = (IBleDevice)Device.Clone();
			State.Value = Sindarin.Core.Ble.Connection.DeviceState.Disconnected;
		}

		public override void Dispose()
		{
			base.Dispose();
			whenDeviceChangedSub?.Dispose();
			if (IsDisconnected)
			{
				Device?.Dispose();
			}
		}

		public override object Clone()
		{
			HeartRatePickerItemViewModel heartRatePickerItemViewModel = new HeartRatePickerItemViewModel(Device);
			heartRatePickerItemViewModel.State.Value = State.Value;
			return heartRatePickerItemViewModel;
		}
	}
	public static class PickerItemViewModelExtensions
	{
		public static Sindarin.Core.Ble.Connection.DeviceState ToDeviceState(this HeadphoneDeviceState value)
		{
			return value switch
			{
				HeadphoneDeviceState.Connected => Sindarin.Core.Ble.Connection.DeviceState.Connected, 
				HeadphoneDeviceState.Connecting => Sindarin.Core.Ble.Connection.DeviceState.Connecting, 
				HeadphoneDeviceState.Disconnected => Sindarin.Core.Ble.Connection.DeviceState.Disconnected, 
				_ => throw new ArgumentOutOfRangeException("value", value, null), 
			};
		}
	}
}
namespace Wolf.Core.ViewModels.Ble
{
	public abstract class BaseBleViewModel : AutoUpdateDialogViewModel
	{
		public readonly float BlePhoneAnimationWidthScaleFactor = 0.9f;

		public readonly float BlePhoneAnimationHeightScaleFactor = 0.75f;

		protected const int DefaultTryAgainAwaitTime = 60;

		protected bool wasDismissed;

		protected new IBleConsoleService bleConsoleService;

		protected readonly IBleRadioStatusService bleRadioStatusService;

		private readonly Subject<object> _whenRetryButtonTapped = new Subject<object>();

		public new IMvxCommand Dismiss => new MvxCommand(DoDismiss);

		public IObservable<object> WhenRetryButtonTapped => _whenRetryButtonTapped;

		protected new BleDialogInitializationData ArbitraryData
		{
			get
			{
				return base.ArbitraryData;
			}
			set
			{
				base.ArbitraryData = value;
			}
		}

		protected override void DoDismiss()
		{
			if (!wasDismissed)
			{
				wasDismissed = true;
				base.DoDismiss();
			}
		}

		protected BaseBleViewModel(ILocalSettings localSettings, IBleRadioStatusService bleRadioStatusService, IBleConsoleService bleConsoleService = null)
			: base(localSettings)
		{
			try
			{
				this.bleRadioStatusService = bleRadioStatusService;
				this.bleConsoleService = bleConsoleService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected bool IsBleConsoleServiceNull([CallerMemberName] string caller = null)
		{
			if (bleConsoleService == null)
			{
				ShowViewModel(base.ParentType, (object)null, (IMvxBundle)ShireViewParams.DismissChildren(), (MvxRequestedBy)null);
				Log.Error("Ble", GetType().Name + "->" + caller + " the bleConsoleService is null closing dialog");
				return true;
			}
			return false;
		}

		protected override void DoClose()
		{
			base.DoClose();
			Dispose();
		}

		protected void RetryAndClose()
		{
			_whenRetryButtonTapped.OnNext(null);
			DoClose();
			BleDialogInitializationData arbitraryData = new BleDialogInitializationData
			{
				CanClose = (ArbitraryData?.CanClose ?? false),
				IsOnboarding = (ArbitraryData?.IsOnboarding ?? false),
				OnDismiss = ArbitraryData?.OnDismiss,
				CloseOnDismiss = (ArbitraryData?.CloseOnDismiss ?? false),
				OnFinishedUpdateAvailable = ArbitraryData?.OnFinishedUpdateAvailable,
				OnFinished = ArbitraryData?.OnFinished,
				TargetDeviceGuid = (ArbitraryData?.TargetDeviceGuid ?? Guid.Empty)
			};
			BaseBleDialogViewModel.ShowDialogViewModel<BleScanningViewModel>(arbitraryData);
		}

