	public class BleConnectingViewModel : BaseBleViewModel
	{
		public const double SuccessAnimationDelay = 3.1;

		private const double ErrorAnimationDelay = 2.2;

		private readonly IVideoService videoService;

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly IIfitApiService apiService;

		private readonly Subject<object> _whenBleConnectionSucceeded = new Subject<object>();

		private readonly Subject<object> _whenBleConnectionFailed = new Subject<object>();

		public readonly Dictionary<BleAnimationSequence, Tuple<float, float>> AnimationDictionary = new Dictionary<BleAnimationSequence, Tuple<float, float>>
		{
			{
				BleAnimationSequence.Tablet,
				new Tuple<float, float>(0f, 0.3f)
			},
			{
				BleAnimationSequence.Search,
				new Tuple<float, float>(0.3f, 0.37f)
			},
			{
				BleAnimationSequence.Success,
				new Tuple<float, float>(0.5f, 0.83f)
			},
			{
				BleAnimationSequence.Error,
				new Tuple<float, float>(0.86f, 0.99f)
			}
		};

		private CancellationTokenSource _scanCts;

		private CancellationToken _scanCancellationToken;

		public readonly INC<BleAnimationState> AnimationState = new NC<BleAnimationState>(BleAnimationState.Connecting);

		private IDisposable _deviceStateSubscribe;

		public int TryAgainAwaitTime { get; protected set; }

		public IObservable<object> WhenBleConnectionSucceeded => _whenBleConnectionSucceeded;

		public IObservable<object> WhenBleConnectionFailed => _whenBleConnectionFailed;

		public string TitleText => Wolf.Core.Resources.AppStrings.ble_dialog_connecting_title;

		public string BeSureText => string.Format(Wolf.Core.Resources.AppStrings.ble_dialog_searching_be_sure, IsTablet ? Wolf.Core.Resources.AppStrings.tablet : Wolf.Core.Resources.AppStrings.phone);

		public string PowerOnText => Wolf.Core.Resources.AppStrings.ble_dialog_searching_power_on;

		public string BleOnText => Wolf.Core.Resources.AppStrings.ble_dialog_searching_ble_on;

		public IMvxCommand UserDisconnectDuringConnectingStep => new MvxCommand(ExplicitDisconnect);

		public BleConnectingViewModel(ILocalSettings localSettings, IBleRadioStatusService bleRadioStatusService, IVideoService videoService, IWolfAnalytics wolfAnalytics, IIfitApiService apiService, IBleConsoleService bleConsoleService = null)
			: base(localSettings, bleRadioStatusService, bleConsoleService)
		{
			try
			{
				this.videoService = videoService;
				this.wolfAnalytics = wolfAnalytics;
				this.apiService = apiService;
				TryAgainAwaitTime = 60;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			CanClose.Value = false;
			AnimationState.Value = BleAnimationState.Connecting;
			IsOnboarding.Value = base.ArbitraryData?.IsOnboarding ?? false;
			if (IsBleConsoleServiceNull("OnViewShown"))
			{
				ViewModelInitialized.Value = true;
				return;
			}
			int num;
			if (bleConsoleService?.CurrentDevice?.Id == base.ArbitraryData?.TargetDeviceGuid)
			{
				IBleConsoleService obj = bleConsoleService;
				num = ((obj != null && obj.ConnectionState == ConsoleConnectionState.Connected) ? 1 : 0);
			}
			else
			{
				num = 0;
			}
			bool flag = (byte)num != 0;
			try
			{
				if (flag)
				{
					ViewModelInitialized.Value = true;
					Log.Trace("Ble", "BleConnectingViewModel: Already connected to device, showing BleSuccessOverlay");
					await SuccessfulConnection().ConfigureAwait(continueOnCapturedContext: false);
					return;
				}
				ViewModelInitialized.Value = true;
				_scanCts?.Dispose();
				_scanCancellationToken.DisposeIfDisposable();
				_scanCts = new CancellationTokenSource();
				_scanCancellationToken = _scanCts.Token;
				_deviceStateSubscribe = bleConsoleService?.CurrentDevice?.WhenStateChanged.Where((Sindarin.Core.Ble.Connection.DeviceState x) => x == Sindarin.Core.Ble.Connection.DeviceState.LostConnection).Subscribe(delegate
				{
					MakeCloseButtonVisible();
				});
				ConsoleConnectionState consoleState = await bleConsoleService.WhenConnectionStateChanged.Where((ConsoleConnectionState x) => x == ConsoleConnectionState.Connected).Timeout(TimeSpan.FromSeconds(TryAgainAwaitTime)).Take(1)
					.ToTask(_scanCts.Token)
					.ConfigureAwait(continueOnCapturedContext: false);
				bool flag2 = bleConsoleService.IsConnectedToConsole && bleConsoleService.Console.Initialized;
				if (!flag2)
				{
					flag2 = await (from x in bleConsoleService.WhenConsoleInitialized
						where x != null
						select x != null).Timeout(TimeSpan.FromSeconds(TryAgainAwaitTime)).Take(1).ToTask(_scanCts.Token)
						.ConfigureAwait(continueOnCapturedContext: false);
				}
				if (consoleState == ConsoleConnectionState.Connected && flag2)
				{
					Log.Trace("Ble", "Device connected, successful connection.");
					await SuccessfulConnection().ConfigureAwait(continueOnCapturedContext: false);
					return;
				}
			}
			catch (Exception exception)
			{
				Log.Error("Ble", "Failed to connect to BLE device", exception);
			}
			IBleConsoleService obj2 = bleConsoleService;
			if (obj2 == null || obj2.ConnectionState != ConsoleConnectionState.Connected)
			{
				IBleConsoleService obj3 = bleConsoleService;
				if (obj3 == null || obj3.ConnectionState != ConsoleConnectionState.Connecting)
				{
					bleConsoleService?.DisconnectImmediate(forgetDevice: true);
				}
			}
			if (_scanCancellationToken.IsCancellationRequested)
			{
				Log.Trace("Ble", "Scan Cancellation Token Source received cancellation request, ending scan.");
				return;
			}
			Log.Trace("Ble", "Showing Try Again screen.");
			await ShowTryAgainViewModel().ConfigureAwait(continueOnCapturedContext: true);
		}

		protected virtual async Task SuccessfulConnection()
		{
			bool firmwareUpdateAvailable = false;
			if (base.ArbitraryData?.OnFinishedUpdateAvailable != null)
			{
				firmwareUpdateAvailable = await ShouldUpdateFirmware();
			}
			if (firmwareUpdateAvailable)
			{
				string videoUri = (await Video.Get(apiService, IsTablet ? "firmware-update-video-tablet" : "firmware-update-video-phone").ConfigureAwait(continueOnCapturedContext: false))?.Sources?.HlsSource?.SourceUrl;
				await videoService.StartPrebufferingVodVideo(videoUri).ConfigureAwait(continueOnCapturedContext: false);
			}
			AnimationState.Value = BleAnimationState.Success;
			Task.Run(async delegate
			{
				await Task.Delay(TimeSpan.FromSeconds(3.1));
				_whenBleConnectionSucceeded.OnNext(null);
				if (firmwareUpdateAvailable)
				{
					InvokeOnMainThread(base.ArbitraryData?.OnFinishedUpdateAvailable);
				}
				else if (base.ArbitraryData?.OnFinished != null)
				{
					InvokeOnMainThread(base.ArbitraryData?.OnFinished);
				}
				DoClose();
			});
			wolfAnalytics.EquipmentPairingSuccessful(base.ArbitraryData?.Email);
		}

		private async Task<bool> ShouldUpdateFirmware()
		{
			if (Mvx.TryResolve<ICheckUpdateService>(out var service) && !(bleConsoleService.CurrentDevice is MockDevice))
			{
				return await service.CheckForUpdate() == CheckUpdateState.UpdateAvailable;
			}
			return false;
		}

		private async Task ShowTryAgainViewModel()
		{
			await DisconnectBleConsole(bleConsoleService).ConfigureAwait(continueOnCapturedContext: false);
			AnimationState.Value = BleAnimationState.Error;
			TryAgainDialogInitializationData initData = new TryAgainDialogInitializationData
			{
				CanClose = (base.ArbitraryData?.CanClose ?? false),
				IsOnboarding = IsOnboarding.Value,
				OnFinishedUpdateAvailable = base.ArbitraryData?.OnFinishedUpdateAvailable,
				OnFinished = base.ArbitraryData?.OnFinished,
				OnDismiss = base.ArbitraryData?.OnDismiss,
				CloseOnDismiss = (base.ArbitraryData?.CloseOnDismiss ?? false),
				Email = base.ArbitraryData?.Email,
				Error1 = TryAgainErrors.BleSettings,
				Error2 = TryAgainErrors.BluetoothSupport2,
				Error3 = TryAgainErrors.BluetoothSupport3,
				Error4 = TryAgainErrors.BleActivationInstructions,
				Error5 = TryAgainErrors.EquipmentRecovery,
				Retry = base.RetryAndClose
			};
			await Task.Delay(TimeSpan.FromSeconds(2.2)).ConfigureAwait(continueOnCapturedContext: false);
			_whenBleConnectionFailed.OnNext(null);
			DoClose();
			BaseBleDialogViewModel.ShowDialogViewModel<TryAgainViewModel>(initData);
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			_scanCts?.Cancel();
			_deviceStateSubscribe.DisposeIfDisposable();
		}

		private void ExplicitDisconnect()
		{
			bleConsoleService.DisconnectImmediate(forgetDevice: true, forceCleanup: true, forceDisconnect: true);
			DoClose();
			base.Dismiss.Execute();
		}

		public void MakeCloseButtonVisible()
		{
			CanClose.Value = true;
			AnimationState.Value = BleAnimationState.Error;
		}

