	public class BleFoundViewModel : BaseBleViewModel
	{
		public readonly ImprovedObservableCollection<IBleDevice> Devices = new ImprovedObservableCollection<IBleDevice>();

		public readonly INC<string> TitleText = new NC<string>();

		public readonly INC<string> DescText = new NC<string>();

		public readonly INC<string> TipTitleText = new NC<string>();

		public readonly INC<string> BeSureText = new NC<string>();

		public readonly INC<string> PowerOnText = new NC<string>();

		public readonly INC<string> BleOnText = new NC<string>();

		private readonly Subject<object> _whenBleConnectingScreenAppears = new Subject<object>();

		private readonly IScanner scanner;

		private readonly IDeveloperSettings developerSettings;

		private readonly IBleTcpConnectionService bleTcpConnectionService;

		private readonly BaseDeviceFilter filter = new FitProDeviceFilter();

		private IDisposable deviceFoundSub;

		private IDisposable deviceConnectingConnectedSub;

		private bool hasShownConnectingViewModel;

		public MvxAsyncCommand<IBleDevice> HandleConnection => new MvxAsyncCommand<IBleDevice>(DoHandleConnection);

		public MvxCommand ViewMoreHelpTips => new MvxCommand(DoViewMoreHelpTips);

		public MvxCommand ShowBleInfoDialog => new MvxCommand(DoShowBleInfoDialog);

		public IObservable<object> WhenBleConnectingScreenAppears => _whenBleConnectingScreenAppears;

		public BleFoundViewModel(ILocalSettings localSettings, IScanner scanner, IBleRadioStatusService bleRadioStatusService, IDeveloperSettings developerSettings, IBleConsoleService bleConsoleService = null, IBleTcpConnectionService bleTcpConnectionService = null)
			: base(localSettings, bleRadioStatusService, bleConsoleService)
		{
			try
			{
				this.scanner = scanner;
				this.bleTcpConnectionService = bleTcpConnectionService;
				this.developerSettings = developerSettings;
				TitleText.Value = Wolf.Core.Resources.AppStrings.ble_dialog_equipment_found_title;
				DescText.Value = string.Format(Wolf.Core.Resources.AppStrings.ble_dialog_equipment_found_description_line, IsTablet ? "\n" : " ");
				TipTitleText.Value = Wolf.Core.Resources.AppStrings.ble_dialog_tip_title_description;
				BeSureText.Value = string.Format(Wolf.Core.Resources.AppStrings.ble_dialog_searching_be_sure, IsTablet ? Wolf.Core.Resources.AppStrings.tablet : Wolf.Core.Resources.AppStrings.phone);
				PowerOnText.Value = Wolf.Core.Resources.AppStrings.ble_dialog_searching_power_on;
				BleOnText.Value = Wolf.Core.Resources.AppStrings.ble_dialog_searching_ble_on;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			CleanUp();
			CanClose.Value = base.ArbitraryData?.CanClose ?? false;
			IsOnboarding.Value = base.ArbitraryData?.IsOnboarding ?? false;
			ViewModelInitialized.Value = true;
			if (IsBleConsoleServiceNull("OnViewShown"))
			{
				return;
			}
			RequestEnableBluetooth(notifyIfCannotEnable: true);
			ConsoleConnectionState connectionState = bleConsoleService.ConnectionState;
			if (connectionState == ConsoleConnectionState.NotConnected)
			{
				Log.Trace("Ble", "Console state is not connected. Disconnecting from device " + bleConsoleService?.CurrentDevice?.PairKey);
				bleConsoleService.DisconnectImmediate(forgetDevice: true);
			}
			if ((base.ArbitraryData?.IsOnboarding ?? false) && (connectionState == ConsoleConnectionState.Connecting || connectionState == ConsoleConnectionState.Connected) && !(bleConsoleService.CurrentDevice is NonConnectedMockDevice))
			{
				GoToConnectingViewModel(bleConsoleService.CurrentDevice);
				return;
			}
			if (bleConsoleService.CurrentDevice != null && !(bleConsoleService.CurrentDevice is NonConnectedMockDevice))
			{
				AddDeviceOnMainThread(bleConsoleService.CurrentDevice);
			}
			deviceConnectingConnectedSub?.Dispose();
			deviceConnectingConnectedSub = bleConsoleService.WhenConnectionStateChanged.Where((ConsoleConnectionState x) => x == ConsoleConnectionState.Connected || x == ConsoleConnectionState.Connecting).Subscribe(delegate
			{
				GoToConnectingViewModel(bleConsoleService.CurrentDevice);
			});
			if (developerSettings.MockDevicesEnabled)
			{
				InvokeOnMainThread(delegate
				{
					MockDeviceUtil.AddMockDevices(Devices);
					Devices.Add(TcpDevice.SharedDevice);
					Devices.SortDevices();
				});
				if (localSettings.IsRoboRunMode)
				{
					await DoHandleConnection(Devices[0]);
				}
			}
			deviceFoundSub = scanner.ScanWithFilter(filter).Distinct((IBleDevice x) => x.PairKey).SubscribeWithErrorLogging(AddDeviceOnMainThread);
		}

		protected void AddDeviceOnMainThread(IBleDevice device)
		{
			if (device is NonConnectedMockDevice)
			{
				DisposeUnconnectedDevice(device);
				return;
			}
			Guid id = device.Id;
			Guid? guid = bleConsoleService.CurrentDevice?.Id;
			if (guid.HasValue && id == guid.GetValueOrDefault() && device != bleConsoleService.CurrentDevice && bleConsoleService.ConnectionState != ConsoleConnectionState.Connecting)
			{
				Log.Trace("Ble", "BleFoundViewModel found device " + device?.Name + " (" + device?.PairKey + ")");
				bleConsoleService.Connect(device);
				GoToConnectingViewModel(device);
				return;
			}
			InvokeOnMainThread(delegate
			{
				IBleDevice bleDevice = Devices.FirstOrDefault((IBleDevice dev) => dev.Id == device.Id);
				Devices.Remove(bleDevice);
				DisposeUnconnectedDevice(bleDevice);
				bleDevice = Devices.FirstOrDefault((IBleDevice dev) => string.Equals(dev.Name, device.Name, StringComparison.CurrentCultureIgnoreCase) && string.IsNullOrEmpty(dev.PairKey));
				Devices.Remove(bleDevice);
				DisposeUnconnectedDevice(bleDevice);
				Devices.Add(device);
				Devices.SortDevices();
			});
		}

		protected override void OnViewHidden()
		{
			base.OnViewHidden();
			CleanUp();
		}

		public override void Dispose()
		{
			CleanUp();
			((AutoUpdateDialogViewModel)this).Dispose();
			UnregisterChangeHandlers();
		}

		private void CleanUp()
		{
			Devices.ForEach(DisposeUnconnectedDevice);
			if (Devices.Any())
			{
				InvokeOnMainThread(Devices.Clear);
			}
			deviceFoundSub?.Dispose();
			deviceFoundSub = null;
			deviceConnectingConnectedSub?.Dispose();
			deviceConnectingConnectedSub = null;
			scanner?.StopScan();
		}

		private void DisposeUnconnectedDevice(IBleDevice device)
		{
			if (device != null && device.State != Sindarin.Core.Ble.Connection.DeviceState.Connected && device.State != Sindarin.Core.Ble.Connection.DeviceState.Connecting)
			{
				device.Dispose();
				device = null;
			}
		}

		private void GoToConnectingViewModel(IBleDevice device)
		{
			if (device != null)
			{
				deviceConnectingConnectedSub?.Dispose();
				if (base.ArbitraryData == null)
				{
					base.ArbitraryData = new BleDialogInitializationData
					{
						CanClose = CanClose.Value,
						IsOnboarding = IsOnboarding.Value
					};
				}
				base.ArbitraryData.TargetDeviceGuid = device.Id;
				_whenBleConnectingScreenAppears?.OnNext(null);
				if (!hasShownConnectingViewModel)
				{
					hasShownConnectingViewModel = true;
					BaseBleDialogViewModel.ShowDialogViewModel<BleConnectingViewModel>(base.ArbitraryData);
				}
				Task.Run(async delegate
				{
					await Task.Delay(1000);
					DoClose();
				});
			}
		}

		private async Task DoHandleConnection(IBleDevice device)
		{
			if (device is TcpDevice tcpDevice && bleTcpConnectionService != null && !(await bleTcpConnectionService.PromptForVirtualConsoleAddress(tcpDevice)))
			{
				return;
			}
			switch (device.State)
			{
			case Sindarin.Core.Ble.Connection.DeviceState.Disconnected:
			case Sindarin.Core.Ble.Connection.DeviceState.Connecting:
			case Sindarin.Core.Ble.Connection.DeviceState.LostConnection:
			{
				if (FitProConsoleDeviceFilterUtil.HasValidDfuDeviceName(device) && Mvx.TryResolve<IDfuConnectionService>(out var service))
				{
					await service.ScanForRecoverableDevices(null, showNoRecoverableDialog: true).ConfigureAwait(continueOnCapturedContext: false);
					break;
				}
				Log.Trace("Ble", "Connecting to device " + device?.Name + " (" + device?.PairKey + ")");
				await bleConsoleService.Connect(device, 60);
				GoToConnectingViewModel(device);
				break;
			}
			case Sindarin.Core.Ble.Connection.DeviceState.Connected:
				Log.Trace("Ble", "Disconnecting from device " + device?.PairKey);
				Task.Run((Func<Task>)CloseThenDisconnect);
				break;
			default:
				throw new ArgumentOutOfRangeException();
			}
		}

		private async Task CloseThenDisconnect()
		{
			DoClose();
			base.ArbitraryData?.OnDismiss?.Invoke();
			Subject<object> whenShouldDismissDialog = new Subject<object>();
			try
			{
				ShowProgressDialog(Wolf.Core.Resources.AppStrings.disconnecting, whenShouldDismissDialog);
				Task task = DisconnectBleConsole(bleConsoleService);
				Task task2 = Task.Delay(1000);
				await Task.WhenAll(task2, task).ConfigureAwait(continueOnCapturedContext: false);
			}
			finally
			{
				whenShouldDismissDialog.OnNext(null);
			}
		}

		private void DoViewMoreHelpTips()
		{
			deviceFoundSub?.Dispose();
			bleConsoleService?.DisconnectImmediate(forgetDevice: true);
			TryAgainDialogInitializationData arbitraryData = new TryAgainDialogInitializationData
			{
				CanClose = true,
				IsOnboarding = IsOnboarding.Value,
				OnFinishedUpdateAvailable = base.ArbitraryData?.OnFinishedUpdateAvailable,
				OnFinished = base.ArbitraryData?.OnFinished,
				OnDismiss = base.ArbitraryData?.OnDismiss,
				CloseOnDismiss = (base.ArbitraryData?.CloseOnDismiss ?? false),
				Email = base.ArbitraryData?.Email,
				Error1 = TryAgainErrors.BleSettings,
				Error2 = TryAgainErrors.EmptyBluetoothSupport2,
				Error3 = TryAgainErrors.EmptyBluetoothSupport3,
				Error4 = TryAgainErrors.BleActivationInstructions,
				Error5 = TryAgainErrors.EquipmentRecovery,
				ErrorText = string.Empty,
				Retry = base.RetryAndClose
			};
			BaseBleDialogViewModel.ShowDialogViewModel<TryAgainViewModel>(arbitraryData);
		}

		public void DoShowBleInfoDialog()
		{
			IDialogPresenter dialogPresenter = Mvx.Resolve<IDialogPresenter>();
			dialogPresenter.ShowDialog<BleFoundInfoDialogViewModel>();
		}

