	public class BlePairFilterDialogViewModel : BaseDialogViewModel
	{
		public class BlePairFilterOptions
		{
			public bool IsOnboarding { get; set; }

			public bool EnableAutoUpdate { get; set; }

			public string Email { get; set; }

			public Workout.WorkoutType DesiredType { get; set; }
		}

		private const string Tag = "BlePairFilter";

		private new readonly IBleConsoleService bleConsoleService;

		private readonly IIfitApiService apiService;

		private readonly IMvxMessenger messenger;

		private readonly IBleRadioStatusService bleRadioStatusService;

		private readonly SemaphoreSlim procCommand = new SemaphoreSlim(1);

		private IDisposable consoleState;

		public readonly INC<bool> IsOnboarding = new NC<bool>(value: false);

		public readonly INC<bool> IsConnecting = new NC<bool>(value: false);

		private MockType desiredMockType;

		private bool navigatedAway;

		private bool IsUserPremium => apiService.CurrentlyAuthenticatedUser?.Premium == true;

		private bool softPaywallEnabled => featureFlagManager.IsFeatureEnabled(FeatureFlags.SoftPaywallEnabled);

		public bool EnableAutoUpdate { get; protected set; }

		public string Email { get; protected set; }

		public ICommand Cancel => new MvxAsyncCommand(DoCancel);

		public ICommand SkipConnection => new MvxAsyncCommand(DoSkipConnection);

		public ICommand PairDevice => new MvxAsyncCommand(DoPairDevice);

		protected new BlePairFilterOptions ArbitraryData
		{
			get
			{
				return base.ArbitraryData as BlePairFilterOptions;
			}
			set
			{
				base.ArbitraryData = value;
			}
		}

		public BlePairFilterDialogViewModel(ILocalSettings localSettings, IBleConsoleService bleConsoleService, IIfitApiService apiService, IMvxMessenger messenger, IBleRadioStatusService bleRadioStatusService, IFeatureFlagManager manager)
			: base(localSettings)
		{
			try
			{
				this.bleConsoleService = bleConsoleService;
				this.apiService = apiService;
				this.messenger = messenger;
				this.bleRadioStatusService = bleRadioStatusService;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override void InitWithArbitraryData()
		{
			CanClose.Value = !ArbitraryData.IsOnboarding;
			IsOnboarding.Value = ArbitraryData.IsOnboarding;
			EnableAutoUpdate = ArbitraryData.EnableAutoUpdate;
			Email = ArbitraryData.Email;
			desiredMockType = ArbitraryData.DesiredType.ToMockType();
		}

		public override Task OnViewShown()
		{
			navigatedAway = false;
			IsConnecting.Value = false;
			ViewModelInitialized.Value = true;
			SetupConnectionSubscription();
			return base.OnViewShown();
		}

		private void SetupConnectionSubscription()
		{
			if (bleConsoleService?.WhenConnectionStateChanged != null)
			{
				consoleState?.Dispose();
				consoleState = bleConsoleService.WhenConnectionStateChanged.Where((ConsoleConnectionState x) => x == ConsoleConnectionState.Connected).Subscribe(async delegate
				{
					await DoSkipConnection().ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		private async Task DoCancel()
		{
			if (navigatedAway)
			{
				return;
			}
			try
			{
				await procCommand.WaitAsync();
				messenger.Publish(new ResolvedConsoleMessage(this, ResolvedConsoleMessage.Resolution.Cancelled));
				DoClose();
				navigatedAway = true;
			}
			finally
			{
				procCommand.Release();
			}
		}

		private async Task DoSkipConnection()
		{
			if (navigatedAway)
			{
				return;
			}
			try
			{
				await procCommand.WaitAsync();
				IsConnecting.Value = true;
				if (ShouldConnectToNewMock())
				{
					Log.Trace("BlePairFilter", $"Connecting to {desiredMockType} non-connected device.");
					NonConnectedMockDevice nonConnectedMockDevice = MockDeviceUtil.GetNonConnectedMockDevice(desiredMockType);
					await bleConsoleService.Connect(nonConnectedMockDevice);
				}
				PairingFinished(IsUserPremium);
				navigatedAway = true;
			}
			finally
			{
				procCommand.Release();
			}
		}

		private bool ShouldConnectToNewMock()
		{
			if (bleConsoleService.Console == null)
			{
				return true;
			}
			MockType? mockType = (bleConsoleService.CurrentDevice as NonConnectedMockDevice)?.Type;
			if (!mockType.HasValue)
			{
				return true;
			}
			if (desiredMockType == MockType.Treadmill)
			{
				switch (mockType)
				{
				case MockType.Treadmill:
				case MockType.Elliptical:
				case MockType.VerticalElliptical:
				case MockType.FreeStrider:
				case MockType.Hybrid:
				case MockType.Yoga:
				case MockType.Mind:
				case MockType.Nutrition:
				case MockType.Sleep:
					return false;
				default:
					return true;
				}
			}
			return mockType != desiredMockType;
		}

		private async Task DoPairDevice()
		{
			if (navigatedAway)
			{
				return;
			}
			if (!(bleRadioStatusService?.CheckAndRequestBluetooth(notifyIfCannotEnable: true, GetType().Name) ?? false))
			{
				Log.Warn("BlePairFilter", "BLE radio is disabled. Not proceeding to scan screen.");
				return;
			}
			await procCommand.WaitAsync();
			try
			{
				ShowBleScanningDialog(showSafely: false, new BleDialogInitializationData
				{
					CanClose = true,
					IsOnboarding = IsOnboarding.Value,
					OnFinishedUpdateAvailable = delegate
					{
						if (EnableAutoUpdate)
						{
							ShowViewModel<OnboardingFirmwareUpdateViewModel>();
						}
						else
						{
							PairingFinished(IsUserPremium);
						}
					},
					OnFinished = delegate
					{
						PairingFinished(IsUserPremium);
					},
					OnDismiss = delegate
					{
						navigatedAway = false;
					},
					CloseOnDismiss = true,
					Email = Email
				});
				navigatedAway = true;
			}
			finally
			{
				procCommand.Release();
			}
		}

		private void PairingFinished(bool isPremium)
		{
			if (IsOnboarding.Value)
			{
				if (softPaywallEnabled || isPremium)
				{
					NavigateToFirstViewModel();
				}
				else
				{
					IFitnessConsole console = bleConsoleService.Console;
					if (console != null && console.IsNonconnectedConsole())
					{
						ShowViewModel<OnboardingWebViewModel>();
					}
					else
					{
						ShowViewModel<OnboardingPreVideoViewModel>();
					}
				}
				DoClose();
			}
			else
			{
				DoClose();
				messenger.Publish(new ResolvedConsoleMessage(this, ResolvedConsoleMessage.Resolution.Resolved));
			}
		}

		public override void Dispose()
		{
			((BaseViewModel)this).Dispose();
			consoleState?.Dispose();
			consoleState = null;
			UnregisterChangeHandlers();
		}

