	public class BleScanningViewModel : BaseBleViewModel
	{
		private const int ScanDurationSeconds = 30;

		public readonly Dictionary<BleAnimationSequence, Tuple<float, float>> AnimationDictionary = new Dictionary<BleAnimationSequence, Tuple<float, float>>
		{
			{
				BleAnimationSequence.Tablet,
				new Tuple<float, float>(0f, 0.3f)
			},
			{
				BleAnimationSequence.Search,
				new Tuple<float, float>(0.3f, 0.37f)
			},
			{
				BleAnimationSequence.Success,
				new Tuple<float, float>(0.5f, 0.83f)
			},
			{
				BleAnimationSequence.Error,
				new Tuple<float, float>(0.86f, 0.99f)
			}
		};

		private readonly Subject<object> _whenBleFoundScreenAppears = new Subject<object>();

		private readonly Subject<object> _whenBleScanningFailed = new Subject<object>();

		private readonly IScanner scanner;

		private readonly IDeveloperSettings developerSettings;

		private readonly BaseDeviceFilter filter = new FitProDeviceFilter();

		private IDisposable deviceFoundSub;

		protected CancellationTokenSource scanCts;

		private bool restarting;

		public IMvxCommand RestartScan => new MvxAsyncCommand(DoRestartScan);

		public IObservable<object> WhenBleFoundScreenAppears => _whenBleFoundScreenAppears;

		public IObservable<object> WhenBleScanningFailed => _whenBleScanningFailed;

		public string TitleText => Wolf.Core.Resources.AppStrings.ble_dialog_searching_for_equipment;

		public string BeSureText => string.Format(Wolf.Core.Resources.AppStrings.ble_dialog_searching_be_sure, IsTablet ? Wolf.Core.Resources.AppStrings.tablet : Wolf.Core.Resources.AppStrings.phone);

		public string PowerOnText => Wolf.Core.Resources.AppStrings.ble_dialog_searching_power_on;

		public string BleOnText => Wolf.Core.Resources.AppStrings.ble_dialog_searching_ble_on;

		public bool IsRoboRunMode => localSettings.IsRoboRunMode;

		public BleScanningViewModel(ILocalSettings localSettings, IScanner scanner, IBleRadioStatusService bleRadioStatusService, IDeveloperSettings developerSettings, IBleConsoleService bleConsoleService = null)
			: base(localSettings, bleRadioStatusService, bleConsoleService)
		{
			try
			{
				this.scanner = scanner;
				this.developerSettings = developerSettings;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void NavigateToFoundViewModel()
		{
			_whenBleFoundScreenAppears.OnNext(null);
			BaseBleDialogViewModel.ShowDialogViewModel<BleFoundViewModel>(base.ArbitraryData);
			Task.Run(async delegate
			{
				await Task.Delay(1000);
				DoClose();
			});
		}

		private void NavigateToTryAgainViewModel()
		{
			TryAgainDialogInitializationData arbitraryData = new TryAgainDialogInitializationData
			{
				CanClose = CanClose.Value,
				IsOnboarding = IsOnboarding.Value,
				OnFinishedUpdateAvailable = base.ArbitraryData?.OnFinishedUpdateAvailable,
				OnFinished = base.ArbitraryData?.OnFinished,
				OnDismiss = base.ArbitraryData?.OnDismiss,
				CloseOnDismiss = (base.ArbitraryData?.CloseOnDismiss ?? false),
				Email = base.ArbitraryData?.Email,
				Error1 = TryAgainErrors.BleSettings,
				Error2 = TryAgainErrors.BluetoothSupport2,
				Error3 = TryAgainErrors.BluetoothSupport3,
				Error4 = TryAgainErrors.None,
				Error5 = TryAgainErrors.None,
				Retry = base.RetryAndClose
			};
			_whenBleScanningFailed.OnNext(null);
			DoClose();
			BaseBleDialogViewModel.ShowDialogViewModel<TryAgainViewModel>(arbitraryData);
		}

		public override async Task OnViewShown()
		{
			if (base.viewShownCount <= 0)
			{
				await base.OnViewShown();
				CanClose.Value = base.ArbitraryData?.CanClose ?? false;
				IsOnboarding.Value = base.ArbitraryData?.IsOnboarding ?? false;
				if (IsBleConsoleServiceNull("OnViewShown"))
				{
					ViewModelInitialized.Value = true;
				}
				else if (developerSettings.MockDevicesEnabled)
				{
					NavigateToFoundViewModel();
				}
				else
				{
					await StartScan();
				}
			}
		}

		private async Task StartScan()
		{
			scanCts?.Cancel();
			scanCts = new CancellationTokenSource();
			bool deviceAdded = false;
			deviceFoundSub?.Dispose();
			deviceFoundSub = bleConsoleService.WhenConnectionStateChanged.Where((ConsoleConnectionState x) => x == ConsoleConnectionState.Connected || x == ConsoleConnectionState.Connecting).Take(1).Subscribe(delegate
			{
				OnDeviceAdded(bleConsoleService.CurrentDevice);
			});
			ViewModelInitialized.Value = true;
			try
			{
				IBleDevice bleDevice = bleConsoleService.CurrentDevice;
				if (bleDevice == null || bleDevice is NonConnectedMockDevice)
				{
					bleDevice = await scanner.ScanWithFilter(filter, 30).Timeout(TimeSpan.FromSeconds(30.0)).Take(1)
						.ToTask(scanCts.Token);
				}
				if (bleDevice != null && !(bleDevice is NonConnectedMockDevice))
				{
					OnDeviceAdded(bleDevice);
					return;
				}
			}
			catch (TimeoutException)
			{
			}
			catch (Exception exception)
			{
				Log.Error("Ble", "Failed to find device", exception);
			}
			if (!wasDismissed && !restarting)
			{
				NavigateToTryAgainViewModel();
			}
			restarting = false;
			void OnDeviceAdded(IBleDevice newDevice)
			{
				if (!deviceAdded && newDevice != null && bleConsoleService.ConnectionState != ConsoleConnectionState.Disconnecting && !(newDevice is NonConnectedMockDevice))
				{
					deviceAdded = true;
					NavigateToFoundViewModel();
				}
			}
		}

		public async Task DoRestartScan()
		{
			restarting = true;
			scanner.StopScan();
			await StartScan();
		}

		public void CancelScan()
		{
			if (scanCts != null)
			{
				scanCts.Cancel();
				DoClose();
			}
		}

		protected override void DoClose()
		{
			base.DoClose();
			Dispose();
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				((AutoUpdateDialogViewModel)this).Dispose();
				deviceFoundSub?.Dispose();
				deviceFoundSub = null;
				scanCts?.Cancel();
				scanCts?.Dispose();
				scanCts = null;
				UnregisterChangeHandlers();
			}
		}

