	[ViewModelOverride(typeof(DashboardViewModel))]
	public class DashboardViewModelOverride : IViewModelOverride
	{
		private readonly IConnectivity connectivity;

		private readonly IDeviceInformation deviceInformation;

		public const string ErrorCodeKey = "ErrorCode";

		private string LogTag => "DashboardViewModelOverride";

		private bool IsConnected => connectivity?.IsConnected == true;

		public DashboardViewModelOverride(IConnectivity connectivity, IDeviceInformation deviceInformation)
		{
			this.connectivity = connectivity;
			this.deviceInformation = deviceInformation;
		}

		public MvxViewModelRequest OverrideRequest(MvxViewModelRequest request)
		{
			ErrorCode errorCode = ErrorCode.None;
			IFeatureFlagManager service;
			if (!IsConnected)
			{
				errorCode = ErrorCode.WifiNoInternet;
			}
			else if (Mvx.TryResolve<IFeatureFlagManager>(out service))
			{
				if (string.IsNullOrWhiteSpace(service.GetString(FeatureFlags.WolfDashboardWebviewUrl)))
				{
					errorCode = ErrorCode.LaunchDarklyFailureTimeout;
				}
			}
			else
			{
				errorCode = ErrorCode.LaunchDarklyFailureResolve;
			}
			if (errorCode != ErrorCode.None)
			{
				Log.Trace(LogTag, "Showing no wifi screen because of error: " + errorCode.ToString() + " - error");
				request.ParameterValues = new Dictionary<string, string> { ["ErrorCode"] = errorCode.ToString() };
				if (deviceInformation.IsBuiltIn)
				{
					Log.Trace(LogTag, "Not connected. Showing EmbeddedNoWifiDashboardViewModel");
					request.ViewModelType = typeof(EmbeddedNoWifiDashboardViewModel);
				}
				else
				{
					Log.Trace(LogTag, "Not connected. Showing MobileNoWifiViewModel");
					request.ViewModelType = typeof(MobileNoWifiViewModel);
				}
			}
			return request;
		}
	}
	[ViewModelOverride(typeof(EmbeddedNoWifiDashboardViewModel))]
	public class EmbeddedNoWifiDashboardViewModelOverride : IViewModelOverride
	{
		private readonly IDeviceInformation deviceInformation;

		public EmbeddedNoWifiDashboardViewModelOverride(IDeviceInformation deviceInformation)
		{
			this.deviceInformation = deviceInformation;
		}

		public MvxViewModelRequest OverrideRequest(MvxViewModelRequest request)
		{
			if (!deviceInformation.IsBuiltIn)
			{
				Log.Trace("EmbeddedNoWifiDashboardViewModelOverride", "Not embedded. Showing MobileNoWifiViewModel");
				request.ViewModelType = typeof(MobileNoWifiViewModel);
			}
			else
			{
				Log.Trace("EmbeddedNoWifiDashboardViewModelOverride", "Not overriding, continuing on to show EmbeddedNoWifiDashboardViewModelOverride");
			}
			return request;
		}
	}
