	[ViewModelOverride(typeof(LoginViewModel))]
	public class LoginViewModelOverride : IViewModelOverride
	{
		public class NavObject : ShowViewModelParameters
		{
			public bool ShouldBleShowWall { get; set; }

			public bool ForceLoggedInUserToDashboard { get; set; }
		}

		public const string ShouldBleShowWallKey = "ShouldBleShowWall";

		public const string ShowLoginKey = "ShowLogin";

		private readonly IDeviceInformation deviceInformation;

		private readonly ICurrentConsoleService currentConsoleService;

		public LoginViewModelOverride(IDeviceInformation deviceInformation, ICurrentConsoleService currentConsoleService)
