	[ViewModelOverride(typeof(LogScreenViewModel))]
	public class PostWorkoutViewModelOverride : IViewModelOverride
	{
		private const string LogTag = "ViewModelOverride";

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IDeviceInformation deviceInfo;

		private readonly IConnectivity connectivityService;

		private readonly IIfitApiService ifitApi;

		private bool useOfflinePostWorkout => featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfUseOfflinePostworkoutWebview);

		public PostWorkoutViewModelOverride(IFeatureFlagManager featureFlagManager, IDeviceInformation deviceInfo, IConnectivity connectivityService, IIfitApiService ifitApi)
		{
			this.featureFlagManager = featureFlagManager;
			this.deviceInfo = deviceInfo;
			this.connectivityService = connectivityService;
			this.ifitApi = ifitApi;
		}

		public MvxViewModelRequest OverrideRequest(MvxViewModelRequest request)
		{
			try
			{
				if (!connectivityService.IsConnected)
				{
					goto IL_0024;
				}
				IIfitApiService ifitApiService = ifitApi;
				if (ifitApiService != null && !ifitApiService.HasLoggedInUser)
				{
					goto IL_0024;
				}
				Log.Trace("ViewModelOverride", "Attempting to show the workout log screen.");
				if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfUsePrePostWebviewPhone) && !deviceInfo.IsTablet)
				{
					Log.Trace("ViewModelOverride", "Showing webview log screen...");
					return request;
				}
				bool flag = IsWolf(request);
				bool flag2 = IsPostWorkout(request);
				bool flag3 = IsWorkoutCategory(request);
				bool flag4 = IsSuccessfulUpload(request);
				if (!flag2 && !flag3 && !flag)
				{
					Log.Trace("ViewModelOverride", "Showing webview log screen...");
					return request;
				}
				if (!flag4 && flag2)
				{
					if (useOfflinePostWorkout)
					{
						Log.Trace("ViewModelOverride", "Showing OfflinePostWorkoutWebviewViewModel because upload was not successful");
						request.ViewModelType = typeof(OfflinePostWorkoutWebviewViewModel);
					}
					else
					{
						Log.Trace("ViewModelOverride", "Defaulting to NoWifiLogScreenViewModel...");
						request.ViewModelType = typeof(NoWifiLogScreenViewModel);
					}
					return request;
				}
				if (featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfUsePostworkoutWebview))
				{
					request.ViewModelType = typeof(PostWorkoutWebviewViewModel);
				}
				goto end_IL_0000;
				IL_0024:
				Log.Trace("ViewModelOverride", "Network is unreachable or user is logged out.");
				if (useOfflinePostWorkout)
				{
					Log.Trace("ViewModelOverride", "Defaulting to OfflinePostWorkoutWebviewViewModel...");
					request.ViewModelType = typeof(OfflinePostWorkoutWebviewViewModel);
				}
				else
				{
					Log.Trace("ViewModelOverride", "Defaulting to NoWifiLogScreenViewModel...");
					request.ViewModelType = typeof(NoWifiLogScreenViewModel);
				}
				return request;
				end_IL_0000:;
			}
			catch (Exception exception)
			{
				Log.Error("ViewModelOverride", "PostWorkoutViewModelOverride Unable to parse request navigation parameters - " + SerializeNavParams(request.ParameterValues), exception);
			}
			return request;
		}

		private bool IsPostWorkout(MvxViewModelRequest request)
		{
			return ParseBoolParameter(request, "PostWorkout");
		}

		private bool IsWolf(MvxViewModelRequest request)
		{
			return ParseBoolParameter(request, "FromWolf");
		}

		private bool IsWorkoutCategory(MvxViewModelRequest request)
		{
			request.ParameterValues.TryGetValue("LogCategory", out var value);
			return value == "workout";
		}

		private bool IsSuccessfulUpload(MvxViewModelRequest request)
		{
			request.ParameterValues.TryGetValue("UploadResult", out var value);
			return value?.Equals(UploadResult.Success.ToString()) ?? false;
		}

		private bool ParseBoolParameter(MvxViewModelRequest request, string parameterKey)
		{
			request.ParameterValues.TryGetValue(parameterKey, out var value);
			bool.TryParse(value, out var result);
			return result;
		}

		private string SerializeNavParams(IDictionary<string, string> navParams)
		{
			try
			{
				return JsonConvert.SerializeObject(navParams, Formatting.Indented);
			}
			catch (Exception)
			{
			}
			return string.Empty;
		}
	}
