	public static class AsyncFuncExtensions
	{
		public static async Task<TRESULT> RetryWithExponentialBackoff<TRESULT>(this Func<Task<TRESULT>> func, Func<TRESULT, bool> shouldRetryOnResult = null, Func<Exception, bool> shouldRetryOnException = null, int maxRetries = 3, IScheduler scheduler = null)
		{
			scheduler = scheduler ?? DefaultScheduler.Instance;
			int tryCount = 0;
			bool retry = true;
			Exception lastException = null;
			while (retry)
			{
				try
				{
					TRESULT val = await func();
					if (shouldRetryOnResult == null || !shouldRetryOnResult(val))
					{
						return val;
					}
				}
				catch (Exception ex)
				{
					if (shouldRetryOnException != null && !shouldRetryOnException(ex))
					{
						throw;
					}
					lastException = ex;
				}
				tryCount++;
				retry = tryCount <= maxRetries;
				if (retry)
				{
					int num = 1 << tryCount - 1;
					TimeSpan dueTime = TimeSpan.FromSeconds(num);
					await Observable.Timer(dueTime, scheduler);
				}
			}
			throw new TooManyRetriesException(lastException);
		}
	}
	public class TooManyRetriesException : ApplicationException
	{
		public TooManyRetriesException(Exception innerException)
			: base("Function was retried too many times.", innerException)
		{
		}
	}
