	public abstract class BaseUserAvatarImageFactory
	{
		protected static readonly int ImageSize = 120;

		protected static readonly int FontSize = 42;

		protected static readonly SplatColor FontColor = SplatColor.White;

		public IBlobCacheService BlobCacheService { get; set; }

		protected static SplatColor GetBGColorForUser(User user)
		{
			SplatColor result = Colors.AvatarAtoF;
			string initialsForUser = GetInitialsForUser(user);
			if (!string.IsNullOrWhiteSpace(initialsForUser))
			{
				char c = initialsForUser.ToCharArray().First();
				result = ((c <= 'F') ? Colors.AvatarAtoF : ((c <= 'L') ? Colors.AvatarGtoL : ((c > 'R') ? Colors.AvatarStoZ : Colors.AvatarMtoR)));
			}
			return result;
		}

		protected static string GetInitialsForUser(User user)
		{
			if (Mvx.TryResolve<ICulture>(out var service))
			{
				string formattedInitials = service.GetFormattedInitials(user.Firstname, user.Lastname);
				if (!string.IsNullOrEmpty(formattedInitials))
				{
					return formattedInitials;
				}
			}
			string text = "";
			if (!string.IsNullOrEmpty(user.Firstname))
			{
				text = StringInfo.GetNextTextElement(user.Firstname.ToUpper());
			}
			string text2 = "";
			if (!string.IsNullOrEmpty(user.Lastname))
			{
				text2 = StringInfo.GetNextTextElement(user.Lastname.ToUpper());
			}
			return text + text2;
		}

		protected static string GetKeyForUser(User user)
		{
			StringBuilder stringBuilder = new StringBuilder();
			if (!string.IsNullOrWhiteSpace(user?.Id))
			{
				stringBuilder.Append(user.Id + GetInitialsForUser(user));
			}
			if (!string.IsNullOrWhiteSpace(user?.ImageUrl))
			{
				stringBuilder.Append(user.ImageUrl);
			}
			return stringBuilder.ToString();
		}
	}
