		public static async Task<bool> ShowSimpleConfirmationDialogAsync(this BaseViewModel viewModel, string title, string message, string cancelButtonText = null, string confirmButtonText = null, bool dismissible = true, bool cancellable = true, string dialogTag = "")
		{
			bool isConfirmed = false;
			if (await viewModel.ShowSimpleConfirmationDialogAsync(title, message, delegate
			{
				isConfirmed = true;
			}, cancelButtonText, confirmButtonText, null, null, dismissible, cancellable, dialogTag).ConfigureAwait(continueOnCapturedContext: false) is Task task)
			{
				await task.ConfigureAwait(continueOnCapturedContext: false);
			}
			return isConfirmed;
		}

		public static async Task<object> ShowSimpleConfirmationDialogAsync(this BaseViewModel viewModel, string title, string message, Action onConfirm, string cancelButtonText = null, string confirmButtonText = null, Action onClose = null, Action onCancel = null, bool dismissible = true, bool cancellable = true, string dialogTag = "")
		{
			TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
			viewModel.ShowSimpleConfirmationDialog(title, message, async delegate
			{
				await Task.Run(delegate
				{
					onConfirm?.Invoke();
				});
				return (object)null;
			}, cancelButtonText, confirmButtonText, onClose, onCancel, dismissible, cancellable, dialogTag, taskCompletionSource);
			return await taskCompletionSource.Task;
		}

