	public interface IConsoleStateAwaiter
	{
		IConsoleStateAwaiter FromCurrentState(ConsoleState consoleState);

		IConsoleStateAwaiter AfterConsoleCommand(Action action);

		IConsoleStateAwaiter WithTimeout(TimeSpan timeSpan);

		IConsoleStateAwaiter WithSkipCondition(bool condition);

		Task Run();
	}
	public class ConsoleStateAwaiterFactory
	{
		private class ConsoleStateAwaiter : IConsoleStateAwaiter
		{
			private const int DefaultTimeoutSeconds = 15;

			private ConsoleState startingConsoleState;

			private Action startCommand;

			private TimeSpan timeout = TimeSpan.FromSeconds(15.0);

			private bool skipCondition;

			public IConsoleStateAwaiter FromCurrentState(ConsoleState consoleState)
			{
				startingConsoleState = consoleState;
				return this;
			}

			public IConsoleStateAwaiter AfterConsoleCommand(Action action)
			{
				startCommand = action;
				return this;
			}

			public IConsoleStateAwaiter WithTimeout(TimeSpan timeSpan)
			{
				timeout = timeSpan;
				return this;
			}

			public IConsoleStateAwaiter WithSkipCondition(bool condition)
			{
				skipCondition = condition;
				return this;
			}

			public async Task Run()
			{
				startCommand?.Invoke();
				ICurrentConsoleService currentConsoleService = Mvx.Resolve<ICurrentConsoleService>();
				Task<StateChange> task = currentConsoleService.ActiveConsole.WhenStateChanged.Where((StateChange x) => x.Current == startingConsoleState).Take(1).Timeout(timeout)
					.ToTask();
				if (skipCondition)
				{
					try
					{
						await task.ConfigureAwait(continueOnCapturedContext: false);
					}
					catch (TimeoutException exception)
					{
						Log.Error("Ble", $"Awaiting console state change from state \"{startingConsoleState}\" timed out", exception);
					}
				}
			}
		}

		public static IConsoleStateAwaiter Builder()
		{
			return new ConsoleStateAwaiter();
		}
	}
	public static class ConsoleStateExtensions
	{
