			}
			return false;
		}
	}
	public class CpuUtilizationReport : UtilizationReport
	{
		public virtual CpuUtilizationReportSection Warmup { get; private set; }

		public virtual CpuUtilizationReportSection InWorkout { get; private set; }

		public virtual CpuUtilizationReportSection Cooldown { get; private set; }

		public virtual int CpuHighUsageThreshold { get; private set; }

		public CpuUtilizationReport(TimeSpan samplingInterval, int cpuHighUsageThreshold)
			: base(samplingInterval)
		{
			Warmup = new CpuUtilizationReportSection();
			InWorkout = new CpuUtilizationReportSection();
			Cooldown = new CpuUtilizationReportSection();
			CpuHighUsageThreshold = cpuHighUsageThreshold;
		}
	}
	public class CpuUtilizationReportSection
	{
		public virtual int NumSamples { get; private set; }

		public virtual long SamplesOverHighUsageThreshold { get; private set; }

		public virtual double StartingCpuUtil { get; private set; }

		public virtual double AvgCpuUtil { get; private set; }

		public virtual double MaxCpuUtil { get; private set; }

		public void AddSample(double cpuUtilization, int cpuHighUsageThreshold)
		{
			if (NumSamples == 0)
			{
				StartingCpuUtil = cpuUtilization;
			}
			int numSamples = NumSamples;
			NumSamples = numSamples + 1;
			AvgCpuUtil += (cpuUtilization - AvgCpuUtil) / (double)NumSamples;
			MaxCpuUtil = Math.Max(MaxCpuUtil, cpuUtilization);
			if (cpuUtilization > (double)cpuHighUsageThreshold)
			{
				long samplesOverHighUsageThreshold = SamplesOverHighUsageThreshold;
				SamplesOverHighUsageThreshold = samplesOverHighUsageThreshold + 1;
			}
		}

		public void Reset()
		{
			NumSamples = 0;
			SamplesOverHighUsageThreshold = 0L;
			StartingCpuUtil = 0.0;
			AvgCpuUtil = 0.0;
			MaxCpuUtil = 0.0;
		}
	}
