	public interface IBlobCacheFileManager
	{
		void NukeSQLDB();

		void NukeCacheDir(BlobCacheType cacheType);

		bool NukeCacheDirIfTooLarge(BlobCacheType cacheType, int maxSizeInBytes);

		void CorruptCache(BlobCacheType cacheType);

		void LogCacheInformation();
	}
	public enum BlobCacheType
	{
		Secure,
		LocalMachine
	}
	public abstract class BlobCacheFileManagerBase : IBlobCacheFileManager
	{
		protected const string Tag = "CacheFileManager";

		public void NukeSQLDB()
		{
			Log.Trace("CacheFileManager", "Attempting to nuke SQL DB");
			List<string> files = GetCacheFiles(BlobCacheType.LocalMachine).Concat(GetCacheFiles(BlobCacheType.Secure)).ToList();
			NukeFiles(files);
		}

		public void NukeCacheDir(BlobCacheType cacheType)
		{
			Log.Trace("CacheFileManager", $"Attempting to nuke {cacheType} cache & its SQL DB");
			IEnumerable<string> cacheFiles = GetCacheFiles(cacheType);
			NukeFiles(cacheFiles);
		}

		public bool NukeCacheDirIfTooLarge(BlobCacheType cacheType, int maxSizeInBytes)
		{
			IEnumerable<string> cacheFiles = GetCacheFiles(cacheType);
			if (GetCacheFilesSize(cacheType) > maxSizeInBytes)
			{
				Log.Trace("CacheFileManager", $"Should delete {cacheType} files because they're too big");
				DeleteFiles(cacheFiles);
				return true;
			}
			return false;
		}

		public void CorruptCache(BlobCacheType cacheType)
		{
			string cacheDir = GetCacheDir(cacheType);
			if (cacheType == BlobCacheType.Secure)
			{
				CorruptCache(cacheDir, "secret.db");
			}
			else
			{
				CorruptCache(cacheDir, "blobs.db");
			}
		}

		public void LogCacheInformation()
		{
			GetCacheFilesSize(BlobCacheType.LocalMachine, null, logInfo: true);
			GetCacheFilesSize(BlobCacheType.Secure, null, logInfo: true);
			LogDriveInfo();
		}

		private void NukeFiles(IEnumerable<string> files)
		{
			if (files.IsNullOrEmpty())
			{
				Log.Trace("CacheFileManager", "Not nuking because there are no files to nuke.");
				return;
			}
			Log.Trace("CacheFileManager", "########## NUKING SQLITE DB ##########");
			DeleteFiles(files);
			Log.Trace("CacheFileManager", "Nuke complete");
		}

		protected abstract string GetCacheDir(BlobCacheType cacheType);

		protected abstract IEnumerable<string> GetCacheFiles(BlobCacheType cacheType);

		protected abstract long GetCacheFilesSize(BlobCacheType cacheType, IEnumerable<string> files = null, bool logInfo = false);

		protected abstract void DeleteFiles(IEnumerable<string> files);

		protected abstract void CorruptCache(string cacheDir, string dbFilename);

		protected abstract void LogDriveInfo();
	}
