	public class InWorkoutHeaderPageViewMapper
	{
		private readonly Dictionary<InWorkoutHeaderHudType, Type> mappings;

		public InWorkoutHeaderPageViewMapper(IEnumerable<Type> assemblyTypes)
		{
			mappings = new Dictionary<InWorkoutHeaderHudType, Type>();
			Dictionary<string, Type> dictionary = assemblyTypes.Where((Type x) => x.Name.EndsWith("HeaderPageViewModel", StringComparison.Ordinal)).ToDictionary((Type x) => x.Name, (Type x) => x, StringComparer.CurrentCultureIgnoreCase);
