	public static class InWorkoutUserMarker
	{
		private static readonly SemaphoreSlim addMarkerSemaphore = new SemaphoreSlim(1, 1);

		public static async Task UpdateMarker(IMap map, object sender, PropertyChangedEventArgs args, Dictionary<string, IMarker> userMap, bool isLoaded, bool isActive, byte[] iconBytes = null)
		{
			await addMarkerSemaphore.WaitAsync();
			if (!(sender is IUserPositionUpdate userUpdate) || !isLoaded || !isActive || args.PropertyName != "Location")
			{
				addMarkerSemaphore.Release();
				return;
			}
			if (!userMap.ContainsKey(userUpdate.UserId))
			{
				userMap.Add(value: (iconBytes != null) ? (await map.AddMarker(userUpdate.Location, iconBytes, isVisible: true, 0.5f, 0.75f)) : (await map.AddMarker(userUpdate.Location, "https://s3.amazonaws.com/ifit-wolf/release/assets/updateIcon.png")), key: userUpdate.UserId);
			}
			else
			{
				IMarker marker = userMap[userUpdate.UserId];
				marker.Location = userUpdate.Location;
			}
			addMarkerSemaphore.Release();
		}
	}
	public interface IOverlayNotifier
	{
		bool AnyOverlayShowing { get; }

		IObservable<bool> OnAnyOverlayShowing { get; }

		void SetIsShowing(OverlayType type, bool isShowing);
	}
	public class OverlayNotifier : IOverlayNotifier
	{
		private readonly HashSet<OverlayType> _showingOverlays = new HashSet<OverlayType>();

		private readonly Subject<bool> _onAnyOverlayShowing = new Subject<bool>();

		public bool AnyOverlayShowing => _showingOverlays.Any();

		public IObservable<bool> OnAnyOverlayShowing => _onAnyOverlayShowing;

		public void SetIsShowing(OverlayType type, bool isShowing)
		{
			if (isShowing)
			{
				if (_showingOverlays.Add(type) && _showingOverlays.Count == 1)
				{
					_onAnyOverlayShowing.OnNext(value: true);
				}
			}
			else if (_showingOverlays.Remove(type) && _showingOverlays.Count == 0)
			{
				_onAnyOverlayShowing.OnNext(value: false);
			}
		}
	}
	public enum OverlayType
	{
		Pause,
		Volume,
		Music
	}
