	public static class LogScreenStatModelHelper
	{
		private const string Tag = "LogScreen";

		public static LogScreenStatModel Create(StatInfoLabelType type, ActivityLog log, bool isMetric)
		{
			bool flag = false;
			if (Mvx.TryResolve<IFeatureFlagManager>(out var service))
			{
				flag = service.IsFeatureEnabled(FeatureFlags.WolfUseOfflinePostworkoutWebview);
			}
			try
			{
				LogScreenStatModel logScreenStatModel = SetupLabelAndUnits(type, isMetric);
				switch (type)
				{
				case StatInfoLabelType.Time:
				{
					int seconds = (int)((float)log.Duration / 1000f);
					return GetTimeStats(logScreenStatModel, seconds);
				}
				case StatInfoLabelType.Distance:
					return GetDistanceStats(logScreenStatModel, (log.Summary?.TotalMeters).GetValueOrDefault(), isMetric);
				case StatInfoLabelType.DistanceInMeters:
					return GetDistanceInMetersStats(logScreenStatModel, (log.Summary?.TotalMeters).GetValueOrDefault());
				case StatInfoLabelType.Pace:
				{
					double paceFrom = PaceMetricBase.GetPaceFrom(SpeedUnit.Mps, isMetric, (log.Stats?.Meters != null) ? GetAverageMpsFromDistance(log.Stats?.Meters) : GetAverage(log.Stats?.Mps));
					double paceFrom2 = PaceMetricBase.GetPaceFrom(SpeedUnit.Mps, isMetric, GetMax(log.Stats?.Mps));
					paceFrom2 = Math.Min(paceFrom2, paceFrom);
					return GetPaceStats(logScreenStatModel, paceFrom, paceFrom2, isMetric);
				}
				case StatInfoLabelType.Calories:
					return GetCalorieStats(logScreenStatModel, (int)(log.Summary?.TotalCalories).GetValueOrDefault());
				case StatInfoLabelType.Incline:
					return GetInclineStats(logScreenStatModel, GetAverage(log.Stats?.Incline), GetMax(log.Stats?.Incline));
				case StatInfoLabelType.HeartRate:
					if (log.Stats.Bpm != null)
					{
						List<ActivityLog.StatGroup.Stat> stats = log.Stats.Bpm.Where((ActivityLog.StatGroup.Stat x) => !x.Value.Value.AlmostEqual(0.0))?.ToList();
						return GetHeartRateStats(logScreenStatModel, (int)GetAverage(stats), (int)GetMax(log.Stats.Bpm));
					}
					return GetHeartRateStats(logScreenStatModel, (int)(log.Summary?.AverageBpm).GetValueOrDefault(), Math.Max(0, (int)(log.Summary?.AverageBpm).GetValueOrDefault()));
				case StatInfoLabelType.Speed:
				{
					double num = UnitUtil.Ensure(SpeedUnit.Mps, isMetric ? SpeedUnit.Kph : SpeedUnit.Mph, (log.Stats?.Meters != null) ? GetAverageMpsFromDistance(log.Stats?.Meters) : GetAverage(log.Stats?.Mps));
					double val = UnitUtil.Ensure(SpeedUnit.Mps, isMetric ? SpeedUnit.Kph : SpeedUnit.Mph, GetMax(log.Stats?.Mps));
					val = Math.Max(val, num);
					return GetSpeedStats(logScreenStatModel, num, val);
				}
				case StatInfoLabelType.Watts:
					return GetWattsStats(logScreenStatModel, (int)GetAverage(log.Stats?.Watts), Math.Max((int)GetMax(log.Stats?.Watts), (int)GetAverage(log.Stats?.Watts)));
				case StatInfoLabelType.Elevation:
				{
					double elevationInUnits;
					double elevationInUnits2;
					if (log.Stats.Elevation != null)
					{
						if (!log.Stats.Elevation.Any())
						{
							return null;
						}
						List<double> changes = log.Stats.Elevation.Select((ActivityLog.StatGroup.Stat x) => x.Value.Value)?.ToList();
						elevationInUnits = GetElevationInUnits(isMetric, GetElevationChanges(changes, increasing: true).Sum());
						elevationInUnits2 = GetElevationInUnits(isMetric, GetElevationChanges(changes, increasing: false).Sum());
					}
					else
					{
						elevationInUnits = GetElevationInUnits(isMetric, (log.Summary?.TotalElevationGain).GetValueOrDefault());
						elevationInUnits2 = GetElevationInUnits(isMetric, (log.Summary?.TotalElevationLoss).GetValueOrDefault());
					}
					return GetElevationStats(logScreenStatModel, elevationInUnits, Math.Abs(elevationInUnits2));
				}
				case StatInfoLabelType.Cadence:
					return GetCadenceStats(logScreenStatModel, (int)GetAverage(log.Stats?.Rpm), (int)GetMax(log.Stats?.Rpm));
				case StatInfoLabelType.VerticalGain:
				{
					double elevation = ((!log.Stats.Elevation.Any()) ? 0.0 : (log.Stats?.Elevation.Max((ActivityLog.StatGroup.Stat x) => x.Value)).Value);
					return GetVerticalGainStats(logScreenStatModel, GetElevationInUnits(isMetric, elevation));
				}
				case StatInfoLabelType.Grade:
					return GetGradeStats(logScreenStatModel, GetMax(log.Stats?.Incline));
				case StatInfoLabelType.StrokesPerMin:
					return GetSpmStats(logScreenStatModel, (int)GetAverage(log.Stats?.Spm), Math.Max((int)GetMax(log.Stats?.Spm), (int)GetAverage(log.Stats?.Spm)));
				case StatInfoLabelType.FiveHundred:
				{
					int valueOrDefault = ((int?)log.Stats?.AverageFiveHundredSplit.Last()?.Value).GetValueOrDefault();
					return GetFiveHundredStat(logScreenStatModel, valueOrDefault, Math.Min((int)GetMinWithoutZeros(log.Stats?.FiveHundredSplit), valueOrDefault));
				}
				case StatInfoLabelType.Resistance:
					if (!flag)
					{
						return null;
					}
					if (log.Stats.Resistance != null)
					{
						List<ActivityLog.StatGroup.Stat> stats2 = log.Stats.Resistance.Where((ActivityLog.StatGroup.Stat x) => !x.Value.Value.AlmostEqual(0.0))?.ToList();
						return GetResistanceStats(logScreenStatModel, (int)GetAverage(stats2), (int)GetMax(log.Stats.Resistance));
					}
					return logScreenStatModel;
				case StatInfoLabelType.XScore:
					return flag ? GetXScoreStats(logScreenStatModel, (int)GetAverage(log.Stats?.XScore)) : null;
				case StatInfoLabelType.TotalReps:
					return flag ? GetTotalRepsStats(logScreenStatModel, log.Stats.Reps.Count) : null;
				default:
					return null;
				}
			}
			catch (Exception exception)
			{
				Log.Error("LogScreen", $"Failed to generate stat of type {type}", exception);
				return null;
			}
		}

		private static LogScreenStatModel GetTotalRepsStats(LogScreenStatModel model, int count)
		{
			model.MainValue = count.ToString();
			return model;
		}

