		private static LogScreenStatModel GetPaceStats(LogScreenStatModel model, double avgPace, double? bestPace, bool isMetric)
		{
			if (avgPace.AlmostEqual(0.0) && bestPace == 0.0)
			{
				return null;
			}
			model.MainValue = StatInfoLabelType.Pace.GetFormattedValue(avgPace);
			model.MainUnits = GetPaceUnits(isMetric, avgPace >= 3600.0);
			if (bestPace.HasValue && (!avgPace.AlmostEqual(0.0) || !bestPace.Value.AlmostEqual(0.0)))
			{
				model.LeftValue = StatInfoLabelType.Pace.GetFormattedValue(bestPace.Value);
				model.LeftUnits = GetPaceUnits(isMetric, bestPace >= 3600.0);
				return model;
			}
			model.ResetLeftAndRightValues();
			return model;
		}

