		private static LogScreenStatModel SetupLabelAndUnits(StatInfoLabelType type, bool isMetric)
		{
			LogScreenStatModel logScreenStatModel = new LogScreenStatModel
			{
				StatType = type
			};
			switch (type)
			{
			case StatInfoLabelType.Time:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.time.ToUpper();
				break;
			case StatInfoLabelType.Distance:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.distance.ToUpper();
				logScreenStatModel.MainUnits = (isMetric ? Wolf.Core.Resources.AppStrings.km : Wolf.Core.Resources.AppStrings.mi).ToUpper();
				break;
			case StatInfoLabelType.DistanceInMeters:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.distance.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.m.ToUpper();
				break;
			case StatInfoLabelType.Pace:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.avg_pace.ToUpper();
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.best.ToUpper();
				break;
			case StatInfoLabelType.Calories:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.calorie_burn.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.cals.ToUpper();
				break;
			case StatInfoLabelType.Incline:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.AVG_INCLINE.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.percent;
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.best.ToUpper();
				logScreenStatModel.LeftUnits = Wolf.Core.Resources.AppStrings.percent;
				break;
			case StatInfoLabelType.HeartRate:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.AVG_HEART_RATE.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.bpm.ToUpper();
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.max.ToUpper();
				logScreenStatModel.LeftUnits = Wolf.Core.Resources.AppStrings.bpm.ToUpper();
				break;
			case StatInfoLabelType.Speed:
			{
				string text3 = (isMetric ? Wolf.Core.Resources.AppStrings.kph : Wolf.Core.Resources.AppStrings.mph).ToUpper();
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.avg_speed.ToUpper();
				logScreenStatModel.MainUnits = text3;
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.max.ToUpper();
				logScreenStatModel.LeftUnits = text3;
				break;
			}
			case StatInfoLabelType.Watts:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.AVG_WATTS.ToUpper();
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.max.ToUpper();
				break;
			case StatInfoLabelType.Elevation:
			{
				string text2 = (isMetric ? Wolf.Core.Resources.AppStrings.m : Wolf.Core.Resources.AppStrings.ft).ToUpper();
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.elevation_gain.ToUpper();
				logScreenStatModel.MainUnits = text2;
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.loss.ToUpper();
				logScreenStatModel.LeftUnits = text2;
				logScreenStatModel.RightLabel = Wolf.Core.Resources.AppStrings.net.ToUpper();
				logScreenStatModel.RightUnits = text2;
				break;
			}
			case StatInfoLabelType.Cadence:
			{
				string text = Wolf.Core.Resources.AppStrings.rpm.ToUpper();
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.avg_cadence.ToUpper();
				logScreenStatModel.MainUnits = text;
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.best.ToUpper();
				logScreenStatModel.LeftUnits = text;
				break;
			}
			case StatInfoLabelType.VerticalGain:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.vertical_gain.ToUpper();
				logScreenStatModel.MainUnits = (isMetric ? Wolf.Core.Resources.AppStrings.m : Wolf.Core.Resources.AppStrings.ft).ToUpper();
				break;
			case StatInfoLabelType.Grade:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.max_grade.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.percent;
				break;
			case StatInfoLabelType.StrokesPerMin:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.AVG_SPM.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.spm;
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.best.ToUpper();
				logScreenStatModel.LeftUnits = Wolf.Core.Resources.AppStrings.spm;
				break;
			case StatInfoLabelType.FiveHundred:
				logScreenStatModel.MainLabel = Wolf.Core.Resources.AppStrings.AVG_FIVEHUNDRED.ToUpper();
				logScreenStatModel.MainUnits = Wolf.Core.Resources.AppStrings.fivehundredunit;
				logScreenStatModel.LeftLabel = Wolf.Core.Resources.AppStrings.best.ToUpper();
				logScreenStatModel.LeftUnits = Wolf.Core.Resources.AppStrings.fivehundredunit;
				break;
			default:
				return null;
			case StatInfoLabelType.Resistance:
			case StatInfoLabelType.XScore:
			case StatInfoLabelType.TotalReps:
				break;
			}
			return logScreenStatModel;
		}

		private static List<double> GetElevationChanges(List<double> changes, bool increasing)
		{
			List<double> list = new List<double>();
			for (int i = 1; i < changes.Count; i++)
			{
				double num = changes[i - 1];
				double num2 = changes[i];
				double item = num2 - num;
				if (increasing && num2 > num)
				{
					list.Add(item);
				}
				else if (!increasing && num2 < num)
				{
					list.Add(item);
				}
			}
			return list;
		}

		private static string GetPaceUnits(bool isMetric, bool isSlowPace)
		{
			if (isMetric)
			{
				return (isSlowPace ? Wolf.Core.Resources.AppStrings.hrs_per_km : Wolf.Core.Resources.AppStrings.min_per_km).ToUpper();
			}
			return (isSlowPace ? Wolf.Core.Resources.AppStrings.hrs_per_mi : Wolf.Core.Resources.AppStrings.min_per_mi).ToUpper();
		}

		private static double GetMax(List<ActivityLog.StatGroup.Stat> stats)
		{
			return (stats.IsNullOrEmpty() ? new double?(0.0) : stats.Max((ActivityLog.StatGroup.Stat x) => x.Value)).Value;
		}

		private static double GetMinWithoutZeros(List<ActivityLog.StatGroup.Stat> stats)
		{
			if (stats.IsNullOrEmpty())
			{
				return 0.0;
			}
			IEnumerable<ActivityLog.StatGroup.Stat> enumerable = stats.Where((ActivityLog.StatGroup.Stat x) => !x.Value.Value.AlmostEqual(0.0, 3));
			return ((enumerable.CountSafe() == 0) ? new double?(0.0) : enumerable.Min((ActivityLog.StatGroup.Stat x) => x.Value)).Value;
		}

		private static double GetAverage(List<ActivityLog.StatGroup.Stat> stats)
		{
			if (stats.IsNullOrEmpty())
			{
				return 0.0;
			}
			if (stats.Count == 1)
			{
				return stats.First().Value.Value;
			}
			double num = 0.0;
			for (int i = 1; i < stats.Count; i++)
			{
				ActivityLog.StatGroup.Stat stat = stats[i - 1];
				ActivityLog.StatGroup.Stat stat2 = stats[i];
				num += ((double)(stat2.Offset - stat.Offset) * stat.Value).Value;
			}
			long num2 = stats.Last().Offset - stats.First().Offset;
			if (num2 != 0L)
			{
				return num / (double)num2;
			}
			return 0.0;
		}

		private static double GetAverageMpsFromDistance(List<ActivityLog.StatGroup.Stat> stats)
		{
			if (stats.IsNullOrEmpty())
			{
				return 0.0;
			}
			int count = stats.Count;
			if (count < 2)
			{
				return 0.0;
			}
			ActivityLog.StatGroup.Stat stat = stats.Last();
			if (stat.Value.GetValueOrDefault().AlmostEqual(0.0))
			{
				stat = stats[count - 2];
			}
			double? value = stat.Value;
			long offset = stat.Offset;
			return Math.Max(value.GetValueOrDefault() / (double)(offset / 1000), 0.0);
		}
	}
	public class MemoryUtilizationReport : UtilizationReport
	{
		public class MemoryUtilizationReportSection
		{
			public int NumberOfSamples { get; private set; }

			public virtual MemorySample StartingSample { get; private set; } = new MemorySample();

			public virtual MemorySample AverageValues { get; private set; } = new MemorySample();

			public virtual MemorySample MaxValues { get; private set; } = new MemorySample();

			public void AddSample(MemorySample memorySample)
			{
				if (NumberOfSamples == 0)
				{
					StartingSample = memorySample;
				}
				NumberOfSamples++;
				UpdateAverages(memorySample);
				UpdateMaxValues(memorySample);
			}

			public void Reset()
			{
				NumberOfSamples = 0;
				StartingSample.Reset();
				AverageValues.Reset();
				MaxValues.Reset();
			}

			private void UpdateAverages(MemorySample memorySample)
			{
				AverageValues.AndroidAvailableMemoryKb += (memorySample.AndroidAvailableMemoryKb - AverageValues.AndroidAvailableMemoryKb) / NumberOfSamples;
				AverageValues.AndroidTotalPrivateDirtyKb += (memorySample.AndroidTotalPrivateDirtyKb - AverageValues.AndroidTotalPrivateDirtyKb) / NumberOfSamples;
				AverageValues.AndroidTotalProportionalSetSizeKb += (memorySample.AndroidTotalProportionalSetSizeKb - AverageValues.AndroidTotalProportionalSetSizeKb) / NumberOfSamples;
				AverageValues.LinuxResidentSetSizePages += (memorySample.LinuxResidentSetSizePages - AverageValues.LinuxResidentSetSizePages) / NumberOfSamples;
				AverageValues.MonoTotalManagedMemoryKb += (memorySample.MonoTotalManagedMemoryKb - AverageValues.MonoTotalManagedMemoryKb) / NumberOfSamples;
			}

			private void UpdateMaxValues(MemorySample memorySample)
			{
				MaxValues.AndroidAvailableMemoryKb = Math.Max(MaxValues.AndroidAvailableMemoryKb, memorySample.AndroidAvailableMemoryKb);
				MaxValues.AndroidTotalPrivateDirtyKb = Math.Max(MaxValues.AndroidTotalPrivateDirtyKb, memorySample.AndroidTotalPrivateDirtyKb);
				MaxValues.AndroidTotalProportionalSetSizeKb = Math.Max(MaxValues.AndroidTotalProportionalSetSizeKb, memorySample.AndroidTotalProportionalSetSizeKb);
				MaxValues.LinuxResidentSetSizePages = Math.Max(MaxValues.LinuxResidentSetSizePages, memorySample.LinuxResidentSetSizePages);
				MaxValues.MonoTotalManagedMemoryKb = Math.Max(MaxValues.MonoTotalManagedMemoryKb, memorySample.MonoTotalManagedMemoryKb);
			}
		}

		public class MemorySample
		{
			public virtual int AndroidTotalProportionalSetSizeKb { get; set; }

			public virtual int AndroidTotalPrivateDirtyKb { get; set; }

			public virtual long AndroidAvailableMemoryKb { get; set; }

			public virtual long LinuxResidentSetSizePages { get; set; }

			public virtual long MonoTotalManagedMemoryKb { get; set; }

			public void Reset()
			{
				AndroidTotalProportionalSetSizeKb = 0;
				AndroidTotalPrivateDirtyKb = 0;
				AndroidAvailableMemoryKb = 0L;
				LinuxResidentSetSizePages = 0L;
				MonoTotalManagedMemoryKb = 0L;
			}
		}

		public virtual MemoryUtilizationReportSection Warmup { get; private set; }

		public virtual MemoryUtilizationReportSection InWorkout { get; private set; }

		public virtual MemoryUtilizationReportSection Cooldown { get; private set; }

		public virtual long AndroidTotalMemoryKb { get; set; }

		public virtual long AndroidThresholdMemoryKb { get; set; }

		public MemoryUtilizationReport(TimeSpan samplingInterval)
			: base(samplingInterval)
		{
			Warmup = new MemoryUtilizationReportSection();
			InWorkout = new MemoryUtilizationReportSection();
			Cooldown = new MemoryUtilizationReportSection();
		}
	}
	public class MinimumTimeSubject<T> : SubjectBase<T>
	{
		private readonly TimeSpan delay;

		private readonly Subject<T> itemReceived = new Subject<T>();

		private readonly List<T> queueItems = new List<T>();

		private readonly object lockObj = new object();

		protected DateTime lastItemSent;

		private IDisposable delayTimerSub;

		public override bool HasObservers => itemReceived.HasObservers;

		public override bool IsDisposed => itemReceived.IsDisposed;

		public MinimumTimeSubject(TimeSpan delay)
		{
			this.delay = delay;
			lastItemSent = Now();
		}

		public override void Dispose()
		{
			delayTimerSub?.Dispose();
			delayTimerSub = null;
			itemReceived.Dispose();
		}

		public override void OnCompleted()
		{
			itemReceived.OnCompleted();
		}

		public override void OnError(Exception error)
		{
			itemReceived.OnError(error);
		}

		public override void OnNext(T value)
		{
			lock (lockObj)
			{
				TimeSpan timeSpan = Now() - lastItemSent;
				if (timeSpan >= delay)
				{
					lastItemSent = Now();
					itemReceived.OnNext(value);
					return;
				}
				queueItems.Add(value);
				if (delayTimerSub == null)
				{
					DateTime dateTime = lastItemSent + delay;
					delayTimerSub = Observable.Timer(dateTime).Subscribe(delegate
					{
						DelayTimerOnNext();
					});
				}
			}
		}

		private void DelayTimerOnNext()
		{
			delayTimerSub?.Dispose();
			delayTimerSub = null;
			foreach (T queueItem in queueItems)
			{
				itemReceived.OnNext(queueItem);
			}
		}

		public override IDisposable Subscribe(IObserver<T> observer)
		{
			return itemReceived.Subscribe(observer);
		}

		protected virtual DateTime Now()
		{
			return DateTime.Now;
		}
	}
