	public class StartPeriodicDataTimingReportSection
	{
		public class ElapsedStats
		{
			public virtual int Count { get; set; }

			public virtual double Avg { get; set; }

			public virtual double Min { get; set; }

			public virtual double Max { get; set; }

			public void Reset()
			{
				Count = 0;
				Avg = 0.0;
				Min = 0.0;
				Max = 0.0;
			}
		}

		private readonly SemaphoreSlim thresholdLock = new SemaphoreSlim(1, 1);

		private readonly string name;

		private List<int> _thresholds;

		private readonly ConcurrentDictionary<int, ElapsedStats> statsByThreshold = new ConcurrentDictionary<int, ElapsedStats>();

		private readonly ElapsedStats overallStats = new ElapsedStats();

		public List<int> Thresholds
		{
			get
			{
				return _thresholds;
			}
			set
			{
				_thresholds = value;
				_thresholds?.ForEach(delegate(int threshold)
				{
					statsByThreshold.TryAdd(threshold, new ElapsedStats());
				});
			}
		}

		public StartPeriodicDataTimingReportSection(string name)
		{
			this.name = name;
		}

		public void AddSample(long elapsedMs)
		{
			try
			{
				thresholdLock.Wait();
				foreach (int threshold in Thresholds)
				{
					if (statsByThreshold.TryGetValue(threshold, out var value) && elapsedMs > threshold)
					{
						UpdateStats(value, elapsedMs);
						break;
					}
				}
				UpdateStats(overallStats, elapsedMs);
			}
			finally
			{
				thresholdLock.Release();
			}
		}

		private void UpdateStats(ElapsedStats stats, long elapsedMs)
		{
			if (stats.Count == 0)
			{
				stats.Min = elapsedMs;
				stats.Max = elapsedMs;
			}
			stats.Count++;
			stats.Avg += ((double)elapsedMs - stats.Avg) / (double)stats.Count;
			stats.Min = Math.Min(stats.Min, elapsedMs);
			stats.Max = Math.Max(stats.Max, elapsedMs);
		}

		public override string ToString()
		{
			StringBuilder sb = new StringBuilder();
			Thresholds?.ForEach(delegate(int threshold)
			{
				if (statsByThreshold.TryGetValue(threshold, out var value))
				{
					if (value.Count == 0)
					{
						statsByThreshold[threshold].Reset();
					}
					sb.AppendLine($">{threshold}ms,{value.Min:F3},{value.Max:F3},{value.Count},{value.Avg:F3}");
				}
			});
			if (overallStats.Count == 0)
			{
				overallStats.Reset();
			}
			sb.AppendLine($"Total,{overallStats.Min:F3},{overallStats.Max:F3},{overallStats.Count},{overallStats.Avg:F3}");
			return sb.ToString();
		}

		public void AddAnalyticsProperties(Dictionary<string, object> properties)
		{
			if (properties == null)
			{
				Log.Debug("Analytics", "Null properties dictionary passed to StartPeriodicDataTimingReport.AddAnalyticsProperties! This should never happen.");
				return;
			}
			properties.Add(name + "Average", overallStats.Avg);
			properties.Add(name + "Max", overallStats.Max);
			foreach (KeyValuePair<int, ElapsedStats> item in statsByThreshold)
			{
				properties.Add($"{name}>{item.Key}SampleCount", item.Value.Count);
			}
		}

		public void Reset()
		{
			overallStats.Reset();
			statsByThreshold.Clear();
		}
	}
	public static class ObservableExtensions
	{
		public static Task WhenCompleted<T>(this IObservable<T> observable)
		{
			TaskCompletionSource<int> tcs = new TaskCompletionSource<int>();
			observable.Subscribe(delegate
			{
			}, delegate(Exception e)
			{
				tcs.SetException(e);
			}, delegate
			{
				tcs.SetResult(0);
			});
			return tcs.Task;
		}
	}
	public class ReportHelper
	{
		private ILocalSettings _localSettings;

		private IDeviceInformation _deviceInformation;

		private IWolfAnalytics _reporter;

		private readonly string eventName;

		private readonly TimeSpan minDurationBetweenReports;

		private DateTime lastReportTime;

		public ILocalSettings LocalSettings
		{
			get
			{
				if (_localSettings == null)
				{
					Mvx.TryResolve<ILocalSettings>(out _localSettings);
				}
				return _localSettings;
			}
		}

		public IDeviceInformation DeviceInformation
		{
			get
			{
				if (_deviceInformation == null)
				{
					Mvx.TryResolve<IDeviceInformation>(out _deviceInformation);
				}
				return _deviceInformation;
			}
		}

		public IWolfAnalytics Reporter
		{
			get
			{
				if (_reporter == null)
				{
					Mvx.TryResolve<IWolfAnalytics>(out _reporter);
				}
				return _reporter;
			}
		}

		public ReportHelper(string eventName, TimeSpan minDurationBetweenReports = default(TimeSpan))
		{
			this.eventName = eventName;
			this.minDurationBetweenReports = ((minDurationBetweenReports == default(TimeSpan)) ? TimeSpan.FromMinutes(15.0) : minDurationBetweenReports);
		}

		public async Task Track(Dictionary<string, object> properties = null)
		{
			if (Reporter != null && DateTime.UtcNow - lastReportTime > minDurationBetweenReports)
			{
				lastReportTime = DateTime.UtcNow;
				try
				{
					await Reporter.Track(eventName, properties);
				}
				catch (Exception ex)
				{
					Log.Error("Analytics", "Failed to report event", ex.GetBaseException());
				}
			}
		}
	}
	public static class ShareWorkoutTextRetriever
	{
		public class ShareWorkoutText
		{
			public string Url { get; set; }

			public string Description { get; set; }
		}

		public static ShareWorkoutText GetShareText(string workoutId, string activityLogId, double distanceMeters, string baseUrl, bool isMetric)
		{
			return new ShareWorkoutText
			{
				Url = GetWorkoutUrl(activityLogId, workoutId, baseUrl),
				Description = GetDescription(isMetric, distanceMeters)
			};
		}

		private static string GetWorkoutUrl(string activityLogId, string workoutId, string baseUrl)
		{
			string text = baseUrl + "/workout";
			return text + ((!string.IsNullOrEmpty(workoutId)) ? ("/" + workoutId) : string.Empty) + ((!string.IsNullOrEmpty(activityLogId)) ? ("/" + activityLogId) : string.Empty);
		}

		private static string GetDescription(bool isMetric, double distanceMeters)
		{
			DistanceUnit distanceUnit = UnitUtil.GetDistanceUnit(isMetric);
			string text = string.Format(Wolf.Core.Resources.AppStrings.share_workout_text, UnitUtil.Ensure(DistanceUnit.M, distanceUnit, distanceMeters), distanceUnit, "@iFIT");
			string share_workout_view_workout = Wolf.Core.Resources.AppStrings.share_workout_view_workout;
			return (text + " " + share_workout_view_workout).Trim();
		}
	}
	public static class StringExtensions
	{
		public static bool IsNullOrEmpty(this string value)
		{
			return string.IsNullOrEmpty(value);
		}

		public static bool IsNullOrWhitespace(this string value)
		{
			return string.IsNullOrWhiteSpace(value);
		}

		public static bool HasValue(this string value)
		{
			return !value.IsNullOrWhitespace();
		}

		public static string Base64Encode(this string plainText)
		{
			byte[] bytes = Encoding.UTF8.GetBytes(plainText);
			return Convert.ToBase64String(bytes);
		}

		public static string ToAsciiHexString(this string value)
		{
			if (value == null)
			{
				return null;
			}
			return BitConverter.ToString(Encoding.ASCII.GetBytes(value));
		}
	}
	public static class TaskExtensions
	{
		public static async Task WithCancellation(this Task task, CancellationToken cancellationToken)
		{
			TaskCompletionSource<bool> taskCompletionSource = new TaskCompletionSource<bool>();
			using (cancellationToken.Register(delegate(object x)
			{
				((TaskCompletionSource<bool>)x).TrySetResult(result: true);
			}, taskCompletionSource))
			{
				if (task != await Task.WhenAny(task, taskCompletionSource.Task))
				{
					throw new OperationCanceledException(cancellationToken);
				}
			}
		}

		public static async Task TimeoutAfter(this Task task, TimeSpan span, CancellationToken token = default(CancellationToken))
		{
			if (task == await Task.WhenAny(task, Task.Delay(span, token)).ConfigureAwait(continueOnCapturedContext: false))
			{
				await task.ConfigureAwait(continueOnCapturedContext: false);
				return;
			}
			token.ThrowIfCancellationRequested();
			throw new TimeoutException();
		}

		public static async Task<T> TimeoutAfter<T>(this Task<T> task, TimeSpan span, CancellationToken token = default(CancellationToken))
		{
			if (task == await Task.WhenAny(task, Task.Delay(span, token)).ConfigureAwait(continueOnCapturedContext: false))
			{
				return await task.ConfigureAwait(continueOnCapturedContext: false);
			}
			token.ThrowIfCancellationRequested();
			throw new TimeoutException();
		}

		public static async void SafeFireAndForget(this Task task, bool continueOnCapturedContext = true, Action<Exception> onException = null)
		{
			try
			{
				await task.ConfigureAwait(continueOnCapturedContext);
			}
			catch (Exception obj) when (onException != null)
			{
				onException(obj);
			}
		}

		public static Task DisposeIfCompleted(this Task task)
		{
			if (task != null && task.IsCompleted)
			{
				task.Dispose();
			}
			return null;
		}

		public static Task<TData> DisposeIfCompleted<TData>(this Task<TData> task)
		{
			if (task != null && task.IsCompleted)
			{
				task.Dispose();
			}
			return null;
		}
	}
