	public static class WorkoutExtensions
	{
		public static FitnessValue ToMetricChangeType(this Workout workout)
		{
			return workout.Target switch
			{
				Workout.TargetType.Calories => FitnessValue.CurrentCalories, 
				Workout.TargetType.Meters => FitnessValue.CurrentDistance, 
				Workout.TargetType.Seconds => FitnessValue.CurrentTime, 
				_ => FitnessValue.CurrentDistance, 
			};
		}

		public static async Task<bool> WorkoutHasPopMusic(this Workout workout, IBlobCache cache, bool ignoreBlankTracks)
		{
			if (string.IsNullOrWhiteSpace(workout?.Metadata?.Audio))
			{
				return false;
			}
			bool hasMusic = false;
			using (WorkoutMusicInfoService musicInfoService = new WorkoutMusicInfoService(workout, cache, automaticallyStartLoad: false))
			{
				try
				{
					await musicInfoService.LoadMusicTracks();
					hasMusic = ((!ignoreBlankTracks) ? musicInfoService.HasMusicTrackInfo : (musicInfoService.MusicTracks?.Any((MusicTrack t) => !string.IsNullOrWhiteSpace(t.Title)) ?? false));
				}
				catch (Exception exception)
				{
					Log.Error("Music", "Could not fetch workout music tracks", exception);
				}
			}
			return hasMusic;
		}

		public static async Task<string> DetermineWorkoutIdToUse(this Workout workout, IIfitApiService ifitApi)
		{
			if (workout.Type != Workout.WorkoutType.Fusion || string.IsNullOrEmpty(workout.WorkoutGroupId))
			{
				return workout.Id;
			}
			try
			{
				return (await WorkoutGroup.Get(ifitApi, workout.WorkoutGroupId, force: true)).WorkoutsOrderedByDifficulty.First().Id;
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Error fetching workoutGroup: (WorkoutGroup " + workout.WorkoutGroupId + ") " + ex.Message + " " + ex.StackTrace);
				return null;
			}
		}
	}
