namespace Wolf.Core.Util.Monitoring
{
	public interface IStartPeriodicDataTimingMonitor
	{
		StartPeriodicDataTimingReport PeriodicDataTimingReport { get; }
	}
	public class StartPeriodicDataTimingMonitor : WorkoutEventMonitor, IStartPeriodicDataTimingMonitor
	{
		private const string LogTag = "StartPeriodicDataTimingMonitor";

		private const string FeatureDisabled = "DISABLED";

		private IDisposable measurementEventSub;

		public bool IsReportEnabled { get; private set; }

		public StartPeriodicDataTimingReport PeriodicDataTimingReport { get; private set; }

		public StartPeriodicDataTimingMonitor()
		{
			Init();
		}

		public virtual void SubscribeToEvents()
		{
			IsReportEnabled = false;
			if (!Mvx.TryResolve<IFeatureFlagManager>(out var service))
			{
				return;
			}
			string text = service.GetString(FeatureFlags.StartPeriodicDataMonitoringThresholds);
			if (text == "DISABLED" || string.IsNullOrWhiteSpace(text))
			{
				return;
			}
			List<int> list = (from x in (from x in text.Split(',')
					where int.TryParse(x, out var _)
					select x).Select(int.Parse)
				orderby x descending
				select x).ToList();
			if (list.Count <= 0)
			{
				return;
			}
			IsReportEnabled = true;
			PeriodicDataTimingReport.SetThresholds(list);
			if (!Mvx.TryResolve<ICurrentConsoleService>(out var service2))
			{
				return;
			}
			measurementEventSub?.Dispose();
			try
			{
				measurementEventSub = service2.ActiveConsole.WhenDataTimerChanged.Subscribe(base.RecordElapsedTime);
			}
			catch (NullReferenceException exception)
			{
				Log.Fatal("StartPeriodicDataTimingMonitor", "Attempted to subscribe to RecordElapsedTime with null console", exception);
			}
		}

		public override void SubscribeToWorkoutTransitions(ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings)
		{
			IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
			if ((activeConsole == null || !activeConsole.IsMock()) && !(activeConsole is EquipmentlessConsoleBase))
			{
				base.SubscribeToWorkoutTransitions(currentConsoleService, workoutSettings);
			}
		}

		public override Task ConsoleStateChangeDetected(MonitoringReportTypes monitoringType)
		{
			if (PeriodicDataTimingReport == null)
			{
				PeriodicDataTimingReport = new StartPeriodicDataTimingReport();
			}
			else if (monitoringType == MonitoringReportTypes.Warmup)
			{
				PeriodicDataTimingReport.Reset();
			}
			if (measurementEventSub == null)
			{
				SubscribeToEvents();
			}
			CurrReportType = monitoringType;
			return Task.CompletedTask;
		}

		public override void AddElapsedSample(long elapsedMs, MonitoringReportTypes reportType)
		{
			switch (reportType)
			{
			case MonitoringReportTypes.Warmup:
				PeriodicDataTimingReport.Warmup.AddSample(elapsedMs);
				break;
			case MonitoringReportTypes.InWorkout:
				PeriodicDataTimingReport.InWorkout.AddSample(elapsedMs);
				break;
			case MonitoringReportTypes.Cooldown:
				PeriodicDataTimingReport.Cooldown.AddSample(elapsedMs);
				break;
			}
		}

		public override void PopulateWorkoutInfo(IWorkoutSettings workoutSettings)
		{
			PeriodicDataTimingReport?.PopulateWorkoutInfo(workoutSettings);
		}

		protected override void StartNewReport()
		{
		}

		protected override void ResetReport()
		{
		}

		protected override async Task FinalizeReport()
		{
			measurementEventSub?.Dispose();
			measurementEventSub = null;
			if (IsReportEnabled)
			{
				Log.Trace("StartPeriodicDataTimingMonitor", "Finalized Report: " + PeriodicDataTimingReport);
			}
			await Task.FromResult(0);
		}
	}
	public class UtilizationReport
	{
		public virtual double SamplingIntervalMs { get; }

		public virtual string WorkoutId { get; set; }

		public virtual string WorkoutCategory { get; set; }

		public virtual bool? IsRecoveryWorkout { get; set; }

		protected UtilizationReport()
		{
		}

		protected UtilizationReport(TimeSpan samplingInterval)
		{
			SamplingIntervalMs = samplingInterval.TotalMilliseconds;
		}

		public void PopulateWorkoutInfo(IWorkoutSettings workoutSettings)
		{
			WorkoutId = workoutSettings?.WorkoutContainer?.Workout?.Id ?? "";
			WorkoutCategory = workoutSettings?.WorkoutContainer?.Workout?.Category().ToString() ?? "";
			IsRecoveryWorkout = workoutSettings?.WorkoutContainer?.IsRecoveryWorkout;
		}
	}
	public abstract class WorkoutEventMonitor : WorkoutMonitor
	{
		public readonly Stopwatch eventStopwatch = new Stopwatch();

		protected MonitoringReportTypes CurrReportType;

		public abstract Task ConsoleStateChangeDetected(MonitoringReportTypes monitoringType);

		public abstract void AddElapsedSample(long elapsedMs, MonitoringReportTypes reportType);

		public override async Task EnteredWarmup()
		{
			await ConsoleStateChangeDetected(MonitoringReportTypes.Warmup).ConfigureAwait(continueOnCapturedContext: false);
		}

		public override async Task EnteredWorkout()
		{
			await ConsoleStateChangeDetected(MonitoringReportTypes.InWorkout).ConfigureAwait(continueOnCapturedContext: false);
		}

		public override async Task EnteredCooldown()
		{
			await ConsoleStateChangeDetected(MonitoringReportTypes.Cooldown).ConfigureAwait(continueOnCapturedContext: false);
		}

		public void RecordElapsedTime(bool start)
		{
			if (start)
			{
				eventStopwatch.Reset();
				eventStopwatch.Start();
			}
			else if (eventStopwatch.IsRunning)
			{
				eventStopwatch.Stop();
				AddElapsedSample(eventStopwatch.ElapsedMilliseconds, CurrReportType);
			}
		}
	}
	public enum MonitoringReportTypes
	{
		Warmup,
		InWorkout,
		Cooldown
	}
	public class MonitoringException : Exception
	{
		public MonitoringException(string message)
			: base(message)
		{
		}
	}
	public abstract class WorkoutMonitor
	{
		protected const int StartingSampleDelayMs = 25;

		protected const string SpaceSeparator = " ";

		protected IDisposable enteredWarmupSub;

		protected IDisposable enteredWorkoutSub;

		protected IDisposable enteredCooldownSub;

		protected IDisposable endOfWorkoutSub;

		public abstract void PopulateWorkoutInfo(IWorkoutSettings workoutSettings);

		protected abstract void StartNewReport();

		protected abstract void ResetReport();

		protected abstract Task FinalizeReport();

		protected void Init()
		{
			if (!Mvx.TryResolve<IWorkoutSettings>(out var workoutSettings) || !Mvx.TryResolve<ICurrentConsoleService>(out var currentConsoleService))
			{
				return;
			}
			if (currentConsoleService.ActiveConsole != null)
			{
				SubscribeToWorkoutTransitions(currentConsoleService, workoutSettings);
				return;
			}
			currentConsoleService.WhenConsoleChanged.SubscribeWithErrorLogging(delegate
			{
				SubscribeToWorkoutTransitions(currentConsoleService, workoutSettings);
			});
		}

		public virtual void UnsubscribeFromWorkoutTransitions()
		{
			enteredWarmupSub?.Dispose();
			enteredWarmupSub = null;
			enteredWorkoutSub?.Dispose();
			enteredWorkoutSub = null;
			enteredCooldownSub?.Dispose();
			enteredCooldownSub = null;
			endOfWorkoutSub?.Dispose();
			endOfWorkoutSub = null;
		}

		public virtual void SubscribeToWorkoutTransitions(ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings)
		{
			if (currentConsoleService?.ActiveConsole != null)
			{
				StartNewReport();
				UnsubscribeFromWorkoutTransitions();
				enteredWarmupSub = currentConsoleService.ActiveConsole.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WarmUp && x.Old != ConsoleState.Paused && x.Old != ConsoleState.Resume).SubscribeAsyncWithErrorLogging(async delegate
				{
					await EnteredWarmup().ConfigureAwait(continueOnCapturedContext: false);
				});
				enteredWorkoutSub = currentConsoleService.ActiveConsole.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Workout && x.Old != ConsoleState.Paused && x.Old != ConsoleState.Resume).SubscribeAsyncWithErrorLogging(async delegate
				{
					await EnteredWorkout().ConfigureAwait(continueOnCapturedContext: false);
				});
				enteredCooldownSub = currentConsoleService.ActiveConsole.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.CoolDown && x.Old != ConsoleState.Resume).SubscribeAsyncWithErrorLogging(async delegate
				{
					await EnteredCooldown().ConfigureAwait(continueOnCapturedContext: false);
				});
				endOfWorkoutSub = currentConsoleService.ActiveConsole.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WorkoutResults).SubscribeAsyncWithErrorLogging(async delegate
				{
					PopulateWorkoutInfo(workoutSettings);
					await EndOfWorkout().ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		public abstract Task EnteredWarmup();

		public abstract Task EnteredWorkout();

		public abstract Task EnteredCooldown();

		public virtual async Task EndOfWorkout()
		{
			await FinalizeReport().ConfigureAwait(continueOnCapturedContext: false);
			ResetReport();
		}
	}
	public abstract class WorkoutPeriodicMonitor : WorkoutMonitor
	{
		private IDisposable periodicSampling;

		protected TimeSpan samplingInterval { get; set; }

		public virtual void TrySetSamplingParams()
		{
		}

		protected virtual async Task AddStartingSample(MonitoringReportTypes reportType)
		{
			await Task.FromResult(0);
		}

		protected virtual void AddSample(MonitoringReportTypes reportType)
		{
		}

		public override void SubscribeToWorkoutTransitions(ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings)
		{
			if (currentConsoleService?.ActiveConsole != null)
			{
				TrySetSamplingParams();
				base.SubscribeToWorkoutTransitions(currentConsoleService, workoutSettings);
			}
		}

		public virtual async Task StartSampling(MonitoringReportTypes reportType)
		{
			if (samplingInterval == default(TimeSpan))
			{
				TrySetSamplingParams();
			}
			if (!(samplingInterval == default(TimeSpan)))
			{
				await AddStartingSample(reportType).ConfigureAwait(continueOnCapturedContext: false);
				periodicSampling?.Dispose();
				periodicSampling = Observable.Interval(samplingInterval).SubscribeWithErrorLogging(delegate
				{
					AddSample(reportType);
				});
			}
		}

		public virtual void StopSampling()
		{
			periodicSampling?.Dispose();
			periodicSampling = null;
		}

		public override async Task EnteredWarmup()
		{
			StopSampling();
			await StartSampling(MonitoringReportTypes.Warmup).ConfigureAwait(continueOnCapturedContext: false);
		}

		public override async Task EnteredWorkout()
		{
			StopSampling();
			await StartSampling(MonitoringReportTypes.InWorkout).ConfigureAwait(continueOnCapturedContext: false);
		}

		public override async Task EnteredCooldown()
		{
			StopSampling();
			await StartSampling(MonitoringReportTypes.Cooldown).ConfigureAwait(continueOnCapturedContext: false);
		}

		public override async Task EndOfWorkout()
		{
			StopSampling();
			await base.EndOfWorkout().ConfigureAwait(continueOnCapturedContext: false);
		}
	}
