namespace Wolf.Core.Util.Downloader
{
	public class DownloadProgress
	{
		public long BytesReceived { get; }

		public long TotalBytes { get; }

		public string Status { get; }

		public DownloadProgress(long bytesReceived, long totalBytes, string status)
		{
			BytesReceived = bytesReceived;
			TotalBytes = totalBytes;
			Status = status;
		}
	}
	public class FileDownloader : IFileDownloader, IDownloader<IObservable<DownloadProgress>>
	{
		private readonly IFileSystem fileSystem;

		private readonly IWebUtils webUtils;

		private readonly Uri sourceUri;

		private readonly string destinationFilePath;

		private readonly string tempDestinationFilePath;

		private readonly CancellationToken cancellationToken;

		private readonly string status;

		private static readonly TimeSpan DownloadPartTimeout = TimeSpan.FromSeconds(15.0);

		private const string tempExtension = ".download";

		private const int FileBufferSize = 8192;

		private HttpResponseMessage response;

		public FileDownloader(IFileSystem fileSystem, IWebUtils webUtils, Uri sourceUri, string destinationFilePath, CancellationToken cancellationToken)
		{
			this.fileSystem = fileSystem;
			this.webUtils = webUtils;
			this.sourceUri = sourceUri;
			this.destinationFilePath = destinationFilePath;
			this.cancellationToken = cancellationToken;
			tempDestinationFilePath = Path.ChangeExtension(destinationFilePath, Path.GetExtension(destinationFilePath) + ".download");
			status = Path.GetFileName(destinationFilePath);
		}

		private async Task<HttpResponseMessage> GetHttpResponse()
		{
			if (response != null)
			{
				return response;
			}
			using (IHttpClient client = webUtils.GetHttpClient())
			{
				response = await client.GetAsync(sourceUri, HttpCompletionOption.ResponseHeadersRead, cancellationToken).TimeoutAfter(DownloadPartTimeout, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				HttpResponseMessage httpResponseMessage = response;
				if (httpResponseMessage == null || !httpResponseMessage.IsSuccessStatusCode)
				{
					throw new WebException("Request was responded to with status code: " + (response?.StatusCode.ToString() ?? "<unknown>"));
				}
				if (response.Content == null)
				{
					throw new WebException("Request was responded to with missing content value.");
				}
			}
			return response;
		}

		public async Task<long> GetDownloadSizeAsync()
		{
			return ((await GetHttpResponse()).Content?.Headers?.ContentLength).GetValueOrDefault();
		}

		public Task<IObservable<DownloadProgress>> DownloadAsync()
		{
			ReplaySubject<DownloadProgress> subject = new ReplaySubject<DownloadProgress>(1);
			Task.Run(async delegate
			{
				try
				{
					await DownloadInternalAsync(subject);
				}
				catch (Exception ex)
				{
					Log.Error("FileDownloader", $"Error downloading {sourceUri}.", ex);
					subject.OnError(ex);
				}
			});
			IObservable<DownloadProgress> result = subject.AsObservable();
			return Task.FromResult(result);
		}

		private async Task DownloadInternalAsync(IObserver<DownloadProgress> observer)
		{
			_ = 3;
			try
			{
				int downloadedBytes = 0;
				long totalBytes = await GetDownloadSizeAsync();
				cancellationToken.ThrowIfCancellationRequested();
				if (fileSystem.FileExists(destinationFilePath))
				{
					if (fileSystem.GetFileSize(destinationFilePath) == totalBytes)
					{
						observer.OnCompleted();
						return;
					}
					fileSystem.DeleteFile(destinationFilePath);
				}
				if (fileSystem.FileExists(tempDestinationFilePath))
				{
					fileSystem.DeleteFile(tempDestinationFilePath);
				}
				string directoryName = Path.GetDirectoryName(tempDestinationFilePath);
				fileSystem.CreateDirectory(directoryName);
				using (Stream destinationStream = fileSystem.OpenFile(tempDestinationFilePath, FileMode.Create))
				{
					using Stream sourceStream = await response.Content.ReadAsStreamAsync().TimeoutAfter(DownloadPartTimeout, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					byte[] buffer = new byte[8192];
					bool doneReading = false;
					while (!doneReading)
					{
						cancellationToken.ThrowIfCancellationRequested();
						int bytesRead = await sourceStream.ReadAsync(buffer, 0, buffer.Length, cancellationToken).TimeoutAfter(DownloadPartTimeout, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						if (bytesRead < 1)
						{
							doneReading = true;
							continue;
						}
						await destinationStream.WriteAsync(buffer, 0, bytesRead, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
						downloadedBytes += bytesRead;
						DownloadProgress value = new DownloadProgress(downloadedBytes, totalBytes, status);
						observer.OnNext(value);
					}
				}
				fileSystem.MoveFile(tempDestinationFilePath, destinationFilePath);
				observer.OnCompleted();
			}
			catch (Exception error)
			{
				observer.OnError(error);
			}
		}
	}
	public interface IFileSystem
	{
