	public interface IDownloader<TResult>
	{
		Task<TResult> DownloadAsync();
	}
	public interface IFileDownloader : IDownloader<IObservable<DownloadProgress>>
	{
		Task<long> GetDownloadSizeAsync();
	}
	public class JsonObjectDownloader<T> : IDownloader<T>
	{
		private readonly IWebUtils webUtils;

		private readonly Uri source;

		public JsonObjectDownloader(IWebUtils webUtils, Uri source)
		{
			this.webUtils = webUtils;
			this.source = source;
		}

		public Task<T> DownloadAsync()
		{
			try
			{
				string value = webUtils.DownloadString(source);
				T result = JsonConvert.DeserializeObject<T>(value);
				return Task.FromResult(result);
			}
			catch (Exception exception)
			{
				Log.Error("JsonObjectDownloader", $"Error downloading {source} as type {typeof(T).Name}.", exception);
				throw;
			}
		}
	}
