	public interface IHttpClient : IDisposable
	{
		HttpRequestHeaders DefaultRequestHeaders { get; }

		Task<HttpResponseMessage> SendAsync(HttpRequestMessage request);

		Task<HttpResponseMessage> GetAsync(Uri requestUri, HttpCompletionOption completionOption, CancellationToken cancellationToken);

		Task<HttpResponseMessage> PostAsync(string requestUri, HttpContent content);
	}
	public class WebUtils : IWebUtils
	{
		private sealed class HttpClient : IHttpClient, IDisposable
		{
			private readonly System.Net.Http.HttpClient client = new System.Net.Http.HttpClient(new NativeMessageHandler());

			HttpRequestHeaders IHttpClient.DefaultRequestHeaders => client.DefaultRequestHeaders;

			public Task<HttpResponseMessage> GetAsync(Uri requestUri, HttpCompletionOption completionOption, CancellationToken cancellationToken)
			{
				return client.GetAsync(requestUri, completionOption, cancellationToken);
			}

			public Task<HttpResponseMessage> PostAsync(string requestUri, HttpContent content)
			{
				return client.PostAsync(requestUri, content);
			}

			public Task<HttpResponseMessage> SendAsync(HttpRequestMessage request)
			{
				return client.SendAsync(request);
			}

			public void Dispose()
			{
				client.Dispose();
			}
		}

		public string DownloadString(Uri address)
		{
			using WebClient webClient = new WebClient();
			return webClient.DownloadString(address);
		}

		public IHttpClient GetHttpClient()
		{
			return new HttpClient();
		}
	}
