namespace Wolf.Core.Util.Dashboard
{
	public class DashboardActivityStatLoader : IDashboardActivityStatLoader
	{
		private readonly IIfitApiService ifitApi;

		public DashboardActivityStatLoader(IIfitApiService ifitApi)
		{
			this.ifitApi = ifitApi;
		}

		public async Task<DashboardUserStats> LoadUserStats(bool isMetric, bool force)
		{
			DateTime startDay = GetWebWeeklyStatsStartDate();
			string[] activityLogTypes = (await ActivityLogType.GetTypes(ifitApi)).Select((ActivityLogType x) => x.Type).ToArray();
			UserStats.Query query = new UserStats.Query
			{
				After = startDay,
				ActivityLogTypes = activityLogTypes,
				WorkoutBased = true
			};
			return new DashboardUserStats(await UserStats.GetMyStats(ifitApi, query, force), isMetric);
		}

		public Task ClearUserStatCache()
		{
			return UserStats.ClearStatCache(ifitApi);
		}

		private DateTime GetWebWeeklyStatsStartDate()
		{
			DateTimeZone zoneOrNull = DateTimeZoneProviders.Tzdb.GetZoneOrNull("America/Denver");
			ZonedDateTime zonedDateTime = new ZonedDateTime(Instant.FromDateTimeUtc(DateTime.UtcNow), zoneOrNull);
			return zonedDateTime.Minus(Duration.FromTimeSpan(new TimeSpan(0, zonedDateTime.Hour, zonedDateTime.Minute, zonedDateTime.Second, zonedDateTime.Millisecond))).Minus(Duration.FromDays(6)).ToDateTimeUtc();
		}
	}
	public static class DashboardNonConnectedUtils
	{
		public static MockType ConvertInitialModalityToMockType(string modality)
		{
			return modality switch
			{
				"treadmill" => MockType.Treadmill, 
				"elliptical" => MockType.Elliptical, 
				"bike" => MockType.Bike, 
				"rower" => MockType.Rower, 
				"strength" => MockType.Strength, 
				"yoga" => MockType.Yoga, 
				"mind" => MockType.Mind, 
				"nutrition" => MockType.Nutrition, 
				"core" => MockType.Core, 
				"sleep" => MockType.Sleep, 
				"stretch" => MockType.Stretch, 
				_ => throw new ArgumentException("modality must match supported values"), 
			};
		}

		public static MockType ConvertSoftwareNumberTypeToMockType(int softwareNumber)
		{
			return softwareNumber switch
			{
				424111 => MockType.Bike, 
				424110 => MockType.Treadmill, 
				424112 => MockType.Rower, 
				424992 => MockType.Strength, 
				424113 => MockType.Elliptical, 
				433917 => MockType.Yoga, 
				433918 => MockType.Mind, 
				433946 => MockType.Nutrition, 
				433947 => MockType.Core, 
				433948 => MockType.Sleep, 
				433949 => MockType.Stretch, 
				_ => throw new ArgumentException("software number must match supported values"), 
			};
		}

		public static MockType GetMockTypeFromConsole(ICurrentConsoleService currentConsoleService)
		{
			ConsoleType? currentConsoleType = currentConsoleService.CurrentConsoleType;
			if (!currentConsoleType.HasValue || currentConsoleType == ConsoleType.Equipmentless)
			{
				return GetMockTypeFromLastKnownConsole(currentConsoleService);
			}
			return GetMockTypeFromCurrentConsole(currentConsoleService);
		}

		private static MockType GetMockTypeFromLastKnownConsole(ICurrentConsoleService currentConsoleService)
		{
			return ConvertConsoleTypeToMockType(currentConsoleService.LastKnownConsoleType);
		}

		private static MockType GetMockTypeFromCurrentConsole(ICurrentConsoleService currentConsoleService)
		{
			if (currentConsoleService.ActiveConsole is INonconnectedFitnessConsole nonconnectedFitnessConsole)
			{
				return nonconnectedFitnessConsole.MockType;
			}
			return ConvertConsoleTypeToMockType(currentConsoleService.CurrentConsoleType);
		}

		public static MockType ConvertConsoleTypeToMockType(ConsoleType? type)
		{
			switch (type)
			{
			case ConsoleType.Treadmill:
			case ConsoleType.InclineTrainer:
				return MockType.Treadmill;
			case ConsoleType.Elliptical:
			case ConsoleType.Strider:
			case ConsoleType.FreeStrider:
			case ConsoleType.VerticalElliptical:
				return MockType.Elliptical;
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return MockType.Bike;
			case ConsoleType.Rower:
				return MockType.Rower;
			case ConsoleType.Equipmentless:
			case ConsoleType.Mirror:
				return MockType.Strength;
			default:
				return MockType.Strength;
			}
		}
	}
