	public abstract class BaseWebViewMethodCallMessage : MvxMessage, IDisposable
	{
		public string MethodCallName { get; private set; }

		public IDictionary<string, string> MethodBody { get; private set; }

		protected BaseWebViewMethodCallMessage(object sender, string methodCallName, IDictionary<string, string> methodBody)
			: base(sender)
		{
			MethodCallName = methodCallName;
			MethodBody = methodBody;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				MethodCallName = null;
				MethodBody?.Clear();
				MethodBody = null;
			}
		}
	}
