				if (workoutStationModel != null && workoutStationModel.PrimarySpecialtyStation()?.IsFeedFm == true)
				{
					return !string.IsNullOrWhiteSpace(FeedFmStations?.PrimarySpecialtyStation()?.StationId);
				}
				return false;
			}
		}

