		public MusicService(IIfitApiService ifitApi, IWolfAnalytics analytics, IFeedFmAnalyticsService feedFmAnalyticsService, IInAppNotificationService inAppNotificationService, IPersistentMusicSettings persistentMusicSettings, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IFeatureFlagManager featureFlagManager, IMediaSettings mediaSettings, IMusicStateService musicStateService, IVolumeControlBehavior volumeControl = null, IMvxMessenger mvxMessenger = null, ICrashReporter crashReporter = null, IFeedFmNativeStationService feedFmNativeStationService = null, IVideoService videoService = null)
		{
			this.ifitApi = ifitApi;
			this.analytics = analytics;
			this.feedFmAnalyticsService = feedFmAnalyticsService;
			this.inAppNotificationService = inAppNotificationService;
			this.persistentMusicSettings = persistentMusicSettings;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
			this.featureFlagManager = featureFlagManager;
			this.mediaSettings = mediaSettings;
			VolumeControl = volumeControl;
			this.mvxMessenger = mvxMessenger;
			this.crashReporter = crashReporter;
			this.feedFmNativeStationService = feedFmNativeStationService;
			this.videoService = videoService;
			messageTokenFeedFmToggled?.Dispose();
			messageTokenFeedFmToggled = mvxMessenger?.Subscribe<InWorkoutMusicControlsViewModel.InWorkoutFeedFmMusicToggledMessage>(delegate
			{
				HandleExternalFeedFmToggleAction();
			});
			MusicStateService = musicStateService;
			if (MusicStateService != null)
			{
				MusicStateService.OnPausedAsync = OnPausedTask;
				MusicStateService.OnPlayingAsync = OnPlayingAsync;
				MusicStateService.OnStoppedAsync = OnStoppedAsync;
				MusicStateService.OnReadyAsync = OnReadyAsync;
				MusicStateService.OnLoadingAsync = OnLoadingAsync;
			}
			else
			{
				Log.Trace("Audio", "MusicStateService is null");
			}
		}

		private void HandleAudioServiceUnhandledError(AudioServiceUnhandledError error)
		{
			Log.Error("MusicService", "Unhandled Error on IAudioService: " + error.Exception.Message, error.Exception.InnerException);
			analytics.InWorkoutMusicUnhandledError(workoutSettings?.WorkoutContainer?.Workout, workoutSettings?.WorkoutContainer?.Media?.Music?.FeedFm?.ActiveState ?? MusicState.Uninitialized, error);
		}

		public void SetUpFeedFmAudioServiceIfAvailable(bool shouldStartFeedFmServiceAutomatically)
		{
			liveWorkoutMusicStateChanged.OnNext(LiveWorkoutMusicState.Other);
			if (HasInitializedAudioService)
			{
				Log.Trace("Audio", "Not setting up Audio Service, service is already initialized");
				return;
			}
			if (!WorkoutHasFeedFmMix)
			{
				Log.Trace("Audio", string.Format("{0}: {1} is {2}. Not assigning {3}.", "SetUpFeedFmAudioServiceIfAvailable", "WorkoutHasFeedFmMix", WorkoutHasFeedFmMix, "FeedFm"));
				if (LegacyMix == null)
				{
					Log.Trace("Audio", "LegacyMix is null.");
					return;
				}
				try
				{
					Log.Trace("Audio", "LegacyMix: " + JsonConvert.SerializeObject(LegacyMix));
					return;
				}
				catch (Exception ex)
				{
					Log.Error("Audio", ex.GetType().Name + " occurred while serializing LegacyMix for logging.", ex);
					return;
				}
			}
			if (FeedFm == null)
			{
				if (!Mvx.TryResolve<IAudioService>(out var service))
				{
					Log.Error("Audio", "SetUpFeedFmAudioServiceIfAvailable: Mvx could not resolve instance of IAudioService");
					return;
				}
				FeedFm = service;
				Log.Trace("Audio", string.Format("{0}: {1} resolved from Mvx: {2}", "SetUpFeedFmAudioServiceIfAvailable", "FeedFm", FeedFm));
			}
			else
			{
				Log.Trace("Audio", string.Format("{0}: {1} is already assigned: {2}", "SetUpFeedFmAudioServiceIfAvailable", "FeedFm", FeedFm));
			}
			if (WorkoutUsingBlankFeedFmMix())
			{
				Log.Trace("Audio", "Not setting up Audio Service, workout is using a blank feed mix");
				return;
			}
			HasInitializedAudioService = true;
			_whenAudioServiceInitialized.OnNext(value: true);
			audioServiceWhenPlayStartedSub?.Dispose();
			audioServiceWhenPlayStartedSub = FeedFm.WhenPlayStarted.SubscribeAsyncWithErrorLogging(HandleAudioServicePlayStarted);
			MusicStateService.Init(FeedFm);
			audioServiceWhenSkipRequestedSub?.Dispose();
			audioServiceWhenSkipRequestedSub = FeedFm.WhenSkipRequested.SubscribeWithErrorLogging(HandleSkipRequested);
			whenStationOutOfMusicSub?.Dispose();
			whenStationOutOfMusicSub = FeedFm.WhenStationOutOfMusic.SubscribeWithErrorLogging(delegate
			{
				WhenStationOutOfMusic();
			});
			feedFmPlaybackQueuedSub?.Dispose();
			feedFmPlaybackQueuedSub = FeedFm.WhenInstantPlaybackReady.SubscribeWithErrorLogging(delegate
			{
				HandleInstantPlaybackReady();
			});
			consoleStateChangedSub?.Dispose();
			consoleStateChangedSub = currentConsoleService?.Console?.WhenStateChanged?.Subscribe(delegate(StateChange state)
			{
				if (state.Current == ConsoleState.Workout && state.Old != ConsoleState.PauseOverride)
				{
					liveWorkoutMusicStateChanged.OnNext(LiveWorkoutMusicState.Other);
				}
			});
			if (WorkoutHasFeedFmMix && WorkoutHasMusic)
			{
				Log.Trace("Audio", "Setting up FeedFm Mix...");
				FeedFm.SetWorkoutContextScheduled(IsWorkoutContextScheduled);
				SetUpFeedFmMixes(FeedFmStations.SpecialtyStations ?? new List<Mix>(0), FeedFmStations.AvailableStations ?? new List<Mix>(0), FeedFmStations.TrainerSelectStationId, FeedFmStations.TrainerId, shouldStartFeedFmServiceAutomatically);
				Log.Trace("Audio", string.Format("{0}: {1}", "ContainsMusicRegions", WorkoutRegions.ContainsMusicRegions));
				if (WorkoutRegions.ContainsMusicRegions)
				{
					workoutCrossedMusicRegionThresholdSub?.Dispose();
					workoutCrossedMusicRegionThresholdSub = WhenVideoMusicRegionThresholdCrossed?.SubscribeWithErrorLogging(HandleWhenMusicRegionThresholdCrossed);
				}
				if (workoutSettings?.WorkoutContainer?.WorkoutRunner is LiveWorkoutRunner)
				{
					HandleLiveWorkoutStartingState(shouldStartFeedFmServiceAutomatically);
				}
			}
			else
			{
				Log.Trace("Audio", $"Not setting up Audio Service, WorkoutHasFeedFmMix is {WorkoutHasFeedFmMix} and WorkoutHasMusic is {WorkoutHasMusic}");
			}
		}

		private void HandleLiveWorkoutStartingState(bool shouldStartFeedFmServiceAutomatically)
		{
			if (shouldStartFeedFmServiceAutomatically && !mediaSettings.HasDisabledFeedFmPlayback)
			{
				FeedFm.LiveWorkoutStarting();
			}
			else if (mediaSettings.HasDisabledFeedFmPlayback)
			{
				feedFm.Pause();
			}
		}

		private void HandleInstantPlaybackReady()
		{
			if (!isDisposed && feedFm != null)
			{
				_onFeedFmInstantPlaybackReady?.OnNext(this);
			}
		}

		public void UpdateMusicAvailability()
		{
			if (WorkoutHasFeedFmMix && FeedFm != null && WorkoutHasMusic)
			{
				_volumeScreenAvailable.SetTrue();
				ForceUpdateDisabledPausedStateInCooldownIfNecessary();
				return;
			}
			ConsoleState? consoleState = currentConsoleService?.ActiveConsole?.LatestBasicInfo?.CurrentState;
			if (!consoleState.HasValue || !Enumerable.Contains(validStatesForVolumeScreen, consoleState.Value))
			{
				_volumeScreenAvailable.SetFalse();
				return;
			}
			BooleanCycle volumeScreenAvailable = _volumeScreenAvailable;
			IWorkoutSettings obj = workoutSettings;
			volumeScreenAvailable.Value = obj != null && obj.WorkoutContainer?.Workout?.IsVideoWorkout() == true;
			if (consoleState == ConsoleState.CoolDown && !WorkoutHasMusic)
			{
				_volumeScreenAvailable.Value = false;
			}
		}

		private void ForceUpdateDisabledPausedStateInCooldownIfNecessary()
		{
			if (!isDisposed && FeedFm.ActiveState == MusicState.PausedDisabled && CurrentConsoleState == ConsoleState.CoolDown)
			{
				PauseOrPlayMusicBasedOnInsideVideoMusicRegion(inMusicRegion: false);
			}
		}

		protected void SetUpFeedFmMixes(IReadOnlyList<Mix> specialtyStations, IReadOnlyList<Mix> availableStations, string trainerSelectStationId = null, string trainerId = null, bool shouldPlayWhenReady = true)
		{
			if (specialtyStations == null)
			{
				throw new ArgumentNullException("specialtyStations");
			}
			if (specialtyStations.Count <= 0)
			{
				throw new ArgumentException("Parameter must contain Mixes.", "specialtyStations");
			}
			if (specialtyStations.Any((Mix x) => !x.IsFeedFm))
			{
				throw new ArgumentException("Parameter must be a list of FeedFM mixes.", "specialtyStations");
			}
			if (specialtyStations.Any((Mix x) => string.IsNullOrWhiteSpace(x.StationId)))
			{
				throw new ArgumentNullException("specialtyStations", "specialtyStations. Internal station names must not be null or empty.");
			}
			if (WorkoutHasFeedFmMix && FeedFm != null)
			{
				UserStartedMusicDuringMusicRegion = false;
				FeedFmStations = new WorkoutStationModel(specialtyStations, availableStations)
				{
					TrainerSelectStationId = (string.IsNullOrWhiteSpace(trainerSelectStationId) ? null : trainerSelectStationId),
					TrainerId = trainerId,
					OverrideUserPreferenceWithDefaultStation = (FeedFmStations?.OverrideUserPreferenceWithDefaultStation ?? false)
				};
				StartFeedFmPlayerSetup(shouldPlayWhenReady);
			}
			else
			{
				Log.Trace("Audio", $"Not setting up FeedFM service - WorkoutHasFeedFmMix is {WorkoutHasFeedFmMix} and FeedFm is {FeedFm}");
			}
		}

		protected virtual string GetUsersPreferredStationIfAvailable(List<string> specialtyStations, List<string> availableStations, List<string> feedFmSdkStations)
		{
			string result = "";
			if (ifitApi?.CurrentlyAuthenticatedUserId != null && persistentMusicSettings?.UserPreferredStations != null)
			{
				if (!persistentMusicSettings.UserPreferredStations.ContainsKey(ifitApi.CurrentlyAuthenticatedUserId))
				{
					return "";
				}
				List<string> list = persistentMusicSettings.UserPreferredStations[ifitApi.CurrentlyAuthenticatedUserId];
				if (list.Count > 0)
				{
					foreach (string item in list)
					{
						if ((availableStations.Contains(item) || specialtyStations.Contains(item) || ShouldListAllSelectableStationsFromSdk) && feedFmSdkStations.Contains(item))
						{
							result = item;
							break;
						}
					}
				}
			}
			return result;
		}

		private void WhenStationOutOfMusic()
		{
			AudioPlayerStation activeStation = FeedFm.ActiveStation;
			if (activeStation.FirstPlay)
			{
				Log.Trace("Audio", $"First Play Station {activeStation} ran out of music");
				StartFeedFmPlayerSetup();
			}
			Log.Trace("Audio", $"Station {activeStation} ran out of music");
			PlayPrioritizedStation(shouldPlayWhenReady: true, activeStation.Id);
		}

		protected void HandleFeedFmPlayerReady(string clientId, bool shouldPlayWhenReady = true)
		{
			if (FeedFm == null || FeedFmStations == null)
			{
				HandleFeedFmPlayerSetupFailure(new NullReferenceException("IAudioService is null."));
				return;
			}
			UpdateMusicAvailability();
			VolumeControl?.UpdateAudioServicePlayerToAppropriateVolumeAsync();
			PlayPrioritizedStation(shouldPlayWhenReady, null, initialTssPlaylistStartTime);
			FeedFmUpdateClientIdTask = UpdateUserClientId(clientId);
			WorkoutStationModel workoutStationModel = FeedFmStations;
			if (workoutStationModel != null && workoutStationModel.TrainerSelectStationSet)
			{
				_whenFeedFmStationsInitialized.OnNext(value: true);
			}
		}

		public void SetInitialTssStartTime(float seconds)
		{
			if (seconds < 0f)
			{
				initialTssPlaylistStartTime = 0f;
			}
			else
			{
				initialTssPlaylistStartTime = seconds;
			}
		}

		private void UpdateCurrentStationIsTrainerSelect()
		{
			WorkoutStationModel workoutStationModel = FeedFmStations;
			int num;
			if (workoutStationModel != null && workoutStationModel.TrainerSelectStationSet)
			{
				IAudioService audioService = feedFm;
				num = ((audioService != null && audioService.ActiveStation?.FirstPlay == true) ? 1 : 0);
			}
			else
			{
				num = 0;
			}
			bool flag = (byte)num != 0;
			if (CurrentStationIsTrainerSelect != flag)
			{
				currentStationIsTrainerSelectChanged.OnNext(flag);
			}
		}

		private void PlayPrioritizedStation(bool shouldPlayWhenReady = true, string excludeStationId = null, float tssStartTime = 0f)
		{
			List<string> specialtyStations = FeedFmStations.SpecialtyStationIDs();
			List<string> availableStations = FeedFmStations.AvailableStationIDs();
			string text = (FeedFmStations.TrainerSelectStationSet ? FeedFmStations.TrainerSelectStationId : null);
			bool overrideUserPreference = FeedFmStations.OverrideUserPreferenceWithDefaultStation || mediaSettings.SecretSettingFeedFmOverrideUserStation;
			List<string> list = CreatePriorityListOfStations(specialtyStations, availableStations, text, FeedFmStations.TrainerId, overrideUserPreference);
			if (!string.IsNullOrWhiteSpace(excludeStationId))
			{
				list.RemoveAll((string station) => station == excludeStationId);
			}
			foreach (string item in list)
			{
				float startAt = ((item == text) ? tssStartTime : 0f);
				SwitchToFeedFmStation(item, shouldPlayWhenReady, startAt);
				if (FeedFm.IsPlaying)
				{
					break;
				}
			}
		}

		private List<string> CreatePriorityListOfStations(List<string> specialtyStations, List<string> availableStations, string trainerSelectStationId = null, string trainerId = null, bool overrideUserPreference = false)
		{
			List<string> priorityStationList = new List<string>();
			"".HasValue();
			if (trainerSelectStationId.HasValue())
			{
				AudioPlayerStation audioPlayerStation = FeedFm.Stations.FirstOrDefault((AudioPlayerStation x) => x.Id == trainerSelectStationId && x.FirstPlay);
				if (audioPlayerStation != null && !audioPlayerStation.HasListened)
				{
					priorityStationList.Add(trainerSelectStationId);
					feedFmAnalyticsService.SetTSSFirstPlaybackForUser(isFirstPlayback: true);
					if (CurrentConsoleState == ConsoleState.WarmUp)
					{
						liveWorkoutMusicStateChanged.OnNext(LiveWorkoutMusicState.TssStartingSoon);
					}
				}
			}
			if (LiveWorkoutMusicState != LiveWorkoutMusicState.TssStartingSoon && WorkoutContainer?.WorkoutRunner is LiveWorkoutRunner && CurrentConsoleState == ConsoleState.WarmUp)
			{
				liveWorkoutMusicStateChanged.OnNext(LiveWorkoutMusicState.StationChangerStartingSoon);
			}
			List<string> feedFmSdkStations = (from station in FeedFm.Stations
				where station?.IsSelectableStation ?? false
				orderby station.SortOrder ?? string.Empty, x.DisplayName
				select station.Id).ToList();
			IFeedFmAvailabilityService service;
			bool flag = Mvx.TryResolve<IFeedFmAvailabilityService>(out service) && service.IsFeedFmTrainerFavoritesFeatureEnabledForDevice();
			string text = null;
			if (flag && trainerId.HasValue())
			{
				text = FeedFm.Stations.FirstOrDefault((AudioPlayerStation x) => x.TFSTrainerId == trainerId)?.Id;
				if (text.HasValue())
				{
					if (!feedFmSdkStations.Contains(text))
					{
						feedFmSdkStations.Add(text);
					}
					if (!availableStations.Contains(text))
					{
						availableStations.Add(text);
					}
				}
			}
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMStationChanger))
			{
				string usersPreferredStationIfAvailable = GetUsersPreferredStationIfAvailable(specialtyStations, availableStations, feedFmSdkStations);
				if (!usersPreferredStationIfAvailable.IsNullOrWhitespace())
				{
					priorityStationList.Add(usersPreferredStationIfAvailable);
				}
			}
			if (text.HasValue() && !priorityStationList.Contains(text))
			{
				priorityStationList.Add(text);
			}
			specialtyStations.Where((string id) => feedFmSdkStations.Contains(id)).Except(priorityStationList)?.DoForEach(delegate(string id)
			{
				if (overrideUserPreference || StationShouldOverrideUserPreference(id))
				{
					priorityStationList.Insert(0, id);
				}
				else
				{
					priorityStationList.Add(id);
				}
			}, ignoreNulls: true);
			priorityStationList.AddRange(availableStations.Where((string station) => feedFmSdkStations.Contains(station)).Except(priorityStationList));
			if (!ShouldListAllSelectableStationsFromSdk)
			{
				return priorityStationList;
			}
			priorityStationList.AddRange(feedFmSdkStations.Except(priorityStationList));
			return priorityStationList;
		}

		private bool StationShouldOverrideUserPreference(string stationId)
		{
			IAudioService audioService = FeedFm;
			if (audioService == null)
			{
				return false;
			}
			return audioService.Stations?.FirstOrDefault((AudioPlayerStation x) => x.Id == stationId)?.OverridesUserPreference == true;
		}

		public void ClearFeedFmMix()
		{
			Log.Trace("MusicService", "ClearFeedFmMix called.");
			FeedFmStations = null;
			LegacyMix = null;
			Stock?.Dispose();
			Stock = null;
			_volumeScreenAvailable.SetFalse();
			WorkoutRegions = default(WorkoutMusicRegions);
			CleanUpAudioServiceSubscribers();
			previousFeedFmNotification = null;
			AudioTrack = null;
			ShouldListAllSelectableStationsFromSdk = false;
			initialTssPlaylistStartTime = 0f;
			IsWorkoutContextScheduled = false;
			if (workoutSettings?.WorkoutContainer?.Workout != null)
			{
				feedFmAnalyticsService?.HandleUserStartedStoppedMusic(started: false);
			}
		}

		public async Task FetchLegacyMix(string workoutId)
		{
			List<Mix> mixes = null;
			try
			{
				mixes = await Mix.GetWorkoutMixes(ifitApi, workoutId);
			}
			catch (Exception ex)
			{
				Log.Error("Audio", ex.GetType().Name + " occurred in FetchLegacyMix.", ex);
			}
			if ((mixes?.CountSafe() ?? 0) <= 0)
			{
				return;
			}
			LegacyMix = mixes.FirstOrDefault();
			if (LegacyMix?.IsFeedFm ?? false)
			{
				Log.Trace("Audio", "FetchLegacyMix was called, but LegacyMix is a FeedFM mix. Falling back to the first non-FeedFM mix...");
				LegacyMix = mixes.FirstOrDefault((Mix x) => !x.IsFeedFm);
			}
		}

		public async Task SetFeedFmStationsForWorkoutIfAvailable(Workout subjectWorkout, WorkoutRunnerContext liveWorkoutContext = null)
		{
			LegacyMix = null;
			if (subjectWorkout == null)
			{
				Log.Trace("Audio", "SetFeedFmStationsForWorkoutIfAvailable called, but subjectWorkout was null.");
				FeedFmStations = null;
				return;
			}
			IsWorkoutContextScheduled = liveWorkoutContext?.ScheduleInfo != null && liveWorkoutContext.Context != Workout.WorkoutContext.OnDemand;
			bool flag = featureFlagManager?.IsFeatureEnabled(FeatureFlags.WolfFeedFmCeolService) ?? false;
			Log.Trace("Audio", string.Format("{0} flag enabled: {1}", "WolfFeedFmCeolService", flag));
			if (flag)
			{
				FeedFmStations = await GetWorkoutStationFromCeol(subjectWorkout, liveWorkoutContext).ConfigureAwait(continueOnCapturedContext: false);
				if (FeedFmStations != null)
				{
					Log.Trace("Audio", "GetWorkoutStationFromCeol returned WorkoutStationModel successfully.");
					ShouldListAllSelectableStationsFromSdk = false;
					return;
				}
				Log.Error("Audio", "GetWorkoutStationFromCeol called, but did not return a WorkoutStationModel successfully. See prior log statements for details.");
			}
			FeedFmStations = FeedFmStationsFallback(subjectWorkout);
			ShouldListAllSelectableStationsFromSdk = true;
		}

		private WorkoutStationModel FeedFmStationsFallback(Workout subjectWorkout)
		{
			Mix mix = null;
			try
			{
				mix = feedFmNativeStationService?.FeedFmMixForWorkout(subjectWorkout);
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error in SetFeedFmStationsForWorkoutIfAvailable", exception);
			}
			List<Mix> list = new List<Mix>();
			if (mix != null)
			{
				list.Add(mix);
			}
			return new WorkoutStationModel(list, list)
			{
				TrainerId = subjectWorkout?.Metadata?.TrainerId
			};
		}

		public void FeedFmDisabled()
		{
			DismissFeedFmNotification();
		}

		private async Task<WorkoutStationModel> GetWorkoutStationFromCeol(Workout subjectWorkout, WorkoutRunnerContext liveWorkoutContext = null)
		{
			if (string.IsNullOrWhiteSpace(subjectWorkout?.Id))
			{
				Log.Trace("Audio", "Workout Id is empty, not making Ceol API call.");
				return null;
			}
			try
			{
				CeolWorkoutMusicInfo ceolResponse = await AttemptToGetMixesFromCeolV2(subjectWorkout).ConfigureAwait(continueOnCapturedContext: false);
				List<Mix> list = ceolResponse.ToFeedFmMixes();
				if (list == null || list.Count == 0)
				{
					Log.Error("Audio", "Error trying to parse Mix from CeolWorkoutMusicInfo.");
					Log.Error("Audio", "Ceol response: " + ((ceolResponse == null) ? "<null>" : JsonConvert.SerializeObject(ceolResponse)));
					return null;
				}
				Log.Trace("Audio", "Mix parsed from Ceol response: " + JsonConvert.SerializeObject(list));
				ceolResponse.DefaultToFeedFmMix();
				WorkoutStationModel workoutStationModel = new WorkoutStationModel(new List<Mix>(1) { ceolResponse.DefaultToFeedFmMix() }, list);
				WorkoutStationModel workoutStationModel2 = workoutStationModel;
				workoutStationModel2.TrainerSelectStationId = await GetTrainerSelectStationIfAvailable(subjectWorkout, liveWorkoutContext).ConfigureAwait(continueOnCapturedContext: false);
				workoutStationModel.TrainerId = subjectWorkout?.Metadata?.TrainerId;
				workoutStationModel.OverrideUserPreferenceWithDefaultStation = ceolResponse.OverridesUserPreference;
				return workoutStationModel;
			}
			catch (Exception exception)
			{
				Log.Error("Audio", "Could not parse response from Ceol service.", exception);
			}
			return null;
		}

		private async Task<string> GetTrainerSelectStationIfAvailable(Workout workout, WorkoutRunnerContext liveWorkoutContext = null)
		{
			bool flag = liveWorkoutContext?.ScheduleInfo != null && liveWorkoutContext.Context != Workout.WorkoutContext.OnDemand;
			if (workout == null || !flag || !Mvx.TryResolve<IFeedFmAvailabilityService>(out var service) || !service.IsFeedFmTrainerSelectFeatureEnabledForDevice())
			{
				return null;
			}
			string text = await GetStationIdForTSSWorkoutFromCeolIfAvailable(liveWorkoutContext.ScheduleInfo).ConfigureAwait(continueOnCapturedContext: false);
			return text.IsNullOrWhitespace() ? null : text;
		}

		private async Task<string> GetStationIdForTSSWorkoutFromCeolIfAvailable(LiveWorkouts.WorkoutInfo liveWorkoutInfo)
		{
			if ("".HasValue())
			{
				return "";
			}
			for (int attempts = 0; attempts < 3; attempts++)
			{
				try
				{
					CeolLiveWorkoutMusicInfo ceolLiveWorkoutMusicInfo = await ifitApi.GetGatewayService<IIFitCeolApi>().GetLiveWorkoutMusicInfo(liveWorkoutInfo.Id).ConfigureAwait(continueOnCapturedContext: false);
					if (ceolLiveWorkoutMusicInfo != null)
					{
						return ceolLiveWorkoutMusicInfo.StationId;
					}
					throw new Exception("Expected non-null response from IIFitCeolApi GetLiveWorkoutMusicInfo call.");
				}
				catch (Exception exception)
				{
					Log.Error("Audio", $"Ceol request attempt failure {attempts + 1}/{3}.", exception);
				}
			}
			return null;
		}

		private async Task<CeolWorkoutMusicInfo> AttemptToGetMixesFromCeolV2(Workout subjectWorkout)
		{
			for (int attempts = 0; attempts < 3; attempts++)
			{
				try
				{
					CeolWorkoutMusicInfo ceolWorkoutMusicInfo = await ifitApi.GetGatewayService<IIFitCeolApi>().GetWorkoutMixes(subjectWorkout.Id).ConfigureAwait(continueOnCapturedContext: false);
					if (ceolWorkoutMusicInfo != null)
					{
						return ceolWorkoutMusicInfo;
					}
					throw new Exception("Expected non-null response from IIFitCeolApi GetWorkoutMixes call.");
				}
				catch (Exception ex)
				{
					Log.Error("Audio", $"Ceol request attempt failure {attempts + 1}/{3}.", ex);
					if (analytics != null)
					{
						try
						{
							await analytics.InWorkoutCeolAttemptFailure(subjectWorkout, ex).ConfigureAwait(continueOnCapturedContext: false);
						}
						catch (Exception exception)
						{
							Log.Error("Analytics", "Error when trying to report Ceol attempt failure.", exception);
						}
					}
				}
			}
			Log.Error("Audio", "Ceol request attempts exceeded. Returning null from AttemptToGetMixesFromCeolV2.");
			if (analytics != null)
			{
				try
				{
					await analytics.InWorkoutCeolFailureFallback(subjectWorkout).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (Exception exception2)
				{
					Log.Error("Analytics", "Error when trying to report Ceol failure fallback.", exception2);
				}
			}
			return null;
		}

		private void StartFeedFmPlayerSetup(bool shouldPlayWhenReady = true)
		{
			feedFmPlayerReadySub?.Dispose();
			feedFmPlayerReadySub = FeedFm.WhenPlayerAvailable.Take(1).Subscribe(delegate(string clientId)
			{
				HandleFeedFmPlayerReady(clientId, shouldPlayWhenReady);
			}, HandleFeedFmPlayerSetupFailure);
			feedFmPlayerStationChangedSub?.Dispose();
			feedFmPlayerStationChangedSub = FeedFm.WhenStationChanged.SubscribeWithErrorLogging(delegate
			{
				Log.Info("MusicService", "HandleAudioServiceStationChanged");
				HandleAudioServiceStationChanged(null);
			});
			FeedFmPlayerInitTask = Task.Run(async delegate
			{
				await UpdateUserAndInitFeedFmAudioService();
			});
		}

		private void HandleAudioServiceStationChanged(AudioPlayerStation station)
		{
			UpdateCurrentStationIsTrainerSelect();
			VolumeControl?.UpdatePlayerVolumesFromSettingsAsync();
		}

		private async Task UpdateUserAndInitFeedFmAudioService()
		{
			if (isDisposed)
			{
				return;
			}
			if (FeedFm == null)
			{
				Log.Error("MusicService", "UpdateUserAndInitFeedFmAudioService called, but FeedFm property was null.");
				return;
			}
			User user;
			try
			{
				user = await ifitApi.RefreshCurrentlyAuthenticatedUser().ConfigureAwait(continueOnCapturedContext: false);
				if (user == null)
				{
					Log.Error("MusicService", "UpdateUserAndInitFeedFmAudioService called, but calling RefreshCurrentlyAuthenticatedUser returned null.");
					return;
				}
			}
			catch (Exception exception)
			{
				Log.Error("MusicService", "UpdateUserAndInitFeedFmAudioService called, but calling RefreshCurrentlyAuthenticatedUser threw an exception.", exception);
				return;
			}
			if (FeedFm == null)
			{
				Log.Error("MusicService", "UpdateUserAndInitFeedFmAudioService called, but FeedFm property was null after retrieving the current user.");
			}
			else
			{
				FeedFm.Init(user.HasFeedFmClientId ? user.FeedFmClientId : null);
			}
		}

		protected void SwitchToFeedFmStation(string stationId, bool shouldPlayWhenReady = true, float startAt = 0f)
		{
			if (string.IsNullOrWhiteSpace(stationId))
			{
				throw new ArgumentNullException("stationId");
			}
			bool flag = FeedFm?.ActiveStation.Id != stationId;
			feedFmStationChangeAutoPlay?.Dispose();
			if (shouldPlayWhenReady && flag && startAt <= 0f)
			{
				feedFmStationChangeAutoPlay?.Dispose();
				feedFmStationChangeAutoPlay = FeedFm?.WhenStationChanged.Where((AudioPlayerStation x) => x.Id == stationId).Take(1).SubscribeWithErrorLogging(delegate
				{
					PlayAudioServicePlayerIfEnabled();
				});
			}
			FeedFm?.ChangeToStationWithId(stationId, startAt);
			if (shouldPlayWhenReady && !flag)
			{
				PlayAudioServicePlayerIfEnabled();
			}
			feedFmAnalyticsService.HandleStationChanged(stationId);
		}

		public void PlayAudioServicePlayerIfEnabled()
		{
			if (FeedFm == null)
			{
				Log.Error("MusicService", "Cannot call Play on a null FeedFm service.");
				return;
			}
			BehaviorSubject<PauseMusicType> pauseTypeChanged = FeedFm.PauseTypeChanged;
			if (pauseTypeChanged != null && pauseTypeChanged.Value == PauseMusicType.PausedDisabled)
			{
				FeedFm.Pause(PauseMusicType.PausedDisabled);
				return;
			}
			bool flag = LiveWorkoutMusicState != LiveWorkoutMusicState.Other && WorkoutContainer?.WorkoutRunner is LiveWorkoutRunner && CurrentConsoleState == ConsoleState.WarmUp;
			if (mediaSettings.HasDisabledFeedFmPlayback || flag)
			{
				FeedFm.Pause();
				if (mediaSettings.HasDisabledFeedFmPlayback && CurrentStationIsTrainerSelect)
				{
					IWorkoutContainer workoutContainer = WorkoutContainer;
					if ((workoutContainer == null || workoutContainer.WorkoutRunner?.RunContext?.Context != Workout.WorkoutContext.OnDemand) && FeedFm.ActiveTrack == null && CurrentConsoleState.IsRunningState())
					{
						ForceTSSPlayThenPause();
					}
				}
			}
			else
			{
				FeedFm.Play();
				feedFmAnalyticsService.HandleUserStartedStoppedMusic(started: true);
			}
		}

		private void ForceTSSPlayThenPause()
		{
			FeedFm.Play();
			FeedFm.Pause();
			liveWorkoutMusicStateChanged?.OnNext(LiveWorkoutMusicState.Other);
		}

		private async Task UpdateUserClientId(string newClientId)
		{
			if (string.IsNullOrWhiteSpace(newClientId))
			{
				Log.Error("MusicService", "UpdateUserClientId called with newClientId value: " + (newClientId ?? "<null>") + ". Not updating User.");
				return;
			}
			User user;
			try
			{
				user = await ifitApi.RefreshCurrentlyAuthenticatedUser().ConfigureAwait(continueOnCapturedContext: false);
				if (user == null)
				{
					Log.Error("MusicService", "UpdateUserClientId called, but CurrentlyAuthenticatedUser is null.");
					return;
				}
			}
			catch (Exception exception)
			{
				Log.Error("MusicService", "UpdateUserClientId called, but calling RefreshCurrentlyAuthenticatedUser thorwed exception.", exception);
				return;
			}
			if (user.FeedFmClientId?.Equals(newClientId, StringComparison.Ordinal) ?? false)
			{
				Log.Trace("MusicService", "FeedFmClientId is being reused for this user. Not updating User.");
				return;
			}
			Log.Trace("MusicService", "Updating FeedFmClientId for current User...");
			user.FeedFmClientId = newClientId;
			try
			{
				await UpdateUserWithApi(user).ConfigureAwait(continueOnCapturedContext: false);
				User user2 = await ifitApi.RefreshCurrentlyAuthenticatedUser().ConfigureAwait(continueOnCapturedContext: false);
				Log.Trace("MusicService", "User updated.");
				if (user2 == null || user2.FeedFmClientId?.Equals(newClientId, StringComparison.Ordinal) != true)
				{
					Log.Error("MusicService", "Something went wrong in UpdateUserClientId.");
					Log.Error("MusicService", "newClientId and FeedFmClientId are mismatched after update.");
				}
			}
			catch (Exception exception2)
			{
				Log.Error("MusicService", "Updating FeedFmClientId for current User failed.", exception2);
			}
		}

		protected virtual async Task<User> UpdateUserWithApi(User user)
		{
			if (user != null)
			{
				await user.Update(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
			}
			return user;
		}

		private void HandleFeedFmPlayerSetupFailure(Exception error)
		{
			Log.Error("MusicService", "Error handling IAudioService WhenPlayerAvailable observable. Clearing FeedFM mix.", error);
			ClearFeedFmMix();
			analytics.InWorkoutMusicServiceIssue(workoutSettings.WorkoutContainer.Workout, FeedFm?.ActiveTrack, MusicState.Unavailable);
		}

		public bool ShouldWorkoutStartWithFeedFm(bool enteringRunningFromWarmup, bool doesWorkoutStartInMusicRegion, bool isVideoCurrentlyInsideMusicRegion)
		{
			if (!mediaSettings.HasDisabledFeedFmPlayback)
			{
				return !WorkoutStartingInMusicRegion(enteringRunningFromWarmup, doesWorkoutStartInMusicRegion, isVideoCurrentlyInsideMusicRegion);
			}
			return false;
		}

		private bool WorkoutStartingInMusicRegion(bool enteringRunningFromWarmup, bool doesWorkoutStartInMusicRegion, bool isVideoCurrentlyInsideMusicRegion)
		{
			if (!isVideoCurrentlyInsideMusicRegion)
			{
				return enteringRunningFromWarmup && doesWorkoutStartInMusicRegion;
			}
			return true;
		}

		public void HandleVideoPositionTimeChanged(bool isNowInMusicRegion)
		{
			if (!HasInitializedAudioService || !CurrentConsoleState.IsRunningState())
			{
				InsideVideoMusicRegion = false;
			}
			else if (InsideVideoMusicRegion != isNowInMusicRegion)
			{
				_whenVideoMusicRegionThresholdCrossed?.OnNext(isNowInMusicRegion && !UserStartedMusicDuringMusicRegion);
				if (UserStartedMusicDuringMusicRegion && !isNowInMusicRegion && CurrentConsoleState.IsRunningState())
				{
					UserStartedMusicDuringMusicRegion = false;
				}
				InsideVideoMusicRegion = isNowInMusicRegion;
				Log.Trace("MusicService", string.Format("Video music region crossed. New {0} value: {1}", "InsideVideoMusicRegion", InsideVideoMusicRegion));
			}
		}

		public void HandleUserSkipRequest(bool isWarmup, bool musicShouldBeDisabledInMainWorkout, float lastTrainerVolume)
		{
			if (WorkoutHasMusic)
			{
				if (isWarmup && musicShouldBeDisabledInMainWorkout)
				{
					FeedFm?.SetVolume(0f);
					FeedFm?.Pause(PauseMusicType.PausedDisabled);
				}
				else if (isWarmup && WorkoutRegions.BeginsWithMusicRegion && lastTrainerVolume >= 0.001f)
				{
					IAudioService audioService = feedFm;
					bool flag = audioService != null && audioService.PauseTypeChanged?.Value == PauseMusicType.PausedManually;
					FeedFm?.SetVolume(0f);
					FeedFm?.Pause(flag ? PauseMusicType.PausedManually : PauseMusicType.PausedForMusicRegion);
				}
				else
				{
					PlayAudioServicePlayerIfEnabled();
				}
			}
		}

		protected void PauseOrResumePlayback()
		{
			if (!isDisposed && IsUsingFeedFmAudioServiceForMusic)
			{
				if (mediaSettings.HasDisabledFeedFmPlayback || (feedFm.PauseTypeChanged.Value != PauseMusicType.PausedManually && feedFm.PauseTypeChanged.Value != PauseMusicType.PausedForMusicRegion))
				{
					mediaSettings.HasDisabledFeedFmPlayback = !mediaSettings.HasDisabledFeedFmPlayback;
				}
				if (feedFm.PauseTypeChanged.Value == PauseMusicType.PausedManually || feedFm.PauseTypeChanged.Value == PauseMusicType.PausedForMusicRegion)
				{
					PauseOrResumeFeedFmPlayback(feedEnabled: true);
				}
				else if (feedFm.PauseTypeChanged.Value == PauseMusicType.None)
				{
					PauseOrResumeFeedFmPlayback(feedEnabled: false);
				}
			}
		}

		private async Task OnPausedTask()
		{
			IAudioService audioService = FeedFm;
			int num;
			if (audioService == null)
			{
				num = 0;
			}
			else
			{
				_ = audioService.PauseTypeChanged.Value;
				num = 1;
			}
			if (num != 0)
			{
				switch (FeedFm.PauseTypeChanged.Value)
				{
				case PauseMusicType.PausedManually:
					FeedFmMusicState = MusicState.PausedManually;
					await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
					break;
				case PauseMusicType.PausedForMusicRegion:
					FeedFmMusicState = MusicState.PausedForMusicRegion;
					await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
					break;
				case PauseMusicType.PausedByHeadphoneRemoval:
					FeedFmMusicState = MusicState.PausedByHeadphoneRemoval;
					await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
					break;
				case PauseMusicType.PausedDisabled:
					FeedFmMusicState = MusicState.PausedDisabled;
					await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
					break;
				}
			}
		}

		private async Task OnPlayingAsync()
		{
			if (CurrentConsoleState != ConsoleState.Paused)
			{
				FeedFmMusicState = MusicState.Playing;
				HasStartedPlayingMusic = true;
				UpdateCurrentTrackFromPlayHistory();
			}
		}

		private async Task OnStoppedAsync()
		{
			FeedFmMusicState = MusicState.Off;
		}

		private async Task OnReadyAsync()
		{
			if (WorkoutContainer?.WorkoutRunner is LiveWorkoutRunner && CurrentConsoleState == ConsoleState.WarmUp)
			{
				FeedFmMusicState = MusicState.PausedManually;
			}
			else
			{
				FeedFmMusicState = (mediaSettings.HasDisabledFeedFmPlayback ? MusicState.PausedManually : MusicState.Loading);
			}
			await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
		}

		private async Task OnLoadingAsync()
		{
			if (CurrentConsoleState != ConsoleState.Paused)
			{
				FeedFmMusicState = MusicState.Loading;
				await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
			}
		}

		private void UpdateCurrentTrackFromPlayHistory()
		{
			if (!isDisposed)
			{
				AudioTrack audioTrack = TryGetLastTrackFromAudioServiceHistory();
				if (IsUsingFeedFmAudioServiceForMusic && audioTrack != null && !AudioTrack.IsMetadataEqual(AudioTrack, audioTrack))
				{
					AudioTrack = audioTrack;
				}
			}
		}

		public void HandleExternalFeedFmToggleAction()
		{
			if (!isDisposed && IsUsingFeedFmAudioServiceForMusic)
			{
				PauseOrResumeFeedFmPlayback(!mediaSettings.HasDisabledFeedFmPlayback);
			}
		}

		public void PauseOrPlayMusicBasedOnInsideVideoMusicRegion(bool inMusicRegion)
		{
			if (MusicDisabledDuringMainWorkoutAndWorkoutModeIsRunning())
			{
				FeedFm?.Pause(PauseMusicType.PausedDisabled);
				DismissFeedFmNotification();
			}
			else if (inMusicRegion)
			{
				IAudioService audioService = feedFm;
				bool flag = audioService != null && audioService.ActiveState == MusicState.PausedManually;
				FeedFm?.Pause(flag ? PauseMusicType.PausedManually : PauseMusicType.PausedForMusicRegion);
				DismissFeedFmNotification();
			}
			else if (!PlayWorkoutAudioServicePlayerIfEnabled() && mediaSettings.HasDisabledFeedFmPlayback)
			{
				FeedFm?.Pause();
			}
		}

		private void HandleSkipRequested(bool skipRequested)
		{
			if (skipRequested)
			{
				analytics?.InWorkoutMusicAction(WorkoutContainer?.Workout, AudioPlayerAction.SkipRequest, AudioPlayerType.FeedFm, LastMusicVolumeAsInt, WorkoutContainer?.WorkoutRunner?.WolfGeneratedId);
			}
		}

		private void HandleWhenMusicRegionThresholdCrossed(bool inMusicRegion)
		{
			if (!HasInitializedAudioService || !CurrentConsoleState.IsRunningState())
			{
				InsideVideoMusicRegion = false;
				return;
			}
			bool flag = InsideVideoMusicRegion && !inMusicRegion;
			InsideVideoMusicRegion = inMusicRegion;
			PauseOrPlayMusicBasedOnInsideVideoMusicRegion(inMusicRegion);
			if (flag && AudioTrack != null && IsFeedFmEnabledInSettings && !MusicShouldBeDisabledInMainWorkout)
			{
				PlayWorkoutAudioServicePlayerIfEnabled();
				ShowFeedFmNotification();
			}
		}

		protected virtual async Task HandleAudioServicePlayStarted(AudioTrack track)
		{
			if (!isDisposed && !musicWasInitializingWhenWarmupEnded)
			{
				UpdateMusicAvailability();
				await VolumeControl.UpdatePlayerVolumesFromSettingsAsync();
				UpdateAudioTrack(track);
			}
		}

		private void UpdateAudioTrack(AudioTrack track)
		{
			if (isDisposed || musicWasInitializingWhenWarmupEnded)
			{
				if (musicWasInitializingWhenWarmupEnded && AudioTrack == null)
				{
					AudioTrack audioTrack = (AudioTrack = track);
				}
			}
			else
			{
				AudioTrack = track;
			}
		}

		private void PauseOrResumeFeedFmPlayback(bool feedEnabled)
		{
			if (isDisposed)
			{
				return;
			}
			if (feedEnabled)
			{
				if (PlayWorkoutAudioServicePlayerIfEnabled())
				{
					feedFmAnalyticsService.HandleUserStartedStoppedMusic(started: true);
					if (InsideVideoMusicRegion)
					{
						UserStartedMusicDuringMusicRegion = true;
					}
				}
			}
			else
			{
				FeedFm?.Pause();
				DismissFeedFmNotification();
				feedFmAnalyticsService.HandleUserStartedStoppedMusic(started: false);
			}
		}

		public bool PlayWorkoutAudioServicePlayerIfEnabled()
		{
			if (isDisposed)
			{
				return false;
			}
			if (mediaSettings.HasDisabledFeedFmPlayback)
			{
				return false;
			}
			if (FeedFm != null)
			{
				MusicState activeState = FeedFm.ActiveState;
				if (LiveWorkoutMusicState == LiveWorkoutMusicState.TssStartingSoon || LiveWorkoutMusicState == LiveWorkoutMusicState.StationChangerStartingSoon)
				{
					Log.Trace("Audio", "Trying to play music while still in warm-up of a live workout.");
					FeedFm.Pause();
					return false;
				}
				if (InsideVideoMusicRegion)
				{
					Log.Trace("Audio", "Workout in VMR, Calling Temporary Pause on FeedFm");
					FeedFm.Pause(PauseMusicType.PausedForMusicRegion);
				}
				else
				{
					Log.Trace("Audio", "Calling Play on FeedFm");
					FeedFm.Play();
					if (activeState != MusicState.Playing)
					{
						Log.Trace("Audio", $"Showing notification for ${AudioTrack}");
						ShowFeedFmNotification();
					}
				}
			}
			feedFmAnalyticsService.HandleUserStartedStoppedMusic(started: true);
			return true;
		}

		public bool ShowFeedFmNotification()
		{
			if (isDisposed)
			{
				return false;
			}
			if (AudioTrack == null)
			{
				Log.Error("Audio", "Attempted to show notification for a null AudioTrack");
				return false;
			}
			if (WorkoutContainer == null)
			{
				Log.Error("Audio", string.Format("Attempted to show Feed.fm notification for {0} but {1} was null.", AudioTrack, "WorkoutContainer"));
				return false;
			}
			bool flag = FeedFmNativeStationService.WorkoutNotApplicableForMusic(WorkoutContainer.Workout);
			IWorkoutRunner workoutRunner = WorkoutContainer.WorkoutRunner;
			if (workoutRunner == null)
			{
				Log.Error("Audio", string.Format("Attempted to show Feed.fm notification for {0} but {1} was null.", AudioTrack, "workoutRunner"));
				return false;
			}
			bool flag2 = workoutRunner.HasStartedWarmUp || workoutRunner.HasStartedCoolDown;
			if (!flag2 && flag)
			{
				return false;
			}
			FeedFmNotificationData feedFmNotificationData = previousFeedFmNotification;
			if (feedFmNotificationData != null && !feedFmNotificationData.Dismissed && AudioTrack.IsMetadataEqual(previousFeedFmNotification?.AudioTrack, AudioTrack))
			{
				return false;
			}
			FeedFmNotificationData notification = new FeedFmNotificationData(AudioTrack);
			inAppNotificationService?.Post(notification, ignoreSuppressed: true);
			previousFeedFmNotification = notification;
			return true;
		}

		public void DismissFeedFmNotification()
		{
			Log.Trace("Audio", "Dismissing Feed.FM notification");
			inAppNotificationService?.DismissAll(typeof(FeedFmNotificationData));
		}

		private AudioTrack TryGetLastTrackFromAudioServiceHistory()
		{
			return FeedFm?.PlayHistory?.LastOrDefault();
		}

		private bool MusicDisabledDuringMainWorkoutAndWorkoutModeIsRunning()
		{
			if (WorkoutRegions.IsEntirelyWithinMusicRegion || MusicShouldBeDisabledInMainWorkout)
			{
				return CurrentConsoleState.IsRunningState();
			}
			return false;
		}

		public bool WorkoutUsingBlankFeedFmMix()
		{
			if (WorkoutHasFeedFmMix)
			{
				return string.IsNullOrWhiteSpace(FeedFmStations?.PrimarySpecialtyStation()?.StationId);
			}
			return false;
		}

		private void CleanUpAudioServiceSubscribers()
		{
			feedFmPlayerReadySub?.Dispose();
			feedFmPlayerReadySub = null;
			feedFmPlayerStationChangedSub?.Dispose();
			feedFmPlayerStationChangedSub = null;
			feedFmStationChangeAutoPlay?.Dispose();
			feedFmStationChangeAutoPlay = null;
			whenStationOutOfMusicSub?.Dispose();
			whenStationOutOfMusicSub = null;
			feedFmPlaybackQueuedSub?.Dispose();
			feedFmPlaybackQueuedSub = null;
			consoleStateChangedSub?.Dispose();
			consoleStateChangedSub = null;
		}
	}
}
namespace Wolf.Core.Music.ViewModels
{
