		[DependsOn(new string[] { "IsConsoleRunning" })]
		public bool IsShowingBluetoothHeadphones
		{
			get
			{
				if (deviceInfo.IsBuiltIn)
				{
					IFeatureFlagManager obj = featureFlagManager;
					if (obj != null && obj.IsFeatureEnabled(FeatureFlags.EmbeddedBluetoothHeadphoneFeature))
					{
						HeadphoneConnectionHelperBase headphoneConnectionHelperBase = headphoneConnectionHelper;
						if (headphoneConnectionHelperBase == null || !headphoneConnectionHelperBase.DoesConnectingDuringPlaybackStopBuffering || !IsConsoleRunning.Value)
						{
							ViewPagerSource pages = Pages;
							if (pages == null)
							{
								return false;
							}
							return pages.CurrentPage?.Value == 1;
						}
					}
				}
				return false;
			}
		}

