		public InWorkoutAudioSettingsViewModel(ILocalSettings localSettings, HeadphoneConnectionHelperBase headphoneConnectionHelper, IMediaService mediaService, IMediaSettings mediaSettings, IConnectedBluetoothAccessories connectedBluetoothAccessories, IMusicStateService musicStateService, IMvxMessenger mvxMessenger = null, IFeedFmAnalyticsService feedFmAnalyticsService = null, IFeedFmAvailabilityService feedFmAvailabilityService = null)
			: base(localSettings)
		{
			try
			{
				this.headphoneConnectionHelper = headphoneConnectionHelper;
				this.mediaService = mediaService;
				this.mediaSettings = mediaSettings;
				this.mvxMessenger = mvxMessenger;
				this.feedFmAnalyticsService = feedFmAnalyticsService;
				this.connectedBluetoothAccessories = connectedBluetoothAccessories;
				this.feedFmAvailabilityService = feedFmAvailabilityService;
				MusicButtonTapped = new MvxCommand(delegate
				{
					SelectTab(AudioSettingsTab.FeedFm);
				});
				VolumeButtonTapped = new MvxCommand(delegate
				{
					SelectTab(AudioSettingsTab.VolumeMixer);
				});
				BluetoothAccessoriesButtonVM = new BluetoothAccessoriesButtonViewModel(localSettings, connectedBluetoothAccessories);
				INC<bool> isConsoleRunning = IsConsoleRunning;
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				isConsoleRunning.Value = activeConsole != null && activeConsole.LatestBasicInfo?.CurrentState.IsRunningState() == true;
				consoleStateSub = currentConsoleService.ActiveConsole?.WhenStateChanged.SubscribeWithErrorLogging(delegate(StateChange sc)
				{
					IsConsoleRunning.Value = sc.Current.IsRunningState();
				});
				ShowMusicFeatures.Value = IsFeedFm && IsUsingFeedFmService;
				MusicStateService = musicStateService;
				MusicStateService.OnPausedAsync = OnPausedTask;
				MusicStateService.OnPlayingAsync = OnPlayingAsync;
				MusicStateService.OnStoppedAsync = OnStoppedAsync;
				MusicStateService.OnReadyAsync = OnReadyAsync;
				MusicStateService.OnLoadingAsync = OnLoadingAsync;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			INC<bool> isConsoleRunning = IsConsoleRunning;
			ICurrentConsoleService obj = currentConsoleService;
			isConsoleRunning.Value = obj != null && obj.ActiveConsole?.LatestBasicInfo?.CurrentState.IsRunningState() == true;
			await Task.Run(delegate
			{
				if (IsFeedFm)
				{
					feedFmTrackChangeSub?.Dispose();
					feedFmTrackChangeSub = mediaService?.Music?.FeedFm?.WhenPlayStarted?.SubscribeWithErrorLogging(UpdateFeedFmTrack);
					MusicStateService.Init(mediaService?.Music?.FeedFm);
					UpdateFeedFmTrack();
				}
				messageTokenMusicSettingsAction?.Dispose();
				messageTokenMusicControlsAction?.Dispose();
				messageTokenVolumeReleasedAction?.Dispose();
				messageTokenMusicSettingsAction = null;
				messageTokenMusicControlsAction = null;
				messageTokenVolumeReleasedAction = null;
				messageTokenMusicSettingsAction = mvxMessenger?.Subscribe(delegate(InWorkoutMusicSettingsViewModel.InWorkoutMusicSettingsActionMessage x)
				{
					HandleExternalSettingsAction(x.StationIsLoading, x.ShouldChangeMusicState);
				});
				messageTokenMusicControlsAction = mvxMessenger?.Subscribe<InWorkoutVolumeMixerViewModel.InWorkoutVolumeMixerVolumeChangedMessage>(delegate
				{
					VolumeMovedShouldLockDismiss = true;
					HandleExternalSettingsAction(isLoading: false, shouldChangeMusicState: false);
				});
				messageTokenVolumeReleasedAction = mvxMessenger?.Subscribe<InWorkoutVolumeMixerViewModel.InWorkoutVolumeMixerVolumeReleasedMessage>(delegate
				{
					VolumeMovedShouldLockDismiss = false;
				});
				if (autoDismissTimer != null)
				{
					autoDismissTimer.Elapsed -= AudioSettingsScreenDismissFromTimer;
					autoDismissTimer.Elapsed += AudioSettingsScreenDismissFromTimer;
					autoDismissTimer.Start();
				}
				else
				{
					string text2 = "autoDismissTimer is null in InWorkoutAudioSettingsViewModel.Init";
					Log.Error("Music", text2);
				}
			});
			if (ArbitraryData != null)
			{
				FocusPreferredTab();
				ArbitraryData.OnAppear?.Invoke();
			}
			else
			{
				string text = "ArbitraryData is null in InWorkoutAudioSettingsViewModel.Init";
				Log.Error("Music", text);
			}
		}

		[DependsOn(new string[] { "HasLoaded" })]
		private void HasLoadedValueChanged()
		{
			RaisePropertyChanged(() => CloseWithAnimation);
			CloseWithAnimation.RaiseCanExecuteChanged();
		}

		private void HandleExternalSettingsAction(bool isLoading = false, bool shouldChangeMusicState = true)
		{
			StationIsLoading = isLoading;
			if (shouldChangeMusicState)
			{
				FeedFmMusicState.Value = (isLoading ? MusicState.Loading : MusicState.Playing);
			}
			Log.Trace("Audio", "Action Taken on Music Settings or Volume Mixer. Resetting Auto Dismiss Timer.");
			ResetAutoDismissTimer();
		}

		private async Task OnPausedTask()
		{
			IMediaService obj = mediaService;
			int num;
			if (obj == null)
			{
				num = 0;
			}
			else
			{
				IMusicService music = obj.Music;
				if (music == null)
				{
					num = 0;
				}
				else
				{
					IAudioService feedFm = music.FeedFm;
					if (feedFm == null)
					{
						num = 0;
					}
					else
					{
						_ = feedFm.PauseTypeChanged.Value;
						num = 1;
					}
				}
			}
			if (num != 0)
			{
				switch (mediaService.Music.FeedFm.PauseTypeChanged.Value)
				{
				case PauseMusicType.PausedManually:
					FeedFmMusicState.Value = MusicState.PausedManually;
					break;
				case PauseMusicType.PausedForMusicRegion:
					FeedFmMusicState.Value = MusicState.PausedForMusicRegion;
					break;
				case PauseMusicType.PausedByHeadphoneRemoval:
					FeedFmMusicState.Value = MusicState.PausedByHeadphoneRemoval;
					break;
				case PauseMusicType.PausedDisabled:
					FeedFmMusicState.Value = MusicState.PausedDisabled;
					break;
				}
			}
		}

		private async Task OnPlayingAsync()
		{
			FeedFmMusicState.Value = MusicState.Playing;
		}

		private async Task OnStoppedAsync()
		{
			FeedFmMusicState.Value = MusicState.Off;
		}

		private async Task OnReadyAsync()
		{
			if (workoutSettings?.WorkoutContainer?.WorkoutRunner is LiveWorkoutRunner)
			{
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				if (activeConsole != null && activeConsole.LatestBasicInfo?.CurrentState == ConsoleState.WarmUp)
				{
					FeedFmMusicState.Value = MusicState.PausedManually;
					return;
				}
			}
			FeedFmMusicState.Value = (mediaSettings.HasDisabledFeedFmPlayback ? MusicState.PausedManually : MusicState.Loading);
		}

		private async Task OnLoadingAsync()
		{
			FeedFmMusicState.Value = MusicState.Loading;
		}

		private void UpdateFeedFmTrack()
		{
			try
			{
				AudioTrack track = mediaService?.Music?.FeedFm?.ActiveTrack ?? mediaService?.Music?.FeedFm?.PlayHistory?.LastOrDefault();
				UpdateFeedFmTrack(track);
			}
			catch (Exception exception)
			{
				Log.Error("Music", "Error updating FeedFm track info.", exception);
			}
		}

		private void UpdateFeedFmTrack(AudioTrack track)
		{
			if (!isDisposed && track != null)
			{
				InvokeOnMainThread(delegate
				{
					AudioTrack.SafeUpdateValue(track);
				});
			}
		}

		private async Task DoCloseWithAnimationFromView()
		{
			feedFmAnalyticsService.HandleUserOpenedDismissedVolumeMixer(opened: false);
			await DoCloseWithAnimation();
		}

		private async Task DoCloseWithAnimation()
		{
			if (!HasLoaded.Value)
			{
				return;
			}
			if (!IsTablet || VisibilityAnimationRequestsDisabled)
			{
				DoClose();
				return;
			}
			fadeAnimCts.Cancel();
			fadeAnimCts = new CancellationTokenSource();
			TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
			_animateVisibility.Raise(new VisibilityAnimationRequest(visible: false, taskCompletionSource, fadeAnimCts.Token));
			try
			{
				await taskCompletionSource.Task;
			}
			catch (OperationCanceledException)
			{
			}
			DoClose();
		}

		protected override void DoClose()
		{
			ArbitraryData?.OnDismiss?.Invoke();
			base.DoClose();
		}

		public void SelectTab(AudioSettingsTab tab)
		{
			if (Pages?.CurrentPage == null)
			{
				return;
			}
			switch (tab)
			{
			case AudioSettingsTab.FeedFm:
				InvokeOnMainThread(delegate
				{
					Pages.CurrentPage.Value = 0;
				});
				_whenTabIsTapped.OnNext(0);
				break;
			case AudioSettingsTab.VolumeMixer:
				InvokeOnMainThread(delegate
				{
					Pages.CurrentPage.Value = 1;
				});
				_whenTabIsTapped.OnNext(1);
				break;
			}
			ResetAutoDismissTimer();
		}

		private void ViewWasLoaded()
		{
			HasLoaded.Value = true;
			mvxMessenger.Publish(new AudioSettingsViewLoaded(this));
		}

		public void FocusPreferredTab()
		{
			SelectTab(PreferredTab);
		}

		private async Task DoShowHeadphonePicker()
		{
			await DoCloseWithAnimation();
			if (base.IsBuiltInClubUnit)
			{
				InWorkoutHeadphonePickerViewModel.Show(InWorkoutHeadphonePickerViewModel.OverlaySource.FromMusic);
			}
			else
			{
				BluetoothDevicePickerViewModel.Show(BluetoothDevicePickerViewModel.OverlaySource.FromMusic);
			}
		}

		private void ResetAutoDismissTimer()
		{
			autoDismissTimer?.Stop();
			autoDismissTimer?.Start();
		}

		private void AudioSettingsScreenDismissFromTimer(object sender, EventArgs e)
		{
			if (IsTablet)
			{
				if (StationIsLoading)
				{
					Log.Trace("Workout", "Resetting audio settings auto dismiss timer because the selected station is still loading.");
					ResetAutoDismissTimer();
				}
				else
				{
					Log.Trace("Workout", "AudioSettingsScreenDismissFromTimer");
					CloseWithAnimation.ExecuteAsync();
				}
			}
		}

		public override void Dispose()
		{
			HasDisposed.Value = true;
			consoleStateSub?.Dispose();
			consoleStateSub = null;
			BluetoothAccessoriesButtonVM.Dispose();
			feedFmTrackChangeSub?.Dispose();
			feedFmTrackChangeSub = null;
			feedFmServiceStateChanged?.Dispose();
			feedFmServiceStateChanged = null;
			if (autoDismissTimer != null)
			{
				autoDismissTimer.Stop();
				autoDismissTimer.Elapsed -= AudioSettingsScreenDismissFromTimer;
				autoDismissTimer.Dispose();
				autoDismissTimer = null;
			}
			fadeAnimCts?.Cancel();
			fadeAnimCts?.Dispose();
			fadeAnimCts = null;
			messageTokenMusicSettingsAction?.Dispose();
			messageTokenMusicControlsAction?.Dispose();
			messageTokenVolumeReleasedAction?.Dispose();
			messageTokenMusicSettingsAction = null;
			messageTokenMusicControlsAction = null;
			messageTokenVolumeReleasedAction = null;
			connectedBluetoothAccessories.Dispose();
			MusicStateService?.Dispose();
			MusicStateService = null;
			UnregisterChangeHandlers();
		}

