			{
				this.blobCacheService = blobCacheService;
				this.schedulerService = schedulerService;
				this.headphoneConnectionHelper = headphoneConnectionHelper;
				this.overlayNotifier = overlayNotifier;
				this.mediaService = mediaService;
				this.platformMediaVolumeService = platformMediaVolumeService;
