				headphonesConnectedSub = headphoneConnectionHelper?.OnConnected.Subscribe(delegate(bool connected)
				{
					IsHeadphonesConnected = connected;
				});
				IsHeadphonesConnected = headphoneConnectionHelper?.IsConnected() ?? false;
				INC<bool> isConsoleRunning = IsConsoleRunning;
				ICurrentConsoleService obj = currentConsoleService;
				isConsoleRunning.Value = obj != null && obj.ActiveConsole?.LatestBasicInfo?.CurrentState.IsRunningState() == true;
				consoleStateSub = currentConsoleService?.ActiveConsole?.WhenStateChanged.SubscribeWithErrorLogging(delegate(StateChange sc)
				{
					IsConsoleRunning.Value = sc.Current.IsRunningState();
				});
