		public async Task Init()
		{
			await Task.Run(delegate
			{
				MusicVolumeLabel.Value = Wolf.Core.Resources.AppStrings.music_volume;
				TrainerVolumeLabel.Value = Wolf.Core.Resources.AppStrings.trainer_volume;
				SystemVolumeLabel.Value = Wolf.Core.Resources.AppStrings.master_volume;
				musicTracksLoadedSub?.Dispose();
				musicTracksLoadedSub = workoutSettings.WorkoutContainer?.MusicInfoService?.WhenMusicInfoChanged?.SubscribeWithErrorLogging(async delegate
				{
					UpdateMusicVolumeAvailability();
					UpdateMusicTrackInfo();
				});
				if (IsFeedFm)
				{
					feedFmTrackChangeSub?.Dispose();
					feedFmTrackChangeSub = mediaService.Music.FeedFm?.WhenPlayStarted.SubscribeWithErrorLogging(UpdateFeedFmTrack);
					feedFmServiceStateChanged?.Dispose();
					feedFmServiceStateChanged = mediaService.Music.FeedFm?.WhenPlayerStateChanged.Subscribe(HandleAudioServiceStateChanges, HandleMusicServiceIssues);
					feedFmTrackUpdateSub?.Dispose();
					feedFmTrackUpdateSub = Observable.Timer(TimeSpan.Zero, TimeSpan.FromSeconds(1.0)).Subscribe(delegate
					{
						UpdateFeedFmTrack();
					});
					HandleAudioServiceActiveState();
				}
				else
				{
					timerTickSub?.Dispose();
					timerTickSub = Observable.Interval(TimeSpan.FromSeconds(1.0), intervalScheduler).SubscribeWithErrorLogging(delegate
					{
						UpdateMusicTrackInfo();
					});
				}
				TrainerVolume.Value = mediaSettings.TrainerVolume;
				TrainerVolumeChanged();
				UpdateMusicVolumeAvailability();
				IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
				INC<bool> showTrainerVolume = ShowTrainerVolume;
				int value;
				if (workoutContainer != null && workoutContainer.Workout?.IsVideoWorkout() == true)
				{
					ICurrentConsoleService obj = currentConsoleService;
					if (obj == null || obj.ActiveConsole?.LatestBasicInfo?.CurrentState != ConsoleState.CoolDown)
					{
						value = ((!localSettings.IsRetailDemoModeEnabled) ? 1 : 0);
						goto IL_0289;
					}
				}
				value = 0;
				goto IL_0289;
				IL_0289:
				showTrainerVolume.Value = (byte)value != 0;
				Task.Run((Action)UpdateMusicTrackInfo);
				if (deviceInfo.IsBuiltIn || base.IsStrengthMirror)
				{
					ShowSystemVolume.Value = true;
					if (IsBuiltinWithHeadphonesConnected)
					{
						SystemVolume.Value = Math.Max(TrainerVolume.Value, MusicVolume.Value);
					}
					else if (base.IsStrengthMirror)
					{
						float? num = platformMediaVolumeService?.GetPlatformMediaVolume();
						if (num.HasValue)
						{
							SystemVolume.Value = num.Value;
						}
					}
					else
					{
						SystemVolume.Value = (float)(currentConsoleService?.PhysicalConsole?.LatestBasicInfo?.Volume ?? 0) / 100f;
					}
					volumeMetricSub = facadeFactoryDependencies.VolumeFacade.ObserveVolumeChanges().SubscribeWithErrorLogging(WhenConsoleVolumeChanged);
				}
			});
		}

		private void HandleMusicServiceIssues(Exception e)
		{
			Log.Error("Audio", $"FeedFM player state exception with message: {e.Message}. Current state: {mediaService.Music.FeedFm?.ActiveState}", e);
			analytics.InWorkoutMusicServiceIssue(workoutSettings?.WorkoutContainer?.Workout, AudioTrack?.Value, mediaService.Music.FeedFm?.ActiveState ?? MusicState.Uninitialized);
		}

		public override Task OnViewShown()
		{
			overlayNotifier.SetIsShowing(OverlayType.Volume, isShowing: true);
			UpdateDismissSub();
			fadeAnimCts.Cancel();
			fadeAnimCts = new CancellationTokenSource();
			_animateVisibility.Raise(new VisibilityAnimationRequest(visible: true, null, fadeAnimCts.Token));
			ArbitraryData?.OnAppear?.Invoke();
			feedFmAnalyticsService.HandleUserOpenedDismissedVolumeMixer(opened: true);
			return base.OnViewShown();
		}

		protected override void DoClose()
		{
			ArbitraryData?.OnDismiss?.Invoke();
			base.DoClose();
			CommitVolumeLevelsToStorage();
			overlayNotifier.SetIsShowing(OverlayType.Volume, isShowing: false);
			Dispose();
		}

		private async Task DoCloseWithAnimationFromView()
		{
			PostMixerDismissedAnalytics(dismissedByUser: true);
			await DoCloseWithAnimation();
		}

		private void PostMixerDismissedAnalytics(bool dismissedByUser)
		{
			if (dismissedByUser)
			{
				feedFmAnalyticsService.HandleUserOpenedDismissedVolumeMixer(opened: false);
			}
		}

		private async Task DoCloseWithAnimation()
		{
			if (!isUserSlidingSystemVolume && !isUserSlidingMusicVolume && !isUserSlidingTrainerVolume)
			{
				if (!IsTablet)
				{
					DoClose();
				}
				fadeAnimCts.Cancel();
				fadeAnimCts = new CancellationTokenSource();
				TaskCompletionSource<object> taskCompletionSource = new TaskCompletionSource<object>();
				_animateVisibility.Raise(new VisibilityAnimationRequest(visible: false, taskCompletionSource, fadeAnimCts.Token));
				try
				{
					await taskCompletionSource.Task;
				}
				catch (OperationCanceledException)
				{
				}
				DoClose();
			}
		}

		private void CommitVolumeLevelsToStorage()
		{
			mediaSettings.CommitTrainerVolumeToStorage();
			mediaSettings.CommitMusicVolumeToStorage();
			if (deviceInfo.IsStrengthMirror)
			{
				mediaSettings.CommitStrengthMirrorSystemVolumeToStorage();
			}
		}

		[DependsOn(new string[] { "MusicVolume" })]
		public void MusicVolumeChanged()
		{
			bool musicVolumeMuted = mediaSettings.MusicVolumeMuted;
			float num = MusicVolume.Value.Clamp(0f, 1f);
			mediaService.SetMusicVolume(num, commit: false);
			if (musicVolumeMuted && !mediaSettings.MusicVolumeMuted && Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				float num2 = num * 100f;
				service.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.MusicUnMuted, ActivePlayer, (int)num2, WolfWorkoutInstanceId);
			}
		}

		[DependsOn(new string[] { "TrainerVolume" })]
		public void TrainerVolumeChanged()
		{
			float trainerVolume = mediaSettings.TrainerVolume;
			float newVal = TrainerVolume.Value.Clamp(0f, 1f);
			if (trainerVolume < 1E-45f && newVal > 1E-45f && Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				float num = newVal * 100f;
				service.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.TrainerUnMuted, ActivePlayer, (int)num, WolfWorkoutInstanceId);
			}
			InvokeOnMainThread(delegate
			{
				mediaService.SetVideoVolume(newVal, commit: false);
			});
		}

		private void CheckToAdjustSystemVolume(float volume)
		{
			if (IsBuiltinWithHeadphonesConnected && volume > 0f && SystemVolume.Value.AlmostEqual(0f))
			{
				ignoreSystemVolumeSliderUpdate = true;
				SystemVolume.Value = volume;
				SystemVolumeFromSlider.Value = volume;
				ignoreSystemVolumeSliderUpdate = false;
			}
		}

		public void MusicVolumeTouched()
		{
			isUserSlidingMusicVolume = true;
		}

		public void MusicVolumeReleased()
		{
			UpdateDismissSub();
			isUserSlidingMusicVolume = false;
			CommitVolumeLevelsToStorage();
			CheckToAdjustSystemVolume(MusicVolume.Value);
			float num = (MusicVolume.Value * 100f).Clamp(0f, 100f);
			feedFmAnalyticsService.HandleVolumeChange((int)num, VolumeChangeLocation.Slider, VolumeChangeType.Music, VolumeChangeSource.Mixer);
		}

		public void TrainerVolumeTouched()
		{
			isUserSlidingTrainerVolume = true;
		}

		public void TrainerVolumeReleased()
		{
			UpdateDismissSub();
			isUserSlidingTrainerVolume = false;
			CommitVolumeLevelsToStorage();
			CheckToAdjustSystemVolume(TrainerVolume.Value);
			if (Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				Workout workout = workoutSettings.WorkoutContainer?.Workout;
				if (TrainerVolume.Value == 0f)
				{
					service.InWorkoutMusicAction(workout, AudioPlayerAction.TrainerMuted, ActivePlayer, 0, WolfWorkoutInstanceId);
				}
			}
			float num = (TrainerVolume.Value * 100f).Clamp(0f, 100f);
			feedFmAnalyticsService.HandleVolumeChange((int)num, VolumeChangeLocation.Slider, VolumeChangeType.Trainer, VolumeChangeSource.Mixer);
		}

		public void SystemVolumeTouched()
		{
			isUserSlidingSystemVolume = true;
		}

		public void SystemVolumeReleased()
		{
			UpdateDismissSub();
			CommitVolumeLevelsToStorage();
			isUserSlidingSystemVolume = false;
			UpdateSystemVolume(force: true);
			float num = (SystemVolume.Value * 100f).Clamp(0f, 100f);
			if (Mvx.TryResolve<IWolfAnalytics>(out var service))
			{
				Workout workout = workoutSettings.WorkoutContainer?.Workout;
				if (num < 1E-45f)
				{
					service.InWorkoutMusicAction(workout, AudioPlayerAction.SystemMuted, ActivePlayer, (int)num, WolfWorkoutInstanceId);
				}
				else if (mediaSettings.MusicVolume < 1E-45f && num > 1E-45f)
				{
					service.InWorkoutMusicAction(workout, AudioPlayerAction.SystemUnMuted, ActivePlayer, (int)num, WolfWorkoutInstanceId);
				}
			}
			feedFmAnalyticsService.HandleVolumeChange((int)num, VolumeChangeLocation.Slider, VolumeChangeType.Master, VolumeChangeSource.Mixer);
		}

		public void SystemVolumeSlidingStarted()
		{
			isUserSlidingSystemVolume = true;
		}

		[DependsOn(new string[] { "SystemVolumeFromSlider" })]
		protected void SystemVolumeFromSliderChanged()
		{
			if (isUserSlidingSystemVolume)
			{
				float value = SystemVolume.Value;
				SystemVolume.Value = SystemVolumeFromSlider.Value;
				int currentSystemVolume = SystemVolumeHelper.MapVolume(SystemVolume.Value);
				int previousSystemVolume = SystemVolumeHelper.MapVolume(value);
				platformMediaVolumeService.IncreaseVolumeIfNeeded(deviceInfo.IsBuiltIn, headphoneConnectionHelper.IsConnected(), previousSystemVolume, currentSystemVolume);
				UpdateSystemVolume();
			}
		}

		private void UpdateSystemVolume(bool force = false)
		{
			if (ignoreSystemVolumeSliderUpdate)
			{
				return;
			}
			DateTime utcNow = DateTime.UtcNow;
			if (!(utcNow - lastSystemVolumeTouchTime < TimeSpan.FromMilliseconds(200.0)) || force)
			{
				int num = (SystemVolume.Value * 100f).RoundToNearest(10.0);
				if (IsBuiltinWithHeadphonesConnected)
				{
					SetTrainerAndMusicVolumes(num);
				}
				else
				{
					lastSystemVolumeTouchTime = utcNow;
					SystemVolumeHelper.UpdateVolumeLevel(currentConsoleService, deviceInfo, workoutSettings, num, force);
				}
				if (!isUserSlidingSystemVolume)
				{
					SystemVolume.Value = Convert.ToSingle((double)num / 100.0);
				}
			}
		}

		private void SetTrainerAndMusicVolumes(int systemPercent)
		{
			float num = MusicVolume.Value * 100f;
			float num2 = TrainerVolume.Value * 100f;
			MusicVolume.Value = GetMusicTrainerVolumeFraction(systemPercent, num, num2);
			TrainerVolume.Value = GetMusicTrainerVolumeFraction(systemPercent, num2, num);
		}

		public static float GetMusicTrainerVolumeFraction(int systemPercent, float currentPercent, float otherPercent)
		{
			currentPercent = currentPercent.Clamp(0f, 100f);
			otherPercent = otherPercent.Clamp(0f, 100f);
			if (currentPercent.AlmostEqual(0f))
			{
				return 0f;
			}
			float num = (otherPercent.AlmostEqual(0f) ? 0f : (currentPercent / otherPercent));
			float value = ((currentPercent > otherPercent) ? ((float)systemPercent) : ((float)systemPercent * num));
			return GetRoundedMusicTrainerVolumeFraction(value);
		}

		internal static float GetRoundedMusicTrainerVolumeFraction(float value)
		{
			int num = value.RoundToNearest(10.0);
			double value2 = (double)num / 100.0;
			return Convert.ToSingle(value2);
		}

		private void UpdateMusicTrackInfo()
		{
			if (workoutSettings.WorkoutContainer?.MusicInfoService == null && !mediaService.Music.WorkoutHasFeedFmMix)
			{
				return;
			}
			if (!hasLoaded)
			{
				ShowTrackInfo.SafeUpdateValue(newValue: false);
			}
			if (IsFeedFm)
			{
				UpdateFeedFmTrack();
				return;
			}
			InvokeOnMainThread(async delegate
			{
				if (!isDisposed && AVPlayer != null)
				{
					int currentTime = Convert.ToInt32(Math.Floor(AVPlayer.AudioPosition));
					MusicTrack track = null;
					try
					{
						track = await workoutSettings.WorkoutContainer.MusicInfoService.TrackAtTime(currentTime);
					}
					catch (Exception ex)
					{
						Log.Error("Music", $"Error loading track at time ({currentTime} sec): {ex}", ex);
					}
					finally
					{
						hasLoaded = true;
					}
					if (track == null || track.IsStock)
					{
						ShowTrackInfo.SafeUpdateValue(newValue: false);
					}
					else
					{
						ShowTrackInfo.SafeUpdateValue(newValue: true);
						Album.SafeUpdateValue(track.Album ?? string.Empty);
						Artist.SafeUpdateValue(track.Artist ?? string.Empty);
						Song.SafeUpdateValue(track.Title ?? string.Empty);
					}
				}
			});
		}

		private void UpdateFeedFmTrack()
		{
			try
			{
				AudioTrack track = mediaService.Music.FeedFm?.PlayHistory?.LastOrDefault();
				IAudioService feedFm = mediaService.Music.FeedFm;
				if (feedFm == null || feedFm.ActiveState != MusicState.Playing)
				{
					IAudioService feedFm2 = mediaService.Music.FeedFm;
					if (feedFm2 == null || feedFm2.ActiveState != MusicState.PausedForMusicRegion)
					{
						track = null;
					}
				}
				UpdateFeedFmTrack(track);
			}
			catch (Exception exception)
			{
				Log.Error("Music", "Error updating FeedFm track info.", exception);
			}
		}

		private void UpdateFeedFmTrack(AudioTrack track)
		{
			InvokeOnMainThread(delegate
			{
				if (!isDisposed)
				{
					if (track == null)
					{
						ShowTrackInfo.SafeUpdateValue(newValue: false);
					}
					else
					{
						hasLoaded = true;
						ShowTrackInfo.SafeUpdateValue(newValue: true);
						AudioTrack.SafeUpdateValue(track);
					}
				}
			});
		}

		private void UpdateMusicVolumeAvailability()
		{
			ShowMusicVolume.Value = mediaService.Music.WorkoutHasMusic;
			if (ShowMusicVolume.Value && !hasSetInitialMusicVolume)
			{
				MusicVolume.Value = mediaSettings.MusicVolume;
				MusicVolumeChanged();
				hasSetInitialMusicVolume = true;
			}
		}

		private void WhenConsoleVolumeChanged(FitnessValueChange<int> metricChange)
		{
			if (!isUserSlidingSystemVolume && workoutSettings?.WorkoutContainer?.InWorkoutSystemVolumeInteractor?.IsProcessingVolumeChanges != true)
			{
				int num = metricChange.Current.RoundToNearest(10.0);
				SystemVolume.Value = Convert.ToSingle((double)num / 100.0);
				if (IsBuiltinWithHeadphonesConnected)
				{
					TrainerVolume.Value = mediaSettings.TrainerVolume;
					MusicVolume.Value = mediaSettings.MusicVolume;
				}
				UpdateDismissSub();
			}
		}

		private void UpdateDismissSub()
		{
			if (IsTablet)
			{
				dismissTimerSub?.Dispose();
				TimeSpan dueTime = ArbitraryData?.SecondsToKeepAliveAfterInteraction ?? TimeSpan.FromSeconds(15.0);
				dismissTimerSub = Observable.Timer(dueTime).ObserveOn(schedulerService.Scheduler).SubscribeAsyncWithErrorLogging(async delegate
				{
					await DoCloseWithAnimation();
					PostMixerDismissedAnalytics(dismissedByUser: false);
				});
			}
		}

		private Task DoMuteMusic()
		{
			return DoMuteVolume(MusicVolume, "PreMuteMusicVolumeKey", 0.5f);
		}

		private Task DoMuteTrainer()
		{
			return DoMuteVolume(TrainerVolume, "PreMuteTrainerVolumeKey", 1f);
		}

		private async Task DoMuteSystem()
		{
			await DoMuteVolume(SystemVolume, "PreMuteSystemVolumeKey", 0.25f);
			UpdateSystemVolume(force: true);
		}

		private async Task DoMuteVolume(INC<float> volumeNotifyChange, string preMuteVolumeKey, float defaultVolume)
		{
			if (volumeNotifyChange.Value.AlmostEqual(0f, 0.009999999776482582))
			{
				volumeNotifyChange.Value = await blobCacheService.LocalMachine.GetObject<float>(preMuteVolumeKey).Catch(Observable.Return(defaultVolume));
				return;
			}
			await blobCacheService.LocalMachine.InsertObject(preMuteVolumeKey, volumeNotifyChange.Value);
			volumeNotifyChange.Value = 0f;
		}

