		[DependsOn(new string[] { "IsConsoleRunning" })]
		protected void HandleAudioServiceActiveState()
		{
			HandleAudioServiceStateChanges(mediaService.Music?.FeedFm?.ActiveState ?? MusicState.Uninitialized);
		}

		private void HandleAudioServiceStateChanges(MusicState playerState)
		{
			if (IsFeedFm)
			{
				if ((playerState == MusicState.Ready || playerState == MusicState.PausedManually) && IsConsoleRunning.Value)
				{
					playerState = mediaService.Music?.FeedFm?.PauseTypeChanged.Value switch
					{
						PauseMusicType.PausedManually => MusicState.PausedManually, 
						PauseMusicType.PausedForMusicRegion => MusicState.PausedForMusicRegion, 
						PauseMusicType.PausedDisabled => MusicState.PausedDisabled, 
						_ => playerState, 
					};
				}
				DisableMusicVolume.Value = playerState == MusicState.PausedForMusicRegion || playerState == MusicState.PausedDisabled || (mediaSettings?.HasDisabledFeedFmPlayback ?? false);
				switch (playerState)
				{
				case MusicState.AvailableOfflineOnly:
				case MusicState.PausedManually:
				case MusicState.Ready:
					FeedFmMusicState.Value = MusicState.PausedManually;
					break;
				case MusicState.PausedForMusicRegion:
					FeedFmMusicState.Value = MusicState.PausedForMusicRegion;
					break;
				case MusicState.PausedDisabled:
					FeedFmMusicState.Value = MusicState.PausedDisabled;
					break;
				case MusicState.Playing:
					FeedFmMusicState.Value = MusicState.Playing;
					UpdateFeedFmTrack();
					break;
				case MusicState.RequestingSkip:
				case MusicState.Stalled:
				case MusicState.Uninitialized:
				case MusicState.Waiting:
					FeedFmMusicState.Value = MusicState.Loading;
					break;
				case MusicState.Complete:
				case MusicState.Unavailable:
					FeedFmMusicState.Value = MusicState.Unavailable;
					break;
				case MusicState.Idle:
				case MusicState.Loading:
				case MusicState.PausedByHeadphoneRemoval:
				case MusicState.Stopped:
					break;
				}
			}
		}

		private void DoFeedFmToggled(bool toggledOn)
		{
			mediaSettings.HasDisabledFeedFmPlayback = !toggledOn;
			messenger?.Publish(new InWorkoutFeedFmMusicToggledMessage(this, toggledOn));
		}

