		public InWorkoutMusicSettingsViewModel(ILocalSettings localSettings, IFeedFmAnalyticsService feedFmAnalyticsService, IFeedFmAvailabilityService feedFmAvailabilityService, IPersistentMusicSettings persistentMusicSettings, IInAppNotificationService notificationService, IMediaSettings mediaSettings, IMediaService mediaService, IMusicStateService musicStateService, IMvxMessenger messenger = null, IFeedFmMuteDisablingService feedFmMuteDisablingService = null)
			: base(localSettings)
		{
			try
			{
				this.feedFmMuteDisablingService = feedFmMuteDisablingService;
				this.feedFmAnalyticsService = feedFmAnalyticsService;
				this.messenger = messenger;
				this.feedFmAnalyticsService = feedFmAnalyticsService;
				this.feedFmAvailabilityService = feedFmAvailabilityService;
				this.persistentMusicSettings = persistentMusicSettings;
				this.notificationService = notificationService;
				this.mediaService = mediaService;
				this.mediaSettings = mediaSettings;
				MusicStateService = musicStateService;
				MusicStateService.OnPausedAsync = OnPausedTask;
				MusicStateService.OnPlayingAsync = OnPlayingAsync;
				MusicStateService.OnStoppedAsync = OnStoppedAsync;
				MusicStateService.OnReadyAsync = OnReadyAsync;
