		private void Init()
		{
			INC<bool> feedFmEnabledByUser = FeedFmEnabledByUser;
			IMediaSettings obj = mediaSettings;
			feedFmEnabledByUser.Value = obj == null || !obj.HasDisabledFeedFmPlayback;
			CreateFeedFmStationList();
			INC<bool> isConsoleRunning = IsConsoleRunning;
			IFitnessConsole console = currentConsoleService.Console;
			isConsoleRunning.Value = console != null && console.LatestBasicInfo?.CurrentState.IsRunningState() == true;
			UpdateTrainerSelectStationTextVisible();
			consoleStateSub?.Dispose();
			consoleStateSub = currentConsoleService.Console?.WhenStateChanged.SubscribeWithErrorLogging(delegate(StateChange sc)
			{
				IsConsoleRunning.Value = sc.Current.IsRunningState();
				UpdateTrainerSelectStationTextVisible();
			});
			MusicStateService.Init(mediaService.Music.FeedFm);
			stationChangeSub?.Dispose();
			stationChangeSub = WorkoutAudioService?.WhenStationChanged?.SubscribeAsyncWithErrorLogging(HandleStationChanged);
			currentStationIsTrainerSelectChangeSub?.Dispose();
			currentStationIsTrainerSelectChangeSub = mediaService.Music.CurrentStationIsTrainerSelectChanged.Subscribe(delegate(bool currentStationIsTrainerSelect)
			{
				UpdateTrainerSelectStationTextVisible();
				if (currentStationIsTrainerSelect)
				{
					SetStationChangerVisibility(isVisible: false);
				}
			});
			liveWorkoutMusicStateChangedSub?.Dispose();
			liveWorkoutMusicStateChangedSub = mediaService.Music.LiveWorkoutMusicStateChanged.Subscribe(delegate(LiveWorkoutMusicState liveWorkoutMusicState)
			{
				if (liveWorkoutMusicState != LiveWorkoutMusicState.Other)
				{
					SetStationChangerVisibility(isVisible: false);
				}
			});
			IFeedFmMuteDisablingService obj2 = feedFmMuteDisablingService;
			if (obj2 != null && obj2.IsEnabled)
			{
				feedFmSTurnOnFromOffscreen?.Dispose();
				feedFmSTurnOnFromOffscreen = feedFmMuteDisablingService.FeedFmTurnedOn.SubscribeWithErrorLogging(OnFeedFmTurnedOn);
			}
			RefreshStationList();
		}

		private void OnFeedFmTurnedOn(bool arg)
		{
			INC<bool> feedFmEnabledByUser = FeedFmEnabledByUser;
			IMediaSettings obj = mediaSettings;
			feedFmEnabledByUser.Value = obj == null || !obj.HasDisabledFeedFmPlayback;
		}

		private void UpdateTrainerSelectStationTextVisible()
		{
			INC<bool> trainerSelectStationTextVisible = TrainerSelectStationTextVisible;
			int value;
			if (!mediaSettings.HasDisabledFeedFmPlayback)
			{
				IFitnessConsole console = currentConsoleService.Console;
				if (console == null || console.LatestBasicInfo?.CurrentState != ConsoleState.WarmUp)
				{
					value = (mediaService.Music.CurrentStationIsTrainerSelect ? 1 : 0);
					goto IL_0070;
				}
			}
			value = 0;
			goto IL_0070;
			IL_0070:
			trainerSelectStationTextVisible.Value = (byte)value != 0;
		}

		private void RefreshStationList()
		{
			if (Stations == null || Stations.Count < 1)
			{
				CreateFeedFmStationList();
			}
			RefreshCurrentlySelectedStationStatuses();
		}

		private void RefreshCurrentlySelectedStationStatuses()
		{
			Stations?.DoForEach(delegate(StationChangerItemViewModel x)
			{
				x.Selected.Value = false;
			}, ignoreNulls: true);
			if (CurrentStation != null)
			{
				CurrentStation.Selected.Value = true;
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			RefreshStationList();
		}

		private void CreateFeedFmStationList()
		{
			List<StationChangerItemViewModel> list = new List<StationChangerItemViewModel>();
			WorkoutStationModel workoutStationModel = mediaService?.Music?.FeedFmStations;
			List<AudioPlayerStation> list2 = WorkoutAudioService?.Stations;
			if (list2 == null)
			{
				Log.Error("Audio", "Unable to initialize audio stations because WorkoutAudioService.Stations is null");
				return;
			}
			if (workoutStationModel == null)
			{
				Log.Error("Audio", "Unable to initialize audio stations because popMixes is null");
				return;
			}
			if (mediaService.Music.ShouldListAllSelectableStationsFromSdk && list2.Count > 0)
			{
				list.AddRange((from x in list2.Where((AudioPlayerStation x) => x != null && x.IsSelectableStation && !string.IsNullOrWhiteSpace(x.Id)).DistinctBy((AudioPlayerStation x) => x.Id)
					select new StationChangerItemViewModel(x))?.ToList());
			}
			else
			{
				foreach (Mix recStation in workoutStationModel.AvailableStations.ToList())
				{
					AudioPlayerStation audioPlayerStation = list2.FirstOrDefault((AudioPlayerStation x) => x.Id == recStation.StationId);
					if (audioPlayerStation != null && audioPlayerStation.IsSelectableStation && !string.IsNullOrWhiteSpace(recStation.StationId))
					{
						list.Add(new StationChangerItemViewModel(audioPlayerStation));
					}
				}
			}
			IFeedFmAvailabilityService obj = feedFmAvailabilityService;
			if (obj != null && obj.IsFeedFmTrainerFavoritesFeatureEnabledForDevice() && !string.IsNullOrWhiteSpace(mediaService.Music.FeedFmStations?.TrainerId))
			{
				AudioPlayerStation audioPlayerStation2 = list2.FirstOrDefault((AudioPlayerStation x) => x.TFSTrainerId == mediaService.Music.FeedFmStations.TrainerId);
				if (audioPlayerStation2 != null)
				{
					list.Add(new StationChangerItemViewModel(audioPlayerStation2, isTrainerFavoriteStation: true));
				}
			}
			List<StationChangerItemViewModel> source = (from x in list
				orderby x.IsTrainerFavoriteStation.Value, x.SortOrder ?? string.Empty, x.DisplayName.Value
				select x).ToList();
			foreach (StationChangerItemViewModel item in source.Take(12))
			{
				Stations.Add(item);
			}
			IEnumerable<string> values = Stations.Select((StationChangerItemViewModel x) => x.DisplayName.Value);
			Log.Trace("Audio", "All station display names: [" + string.Join(", ", values) + "]");
			Stations.DoForEach(delegate(StationChangerItemViewModel x)
			{
				x.Enabled.Value = !StationChangePending.Value;
			});
			UpdateCurrentlyPlayingStationStatuses(WorkoutAudioService?.ActiveState);
			SetNewStations();
		}

		private void SetNewStations()
		{
			string[] newStations = (from x in featureFlagManager?.GetString(FeatureFlags.WolfFeedFMNewStations)?.Split(',')
				select x.Trim() into x
				where !string.IsNullOrWhiteSpace(x)
				select x).ToArray();
			string[] array = newStations;
			if (array != null && !array.IsEmpty())
			{
				Stations.Where((StationChangerItemViewModel x) => Enumerable.Contains(newStations, x.Id.Value)).DoForEach(delegate(StationChangerItemViewModel x)
				{
					x.IsNew.Value = true;
				});
			}
		}

		private async Task HandleStationChanged(AudioPlayerStation obj)
		{
			if (requestedStation?.Id?.Value == null || !FeedFmEnabledByUser.Value)
			{
				return;
			}
			TaskCompletionSource<object> tcs = new TaskCompletionSource<object>();
			using (mediaService?.Music?.FeedFm?.WhenPlayStarted.Subscribe(delegate
			{
				tcs.SetResult(null);
			}))
			{
				await tcs.Task;
			}
			requestedStation = null;
			StationChangePending.Value = false;
			if (isDisposed)
			{
				return;
			}
			foreach (StationChangerItemViewModel station in Stations)
			{
				station.IsLoading.Value = false;
				station.Enabled.Value = true;
			}
			RefreshCurrentlySelectedStationStatuses();
			stationLoadingStopwatch.Stop();
			feedFmAnalyticsService.CalculateMaxStationLoadingTime(stationLoadingStopwatch.Elapsed.TotalSeconds);
			feedFmAnalyticsService.HandleStationChanged(obj.DisplayName);
			messenger?.Publish(new InWorkoutMusicSettingsActionMessage(this));
		}

		private void DoFeedFmToggled(bool toggledOn)
		{
			if (!toggledOn)
			{
				stationChangeCTS?.Cancel();
				ResetStationChangerButtons();
				StationChangePending.Value = false;
				mediaService.Music?.FeedFmDisabled();
			}
			bool flag = FeedFmMusicState.Value == MusicState.Loading;
			mediaSettings.HasDisabledFeedFmPlayback = !toggledOn;
			IFeedFmMuteDisablingService obj = feedFmMuteDisablingService;
			if (obj != null && obj.IsEnabled)
			{
				feedFmMuteDisablingService?.UpdateMusicVolumeOnFeedFmToggleOn(mediaService);
			}
			messenger?.Publish(new InWorkoutMusicControlsViewModel.InWorkoutFeedFmMusicToggledMessage(this, toggledOn));
			messenger?.Publish(new InWorkoutMusicSettingsActionMessage(this, flag, flag));
			UpdateTrainerSelectStationTextVisible();
			OnFeedFmTurnedOn(toggledOn);
		}

		private void SetStationChangerVisibility(bool isVisible)
		{
			StationChangerVisible.Value = FeedFmStationChangerEnabled && !mediaService.Music.CurrentStationIsTrainerSelect && mediaService.Music.LiveWorkoutMusicState == LiveWorkoutMusicState.Other && isVisible;
		}

		private async Task OnPausedTask()
		{
			IMediaService obj = mediaService;
			int num;
			if (obj == null)
			{
				num = 0;
			}
			else
			{
				IMusicService music = obj.Music;
				if (music == null)
				{
					num = 0;
				}
				else
				{
					IAudioService feedFm = music.FeedFm;
					if (feedFm == null)
					{
						num = 0;
					}
					else
					{
						_ = feedFm.PauseTypeChanged.Value;
						num = 1;
					}
				}
			}
			if (num == 0)
			{
				return;
			}
			switch (mediaService.Music.FeedFm.PauseTypeChanged.Value)
			{
			case PauseMusicType.PausedManually:
				FeedFmMusicState.Value = MusicState.PausedManually;
				SetStationChangerVisibility(isVisible: false);
				break;
			case PauseMusicType.PausedForMusicRegion:
				FeedFmMusicState.Value = MusicState.PausedForMusicRegion;
				foreach (StationChangerItemViewModel station in Stations)
				{
					station.Enabled.Value = station.Selected.Value;
				}
				SetStationChangerVisibility(FeedFmEnabledByUser.Value);
				break;
			case PauseMusicType.PausedByHeadphoneRemoval:
				FeedFmMusicState.Value = MusicState.PausedByHeadphoneRemoval;
				SetStationChangerVisibility(isVisible: false);
				break;
			case PauseMusicType.PausedDisabled:
				FeedFmMusicState.Value = MusicState.PausedDisabled;
				SetStationChangerVisibility(isVisible: false);
				break;
			}
			UpdateCurrentlyPlayingStationStatuses(FeedFmMusicState.Value);
			RefreshCurrentlySelectedStationStatuses();
			Log.Trace("Audio", $"MusicState == {FeedFmMusicState.Value}. StationChangerVisible == {StationChangerVisible.Value}.");
		}

		private async Task OnPlayingAsync()
		{
			FeedFmMusicState.Value = MusicState.Playing;
			foreach (StationChangerItemViewModel station in Stations)
			{
				station.Enabled.Value = true;
				station.IsLoading.Value = false;
			}
			RefreshStationList();
			SetStationChangerVisibility(isVisible: true);
			UpdateCurrentlyPlayingStationStatuses(FeedFmMusicState.Value);
			RefreshCurrentlySelectedStationStatuses();
			Log.Trace("Audio", $"MusicState == {FeedFmMusicState.Value}. StationChangerVisible == {StationChangerVisible.Value}.");
		}

		private async Task OnStoppedAsync()
		{
			FeedFmMusicState.Value = MusicState.Unavailable;
			SetStationChangerVisibility(isVisible: false);
			UpdateCurrentlyPlayingStationStatuses(FeedFmMusicState.Value);
			RefreshCurrentlySelectedStationStatuses();
			Log.Trace("Audio", $"MusicState == {FeedFmMusicState.Value}. StationChangerVisible == {StationChangerVisible.Value}.");
		}

		private async Task OnReadyAsync()
		{
			if (workoutSettings?.WorkoutContainer?.WorkoutRunner is LiveWorkoutRunner)
			{
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				if (activeConsole != null && activeConsole.LatestBasicInfo?.CurrentState == ConsoleState.WarmUp)
				{
					FeedFmMusicState.Value = MusicState.PausedManually;
					goto IL_00a5;
				}
			}
			FeedFmMusicState.Value = (mediaSettings.HasDisabledFeedFmPlayback ? MusicState.PausedManually : MusicState.Loading);
			goto IL_00a5;
			IL_00a5:
			SetStationChangerVisibility(!mediaSettings.HasDisabledFeedFmPlayback);
			UpdateCurrentlyPlayingStationStatuses(FeedFmMusicState.Value);
			RefreshCurrentlySelectedStationStatuses();
			Log.Trace("Audio", $"MusicState == {FeedFmMusicState.Value}. StationChangerVisible == {StationChangerVisible.Value}.");
		}

		private async Task OnLoadingAsync()
		{
			FeedFmMusicState.Value = MusicState.Loading;
			SetStationChangerVisibility(isVisible: true);
			UpdateCurrentlyPlayingStationStatuses(FeedFmMusicState.Value);
			RefreshCurrentlySelectedStationStatuses();
			Log.Trace("Audio", $"MusicState == {FeedFmMusicState.Value}. StationChangerVisible == {StationChangerVisible.Value}.");
		}

		private void UpdateCurrentlyPlayingStationStatuses(MusicState? playerState)
		{
			Stations?.DoForEach(delegate(StationChangerItemViewModel x)
			{
				x.Playing.Value = false;
			}, ignoreNulls: true);
			if (CurrentStation != null && playerState == MusicState.Playing)
			{
				CurrentStation.Playing.Value = true;
			}
		}

		private async Task DoHandleStationSelected(StationChangerItemViewModel model)
		{
			if (model == null)
			{
				Log.Error("Audio", "DoHandleStationSelected called with null parameter model.");
				return;
			}
			if (model == CurrentStation)
			{
				Log.Error("Audio", "DoHandleStationSelected called, but parameter model and CurrentStation are the same.");
				return;
			}
			if (WorkoutAudioService == null)
			{
				Log.Error("Audio", "DoHandleStationSelected called, but WorkoutAudioService is null.");
				return;
			}
			Log.Trace("Audio", "DoHandleStationSelected called with station: " + (model.Id?.Value ?? "null"));
			if (!base.IsInternetConnectionAvailable)
			{
				dialogPresenter?.ShowToast(Wolf.Core.Resources.AppStrings.default_no_wifi_title);
				StationNotChanged(Wolf.Core.Resources.AppStrings.default_no_internet_connection_title);
				return;
			}
			stationLoadingStopwatch.Reset();
			stationLoadingStopwatch.Start();
			messenger?.Publish(new InWorkoutMusicSettingsActionMessage(this, stationIsLoading: true));
			StationChangePending.Value = true;
			requestedStation = model;
			foreach (StationChangerItemViewModel station in Stations)
			{
				if (station == model)
				{
					persistentMusicSettings.LastStationUserSelected = station.Id.Value;
					station.IsLoading.Value = true;
					station.Selected.Value = true;
				}
				else
				{
					station.Enabled.Value = false;
					station.Selected.Value = false;
				}
			}
			stationChangeCTS?.Cancel();
			stationChangeCTS?.Dispose();
			stationChangeCTS = new CancellationTokenSource();
			bool success = false;
			try
			{
				success = await WorkoutAudioService.QueueStationWithId(model.Id.Value, stationChangeCTS.Token).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				Log.Error("Audio", ex.GetType().Name + " occurred in WorkoutAudioService.QueueStationWithId", ex);
			}
			if (!success)
			{
				StationNotChanged();
			}
		}

		private void StationNotChanged(string message = "")
		{
			Log.Error("Audio", "Station change unsuccessful. " + message);
			StationChangePending.Value = false;
			requestedStation = null;
			ResetStationChangerButtons();
		}

		private void ResetStationChangerButtons()
		{
			foreach (StationChangerItemViewModel station in Stations)
			{
				station.IsLoading.Value = false;
				station.Enabled.Value = true;
				station.Selected.Value = station.Id.Value == WorkoutAudioService.ActiveStation.Id;
			}
		}

		public override void Dispose()
		{
			consoleStateSub?.Dispose();
			consoleStateSub = null;
			feedFmServiceStateChanged?.Dispose();
			feedFmServiceStateChanged = null;
			stationChangeSub?.Dispose();
			stationChangeSub = null;
			currentStationIsTrainerSelectChangeSub?.Dispose();
			currentStationIsTrainerSelectChangeSub = null;
			liveWorkoutMusicStateChangedSub?.Dispose();
			liveWorkoutMusicStateChangedSub = null;
			stationLoadingStopwatch = null;
			stationChangeCTS?.Cancel();
			stationChangeCTS?.Dispose();
			stationChangeCTS = null;
			MusicStateService?.Dispose();
			MusicStateService = null;
			feedFmSTurnOnFromOffscreen?.Dispose();
			feedFmSTurnOnFromOffscreen = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

