			timerTickSub = null;
			dismissTimerSub?.Dispose();
			dismissTimerSub = null;
			volumeMetricSub?.Dispose();
			volumeMetricSub = null;
			consoleStateSub?.Dispose();
			consoleStateSub = null;
			feedFmServiceStateChanged?.Dispose();
			feedFmServiceStateChanged = null;
			musicVolumeChanged?.Dispose();
			musicVolumeChanged = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

