	public class StationChangerItemViewModel : MvxViewModel
	{
		public readonly INC<bool> Enabled = new NC<bool>();

		public readonly INC<bool> Playing = new NC<bool>();

		public readonly INC<bool> Selected = new NC<bool>();

		public readonly INC<bool> IsLoading = new NC<bool>();

		public readonly INC<bool> IsNew = new NC<bool>();

		public readonly INC<bool> IsTrainerFavoriteStation = new NC<bool>();

		public readonly INC<string> Id = new NC<string>();

		public readonly INC<string> DisplayName = new NC<string>();

		public string SortOrder { get; private set; }

		public StationChangerItemViewModel(AudioPlayerStation station, bool isTrainerFavoriteStation = false)
		{
			Id.Value = station.Id;
			SortOrder = station.SortOrder ?? string.Empty;
			IsTrainerFavoriteStation.Value = isTrainerFavoriteStation;
			SetAppropriateDisplayName(station);
		}

		private void SetAppropriateDisplayName(AudioPlayerStation station)
		{
			DisplayName.Value = station.DisplayName;
			if (station.TranslatedNames.CountSafe() > 0 && Mvx.TryResolve<IChangeLanguageService>(out var languageService))
			{
				KeyValuePair<string, string> keyValuePair = station.TranslatedNames.FirstOrDefault((KeyValuePair<string, string> kvp) => kvp.Key.Equals(languageService.CurrentLanguageTwoLetterISOCode, StringComparison.InvariantCultureIgnoreCase));
				if (!string.IsNullOrWhiteSpace(keyValuePair.Value))
				{
					DisplayName.Value = keyValuePair.Value;
				}
			}
		}
	}
