	public class WorkoutMusicInfoService : IWorkoutMusicInfoService, IDisposable
	{
		private const string Tag = "Music";

		private const int WorkoutMusicTracksCacheDays = 1;

		private const string TrackInfoUrlFormat = "https://ifit-music.s3-cdn.ifit.com/{0}.json";

		private static readonly Regex trackFileIdRegex = new Regex("^https?\\:\\/\\/(ifit-music\\.)?s3\\.amazonaws\\.com\\/(ifit-music\\/)?([a-z0-9]+)\\.([a-z0-9]{2,10})$", RegexOptions.IgnoreCase);

		private static readonly Regex newTrackFileIdRegex = new Regex("^https?\\:\\/\\/ifit-music\\.s3-cdn\\.ifit\\.com\\/([a-z0-9]+)\\.([a-z0-9]{2,10})$", RegexOptions.IgnoreCase);

		private bool isDisposed;

		private List<CancellationTokenSource> cancellationTokenSources = new List<CancellationTokenSource>();

		private readonly IBlobCache cache;

		private readonly Workout workout;

		private IList<MusicTrack> _musicTracks;

		private readonly ISubject<IList<MusicTrack>> _whenMusicInfoChanged = new Subject<IList<MusicTrack>>();

		public bool HasMusicTrackInfo => _musicTracks.CountSafe() > 0;

		public IList<MusicTrack> MusicTracks
		{
			get
			{
				return _musicTracks;
			}
			protected set
			{
				_musicTracks = value?.OrderBy((MusicTrack t) => t.TrackStartTimeSeconds)?.ToList();
				_whenMusicInfoChanged.OnNext(_musicTracks);
			}
		}

		public IObservable<IList<MusicTrack>> WhenMusicInfoChanged => _whenMusicInfoChanged.AsObservable();

		public WorkoutMusicInfoService(Workout workout, IBlobCache cache, bool automaticallyStartLoad = true)
		{
			this.workout = workout;
			this.cache = cache;
			if (automaticallyStartLoad)
			{
				Task.Run((Func<Task>)LoadMusicTracks);
			}
		}

		public virtual async Task LoadMusicTracks()
		{
			string trackFileId = GetTrackFileId(workout);
			if (string.IsNullOrWhiteSpace(trackFileId))
			{
				return;
			}
			string cacheKey = "workoutmusictrackinfo-" + trackFileId;
			CancellationTokenSource newCts = new CancellationTokenSource();
			cancellationTokenSources.Add(newCts);
			if (cache != null)
			{
				MusicTracks = (from t in (await cache.GetOrFetchObject(cacheKey, Fetch, DateTimeOffset.Now.AddDays(1.0)))?.Where((MusicTrack t) => t != null)
					orderby t.TrackStartTimeSeconds
					select t)?.ToList();
				if (MusicTracks.CountSafe() < 1)
				{
					await cache.InvalidateObject<IList<MusicTrack>>(cacheKey);
				}
			}
			async Task<IList<MusicTrack>> Fetch()
			{
				return await FetchMusicTracks(trackFileId, newCts.Token);
			}
		}

		public async Task<MusicTrack> TrackAtTime(int seconds)
		{
			return await Task.Run(() => _musicTracks?.Where((MusicTrack t) => t.TrackStartTimeSeconds <= seconds)?.LastOrDefault());
		}

		private static async Task<IList<MusicTrack>> FetchMusicTracks(string trackFileId, CancellationToken token)
		{
			string url = $"https://ifit-music.s3-cdn.ifit.com/{trackFileId}.json";
			IList<MusicTrack> tracks = null;
			try
			{
				tracks = await JsonDownloadUtil.DownloadAndParseJson<IList<MusicTrack>>(url, null, token);
			}
			catch (Exception exception)
			{
				Log.Error("Music", "Could not download and parse music track information", exception);
			}
			return tracks;
		}

		private static string GetTrackFileId(Workout workout)
		{
			if (workout == null || !workout.HasAudioMetadata())
			{
				return null;
			}
			string text = workout?.GetWorkoutMetadataAudioUrl();
			string trackFileIdFromFormat = GetTrackFileIdFromFormat(text, trackFileIdRegex, 3);
			if (!string.IsNullOrWhiteSpace(trackFileIdFromFormat))
			{
				return trackFileIdFromFormat;
			}
			string trackFileIdFromFormat2 = GetTrackFileIdFromFormat(text, newTrackFileIdRegex, 1);
			if (!string.IsNullOrWhiteSpace(trackFileIdFromFormat2))
			{
				return trackFileIdFromFormat2;
			}
			Log.Error("Music", "Unable to parse track file ID from string: " + text);
			return null;
		}

		private static string GetTrackFileIdFromFormat(string url, Regex regex, int valueIndex)
		{
			if (url == null)
			{
				return null;
			}
			if (valueIndex < 0)
			{
				return null;
			}
			GroupCollection groupCollection = regex?.Match(url)?.Groups;
			if ((groupCollection?.Count).GetValueOrDefault() >= valueIndex + 1 && !string.IsNullOrWhiteSpace(groupCollection[valueIndex]?.Value))
			{
				return groupCollection[valueIndex].Value.Trim();
			}
			return null;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		public void Dispose(bool disposing)
		{
			if (isDisposed)
			{
				return;
			}
			if (disposing)
			{
				cancellationTokenSources?.DoForEach(delegate(CancellationTokenSource t)
				{
					t?.Cancel();
					t?.Dispose();
				});
				cancellationTokenSources?.Clear();
				cancellationTokenSources = null;
				_musicTracks?.Clear();
				_musicTracks = null;
			}
			isDisposed = true;
		}
	}
	public class WorkoutPopMusicInfoService : IWorkoutMusicInfoService, IDisposable
	{
		private const string Tag = "Music";

		private bool isDisposed;

		private readonly Mix mix;

		private readonly IIfitApiService ifitApi;

		private Subject<IList<MusicTrack>> _whenMusicInfoChanged = new Subject<IList<MusicTrack>>();

		public bool HasMusicTrackInfo => true;

		private bool MixHasValidId => !string.IsNullOrWhiteSpace(mix?.Id);

		public IObservable<IList<MusicTrack>> WhenMusicInfoChanged => _whenMusicInfoChanged?.AsObservable();

		public WorkoutPopMusicInfoService(Mix mix, IIfitApiService ifitApi)
		{
			this.mix = mix;
			this.ifitApi = ifitApi;
		}

		public async Task<MusicTrack> TrackAtTime(int seconds)
		{
			MixTrack mixTrack = await MixTrackAtTime(seconds).ConfigureAwait(continueOnCapturedContext: false);
			if (mixTrack?.Track == null)
			{
				return null;
			}
			if (mix.IsRadioStation)
			{
				return new MusicTrack
				{
					Album = mixTrack.Track.Album,
					Artist = mixTrack.Track.Artist,
					Title = mixTrack.Track.Title
				};
			}
			return new MusicTrack
			{
				Album = mixTrack.Track.Album,
				Artist = mixTrack.Track.Artist,
				Title = mixTrack.Track.Title,
				TrackStartTimeSeconds = mixTrack.At,
				IsStock = (mixTrack.Track.IsStockMusic == true)
			};
		}

		public async Task<MixTrack> MixTrackAtTime(int seconds)
		{
			if (mix == null)
			{
				return null;
			}
			if (mix.IsRadioStation)
			{
				Track track;
				try
				{
					track = await Mix.GetMixStatus(ifitApi, mix.Id);
				}
				catch (Exception exception)
				{
					Log.Error("Music", "Error occurred getting mix status", exception);
					return null;
				}
				return new MixTrack
				{
					Track = track
				};
			}
			return mix.Tracks?.OrderBy((MixTrack t) => t.At)?.Where((MixTrack t) => t.At <= seconds)?.LastOrDefault();
		}

		public async Task NotifyMixPlayed()
		{
			if (!isDisposed && MixHasValidId)
			{
				Log.Trace("Updating", "Notifying mix played, mix ID: " + mix.Id);
				await Mix.NotifyMixPlayed(ifitApi, mix.Id).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public async Task NotifyTrackPlayed(string trackId)
		{
			if (!isDisposed && MixHasValidId && !string.IsNullOrWhiteSpace(trackId))
			{
				Log.Trace("Updating", "Notifying track played, track ID: " + trackId);
				await MixTrack.NotifyMixTrackPlayed(ifitApi, trackId).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public async Task LoadMusicTracks()
		{
			await Task.Delay(0);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		public void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					_whenMusicInfoChanged?.Dispose();
					_whenMusicInfoChanged = null;
				}
				isDisposed = true;
			}
		}
	}
