namespace Wolf.Core.Music.FeedFm
{
	public class FeedFmAvailabilityService : IFeedFmAvailabilityService
	{
		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IDeviceInformation deviceInfo;

		private readonly IIfitApiService ifitApi;

		public FeedFmAvailabilityService(IFeatureFlagManager featureFlagManager, IDeviceInformation deviceInfo, IIfitApiService ifitApi)
		{
			this.featureFlagManager = featureFlagManager;
			this.deviceInfo = deviceInfo;
			this.ifitApi = ifitApi;
		}

		public bool IsFeedFmTrainerSelectFeatureEnabledForDevice()
		{
			bool flag = deviceInfo?.IsBuiltIn ?? false;
			bool flag2 = deviceInfo?.IsStrengthMirror ?? false;
			bool flag3 = featureFlagManager?.IsFeatureEnabled(FeatureFlags.WolfFeedFMTrainerSelectStationsFeature) ?? false;
			if (IsFeedFmFeatureEnabledForDevice() && flag && flag3)
			{
				return !flag2;
			}
			return false;
		}

		public bool IsFeedFmTrainerFavoritesFeatureEnabledForDevice()
		{
			bool flag = featureFlagManager?.IsFeatureEnabled(FeatureFlags.WolfFeedFMTrainerFavoriteStationFeatureFlag) ?? false;
			return IsFeedFmFeatureEnabledForDevice() && flag;
		}

		public bool IsFeedFmFeatureEnabledForDevice()
		{
			User currentlyAuthenticatedUser = ifitApi.CurrentlyAuthenticatedUser;
			if (currentlyAuthenticatedUser == null || currentlyAuthenticatedUser.Premium != true)
			{
				Log.Trace("Audio", "FeedFm feature not enabled: current user is not premium");
				return false;
			}
			if (featureFlagManager == null)
			{
				Log.Trace("Audio", "FeedFm feature not enabled: FeatureFlagManager not resolved.");
				return false;
			}
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMFeature))
			{
				Log.Trace("Audio", "FeedFm Feature not enabled: WolfFeedFMFeature was not enabled");
				return false;
			}
			if (!deviceInfo.IsBuiltIn)
			{
				if (deviceInfo.IsTablet)
				{
					if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMFeatureTablet))
					{
						Log.Trace("Audio", "FeedFm Feature not enabled for ble tablet: WolfFeedFMFeatureTablet was not enabled");
						return false;
					}
				}
				else if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMFeaturePhone))
				{
					Log.Trace("Audio", "FeedFm Feature not enabled for ble phone: WolfFeedFMFeaturePhone was not enabled");
					return false;
				}
			}
			else if (deviceInfo.IsStrengthMirror && !featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMFeatureStrengthMirror))
			{
				Log.Trace("Audio", "FeedFm Feature not enabled for strength mirror: WolfFeedFMFeatureStrengthMirror was not enabled");
				return false;
			}
			return true;
		}

		public bool ShouldUseStationChangeViewModels()
		{
			return IsFeedFmFeatureEnabledForDevice();
		}

		public bool ShouldShowStationChanger()
		{
			if (ShouldUseStationChangeViewModels())
			{
				return featureFlagManager?.IsFeatureEnabled(FeatureFlags.WolfFeedFMStationChanger) ?? false;
			}
			return false;
		}

		public bool IsFeedFmFeatureEnabledForWorkout(Workout workout)
		{
			if (workout == null || !IsFeedFmFeatureEnabledForDevice())
			{
				return false;
			}
			if (workout.IsGoogleMap)
			{
				if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMMapWorkouts))
				{
					Log.Trace("Audio", "FeedFm Feature not enabled for map workout, but WolfFeedFMMapWorkouts was not enabled");
					return false;
				}
			}
			else if (!workout.IsVideoWorkout() && !featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMManualWorkouts))
			{
				Log.Trace("Audio", "FeedFm Feature not enabled for manual workout, but WolfFeedFMManualWorkouts was not enabled");
				return false;
			}
			Log.Trace("Audio", "FeedFm Feature is enabled");
			return true;
		}

		public bool GetDefaultEnabledState()
		{
			IDeviceInformation deviceInformation = deviceInfo;
			if (deviceInformation != null && deviceInformation.IsBuiltIn)
			{
				return true;
			}
			return featureFlagManager?.IsFeatureEnabled(FeatureFlags.WolfFeedFmBleDefaultStateEnabled) ?? false;
		}
	}
