	public class FeedFmNativeStationService : IFeedFmNativeStationService
	{
		protected const string DefaultStationId = "cardio-v1";

		private static readonly IReadOnlyList<string> OmittedMusicCategories = new List<string> { "audio only", "outdoor audio only", "ted talk", "ted talks" };

		private readonly IFeedFmAvailabilityService feedFmAvailabilityService;

		public FeedFmNativeStationService(IFeedFmAvailabilityService feedFmAvailabilityService)
		{
			this.feedFmAvailabilityService = feedFmAvailabilityService;
		}

		public Mix FeedFmMixForWorkout(Workout workout)
		{
			if (workout == null)
			{
				return null;
			}
			if (!feedFmAvailabilityService.IsFeedFmFeatureEnabledForWorkout(workout))
			{
				return null;
			}
			return Mix.BuildMixFromFeedFmStationId("cardio-v1");
		}

		public static bool WorkoutNotApplicableForMusic(Workout workout)
		{
			return workout?.DoesContainAtLeastOneCategoryFromList(OmittedMusicCategories) ?? false;
		}
	}
	public class FeedFmVideoLoadingWatcher : IDisposable
	{
		private readonly TimeSpan loadingTimeout;

		private int totalNumberOfLoadingTimeouts;

		private bool waitingForVideoResumeAfterTimeout;

		private IDisposable videoIsLoadingChangedSub;

		private readonly Subject<int> onVideoLoadingTimeout = new Subject<int>();

		private readonly Subject<int> onVideoResumedAfterLoadingTimeout = new Subject<int>();

		private CancellationTokenSource cts;

		public IObservable<int> OnVideoLoadingTimeout => onVideoLoadingTimeout;

		public IObservable<int> OnVideoResumedAfterLoadingTimeout => onVideoResumedAfterLoadingTimeout;

		public FeedFmVideoLoadingWatcher(TimeSpan loadingTimeout, IObservable<bool> whenIsLoadingChanged)
		{
			this.loadingTimeout = loadingTimeout;
			videoIsLoadingChangedSub = whenIsLoadingChanged?.SubscribeAsync(HandleVideoIsLoadingChangedAsync);
		}

		private async Task HandleVideoIsLoadingChangedAsync(bool isLoading)
		{
			if (isLoading)
			{
				if (cts == null)
				{
					cts = new CancellationTokenSource();
					CancellationToken cancellationToken = cts.Token;
					await Task.Delay(loadingTimeout);
					if (!cancellationToken.IsCancellationRequested)
					{
						waitingForVideoResumeAfterTimeout = true;
						totalNumberOfLoadingTimeouts++;
						onVideoLoadingTimeout.OnNext(totalNumberOfLoadingTimeouts);
					}
				}
			}
			else
			{
				cts?.Cancel();
				cts = null;
				if (waitingForVideoResumeAfterTimeout)
				{
					onVideoResumedAfterLoadingTimeout.OnNext(totalNumberOfLoadingTimeouts);
					waitingForVideoResumeAfterTimeout = false;
				}
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				videoIsLoadingChangedSub?.Dispose();
				videoIsLoadingChangedSub = null;
			}
		}
	}
