	public class FeedFmNotificationViewModel : NotificationViewModel<FeedFmNotificationData>
	{
		public class FeedFmNotificationTapped : MvxMessage
		{
			public FeedFmNotificationTapped(object sender)
				: base(sender)
			{
			}
		}

		public class FeedFmNotificationDismissed : MvxMessage
		{
			public FeedFmNotificationDismissed(object sender)
				: base(sender)
			{
			}
		}

		public readonly INC<bool> WasFeedFmNotificationTapped = new NC<bool>();

		public readonly INC<AudioTrack> AudioTrack = new NC<AudioTrack>();

		private readonly IFeedFmAnalyticsService feedFmAnalyticsService;

		private readonly IMvxMessenger mvxMessenger;

		private MvxSubscriptionToken feedFmNotificationDismissed;

		public FeedFmNotificationViewModel(IInAppNotificationService notificationService, IHowlService howlService, IFeedFmAnalyticsService feedFmAnalyticsService = null, IMvxMessenger mvxMessenger = null)
			: base(notificationService, howlService)
		{
			try
			{
				this.feedFmAnalyticsService = feedFmAnalyticsService;
				this.mvxMessenger = mvxMessenger;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task Init(string guid)
		{
			await base.Init(guid).ConfigureAwait(continueOnCapturedContext: false);
			AudioTrack.Value = base.Data?.AudioTrack;
		}

		public override void Dispose()
		{
			base.Dispose();
			CleanUpSubscriptions();
			UnregisterChangeHandlers();
		}

		private void CleanUpSubscriptions()
		{
			feedFmNotificationDismissed?.Dispose();
			feedFmNotificationDismissed = null;
		}

		public void ReloadNotificationContent(string guid)
		{
			ReloadData(guid);
			AudioTrack.Value = base.Data?.AudioTrack;
		}

		public void HandleNotificationTap(bool showMusicControlsDialog = true)
		{
			Log.Trace("Audio", "Feed.fm notification tapped. Track info: " + (AudioTrack?.Value?.ToString() ?? "<null>"));
			Log.Trace("Audio", string.Format("{0}: {1}", "showMusicControlsDialog", showMusicControlsDialog));
			if (!showMusicControlsDialog)
			{
				return;
			}
			if (WasFeedFmNotificationTapped.Value)
			{
				Log.Trace("Navigation", "WasFeedFmNotificationTapped is already True. Not sending FeedFmNotificationTapped.");
				return;
			}
			WasFeedFmNotificationTapped.Value = true;
			Log.Trace("Navigation", "Sending FeedFmNotificationTapped from Feed.FM notification.");
			mvxMessenger.Publish(new FeedFmNotificationTapped(this));
			feedFmNotificationDismissed?.Dispose();
			feedFmNotificationDismissed = null;
			feedFmNotificationDismissed = mvxMessenger?.Subscribe<FeedFmNotificationDismissed>(delegate
			{
				WasFeedFmNotificationTapped.Value = false;
			});
			feedFmAnalyticsService.AddAudioSettingsEntryPoint(FeedFmAnalytics.AudioSettingsEntryPoint.Notification);
		}

