	public class ChartGroupModel : IHardwareDependent
	{
		public readonly List<INC<bool>> DependentVisibility = new List<INC<bool>>();

		private Dictionary<string, INC<bool>> LegendVisibilityMap;

		[JsonIgnore]
		public readonly INC<bool> GroupEnabled = new NC<bool>(value: true);

		public List<ChartMetricConfiguration> Lines { get; set; }

		public ChartGroupType GroupType { get; set; }

		public Dictionary<Theme, JsonConsoleConfigurationModel.ThemeColorModel> GroupColor { get; set; }

		public ChartScalerType Scaler { get; set; }

		public bool DisplayLegend { get; set; }

		public bool LeftAxis { get; set; }

		public bool AlwaysDisplay { get; set; }

		[JsonIgnore]
		public ICommand ToggleGroup => new MvxCommand<ToggleViewToggledEventArgs>(DoToggleGroup);

		[JsonIgnore]
		public bool IsGoalBased => false;

		[JsonIgnore]
		public bool HideWhenTimeBased => false;

		[JsonIgnore]
		public bool HideWhenDistanceBased => false;

		[JsonIgnore]
		public bool RequiresKph => false;

		[JsonIgnore]
		public bool RequiresIncline => GroupType == ChartGroupType.Incline;

		[JsonIgnore]
		public bool RequiresResistance => GroupType == ChartGroupType.Resistance;

		[JsonIgnore]
		public bool RequiresGear => GroupType == ChartGroupType.Gear;

		[JsonIgnore]
		public bool RequiresHeartMonitor => GroupType == ChartGroupType.HeartRate;

		[JsonIgnore]
		public bool RequiresVerticalGain => GroupType == ChartGroupType.Elevation;

		[JsonIgnore]
		public bool RequiresVerticalNet => GroupType == ChartGroupType.Elevation;

		[JsonIgnore]
		public bool RequiresFiveHundredSplit => GroupType == ChartGroupType.FiveHundredSplit;

		[JsonIgnore]
		public IList<FitnessValue> RequiredFitnessValues => null;

		public ChartGroupModel(ChartGroupType group, Dictionary<Theme, JsonConsoleConfigurationModel.ThemeColorModel> color, bool displayLegend, bool leftAxis)
		{
			GroupType = group;
			GroupColor = color;
			DisplayLegend = displayLegend;
			LeftAxis = leftAxis;
		}

		private void DoToggleGroup(ToggleViewToggledEventArgs eventArgs)
		{
			if (eventArgs != null && eventArgs.ToggledByUserTap)
			{
				SetGroupDependents(eventArgs.On);
				Dictionary<string, INC<bool>> legendVisibilityMap = LegendVisibilityMap;
				if (legendVisibilityMap != null && legendVisibilityMap.ContainsKey(GroupType.ToString()))
				{
					LegendVisibilityMap[GroupType.ToString()].Value = GroupEnabled.Value;
				}
			}
		}

		public void SetGroupDependents(bool on)
		{
			GroupEnabled.Value = on;
			foreach (INC<bool> item in DependentVisibility)
			{
				item.Value = GroupEnabled.Value;
			}
		}

		public string DisplayName()
		{
			return GroupType switch
			{
				ChartGroupType.Speed => Wolf.Core.Resources.AppStrings.speed, 
