	[JsonObject(MemberSerialization.OptIn)]
	public class GoalValues
	{
		public const int GoalTypeCalorie = 0;

		public const int GoalTypeTime = 1;

		public const int GoalTypeDistance = 2;

		public const int GoalTypePace = 3;

		[JsonProperty]
		public double Weight { get; set; }

		[JsonProperty]
		public double Calories { get; set; }

		[JsonProperty]
		public double Incline { get; set; }

		[JsonProperty]
		public double Speed { get; set; }

		[JsonProperty]
		public double Distance { get; set; }

		[JsonProperty]
		public int TimeSeconds { get; set; }

		[JsonProperty]
		public int PaceSeconds { get; set; }

		[JsonProperty]
		public int GoalType { get; set; }

		[JsonProperty]
		public bool IsMetric { get; set; }

		public double CalculateCalories()
		{
			return UnitUtil.Round(CalorieFormulas.Running(Weight, TimeSeconds, Speed, Incline), 0);
		}

		public int CalculatePaceSeconds()
		{
			if (Speed != 0.0)
			{
				return UnitUtil.PaceSecondsPerDistanceFromSpeed(UnitUtil.GetSpeedUnit(IsMetric), Speed);
			}
			return 0;
		}

		public double CalculateSpeed()
		{
			if (PaceSeconds != 0)
			{
				return UnitUtil.Round(1.0 / ((double)PaceSeconds / 3600.0), 2);
			}
			return 0.0;
		}

		public double CalculateDistance()
		{
			double num = CalorieFormulas.Running(Weight, TimeSeconds, Speed, Incline);
			double num2 = Calories / num;
			double value = num2 / 60.0 * Speed;
			return UnitUtil.Round(value, 2);
		}

		public static GoalValues GetCalorieGoalValues(bool isMetric, double weight, double speed, double incline, int calories)
		{
			GoalValues goalValues = new GoalValues();
			goalValues.GoalType = 0;
			goalValues.IsMetric = isMetric;
			goalValues.Weight = weight;
			goalValues.Speed = speed;
			goalValues.Incline = incline;
			goalValues.Calories = calories;
			goalValues.Distance = goalValues.CalculateDistance();
			goalValues.TimeSeconds = goalValues.CalculateTimeSeconds();
			goalValues.PaceSeconds = goalValues.CalculatePaceSeconds();
			return goalValues;
		}

		public static GoalValues GetTimeGoalValues(bool isMetric, double weight, double speed, double incline, int timeSeconds)
		{
			GoalValues goalValues = new GoalValues();
			goalValues.GoalType = 1;
			goalValues.IsMetric = isMetric;
			goalValues.Weight = weight;
			goalValues.Speed = speed;
			goalValues.Incline = incline;
			goalValues.TimeSeconds = timeSeconds;
			goalValues.Calories = goalValues.CalculateCalories();
			goalValues.Distance = goalValues.CalculateDistance();
			goalValues.PaceSeconds = goalValues.CalculatePaceSeconds();
			return goalValues;
		}

		public static GoalValues GetDistanceGoalValues(bool isMetric, double weight, double distance, double speed, double incline)
		{
			GoalValues goalValues = new GoalValues();
			goalValues.GoalType = 2;
			goalValues.IsMetric = isMetric;
			goalValues.Weight = weight;
			goalValues.Distance = distance;
			goalValues.Speed = speed;
			goalValues.Incline = incline;
			goalValues.TimeSeconds = goalValues.CalculateTimeSeconds();
			goalValues.Calories = goalValues.CalculateCalories();
			goalValues.PaceSeconds = goalValues.CalculatePaceSeconds();
			return goalValues;
		}

		public static GoalValues GetPaceGoalValues(bool isMetric, double weight, double distance, int paceSeconds, double incline)
		{
			GoalValues goalValues = new GoalValues();
			goalValues.GoalType = 3;
			goalValues.IsMetric = isMetric;
			goalValues.Weight = weight;
			goalValues.Distance = distance;
			goalValues.PaceSeconds = paceSeconds;
			goalValues.Incline = incline;
			goalValues.Speed = goalValues.CalculateSpeed();
			goalValues.TimeSeconds = goalValues.CalculateTimeSeconds();
			goalValues.Calories = goalValues.CalculateCalories();
			return goalValues;
		}

		protected int CalculateTimeSeconds()
		{
			return (int)UnitUtil.Round(Distance / Speed * 3600.0, 0);
		}
	}
