namespace Wolf.Core.Media
{
	public static class MediaConstants
	{
		public const int VideoMusicRegionMarginSeconds = 6;
	}
	public interface IMediaService
	{
		IVideoService Video { get; }

		IMusicService Music { get; }

		bool IsVideoCurrentlyInsideMusicRegion { get; }

		WorkoutVideo WorkoutVideo { get; }

