		void UpdateAudioServicePlayerToAppropriateVolume();

		void SetUpVideoMusicRegionHandlers();

		void SetWorkoutVideo(Workout workout, WorkoutVideo workoutVideo);

		void HandleAudioServicePlaybackChanges(ConsoleState state);

		Task<bool> ShouldMusicStartAutomaticallyAsync();

