	public class MediaService : IMediaService
	{
		private readonly IWolfAnalytics wolfAnalytics;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IMainThreadService mainThreadService;

		private readonly IMediaSettings mediaSettings;

		private readonly IFeedFmAnalyticsService feedFmAnalyticsService;

		private readonly IFeedFmMuteDisablingService feedFmMuteDisablingService;

		private IDisposable workoutTimeChangedMusicRegionSub;

		private bool musicWasInitializingWhenWarmupEnded;

		private bool audioFocusLocked;

		protected ConsoleState CurrentConsoleState => (currentConsoleService.ActiveConsole?.LatestBasicInfo?.CurrentState).GetValueOrDefault();

		public IVideoService Video { get; }

		public IMusicService Music { get; }

		private int LastMusicVolumeAsInt => (int)(mediaSettings.MusicVolume * 100f);

		public WorkoutVideo WorkoutVideo { get; protected set; }

		public bool IsVideoCurrentlyInsideMusicRegion
		{
			get
			{
				IWorkoutSettings obj = workoutSettings;
				if (obj != null && obj.WorkoutContainer?.WorkoutRunner?.HasStartedWorkout == true && WorkoutVideo?.VideoMusicRegions != null && Music.WorkoutRegions.ContainsMusicRegions && Video.PreBufferedVideoPlayer != null && WorkoutVideo.IsTimeWithinAnyVideoMusicRange(Video.PreBufferedVideoPlayer.VideoPositionSeconds) && (double)Video.PreBufferedVideoPlayer.VideoVolume >= 0.001)
				{
					return CurrentConsoleState.IsRunningState();
				}
				return false;
			}
		}

		public MediaService(IVideoService video, IMusicService music, IWolfAnalytics wolfAnalytics, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IMainThreadService mainThreadService, IMediaSettings mediaSettings, IFeedFmAnalyticsService feedFmAnalyticsService, IFeedFmMuteDisablingService feedFmMuteDisablingService)
		{
			this.wolfAnalytics = wolfAnalytics;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
			this.mainThreadService = mainThreadService;
			this.mediaSettings = mediaSettings;
			this.feedFmAnalyticsService = feedFmAnalyticsService;
			this.feedFmMuteDisablingService = feedFmMuteDisablingService;
			Video = video;
			Music = music;
			Music.VolumeControl = new VolumeControlBehavior(UpdatePlayerVolumesFromSettingsTask, UpdateAudioServicePlayerToAppropriateVolumeTask);
		}

		public void AdditionalInitializationForWorkout()
		{
			IFeedFmMuteDisablingService obj = feedFmMuteDisablingService;
			if (obj != null && obj.IsEnabled)
			{
				Music.MusicVolumeMutedBehavior = feedFmMuteDisablingService.GetMusicVolumeMutedBehavior();
			}
		}

		public void Cleanup()
		{
			Log.Trace("Workout", "MediaService - Cleanup()");
			WorkoutVideo = null;
			workoutTimeChangedMusicRegionSub?.Dispose();
			workoutTimeChangedMusicRegionSub = null;
			musicWasInitializingWhenWarmupEnded = false;
			Music.MusicVolumeMutedBehavior?.Dispose();
			Music.MusicVolumeMutedBehavior = null;
		}

		public void SetWorkoutVideo(Workout workout, WorkoutVideo workoutVideo)
		{
			WorkoutVideo = workoutVideo;
			Music.WorkoutRegions = new WorkoutMusicRegions
			{
				ContainsMusicRegions = false,
				BeginsWithMusicRegion = false,
				IsEntirelyWithinMusicRegion = false
			};
			Log.Trace("Workout", "WorkoutVideo value updated: " + ((workoutVideo == null) ? "<null>" : JsonConvert.SerializeObject(workoutVideo)));
			if (workoutVideo != null && Mvx.TryResolve<IFeatureFlagManager>(out var service))
			{
				if (service.IsFeatureEnabled(FeatureFlags.WolfFeedFMIntroOutro))
				{
					UpdateWorkoutVideoMusicRegions(workout);
					Log.Trace("Workout", string.Format("{0}: {1}", "ContainsMusicRegions", Music.WorkoutRegions.ContainsMusicRegions));
					Log.Trace("Workout", string.Format("{0}: {1}", "BeginsWithMusicRegion", Music.WorkoutRegions.BeginsWithMusicRegion));
					Log.Trace("Workout", string.Format("{0}: {1}", "IsEntirelyWithinMusicRegion", Music.WorkoutRegions.IsEntirelyWithinMusicRegion));
				}
				else
				{
					Log.Trace("Workout", "Feature flag \"" + FeatureFlags.WolfFeedFMIntroOutro.Key + "\" is not enabled. Video music regions will be ignored.");
				}
			}
		}

		private void UpdateWorkoutVideoMusicRegions(Workout workout)
		{
			if (FeedFmNativeStationService.WorkoutNotApplicableForMusic(workout))
			{
				Music.WorkoutRegions = new WorkoutMusicRegions
				{
					ContainsMusicRegions = true,
					BeginsWithMusicRegion = true,
					IsEntirelyWithinMusicRegion = true
				};
				return;
			}
			List<WorkoutVideo.Timestamp> list = WorkoutVideo?.VideoMusicRegions?.CollapseValidVideoMusicRegions();
			if (list == null || list.Count < 1)
			{
				Music.WorkoutRegions = new WorkoutMusicRegions
				{
					ContainsMusicRegions = false,
					BeginsWithMusicRegion = false,
					IsEntirelyWithinMusicRegion = false
				};
				return;
			}
			IMusicService music = Music;
			WorkoutMusicRegions workoutRegions = new WorkoutMusicRegions
			{
				BeginsWithMusicRegion = list.Any((WorkoutVideo.Timestamp x) => x.Start <= 6),
				ContainsMusicRegions = (list.Count > 0)
			};
			Workout workout2 = workout;
			workoutRegions.IsEntirelyWithinMusicRegion = workout2 != null && workout2.Target == Workout.TargetType.Seconds && list.Any((WorkoutVideo.Timestamp x) => x.Start <= 6 && (double)x.End >= workout.TargetValue - 6.0);
			music.WorkoutRegions = workoutRegions;
		}

		public void StopMusic()
		{
			Workout workout = workoutSettings.WorkoutContainer.Workout;
			if (Music.IsUsingFeedFMService)
			{
				Music.FeedFm?.Stop();
			}
			else
			{
				Video.PreBufferedVideoPlayer?.Stop(PlayerType.Audio);
			}
			feedFmAnalyticsService.HandleUserStartedStoppedMusic(started: false);
		}

		public void PlayMusic()
		{
			if (Music.IsUsingFeedFMService)
			{
				Music.PlayAudioServicePlayerIfEnabled();
			}
			else
			{
				Video.PreBufferedVideoPlayer?.Play(PlayerType.Audio);
			}
			feedFmAnalyticsService.HandleUserStartedStoppedMusic(started: true);
			if (LastMusicVolumeAsInt == 0)
			{
				wolfAnalytics.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.MusicMuted, Music.ActivePlayerType, LastMusicVolumeAsInt, workoutSettings.WorkoutContainer.WorkoutRunner.WolfGeneratedId);
			}
		}

		public void SetVideoVolume(float volume, bool commit = true)
		{
			if (!audioFocusLocked)
			{
				volume = volume.Clamp(0f, 1f);
				if (Video?.PreBufferedVideoPlayer != null)
				{
					Video.PreBufferedVideoPlayer.VideoVolume = volume;
				}
				mediaSettings.UpdateTrainerVolume(volume, commit);
			}
		}

		public void SetMusicVolume(float volume, bool commit = true)
		{
			if (!audioFocusLocked)
			{
				volume = volume.Clamp(0f, 1f);
				int num = (int)(volume * 100f);
				if (volume < 1E-45f && num != LastMusicVolumeAsInt)
				{
					Music.MusicVolumeMutedBehavior?.PauseOnMute();
					wolfAnalytics.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.MusicMuted, Music.ActivePlayerType, LastMusicVolumeAsInt, workoutSettings.WorkoutContainer.WorkoutRunner.WolfGeneratedId);
				}
				else if (num != LastMusicVolumeAsInt && LastMusicVolumeAsInt == 0)
				{
					Music.MusicVolumeMutedBehavior?.PlayOnUnmute();
				}
				if (Music.IsUsingFeedFMService)
				{
					Music.FeedFm?.SetVolume(volume);
				}
				else if (Video.PreBufferedVideoPlayer != null)
				{
					Video.PreBufferedVideoPlayer.AudioVolume = volume;
				}
				mediaSettings.UpdateMusicVolume(volume, commit);
			}
		}

		public void LockAudioFocus(bool locked, float? lockVolume = null)
		{
			if (!locked)
			{
				audioFocusLocked = false;
				UpdatePlayerVolumesFromSettings();
				return;
			}
			float valueOrDefault = lockVolume.GetValueOrDefault();
			if (Video?.PreBufferedVideoPlayer != null)
			{
				Video.PreBufferedVideoPlayer.VideoVolume = valueOrDefault;
			}
			if (Music.IsUsingFeedFMService)
			{
				Music.FeedFm?.SetVolume(valueOrDefault);
			}
			else if (Video?.PreBufferedVideoPlayer != null)
			{
				Video.PreBufferedVideoPlayer.AudioVolume = valueOrDefault;
			}
			audioFocusLocked = true;
		}

		public void PauseVideoAndMusic()
		{
			if (Music.IsUsingFeedFMService)
			{
				Video.PreBufferedVideoPlayer?.Pause(PlayerType.Video);
				Music.FeedFm?.Pause();
			}
			else
			{
				Video.PreBufferedVideoPlayer?.Pause();
			}
			wolfAnalytics.InWorkoutMusicAction(workoutSettings.WorkoutContainer.Workout, AudioPlayerAction.Paused, Music.ActivePlayerType, LastMusicVolumeAsInt, workoutSettings.WorkoutContainer.WorkoutRunner.WolfGeneratedId);
		}

		public void Play(StateChange stateChange = null)
		{
			bool enteringRunningFromWarmup = stateChange != null && stateChange.Old == ConsoleState.WarmUp && stateChange.Current.IsRunningState();
			bool beginsWithMusicRegion = Music.WorkoutRegions.BeginsWithMusicRegion;
			if (Music.ShouldWorkoutStartWithFeedFm(enteringRunningFromWarmup, beginsWithMusicRegion, IsVideoCurrentlyInsideMusicRegion) || !Music.IsUsingFeedFMService)
			{
				if (stateChange != null && stateChange.Current == ConsoleState.WarmUp && Music.CurrentStationIsTrainerSelect)
				{
					Video.PreBufferedVideoPlayer?.Play(PlayerType.Video);
				}
				else
				{
					PlayVideoAndMusic();
				}
			}
			else
			{
				Video.PreBufferedVideoPlayer?.Play(PlayerType.Video);
			}
		}

		public void PlayVideoAndMusic()
		{
			if (Music.IsUsingFeedFMService)
			{
				Video.PreBufferedVideoPlayer?.Play(PlayerType.Video);
				Music.PlayAudioServicePlayerIfEnabled();
			}
			else
			{
				Video.PreBufferedVideoPlayer?.Play();
			}
		}

		public void UpdatePlayerVolumesFromSettings()
		{
			SetMusicVolume(mediaSettings.MusicVolume);
			SetVideoVolume(mediaSettings.TrainerVolume);
		}

		private Task UpdateAudioServicePlayerToAppropriateVolumeTask()
		{
			UpdateAudioServicePlayerToAppropriateVolume();
			return Task.FromResult(0);
		}

		public void SetUpVideoMusicRegionHandlers()
		{
			if (Video?.PreBufferedVideoPlayer != null && Music.WorkoutRegions.ContainsMusicRegions)
			{
				workoutTimeChangedMusicRegionSub?.Dispose();
				workoutTimeChangedMusicRegionSub = Video.PreBufferedVideoPlayer.WhenVideoPositionSecondsChanged.SubscribeWithErrorLogging(delegate
				{
					HandleVideoPositionTimeChanged();
				});
			}
		}

		public void UpdateAudioServicePlayerToAppropriateVolume()
		{
			Music.FeedFm?.SetVolume(mediaSettings.MusicVolume);
		}

		private void HandleVideoPositionTimeChanged()
		{
			Music.HandleVideoPositionTimeChanged(IsVideoCurrentlyInsideMusicRegion);
		}

		private Task UpdatePlayerVolumesFromSettingsTask()
		{
			UpdatePlayerVolumesFromSettings();
			return Task.FromResult(0);
		}

		public void HandleAudioServicePlaybackChanges(ConsoleState state)
		{
			UpdatePlayerVolumesFromSettings();
			if (Music.FeedFm == null)
			{
				return;
			}
			switch (state)
			{
			case ConsoleState.Workout:
			case ConsoleState.PauseOverride:
			{
				bool isVideoCurrentlyInsideMusicRegion = IsVideoCurrentlyInsideMusicRegion;
				if (isVideoCurrentlyInsideMusicRegion && Music.FeedFm.ActiveState != MusicState.PausedManually && !Music.HasStartedPlayingMusic)
				{
					PreventInitialPlaybackInVideoMusicRegion();
				}
				Music.InsideVideoMusicRegion = isVideoCurrentlyInsideMusicRegion;
				Music.PauseOrPlayMusicBasedOnInsideVideoMusicRegion(isVideoCurrentlyInsideMusicRegion && !Music.UserStartedMusicDuringMusicRegion);
				break;
			}
			case ConsoleState.WarmUp:
			case ConsoleState.CoolDown:
			{
				Music.InsideVideoMusicRegion = false;
				IMediaSettings obj = mediaSettings;
				if (obj != null && obj.HasDisabledFeedFmPlayback)
				{
					Music.FeedFm.Pause();
				}
				else
				{
					Music.PlayWorkoutAudioServicePlayerIfEnabled();
				}
				break;
			}
			case ConsoleState.Paused:
				Music.FeedFm?.Pause();
				break;
			default:
				Music.InsideVideoMusicRegion = false;
				Music.FeedFm?.Pause();
				break;
			}
		}

		public async Task<bool> ShouldMusicStartAutomaticallyAsync()
		{
			ConsoleState valueOrDefault = (currentConsoleService.ActiveConsole?.LatestBasicInfo?.CurrentState).GetValueOrDefault();
			if (valueOrDefault == ConsoleState.WarmUp || valueOrDefault == ConsoleState.CoolDown)
			{
				return true;
			}
			if (valueOrDefault.IsRunningState())
			{
				double seconds = await mainThreadService.InvokeOnMainThreadAsync(() => (Video?.PreBufferedVideoPlayer?.VideoPositionSeconds).GetValueOrDefault());
				WorkoutVideo workoutVideo = WorkoutVideo;
				return workoutVideo == null || !workoutVideo.IsTimeWithinAnyVideoMusicRange(seconds);
			}
			return false;
		}

		private void PreventInitialPlaybackInVideoMusicRegion()
		{
			musicWasInitializingWhenWarmupEnded = true;
			Music.FeedFm?.SetVolume(0f);
		}
	}
