	}
	public class MusicVolumeMutedBehavior : IMusicVolumeMutedBehavior, IDisposable
	{
		private readonly IWorkoutSettings workoutSettings;

		private readonly IMusicService musicService;

		private readonly IMediaSettings mediaSettings;

		private IDisposable volumeChangeSub;

		private readonly Subject<bool> feedFmStateChanged = new Subject<bool>();

		public IObservable<bool> FeedFmStateChanged => feedFmStateChanged;

		public MusicVolumeMutedBehavior(IWorkoutSettings workoutSettings, IMusicService musicService, IMediaSettings mediaSettings, IReadWriteFacadeFactoryDependencies facadeFactoryDependencies)
		{
			this.workoutSettings = workoutSettings;
			this.mediaSettings = mediaSettings;
			this.musicService = musicService;
		}

		public void PauseOnMute()
		{
			mediaSettings.HasDisabledFeedFmPlayback = true;
			feedFmStateChanged.OnNext(value: false);
			musicService.HandleExternalFeedFmToggleAction();
		}

		public void PlayOnUnmute()
		{
			mediaSettings.HasDisabledFeedFmPlayback = false;
			feedFmStateChanged.OnNext(value: true);
			musicService.HandleExternalFeedFmToggleAction();
		}

		public void Dispose()
		{
			volumeChangeSub?.Dispose();
			volumeChangeSub = null;
		}
	}
