	public interface IFeedFmMuteDisablingService
	{
		bool IsEnabled { get; }

		IObservable<float> MusicVolumeChanged { get; }

		IObservable<bool> FeedFmTurnedOn { get; }

		IMusicVolumeMutedBehavior GetMusicVolumeMutedBehavior();

		void StartupFeedFmDisablingCheck();

		void UpdateMusicVolumeOnFeedFmToggleOn(IMediaService mediaService);
	}
	public class FeedFmMuteDisablingService : IFeedFmMuteDisablingService
	{
		private const float MusicReEnableVolume = 0.1f;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IMusicService musicService;

		private readonly IMediaSettings mediaSettings;

		private readonly IReadWriteFacadeFactoryDependencies facadeFactoryDependencies;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IDeviceInformation deviceInformation;

		private IDisposable feedFmToggledSub;

		private readonly Subject<bool> feedFmTurnedOn = new Subject<bool>();

		private readonly Subject<float> musicVolumeChanged = new Subject<float>();

		public IObservable<bool> FeedFmTurnedOn => feedFmTurnedOn;

		public IObservable<float> MusicVolumeChanged => musicVolumeChanged;

		public bool IsEnabled
		{
			get
			{
				if (deviceInformation.IsBuiltIn)
				{
					return featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfFeedFMDisableOnMute);
				}
				return false;
			}
		}

		public FeedFmMuteDisablingService(IWorkoutSettings workoutSettings, IMusicService musicService, IMediaSettings mediaSettings, IReadWriteFacadeFactoryDependencies facadeFactoryDependencies, IFeatureFlagManager featureFlagManager, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation)
		{
			this.workoutSettings = workoutSettings;
			this.musicService = musicService;
			this.mediaSettings = mediaSettings;
			this.facadeFactoryDependencies = facadeFactoryDependencies;
			this.featureFlagManager = featureFlagManager;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
		}

		public IMusicVolumeMutedBehavior GetMusicVolumeMutedBehavior()
		{
			if (!IsEnabled)
			{
				return null;
			}
			MusicVolumeMutedBehavior musicVolumeMutedBehavior = new MusicVolumeMutedBehavior(workoutSettings, musicService, mediaSettings, facadeFactoryDependencies);
			feedFmToggledSub?.Dispose();
			feedFmToggledSub = musicVolumeMutedBehavior.FeedFmStateChanged.SubscribeWithErrorLogging(HandleFeedFmStateChanged);
			return musicVolumeMutedBehavior;
		}

		private void HandleFeedFmStateChanged(bool on)
		{
			feedFmTurnedOn.OnNext(on);
		}

		public void StartupFeedFmDisablingCheck()
		{
			if (IsEnabled && mediaSettings.MusicVolumeMuted)
			{
				mediaSettings.HasDisabledFeedFmPlayback = true;
			}
		}

		public void UpdateMusicVolumeOnFeedFmToggleOn(IMediaService mediaService)
		{
			if (IsEnabled && !mediaSettings.HasDisabledFeedFmPlayback && mediaSettings.MusicVolumeMuted)
			{
				mediaService.SetMusicVolume(0.1f);
				musicVolumeChanged.OnNext(0.1f);
			}
		}
	}
	public interface IFeedFmToggleSettingService
	{
		bool FeedFmEnabledForCurrentUser { get; }

		void SetFeedFmToggleSettingForCurrentUser(bool enabled);

		Task InitializeAsync();
	}
	public class FeedFmToggleSettingService : IFeedFmToggleSettingService
	{
		private const int ReadFromCacheTimeoutMs = 1000;

		private readonly IIfitApiService api;

		private readonly IBlobCacheService cacheService;

		private readonly IDeviceInformation deviceInformation;

		private IFeedFmAvailabilityService feedFmAvailabilityService;

		protected readonly Dictionary<string, bool> FeedFmEnabledForCurrentUserDict = new Dictionary<string, bool>();

		private string FeedFmEnabledForUserKeyStub
		{
			get
			{
				if (!deviceInformation.IsBuiltIn)
				{
					return "FeedFmEnabledNonDefault";
				}
				return "FeedFmEnabled";
			}
		}

		public bool FeedFmEnabledForCurrentUser => GetFeedFmEnabledForCurrentUser();

		private bool DefaultEnabledState
		{
			get
			{
				if (feedFmAvailabilityService == null)
				{
					Mvx.TryResolve<IFeedFmAvailabilityService>(out feedFmAvailabilityService);
				}
				return feedFmAvailabilityService?.GetDefaultEnabledState() ?? true;
			}
		}

		public FeedFmToggleSettingService(IIfitApiService api, IBlobCacheService cacheService, IDeviceInformation deviceInformation)
		{
			this.api = api;
			this.cacheService = cacheService;
			this.deviceInformation = deviceInformation;
		}

		private bool GetFeedFmEnabledForCurrentUser()
		{
			if (string.IsNullOrEmpty(api?.CurrentlyAuthenticatedUserId))
			{
				return DefaultEnabledState;
			}
			string currentlyAuthenticatedUserId = api.CurrentlyAuthenticatedUserId;
			if (FeedFmEnabledForCurrentUserDict.ContainsKey(currentlyAuthenticatedUserId))
			{
				return FeedFmEnabledForCurrentUserDict[currentlyAuthenticatedUserId];
			}
			FeedFmEnabledForCurrentUserDict[currentlyAuthenticatedUserId] = DefaultEnabledState;
			return DefaultEnabledState;
		}

		public void SetFeedFmToggleSettingForCurrentUser(bool enabled)
		{
			if (!string.IsNullOrEmpty(api?.CurrentlyAuthenticatedUserId))
			{
				SetFeedFmToggleSettingForUser(enabled, api.CurrentlyAuthenticatedUserId);
			}
		}

		public void SetFeedFmToggleSettingForAllUsers(bool enabled)
		{
			api?.AuthenticatedUsers?.DoForEach(delegate(User x)
			{
				SetFeedFmToggleSettingForUser(enabled, x.Id);
			}, ignoreNulls: true);
		}

		protected void SetFeedFmToggleSettingForUser(bool enabled, string userId)
		{
			FeedFmEnabledForCurrentUserDict[userId] = enabled;
			string key = GenerateCacheStorageKeyForUser(userId);
			bool? data = enabled;
			StoreProperty(key, data);
		}

		protected string GenerateCacheStorageKeyForUser(string userId)
		{
			return FeedFmEnabledForUserKeyStub + "_" + userId;
		}

		protected void StoreProperty<TData>(string key, TData data)
		{
			cacheService?.Flush(data, key, "FeedFmToggleSettingService");
		}

		public async Task InitializeAsync()
		{
			try
			{
				string currentUserId = api.CurrentlyAuthenticatedUserId;
				string valueName = GenerateCacheStorageKeyForUser(currentUserId);
				bool? flag = await cacheService.GetFromCache<bool?>(valueName, "FeedFmToggleSettingService");
				if (flag.HasValue)
				{
					FeedFmEnabledForCurrentUserDict[currentUserId] = flag.Value;
				}
			}
			catch (Exception ex)
			{
				Log.Error("Audio", ex.GetType().Name + " in FeedFmToggleSettingService.GetFeedFmEnabledForCurrentUser: ", ex);
			}
		}
	}
	public interface IMasterVolumeMixerService
	{
		float UserDisplayedMasterVolume { get; }

		void ScaleVolumeLevels(float masterLevel);

		void CommitVolumeLevels();
	}
	public class MasterVolumeMixerService : IMasterVolumeMixerService
	{
		private readonly IMediaSettings mediaSettings;

		private float TrainerVolume => mediaSettings?.TrainerVolume ?? 0f;

		private float MusicVolume => mediaSettings?.MusicVolume ?? 0f;

		public float UserDisplayedMasterVolume => Math.Max(TrainerVolume, MusicVolume);

		public MasterVolumeMixerService(IMediaSettings mediaSettings)
		{
			this.mediaSettings = mediaSettings;
		}

		public void ScaleVolumeLevels(float masterLevel)
		{
			if (TrainerVolume.Equals(MusicVolume))
			{
				UpdateTrainerVolume(masterLevel);
				UpdateMusicVolume(masterLevel);
			}
			else if (MusicVolume.Equals(0f) && TrainerVolume > 0f)
			{
				UpdateTrainerVolume(masterLevel);
			}
			else if (TrainerVolume.Equals(0f) && MusicVolume > 0f)
			{
				UpdateMusicVolume(masterLevel);
			}
			else if (TrainerVolume > MusicVolume)
			{
				float num = MusicVolume / TrainerVolume;
				UpdateTrainerVolume(masterLevel);
				UpdateMusicVolume(masterLevel * num);
			}
			else if (MusicVolume > TrainerVolume)
			{
				float num2 = TrainerVolume / MusicVolume;
				UpdateMusicVolume(masterLevel);
				UpdateTrainerVolume(masterLevel * num2);
			}
		}

		private void UpdateTrainerVolume(float level)
		{
			mediaSettings?.UpdateTrainerVolume(level.Clamp(0f, 1f), commit: false);
		}

		private void UpdateMusicVolume(float level)
		{
			mediaSettings?.UpdateMusicVolume(level.Clamp(0f, 1f), commit: false);
		}

		public void CommitVolumeLevels()
		{
			mediaSettings?.UpdateTrainerVolume(TrainerVolume, commit: true);
			mediaSettings?.UpdateMusicVolume(MusicVolume, commit: true);
		}
	}
