	public class MediaSettings : IMediaSettings
	{
		public const float DefaultStrengthMirrorSystemVolume = 0.25f;

		public const float DefaultMusicVolume = 0.5f;

		public const float DefaultTrainerVolume = 1f;

		private const string HasTransitionedToFeedFmToggleSettingServiceKey = "HasTransitionedToFeedFmToggleSettingService";

		private readonly IBlobCacheService cacheService;

		private readonly IFeedFmToggleSettingService feedFmToggleSettingService;

		private readonly IDeviceInformation deviceInformation;

		public float TrainerVolume { get; protected set; } = 1f;

		public bool TrainerVolumeMuted => TrainerVolume < 1E-45f;

		public float MusicVolume { get; protected set; } = 0.5f;

		public bool MusicVolumeMuted => MusicVolume < 1E-45f;

		public float StrengthMirrorSystemVolume { get; protected set; } = 0.25f;

		public bool StrengthMirrorSystemVolumeMuted => StrengthMirrorSystemVolume < 1E-45f;

		public bool HasDisabledFeedFmPlayback
		{
			get
			{
				IFeedFmToggleSettingService obj = feedFmToggleSettingService;
				if (obj == null)
				{
					return false;
				}
				return !obj.FeedFmEnabledForCurrentUser;
			}
			set
			{
				feedFmToggleSettingService?.SetFeedFmToggleSettingForCurrentUser(!value);
			}
		}

		public bool SecretSettingFeedFmOverrideUserStation { get; set; }

		protected MediaSettings(IBlobCacheService cacheService = null, IFeedFmToggleSettingService feedFmToggleSettingService = null, IDeviceInformation deviceInformation = null)
		{
			this.cacheService = cacheService;
			this.feedFmToggleSettingService = feedFmToggleSettingService;
			this.deviceInformation = deviceInformation;
		}

		private async Task<IMediaSettings> InitializeAsync()
		{
			if (feedFmToggleSettingService != null)
			{
				await feedFmToggleSettingService.InitializeAsync();
			}
			if (cacheService != null)
			{
				TrainerVolume = (await cacheService.GetFromCache("TrainerVolume", "IMediaSettings", "", temp: false, 1f)).Clamp(0f, 1f);
				MusicVolume = (await cacheService.GetFromCache("MusicVolume", "IMediaSettings", "", temp: false, 0.5f)).Clamp(0f, 1f);
				StrengthMirrorSystemVolume = (await cacheService.GetFromCache("StrengthMirrorSystemVolume", "IMediaSettings", "", temp: false, 0.25f)).Clamp(0f, 1f);
				await TransitionFeedFmToggleSettingToServiceIfNecessary(cacheService);
			}
			return this;
		}

		private async Task TransitionFeedFmToggleSettingToServiceIfNecessary(IBlobCacheService cache)
		{
			IDeviceInformation obj = deviceInformation;
			if ((obj != null && !obj.IsBuiltIn) || await cache.GetFromCache("HasTransitionedToFeedFmToggleSettingService", "IMediaSettings", "", temp: false, defaultValue: false))
			{
				return;
			}
			IFeedFmToggleSettingService feedFmToggleSettingService = this.feedFmToggleSettingService;
			if (feedFmToggleSettingService is FeedFmToggleSettingService concreteFeedFmToggleSettingService)
			{
				try
				{
					concreteFeedFmToggleSettingService.SetFeedFmToggleSettingForAllUsers(!(await cache.GetFromCache("HasDisabledFeedFmPlayback", "IMediaSettings", "", temp: false, defaultValue: false)));
				}
				catch (Exception ex)
				{
					Log.Error("Audio", ex.GetType().Name + " occurred in MediaSettings.TransitionFeedFmToggleSettingToServiceIfNecessary: ", ex);
				}
				StoreProperty("HasTransitionedToFeedFmToggleSettingService", data: true);
			}
		}

		public static Task<IMediaSettings> CreateAsync(IBlobCacheService cacheService, IFeedFmToggleSettingService feedFmToggleSettingService, IDeviceInformation deviceInformation)
		{
			MediaSettings mediaSettings = new MediaSettings(cacheService, feedFmToggleSettingService, deviceInformation);
			return mediaSettings.InitializeAsync();
		}

		public void UpdateTrainerVolume(float newVolume, bool commit)
		{
			TrainerVolume = newVolume.Clamp(0f, 1f);
			if (commit)
			{
				CommitTrainerVolumeToStorage();
			}
		}

		public void UpdateMusicVolume(float newVolume, bool commit)
		{
			MusicVolume = newVolume.Clamp(0f, 1f);
			if (commit)
			{
				CommitMusicVolumeToStorage();
			}
		}

		public void UpdateStrengthMirrorSystemVolume(float newVolume, bool commit)
		{
			StrengthMirrorSystemVolume = newVolume.Clamp(0f, 1f);
			if (commit)
			{
				CommitStrengthMirrorSystemVolumeToStorage();
			}
		}

		public void ResetTrainerVolumeToDefault()
		{
			UpdateTrainerVolume(1f, commit: true);
		}

		public void ResetMusicVolumeToDefault()
		{
			UpdateMusicVolume(0.5f, commit: true);
		}

		public virtual void CommitTrainerVolumeToStorage()
		{
			StoreProperty("TrainerVolume", TrainerVolume);
		}

		public virtual void CommitMusicVolumeToStorage()
		{
			StoreProperty("MusicVolume", MusicVolume);
		}

		public virtual void CommitStrengthMirrorSystemVolumeToStorage()
		{
			StoreProperty("StrengthMirrorSystemVolume", StrengthMirrorSystemVolume);
		}

		private void StoreProperty<TData>(string key, TData data)
		{
			cacheService?.Flush(data, key, "IMediaSettings");
		}
	}
	public class MediaSettingsDataMigrationUtil
	{
		private class LegacySettingsDataSchema
		{
			public float LastMusicVolume { get; set; }

			public float LastTrainerVolume { get; set; }

			public float LastPlatformMediaVolume { get; set; }

			public bool HasDisabledFeedFmPlayback { get; set; }
		}

		private class MediaSettingsDataMigrationUtilStorage : PersistentSettings
		{
			private const string CacheKey = "media-settings-data-migration-util";

			protected override string Key => "media-settings-data-migration-util";

			public bool HasChecked { get; set; }

			public MediaSettingsDataMigrationUtilStorage(IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager)
				: base(blobCacheService, blobCacheFileManager)
			{
			}

			public static async Task<MediaSettingsDataMigrationUtilStorage> LoadFromCache(IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager)
			{
				try
				{
					MediaSettingsDataMigrationUtilStorage mediaSettingsDataMigrationUtilStorage = await blobCacheService.Secure.GetObject<MediaSettingsDataMigrationUtilStorage>("media-settings-data-migration-util").FirstAsync().ToTask()
						.ConfigureAwait(continueOnCapturedContext: false);
					mediaSettingsDataMigrationUtilStorage.BlobCacheService = blobCacheService;
					mediaSettingsDataMigrationUtilStorage.BlobCacheFileManager = blobCacheFileManager;
					return mediaSettingsDataMigrationUtilStorage;
				}
				catch
				{
					return new MediaSettingsDataMigrationUtilStorage(blobCacheService, blobCacheFileManager);
				}
			}

			public async Task MarkAsChecked()
			{
				HasChecked = true;
				await FlushAsync().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private const string LogTag = "Media";

		private const string LegacyVersionSettingsKey = "local-settings";

		public static MediaSettingsDataMigrationUtil Shared { get; } = new MediaSettingsDataMigrationUtil();

		private MediaSettingsDataMigrationUtil()
		{
		}

		public async Task TransferMediaSettingsDataIfNecessary(IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager, IMediaSettings mediaSettings, IDeviceInformation deviceInformation)
		{
			if (blobCacheService == null)
			{
				Log.Error("Media", "MediaSettingsDataMigrationUtil.TransferMediaSettingsDataIfNecessary called, but blobCacheService was null.");
				return;
			}
			if (blobCacheFileManager == null)
			{
				Log.Error("Media", "MediaSettingsDataMigrationUtil.TransferMediaSettingsDataIfNecessary called, but blobCacheFileManager was null.");
				return;
			}
			if (mediaSettings == null)
			{
				Log.Error("Media", "MediaSettingsDataMigrationUtil.TransferMediaSettingsDataIfNecessary called, but mediaSettings was null.");
				return;
			}
			try
			{
				await UnsafeTransferMediaSettingsDataIfNecessary(blobCacheService, blobCacheFileManager, mediaSettings, deviceInformation);
			}
			catch (Exception exception)
			{
				LogError(exception, "TransferMediaSettingsDataIfNecessary");
			}
		}

		private async Task UnsafeTransferMediaSettingsDataIfNecessary(IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager, IMediaSettings mediaSettings, IDeviceInformation deviceInformation)
		{
			MediaSettingsDataMigrationUtilStorage storage = null;
			try
			{
				storage = await MediaSettingsDataMigrationUtilStorage.LoadFromCache(blobCacheService, blobCacheFileManager).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch
			{
			}
			if (storage?.HasChecked ?? false)
			{
				Log.Info("Media", "MediaSettingsDataMigrationUtil has already checked for legacy MediaSettings data before.");
				return;
			}
			Log.Info("Media", "MediaSettingsDataMigrationUtil has not yet checked for legacy MediaSettings data. Checking now...");
			LegacySettingsDataSchema legacySettingsDataSchema = await LoadOldMediaSettings(blobCacheService);
			if (legacySettingsDataSchema == null)
			{
				Log.Info("Media", "MediaSettingsDataMigrationUtil did not find legacy MediaSettings data.");
				if (storage != null)
				{
					await storage.MarkAsChecked().ConfigureAwait(continueOnCapturedContext: false);
				}
				return;
			}
			Log.Info("Media", "MediaSettingsDataMigrationUtil found legacy MediaSettings data:");
			try
			{
				Log.Info("Media", JsonConvert.SerializeObject(legacySettingsDataSchema));
			}
			catch
			{
			}
			mediaSettings.UpdateTrainerVolume(legacySettingsDataSchema.LastTrainerVolume, commit: true);
			mediaSettings.UpdateMusicVolume(legacySettingsDataSchema.LastMusicVolume, commit: true);
			mediaSettings.UpdateStrengthMirrorSystemVolume(legacySettingsDataSchema.LastPlatformMediaVolume, commit: true);
			if (deviceInformation?.IsBuiltIn ?? false)
			{
				mediaSettings.HasDisabledFeedFmPlayback = legacySettingsDataSchema.HasDisabledFeedFmPlayback;
			}
			if (storage != null)
			{
				await storage.MarkAsChecked().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task<LegacySettingsDataSchema> LoadOldMediaSettings(IBlobCacheService blobCacheService)
		{
			try
			{
				return await blobCacheService.Secure.GetObject<LegacySettingsDataSchema>("local-settings").FirstAsync().ToTask()
					.ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (KeyNotFoundException)
			{
			}
			catch (Exception exception)
			{
				LogError(exception, "LoadOldMediaSettings");
			}
			return null;
		}

		private static void LogError(Exception exception, string calledMethod)
		{
			Log.Error("Media", exception.GetType().Name + " caught in MediaSettingsDataMigrationUtil." + calledMethod + " ", exception);
		}
	}
