	public class MockLiveWorkoutService : IMockLiveWorkoutService
	{
		private const string ConstantMockedLiveWorkoutStreamUrl = "https://cph-p2p-msl.akamaized.net/hls/live/2000341/test/master.m3u8";

		private const string ConstantMockedLiveWorkoutScheduleId = "0";

		private const int WaitingRoomState = 0;

		private const int RunningState = 1;

		private const int CooldownState = 2;

		private int mockLiveWorkoutStartTime;

		private int mockLiveWorkoutEndTime;

		private int currentMockLiveTime;

		private IDisposable timerTickSub;

		private IVideoCaptionMonitoringService currentVCMS;

		public string MockedLiveWorkoutScheduleId => "0";

		public string MockedLiveWorkoutStreamUrl => "https://cph-p2p-msl.akamaized.net/hls/live/2000341/test/master.m3u8";

		public bool IsMockedLiveWorkoutSet { get; private set; }

		public bool IsMockedLiveWorkoutRunning => timerTickSub != null;

		public void SetMockedLiveWorkoutSettings(int startingTime, int endingTime)
		{
			if (startingTime >= endingTime)
			{
				throw new ArgumentOutOfRangeException("startingTime");
			}
			if (endingTime < 1)
			{
				throw new ArgumentOutOfRangeException("endingTime");
			}
			ClearMockedLiveWorkoutSettings();
			mockLiveWorkoutStartTime = startingTime;
			mockLiveWorkoutEndTime = endingTime;
			IsMockedLiveWorkoutSet = true;
		}

		public void BeginMockedLiveWorkoutCaptions(IVideoCaptionMonitoringService vcms)
		{
			if (IsMockedLiveWorkoutSet && !IsMockedLiveWorkoutRunning)
			{
				currentVCMS = vcms ?? throw new ArgumentNullException("vcms");
				currentMockLiveTime = mockLiveWorkoutStartTime;
				UpdateLiveWorkoutCaptionWithData(-2147483648, 0);
				ResumeMockedLiveWorkoutCaptionsObserver();
			}
		}

		private void ResumeMockedLiveWorkoutCaptionsObserver()
		{
			PauseMockedLiveWorkoutCaptions();
			timerTickSub = CreateTickObservable().Subscribe(HandleTimerTick);
		}

		public void PauseMockedLiveWorkoutCaptions()
		{
			timerTickSub?.Dispose();
			timerTickSub = null;
		}

		protected virtual IObservable<long> CreateTickObservable()
		{
			return Observable.Timer(TimeSpan.Zero, TimeSpan.FromSeconds(1.0));
		}

		private void HandleTimerTick(long obj)
		{
			currentMockLiveTime++;
			if (currentMockLiveTime > mockLiveWorkoutEndTime)
			{
				SignalEndOfLiveWorkout();
			}
			else
			{
				UpdateLiveWorkoutCaptions();
			}
		}

		private void UpdateLiveWorkoutCaptionWithData(int time, int state)
		{
			string caption = $"{time},0,0,0,0,0,0,0,{state}";
			currentVCMS.CaptionStringReceived(this, caption);
		}

		private void SignalEndOfLiveWorkout()
		{
			UpdateLiveWorkoutCaptionWithData(-1, 2);
			PauseMockedLiveWorkoutCaptions();
		}

		private void UpdateLiveWorkoutCaptions()
		{
			int state = ((currentMockLiveTime >= 0) ? 1 : 0);
			UpdateLiveWorkoutCaptionWithData(currentMockLiveTime, state);
		}

		public void ClearMockedLiveWorkoutSettings()
		{
			PauseMockedLiveWorkoutCaptions();
			mockLiveWorkoutStartTime = 0;
			mockLiveWorkoutEndTime = 0;
			IsMockedLiveWorkoutSet = false;
			currentVCMS = null;
		}
	}
}
namespace Wolf.Core.Media.Analytics
{
	public class FeedFmAnalyticsService : IFeedFmAnalyticsService
	{
		private string lastStationPlayed;

		private string defaultStation;

		private int numberOfStationChanges;

		private int numberOfVolumeChanges;

		private int numberOfVolumeMixerOpens;

		private int numberOfVolumeMixerClosed;

		private int numberOfMusicStarts;

		private int numberOfMusicStops;

		private double maxStationLoadingTime;

		private object firstStationPlayTime;

		private DateTime? lastTimeEnabled;

		private double totalSecondsEnabled;

		private FeedFmMutedVolumeTracker musicMutedVolumeTracker;

		private FeedFmMutedVolumeTracker systemMutedVolumeTracker;

		private DateTime workOutStartDateTime;

		private bool tssFirstPlaybackForUser;

		private Dictionary<string, string> AudioStateAtBeginningOfWorkout = new Dictionary<string, string>();

		private Dictionary<string, string> AudioStateAtEndOfWorkout = new Dictionary<string, string>();

		private List<TimeSpan> durationsBetweenStationChanges = new List<TimeSpan>();

		private readonly List<object> volumeChangeData = new List<object>();

		private readonly List<string> volumeMixerOpenedTS = new List<string>();

		private readonly List<string> volumeMixerClosedTS = new List<string>();

		private readonly List<string> musicStartsData = new List<string>();

		private readonly List<string> musicStopsData = new List<string>();

		private readonly IMediaSettings media;

		private readonly IFeedFmAvailabilityService feedFmAvailabilityService;

		private readonly ICurrentConsoleService currentConsoleService;

		private FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics completedWorkoutAnalytics = new FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics();

		private static List<FeedFmAnalytics.AudioSettingsEntryPoint> audioSettingsEntryPoints = new List<FeedFmAnalytics.AudioSettingsEntryPoint>();

		private bool isEnabled;

		private FeedFmAnalytics.AudioSettingsEntryPoint MostCommonAudioSettingsEntryPoint => MostCommonEntryPointInList(audioSettingsEntryPoints);

		private static int NumberOfNotificationTaps => audioSettingsEntryPoints.Count((FeedFmAnalytics.AudioSettingsEntryPoint x) => x == FeedFmAnalytics.AudioSettingsEntryPoint.Notification);

		private static int NumberOfAudioSettingsButtonTaps => audioSettingsEntryPoints.Count((FeedFmAnalytics.AudioSettingsEntryPoint x) => x == FeedFmAnalytics.AudioSettingsEntryPoint.AudioSettingsButton);

		private static int NumberOfPauseOverlayWidgetTaps => audioSettingsEntryPoints.Count((FeedFmAnalytics.AudioSettingsEntryPoint x) => x == FeedFmAnalytics.AudioSettingsEntryPoint.PauseOverlayWidget);

		private int AverageAmountOfTimeBetweenStationChanges
		{
			get
			{
				if (durationsBetweenStationChanges.IsEmpty())
				{
					return 0;
				}
				return (int)durationsBetweenStationChanges.Average((TimeSpan x) => x.TotalSeconds);
			}
		}

		public bool IsEnabled
		{
			get
			{
				return isEnabled;
			}
			private set
			{
				if (isEnabled != value)
				{
					CalculateTotalTimeEnabled(value);
					isEnabled = value;
					musicMutedVolumeTracker?.FeedFmEnableChanged(isEnabled);
					systemMutedVolumeTracker?.FeedFmEnableChanged(isEnabled);
				}
			}
		}

		public FeedFmAnalyticsService(IMediaSettings media, IFeedFmAvailabilityService feedFmAvailabilityService, ICurrentConsoleService currentConsoleService)
		{
			this.media = media;
			this.feedFmAvailabilityService = feedFmAvailabilityService;
			this.currentConsoleService = currentConsoleService;
		}

		public FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics BundleFeedFmAnalytics(string activityLogId)
		{
			IsEnabled = false;
			double totalSeconds = (DateTime.Now - workOutStartDateTime).TotalSeconds;
			Dictionary<string, object> volumeChanges = new Dictionary<string, object>
			{
				{ "numberOfVolumeChanges", numberOfVolumeChanges },
				{ "volumeChanges", volumeChangeData }
			};
			Dictionary<string, object> volumeMixerOpenedData = new Dictionary<string, object>
			{
				{ "numberOfVolumeMixerOpens", numberOfVolumeMixerOpens },
				{ "volumeMixerOpenedTS", volumeMixerOpenedTS }
			};
			Dictionary<string, object> volumeMixerClosedData = new Dictionary<string, object>
			{
				{ "numberOfVolumeMixerClosed", numberOfVolumeMixerClosed },
				{ "volumeMixerClosedTS", volumeMixerClosedTS }
			};
			Dictionary<string, object> musicStarts = new Dictionary<string, object>
			{
				{
					"numberOfMusicStarts",
					numberOfMusicStarts.ToString()
				},
				{ "timestamps", musicStartsData }
			};
			Dictionary<string, object> musicStops = new Dictionary<string, object>
			{
				{
					"numberOfMusicStops",
					numberOfMusicStops.ToString()
				},
				{ "timestamps", musicStopsData }
			};
			Mvx.TryResolve<IMusicService>(out var service);
			FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics obj = new FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics
			{
				AverageAmountOfTimeBetweenStationChanges = AverageAmountOfTimeBetweenStationChanges,
				NumberOfStationChanges = numberOfStationChanges,
				DefaultStation = defaultStation,
				LastStationPlayed = (lastStationPlayed ?? defaultStation),
				NumberOfNotificationTaps = NumberOfNotificationTaps,
				NumberOfAudioSettingsButtonTaps = NumberOfAudioSettingsButtonTaps,
				NumberOfPauseOverlayWidgetTaps = NumberOfPauseOverlayWidgetTaps,
				PreferredAudioSettingsEntryPoint = MostCommonAudioSettingsEntryPoint,
				MaxStationLoadingTime = maxStationLoadingTime,
				WolfWorkoutInstanceId = (activityLogId ?? "Activity Log Id was unavailable"),
				AudioStateAtBeginningOfWorkout = AudioStateAtBeginningOfWorkout,
				AudioStateAtEndOfWorkout = AudioStateAtEndOfWorkout,
				VolumeChanges = volumeChanges,
				VolumeMixerOpenedData = volumeMixerOpenedData,
				VolumeMixerClosedData = volumeMixerClosedData,
				MusicStarts = musicStarts,
				MusicStops = musicStops
			};
			int feedFmEnabledAtEndOfWorkout;
			if (service != null && service.HasInitializedAudioService)
			{
				IMediaSettings mediaSettings = media;
				feedFmEnabledAtEndOfWorkout = ((mediaSettings != null && !mediaSettings.HasDisabledFeedFmPlayback) ? 1 : 0);
			}
			else
			{
				feedFmEnabledAtEndOfWorkout = 0;
			}
			obj.FeedFmEnabledAtEndOfWorkout = (byte)feedFmEnabledAtEndOfWorkout != 0;
			obj.FeedFmTimeEnabled = totalSecondsEnabled;
			obj.FeedFmTimeEnabledButMuted = musicMutedVolumeTracker?.TotalMutedSeconds ?? 0.0;
			obj.FeedFmTimeEnabledButSystemMuted = systemMutedVolumeTracker?.TotalMutedSeconds ?? 0.0;
			obj.TotalWorkoutTime = totalSeconds;
			obj.TSSFeatureEnabled = feedFmAvailabilityService?.IsFeedFmTrainerSelectFeatureEnabledForDevice() ?? false;
			obj.TSSProvidedByCeol = service?.FeedFmStations?.TrainerSelectStationSet == true;
			obj.TSSFirstPlaybackForUser = tssFirstPlaybackForUser;
			obj.HasUserChangedStationBefore = service?.CurrentUserHasPreferredStation ?? false;
			return obj;
		}

		public void HandleStationChanged(string station)
		{
			if (defaultStation == null)
			{
				defaultStation = station;
			}
			else
			{
				lastStationPlayed = station;
			}
			if (durationsBetweenStationChanges.IsEmpty() && firstStationPlayTime == null)
			{
				firstStationPlayTime = DateTime.Now.TimeOfDay;
				return;
			}
			TimeSpan item = DateTime.Now.TimeOfDay - (TimeSpan)firstStationPlayTime;
			firstStationPlayTime = DateTime.Now.TimeOfDay;
			numberOfStationChanges++;
			durationsBetweenStationChanges.Add(item);
		}

		public void AddAudioSettingsEntryPoint(FeedFmAnalytics.AudioSettingsEntryPoint entryPoint)
		{
			audioSettingsEntryPoints.Add(entryPoint);
		}

		private FeedFmAnalytics.AudioSettingsEntryPoint MostCommonEntryPointInList(List<FeedFmAnalytics.AudioSettingsEntryPoint> list)
		{
			if (list.IsEmpty())
			{
				return FeedFmAnalytics.AudioSettingsEntryPoint.DidNotOpenAudioSettings;
			}
			return (from i in list
				group i by i into grp
				orderby grp.Count() descending
				select grp.Key).First();
		}

		public void CalculateMaxStationLoadingTime(double loadingTime)
		{
			if (loadingTime > maxStationLoadingTime)
			{
				maxStationLoadingTime = loadingTime;
			}
		}

		public void SetInWorkoutMusicState(bool startingWorkout, MusicState musicState, AudioPlayerAction volumeState)
		{
			if (startingWorkout)
			{
				AudioStateAtBeginningOfWorkout = new Dictionary<string, string>
				{
					{
						"audioPlayerState",
						musicState.ToString()
					},
					{
						"volumeState",
						volumeState.ToString()
					},
					{
						"event_ts",
						DateTime.UtcNow.ToString()
					}
				};
			}
			else
			{
				AudioStateAtEndOfWorkout = new Dictionary<string, string>
				{
					{
						"audioPlayerState",
						musicState.ToString()
					},
					{
						"volumeState",
						volumeState.ToString()
					},
					{
						"event_ts",
						DateTime.UtcNow.ToString()
					}
				};
			}
		}

		public void HandleVolumeChange(int value, VolumeChangeLocation volumeChangeLocation, VolumeChangeType volumeChangeType, VolumeChangeSource volumeChangeSource)
		{
			switch (volumeChangeType)
			{
			case VolumeChangeType.Music:
				musicMutedVolumeTracker?.VolumeChanged(value, isEnabled);
				break;
			case VolumeChangeType.Master:
				systemMutedVolumeTracker?.VolumeChanged(value, IsEnabled);
				break;
			}
			Dictionary<string, string> item = new Dictionary<string, string>
			{
				{
					"event_ts",
					DateTime.UtcNow.ToString()
				},
				{
					"newValue",
					value.ToString()
				},
				{
					"volumeChangeLocation",
					volumeChangeLocation.ToString()
				},
				{
					"volumeChangeType",
					volumeChangeType.ToString()
				},
				{
					"volumeChangeSource",
					volumeChangeSource.ToString()
				}
			};
			numberOfVolumeChanges++;
			volumeChangeData.Add(item);
		}

		private void CalculateTotalTimeEnabled(bool isEnabled)
		{
			if (!isEnabled)
			{
				if (lastTimeEnabled.HasValue)
				{
					double totalSeconds = TimeSpan.FromTicks(DateTime.Now.Subtract(lastTimeEnabled.Value).Ticks).TotalSeconds;
					totalSecondsEnabled += totalSeconds;
				}
			}
			else
			{
				lastTimeEnabled = DateTime.Now;
			}
		}

		public void HandleUserOpenedDismissedVolumeMixer(bool opened)
		{
			if (opened)
			{
				numberOfVolumeMixerOpens++;
				volumeMixerOpenedTS.Add(DateTime.UtcNow.ToString());
			}
			else
			{
				numberOfVolumeMixerClosed++;
				volumeMixerClosedTS.Add(DateTime.UtcNow.ToString());
			}
		}

		public void HandleUserStartedStoppedMusic(bool started)
		{
			if (started)
			{
				numberOfMusicStarts++;
				musicStartsData.Add(DateTime.UtcNow.ToString());
			}
			else
			{
				numberOfMusicStops++;
				musicStopsData.Add(DateTime.UtcNow.ToString());
			}
			IsEnabled = started;
		}

		public void Start()
		{
			systemMutedVolumeTracker = new FeedFmMutedVolumeTracker((currentConsoleService.Console?.LatestBasicInfo?.Volume).GetValueOrDefault() * 100);
			musicMutedVolumeTracker = new FeedFmMutedVolumeTracker((int)(media.MusicVolume * 100f));
			workOutStartDateTime = DateTime.Now;
			IsEnabled = !media.HasDisabledFeedFmPlayback;
		}

		public void SetTSSFirstPlaybackForUser(bool isFirstPlayback)
		{
			tssFirstPlaybackForUser = isFirstPlayback;
		}

		public void Reset()
		{
			defaultStation = null;
			lastStationPlayed = null;
			firstStationPlayTime = null;
			firstStationPlayTime = null;
			lastTimeEnabled = null;
			tssFirstPlaybackForUser = false;
			workOutStartDateTime = DateTime.MinValue;
			systemMutedVolumeTracker = null;
			musicMutedVolumeTracker = null;
			numberOfStationChanges = 0;
			numberOfVolumeChanges = 0;
			maxStationLoadingTime = 0.0;
			numberOfVolumeMixerOpens = 0;
			numberOfVolumeMixerClosed = 0;
			numberOfMusicStarts = 0;
			numberOfMusicStops = 0;
			maxStationLoadingTime = 0.0;
			totalSecondsEnabled = 0.0;
			volumeChangeData.Clear();
			AudioStateAtBeginningOfWorkout.Clear();
			AudioStateAtEndOfWorkout.Clear();
			volumeMixerOpenedTS.Clear();
			volumeMixerClosedTS.Clear();
			musicStartsData.Clear();
			musicStopsData.Clear();
			durationsBetweenStationChanges.Clear();
			audioSettingsEntryPoints.Clear();
			completedWorkoutAnalytics = new FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics();
		}
	}
