	public class FeedFmMutedVolumeTracker
	{
		private DateTime? lastMutedTime;

		private int currentVolume;

		public double TotalMutedSeconds { get; private set; }

		public FeedFmMutedVolumeTracker(int initialVolume)
		{
			currentVolume = initialVolume;
		}

		private void StartTracking()
		{
			lastMutedTime = DateTime.Now;
		}

		private void Record()
		{
			if (lastMutedTime.HasValue)
			{
				double totalSeconds = TimeSpan.FromTicks(DateTime.Now.Subtract(lastMutedTime.Value).Ticks).TotalSeconds;
				TotalMutedSeconds += totalSeconds;
			}
		}

		private void EndTracking()
		{
			lastMutedTime = null;
		}

		public void FeedFmEnableChanged(bool enabled)
		{
			if (currentVolume == 0)
			{
				if (enabled)
				{
					StartTracking();
				}
				else
				{
					Record();
				}
			}
			else
			{
				EndTracking();
			}
		}

		public void VolumeChanged(int volume, bool isEnabled)
		{
			if (volume == currentVolume)
			{
				return;
			}
			if (!isEnabled)
			{
				currentVolume = volume;
				return;
			}
			if (currentVolume == 0)
			{
				Record();
				EndTracking();
			}
			else if (volume == 0)
			{
				StartTracking();
			}
			currentVolume = volume;
		}
	}
	public interface IFeedFmAnalyticsService
	{
		void Start();

		void Reset();

		void HandleStationChanged(string station);

		void CalculateMaxStationLoadingTime(double loadingTime);

		void AddAudioSettingsEntryPoint(FeedFmAnalytics.AudioSettingsEntryPoint entryPoint);

		void SetInWorkoutMusicState(bool startingWorkout, MusicState musicState, AudioPlayerAction volumeState);

		void HandleVolumeChange(int value, VolumeChangeLocation volumeChangeLocation, VolumeChangeType volumeChangeType, VolumeChangeSource volumeChangeSource);

		void HandleUserOpenedDismissedVolumeMixer(bool opened);

		void HandleUserStartedStoppedMusic(bool started);

		void SetTSSFirstPlaybackForUser(bool isFirstPlayback);

		FeedFmAnalytics.FeedFmCompletedWorkoutAnalytics BundleFeedFmAnalytics(string activityLogId);
	}
