namespace Wolf.Core.Hollywood
{
	public static class BandwidthVideoQualityMapping
	{
		public class QualityMapping
		{
			public VideoQuality VideoQuality => GetVideoQualityFromString(Quality);

			public string Quality { get; set; }

			public double Mbps { get; set; }
		}

		private static readonly List<QualityMapping> FallbackMapping = new List<QualityMapping>
		{
			new QualityMapping
			{
				Quality = "270p",
				Mbps = 1.5
			},
			new QualityMapping
			{
				Quality = "360p",
				Mbps = 2.0
			},
			new QualityMapping
			{
				Quality = "540p",
				Mbps = 2.5
			},
			new QualityMapping
			{
				Quality = "720p",
				Mbps = 6.0
			},
			new QualityMapping
			{
				Quality = "1080p",
				Mbps = 12.0
			}
		};

		public static VideoQuality GetVideoQualityFromString(string s)
		{
			return s switch
			{
				"1080p" => VideoQuality.Resolution1080P, 
				"720p" => VideoQuality.Resolution720P, 
				"540p" => VideoQuality.Resolution540P, 
				"360p" => VideoQuality.Resolution360P, 
				"270p" => VideoQuality.Resolution270P, 
				_ => VideoQuality.Resolution1080P, 
			};
		}

		public static VideoQuality GetVideoQualityFromMbps(double mbps, IFeatureFlagManager featureFlagManager)
		{
			try
			{
				List<QualityMapping> map = featureFlagManager.GetObject<List<QualityMapping>>(FeatureFlags.VideoMbpsToQualityMapping);
				return MapMbps(mbps, map);
			}
			catch (Exception exception)
			{
				Log.Error("Wifi", "BandwidthVideoQualityMapping was unable to parse the feature flag", exception);
				return MapMbps(mbps, FallbackMapping);
			}
		}

		private static VideoQuality MapMbps(double mbps, List<QualityMapping> map)
		{
			List<QualityMapping> list = map.OrderByDescending((QualityMapping x) => x.Mbps).ToList();
			foreach (QualityMapping item in list)
			{
				if (mbps >= item.Mbps)
				{
					return item.VideoQuality;
				}
			}
			return list.Last().VideoQuality;
		}
	}
