		public InWorkoutStreamingVideoViewModel(ILocalSettings localSettings, IMediaService mediaService, IVideoSyncService videoSyncService, IWolfAnalytics wolfAnalytics, HeadphoneConnectionHelperBase headphoneConnection, ILockScreenMediaSettings lockScreenMediaSettings, IDeveloperSettings developerSettings, IMediaSettings mediaSettings, IVideoPlayerErrorHandler videoPlayerErrorHandler, IVideoBufferMonitoringService videoBufferService = null)
