					workoutSettings?.WorkoutContainer?.WorkoutRunner?.StopAsync();
				}
				VideoTitle.Value = workoutSettings?.WorkoutContainer?.Workout?.Title ?? "";
				ShouldShowDebugOverlay.Value = developerSettings?.ShowMediaPlayerDebugOverlay ?? false;
				if (ShouldShowDebugOverlay.Value)
				{
					PerformDebugBindings = true;
					playerStateSub = Observable.Interval(TimeSpan.FromSeconds(2.0)).Subscribe(UpdateVideoDebugOverlay);
				}
				syncService.VideoSessionStarted();
				VideoBufferingDescription.Value = string.Format(Wolf.Core.Resources.AppStrings.video_buffering_explanation, videoBufferService?.MinStartResumeBufferSeconds);
				stateChangeSub?.Dispose();
				stateChangeSub = currentConsoleService?.ActiveConsole?.WhenStateChanged?.SubscribeWithErrorLogging(OnStateChanged);
				headphoneConnectionSub = headphoneConnection.OnConnected.Where((bool c) => c).SubscribeWithErrorLogging(OnHeadphoneDidConnect);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void UpdateVideoDebugOverlay(long s)
		{
			InvokeOnMainThread(delegate
			{
				VideoDebugString.Value = VideoPlayer?.GetVideoString();
			});
		}

		public override async Task OnViewShown()
		{
			VideoBufferText.Value = string.Empty;
			videoErrorSub?.Dispose();
			videoErrorSub = VideoPlayer?.VideoErrorOccured?.SubscribeAsyncWithErrorLogging((Exception ex) => videoPlayerErrorHandler.HandleVideoPlayerError(ex));
			videoBufferStatusSub?.Dispose();
			videoBufferStatusSub = videoBufferService?.WhenVideoBufferStatusChanged?.SubscribeWithErrorLogging(HandleVideoBufferStatusChange);
			videoBufferService?.StartVideoBufferMonitoring(VideoPlayer.CurrentSettingsInfo);
			OnStateChanged();
			await base.OnViewShown();
		}

		private void HandleVideoBufferStatusChange(VideoBufferMonitoringService.VideoBufferingStatus status)
		{
			if (!didReportVideoFailedToLoad && status.VideoFailedToLoad && !status.IsBuffering)
			{
				Log.Trace("Video", "Video failed to load but is not buffering");
				MediaAnalyticsExtensions.VideoFailedToLoadInWorkout(workoutId: (workoutSettings?.WorkoutContainer?.Workout)?.Id, analytics: wolfAnalytics, videoUrl: workoutSettings?.WorkoutContainer?.Media?.WorkoutVideo?.Sources?.HlsSource?.SourceUrl);
				didReportVideoFailedToLoad = true;
			}
			InvokeOnMainThread(delegate
			{
				VideoBufferText.Value = status.BufferText ?? string.Empty;
				ShouldShowLoading.Value = status.IsBuffering;
			});
		}

		private void OnStateChanged(StateChange state = null)
		{
			InvokeOnMainThread(delegate
			{
				switch (state?.Current ?? (currentConsoleService.ActiveConsole?.LatestBasicInfo?.CurrentState).GetValueOrDefault())
				{
				case ConsoleState.WarmUp:
				{
					IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
					if (workoutContainer == null || workoutContainer.WorkoutRunner?.RunContext.Context != Workout.WorkoutContext.OnDemand)
					{
						StartPlaying(state);
					}
					break;
				}
				case ConsoleState.Workout:
				case ConsoleState.PauseOverride:
					StartPlaying(state);
					break;
				case ConsoleState.CoolDown:
					VideoPlayer?.Pause(PlayerType.Video);
					if (MediaService.Music.WorkoutHasLegacyPopMusic)
					{
						VideoPlayer?.Play(PlayerType.Audio);
					}
					break;
				default:
					PauseAudioVideoOrMuteIfAppropriate();
					break;
				}
			});
		}

		private void PauseAudioVideoOrMuteIfAppropriate()
		{
			if (VideoPlayer != null)
			{
				IMediaService mediaService = MediaService;
				if (mediaService != null && mediaService.Music?.LegacyMix?.IsRadioStation == true)
				{
					VideoPlayer.Pause(PlayerType.Video);
					VideoPlayer.AudioVolume = 0f;
				}
				else
				{
					MediaService?.PauseVideoAndMusic();
				}
			}
		}

		private void StartPlaying(StateChange stateChange)
		{
			bool wasWarmingUp = stateChange != null && stateChange.Old == ConsoleState.WarmUp && stateChange.Current.IsRunningState();
			VideoPlayerWillPlay?.OnNext(value: true);
			ResetPlayerVolumesFromLocalSettings(wasWarmingUp);
			lockScreenMediaSettings.SetNowPlayingInfo(new LockScreenMediaInfo
			{
				Artist = AppNameString,
				Track = VideoTitle.Value
			}, LockScreenMediaType.Video, updateCurrentControl: true);
			MediaService?.Play(stateChange);
		}

		private void ResetPlayerVolumesFromLocalSettings(bool wasWarmingUp)
		{
			SetVolumes(mediaSettings.MusicVolume, mediaSettings.TrainerVolume, wasWarmingUp);
		}

		private void OnHeadphoneDidConnect(bool isConnected)
		{
			InvokeOnMainThread(delegate
			{
				if (VideoPlayer != null)
				{
					float audio = VideoPlayer.AudioVolume.Clamp(0f, 1f);
					float video = VideoPlayer.VideoVolume.Clamp(0f, 1f);
					SetVolumes(audio, video, isHeadphoneMaxEnabled: true);
				}
			});
		}

		private void SetVolumes(float audio, float video, bool isHeadphoneMaxEnabled)
		{
			if (VideoPlayer != null)
			{
				isHeadphoneMaxEnabled &= headphoneConnection.IsConnected();
				float num = GetHeadphoneSafeVolume(audio);
				float volume = GetHeadphoneSafeVolume(video);
				MediaService.SetMusicVolume(num);
				MediaService.SetVideoVolume(volume);
				if (isHeadphoneMaxEnabled)
				{
					int consoleVolume = (100f * Math.Max(num, VideoPlayer.VideoVolume)).RoundToNearest(1.0);
					workoutSettings.WorkoutContainer?.InWorkoutSystemVolumeInteractor?.SetConsoleVolume(consoleVolume);
				}
			}
			float GetHeadphoneSafeVolume(float num2)
			{
				if (!isHeadphoneMaxEnabled || !(num2 > 0.1f))
				{
					return num2;
				}
				return 0.1f;
			}
		}

		public override void Dispose()
		{
			if (!isDisposed)
			{
				syncService?.VideoSessionStopped();
				stateChangeSub?.Dispose();
				stateChangeSub = null;
				videoErrorSub?.Dispose();
				videoErrorSub = null;
				videoBufferStatusSub?.Dispose();
				videoBufferStatusSub = null;
				playerStateSub?.Dispose();
				playerStateSub = null;
				headphoneConnectionSub?.Dispose();
				headphoneConnectionSub = null;
				((BaseViewModel)this).Dispose();
				isDisposed = true;
				UnregisterChangeHandlers();
			}
		}

