	public class VideoService : IVideoService
	{
		private readonly IWolfTrackingService wolfTrackingService;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IFeatureFlagManager featureFlagManager;

		private ICombinedAudioVideoPlayer preBufferedVideoPlayer;

		private readonly Subject<ICombinedAudioVideoPlayer> _videoPlayerReady = new Subject<ICombinedAudioVideoPlayer>();

		private readonly Subject<bool> _whenCleaned = new Subject<bool>();

		public virtual ICombinedAudioVideoPlayer PreBufferedVideoPlayer => preBufferedVideoPlayer;

		public IObservable<ICombinedAudioVideoPlayer> VideoReady => _videoPlayerReady;

		public IObservable<bool> WhenCleaned => _whenCleaned;

		public bool ShowCaptions { get; set; }

		public VideoService(IWolfTrackingService wolfTrackingService, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IFeatureFlagManager featureFlagManager)
		{
			this.wolfTrackingService = wolfTrackingService;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
			this.featureFlagManager = featureFlagManager;
		}

		public ICombinedAudioVideoPlayer GetVideoPlayer(out PlaybackType selectedPlaybackType)
		{
			try
			{
				selectedPlaybackType = GetSelectedPlaybackType();
				Log.Trace("Video", $"Determined video settings: PlaybackType: {selectedPlaybackType} | VideoQuality: {workoutSettings.VideoQuality}");
				return Mvx.Resolve<ICombinedAudioVideoPlayer>();
			}
			catch (Exception ex)
			{
				Log.Error("Video", $"Exception occurred creating video player: {ex}");
				throw new VideoServiceException("Create Video Player Exception: " + ex.Message, ex);
			}
		}

		public ICombinedAudioVideoPlayer GetVideoPlayer()
		{
			PlaybackType selectedPlaybackType;
			return GetVideoPlayer(out selectedPlaybackType);
		}

		public async Task<ICombinedAudioVideoPlayer> StartPrebufferingVodVideo(string videoUri, string audioUri = null)
		{
			Log.Trace("Video", "Starting pre-buffering VOD video: uri: " + videoUri + " | audioUri: " + audioUri);
			preBufferedVideoPlayer = GetVideoPlayer(out var selectedPlaybackType);
			try
			{
				await preBufferedVideoPlayer.StartLoadVodSource(videoUri, selectedPlaybackType, audioUri);
				wolfTrackingService.LastRequestedVideoUrl = videoUri;
			}
			catch (Exception ex)
			{
				Log.Error("Video", "Exception occurred starting to load video source", ex);
				throw new VideoServiceException("Load Video Source Exception " + ex.Message, ex);
			}
			Log.Trace("Video", "Finished pre-buffering VOD video");
			_videoPlayerReady.OnNext(preBufferedVideoPlayer);
			return preBufferedVideoPlayer;
		}

		public async Task<ICombinedAudioVideoPlayer> StartPrebufferingLiveVideo(string liveVideoUri, string audioUri = null)
		{
			Log.Trace("Video", "Starting pre-buffering live video: Url: " + liveVideoUri + " audioUrl: " + audioUri);
			preBufferedVideoPlayer = GetVideoPlayer(out var selectedPlaybackType);
			try
			{
				await preBufferedVideoPlayer.StartLoadStream(liveVideoUri, selectedPlaybackType, audioUri);
				wolfTrackingService.LastRequestedVideoUrl = liveVideoUri;
			}
			catch (Exception ex)
			{
				Log.Error("Video", $"Exception occured starting to load video stream: {ex}");
				throw new VideoServiceException("Load Video Stream Exception: " + ex.Message, ex);
			}
			_videoPlayerReady.OnNext(preBufferedVideoPlayer);
			return PreBufferedVideoPlayer;
		}

		public async Task<ICombinedAudioVideoPlayer> LoadFromDirectSource(string directVideoUri, string audioUri = null)
		{
			Log.Trace("Video", "Loading video from direct source: uri: " + directVideoUri + " | audioUri: " + audioUri);
			preBufferedVideoPlayer = GetVideoPlayer(out var _);
			try
			{
				await preBufferedVideoPlayer.StartLoadDirectSource(directVideoUri, audioUri);
				wolfTrackingService.LastRequestedVideoUrl = directVideoUri;
			}
			catch (Exception ex)
			{
				Log.Error("Video", $"Exception occurred loading from direct video source: {ex}");
				throw new VideoServiceException("Load Direct Video Source Exception: " + ex.Message, ex);
			}
			_videoPlayerReady.OnNext(preBufferedVideoPlayer);
			return preBufferedVideoPlayer;
		}

		public PlaybackType GetSelectedPlaybackType()
		{
			if (ShouldUseHls())
			{
				return PlaybackType.Hls;
			}
			return PlaybackType.Fixed;
		}

		private bool ShouldUseHls()
		{
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.VideoHlsEnabled))
			{
				return false;
			}
			bool flag = currentConsoleService.CheckForHlsSupport() == HlsSupported.Supported;
			Log.Trace("Video", $"VideoService: HLS supported: {flag}");
			return flag;
		}

		public void ClearBuffer()
		{
		}

		public void Cleanup()
		{
			preBufferedVideoPlayer?.Dispose();
			preBufferedVideoPlayer = null;
			_whenCleaned?.OnNext(value: true);
		}
	}
	public class VideoServiceException : Exception
	{
		internal VideoServiceException(string message = null, Exception innerException = null)
			: base(message, innerException)
		{
		}
	}
	public class VideoSyncService : IVideoSyncService
	{
		private const int BleMinOffsetSeconds = 5;

		private const int UsbMinOffsetSeconds = 2;

		private const int VideoBufferingUpdateDelaySeconds = 20;

		private bool currentlyBuffering;

		private readonly SemaphoreSlim goalTimeLock = new SemaphoreSlim(1, 1);

		protected readonly IVideoService videoService;

		protected readonly ILocalSettings localSettings;

		private readonly IWifiService wifiService;

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly IFeatureFlagManager featureFlagManager;

		protected readonly ICurrentConsoleService currentConsoleService;

		private readonly IWolfTrackingService trackingService;

		private readonly IMediaAnalyticsService videoAnalyticsService;

		private readonly IWorkoutSettings workoutSettings;

		private IDisposable wifiSubscriber;

		private IDisposable videoBufferStatusSub;

		private int minOffsetSeconds;

		private DateTime lastSetTime;

		private DateTime bufferingStartedTime;

		private MediaAnalyticsSyncDataObject analyticsDataObject = new MediaAnalyticsSyncDataObject();

		private VideoBufferMonitoringService.VideoBufferingStatus lastBufferingStatus;

		private IVideoBufferMonitoringService videoBufferService;

		private IVideoQualitySettings videoQualitySettings;

		protected ICombinedAudioVideoPlayer combinedAudioVideoPlayer => videoService.PreBufferedVideoPlayer;

		public double LastVideoPositionSeconds => combinedAudioVideoPlayer?.LastVideoPositionSeconds ?? 0.0;

		public MediaAnalyticsSyncDataObject AnalyticsData => analyticsDataObject;

		public VideoSyncService(ILocalSettings localSettings, IVideoService videoService, IWifiService wifiService, IWolfAnalytics wolfAnalytics, IFeatureFlagManager featureFlagManager, IVideoQualitySettings videoQualitySettings, IWolfTrackingService trackingService, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IMediaAnalyticsService videoAnalyticsService = null, IVideoBufferMonitoringService videoBufferService = null)
		{
			this.localSettings = localSettings;
			this.videoService = videoService;
			this.wifiService = wifiService;
			this.wolfAnalytics = wolfAnalytics;
			this.featureFlagManager = featureFlagManager;
			this.videoQualitySettings = videoQualitySettings;
			this.trackingService = trackingService;
			this.videoAnalyticsService = videoAnalyticsService;
			this.videoBufferService = videoBufferService;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
			bufferingStartedTime = DateTime.UtcNow;
		}

		public virtual void VideoSessionStarted()
		{
			analyticsDataObject = new MediaAnalyticsSyncDataObject();
			wifiSubscriber?.Dispose();
			wifiSubscriber = wifiService?.WhenNetworkStateChanged?.SubscribeWithErrorLogging(OnWifiStateChange);
			videoBufferStatusSub?.Dispose();
			videoBufferStatusSub = videoBufferService?.WhenVideoBufferStatusChanged?.SubscribeWithErrorLogging(HandleVideoBufferStatusChange);
			videoBufferService?.StartVideoBufferMonitoring(combinedAudioVideoPlayer.CurrentSettingsInfo);
			lastBufferingStatus.IsBuffering = false;
			HandleVideoBufferStatusChange(new VideoBufferMonitoringService.VideoBufferingStatus
			{
				IsBuffering = true
			});
			videoAnalyticsService?.StartWorkout();
		}

		public virtual void VideoSessionStopped()
		{
			VideoSessionCleanup();
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.VideoBufferAnalytics))
			{
				return;
			}
			if (currentlyBuffering)
			{
				UpdateTotalTimeSpentBuffering();
			}
			Task.Run(async delegate
			{
				MediaAnalyticsData mediaAnalyticsData = MediaAnalyticsData.Empty;
				if (videoAnalyticsService != null)
				{
					mediaAnalyticsData = await videoAnalyticsService.FinishWorkoutAsync(analyticsDataObject).ConfigureAwait(continueOnCapturedContext: false);
					Log.Info("Video", "Video log uploaded to: " + mediaAnalyticsData?.VideoPlayerLogUrl);
				}
				wolfAnalytics.PostWorkoutBufferingSummary(videoQualitySettings, trackingService, analyticsDataObject, workoutSettings, mediaAnalyticsData);
			});
		}

		public void VideoSessionCleanup()
		{
			videoBufferService?.StopVideoBufferMonitoring();
			wifiSubscriber?.Dispose();
			wifiSubscriber = null;
			videoBufferStatusSub?.Dispose();
			videoBufferStatusSub = null;
		}

		private void SendBufferingEventToAnalytics(int wifiConnectionStrength)
		{
			Workout workout = workoutSettings?.WorkoutContainer?.Workout;
			Workout.WorkoutContext valueOrDefault = (workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.Context).GetValueOrDefault();
			string idOrUrl = ((valueOrDefault != Workout.WorkoutContext.OnDemand) ? workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.LiveStreamUrl : workoutSettings?.WorkoutContainer?.Media?.WorkoutVideo?.Sources?.HlsSource?.SourceUrl);
			string text = workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.Id;
			wolfAnalytics.VideoBuffering(idOrUrl, workout?.Id, wifiConnectionStrength, (valueOrDefault == Workout.WorkoutContext.OnDemand) ? null : text);
		}

		private void OnWifiStateChange(WifiNetworkState wifiState)
		{
			if (wifiState == WifiNetworkState.Disconnected)
			{
				analyticsDataObject.WifiDisconnects++;
			}
		}

		public void UpdateVideoCaptionStatus(VideoCaptionStatus status)
		{
			if (status != null && analyticsDataObject != null)
			{
				if (status.CaptionsAreInTrouble)
				{
					analyticsDataObject.CaptionsAreInTroubleCount++;
				}
				if (status.CaptionsAreMalformed)
				{
					analyticsDataObject.CaptionsAreMalformedCount++;
				}
			}
		}

		private void HandleVideoBufferStatusChange(VideoBufferMonitoringService.VideoBufferingStatus status)
		{
			analyticsDataObject.UpdateMediaProperties(combinedAudioVideoPlayer);
			currentlyBuffering = status.IsBuffering;
			bool isBuffering = lastBufferingStatus.IsBuffering;
			bool flag = currentlyBuffering && !isBuffering;
			bool flag2 = !currentlyBuffering && isBuffering;
			if (flag)
			{
				bufferingStartedTime = DateTime.UtcNow;
				analyticsDataObject.BufferingEventStarted = bufferingStartedTime;
				analyticsDataObject.TotalBufferAttempts++;
				int valueOrDefault = (wifiService?.ActiveNetworkInfo?.ConnectionStrength).GetValueOrDefault();
				analyticsDataObject.SumWifiConnectionStrengths += valueOrDefault;
				SendBufferingEventToAnalytics(valueOrDefault);
			}
			if (flag2 && analyticsDataObject.BufferingEventStarted != default(DateTime))
			{
				UpdateTotalTimeSpentBuffering();
			}
			ICurrentConsoleService obj = currentConsoleService;
			bool flag3 = obj != null && obj.ActiveConsole?.LatestBasicInfo?.IsInState(ConsoleState.WarmUp) == true;
			if (!analyticsDataObject.BadConnectWarningDisplayed && flag3 && status.BadConnection)
			{
				analyticsDataObject.BadConnectWarningDisplayed = true;
			}
			lastBufferingStatus = status;
		}

		private void UpdateTotalTimeSpentBuffering()
		{
			if (analyticsDataObject.BufferingEventStarted == default(DateTime))
			{
				analyticsDataObject.BufferingEventStarted = bufferingStartedTime;
			}
			analyticsDataObject.TotalTimeSpentBuffering = analyticsDataObject.TotalTimeSpentBuffering.Add(DateTime.UtcNow.Subtract(analyticsDataObject.BufferingEventStarted));
		}

		protected virtual bool ShouldSkipGoalTimeUpdate()
		{
			return false;
		}

		public void UpdateGoalTime(Workout currentWorkout, IFitnessConsole console)
		{
			try
			{
				goalTimeLock.Wait();
				DateTime utcNow = DateTime.UtcNow;
				if ((utcNow - bufferingStartedTime).TotalSeconds < 20.0)
				{
					return;
				}
				SetupMinOffsetIfNeeded(console);
				if (combinedAudioVideoPlayer == null || ShouldSkipGoalTimeUpdate() || !currentWorkout.IsVideoWorkout() || console.LatestBasicInfo.CurrentState != ConsoleState.Workout || LastVideoPositionSeconds < (double)minOffsetSeconds || (utcNow - lastSetTime).TotalSeconds < (double)minOffsetSeconds)
				{
					return;
				}
				int runningTime = console.LatestBasicInfo.RunningTime;
				double num = (double)runningTime - LastVideoPositionSeconds;
				if (!(num < (double)minOffsetSeconds))
				{
					double targetValue = currentWorkout.TargetValue;
					int num2 = (int)Math.Round(targetValue + num);
					if (console.LatestBasicInfo.GoalTime < num2 && !console.LatestBasicInfo.IsInState(ConsoleState.Paused, ConsoleState.PauseOverride))
					{
						Log.Trace("Workout", $"Setting GoalTime: {num2}, previous GoalTime: {console.LatestBasicInfo.GoalTime}, lastVideoPosition: {LastVideoPositionSeconds}, consoleRunningTime: {runningTime}, workoutTargetTime: {targetValue}, state: {console.LatestBasicInfo.CurrentState}");
						IGoalTimeFacade goalTimeFacade = Mvx.Resolve<IGoalTimeFacade>();
						goalTimeFacade.SetGoalTime(num2);
						lastSetTime = utcNow;
					}
				}
			}
			catch (Exception exception)
			{
				Log.Error("Video", "Unable to update GoalTime", exception);
			}
			finally
			{
				goalTimeLock.Release();
			}
		}

		private void SetupMinOffsetIfNeeded(IFitnessConsole console)
		{
			if (minOffsetSeconds == 0)
			{
				minOffsetSeconds = ((console.ConnectionType == Sindarin.Core.Connection.ConnectionType.USB) ? 2 : 5);
			}
		}
	}
	public class VideoCaptionStatus
	{
		public int SecondsSinceLastCaption;

		public bool CaptionsAreInTrouble;

		public bool CaptionsAreMalformed;
	}
	public interface IVideoDownloadCache : IDisposable
	{
		IObservable<IDownloadUpdate> WhenDownloadProgressChanged { get; }

		Task<string> DownloadOrRetrieveCachedVodVideoPath(string workoutId);
	}
	public class VideoDownloadCache : IVideoDownloadCache, IDisposable
	{
		private const string SaveFolderName = ".wolfVideos";

		private readonly IFileDownloaderFactory fileDownloaderFactory;

		private readonly IIfitApiService iFitApi;

		private readonly Subject<IDownloadUpdate> _whenProgressChanged = new Subject<IDownloadUpdate>();

		private readonly string baseDir;

		private IDisposable whenProgressChanged;

		private IFolder saveFolder;

		public IObservable<IDownloadUpdate> WhenDownloadProgressChanged => _whenProgressChanged;

		public iFit.Files.IFileSystem FileSys { get; }

		public VideoDownloadCache(IFileDownloaderFactory fileDownloaderFactory, IIfitApiService iFitApi, string baseDir, iFit.Files.IFileSystem fileSystem = null)
		{
			this.fileDownloaderFactory = fileDownloaderFactory;
			this.baseDir = baseDir;
			this.iFitApi = iFitApi;
			FileSys = fileSystem ?? iFit.Files.FileSystem.Current;
		}

		public async Task<string> DownloadOrRetrieveCachedVodVideoPath(string workoutId)
		{
			_ = 3;
			try
			{
				if (saveFolder == null)
				{
					saveFolder = await FileSys.LocalStorage.CreateFolderAsync(Path.Combine(baseDir, ".wolfVideos"), CreationCollisionOption.OpenIfExists);
				}
				if (!(await HasCachedVideo(workoutId)) && !(await DownloadVodVideo(workoutId)))
				{
					return null;
				}
				return await LoadCachedVideoPath(workoutId);
			}
			catch (Exception ex)
			{
				Log.Error("Video", "VideoDownloadCache - DownloadOrRetrieveCachedVodVideoPath: (workoutId " + workoutId + ") " + ex.Message + " " + ex.StackTrace);
			}
			return null;
		}

		private async Task<bool> HasCachedVideo(string videoId)
		{
			IList<IFile> list = await saveFolder.GetFilesAsync();
			if (list.IsNullOrEmpty())
			{
				return false;
			}
			return list.Any((IFile x) => x.Name.Contains(videoId));
		}

		private async Task<string> LoadCachedVideoPath(string videoId)
		{
			return (await saveFolder.GetFilesAsync())?.FirstOrDefault((IFile x) => x.Name.Contains(videoId))?.Path;
		}

		private async Task<bool> DownloadVodVideo(string workoutId)
		{
			List<Video.FixedSource> fixedSources = (await WorkoutVideo.GetWorkoutVideo(iFitApi, workoutId)).Sources.FixedSources;
			if (fixedSources.IsNullOrEmpty())
			{
				return false;
			}
			string text = fixedSources.OrderByDescending((Video.FixedSource x) => x.Bitrate).Take(1)?.First()?.SourceUrl;
			if (text == null)
			{
				return false;
			}
			Shire.Core.Util.IFileDownloader fileDownloader = fileDownloaderFactory.CreateFileDownloader(saveFolder);
			whenProgressChanged?.Dispose();
			whenProgressChanged = fileDownloader.WhenProgress.Subscribe(delegate(IDownloadUpdate x)
			{
				_whenProgressChanged.OnNext(x);
			});
			IDownloadUpdate downloadUpdate = await fileDownloader.DownloadFiles(new List<string> { text });
			if (downloadUpdate.FilesDownloaded != 1)
			{
				return false;
			}
			try
			{
				IFile destinationFile = downloadUpdate.Files[0].DestinationFile;
				string newName = workoutId + "." + destinationFile.Name.Split('.').Last();
				await destinationFile.RenameAsync(newName);
				return true;
			}
			catch (Exception exception)
			{
				Log.Error("Video", "VideoDownloadCache - DownloadVodVideo - An error occurred renaming downloaded file", exception);
				return false;
			}
		}

		public void Dispose()
		{
			whenProgressChanged?.Dispose();
			whenProgressChanged = null;
		}
	}
