	public interface IVideoPlayerErrorHandler
	{
		Task HandleVideoPlayerError(Exception exception);
	}
	public class VideoPlayerErrorHandler : IVideoPlayerErrorHandler
	{
		private readonly IDialogPresenter dialogPresenter;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IMediaService mediaService;

		private readonly IWolfAnalytics wolfAnalytics;

		public ICombinedAudioVideoPlayer VideoPlayer => mediaService?.Video?.PreBufferedVideoPlayer;

		public VideoPlayerErrorHandler(IDialogPresenter dialogPresenter, IWorkoutSettings workoutSettings, IMediaService mediaService, IWolfAnalytics wolfAnalytics)
		{
			this.dialogPresenter = dialogPresenter;
			this.workoutSettings = workoutSettings;
			this.mediaService = mediaService;
			this.wolfAnalytics = wolfAnalytics;
		}

		public async Task HandleVideoPlayerError(Exception exception)
		{
			if (exception is MediaServicesWereResetException)
			{
				Log.Trace("Video", "InWorkoutStreamingVideoViewModel has been notified that media services were reset");
				IWorkoutSettings obj = workoutSettings;
				string videoIdOrUrl = ((obj == null || obj.WorkoutContainer?.WorkoutRunner?.RunContext?.Context != Workout.WorkoutContext.OnDemand) ? workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.LiveStreamUrl : mediaService?.WorkoutVideo?.Sources?.HlsSource?.SourceUrl);
				string audioUrl = workoutSettings?.WorkoutContainer?.Workout?.GetWorkoutMetadataAudioUrl();
				if (dialogPresenter.CurrentMainViewModel is BaseViewModel baseViewModel)
				{
					baseViewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.media_player_error, Wolf.Core.Resources.AppStrings.media_player_reset_msg, async delegate
					{
						await StartNewLoadSource(VideoPlayer?.LastVideoPositionSeconds ?? 0.0).ConfigureAwait(continueOnCapturedContext: false);
						mediaService?.Play();
					}, cancellableOperation: false, null, Wolf.Core.Resources.AppStrings.media_player_reset_end_workout, Wolf.Core.Resources.AppStrings.media_player_reset_rejoin_workout, null, async delegate
					{
						await (workoutSettings?.WorkoutContainer?.WorkoutRunner?.FinishWorkout(completed: false));
					}, dismissible: false);
				}
				wolfAnalytics.MediaServicesWereReset(videoIdOrUrl, audioUrl, workoutSettings?.WorkoutContainer?.Workout?.Id, workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.Id).ConfigureAwait(continueOnCapturedContext: false);
			}
			else
			{
				Log.Trace("Video", "An error occurred with the video player, reloading source");
				await StartNewLoadSource(VideoPlayer?.LastVideoPositionSeconds ?? 0.0).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task StartNewLoadSource(double position)
		{
			Log.Trace("Video", $"Kicking off task to reload new source at {position}");
			try
			{
				Workout workout = workoutSettings?.WorkoutContainer?.Workout;
				if (VideoPlayer != null)
				{
					IWorkoutSettings obj = workoutSettings;
					if (obj == null || obj.WorkoutContainer?.WorkoutRunner?.RunContext.Context != Workout.WorkoutContext.OnDemand)
					{
						await VideoPlayer.StartLoadStream(workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo.LiveStreamUrl, mediaService.Video.GetSelectedPlaybackType(), workout?.GetWorkoutMetadataAudioUrl());
					}
					else
					{
						WorkoutVideo obj2 = workoutSettings?.WorkoutContainer?.Media?.WorkoutVideo;
						await VideoPlayer.StartLoadVodSource(obj2?.Sources?.HlsSource?.SourceUrl, VideoPlayer.SelectedPlaybackType, workout?.GetWorkoutMetadataAudioUrl());
					}
					if (!VideoPlayer.VideoFailedToLoad)
					{
						VideoPlayer.SeekTo(position, PlayerType.Both, forceSeek: true);
					}
					else
					{
						Log.Error("Video", "Failed to load video. No error available.");
					}
				}
			}
			catch (Exception ex)
			{
				Log.Error("Video", $"Failed to load video after player Error. Exception: {ex.GetBaseException()}");
			}
		}
	}
	public class VideoQualitySettings : IVideoQualitySettings
	{
		public class VerifiedQualitySettings
		{
			public const int PlaybackBufferMsDefault = 7000;

			public const int MinBufferMsDefault = 15000;

			public const int MaxBufferMsDefault = 120000;

			public const int PlaybackBufferAfterRebufferMsDefault = 7000;

			public const bool ViewportOrientationMayChangeDefault = true;

			public const int BandwidthFractionDefault = 60;

			public const int BufferedFractionToLiveEdgeForQualityIncreaseDefault = 75;

			public const int MaxDurationForQualityDecreaseMsDefault = 120000;

			public const int InitialBitrateEstimateDefault = -1;

			public const int MinDurationForQualityIncreaseMsDefault = 45000;

			public const int MinDurationToRetainAfterDiscardMsDefault = 7000;

			public const int LiveStreamSecondsBehindEdgeDefault = 10;

			public const int PreferredForwardBufferSecondsLiveDefault = 12;

			public const int PreferredForwardBufferSecondsVodDefault = 60;

			public bool ViewportOrientationMayChange { get; }

			public int MinBufferMs { get; }

			public int MaxBufferMs { get; }

			public int PlaybackBufferMs { get; }

			public int LiveStreamSecondsBehindEdge { get; }

			public DataSourceType DataSourceType { get; }

			public LoadControlType LoadControlType { get; }

			public SettingsInfo LiveSettings { get; set; }

			public SettingsInfo VodSettings { get; set; }

			public VerifiedQualitySettings(IFeatureFlagManager ffm)
			{
				if (!ffm.GetBool(FeatureFlags.ExoPlayerAbAllowVideoNonSeamlessAdaptivenessLive) || ffm.GetInt(FeatureFlags.PreferredForwardBufferSecondsLive) != 0 || ffm.GetInt(FeatureFlags.ExoPlayerAbBufferedFractionToLiveEdgeForQualityIncrease) != 0 || ffm.GetInt(FeatureFlags.ExoPlayerAbBufferForPlaybackAfterRebufferMsLive) != 0)
				{
					LiveSettings = new SettingsInfo
					{
						AllowVideoNonSeamlessAdaptiveness = ffm.GetBool(FeatureFlags.ExoPlayerAbAllowVideoNonSeamlessAdaptivenessLive),
						AllowBufferingWhilePaused = ffm.GetBool(FeatureFlags.AVPlayerAllowBufferingWhilePaused),
						BandwidthFraction = (float)ffm.GetInt(FeatureFlags.ExoPlayerAbBandwidthFraction, 60) / 100f,
						BufferedFractionToLiveEdgeForQualityIncrease = (float)ffm.GetInt(FeatureFlags.ExoPlayerAbBufferedFractionToLiveEdgeForQualityIncrease, 75) / 100f,
						MaxDurationForQualityDecreaseMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMaxDurationForQualityDecreaseMs, 120000),
						InitialBitrateEstimate = ffm.GetInt(FeatureFlags.ExoPlayerAbInitialBitrateEstimate, -1),
						MinDurationForQualityIncreaseMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMinDurationForQualityIncreaseMs, 45000),
						MinDurationToRetainAfterDiscardMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMinDurationToRetainAfterDiscardMs, 7000),
						PlaybackBufferMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMinPlaybackBufferMs, 7000),
						PlaybackBufferAfterRebufferMs = ffm.GetInt(FeatureFlags.ExoPlayerAbBufferForPlaybackAfterRebufferMsLive, 7000),
						PreferredForwardBufferSeconds = ffm.GetInt(FeatureFlags.PreferredForwardBufferSecondsLive, 12)
					};
				}
				VodSettings = new SettingsInfo
				{
					AllowVideoNonSeamlessAdaptiveness = ffm.GetBool(FeatureFlags.ExoPlayerAbAllowVideoNonSeamlessAdaptivenessVod),
					AllowBufferingWhilePaused = ffm.GetBool(FeatureFlags.AVPlayerAllowBufferingWhilePaused),
					BandwidthFraction = (float)ffm.GetInt(FeatureFlags.ExoPlayerAbBandwidthFraction, 60) / 100f,
					BufferedFractionToLiveEdgeForQualityIncrease = (float)ffm.GetInt(FeatureFlags.ExoPlayerAbBufferedFractionToLiveEdgeForQualityIncrease, 75) / 100f,
					MaxDurationForQualityDecreaseMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMaxDurationForQualityDecreaseMs, 120000),
					InitialBitrateEstimate = ffm.GetInt(FeatureFlags.ExoPlayerAbInitialBitrateEstimate, -1),
					MinDurationForQualityIncreaseMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMinDurationForQualityIncreaseMs, 45000),
					MinDurationToRetainAfterDiscardMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMinDurationToRetainAfterDiscardMs, 7000),
					PlaybackBufferMs = ffm.GetInt(FeatureFlags.ExoPlayerAbMinPlaybackBufferMs, 7000),
					PlaybackBufferAfterRebufferMs = ffm.GetInt(FeatureFlags.ExoPlayerAbBufferForPlaybackAfterRebufferMsVod, 7000),
					PreferredForwardBufferSeconds = ffm.GetInt(FeatureFlags.PreferredForwardBufferSecondsVod, 60)
				};
				int num = ffm.GetInt(FeatureFlags.ExoPlayerAbMinBufferVideoMs);
				if (num <= 0)
				{
					Log.Debug("Settings", $"LaunchDarkly attempted to get MinBufferMs to invalid non-positive value, instead we set to default {15000}s");
				}
				SetMinBuffer((num <= 0) ? 15000 : num);
				int num2 = ffm.GetInt(FeatureFlags.ExoPlayerAbMaxBufferMs, 120000);
				if (num2 < 60000)
				{
					Log.Debug("Settings", $"LaunchDarkly attempted to get MaxBufferMs to invalid value less than 60s, instead we set to default {120000}s");
				}
				SetMaxBuffer((num2 < 60000) ? 120000 : num2);
				LiveStreamSecondsBehindEdge = ffm.GetInt(FeatureFlags.LiveStreamSecondsBehindEdge, 10);
				ViewportOrientationMayChange = ffm.GetBool(FeatureFlags.ExoPlayerAbViewportOrientationMayChange, fallback: true);
				if (Enum.TryParse<DataSourceType>(ffm.GetString(FeatureFlags.ExoPlayerAbDataSourceType), ignoreCase: true, out var result))
				{
					DataSourceType = result;
				}
				else
				{
					DataSourceType = DataSourceType.Default;
				}
				if (Enum.TryParse<LoadControlType>(ffm.GetString(FeatureFlags.ExoPlayerAbLoadControlType), ignoreCase: true, out var result2))
				{
					LoadControlType = result2;
				}
				else
				{
					LoadControlType = LoadControlType.Default;
				}
				(PlaybackBufferMs, MinBufferMs, MaxBufferMs) = VerifyBufferValues(PlaybackBufferMs, MinBufferMs, MaxBufferMs);
				if (LiveSettings != null && LiveSettings.PlaybackBufferAfterRebufferMs > LiveStreamSecondsBehindEdge)
				{
					Log.Debug("Settings", $"LaunchDarkly attempted to set PlaybackBufferAfterRebufferMs to {LiveSettings.PlaybackBufferAfterRebufferMs}, which is more than LiveStreamSecondsBehindEdge {LiveStreamSecondsBehindEdge}, which would cause exoplayer to explode. Lowering the PlaybackBufferAfterRebufferMs value");
					LiveSettings.PlaybackBufferAfterRebufferMs = LiveStreamSecondsBehindEdge;
				}
			}

			private void SetMaxBuffer(int max)
			{
				if (LiveSettings != null)
				{
					LiveSettings.MaxBufferMs = max;
				}
				VodSettings.MaxBufferMs = max;
			}

			private void SetMinBuffer(int min)
			{
				if (LiveSettings != null)
				{
					LiveSettings.MinBufferMs = min;
				}
				VodSettings.MinBufferMs = min;
			}

			public (int PlaybackBufferMs, int MinBufferMs, int MaxBufferMs) VerifyBufferValues(int playbackBufferMs, int minBufferMs, int maxBufferMs)
			{
				if (maxBufferMs < minBufferMs)
				{
					Log.Debug("Settings", $"LaunchDarkly attempted to set minBufferMs to {minBufferMs}, which is more than maxBufferMs {maxBufferMs}, which would cause exoplayer to explode. Using default values for both max and min");
					if (Mvx.TryResolve<IWolfAnalytics>(out var service))
					{
						service.HandledInvalidBufferSize(minBufferMs, maxBufferMs);
					}
					minBufferMs = 15000;
					maxBufferMs = 120000;
				}
				if (playbackBufferMs > minBufferMs)
				{
					Log.Debug("Settings", $"LaunchDarkly attempted to set PlaybackBufferMs to {playbackBufferMs}, which needs to be less than MinBufferMs {minBufferMs}, which would cause exoplayer to explode.");
					if (Mvx.TryResolve<IWolfAnalytics>(out var service2))
					{
						service2.HandledInvalidPlaybackBufferSize(minBufferMs, playbackBufferMs);
					}
					playbackBufferMs = minBufferMs;
				}
				return (PlaybackBufferMs: playbackBufferMs, MinBufferMs: minBufferMs, MaxBufferMs: maxBufferMs);
			}
		}

		private readonly IFeatureFlagManager featureFlagManager;

		private static readonly object padlock = new object();

		private VerifiedQualitySettings _verifiedQualitySettings;

		public VideoQuality VideoQuality => GetVideoQuality();

		public int LiveStreamSecondsBehindEdge => verifiedQualitySettings.LiveStreamSecondsBehindEdge;

		public bool ViewportOrientationMayChange => verifiedQualitySettings.ViewportOrientationMayChange;

		public SettingsInfo LiveSettings => verifiedQualitySettings.LiveSettings;

		public SettingsInfo VodSettings => verifiedQualitySettings.VodSettings;

		public DataSourceType DataSourceType => verifiedQualitySettings.DataSourceType;

		public LoadControlType LoadControlType => verifiedQualitySettings.LoadControlType;

		private VerifiedQualitySettings verifiedQualitySettings
		{
			get
			{
				lock (padlock)
				{
					if (_verifiedQualitySettings == null)
					{
						_verifiedQualitySettings = new VerifiedQualitySettings(featureFlagManager);
					}
					return _verifiedQualitySettings;
				}
			}
		}

		public VideoQualitySettings(IFeatureFlagManager featureFlagManager)
		{
			this.featureFlagManager = featureFlagManager;
		}

		public void ClearQualitySettings()
		{
			_verifiedQualitySettings = null;
		}

		private VideoQuality GetVideoQuality()
		{
			if (Mvx.TryResolve<IWorkoutSettings>(out var service))
			{
				if (service.VideoQuality == VideoQuality.Auto)
				{
					return service.OptimizedVideoQuality;
				}
				return service.VideoQuality;
			}
			return VideoQuality.Resolution1080P;
		}
	}
	public interface IWorkoutVideoSpeedTest
	{
		Task<VideoQuality> DetermineVideoQuality(CancellationToken token);
	}
	public class WorkoutVideoSpeedTest : IWorkoutVideoSpeedTest
	{
		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly int bufferByteSize;

		private readonly int testDurationMs;

		private readonly string speedTestUrl;

		private readonly VideoQuality defaultQuality;

		public WorkoutVideoSpeedTest(IFeatureFlagManager featureFlagManager, IWolfAnalytics wolfAnalytics)
		{
			this.featureFlagManager = featureFlagManager;
			this.wolfAnalytics = wolfAnalytics;
			testDurationMs = featureFlagManager.GetInt(FeatureFlags.VideoSpeedTestSeconds) * 1000;
			speedTestUrl = featureFlagManager.GetString(FeatureFlags.VideoSpeedTestUrl);
			defaultQuality = BandwidthVideoQualityMapping.GetVideoQualityFromString(featureFlagManager.GetString(FeatureFlags.VideoPlaybackQualityDefault));
			bufferByteSize = featureFlagManager.GetInt(FeatureFlags.VideoSpeedTestBufferBytes);
		}

		public async Task<VideoQuality> DetermineVideoQuality(CancellationToken token)
		{
			int totalBytesRead = 0;
			double speedMbps = default(double);
			try
			{
				using HttpClient httpClient = new HttpClient();
				using HttpResponseMessage response = await httpClient.GetAsync(speedTestUrl, HttpCompletionOption.ResponseHeadersRead, token);
				response.EnsureSuccessStatusCode();
				byte[] buffer = new byte[bufferByteSize];
				Stopwatch st = new Stopwatch();
				st.Start();
				token.ThrowIfCancellationRequested();
				Stream contentStream = await response.Content.ReadAsStreamAsync().ConfigureAwait(continueOnCapturedContext: false);
				object obj = null;
				int num = 0;
				VideoQuality result = default(VideoQuality);
				try
				{
					token.ThrowIfCancellationRequested();
					while (true)
					{
						if (st.ElapsedMilliseconds < testDurationMs)
						{
							int num2 = await contentStream.ReadAsync(buffer, 0, buffer.Length, token).ConfigureAwait(continueOnCapturedContext: false);
							if (num2 == 0)
							{
								await wolfAnalytics.VideoSpeedTestFailure(ErrorCode.VideoSpeedTestFailedCouldNotReadBytes, "Could not read any bytes from the stream.").ConfigureAwait(continueOnCapturedContext: false);
								result = defaultQuality;
								num = 1;
								break;
							}
							totalBytesRead += num2;
							token.ThrowIfCancellationRequested();
							continue;
						}
						st.Stop();
						speedMbps = ConvertToMbps(totalBytesRead, st.ElapsedMilliseconds);
						if (double.IsNaN(speedMbps))
						{
							speedMbps = 0.0;
						}
						Log.Info("Wifi", $"Download speed is {speedMbps} mbps");
						break;
					}
				}
				catch (object obj2)
				{
					obj = obj2;
				}
				if (contentStream != null)
				{
					await ((IAsyncDisposable)contentStream).DisposeAsync();
				}
				object obj3 = obj;
				if (obj3 != null)
				{
					if (!(obj3 is Exception source))
					{
						throw obj3;
					}
					ExceptionDispatchInfo.Capture(source).Throw();
				}
				if (num == 1)
				{
					return result;
				}
			}
			catch (OperationCanceledException)
			{
				Log.Info("Wifi", "Workout video speed cancelled");
				throw;
			}
			catch (Exception ex2)
			{
				Log.Error("Wifi", "Workout video speed test failed, giving default quality", ex2);
				await wolfAnalytics.VideoSpeedTestFailure(ErrorCode.VideoSpeedTestFailedOther, "Speed test failed because: " + ex2.Message).ConfigureAwait(continueOnCapturedContext: false);
				return defaultQuality;
			}
			token.ThrowIfCancellationRequested();
			VideoQuality videoQuality = BandwidthVideoQualityMapping.GetVideoQualityFromMbps(speedMbps, featureFlagManager);
			await wolfAnalytics.VideoSpeedTestSuccess(speedMbps, videoQuality).ConfigureAwait(continueOnCapturedContext: false);
			return videoQuality;
		}

		private double ConvertToMbps(double bytes, double ms)
		{
			return 8.0 * bytes / (ms * 1000.0);
		}
	}
