namespace Wolf.Core.Hollywood.Services.VideoCaptionMonitoring
{
	public interface IVideoCaptionMonitoringService : IDisposable
	{
		BooleanCycle NoLongerFollowingWorkout { get; set; }

		IObservable<VideoCaptionStatus> WhenVideoCaptionStatusChanged { get; }

		void StartMonitoringCaptions();

		void StopMonitoringCaptions();

		void CaptionStringReceived(object sender, string caption);
	}
	public class VideoCaptionMonitoringService : IVideoCaptionMonitoringService, IDisposable
	{
		public const int CaptionsInTroubleSecs = 30;

		public const int CaptionsFailsafeSecs = 60;

		public const int CaptionsHaveFailedSecs = 180;

		public const int MalformedCaptionTolerance = 60;

		private readonly IVideoService videoService;

		private readonly IVideoSyncService videoSyncService;

		private readonly IWorkoutSettings workoutSettings;

		private ICombinedAudioVideoPlayer player;

		private DateTime lastCaptionReceived;

		private DateTime lastCaptionApplied;

		private ILocalSettings localSettings;

		private ILiveWorkoutTranslatorService liveWorkoutTranslator;

		private int malformedCaptionCount;

		private IDisposable timeChangedMetricSub;

		private IDisposable playbackCompletedSub;

		protected readonly Subject<VideoCaptionStatus> _whenVideoCaptionStatusChanged = new Subject<VideoCaptionStatus>();

		private string lastCaption;

		public IObservable<VideoCaptionStatus> WhenVideoCaptionStatusChanged => _whenVideoCaptionStatusChanged;

		public BooleanCycle NoLongerFollowingWorkout { get; set; }

		public VideoCaptionMonitoringService(IVideoService videoService, ILocalSettings localSettings, ILiveWorkoutTranslatorService liveWorkoutTranslator, IVideoSyncService videoSyncService, IWorkoutSettings workoutSettings)
		{
			this.videoService = videoService;
			player = videoService.PreBufferedVideoPlayer;
			this.localSettings = localSettings;
			this.liveWorkoutTranslator = liveWorkoutTranslator;
			this.videoSyncService = videoSyncService;
			this.workoutSettings = workoutSettings;
		}

		public void CaptionStringReceived(object sender, string caption)
		{
			lastCaptionReceived = DateTime.Now;
			lastCaption = caption;
			Log.Trace("Workout", "Caption received: " + caption);
			if (lastCaptionApplied.AddMilliseconds(750.0) < DateTime.Now)
			{
				lastCaptionApplied = DateTime.Now;
				try
				{
					liveWorkoutTranslator.ApplyControlStringToConsole(caption, workoutSettings.WorkoutContainer?.WorkoutRunner);
					malformedCaptionCount = 0;
				}
				catch (ArgumentException)
				{
					malformedCaptionCount++;
				}
				catch (LiveWorkoutTranslatorService.LiveWorkoutTranslatorServiceCoolDownStateException error)
				{
					_whenVideoCaptionStatusChanged.OnError(error);
				}
			}
		}

		public void StartMonitoringCaptions()
		{
			if (player == null)
			{
				Log.Trace("Video", "StartMonitoringCaptions: PreBufferedVideoPlayer is null, subscribing to VideoReady event");
				videoService.VideoReady.Subscribe(delegate(ICombinedAudioVideoPlayer x)
				{
					player = x;
					StartMonitoringCaptions_VideoReady();
				});
			}
			else
			{
				StartMonitoringCaptions_VideoReady();
			}
		}

		private void StartMonitoringCaptions_VideoReady()
		{
			Log.Trace("Video", "StartMonitoringCaptions");
			StopMonitoringCaptions();
			player.OnNewCaptionString -= CaptionStringReceived;
			player.OnNewCaptionString += CaptionStringReceived;
			lastCaptionReceived = DateTime.Now;
			timeChangedMetricSub?.Dispose();
			timeChangedMetricSub = Observable.Interval(TimeSpan.FromSeconds(5.0)).Subscribe(CheckVideoCaptions);
			lastCaptionApplied = DateTime.Now.AddSeconds(-1.0);
			malformedCaptionCount = 0;
			playbackCompletedSub = player.VideoPlaybackCompleted.Subscribe(delegate
			{
				Log.Trace("Video", "VideoCaptionMonitoringService playback completed");
				CaptionStringReceived(this, "-1,0,0,0,0,0,0,0,2");
				StopMonitoringCaptions();
			});
			if (NoLongerFollowingWorkout != null)
			{
				NoLongerFollowingWorkout.Changed -= NoLongerFollowingWorkoutChanged;
				NoLongerFollowingWorkout.Changed += NoLongerFollowingWorkoutChanged;
			}
		}

		public void CheckVideoCaptions(long seconds)
		{
			double totalSeconds = (DateTime.Now - lastCaptionReceived).TotalSeconds;
			VideoCaptionStatus videoCaptionStatus = new VideoCaptionStatus
			{
				SecondsSinceLastCaption = (int)totalSeconds,
				CaptionsAreInTrouble = (totalSeconds >= 30.0),
				CaptionsAreMalformed = (malformedCaptionCount >= 60)
			};
			videoSyncService?.UpdateVideoCaptionStatus(videoCaptionStatus);
			_whenVideoCaptionStatusChanged.OnNext(videoCaptionStatus);
		}

		public void StopMonitoringCaptions()
		{
			Log.Trace("Video", "StopMonitoringCaptions");
			if (player != null)
			{
				player.OnNewCaptionString -= CaptionStringReceived;
			}
			if (NoLongerFollowingWorkout != null)
			{
				NoLongerFollowingWorkout.Changed -= NoLongerFollowingWorkoutChanged;
			}
			timeChangedMetricSub?.Dispose();
			timeChangedMetricSub = null;
		}

		private void NoLongerFollowingWorkoutChanged(object sender, EventArgs e)
		{
			Log.Trace("Workout", $"NoLongerFollowingWorkout changed: {NoLongerFollowingWorkout.Value}");
			if (!NoLongerFollowingWorkout.Value)
			{
				CaptionStringReceived(this, lastCaption);
			}
		}

		public void Dispose()
		{
			StopMonitoringCaptions();
			NoLongerFollowingWorkout = null;
			_whenVideoCaptionStatusChanged.Dispose();
			playbackCompletedSub?.Dispose();
			playbackCompletedSub = null;
		}
	}
}
namespace Wolf.Core.Hollywood.Services.VideoBufferMonitoring
{
	public interface IVideoBufferMonitoringService : IDisposable
	{
		int MinStartResumeBufferSeconds { get; }

		bool IsBuffering { get; }

		IObservable<VideoBufferMonitoringService.VideoBufferingStatus> WhenVideoBufferStatusChanged { get; }

		Task StartVideoBufferMonitoring(SettingsInfo settingsInfo = null);

