	public class VideoBufferMonitoringService : IVideoBufferMonitoringService, IDisposable
	{
		public struct VideoBufferingStatus
		{
			public bool VideoFailedToLoad { get; set; }

			public bool BadConnection { get; set; }

			public bool AllowSkip { get; set; }

			public string BufferText { get; set; }

			public int BufferPercentage { get; set; }

			public int BufferedSeconds { get; set; }

			public bool IsBuffering { get; set; }

			public double CurrentPosition { get; set; }

			public override string ToString()
			{
				return $"[VideoBufferingStatus: BadConnection={BadConnection}, AllowSkip={AllowSkip}, BufferText={BufferText}, BufferPercentage={BufferPercentage}]";
			}
		}

		private const int PlaybackBufferAfterRebufferSeconds = 12;

		private const int MaxInitializationDurationSeconds = 10;

		private const int MinNonHlsBufferSeconds = 60;

		private const int HowLongToWaitBeforeShowingBadConnectionTextOnInitialBufferSec = 20;

		private static readonly TimeSpan timeoutTime = TimeSpan.FromMilliseconds(100.0);

		private readonly bool UsingHlsPlaybackType;

		private readonly SemaphoreSlim semaphore = new SemaphoreSlim(1);

		protected readonly Subject<VideoBufferingStatus> _whenVideoBufferStatusChanged = new Subject<VideoBufferingStatus>();

		private readonly IVideoService videoService;

		private readonly IVideoQualitySettings qualitySettings;

		private readonly IMainThreadService mainThreadService;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWorkoutSettings workoutSettings;

		private int minHlsRebufferSec;

		private ICombinedAudioVideoPlayer videoPlayer;

		private IDisposable timeChangedMetricSub;

		private IDisposable whenIsBufferingSubscription;

		private double bufferedSecondsRemaining;

		public int MinStartResumeBufferSeconds
		{
			get
			{
				if (!UsingHlsPlaybackType)
				{
					return 60;
				}
				return minHlsRebufferSec;
			}
		}

		protected DateTime CreationTime { get; set; } = DateTime.Now;

		public bool IsBuffering { get; private set; }

		public IObservable<VideoBufferingStatus> WhenVideoBufferStatusChanged => _whenVideoBufferStatusChanged;

		public VideoBufferMonitoringService(IVideoService videoService, IVideoQualitySettings qualitySettings, IMainThreadService mainThreadService, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings)
		{
			this.qualitySettings = qualitySettings;
			this.mainThreadService = mainThreadService;
			this.videoService = videoService;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
			UsingHlsPlaybackType = videoService.GetSelectedPlaybackType() == PlaybackType.Hls;
		}

		public async Task StartVideoBufferMonitoring(SettingsInfo settingsInfo = null)
		{
			if (settingsInfo == null || qualitySettings.LiveSettings == null)
			{
				settingsInfo = qualitySettings?.VodSettings;
			}
			if (settingsInfo != null)
			{
				minHlsRebufferSec = Math.Min(settingsInfo.PlaybackBufferMs, settingsInfo.PlaybackBufferAfterRebufferMs) / 1000;
			}
			else
			{
				minHlsRebufferSec = 12;
			}
			try
			{
				StopVideoBufferMonitoring();
				await semaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				videoPlayer = videoService?.PreBufferedVideoPlayer;
				if (videoPlayer != null)
				{
					CreationTime = DateTime.Now;
					timeChangedMetricSub?.Dispose();
					timeChangedMetricSub = Observable.Interval(TimeSpan.FromSeconds(1.0)).SubscribeAsync(CheckVideoBuffer);
					whenIsBufferingSubscription?.Dispose();
					whenIsBufferingSubscription = videoPlayer.WhenIsBufferingChanged.SubscribeAsync((bool _) => ChangeVideoBufferState());
				}
			}
			catch (Exception ex)
			{
				Log.Trace("Video", ex.Message);
			}
			finally
			{
				semaphore.Release();
			}
		}

		public void StopVideoBufferMonitoring()
		{
			timeChangedMetricSub?.Dispose();
			timeChangedMetricSub = null;
			whenIsBufferingSubscription?.Dispose();
			whenIsBufferingSubscription = null;
		}

		public async Task CheckVideoBuffer(long seconds)
		{
			IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
			Workout workout = workoutContainer?.Workout;
			bool valueOrDefault = workoutContainer?.Workout?.IsVideoWorkout() == true;
			bool valueOrDefault2 = currentConsoleService.ActiveConsole?.LatestBasicInfo?.IsInState(ConsoleState.WarmUp, ConsoleState.Workout, ConsoleState.Paused, ConsoleState.PauseOverride) == true;
			if (workoutContainer == null || workout == null || videoPlayer == null || !valueOrDefault || !valueOrDefault2)
			{
				if (seconds >= 10)
				{
					Dispose();
				}
			}
			else if (videoPlayer.VideoFailedToLoad)
			{
				VideoBufferingStatus value = new VideoBufferingStatus
				{
					VideoFailedToLoad = true
				};
				_whenVideoBufferStatusChanged.OnNext(value);
			}
			else
			{
				await ChangeVideoBufferState();
			}
		}

		private async Task ChangeVideoBufferState()
		{
			var (num, num2, flag, allowSkip) = await mainThreadService.InvokeOnMainThreadAsync(timeoutTime, delegate
			{
				bufferedSecondsRemaining = videoPlayer?.BufferSecondsRemaining ?? 0.0;
				double item = Math.Round(bufferedSecondsRemaining, 2);
				double item2 = Math.Round(videoPlayer?.VideoPositionSeconds ?? 0.0, 2);
				bool? item3 = videoPlayer?.IsBuffering;
				bool item4 = AllowSkip();
				return (secondsRounded: item, position: item2, isBuffering: item3, skip: item4);
			});
			Log.Trace("Video", $"Buffered seconds: {num} Current Position: {num2}");
			int bufferPercentage = PercentBufferFilled(num);
			string bufferText = (UsingHlsPlaybackType ? string.Empty : Wolf.Core.Resources.AppStrings.buffering_video_workout.ToUpper());
			bool badConnection = CheckBadConnection(num);
			bool flag2 = false;
			if (flag ?? true)
			{
				flag2 = true;
			}
			if (flag2 != IsBuffering)
			{
				int? num3 = Mvx.Resolve<IWifiService>()?.ActiveNetworkInfo?.Rssi;
				Log.Trace("Video", $"IsBuffering=>{flag2}, BufferSecRemaining={bufferedSecondsRemaining}, Wifi RSSI={num3} dBm");
				IsBuffering = flag2;
			}
			VideoBufferingStatus value = new VideoBufferingStatus
			{
				VideoFailedToLoad = false,
				AllowSkip = allowSkip,
				BadConnection = badConnection,
				BufferPercentage = bufferPercentage,
				BufferText = bufferText,
				BufferedSeconds = (int)num,
				IsBuffering = flag2,
				CurrentPosition = num2
			};
			_whenVideoBufferStatusChanged.OnNext(value);
		}

		public double CheckBufferPercentage()
		{
			return PercentBufferFilled(bufferedSecondsRemaining);
		}

		private int PercentBufferFilled(double bufferedSeconds)
		{
			int val = (int)(bufferedSeconds * 100.0 / (double)MinStartResumeBufferSeconds);
			return Math.Max(0, Math.Min(val, 100));
		}

		private bool AllowSkip()
		{
			return videoPlayer.IsReadyToPlay();
		}

		public bool CheckBadConnection(double bufferedSeconds)
		{
			bool result = false;
			TimeSpan timeSpan = DateTime.Now - CreationTime;
			if ((UsingHlsPlaybackType ? (timeSpan > TimeSpan.FromSeconds(20.0)) : (timeSpan > TimeSpan.FromSeconds((double)MinStartResumeBufferSeconds * 0.75))) && bufferedSeconds < (double)MinStartResumeBufferSeconds)
			{
				result = true;
			}
			return result;
		}

		public void CleanUp()
		{
			StopVideoBufferMonitoring();
			videoPlayer?.Dispose();
			videoPlayer = null;
		}

		public void Dispose()
		{
			StopVideoBufferMonitoring();
		}
	}
}
namespace Wolf.Core.Hollywood.Services.MediaAnalyticsLog
{
	public interface IMediaAnalyticsLogService
	{
		void Initialize(string playerLogFileName);

		void StartWorkout();

		Task<List<LogFileUploadResult>> UploadLogs(double totalTimeSpendBufferingSec, int videoStutteringCount, bool liveWorkoutKickout = false);

		Task CleanUp();

		void WriteToLog(string methodName, string text = "");
	}
	public class MediaAnalyticsLogService : IMediaAnalyticsLogService
	{
		public const int VideoStutteringThresholdCount = 5;

		private const string NoParams = "(no params)";

		private const string WolfLogTag = "VideoAnalytics";

		private const string WolfRegEx = "[0-9]{4}-[0-9]{2}-[0-9]{2}_logs";

		private const string TimeStampFmt = "MM/dd/yyyy HH:mm:ss.fff";

		public bool enabled;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ILogFileService logFileService;

		private readonly IFileService fileService;

		private string playerLogFileName;

		public MediaAnalyticsLogService(IFeatureFlagManager featureFlagManager, ILogFileService logFileService, IFileService fileService)
		{
			this.featureFlagManager = featureFlagManager;
			this.logFileService = logFileService;
			this.fileService = fileService;
		}

		public void Initialize(string logFileName)
		{
			playerLogFileName = logFileName;
		}

		public void StartWorkout()
		{
			WriteToLog("StartWorkout");
			enabled = featureFlagManager.IsFeatureEnabled(FeatureFlags.VideoBufferLogging);
			Log.Trace("VideoAnalytics", $"Video analytics log, enabled: {enabled}");
		}

		public void WriteToLog(string methodName, string text = "(no params)")
		{
			if (enabled)
			{
				logFileService?.WriteTextToFile(playerLogFileName, "[" + DateTime.Now.ToString("MM/dd/yyyy HH:mm:ss.fff") + "] " + methodName + " -- " + text);
			}
		}

		public async Task<List<LogFileUploadResult>> UploadLogs(double totalTimeSpendBufferingSec, int videoStutteringCount, bool liveWorkoutKickout = false)
		{
			if (!enabled)
			{
				return null;
			}
			List<iFit.Files.IFileInfo> list = fileService?.GetFiles(logFileService.Config.LogDirPath, includeDirectories: false);
			iFit.Files.IFileInfo fileInfo = list?.FirstOrDefault((iFit.Files.IFileInfo f) => playerLogFileName.Equals(f.Name));
			if (fileInfo == null)
			{
				Log.Warn("Video", "Video analytics log enabled, but no file found at " + logFileService.Config.LogDirPath + ". Not submitting.");
				return null;
			}
			int num = featureFlagManager.GetInt(FeatureFlags.VideoStutteringReportingThresholdCount, 5);
			if (!ThresholdReached(totalTimeSpendBufferingSec) && !liveWorkoutKickout && videoStutteringCount < num)
			{
				Log.Trace("Video", "Video analytics log enabled, but threshold is not set (-1) or bufferingTime < threshold. Or video stuttering count is not enough. Not submitting.");
				return null;
			}
			iFit.Files.IFileInfo item = (from w in list?.Where((iFit.Files.IFileInfo w) => Regex.Match(w.Name, "[0-9]{4}-[0-9]{2}-[0-9]{2}_logs").Success)
				orderby w.CreationTime descending
				select w).FirstOrDefault();
			List<LogFileUploadResult> list2 = logFileService.PrepareFilesForS3(new List<iFit.Files.IFileInfo> { item, fileInfo });
			if (list2 == null)
			{
				return null;
			}
			return await logFileService.UploadLogsToS3(list2).ConfigureAwait(continueOnCapturedContext: false);
		}

		protected bool ThresholdReached(double totalTimeSpendBufferingSec)
		{
			int num = featureFlagManager.GetInt(FeatureFlags.VideoBufferThresholdSec, -1);
			Log.Trace("Video", $"Buffering threshold: {num}, Buffering time: {totalTimeSpendBufferingSec}");
			if (num > -1)
			{
				return totalTimeSpendBufferingSec >= (double)num;
			}
			return false;
		}

		public async Task CleanUp()
		{
			iFit.Files.IFileInfo fileInfo = (fileService?.GetFiles(logFileService.Config.LogDirPath, includeDirectories: false))?.FirstOrDefault((iFit.Files.IFileInfo f) => playerLogFileName.Equals(f.Name));
			if (fileInfo == null)
			{
				return;
			}
			try
			{
				await fileInfo.DeleteAsync().ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception)
			{
			}
		}
	}
}
namespace Wolf.Core.Hollywood.ClosedCaptions
{
	public class ClosedCaptionsMonitoringService : IClosedCaptionsMonitoringService, IDisposable
	{
		private readonly IVideoService videoService;

		private ICombinedAudioVideoPlayer player;

		private IDisposable playbackCompletedSub;

		private IDisposable newCaptionStringSub;

		private IDisposable videoReadySub;

		private IDisposable languageChangedSub;

		public ClosedCaptionLanguage CurrentMonitoredLanguage { get; private set; }

		public event EventHandler<ClosedCaptionLanguage> LanguageChanged;

		public event EventHandler<string> ClosedCaptionReceived;

		public ClosedCaptionsMonitoringService(IVideoService videoService)
		{
			this.videoService = videoService;
			player = videoService.PreBufferedVideoPlayer;
		}

		public void StartMonitoringCaptions()
		{
			if (player != null)
			{
				StartMonitoringCaptions_VideoReady(player);
				return;
			}
			Log.Trace("ClosedCaptions", "StartMonitoringCaptions: PreBufferedVideoPlayer is null, subscribing to VideoReady event");
			videoReadySub = videoService.VideoReady.Subscribe(StartMonitoringCaptions_VideoReady);
		}

		private void StartMonitoringCaptions_VideoReady(ICombinedAudioVideoPlayer newVideoPlayer)
		{
			player = newVideoPlayer;
			Log.Trace("ClosedCaptions", "StartMonitoringCaptions_VideoReady");
			if (newCaptionStringSub != null || playbackCompletedSub != null)
			{
				StopMonitoringCaptions();
			}
			newCaptionStringSub = player.WeakSubscribe<ICombinedAudioVideoPlayer, string>("OnNewCaptionString", OnClosedCaptionReceived);
			CurrentMonitoredLanguage = player.SelectedClosedCaptionsLanguage;
			languageChangedSub = player.WeakSubscribe<ICombinedAudioVideoPlayer, ClosedCaptionLanguage>("OnClosedCaptionsLanguageChanged", OnClosedCaptionsLanguageChanged);
			playbackCompletedSub = player.VideoPlaybackCompleted.Subscribe(delegate
			{
				Log.Trace("ClosedCaptions", "ClosedCaptionsMonitoringService playback completed");
				StopMonitoringCaptions();
			});
		}

		private void OnClosedCaptionsLanguageChanged(object sender, ClosedCaptionLanguage language)
		{
			CurrentMonitoredLanguage = language;
			this.LanguageChanged?.Invoke(this, language);
		}

		private void OnClosedCaptionReceived(object sender, string caption)
		{
			this.ClosedCaptionReceived?.Invoke(this, caption);
		}

		public void StopMonitoringCaptions()
		{
			Log.Trace("ClosedCaptions", "StopMonitoringCaptions");
			languageChangedSub?.Dispose();
			languageChangedSub = null;
			newCaptionStringSub?.Dispose();
			newCaptionStringSub = null;
			playbackCompletedSub?.Dispose();
			playbackCompletedSub = null;
			videoReadySub?.Dispose();
			videoReadySub = null;
		}

		public void Dispose()
		{
			StopMonitoringCaptions();
		}
	}
	public class ClosedCaptionsSettings : PersistentSettings, IClosedCaptionsSettings, IClosedCaptionsPreferredLanguage
	{
		private const string closedCaptionsSettingsCacheKey = "closedcaptions-settings";

		private const string Tag = "ClosedCaptionsSettings";

		private Subject<bool> isClosedCaptionsOnSubject;

		private IIfitApiService ifitApiService;

		private IFeatureFlagManager featureFlagManager;

		private ILocalSettings localSettings;

		private IChangeLanguageService changeLanguageService;

		private ISystemAccessibilityOptions systemAccessibilityOptions;

		private IDisposable appStateChangedSubscription;

		private IDisposable onBoardingLanguageConfirmedSubscription;

		private IConnectivity connectivityService;

		private readonly Lazy<IList<ClosedCaptionLanguage>> lazyClosedCaptionsLanguages;

		protected ClosedCaptionLanguage memoryCachedPreferredLanguage;

		protected ClosedCaptionLanguage userSettingsCachedPreferredLanguage;

		protected Lazy<ClosedCaptionLanguage> deviceCachedPreferredLanguage;

		protected ClosedCaptionLanguage onboardingSelectedLanguage;

		private bool _isClosedCaptionsOn;

		private bool? _storedIsClosedCaptionsOn;

		protected override string Key => "closedcaptions-settings";

		[JsonIgnore]
		public IObservable<bool> IsClosedCaptionsOnObservable => isClosedCaptionsOnSubject;

		[JsonIgnore]
		public bool IsClosedCaptionsOn
		{
			get
			{
				return _isClosedCaptionsOn;
			}
			protected set
			{
				_isClosedCaptionsOn = value;
			}
		}

		public bool? StoredIsClosedCaptionsOn
		{
			get
			{
				return _storedIsClosedCaptionsOn;
			}
			set
			{
				if (_storedIsClosedCaptionsOn != value)
				{
					_storedIsClosedCaptionsOn = value;
					Flush();
					TrySetAndRaiseCloseCaptionsOnChanged();
				}
			}
		}

		[Obsolete("Use async methods GetPreferredLanguage and SavePreferredLanguage")]
		public ClosedCaptionLanguage PreferredLanguage
		{
			get
			{
				if (ifitApiService.HasLoggedInUser && connectivityService.IsConnected)
				{
					if (userSettingsCachedPreferredLanguage != null)
					{
						return userSettingsCachedPreferredLanguage;
					}
					Log.Error("Workout", "UserSettingsCachedPreferredLanguage was not populated. This should not happen.");
				}
				return onboardingSelectedLanguage ?? GetDeviceLanguage();
			}
			set
			{
				SavePreferredLanguage(value).SafeFireAndForget();
			}
		}

		[JsonIgnore]
		public virtual IList<ClosedCaptionLanguage> ClosedCaptionsLanguages => lazyClosedCaptionsLanguages?.Value;

		public ClosedCaptionsSettings(ISystemAccessibilityOptions systemAccessibilityOptions, IFeatureFlagManager featureFlagManager, IAppLifecycleService appLifecycleService, IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager, ILocalSettings localSettings, IChangeLanguageService changeLanguageService, IIfitApiService ifitApiService, IConnectivity connectivityService)
			: base(blobCacheService, blobCacheFileManager)
		{
			lazyClosedCaptionsLanguages = new Lazy<IList<ClosedCaptionLanguage>>(GetClosedCaptionsLanguages);
			SetupClosedCaptionsSettings(systemAccessibilityOptions, featureFlagManager, appLifecycleService, localSettings, changeLanguageService, ifitApiService, connectivityService);
		}

		private ClosedCaptionLanguage GetDeviceLanguage()
		{
			ClosedCaptionLanguage value = memoryCachedPreferredLanguage;
			if (value == null)
			{
				Lazy<ClosedCaptionLanguage> lazy = deviceCachedPreferredLanguage;
				if (lazy == null)
				{
					return null;
				}
				value = lazy.Value;
			}
			return value;
		}

		public static async Task<IClosedCaptionsSettings> LoadClosedCaptionsSettings(ISystemAccessibilityOptions systemAccessibilityOptions, IFeatureFlagManager featureFlagManager, IAppLifecycleService appLifecycleService, IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager, IChangeLanguageService changeLanguageService, ILocalSettings localSettings, IIfitApiService ifitApiService, IConnectivity connectivityService)
		{
			ClosedCaptionsSettings settings = null;
			try
			{
				settings = await blobCacheService.Secure.GetObject<ClosedCaptionsSettings>("closedcaptions-settings").FirstAsync().ToTask()
					.ConfigureAwait(continueOnCapturedContext: false);
				settings.SetupCachedClosedCaptionsSettings(systemAccessibilityOptions, featureFlagManager, appLifecycleService, blobCacheService, blobCacheFileManager, localSettings, changeLanguageService, ifitApiService, connectivityService);
			}
			catch (Exception)
			{
				settings = new ClosedCaptionsSettings(systemAccessibilityOptions, featureFlagManager, appLifecycleService, blobCacheService, blobCacheFileManager, localSettings, changeLanguageService, ifitApiService, connectivityService);
			}
			finally
			{
				if (settings != null)
				{
					settings.deviceCachedPreferredLanguage = new Lazy<ClosedCaptionLanguage>(settings.InitAndReturnPreferredLanguage);
				}
			}
			return settings;
		}

		public async Task ToggleClosedCaptions()
		{
			Log.Trace("Workout", "ToggleClosedCaptions called.");
			if (!ifitApiService.HasLoggedInUser)
			{
				StoredIsClosedCaptionsOn = !IsClosedCaptionsOn;
				return;
			}
			try
			{
				User user = ifitApiService.CurrentlyAuthenticatedUser;
				UserSettings settings = await user.GetSettings(ifitApiService);
				settings.WorkoutCaptionsEnabled = !IsClosedCaptionsOn;
				await user.UpdateSettings(ifitApiService);
				IsClosedCaptionsOn = settings.WorkoutCaptionsEnabled == true;
				isClosedCaptionsOnSubject.OnNext(IsClosedCaptionsOn);
			}
			catch (Exception ex)
			{
				Log.Trace("ClosedCaptionsSettings", ex.Message);
				IsClosedCaptionsOn = !IsClosedCaptionsOn;
				isClosedCaptionsOnSubject.OnNext(IsClosedCaptionsOn);
			}
		}

		public async Task<ClosedCaptionLanguage> GetPreferredLanguage()
		{
			Log.Trace("Workout", "GetPreferredLanguage called.");
			if (!ifitApiService.HasLoggedInUser || !connectivityService.IsConnected)
			{
				return GetDeviceLanguage();
			}
			User user = ifitApiService.CurrentlyAuthenticatedUser;
			if (user == null)
			{
				throw new iFit.Api.Support.ConnectivityException("CurrentlyAuthenticatedUser returned null.");
			}
			UserSettings settings = await user.GetSettings(ifitApiService);
			if (settings == null)
			{
				throw new iFit.Api.Support.ConnectivityException("User.GetSettings returned null.");
			}
			if (onboardingSelectedLanguage != null)
			{
				settings.WorkoutCaptionLanguage = GetLanguageCodeForUserSettings(onboardingSelectedLanguage.LanguageCode);
				onboardingSelectedLanguage = null;
				await user.UpdateSettings(ifitApiService);
				Log.Trace("Workout", "Language from onboarding is used for CC.");
			}
			else if (string.IsNullOrWhiteSpace(settings.WorkoutCaptionLanguage))
			{
				settings.WorkoutCaptionLanguage = GetLanguageCodeForUserSettings(GetDeviceLanguage().LanguageCode);
				await user.UpdateSettings(ifitApiService);
				Log.Trace("Workout", "Device or cached language is used for CC.");
			}
			return userSettingsCachedPreferredLanguage = GetClosedCaptionLanguageFromThreeLetterIsoLanguageName(GetLanguageCodeForCloseCaption(settings.WorkoutCaptionLanguage));
		}

		public async Task<bool> GetIsClosedCaptionsOn()
		{
			Log.Trace("Workout", "GetIsClosedCaptionsOn called.");
			if (!ifitApiService.HasLoggedInUser)
			{
				return IsClosedCaptionsOn;
			}
			User user = ifitApiService.CurrentlyAuthenticatedUser;
			UserSettings settings = await user.GetSettings(ifitApiService);
			if (settings == null)
			{
				throw new iFit.Api.Support.ConnectivityException("User.GetSettings returned null.");
			}
			if (!settings.WorkoutCaptionsEnabled.HasValue)
			{
				settings.WorkoutCaptionsEnabled = IsClosedCaptionsOn;
				await user.UpdateSettings(ifitApiService);
			}
			IsClosedCaptionsOn = settings.WorkoutCaptionsEnabled == true;
			return settings.WorkoutCaptionsEnabled.Value;
		}

		public virtual async Task SavePreferredLanguage(ClosedCaptionLanguage language)
		{
			Log.Trace("Workout", "SavePreferredLanguage called.");
			if (memoryCachedPreferredLanguage != language)
			{
				memoryCachedPreferredLanguage = language;
				FlushAsync();
			}
			if (userSettingsCachedPreferredLanguage == language || !ifitApiService.HasLoggedInUser || !connectivityService.IsConnected)
			{
				return;
			}
			UserSettings settings = null;
			string previousWorkoutCaptionLanguage = null;
			try
			{
				User user = ifitApiService.CurrentlyAuthenticatedUser;
				settings = await user.GetSettings(ifitApiService);
				previousWorkoutCaptionLanguage = settings.WorkoutCaptionLanguage;
				settings.WorkoutCaptionLanguage = GetLanguageCodeForUserSettings(language.LanguageCode);
				await user.UpdateSettings(ifitApiService);
				userSettingsCachedPreferredLanguage = language;
			}
			catch (Exception exception)
			{
				if (settings != null && previousWorkoutCaptionLanguage != null)
				{
					settings.WorkoutCaptionLanguage = previousWorkoutCaptionLanguage;
				}
				Log.Error("ClosedCaptionsSettings", "Unable to save language choice to user", exception);
			}
		}

		public async Task SavePreferredLanguage(Language language)
		{
			Log.Trace("Workout", "Short SavePreferredLanguage called.");
			ClosedCaptionLanguage closedCaptionLanguageFromLanguage = GetClosedCaptionLanguageFromLanguage(language);
			if (closedCaptionLanguageFromLanguage != null)
			{
				await SavePreferredLanguage(closedCaptionLanguageFromLanguage);
			}
		}

		private IList<ClosedCaptionLanguage> GetClosedCaptionsLanguages()
		{
			return featureFlagManager?.GetObject<List<ClosedCaptionLanguage>>(FeatureFlags.ClosedCaptioningLanguages);
		}

		private void SetupCachedClosedCaptionsSettings(ISystemAccessibilityOptions systemAccessibilityOptions, IFeatureFlagManager featureFlagManager, IAppLifecycleService appLifecycleService, IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager, ILocalSettings localSettings, IChangeLanguageService changeLanguageService, IIfitApiService ifitApiService, IConnectivity connectivityService)
		{
			BlobCacheService = blobCacheService;
			BlobCacheFileManager = blobCacheFileManager;
			SetupClosedCaptionsSettings(systemAccessibilityOptions, featureFlagManager, appLifecycleService, localSettings, changeLanguageService, ifitApiService, connectivityService);
		}

		private void SetupClosedCaptionsSettings(ISystemAccessibilityOptions systemAccessibilityOptions, IFeatureFlagManager featureFlagManager, IAppLifecycleService appLifecycleService, ILocalSettings localSettings, IChangeLanguageService changeLanguageService, IIfitApiService ifitApiService, IConnectivity connectivityService)
		{
			this.systemAccessibilityOptions = systemAccessibilityOptions;
			this.featureFlagManager = featureFlagManager;
			this.localSettings = localSettings;
			this.changeLanguageService = changeLanguageService;
			this.ifitApiService = ifitApiService;
			this.connectivityService = connectivityService;
			isClosedCaptionsOnSubject = new Subject<bool>();
			appStateChangedSubscription = appLifecycleService?.WeakSubscribe<IAppLifecycleService, AppStateEventArgs>("AppStateChanged", OnAppStateChanged);
			SubscribeToLanguageChangeInOnBoarding();
			TrySetAndRaiseCloseCaptionsOnChanged();
		}

		private ClosedCaptionLanguage InitAndReturnPreferredLanguage()
		{
			if (memoryCachedPreferredLanguage == null)
			{
				string threeLetterIsoLanguageName = ((localSettings.CurrentLanguage == Language.SystemDefault) ? changeLanguageService.SystemPreferredCulture.ThreeLetterISOLanguageName : CultureInfo.CurrentCulture.ThreeLetterISOLanguageName);
				memoryCachedPreferredLanguage = GetClosedCaptionLanguageFromThreeLetterIsoLanguageName(threeLetterIsoLanguageName);
				Flush();
			}
			return memoryCachedPreferredLanguage;
		}

		private void SubscribeToLanguageChangeInOnBoarding()
		{
			onBoardingLanguageConfirmedSubscription = changeLanguageService?.WhenLanguageConfirmedInOnBoarding.SubscribeAsyncWithErrorLogging(async delegate(CultureInfo cultureInfo)
			{
				onboardingSelectedLanguage = GetClosedCaptionLanguageFromThreeLetterIsoLanguageName(cultureInfo.ThreeLetterISOLanguageName);
				await SavePreferredLanguage(onboardingSelectedLanguage);
				if (PreferredLanguage != null)
				{
					onBoardingLanguageConfirmedSubscription.Dispose();
					onBoardingLanguageConfirmedSubscription = null;
				}
			});
		}

		private void OnAppStateChanged(object sender, AppStateEventArgs appStateEventArgs)
		{
			if (appStateEventArgs.CurrentState == AppLifecycleService.AppState.Foreground)
			{
				TrySetAndRaiseCloseCaptionsOnChanged();
			}
		}

		private void TrySetAndRaiseCloseCaptionsOnChanged()
		{
			if (ifitApiService.HasLoggedInUser)
			{
				return;
			}
			if (StoredIsClosedCaptionsOn.HasValue)
			{
				if (IsClosedCaptionsOn == StoredIsClosedCaptionsOn.Value)
				{
					return;
				}
				IsClosedCaptionsOn = StoredIsClosedCaptionsOn.Value;
			}
			else
			{
				if (systemAccessibilityOptions == null || IsClosedCaptionsOn == systemAccessibilityOptions.IsClosedCaptionsOn)
				{
					return;
				}
				IsClosedCaptionsOn = systemAccessibilityOptions.IsClosedCaptionsOn;
			}
			isClosedCaptionsOnSubject.OnNext(IsClosedCaptionsOn);
		}

		private ClosedCaptionLanguage GetClosedCaptionLanguageFromThreeLetterIsoLanguageName(string threeLetterIsoLanguageName)
		{
			ClosedCaptionLanguage closedCaptionLanguage = ClosedCaptionsLanguages?.FirstOrDefault((ClosedCaptionLanguage l) => l.LanguageCode == threeLetterIsoLanguageName);
			return closedCaptionLanguage ?? ClosedCaptionsLanguages?.FirstOrDefault();
		}

		private ClosedCaptionLanguage GetClosedCaptionLanguageFromLanguage(Language language)
		{
			string twoLetterISOCode = changeLanguageService.GetTwoLetterISOCode(language);
			string languageCodeForCloseCaption = GetLanguageCodeForCloseCaption(twoLetterISOCode);
			ClosedCaptionLanguage closedCaptionLanguageFromThreeLetterIsoLanguageName = GetClosedCaptionLanguageFromThreeLetterIsoLanguageName(languageCodeForCloseCaption);
			if (languageCodeForCloseCaption == closedCaptionLanguageFromThreeLetterIsoLanguageName?.LanguageCode)
			{
				return closedCaptionLanguageFromThreeLetterIsoLanguageName;
			}
			return null;
		}

		private string ConvertThreeLetterNameToTwoLetterName(string name)
		{
			CultureInfo[] cultures = CultureInfo.GetCultures(CultureTypes.SpecificCultures);
			CultureInfo[] array = cultures;
			foreach (CultureInfo cultureInfo in array)
			{
				if (cultureInfo.ThreeLetterISOLanguageName == name)
				{
					return cultureInfo.TwoLetterISOLanguageName;
				}
			}
			return null;
		}

		private string GetLanguageCodeForUserSettings(string code)
		{
			if (code.Length == 2)
			{
				return code;
			}
			return ConvertThreeLetterNameToTwoLetterName(code);
		}

		private string GetLanguageCodeForCloseCaption(string code)
		{
			if (code.Length == 3)
			{
				return code;
			}
			CultureInfo cultureInfo = new CultureInfo(code);
			return cultureInfo.ThreeLetterISOLanguageName;
		}
	}
	public interface IClosedCaptionsMonitoringService : IDisposable
	{
		ClosedCaptionLanguage CurrentMonitoredLanguage { get; }

		event EventHandler<ClosedCaptionLanguage> LanguageChanged;

		event EventHandler<string> ClosedCaptionReceived;

		void StartMonitoringCaptions();

		void StopMonitoringCaptions();
	}
	public interface IClosedCaptionsSettings : IClosedCaptionsPreferredLanguage
	{
		IObservable<bool> IsClosedCaptionsOnObservable { get; }

		IList<ClosedCaptionLanguage> ClosedCaptionsLanguages { get; }

		Task ToggleClosedCaptions();

		Task<ClosedCaptionLanguage> GetPreferredLanguage();

		Task SavePreferredLanguage(ClosedCaptionLanguage language);

		Task SavePreferredLanguage(Language language);

		Task<bool> GetIsClosedCaptionsOn();
	}
}
