		public static Task LiveWorkoutDisconnected(this IWolfAnalytics analytics, Dictionary<string, object> infoProperties, MediaAnalyticsData extraAnalyticsData = null)
		{
			if (extraAnalyticsData != null && !extraAnalyticsData.Equals(MediaAnalyticsData.Empty))
			{
				infoProperties.Add("videoBufferingAboveThreshold", !string.IsNullOrWhiteSpace(extraAnalyticsData?.VideoPlayerLogUrl ?? string.Empty));
				infoProperties.Add("exoPlayerLogUrl", extraAnalyticsData.VideoPlayerLogUrl);
				infoProperties.Add("wolfLogUrl", extraAnalyticsData.WolfLogUrl);
				if (extraAnalyticsData.Data != null)
				{
					foreach (KeyValuePair<string, object> datum in extraAnalyticsData.Data)
					{
						infoProperties.Add(datum.Key, datum.Value);
					}
				}
			}
			return analytics.PostEvent("Live Workout Disconnected", infoProperties);
		}

