		public static async Task VideoSpeedTestSuccess(this IWolfAnalytics analytics, double speedMbps, VideoQuality videoQuality)
		{
			if (Mvx.TryResolve<IFeatureFlagManager>(out var service) && service.IsFeatureEnabled(FeatureFlags.VideoSpeedTestResults))
			{
				Dictionary<string, object> properties = new Dictionary<string, object>
				{
					{ "speedMbps", speedMbps },
					{
						"videoQuality",
						videoQuality.ToString()
					}
				};
				await analytics.TrackWithGoogleAnalytics("Video_Speed_Test_Results", properties, throwIfInvalid: true);
				await analytics.PostEvent("Video Speed Test Results", properties);
			}
		}

