		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>
			{
				{ "workoutId", workoutId },
				{ "connectivityStatus", status }
			};
			if (latestResolution != null)
			{
				dictionary.Add("latestResolution", latestResolution);
			}
			AddUrlInfo(dictionary, idOrUrl, scheduleId);
			return analytics.PostEvent("Video Stalled", dictionary);
		}

