		public static async Task ReportStallEvent(this IWolfAnalytics analytics, string latestResolution = null)
		{
			if (Mvx.TryResolve<IWorkoutSettings>(out var workoutSettings))
			{
				ConnectivityStatus status = Shire.Core.Source.Services.ConnectivityService.ConnectivityStatus.Unknown;
				if (Mvx.TryResolve<IConnectivityService>(out var service))
				{
					status = await service.Status.ConfigureAwait(continueOnCapturedContext: false);
				}
				Workout workout = workoutSettings?.WorkoutContainer?.Workout;
				string idOrUrl = (((workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.Context).GetValueOrDefault() != Workout.WorkoutContext.OnDemand) ? workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.LiveStreamUrl : workoutSettings?.WorkoutContainer?.Media?.WorkoutVideo?.Sources?.HlsSource?.SourceUrl);
				string scheduleId = workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.Id;
				await analytics.VideoStalled(idOrUrl, workout?.Id, status, scheduleId, latestResolution);
			}
		}

		private static void AddUrlInfo(Dictionary<string, object> properties, string idOrUrl, string scheduleId)
		{
			if (scheduleId == null)
			{
				properties.Add("videoUrl", idOrUrl);
				return;
			}
			properties.Add("streamUrl", idOrUrl);
			properties.Add("liveScheduleId", scheduleId);
		}
	}
	public class MediaAnalyticsSyncDataObject
	{
		private TimeSpan? _totalTimeSpentBuffering;

