		public int AudioDroppedBufferCount { get; private set; }

		public int AudioMaxConsecutiveDroppedBufferCount { get; private set; }

		public int VideoStutteringCount => VideoStutteredPeriodTransitionCount + VideoStutteredSeekCount + VideoStutteredSeekAdjustmentCount + VideoStutteredAdInsertionCount + VideoStutteredInternalCount + VideoStutteredUnknownCount;

		public int VideoStutteredPeriodTransitionCount { get; private set; }

		public int VideoStutteredSeekCount { get; private set; }

		public int VideoStutteredSeekAdjustmentCount { get; private set; }

		public int VideoStutteredAdInsertionCount { get; private set; }

		public int VideoStutteredInternalCount { get; private set; }

		public int VideoStutteredUnknownCount { get; private set; }

		public DateTime BufferingEventStarted { get; set; }

		public double SumWifiConnectionStrengths { get; set; }

		public int TotalBufferAttempts { get; set; }

		public string VideoQuality { get; private set; }

		public string PlaybackType { get; private set; }

		public TimeSpan TotalTimeSpentBuffering
		{
			get
			{
				return _totalTimeSpentBuffering.GetValueOrDefault();
			}
			set
			{
				if (!_totalTimeSpentBuffering.HasValue)
				{
					TimeSpentOnInitialBuffering = value;
				}
				_totalTimeSpentBuffering = value;
			}
		}

		public TimeSpan TimeSpentOnInitialBuffering { get; private set; }

		public bool BadConnectWarningDisplayed { get; set; }

		public int WifiDisconnects { get; set; }

		public int CaptionsAreInTroubleCount { get; set; }

		public int CaptionsAreMalformedCount { get; set; }

		public double AvgWifiStrength => SumWifiConnectionStrengths / (double)TotalBufferAttempts;

		public void UpdateMediaProperties(ICombinedAudioVideoPlayer videoPlayer)
		{
			if (videoPlayer == null || !Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				return;
			}
			service.RequestMainThreadAction(delegate
			{
				try
				{
					VideoQuality = videoPlayer.SelectedVideoQuality.ToString();
					PlaybackType = videoPlayer.SelectedPlaybackType.ToString();
					VideoRenderedOutputBufferCount = videoPlayer.VideoRenderedOutputBufferCount;
					VideoSkippedOutputBufferCount = videoPlayer.VideoSkippedOutputBufferCount;
					VideoDroppedBufferCount = videoPlayer.VideoDroppedBufferCount;
					VideoMaxConsecutiveDroppedBufferCount = videoPlayer.VideoMaxConsecutiveDroppedBufferCount;
					AudioRenderedOutputBufferCount = videoPlayer.AudioRenderedOutputBufferCount;
					AudioSkippedOutputBufferCount = videoPlayer.AudioSkippedOutputBufferCount;
					AudioDroppedBufferCount = videoPlayer.AudioDroppedBufferCount;
					AudioMaxConsecutiveDroppedBufferCount = videoPlayer.AudioMaxConsecutiveDroppedBufferCount;
					VideoStutteredPeriodTransitionCount = videoPlayer.VideoStutteredPeriodTransitionCount;
					VideoStutteredSeekCount = videoPlayer.VideoStutteredSeekCount;
					VideoStutteredSeekAdjustmentCount = videoPlayer.VideoStutteredSeekAdjustmentCount;
					VideoStutteredAdInsertionCount = videoPlayer.VideoStutteredAdInsertionCount;
					VideoStutteredInternalCount = videoPlayer.VideoStutteredInternalCount;
					VideoStutteredUnknownCount = videoPlayer.VideoStutteredUnknownCount;
				}
				catch (ObjectDisposedException)
				{
				}
			});
		}
	}
