	public class WolfRayGunCrashReporter : RaygunCrashReporter
	{
		public const string BuiltInTag = "BuiltIn";

		private const string CacheKey = "workout-recovery-info";

		private readonly IDeviceInformation deviceInformation;

		public WolfRayGunCrashReporter(IDeviceInformation deviceInformation, IRaygunClient raygun, IIfitApiService ifitApiService, ILogFileService logFileService, IFileService fileService, ICoreAnalytics analytics, string branchId, string version, bool isDebugMode)
			: base(raygun, ifitApiService, logFileService, fileService, analytics, branchId, version, isDebugMode)
		{
			this.deviceInformation = deviceInformation;
		}

		protected override async Task PrepareErrorReport(IList<string> tags, IDictionary customData)
		{
			Dictionary<string, object> data = new Dictionary<string, object>();
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			if (deviceInformation.IsBuiltIn && !tags.Contains("BuiltIn"))
			{
				tags.Add("BuiltIn");
			}
			if (Mvx.TryResolve<IFeatureFlagManager>(out var service))
			{
				data.Add("EnabledFeatureFlags", GetEnabledFeatureFlags(service));
				data.Add("WebUrls", GetFeatureFlagWebUrls(service));
			}
			else
			{
				data.Add("FeatureFlags", "[Could not get IFeatureFlagManager]");
			}
			data.Add("softwareVersion", deviceInformation.SoftwareNumber.ToString());
			if (Mvx.TryResolve<IBlobCacheService>(out var service2))
			{
				dictionary = await ProcessLastWorkout(service2);
				tags.Add("InWorkout");
			}
			else
			{
				dictionary.Add("IBlobCacheService", "[Could not get IBlobCacheService]");
			}
			data.Add("WorkoutInfo", dictionary);
			customData.Remove("Extra");
			customData.Add("Extra", data);
			await base.PrepareErrorReport(tags, customData);
		}

		private async Task<Dictionary<string, object>> ProcessLastWorkout(IBlobCacheService blobCache)
		{
			Dictionary<string, object> workoutInfo = new Dictionary<string, object>();
			try
			{
				int millisecondsDelay = 2000;
				Task<WorkoutRecoveryInfo> recoveryInfo = GetLastWorkout(blobCache);
				if (await Task.WhenAny(recoveryInfo, Task.Delay(millisecondsDelay)) == recoveryInfo)
				{
					if (recoveryInfo.Result.WorkoutId == null)
					{
						workoutInfo.Add("WorkoutRecovery", "Not Found");
					}
					else
					{
						Dictionary<string, object> dictionary = recoveryInfo.Result.ToDictionary("WorkoutId");
						foreach (KeyValuePair<string, object> item in dictionary)
						{
							workoutInfo.Add(item.Key, item.Value);
						}
					}
				}
				else
				{
					workoutInfo.Add("IBlobCacheService", "Timeout from Blobcache");
				}
			}
			catch (Exception ex)
			{
				workoutInfo.Add("WorkoutRecoveryAttempt", ex.Message);
			}
			return workoutInfo;
		}

		private async Task<WorkoutRecoveryInfo> GetLastWorkout(IBlobCacheService blobCache)
		{
			return await blobCache.Secure.GetObject<WorkoutRecoveryInfo>("workout-recovery-info");
		}

		private string GetEnabledFeatureFlags(IFeatureFlagManager flagManager)
		{
			StringBuilder stringBuilder = new StringBuilder();
			foreach (FeatureFlag allFlag in FeatureFlags.AllFlags)
			{
				if (flagManager.IsFeatureEnabled(allFlag))
				{
					stringBuilder.Append(allFlag.Key);
					stringBuilder.Append(",");
				}
			}
			if (stringBuilder.Length >= 2)
			{
				stringBuilder.Length--;
			}
			return stringBuilder.ToString();
		}

		private Dictionary<string, object> GetFeatureFlagWebUrls(IFeatureFlagManager flagManager)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			foreach (FeatureFlag webviewFlag in FeatureFlags.WebviewFlags)
			{
				string value = flagManager.GetString(webviewFlag);
				if (!string.IsNullOrEmpty(value) && !string.IsNullOrEmpty(webviewFlag.Key))
				{
					dictionary.Add(webviewFlag.Key, value);
				}
			}
			return dictionary;
		}
	}
}
namespace Wolf.Core.DisplayModels
{
	public class WorkoutDisplayModel
	{
		public enum DistanceDisplayType
		{
			Metric,
			English,
			Meters
		}

		public readonly INC<string> Id = new NC<string>();

		public readonly INC<string> Title = new NC<string>();

		public readonly INC<string> Description = new NC<string>();

		public readonly INC<double> Distance = new NC<double>();

		public readonly INC<string> DistanceUnits = new NC<string>();

		public readonly INC<DistanceDisplayType> DistanceType = new NC<DistanceDisplayType>();

		public readonly INC<string> Duration = new NC<string>();

		public readonly INC<double> Elevation = new NC<double>();

		public readonly INC<string> ElevationUnits = new NC<string>();

		public readonly INC<double> Calories = new NC<double>();

		public readonly INC<string> CaloriesUnits = new NC<string>();

		public readonly INC<bool> IsRunWorkout = new NC<bool>();

		public readonly INC<bool> IsDistanceWorkout = new NC<bool>();

		public readonly INC<bool> IsTimeWorkout = new NC<bool>();

		public readonly INC<bool> IsStrengthWorkout = new NC<bool>();

		public Workout Workout { get; private set; }

		public Workout.WorkoutEstimates Estimates { get; }

		public bool IsMetric { get; private set; }

		public bool HasEstimates => Estimates != null;

		public WorkoutDisplayModel(Workout workout, bool isMetric)
		{
			InitializeCommonData(workout, isMetric);
			Estimates = workout.Estimates;
			double value;
			if (workout != null && workout.Type.IsRowWorkout())
			{
				value = UnitUtil.EnsureMeters(DistanceUnit.M, Estimates.Distance, 0);
				DistanceType.Value = DistanceDisplayType.Meters;
			}
			else if (isMetric)
			{
				value = UnitUtil.EnsureKilometers(DistanceUnit.M, Estimates.Distance, 2);
				DistanceType.Value = DistanceDisplayType.Metric;
			}
			else
			{
				value = UnitUtil.EnsureMiles(DistanceUnit.M, Estimates.Distance, 2);
				DistanceType.Value = DistanceDisplayType.English;
			}
			double value2 = (isMetric ? Estimates.GrossElevationGain : UnitUtil.EnsureFeet(DistanceUnit.M, Estimates.GrossElevationGain));
			Distance.Value = value;
			Duration.Value = ValueFormatters.SecondsFormatter.Format(Estimates.Time);
			Elevation.Value = UnitUtil.Round(value2, 0);
			Calories.Value = UnitUtil.Round(Estimates.Calories, 0);
		}

		public WorkoutDisplayModel(Workout workout, ActivityLog log, bool isMetric)
		{
			InitializeCommonData(workout, isMetric);
			double value;
			if (workout != null && workout.Type.IsRowWorkout())
			{
				value = UnitUtil.EnsureMeters(DistanceUnit.M, log.Summary.TotalMeters, 0);
				DistanceType.Value = DistanceDisplayType.Meters;
			}
			else if (isMetric)
			{
				value = UnitUtil.EnsureKilometers(DistanceUnit.M, log.Summary.TotalMeters, 2);
				DistanceType.Value = DistanceDisplayType.Metric;
			}
			else
			{
				value = UnitUtil.EnsureMiles(DistanceUnit.M, log.Summary.TotalMeters, 2);
				DistanceType.Value = DistanceDisplayType.English;
			}
			double value2 = (isMetric ? (log.Summary.TotalElevationGain - log.Summary.TotalElevationLoss) : UnitUtil.EnsureFeet(DistanceUnit.M, log.Summary.TotalElevationGain - log.Summary.TotalElevationLoss));
			Distance.Value = value;
			Duration.Value = ValueFormatters.SecondsFormatter.Format(log.Duration / 1000);
			Elevation.Value = UnitUtil.Round(value2, 0);
			Calories.Value = UnitUtil.Round(log.Summary.TotalCalories, 0);
			if (workout == null)
			{
				string value3 = log?.Title;
				if (!string.IsNullOrEmpty(value3))
				{
					Title.Value = value3;
				}
			}
		}

		public WorkoutDisplayModel(double CalorieCount, double Meters, double Seconds, bool isMetric)
		{
			InitializeCommonData(null, isMetric);
			double value = ((!isMetric) ? UnitUtil.EnsureMiles(DistanceUnit.M, Meters, 2) : UnitUtil.EnsureKilometers(DistanceUnit.M, Meters, 2));
			Distance.Value = value;
			Duration.Value = ValueFormatters.SecondsFormatter.Format(Seconds);
			Elevation.Value = 0.0;
			Calories.Value = UnitUtil.Round(CalorieCount, 0);
		}

		private void InitializeCommonData(Workout workout, bool isMetric)
		{
			Workout = workout;
			IsMetric = isMetric;
			Id.Value = workout?.Id;
			if (workout != null)
			{
				Title.Value = workout?.Title ?? string.Empty;
				if (workout.IsStrengthWorkout())
				{
					Description.Value = Wolf.Core.Resources.AppStrings.workout_type_strength;
				}
				else
				{
					switch (workout.Target)
					{
					case Workout.TargetType.Meters:
						Description.Value = Wolf.Core.Resources.AppStrings.workout_type_distance;
						break;
					case Workout.TargetType.Seconds:
						Description.Value = Wolf.Core.Resources.AppStrings.workout_type_time;
						break;
					case Workout.TargetType.Calories:
						Description.Value = Wolf.Core.Resources.AppStrings.workout_type_calorie;
						break;
					}
				}
				if ((workout.Geo?.Path?.LatLngs?.Count).GetValueOrDefault() > 0)
				{
					Description.Value = Wolf.Core.Resources.AppStrings.workout_type_streetview;
				}
				IsRunWorkout.Value = workout.Type == Workout.WorkoutType.Run;
				IsDistanceWorkout.Value = workout.Target == Workout.TargetType.Meters;
				IsTimeWorkout.Value = workout.Target == Workout.TargetType.Seconds;
				IsStrengthWorkout.Value = workout?.IsStrengthWorkout() ?? false;
			}
			else
			{
				Title.Value = Shire.Core.Resources.AppStrings.manual_workout_title;
				IsRunWorkout.Value = true;
			}
			if (workout != null && workout.Type.IsRowWorkout())
			{
				DistanceUnits.Value = Wolf.Core.Resources.AppStrings.m;
			}
			else if (isMetric)
			{
				DistanceUnits.Value = Wolf.Core.Resources.AppStrings.queue_item_kilometers;
			}
			else
			{
				DistanceUnits.Value = Wolf.Core.Resources.AppStrings.queue_item_miles;
			}
			CaloriesUnits.Value = Wolf.Core.Resources.AppStrings.queue_item_calories;
			string arg = (isMetric ? Wolf.Core.Resources.AppStrings.m : Wolf.Core.Resources.AppStrings.ft);
			ElevationUnits.Value = $" {arg}";
		}

		public void Dispose()
		{
			Workout?.Dispose();
		}
	}
}
