			UpdateAssetPaths();
		}

		protected bool UpdateBindableAssetListWithAssetPath(string assetFileName, INCList<string> ncList, IReadOnlyDictionary<string, FileDownloadReport> assets = null)
		{
			if (base.DemoMode1Service.DoesRequireDownloadingContent && assets != null)
			{
				if (assets == null || !assets.ContainsKey(assetFileName))
				{
					Log.Error(base.LogTag, "Error getting image asset file paths for: " + assetFileName + ". Assets did not contain the key.");
					_whenMarketingAssetPathLookupFailed?.OnNext(assetFileName);
					return false;
				}
				FileDownloadReport fileDownloadReport = assets[assetFileName];
				if (fileDownloadReport == null)
				{
					Log.Error(base.LogTag, "Error getting image asset file paths for: " + assetFileName + ". Asset file report was null.");
					_whenMarketingAssetPathLookupFailed?.OnNext(assetFileName);
					return false;
				}
				if (!fileDownloadReport.DownloadedSuccessfully || fileDownloadReport.DownloadedBytes != fileDownloadReport.ResourceBytes)
				{
					Log.Error(base.LogTag, "Asset " + assetFileName + " not intact:");
					Log.Error(base.LogTag, JsonConvert.SerializeObject(fileDownloadReport, Formatting.Indented));
					_whenMarketingAssetPathLookupFailed?.OnNext(assetFileName);
					return false;
				}
			}
			string text = Path.Combine(base.DemoMode1Service.AssetFolderPath, assetFileName);
			if (base.DemoMode1Service.DoesAssetExist(text))
			{
				Log.Trace(base.LogTag, "Demo Mode asset " + assetFileName + " found and intact: " + text);
				ncList.Value.Add(text);
				return true;
			}
			Log.Error(base.LogTag, "Demo Mode asset " + assetFileName + " not found at expected location: " + text);
			return false;
		}

		private void DoGoToVideoPage()
		{
			if (!isNavigatingAway && !isDisposed)
			{
				isNavigatingAway = true;
				Log.Trace(base.LogTag, "Navigating to Demo Mode marketing video page.");
				NavigateToAppropriateVideoVM();
			}
		}

