	public abstract class DemoModeVideoViewModel : DemoModeViewModelBase
	{
		public interface IDelegate
		{
			Task<bool> ScreenTouched();

			void ScreensaverVolumeChanged(float volume);
		}

		public class NavObject
		{
			public string VideoFilePath { get; set; }

			public bool HideSkipButton { get; set; }

			public bool HideVolumeButton { get; set; }

			public bool LoopVideo { get; set; }

			public float InitialVolume { get; set; } = 0f / 0f;
		}

		private const int VolumeTimeoutMs = 3000;

		private IDisposable videoPlaybackCompletedSub;

		private IDisposable volumeMetricSub;

		private readonly IMainThreadSchedulerService schedulerService;

		private readonly IPlatformMediaVolumeService platformMediaVolumeService;

		protected readonly IMediaSettings mediaSettings;

		protected readonly IVolumeFacade volumeFacade;

		private bool isNavigatingAway;

		private bool videoHasStarted;

		private string videoFilePath;

		private bool loopVideo;

		private float initialVolume;

		private bool shouldHandleScreenTouches = true;

		private Subject<object> _whenMarketingVideoAssetLookupFailed = new Subject<object>();

		public readonly INC<string> VideoFilePath = new NC<string>();

		public readonly INC<bool> ShowLoading = new NC<bool>(value: true);

		public readonly INC<float> VideoVolume = new NC<float>(0f);

		public readonly INC<bool> ShowVolumeBar = new NC<bool>();

		public readonly INC<bool> ShowCaptionControls = new NC<bool>();

		public readonly INC<bool> ShowSkipButton = new NC<bool>();

		public readonly INC<bool> ShowVolumeButton = new NC<bool>();

		private IDisposable dismissTimerSub;

		private IDisposable videoPlaybackChangedSub;

		private IDisposable videoErrorSub;

		private int? ignoreInitialVolume;

		public ICombinedAudioVideoPlayer VideoPlayer { get; private set; }

		protected virtual int VideoStartDelayMs => 1000;

		public IObservable<object> WhenMarketingVideoAssetLookupFailed => _whenMarketingVideoAssetLookupFailed;

		private float LastTrainerVolume => mediaSettings.TrainerVolume;

		public ICommand SkipVideoButtonTapped { get; }

		public ICommand ToggledVolumeButtonTapped { get; }

		public ICommand ScreenTouched => new MvxCommand(DoScreenTouched);

		public IDelegate Delegate { get; }

		protected DemoModeVideoViewModel(ILocalSettings localSettings, IOldDemoModeService oldDemoModeService, ICombinedAudioVideoPlayer videoPlayer, IMainThreadSchedulerService schedulerService, IPlatformMediaVolumeService platformMediaVolumeService, IMediaSettings mediaSettings, IVolumeFacade volumeFacade, IDelegate returnDelegate = null)
			: base(localSettings, oldDemoModeService)
		{
			try
			{
				VideoPlayer = videoPlayer;
				this.schedulerService = schedulerService;
				this.platformMediaVolumeService = platformMediaVolumeService;
				this.mediaSettings = mediaSettings;
				this.volumeFacade = volumeFacade;
				Delegate = returnDelegate;
				SkipVideoButtonTapped = new MvxCommand(DoGoToMarketingPage);
				ToggledVolumeButtonTapped = new MvxCommand(DoToggleVolume);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init(NavObject navigationObject)
		{
			videoFilePath = navigationObject.VideoFilePath;
			ShowSkipButton.Value = !navigationObject.HideSkipButton;
			loopVideo = navigationObject.LoopVideo;
			initialVolume = navigationObject.InitialVolume;
			ShowVolumeButton.Value = !navigationObject.HideVolumeButton;
			volumeMetricSub = volumeFacade.ObserveVolumeChanges().SubscribeWithErrorLogging(WhenConsoleVolumeChanged);
			if (float.IsNaN(initialVolume))
			{
				return;
			}
			InWorkoutSystemVolumeInteractor systemVolumeInteractor = new InWorkoutSystemVolumeInteractor(currentConsoleService, deviceInfo, mediaSettings, platformMediaVolumeService, volumeFacade, 200L);
			int num = SystemVolumeHelper.MapVolume(initialVolume);
			ignoreInitialVolume = num;
			Log.Trace(base.LogTag, $"Setting demo mode video initial volume to {num}.");
			systemVolumeInteractor.SetConsoleVolume(num);
			if (systemVolumeInteractor.IsProcessingVolumeChanges)
			{
				Log.Trace(base.LogTag, "systemVolumeInteractor is attempting to set console volume asynchronously...");
				systemVolumeInteractor.WhenVolumeChangeCompleted.Take(1).SubscribeWithErrorLogging(delegate(bool result)
				{
					Log.Trace(base.LogTag, string.Format("{0} fired {1}: {2}", "systemVolumeInteractor", "WhenVolumeChangeCompleted", result));
					systemVolumeInteractor?.Dispose();
					systemVolumeInteractor = null;
				});
			}
			else
			{
				Log.Trace(base.LogTag, "systemVolumeInteractor updated volume synchronously.");
				systemVolumeInteractor?.Dispose();
				systemVolumeInteractor = null;
			}
		}

		private void WhenConsoleVolumeChanged(FitnessValueChange<int> volumeChange)
		{
			if (ignoreInitialVolume.HasValue && ignoreInitialVolume.Value == volumeChange.Current)
			{
				Log.Trace(base.LogTag, $"Demo mode video ignoring initial volume change from {volumeChange.Old} to {volumeChange.Current}.");
			}
			else
			{
				Log.Trace(base.LogTag, $"Demo mode video handling volume change from {volumeChange.Old} to {volumeChange.Current}.");
				HandleConsoleVolumeChanged(volumeChange);
			}
			ignoreInitialVolume = null;
		}

		protected virtual void HandleConsoleVolumeChanged(FitnessValueChange<int> volumeChange)
		{
			if (Delegate != null)
			{
				float volume = (float)volumeChange.Current / 100f;
				Delegate.ScreensaverVolumeChanged(volume);
			}
		}

		private void DoScreenTouched()
		{
			if (Delegate == null)
			{
				return;
			}
			if (!shouldHandleScreenTouches)
			{
				Log.Trace("DemoModeVideoViewModel", "Screen has been touched - ignored");
				return;
			}
			Log.Trace("DemoModeVideoViewModel", "Screen has been touched.");
			shouldHandleScreenTouches = false;
			Task.Run(async delegate
			{
				if (await Delegate.ScreenTouched())
				{
					isNavigatingAway = true;
					VideoPlayer.Stop();
					DoClose();
				}
				else
				{
					shouldHandleScreenTouches = true;
				}
			});
		}

		public virtual void UpdateConsoleVolume(float volume)
		{
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			StartPlayBackCompleteSub();
			videoErrorSub?.Dispose();
			videoErrorSub = VideoPlayer?.VideoErrorOccured?.SubscribeAsyncWithErrorLogging((Exception ex) => HandleVideoPlayerError(ex));
			if (UpdateVideoFilePath())
			{
				VideoVolume.Value = LastTrainerVolume;
			}
		}

		public override void OnAfterViewShown()
		{
			base.OnAfterViewShown();
			Task.Run((Func<Task>)AttemptLoadStartVideo);
		}

		protected virtual async Task AttemptLoadStartVideo()
		{
			if (!isDisposed && !isNavigatingAway)
			{
				await Task.Delay(VideoStartDelayMs);
				if (await LoadVideo())
				{
					PlayVideo();
					return;
				}
				ShowLoading.Value = false;
				HandleVideoAssetLookupFailed();
			}
		}

		protected void PlayVideo()
		{
			if (!isDisposed)
			{
				VideoPlayer?.Play(PlayerType.Video);
			}
		}

		protected void StopVideo()
		{
			VideoPlayer?.Stop();
		}

		protected void ClearVideo()
		{
			VideoPlayer?.Dispose();
		}

		private bool UpdateVideoFilePath()
		{
			if (base.DemoMode1Service == null)
			{
				Log.Error(base.LogTag, "DemoMode1Service is null.");
				HandleVideoAssetLookupFailed();
				return false;
			}
			string marketingVideoFileName = base.DemoMode1Service.MarketingVideoFileName;
			if (base.DemoMode1Service.DoesRequireDownloadingContent && base.DemoMode1Service is IOldRetailDemoMode1Service { ShouldUseSmdmAssets: not false } oldRetailDemoMode1Service)
			{
				Dictionary<string, FileDownloadReport> storedAssets = oldRetailDemoMode1Service.GetStoredAssets();
				if (storedAssets.CountSafe() < 1)
				{
					Log.Error(base.LogTag, "DemoMode1Service had zero stored assets.");
					HandleVideoAssetLookupFailed();
					return false;
				}
				FileDownloadReport valueSafely = storedAssets.GetValueSafely(marketingVideoFileName);
				if (valueSafely == null)
				{
					Log.Error(base.LogTag, "DemoMode1Service had no file with required filename \"" + marketingVideoFileName + "\".");
					Log.Error(base.LogTag, "Assets found in storage:");
					Log.Error(base.LogTag, JsonConvert.SerializeObject(storedAssets, Formatting.Indented));
					HandleVideoAssetLookupFailed();
					return false;
				}
				if (!valueSafely.DownloadedSuccessfully || valueSafely.ResourceBytes != valueSafely.DownloadedBytes)
				{
					Log.Error(base.LogTag, "DemoMode1Service had incomplete file report for file \"" + marketingVideoFileName + "\".");
					Log.Error(base.LogTag, "Assets found in storage:");
					Log.Error(base.LogTag, JsonConvert.SerializeObject(storedAssets, Formatting.Indented));
					HandleVideoAssetLookupFailed();
					return false;
				}
			}
			if (string.IsNullOrEmpty(videoFilePath))
			{
				VideoFilePath.Value = Path.Combine(base.DemoMode1Service.MarketingVideoFolderPath, marketingVideoFileName);
			}
			else
			{
				VideoFilePath.Value = videoFilePath;
			}
			Log.Trace(base.LogTag, "Marketing video file path found at: " + VideoFilePath.Value);
			return true;
		}

		protected async Task<bool> LoadVideo()
		{
			if (VideoPlayer == null)
			{
				return false;
			}
			Log.Trace("Video", "Loading video from direct source: uri: " + VideoFilePath.Value);
			videoPlaybackChangedSub?.Dispose();
			videoPlaybackChangedSub = VideoPlayer.WhenVideoPositionSecondsChanged.SubscribeWithErrorLogging(HandleVideoPositionSecondsChanged);
			try
			{
				if (float.IsNaN(initialVolume))
				{
					VideoPlayer.VideoVolume = mediaSettings.TrainerVolume;
				}
				else
				{
					VideoPlayer.VideoVolume = 1f;
				}
				await VideoPlayer.StartLoadDirectSource(VideoFilePath.Value);
				await DetermineExistenceOfClosedCaptions();
			}
			catch (Exception arg)
			{
				Log.Error("Video", $"Exception occurred loading from direct video source: {arg}");
				return false;
			}
			return true;
		}

		private async Task DetermineExistenceOfClosedCaptions()
		{
			Mvx.TryResolve<IClosedCaptionsLanguagesDetector>(out var service);
			if (service == null || VideoPlayer == null)
			{
				ShowCaptionControls.Value = false;
				return;
			}
			INC<bool> showCaptionControls = ShowCaptionControls;
			showCaptionControls.Value = await service.CurrentVideoHasCaptions(VideoPlayer);
		}

		private void HandleVideoPositionSecondsChanged(double position)
		{
			if (!isDisposed && !videoHasStarted && position > 0.0)
			{
				videoHasStarted = true;
				videoPlaybackChangedSub?.Dispose();
				videoPlaybackChangedSub = null;
				HandleVideoStarted();
			}
		}

		private void HandleVideoStarted()
		{
			if (!isDisposed)
			{
				ShowLoading.Value = false;
			}
		}

		private void HandleVideoAssetLookupFailed()
		{
			Log.Trace(base.LogTag, "HandleVideoAssetLookupFailed()");
			_whenMarketingVideoAssetLookupFailed?.OnNext(null);
			DoGoToMarketingPage();
		}

		private void VideoPlaybackCompleted(bool completed)
		{
			if (loopVideo)
			{
				VideoPlayer?.SeekTo(0.0, PlayerType.Video, forceSeek: true);
				VideoPlayer?.Play(PlayerType.Video);
			}
			else
			{
				Log.Trace(base.LogTag, "VideoPlaybackCompleted for non looped");
				mediaSettings.CommitTrainerVolumeToStorage();
				DoGoToMarketingPage();
			}
		}

		private void DoGoToMarketingPage()
		{
			if (!isNavigatingAway && !isDisposed)
			{
				isNavigatingAway = true;
				VideoPlayer?.Pause();
				Log.Trace(base.LogTag, "Updating last observed touch.");
				if (Mvx.TryResolve<ITouchMonitor>(out var service))
				{
					service.UpdateLastObservedTouch();
				}
				Log.Trace(base.LogTag, "Navigating to Demo Mode marketing page.");
				GoToDemoModeMarketingPage(useReplayVideoButton: true);
			}
		}

		private void StartPlayBackCompleteSub()
		{
			videoPlaybackCompletedSub?.Dispose();
			videoPlaybackCompletedSub = VideoPlayer?.VideoPlaybackCompleted?.Subscribe(VideoPlaybackCompleted);
		}

		[DependsOn(new string[] { "VideoVolume" })]
		private void UpdateDismissSub()
		{
			dismissTimerSub?.Dispose();
			dismissTimerSub = Observable.Timer(TimeSpan.FromMilliseconds(3000.0)).ObserveOn(schedulerService.Scheduler).SubscribeWithErrorLogging(delegate
			{
				ShowVolumeBar.Value = false;
			});
		}

		protected void DoToggleVolume()
		{
			ShowVolumeBar.Value = !ShowVolumeBar.Value;
			UpdateDismissSub();
		}

		[DependsOn(new string[] { "VideoVolume" })]
		protected void TrainerVolumeChanged()
		{
			if (Delegate == null)
			{
				float num = VideoVolume.Value.Clamp(0f, 1f);
				mediaSettings.UpdateTrainerVolume(num, commit: false);
				if (VideoPlayer != null)
				{
					VideoPlayer.VideoVolume = num;
				}
				UpdateConsoleVolume(num);
			}
		}

		private async Task HandleVideoPlayerError(Exception exception)
		{
			try
			{
				if (VideoPlayer != null)
				{
					await VideoPlayer.StartLoadDirectSource(VideoFilePath.Value);
					if (!VideoPlayer.VideoFailedToLoad)
					{
						VideoPlayer.SeekTo(VideoPlayer?.LastVideoPositionSeconds ?? 0.0, PlayerType.Both, forceSeek: true);
					}
					else
					{
						Log.Error("Video", "Failed to load video. No error available.");
					}
				}
			}
			catch (Exception ex)
			{
				Log.Error("Video", $"Failed to load video after player Error. Exception: {ex.GetBaseException()}");
			}
		}

		protected override void DisposeDisposableObjects()
		{
			_whenMarketingVideoAssetLookupFailed?.Dispose();
			_whenMarketingVideoAssetLookupFailed = null;
			DisposePlayBackCompleteSub();
			DisposeVideoPlayer();
			dismissTimerSub?.Dispose();
			dismissTimerSub = null;
			videoPlaybackChangedSub?.Dispose();
			videoPlaybackChangedSub = null;
			videoErrorSub?.Dispose();
			videoErrorSub = null;
			volumeMetricSub?.Dispose();
			volumeMetricSub = null;
			base.DisposeDisposableObjects();
		}

		private void DisposePlayBackCompleteSub()
		{
			videoPlaybackCompletedSub?.Dispose();
			videoPlaybackCompletedSub = null;
		}

		private void DisposeVideoPlayer()
		{
			VideoPlayer?.Pause();
			VideoPlayer?.Dispose();
			VideoPlayer = null;
		}

