		public new bool IsStrengthMirror
		{
			get
			{
				if (!base.IsStrengthMirror)
				{
					return CurrentConsoleType == ConsoleType.Mirror;
				}
				return true;
			}
		}

		private bool IsInDmk
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.PhysicalConsole?.LatestBasicInfo?.CurrentState == ConsoleState.SafetyKeyRemoved;
			}
		}

		private bool IsIdle
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.PhysicalConsole?.LatestBasicInfo?.CurrentState == ConsoleState.Idle;
			}
		}

		public ConsoleType CurrentConsoleType => currentConsoleService.PhysicalConsole?.ConsoleInfo?.MachineType ?? ConsoleType.None;

		public RetailDemoModeMarketingViewModel(ILocalSettings localSettings, IOldDemoModeService demoMode1Service, IWolfTrackingService wolfTrackingService, IWolfAnalytics analytics)
			: base(localSettings, demoMode1Service, analytics)
		{
			try
			{
				this.wolfTrackingService = wolfTrackingService;
				CreateMarketingFeaturesList();
				UpdateMarketingFeaturesTitlesAndBodies();
				StartWorkoutButtonTap = new MvxCommand(StartWorkout);
				ExitDemoModeButtonTap = new MvxCommand(PromptExitDemoMode);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public override async Task OnViewShown()
		{
			await base.OnViewShown();
			base.StrengthMirrorTouchMonitor?.UpdateLastObservedTouch();
			if (consoleTypeBackgroundImageScaleType.ContainsKey(CurrentConsoleType))
			{
				HeaderBackgroundImageScaleType.Value = consoleTypeBackgroundImageScaleType[CurrentConsoleType];
			}
			if (CurrentConsoleType == ConsoleType.Rower || CurrentConsoleType == ConsoleType.Mirror)
			{
				DarkScrollForBenefitsText.Value = true;
			}
		}

		private void CreateMarketingFeaturesList()
		{
			if (CurrentConsoleType == ConsoleType.Mirror)
			{
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.ReflectiveTraining, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.WorkoutVariety, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.StudioClasses, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.TrainingTogether, CurrentConsoleType));
			}
			else
			{
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.InteractivePersonalTraining, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.GlobalWorkouts, CurrentConsoleType));
				if (CurrentConsoleType != ConsoleType.Rower)
				{
					MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.LiveEvents, CurrentConsoleType));
				}
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.StudioClasses, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.WorkoutVariety, CurrentConsoleType));
			}
			FinishedAddingMarketingFeatures.Value = true;
		}

		private void UpdateMarketingFeaturesTitlesAndBodies()
		{
			foreach (DemoModeMarketingFeature marketingFeature in MarketingFeatures)
			{
				FeatureTitles.Value.Add(marketingFeature.Title);
				FeatureBodies.Value.Add(marketingFeature.Body);
			}
			FinishedUpdatingFeatureText.Value = true;
		}

		protected override void UpdateAssetPaths()
		{
			if (base.DemoMode1Service == null)
			{
				Log.Error(base.LogTag, "Demo Mode Service is null, exiting.");
				FoundAllAssetsIntact.Value = false;
				FinishedUpdatingAssets.Value = false;
				return;
			}
			if (base.DemoMode1Service.GetStoredAssetList().IsNullOrEmpty())
			{
				Log.Error(base.LogTag, "No asset files were detected for Retail Demo Mode, exiting.");
				FoundAllAssetsIntact.Value = false;
				FinishedUpdatingAssets.Value = false;
				return;
			}
			bool flag = true;
			flag &= UpdateBindableAssetListWithAssetPath("marketing-header.jpg", ImagePathsMarketingHeader);
			foreach (DemoModeMarketingFeature marketingFeature in MarketingFeatures)
			{
				if (!base.DemoMode1Service.DoesAssetExist(marketingFeature.ImageFileName))
				{
					Log.Error(base.LogTag, "Asset file " + marketingFeature.ImageFileName + " is missing, exiting.");
				}
				flag &= UpdateBindableAssetListWithAssetPath(marketingFeature.ImageFileName, ImagePathsFeatures);
			}
			flag &= UpdateBindableAssetListWithAssetPath(IsStrengthMirror ? "trainers.png" : "trainers.jpg", ImagePathsTrainers);
			if (IsStrengthMirror)
			{
				for (int i = 1; i <= 9; i++)
				{
					flag &= UpdateBindableAssetListWithAssetPath(string.Format("workout-type-{0}.jpg", i.ToString("D2")), ImagePathsWorkoutTypes);
				}
			}
			else
			{
				flag &= UpdateBindableAssetListWithAssetPath("workout-types.png", ImagePathsWorkoutTypes);
			}
			if (flag)
			{
				Log.Trace(base.LogTag, "All Demo Mode assets found.");
			}
			else
			{
				Log.Error(base.LogTag, "Error finding some Demo Mode asset files.");
			}
			FoundAllAssetsIntact.Value = flag;
			FinishedUpdatingAssets.Value = true;
		}

		private void StartWorkout()
		{
			IRetailDemoLocalWorkoutService service;
			if (IsInDmk)
			{
				Log.Trace(base.LogTag, "Can't start demo workout while in DMK state.");
				PromptInsertDMK();
			}
			else if (!IsIdle && CurrentConsoleType != ConsoleType.Mirror)
			{
				Log.Trace(base.LogTag, "Can't start workout due to unknown state: " + (currentConsoleService?.PhysicalConsole?.LatestBasicInfo?.CurrentState).ToString());
				PromptUnknownStateError();
			}
			else if (Mvx.TryResolve<IRetailDemoLocalWorkoutService>(out service) && service.WorkoutAssetsExistForConsoleType(CurrentConsoleType))
			{
				Workout workout = service.GetWorkoutForConsoleType(CurrentConsoleType);
				Task.Run(async delegate
				{
					await BeginDemoWorkout(workout).ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		private void PromptInsertDMK()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.retail_demo_mode_insert_dmk_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_insert_dmk_message, delegate
			{
			}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
		}

		private void PromptUnknownStateError()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.retail_demo_mode_unknown_state_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_unknown_state_message, delegate
			{
			}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
		}

		private void PromptInsertDMKToExitRDM()
		{
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.retail_demo_mode_exit_insert_dmk_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_exit_insert_dmk_message, delegate
			{
			}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
		}

		private async Task BeginDemoWorkout(Workout workout)
		{
			if (!isDisposed && workout != null)
			{
				WorkoutRunnerContext runningContext = new WorkoutRunnerContext(Workout.WorkoutContext.OnDemand, null)
				{
					DisableCompetition = true
				};
				if (await base.StartWorkoutService.DoStartWorkout(workout, runningContext, WaitForConsoleReady, null).ConfigureAwait(continueOnCapturedContext: false))
				{
					DoClose();
				}
				else
				{
					Log.Error(base.LogTag, "Could not begin RDM demo workout.");
				}
			}
		}

		private void PromptExitDemoMode()
		{
			if (IsInDmk)
			{
				Log.Trace(base.LogTag, "Can't exit demo mode while in DMK state.");
				PromptInsertDMKToExitRDM();
			}
			else
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.retail_demo_mode_exit_prompt_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_exit_prompt_message, ExitDemoModePromptConfirmed, Wolf.Core.Resources.AppStrings.retail_demo_mode_exit_prompt_cancel.ToUpper(), Wolf.Core.Resources.AppStrings.retail_demo_mode_exit_prompt_accept.ToUpper());
			}
		}

		private void ExitDemoModePromptConfirmed()
		{
			if (!isNavigatingAway && !isDisposed)
			{
				isNavigatingAway = true;
				base.DemoMode1Service?.DisableDemoMode();
				Log.Trace(base.LogTag, "Retail Demo Mode exit confirmed.");
				if (wolfTrackingService.FirstRun || !connectivity.IsConnected)
				{
					wolfTrackingService.FirstRun = true;
					GoToViewModelAndClearNavStack<WelcomeViewModel>();
				}
				else
				{
					HardResetNavigation();
				}
			}
		}

		protected override void NavigateToAppropriateVideoVM()
		{
			GoToViewModelAndClearNavStack<RetailDemoModeVideoViewModel>();
		}

