		public bool IsPortrait => currentConsoleService.PhysicalConsole.ConsoleInfo.MachineType == ConsoleType.Mirror;

		public RetailDemoModeScreensaverViewModel(ILocalSettings localSettings, IOldRetailDemoMode1Service demoMode1Service)
			: base(localSettings, demoMode1Service)
		{
			try
			{
				ScreenTapped = new MvxCommand(DoGoToMarketingPage);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void DoGoToMarketingPage()
		{
			if (!isNavigatingAway && !isDisposed)
			{
				isNavigatingAway = true;
				if (Mvx.TryResolve<ITouchMonitor>(out var service))
				{
					Log.Trace(base.LogTag, "DoGoToMarketingPage called in " + GetType().Name);
					Log.Trace(base.LogTag, "Calling ITouchMonitor.UpdateLastObservedTouch");
					service.UpdateLastObservedTouch();
					Log.Trace(base.LogTag, string.Format("{0}: {1:0.000}", "SecondsSinceLastTouch", service.SecondsSinceLastTouch));
				}
				Log.Trace(base.LogTag, "Navigating to Demo Mode marketing page.");
				GoToDemoModeMarketingPage();
			}
		}

		public List<string> getContentForCurrentConsoleType()
