			try
			{
				_oldRetailDemoMode1Service = demoMode1Service;
				FatalityService = fatalityService;
				this.wolfTrackingService = wolfTrackingService;
				Delegate = vmDelegate;
				CancelSync = new MvxCommand(DoCancelSync);
