			}
		}

		public override async Task OnViewShown()
		{
			if (!isDisposed)
			{
				await base.OnViewShown();
				if (!hasStartedInitialization)
				{
					hasStartedInitialization = true;
					StartInitialization();
				}
			}
		}

		protected virtual void StartInitialization()
		{
			if (isDisposed)
			{
				return;
			}
			hasErrorShown = false;
			if (!connectivity.IsConnected)
			{
				ShowWifiErrorRetryDialog();
				return;
			}
			ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_checking_status;
			if (_oldRetailDemoMode1Service == null)
			{
				Log.Error(base.LogTag, "The _oldRetailDemoMode1Service was null. This is pretty much a fatal error at this point.");
				if (FatalityService != null)
				{
					FatalityService.ReportFatalEvent(new NullReferenceException(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_error_message_null_service), Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_error_message_null_service, isPermanent: true);
				}
				else
				{
					ShowErrorBeforeHardReset(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_error_message_null_service);
				}
			}
			else
			{
				Log.Trace(base.LogTag, "Retail Demo Mode is " + (_oldRetailDemoMode1Service.IsInDemoMode ? "already" : "not") + " enabled. Beginning sync process.");
				SyncTask = Task.Run((Func<Task>)StartSyncProcedure);
			}
		}

		private async Task StartSyncProcedure()
		{
			if (isSyncing)
			{
				return;
			}
			isSyncing = true;
			bool success = false;
			bool cancelled = false;
			Exception exception = null;
			try
			{
				success = await BeginServiceSync().ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (TaskCanceledException ex)
			{
				cancelled = true;
				exception = ex;
			}
			catch (OperationCanceledException ex2)
			{
				cancelled = true;
				exception = ex2;
			}
			catch (Exception ex3)
			{
				exception = ex3;
				Log.Trace(base.LogTag, "Retail Demo Mode asset sync operation encountered an error.", ex3);
			}
			finally
			{
				isSyncing = false;
				if (success)
				{
					Log.Trace(base.LogTag, "Retail Demo Mode successfully enabled.");
					CompletedSetup();
				}
				else if (cancelled)
				{
					ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_cancelled;
					Log.Warn(base.LogTag, "Retail Demo Mode sync task was cancelled.");
					HardResetAppNavigation(exception);
				}
				else
				{
					Log.Error(base.LogTag, "Retail Demo Mode could not be enabled.");
					PromptUserToRetryAfterFailedSync(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_error_message_unsuccessful, exception);
				}
			}
		}

		protected virtual async Task<bool> BeginServiceSync()
		{
			ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_syncing;
			if (Delegate != null)
			{
				return await BeginServiceSyncWithDelegate();
			}
			serviceSyncCTS?.Dispose();
			serviceSyncCTS = new CancellationTokenSource();
			assetDownloadProgressSub?.Dispose();
			assetDownloadProgressSub = Observable.FromEventPattern(delegate(EventHandler<FileDownloadProgressEventArgs> x)
			{
				_oldRetailDemoMode1Service.ProgressChanged += x;
			}, delegate(EventHandler<FileDownloadProgressEventArgs> x)
			{
				_oldRetailDemoMode1Service.ProgressChanged -= x;
			}).SubscribeWithErrorLogging(HandleServiceFileDownloadProgressChanged);
			bool success = false;
			try
			{
				success = await _oldRetailDemoMode1Service.SyncRetailDemoModeFilesFromFeatureFlagAndEnable(serviceSyncCTS?.Token ?? CancellationToken.None).ConfigureAwait(continueOnCapturedContext: false) != null && _oldRetailDemoMode1Service.IsInDemoMode && _oldRetailDemoMode1Service.CheckStoredAssetsIntegrity();
			}
			catch (TaskCanceledException)
			{
				throw;
			}
			catch (OperationCanceledException)
			{
				throw;
			}
			catch (Exception exception)
			{
				Log.Error(base.LogTag, "An error occurred during the Retail Demo Mode asset sync.", exception);
			}
			finally
			{
				assetDownloadProgressSub?.Dispose();
				assetDownloadProgressSub = null;
				serviceSyncCTS?.Dispose();
				serviceSyncCTS = null;
			}
			return success;
		}

		protected void HandleServiceFileDownloadProgressChanged(EventPattern<FileDownloadProgressEventArgs> eventPattern)
		{
			if (eventPattern?.EventArgs != null)
			{
				HandleServiceFileDownloadProgressChanged(eventPattern.EventArgs.DownloadedBytes, eventPattern.EventArgs.FileSizeBytes);
			}
		}

		private void HandleServiceFileDownloadProgressChanged(long downloadedBytes, long totalBytes)
		{
			CurrentAssetDownloadedBytes.Value = downloadedBytes;
			CurrentAssetFileBytes.Value = totalBytes;
			CurrentAssetDownloadPercentage = ((CurrentAssetFileBytes.Value < 1) ? 0.0 : Math.Round((100.0 * (double)CurrentAssetDownloadedBytes.Value / (double)CurrentAssetFileBytes.Value).Clamp(0.0, 100.0), 1));
		}

		private void CompletedSetup()
		{
			ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_complete;
			if (!isNavigatingAway)
			{
				isNavigatingAway = true;
				Log.Trace(base.LogTag, "Navigating to Retail Mode Screensaver VM.");
				if (Delegate != null)
				{
					Delegate.DownloadCompleted();
				}
				else
				{
					GoToRetailDemoModeScreensaverIfInDemoMode(showScreensaver: false);
				}
				DoClose();
			}
		}

		private void ShowErrorBeforeHardReset(string errorMessage)
		{
			if (!hasErrorShown && !isDisposed)
			{
				hasErrorShown = true;
				ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_failed;
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_error_title, errorMessage, delegate
				{
					HardResetAppNavigation(new InvalidOperationException());
				}, string.Empty, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_dialog_exit_demo_mode.ToUpper(), null, null, dismissible: false);
			}
		}

		private void ShowRetryOrExitDialog(string title, string errorMessage, string exitButtonText, string retryButtonText, Action exitButtonAction)
		{
			if (hasErrorShown || isDisposed)
			{
				return;
			}
			hasErrorShown = true;
			ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_failed;
			ShowSimpleConfirmationDialog(title, errorMessage, async delegate
			{
				if (exitButtonAction != null)
				{
					await Task.Run(exitButtonAction, CancellationToken.None);
				}
				return (object)null;
			}, cancellableOperation: false, null, (retryButtonText ?? string.Empty).ToUpper(), (exitButtonText ?? string.Empty).ToUpper(), OnConfirmActionTiming.AfterClose, null, StartInitialization, dismissible: false);
		}

		private void PromptUserToRetryAfterFailedSync(string errorMessage, Exception exception)
		{
			ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_failed;
			ShowRetryOrExitDialog(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_retry_download_title, errorMessage, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_dialog_exit, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_dialog_retry, delegate
			{
				ResetNavigationAppropriately(exception);
			});
		}

		private void ShowWifiErrorRetryDialog()
		{
			ProgressStatus.Value = Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_progress_failed;
			ShowRetryOrExitDialog(Wolf.Core.Resources.AppStrings.default_no_wifi_title, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_no_wifi_message, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_no_wifi_exit_button, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_dialog_retry, delegate
			{
				SetFirstRunAndGoBackToWelcomeScreen(new WifiException());
			});
		}

		private void ResetNavigationAppropriately(Exception exception)
		{
			IConnectivity obj = connectivity;
			if (obj != null && obj.IsConnected)
			{
				IWifiService obj2 = wifiService;
				if (obj2 != null && obj2.IsWifiEnabled)
				{
					HardResetAppNavigation(exception);
					return;
				}
			}
			SetFirstRunAndGoBackToWelcomeScreen(exception);
		}

		private void SetFirstRunAndGoBackToWelcomeScreen(Exception exception)
		{
			trackingService.FirstRun = true;
			HardResetAppNavigationToWelcomeScreen(exception);
		}

		private void HardResetAppNavigation(Exception exception)
		{
			if (!isNavigatingAway)
			{
				isNavigatingAway = true;
				if (Delegate != null)
				{
					Delegate.DownloadFailed(exception);
				}
				else if (!connectivity.IsConnected || wolfTrackingService.FirstRun)
				{
					GoToViewModelAndClearNavStack<WelcomeViewModel>();
				}
				else
				{
					HardResetNavigation();
				}
				DoClose();
			}
		}

		private void HardResetAppNavigationToWelcomeScreen(Exception exception)
		{
			if (!isNavigatingAway)
			{
				isNavigatingAway = true;
				if (Delegate != null)
				{
					Delegate.DownloadFailed(exception);
				}
				else
				{
					GoToViewModelAndClearNavStack<WelcomeViewModel>();
				}
				DoClose();
			}
		}

		private void DoCancelSync()
		{
			if (isDisposed || !isSyncing)
			{
				return;
			}
			ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_cancel_sync_title, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_cancel_sync_message, delegate
			{
				if (!isDisposed && isSyncing)
				{
					serviceSyncCTS?.Cancel();
				}
			}, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_dialog_continue_download.ToUpper(), Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_dialog_exit_demo_mode.ToUpper());
		}

		protected override void DisposeDisposableObjects()
		{
			serviceSyncCTS?.Dispose();
			serviceSyncCTS = null;
			assetDownloadProgressSub?.Dispose();
			assetDownloadProgressSub = null;
			base.DisposeDisposableObjects();
		}

		private async Task<bool> BeginServiceSyncWithDelegate()
		{
			serviceSyncCTS?.Dispose();
			serviceSyncCTS = new CancellationTokenSource();
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			(await Delegate.StartDownloadAsync(serviceSyncCTS.Token)).Subscribe(delegate(DownloadProgress progress)
			{
				HandleServiceFileDownloadProgressChanged(progress.BytesReceived, progress.TotalBytes);
			}, delegate(Exception error)
			{
				tcs.SetException(error);
			}, delegate
			{
				tcs.SetResult(result: true);
			});
			bool result = await tcs.Task;
			serviceSyncCTS?.Dispose();
			serviceSyncCTS = null;
			return result;
		}

