	public class RetailDemoModeVideoViewModel : DemoModeVideoViewModel
	{
		private DateTime lastSystemVolumeTouchTime = DateTime.UtcNow;

		private bool isUserSlidingVideoVolume;

		private InWorkoutSystemVolumeInteractor systemVolumeInteractor;

		public RetailDemoModeVideoViewModel(ILocalSettings localSettings, IOldDemoModeService oldDemoModeService, ICombinedAudioVideoPlayer videoPlayer, IMainThreadSchedulerService schedulerService, IMediaSettings mediaSettings, IPlatformMediaVolumeService platformMediaVolumeService, IVolumeFacade volumeFacade, IDelegate returnDelegate = null)
			: base(localSettings, oldDemoModeService, videoPlayer, schedulerService, platformMediaVolumeService, mediaSettings, volumeFacade, returnDelegate)
		{
			try
			{
				systemVolumeInteractor = new InWorkoutSystemVolumeInteractor(currentConsoleService, deviceInfo, mediaSettings, platformMediaVolumeService, volumeFacade, 200L);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void VideoVolumeTouched()
		{
			isUserSlidingVideoVolume = true;
		}

		public void VideoVolumeReleased()
		{
			isUserSlidingVideoVolume = false;
			UpdateVideoVolume(force: true);
		}

		private void UpdateVideoVolume(bool force = false)
		{
			DateTime utcNow = DateTime.UtcNow;
			if (utcNow - lastSystemVolumeTouchTime < TimeSpan.FromMilliseconds(200.0) && !force)
			{
				return;
			}
			int num = (VideoVolume.Value * 100f).RoundToNearest(10.0);
			int num2 = currentConsoleService.Console.LatestBasicInfo.Volume.RoundToNearest(10.0);
			if (Math.Abs(num - num2) >= 10 || force)
			{
				lastSystemVolumeTouchTime = utcNow;
				systemVolumeInteractor.SetConsoleVolume(num);
				if (!isUserSlidingVideoVolume)
				{
					VideoVolume.Value = Convert.ToSingle((double)num / 100.0);
				}
			}
		}

		public override void UpdateConsoleVolume(float volume)
		{
			if (isUserSlidingVideoVolume)
			{
				UpdateVideoVolume();
			}
		}

		protected override void HandleConsoleVolumeChanged(FitnessValueChange<int> volumeChange)
		{
			base.HandleConsoleVolumeChanged(volumeChange);
			if (!isUserSlidingVideoVolume)
			{
				if (!ShowVolumeBar.Value)
				{
					DoToggleVolume();
				}
				int num = volumeChange.Current.RoundToNearest(10.0);
				VideoVolume.Value = Convert.ToSingle((double)num / 100.0);
			}
		}

		public override void Dispose()
		{
			systemVolumeInteractor?.Dispose();
			systemVolumeInteractor = null;
			((DemoModeViewModelBase)this).Dispose();
			UnregisterChangeHandlers();
		}

