		private void CreateMarketingFeaturesList()
		{
			if (CurrentConsoleType == ConsoleType.Mirror)
			{
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.TrainWithTheBest, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.WorkoutYourWay, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.JoinTheCommunity, CurrentConsoleType));
			}
			else
			{
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.TrainWithTheBest, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.YourPerfectWorkout, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.JoinTheCommunity, CurrentConsoleType));
				MarketingFeatures.Add(new DemoModeMarketingFeature(DemoModeMarketingFeature.FeatureType.GetRewarded, CurrentConsoleType));
			}
			FinishedAddingMarketingFeatures.Value = true;
		}

		private void UpdateMarketingFeaturesTitlesAndBodies()
