	public class RetailDemoModeScreensaverVolumeControlDialogViewModel : BaseViewModel
	{
		public interface IDelegate
		{
			void TrySaveVolume(float volume);
		}

		public class NavObject
		{
			public string SampleAudioPath { get; set; }

			public string TitleText { get; set; }

			public string MessageText { get; set; }

			public string PlaySampleText { get; set; }

			public string StopSampleText { get; set; }

			public IDelegate Delegate { get; set; }

			public float InitialVolume { get; set; } = 0f / 0f;
		}

		private IDisposable volumeMetricSub;

		private readonly IPlatformMediaVolumeService platformMediaVolumeService;

		protected IInWorkoutSystemVolumeInteractor systemVolumeInteractor;

		private readonly IVolumeFacade volumeFacade;

		public readonly INC<int> VolumeStep = new NC<int>();

		public readonly INC<bool> SamplePlaying = new NC<bool>();

		public INC<string> SampleAudioPath = new NC<string>();

		private readonly float volumeFractionWhenDialogStarted;

		private bool isInitializing = true;

		public readonly int MaxVolumeStep = 10;

		public ICommand SampleAudioButtonTouched => new MvxCommand(delegate
		{
			SamplePlaying.Value = !SamplePlaying.Value;
		});

		public string TitleText { get; set; } = Wolf.Core.Resources.AppStrings.retail_demo_mode_screensaver_dialog_title;

		public string MessageText { get; set; } = Wolf.Core.Resources.AppStrings.retail_demo_mode_screensaver_dialog_description;

		public string PlaySampleText { get; set; } = Wolf.Core.Resources.AppStrings.retail_demo_mode_screensaver_dialog_preview_button;

		public string StopSampleText { get; set; } = Wolf.Core.Resources.AppStrings.retail_demo_mode_screensaver_dialog_stop_preview_button;

		[DependsOn(new string[] { "SamplePlaying" })]
		public string SampleButtonText
		{
			get
			{
				if (!SamplePlaying.Value)
				{
					return PlaySampleText;
				}
				return StopSampleText;
			}
		}

		public IDelegate Delegate { get; set; }

		public override object ArbitraryData
		{
			get
			{
				return base.ArbitraryData;
			}
			set
			{
				if (value is NavObject navObject)
				{
					if (!navObject.SampleAudioPath.IsNullOrWhitespace())
					{
						SampleAudioPath.Value = navObject.SampleAudioPath;
					}
					if (!navObject.TitleText.IsNullOrWhitespace())
					{
						TitleText = navObject.TitleText;
					}
					if (!navObject.MessageText.IsNullOrWhitespace())
					{
						MessageText = navObject.MessageText;
					}
					if (!navObject.PlaySampleText.IsNullOrWhitespace())
					{
						PlaySampleText = navObject.PlaySampleText;
					}
					if (!navObject.StopSampleText.IsNullOrWhitespace())
					{
						StopSampleText = navObject.StopSampleText;
					}
					if (navObject.Delegate != null)
					{
						Delegate = navObject.Delegate;
					}
					if (float.IsNaN(navObject.InitialVolume))
					{
						isInitializing = false;
						return;
					}
					VolumeStep.Value = VolumeFractionToVolumeStep(navObject.InitialVolume);
					SetSystemVolume(navObject.InitialVolume);
				}
			}
		}

		public RetailDemoModeScreensaverVolumeControlDialogViewModel(ILocalSettings localSettings, IPlatformMediaVolumeService platformMediaVolumeService, IMediaSettings mediaSettings, IVolumeFacade volumeFacade)
			: base(localSettings)
		{
			try
			{
				this.platformMediaVolumeService = platformMediaVolumeService;
				this.volumeFacade = volumeFacade;
				systemVolumeInteractor = new InWorkoutSystemVolumeInteractor(currentConsoleService, deviceInfo, mediaSettings, platformMediaVolumeService, volumeFacade, 200L);
				volumeFractionWhenDialogStarted = ((IsAndroidBuiltIn() && !base.IsStrengthMirror) ? ((float)volumeFacade.GetMostRecentVolume() / 100f) : platformMediaVolumeService.GetPlatformMediaVolume());
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public async Task Init()
		{
			await Task.Run(delegate
			{
				volumeMetricSub = volumeFacade.ObserveVolumeChanges().SubscribeWithErrorLogging(WhenConsoleVolumeChanged);
			});
		}

		private void WhenConsoleVolumeChanged(FitnessValueChange<int> metricChange)
		{
			int current = metricChange.Current;
			int num = VolumePercentToVolumeStep(current);
			if (num != VolumeStep.Value)
			{
				VolumeStep.Value = num;
			}
		}

		public override void Dispose()
		{
			systemVolumeInteractor?.Dispose();
			systemVolumeInteractor = null;
			volumeMetricSub?.Dispose();
			volumeMetricSub = null;
			base.Dispose();
			UnregisterChangeHandlers();
		}

		private void SetSystemVolume(float value)
		{
			float volumeFraction = ((IsAndroidBuiltIn() && !base.IsStrengthMirror) ? ((float)volumeFacade.GetMostRecentVolume() / 100f) : platformMediaVolumeService.GetPlatformMediaVolume());
			int num = VolumeFractionToVolumeStep(volumeFraction);
			int num2 = VolumeFractionToVolumeStep(value);
			if (num != num2)
			{
				int consoleVolume = VolumeStepToVolumePercent(num2);
				if (IsAndroidBuiltIn())
				{
					systemVolumeInteractor.SetConsoleVolume(consoleVolume);
				}
				else
				{
					platformMediaVolumeService.SetPlatformMediaVolume(value);
				}
			}
		}

		protected override void DoClose()
		{
			if (SamplePlaying != null)
			{
				SamplePlaying.Value = false;
			}
			SetSystemVolume(volumeFractionWhenDialogStarted);
			float volume = VolumeStepToVolumeFraction(VolumeStep.Value);
			Delegate?.TrySaveVolume(volume);
			base.DoClose();
		}

		public void VolumeSliderChangedTo(int volumeStep)
		{
			if (isInitializing)
			{
				if (volumeStep == VolumeStep.Value)
				{
					isInitializing = false;
				}
			}
			else
			{
				float systemVolume = VolumeStepToVolumeFraction(volumeStep);
				SetSystemVolume(systemVolume);
			}
		}

		private static float VolumePercentToVolumeFraction(int volumePercent)
		{
			int num = volumePercent.RoundToNearest(10.0);
			return (float)num / 100f;
		}

		private static float VolumeStepToVolumeFraction(int volumeStep)
		{
			int volumePercent = VolumeStepToVolumePercent(volumeStep);
			return VolumePercentToVolumeFraction(volumePercent);
		}

		private static int VolumeFractionToVolumePercent(float volumeFraction)
		{
			return SystemVolumeHelper.MapVolume(volumeFraction);
		}

		private static int VolumeStepToVolumePercent(int volumeStep)
		{
			return volumeStep * 10;
		}

		private static int VolumeFractionToVolumeStep(float volumeFraction)
		{
			int volumePercent = VolumeFractionToVolumePercent(volumeFraction);
			return VolumePercentToVolumeStep(volumePercent);
		}

		private static int VolumePercentToVolumeStep(int volumePercent)
		{
			return volumePercent.RoundToNearest(10.0) / 10;
		}

