		private const string ImageFileNameFeature2 = "feature-image-2.jpg";

		private const string ImageFileNameFeature3 = "feature-image-3.jpg";

		private const string ImageFileNameWorkoutType1 = "workout-type-01.jpg";

		private const string ImageFileNameWorkoutType2 = "workout-type-02.jpg";

		private const string ImageFileNameWorkoutType3 = "workout-type-03.jpg";

		private const string ImageFileNameWorkoutType4 = "workout-type-04.jpg";

		private const string ImageFileNameWorkoutType5 = "workout-type-05.jpg";

		private const string ImageFileNameWorkoutType6 = "workout-type-06.jpg";

		private const string ImageFileNameWorkoutType7 = "workout-type-07.jpg";

		private const string ImageFileNameWorkoutType8 = "workout-type-08.jpg";

		private const string ImageFileNameWorkoutType9 = "workout-type-09.jpg";

		protected IWolfTrackingService wolfTrackingService;

		public ICommand ExitDemoModeButtonTap { get; }

		public StrengthMirrorDemoModeMarketingViewModel(ILocalSettings localSettings, IOldRetailDemoMode1Service demoMode1Service, IWolfTrackingService wolfTrackingService, IWolfAnalytics analytics)
			: base(localSettings, demoMode1Service, analytics)
		{
			try
			{
				this.wolfTrackingService = wolfTrackingService;
				ExitDemoModeButtonTap = new MvxCommand(DoExitDemoModeButtonTapped);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		protected override void UpdateAssetPaths()
		{
			if (base.DemoMode1Service == null)
			{
				Log.Error(base.LogTag, "Error getting image asset file paths. DemoMode1Service was null.");
				FinishedUpdatingAssets.Value = false;
				return;
			}
			Dictionary<string, FileDownloadReport> dictionary = null;
			if (base.DemoMode1Service is IOldRetailDemoMode1Service { ShouldUseSmdmAssets: not false } oldRetailDemoMode1Service)
			{
				dictionary = oldRetailDemoMode1Service.GetStoredAssets();
			}
			if (dictionary.CountSafe() < 1)
			{
				Log.Error(base.LogTag, "Error getting image asset file paths. DemoMode1Service returned a null or empty asset list.");
				FinishedUpdatingAssets.Value = false;
				return;
			}
			bool flag = true;
			flag &= UpdateBindableAssetListWithAssetPath("marketing-header.jpg", ImagePathsMarketingHeader, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("feature-image-1.jpg", ImagePathsFeatures, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("feature-image-2.jpg", ImagePathsFeatures, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("feature-image-3.jpg", ImagePathsFeatures, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-01.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-02.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-03.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-04.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-05.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-06.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-07.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-08.jpg", ImagePathsWorkoutTypes, dictionary);
			flag &= UpdateBindableAssetListWithAssetPath("workout-type-09.jpg", ImagePathsWorkoutTypes, dictionary);
			FinishedUpdatingAssets.Value = flag;
			if (flag)
			{
				Log.Trace(base.LogTag, "All Demo Mode assets intact and accounted for:");
				Log.Trace(base.LogTag, JsonConvert.SerializeObject(dictionary, Formatting.Indented));
			}
			else
			{
				Log.Error(base.LogTag, "Some or all Demo Mode assets were missing or not intact. Stored assets:");
				Log.Error(base.LogTag, JsonConvert.SerializeObject(dictionary, Formatting.Indented));
			}
		}

		private void DoExitDemoModeButtonTapped()
		{
			if (!isNavigatingAway && !isDisposed)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_exit_dialog_title, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_exit_dialog_message, delegate
				{
					OnExitConfirmed();
				}, Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_exit_dialog_cancel.ToUpper(), Wolf.Core.Resources.AppStrings.strength_mirror_demo_mode_exit_dialog_confirm.ToUpper());
			}
		}

		private void OnExitConfirmed()
		{
			if (!isNavigatingAway && !isDisposed)
			{
				isNavigatingAway = true;
				Log.Trace(base.LogTag, "Strength Mirror Demo Mode exit confirmed.");
				if (connectivity.IsConnected)
				{
					Log.Trace(base.LogTag, "Internet is connected. Navigating to OnboardingWebViewModel");
					GoToViewModelAndClearNavStack<OnboardingWebViewModel>();
				}
				else
				{
					Log.Trace(base.LogTag, "Internet is not connected. Beginning first run procedure.");
					wolfTrackingService.FirstRun = true;
					GoToViewModelAndClearNavStack<WelcomeViewModel>();
				}
			}
		}

		protected override void NavigateToAppropriateVideoVM()
		{
			GoToViewModelAndClearNavStack<StrengthMirrorDemoModeVideoViewModel>();
		}

