	public abstract class OldDemoModeServiceBase : Progress<FileDownloadProgressEventArgs>, IOldDemoModeService, IProgress<FileDownloadProgressEventArgs>
	{
		protected virtual string EnabledFileName => "enabled";

		protected virtual string EnabledFilePath => CombineFilePath(AssetFolderPath, EnabledFileName);

		protected abstract string LogTag { get; }

		public bool IsInDemoMode => DoesFileExistAtLocation(EnabledFilePath);

		public abstract string AssetFolderPath { get; }

		public abstract string MarketingVideoFolderPath { get; }

		public abstract string MarketingVideoFileName { get; }

		public abstract bool DoesRequireDownloadingContent { get; }

		public abstract bool ShouldDemoModeAssetsBeDeleted { get; }

		public abstract bool ShouldUseSmdmAssets { get; }

		public abstract bool CheckStoredAssetsIntegrity();

		protected abstract void DeleteAssetFolder();

		protected abstract bool DoesFileExistAtLocation(string filePath);

		protected abstract bool DoesDirectoryExistAtLocation(string directoryPath);

		protected abstract IEnumerable<string> GetFilesInsideDirectory(string directoryPath);

		protected abstract string CombineFilePath(params string[] pathParts);

		protected abstract void DeleteFile(string filePath);

		protected abstract void CreateTextFile(string filePath, string contents, bool overwriteIfExists);

		public void EnableDemoModeIfAssetsIntact()
		{
			Log.Trace(LogTag, "Checking for Demo Mode asset integrity...");
			if (CheckStoredAssetsIntegrity())
			{
				Log.Trace(LogTag, "Demo Mode assets are intact. Enabling...");
				ToggleDemoMode(enable: true);
			}
			else
			{
				Log.Trace(LogTag, "Demo Mode assets are missing or otherwise not intact.");
			}
		}

		protected virtual void ToggleDemoMode(bool enable)
		{
			if (IsInDemoMode && !enable)
			{
				DeleteFile(EnabledFilePath);
			}
			else if (!IsInDemoMode && enable)
			{
				CreateTextFile(EnabledFilePath, string.Empty, overwriteIfExists: true);
			}
		}

		public void DisableDemoMode(bool deleteAllContent = false)
		{
			ToggleDemoMode(enable: false);
			if (deleteAllContent)
			{
				DeleteAssetFolder();
			}
		}

		public virtual List<string> GetStoredAssetList()
		{
			if (!DoesDirectoryExistAtLocation(AssetFolderPath))
			{
				return null;
			}
			return GetFilesInsideDirectory(AssetFolderPath).ToList();
		}

		public bool DoesAssetExist(string assetPath)
		{
			List<string> storedAssetList = GetStoredAssetList();
			if (storedAssetList == null)
			{
				return false;
			}
			return storedAssetList.FindAll((string x) => x.EndsWith(assetPath)).Count > 0;
		}
	}
