			{
				Log.Trace(LogTag, "Retail Demo Mode asset folders already does not exist.");
				return;
			}
			Log.Trace(LogTag, "Attempting to delete Retail Demo Mode asset folder.");
			try
			{
				DeleteFolder(BasePersistentAssetFolderPath);
				if (DoesFolderExistAtLocation(BasePersistentAssetFolderPath))
				{
					Log.Error(LogTag, "Could not delete Retail Demo Mode asset folder at: " + BasePersistentAssetFolderPath);
				}
				else
				{
					Log.Trace(LogTag, "Retail Demo Mode asset folder deleted at: " + BasePersistentAssetFolderPath);
				}
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error trying to delete Retail Demo Mode asset folder at: " + BasePersistentAssetFolderPath, exception);
