		public Dictionary<string, FileDownloadReport> GetStoredAssets()
		{
			Dictionary<string, FileDownloadReport> downloadedFileReport = GetDownloadedFileReport();
			if (downloadedFileReport == null)
			{
				return new Dictionary<string, FileDownloadReport>();
			}
			return downloadedFileReport.Where((KeyValuePair<string, FileDownloadReport> x) => DoesFileExistAtLocation(ShouldUseSmdmAssets ? GenerateAssetFilePath(x.Key) : x.Value.FilePath)).ToDictionary((KeyValuePair<string, FileDownloadReport> x) => x.Key, (KeyValuePair<string, FileDownloadReport> x) => x.Value);
		}

		protected Dictionary<string, FileDownloadReport> GetDownloadedFileReport()
		{
			if (!DoesFolderExistAtLocation(AssetFolderPath))
			{
				return null;
			}
			if (!DoesFileExistAtLocation(DownloadReportFilePath))
			{
				return null;
			}
			string text;
			try
			{
				text = ReadAllTextFromFile(DownloadReportFilePath);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Could not read text from file at: " + DownloadReportFilePath, exception);
				return null;
			}
			if (string.IsNullOrWhiteSpace(text))
			{
				return null;
			}
			try
			{
				Dictionary<string, FileDownloadReport> dictionary = JsonConvert.DeserializeObject<Dictionary<string, FileDownloadReport>>(text);
				if (dictionary != null)
				{
					return dictionary;
				}
			}
			catch (Exception exception2)
			{
				Log.Error(LogTag, "Could not parse downloaded file report at: " + DownloadReportFilePath, exception2);
				Log.Error(LogTag, text);
			}
			return null;
		}

		protected bool DoesFileDownloadReportHaveCorrectFileInStorage(string fileName, FileDownloadReport report)
		{
			if (string.IsNullOrWhiteSpace(fileName))
			{
				throw new ArgumentNullException("fileName");
			}
			if (report == null)
			{
				throw new ArgumentNullException("report");
			}
			string filePath = GenerateAssetFilePath(fileName);
			if (!DoesFileExistAtLocation(filePath))
			{
				return false;
			}
			long num = -1L;
			try
			{
				num = GetFileSize(filePath);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error occurred in DoesFileDownloadReportHaveCorrectFileInStorage", exception);
				return false;
			}
			return report.ResourceBytes == num;
		}

		protected void PrepareFolderStructure()
		{
			Log.Trace(LogTag, "Creating folder at " + AssetFolderPath + " if does not exist...");
			try
			{
				CreateFolder(AssetFolderPath, overwrite: false);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error occurred while creating folder at: " + AssetFolderPath, exception);
			}
			Log.Trace(LogTag, "Creating folder at " + WorkoutsFolderPath + " if does not exist...");
			try
			{
				CreateFolder(WorkoutsFolderPath, overwrite: false);
			}
			catch (Exception exception2)
			{
				Log.Error(LogTag, "Error occurred while creating folder at: " + WorkoutsFolderPath, exception2);
			}
			if (!DoesFolderExistAtLocation(AssetFolderPath))
			{
				Log.Error(LogTag, "Unknown error occurred while creating folder at: " + AssetFolderPath);
			}
			if (!DoesFolderExistAtLocation(WorkoutsFolderPath))
			{
				Log.Error(LogTag, "Unknown error occurred while creating folder at: " + WorkoutsFolderPath);
			}
		}

		public async Task<Dictionary<string, FileDownloadReport>> SyncRetailDemoModeFilesFromFeatureFlagAndEnable(CancellationToken cancellationToken = default(CancellationToken))
		{
			Uri uri = GetAssetJsonFileUrl();
			if (string.IsNullOrWhiteSpace(uri?.AbsoluteUri))
			{
				Log.Error(LogTag, "Retail Demo Mode failed when trying to get the Url for the asset json file.");
				return null;
			}
			cancellationToken.ThrowIfCancellationRequested();
			RemoteFileConfiguration config;
			try
			{
				config = await DownloadAssetJson(uri, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Retail Demo Mode failed when trying to download the asset json file: " + uri.AbsoluteUri, exception);
				return null;
			}
			if (config.assets == null)
			{
				Log.Error(LogTag, "Retail Demo Mode failed when trying to download the asset json file: " + uri.AbsoluteUri);
				return null;
			}
			cancellationToken.ThrowIfCancellationRequested();
			Dictionary<string, FileDownloadReport> dictionary;
			if (config.assets.Count < 1)
			{
				Log.Trace(LogTag, "Retail Demo Mode downloaded empty asset file: " + uri.AbsoluteUri);
				dictionary = new Dictionary<string, FileDownloadReport>();
			}
			else
			{
				Log.Trace(LogTag, "Assets required: " + JsonConvert.SerializeObject(config.assets));
				dictionary = await DownloadAndStoreNecessaryAssetFiles(config, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			if (dictionary == null)
			{
				Log.Error(LogTag, "Retail Demo Mode failed when trying to download the necessary asset files.");
				return null;
			}
			PrepareFolderStructure();
			CreateTextFile(DownloadReportFilePath, JsonConvert.SerializeObject(dictionary, Formatting.Indented), overwriteIfExists: true);
			if (!DoesFileExistAtLocation(DownloadReportFilePath))
			{
				Log.Error(LogTag, "Retail Demo Mode results file not found at " + DownloadReportFilePath);
				return null;
			}
			Dictionary<string, FileDownloadReport> storedAssets = GetStoredAssets();
			Log.Trace(LogTag, "Verifying downloaded assets...");
			bool flag = true;
			string name = Enum.GetName(typeof(ConsoleType), CurrentConsoleType);
			foreach (RemoteAsset asset in config.assets)
			{
				if (!asset.consoleTypes.Contains(name))
				{
					continue;
				}
				Log.Trace(LogTag, "Verifying " + asset.fileName + "...");
				if (!storedAssets.ContainsKey(asset.fileName))
				{
					Log.Trace(LogTag, "Asset file " + asset.fileName + " was not found in local results file.");
					flag = false;
					continue;
				}
				FileDownloadReport fileDownloadReport = storedAssets[asset.fileName];
				if (!fileDownloadReport.DownloadedSuccessfully || !DoesFileExistAtLocation(fileDownloadReport.FilePath))
				{
					Log.Trace(LogTag, "Asset file " + asset.fileName + " was not downloaded successfully.");
					flag = false;
					continue;
				}
				string filePath = fileDownloadReport.FilePath;
				long fileSize;
				try
				{
					fileSize = GetFileSize(filePath);
				}
				catch (Exception exception2)
				{
					Log.Trace(LogTag, "Exception occurred trying to get the size for the file at: " + filePath, exception2);
					flag = false;
					continue;
				}
				if (fileDownloadReport.ResourceBytes != fileSize || fileDownloadReport.ResourceBytes != fileDownloadReport.DownloadedBytes)
				{
					Log.Trace(LogTag, "Asset file " + asset.fileName + " has different file size from report.");
					flag = false;
				}
			}
			if (!flag)
			{
				Log.Trace(LogTag, "Retail Demo Mode file verification check failed.");
				Log.Trace(LogTag, "Retail Demo Mode is NOT enabled.");
				return null;
			}
			ToggleDemoMode(enable: true);
			if (!base.IsInDemoMode)
			{
				Log.Error(LogTag, string.Format("Could not enable Retail Demo Mode. {0} is {1} despite successful asset download.", "IsInDemoMode", base.IsInDemoMode));
				return null;
			}
			Log.Trace(LogTag, "Retail Demo Mode successfully enabled!");
			Log.Trace(LogTag, "Download report:");
			Log.Trace(LogTag, JsonConvert.SerializeObject(dictionary, Formatting.Indented));
			return dictionary;
		}

		protected Task<FileDownloadReport> DownloadAndStoreAssetForItemIfNecessary(string filename, Uri assetUrl, string filepath, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (string.IsNullOrEmpty(filename))
			{
				throw new ArgumentNullException("filename");
			}
			if (string.IsNullOrWhiteSpace(assetUrl?.AbsoluteUri))
			{
				throw new ArgumentNullException("assetUrl");
			}
			if (string.IsNullOrEmpty(filepath))
			{
				throw new ArgumentNullException("filename");
			}
			string newValue = consoleTypeDirectoryNameMapping[CurrentConsoleType];
			string path = filepath.Replace("{consoleType}", newValue);
			string filepath2 = Path.Combine(path, filename);
			return DownloadAndStoreAssetForItemIfNecessaryInternal(filename, assetUrl, filepath2, cancellationToken);
		}

		private async Task<FileDownloadReport> DownloadAndStoreAssetForItemIfNecessaryInternal(string filename, Uri assetUrl, string filepath, CancellationToken cancellationToken = default(CancellationToken))
		{
			Log.Trace(LogTag, "Retail Demo Mode asset file " + filename + " downloading from: " + assetUrl.AbsoluteUri);
			return await DownloadAndStoreAssetFileIfNecessary(assetUrl, filepath, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		}

		protected Task<Dictionary<string, FileDownloadReport>> DownloadAndStoreNecessaryAssetFiles(RemoteFileConfiguration config, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (config == null)
			{
				throw new ArgumentNullException("config");
			}
			return DownloadAndStoreNecessaryAssetFilesInternal(config, cancellationToken);
		}

		private async Task<Dictionary<string, FileDownloadReport>> DownloadAndStoreNecessaryAssetFilesInternal(RemoteFileConfiguration config, CancellationToken cancellationToken = default(CancellationToken))
		{
			Dictionary<string, FileDownloadReport> results = new Dictionary<string, FileDownloadReport>();
			PrepareFolderStructure();
			if (config.assets.CountSafe() < 1)
			{
				return results;
			}
			string stringConsoleType = Enum.GetName(typeof(ConsoleType), CurrentConsoleType);
			foreach (RemoteAsset asset in config.assets)
			{
				if (asset.consoleTypes.Contains(stringConsoleType))
				{
					FileDownloadReport fileDownloadReport = await DownloadAndStoreAssetForItemIfNecessary(asset.fileName, new Uri(asset.url), asset.filePath, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					if (fileDownloadReport != null)
					{
						results.Add(asset.fileName, fileDownloadReport);
					}
				}
				else
				{
					Log.Debug(LogTag, "Console: " + stringConsoleType + " is not in item for " + asset.fileName);
				}
			}
			return results;
		}

		protected Task<RemoteFileConfiguration> DownloadAssetJson(Uri assetJsonFileUrl, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (assetJsonFileUrl == null)
			{
				throw new ArgumentNullException("assetJsonFileUrl");
			}
			return DownloadAssetJsonInternal(assetJsonFileUrl, cancellationToken);
		}

		private async Task<RemoteFileConfiguration> DownloadAssetJsonInternal(Uri assetJsonFileUrl, CancellationToken cancellationToken = default(CancellationToken))
		{
			try
			{
				FileDownloadProgressChangedOccurred("Asset Json File", 1L, 0L);
				RemoteFileConfiguration result = await DownloadAndParseFromJsonResource(assetJsonFileUrl, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
				FileDownloadProgressChangedOccurred("Asset Json File", 1L, 1L);
				return result;
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Could not download Retail Demo asset json file.", exception);
			}
			return null;
		}

		protected virtual Task<RemoteFileConfiguration> DownloadAndParseFromJsonResource(Uri assetJsonFileUrl, CancellationToken cancellationToken = default(CancellationToken))
		{
			if (string.IsNullOrWhiteSpace(assetJsonFileUrl?.AbsoluteUri))
			{
				throw new ArgumentNullException("assetJsonFileUrl");
			}
			return DownloadAndParseFromJsonResourceInternal(assetJsonFileUrl, cancellationToken);
		}

		private static async Task<RemoteFileConfiguration> DownloadAndParseFromJsonResourceInternal(Uri assetJsonFileUrl, CancellationToken cancellationToken = default(CancellationToken))
		{
			return await JsonDownloadUtil.DownloadAndParseJson<RemoteFileConfiguration>(assetJsonFileUrl.AbsoluteUri, null, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		}

		public Uri GetAssetJsonFileUrl()
		{
			try
			{
				return new Uri(featureFlagManager?.GetString(RetailDemoModeContentJsonUrlFlag));
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error getting asset json file url from LD.", exception);
			}
			return null;
		}

		protected void FileDownloadProgressChangedOccurred(string fileName, long fileBytes, long downloadedBytes)
		{
			OnReport(new FileDownloadProgressEventArgs
			{
				Filename = fileName,
				FileSizeBytes = fileBytes,
				DownloadedBytes = downloadedBytes
			});
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				featureFlagManager = null;
			}
		}

		protected abstract void CreateFolder(string folderPath, bool overwrite);

		protected abstract void DeleteFolder(string folderPath);

		protected abstract bool DoesFolderExistAtLocation(string folderPath);

		protected abstract Task<FileDownloadReport> DownloadAndStoreAssetFileIfNecessary(Uri assetFileUrl, string assetFilePath, CancellationToken cancellationToken = default(CancellationToken));

		protected abstract string GetBaseName(string filePath);

		protected abstract List<string> GetFilePathsInFolder(string folderPath);

		protected abstract long GetFileSize(string filePath);

		protected abstract string ReadAllTextFromFile(string filePath);

		[SpecialName]
		void IOldRetailDemoMode1Service.add_ProgressChanged(EventHandler<FileDownloadProgressEventArgs> value)
		{
			base.ProgressChanged += value;
		}

		[SpecialName]
		void IOldRetailDemoMode1Service.remove_ProgressChanged(EventHandler<FileDownloadProgressEventArgs> value)
		{
			base.ProgressChanged -= value;
		}
	}
