		private const string ConsoleTypeDirectoryMirror = "mirror";

		private const string JsonFileExt = ".json";

		private const string VideoFileExt = ".mp4";

		private readonly IDictionary<ConsoleType, string> ConsoleTypeDirectoryNameMapping = new Dictionary<ConsoleType, string>
		{
			{
				ConsoleType.Treadmill,
				"treadmill"
			},
			{
				ConsoleType.InclineTrainer,
				"treadmill"
			},
			{
				ConsoleType.Bike,
				"bike"
