		public string GetWorkoutDirectoryPathForConsoleType(ConsoleType consoleType)
		{
			if (!ConsoleTypeDirectoryNameMapping.ContainsKey(consoleType))
			{
				return null;
			}
			return Path.Combine(AbsoluteWorkoutContentPath, ConsoleTypeDirectoryNameMapping[consoleType]);
		}

		private string GetFirstFileInConsoleDirectoryWithExtension(ConsoleType consoleType, string extension)
		{
			string workoutDirectoryPathForConsoleType = GetWorkoutDirectoryPathForConsoleType(consoleType);
			if (string.IsNullOrWhiteSpace(workoutDirectoryPathForConsoleType))
			{
				return null;
			}
			return GetFilesWithinDirectory(workoutDirectoryPathForConsoleType)?.FirstOrDefault((string x) => x.EndsWith(extension, StringComparison.InvariantCultureIgnoreCase));
		}

		public Workout GetWorkoutForConsoleType(ConsoleType consoleType)
		{
			string firstFileInConsoleDirectoryWithExtension = GetFirstFileInConsoleDirectoryWithExtension(consoleType, ".json");
			if (string.IsNullOrWhiteSpace(firstFileInConsoleDirectoryWithExtension))
			{
				return null;
			}
			if (!DoesFileExist(firstFileInConsoleDirectoryWithExtension))
			{
				Log.Error("RetailDemoMode", "No workout json file exists.");
				return null;
			}
			try
			{
				return JsonConvert.DeserializeObject<Workout>(ReadFileContents(firstFileInConsoleDirectoryWithExtension));
			}
			catch (Exception exception)
			{
				Log.Error("RetailDemoMode", "Could not deserialize workout json at " + firstFileInConsoleDirectoryWithExtension, exception);
			}
			return null;
		}

		public string GetWorkoutVideoFilePathForConsoleType(ConsoleType consoleType)
		{
			return GetFirstFileInConsoleDirectoryWithExtension(consoleType, ".mp4");
		}

		public bool WorkoutAssetsExistForConsoleType(ConsoleType consoleType)
		{
			if (GetWorkoutForConsoleType(consoleType) != null)
			{
				return DoesFileExist(GetWorkoutVideoFilePathForConsoleType(consoleType));
			}
			return false;
		}

		protected abstract string[] GetFilesWithinDirectory(string directoryPath);

		protected abstract bool DoesFileExist(string path);

		protected abstract string ReadFileContents(string path);
	}
