	public sealed class RetailDemoMode2Settings : IRetailDemoMode2Settings, IDisposable
	{
		private sealed class SerializableSettings
		{
			public float ScreensaverVolume { get; set; }

			public Manufacturer SelectedManufacturer { get; set; }
		}

		private const string filename = ".settings.json";

		private const string tag = "RetailDemoMode2Settings";

		private readonly string basePath;

		private readonly string filepath;

		private readonly Wolf.Core.Util.Downloader.IFileSystem fileSystem;

		private SerializableSettings _settings;

		private SerializableSettings Settings
		{
			get
			{
				if (_settings == null)
				{
					_settings = Load();
				}
				return _settings;
			}
		}

		public bool IsInDemoMode => Settings.SelectedManufacturer != Manufacturer.None;

		public float ScreensaverVolume
		{
			get
			{
				return Settings.ScreensaverVolume;
			}
			set
			{
				Settings.ScreensaverVolume = value;
				Save();
			}
		}

		public Manufacturer SelectedManufacturer => Settings.SelectedManufacturer;

		public RetailDemoMode2Settings(string basePath, Wolf.Core.Util.Downloader.IFileSystem fileSystem)
		{
			this.basePath = basePath;
			this.fileSystem = fileSystem;
			filepath = Path.Combine(basePath, ".settings.json");
		}

		private SerializableSettings Load()
		{
			try
			{
				if (fileSystem.FileExists(filepath))
				{
					string value = fileSystem.ReadAllText(filepath);
					SerializableSettings serializableSettings = JsonConvert.DeserializeObject<SerializableSettings>(value);
					if (serializableSettings == null)
					{
						Log.Error("RetailDemoMode2Settings", "Error loading retail demo mode 2.0 settings. Loaded settings object was null.");
						serializableSettings = new SerializableSettings();
					}
					return serializableSettings;
				}
				return new SerializableSettings();
			}
			catch (JsonReaderException exception)
			{
				Log.Error("RetailDemoMode2Settings", "Error loading retail demo mode 2.0 settings.", exception);
				return new SerializableSettings();
			}
			catch (Exception exception2)
			{
				Log.Error("RetailDemoMode2Settings", "Error loading retail demo mode 2.0 settings.", exception2);
				return new SerializableSettings();
			}
		}

		private void Save()
		{
			try
			{
				fileSystem.CreateDirectory(basePath);
				string contents = JsonConvert.SerializeObject(Settings);
				fileSystem.WriteAllText(filepath, contents);
			}
			catch (Exception exception)
			{
				Log.Error("RetailDemoMode2Settings", "Error saving retail demo mode 2.0 settings.", exception);
			}
		}

		public void SetIsInDemoModeWithSelectedManufacturer(Manufacturer selectedManufacturer)
		{
			Settings.SelectedManufacturer = selectedManufacturer;
			Save();
		}

		public void SetIsInDemoModeFalse()
		{
			Settings.SelectedManufacturer = Manufacturer.None;
			Save();
		}

		private void Dispose(bool disposing)
		{
			if (disposing)
			{
				Save();
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
}
namespace Wolf.Core.DemoMode
{
	public class DemoModeServiceSelector : IDemoModeService
	{
		private const string LogTag = "DemoModeServiceSelector";

		private IDemoModeService _selectedService;

		private readonly IDemoModeService rdm1Service;

		private readonly IDemoModeService rdm2Service;

		private IDemoModeService SelectedService
		{
			get
			{
				return _selectedService;
			}
			set
			{
				_selectedService = value;
				Log.Trace("DemoModeServiceSelector", "Selected " + value?.Id + " service.");
			}
		}

		private IDemoModeService OtherService
		{
			get
			{
				if (SelectedService == null)
				{
					return null;
				}
				if (SelectedService != rdm1Service)
				{
					return rdm1Service;
				}
				return rdm2Service;
			}
		}

		public string Id => SelectedService?.Id ?? "DemoModeSelector";

		public bool IsInDemoMode
		{
			get
			{
				if (!rdm2Service.IsInDemoMode)
				{
					return rdm1Service.IsInDemoMode;
				}
				return true;
			}
		}

		public bool RequiresDownload
		{
			get
			{
				if (!rdm2Service.RequiresDownload)
				{
					return rdm1Service.RequiresDownload;
				}
				return true;
			}
		}

		public DemoModeServiceSelector(IDemoModeService rdm1Service, IDemoModeService rdm2Service)
		{
			this.rdm1Service = rdm1Service;
			this.rdm2Service = rdm2Service;
		}

		public bool CanEnterDemoMode()
		{
			if (!rdm2Service.CanEnterDemoMode())
			{
				return rdm1Service.CanEnterDemoMode();
			}
			return true;
		}

		public async Task EnterDemoModeAsync()
		{
			SelectDemoModeServiceAsync();
			if (CanDeleteAssets())
			{
				DeleteAllAssets();
			}
			await SelectedService.EnterDemoModeAsync();
		}

		public void ResumeDemoMode()
		{
			if (!IsInDemoMode)
			{
				throw new InvalidOperationException("ResumeDemoMode called when not in demo mode.");
			}
			SelectedService = (rdm2Service.IsInDemoMode ? rdm2Service : rdm1Service);
			SelectedService.ResumeDemoMode();
		}

		public async Task ExitDemoModeAsync()
		{
			if (SelectedService != null)
			{
				await SelectedService.ExitDemoModeAsync();
			}
		}

		public void ForceExitDemoMode()
		{
			SelectedService?.ForceExitDemoMode();
		}

		public bool CanDeleteAssets()
		{
			if (!rdm2Service.CanDeleteAssets())
			{
				return rdm1Service.CanDeleteAssets();
			}
			return true;
		}

		public void DeleteAllAssets()
		{
			rdm1Service.DeleteAllAssets();
			rdm2Service.DeleteAllAssets();
		}

		public void DemoWorkoutCompleted()
		{
			SelectedService.DemoWorkoutCompleted();
		}

		private void SelectDemoModeServiceAsync()
		{
			if (!rdm1Service.CanEnterDemoMode() && !rdm2Service.CanEnterDemoMode())
			{
				SelectedService = null;
				throw new TaskCanceledException();
			}
			if (!rdm1Service.CanEnterDemoMode() && rdm2Service.CanEnterDemoMode())
			{
				SelectedService = rdm2Service;
			}
			else if (rdm1Service.CanEnterDemoMode() && !rdm2Service.CanEnterDemoMode())
			{
				SelectedService = rdm1Service;
			}
			else
			{
				SelectedService = rdm2Service;
			}
		}
	}
	public interface IDemoModeService
	{
		string Id { get; }

		bool IsInDemoMode { get; }

		bool RequiresDownload { get; }

		bool CanEnterDemoMode();

		Task EnterDemoModeAsync();

		void ResumeDemoMode();

		Task ExitDemoModeAsync();

		void ForceExitDemoMode();

		bool CanDeleteAssets();

		void DeleteAllAssets();

		void DemoWorkoutCompleted();
	}
}
