	public class RetailDemoMode2WorkoutPresenter
	{
		private const string LogTag = "RetailDemoMode2WorkoutPresenter";

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IStartWorkoutService startWorkoutService;

		private readonly BaseViewModel baseViewModel;

		private readonly IWolfAnalytics wolfAnalytics;

		private readonly IRetailDemoLocalWorkoutService localWorkoutService;

		private bool IsInDmk
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.PhysicalConsole?.LatestBasicInfo?.CurrentState == ConsoleState.SafetyKeyRemoved;
			}
		}

		private bool IsIdle
		{
			get
			{
				ICurrentConsoleService obj = currentConsoleService;
				if (obj == null)
				{
					return false;
				}
				return obj.PhysicalConsole?.LatestBasicInfo?.CurrentState == ConsoleState.Idle;
			}
		}

		private ConsoleType CurrentConsoleType => currentConsoleService.PhysicalConsole?.ConsoleInfo?.MachineType ?? ConsoleType.None;

		public RetailDemoMode2WorkoutPresenter(ICurrentConsoleService currentConsoleService, IStartWorkoutService startWorkoutService, IRetailDemoLocalWorkoutService localWorkoutService, BaseViewModel baseViewModel, IWolfAnalytics wolfAnalytics)
		{
			this.currentConsoleService = currentConsoleService;
			this.startWorkoutService = startWorkoutService;
			this.localWorkoutService = localWorkoutService;
			this.baseViewModel = baseViewModel;
			this.wolfAnalytics = wolfAnalytics;
		}

		public async Task<bool> StartWorkoutAsync(float volume)
		{
			if (IsInDmk)
			{
				Log.Trace("RetailDemoMode2WorkoutPresenter", "Can't start demo workout while in DMK state.");
				PromptInsertDMK();
				return false;
			}
			if (!IsIdle && CurrentConsoleType != ConsoleType.Mirror)
			{
				Log.Trace("RetailDemoMode2WorkoutPresenter", "Can't start workout due to unknown state: " + (currentConsoleService?.PhysicalConsole?.LatestBasicInfo?.CurrentState).ToString());
				PromptUnknownStateError();
				return false;
			}
			Mvx.RegisterSingleton(localWorkoutService);
			if (localWorkoutService.WorkoutAssetsExistForConsoleType(CurrentConsoleType))
			{
				iFit.Api.DataObjects.Workout workout = localWorkoutService.GetWorkoutForConsoleType(CurrentConsoleType);
				return await Task.Run(async () => await BeginDemoWorkout(workout, volume).ConfigureAwait(continueOnCapturedContext: false));
			}
			return false;
		}

		private async Task<bool> BeginDemoWorkout(iFit.Api.DataObjects.Workout workout, float volume)
		{
			if (workout == null)
			{
				return false;
			}
			WorkoutRunnerContext runningContext = new WorkoutRunnerContext(iFit.Api.DataObjects.Workout.WorkoutContext.OnDemand, null)
			{
				DisableCompetition = true
			};
			bool flag = await startWorkoutService.DoStartWorkout(workout, runningContext, baseViewModel.WaitForConsoleReady, null).ConfigureAwait(continueOnCapturedContext: false);
			if (flag)
			{
				IDeviceInformation deviceInformation = Mvx.Resolve<IDeviceInformation>();
				IMediaSettings mediaSettings = Mvx.Resolve<IMediaSettings>();
				IPlatformMediaVolumeService platformMediaVolumeService = Mvx.Resolve<IPlatformMediaVolumeService>();
				IVolumeFacade volumeFacade = Mvx.Resolve<IVolumeFacade>();
				InWorkoutSystemVolumeInteractor systemVolumeInteractor = new InWorkoutSystemVolumeInteractor(currentConsoleService, deviceInformation, mediaSettings, platformMediaVolumeService, volumeFacade, 200L);
				int consoleVolume = SystemVolumeHelper.MapVolume(volume);
				systemVolumeInteractor.SetConsoleVolume(consoleVolume);
				if (systemVolumeInteractor.IsProcessingVolumeChanges)
				{
					Log.Trace("RetailDemoMode2WorkoutPresenter", "systemVolumeInteractor is attempting to set console volume asynchronously...");
					systemVolumeInteractor.WhenVolumeChangeCompleted.Take(1).SubscribeWithErrorLogging(delegate(bool result)
					{
						Log.Trace("RetailDemoMode2WorkoutPresenter", string.Format("{0} fired {1}: {2}", "systemVolumeInteractor", "WhenVolumeChangeCompleted", result));
						systemVolumeInteractor?.Dispose();
						systemVolumeInteractor = null;
					});
				}
				else
				{
					Log.Trace("RetailDemoMode2WorkoutPresenter", "systemVolumeInteractor updated volume synchronously.");
					systemVolumeInteractor?.Dispose();
					systemVolumeInteractor = null;
				}
				Dictionary<string, object> properties = new Dictionary<string, object>
				{
					{ "softwareNumber", deviceInformation.SoftwareNumber },
					{ "machineType", CurrentConsoleType }
				};
				wolfAnalytics.OnRetailDemoModeWorkoutStartedEvent(properties).SafeFireAndForget();
			}
			else
			{
				Log.Error("RetailDemoMode2WorkoutPresenter", "Could not begin RDM demo workout.");
			}
			return flag;
		}

		private void PromptInsertDMK()
		{
			baseViewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.retail_demo_mode_insert_dmk_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_insert_dmk_message, delegate
			{
			}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
		}

		private void PromptUnknownStateError()
		{
			baseViewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.retail_demo_mode_unknown_state_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_unknown_state_message, delegate
			{
			}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
		}
	}
}
