		public bool ProFormEnabled => selectedManufacturer.Value == Manufacturer.ProForm;

		public EnableDemoModeDialogViewModel(ILocalSettings settings)
			: base(settings)
		{
			try
			{
				ConfirmCommand = new MvxCommand(DoConfirm);
				CancelCommand = new MvxCommand(DoCancel);
				EnableNordicTrackCommand = new MvxCommand(delegate
				{
					UpdateManufacturer(Manufacturer.NordicTrack);
				});
				EnableProFormCommand = new MvxCommand(delegate
				{
					UpdateManufacturer(Manufacturer.ProForm);
				});
