		public void GoToScreensaver(string videoFilePath, float volume, DemoModeVideoViewModel.IDelegate vmDelegate, bool clearBackStack = false)
		{
			Mvx.RegisterSingleton(vmDelegate);
			DemoModeVideoViewModel.NavObject navObject = new DemoModeVideoViewModel.NavObject
			{
				VideoFilePath = videoFilePath,
				HideSkipButton = true,
				HideVolumeButton = true,
				LoopVideo = true,
				InitialVolume = volume
			};
			if (clearBackStack)
			{
