				{
					ShowViewModel<RetailDemoModeVideoViewModel>(navObject, ShireViewParams.ClearStackToRequested());
				});
			}
			else
			{
				InvokeOnMainThread(delegate
				{
					ShowViewModel<RetailDemoModeVideoViewModel>(navObject);
				});
