	public class RetailDemoMode2Service : IDemoModeService, DemoModeVideoViewModel.IDelegate, RetailDemoMode2MarketingViewModel.IDelegate
	{
		public interface IDelegate
		{
			Task<Manufacturer> PromptForManufacturer();

			Task GoToDownloadProgressView(IRetailDemoMode2SingleNodeRepository repository, IRetailDemoMode2DownloaderFactory downloaderFactory);

			void GoToScreensaver(string videoFilePath, float volume, DemoModeVideoViewModel.IDelegate vmDelegate, bool clearBackStack = false);

			void GoToMarketingView(RetailDemoMode2MarketingViewModel.IDelegate vmDelegate, IRetailDemoMode2SingleNodeRepository repository);

			Task<bool> StartDemoWorkout(IRetailDemoMode2SingleNodeRepository repository, float volume);

			void ExitDemoMode();

			void DoClose();
		}

		private const string LogTag = "RetailDemoMode2Service";

		private const float DefaultScreensaverVolume = 0.2f;

		private const float DefaultWorkoutVolume = 0.5f;

		private readonly ICurrentConsoleService consoleService;

		private readonly IRetailDemoMode2Settings retailDemoMode2Settings;

		private readonly IRetailDemoMode2Repository repository;

		private readonly IRetailDemoMode2DownloaderFactory downloaderFactory;

		private readonly ITouchMonitor touchMonitor;

		private readonly IBleRadioStatusService bleRadioStatusService;

		private readonly ConsoleType consoleType;

		public IDictionary<ConsoleType, ConsoleType> consoleTypeDirectoryNameMapping = new Dictionary<ConsoleType, ConsoleType>
		{
			{
				ConsoleType.Treadmill,
				ConsoleType.Treadmill
			},
			{
				ConsoleType.InclineTrainer,
				ConsoleType.Treadmill
			},
			{
				ConsoleType.Bike,
				ConsoleType.Bike
			},
			{
				ConsoleType.SpinBike,
				ConsoleType.Bike
			},
			{
				ConsoleType.Elliptical,
				ConsoleType.Elliptical
			},
			{
				ConsoleType.Strider,
				ConsoleType.Elliptical
			},
			{
				ConsoleType.FreeStrider,
				ConsoleType.Elliptical
			},
			{
				ConsoleType.VerticalElliptical,
				ConsoleType.Elliptical
			},
			{
				ConsoleType.Rower,
				ConsoleType.Rower
			}
		};

		public HashSet<Enum> SupportedManufacturers = new HashSet<Enum>
		{
			Manufacturer.NordicTrack,
			Manufacturer.ProForm
		};

		private readonly TimeSpan ScreensaverTimeout = TimeSpan.FromMinutes(1.0);

		private IDelegate Delegate { get; }

		private bool ConsoleTypeIsSupported => consoleTypeDirectoryNameMapping.ContainsKey(consoleService?.PhysicalConsole?.ConsoleInfo?.MachineType ?? ConsoleType.None);

		public string Id => "RDM2";

		public bool IsInDemoMode => retailDemoMode2Settings.IsInDemoMode;

		public bool RequiresDownload => repository.RequiresDownload;

		public RetailDemoMode2Service(IDelegate @delegate, ICurrentConsoleService consoleService, IRetailDemoMode2Settings retailDemoMode2Settings, IRetailDemoMode2Repository repository, IRetailDemoMode2DownloaderFactory downloaderFactory, ITouchMonitor touchMonitor, IBleRadioStatusService bleRadioStatusService)
		{
			Delegate = @delegate;
			this.consoleService = consoleService;
			this.retailDemoMode2Settings = retailDemoMode2Settings;
			this.repository = repository;
			this.downloaderFactory = downloaderFactory;
			this.touchMonitor = touchMonitor;
			this.bleRadioStatusService = bleRadioStatusService;
			if (consoleTypeDirectoryNameMapping.ContainsKey(consoleService.ConsoleType))
			{
				consoleType = consoleTypeDirectoryNameMapping[consoleService.ConsoleType];
			}
			else
			{
				consoleType = consoleService.ConsoleType;
			}
			if (consoleService.ConsoleType != consoleType)
			{
				Log.Trace("RetailDemoMode2Service", $"Console type {consoleService.ConsoleType} ({consoleType}) is supported = {ConsoleTypeIsSupported}.");
			}
			else
			{
				Log.Trace("RetailDemoMode2Service", $"Console type {consoleService.ConsoleType} is supported = {ConsoleTypeIsSupported}.");
			}
		}

		public bool CanEnterDemoMode()
		{
			return ConsoleTypeIsSupported;
		}

		public async Task EnterDemoModeAsync()
		{
			bleRadioStatusService.DisableBleRadio();
			if (IsInDemoMode)
			{
				ResumeDemoMode();
				return;
			}
			Manufacturer manufacturer = await Delegate.PromptForManufacturer();
			repository.Select(manufacturer, consoleType);
			retailDemoMode2Settings.SetIsInDemoModeWithSelectedManufacturer(manufacturer);
			await DownloadAssetsIfNecessaryAsync();
			(repository as IRetailDemoMode2DeletableRepository)?.DeleteAllAssetsExceptSelected();
			retailDemoMode2Settings.ScreensaverVolume = 0.2f;
			GoToScreensaver(clearBackStack: true);
		}

		private async Task DownloadAssetsIfNecessaryAsync()
		{
			if (!repository.Selected.AreAssetsReady())
			{
				try
				{
					await Delegate.GoToDownloadProgressView(repository.Selected, downloaderFactory);
				}
				catch (Exception exception)
				{
					Log.Error("RetailDemoMode2Service", "Error downloading RDM2 assets", exception);
					ForceExitDemoMode();
					throw;
				}
			}
		}

		public void ResumeDemoMode()
		{
			if (repository.Selected == null)
			{
				repository.Select(retailDemoMode2Settings.SelectedManufacturer, consoleType);
			}
			if (repository.Selected.AreAssetsReady())
			{
				GoToScreensaver();
				return;
			}
			Task.Run(async delegate
			{
				await DownloadAssetsIfNecessaryAsync();
				GoToScreensaver();
			});
		}

		public Task ExitDemoModeAsync()
		{
			ExitDemoModeInternal();
			return Task.CompletedTask;
		}

		public void ForceExitDemoMode()
		{
			if (IsInDemoMode)
			{
				ExitDemoModeInternal();
			}
		}

		private void ExitDemoModeInternal()
		{
			retailDemoMode2Settings.SetIsInDemoModeFalse();
			StopScreensaverTimer();
			DeleteAllAssets();
			Delegate.ExitDemoMode();
			bleRadioStatusService.EnableBleRadio();
		}

		public bool CanDeleteAssets()
		{
			return (repository as IRetailDemoMode2DeletableRepository)?.CanDeleteAssets() ?? false;
		}

		public void DeleteAllAssets()
		{
			(repository as IRetailDemoMode2DeletableRepository)?.DeleteAllAssets();
		}

		public void DemoWorkoutCompleted()
		{
			GoToMarketingView();
		}

		private void GoToMarketingView()
		{
			StartScreensaverTimer();
			Delegate.GoToMarketingView(this, repository.Selected);
		}

		private Task<bool> StartDemoWorkout()
		{
			StopScreensaverTimer();
			return Delegate.StartDemoWorkout(repository.Selected, 0.5f);
		}

		private void GoToScreensaver(bool clearBackStack = false)
		{
			Delegate.DoClose();
			StopScreensaverTimer();
			Delegate.GoToScreensaver(repository.Selected.ScreensaverVideoFilePath, retailDemoMode2Settings.ScreensaverVolume, this, clearBackStack);
		}

		public Task<bool> ScreenTouched()
		{
			return StartDemoWorkout();
		}

		public void ScreensaverVolumeChanged(float volume)
		{
			retailDemoMode2Settings.ScreensaverVolume = volume;
		}

		public Task<bool> RepeatWorkout()
		{
			return StartDemoWorkout();
		}

		public void ReturnToScreensaver()
		{
			GoToScreensaver();
		}

		public float GetScreensaverVolume()
		{
			return retailDemoMode2Settings.ScreensaverVolume;
		}

		public void SetScreensaverVolume(float volume)
		{
			retailDemoMode2Settings.ScreensaverVolume = volume;
		}

		private void StopScreensaverTimer()
		{
			ITouchMonitor obj = touchMonitor;
			obj.TestTimeoutElapsed = (EventHandler)System.Delegate.Remove(obj.TestTimeoutElapsed, new EventHandler(TestScreensaverTimeoutElapsed));
			touchMonitor.IsActive = false;
		}

		private void StartScreensaverTimer()
		{
			touchMonitor.UpdateLastObservedTouch();
			ITouchMonitor obj = touchMonitor;
			obj.TestTimeoutElapsed = (EventHandler)System.Delegate.Remove(obj.TestTimeoutElapsed, new EventHandler(TestScreensaverTimeoutElapsed));
			ITouchMonitor obj2 = touchMonitor;
			obj2.TestTimeoutElapsed = (EventHandler)System.Delegate.Combine(obj2.TestTimeoutElapsed, new EventHandler(TestScreensaverTimeoutElapsed));
			touchMonitor.IsActive = true;
		}

		private void TestScreensaverTimeoutElapsed(object sender, EventArgs e)
		{
			if (IsInDemoMode && sender is ITouchMonitor touchMonitor && touchMonitor.SecondsSinceLastTouch >= ScreensaverTimeout.TotalSeconds)
			{
				GoToScreensaver();
			}
		}
	}
}
