	public class RetailDemoMode2DeletableRepository : IRetailDemoMode2Repository, IRetailDemoMode2DeletableRepository
	{
		private const string LogTag = "RetailDemoMode2DeletableRepository";

		private const string DemoMode2Path = "/sdcard/.demoMode2";

		private readonly IRetailDemoMode2Repository baseRepository;

		private readonly string basePath;

		private readonly Wolf.Core.Util.Downloader.IFileSystem fileSystem;

		public bool RequiresDownload => baseRepository.RequiresDownload;

		public IRetailDemoMode2SingleNodeRepository Selected => baseRepository.Selected;

		public RetailDemoMode2DeletableRepository(IRetailDemoMode2Repository baseRepository, Wolf.Core.Util.Downloader.IFileSystem fileSystem, string basePath)
		{
			this.baseRepository = baseRepository;
			this.fileSystem = fileSystem;
			this.basePath = basePath;
		}

		public void Select(Manufacturer manufacturer, ConsoleType consoleType)
		{
			baseRepository.Select(manufacturer, consoleType);
		}

		public bool CanDeleteAssets()
		{
			if (fileSystem.DirectoryExists(basePath))
			{
				return fileSystem.GetFiles(basePath, recursive: true).Any();
			}
			return false;
		}

		public void DeleteAllAssets()
		{
			if (fileSystem.DirectoryExists(basePath))
			{
				fileSystem.DeleteDirectory(basePath, recursive: true);
			}
			if (fileSystem.DirectoryExists("/sdcard/.demoMode2"))
			{
				fileSystem.DeleteDirectory("/sdcard/.demoMode2", recursive: true);
			}
		}

		public void DeleteAllAssetsExceptSelected()
		{
			if (Selected == null)
			{
				InvalidOperationException ex = new InvalidOperationException("RetailDemoMode2Repository.DeleteAllAssetsExceptSelected called when Selected is null.");
				Log.Error("RetailDemoMode2DeletableRepository", "Error deleting all assets except selected.", ex);
				throw ex;
			}
			string[] files = fileSystem.GetFiles(basePath, recursive: true);
			files.DoForEach(delegate(string filePath)
			{
				if (!Path.GetFileName(filePath).StartsWith(".") && filePath != Selected.ScreensaverVideoFilePath && filePath != Selected.WorkoutVideoFilePath && filePath != Selected.WorkoutDataFilePath && filePath != Selected.MarketingHeaderFilename && !Enumerable.Contains(Selected.MarketingFeaturesFilenames, filePath) && filePath != Selected.MarketingTrainersFilename && filePath != Selected.MarketingWorkoutsFilename && filePath != Selected.MarketingVideoFilename)
				{
					fileSystem.DeleteFile(filePath);
				}
			});
			string[] directories = fileSystem.GetDirectories(basePath);
			directories.DoForEach(delegate(string path)
			{
				if (!fileSystem.GetFiles(path, recursive: true).Any())
				{
					fileSystem.DeleteDirectory(path, recursive: true);
				}
			});
			if (fileSystem.DirectoryExists("/sdcard/.demoMode2"))
			{
				fileSystem.DeleteDirectory("/sdcard/.demoMode2", recursive: true);
			}
		}
	}
	public class RetailDemoMode2Repository : IRetailDemoMode2Repository
	{
		private const string allAssetsListFilename = ".allAssetsList.json";

		private const string LogTag = "RetailDemoMode2Repository";

		private readonly IRetailDemoMode2SingleNodeRepositoryFactory repositoryFactory;

		private readonly string basePath;

		private readonly Wolf.Core.Util.Downloader.IFileSystem fileSystem;

		private AllAssetsList _allAssetsList;

		private AllAssetsList AllAssetsList
		{
			get
			{
				string allAssetsListFilePath = GetAllAssetsListFilePath(basePath);
				if (_allAssetsList == null)
				{
					_allAssetsList = LoadAllAssetsList(fileSystem, allAssetsListFilePath);
				}
				if (_allAssetsList == null)
				{
					try
					{
						_allAssetsList = CreateDefaultAllAssetsList();
						string contents = JsonConvert.SerializeObject(_allAssetsList);
						fileSystem.CreateDirectory(basePath);
						fileSystem.WriteAllText(allAssetsListFilePath, contents);
					}
					catch (Exception exception)
					{
						Log.Error("RetailDemoMode2Repository", "Error saving default assets list to " + allAssetsListFilePath + ".", exception);
					}
				}
				return _allAssetsList;
			}
		}

		public bool RequiresDownload => true;

		public IRetailDemoMode2SingleNodeRepository Selected { get; private set; }

		public RetailDemoMode2Repository(IRetailDemoMode2SingleNodeRepositoryFactory repositoryFactory, Wolf.Core.Util.Downloader.IFileSystem fileSystem, string basePath)
		{
			this.repositoryFactory = repositoryFactory;
			this.fileSystem = fileSystem;
			this.basePath = basePath;
		}

		public void Select(Manufacturer manufacturer, ConsoleType consoleType)
		{
			AssetsList assetsList = AllAssetsList.Assets[manufacturer][consoleType];
			Selected = repositoryFactory.GetNodeRepository(assetsList, manufacturer, consoleType);
		}

		private AllAssetsList CreateDefaultAllAssetsList()
		{
			AllAssetsList allAssetsList = new AllAssetsList();
			allAssetsList.Assets = new Dictionary<Manufacturer, IDictionary<ConsoleType, AssetsList>>();
			allAssetsList.Assets[Manufacturer.NordicTrack] = CreateDefaultAssetsLists(Manufacturer.NordicTrack);
			allAssetsList.Assets[Manufacturer.ProForm] = CreateDefaultAssetsLists(Manufacturer.ProForm);
			return allAssetsList;
		}

		private IDictionary<ConsoleType, AssetsList> CreateDefaultAssetsLists(Manufacturer manufacturer)
		{
			Dictionary<ConsoleType, AssetsList> dictionary = new Dictionary<ConsoleType, AssetsList>();
			dictionary[ConsoleType.Bike] = CreateDefaultAssetsList(manufacturer, ConsoleType.Bike);
			dictionary[ConsoleType.Treadmill] = CreateDefaultAssetsList(manufacturer, ConsoleType.Treadmill);
			dictionary[ConsoleType.Elliptical] = CreateDefaultAssetsList(manufacturer, ConsoleType.Elliptical);
			dictionary[ConsoleType.Rower] = CreateDefaultAssetsList(manufacturer, ConsoleType.Rower);
			return dictionary;
		}

		private AssetsList CreateDefaultAssetsList(Manufacturer manufacturer, ConsoleType consoleType)
		{
			return new AssetsList
			{
				ScreensaverVideoFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/screensaver-video.mp4"),
				WorkoutVideoFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/workout-video.mp4"),
				WorkoutDataFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/workout-programming.json"),
				MarketingHeaderFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-header.jpg"),
				MarketingFeature1FileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-feature-1.jpg"),
				MarketingFeature2FileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-feature-2.jpg"),
				MarketingFeature3FileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-feature-3.jpg"),
				MarketingFeature4FileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-feature-4.jpg"),
				MarketingTrainersFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-trainers.jpg"),
				MarketingWorkoutsFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-workouts.jpg"),
				MarketingVideoFileUri = new Uri($"file://{basePath}/{manufacturer}/{consoleType}/marketing-video.mp4")
			};
		}

		public static bool AllAssetsAreReady(IRetailDemoMode2SingleNodeRepositoryFactory nodeRepositoryFactory, Wolf.Core.Util.Downloader.IFileSystem fileSystem, string basePath)
		{
			string allAssetsListFilePath = GetAllAssetsListFilePath(basePath);
			AllAssetsList allAssetsList = LoadAllAssetsList(fileSystem, allAssetsListFilePath);
			if (allAssetsList == null)
			{
				return false;
			}
			foreach (var (manufacturer2, dictionary2) in allAssetsList.Assets)
			{
				foreach (KeyValuePair<ConsoleType, AssetsList> item in dictionary2)
				{
					item.Deconstruct(out var key, out var value);
					ConsoleType consoleType = key;
					AssetsList assetsList = value;
					IRetailDemoMode2SingleNodeRepository nodeRepository = nodeRepositoryFactory.GetNodeRepository(assetsList, manufacturer2, consoleType);
					if (!nodeRepository.AreAssetsReady())
					{
						return false;
					}
				}
			}
			return true;
		}

		private static string GetAllAssetsListFilePath(string basePath)
		{
			return Path.Combine(basePath, ".allAssetsList.json");
		}

		private static AllAssetsList LoadAllAssetsList(Wolf.Core.Util.Downloader.IFileSystem fileSystem, string allAssetsListFilePath)
		{
			if (fileSystem.FileExists(allAssetsListFilePath))
			{
				try
				{
					string value = fileSystem.ReadAllText(allAssetsListFilePath);
					return JsonConvert.DeserializeObject<AllAssetsList>(value);
				}
				catch (Exception exception)
				{
					Log.Error("RetailDemoMode2Repository", "Error loading " + allAssetsListFilePath + ", using default.", exception);
				}
			}
			return null;
		}
	}
	public interface IRetailDemoMode2RepositoryFactory
	{
		IRetailDemoMode2Repository GetMainRepository();
	}
	public class RetailDemoMode2RepositoryFactory : IRetailDemoMode2RepositoryFactory
	{
		private readonly IRetailDemoMode2Repository mainRepository;

		public RetailDemoMode2RepositoryFactory(Wolf.Core.Util.Downloader.IFileSystem fileSystem, string basePath, string bakedInBasePath, IRetailDemoMode2SingleNodeRepositoryFactory nodeRepositoryFactory)
		{
			if (RetailDemoMode2Repository.AllAssetsAreReady(nodeRepositoryFactory, fileSystem, bakedInBasePath))
			{
				RetailDemoMode2Repository baseRepository = new RetailDemoMode2Repository(nodeRepositoryFactory, fileSystem, bakedInBasePath);
				mainRepository = new RetailDemoMode2BakedInAssetsRepository(baseRepository);
			}
			else
			{
				RetailDemoMode2Repository baseRepository2 = new RetailDemoMode2Repository(nodeRepositoryFactory, fileSystem, basePath);
				mainRepository = new RetailDemoMode2DeletableRepository(baseRepository2, fileSystem, basePath);
			}
		}

		public IRetailDemoMode2Repository GetMainRepository()
		{
			return mainRepository;
		}
	}
	public class RetailDemoMode2SingleNodeRepository : IRetailDemoMode2SingleNodeRepository
	{
		private readonly Wolf.Core.Util.Downloader.IFileSystem fileSystem;

		public Manufacturer Manufacturer { get; }

		public ConsoleType ConsoleType { get; }

		public string ScreensaverVideoFilePath { get; }

		public string WorkoutVideoFilePath { get; }

		public string WorkoutDataFilePath { get; }

		public string MarketingHeaderFilename { get; }

		public string[] MarketingFeaturesFilenames { get; }

		public string MarketingTrainersFilename { get; }

		public string MarketingWorkoutsFilename { get; }

		public string MarketingVideoFilename { get; }

		public RetailDemoMode2SingleNodeRepository(Wolf.Core.Util.Downloader.IFileSystem fileSystem, AssetsList assetsList, Manufacturer manufacturer, ConsoleType consoleType)
		{
			this.fileSystem = fileSystem;
			Manufacturer = manufacturer;
			ConsoleType = consoleType;
			Manufacturer = manufacturer;
			ConsoleType = consoleType;
			ScreensaverVideoFilePath = assetsList.ScreensaverVideoFileUri.LocalPath;
			WorkoutVideoFilePath = assetsList.WorkoutVideoFileUri.LocalPath;
			WorkoutDataFilePath = assetsList.WorkoutDataFileUri.LocalPath;
			MarketingHeaderFilename = assetsList.MarketingHeaderFileUri.LocalPath;
			MarketingFeaturesFilenames = new string[4]
			{
				assetsList.MarketingFeature1FileUri.LocalPath,
				assetsList.MarketingFeature2FileUri.LocalPath,
				assetsList.MarketingFeature3FileUri.LocalPath,
				assetsList.MarketingFeature4FileUri.LocalPath
			};
			MarketingTrainersFilename = assetsList.MarketingTrainersFileUri.LocalPath;
			MarketingWorkoutsFilename = assetsList.MarketingWorkoutsFileUri.LocalPath;
			MarketingVideoFilename = assetsList.MarketingVideoFileUri.LocalPath;
		}

		public bool AreAssetsReady()
		{
			if (!fileSystem.FileExists(ScreensaverVideoFilePath))
			{
				return false;
			}
			if (!fileSystem.FileExists(WorkoutVideoFilePath))
			{
				return false;
			}
			if (!fileSystem.FileExists(WorkoutDataFilePath))
			{
				return false;
			}
			if (!fileSystem.FileExists(MarketingHeaderFilename))
			{
				return false;
			}
			if (MarketingFeaturesFilenames.Any((string filename) => !fileSystem.FileExists(filename)))
			{
				return false;
			}
			if (!fileSystem.FileExists(MarketingTrainersFilename))
			{
				return false;
			}
			if (!fileSystem.FileExists(MarketingWorkoutsFilename))
			{
				return false;
			}
			if (!fileSystem.FileExists(MarketingVideoFilename))
			{
				return false;
			}
			return true;
		}
	}
