	public class RetailDemoMode2AssetsDownloader : IDownloader<IObservable<DownloadProgress>>
	{
		private const string LogTag = "RetailDemoMode2AssetsDownloader";

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly FeatureFlag assetsListFeatureFlag;

		private readonly IRetailDemoMode2DownloaderFactory downloaderFactory;

		private readonly IRetailDemoMode2SingleNodeRepository repository;

		private readonly CancellationToken cancellationToken;

		private long progressReceived;

		public RetailDemoMode2AssetsDownloader(IFeatureFlagManager featureFlagManager, FeatureFlag assetsListFeatureFlag, IRetailDemoMode2DownloaderFactory downloaderFactory, IRetailDemoMode2SingleNodeRepository repository, CancellationToken cancellationToken)
		{
			this.featureFlagManager = featureFlagManager;
			this.assetsListFeatureFlag = assetsListFeatureFlag;
			this.downloaderFactory = downloaderFactory;
			this.repository = repository;
			this.cancellationToken = cancellationToken;
		}

		public Task<IObservable<DownloadProgress>> DownloadAsync()
		{
			ReplaySubject<DownloadProgress> subject = new ReplaySubject<DownloadProgress>(1);
			Task.Run(async delegate
			{
				try
				{
					await DownloadInternalAsync(subject);
				}
				catch (Exception error)
				{
					subject.OnError(error);
				}
			});
			IObservable<DownloadProgress> result = subject.AsObservable();
			return Task.FromResult(result);
		}

		private async Task DownloadInternalAsync(IObserver<DownloadProgress> observer)
		{
			cancellationToken.ThrowIfCancellationRequested();
			string uriString = featureFlagManager.GetString(assetsListFeatureFlag);
			Uri uri = new Uri(uriString);
			cancellationToken.ThrowIfCancellationRequested();
			IDownloader<AllAssetsList> assetsListDownloader = downloaderFactory.GetAssetsListDownloader(uri);
			AssetsList assetsList = (await assetsListDownloader.DownloadAsync()).Assets[repository.Manufacturer][repository.ConsoleType];
			IRetailDemoMode2FileDownloader[] allDownloads = new IRetailDemoMode2FileDownloader[11]
			{
				downloaderFactory.GetAssetDownloader(assetsList.ScreensaverVideoFileUri, repository.ScreensaverVideoFilePath, cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.WorkoutVideoFileUri, repository.WorkoutVideoFilePath, cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.WorkoutDataFileUri, repository.WorkoutDataFilePath, cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingHeaderFileUri, repository.MarketingHeaderFilename, cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingFeature1FileUri, repository.MarketingFeaturesFilenames[0], cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingFeature2FileUri, repository.MarketingFeaturesFilenames[1], cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingFeature3FileUri, repository.MarketingFeaturesFilenames[2], cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingFeature4FileUri, repository.MarketingFeaturesFilenames[3], cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingTrainersFileUri, repository.MarketingTrainersFilename, cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingWorkoutsFileUri, repository.MarketingWorkoutsFilename, cancellationToken),
				downloaderFactory.GetAssetDownloader(assetsList.MarketingVideoFileUri, repository.MarketingVideoFilename, cancellationToken)
			};
			long totalBytes = 0L;
			IEnumerable<Task> tasks = ((IEnumerable<IRetailDemoMode2FileDownloader>)allDownloads).Select((Func<IRetailDemoMode2FileDownloader, Task>)async delegate(IRetailDemoMode2FileDownloader downloader)
			{
				long value = await downloader.GetDownloadSizeAsync();
				Interlocked.Add(ref totalBytes, value);
			});
			await Task.WhenAll(tasks);
			Task[] tasks2 = ((IEnumerable<IRetailDemoMode2FileDownloader>)allDownloads).Select((Func<IRetailDemoMode2FileDownloader, Task>)async delegate(IRetailDemoMode2FileDownloader downloader)
			{
				await DownloadResourceAsync(observer, totalBytes, downloader);
				Log.Trace("RetailDemoMode2AssetsDownloader", $"Successfully downloaded {downloader.SourceUri} to {downloader.DestinationFilePath}");
			}).ToArray();
			await Task.WhenAll(tasks2);
			observer.OnCompleted();
		}

		private async Task DownloadResourceAsync(IObserver<DownloadProgress> observer, long totalBytes, IRetailDemoMode2FileDownloader downloader)
		{
			TaskCompletionSource<int> tcs = new TaskCompletionSource<int>();
			IObservable<DownloadProgress> source = await downloader.DownloadAsync();
			long prevProgress = 0L;
			source.Subscribe(delegate(DownloadProgress progress)
			{
				Interlocked.Add(ref progressReceived, progress.BytesReceived - prevProgress);
				DownloadProgress value = new DownloadProgress(progressReceived, totalBytes, progress.Status);
				observer.OnNext(value);
				prevProgress = progress.BytesReceived;
			}, delegate(Exception error)
			{
				tcs.SetException(error);
			}, delegate
			{
				tcs.SetResult(0);
			});
			await tcs.Task;
		}
	}
