namespace Wolf.Core.DemoMode.RetailDemoMode1
{
	public class RetailDemoMode1ServiceAdapter : IDemoModeService
	{
		public interface IDelegate
		{
			Task PromptEnterDemoMode();

			void ShowStrengthMirrorDemoModeMarketingViewModel();

			void ShowRetailDemoModeMarketingViewModel();

			void GoToStrengthMirrorDemoModeScreensaverIfInDemoMode();

			void GoToRetailDemoModeScreensaverIfInDemoMode();

			void GoToRetailDemoModeSetupViewModel();
		}

		private const string Tag = "RetailDemoMode1ServiceAdapter";

		private readonly IOldRetailDemoMode1Service rdmService;

		private readonly IDelegate _delegate;

		public string Id
		{
			get
			{
				if (!rdmService.ShouldUseSmdmAssets)
				{
					return "RDM1";
				}
				return "SMDM";
			}
		}

		public bool IsInDemoMode => rdmService.IsInDemoMode;

		public bool RequiresDownload => !rdmService.CheckStoredAssetsIntegrity();

		public RetailDemoMode1ServiceAdapter(IOldRetailDemoMode1Service rdmService, IDelegate serviceDelegate)
		{
			this.rdmService = rdmService;
			_delegate = serviceDelegate;
		}

		public bool CanEnterDemoMode()
		{
			return rdmService.IsCurrentConsoleTypeSupported();
		}

		public async Task EnterDemoModeAsync()
		{
			if (rdmService.IsInDemoMode)
			{
				ResumeDemoMode();
				return;
			}
			await _delegate.PromptEnterDemoMode();
			GoToRetailDemoMode();
		}

		public void ResumeDemoMode()
		{
			if (rdmService.ShouldUseSmdmAssets)
			{
				Log.Trace("CustomAppStart", "Strength Mirror Demo Mode is active. Going straight to screensaver view.");
				_delegate.ShowStrengthMirrorDemoModeMarketingViewModel();
			}
			else
			{
				Log.Trace("CustomAppStart", "Retail Demo Mode is active. Going straight to RDM marketing view.");
				_delegate.ShowRetailDemoModeMarketingViewModel();
			}
		}

		private void GoToRetailDemoMode()
		{
			Log.Trace("RetailDemoMode1ServiceAdapter", "User tapped Enable Retail Demo Mode button, navigating.");
			if (rdmService.CanRetailDemoModeBeEnabled && rdmService.ShouldUseSmdmAssets)
			{
				Log.Trace("CustomAppStart", "Strength Mirror Demo Mode assets detected. Redirecting to Strength Mirror Demo Mode Screensaver");
				_delegate.GoToStrengthMirrorDemoModeScreensaverIfInDemoMode();
			}
			if (rdmService.CheckStoredAssetsIntegrity())
			{
				Log.Trace("RetailDemoMode1ServiceAdapter", "Assets downloaded, enabling Retail Demo Mode");
				rdmService.EnableDemoModeIfAssetsIntact();
				_delegate.GoToRetailDemoModeScreensaverIfInDemoMode();
			}
			else
			{
				_delegate.GoToRetailDemoModeSetupViewModel();
			}
		}

		public Task ExitDemoModeAsync()
		{
			rdmService.DisableDemoMode();
			return Task.CompletedTask;
		}

		public void ForceExitDemoMode()
		{
			rdmService.DisableDemoMode();
		}

		public bool CanDeleteAssets()
		{
			return rdmService.ShouldDemoModeAssetsBeDeleted;
		}

		public void DeleteAllAssets()
		{
			rdmService.DisableDemoMode(deleteAllContent: true);
		}

		public void DemoWorkoutCompleted()
		{
			ResumeDemoMode();
		}
	}
	public class RetailDemoMode1ServiceAdapterDelegate : MvxNavigatingObject, RetailDemoMode1ServiceAdapter.IDelegate
	{
		private readonly IDialogPresenter dialogPresenter;

		private BaseViewModel CurrentViewModel => dialogPresenter.CurrentMainViewModel as BaseViewModel;

		public RetailDemoMode1ServiceAdapterDelegate(IDialogPresenter dialogPresenter)
		{
			this.dialogPresenter = dialogPresenter;
		}

		public Task PromptEnterDemoMode()
		{
			TaskCompletionSource<int> tcs = new TaskCompletionSource<int>();
			ConfirmationInitializationData initData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.retail_demo_mode_enter_prompt_title, Wolf.Core.Resources.AppStrings.retail_demo_mode_enter_prompt_message, Wolf.Core.Resources.AppStrings.retail_demo_mode_enter_prompt_cancel.ToUpper(), Wolf.Core.Resources.AppStrings.retail_demo_mode_enter_prompt_accept.ToUpper(), delegate
			{
				tcs.SetResult(0);
			}, delegate
			{
				tcs.SetCanceled();
			});
			InvokeOnMainThread(delegate
			{
				dialogPresenter.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, initData);
			});
			return tcs.Task;
		}

		public void ShowStrengthMirrorDemoModeMarketingViewModel()
		{
			ShowViewModel<StrengthMirrorDemoModeMarketingViewModel>();
		}

		public void ShowRetailDemoModeMarketingViewModel()
		{
			ShowViewModel<RetailDemoModeMarketingViewModel>();
		}

		public void GoToStrengthMirrorDemoModeScreensaverIfInDemoMode()
		{
			CurrentViewModel.GoToStrengthMirrorDemoModeScreensaverIfInDemoMode();
		}

		public void GoToRetailDemoModeScreensaverIfInDemoMode()
		{
			CurrentViewModel.GoToRetailDemoModeScreensaverIfInDemoMode(showScreensaver: true);
		}

		public void GoToRetailDemoModeSetupViewModel()
		{
			ShowViewModel<RetailDemoModeSetupViewModel>((object)null, (IMvxBundle)ShireViewParams.ClearStackToRequested(), (MvxRequestedBy)null);
		}
	}
}
namespace Wolf.Core.DemoMode.Decorators
{
	public class DemoModeServiceAnalyticsDecorator : IDemoModeService
	{
		private const string Tag = "DemoModeServiceAnalyticsDecorator";

		private readonly IDemoModeService service;

		private readonly IWolfAnalytics analytics;

		private readonly IDeviceInformation deviceInformation;

		public string Id => service.Id;

		public bool IsInDemoMode => service.IsInDemoMode;

		public bool RequiresDownload => service.RequiresDownload;

		private Dictionary<string, object> AnalyticsDictionary => new Dictionary<string, object>
		{
			{ "serviceType", Id },
			{
				"canEnterDemoMode",
				CanEnterDemoMode()
			},
			{
				"canDeleteAssets",
				CanDeleteAssets()
			},
			{ "isInDemoMode", IsInDemoMode },
			{ "requiresDownload", RequiresDownload },
			{ "softwareNumber", deviceInformation.SoftwareNumber }
		};

		public bool CanEnterDemoMode()
		{
			return service.CanEnterDemoMode();
		}

		public bool CanDeleteAssets()
		{
			return service.CanDeleteAssets();
		}

		public void ResumeDemoMode()
		{
			service.ResumeDemoMode();
		}

		public void DeleteAllAssets()
		{
			service.DeleteAllAssets();
		}

		public DemoModeServiceAnalyticsDecorator(IDemoModeService service, IWolfAnalytics analytics, IDeviceInformation deviceInformation)
		{
			this.service = service;
			this.analytics = analytics;
			this.deviceInformation = deviceInformation;
		}

		public async Task EnterDemoModeAsync()
		{
			await service.EnterDemoModeAsync();
			await TryPostAnalytics();
		}

		public async Task ExitDemoModeAsync()
		{
			await service.ExitDemoModeAsync();
			analytics.OnRetailDemoModeExitEvent().SafeFireAndForget();
		}

		public void ForceExitDemoMode()
		{
			service.ForceExitDemoMode();
			analytics.OnRetailDemoModeExitEvent().SafeFireAndForget();
		}

		public void DemoWorkoutCompleted()
		{
			service.DemoWorkoutCompleted();
		}

		private async Task TryPostAnalytics()
		{
			try
			{
				string value = await deviceInformation.GetIpAddress();
				Dictionary<string, object> analyticsDictionary = AnalyticsDictionary;
				analyticsDictionary.TryAdd("ipAddress", value);
				analyticsDictionary["eventType"] = new StackTrace().GetFrame(1).ToString();
				analytics.OnRetailDemoModeEvent(analyticsDictionary).SafeFireAndForget();
			}
			catch (Exception exception)
			{
				Log.Error("DemoModeServiceAnalyticsDecorator", Id + " TryPostAnalytics error", exception);
			}
		}
	}
	public class DemoModeServiceBasicLogger : IDemoModeService
	{
		private readonly IDemoModeService service;

		private readonly string logTag;

		public string Id => service.Id;

		public bool IsInDemoMode => InvokeWithLogging(() => service.IsInDemoMode, MethodBase.GetCurrentMethod().Name);

		public bool RequiresDownload => InvokeWithLogging(() => service.RequiresDownload, MethodBase.GetCurrentMethod().Name);

		public DemoModeServiceBasicLogger(IDemoModeService service, string logTag)
		{
			this.service = service;
			this.logTag = logTag;
		}

		public bool CanEnterDemoMode()
		{
			return InvokeWithLogging(() => service.CanEnterDemoMode(), MethodBase.GetCurrentMethod().Name);
		}

		public async Task EnterDemoModeAsync()
		{
			await InvokeAsyncWithLogging(() => service.EnterDemoModeAsync(), "EnterDemoModeAsync");
		}

		public void ResumeDemoMode()
		{
			InvokeWithLogging(delegate
			{
				service.ResumeDemoMode();
			}, MethodBase.GetCurrentMethod().Name);
		}

		public async Task ExitDemoModeAsync()
		{
			await InvokeAsyncWithLogging(() => service.ExitDemoModeAsync(), "ExitDemoModeAsync");
		}

		public void ForceExitDemoMode()
		{
			InvokeWithLogging(delegate
			{
				service.ForceExitDemoMode();
			}, MethodBase.GetCurrentMethod().Name);
		}

		public bool CanDeleteAssets()
		{
			return InvokeWithLogging(() => service.CanDeleteAssets(), MethodBase.GetCurrentMethod().Name);
		}

		public void DeleteAllAssets()
		{
			InvokeWithLogging(delegate
			{
				service.DeleteAllAssets();
			}, MethodBase.GetCurrentMethod().Name);
		}

		public void DemoWorkoutCompleted()
		{
			InvokeWithLogging(delegate
			{
				service.DemoWorkoutCompleted();
			}, MethodBase.GetCurrentMethod().Name);
		}

		private async Task InvokeAsyncWithLogging(Func<Task> action, string name)
		{
			try
			{
				await action();
				Log.Trace(logTag, Id + " " + name + " called.");
			}
			catch (Exception exception)
			{
				Log.Error(logTag, Id + " Error in " + name, exception);
				throw;
			}
		}

		private void InvokeWithLogging(Action action, string name)
		{
			try
			{
				action();
				Log.Trace(logTag, Id + " " + name + " called.");
			}
			catch (Exception exception)
			{
				Log.Error(logTag, Id + " Error in " + name, exception);
				throw;
			}
		}

		private Return InvokeWithLogging<Return>(Func<Return> action, string name)
		{
			try
			{
				Return val = action();
				Log.Trace(logTag, $"{Id} {name} returns {val}.");
				return val;
			}
			catch (Exception exception)
			{
				Log.Error(logTag, Id + " Error in " + name, exception);
				throw;
			}
		}
	}
	public class DemoModeServiceEnabler : IDemoModeService
	{
		private const string Tag = "DemoModeServiceEnabler";

		private readonly IDemoModeService service;

		private readonly bool enabled;

		public string Id => service.Id;

		public bool IsInDemoMode => service.IsInDemoMode;

		public bool RequiresDownload => service.RequiresDownload;

		public DemoModeServiceEnabler(IDemoModeService service, IFeatureFlagManager featureFlagManager, FeatureFlag ff, Func<string, bool> isEnabled)
			: this(service, isEnabled(featureFlagManager.GetString(ff)), ff.Key + " = " + featureFlagManager.GetString(ff))
		{
		}

		public DemoModeServiceEnabler(IDemoModeService service, IFeatureFlagManager featureFlagManager, FeatureFlag ff)
			: this(service, featureFlagManager.IsFeatureEnabled(ff, defaultValue: true), $"{ff.Key} = {featureFlagManager.IsFeatureEnabled(ff, defaultValue: true)}")
		{
		}

		public DemoModeServiceEnabler(IDemoModeService service, bool enabled)
			: this(service, enabled, "it was hard coded")
		{
		}

		private DemoModeServiceEnabler(IDemoModeService service, bool enabled, string reason)
		{
			this.service = service;
			this.enabled = enabled;
			if (!enabled)
			{
				service.ForceExitDemoMode();
			}
			string text = (enabled ? "Not disabling" : "Disabling");
			Log.Trace("DemoModeServiceEnabler", text + " " + Id + " because " + reason);
		}

		public bool CanDeleteAssets()
		{
			return service.CanDeleteAssets();
		}

		public void DeleteAllAssets()
		{
			service.DeleteAllAssets();
		}

		public void DemoWorkoutCompleted()
		{
			if (enabled)
			{
				service.DemoWorkoutCompleted();
			}
		}

		public bool CanEnterDemoMode()
		{
			if (enabled)
			{
				return service.CanEnterDemoMode();
			}
			return false;
		}

		public async Task EnterDemoModeAsync()
		{
			if (enabled)
			{
				await service.EnterDemoModeAsync();
			}
		}

		public void ResumeDemoMode()
		{
			if (enabled)
			{
				service.ResumeDemoMode();
			}
		}

		public async Task ExitDemoModeAsync()
		{
			await service.ExitDemoModeAsync();
		}

		public void ForceExitDemoMode()
		{
			service.ForceExitDemoMode();
		}
	}
