	[MvxUnconventional]
	public class DeviceStateResourceConverter : MvxValueConverter<Sindarin.Core.Ble.Connection.DeviceState, int>
	{
		private readonly int unselectedValue;

		private readonly int selectedValue;

		public DeviceStateResourceConverter(int unselectedValue, int selectedValue)
		{
			this.unselectedValue = unselectedValue;
			this.selectedValue = selectedValue;
		}

		protected override int Convert(Sindarin.Core.Ble.Connection.DeviceState value, Type targetType, object parameter, CultureInfo culture)
		{
			if (value == Sindarin.Core.Ble.Connection.DeviceState.Connecting || value == Sindarin.Core.Ble.Connection.DeviceState.Connected)
			{
				return selectedValue;
			}
			return unselectedValue;
		}
	}
