	public abstract class TimeDistanceIconStatValueConverterBase : IMvxValueConverter
	{
		protected abstract object LoadTimeIcon();

		protected abstract object LoadDistanceIcon();

		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			Workout.TargetType targetType2 = (Workout.TargetType)value;
			if (targetType2 != Workout.TargetType.Meters)
			{
				return LoadTimeIcon();
			}
			return LoadDistanceIcon();
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			throw new NotImplementedException();
		}
	}
	public class TimeDistanceLabelValueConverter : IMvxValueConverter
	{
		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			WorkoutDisplayModel workoutDisplayModel = (WorkoutDisplayModel)value;
			if (workoutDisplayModel.Workout.Target != Workout.TargetType.Meters)
			{
				return string.Empty;
			}
			return workoutDisplayModel.DistanceUnits.Value;
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			throw new NotImplementedException();
		}
	}
	public class TimeDistanceMetricValueConverter : IMvxValueConverter
	{
		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			WorkoutDisplayModel workoutDisplayModel = (WorkoutDisplayModel)value;
			if (workoutDisplayModel.Workout.Target != Workout.TargetType.Meters)
			{
				return ValueFormatters.SecondsFormatter.Format(workoutDisplayModel.Estimates.Time);
			}
			return workoutDisplayModel.Distance.Value.ToString();
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			throw new NotImplementedException();
		}
	}
	public abstract class WorkoutIconTypeValueConverterBase : IMvxValueConverter
	{
		protected abstract object LoadRunIcon();

		protected abstract object LoadBikeIcon();

		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			Workout.WorkoutType workoutType = (Workout.WorkoutType)value;
			if (workoutType != Workout.WorkoutType.Run)
			{
				return LoadBikeIcon();
			}
			return LoadRunIcon();
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			throw new NotImplementedException();
		}
	}
	public class WorkoutStartTypeValueConverter : IMvxValueConverter
	{
		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			ConnectionProgressDialogViewModel.WorkoutStartType workoutStartType = (ConnectionProgressDialogViewModel.WorkoutStartType)value;
			return workoutStartType switch
			{
				ConnectionProgressDialogViewModel.WorkoutStartType.Initializing => Wolf.Core.Resources.AppStrings.please_wait_for_workout, 
				ConnectionProgressDialogViewModel.WorkoutStartType.ReconnectMidWorkout => Wolf.Core.Resources.AppStrings.please_wait_we_have_disconnected, 
				ConnectionProgressDialogViewModel.WorkoutStartType.Restore => Wolf.Core.Resources.AppStrings.please_wait_for_workout_to_restore, 
				_ => throw new ArgumentException("Do not have a workout start type message for " + workoutStartType), 
			};
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			throw new NotImplementedException();
		}
	}
