		{
			return GetNameForTheme(value);
		}

		public static string GetNameForTheme(Theme theme)
		{
			return theme switch
			{
				Theme.Light => Wolf.Core.Resources.AppStrings.theme_name_light, 
				Theme.Dark => Wolf.Core.Resources.AppStrings.theme_name_dark, 
				Theme.StrengthMirror => Wolf.Core.Resources.AppStrings.theme_name_strength_mirror, 
				Theme.Rainbow => Wolf.Core.Resources.AppStrings.theme_name_rainbow, 
				_ => string.Empty, 
			};
		}
	}
	public class UploadingProgressConverter : MvxValueConverter<int, string>
	{
		private readonly int target;

		private readonly ByteSize targetSize;

		public UploadingProgressConverter(int target)
		{
			this.target = target;
			targetSize = ByteSize.FromBytes(target);
		}

		protected override string Convert(int value, Type targetType, object parameter, CultureInfo culture)
		{
			int num = (int)Math.Ceiling((float)target * ((float)value / 100f));
			return ByteSize.FromBytes(num).ToString("#.#") + " of " + targetSize.ToString("#.#");
		}
	}
}
