	[MvxUnconventional]
	public class DistanceLabelConverter : MvxValueConverter<bool, string>
	{
		private bool upperCase;

		public DistanceLabelConverter(bool upperCase = false)
		{
			this.upperCase = upperCase;
		}

		protected override string Convert(bool value, Type targetType, object parameter, CultureInfo culture)
		{
			Func<string, string> func = (string s) => (!upperCase) ? s : s.ToUpper();
			return func(value ? Wolf.Core.Resources.AppStrings.km : Wolf.Core.Resources.AppStrings.mi);
		}
	}
