	public class ViewPagerSource : IEnumerable<Type>, IEnumerable
	{
		public INC<int> CurrentPage = new NC<int>();

		private readonly List<Type> pageVMTypes = new List<Type>();

		public int Count => pageVMTypes.Count;

		public void Add(Type vmType)
		{
			pageVMTypes.Add(vmType);
		}

		public IEnumerator<Type> GetEnumerator()
		{
			return pageVMTypes.GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		public void GoToNextPage()
		{
			CurrentPage.Value = (CurrentPage.Value + 1) % pageVMTypes.Count;
		}

		public void GoToPage(Type vmType)
		{
			for (int i = 0; i < Count; i++)
			{
				if (vmType == pageVMTypes[i])
				{
					CurrentPage.Value = i;
					break;
				}
			}
		}
	}
}
namespace Wolf.Core.Controls.NavigationDrawer
{
	public class UserAccountMenuItemModel : BaseViewModel
	{
		public User ItemUser { get; }

		public string UserTitle { get; }

		public string DescriptionText { get; }

		public UserViewRightImageType RightImageType { get; }

		public bool HasDescription { get; }

		public ICommand SelectedCommand { get; }

		public UserAccountMenuItemModel(ILocalSettings localSettings, IIfitApiService api, User user, UserViewRightImageType otherUsersImage = UserViewRightImageType.None, Func<User, Task> selectUser = null, bool showUsername = false, bool isInvitation = false)
			: base(localSettings)
		{
			try
			{
				UserAccountMenuItemModel userAccountMenuItemModel = this;
				ItemUser = user;
				bool flag = user?.Id == api.CurrentlyAuthenticatedUserId;
				RightImageType = ProduceRightImageType(flag, otherUsersImage);
				UserTitle = (isInvitation ? GetInvitationUserTitle() : user?.FullName);
				DescriptionText = ProduceDescription(flag, showUsername, isInvitation);
				HasDescription = !string.IsNullOrWhiteSpace(DescriptionText);
				if (!flag && ItemUser?.Id != null)
				{
					SelectedCommand = new MvxAsyncCommand(() => selectUser(userAccountMenuItemModel.ItemUser));
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private string ProduceDescription(bool isPrimary, bool showUsername, bool isInvitation)
		{
			if (isInvitation)
			{
				return Wolf.Core.Resources.AppStrings.settings_invitation_not_accepted;
			}
			if (showUsername)
			{
				return "@" + ItemUser.Username;
			}
			if (!isPrimary)
			{
				return string.Empty;
			}
			return "@" + Wolf.Core.Resources.AppStrings.primary_user_title;
		}

		private string GetInvitationUserTitle()
		{
			if (ItemUser == null)
			{
				return Wolf.Core.Resources.AppStrings.settings_invitation_sent;
			}
			if (!string.IsNullOrEmpty(ItemUser.Email))
			{
				return ItemUser.Email;
			}
			if (!string.IsNullOrEmpty(ItemUser.FullName))
			{
				return ItemUser.FullName;
			}
			return Wolf.Core.Resources.AppStrings.settings_invitation_sent;
		}

		private UserViewRightImageType ProduceRightImageType(bool isPrimary, UserViewRightImageType defaultRightImageType)
		{
			if (isPrimary)
			{
				return UserViewRightImageType.Check;
			}
			if (ItemUser?.Id == null)
			{
				return UserViewRightImageType.None;
			}
			return defaultRightImageType;
		}

