		{
			return imageType switch
			{
				UserViewRightImageType.None => null, 
				UserViewRightImageType.Check => "icn_checkmark_line", 
				UserViewRightImageType.Delete => "icn_delete_line", 
				UserViewRightImageType.Switch => "icn_switch_user_line", 
				_ => null, 
			};
		}
