namespace Wolf.Core.Controls.ConnectedApps
{
	public class ConnectedAppPermissionItemModel : ShireBaseViewModel
	{
		private readonly ConnectedAppPermission permission;

		private readonly Func<ConnectedAppPermission, Task<bool>> tryTogglePermissionAsyncFunc;

		public readonly string Description;

		public readonly INC<bool> IsEnabled = new NC<bool>();

		public ICommand TogglePermission { get; }

		public ConnectedAppPermissionItemModel(string connectedAppName, ConnectedAppPermission permission, bool isEnabled, Func<ConnectedAppPermission, Task<bool>> tryTogglePermissionAsyncFunc)
		{
			try
			{
				this.permission = permission;
				this.tryTogglePermissionAsyncFunc = tryTogglePermissionAsyncFunc;
				Description = GetDescription(connectedAppName);
				IsEnabled.Value = isEnabled;
				TogglePermission = new MvxAsyncCommand(DoTogglePermissionAsync);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private string GetDescription(string connectedAppName)
		{
			switch (permission)
			{
			case ConnectedAppPermission.Send:
				return string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_permissions_export_row_toggle, connectedAppName);
			case ConnectedAppPermission.Receive:
				return string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_permissions_import_row_toggle, connectedAppName);
			default:
				Log.Error("Settings", string.Format("{0}: Unable to identify permission - {1}", "ConnectedAppPermissionItemModel", permission));
				return $"{connectedAppName} Permission: {permission}";
			}
		}

		private async Task DoTogglePermissionAsync()
		{
			if (await tryTogglePermissionAsyncFunc(permission))
			{
				IsEnabled.Value = !IsEnabled.Value;
			}
		}

