	public class ConnectedAppsMenuItemModel : ShireBaseViewModel
	{
		public bool IsFreeUser { get; }

		public IConnectedAppContainer ConnectedAppContainer { get; }

		public bool IsConnected
		{
			get
			{
				if (ConnectedAppContainer.IsConnected)
				{
					return !IsFreeUser;
				}
				return false;
			}
		}

		public string AppTitle => ConnectedAppContainer.DisplayItemName;

		public string ImageRef => ConnectedAppContainer.SmallImageReference;

		public ICommand ConnectedAppTapped { get; }

		public ConnectedAppsMenuItemModel(IConnectedAppContainer connectedAppContainer, bool isFreeUser = false)
		{
			try
			{
				IsFreeUser = isFreeUser;
				ConnectedAppContainer = connectedAppContainer;
				if (!isFreeUser)
				{
					ConnectedAppTapped = new MvxCommand(DoConnectedAppTapped);
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void DoConnectedAppTapped()
		{
			if (IsConnected)
			{
				LaunchPermissionsScreen();
			}
			else
			{
				LaunchConnectToAppScreen();
			}
		}

		private void LaunchConnectToAppScreen()
		{
			ConnectToAppNavObject parameterValuesObject = new ConnectToAppNavObject
			{
				App = ConnectedAppContainer.App
			};
			ShowViewModel<ConnectToAppViewModel>(parameterValuesObject);
		}

		private void LaunchPermissionsScreen()
		{
			ConnectedAppPermissionsNavObject parameterValuesObject = new ConnectedAppPermissionsNavObject
			{
				App = ConnectedAppContainer.App,
				IsDisconnectAction = true
			};
			ShowViewModel<ConnectedAppPermissionsViewModel>(parameterValuesObject);
		}

