	public class AccountSelectionSendInviteItemModel : BaseViewModel
	{
		private int invitesLeft;

		public ICommand SelectedCommand { get; }

		public bool IsPossibleToInviteUsers { get; }

		public string InvitesLeft => string.Format(Wolf.Core.Resources.AppStrings.settings_invite_count, invitesLeft);

		public AccountSelectionSendInviteItemModel(ILocalSettings localSettings, int invitesLeft, bool isPossibleToInviteUsers, Action selectFunc = null)
			: base(localSettings)
		{
			try
			{
				this.invitesLeft = invitesLeft;
				IsPossibleToInviteUsers = isPossibleToInviteUsers;
				if (IsPossibleToInviteUsers)
				{
					SelectedCommand = new MvxCommand(delegate
					{
						selectFunc?.Invoke();
					});
				}
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		public void UpdateInvitesLeft(int newInvitesLeft)
		{
