	public class AccountSelectionUserItemModel : BaseViewModel
	{
		private readonly IIfitApiService api;

		public readonly User User;

		public readonly ICommand SelectedCommand;

		public string UserName => "@" + User.Username;

		public bool IsPrimary { get; }

		public bool IsSecondaryUserLoggedIn { get; }

		public bool IsSignInRequired
		{
			get
			{
				if (!IsPrimary)
				{
					return !IsSecondaryUserLoggedIn;
				}
				return false;
			}
		}

		public AccountSelectionUserItemModel(ILocalSettings localSettings, IIfitApiService api, User user)
			: base(localSettings)
		{
			try
			{
				this.api = api;
				User = user;
				IsPrimary = user?.Id == api.CurrentlyAuthenticatedUserId;
				List<string> list = api.AuthenticatedUsers.Select((User x) => x.Id).ToList();
				IsSecondaryUserLoggedIn = !IsPrimary && list.Exists((string x) => x == user?.Id);
				SelectedCommand = new MvxAsyncCommand(DoSwitchUserAsync);
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task DoSwitchUserAsync()
		{
			if (User == null)
			{
				return;
			}
			if (User.Id.Equals(api.CurrentlyAuthenticatedUser.Id))
			{
				ShowViewModel<DashboardViewModel>();
				return;
			}
			ClearDialogs();
			webviewHolderFactory.WebviewHolderStore.FlushAll();
			try
			{
				await api.SwitchUser(User.Id);
				ClearCookies();
				HardResetNavigation(showWallOnBle: false, forceLoggedInUserToDashboard: true);
			}
			catch (Exception)
			{
				ShowLoginViewModel(new OnboardingWebViewModel.NavObject
				{
					ShowLogin = true
				}, null, clearStack: false);
			}
		}

