	public class LanguageSelectionViewModel : BaseViewModel
	{
		public readonly INC<bool> LanguageListInitialized = new NC<bool>();

		public INCList<LanguageItem> Languages = new NCList<LanguageItem>();

		private new readonly IPreferenceResolver preferenceResolver;

		private readonly IChangeLanguageService changeLanguageService;

		public INCString CurrentNextLanguage = new NCString(Wolf.Core.Resources.AppStrings.next);

		public IMvxCommand NextCommand => new MvxCommand(DoNext);

		public LanguageSelectionViewModel(ILocalSettings localSettings, ISupportedLanguageService supportedLanguageService, IChangeLanguageService changeLanguageService)
			: base(localSettings)
		{
			try
			{
				this.changeLanguageService = changeLanguageService;
				Languages.Value = new List<LanguageItem>();
				IEnumerable<Wolf.Core.Services.Culture.Language> enumerable = Enum.GetValues(typeof(Wolf.Core.Services.Culture.Language)).Cast<Wolf.Core.Services.Culture.Language>();
				foreach (Wolf.Core.Services.Culture.Language item in enumerable)
				{
					bool flag = false;
					if ((1 == 0 || item != Wolf.Core.Services.Culture.Language.Klingon) && supportedLanguageService.IsLanguageSupported(item) && item != Wolf.Core.Services.Culture.Language.SystemDefault)
					{
						Languages.Value.Add(new LanguageItem(item, SettingsLanguagesViewModel.LanguageToTitleDictionary.GetValueSafely(item), changeLanguageService.CurrentLanguage == item));
					}
				}
				LanguageListInitialized.Value = true;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private void DoNext()
		{
			changeLanguageService.OnboardingLanguageConfirmed();
			ShowViewModel<OnBoardingSetupViewModel>((IMvxBundle)null, (IMvxBundle)ShireViewParams.ChildView<EmbeddedUpdateCheckViewModel>(), (MvxRequestedBy)null);
		}

		public void DoSelectLanguage(int position)
		{
			foreach (LanguageItem item in Languages.Value)
			{
				item.Selected = false;
			}
			Languages.Value[position].Selected = true;
			changeLanguageService.ChangeOnboardingLanguage(Languages.Value[position].Language);
			CurrentNextLanguage.Value = Wolf.Core.Resources.AppStrings.next;
		}

