	public class ForgotPasswordDialogViewModel : BaseDialogViewModel
	{
		private readonly IIfitUserExistenceService userExistenceService;

		private readonly IIfitApiService ifitApi;

		private string fieldInput;

		public bool ResetButtonEnabled
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(FieldInput))
				{
					return userExistenceService.CheckEmailFormat(FieldInput);
				}
				return false;
			}
		}

		public string FieldInput
		{
			get
			{
				return fieldInput;
			}
			private set
			{
				if (fieldInput != value)
				{
					fieldInput = value;
					RaisePropertyChanged("FieldInput");
					RaisePropertyChanged("ResetButtonEnabled");
				}
			}
		}

		public ICommand Cancel => new MvxCommand(DoClose);

		public ICommand ResetPassword => new MvxAsyncCommand(DoResetPassword);

		public ForgotPasswordDialogViewModel(ILocalSettings localSettings, IIfitUserExistenceService userExistenceService, IIfitApiService ifitApi)
			: base(localSettings)
		{
			try
			{
				this.userExistenceService = userExistenceService;
				this.ifitApi = ifitApi;
			}
			finally
			{
				RegisterChangeHandlers();
			}
		}

		private async Task DoResetPassword()
		{
			if (!connectivity.IsConnected)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.wifi_not_found, null, Wolf.Core.Resources.AppStrings.okay_title);
				return;
			}
			Shire.Core.Util.NonGenericSubject obs = new Shire.Core.Util.NonGenericSubject();
			InvokeOnMainThread(delegate
			{
				ShowProgressDialog(Wolf.Core.Resources.AppStrings.please_wait, obs.ReactiveSubject, null, null, default(TimeSpan), "", showSafety: false).ConfigureAwait(continueOnCapturedContext: false);
			});
			bool success = false;
			string email = FieldInput.Trim();
			try
			{
				if (!(await User.ExistsWithEmail(ifitApi, email).ConfigureAwait(continueOnCapturedContext: false)))
				{
					ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.login_unable_to_validate_email, null, Wolf.Core.Resources.AppStrings.okay_title);
					obs.OnNext();
					return;
				}
				success = await User.ForgotPassword(ifitApi, email).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Exception thrown while attempting to send password email reset.", exception);
			}
			obs.OnNext();
			DoClose();
			if (!success)
			{
				ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.unable_to_reset, null, Wolf.Core.Resources.AppStrings.okay_title);
				return;
			}
			string message = Wolf.Core.Resources.AppStrings.forgot_password_message_reset_to + " " + email + "." + Environment.NewLine + Wolf.Core.Resources.AppStrings.forgot_password_message_reset_link + Environment.NewLine + Environment.NewLine + Wolf.Core.Resources.AppStrings.forgot_password_message_reset_check_spam;
			ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.forgot_password_title_reset, message, delegate
			{
				DoResetPassword().ConfigureAwait(continueOnCapturedContext: false);
				return Task.FromResult<object>(null);
			}, cancellableOperation: false, null, Wolf.Core.Resources.AppStrings.okay_title, Wolf.Core.Resources.AppStrings.forgot_password_button_resend, OnConfirmActionTiming.BeforeClose);
			BaseDialogViewModel.ShowDialogViewModel<PasswordResetDialogViewModel>(arbitraryData);
		}

