			{
				base.ArbitraryData = value;
				UpdateFromArbitraryData();
			}
		}

		private InputPasswordDialogInitializationData InitializationData => ArbitraryData as InputPasswordDialogInitializationData;

		public bool ConfirmButtonEnabled
		{
			get
			{
				string text = FieldInput;
				if (text == null)
				{
					return false;
				}
				return text.Length >= 4;
			}
		}

		public string FieldInput
		{
			get
			{
				return fieldInput;
			}
			private set
			{
				if (fieldInput != value)
				{
					if (HasError.Value)
					{
						HasError.Value = false;
						ErrorMessage.Value = null;
					}
					fieldInput = value;
					RaisePropertyChanged("FieldInput");
					RaisePropertyChanged("ConfirmButtonEnabled");
				}
			}
		}

		public ICommand Cancel => new MvxCommand(DoCancelOperation);

		public ICommand Confirm => new MvxAsyncCommand(DoConfirmOperation, DoConfirmOperationCanExecute);

		public ICommand ForgotPasword => new MvxCommand(DoForgotPasswordOperation);

		public InputPasswordDialogViewModel(ILocalSettings localSettings)
		{
			try
			{
				TitleText = new NC<string>();
				InputHintValueText = new NC<string>();
				CancelButtonText = new NC<string>();
				ConfirmButtonText = new NC<string>();
				ForgotPasswordButtonText = new NC<string>();
				InputHelperText = new NC<string>();
				ErrorMessage = new NC<string>();
				HasError = new NC<bool>();
				base..ctor(localSettings);
			}
			finally
