		private void UpdateFromArbitraryData()
		{
			TitleText.Value = InitializationData?.Title;
			InputHintValueText.Value = InitializationData?.InputHintValueText;
			ConfirmButtonText.Value = InitializationData?.ConfirmButtonText ?? Wolf.Core.Resources.AppStrings.ok;
			CancelButtonText.Value = InitializationData?.CancelButtonText ?? Wolf.Core.Resources.AppStrings.cancel;
			ForgotPasswordButtonText.Value = InitializationData?.ForgotPasswordButtonText ?? Wolf.Core.Resources.AppStrings.account_selection_verify_forgot_password;
			InputHelperText.Value = InitializationData?.InputHelperText ?? Wolf.Core.Resources.AppStrings.input_password_dialog_enter_valid_password;
			errorMessage = InitializationData?.ErrorText;
		}

		private async Task DoConfirmOperation()
		{
			doNotSetResult = true;
			if (await (InitializationData?.ConfirmAction?.Invoke(FieldInput)))
			{
				DoClose();
				return;
			}
			HasError.Value = true;
			ErrorMessage.Value = errorMessage;
		}

		private bool DoConfirmOperationCanExecute()
		{
			return ConfirmButtonEnabled;
		}

		private void DoCancelOperation()
		{
			doNotSetResult = true;
			InitializationData?.CancelAction?.Invoke();
			DoClose();
		}

		private void DoForgotPasswordOperation()
		{
			doNotSetResult = true;
			InitializationData?.ForgotPasswordAction?.Invoke();
			DoClose();
		}

		protected override void DoClose()
		{
			if (!doNotSetResult)
			{
				InitializationData?.TCS.SetResult(result: false);
			}
			base.DoClose();
		}

