	public class PushNotificationHandlingService : IPushNotificationHandlingService
	{
		private static string Tag = "PushNotificationHandlingService";

		private Action afterLeftWorkout = delegate
		{
		};

		private InWorkoutViewModel viewModel;

		private readonly IDialogPresenter dialogPresenter;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IWolfTrackingService trackingService;

		private readonly IAppLifecycleService appLifecycleService;

		public PushNotificationHandlingService(IDialogPresenter dialogPresenter, IWorkoutSettings workoutSettings, IWolfTrackingService trackingService, IAppLifecycleService appLifecycleService)
		{
			this.dialogPresenter = dialogPresenter;
			this.workoutSettings = workoutSettings;
			this.trackingService = trackingService;
			this.appLifecycleService = appLifecycleService;
		}

		public void HandlePushNotification(Action onCancel)
		{
			Mvx.Resolve<IWolfAnalytics>().OnPushNotificationHandled(trackingService.IsInWorkout);
			if (trackingService.IsInWorkout)
			{
				afterLeftWorkout = onCancel;
				viewModel = (InWorkoutViewModel)dialogPresenter.CurrentMainViewModel;
				if (appLifecycleService.IsAppInBackground)
				{
					viewModel.OnViewIsShown += InWorkoutViewModel_OnViewIsShown;
				}
				else
				{
					DisplayDialog();
				}
			}
			else
			{
				onCancel();
			}
		}

		private void onLeaveWorkout()
		{
			viewModel.OnWorkoutFinished += InWorkoutViewModel_OnWorkoutFinished;
			workoutSettings.WorkoutContainer.WorkoutRunner?.StopAsync();
			viewModel?.NavigateAway(showError: false, "HandlePushNotification");
		}

		private void InWorkoutViewModel_OnWorkoutFinished(object sender, EventArgs e)
		{
			afterLeftWorkout();
			viewModel.OnWorkoutFinished -= InWorkoutViewModel_OnWorkoutFinished;
		}

		private void InWorkoutViewModel_OnViewIsShown(object sender, EventArgs e)
		{
			viewModel.OnViewIsShown -= InWorkoutViewModel_OnViewIsShown;
			DisplayDialog();
		}

		private void DisplayDialog()
		{
			bool flag = false;
			try
			{
				flag = workoutSettings.WorkoutContainer.Stats.RunningStats.TimeSeconds.MaxTimestamp < 60.0;
			}
			catch (Exception ex)
			{
				Log.Trace(Tag, "Message: " + ex.Message + Environment.NewLine + "StackTrace: " + ex.StackTrace);
			}
			ConfirmationInitializationData initData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.dialog_leave_workout_title, flag ? Wolf.Core.Resources.AppStrings.dialog_leave_workout_not_saved_text : Wolf.Core.Resources.AppStrings.dialog_leave_workout_text, null, confirmButtonText: Wolf.Core.Resources.AppStrings.dialog_leave_workout_confirmation_text, cancelButtonText: Wolf.Core.Resources.AppStrings.dialog_leave_workout_cancellation_text, onClose: null, onCancel: delegate
			{
				onLeaveWorkout();
			});
			BaseViewModel.ShowSimpleConfirmationDialog(initData, showSafely: true);
		}
	}
	public class PushNotificationService : IPushNotificationService
	{
		private readonly ILocalSettings localSettings;

		private OneSignalSDKInternal.NotificationActionDelegate notificationActionDelegate;

		public PushNotificationService(ILocalSettings localSettings)
		{
			this.localSettings = localSettings;
		}

		~PushNotificationService()
		{
			UnregisterNotificationDelegate();
		}

		private void UnregisterNotificationDelegate()
		{
			OneSignal.Default.NotificationOpened -= notificationActionDelegate;
		}

		public void InitializeOneSignal(OneSignalSDKInternal.NotificationActionDelegate notificationActionDelegate)
		{
			OneSignal.Default.Initialize(localSettings.EnvironmentToUse.OneSignalAppId());
			this.notificationActionDelegate = notificationActionDelegate;
		}

		public void InitNotificationHandling(bool enable)
		{
			if (enable)
			{
				OneSignal.Default.NotificationOpened += notificationActionDelegate;
			}
			else
			{
				UnregisterNotificationDelegate();
			}
		}
	}
