namespace Wolf.Core.Source.Services.InWorkout
{
	public interface IWolfRecoveryStateManager : IShireRecoveryStateManager
	{
		void SaveAndStartRecoveryInterval(IWorkoutContainer workoutContainer);

		WorkoutRecoveryInfo CreateWorkoutRecoveryInfo();
	}
	public class BlobCacheRecoveryStateManager : IWolfRecoveryStateManager, IShireRecoveryStateManager, IDisposable
	{
		private const string CacheKey = "workout-recovery-info";

		private const string WorkoutIdKey = "workoutId";

		private readonly IVideoService videoService;

		private readonly IWolfAnalytics analytics;

		private readonly IWorkoutPathoutService workoutPathoutService;

		private readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		private readonly IBlobCache cache;

		private readonly ICurrentConsoleService currentConsoleService;

		protected readonly Task initialization;

		protected Task savingTask;

		private Task writingTask;

		private IFitnessConsole console;

		private IWorkoutContainer container;

		private WorkoutRecoveryInfo recoveryInfo;

		private bool isShuttingDown;

		private string currentViewModelName;

		private string latestVideoResolution = "Not available";

		private IDisposable saveInfoSub;

		private IDisposable videoReadySub;

		private IDisposable resolutionChangedSub;

		private bool disposedValue;

		public BlobCacheRecoveryStateManager(IVideoService videoService, IAppLifecycleService lifecycleService, IWolfAnalytics analytics, IWorkoutPathoutService workoutPathoutService, IMvxMainThreadDispatcher mainThreadDispatcher, ICurrentConsoleService currentConsoleService, IBlobCache cache = null)
		{
			this.videoService = videoService;
			this.analytics = analytics;
			this.workoutPathoutService = workoutPathoutService;
			this.mainThreadDispatcher = mainThreadDispatcher;
			this.cache = cache ?? GetBlobCache();
			this.currentConsoleService = currentConsoleService;
			initialization = Task.Run(async delegate
			{
				await InitializeRecoveryInfo();
			});
			writingTask = Task.CompletedTask;
			savingTask = Task.CompletedTask;
			lifecycleService.AppStateChanged -= OnAppStateChanged;
			lifecycleService.AppStateChanged += OnAppStateChanged;
			videoReadySub = videoService.VideoReady.Subscribe(VideoPlayerReady);
		}

		public void SaveAndStartRecoveryInterval(IWorkoutContainer workoutContainer)
		{
			if (workoutContainer != null)
			{
				container = workoutContainer;
				console = workoutContainer?.Console;
				saveInfoSub?.Dispose();
				saveInfoSub = Observable.Interval(TimeSpan.FromSeconds(30.0)).SubscribeWithErrorLogging(delegate
				{
					SaveInfo();
				});
				IWorkoutContainer workoutContainer2 = container;
				if (workoutContainer2 != null && !workoutContainer2.IsRecoveryWorkout)
				{
					SaveInfo();
				}
			}
		}

		private void OnAppStateChanged(object sender, AppStateEventArgs e)
		{
			if (saveInfoSub != null)
			{
				if (e.CurrentState == AppLifecycleService.AppState.Background)
				{
					PrepareToShutdown();
					return;
				}
				isShuttingDown = false;
				SaveInfo();
			}
		}

		private void SaveInfo()
		{
			if (savingTask == Task.CompletedTask)
			{
				Log.Trace("Workout", "IShireRecoveryStateManager - SaveInfo begin");
				mainThreadDispatcher.RequestMainThreadAction(delegate
				{
					TryGetCurrentViewModelName();
					savingTask = Task.Run((Func<Task>)SaveInfoAsync);
				});
			}
		}

		private async Task SaveInfoAsync()
		{
			await initialization;
			await writingTask;
			writingTask = Task.Run((Func<Task>)WriteToCacheTask);
			await writingTask;
			savingTask = Task.CompletedTask;
		}

		private async Task WriteToCacheTask()
		{
			WorkoutRecoveryInfo info = null;
			try
			{
				info = CreateWorkoutRecoveryInfo();
				WorkoutRecoveryInfo workoutRecoveryInfo = info;
				if (workoutRecoveryInfo == null || workoutRecoveryInfo.WorkoutCategory != Workout.WorkoutCategory.Video || (info?.LastVideoTimeSeconds.HasValue ?? false))
				{
					await cache.InsertObject("workout-recovery-info", info, TimeSpan.FromHours(1.0));
					await cache.Flush();
				}
				else
				{
					Log.Trace("Workout", "Ignore invalid recovery object");
				}
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error when trying to insert object into cache", exception);
			}
			finally
			{
				info?.Dispose();
			}
			Log.Trace("Workout", "IShireRecoveryStateManager - SaveInfo end");
		}

		public void PrepareToShutdown()
		{
			if (!isShuttingDown && saveInfoSub != null)
			{
				Log.Trace("Workout", "IShireRecoveryStateManager - PrepareToShutdown");
				isShuttingDown = true;
				SaveInfo();
			}
		}

		public WorkoutRecoveryInfo CreateWorkoutRecoveryInfo()
		{
			TryGetLastVideoTimeSeconds(out var lastVideoTimeSeconds);
			TryGetCalorieModifierRecoveryInfo(out var calorieMultiplierRecoveryInfo);
			TryGetMemoryUsageInfo(out var totalMemory, out var availableMemory, out var lowMemoryThreshold);
			TryGetBufferingInfo(out var totalBufferAttempts, out var totalTimeSpentBuffering);
			return new WorkoutRecoveryInfo(container.Workout.Id, container.WorkoutRunner?.RunContext, container.Workout.Category(), container.Workout.IsLiveWorkout, totalBufferAttempts, totalTimeSpentBuffering, (int)container.Workout.TargetValue, latestVideoResolution, console.PauseOverrideTime, console.LatestBasicInfo.PausedTime, lastVideoTimeSeconds, container.WorkoutRunner?.WolfGeneratedId, calorieMultiplierRecoveryInfo, isShuttingDown, currentViewModelName, totalMemory, availableMemory, lowMemoryThreshold, currentConsoleService.Console.ConsoleInfo.MachineType.ToString(), shouldAutomaticallyShowLeaderboard: true, container.Stats);
		}

		private void TryGetLastVideoTimeSeconds(out int? lastVideoTimeSeconds)
		{
			lastVideoTimeSeconds = null;
			Workout workout = container.Workout;
			if (workout == null || !workout.IsVideoWorkout())
			{
				return;
			}
			ICombinedAudioVideoPlayer preBufferedVideoPlayer = videoService.PreBufferedVideoPlayer;
			if (preBufferedVideoPlayer != null)
			{
				_ = preBufferedVideoPlayer.LastVideoPositionSeconds;
				if (true)
				{
					lastVideoTimeSeconds = (int)videoService.PreBufferedVideoPlayer.LastVideoPositionSeconds;
				}
			}
		}

		private void TryGetCalorieModifierRecoveryInfo(out CalorieMultiplierRecoveryInfo calorieMultiplierRecoveryInfo)
		{
			if (!(console.ChangeManager.Decorators.FirstOrDefault((IFitnessValueDecorator arg) => arg is ICalorieMultiplierRecoverable) is ICalorieMultiplierRecoverable calorieMultiplierRecoverable))
			{
				calorieMultiplierRecoveryInfo = null;
			}
			else
			{
				calorieMultiplierRecoveryInfo = calorieMultiplierRecoverable.GetRecoveryInfo();
			}
		}

		private void TryGetVideoResolution(out string videoResolution)
		{
			videoResolution = "Not available";
			if (Mvx.TryResolve<IMediaAnalyticsService>(out var service) && service.AnalyticsData.ContainsKey("LatestResolution"))
			{
				((Tuple<int, int>)service.AnalyticsData["LatestResolution"]).Deconstruct(out var item, out var item2);
				int num = item;
				int num2 = item2;
				videoResolution = $"{num}x{num2}";
			}
		}

		private void TryGetCurrentViewModelName()
		{
			currentViewModelName = string.Empty;
			if (Mvx.TryResolve<IDialogPresenter>(out var service))
			{
				currentViewModelName = service?.CurrentMainViewModel?.GetType().Name ?? string.Empty;
			}
		}

		private void TryGetMemoryUsageInfo(out long totalMemory, out long availableMemory, out long lowMemoryThreshold)
		{
			totalMemory = 0L;
			availableMemory = 0L;
			lowMemoryThreshold = 0L;
			if (Mvx.TryResolve<IDeviceInformation>(out var service))
			{
				totalMemory = service.TotalMemory;
				availableMemory = service.AvailableMemory;
				lowMemoryThreshold = service.LowMemoryThreshold;
			}
		}

		private void TryGetBufferingInfo(out int totalBufferAttempts, out int totalTimeSpentBuffering)
		{
			totalBufferAttempts = 0;
			totalTimeSpentBuffering = 0;
			if (Mvx.TryResolve<IVideoSyncService>(out var service))
			{
				totalBufferAttempts = service.AnalyticsData.TotalBufferAttempts;
				totalTimeSpentBuffering = (int)service.AnalyticsData.TotalTimeSpentBuffering.TotalSeconds;
			}
		}

		private void VideoPlayerReady(ICombinedAudioVideoPlayer player)
		{
			resolutionChangedSub = player.WhenVideoResolutionChanged.Subscribe(delegate(string x)
			{
				latestVideoResolution = x;
			});
		}

		private async Task InitializeRecoveryInfo()
		{
			Log.Trace("Workout", "IShireRecoveryStateManager - GetRecoveryInfo begin");
			try
			{
				recoveryInfo = await cache.GetObject<WorkoutRecoveryInfo>("workout-recovery-info");
				if (recoveryInfo.WorkoutId == null)
				{
					Log.Warn("Workout", $"Found recovery info, but workout is null. CleanShutdown: {recoveryInfo.CleanShutdown}");
				}
				else
				{
					Log.Trace("Workout", "Found recovery info for workout id " + recoveryInfo.WorkoutId);
				}
				if (Mvx.TryResolve<IWorkoutSettings>(out var service))
				{
					recoveryInfo.ShouldAutomaticallyShowLeaderboard = service.PreferredRightWorkoutWidget == WidgetType.Leaderboard;
				}
				if (recoveryInfo.CleanShutdown)
				{
					workoutPathoutService.TrackFromRecovery("shutdown", recoveryInfo.ToDictionary("workoutId"));
				}
				else
				{
					workoutPathoutService.TrackFromRecovery("signalCrash", recoveryInfo.ToDictionary("workoutId"));
					await analytics.UnexpectedShutdownInWorkout(recoveryInfo);
				}
			}
			catch (KeyNotFoundException)
			{
				Log.Trace("Workout", "IShireRecoveryStateManager - Did not find recovery info");
			}
			catch (Exception ex2)
			{
				Log.Error("Workout", string.Format("{0} - Caught {1} while initializing recovery info", "IShireRecoveryStateManager", ex2.GetType()), ex2);
				workoutPathoutService.TrackFromRecovery("recoveryParseFailed");
				cache.Invalidate("workout-recovery-info");
				recoveryInfo = null;
			}
			Log.Trace("Workout", "IShireRecoveryStateManager - GetRecoveryInfo end");
		}

		public async Task<WorkoutRecoveryInfo> GetRecoveryInfo(IFitnessConsole currentConsole, IIfitApiService api, IFeatureFlagManager featureFlagManager, IMultiReadResultSetter multiReadResultSetter, bool isMetric)
		{
			await initialization;
			bool isManualWorkout = false;
			if (recoveryInfo?.WorkoutId == null)
			{
				recoveryInfo = GetManualRecoveryInfo(currentConsole, isMetric);
				isManualWorkout = true;
			}
			EffortScoreCalculator effortScoreCalculator = new EffortScoreCalculator(api?.CurrentlyAuthenticatedUser, currentConsole, featureFlagManager.IsLeaderboardDataUploadEnabledForWorkout(recoveryInfo.RunContext.Context), isManualWorkout);
			ConsoleStateStatsFacade consoleStateStatsFacade = new ConsoleStateStatsFacade(multiReadResultSetter, currentConsole?.FacadeRepository, currentConsoleService.FitnessConsoleManager);
			recoveryInfo?.Stats?.Init(currentConsole, consoleStateStatsFacade, effortScoreCalculator);
			return recoveryInfo;
		}

		public async Task ClearRecoveryInfo()
		{
			Log.Trace("Workout", "BlobCacheRecoveryStateManager - ClearRecoveryInfo");
			saveInfoSub?.Dispose();
			saveInfoSub = null;
			if (cache == null)
			{
				Log.Trace("Workout", "BlobCacheRecoveryStateManager - ClearRecoveryInfo - cache is null, Unable to clear old workout recovery info.");
				return;
			}
			try
			{
				await cache.InvalidateObject<WorkoutRecoveryInfo>("workout-recovery-info");
				await cache.Flush();
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "BlobCacheRecoveryStateManager - ClearRecoveryInfo - Error attempting to clear cache.", exception);
			}
		}

		private static IBlobCache GetBlobCache()
		{
			if (!Mvx.TryResolve<IBlobCacheService>(out var service))
			{
				return null;
			}
			return service.Secure;
		}

		private static WorkoutRecoveryInfo GetManualRecoveryInfo(IFitnessConsole console, bool isMetric)
		{
			return new WorkoutRecoveryInfo(Workout.ManualWorkout(isMetric, console?.LatestBasicInfo?.Grade, console?.LatestBasicInfo?.RunningTime).Id, WorkoutRunnerContext.DefaultOnDemandContext, Workout.WorkoutCategory.Manual, isLiveWorkout: false, 0, 0, 0, "", 0, 0, stats: new ConsoleStateStats(), lastVideoTimeSeconds: 0, wolfGeneratedId: "", calorieMultiplierRecoveryInfo: null, isShuttingDown: false, currentViewModelName: "", totalMemory: 0L, availableMemory: 0L, lowMemoryThreshold: 0L);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!disposedValue)
			{
				if (disposing)
				{
					saveInfoSub?.Dispose();
					saveInfoSub = null;
					videoReadySub?.Dispose();
					videoReadySub = null;
					resolutionChangedSub?.Dispose();
					resolutionChangedSub = null;
					container = null;
				}
				disposedValue = true;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
