	public class StatRecoveryService : IStatRecoveryService
	{
		private const string LogTag = "StatRecoveryService";

		public const string SaveFolderName = ".wolfActivityMetrics";

		private CancellationTokenSource streamCancellationToken;

		private readonly iFit.Files.IFileSystem fileSystem;

		private BinaryWriter Writer { get; set; }

		private IFolder SaveFolder { get; set; }

		private IFile File { get; set; }

		private FileStream Stream { get; set; }

		public StatRecoveryService(iFit.Files.IFileSystem fileSystem)
		{
			this.fileSystem = fileSystem;
		}

		public async Task InitializeWorkout(ConsoleStateStats consoleStateStats, string workoutId)
		{
			_ = 2;
			try
			{
				if (Stream != null && File != null && !File.Name.Contains(workoutId))
				{
					Stream?.Close();
				}
				if (SaveFolder == null)
				{
					SaveFolder = await GetSaveFolder();
				}
				File = await SaveFolder.CreateFileAsync(workoutId, CreationCollisionOption.OpenIfExists);
				Log.Trace("StatRecoveryService", File.Path + " " + File.Name);
				await OpenStream();
				consoleStateStats.ConsoleStateStatsChanged.Subscribe(OnNextConsoleStatsChanged);
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Something went wrong trying to initialize the recovery service for the workout.", exception);
			}
		}

		private async Task<IFolder> GetSaveFolder()
		{
			return await fileSystem.LocalStorage.CreateFolderAsync(".wolfActivityMetrics", CreationCollisionOption.OpenIfExists);
		}

		private async Task OpenStream()
		{
			streamCancellationToken?.Cancel();
			streamCancellationToken = new CancellationTokenSource();
			Stream = await File.OpenAsync(FileAccess.ReadWrite, streamCancellationToken.Token);
			Writer = new BinaryWriter(Stream);
		}

		private void OnNextConsoleStatsChanged((double metricValue, double timestamp, FitnessValue type) obj)
		{
			SaveStat(obj.type, obj.metricValue, obj.timestamp);
		}

		public void SaveStat(FitnessValue type, double value, double timestamp)
		{
			Writer.Write((int)type);
			Writer.Write(value);
			Writer.Write(timestamp);
		}

		public void CloseGracefully()
		{
			streamCancellationToken?.Cancel();
			Stream?.Flush();
			Stream?.Close();
			Stream?.Dispose();
			Stream = null;
			Writer?.Close();
			Writer?.Dispose();
			Writer = null;
		}

		public async Task<ConsoleStateStats> RecoverStats(string workoutId, CancellationToken token = default(CancellationToken))
		{
			ConsoleStateStats stats = new ConsoleStateStats();
			if (SaveFolder == null)
			{
				SaveFolder = await GetSaveFolder();
			}
			File = await SaveFolder.GetFileAsync(workoutId, token);
			if (File == null)
			{
				Log.Error("StatRecoveryService", "RecoverStats - File named " + workoutId + " could not be found.");
				return stats;
			}
			try
			{
				using FileStream fileStream = await File.OpenAsync(FileAccess.Read, token);
				using BinaryReader binaryReader = new BinaryReader(fileStream);
				while (fileStream.Position < fileStream.Length)
				{
					int type = binaryReader.ReadInt32();
					double metricValue = binaryReader.ReadDouble();
					double timeStamp = binaryReader.ReadDouble();
					stats.RecoverMetricToList((FitnessValue)type, metricValue, timeStamp);
				}
			}
			catch (EndOfStreamException)
			{
				Log.Trace("StatRecoveryService", "RecoverStats - Reached the end of the file");
				return stats;
			}
			catch (Exception exception)
			{
				Log.Error("StatRecoveryService", "RecoverStats - Encountered error reading file " + workoutId + ".", exception);
			}
			return stats;
		}

		public async Task DeleteWorkoutRecoveryFile(string id)
		{
			IFile file = File;
			if (file != null && file.Name?.Contains(id) == true)
			{
				CloseGracefully();
				await File.DeleteAsync();
				return;
			}
			if (SaveFolder == null)
			{
				await GetSaveFolder();
			}
			File = await SaveFolder.GetFileAsync(id);
			if (File == null)
			{
				Log.Error("StatRecoveryService", "DeleteWorkout - File named " + id + " could not be found.");
				return;
			}
			await File.DeleteAsync();
			File = null;
		}

		public async Task DeleteAllWorkoutRecoveryFiles()
		{
			CloseGracefully();
			IEnumerable<Task> tasks = (await SaveFolder.GetFilesAsync()).Select((IFile file) => file.DeleteAsync());
			await Task.WhenAll(tasks);
			File = null;
		}
	}
	public class StatServiceRecoveryStateManager : IWolfRecoveryStateManager, IShireRecoveryStateManager, IDisposable
	{
		private const string CacheKey = "workout-recovery-info";

		private const string WorkoutIdKey = "workoutId";

		private readonly IVideoService videoService;

		private readonly IWolfAnalytics analytics;

		private readonly IWorkoutPathoutService workoutPathoutService;

		private readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		private readonly IBlobCache cache;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IStatRecoveryService statRecoveryService;

		protected readonly Task initialization;

		protected Task savingTask;

		private Task writingTask;

		private IFitnessConsole console;

		private IWorkoutContainer container;

		private WorkoutRecoveryInfo recoveryInfo;

		private bool isShuttingDown;

		private string currentViewModelName;

		private string latestVideoResolution = "Not available";

		private IDisposable saveInfoSub;

		private IDisposable videoReadySub;

		private IDisposable resolutionChangedSub;

		private bool disposedValue;

		public StatServiceRecoveryStateManager(IVideoService videoService, IAppLifecycleService lifecycleService, IWolfAnalytics analytics, IWorkoutPathoutService workoutPathoutService, IMvxMainThreadDispatcher mainThreadDispatcher, ICurrentConsoleService currentConsoleService, IStatRecoveryService statRecoveryService, IBlobCache cache = null)
		{
			this.videoService = videoService;
			this.analytics = analytics;
			this.workoutPathoutService = workoutPathoutService;
			this.mainThreadDispatcher = mainThreadDispatcher;
			this.cache = cache ?? GetBlobCache();
			this.currentConsoleService = currentConsoleService;
			this.statRecoveryService = statRecoveryService;
			initialization = Task.Run(async delegate
			{
				await InitializeRecoveryInfo();
			});
			writingTask = Task.CompletedTask;
			savingTask = Task.CompletedTask;
			lifecycleService.AppStateChanged -= OnAppStateChanged;
			lifecycleService.AppStateChanged += OnAppStateChanged;
			videoReadySub = videoService.VideoReady.Subscribe(VideoPlayerReady);
		}

		public void SaveAndStartRecoveryInterval(IWorkoutContainer workoutContainer)
		{
			if (workoutContainer != null)
			{
				container = workoutContainer;
				console = workoutContainer?.Console;
				saveInfoSub?.Dispose();
				saveInfoSub = Observable.Interval(TimeSpan.FromSeconds(30.0)).SubscribeWithErrorLogging(delegate
				{
					SaveInfo();
				});
				Task.Run(async delegate
				{
					await statRecoveryService.InitializeWorkout(container.Stats, container.WorkoutRunner?.WolfGeneratedId);
				});
				IWorkoutContainer workoutContainer2 = container;
				if (workoutContainer2 != null && !workoutContainer2.IsRecoveryWorkout)
				{
					SaveInfo();
				}
			}
		}

		private void OnAppStateChanged(object sender, AppStateEventArgs e)
		{
			if (saveInfoSub != null)
			{
				if (e.CurrentState == AppLifecycleService.AppState.Background)
				{
					PrepareToShutdown();
					return;
				}
				isShuttingDown = false;
				SaveInfo();
			}
		}

		private void SaveInfo()
		{
			if (savingTask == Task.CompletedTask)
			{
				Log.Trace("Workout", "IShireRecoveryStateManager - SaveInfo begin");
				mainThreadDispatcher.RequestMainThreadAction(delegate
				{
					TryGetCurrentViewModelName();
					savingTask = Task.Run((Func<Task>)SaveInfoAsync);
				});
			}
		}

		private async Task SaveInfoAsync()
		{
			await initialization;
			await writingTask;
			writingTask = Task.Run((Func<Task>)WriteToCacheTask);
			await writingTask;
			savingTask = Task.CompletedTask;
		}

		private async Task WriteToCacheTask()
		{
			WorkoutRecoveryInfo info = null;
			try
			{
				info = CreateWorkoutRecoveryInfo();
				WorkoutRecoveryInfo workoutRecoveryInfo = info;
				if (workoutRecoveryInfo == null || workoutRecoveryInfo.WorkoutCategory != Workout.WorkoutCategory.Video || (info?.LastVideoTimeSeconds.HasValue ?? false))
				{
					await cache.InsertObject("workout-recovery-info", info, TimeSpan.FromHours(1.0));
					await cache.Flush();
				}
				else
				{
					Log.Trace("Workout", "Ignore invalid recovery object");
				}
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error when trying to insert object into cache", exception);
			}
			finally
			{
				info?.Dispose();
			}
			Log.Trace("Workout", "IShireRecoveryStateManager - SaveInfo end");
		}

		public void PrepareToShutdown()
		{
			if (!isShuttingDown && saveInfoSub != null)
			{
				Log.Trace("Workout", "IShireRecoveryStateManager - PrepareToShutdown");
				isShuttingDown = true;
				SaveInfo();
			}
		}

		public WorkoutRecoveryInfo CreateWorkoutRecoveryInfo()
		{
			TryGetLastVideoTimeSeconds(out var lastVideoTimeSeconds);
			TryGetCalorieModifierRecoveryInfo(out var calorieMultiplierRecoveryInfo);
			TryGetMemoryUsageInfo(out var totalMemory, out var availableMemory, out var lowMemoryThreshold);
			TryGetBufferingInfo(out var totalBufferAttempts, out var totalTimeSpentBuffering);
			return new WorkoutRecoveryInfo(container.Workout.Id, container.WorkoutRunner?.RunContext, container.Workout.Category(), container.Workout.IsLiveWorkout, totalBufferAttempts, totalTimeSpentBuffering, (int)container.Workout.TargetValue, latestVideoResolution, console.PauseOverrideTime, console.LatestBasicInfo.PausedTime, lastVideoTimeSeconds, container.WorkoutRunner?.WolfGeneratedId, calorieMultiplierRecoveryInfo, isShuttingDown, currentViewModelName, totalMemory, availableMemory, lowMemoryThreshold, currentConsoleService.Console.ConsoleInfo.MachineType.ToString());
		}

		private void TryGetLastVideoTimeSeconds(out int? lastVideoTimeSeconds)
		{
			lastVideoTimeSeconds = null;
			Workout workout = container.Workout;
			if (workout == null || !workout.IsVideoWorkout())
			{
				return;
			}
			ICombinedAudioVideoPlayer preBufferedVideoPlayer = videoService.PreBufferedVideoPlayer;
			if (preBufferedVideoPlayer != null)
			{
				_ = preBufferedVideoPlayer.LastVideoPositionSeconds;
				if (true)
				{
					lastVideoTimeSeconds = (int)videoService.PreBufferedVideoPlayer.LastVideoPositionSeconds;
				}
			}
		}

		private void TryGetCalorieModifierRecoveryInfo(out CalorieMultiplierRecoveryInfo calorieMultiplierRecoveryInfo)
		{
			if (!(console.ChangeManager.Decorators.FirstOrDefault((IFitnessValueDecorator arg) => arg is ICalorieMultiplierRecoverable) is ICalorieMultiplierRecoverable calorieMultiplierRecoverable))
			{
				calorieMultiplierRecoveryInfo = null;
			}
			else
			{
				calorieMultiplierRecoveryInfo = calorieMultiplierRecoverable.GetRecoveryInfo();
			}
		}

		private void TryGetVideoResolution(out string videoResolution)
		{
			videoResolution = "Not available";
			if (Mvx.TryResolve<IMediaAnalyticsService>(out var service) && service.AnalyticsData.ContainsKey("LatestResolution"))
			{
				((Tuple<int, int>)service.AnalyticsData["LatestResolution"]).Deconstruct(out var item, out var item2);
				int num = item;
				int num2 = item2;
				videoResolution = $"{num}x{num2}";
			}
		}

		private void TryGetCurrentViewModelName()
		{
			currentViewModelName = string.Empty;
			if (Mvx.TryResolve<IDialogPresenter>(out var service))
			{
				currentViewModelName = service?.CurrentMainViewModel?.GetType().Name ?? string.Empty;
			}
		}

		private void TryGetMemoryUsageInfo(out long totalMemory, out long availableMemory, out long lowMemoryThreshold)
		{
			totalMemory = 0L;
			availableMemory = 0L;
			lowMemoryThreshold = 0L;
			if (Mvx.TryResolve<IDeviceInformation>(out var service))
			{
				totalMemory = service.TotalMemory;
				availableMemory = service.AvailableMemory;
				lowMemoryThreshold = service.LowMemoryThreshold;
			}
		}

		private void TryGetBufferingInfo(out int totalBufferAttempts, out int totalTimeSpentBuffering)
		{
			totalBufferAttempts = 0;
			totalTimeSpentBuffering = 0;
			if (Mvx.TryResolve<IVideoSyncService>(out var service))
			{
				totalBufferAttempts = service.AnalyticsData.TotalBufferAttempts;
				totalTimeSpentBuffering = (int)service.AnalyticsData.TotalTimeSpentBuffering.TotalSeconds;
			}
		}

		private void VideoPlayerReady(ICombinedAudioVideoPlayer player)
		{
			resolutionChangedSub = player.WhenVideoResolutionChanged.Subscribe(delegate(string x)
			{
				latestVideoResolution = x;
			});
		}

		private async Task InitializeRecoveryInfo()
		{
			Log.Trace("Workout", "IShireRecoveryStateManager - GetRecoveryInfo begin");
			try
			{
				recoveryInfo = await cache.GetObject<WorkoutRecoveryInfo>("workout-recovery-info");
				if (recoveryInfo.WorkoutId == null)
				{
					Log.Warn("Workout", $"Found recovery info, but workout is null. CleanShutdown: {recoveryInfo.CleanShutdown}");
				}
				else
				{
					Log.Trace("Workout", "Found recovery info for workout id " + recoveryInfo.WorkoutId);
				}
				if (recoveryInfo.WolfGeneratedId == null)
				{
					Log.Warn("Workout", $"Found recovery info, but the WolfGeneratedId is null so we can't get the workout stats. CleanShutdown: {recoveryInfo.CleanShutdown}");
				}
				else
				{
					Log.Trace("Workout", "Recovering stats from file for " + recoveryInfo.WolfGeneratedId);
					WorkoutRecoveryInfo workoutRecoveryInfo = recoveryInfo;
					workoutRecoveryInfo.Stats = await statRecoveryService.RecoverStats(recoveryInfo.WolfGeneratedId);
				}
				if (Mvx.TryResolve<IWorkoutSettings>(out var service))
				{
					recoveryInfo.ShouldAutomaticallyShowLeaderboard = service.PreferredRightWorkoutWidget == WidgetType.Leaderboard;
				}
				if (recoveryInfo.CleanShutdown)
				{
					workoutPathoutService.TrackFromRecovery("shutdown", recoveryInfo.ToDictionary("workoutId"));
				}
				else
				{
					workoutPathoutService.TrackFromRecovery("signalCrash", recoveryInfo.ToDictionary("workoutId"));
					await analytics.UnexpectedShutdownInWorkout(recoveryInfo);
				}
			}
			catch (KeyNotFoundException)
			{
				Log.Trace("Workout", "IShireRecoveryStateManager - Did not find recovery info");
			}
			catch (Exception ex2)
			{
				Log.Error("Workout", string.Format("{0} - Caught {1} while initializing recovery info", "IShireRecoveryStateManager", ex2.GetType()), ex2);
				workoutPathoutService.TrackFromRecovery("recoveryParseFailed");
				cache.Invalidate("workout-recovery-info");
				recoveryInfo = null;
			}
			Log.Trace("Workout", "IShireRecoveryStateManager - GetRecoveryInfo end");
		}

		public async Task<WorkoutRecoveryInfo> GetRecoveryInfo(IFitnessConsole currentConsole, IIfitApiService api, IFeatureFlagManager featureFlagManager, IMultiReadResultSetter multiReadResultSetter, bool isMetric)
		{
			await initialization;
			bool isManualWorkout = false;
			if (recoveryInfo?.WorkoutId == null)
			{
				recoveryInfo = GetManualRecoveryInfo(currentConsole, isMetric);
				isManualWorkout = true;
			}
			EffortScoreCalculator effortScoreCalculator = new EffortScoreCalculator(api?.CurrentlyAuthenticatedUser, currentConsole, featureFlagManager.IsLeaderboardDataUploadEnabledForWorkout(recoveryInfo.RunContext.Context), isManualWorkout);
			ConsoleStateStatsFacade consoleStateStatsFacade = new ConsoleStateStatsFacade(multiReadResultSetter, currentConsole?.FacadeRepository, currentConsoleService.FitnessConsoleManager);
			recoveryInfo?.Stats?.Init(currentConsole, consoleStateStatsFacade, effortScoreCalculator);
			return recoveryInfo;
		}

		public async Task ClearRecoveryInfo()
		{
			Log.Trace("Workout", "StatServiceRecoveryStateManager - ClearRecoveryInfo");
			saveInfoSub?.Dispose();
			saveInfoSub = null;
			if (cache == null)
			{
				Log.Trace("Workout", "StatServiceRecoveryStateManager - ClearRecoveryInfo - cache is null, Unable to clear old workout recovery info.");
				return;
			}
			try
			{
				await cache.InvalidateObject<WorkoutRecoveryInfo>("workout-recovery-info");
				await cache.Flush();
				await statRecoveryService.DeleteWorkoutRecoveryFile(recoveryInfo?.WolfGeneratedId);
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "StatServiceRecoveryStateManager - ClearRecoveryInfo - Error attempting to clear cache.", exception);
			}
		}

		private static IBlobCache GetBlobCache()
		{
			if (!Mvx.TryResolve<IBlobCacheService>(out var service))
			{
				return null;
			}
			return service.Secure;
		}

		private static WorkoutRecoveryInfo GetManualRecoveryInfo(IFitnessConsole console, bool isMetric)
		{
			return new WorkoutRecoveryInfo(Workout.ManualWorkout(isMetric, console?.LatestBasicInfo?.Grade, console?.LatestBasicInfo?.RunningTime).Id, WorkoutRunnerContext.DefaultOnDemandContext, Workout.WorkoutCategory.Manual, isLiveWorkout: false, 0, 0, 0, "", 0, 0, stats: new ConsoleStateStats(), lastVideoTimeSeconds: 0, wolfGeneratedId: "", calorieMultiplierRecoveryInfo: null, isShuttingDown: false, currentViewModelName: "", totalMemory: 0L, availableMemory: 0L, lowMemoryThreshold: 0L);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!disposedValue)
			{
				if (disposing)
				{
					saveInfoSub?.Dispose();
					saveInfoSub = null;
					videoReadySub?.Dispose();
					videoReadySub = null;
					resolutionChangedSub?.Dispose();
					resolutionChangedSub = null;
					container = null;
				}
				disposedValue = true;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
}
namespace Wolf.Core.Source.Services.Culture
{
	public interface IChangeLanguageService
	{
		IObservable<CultureInfo> WhenLanguageConfirmedInOnBoarding { get; }

		IObservable<Language> WhenLanguageInitialized { get; }

		IObservable<Language> WhenLanguageChanged { get; }

		string CurrentLanguageTwoLetterISOCode { get; }

		string WebviewLanguageCode { get; }

		Language CurrentLanguage { get; }

		CultureInfo SystemPreferredCulture { get; }

		void InitializeLanguage();

		Task ChangeLanguage(Language language);

		void ChangeOnboardingLanguage(Language language);

		void OnboardingLanguageConfirmed();

		string GetTwoLetterISOCode(Language language);

		void DeviceLanguageChangeConfirmed();
	}
	public interface ISupportedLanguageService
	{
		bool IsLanguageSupported(Language language);
	}
	public class ChangeLanguageService : IChangeLanguageService, ISupportedLanguageService
	{
		private const string Tag = "ChangeLanguageService";

		private const string UnknownLanguage = "unknown";

		private const string SystemDefaultLanguage = "systemDefault";

		private readonly CultureInfo SystemPreferredCultureInfo;

		private readonly ILocalSettings localSettings;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IWolfAnalytics analytics;

		private readonly IDeviceInformation deviceInformation;

		private bool shouldNavigateToDashboardAfterDeviceLanguageChanged;

		private readonly Dictionary<Language, string> languageToLanguageCodeDictionary = new Dictionary<Language, string>
		{
			{
				Language.Chinese,
				"zh"
			},
			{
				Language.Dutch,
				"nl"
			},
			{
				Language.English,
				"en"
			},
			{
				Language.French,
				"fr"
			},
			{
				Language.German,
				"de"
			},
			{
				Language.Italian,
				"it"
			},
			{
				Language.Norwegian,
				"nb"
			},
			{
				Language.Portuguese,
				"pt"
			},
			{
				Language.Russian,
				"ru"
			},
			{
				Language.Spanish,
				"es"
			},
			{
				Language.Klingon,
				"te"
			},
			{
				Language.SystemDefault,
				"systemDefault"
			}
		};

		private readonly Subject<CultureInfo> whenLanguageConfirmedInOnBoarding = new Subject<CultureInfo>();

		private Subject<Language> _whenLanguageInitialized = new Subject<Language>();

		private Subject<Language> _whenLanguageChanged = new Subject<Language>();

		public IObservable<CultureInfo> WhenLanguageConfirmedInOnBoarding => whenLanguageConfirmedInOnBoarding;

		public IObservable<Language> WhenLanguageInitialized => _whenLanguageInitialized;

		public IObservable<Language> WhenLanguageChanged => _whenLanguageChanged;

		public Language CurrentLanguage => languageToLanguageCodeDictionary.FirstOrDefault((KeyValuePair<Language, string> x) => x.Value == CurrentLanguageTwoLetterISOCode).Key;

		public CultureInfo SystemPreferredCulture => SystemPreferredCultureInfo;

		public string CurrentLanguageTwoLetterISOCode => GetCurrentLanguageTwoLetterISOCode();

		public string WebviewLanguageCode
		{
			get
			{
				string currentLanguageTwoLetterISOCode = CurrentLanguageTwoLetterISOCode;
				if (!(currentLanguageTwoLetterISOCode == "te"))
				{
					return currentLanguageTwoLetterISOCode;
				}
				return "te-ST";
			}
		}

		public ChangeLanguageService(ILocalSettings localSettings, IFeatureFlagManager featureFlagManager, IWolfAnalytics analytics, IDeviceInformation deviceInformation = null)
		{
			SystemPreferredCultureInfo = CultureInfo.CurrentCulture;
			this.localSettings = localSettings;
			this.featureFlagManager = featureFlagManager;
			this.analytics = analytics;
			this.deviceInformation = deviceInformation;
			InitializeLanguage();
		}

		public void InitializeLanguage()
		{
			Language currentLanguage = localSettings.CurrentLanguage;
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.UseLocalizedStrings))
			{
				Log.Trace("ChangeLanguageService", "Feature flag disabled, set to English");
				SetCurrentCultureInfo(Language.English);
			}
			else if (currentLanguage != Language.SystemDefault)
			{
				Log.Trace("ChangeLanguageService", "Restoring saved language setting");
				SetCurrentCultureInfo(currentLanguage);
			}
			else if (SystemPreferredCulture.TwoLetterISOLanguageName == "te")
			{
				Log.Trace("ChangeLanguageService", "System language is the same as Klingon language code, setting to English");
				SetCurrentCultureInfo(Language.English);
			}
			else if (IsLanguageSupported(SystemPreferredCulture))
			{
				Log.Trace("ChangeLanguageService", "Set language to system default");
				SetCurrentCultureInfo(SystemPreferredCulture);
			}
			else
			{
				Log.Trace("ChangeLanguageService", "System default language not supported");
				SetCurrentCultureInfo(Language.English);
			}
			analytics.OnLanguageInitialized(CultureInfo.DefaultThreadCurrentCulture.TwoLetterISOLanguageName, languageToLanguageCodeDictionary.GetValueSafely(localSettings.CurrentLanguage, "unknown"));
			_whenLanguageInitialized.OnNext(localSettings.CurrentLanguage);
		}

		public bool IsLanguageSupported(Language language)
		{
			CultureInfo cultureInfoFromLanguage = GetCultureInfoFromLanguage(language);
			return IsLanguageSupported(cultureInfoFromLanguage);
		}

		private bool IsLanguageSupported(CultureInfo cultureInfo)
		{
			string text = cultureInfo?.TwoLetterISOLanguageName ?? "";
			if (text == "en")
			{
				return true;
			}
			return featureFlagManager.GetString(FeatureFlags.SupportedLanguages)?.Contains(text) ?? false;
		}

		public async Task ChangeLanguage(Language language)
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.UseLocalizedStrings))
			{
				if (!IsLanguageSupported(language))
				{
					language = Language.English;
				}
				string twoLetterISOLanguageName = SystemPreferredCulture.TwoLetterISOLanguageName;
				string valueSafely = languageToLanguageCodeDictionary.GetValueSafely(language, "unknown");
				string valueSafely2 = languageToLanguageCodeDictionary.GetValueSafely(localSettings.CurrentLanguage, "unknown");
				await analytics.OnLanguageChanged(twoLetterISOLanguageName, valueSafely, valueSafely2);
				bool flag = TrySetSystemLanguage(language);
				SetCurrentCultureInfo(language);
				shouldNavigateToDashboardAfterDeviceLanguageChanged = !deviceInformation.IsBuiltIn || flag;
				localSettings.CurrentLanguage = language;
				if (!deviceInformation.IsBuiltIn || flag)
				{
					_whenLanguageChanged.OnNext(language);
				}
			}
		}

		public string GetTwoLetterISOCode(Language language)
		{
			return languageToLanguageCodeDictionary.GetValueSafely(language, "unknown");
		}

		public async void DeviceLanguageChangeConfirmed()
		{
			try
			{
				if (shouldNavigateToDashboardAfterDeviceLanguageChanged)
				{
					shouldNavigateToDashboardAfterDeviceLanguageChanged = false;
					await Task.Delay(250);
					_whenLanguageChanged.OnNext(localSettings.CurrentLanguage);
				}
			}
			catch (Exception exception)
			{
				Log.Trace("ChangeLanguageService", "Problem to notify language changed", exception);
				throw;
			}
		}

		public void ChangeOnboardingLanguage(Language language)
		{
			localSettings.CurrentLanguage = language;
			TrySetSystemLanguage(localSettings.CurrentLanguage);
			SetCurrentCultureInfo(language);
		}

		public void OnboardingLanguageConfirmed()
		{
			whenLanguageConfirmedInOnBoarding.OnNext(CultureInfo.CurrentCulture);
		}

		private string GetCurrentLanguageTwoLetterISOCode()
		{
			return CultureInfo.DefaultThreadCurrentCulture.TwoLetterISOLanguageName;
		}

		private CultureInfo GetCultureInfoFromLanguage(Language language)
		{
			string valueSafely = languageToLanguageCodeDictionary.GetValueSafely(language);
			return GetCultureInfoFromLanguageCode(valueSafely);
		}

		private CultureInfo GetCultureInfoFromLanguageCode(string languageCode)
		{
			try
			{
				return new CultureInfo(languageCode);
			}
			catch (Exception exception)
			{
				Log.Error("ChangeLanguageService", "Error finding CultureInfo for languageCode " + languageCode, exception);
				return null;
			}
		}

		private bool TrySetSystemLanguage(Language language)
		{
			Log.Trace("ChangeLanguageService", "TrySetSystemLanguage was called");
			if (deviceInformation == null)
			{
				Log.Trace("ChangeLanguageService", "Device Information was null");
				return false;
			}
			if (!deviceInformation.IsBuiltIn)
			{
				Log.Trace("ChangeLanguageService", "System language can only be changed on a built-in");
				return false;
			}
			string valueSafely = languageToLanguageCodeDictionary.GetValueSafely(language);
			if (valueSafely == null || language == Language.Klingon || language == Language.SystemDefault || valueSafely == CultureInfo.CurrentUICulture.TwoLetterISOLanguageName)
			{
				Log.Error("ChangeLanguageService", "TrySetSystemLanguage: Language " + (language.ToString() ?? "null") + " is invalid");
				return false;
			}
			if (Mvx.TryResolve<ISendBroadcastService>(out var service))
			{
				try
				{
					service.SetLanguage(valueSafely);
					return true;
				}
				catch (Exception exception)
				{
					Log.Error("ChangeLanguageService", "An error occurred while attempting to send language to Eru", exception);
				}
			}
			return false;
		}

		private void SetCurrentCultureInfo(Language language)
		{
			string valueSafely = languageToLanguageCodeDictionary.GetValueSafely(language);
			CultureInfo cultureInfoFromLanguageCode = GetCultureInfoFromLanguageCode(valueSafely);
			if (cultureInfoFromLanguageCode != null)
			{
				SetCurrentCultureInfo(cultureInfoFromLanguageCode);
				Log.Trace("ChangeLanguageService", $"Language changed to {language}");
			}
			else
			{
				Log.Trace("ChangeLanguageService", "CultureInfo is null, not setting language");
			}
		}

		private void SetCurrentCultureInfo(CultureInfo cultureInfo)
		{
			if (cultureInfo.TwoLetterISOLanguageName == "te")
			{
				Log.Trace("ChangeLanguageService", "Not changing language to Klingon on submission build.");
				return;
			}
			Wolf.Core.Resources.AppStrings.Culture = cultureInfo;
			CultureInfo.CurrentCulture = cultureInfo;
			CultureInfo.CurrentUICulture = cultureInfo;
			CultureInfo.DefaultThreadCurrentCulture = cultureInfo;
			CultureInfo.DefaultThreadCurrentUICulture = cultureInfo;
		}
	}
}
namespace Wolf.Core.Source.Services.ConnectivityService
{
	public class ConnectivityService : IConnectivityService
	{
		private const string TestUrl = "https://www.ifit.com";

		public Task<ConnectivityStatus> Status => Connectivity.NetworkAccess switch
		{
			NetworkAccess.Internet => Task.Run(async () => (!(await CanMakeNetworkRequest())) ? ConnectivityStatus.InternetNoAccess : ConnectivityStatus.Internet), 
			NetworkAccess.Local => Task.FromResult(ConnectivityStatus.Local), 
			NetworkAccess.ConstrainedInternet => Task.FromResult(ConnectivityStatus.ConstrainedInternet), 
			NetworkAccess.None => Task.FromResult(ConnectivityStatus.None), 
			_ => Task.FromResult(ConnectivityStatus.Unknown), 
		};

		private static async Task<bool> CanMakeNetworkRequest()
		{
			try
			{
				HttpClient httpClient = new HttpClient();
				return (await httpClient.GetAsync("https://www.ifit.com")).IsSuccessStatusCode;
			}
			catch
			{
				return false;
			}
		}
	}
}
namespace Wolf.Core.Source.Converters
{
	public class BoolToTypeConverter<T> : MvxValueConverter<bool, T>
	{
		private T OnTrue { get; }

		private T OnFalse { get; }

		public BoolToTypeConverter(T onTrue, T onFalse)
		{
			OnTrue = onTrue;
			OnFalse = onFalse;
		}

		protected override T Convert(bool value, Type targetType, object parameter, CultureInfo culture)
		{
			if (!value)
			{
				return OnFalse;
			}
			return OnTrue;
		}
	}
}
