		public static string GetFormattedValue(this MetricType type, double convertedValue)
		{
			if (Math.Abs(convertedValue) < 1E-06)
			{
				return type.GetBlankValue();
			}
			IValueFormatter formatter = type.GetFormatter();
			switch (type)
			{
			case MetricType.ElapsedTime:
			case MetricType.Pace:
			case MetricType.LapTime:
			case MetricType.TimeLeft:
			case MetricType.FiveHundredSplit:
			case MetricType.AvgFiveHundredSplit:
				return formatter.Format(convertedValue);
			case MetricType.Calories:
			case MetricType.CaloriesPerHour:
			case MetricType.Watts:
			case MetricType.AverageWatts:
			case MetricType.RPM:
			case MetricType.LapsCompleted:
			case MetricType.Pulse:
			case MetricType.Resistance:
			case MetricType.AverageSpeed:
			case MetricType.Gear:
			case MetricType.Strokes:
			case MetricType.StrokesPerMin:
				return formatter.Format(convertedValue);
			case MetricType.Speed:
			case MetricType.VerticalGain:
			case MetricType.Incline:
				return formatter.Format(convertedValue, 1);
			case MetricType.Distance:
			case MetricType.DistanceLeft:
				return formatter.Format(convertedValue, 2);
			case MetricType.AverageIncline:
				return formatter.Format(convertedValue, 1);
			default:
				throw new ArgumentOutOfRangeException();
			}
		}

		public static string GetBlankValue(this MetricType type)
		{
			return type.GetFormatter().BlankValue;
		}

		public static IValueFormatter GetFormatter(this MetricType type)
		{
			switch (type)
			{
			case MetricType.ElapsedTime:
			case MetricType.Pace:
			case MetricType.LapTime:
			case MetricType.TimeLeft:
			case MetricType.FiveHundredSplit:
			case MetricType.AvgFiveHundredSplit:
				return ValueFormatters.SecondsFormatter;
			case MetricType.Calories:
			case MetricType.CaloriesPerHour:
			case MetricType.Watts:
			case MetricType.AverageWatts:
			case MetricType.RPM:
			case MetricType.LapsCompleted:
			case MetricType.Pulse:
			case MetricType.Resistance:
			case MetricType.Gear:
			case MetricType.Strokes:
			case MetricType.StrokesPerMin:
				return ValueFormatters.IntegerFormatter;
			case MetricType.AverageSpeed:
			case MetricType.Speed:
			case MetricType.VerticalGain:
			case MetricType.Incline:
			case MetricType.Distance:
			case MetricType.DistanceLeft:
				return ValueFormatters.DecimalFormatter;
			case MetricType.AverageIncline:
				return ValueFormatters.DecimalPercentFormatter;
			default:
				throw new ArgumentOutOfRangeException();
			}
		}

		public static double GetValueFromBasicInfo(this MetricType type, IConsoleBasicInfo info)
		{
			switch (type)
			{
			case MetricType.ElapsedTime:
				return info.TimeSeconds;
			case MetricType.Pace:
			case MetricType.LapTime:
				return info.LapTimeSeconds;
			case MetricType.TimeLeft:
			case MetricType.Calories:
				return info.Calories;
			case MetricType.CaloriesPerHour:
			case MetricType.Watts:
				return info.Watts;
			case MetricType.AverageWatts:
				return info.AvgWatts;
			case MetricType.RPM:
				return info.Rpm;
			case MetricType.LapsCompleted:
				return (int)info.DistanceMeters / 400;
			case MetricType.Pulse:
				return info.CurrentPulse?.UserPulse ?? 0;
			case MetricType.Resistance:
				return info.Resistance;
			case MetricType.AverageSpeed:
			case MetricType.Speed:
			case MetricType.VerticalGain:
			case MetricType.Incline:
				return info.Grade;
			case MetricType.Distance:
				return info.DistanceMeters;
			case MetricType.DistanceLeft:
			case MetricType.AverageIncline:
				return info.AvgGrade;
			case MetricType.Gear:
				return info.Gear.CurrentGear;
			case MetricType.Strokes:
				return info.Strokes;
			case MetricType.StrokesPerMin:
				return info.StrokesPerMin;
			case MetricType.FiveHundredSplit:
				return info.FiveHundredSplit;
			case MetricType.AvgFiveHundredSplit:
				return info.AvgFiveHundredSplit;
			default:
				throw new ArgumentOutOfRangeException();
			}
		}
	}
