			case StatInfoLabelType.StrokesPerMin:
			case StatInfoLabelType.FiveHundred:
			case StatInfoLabelType.DistanceInMeters:
				return formatter.Format(convertedValue);
			case StatInfoLabelType.Incline:
			case StatInfoLabelType.Speed:
			case StatInfoLabelType.Grade:
				return formatter.Format(convertedValue, 1);
			case StatInfoLabelType.Distance:
				return formatter.Format(convertedValue, 2);
			default:
				throw new ArgumentOutOfRangeException($"No Label provided for StatInfoLabelType: {type}");
			}
		}

		public static string GetBlankValue(this StatInfoLabelType type)
		{
			return type.GetFormatter().BlankValue;
		}

		private static IValueFormatter GetFormatter(this StatInfoLabelType type)
		{
			switch (type)
			{
			case StatInfoLabelType.Time:
			case StatInfoLabelType.Pace:
			case StatInfoLabelType.FiveHundred:
