			case StatInfoLabelType.Distance:
			case StatInfoLabelType.Incline:
			case StatInfoLabelType.Speed:
			case StatInfoLabelType.Grade:
				return ValueFormatters.DecimalFormatter;
			case StatInfoLabelType.Calories:
			case StatInfoLabelType.HeartRate:
			case StatInfoLabelType.Watts:
			case StatInfoLabelType.Elevation:
			case StatInfoLabelType.Cadence:
			case StatInfoLabelType.VerticalGain:
			case StatInfoLabelType.StrokesPerMin:
			case StatInfoLabelType.DistanceInMeters:
				return ValueFormatters.IntegerFormatter;
			default:
