	public class HeightSpinnerModel : IfitSpinnerModel
	{
		public enum HeightUnits
		{
			Centimeters,
			Inches,
			BothFromInches
		}

		private int _height;

		public int Height => _height;

		public HeightUnits Units { get; protected set; }

		public HeightSpinnerModel(int index, int height, HeightUnits units = HeightUnits.BothFromInches)
			: base(index, "")
		{
			_height = height;
			Units = units;
			switch (units)
			{
			case HeightUnits.BothFromInches:
			{
				int num = (int)((float)height * 2.54f);
				Tuple<int, int> heightFromInches = GetHeightFromInches(Height);
				string arg = ((heightFromInches.Item2 < 10) ? heightFromInches.Item2.ToString().PadLeft(3) : heightFromInches.Item2.ToString());
				string arg2 = ((num < 100) ? num.ToString().PadLeft(4) : num.ToString());
				base.Caption = string.Format(Wolf.Core.Resources.AppStrings.user_height_both, heightFromInches.Item1, arg, arg2);
				break;
			}
			case HeightUnits.Centimeters:
				base.Caption = string.Format(Wolf.Core.Resources.AppStrings.user_height_metric, Height);
				break;
			case HeightUnits.Inches:
			{
				Tuple<int, int> heightFromInches = GetHeightFromInches(Height);
				base.Caption = string.Format(Wolf.Core.Resources.AppStrings.user_height_standard, heightFromInches.Item1, heightFromInches.Item2);
				break;
			}
			}
		}

		private Tuple<int, int> GetHeightFromInches(int inches)
		{
			if (inches <= 0)
			{
				return new Tuple<int, int>(0, 0);
			}
			return new Tuple<int, int>(inches / 12, inches % 12);
		}
	}
