	public class UnitSpecificHeightSpinnerModel : IfitSpinnerModel
	{
		private readonly string StandardFormatString = "{0}" + Wolf.Core.Resources.AppStrings.ft + " {1} " + Wolf.Core.Resources.AppStrings.inches;

		private readonly string MetricFormatString = "{2} " + Wolf.Core.Resources.AppStrings.cm;

		private int _inches;

		private int _cm;

		public UnitSpecificHeightSpinnerModel(int index, int inches, bool isMetric)
			: base(index, "")
		{
			_inches = inches;
			_cm = (int)((float)inches * 2.54f);
			UpdateCaption(isMetric);
		}

		public void UpdateCaption(bool isMetric)
		{
			if (isMetric)
			{
				UseMetricValue();
			}
			else
			{
				UseStandardValue();
			}
		}

		private void UseStandardValue()
		{
			int num = (int)Math.Floor((float)_inches / 12f);
			int num2 = _inches - num * 12;
			base.Caption = string.Format(StandardFormatString, num, num2);
		}

		private void UseMetricValue()
		{
			string arg = ((_cm < 100) ? _cm.ToString().PadLeft(4) : _cm.ToString());
			base.Caption = string.Format(MetricFormatString, arg);
		}
	}
