			case WeightUnits.Kilograms:
				base.Caption = string.Format(Wolf.Core.Resources.AppStrings.user_weight_metric, weight);
				break;
			case WeightUnits.Pounds:
				base.Caption = string.Format(Wolf.Core.Resources.AppStrings.user_weight_standard, weight);
