namespace Wolf.Core.ConnectedApps
{
	public abstract class ConnectedAppContainer : IConnectedAppContainer
	{
		private string _displayItemName;

		private bool _isUpdatingPermissions;

		private readonly Subject<bool> _whenIsUpdatingPermissionsChanged = new Subject<bool>();

		public ConnectedApp App { get; protected set; }

		public string DisplayName { get; protected set; }

		public string DisplayItemName
		{
			get
			{
				return _displayItemName ?? DisplayName;
			}
			protected set
			{
				_displayItemName = value;
			}
		}

		public IConnectedAppAuthorizationService AuthorizationService { get; protected set; }

		public IConnectedAppWorkoutsService WorkoutsService { get; protected set; }

		public IConnectedAppPermissionsService PermissionsService { get; protected set; }

		public Dictionary<ConnectedAppPermission, bool> Permissions { get; protected set; }

		public FeatureFlag FeatureFlag { get; protected set; }

		public string LargeImageReference { get; protected set; }

		public string SmallImageReference { get; protected set; }

		public string Wordmark { get; protected set; }

		public string AuthorizationDescriptionText { get; protected set; }

		public string PermissionDescriptionText { get; protected set; }

		public bool IsIosActivity { get; protected set; }

		public bool IsAndroidActivity { get; protected set; }

		public bool IsConnected { get; set; }

		public bool IsUpdatingPermissions
		{
			get
			{
				return _isUpdatingPermissions;
			}
			set
			{
				if (value != _isUpdatingPermissions)
				{
					_isUpdatingPermissions = value;
					_whenIsUpdatingPermissionsChanged.OnNext(_isUpdatingPermissions);
				}
			}
		}

		public IObservable<bool> WhenIsUpdatingPermissionsChanged => _whenIsUpdatingPermissionsChanged;

		private string LogTag => GetType().Name;

		protected virtual void OnLanguageChanged()
		{
		}

		protected ConnectedAppContainer(IChangeLanguageService changeLanguageService)
		{
			IsConnected = false;
			Permissions = new Dictionary<ConnectedAppPermission, bool>();
			changeLanguageService.WhenLanguageChanged.SubscribeWithErrorLogging(delegate
			{
				OnLanguageChanged();
			});
		}

		public virtual void Update(UserIntegrationResponse response)
		{
			if (response == null)
			{
				IsConnected = false;
				Permissions.Keys.ToList().DoForEach(delegate(ConnectedAppPermission key)
				{
					Permissions[key] = false;
				});
				return;
			}
			if (response.IntegrationType != App.ToIntegrationType())
			{
				Log.Error(LogTag, "ConnectedAppContainer::Update called with mismatched integration types (container: " + App.ToIntegrationType() + "), response: " + response.IntegrationType + ")");
				return;
			}
			IsConnected = response.IsActive;
			if (response.SyncSettings != null)
			{
				Dictionary<ConnectedAppPermission, bool> list = response.SyncSettings.CreatePermissionsDictionary();
				list.DoForEach(delegate(KeyValuePair<ConnectedAppPermission, bool> permission)
				{
					Permissions[permission.Key] = permission.Value;
				});
			}
		}

		protected string CreateDefaultAuthorizationDescriptionText(bool isTwoWaySync)
		{
			if (!isTwoWaySync)
			{
				return string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_sync_from, DisplayName);
			}
			return string.Format(Wolf.Core.Resources.AppStrings.settings_connected_apps_sync_between, DisplayName);
		}
	}
