	public class ConnectedAppsCollection : IConnectedAppsCollection
	{
		private readonly IIfitApiService apiService;

		public IConnectedAppContainer this[ConnectedApp connectedApp] => ConnectedApps.First((IConnectedAppContainer container) => container.App == connectedApp);

		public IReadOnlyList<IConnectedAppContainer> ConnectedApps { get; }

		public ConnectedAppsCollection(IIfitApiService apiService, IMainThreadService mainThreadService, IWebAuthenticatorService webAuthenticatorService, IChangeLanguageService changeLanguageService)
		{
			this.apiService = apiService;
			List<IConnectedAppContainer> list = new List<IConnectedAppContainer>();
			if (Mvx.TryResolve<IAppleHealthAuthorizationService>(out var service))
			{
				list.Add(new AppleHealthConnectedAppContainer(changeLanguageService, service));
			}
			list.Add(new GarminConnectedAppContainer(changeLanguageService, apiService, mainThreadService, webAuthenticatorService));
			list.Add(new GoogleFitConnectedAppContainer(changeLanguageService, apiService, mainThreadService, webAuthenticatorService));
			list.Add(new StravaConnectedAppContainer(changeLanguageService, apiService, mainThreadService, webAuthenticatorService));
			list.Sort((IConnectedAppContainer x, IConnectedAppContainer y) => string.Compare(x.DisplayItemName, y.DisplayItemName));
			ConnectedApps = list.AsReadOnly();
		}

		public async Task UpdateAsync(CancellationToken cancellationToken = default(CancellationToken))
		{
			IIFitConnectedAppsApi gatewayService = apiService.GetGatewayService<IIFitConnectedAppsApi>();
			UserIntegrationResponse[] source = await gatewayService.GetUserIntegrationsAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			foreach (IConnectedAppContainer container in ConnectedApps)
			{
				UserIntegrationResponse response = source.FirstOrDefault((UserIntegrationResponse integration) => integration.IntegrationType == container.App.ToIntegrationType() && integration.IsActive);
				container.Update(response);
			}
		}
	}
