namespace Wolf.Core.ConnectedApps.Util
{
	public static class ConnectedAppsUtil
	{
		public static ConnectedApp ToConnectedApp(string integrationType)
		{
			return integrationType switch
			{
				"amazon-halo" => ConnectedApp.Strava, 
				"apple-health" => ConnectedApp.AppleHealth, 
				"google-fit" => ConnectedApp.GoogleFit, 
				"garmin" => ConnectedApp.Garmin, 
				"strava" => ConnectedApp.Strava, 
				"oura-ring" => ConnectedApp.Oura, 
				_ => throw new NotSupportedException("Not supported integrationType: " + integrationType), 
			};
		}

		public static string ToIntegrationType(this ConnectedApp connectedApp)
		{
			return connectedApp switch
			{
				ConnectedApp.AmazonHalo => "strava", 
				ConnectedApp.AppleHealth => "apple-health", 
				ConnectedApp.GoogleFit => "google-fit", 
				ConnectedApp.Garmin => "garmin", 
				ConnectedApp.Strava => "strava", 
				ConnectedApp.Oura => "oura-ring", 
				_ => throw new NotSupportedException(string.Format("Not supported {0}: {1}", "connectedApp", connectedApp)), 
			};
		}

		public static ISyncSettings CreateSyncSettings(this Dictionary<ConnectedAppPermission, bool> permissions)
		{
			if (!permissions.ContainsKey(ConnectedAppPermission.Send))
			{
				Log.Debug("Settings", "CreateSyncSettings: Returning Receive-Only sync settings.");
				return new OneWaySyncSettings
				{
					FromThirdParty = permissions[ConnectedAppPermission.Receive]
				};
			}
			Log.Debug("Settings", "CreateSyncSettings: Returning Send & Receive sync settings.");
			return new TwoWaySyncSettings
			{
				FromThirdParty = permissions[ConnectedAppPermission.Receive],
				ToThirdParty = permissions[ConnectedAppPermission.Send]
			};
		}

		private static IEnumerable<KeyValuePair<ConnectedAppPermission, bool>> CreatePermissionPairs(ISyncSettings syncSettings)
		{
			if (!(syncSettings is OneWaySyncSettings oneWaySyncSettings))
			{
				if (syncSettings is TwoWaySyncSettings twoWaySyncSettings)
				{
					yield return KeyValuePair.Create(ConnectedAppPermission.Receive, twoWaySyncSettings.FromThirdParty);
					yield return KeyValuePair.Create(ConnectedAppPermission.Send, twoWaySyncSettings.ToThirdParty);
				}
			}
			else
			{
				yield return KeyValuePair.Create(ConnectedAppPermission.Receive, oneWaySyncSettings.FromThirdParty);
			}
		}

		public static Dictionary<ConnectedAppPermission, bool> CreatePermissionsDictionary(params ConnectedAppPermission[] permissions)
		{
			return permissions.ToDictionary((ConnectedAppPermission permission) => permission, (ConnectedAppPermission _) => false);
		}

		public static Dictionary<ConnectedAppPermission, bool> CreatePermissionsDictionary(this ISyncSettings syncSettings)
		{
			return new Dictionary<ConnectedAppPermission, bool>(CreatePermissionPairs(syncSettings));
		}
	}
}
namespace Wolf.Core.ConnectedApps.Services
{
	public class ConnectedAppPermissionsService : IConnectedAppPermissionsService
	{
		private readonly ConnectedApp app;

		private readonly IIfitApiService apiService;

		public ConnectedAppPermissionsService(ConnectedApp app, IIfitApiService apiService)
		{
			this.app = app;
			this.apiService = apiService;
		}

		public Task UpdatePermissionsAsync(Dictionary<ConnectedAppPermission, bool> permissions, CancellationToken cancellationToken = default(CancellationToken))
		{
			string integrationType = app.ToIntegrationType();
			ISyncSettings syncSettings = permissions.CreateSyncSettings();
			IIFitConnectedAppsApi gatewayService = apiService.GetGatewayService<IIFitConnectedAppsApi>();
			Log.Trace("Settings", string.Format("{0} : Updating permissions for {1} async", "UpdatePermissionsAsync", app));
			return gatewayService.UpdateIntegrationSyncSettings(integrationType, syncSettings, cancellationToken);
		}
	}
	public class ConnectedAppWorkoutsService : IConnectedAppWorkoutsService
	{
		private readonly string workoutBrowserLinkPattern;

		private readonly IMainThreadService mainThreadService;

		public ConnectedAppWorkoutsService(string workoutBrowserLinkPattern, IMainThreadService mainThreadService)
		{
			this.workoutBrowserLinkPattern = workoutBrowserLinkPattern;
			this.mainThreadService = mainThreadService;
		}

		public Task OpenConnectedAppWorkoutAsync(string connectedAppWorkoutId)
		{
			string workoutLink = string.Format(workoutBrowserLinkPattern, connectedAppWorkoutId);
			Log.Trace("Settings", "OpenConnectedAppWorkoutAsync : Launching workoutLink");
			return mainThreadService.InvokeOnMainThreadAsync(() => Browser.OpenAsync(workoutLink));
		}
	}
	public class UrlAuthorizationService : IConnectedAppAuthorizationService
	{
		public const string CallbackScheme = "com.ifit.wolf";

		public const string CallbackHost = "third-party-adapter";

		public const string CallbackPathPrefix = "/connect";

		public const string CallbackUrl = "com.ifit.wolf://third-party-adapter/connect";

		private const string LogTag = "UrlAuthorizationService";

		private readonly ConnectedApp app;

		private readonly IIfitApiService apiService;

		private readonly IMainThreadService mainThreadService;

		private readonly IWebAuthenticatorService webAuthenticatorService;

		private readonly SemaphoreSlim getAuthorizationUrlLock = new SemaphoreSlim(1, 1);

		private readonly bool refreshAuthUrlForEveryAttempt;

		private string cachedAuthorizationUrl;

		public UrlAuthorizationService(ConnectedApp app, bool refreshAuthUrlForEveryAttempt, IIfitApiService apiService, IMainThreadService mainThreadService, IWebAuthenticatorService webAuthenticatorService)
		{
			this.app = app;
			this.refreshAuthUrlForEveryAttempt = refreshAuthUrlForEveryAttempt;
			this.apiService = apiService;
			this.mainThreadService = mainThreadService;
			this.webAuthenticatorService = webAuthenticatorService;
			apiService.WhenCurrentUserIdChanged.SubscribeWithErrorLogging(async delegate
			{
				try
				{
					await getAuthorizationUrlLock.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
					cachedAuthorizationUrl = null;
				}
				finally
				{
					getAuthorizationUrlLock.Release();
				}
			});
			Log.Trace("UrlAuthorizationService", string.Format("{0} created for {1}", "UrlAuthorizationService", app));
		}

		public async Task<bool> AuthorizeAsync(CancellationToken cancellationToken = default(CancellationToken))
		{
			string authorizationUrl = await GetAuthorizationUrlAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			bool result = await mainThreadService.InvokeOnMainThreadAsync(async delegate
			{
				try
				{
					cancellationToken.ThrowIfCancellationRequested();
					AuthorizationResult authorizationResult = new AuthorizationResult((await webAuthenticatorService.AuthenticateAsync(new Uri(authorizationUrl), new Uri("com.ifit.wolf://third-party-adapter/connect"))).Properties);
					if (!authorizationResult.ThirdPartyConnectionSuccess)
					{
						Log.Info("UrlAuthorizationService", $"Authorization failed: {authorizationResult}");
					}
					return authorizationResult.ThirdPartyConnectionSuccess;
				}
				catch (TaskCanceledException arg)
				{
					Log.Info("UrlAuthorizationService", $"Authorization cancelled: {arg}");
					throw;
				}
				finally
				{
					UrlAuthorizationService urlAuthorizationService = this;
					bool forceRefresh = refreshAuthUrlForEveryAttempt;
					urlAuthorizationService.GetAuthorizationUrlAsync(default(CancellationToken), forceRefresh);
				}
			});
			cancellationToken.ThrowIfCancellationRequested();
			return result;
		}

		public async Task DeauthorizeAsync(CancellationToken cancellationToken = default(CancellationToken))
		{
			IIFitConnectedAppsApi gatewayService = apiService.GetGatewayService<IIFitConnectedAppsApi>();
			try
			{
				await gatewayService.DeleteIntegrationAsync(app.ToIntegrationType(), cancellationToken);
			}
			finally
			{
				UrlAuthorizationService urlAuthorizationService = this;
				bool forceRefresh = refreshAuthUrlForEveryAttempt;
				urlAuthorizationService.GetAuthorizationUrlAsync(default(CancellationToken), forceRefresh);
			}
		}

		private async Task<string> GetAuthorizationUrlAsync(CancellationToken cancellationToken = default(CancellationToken), bool forceRefresh = false)
		{
			_ = 1;
			try
			{
				await getAuthorizationUrlLock.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				if (forceRefresh || cachedAuthorizationUrl.IsNullOrEmpty())
				{
					Log.Trace("UrlAuthorizationService", "Fetching Auth Url...");
					cachedAuthorizationUrl = await FetchAuthorizationUrlAsync(cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
					return cachedAuthorizationUrl;
				}
				return cachedAuthorizationUrl;
			}
			catch (Exception ex)
			{
				Log.Error("Settings", "Error getting authorization URL: " + ex.Message);
			}
			finally
			{
				getAuthorizationUrlLock.Release();
			}
			return null;
		}

		private async Task<string> FetchAuthorizationUrlAsync(CancellationToken cancellationToken = default(CancellationToken))
		{
			IIFitConnectedAppsApi gatewayService = apiService.GetGatewayService<IIFitConnectedAppsApi>();
			return (await gatewayService.GetAuthorizationUrlAsync(app.ToIntegrationType(), cancellationToken).ConfigureAwait(continueOnCapturedContext: false)).RedirectUrl;
		}
	}
