	public class HKWorkoutToActivityLogTranslator
	{
		private readonly IStatsToActivityLogTranslator statsToActivityLogTranslator;

		private readonly IHKWorkoutToMetricStatsTranslator hKWorkoutToMetricStatsTranslator;

		public HKWorkoutToActivityLogTranslator(IHKWorkoutToMetricStatsTranslator hKWorkoutToMetricStatsTranslator, IStatsToActivityLogTranslator statsToActivityLogTranslator)
		{
			this.hKWorkoutToMetricStatsTranslator = hKWorkoutToMetricStatsTranslator;
			this.statsToActivityLogTranslator = statsToActivityLogTranslator;
		}

		private void CheckToActivityLogAsyncParameters(IHKWorkoutWrapper workout)
		{
			if (workout == null)
			{
				throw new ArgumentException("workout");
			}
		}

		public async Task<ActivityLog> ToActivityLogAsync(IHKWorkoutWrapper workout)
		{
			CheckToActivityLogAsyncParameters(workout);
			MetricStats metricStats = hKWorkoutToMetricStatsTranslator.ToMetricStats(workout);
			ActivityLog activityLog = await statsToActivityLogTranslator.ToActivityLog(metricStats);
			activityLog.Start = workout.StartDateUtc;
			activityLog.End = workout.EndDateUtc;
			activityLog.Duration = (long)TimeSpan.FromSeconds(workout.DurationInSeconds).TotalMilliseconds;
			activityLog.Title = workout.Source;
			activityLog.Type = workout.IFitActivityType;
			activityLog.SoftwareNumber = null;
			activityLog.MachineId = null;
			activityLog.Origin = ActivityLog.ActivityOrigin.HealthKit.GetEnumMemberAttributeValue();
			activityLog.WolfGeneratedId = workout.Uuid;
			return activityLog;
		}
	}
