namespace Wolf.Core.Services
{
	public class BranchInitializer : IBranchIdentityInterface
	{
		private enum LoginState
		{
			LoggedOut,
			LoggingIn,
			LoggedIn,
			LoggingOut
		}

		private const string Login = "LOGIN";

		private readonly Func<Branch> getInstance;

		private readonly IIfitApiService iFitApi;

		private LoginState loginState;

		private string loggedInId;

		private bool loginPending;

		public static void Initialize(Func<Branch> getInstance, string anonymousId)
		{
			getInstance().SetRequestMetadata("$segment_anonymous_id", anonymousId);
			BranchInitializer service = new BranchInitializer(getInstance);
			Mvx.RegisterSingleton(service);
			if (Mvx.TryResolve<IAppLinking>(out var service2))
			{
				service2.MarkBranchInitialized();
			}
		}

		public BranchInitializer(Func<Branch> getInstance)
		{
			this.getInstance = getInstance;
			loginState = LoginState.LoggedOut;
			if (Mvx.TryResolve<IIfitApiService>(out iFitApi))
			{
				iFitApi.WhenCurrentUserIdChanged.Subscribe(OnUserChanged);
				if (iFitApi.CurrentlyAuthenticatedUser != null)
				{
					loginPending = true;
					OnUserChanged("");
				}
			}
			else
			{
				Log.Error("Branch", "Unable to resolve IIfitApiService in BranchService.Initialize");
			}
		}

		private void OnUserChanged(string newUserId)
		{
			switch (loginState)
			{
			case LoginState.LoggedIn:
				BeginLogout();
				break;
			case LoginState.LoggedOut:
				SetIdentityIfNeeded();
				break;
			default:
				Log.Error("Branch", $"Unhandled state {loginState} in OnUserChanged, please add a case to the switch.");
				break;
			case LoginState.LoggingIn:
			case LoginState.LoggingOut:
				break;
			}
		}

		private void SetIdentityIfNeeded()
		{
			User currentlyAuthenticatedUser = iFitApi.CurrentlyAuthenticatedUser;
			if (currentlyAuthenticatedUser != null)
			{
				loginState = LoginState.LoggingIn;
				loggedInId = currentlyAuthenticatedUser.Id;
				getInstance().SetIdentity(currentlyAuthenticatedUser.Id, this);
			}
		}

		private void BeginLogout()
		{
			loginState = LoginState.LoggingOut;
			Log.Debug("Branch", "Logging out of Branch");
			getInstance().Logout(this);
		}

		public void IdentitySet(Dictionary<string, object> data)
		{
			loginState = LoginState.LoggedIn;
			Log.Debug("Branch", "Successfully set identity in Branch");
			if (loggedInId != iFitApi.CurrentlyAuthenticatedUser?.Id)
			{
				BeginLogout();
			}
			else if (loginPending)
			{
				loginPending = false;
				Log.Debug("Branch", "Sending LOGIN event to Branch");
				BranchEvent branchEvent = new BranchEvent("LOGIN");
				branchEvent.AddCustomData("ifit_id", loggedInId);
				branchEvent.AddCustomData("is_secondary", (iFitApi?.CurrentlyAuthenticatedUser?.IsSecondary == true).ToString());
				getInstance().SendEvent(branchEvent);
			}
		}

		public void LogoutComplete()
		{
			loginState = LoginState.LoggedOut;
			Log.Debug("Branch", "Successfully logged out of Branch");
			SetIdentityIfNeeded();
		}

		public void IdentityRequestError(BranchError error)
		{
			Log.Debug("Branch", $"Encountered error code {error.ErrorCode} trying to SetIdentity in Branch: {error.ErrorMessage}");
		}
	}
