	public interface IAchievementStatsService
	{
		AchievementStats AchievementStats { get; set; }

		Task FetchAndStoreAchievementStats(string workoutId);

		void ClearAchievementStats();
	}
	public class AchievementStatsService : IAchievementStatsService
	{
		public AchievementStats AchievementStats { get; set; }

		public AchievementStatsService()
		{
			ClearAchievementStats();
		}

		public async Task FetchAndStoreAchievementStats(string workoutId)
		{
			if (!workoutId.IsNullOrWhitespace())
			{
				IIfitApiService ifitApi = Mvx.Resolve<IIfitApiService>();
				try
				{
					AchievementStats = new AchievementStats(await ifitApi.GatewayService.PredictCompletedChallenges(workoutId), await GetUserStats(ifitApi));
				}
				catch (ApiException exception)
				{
					Log.Error("Api", "Error getting achievement stats", exception);
				}
			}
		}

		private async Task<string> GetUserStats(IIfitApiService ifitApi)
		{
			int year = DateTime.Now.Year;
			long? firstDayOfYear = WebDataObject.DateTimeToUnix(new DateTime(year, 1, 1));
			string[] value = (await ActivityLogType.GetTypes(ifitApi)).Select((ActivityLogType x) => x.Type).ToArray();
			return await ifitApi.Service.GetUserStatsString(null, firstDayOfYear, string.Join(",", value), true);
		}

		public void ClearAchievementStats()
		{
			AchievementStats = new AchievementStats("", "");
		}
	}
