	public interface IAppConsoleVersionService
	{
		string ConcatenateVersions();
	}
	public abstract class AppConsoleVersionService : IAppConsoleVersionService
	{
		public const string EruVersionKey = "eruVersion";

		public const string LauncherVersionKey = "launcherVersion";

		protected readonly ILocalSettings settings;

		protected readonly IAppVersionService versionService;

		protected readonly ICurrentConsoleService currentConsoleService;

		protected readonly IDeviceInformation deviceInformation;

		protected AppConsoleVersionService(ILocalSettings settings, IAppVersionService versionService, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation)
		{
			this.settings = settings;
			this.versionService = versionService;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
		}

		public string ConcatenateVersions()
		{
			List<string> list = new List<string> { GetAppVersion() };
			list.AddRange(GetPlatformSpecificData());
			list.Add(deviceInformation.SoftwareNumber.ToString());
			list.Add(GetDeviceOSVersion());
			string text = currentConsoleService.Console?.ConsoleInfo.FirmwareVersion;
			if (!string.IsNullOrWhiteSpace(text))
			{
				list.Add(text);
			}
			return string.Join(" | ", list);
		}

		protected abstract string GetDeviceOSVersion();

		protected virtual IEnumerable<string> GetPlatformSpecificData()
		{
			yield break;
		}

		protected virtual string GetAppVersion()
		{
			return versionService.MainAppVersionInfo.FullAppVersion;
		}
	}
	public interface IAppDeepLinks
	{
	}
	public enum DeepLinkSource
	{
		Unknown,
		Notification
	}
	public class AppDeepLinks : IAppDeepLinks
	{
		protected int multilinkInnerWaitTimeMs = 1000;

		private readonly IAppLinking appLinking;

		private readonly IMvxViewDispatcher viewDispatcher;

		private readonly IDeviceInformation deviceInformation;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ILocalSettings localSettings;

		private readonly IIfitApiService apiService;

		private const string LogTag = "DeepLinking";

		private bool isNavigating;

		private const string modalityArgName = "modality";

		public AppDeepLinks(IAppLinking appLinking, IMvxViewDispatcher viewDispatcher, IDeviceInformation deviceInformation, IFeatureFlagManager featureFlagManager, ILocalSettings localSettings, IIfitApiService apiService)
		{
			this.appLinking = appLinking;
			this.viewDispatcher = viewDispatcher;
			this.deviceInformation = deviceInformation;
			this.featureFlagManager = featureFlagManager;
			this.localSettings = localSettings;
			this.apiService = apiService;
			SetupHandlers();
		}

		private void SetupHandlers()
		{
			RegisterHandler("^/dashboard", NavigateToDashboard);
			RegisterHandler("^/library", NavigateToLibrary, !deviceInformation.IsBuiltIn);
			RegisterHandler("^/trophy-case", NavigateToTrophyCase, !deviceInformation.IsBuiltIn);
			RegisterHandler("^/workout/(?<id>[0-9-a-fA-F]+)", NavigateToWorkout, !deviceInformation.IsBuiltIn);
			RegisterHandler("^/live-schedule", TryShowLiveSchedule);
			RegisterHandler("^/whats-new", TryShowWhatsNew);
			RegisterHandler("^/draw-map", TryShowDrawMapViewModel);
			RegisterHandler("^/pairdevice", (Dictionary<string, string> args, Type currentVm, string deepLink) => ShowViewModel<DashboardViewModel>(new DashboardViewModel.NavObject
			{
				PromptForBleWhenShown = true,
				DeepLink = deepLink
			}, ShireViewParams.AnimateTransitionAndClearStack(isAnimated: false)));
			RegisterHandler("^/programDetails/(?<id>[0-9-a-fA-F]+)", GoToLibraryAndProgram, !deviceInformation.IsBuiltIn);
			RegisterHandler("^/liveworkout/(?<id>[0-9a-fA-F]+)", TryShowLiveWorkout);
			RegisterHandler("^/calendar", (Dictionary<string, string> args, Type currentVm, string deepLink) => ShowViewModelOnDashboard<FeedViewModel>(currentVm, new BaseWebViewViewModel.NavObject
			{
				DeepLink = deepLink
			}));
			RegisterHandler("^/settings/secondary-users", (Dictionary<string, string> args, Type currentVm, string deepLink) => ShowViewModelOnDashboard<ManageAccountsViewModel>(currentVm));
			RegisterHandler("^/settings/connected", TryShowConnectedApps);
			RegisterHandler("^/settings/account-info", (Dictionary<string, string> args, Type currentVm, string deepLink) => ShowViewModelOnDashboard<MyProfileViewModel>(currentVm));
			RegisterHandler("^/settings", (Dictionary<string, string> args, Type currentVm, string deepLink) => ShowViewModelOnDashboard<SettingsViewModel>(currentVm));
			RegisterHandler("^/feedback", (Dictionary<string, string> args, Type currentVm, string deepLink) => ShowViewModelOnDashboard<FeedbackViewModel>(currentVm));
		}

		private void RegisterHandler(string pattern, Func<Dictionary<string, string>, Type, string, bool> handler, bool waitForUser = true)
		{
			appLinking.RegisterDeepLinkHandler(pattern, (Dictionary<string, string> args, Type currentVm, string deepLink) => (!waitForUser || (apiService.HasLoggedInUser && apiService.HasPremiumOrEnabledUser)) && handler(args, currentVm, deepLink));
		}

		private bool TryShowDrawMapViewModel(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (deviceInformation.IsTablet)
			{
				return ShowViewModelOnDashboard<DrawMapViewModel>(currentViewModel, new BaseWebViewViewModel.NavObject
				{
					DeepLink = deepLink
				});
			}
			Log.Trace("DeepLinking", "Draw your own map deep link was invoked, but the device is not a tablet, so we did nothing.");
			return false;
		}

		private bool TryShowWhatsNew(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.FeatureAnnouncementsEnabled))
			{
				return ShowViewModelOnDashboard<CloseableWebViewViewModel>(currentViewModel, new CloseableWebViewViewModel.NavObject
				{
					LogTag = "WebView",
					Url = featureFlagManager.GetString(FeatureFlags.WhatsNewWebViewUrl),
					DeepLink = deepLink
				});
			}
			Log.Trace("DeepLinking", "Whats new deep link was invoked, but feature announcements are not enabled, so we did nothing.");
			return false;
		}

		private bool TryShowLiveSchedule(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (deviceInformation.IsTablet ? featureFlagManager.IsFeatureEnabled(FeatureFlags.LiveWorkoutTablet) : featureFlagManager.IsFeatureEnabled(FeatureFlags.LiveWorkoutPhone))
			{
				LiveScheduleViewModel.NavObject navObject = new LiveScheduleViewModel.NavObject
				{
					InitialModality = GetRequestedModality(args),
					DeepLink = deepLink
				};
				return ShowViewModelOnDashboard<LiveScheduleViewModel>(currentViewModel, navObject);
			}
			Log.Trace("DeepLinking", "Live schedule deep link was invoked, but live is not enabled on this device, so we did nothing.");
			return false;
		}

		private bool TryShowLiveWorkout(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (deviceInformation.IsTablet ? featureFlagManager.IsFeatureEnabled(FeatureFlags.LiveWorkoutTablet) : featureFlagManager.IsFeatureEnabled(FeatureFlags.LiveWorkoutPhone))
			{
				PreWorkoutViewModel.NavObject navObject = new PreWorkoutViewModel.NavObject
				{
					ScheduleId = args["id"],
					WorkoutSource = WorkoutSource.DeepLink,
					DashboardIndex = -1,
					DeepLink = deepLink
				};
				return ShowViewModelOnDashboard<PreWorkoutViewModel>(currentViewModel, navObject);
			}
			Log.Trace("DeepLinking", "Live workout deep link was invoked, but live is not enabled on this device. Opening schedule url instead");
			return ShowViewModel<DashboardViewModel>(new DashboardViewModel.NavObject
			{
				ExternalUrlToOpen = "https://www.ifit.com/live-schedule"
			}, ShireViewParams.AnimateTransitionAndClearStack(isAnimated: false));
		}

		private bool TryShowConnectedApps(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.ConnectedAppsFeature))
			{
				return ShowViewModelOnDashboard<ConnectedAppsListViewModel>(currentViewModel);
			}
			Log.Trace("DeepLinking", "Connected apps deep link was invoked, but connected apps is not enabled, so we did nothing.");
			return false;
		}

		private bool ShowViewModel<T>(object navObject = null, MvxBundle presentationBundle = null) where T : BaseViewModel
		{
			return ShowViewModel(typeof(T), navObject, presentationBundle);
		}

		private bool ShowViewModel(Type type, object navObject = null, MvxBundle presentationBundle = null)
		{
			MvxBundle parameterBundle = new MvxBundle(navObject?.ToSimplePropertyDictionary());
			MvxViewModelRequest request = new MvxViewModelRequest(type, parameterBundle, presentationBundle, null);
			return viewDispatcher.ShowViewModel(request);
		}

		private bool ShowViewModelOnDashboard<T>(Type currentViewModel, object navObject = null, MvxBundle presentationBundle = null) where T : BaseViewModel
		{
			return ShowRootThenViewModel<DashboardViewModel>(currentViewModel, new(Type, object, MvxBundle)[1] { (typeof(T), navObject, presentationBundle) });
		}

		private bool ShowRootThenViewModel<TRootViewModel>(Type currentViewModel, params (Type vmType, object navObject, MvxBundle presentationBundle)[] finalViewModels) where TRootViewModel : MainToolbarViewModel
		{
			List<(Type vmType, object navObject, MvxBundle presentationBundle)> allVms = new List<(Type, object, MvxBundle)> { (typeof(TRootViewModel), null, ShireViewParams.AnimateTransitionAndClearStack(isAnimated: false)) };
			allVms.AddRange(finalViewModels);
			int num = allVms.Count;
			for (int i = 0; i < allVms.Count; i++)
			{
				if (allVms[i].vmType == currentViewModel)
				{
					num = i;
					break;
				}
			}
			if (num < allVms.Count - 1)
			{
				allVms.RemoveRange(0, num + 1);
			}
			if (!isNavigating)
			{
				Task.Run(async delegate
				{
					try
					{
						isNavigating = true;
						foreach (var (type, navObject, presentationBundle) in allVms)
						{
							if (!ShowViewModel(type, navObject, presentationBundle))
							{
								break;
							}
							await Task.Delay(multilinkInnerWaitTimeMs);
						}
					}
					catch (Exception arg)
					{
						Log.Error("DeepLinking", $"Tried to navigate with a deep link but something went wrong: {arg}");
					}
					finally
					{
						isNavigating = false;
					}
				});
			}
			return true;
		}

		private bool GoToLibraryAndProgram(Dictionary<string, string> args, Type currentVm, string deepLink)
		{
			string id = args["id"];
			DetailsViewModel.NavObject navObject = new DetailsViewModel.NavObject
			{
				Id = id,
				UrlRouteName = "program",
				ReferralSource = WorkoutSource.Library.ToString(),
				DeepLink = deepLink
			};
			if (args.TryGetValue("urlRouteName", out var value))
			{
				navObject.UrlRouteName = value;
			}
			LibraryAthenaeumViewModel.NavObject item = new LibraryAthenaeumViewModel.NavObject
			{
				InitialModality = GetRequestedModality(args)
			};
			return ShowRootThenViewModel<DashboardViewModel>(currentVm, new(Type, object, MvxBundle)[2]
			{
				(typeof(LibraryAthenaeumViewModel), item, null),
				(typeof(DetailsViewModel), navObject, null)
			});
		}

		private bool NavigateToDashboard(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (args.IsNullOrEmpty())
			{
				return ShowViewModel<DashboardViewModel>(new DashboardViewModel.NavObject
				{
					DeepLink = deepLink
				}, ShireViewParams.AnimateTransitionAndClearStack(isAnimated: false));
			}
			string requestedModality = GetRequestedModality(args);
			if (!requestedModality.IsNullOrEmpty())
			{
				return ShowViewModel<DashboardViewModel>(new DashboardViewModel.NavObject
				{
					InitialModality = requestedModality,
					DeepLink = deepLink
				}, ShireViewParams.AnimateTransitionAndClearStack(isAnimated: false));
			}
			return ShowViewModel<DashboardViewModel>(new DashboardViewModel.NavObject
			{
				DeepLink = deepLink
			}, ShireViewParams.AnimateTransitionAndClearStack(isAnimated: false));
		}

		private bool NavigateToWorkout(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			PreWorkoutViewModel.NavObject navObject = new PreWorkoutViewModel.NavObject
			{
				WorkoutId = args["id"],
				WorkoutSource = WorkoutSource.NA,
				DashboardIndex = -1,
				DeepLink = deepLink
			};
			return ShowViewModelOnDashboard<PreWorkoutViewModel>(currentViewModel, navObject);
		}

		private string SanitizeLibrarySearchInput(string dirty)
		{
			if (dirty == null)
			{
				return null;
			}
			StringBuilder builder = new StringBuilder();
			dirty.ForEach(delegate(char c)
			{
				if (char.IsLetterOrDigit(c) || c == '+' || c == '%' || c == '-')
				{
					builder.Append(c);
				}
			});
			return builder.ToString();
		}

		private bool NavigateToTrophyCase(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.TrophyCaseEnabled))
			{
				return false;
			}
			if (args.Count == 0)
			{
				return ShowViewModelOnDashboard<TrophyCaseViewModel>(currentViewModel, new BaseWebViewViewModel.NavObject
				{
					DeepLink = deepLink
				});
			}
			Dictionary<string, string> dictionary = new Dictionary<string, string>(args);
			string requestedModality = GetRequestedModality(dictionary);
			if (dictionary.ContainsKey("modality"))
			{
				dictionary.Remove("modality");
			}
			LibraryAthenaeumViewModel.NavObject navObject;
			if (args.ContainsKey("page"))
			{
				string page = args["page"];
				navObject = LibraryAthenaeumViewModel.NavObject.CreateTrophyCaseWith(page);
			}
			else
			{
				navObject = LibraryAthenaeumViewModel.NavObject.CreateTrophyCase();
			}
			navObject.DeepLink = deepLink;
			navObject.InitialModality = requestedModality;
			return ShowViewModelOnDashboard<TrophyCaseViewModel>(currentViewModel, navObject);
		}

		private bool NavigateToLibrary(Dictionary<string, string> args, Type currentViewModel, string deepLink)
		{
			LibraryAthenaeumViewModel.NavObject navObject = new LibraryAthenaeumViewModel.NavObject
			{
				DeepLink = deepLink
			};
			if (args.Count == 0)
			{
				return ShowViewModelOnDashboard<LibraryAthenaeumViewModel>(currentViewModel, navObject);
			}
			Dictionary<string, string> dictionary = new Dictionary<string, string>(args);
			string requestedModality = GetRequestedModality(dictionary);
			if (dictionary.ContainsKey("modality"))
			{
				dictionary.Remove("modality");
			}
			switch (dictionary.Count)
			{
			case 0:
				if (args.ContainsKey("modality"))
				{
					navObject = new LibraryAthenaeumViewModel.NavObject();
					break;
				}
				goto default;
			case 1:
				if (args.ContainsKey("page"))
				{
					string text = args["page"];
					navObject = LibraryAthenaeumViewModel.NavObject.CreatePage(text);
					if (text == "challenges" && featureFlagManager.IsFeatureEnabled(FeatureFlags.ChallengesButtonEnabled) && !featureFlagManager.IsFeatureEnabled(FeatureFlags.TrophyCaseEnabled))
					{
						navObject.DefaultToolbarMode = MainToolbarViewModel.ToolbarMode.Challenges;
					}
					break;
				}
				if (args.ContainsKey("trainer"))
				{
					navObject = LibraryAthenaeumViewModel.NavObject.CreateTrainer(SanitizeLibrarySearchInput(args["trainer"]));
					break;
				}
				if (args.ContainsKey("category"))
				{
					navObject = LibraryAthenaeumViewModel.NavObject.CreateCategory(SanitizeLibrarySearchInput(args["category"]));
					break;
				}
				goto default;
			case 2:
				if (args.ContainsKey("category") && args.ContainsKey("subcategory"))
				{
					navObject = LibraryAthenaeumViewModel.NavObject.CreateCategory(SanitizeLibrarySearchInput(args["category"]), SanitizeLibrarySearchInput(args["subcategory"]));
					break;
				}
				goto default;
			default:
			{
				LibraryAthenaeumViewModel.LibrarySearchParams librarySearchParams = new LibraryAthenaeumViewModel.LibrarySearchParams();
				if (args.TryGetValue("category", out var value))
				{
					librarySearchParams.Category = SanitizeLibrarySearchInput(value);
				}
				if (args.TryGetValue("trainer", out var value2))
				{
					librarySearchParams.TrainerId = SanitizeLibrarySearchInput(value2);
				}
				if (args.TryGetValue("continent", out var value3))
				{
					librarySearchParams.Continent = SanitizeLibrarySearchInput(value3);
				}
				if (args.TryGetValue("target-area", out var value4))
				{
					librarySearchParams.TargetArea = SanitizeLibrarySearchInput(value4);
				}
				if (args.TryGetValue("environment", out var value5))
				{
					librarySearchParams.LocationType = SanitizeLibrarySearchInput(value5);
				}
				if (args.TryGetValue("required-equipment", out var value6))
				{
					librarySearchParams.RequiredEquipment = SanitizeLibrarySearchInput(value6);
				}
				if (args.TryGetValue("duration", out var value7))
				{
					librarySearchParams.Duration = SanitizeLibrarySearchInput(value7);
				}
				if (args.TryGetValue("intensity", out var value8))
				{
					librarySearchParams.Intensity = SanitizeLibrarySearchInput(value8);
				}
				if (args.TryGetValue("language", out var value9))
				{
					librarySearchParams.Language = SanitizeLibrarySearchInput(value9);
				}
				if (args.TryGetValue("completed", out var value10))
				{
					librarySearchParams.Completed = SanitizeLibrarySearchInput(value10);
				}
				navObject = LibraryAthenaeumViewModel.NavObject.CreateSearch(librarySearchParams);
				break;
			}
			}
			navObject.DeepLink = deepLink;
			navObject.InitialModality = requestedModality;
			if (currentViewModel != null && currentViewModel.IsSubclassOf(typeof(MainToolbarViewModel)))
			{
				return ShowViewModel<LibraryAthenaeumViewModel>(navObject);
			}
			return ShowViewModelOnDashboard<LibraryAthenaeumViewModel>(currentViewModel, navObject);
		}

		private string GetRequestedModality(Dictionary<string, string> args)
		{
			if (!args.ContainsKey("modality"))
			{
				return null;
			}
			try
			{
				int result;
				return int.TryParse(args["modality"], out result) ? DashboardNonConnectedUtils.ConvertSoftwareNumberTypeToMockType(result).ToString().ToLowerInvariant() : args["modality"];
			}
			catch (ArgumentException exception)
			{
				Log.Error("DeepLinking", "Exception converting software number to mock type", exception);
				return null;
			}
		}
	}
	public interface IAppReviewService
	{
		void RequestReview();
	}
	public abstract class AppReviewServiceBase : IAppReviewService
	{
		protected const string Tag = "AppReviewService";

		protected readonly IDeviceInformation deviceInformation;

		private readonly IDialogPresenter dialogPresenter;

		private readonly IWolfAnalytics analytics;

		protected readonly IWolfTrackingService trackingService;

		private readonly IBranchService branchService;

		private bool currentlyRequesting;

		protected AppReviewServiceBase(IDeviceInformation deviceInformation, IDialogPresenter dialogPresenter, IWolfAnalytics analytics, IWolfTrackingService trackingService, IBranchService branchService = null)
		{
			this.deviceInformation = deviceInformation;
			this.dialogPresenter = dialogPresenter;
			this.analytics = analytics;
			this.trackingService = trackingService;
			this.branchService = branchService;
		}

		public void RequestReview()
		{
			if (!currentlyRequesting && !deviceInformation.IsBuiltIn && ShouldRequestReview())
			{
				if (dialogPresenter.CurrentMainViewModel is BaseViewModel baseViewModel)
				{
					currentlyRequesting = true;
					baseViewModel.ShowSimpleConfirmationDialog(string.Format(Wolf.Core.Resources.AppStrings.request_review_title, Wolf.Core.Resources.AppStrings.app_name), Wolf.Core.Resources.AppStrings.request_review_message, OnReviewAccepted, Wolf.Core.Resources.AppStrings.not_now.ToUpper(), Wolf.Core.Resources.AppStrings.review.ToUpper(), OnClose, OnClose, dismissible: false);
				}
				trackingService.LastReviewRequestDate = DateTime.UtcNow;
			}
		}

		private void OnReviewAccepted()
		{
			analytics.ReviewedApp();
			RequestPlatformReview();
			currentlyRequesting = false;
		}

		private void OnClose()
		{
			currentlyRequesting = false;
		}

		protected abstract bool ShouldRequestReview();

		protected abstract void RequestPlatformReview();
	}
