	public abstract class BaseTouchTimeoutService
	{
		protected readonly ITouchMonitor TouchMonitor;

		protected abstract double TimeoutSeconds { get; }

		protected BaseTouchTimeoutService(ITouchMonitor touchMonitor)
		{
			TouchMonitor = touchMonitor;
			touchMonitor.TestTimeoutElapsed = (EventHandler)Delegate.Remove(touchMonitor.TestTimeoutElapsed, new EventHandler(OnTestTimeoutElapsed));
			touchMonitor.TestTimeoutElapsed = (EventHandler)Delegate.Combine(touchMonitor.TestTimeoutElapsed, new EventHandler(OnTestTimeoutElapsed));
		}

		protected virtual void OnTestTimeoutElapsed(object sender, EventArgs e)
		{
			if (TouchMonitor.SecondsSinceLastTouch >= TimeoutSeconds)
			{
				OnTimeoutSinceTouchDidElapse();
			}
		}

