	public class BleConsoleService : IBleConsoleService, IDisposable
	{
		private const string ClubTag = "ClubUnit";

		private const int DataReceivedTimeoutInterval = 60;

		private bool needsConsoleReset;

		private bool hasConnectedOnce;

		private IDisposable receiveDataTimerSub;

		private IDisposable forceDisconnectWhenReadySub;

		private IDisposable clubUnitChangedSub;

		private IDisposable clubUnitEnableDisconnectWhenLosingConnectionSub;

		private IDisposable clubUnitDisconnectWhenLosingConnectionSub;

		private ConsoleConnectionState _connectionState;

		private readonly Subject<bool> _whenEquipmentConsoleInitialized = new Subject<bool>();

		private readonly Subject<ConsoleConnectionState> _whenConnectionStateChanged = new Subject<ConsoleConnectionState>();

		private TimeSpan _dataTimeoutSpan;

		private readonly Subject<IFitnessConsole> _whenConsoleChanged = new Subject<IFitnessConsole>();

		private readonly ILocalSettings localSettings;

		private readonly IScanner scanner;

		private readonly IBleRadioStatusService bleRadioStatusService;

		private readonly ISindarinEventHandler sindarinEventHandler;

		private readonly IFatalityService fatalityService;

		private readonly IAppLifecycleService lifecycleService;

		private readonly IDeveloperSettings developerSettings;

		private readonly BaseDeviceFilter filter = new FitProDeviceFilter();

		private readonly ILogFileService logFileService;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IDisposable radioStatusSub;

		private readonly IReadWriteFacadeFactoryDependencies facadeFactoryDependencies;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IBlobCacheService cacheService;

		private readonly IDeviceInformation deviceInformation;

		private readonly IWorkoutSettings workoutSettings;

		private readonly List<Guid> registeredEquipmentIds = new List<Guid>();

		private IDisposable deviceStateSub;

		private TaskCompletionSource<IFitnessConsole> consoleTcs;

		private CancellationTokenSource consoleInitCts;

		private bool isBuiltInRegistered;

		public IBleDevice CurrentDevice { get; private set; }

		public bool IsConnectedToConsole
		{
			get
			{
				if (Console?.ConsoleInfo != null)
				{
					return ConnectionState == ConsoleConnectionState.Connected;
				}
				return false;
			}
		}

		public ConsoleConnectionState ConnectionState
		{
			get
			{
				return _connectionState;
			}
			protected set
			{
				if (_connectionState == value)
				{
					return;
				}
				Log.Trace("Ble", $"ConsoleConnectionState changed from {_connectionState} to {value}");
				_connectionState = value;
				needsConsoleReset |= hasConnectedOnce && value == ConsoleConnectionState.NotConnected;
				hasConnectedOnce |= !hasConnectedOnce && value == ConsoleConnectionState.Connected;
				if (needsConsoleReset && value == ConsoleConnectionState.Connected)
				{
					needsConsoleReset = false;
					Console?.InitializeConsole().ContinueWith(delegate
					{
						_whenEquipmentConsoleInitialized.OnNext(value: true);
					});
					facadeFactoryDependencies.RequireStartRequestedFacade.SetRequireStartRequested(requireStartRequested: true);
					_whenConnectionStateChanged.OnNext(_connectionState);
				}
				else
				{
					_whenEquipmentConsoleInitialized.OnNext(value: true);
					_whenConnectionStateChanged.OnNext(_connectionState);
				}
			}
		}

		public IObservable<bool> WhenEquipmentConsoleInitialized => _whenEquipmentConsoleInitialized?.AsObservable();

		public IObservable<ConsoleConnectionState> WhenConnectionStateChanged => _whenConnectionStateChanged?.AsObservable();

		public IFitnessConsole Console
		{
			get
			{
				return currentConsoleService.PhysicalConsole;
			}
			private set
			{
				if (currentConsoleService.PhysicalConsole != value)
				{
					needsConsoleReset = false;
					hasConnectedOnce = false;
					currentConsoleService.Console = value;
					if (Console != null)
					{
						_whenConsoleChanged.OnNext(Console);
					}
					else
					{
						_whenConsoleChanged.OnCompleted();
					}
				}
			}
		}

		public TimeSpan DataTimeoutSpan
		{
			get
			{
				return _dataTimeoutSpan;
			}
			set
			{
				if (!value.Equals(_dataTimeoutSpan))
				{
					receiveDataTimerSub?.Dispose();
					if (value.TotalSeconds <= 0.0)
					{
						_dataTimeoutSpan = TimeSpan.FromSeconds(60.0);
					}
					else
					{
						_dataTimeoutSpan = value;
					}
					receiveDataTimerSub = CurrentDevice?.WhenDataChanged.Throttle(_dataTimeoutSpan).Subscribe(delegate
					{
						DisconnectImmediate(forgetDevice: false);
					});
				}
			}
		}

		public IObservable<IFitnessConsole> WhenConsoleChanged => _whenConsoleChanged?.AsObservable();

		public IObservable<IConsoleInfo> WhenConsoleInitialized => Console.WhenConsoleInitialized.AsObservable();

		public bool? IsEquipmentRegistered
		{
			get
			{
				if (!deviceInformation.IsBuiltIn)
				{
					if (CurrentDevice == null)
					{
						return null;
					}
					return registeredEquipmentIds.Contains(CurrentDevice.Id);
				}
				return isBuiltInRegistered;
			}
		}

		public BleConsoleService(ILocalSettings localSettings, IBlobCacheService cacheService, IScanner scanner, IBleRadioStatusService bleRadioStatusService, IAppLifecycleService lifecycleService, ILogFileService logFileService, ISindarinEventHandler fitProEventHandler, IFatalityService fatalityService, IDeveloperSettings developerSettings, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IWorkoutSettings workoutSettings, IReadWriteFacadeFactoryDependencies facadeFactoryDependencies)
		{
			this.localSettings = localSettings;
			this.scanner = scanner;
			this.bleRadioStatusService = bleRadioStatusService;
			sindarinEventHandler = fitProEventHandler;
			this.fatalityService = fatalityService;
			this.lifecycleService = lifecycleService;
			this.logFileService = logFileService;
			this.currentConsoleService = currentConsoleService;
			this.cacheService = cacheService;
			this.developerSettings = developerSettings;
			this.deviceInformation = deviceInformation;
			this.workoutSettings = workoutSettings;
			this.facadeFactoryDependencies = facadeFactoryDependencies;
			radioStatusSub = bleRadioStatusService.WhenBluetoothRadioEnabledChanged.Subscribe(OnRadioStatusChanged);
			List<Guid> result = cacheService.GetFromCache<List<Guid>>("registeredEquipmentIds", "CurrentConsoleService").Result;
			if (result == null)
			{
				return;
			}
			foreach (Guid item in result)
			{
				registeredEquipmentIds.Add(item);
			}
		}

		public async Task<IFitnessConsole> ConnectToCachedConsole()
		{
			if (consoleTcs != null && !consoleTcs.Task.IsCompleted && !consoleTcs.Task.IsCanceled)
			{
				return await consoleTcs.Task;
			}
			Guid? lastDeviceGuid = currentConsoleService.SavedBleMachineId;
			if (!lastDeviceGuid.HasValue)
			{
				return null;
			}
			if (ConnectionState == ConsoleConnectionState.Connected)
			{
				IBleDevice currentDevice = CurrentDevice;
				bool num;
				if (currentDevice == null)
				{
					num = !lastDeviceGuid.HasValue;
				}
				else
				{
					Guid id = currentDevice.Id;
					Guid? guid = lastDeviceGuid;
					num = id == guid;
				}
				if (num && Console != null)
				{
					Log.Trace("Ble", "Already connected to cached BLE device console '" + CurrentDevice?.Name + "'");
					return Console;
				}
			}
			if (MockDeviceUtil.TryGetMockDevice(lastDeviceGuid.Value, out var mockDevice))
			{
				return await Connect(mockDevice);
			}
			if (lastDeviceGuid.Equals(Guid.Parse("5A63C50B-1784-4BE2-977A-6F88475AD74B")) && !string.IsNullOrEmpty(developerSettings.LastTcpIpVirtualConsoleAddress))
			{
				TcpDevice sharedDevice = TcpDevice.SharedDevice;
				byte[] bytes = Encoding.UTF8.GetBytes(developerSettings.LastTcpIpVirtualConsoleAddress);
				AdvertisementRecord item = new AdvertisementRecord(AdvertisementRecordType.DeviceAddress, bytes);
				sharedDevice.AdvertisementRecords.Add(item);
				return await Connect(TcpDevice.SharedDevice);
			}
			Log.Trace("Ble", $"Scanning for device with guid {lastDeviceGuid}");
			IFitnessConsole fitnessConsole = await ConnectWithCondition((IBleDevice x) => x.Id.Equals(lastDeviceGuid));
			Log.Trace("Ble", string.Format("{0} device with guid {1}", (fitnessConsole != null) ? "Found" : "Did not find", lastDeviceGuid));
			return fitnessConsole;
		}

		public async Task<IFitnessConsole> Connect(string pairKey)
		{
			if (consoleTcs != null && !consoleTcs.Task.IsCompleted && !consoleTcs.Task.IsCanceled)
			{
				return await consoleTcs.Task;
			}
			Log.Trace("Ble", "Scanning for device with pair key " + pairKey);
			IFitnessConsole fitnessConsole = await ConnectWithCondition((IBleDevice x) => x.PairKey == pairKey);
			Log.Trace("Ble", ((fitnessConsole != null) ? "Found" : "Did not find") + " device with pair key " + pairKey);
			return fitnessConsole;
		}

		public async Task<IFitnessConsole> Connect(IBleDevice device, int timeoutSeconds = 45)
		{
			if (consoleTcs != null && !consoleTcs.Task.IsCompleted && !consoleTcs.Task.IsCanceled)
			{
				return await consoleTcs.Task;
			}
			if (device == null)
			{
				return null;
			}
			if (Console != null && ConnectionState != ConsoleConnectionState.NotConnected)
			{
				Log.Trace("Ble", "Disconnect from current device as we wish to connect to a new one");
				await Disconnect(forgetDevice: true);
			}
			Log.Trace("Ble", $"ConsoleService Connect to {device?.Name} ({device?.PairKey}), timeout={timeoutSeconds} s, CurrentDevice {CurrentDevice?.Name} ({CurrentDevice?.PairKey}), Console {Console}");
			CurrentDevice = device;
			ConnectionState = ConsoleConnectionState.Connecting;
			IFitnessConsole console;
			if (device is NonConnectedMockDevice nonConnectedMockDevice)
			{
				await nonConnectedMockDevice.Connect();
				console = MockNonConnectedFitProConsoleFactory(nonConnectedMockDevice);
			}
			else if (device is MockDevice mockDevice)
			{
				await mockDevice.Connect();
				console = MockMockFitnessConsoleOptions(mockDevice);
			}
			else
			{
				console = ((!(device is TcpDevice device2)) ? MockBluetoothFactory(device) : MockTcpDevice(device2));
			}
			try
			{
				consoleTcs = new TaskCompletionSource<IFitnessConsole>();
				consoleInitCts = new CancellationTokenSource();
				IConsoleInfo consoleInfo = console.ConsoleInfo;
				IConsoleInfo consoleInfo2 = consoleInfo;
				if (consoleInfo2 == null)
				{
					consoleInfo2 = await console.WhenConsoleInitialized.Timeout(TimeSpan.FromSeconds(timeoutSeconds)).Take(1).ToTask(consoleInitCts.Token);
				}
				IConsoleInfo consoleInfo3 = consoleInfo2;
				if (consoleInfo3 != null)
				{
					int num = 0;
					if (device is NonConnectedMockDevice)
					{
						num = 1;
					}
					else if (device is MockDevice)
					{
						num = 1000;
					}
					if (num > 0)
					{
						await Task.Delay(num).ConfigureAwait(continueOnCapturedContext: false);
					}
					OnConnectedToNewConsole(console, device);
					ConnectionState = ConsoleConnectionState.Connected;
					consoleTcs.TrySetResult(console);
					consoleTcs = null;
					consoleInitCts?.Dispose();
					consoleInitCts = null;
					DataTimeoutSpan = TimeSpan.FromSeconds(60.0);
					currentConsoleService.LastKnownConsoleType = console.ConsoleInfo?.MachineType ?? ConsoleType.None;
					currentConsoleService.LastMockType = (console.IsNonconnectedConsole() ? new MockType?((console as INonconnectedFitnessConsole).MockType) : ((MockType?)null));
					deviceInformation.LatestSoftwareNumber = console.ConsoleInfo?.PartNumber;
					currentConsoleService.LastConsoleWasNonConnected = console.IsNonconnectedConsole();
					return console;
				}
			}
			catch (TimeoutException)
			{
				Log.Error("Ble", "Initializing the console timed out");
			}
			catch (TaskCanceledException)
			{
				Log.Error("Ble", "Awaiting initialization for console with device " + device?.Name + " " + device?.PairKey + " was cancelled.");
			}
			catch (Exception arg)
			{
				Log.Error("Ble", $"Initializing console failed due to {arg}");
			}
			await Disconnect(forgetDevice: true);
			Log.Trace("Ble", "Failed to connect to or initialize console");
			console?.Connection?.Dispose();
			console?.Dispose();
			CleanUpAfterDisconnect();
			return null;
		}

		public async Task<bool> Disconnect(bool forgetDevice)
		{
			bool flag = await PerformDisconnect(forgetDevice).ConfigureAwait(continueOnCapturedContext: false);
			if (flag)
			{
				ConnectionState = ConsoleConnectionState.NotConnected;
			}
			return flag;
		}

		public void DisconnectImmediate(bool forgetDevice, bool forceCleanup = false, bool forceDisconnect = false)
		{
			Task.Run(() => PerformDisconnect(forgetDevice, wasImmediate: true, forceCleanup, forceDisconnect));
			ConnectionState = ConsoleConnectionState.NotConnected;
		}

		public async Task ForceClubUnitDisconnect()
		{
			IFitnessConsole console = Console;
			if (console != null && console.LatestBasicInfo?.CurrentState == ConsoleState.WorkoutResults)
			{
				await Task.Delay(TimeSpan.FromSeconds(3.0));
			}
			Guid? guid = CurrentDevice?.Id;
			if (guid.HasValue)
			{
				currentConsoleService.ForgetBleMachineId(guid.Value);
			}
			CurrentDevice = null;
			DisconnectImmediate(forgetDevice: true);
		}

		private async Task<IFitnessConsole> ConnectWithCondition(Func<IBleDevice, bool> condition)
		{
			_ = 1;
			try
			{
				IBleDevice bleDevice = await scanner.ScanWithFilter(filter).Where(condition).Timeout(TimeSpan.FromSeconds(35.0))
					.Take(1)
					.ToTask();
				Log.Trace("Ble", "ConsoleService scan found device " + bleDevice?.Name + " (" + bleDevice?.PairKey + ")");
				return await Connect(bleDevice);
			}
			catch (Exception exception)
			{
				if (ConnectionState == ConsoleConnectionState.Connected && CurrentDevice != null && condition(CurrentDevice) && Console != null)
				{
					Log.Trace("Ble", "ConsoleService scan/connect failed, but already connected to what it was scanning for", exception);
					return Console;
				}
				string arg = ((CurrentDevice == null) ? "null" : $"'{CurrentDevice.Name}' id={CurrentDevice.Id}");
				Log.Error("Ble", $"ConsoleService scan/connect failed, ConnectionState={ConnectionState} CurrentDevice={arg} Console={Console}", exception);
			}
			if (Console == null)
			{
				ConnectionState = ConsoleConnectionState.NotConnected;
			}
			return null;
		}

		private async Task<bool> PerformDisconnect(bool forgetDevice, bool wasImmediate = false, bool forceCleanup = false, bool forceDisconnect = false)
		{
			if (CurrentDevice == null || !bleRadioStatusService.IsBluetoothRadioEnabled())
			{
				CleanUpAfterDisconnect();
				return true;
			}
			if (!wasImmediate)
			{
				ConnectionState = ConsoleConnectionState.Disconnecting;
			}
			_ = CurrentDevice.Id;
			await LockIfNecessary().ConfigureAwait(continueOnCapturedContext: false);
			bool flag = false;
			if (Console?.Connection != null)
			{
				flag = await Console.Connection.Disconnect().ConfigureAwait(continueOnCapturedContext: false);
			}
			else if (CurrentDevice == null)
			{
				flag = true;
			}
			else if (CurrentDevice.State == Sindarin.Core.Ble.Connection.DeviceState.Connected || CurrentDevice.State == Sindarin.Core.Ble.Connection.DeviceState.Connecting)
			{
				flag = await CurrentDevice.Disconnect(forceDisconnect).ConfigureAwait(continueOnCapturedContext: false);
			}
			if (forgetDevice && CurrentDevice != null)
			{
				currentConsoleService.ForgetBleMachineId(CurrentDevice.Id);
			}
			if (!(forceCleanup || flag))
			{
				IBleDevice currentDevice = CurrentDevice;
				if (currentDevice == null || currentDevice.State != Sindarin.Core.Ble.Connection.DeviceState.Disconnected)
				{
					goto IL_024f;
				}
			}
			CleanUpAfterDisconnect();
			flag = true;
			goto IL_024f;
			IL_024f:
			if (!flag)
			{
				IBleDevice currentDevice2 = CurrentDevice;
				if (currentDevice2 != null && currentDevice2.State == Sindarin.Core.Ble.Connection.DeviceState.Connected)
				{
					Log.Trace("Ble", "Device failed to disconnect need to close connection");
					currentConsoleService.ForgetBleMachineId(CurrentDevice.Id);
					CleanUpAfterDisconnect();
					flag = true;
				}
			}
			Log.Trace("Ble", "Disconnect was " + (flag ? "successful" : "unsuccessful"));
			return flag;
		}

		private void CleanUpAfterDisconnect()
		{
			Console?.Dispose();
			Console = null;
			CurrentDevice?.Dispose();
			CurrentDevice = null;
			ConnectionState = ConsoleConnectionState.NotConnected;
			consoleTcs?.TrySetResult(null);
			consoleTcs = null;
			consoleInitCts?.Cancel();
			consoleInitCts?.Dispose();
			consoleInitCts = null;
			receiveDataTimerSub?.Dispose();
			receiveDataTimerSub = null;
			deviceStateSub?.Dispose();
			deviceStateSub = null;
		}

		private async Task LockIfNecessary()
		{
			if (!localSettings.InDebugMode || Console == null)
			{
				return;
			}
			bool valueOrDefault = Console?.ConsoleInfo?.CanSetActivationLock == true;
			Log.Trace("Ble", $"Device supports activationLock: {valueOrDefault}");
			if (!valueOrDefault)
			{
				return;
			}
			facadeFactoryDependencies.ActivationLockFacade.SetActivationLock(ActivationLockState.Locked);
			try
			{
				await (from x in facadeFactoryDependencies.ActivationLockFacade.ObserveActivationLockChanges()
					where x != null && x.Current == ActivationLockState.Locked
					select x).Take(1).Timeout(TimeSpan.FromSeconds(15.0)).ToTask();
			}
			catch (TimeoutException)
			{
			}
			catch (ObjectDisposedException)
			{
			}
		}

		private void OnConnectedToNewConsole(IFitnessConsole console, IBleDevice device)
		{
			if (console == null || device == null)
			{
				return;
			}
			Log.Trace("Ble", "Successfully connected to and initialized device " + device.Name);
			CurrentDevice = device;
			currentConsoleService.RememberBleMachineId(device.Id);
			Console = console;
			(from x in facadeFactoryDependencies.IsClubUnitFacade.ObserveIsClubUnitChanges()
				select x.Current into isClubUnit
				where isClubUnit
				select isClubUnit).SubscribeOrInvoke(console != null && console.LatestBasicInfo?.IsClubUnit == true, delegate
			{
				SetupClubUnitSubs();
			}, ref clubUnitChangedSub);
			if (console.ConsoleInfo.MachineType == ConsoleType.Rower)
			{
				workoutSettings.ShowSliders = true;
			}
			forceDisconnectWhenReadySub?.Dispose();
			forceDisconnectWhenReadySub = (from x in facadeFactoryDependencies.IsReadyToDisconnectFacade.ObserveIsReadyToDisconnectChanges()
				select x.Current into isReadyToDisconnect
				where isReadyToDisconnect
				select isReadyToDisconnect).SubscribeAsyncWithErrorLogging((bool _) => ForceClubUnitDisconnect());
			deviceStateSub?.Dispose();
			deviceStateSub = device.WhenStateChanged.Subscribe(delegate(Sindarin.Core.Ble.Connection.DeviceState x)
			{
				switch (x)
				{
				case Sindarin.Core.Ble.Connection.DeviceState.Connected:
				{
					IFitnessConsole console2 = Console;
					ConnectionState = ((console2 != null && console2.Initialized) ? ConsoleConnectionState.Connected : ConsoleConnectionState.Connecting);
					break;
				}
				case Sindarin.Core.Ble.Connection.DeviceState.Connecting:
					ConnectionState = ConsoleConnectionState.Connecting;
					break;
				case Sindarin.Core.Ble.Connection.DeviceState.Disconnected:
				case Sindarin.Core.Ble.Connection.DeviceState.LostConnection:
					ConnectionState = ConsoleConnectionState.NotConnected;
					break;
				}
			});
		}

		public void RegisterCurrentEquipment()
		{
			if (deviceInformation.IsBuiltIn)
			{
				isBuiltInRegistered = true;
			}
			else if (CurrentDevice != null)
			{
				registeredEquipmentIds?.Add(CurrentDevice.Id);
			}
			cacheService.Flush(registeredEquipmentIds, "registeredEquipmentIds", "CurrentConsoleService");
		}

		private void SetupClubUnitSubs()
		{
			Log.Trace("ClubUnit", "Setting up club unit subs");
			IBleDevice currentDevice = CurrentDevice;
			if (currentDevice != null)
			{
				_ = currentDevice.Id;
				if (true)
				{
					Log.Trace("ClubUnit", "Forgetting the console since it is a club unit");
					currentConsoleService.ForgetBleMachineId(CurrentDevice.Id);
				}
			}
			IObservable<bool> whenObjChanged = Console.WhenStateChanged.Select((StateChange change) => change.Current == ConsoleState.Idle);
			IFitnessConsole console = Console;
			whenObjChanged.SubscribeAndInvoke(console != null && console.LatestBasicInfo?.CurrentState == ConsoleState.Idle, setDisconnectWhenLosingConnectionEnabled, ref clubUnitEnableDisconnectWhenLosingConnectionSub);
			void setDisconnectWhenLosingConnectionEnabled(bool enable)
			{
				clubUnitDisconnectWhenLosingConnectionSub?.Dispose();
				if (enable)
				{
					clubUnitDisconnectWhenLosingConnectionSub = CurrentDevice.WhenStateChanged.Where((Sindarin.Core.Ble.Connection.DeviceState state) => state == Sindarin.Core.Ble.Connection.DeviceState.LostConnection).SubscribeAsyncWithErrorLogging(delegate
					{
						Log.Trace("ClubUnit", "Disconnect club unit when losing connection");
						return ForceClubUnitDisconnect();
					});
				}
				bool shouldReconnect = !enable;
				if (Console?.Connection is PersistentConnection persistentConnection)
				{
					persistentConnection.ShouldReconnect = shouldReconnect;
				}
			}
		}

		private void OnRadioStatusChanged(bool enabled)
		{
			if (enabled && Console == null)
			{
				ConnectToCachedConsole();
			}
			if (!enabled)
			{
				IFitnessConsole console = Console;
				if (console == null || !console.IsMock())
				{
					DisconnectImmediate(forgetDevice: false, forceCleanup: true);
				}
			}
		}

		public void Dispose()
		{
			radioStatusSub?.Dispose();
			deviceStateSub?.Dispose();
			forceDisconnectWhenReadySub?.Dispose();
			clubUnitChangedSub?.Dispose();
			clubUnitEnableDisconnectWhenLosingConnectionSub?.Dispose();
			clubUnitDisconnectWhenLosingConnectionSub?.Dispose();
			receiveDataTimerSub?.Dispose();
		}

