	public interface IBleSoftwareNumberCompatibilityService : IDisposable
	{
		SupportedVersionsTable SupportedVersionsTable { get; }

		IObservable<object> WhenSupportedVersionsRetrieved { get; }

		bool HasRetrieved { get; }

		bool IsSupported(int softwareNumber);
	}
	public class BleSoftwareNumberCompatibilityService : IBleSoftwareNumberCompatibilityService, IDisposable
	{
		private const string supportedVersionsJsonUrl = "https://s3.amazonaws.com/ifit-wolf/release/Brainboard+App+Compatibility+File/compatibility.json";

		private readonly string appVersion;

		private readonly IWifiService wifiService;

		private IDisposable wifiConnectionChangedSub;

		private bool isDownloading;

		private readonly Subject<object> whenSupportedVersionsRetrieved = new Subject<object>();

		public IObservable<object> WhenSupportedVersionsRetrieved => whenSupportedVersionsRetrieved;

		public bool HasRetrieved => SupportedVersionsTable?.HasRetrieved ?? false;

		public SupportedVersionsTable SupportedVersionsTable { get; private set; }

		public BleSoftwareNumberCompatibilityService(IAppVersionService appVersionService, IWifiService wifiService)
		{
			appVersion = appVersionService.MainAppVersionInfo.AppVersion;
			this.wifiService = wifiService;
			if (SupportedVersionsTable == null && !isDownloading)
			{
				Task.Run((Func<Task>)DownloadDictionary);
			}
		}

		private async Task DownloadDictionary()
		{
			isDownloading = true;
			try
			{
				Dictionary<string, Dictionary<string, List<int>>> dictionary = await JsonDownloadUtil.DownloadAndParseJson<Dictionary<string, Dictionary<string, List<int>>>>("https://s3.amazonaws.com/ifit-wolf/release/Brainboard+App+Compatibility+File/compatibility.json");
				if (dictionary != null && dictionary.ContainsKey("AppVersions") && dictionary["AppVersions"] != null)
				{
					SupportedVersionsTable = new SupportedVersionsTable(dictionary["AppVersions"]);
					whenSupportedVersionsRetrieved.OnNext(null);
				}
				else
				{
					whenSupportedVersionsRetrieved.OnError(new Exception("Could not parse Json, or Json is invalid"));
				}
			}
			catch (Exception ex)
			{
				Log.Error("Ble", "Unable to download compatible software numbers", ex);
				whenSupportedVersionsRetrieved.OnError(ex);
				if (!wifiService.IsWifiEnabled)
				{
					wifiConnectionChangedSub?.Dispose();
					wifiConnectionChangedSub = (from x in wifiService.WhenNetworkStateChanged.SkipWhile((WifiNetworkState x) => x == WifiNetworkState.Connected).DistinctUntilChanged()
						where x == WifiNetworkState.Connected
						select x).Delay(TimeSpan.FromSeconds(2.0)).Subscribe(delegate
					{
						Task.FromResult(HandleWifiChanged());
					});
				}
			}
			finally
			{
				isDownloading = false;
			}
		}

		public bool IsSupported(int softwareNumber)
		{
			return SupportedVersionsTable?.IsSupported(softwareNumber, appVersion) ?? false;
		}

		private async Task HandleWifiChanged()
		{
			wifiConnectionChangedSub?.Dispose();
			wifiConnectionChangedSub = null;
			await DownloadDictionary();
		}

		public void Dispose()
		{
			wifiConnectionChangedSub?.Dispose();
		}
	}
	public class SupportedVersionsTable
	{
		private const string WildcardKey = "*";

		public Dictionary<string, List<int>> AppVersions { get; private set; }

		public List<int> WildcardNumbers
		{
			get
			{
				Dictionary<string, List<int>> appVersions = AppVersions;
				if (appVersions == null || !appVersions.ContainsKey("*"))
				{
					return null;
				}
				return AppVersions["*"];
			}
		}

		public bool HasRetrieved => AppVersions != null;

		public SupportedVersionsTable(Dictionary<string, List<int>> appVersions)
		{
			AppVersions = appVersions;
		}

		public bool IsInWildcard(int softwareNumber)
		{
			bool flag = WildcardNumbers?.Contains(softwareNumber) ?? false;
			if (flag)
			{
				Log.Trace("Connection", "Found valid software number in wild card list");
			}
			return flag;
		}

		public bool IsSupportedForBuild(int softwareNumber, string buildVer)
		{
			if (!BuildVersionExists(buildVer))
			{
				Log.Error("Connection", "Unable to find supported software numbers for current version: " + buildVer);
				return false;
			}
			Log.Trace("Connection", "Found valid software numbers from JSON: " + string.Join(", ", AppVersions[buildVer]));
			return AppVersions[buildVer].Contains(softwareNumber);
		}

		public bool BuildVersionExists(string buildVer)
		{
			if (!string.IsNullOrWhiteSpace(buildVer))
			{
				Dictionary<string, List<int>> appVersions = AppVersions;
				if (appVersions != null && appVersions.ContainsKey(buildVer))
				{
					return AppVersions[buildVer] != null;
				}
			}
			return false;
		}

		public bool IsSupported(int softwareNumber, string buildVer)
		{
			if (!IsInWildcard(softwareNumber))
			{
				return IsSupportedForBuild(softwareNumber, buildVer);
			}
			return true;
		}
	}
	public interface IBleTcpConnectionService
	{
		Task<bool> PromptForVirtualConsoleAddress(IBleDevice tcpDevice);
	}
	public class BleTcpConnectionService : IBleTcpConnectionService
	{
		private readonly ILocalSettings localSettings;

		private readonly IMvxMainThreadDispatcher dispatch;

		private readonly IDialogPresenter dialogPresenter;

		private readonly IDeveloperSettings developerSettings;

		public BleTcpConnectionService(ILocalSettings localSettings, IMvxMainThreadDispatcher dispatch, IDialogPresenter dialogPresenter, IDeveloperSettings developerSettings)
		{
			this.localSettings = localSettings;
			this.dispatch = dispatch;
			this.dialogPresenter = dialogPresenter;
			this.developerSettings = developerSettings;
		}

		public async Task<bool> PromptForVirtualConsoleAddress(IBleDevice tcpDevice)
		{
			string defaultAddress = developerSettings.LastTcpIpVirtualConsoleAddress ?? "127.0.0.1";
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			dispatch?.RequestMainThreadAction(delegate
			{
				dialogPresenter?.ShowDialog<PromptForInputDialogViewModel>(null, showSafely: false, new PromptForInputDialogViewModel.InputDialogInitializationData("Virtual Console", "Enter the address of the virtual console in the format of IPAddress:port (port optional).", defaultAddress, null, null, delegate(string addr)
				{
					ProcessIpAddress(tcpDevice, addr, tcs);
				}, delegate
				{
					tcs.TrySetResult(result: false);
				}));
			});
			return await tcs.Task;
		}

		protected void ProcessIpAddress(IBleDevice device, string ipAddress, TaskCompletionSource<bool> tcs)
		{
			developerSettings.LastTcpIpVirtualConsoleAddress = ipAddress;
			string text = FitProTcpConnection.IsAddressValid(ipAddress);
			if (text.IsNotNullOrWhiteSpace())
			{
				ShowErrorMessage(text);
				tcs.TrySetResult(result: false);
				return;
			}
			byte[] bytes = Encoding.UTF8.GetBytes(ipAddress);
			AdvertisementRecord item = new AdvertisementRecord(AdvertisementRecordType.DeviceAddress, bytes);
			device.AdvertisementRecords.Add(item);
			tcs.TrySetResult(result: true);
		}

		private void ShowErrorMessage(string addressErrorMessage)
		{
			dispatch?.RequestMainThreadAction(delegate
			{
				ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData("Virtual Console Error", addressErrorMessage, Wolf.Core.Resources.AppStrings.ok, dismissible: false, cancellable: false);
				dialogPresenter?.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: false, arbitraryData);
			});
		}
	}
	public class BranchService : IBranchService
	{
		public async Task<string> ResolveBranchLink(string shortLink, string branchKey, string os)
		{
			string link = shortLink;
			if (!Mvx.TryResolve<IBranchApi>(out var service))
			{
				Log.Trace("Branch", "Branch Not Initialized. Returning referring link: " + link);
				return link;
			}
			try
			{
				IBranchApiService branchApiService = Mvx.Resolve<IBranchApiService>();
				BranchLinkRequest valObject = branchApiService.CreateBranchLinkRequest(branchKey, shortLink, os);
				ApiResponse<BranchLinkResponse> apiResponse = await service.ResolveBranchLink(valObject).ConfigureAwait(continueOnCapturedContext: false);
				if (apiResponse.IsSuccessStatusCode && apiResponse.Content?.BranchData?.ClickedBranchLink == true)
				{
					link = apiResponse.Content?.BranchData?.CanonicalUrl ?? string.Empty;
					Log.Trace("Branch", "Link Resolved : " + shortLink + " -> " + link);
				}
				else
				{
					Log.Trace("Branch", "ResolveBranchLink failed(" + apiResponse.ReasonPhrase + "), or non branch link passed. Returning referring link: " + shortLink + ".");
				}
			}
			catch (Exception arg)
			{
				Log.Trace("Branch", $"ResolveBranchLink failed: {arg}");
			}
			return link;
		}
	}
	public interface ICalibrationDialogService : IDisposable
	{
		bool IsCalibrating { get; }
	}
	public class CalibrationDialogService : ICalibrationDialogService, IDisposable
	{
		private ILocalSettings localSettings;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IDisposable consoleSub;

		private IDisposable calibratingSub;

		private IDisposable calibrationFailSub;

		public bool IsCalibrating { get; private set; }

		public CalibrationDialogService(ILocalSettings localSettings, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings)
		{
			this.localSettings = localSettings;
			this.workoutSettings = workoutSettings;
			if (localSettings == null || !localSettings.IsAutomatedTestingMode)
			{
				consoleSub = currentConsoleService?.WhenConsoleChanged.Subscribe(ConsoleChanged);
				if (currentConsoleService?.ActiveConsole != null)
				{
					ConsoleChanged(currentConsoleService.ActiveConsole);
				}
			}
		}

		private void ConsoleChanged(IFitnessConsole console)
		{
			calibratingSub?.Dispose();
			if (console != null)
			{
				calibratingSub = console.WhenCalibrationStarted.Subscribe(CalibrationChanged);
				calibrationFailSub = console.WhenCalibrationStatusChanged.Where((CalibrateInclineState x) => x == CalibrateInclineState.Failed).Subscribe(OnFailedCalibration);
			}
		}

		private void OnFailedCalibration(CalibrateInclineState status)
		{
			if (!Mvx.TryResolve<IDialogPresenter>(out var presenter) || !Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				return;
			}
			service.RequestMainThreadAction(delegate
			{
				if (!presenter.IsDialogShown<CalibrateInclineDialogViewModel>() && presenter.CurrentMainViewModel is BaseViewModel baseViewModel)
				{
					baseViewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.calibration_failed, Wolf.Core.Resources.AppStrings.calibration_failed_message, delegate
					{
						presenter.ShowDialog<CalibrateInclineDialogViewModel>();
					}, Wolf.Core.Resources.AppStrings.ok, Wolf.Core.Resources.AppStrings.cancel);
				}
			});
		}

		private void CalibrationChanged(bool isCalibrating)
		{
			IsCalibrating = isCalibrating;
			if (!isCalibrating)
			{
				return;
			}
			IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
			if ((workoutContainer != null && workoutContainer.IsInEquipmentlessWorkout) || !Mvx.TryResolve<IDialogPresenter>(out var presenter) || !Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				return;
			}
			service.RequestMainThreadAction(delegate
			{
				if (!presenter.IsDialogShown<CalibrateInclineDialogViewModel>() && presenter.CurrentMainViewModel is BaseViewModel baseViewModel)
				{
					baseViewModel.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.calibrating_incline_attention, Wolf.Core.Resources.AppStrings.calibrating_incline_attention_message, delegate
					{
					}, string.Empty, Wolf.Core.Resources.AppStrings.ok);
				}
			});
		}

		public void Dispose()
		{
			consoleSub?.Dispose();
			calibratingSub?.Dispose();
			calibrationFailSub?.Dispose();
		}
	}
