	public interface ICheckUpdateService
	{
		IObservable<ConsoleAppsUpdates.AppUpdate> WhenConsoleAppUpdateFetched { get; }

		IObservable<BrainboardUpdate> WhenBrainboardUpdateFetched { get; }

		Task<CheckUpdateState> CheckForUpdate();
	}
	public abstract class CheckUpdateServiceBase : ICheckUpdateService
	{
		protected const string AppUpdateName = "com.ifit.standalone";

		protected const string NoUpdateOnServerTag = "No Update On Server";

		private readonly Subject<ConsoleAppsUpdates.AppUpdate> _whenConsoleAppUpdateFetched = new Subject<ConsoleAppsUpdates.AppUpdate>();

		private readonly Subject<BrainboardUpdate> _whenBrainboardUpdateFetched = new Subject<BrainboardUpdate>();

		protected readonly IIfitApiService ifitApi;

		protected readonly ILocalSettings settings;

		protected readonly IWolfAnalytics reporter;

		protected readonly IConnectivity connectivity;

		protected readonly ICurrentConsoleService currentConsoleService;

		protected readonly IDeviceInformation deviceInformation;

		public IObservable<ConsoleAppsUpdates.AppUpdate> WhenConsoleAppUpdateFetched => _whenConsoleAppUpdateFetched;

		public IObservable<BrainboardUpdate> WhenBrainboardUpdateFetched => _whenBrainboardUpdateFetched;

		protected int SoftwareNumber => (deviceInformation.SpoofedSoftwareNumber ?? currentConsoleService.Console?.ConsoleInfo?.PartNumber) ?? (-1);

		protected CheckUpdateServiceBase(IIfitApiService ifitApi, ILocalSettings settings, IWolfAnalytics reporter, IConnectivity connectivity, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation)
		{
			this.ifitApi = ifitApi;
			this.settings = settings;
			this.reporter = reporter;
			this.connectivity = connectivity;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
		}

		protected abstract Task<CheckUpdateState> CheckUpdateStatesNeeded();

		public async Task<CheckUpdateState> CheckForUpdate()
		{
			if (!HasConsole())
			{
				return CheckUpdateState.NoMachine;
			}
			if (!HasInternet())
			{
				return CheckUpdateState.NoNetwork;
			}
			if (IsMockConsole())
			{
				return CheckUpdateState.UpToDate;
			}
			return await Task.Run((Func<Task<CheckUpdateState>>)CheckUpdateStatesNeeded);
		}

		protected async Task<CheckUpdateState> GetConsoleAppUpdateState()
		{
			ConsoleAppsUpdates.AppUpdate appUpdate;
			try
			{
				ConsoleAppsUpdates consoleAppsUpdates = await ConsoleAppsUpdates.Get(ifitApi, SoftwareNumber);
				appUpdate = consoleAppsUpdates?.Info?.Apps?.Updates?.Where((ConsoleAppsUpdates.AppUpdate x) => "com.ifit.standalone".Equals(x?.Fqn, StringComparison.OrdinalIgnoreCase))?.FirstOrDefault();
				if (string.IsNullOrWhiteSpace(appUpdate?.Version))
				{
					await LogNoUpdateOnServer($"ICheckUpdateService -> ConsoleAppUpdates.Get returned [{consoleAppsUpdates}] and Version doesn't exist [SoftwareNumber: {SoftwareNumber}]");
					return CheckUpdateState.UpToDate;
				}
			}
			catch (WebException ex)
			{
				Log.Trace("Updating", $"There was a problem getting the update for [Software Number : {SoftwareNumber}] Stack Trace => {ex}");
				await ReportError($"There was a problem getting the update for [Software Number : {SoftwareNumber}]", ex.ToString());
				return CheckUpdateState.UpToDate;
			}
			catch (Exception ex2)
			{
				Log.Error("Updating", $"GetConsoleAppUpdateState -> Problem Getting Latest Update Check {ex2}");
				await ReportError($"GetConsoleAppUpdateState -> Problem getting the update for [Software Number : {SoftwareNumber}]", ex2.ToString());
				return CheckUpdateState.Error;
			}
			_whenConsoleAppUpdateFetched.OnNext(appUpdate);
			bool flag = UpdateVersion.CheckVersionStrings(settings.CurrentVersion, appUpdate.Version);
			Log.Trace("Updating", $"ICheckUpdateService -> Console App version [Has Update: {flag}], [server version: {appUpdate.Version}], [local version: {settings.CurrentVersion}]");
			return flag ? CheckUpdateState.UpdateAvailable : CheckUpdateState.UpToDate;
		}

		protected async Task<CheckUpdateState> GetBrainboardUpdateState()
		{
			BrainboardUpdate update;
			try
			{
				update = await BrainboardUpdate.Get(ifitApi, SoftwareNumber);
				if (update == null || !update.SoftwareNumbers.Contains(SoftwareNumber) || !update.Url.IsValidUrl() || string.IsNullOrWhiteSpace(update.Version))
				{
					await LogNoUpdateOnServer($"ICheckUpdateService -> BrainboardUpdate.Get returned threw the following [{update}]");
					return CheckUpdateState.UpToDate;
				}
			}
			catch (WebException ex)
			{
				Log.Trace("Updating", $"BrainboardHasUpdate -> Problem getting the update for [Software Number : {SoftwareNumber}] Stack Trace => {ex}");
				await ReportError($"BrainboardHasUpdate -> Problem getting the update for [Software Number : {SoftwareNumber}]", ex.ToString());
				return CheckUpdateState.UpToDate;
			}
			catch (Exception ex2)
			{
				Log.Error("Updating", $"GetBrainboardUpdateState -> Problem Getting Latest Update Check {ex2}");
				await ReportError($"BrainboardHasUpdate -> Problem getting the update for [Software Number : {SoftwareNumber}]", ex2.ToString());
				return CheckUpdateState.Error;
			}
			_whenBrainboardUpdateFetched.OnNext(update);
			UpdateVersion updateVersion = UpdateVersion.Factory(update, SoftwareNumber);
			UpdateVersion updateVersion2 = UpdateVersion.Factory(currentConsoleService.Console?.ConsoleInfo?.MasterLibraryVersion ?? (-1), currentConsoleService.Console?.ConsoleInfo?.MasterLibraryBuild ?? (-1), SoftwareNumber);
			bool flag = updateVersion.IsAnUpgradeFrom(updateVersion2);
			Log.Trace("Updating", $"ICheckUpdateService ({ifitApi.Environment.Name}) -> Brainboard version [Has Update: {flag}], [server version: {updateVersion}], [local version: {updateVersion2}]");
			return flag ? CheckUpdateState.UpdateAvailable : CheckUpdateState.UpToDate;
		}

