		protected async Task LogNoUpdateOnServer(string message)
		{
			Log.Trace("Updating", $"There was a problem getting the update for [Software Number : {SoftwareNumber}] Message => {message}");
			await ReportError(message);
		}

		protected async Task ReportError(string message, string stackTrace = null)
		{
			await reporter.Track("No Update On Server", new Dictionary<string, object>
			{
				["machinePartNumber"] = SoftwareNumber,
				["isBuiltIn"] = deviceInformation.IsBuiltIn,
				["notes"] = message ?? "",
				["stackTrace"] = stackTrace ?? ""
			});
		}
