		public ClubUserClubSettingsRouter(ILocalSettings settings, IClubLocalSettings clubLocalSettings, IIfitApiService api, IPreferenceResolver preferenceResolver, ITelevisionSettings televisionSettings)
			: base(settings, api, preferenceResolver, televisionSettings)
		{
			this.clubLocalSettings = clubLocalSettings;
		}

		public override async Task<bool> GetIsMetric(bool clubOwnerSettings = false)
		{
			if (clubOwnerSettings)
			{
				return clubLocalSettings.ClubDefaultIsMetric;
			}
			if (!api.HasLoggedInUser)
			{
				return preferenceResolver.IsMetric;
			}
			return await base.GetIsMetric(clubOwnerSettings).ConfigureAwait(continueOnCapturedContext: false);
		}

