		{
			if (clubOwnerSettings)
			{
				return televisionSettings.ClubDefaultTvClosedCaptions;
			}
			if (!api.HasLoggedInUser)
			{
				return televisionSettings.GuestTvClosedCaptions;
			}
			return base.GetShowTvClosedCaptions(clubOwnerSettings);
		}

		public override void SetShowTvClosedCaptions(bool value, bool clubOwnerSettings = false)
		{
