	public abstract class ConsoleStateChangeHandler<TViewModel> : IDisposable
	{
		protected readonly IWorkoutSettings workoutSettings;

		protected readonly ICurrentConsoleService currentConsoleService;

		private readonly IScreenSaverHandler screenSaverHandler;

		private readonly ConsoleState[] states;

		protected IDisposable stateChangeSub;

		protected ConsoleStateChangeHandler(IWorkoutSettings workoutSettings, IScreenSaverHandler screenSaverHandler, ICurrentConsoleService currentConsoleService, ConsoleState[] states)
		{
			this.workoutSettings = workoutSettings;
			this.screenSaverHandler = screenSaverHandler;
			this.states = states;
			this.currentConsoleService = currentConsoleService;
			if (currentConsoleService.Console != null)
			{
				SubscribeToRelevantStateChanges();
			}
			currentConsoleService.WhenConsoleChanged.Subscribe(delegate
			{
				ConsoleChanged();
			});
		}

		protected virtual void ConsoleChanged()
		{
			SubscribeToRelevantStateChanges();
		}

		private void SubscribeToRelevantStateChanges()
		{
			stateChangeSub?.Dispose();
			stateChangeSub = currentConsoleService.Console?.WhenStateChanged.Where((StateChange x) => x.ChangedToOrFromState(states)).Subscribe(RelevantStateChangeDetected);
		}

		protected virtual void RelevantStateChangeDetected(StateChange change)
		{
			Log.Debug("ConsoleError", $"{GetType().Name} detected ConsoleState changed from {change.Old} to {change.Current}");
			bool wasShowingScreenSaver = screenSaverHandler?.IsScreenSaverVisible ?? false;
			screenSaverHandler?.Touched();
			IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
			IDialogPresenter presenter;
			IMvxMainThreadDispatcher service2;
			if (workoutContainer != null && workoutContainer.IsInEquipmentlessWorkout)
			{
				Log.Trace("Workout", GetType().Name + " ignoring event during equipmentless workout.");
			}
			else if (change.ChangedFromState(ConsoleState.Demo, ConsoleState.SafetyKeyRemoved))
			{
				if (Mvx.TryResolve<ILockScreenHandler>(out var service))
				{
					if (change.Current == ConsoleState.WorkoutResults)
					{
						service.LockWhenFinishProcess = true;
					}
					else
					{
						service?.NavigateToLockScreen();
					}
				}
			}
			else if (change.ChangedToState(states) && Mvx.TryResolve<IDialogPresenter>(out presenter) && Mvx.TryResolve<IMvxMainThreadDispatcher>(out service2))
			{
				service2.RequestMainThreadAction(delegate
				{
					ShowDialogViewModelSafely(presenter, ShouldNotShowDismiss(change), wasShowingScreenSaver);
				});
			}
		}

		public static void ShowDialogViewModelSafely(IDialogPresenter presenter, bool shouldNotShowDismiss, bool wasShowingScreenSaver)
		{
			try
			{
				Log.Debug("ConsoleError", "Showing dialog with view model " + typeof(TViewModel).Name);
				presenter.ShowDialog(typeof(TViewModel).FullName, null, showSafely: true, new SafetyKeyDialogInitialization(!shouldNotShowDismiss, wasShowingScreenSaver));
			}
			catch (ObjectDisposedException exception)
			{
				Log.Trace("MvxTrace", "Attempting to show already disposed dialog.", exception);
			}
			catch (Exception exception2)
			{
				Log.Error("MvxTrace", "Unable to show dialog.", exception2);
			}
		}

		protected virtual bool ShouldNotShowDismiss(StateChange change)
		{
			if (change.Old != ConsoleState.WarmUp && change.Old != ConsoleState.Workout && change.Old != ConsoleState.CoolDown)
			{
				return change.Old == ConsoleState.Paused;
			}
			return true;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			stateChangeSub?.Dispose();
			stateChangeSub = null;
		}
	}
