	public class ConsoleTypeChangeService : IConsoleTypeChangeService, IDisposable
	{
		private readonly ILocalSettings localSettings;

		private readonly ICurrentConsoleService currentConsoleService;

		private Subject<Unit> _whenConsoleTypeChanged = new Subject<Unit>();

		private IDisposable consoleChangedSub;

		public IObservable<Unit> WhenConsoleTypeChanged => _whenConsoleTypeChanged;

		public ConsoleTypeChangeService(ILocalSettings localSettings, IBleConsoleService bleConsoleService, ICurrentConsoleService currentConsoleService)
		{
			ConsoleTypeChangeService consoleTypeChangeService = this;
			this.localSettings = localSettings;
			this.currentConsoleService = currentConsoleService;
			ConsoleType lastKnownConsoleType = currentConsoleService.LastKnownConsoleType;
			bool lastConsoleWasNonConnected = currentConsoleService.LastConsoleWasNonConnected;
			MockType? lastMockType = currentConsoleService.LastMockType;
			Log.Trace("Connection", $"prevConsoleType has been initialized with ConsoleType: {lastKnownConsoleType} NC: {lastConsoleWasNonConnected}");
			consoleChangedSub = bleConsoleService?.WhenConnectionStateChanged.SubscribeAsyncWithErrorLogging(async delegate(ConsoleConnectionState connectionState)
			{
				if (connectionState == ConsoleConnectionState.Connected)
				{
					ConsoleType consoleType = consoleTypeChangeService.GetConsoleType();
					bool flag = currentConsoleService.ActiveConsole?.IsNonconnectedConsole() ?? false;
					MockType? mockType = ((currentConsoleService.ActiveConsole?.IsNonconnectedConsole() ?? false) ? new MockType?((currentConsoleService.ActiveConsole as INonconnectedFitnessConsole).MockType) : ((MockType?)null));
					bool flag2 = !flag && lastConsoleWasNonConnected;
					bool flag3 = consoleType != lastKnownConsoleType;
					bool flag4 = !flag3 && lastMockType != mockType;
					Log.Trace("Connection", $"New connection detected. New ConsoleType: {consoleType} Previous ConsoleType: {lastKnownConsoleType}");
					Log.Trace("Connection", $"New Console NC Status: {flag} Previous Console NC Status: {lastConsoleWasNonConnected}");
					lastKnownConsoleType = consoleType;
					lastConsoleWasNonConnected = flag;
					lastMockType = mockType;
					if (flag2 || flag3 || flag4)
					{
						Log.Trace("Connection", $"Triggering WhenConsoleTypeChanged -- Swapped Non Connected Status {flag2} or swappedConsoleTypes {flag3}");
						consoleTypeChangeService._whenConsoleTypeChanged.OnNext(default(Unit));
					}
				}
			});
		}

		public void Dispose()
		{
			consoleChangedSub?.Dispose();
			consoleChangedSub = null;
		}

		private ConsoleType GetConsoleType()
		{
			return currentConsoleService.GetCurrentConsoleType(ConsoleType.None);
		}
	}
