	public interface IDfuConnectionService
	{
		Task<bool> ScanForRecoverableDevices(Action onUpdateComplete = null, bool showNoRecoverableDialog = false, bool showScanningDialog = false);
	}
	public class DfuConnectionService : IDfuConnectionService
	{
		private readonly IScanner scanner;

		private readonly IDormantUpdateChecker dormantUpdateService;

		public DfuConnectionService(IDormantUpdateChecker dormantUpdateService, IScanner scanner)
		{
			this.scanner = scanner;
			this.dormantUpdateService = dormantUpdateService;
		}

		public async Task<bool> ScanForRecoverableDevices(Action onUpdateComplete = null, bool showNoRecoverableDialog = false, bool showScanningDialog = false)
		{
			List<Tuple<string, int>> list = await dormantUpdateService.GetSavedPairKeysAndSoftwareNumbers();
			if (list.CountSafe() == 0)
			{
				if (showNoRecoverableDialog)
				{
					ShowNoRecoverableDialog();
				}
				return false;
			}
			Shire.Core.Util.NonGenericSubject obs = new Shire.Core.Util.NonGenericSubject();
			if (showScanningDialog && Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service) && Mvx.TryResolve<IDialogPresenter>(out var presenter))
			{
				service.RequestMainThreadAction(delegate
				{
					ShireBaseViewModel currentMainViewModel = presenter.CurrentMainViewModel;
					BaseViewModel baseViewModel = currentMainViewModel as BaseViewModel;
					if (baseViewModel != null)
					{
						Task.Run(() => baseViewModel.ShowProgressDialog(Wolf.Core.Resources.AppStrings.firmware_scanning_equipment, obs.ReactiveSubject, null, null, default(TimeSpan), "", showSafety: false));
					}
				});
			}
			DfuScanner dfuScanner = new DfuScanner(scanner);
			Tuple<string, int> tuple = await dfuScanner.ScanForDfuPairKeys(list);
			obs.OnNext();
			if (string.IsNullOrWhiteSpace(tuple?.Item1) || tuple.Item2 == -1)
			{
				if (showNoRecoverableDialog)
				{
					ShowNoRecoverableDialog();
				}
				return false;
			}
			ShowDialog(tuple.Item1, tuple.Item2, onUpdateComplete);
			return true;
		}

		private void ShowDialog(string pairKey, int softwareNumber, Action onUpdateComplete = null, int retryAttempts = 3)
		{
			if (retryAttempts <= 0)
			{
				return;
			}
			try
			{
				if (Mvx.TryResolve<IDialogPresenter>(out var presenter) && Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
				{
					service.RequestMainThreadAction(delegate
					{
						(presenter?.CurrentMainViewModel as BaseViewModel)?.ShowUpdateConfirmationDialog(pairKey, softwareNumber, cancellable: false, onUpdateComplete);
					});
				}
			}
			catch (Exception)
			{
				Observable.Timer(TimeSpan.FromMilliseconds(500.0)).Subscribe(delegate
				{
					ShowDialog(pairKey, softwareNumber, onUpdateComplete, retryAttempts - 1);
				});
			}
		}

		private void ShowNoRecoverableDialog()
		{
			try
			{
				if (Mvx.TryResolve<IDialogPresenter>(out var presenter) && Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
				{
					service.RequestMainThreadAction(delegate
					{
						(presenter?.CurrentMainViewModel as BaseViewModel)?.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ble_dialog_dfu_no_machine_found_title, Wolf.Core.Resources.AppStrings.ble_dialog_dfu_no_machine_found_desc, Wolf.Core.Resources.AppStrings.close, dismissible: true, cancellable: true);
					});
				}
			}
			catch (Exception)
			{
			}
		}
	}
	public interface IDormantUpdateChecker : IDisposable
	{
		bool UpdateCheckCompletedWorkout { get; set; }

		void ShowUpdateDialogIfNeeded();

		Task<List<Tuple<string, int>>> GetSavedPairKeysAndSoftwareNumbers();
	}
	public class DormantUpdateChecker : IDormantUpdateChecker, IDisposable
	{
		private static readonly List<Type> ForbiddenViewModelTypes = new List<Type>
		{
			typeof(PreparingWorkoutViewModel),
			typeof(InWorkoutViewModel)
		};

		private const string AppUpdateDialogTag = "app-update-dialog";

		private readonly ISaveUpdateFilesService saveFileService;

		private readonly ILocalSettings localSettings;

		private readonly ICheckUpdateService checkUpdateService;

		private readonly ILaunchUpdate updateLauncher;

		private readonly IBlobCacheService cacheService;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IDeviceInformation deviceInformation;

		private readonly IDisposable consoleChangeSub;

		private bool _updateCheckCompletedWorkout;

		public bool UpdateCheckCompletedWorkout
		{
			get
			{
				return _updateCheckCompletedWorkout;
			}
			set
			{
				_updateCheckCompletedWorkout = value;
				cacheService.Flush(_updateCheckCompletedWorkout, "_updateCheckCompletedWorkout", "DormantUpdateChecker");
			}
		}

		public DormantUpdateChecker(ILocalSettings localSettings, ICheckUpdateService checkUpdateService, ILaunchUpdate updateLauncher, IBlobCacheService cacheService, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, ISaveUpdateFilesService saveFileService = null)
		{
			this.localSettings = localSettings;
			this.checkUpdateService = checkUpdateService;
			this.updateLauncher = updateLauncher;
			this.saveFileService = saveFileService;
			this.cacheService = cacheService;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
			consoleChangeSub = currentConsoleService.WhenConsoleChanged.Subscribe(OnConsoleChange);
			Setup();
		}

		public async Task Setup()
		{
			_updateCheckCompletedWorkout = await cacheService.GetFromCache("_updateCheckCompletedWorkout", "DormantUpdateChecker", "", temp: false, defaultValue: false);
		}

		public void ShowUpdateDialogIfNeeded()
		{
			bool updateCheckCompletedWorkout = UpdateCheckCompletedWorkout;
			UpdateCheckCompletedWorkout = false;
			if (localSettings.ShowAutomaticUpdate && currentConsoleService.Console != null && !localSettings.IsRoboRunMode && updateCheckCompletedWorkout)
			{
				Task.Run((Func<Task>)UpdateIfAvailable);
			}
		}

		public async Task<List<Tuple<string, int>>> GetSavedPairKeysAndSoftwareNumbers()
		{
			try
			{
				if (saveFileService != null)
				{
					return await saveFileService.GetSetOfPreviouslyConnectedMachines();
				}
			}
			catch (Exception exception)
			{
				Log.Error("Updating", "DormantUpdateChecker.GetSavedPairKeysAndSoftwareNumbers Error", exception);
			}
			return null;
		}

		private async Task UpdateIfAvailable()
		{
			if (await checkUpdateService.CheckForUpdate() != CheckUpdateState.UpdateAvailable || !Mvx.TryResolve<IDialogPresenter>(out var presenter) || !Mvx.TryResolve<IMvxMainThreadDispatcher>(out var dispatcher))
			{
				return;
			}
			dispatcher.RequestMainThreadAction(delegate
			{
				ShireBaseViewModel currentMainViewModel = presenter.CurrentMainViewModel;
				BaseViewModel vm = currentMainViewModel as BaseViewModel;
				if (vm != null && presenter.CurrentDialogViewModel<SimpleConfirmationDialogViewModel>()?.InitializationData?.DialogTag?.Equals("app-update-dialog") != true)
				{
					foreach (Type forbiddenViewModelType in ForbiddenViewModelTypes)
					{
						if (presenter.CurrentMainViewModel.GetType() == forbiddenViewModelType)
						{
							return;
						}
					}
					vm.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.update_available, Wolf.Core.Resources.AppStrings.update_do_you_want_to_start, delegate
					{
						OnStartUpdateConfirmedAsync(vm);
					}, Wolf.Core.Resources.AppStrings.later.ToUpper(), Wolf.Core.Resources.AppStrings.start.ToUpper(), null, null, dismissible: false, cancellable: true, "app-update-dialog");
				}
			});
			Observable.Timer(TimeSpan.FromMinutes(5.0)).Subscribe(delegate
			{
				dispatcher.RequestMainThreadAction(delegate
				{
					SimpleConfirmationDialogViewModel simpleConfirmationDialogViewModel = presenter.CurrentDialogViewModel<SimpleConfirmationDialogViewModel>();
					if (simpleConfirmationDialogViewModel != null && simpleConfirmationDialogViewModel.InitializationData?.DialogTag?.Equals("app-update-dialog") == true)
					{
						simpleConfirmationDialogViewModel.CloseViewModel.SafeExecute();
					}
				});
			});
		}

		private void OnStartUpdateConfirmedAsync(BaseViewModel vm)
		{
			if (deviceInformation.IsBuiltIn)
			{
				updateLauncher.UpdateConnectedMachine();
			}
			else
			{
				if (!Mvx.TryResolve<IUpdater>(out var updater))
				{
					return;
				}
				Task.Run(async delegate
				{
					updateLauncher.UpdateConnectedMachine();
					await vm.ShowProgressDialog(Wolf.Core.Resources.AppStrings.getting_update, from x in updater.WhenIsUpdatingChanged.Timeout(TimeSpan.FromSeconds(30.0)).Take(1)
						select (object)null);
				});
			}
		}

		private void OnConsoleChange(IFitnessConsole console)
		{
			if (console == null || saveFileService == null || !Mvx.TryResolve<IBleConsoleService>(out var service))
			{
				return;
			}
			string pairKey = service.CurrentDevice?.PairKey;
			int softwareNumber = deviceInformation.SpoofedSoftwareNumber ?? console.ConsoleInfo?.PartNumber ?? (-1);
			if (!string.IsNullOrWhiteSpace(pairKey) && softwareNumber != -1)
			{
				Task.Run(() => saveFileService?.SavePairKeySoftwareNumber(pairKey, softwareNumber));
			}
		}

		public void Dispose()
		{
			consoleChangeSub?.Dispose();
		}
	}
