	public interface IEquipmentlessConsoleService
	{
		bool HasInstantiatedConsole { get; }

		StrengthWorkoutCalorieBurnEstimator CalorieBurnEstimator { get; }

		bool EquipmentlessConsoleOverrideEnabled { get; }

		Task ReinstantiateConsoleWithWorkout(bool isStrength, bool isTimeGoal, IList<WorkoutSegment> segments, double userKg, double userAge, bool userMale, double? averageHeartRate);

		void CleanUpConsole();
	}
	public class EquipmentlessConsoleService : IEquipmentlessConsoleService
	{
		private readonly IFitnessConsoleManager fitnessConsoleManager;

		private readonly ICurrentConsoleService currentConsoleService;

		public bool HasInstantiatedConsole => StrengthWorkoutEquipmentlessConsole?.Initialized ?? false;

		public EquipmentlessConsoleBase StrengthWorkoutEquipmentlessConsole { get; private set; }

		public StrengthWorkoutCalorieBurnEstimator CalorieBurnEstimator { get; private set; }

		public bool EquipmentlessConsoleOverrideEnabled => HasInstantiatedConsole;

		public EquipmentlessConsoleService(IFitnessConsoleManager fitnessConsoleManager, ICurrentConsoleService currentConsoleService)
		{
			this.fitnessConsoleManager = fitnessConsoleManager;
			this.currentConsoleService = currentConsoleService;
		}

		public Task ReinstantiateConsoleWithWorkout(bool isStrength, bool isTimeGoal, IList<WorkoutSegment> segments, double userKg, double userAge, bool userMale, double? averageHeartRate)
		{
			if (StrengthWorkoutEquipmentlessConsole != null)
			{
				return Task.CompletedTask;
			}
			CalorieBurnEstimator = StrengthWorkoutCalorieBurnEstimator.FromWorkout(isStrength, isTimeGoal, segments, userKg, userAge, userMale, averageHeartRate);
			ICurrentConsoleService obj = currentConsoleService;
			EquipmentlessConsoleBase console = (StrengthWorkoutEquipmentlessConsole = new StrengthWorkoutEquipmentlessConsole(CalorieBurnEstimator));
			obj.Console = console;
			return StrengthWorkoutEquipmentlessConsole.InitializeConsole();
		}

		public void CleanUpConsole()
		{
			if (StrengthWorkoutEquipmentlessConsole != null && fitnessConsoleManager.PhysicalConsole != null)
			{
				currentConsoleService.Console = fitnessConsoleManager.PhysicalConsole;
			}
			CalorieBurnEstimator?.DisposeIfDisposable();
			CalorieBurnEstimator = null;
			StrengthWorkoutEquipmentlessConsole?.CleanUpWorkout();
			StrengthWorkoutEquipmentlessConsole?.Dispose();
			StrengthWorkoutEquipmentlessConsole = null;
		}
	}
	public interface IFatalityHandler
	{
		IObservable<FatalRecovery> WhenFatalityRecovered { get; }
	}
	public class FatalityHandler : IFatalityHandler
	{
		private readonly IDeviceInformation deviceInformation;

		private readonly IAppSetupFatalityHandler appSetupFatalityHandler;

		private readonly IWolfTrackingService trackingService;

		private FatalEvent lastFatalEvent;

		private readonly Subject<FatalRecovery> _whenFatalityRecovered = new Subject<FatalRecovery>();

		private bool inFatalState;

		protected TimeSpan OnFatalityBleTimer = TimeSpan.FromSeconds(5.0);

		protected TimeSpan FatalityRecoveryRetryTimer = TimeSpan.FromSeconds(2.0);

		public IObservable<FatalRecovery> WhenFatalityRecovered => _whenFatalityRecovered;

		public FatalityHandler(IDeviceInformation deviceInformation, IFatalityService fatality, IAppSetupFatalityHandler appSetupFatalityHandler, IWolfTrackingService trackingService)
		{
			this.deviceInformation = deviceInformation;
			this.appSetupFatalityHandler = appSetupFatalityHandler;
			this.trackingService = trackingService;
			fatality.WhenFatalityHappened.Subscribe(OnFatality);
			fatality.WhenFatalityRecovered.Subscribe(OnFatalityRecovered);
		}

		private void OnFatality(FatalEvent fatalEvent)
		{
			lastFatalEvent = fatalEvent;
			inFatalState = true;
			Observable.Timer(OnFatalityBleTimer).Subscribe(delegate
			{
				if (inFatalState)
				{
					FireFatality(fatalEvent);
				}
			});
		}

		private void FireFatality(FatalEvent fatalEvent)
		{
			if (string.IsNullOrEmpty(fatalEvent.Message))
			{
				fatalEvent.Message = Wolf.Core.Resources.AppStrings.machine_fatal_error_text;
			}
			appSetupFatalityHandler.OnAppSetupFatality(fatalEvent);
			if (trackingService.IsRestartDialogShowing)
			{
				return;
			}
			if (Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service) && Mvx.TryResolve<IDialogPresenter>(out var presenter))
			{
				if (deviceInformation?.IsBuiltIn == true)
				{
					RestartDialogViewModel.NavObject navObject = new RestartDialogViewModel.NavObject
					{
						DisplayMessage = fatalEvent.Message,
						FatalityExceptionType = fatalEvent.ExceptionType.ToString()
					};
					service.RequestMainThreadAction(delegate
					{
						presenter.ShowDialog<RestartDialogViewModel, RestartDialogViewModel.NavObject>(navObject, showSafely: true);
					});
				}
				else
				{
					ConfirmationInitializationData initObject = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.machine_fatal_error_title, fatalEvent.Message, null, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), OnConfirmActionTiming.AfterClose);
					service.RequestMainThreadAction(delegate
					{
						presenter.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, initObject);
					});
				}
			}
			else
			{
				Observable.Timer(FatalityRecoveryRetryTimer).Subscribe(RetryFatality);
			}
		}

		private void OnFatalityRecovered(FatalRecovery recovery)
		{
			inFatalState = false;
			_whenFatalityRecovered.OnNext(recovery);
		}

		private void RetryFatality(long x)
		{
			OnFatality(lastFatalEvent);
		}
	}
