		public FeedbackService(ILocalSettings localSettings, IIfitApiService ifitApi, IAtlassianApiService atlassianApiService, IAppVersionService appVersionService, ILogFileService logFileService, IHardwareInfo hardwareInfo, IFeatureFlagManager featureFlagManager, IBackgroundEmailerService backgroundEmailerService, IIpcVersionInfo ipcVersionInfo, IConnectivity connectivity, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IWebUtils webUtils)
		{
			this.localSettings = localSettings;
			this.ifitApi = ifitApi;
			atlassianApi = atlassianApiService;
			this.appVersionService = appVersionService;
			this.logFileService = logFileService;
			this.hardwareInfo = hardwareInfo;
			this.featureFlagManager = featureFlagManager;
			this.backgroundEmailerService = backgroundEmailerService;
			this.connectivity = connectivity;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
			this.webUtils = webUtils;
			Platform = hardwareInfo.OperatingSystem;
			OsVersion = hardwareInfo.OperatingSystemVersion;
			OsIncrementalVersion = hardwareInfo.AndroidOsIncrementalVersion;
			webViewVersion = ipcVersionInfo?.WebViewVersion;
		}

		public async Task CheckForUploadRequest()
		{
			if (!uploadCheckInProgress)
			{
				uploadCheckInProgress = true;
				bool flag = featureFlagManager.GetBool(FeatureFlags.OneTimeJiraLogUpload);
				if (flag && !localSettings.HasDoneOneTimeJiraLogUpload)
				{
					FeedbackInfo feedbackInfo = await GetDefaultFeedbackInfo();
					feedbackInfo.Description = "Automatic report triggered by OneTimeJiraLogUpload";
					await SendFeedback(feedbackInfo, default(CancellationToken), null, forceJira: true, isApiErrorIgnored: true);
					localSettings.HasDoneOneTimeJiraLogUpload = true;
				}
				else if (!flag && localSettings.HasDoneOneTimeJiraLogUpload)
				{
					localSettings.HasDoneOneTimeJiraLogUpload = false;
				}
				uploadCheckInProgress = false;
			}
		}

		public async Task<FeedbackInfo> GetDefaultFeedbackInfo()
		{
			FeedbackInfo feedbackInfo = new FeedbackInfo();
			if (ifitApi.HasLoggedInUser)
			{
				try
				{
					User user = await User.GetMe(ifitApi, populate: true, force: true);
					User user2 = user;
					user2.Shipping = await user.GetShipping(ifitApi);
					feedbackInfo.User = user;
					feedbackInfo.FirstName = user.Firstname;
					feedbackInfo.LastName = user.Lastname;
					if (user.Shipping != null)
					{
						feedbackInfo.StreetAddress = user.Shipping.Address;
						feedbackInfo.City = user.Shipping.City;
						feedbackInfo.State = user.Shipping.State;
						feedbackInfo.PostalCode = user.Shipping.Zip;
					}
					feedbackInfo.EmailAddress = user.Email;
				}
				catch (Exception ex)
				{
					Log.Error("Api", "Error getting current user", ex.GetBaseException());
				}
			}
			if (currentConsoleService?.Console?.ConsoleInfo != null && currentConsoleService.Console.ConsoleInfo.ManufacturerId != Manufacturer.Ifit)
			{
				feedbackInfo.ModelNumber = $"{ConsoleInfoBase.GetMachineTypeCode(currentConsoleService.Console.ConsoleInfo.MachineType)}{ConsoleInfoBase.GetManufacturerCode(currentConsoleService.Console.ConsoleInfo.ManufacturerId)}{currentConsoleService.Console.ConsoleInfo.ModelNumber:D5}.{currentConsoleService.Console.ConsoleInfo.HardwareVersion}";
			}
			return feedbackInfo;
		}

		public async Task<bool> SendFeedback(FeedbackInfo feedbackInfo, CancellationToken cancellationToken = default(CancellationToken), string supplementalCrashLogReport = null, bool forceJira = false, bool isApiErrorIgnored = false)
		{
			cancellationToken.ThrowIfCancellationRequested();
			if (feedbackInfo == null || feedbackInfo.Description.IsNullOrWhitespace() || !connectivity.IsConnected)
			{
				return false;
			}
			User user = feedbackInfo.User;
			string userName = user?.Username ?? "anon";
			string email = CheckEmail(feedbackInfo, user);
			bool flag = CheckIsEmployee(user, email);
			bool useFreemotion = !forceJira && currentConsoleService.IsBuiltinClub && !flag;
			bool useSalesForce = !forceJira && (user == null || !currentConsoleService.IsBuiltinClub) && !flag;
			string subject = BuildFeedbackSubject(userName, feedbackInfo.Description);
			string text = ((!useSalesForce) ? (await BuildFeedbackDescription(userName, feedbackInfo, useSalesForce, flag, supplementalCrashLogReport)) : (await BuildFeedbackSalesForce(userName, feedbackInfo, supplementalCrashLogReport)));
			string text2 = text;
			List<string> list = new List<string>();
			list.Add(forceJira ? "Automatic" : "Employee");
			cancellationToken.ThrowIfCancellationRequested();
			try
			{
				if (useFreemotion)
				{
					SendFreemotionEmail(subject, text2);
				}
				else
				{
					if (useSalesForce)
					{
						return await SendToSalesForce(text2);
					}
					await Issue.SendFeedback(atlassianApi, "Wolf", subject, text2, "1", list, cancellationToken, connectivity);
				}
			}
			catch (ApiException e)
			{
				if (!isApiErrorIgnored)
				{
					throw;
				}
				LogApiError(e, useSalesForce);
			}
			catch (Exception e2)
			{
				LogApiError(e2, useSalesForce);
				return false;
			}
			return true;
		}

		private void LogApiError(Exception e, bool useSalesForce)
		{
			string text = ((!currentConsoleService.IsBuiltinClub) ? (useSalesForce ? "SalesForce" : "Jira") : "Gmail SMTP");
			Log.Error("Api", "Error sending feedback through " + text, e.GetBaseException());
		}

		private void SendFreemotionEmail(string subject, string description)
		{
			if (!Get<EmailCredentials>(FeatureFlags.EmbeddedClubFeedbackSender, out var result))
			{
				result = new EmailCredentials("FreeMotion Feedback", "fmfeedback@ifit.com", DefaultBuiltinClubFeedbackSenderPassword);
			}
			if (!Get<EmailRecipient>(FeatureFlags.EmbeddedClubFeedbackRecipient, out var result2))
			{
				result2 = new EmailRecipient("FreeMotion Customer Care", "customercare@freemotionfitness.com");
			}
			backgroundEmailerService.SendEmail(result, result2, subject, description);
			bool Get<T>(FeatureFlag flag, out T reference)
			{
				string value = featureFlagManager.GetString(flag);
				try
				{
					reference = JsonConvert.DeserializeObject<T>(value);
				}
				catch (Exception ex)
				{
					if (!(ex is JsonSerializationException) && !(ex is JsonReaderException) && !(ex is ArgumentNullException))
					{
						throw;
					}
					reference = default(T);
					Log.Trace("Api", "Error deserializing Json object", ex);
					return false;
				}
				return true;
			}
		}

		private static string BuildFeedbackSubject(string userName, string feedbackText)
		{
			string text = feedbackText.Substring(0, Math.Min(32, feedbackText.Length));
			text = text.Replace("\n", " ");
			return userName + ": " + text + "...";
		}

		private string CheckEmail(FeedbackInfo feedbackInfo, User user)
		{
			if (!feedbackInfo.EmailAddress.IsNullOrWhitespace())
			{
				return feedbackInfo.EmailAddress;
			}
			return user?.Email ?? "anon@ifit.com";
		}

		private bool CheckIsEmployee(User user, string email)
		{
			if (user == null || !user.IsEmployee)
			{
				if (!email.Equals("anon@ifit.com", StringComparison.OrdinalIgnoreCase))
				{
					if (!email.EndsWith("@ifit.com", StringComparison.OrdinalIgnoreCase))
					{
						return email.EndsWith("@iconfitness.com", StringComparison.OrdinalIgnoreCase);
					}
					return true;
				}
				return false;
			}
			return true;
		}

		private string SectionHeader(string title, bool useConfluenceHeader)
		{
			if (!useConfluenceHeader)
			{
				return title;
			}
			return "h2. " + title;
		}

		private async Task<string> BuildUserInformationSection(bool useConfluenceHeader)
		{
			string header = SectionHeader("User Information", useConfluenceHeader);
			List<User> list = await ifitApi.GetAuthenticatedUsers();
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(header).Append("\n");
			if (list.Count > 0)
			{
				foreach (User item in list)
				{
					stringBuilder.Append("- ID: ").Append(item.Id).Append("\n");
					stringBuilder.Append("- Currently Authenticated: ").Append(ifitApi.CurrentlyAuthenticatedUserId == item.Id).Append("\n");
					stringBuilder.Append("- Username: ").Append(item.Username).Append("\n");
					stringBuilder.Append("- First Name: ").Append(item.Firstname).Append("\n");
					stringBuilder.Append("- Last Name: ").Append(item.Lastname).Append("\n");
					stringBuilder.Append("- Email: ").Append(item.Email).Append("\n");
					stringBuilder.Append("- Gender: ").Append(item.Gender).Append("\n");
					stringBuilder.Append("- Locale: ").Append(item.Locale).Append("\n");
					stringBuilder.Append("- Timezone: ").Append(item.Timezone).Append("\n");
					stringBuilder.Append("- Units: ").Append(item.Units).Append("\n");
					stringBuilder.Append("- Premium: ").Append(item.Premium).Append("\n");
				}
			}
			else
			{
				stringBuilder.Append("No Authenticated Users");
			}
			return stringBuilder.ToString();
		}

		private async Task<string> BuildSystemInformationSection(bool useConfluenceHeader)
		{
			string value = SectionHeader("System Information", useConfluenceHeader);
			StringBuilder sb = new StringBuilder();
			sb.Append(value).Append("\n");
			sb.Append("- Platform: ").Append(Platform).Append("\n");
			sb.Append("- OS Version: ").Append(OsVersion).Append("\n");
			if (OsIncrementalVersion != null)
			{
				sb.Append("- OS Incremental Version: ").Append(OsIncrementalVersion).Append("\n");
			}
			sb.Append("- App Version: ").Append(AppVersion).Append("\n");
			if (!string.IsNullOrEmpty(webViewVersion) && !webViewVersion.Equals("Unknown"))
			{
				sb.Append("- WebView Version: ").Append(webViewVersion).Append("\n");
			}
			sb.Append("- Screen Size: ").Append(deviceInformation.ScreenWidth).Append("x")
				.Append(deviceInformation.ScreenHeight)
				.Append("\n");
			sb.Append("- Pixel Screen Size: ").Append(deviceInformation.PixelScreenWidth).Append("x")
				.Append(deviceInformation.PixelScreenHeight)
				.Append("\n");
			sb.Append("- Screen Pixel Density: ").Append(deviceInformation.ScreenPixelDensity).Append("\n");
			sb.Append("\n");
			IConsoleInfo consoleInfo = currentConsoleService?.Console?.ConsoleInfo;
			if (consoleInfo != null)
			{
				sb.Append("Console Information: ").Append("\n");
				sb.Append("- Model: ").Append(consoleInfo.ModelNumber).Append("\n");
				sb.Append("- PartNumber: ").Append(deviceInformation.SoftwareNumber).Append(deviceInformation.SpoofedSoftwareNumber.HasValue ? " (spoofed)" : "")
					.Append("\n");
				sb.Append("- IsClub: ").Append(consoleInfo.IsClub).Append("\n");
				sb.Append("- Brainboard Software Version: ").Append(consoleInfo.SoftwareVersion).Append("\n");
				sb.Append("- Hardware Version: ").Append(consoleInfo.HardwareVersion).Append("\n");
				sb.Append("- Machine Type: ").Append(consoleInfo.MachineType).Append("\n");
				sb.Append("- Serial Number: ").Append(consoleInfo.SerialNumber).Append("\n");
				if (Mvx.TryResolve<IConsoleUpdateInfo>(out var service))
				{
					Guid guid = (await service.GetInfo()).Guid;
					if (guid != Guid.Empty)
					{
						sb.Append("- Console UUID: ").Append(guid.ToString()).Append("\n");
					}
				}
				sb.Append("- MasterLibVersion: ").Append(consoleInfo.MasterLibraryVersion).Append("\n");
				sb.Append("- MasterLibBuild: ").Append(consoleInfo.MasterLibraryBuild).Append("\n");
				sb.Append("- System Units: ").Append(consoleInfo.SystemUnits).Append("\n");
			}
			else
			{
				sb.Append("Not connected to a console").Append("\n");
			}
			return sb.ToString();
		}

		private async Task<string> BuildLogsSection(string userName, bool useZendesk, bool useConfluenceHeader, string supplementalCrashLogReport = null)
		{
			string text = DateTime.UtcNow.ToString("yyyyMMdd");
			string uploadDirectory = "wolf_feedback/" + userName + "_" + text + "/";
			List<string> excludedLogs = new List<string> { "FitProBytes.txt" };
			string text2 = (await logFileService.UploadLogsToS3AndCreateDescription(uploadDirectory, supplementalCrashLogReport, excludedLogs))?.Replace("\\n", "\n");
			string value = SectionHeader("Logs", useConfluenceHeader);
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(value).Append("\n");
			if (useZendesk)
			{
				text2 = text2?.Replace(".txt", "");
				stringBuilder.Append("NOTE: Following URLs are missing .txt extensions due to Zendesk API bug").Append("\n");
			}
			stringBuilder.Append(text2);
			return stringBuilder.ToString();
		}

		private string BuildFeatureFlagInformationSection(bool useConfluenceHeader)
		{
			string value = SectionHeader("Feature Flag Information", useConfluenceHeader);
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append(value).Append("\n");
			IReadOnlyList<FeatureFlag> allFlags = FeatureFlags.AllFlags;
			if (allFlags != null)
			{
				foreach (FeatureFlag item in allFlags)
				{
					stringBuilder.Append("- " + item.Key + ": ");
					switch (item.Type)
					{
					case FeatureFlagType.Bool:
						stringBuilder.Append(featureFlagManager.IsFeatureEnabled(item).ToString());
						break;
					case FeatureFlagType.Int:
						stringBuilder.Append(featureFlagManager.GetInt(item));
						break;
					case FeatureFlagType.String:
					case FeatureFlagType.WebviewUrl:
						stringBuilder.Append(featureFlagManager.GetString(item));
						break;
					default:
						stringBuilder.Append("Feature flag type unknown.");
						break;
					}
					stringBuilder.Append("\n");
				}
			}
			else
			{
				stringBuilder.Append("Feature Flags are null");
			}
			return stringBuilder.ToString();
		}

		private async Task<string> BuildFeedbackDescription(string userName, FeedbackInfo feedbackInfo, bool useZendesk, bool useConfluenceHeader, string supplementalCrashLogReport = null)
		{
			string userFeedbackSection = feedbackInfo.ToString();
			Task<string> userInformationSectionTask = BuildUserInformationSection(useConfluenceHeader);
			string systemInformationSection = await BuildSystemInformationSection(useConfluenceHeader);
			string featureFlagInformationSection = BuildFeatureFlagInformationSection(useConfluenceHeader);
			Task<string> logsSectionTask = BuildLogsSection(userName, useZendesk, useConfluenceHeader, supplementalCrashLogReport);
			await Task.WhenAll<string>(userInformationSectionTask, logsSectionTask);
			return userFeedbackSection + "\n\n" + userInformationSectionTask.Result + "\n\n" + systemInformationSection + "\n\n" + featureFlagInformationSection + "\n\n" + logsSectionTask.Result;
		}

		private Dictionary<string, object> BuildDescriptionSalesForce(FeedbackInfo feedbackInfo)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			dictionary.Add("User Feedback", feedbackInfo.Description);
			dictionary.Add("Report Time", DateTime.Now.ToString("o"));
			dictionary.Add("First Name", feedbackInfo.FirstName);
			dictionary.Add("Last Name", feedbackInfo.LastName);
			dictionary.Add("Address", feedbackInfo.StreetAddress);
			dictionary.Add("City", feedbackInfo.City);
			dictionary.Add("State", feedbackInfo.State);
			dictionary.Add("Zip Code", feedbackInfo.PostalCode);
			dictionary.Add("Email Address", feedbackInfo.EmailAddress);
			dictionary.Add("Serial Number", feedbackInfo.SerialNumber);
			dictionary.Add("Model Number", feedbackInfo.ModelNumber);
			dictionary.Add("Purchase Location", feedbackInfo.PurchaseLocation);
			dictionary.Add("Purchase Date", feedbackInfo.PurchaseDate);
			return dictionary;
		}

		private async Task<List<Dictionary<string, object>>> BuildUserInfoSalesForce()
		{
			List<Dictionary<string, object>> allUserInfo = new List<Dictionary<string, object>>();
			List<User> list = await ifitApi.GetAuthenticatedUsers();
			if (list.Count > 0)
			{
				foreach (User item2 in list)
				{
					Dictionary<string, object> item = new Dictionary<string, object>
					{
						{ "ID", item2.Id },
						{
							"Currently Authenticate",
							ifitApi.CurrentlyAuthenticatedUserId == item2.Id
						},
						{ "Username", item2.Username },
						{ "First Name", item2.Firstname },
						{ "Last Name", item2.Lastname },
						{ "Email", item2.Email },
						{ "Gender", item2.Gender },
						{ "Locale", item2.Locale },
						{ "Timezone", item2.Timezone },
						{ "Units", item2.Units },
						{ "Premium", item2.Premium }
					};
					allUserInfo.Add(item);
				}
			}
			else
			{
				Dictionary<string, object> dictionary = new Dictionary<string, object>();
				dictionary.Add("No Authenticated Users", "None");
				allUserInfo.Add(dictionary);
			}
			return allUserInfo;
		}

		private async Task<Dictionary<string, object>> BuildSystemInfoSaleForce()
		{
			Dictionary<string, object> systemInfo = new Dictionary<string, object>
			{
				{ "Platform", Platform },
				{ "OS Version", OsVersion }
			};
			if (OsIncrementalVersion != null)
			{
				systemInfo.Add("OS Incremental Version", OsIncrementalVersion);
			}
			systemInfo.Add("App Version", AppVersion);
			if (!string.IsNullOrEmpty(webViewVersion) && !webViewVersion.Equals("Unknown"))
			{
				systemInfo.Add("WebView Version", webViewVersion);
			}
			systemInfo.Add("Screen Size", deviceInformation.ScreenWidth + "x" + deviceInformation.ScreenHeight);
			systemInfo.Add("Pixel Screen Size", deviceInformation.PixelScreenWidth + "x" + deviceInformation.PixelScreenHeight);
			systemInfo.Add("Screen Pixel Density", deviceInformation.ScreenPixelDensity);
			IConsoleInfo consoleInfo = currentConsoleService?.Console?.ConsoleInfo;
			if (consoleInfo != null)
			{
				systemInfo.Add("Model", consoleInfo.ModelNumber);
				systemInfo.Add("PartNumber", deviceInformation.SoftwareNumber + (deviceInformation.SpoofedSoftwareNumber.HasValue ? " (spoofed)" : ""));
				systemInfo.Add("IsClub", consoleInfo.IsClub);
				systemInfo.Add("Brainboard Software Version", consoleInfo.SoftwareVersion);
				systemInfo.Add("Hardware Version", consoleInfo.HardwareVersion);
				systemInfo.Add("Machine Type", consoleInfo.MachineType);
				systemInfo.Add("Serial Number", consoleInfo.SerialNumber);
				if (Mvx.TryResolve<IConsoleUpdateInfo>(out var service))
				{
					Guid guid = (await service.GetInfo()).Guid;
					if (guid != Guid.Empty)
					{
						systemInfo.Add("Console UUID", guid.ToString());
					}
				}
				systemInfo.Add("MasterLibVersion", consoleInfo.MasterLibraryVersion);
				systemInfo.Add("MasterLibBuild", consoleInfo.MasterLibraryBuild);
				systemInfo.Add("System Units", consoleInfo.SystemUnits);
				systemInfo.Add("Machine ID", consoleInfo.BrainboardSerialNumber);
			}
			else
			{
				systemInfo.Add("Console Not Detected", "");
			}
			return systemInfo;
		}

		private Dictionary<string, object> BuildFeatureFlagSalesForce()
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			IReadOnlyList<FeatureFlag> allFlags = FeatureFlags.AllFlags;
			if (allFlags != null)
			{
				foreach (FeatureFlag item in allFlags)
				{
					switch (item.Type)
					{
					case FeatureFlagType.Bool:
						dictionary.Add(item.Key, featureFlagManager.IsFeatureEnabled(item).ToString());
						break;
					case FeatureFlagType.Int:
						dictionary.Add(item.Key, featureFlagManager.GetInt(item));
						break;
					case FeatureFlagType.String:
					case FeatureFlagType.WebviewUrl:
						dictionary.Add(item.Key, featureFlagManager.GetString(item));
						break;
					default:
						dictionary.Add("Feature flag type unknown.", "");
						break;
					}
				}
			}
			else
			{
				dictionary.Add("Feature Flags are null", "");
			}
			return dictionary;
		}

		private async Task<List<Dictionary<string, object>>> BuildConsoleLogsSalesForce(string userName, string supplementalCrashLogReport = null)
		{
			List<Dictionary<string, object>> logResults = new List<Dictionary<string, object>>();
			string text = DateTime.UtcNow.ToString("yyyyMMdd");
			string uploadDirectory = "wolf_feedback/" + userName + "_" + text + "/";
			List<string> excludedLogs = new List<string> { "FitProBytes.txt" };
			string text2 = await logFileService.UploadLogsToS3AndCreateDescription(uploadDirectory, supplementalCrashLogReport, excludedLogs);
			if (!string.IsNullOrEmpty(text2))
			{
				string[] array = text2.Split("\n");
				string[] array2 = array;
				foreach (string value in array2)
				{
					Dictionary<string, object> dictionary = new Dictionary<string, object>();
					dictionary.Add("log", value);
					logResults.Add(dictionary);
				}
			}
			return logResults;
		}

		private async Task<string> BuildFeedbackSalesForce(string userName, FeedbackInfo feedbackInfo, string supplementalCrashLogReport = null)
		{
			Dictionary<string, object> finalJson = new Dictionary<string, object> { 
			{
				"Customer Care Summary",
				BuildDescriptionSalesForce(feedbackInfo)
			} };
			Dictionary<string, object> dictionary = finalJson;
			dictionary.Add("User Information", await BuildUserInfoSalesForce());
			dictionary = finalJson;
			dictionary.Add("System Information", await BuildSystemInfoSaleForce());
			finalJson.Add("Feature Flags", BuildFeatureFlagSalesForce());
			dictionary = finalJson;
			dictionary.Add("Console Logs", await BuildConsoleLogsSalesForce(userName, supplementalCrashLogReport));
			string text = JsonConvert.SerializeObject(finalJson);
			return text.Replace("\"\"", "null");
		}

		private async Task<bool> SendToSalesForce(string salesForceJson)
		{
			SalesForceCreds salesForceInfo = new SalesForceCreds(localSettings);
			using IHttpClient httpClient = webUtils.GetHttpClient();
			using HttpRequestMessage request = new HttpRequestMessage(new HttpMethod("POST"), salesForceInfo.salesForceTokenUrl);
			request.Headers.TryAddWithoutValidation("Accept", "application/json");
			string content = "username=integrationcase@ifit.com&client_secret=" + iFit.Extensions.StringExtensions.TransformString(salesForceInfo.clientSecret) + "&password=" + iFit.Extensions.StringExtensions.TransformString(salesForceInfo.clientPassword) + "&grant_type=password&client_id=" + iFit.Extensions.StringExtensions.TransformString(salesForceInfo.clientId);
			request.Content = new StringContent(content);
			request.Content.Headers.ContentType = MediaTypeHeaderValue.Parse("application/x-www-form-urlencoded");
			HttpResponseMessage response = await httpClient.SendAsync(request);
			if (response.StatusCode != HttpStatusCode.OK)
			{
				return false;
			}
			Task<string> task = response.Content.ReadAsStringAsync();
			SalesForceOAuth salesForceOAuth = JsonConvert.DeserializeObject<SalesForceOAuth>(task.Result);
			if (string.IsNullOrEmpty(salesForceOAuth.access_token))
			{
				return false;
			}
			using IHttpClient newClient = webUtils.GetHttpClient();
			newClient.DefaultRequestHeaders.Add("Authorization", "Bearer " + salesForceOAuth.access_token);
			StringContent content2 = new StringContent(salesForceJson);
			HttpResponseMessage httpResponseMessage = await newClient.PostAsync(salesForceInfo.salesForceUrl, content2);
			if (response.StatusCode != HttpStatusCode.OK)
			{
				return false;
			}
			SalesForceResponse salesForceResponse = JsonConvert.DeserializeObject<SalesForceResponse>(await httpResponseMessage.Content.ReadAsStringAsync());
			return salesForceResponse.status == "success";
		}
	}
