	public interface IGlobalErrorHandler
	{
	}
	public class GlobalErrorHandler : IGlobalErrorHandler
	{
		private const string tag = "GlobalError";

		public GlobalErrorHandler(IGlobalErrorService globalErrorService)
		{
			globalErrorService.WhenGlobalErrorHappened.Subscribe(OnGlobalError);
		}

		private void OnGlobalError(GlobalError error)
		{
			Action toDo = delegate
			{
				Log.Error("GlobalError", $"Global error reported: {error.Message}. ForceLogout={error.ForceLogout}");
				if (error.ForceLogout)
				{
					if (Mvx.TryResolve<ILogOutService>(out var logOutService))
					{
						Log.Trace("GlobalError", "Forcing logout.");
						Task.Run(async delegate
						{
							await logOutService.LogOut();
						});
					}
					else
					{
						Log.Error("GlobalError", "Could not resolve ILogOutService, so could not force logout. That's bad.");
					}
				}
			};
			if (error.ShowDialog)
			{
				if (Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service) && Mvx.TryResolve<IDialogPresenter>(out var presenter))
				{
					ConfirmationInitializationData initObject = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.global_error_title, error.Message, async delegate
					{
						toDo();
						return Task.CompletedTask;
					}, cancellableOperation: false, null, null, Wolf.Core.Resources.AppStrings.ok, OnConfirmActionTiming.AfterClose, null, null, dismissible: false, cancellable: false);
					service.RequestMainThreadAction(delegate
					{
						presenter.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, initObject);
					});
				}
			}
			else
			{
				toDo();
			}
		}
	}
