		public HeartRateService(ICurrentConsoleService currentConsoleService, IDeveloperSettings developerSettings, IScanner scanner, IBleRadioStatusService bluetoothStatusService, IFeatureFlagManager featureFlagManager)
		{
			this.bluetoothStatusService = bluetoothStatusService;
			HeartRateHelperFlags heartRateHelperFlags = new HeartRateHelperFlags(featureFlagManager);
			HeartRateScanner = new HeartRateScanner(heartRateHelperFlags, scanner);
			SetHeartRateHelper();
			currentConsoleService.WhenConsoleChanged.Subscribe(OnWhenConsoleChanged);
			if (currentConsoleService.ActiveConsole != null)
			{
				OnWhenConsoleChanged(currentConsoleService.ActiveConsole);
			}
			developerSettings.OnMockHRUIChanged.Subscribe(OnMockHRUIChanged);
		}

		private void OnMockHRUIChanged(bool nextMock)
		{
			Mock = nextMock;
			SetHeartRateHelper();
