		{
			console = iFitConsole;
			HeartRate.Console = console;
		}

		private void SetHeartRateHelper()
		{
			HeartRate?.Dispose();
			if (Mock)
			{
				HeartRate = new MockHeartRateHelper(console, Mvx.Resolve<IPulseFacade>());
			}
			else
			{
				HeartRate = new HeartRateHelper(HeartRateScanner, console, bluetoothStatusService, Mvx.Resolve<IPulseFacade>());
