	public struct EmailCredentials
	{
		public string Name { get; }

		public string Address { get; }

		public string[] Password { get; }

		public EmailCredentials(string name, string address, string[] password)
		{
			Name = name;
			Address = address;
			Password = password;
		}

		public override string ToString()
		{
			return "[Name:" + Name + " Address:" + Address + " Password:[" + string.Join(',', Password) + "]]";
		}

		public override bool Equals(object obj)
		{
			if (obj is EmailCredentials emailCredentials && Name == emailCredentials.Name && Address == emailCredentials.Address)
			{
				return Enumerable.SequenceEqual(Password, emailCredentials.Password);
			}
			return false;
		}

		public override int GetHashCode()
		{
			return HashCode.Combine(Name, Address, Password);
		}
	}
	public struct EmailRecipient
	{
		public string Name { get; }

		public string Address { get; }

		public EmailRecipient(string name, string address)
		{
			Name = name;
			Address = address;
		}

		public override string ToString()
		{
			return "[Name:" + Name + " Address:" + Address + "]";
		}
	}
