		private readonly IWorkoutSettings workoutSettings;

		private readonly IMediaSettings mediaSettings;

		private bool _clubDefaultIsMetric;

		public const int DefaultClubMaxWorkoutTimeMinutes = 60;

		public const int MinimumClubMaxWorkoutTimeMinutes = 15;

		public const int MaximumClubMaxWorkoutTimeMinutes = 300;

		private int _clubMaxWorkoutTimeMinutes;

		public const int DefaultClubMaxPauseTimeMinutes = 2;

		public const int MinimumClubMaxPauseTimeMinutes = 1;

		public const int MaximumClubMaxPauseTimeMinutes = 15;

		private int _clubMaxPauseTimeMinutes;

		private const int DefaultWarmUpTimeSeconds = 180;

		private const MapView DefaultMapCycleViews = MapView.StreetView | MapView.Map | MapView.Satellite;

		public bool DisableLogoutService { get; set; }

		public bool ClubDefaultIsMetric
		{
			get
			{
				return _clubDefaultIsMetric;
			}
			set
			{
				if (_clubDefaultIsMetric != value)
				{
					_clubDefaultIsMetric = value;
					cacheService.Flush(_clubDefaultIsMetric, "_clubDefaultIsMetric", "IClubLocalSettings");
				}
			}
		}

		public int ClubMaxWorkoutTimeMinutes
		{
			get
			{
				if (_clubMaxWorkoutTimeMinutes >= 15)
				{
					return _clubMaxWorkoutTimeMinutes;
				}
				return 60;
			}
			set
			{
				if (_clubMaxWorkoutTimeMinutes != value)
				{
					if (value < 15 || value > 300)
					{
						throw new InvalidClubValueException();
					}
					_clubMaxWorkoutTimeMinutes = value;
					cacheService.Flush(_clubMaxWorkoutTimeMinutes, "_clubMaxWorkoutTimeMinutes", "IClubLocalSettings");
				}
			}
		}

		public int ClubMaxPauseTimeMinutes
		{
			get
			{
				if (_clubMaxPauseTimeMinutes >= 1)
				{
					return _clubMaxPauseTimeMinutes;
				}
				return 2;
			}
			set
			{
				if (_clubMaxPauseTimeMinutes != value)
				{
					if (value < 1 || value > 15)
					{
						throw new InvalidClubValueException();
					}
					_clubMaxPauseTimeMinutes = value;
					cacheService.Flush(_clubMaxPauseTimeMinutes, "_clubMaxPauseTimeMinutes", "IClubLocalSettings");
				}
			}
		}

