		{
			this.localSettings = localSettings;
			this.cacheService = cacheService;
			this.deviceInformation = deviceInformation;
			this.workoutSettings = workoutSettings;
			this.mediaSettings = mediaSettings;
		}

		private async Task<IClubLocalSettings> InitializeAsync()
		{
			_clubDefaultIsMetric = await cacheService.GetFromCache("_clubDefaultIsMetric", "IClubLocalSettings", "", temp: false, defaultValue: false);
			_clubMaxWorkoutTimeMinutes = await cacheService.GetFromCache("_clubMaxWorkoutTimeMinutes", "IClubLocalSettings", "", temp: false, 0);
			_clubMaxPauseTimeMinutes = await cacheService.GetFromCache("_clubMaxPauseTimeMinutes", "IClubLocalSettings", "", temp: false, 0);
			return this;
		}

		public static Task<IClubLocalSettings> CreateAsync(ILocalSettings localSettings, IBlobCacheService cacheService, IDeviceInformation deviceInformation, IWorkoutSettings workoutSettings, IMediaSettings mediaSettings)
		{
			ClubLocalSettings clubLocalSettings = new ClubLocalSettings(localSettings, cacheService, deviceInformation, workoutSettings, mediaSettings);
			return clubLocalSettings.InitializeAsync();
		}

		public void ResetGuestSettings()
		{
			workoutSettings.WarmUpSeconds = 180;
			workoutSettings.ShowSliders = !deviceInformation.IsBuiltIn;
			localSettings.MapCycleViews = MapView.StreetView | MapView.Map | MapView.Satellite;
			mediaSettings.ResetMusicVolumeToDefault();
			mediaSettings.ResetTrainerVolumeToDefault();
		}
