	public class IdleLogoutService : BaseTouchTimeoutService, IIdleLogoutService
	{
		private readonly IClubLocalSettings clubLocalSettings;

		private readonly IIfitApiService api;

		private readonly IDialogPresenter dialogPresenter;

		private readonly IAppLifecycleService lifecycleService;

		private readonly IMvxMainThreadDispatcher mvxMainThreadDispatcher;

		private readonly ICurrentConsoleService currentConsoleService;

		protected override double TimeoutSeconds => TimeSpan.FromSeconds(60.0).TotalSeconds;

		public IdleLogoutService(IClubLocalSettings clubLocalSettings, ITouchMonitor touchMonitor, IIfitApiService api, IDialogPresenter dialogPresenter, IAppLifecycleService lifecycleService, IMvxMainThreadDispatcher mvxMainThreadDispatcher, ICurrentConsoleService currentConsoleService)
			: base(touchMonitor)
		{
			this.clubLocalSettings = clubLocalSettings;
			this.api = api;
			this.dialogPresenter = dialogPresenter;
			this.lifecycleService = lifecycleService;
			this.mvxMainThreadDispatcher = mvxMainThreadDispatcher;
			this.currentConsoleService = currentConsoleService;
			touchMonitor.Touched = (EventHandler)Delegate.Remove(touchMonitor.Touched, new EventHandler(OnTouched));
			touchMonitor.Touched = (EventHandler)Delegate.Combine(touchMonitor.Touched, new EventHandler(OnTouched));
			Log.Trace("Navigation", "Idle Logout Service starting.");
			lifecycleService.AppStateChanged -= LifecycleServiceOnAppStateChanged;
			lifecycleService.AppStateChanged += LifecycleServiceOnAppStateChanged;
		}

		private void LifecycleServiceOnAppStateChanged(object sender, AppStateEventArgs e)
		{
			SetActive(e.CurrentState == AppLifecycleService.AppState.Foreground);
		}

		public void SetActive(bool active)
		{
			ITouchMonitor touchMonitor = TouchMonitor;
			touchMonitor.TestTimeoutElapsed = (EventHandler)Delegate.Remove(touchMonitor.TestTimeoutElapsed, new EventHandler(OnTestTimeoutElapsed));
			if (active && !clubLocalSettings.DisableLogoutService)
			{
				Log.Trace("Navigation", "Idle Logout Service starting.");
				TouchMonitor.UpdateLastObservedTouch();
				ITouchMonitor touchMonitor2 = TouchMonitor;
				touchMonitor2.TestTimeoutElapsed = (EventHandler)Delegate.Combine(touchMonitor2.TestTimeoutElapsed, new EventHandler(OnTestTimeoutElapsed));
			}
		}

		private void OnTouched(object sender, EventArgs e)
		{
			TouchMonitor.UpdateLastObservedTouch();
		}

		protected override void OnTimeoutSinceTouchDidElapse()
		{
			string text = $"No activity for {TimeoutSeconds} sec, ";
			switch (currentConsoleService.Console?.LatestBasicInfo?.CurrentState)
			{
			case ConsoleState.Error:
				if (dialogPresenter.IsDialogShown<ConsoleErrorDialogViewModel>())
				{
					Log.Trace("Navigation", text + "in console error dialog, not logging out.");
					return;
				}
				break;
			case ConsoleState.Workout:
			case ConsoleState.Paused:
			case ConsoleState.WarmUp:
			case ConsoleState.CoolDown:
			case ConsoleState.PauseOverride:
				return;
			}
			ClubUnitPreloginBaseDialogViewModel clubPreloginDialogViewModel = GetClubPreloginDialogViewModel();
			if (clubPreloginDialogViewModel != null)
			{
				Log.Trace("Navigation", text + "closing Club Unit Prelogin dialog.");
				clubPreloginDialogViewModel.CloseViewModel.Execute();
				return;
			}
			ShireBaseViewModel currentMainViewModel = dialogPresenter.CurrentMainViewModel;
			if (!(currentMainViewModel is ClubUnitAccountSelectionViewModel))
			{
				if (!(currentMainViewModel is WelcomeViewModel) && !(currentMainViewModel is LaunchScreenViewModel) && !(currentMainViewModel is OnBoardingSetupViewModel) && !(currentMainViewModel is SettingsOtherWifiDialogViewModel) && !(currentMainViewModel is RegisterEquipmentViewModel))
				{
					if (!(currentMainViewModel is PowerCycleViewModel))
					{
						BaseViewModel baseViewModel = currentMainViewModel as BaseViewModel;
						if (baseViewModel != null)
						{
							Log.Trace("Navigation", text + "logging out.");
							mvxMainThreadDispatcher.RequestMainThreadAction(delegate
							{
								baseViewModel.LogOut.Execute();
							});
						}
						else
						{
							Log.Warn("Navigation", text + "but no current base view model to log out with!");
						}
					}
					else
					{
						Log.Trace("Navigation", text + "in power cycle, not logging out.");
					}
				}
				else
				{
					Log.Trace("Navigation", text + "in onboarding setup, not logging out.");
				}
			}
			else
			{
				Log.Trace("Navigation", text + "already on account selection view.");
			}
		}

		private ClubUnitPreloginBaseDialogViewModel GetClubPreloginDialogViewModel()
		{
			return (ClubUnitPreloginBaseDialogViewModel)(dialogPresenter.CurrentDialogViewModel<ClubUnitLoginDialogViewModel>() ?? ((object)dialogPresenter.CurrentDialogViewModel<ClubUnitForgotPasswordDialogViewModel>()) ?? ((object)dialogPresenter.CurrentDialogViewModel<ClubRequestInformationDialogViewModel>()));
		}
	}
