	public class LastGoodStateReporter : ILastGoodStateReporter
	{
		private readonly IBlobCacheService cacheService;

		private readonly IWolfAnalytics analytics;

		private readonly IDeviceInformation deviceInformation;

		private readonly IWolfTrackingService trackingService;

		private readonly ICurrentConsoleService currentConsoleService;

		private const string Tag = "LastGoodStateReporter";

		private const string CacheKey = "last-good-state-info";

		private string latestViewModel;

		protected Task writingTask = Task.CompletedTask;

		public LastGoodStateReporter(IBlobCacheService cacheService, IAppLifecycleService lifecycleService, IWolfAnalytics analytics, IDeviceInformation deviceInformation, IWolfTrackingService trackingService, ICurrentConsoleService currentConsoleService)
		{
			this.cacheService = cacheService;
			this.analytics = analytics;
			this.deviceInformation = deviceInformation;
			this.trackingService = trackingService;
			this.currentConsoleService = currentConsoleService;
			lifecycleService.AppStateChanged -= OnAppStateChanged;
			lifecycleService.AppStateChanged += OnAppStateChanged;
			CheckLastRecord();
		}

		private async Task CheckLastRecord()
		{
			_ = 1;
			try
			{
				LastGoodStateReporterInfo lastGoodStateReporterInfo = await cacheService.Secure.GetObject<LastGoodStateReporterInfo>("last-good-state-info");
				if (!lastGoodStateReporterInfo.ExpectedShutdown)
				{
					await analytics.UnexpectedShutdown(lastGoodStateReporterInfo);
				}
			}
			catch (KeyNotFoundException)
			{
				Log.Trace("LastGoodStateReporter", "Did not find last state record");
			}
		}

		public async Task OnViewModelChanged(string viewModelName)
		{
			latestViewModel = viewModelName;
			await SaveInfo(shuttingDown: false);
		}

		private async void OnAppStateChanged(object sender, AppStateEventArgs e)
		{
			bool shuttingDown = e.CurrentState == AppLifecycleService.AppState.Background;
			await SaveInfo(shuttingDown);
		}

		private async Task SaveInfo(bool shuttingDown)
		{
			if (trackingService.IsInWorkout)
			{
				ClearCache();
				return;
			}
			await writingTask;
			writingTask = Task.Run(() => WriteToCacheTask(shuttingDown));
			await writingTask;
		}

		private async Task WriteToCacheTask(bool shuttingDown)
		{
			_ = 1;
			try
			{
				LastGoodStateReporterInfo value = CreateStateInfo(shuttingDown);
				await cacheService.Secure.InsertObject("last-good-state-info", value, TimeSpan.FromHours(1.0));
				await cacheService.Secure.Flush();
			}
			catch (Exception exception)
			{
				Log.Error("LastGoodStateReporter", "Error when trying to insert object into cache", exception);
			}
		}

		public void ClearCache()
		{
			cacheService.Secure.Invalidate("last-good-state-info");
		}

		private LastGoodStateReporterInfo CreateStateInfo(bool shuttingDown)
		{
			return new LastGoodStateReporterInfo(latestViewModel, deviceInformation?.TotalMemory ?? 0, deviceInformation?.AvailableMemory ?? 0, deviceInformation?.LowMemoryThreshold ?? 0, currentConsoleService.Console.ConsoleInfo.MachineType.ToString(), shuttingDown);
		}
	}
