	public interface ILaunchBehaviorService
	{
		bool HasLaunchBehaviorOccurred(LaunchBehaviorFlag launchBehavior);

		void SetLaunchBehaviorOccurred(LaunchBehaviorFlag launchBehavior, bool hasOccurred = true);

		void ResetAllLaunchBehaviors();
	}
	public class LaunchBehaviorService : ILaunchBehaviorService
	{
		private readonly IBlobCacheService cacheService;

		public List<string> OccurredLaunchBehaviors { get; set; }

		public LaunchBehaviorService(IBlobCacheService cacheService)
		{
			this.cacheService = cacheService;
		}

		private async Task<ILaunchBehaviorService> InitializeAsync()
		{
			OccurredLaunchBehaviors = await cacheService.GetFromCache<List<string>>("OccurredLaunchBehaviors", "ILaunchBehaviorService");
			return this;
		}

		public static Task<ILaunchBehaviorService> CreateAsync(IBlobCacheService cacheService)
		{
			LaunchBehaviorService launchBehaviorService = new LaunchBehaviorService(cacheService);
			return launchBehaviorService.InitializeAsync();
		}

		public bool HasLaunchBehaviorOccurred(LaunchBehaviorFlag launchBehavior)
		{
			return OccurredLaunchBehaviors?.Contains(launchBehavior.ToString()) ?? false;
		}

		public void SetLaunchBehaviorOccurred(LaunchBehaviorFlag launchBehavior, bool hasOccurred = true)
		{
			if (OccurredLaunchBehaviors == null)
			{
				Log.Trace("LaunchBehaviorFlag", "OccurredLaunchBehaviors list was null, rebuilding.");
				OccurredLaunchBehaviors = new List<string>();
			}
			if (hasOccurred && !HasLaunchBehaviorOccurred(launchBehavior))
			{
				OccurredLaunchBehaviors.Add(launchBehavior.ToString());
				cacheService.Flush(OccurredLaunchBehaviors, "OccurredLaunchBehaviors", "ILaunchBehaviorService");
				Log.Trace("LaunchBehaviorFlag", $"Launch behavior flag {launchBehavior} added to occurrence list.");
			}
			else if (!hasOccurred && HasLaunchBehaviorOccurred(launchBehavior))
			{
				OccurredLaunchBehaviors.Remove(launchBehavior.ToString());
				cacheService.Flush(OccurredLaunchBehaviors, "OccurredLaunchBehaviors", "ILaunchBehaviorService");
				Log.Trace("LaunchBehaviorFlag", $"Launch behavior flag {launchBehavior} removed from occurrence list.");
			}
		}

		public void ResetAllLaunchBehaviors()
		{
			OccurredLaunchBehaviors?.Clear();
			cacheService.Flush(OccurredLaunchBehaviors, "OccurredLaunchBehaviors", "ILaunchBehaviorService");
			Log.Trace("LaunchBehaviorFlag", "All launch behavior flag occurrences reset.");
		}
	}
