	public class LaunchBleUpdateService : ILaunchUpdate
	{
		private readonly ILocalSettings localSettings;

		private readonly ICheckUpdateService checkService;

		private readonly IUpdater updater;

		private readonly IFirmwareFactoryService firmwareFactory;

		private readonly IWolfAnalytics reporter;

		private readonly IBleConsoleService bleConsoleService;

		private readonly IIfitApiService apiService;

		private readonly ISaveUpdateFilesService saveFileService;

		private readonly IDeviceInformation deviceInformation;

		public LaunchBleUpdateService(ILocalSettings localSettings, ICheckUpdateService checkService, IUpdater updater, IFirmwareFactoryService firmwareFactory, IWolfAnalytics reporter, IBleConsoleService bleConsoleService, IIfitApiService apiService, ISaveUpdateFilesService saveFileService, IDeviceInformation deviceInformation)
		{
			this.localSettings = localSettings;
			this.checkService = checkService;
			this.updater = updater;
			this.firmwareFactory = firmwareFactory;
			this.reporter = reporter;
			this.bleConsoleService = bleConsoleService;
			this.apiService = apiService;
			this.saveFileService = saveFileService;
			this.deviceInformation = deviceInformation;
		}

		public void UpdateConnectedMachine(bool attemptToRecover = false)
		{
			Task.Run(() => UpdateCurrentConnected(attemptToRecover));
		}

		public void RecoverMachine(int softwareNumber, string pairKey = null)
		{
			Task.Run(() => Recover(softwareNumber, pairKey));
		}

		private async Task Recover(int softwareNumber, string pairKey = null)
		{
			BleUpdateArgs args = new BleUpdateArgs
			{
				PairKey = pairKey
			};
			try
			{
				BleUpdateArgs bleUpdateArgs = args;
				bleUpdateArgs.Firmware = await GetFirmwareFromSoftwareNumber(softwareNumber);
			}
			catch (Exception arg)
			{
				LogIt($"Recover Update couldn't get firmware from [softwareNumber : {softwareNumber}] [pairKey : {pairKey}] EXCEPTION => {arg}");
				return;
			}
			if (args.Firmware != null)
			{
				try
				{
					await updater.AttemptUpdateAsync(args);
				}
				catch (Exception arg2)
				{
					LogIt($"Recover Update failed [softwareNumber : {softwareNumber}] [pairKey : {pairKey}] EXCEPTION => {arg2}");
				}
			}
		}

		private async Task<IFirmware> GetFirmwareFromSoftwareNumber(int softwareNumber)
		{
			IFirmware firmware = null;
			BrainboardUpdate bbUpdate = null;
			try
			{
				bbUpdate = await BrainboardUpdate.Get(apiService, softwareNumber);
			}
			catch (Exception ex)
			{
				await reporter.Track("Firmware Action Needed", new Dictionary<string, object>
				{
					["softwareNumber"] = softwareNumber,
					["problem"] = "Unable to download firmware, likely a problem with the files in the AWS bin",
					["exception"] = ex.ToString()
				});
				LogIt($"Problem downloading brainboard firmware from [softwareNumber: {softwareNumber}]");
			}
			try
			{
				firmware = await firmwareFactory.Create(bbUpdate, softwareNumber);
			}
			catch (Exception ex2)
			{
				await reporter.Track("Firmware Action Needed", new Dictionary<string, object>
				{
					["updateName"] = bbUpdate?.Name,
					["updateId"] = bbUpdate?.Id,
					["awsBin"] = bbUpdate?.Url,
					["intendedSoftwareNumber"] = softwareNumber,
					["responseSoftwareNumbers"] = string.Join(",", bbUpdate?.SoftwareNumbers),
					["problem"] = "Unable to create firmware, likely a problem with the files in the AWS bin",
					["exception"] = ex2.ToString()
				});
				LogIt($"Problem downloading brainboard firmware from update: {bbUpdate}");
			}
			return firmware;
		}

		private async Task UpdateCurrentConnected(bool attemptToRecover = false)
		{
			if (bleConsoleService.CurrentDevice == null)
			{
				if (attemptToRecover && Mvx.TryResolve<IDfuConnectionService>(out var service))
				{
					service.ScanForRecoverableDevices();
				}
				LogIt("No connected device, aborting update");
				return;
			}
			BleUpdateArgs args = new BleUpdateArgs
			{
				Device = bleConsoleService.CurrentDevice,
				PairKey = bleConsoleService.CurrentDevice?.PairKey
			};
			int softwareNumber = deviceInformation.SpoofedSoftwareNumber ?? bleConsoleService.Console?.ConsoleInfo?.PartNumber ?? (-1);
			if (softwareNumber == -1)
			{
				try
				{
					softwareNumber = (from tuple in await saveFileService.GetSetOfPreviouslyConnectedMachines()
						where tuple.Item1.Equals(args.PairKey)
						select tuple.Item2).DefaultIfEmpty(-1).First();
				}
				catch (Exception arg)
				{
					LogIt($"UpdateCurrentConnected Error getting [update args: {args}] ERROR => {arg}");
					return;
				}
			}
			if (softwareNumber == -1)
			{
				LogIt("No Machine -> No SoftwareNumber (Console.ConsoleInfo.PartNumber)");
				return;
			}
			CheckUpdateState updateAvailable;
			BrainboardUpdate update;
			try
			{
				Task<BrainboardUpdate> bbUpdateTask = (from x in checkService.WhenBrainboardUpdateFetched.Timeout(TimeSpan.FromSeconds(10.0))
					where x.SoftwareNumbers.Contains(softwareNumber)
					select x).Take(1).ToTask();
				updateAvailable = await checkService.CheckForUpdate();
				update = await bbUpdateTask;
			}
			catch (Exception arg2)
			{
				LogIt($"Error in Getting Update  [update args: {args}] ERROR => {arg2}");
				return;
			}
			try
			{
				BleUpdateArgs bleUpdateArgs = args;
				bleUpdateArgs.Firmware = await firmwareFactory.Create(update, softwareNumber);
			}
			catch (Exception arg3)
			{
				LogIt($"UpdateCurrentConnected Error creating firmware [update args: {args}] ERROR => {arg3}");
				return;
			}
			if (updateAvailable != CheckUpdateState.UpdateAvailable || args.Firmware == null)
			{
				return;
			}
			try
			{
				await updater.AttemptUpdateAsync(args);
			}
			catch (Exception ex)
			{
				LogIt($"Error update connected console [update args: {args}] ERROR => {ex.Message}");
			}
		}

		private void LogIt(string msg, bool isError = true)
		{
			if (isError)
			{
				Log.Error("Updating", "[ILaunchUpdate] -> " + msg);
			}
			else
			{
				Log.Trace("Updating", "[ILaunchUpdate] -> " + msg);
			}
		}
	}
