	public interface ILogOutService
	{
		Task LogOut(bool skipNavigation = false, bool showLaunchScreen = true);
	}
	public class LogOutService : BaseWebViewBehaviorProvider, ILogOutService
	{
		public const string NativeMethodLogout = "Logout";

		public const string SkipNavigation = "SkipNavigation";

		public const string ShowLaunchScreen = "ShowLaunchScreen";

		private readonly IMvxViewDispatcher viewDispatcher;

		private readonly IMvxMainThreadDispatcher mainThreadDispatcher;

		private readonly IWebviewHolderFactory webviewHolderFactory;

		private readonly ILocalSettings localSettings;

		private readonly IIfitApiService api;

		private readonly IMembershipSettings membershipSettings;

		private readonly ICurrentConsoleService currentConsoleService;

		public override string BehaviorName => "Logout";

		public LogOutService(IMvxViewDispatcher viewDispatcher, IMvxMainThreadDispatcher mainThreadDispatcher, IWebviewHolderFactory webviewHolderFactory, ILocalSettings localSettings, IIfitApiService api, IMembershipSettings membershipSettings, ICurrentConsoleService currentConsoleService)
		{
			this.viewDispatcher = viewDispatcher;
			this.mainThreadDispatcher = mainThreadDispatcher;
			this.webviewHolderFactory = webviewHolderFactory;
			this.localSettings = localSettings;
			this.api = api;
			this.membershipSettings = membershipSettings;
			this.currentConsoleService = currentConsoleService;
		}

		public async Task LogOut(bool skipNavigation = false, bool showLaunchScreen = true)
		{
			Log.Trace("Settings", "Clearing web cache started");
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			mainThreadDispatcher.RequestMainThreadAction(delegate
			{
				webviewHolderFactory.WebviewHolderStore.ClearWebViewCache();
				webviewHolderFactory.WebviewHolderStore.FlushAll();
				tcs.SetResult(result: true);
			});
			await tcs.Task;
			Log.Trace("Settings", "Clearing web cache finished");
			membershipSettings.Reset();
			await api.Logout(currentConsoleService.IsBuiltinClub || !api.HasLoggedInUser);
			try
			{
				User user = api.AuthenticatedUsers.FirstOrDefault((User u) => u.Premium == true) ?? api.AuthenticatedUsers.FirstOrDefault((User u) => u.Premium == false);
				if (user != null)
				{
					await api.SwitchUser(user.Id);
					if (!skipNavigation)
					{
						HardResetNavigation(!api.HasLoggedInUser, forceLoggedInUserToDashboard: false, showLaunchScreen);
					}
					return;
				}
			}
			catch (Exception exception)
			{
				Log.Warn("Navigation", "Logged out, falling back to logged in user failed.", exception);
			}
			if (!skipNavigation)
			{
				await WaitForFeatureFlags().ConfigureAwait(continueOnCapturedContext: false);
				HardResetNavigation(!api.HasLoggedInUser, forceLoggedInUserToDashboard: false, showLaunchScreen);
			}
		}

		private async Task WaitForFeatureFlags()
		{
			for (int i = 0; i <= 2; i++)
			{
				await Task.Delay(1000);
				if (Mvx.Resolve<IFeatureFlagManager>()?.GetString(FeatureFlags.CommonOnboardingWebViewUrl) != null)
				{
					Log.Trace("FeatureFlags", "Feature flag for onboarding is ready during logout");
					return;
				}
			}
			Log.Warn("FeatureFlags", "Feature flag for onboarding not loaded in 3 seconds during logout");
		}

		public void HardResetNavigation(bool showWallOnBle = false, bool forceLoggedInUserToDashboard = false, bool showLaunchScreen = true)
		{
			Log.Trace("Navigation", $"Hard resetting navigation - show BLE wall {showWallOnBle}");
			MvxBundle parameterBundle = new MvxBundle(new LoginViewModelOverride.NavObject
			{
				ShouldBleShowWall = showWallOnBle,
				ForceLoggedInUserToDashboard = forceLoggedInUserToDashboard
			}.ToSimplePropertyDictionary());
			webviewHolderFactory.WebviewHolderStore.FlushAll();
			if (showLaunchScreen)
			{
				MvxViewModelRequest request = new MvxViewModelRequest(typeof(LaunchScreenViewModel), parameterBundle, ShireViewParams.ClearStackToRequested(), null);
				viewDispatcher.ShowViewModel(request);
			}
		}

		public override Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			bool skipNavigation = false;
			bool showLaunchScreen = true;
			if (parameters != null)
			{
				if (parameters.ContainsKey("SkipNavigation") && bool.TryParse(parameters["SkipNavigation"], out var result))
				{
					skipNavigation = result;
				}
				if (parameters.ContainsKey("ShowLaunchScreen") && bool.TryParse(parameters["ShowLaunchScreen"], out var result2))
				{
					showLaunchScreen = result2;
				}
			}
			return LogOut(skipNavigation, showLaunchScreen);
		}
	}
	public interface ILostWifiService : IDisposable
	{
	}
	public class LostWifiService : ILostWifiService, IDisposable
	{
		private readonly IDialogPresenter dialogPresenter;

		private IDisposable lostWifiSub;

		private IDisposable gainedWifiSub;

		public LostWifiService(IDialogPresenter dialogPresenter, INeedsRefreshService needsRefreshService)
		{
			this.dialogPresenter = dialogPresenter;
			lostWifiSub = needsRefreshService.WhenNeedsRefresh.Where((IRefreshPayload x) => x.Cause == RefreshCause.LostInternet).Subscribe(OnLostInternet);
		}

		private void OnLostInternet(IRefreshPayload payload)
		{
			if (dialogPresenter?.CurrentMainViewModel is BaseInternetConnectionViewModel baseInternetConnectionViewModel)
			{
				baseInternetConnectionViewModel.ShowNoWifiScreen.Execute();
			}
		}

		public void Dispose()
		{
			lostWifiSub?.Dispose();
			lostWifiSub = null;
			gainedWifiSub?.Dispose();
			gainedWifiSub = null;
		}
	}
	public class ManageSubscriptionService : IManageSubscriptionService
	{
		private const string UpgradeMembershipLink = "www.ifit.com/upgrade";

		private const string ManageMembershipLink = "www.ifit.com/membership";

		private const string Tag = "ManageSubscriptionService";

		private const string GoogleStoreLink = "https://play.google.com/store/account/subscriptions";

		private const string AppleStoreLink = "https://apps.apple.com/account/subscriptions";

		private readonly IBrowserService _browserService;

		private readonly IInAppPurchaseService _inAppPurchaseService;

		private readonly IHardwareInfo _hardwareInfo;

		private readonly string _manageIfitSubscriptionLink;

		private readonly string _upgradeIfitSubscriptionLink;

		public ManageSubscriptionService(IBrowserService browserService, IInAppPurchaseService inAppPurchaseService, IHardwareInfo hardwareInfo)
		{
			_browserService = browserService;
			_inAppPurchaseService = inAppPurchaseService;
			_hardwareInfo = hardwareInfo;
			_manageIfitSubscriptionLink = "https://www.ifit.com/membership";
			_upgradeIfitSubscriptionLink = "https://www.ifit.com/upgrade";
		}

		public async Task ManageMembershipSubscription()
		{
			string url = await GetLinkBasedOnAppSubscriptionStatus();
			_browserService.OpenUrl(url);
		}

		public void ManageIfitMembershipSubscription()
		{
			_browserService.OpenUrl(_manageIfitSubscriptionLink);
		}

		public void UpgradeIfitMembership()
		{
			_browserService.OpenUrl(_upgradeIfitSubscriptionLink);
		}

		public string GetUpgradeMembershipLink()
		{
			return "www.ifit.com/upgrade";
		}

		public string GetManageMembershipLink()
		{
			return "www.ifit.com/membership";
		}

		private async Task<string> GetLinkBasedOnAppSubscriptionStatus()
		{
			_ = 2;
			try
			{
				await _inAppPurchaseService.OpenConnection();
				SubscriptionStatus status = await _inAppPurchaseService.GetSubscriptionStatus();
				await _inAppPurchaseService.CloseConnection();
				return status switch
				{
					SubscriptionStatus.Active => GetStoreLink(), 
					_ => _manageIfitSubscriptionLink, 
				};
			}
			catch (Exception exception)
			{
				Log.Trace("ManageSubscriptionService", "Can't to get InAppSubscription status!", exception);
				return _manageIfitSubscriptionLink;
			}
		}

		private string GetStoreLink()
		{
			if (!_hardwareInfo.IsAndroid)
			{
				return "https://apps.apple.com/account/subscriptions";
			}
			return "https://play.google.com/store/account/subscriptions";
		}
	}
