	public class ModalityChangeService : IModalityChangeService
	{
		private const string LogTag = "ModalityChangeService";

		private readonly IDeviceInformation deviceInformation;

		private readonly IStartWorkoutService startWorkoutService;

		private readonly IDialogPresenter dialogPresenter;

		private readonly IIfitApiService ifitApi;

		private readonly IBleConsoleService bleConsoleService;

		private readonly ICurrentConsoleService currentConsoleService;

		private Dictionary<string, string> overriddenSoftwareNumbersForLive;

		public IFitnessConsole HybridConsoleOverride { get; set; }

		public string HybridSoftwareNumberOverride
		{
			get
			{
				if (!ShouldOverrideConsole)
				{
					return null;
				}
				return HybridConsoleOverride?.ConsoleInfo?.PartNumber.ToString();
			}
		}

		public string HybridConsoleTypeOverride
		{
			get
			{
				if (!ShouldOverrideConsole)
				{
					return null;
				}
				return HybridConsoleOverride?.ConsoleInfo?.MachineType.ToString();
			}
		}

		private bool ShouldOverrideConsole
		{
			get
			{
				IFitnessConsole console = currentConsoleService.Console;
				if (console != null && console.IsHybridMachine())
				{
					return HybridConsoleOverride != null;
				}
				return false;
			}
		}

		private bool IsConsoleTypeCompatibleWithLive(string type)
		{
			if (!type.IsNullOrWhitespace())
			{
				if (!type.ToLower().Contains("treadmill"))
				{
					return type.ToLower().Contains("bike");
				}
				return true;
			}
			return false;
		}

		public string GetOverrideConsoleType(string defaultValue)
		{
			IDeviceInformation obj = deviceInformation;
			if (obj != null && obj.IsHeadlessBikeVault && currentConsoleService?.AttachedConsole != null)
			{
				ICurrentConsoleService obj2 = currentConsoleService;
				if (obj2 != null && obj2.IsAttachedConsoleActive)
				{
					Log.Trace("ModalityChangeService", "Headless Bike Vault has an attached console override");
					return currentConsoleService?.AttachedConsole.ConsoleInfo.MachineType.ToString();
				}
			}
			IDeviceInformation obj3 = deviceInformation;
			if (obj3 != null && obj3.IsBuiltIn)
			{
				Log.Trace("ModalityChangeService", "Not overriding console type, we're on an embedded.");
				return defaultValue;
			}
			if (dialogPresenter?.CurrentMainViewModel is LiveScheduleViewModel)
			{
				Log.Trace("ModalityChangeService", "On Live screen.");
				return GetOverrideConsoleTypeForLive(defaultValue);
			}
			string text = ((!HybridConsoleTypeOverride.IsNullOrWhitespace()) ? HybridConsoleTypeOverride : defaultValue);
			Log.Trace("ModalityChangeService", "Not on Live screen. Default console type: " + defaultValue + ", overriden console type: " + text);
			return text;
		}

		private string GetOverrideConsoleTypeForLive(string defaultValue)
		{
			string text = "";
			if (HybridConsoleTypeOverride.IsNullOrWhitespace())
			{
				text = (IsConsoleTypeCompatibleWithLive(defaultValue) ? defaultValue : "treadmill");
				Log.Trace("ModalityChangeService", "Default console type: " + defaultValue + ", overriden console type for live: " + text);
				return text;
			}
			string hybridConsoleTypeOverride = HybridConsoleTypeOverride;
			if (IsConsoleTypeCompatibleWithLive(hybridConsoleTypeOverride))
			{
				Log.Trace("ModalityChangeService", "Overriden hybrid console type " + defaultValue + " is compatible with live, no need to override");
				return hybridConsoleTypeOverride;
			}
			text = (IsConsoleTypeCompatibleWithLive(defaultValue) ? defaultValue : "treadmill");
			Log.Trace("ModalityChangeService", "Overriden hybrid console type " + defaultValue + " is compatible with live, no need to override");
			return text;
		}

		public async Task<string> GetOverrideSoftwareNumber(string defaultValue)
		{
			if ((deviceInformation?.IsHeadlessBikeVault ?? false) && currentConsoleService?.AttachedConsole != null && (currentConsoleService?.IsAttachedConsoleActive ?? false))
			{
				Log.Trace("ModalityChangeService", "Overriding software number for Vault-attached Headless Bike");
				return currentConsoleService.AttachedConsole.ConsoleInfo.PartNumber.ToString();
			}
			if (deviceInformation?.IsBuiltIn ?? false)
			{
				Log.Trace("ModalityChangeService", "Not overriding software number, we're on an embedded.");
				return defaultValue;
			}
			if (!(dialogPresenter?.CurrentMainViewModel is LiveScheduleViewModel))
			{
				string text = ((!HybridSoftwareNumberOverride.IsNullOrWhitespace()) ? HybridSoftwareNumberOverride : defaultValue);
				Log.Trace("ModalityChangeService", "Not on Live screen, using " + text + " software number.");
				return text;
			}
			if (!overriddenSoftwareNumbersForLive.ContainsKey(defaultValue))
			{
				Log.Trace("ModalityChangeService", "overriddenSoftwareNumbersForLive does not contain a value for " + defaultValue + " (we haven't checked it yet). Fetching equipment info now.");
				Dictionary<string, string> dictionary = overriddenSoftwareNumbersForLive;
				dictionary[defaultValue] = await GetOverrideSoftwareNumberForLive(defaultValue);
			}
			string text2 = overriddenSoftwareNumbersForLive[defaultValue];
			Log.Trace("ModalityChangeService", "On live screen, returning " + text2 + " for software number " + defaultValue + ".");
			return text2;
		}

		private async Task<string> GetOverrideSoftwareNumberForLive(string defaultValue)
		{
			if (int.TryParse(defaultValue, out var result))
			{
				if (result == 433918)
				{
					Log.Trace("ModalityChangeService", "software number is 433918 (mind console). Returning NonConnectedTreadmill software number.");
					return 424110.ToString();
				}
				ConsoleSpecs consoleSpecs = null;
				try
				{
					consoleSpecs = await ConsoleSpecs.GetConsole(ifitApi, result);
				}
				catch (Exception exception)
				{
					Log.Trace("ModalityChangeService", "Software number API request failed.", exception);
				}
				string text = consoleSpecs?.EquipmentType ?? currentConsoleService?.GetCurrentConsoleType(ConsoleType.None).ToString();
				Log.Trace("ModalityChangeService", "Software number API request gives an equipment type of " + text + ".");
				string text2;
				if (HybridConsoleTypeOverride.IsNullOrWhitespace())
				{
					text2 = (IsConsoleTypeCompatibleWithLive(text) ? defaultValue : 424110.ToString());
					Log.Trace("ModalityChangeService", "On Live screen, no hybrid override. Using software number " + text2 + ".");
					return text2;
				}
				if (IsConsoleTypeCompatibleWithLive(HybridConsoleTypeOverride) && !HybridSoftwareNumberOverride.IsNullOrWhitespace())
				{
					Log.Trace("ModalityChangeService", "On Live screen with a compatible hybrid override. Using software number " + HybridSoftwareNumberOverride + ".");
					return HybridSoftwareNumberOverride;
				}
				text2 = (IsConsoleTypeCompatibleWithLive(text) ? defaultValue : 424110.ToString());
				Log.Trace("ModalityChangeService", "On Live screen with no hybrid override. Using software number " + text2 + " for default value " + defaultValue + ".");
				return text2;
			}
			Log.Trace("ModalityChangeService", "Couldn't parse software number " + defaultValue + ".");
			return defaultValue;
		}

		public ModalityChangeService(IStartWorkoutService startWorkoutService, ICurrentConsoleService currentConsoleService, IDialogPresenter dialogPresenter, IIfitApiService ifitApi, IDeviceInformation deviceInformation, IBleConsoleService bleConsoleService = null)
		{
			this.startWorkoutService = startWorkoutService;
			this.dialogPresenter = dialogPresenter;
			this.ifitApi = ifitApi;
			this.bleConsoleService = bleConsoleService;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
			overriddenSoftwareNumbersForLive = new Dictionary<string, string>();
		}

		public MockType GetMockTypeFromWebviewParams(IDictionary<string, string> parameters)
		{
			if (parameters.TryGetValue("softwareNumber", out var value) && int.TryParse(value, out var result))
			{
				return DashboardNonConnectedUtils.ConvertSoftwareNumberTypeToMockType(result);
			}
			Log.Trace("ModalityChangeService", $"WebviewDoConsoleTypeSwitch: Invalid parameter input: {parameters}");
			throw new ArgumentException($"WebviewDoConsoleTypeSwitch: Invalid parameter input: {parameters}");
		}

		public async Task<MockType> ChangeNonConnectedModality(MockType desiredConsoleType)
		{
			if (startWorkoutService.StartingWorkout || CurrentConsoleIs(desiredConsoleType))
			{
				throw new NotChangingModalityException();
			}
			if (CurrentDeviceIsCompatibleWith(desiredConsoleType))
			{
				throw new OverrideModalityChangeException(desiredConsoleType);
			}
			if (ShouldPromptUserForDisconnect())
			{
				throw new MustDisconnectCurrentDeviceException(desiredConsoleType);
			}
			return await ContinueAndConnectToMockConsole(desiredConsoleType);
		}

		public async Task<MockType> ContinueAndConnectToMockConsole(MockType desiredConsoleType, bool disconnectImmediate = false)
		{
			NonConnectedMockDevice nonConnectedMockDevice = await PerformConnectToMockConsole(desiredConsoleType, disconnectImmediate);
			if (bleConsoleService != null)
			{
				if (nonConnectedMockDevice == null || bleConsoleService?.Console == null || bleConsoleService?.CurrentDevice != nonConnectedMockDevice)
				{
					throw new ModalityChangeErroredException();
				}
			}
			else if (nonConnectedMockDevice == null)
			{
				throw new ModalityChangeErroredException();
			}
			bool flag = (bleConsoleService?.Console == null || bleConsoleService?.CurrentDevice != nonConnectedMockDevice) && !deviceInformation.IsHeadlessBikeVault;
			if (nonConnectedMockDevice == null || flag)
			{
				throw new ModalityChangeErroredException();
			}
			HybridConsoleOverride = null;
			return nonConnectedMockDevice.Type;
		}

		private async Task<NonConnectedMockDevice> PerformConnectToMockConsole(MockType consoleType, bool disconnectImmediate = false)
		{
			if (deviceInformation.IsHeadlessBikeVault)
			{
				return MockDeviceUtil.GetNonConnectedMockDevice(consoleType);
			}
			if (!disconnectImmediate)
			{
				await bleConsoleService.Disconnect(forgetDevice: true);
			}
			else
			{
				bleConsoleService.DisconnectImmediate(forgetDevice: true);
			}
			NonConnectedMockDevice device = MockDeviceUtil.GetNonConnectedMockDevice(consoleType);
			try
			{
				await bleConsoleService.Connect(device);
			}
			catch (Exception exception)
			{
				Log.Error("Connection", string.Format("Error connecting to {0} in {1}.{2}.", device.GetType(), "ModalityChangeService", "PerformConnectToMockConsole"), exception);
			}
			return device;
		}

		private bool ShouldPromptUserForDisconnect()
		{
			if (currentConsoleService.Console != null && !currentConsoleService.Console.IsNonconnectedConsole())
			{
				IBleConsoleService obj = bleConsoleService;
				if (obj != null && obj.IsConnectedToConsole)
				{
					goto IL_0065;
				}
			}
			IFitProDeviceConnection obj2 = currentConsoleService.Console?.Connection as IFitProDeviceConnection;
			if (obj2 == null || !obj2.IsReconnecting)
			{
				return false;
			}
			goto IL_0065;
			IL_0065:
			return true;
		}

		private bool CurrentConsoleIs(MockType desiredConsoleType)
		{
			if (HybridConsoleOverride != null)
			{
				return desiredConsoleType == DashboardNonConnectedUtils.ConvertConsoleTypeToMockType(HybridConsoleOverride.ConsoleInfo.MachineType);
			}
			if (deviceInformation.IsHeadlessBikeVault)
			{
				if (currentConsoleService.IsAttachedConsoleActive)
				{
					return desiredConsoleType == DashboardNonConnectedUtils.ConvertConsoleTypeToMockType(currentConsoleService.AttachedConsole.ConsoleInfo.MachineType);
				}
				return desiredConsoleType == DashboardNonConnectedUtils.ConvertConsoleTypeToMockType(currentConsoleService.Console.ConsoleInfo.MachineType);
			}
			return desiredConsoleType == DashboardNonConnectedUtils.GetMockTypeFromConsole(currentConsoleService);
		}

		private bool CurrentDeviceIsCompatibleWith(MockType consoleType)
		{
			if ((consoleType == MockType.Elliptical || consoleType == MockType.Bike) && currentConsoleService?.Console != null)
			{
				IFitnessConsole console = currentConsoleService.Console;
				if (console != null && console.IsHybridMachine())
				{
					return true;
				}
			}
			return false;
		}
	}
