	public class OneSignalService : IOneSignalService
	{
		private static OneSignalService _instance;

		private readonly IIfitApiService iFitApi;

		private readonly IWolfAnalytics WolfAnalytics;

		public static void Initialize()
		{
			_instance = new OneSignalService();
			Mvx.RegisterSingleton(_instance);
		}

		private OneSignalService()
		{
			if (Mvx.TryResolve<IIfitApiService>(out iFitApi) && Mvx.TryResolve<IWolfAnalytics>(out WolfAnalytics))
			{
				iFitApi.WhenCurrentUserIdChanged.Subscribe(OnUserChanged);
				iFitApi.WhenLoggingOut.Subscribe(OnLogOut);
				if (iFitApi.HasLoggedInUser)
				{
					OnUserChanged("");
				}
				else
				{
					SetUserAnonymous();
				}
			}
			else
			{
				Log.Error("OneSignal", "Could not initialize OneSignal service because a service was not found.");
			}
		}

		private void SetUserId(string id)
		{
			OneSignal.Default.SetExternalUserId(id);
		}

		private void SetUserAnonymous()
		{
			OneSignal.Default.SetExternalUserId(WolfAnalytics.AnonymousUserId);
		}

		private void OnUserChanged(string newUserId)
		{
			if (iFitApi.HasLoggedInUser)
			{
				SetUserId(iFitApi.CurrentlyAuthenticatedUserId);
			}
		}

		private void OnLogOut(Unit ignored)
		{
			Log.Debug("OneSignal", "Logged out");
			SetUserAnonymous();
		}
	}
