	public abstract class PersistentSettings
	{
		private const string Tag = "PersistentSettings";

		[JsonIgnore]
		protected IBlobCacheService BlobCacheService;

		[JsonIgnore]
		protected IBlobCacheFileManager BlobCacheFileManager;

		private bool finishedRestore;

		private SemaphoreSlim _settingValueUpdateLock = new SemaphoreSlim(1);

		protected abstract string Key { get; }

		protected SemaphoreSlim SettingValueUpdateLock => _settingValueUpdateLock;

		protected PersistentSettings(IBlobCacheService blobCacheService, IBlobCacheFileManager blobCacheFileManager)
		{
			BlobCacheService = blobCacheService;
			BlobCacheFileManager = blobCacheFileManager;
			finishedRestore = true;
		}

		[OnDeserialized]
		private void OnDeserialized(StreamingContext context)
		{
			finishedRestore = true;
		}

		protected virtual void Flush()
		{
			Task.Run((Func<Task>)FlushAsync);
		}

		protected virtual async Task FlushAsync()
		{
			_ = 1;
			try
			{
				await SettingValueUpdateLock.WaitAsync();
				if (finishedRestore && BlobCacheService != null)
				{
					await SerializeToCache();
				}
			}
			finally
			{
				SettingValueUpdateLock.Release();
			}
		}

		protected async Task SerializeToCache()
		{
			try
			{
				await BlobCacheService.Secure.InsertObject(Key, this);
			}
			catch (SQLiteException ex)
			{
				BlobCacheFileManager.LogCacheInformation();
				Log.Fatal("PersistentSettings", $"Caught a SQLiteException in SerializeToCache. Result: {ex.Result}, Message: {ex.Message}");
				if (ex.Message.Contains("malformed") || ex.Result == SQLite3.Result.Corrupt || ex.Result == SQLite3.Result.Full || ex.Result == SQLite3.Result.NonDBFile)
				{
					ReportWipeAndResetCache();
				}
				IFatalityService fatalityService = Mvx.Resolve<IFatalityService>();
				fatalityService.ReportFatalEvent(ex, Shire.Core.Resources.AppStrings.database_malformed_error);
			}
			catch (Exception exception)
			{
				Log.Error("PersistentSettings", "Unhandled exception in SerializeToCache() method", exception);
				throw;
			}
		}

		public void ReportWipeAndResetCache()
		{
			Log.Debug("PersistentSettings", "Malformed DB Error");
			BlobCacheFileManager.LogCacheInformation();
			BlobCacheFileManager.NukeSQLDB();
		}
	}
	public interface IPersonalTrainingSettings
	{
		bool ActivePulseEnabled { get; set; }

		bool SmartAdjustEnabled { get; set; }

		IObservable<UserSettings> UserSettingsRefreshed { get; }

		IObservable<bool> WhenActivePulseEnabledChanged { get; }

		void ListenForSmartAdjustEnabledChanges(IWorkoutFeatureService workoutFeatureService);

		void ListenForActivePulseEnabledChanges(IWorkoutFeatureService workoutFeatureService);

		void UpdateUserSettings(object source, ElapsedEventArgs e);

		Task RefreshUserSettings(bool force = true);
	}
	public class PersonalTrainingSettings : IPersonalTrainingSettings, IDisposable
	{
		private IDisposable smartAdjustEnabledChangedSub;

		private IDisposable activePulseEnabledChangedSub;

		private IDisposable activePulseModeChangedSub;

		private readonly SemaphoreSlim updateSettingsLock = new SemaphoreSlim(1, 1);

		private readonly Subject<bool> _whenActivePulseEnabledChanged = new Subject<bool>();

		private readonly Subject<UserSettings> _usersettingsRefreshed = new Subject<UserSettings>();

		private const string LogTag = "PersonalTrainingSettings";

		private readonly IIfitApiService ifitApiService;

		private System.Timers.Timer timer;

		private bool _activePulseEnabled;

		private bool _smartAdjustEnabled;

		public IObservable<bool> WhenActivePulseEnabledChanged => _whenActivePulseEnabledChanged;

		public IObservable<UserSettings> UserSettingsRefreshed => _usersettingsRefreshed;

		public bool ActivePulseEnabled
		{
			get
			{
				return _activePulseEnabled;
			}
			set
			{
				if (value != ActivePulseEnabled)
				{
					_activePulseEnabled = value;
					_whenActivePulseEnabledChanged.OnNext(value);
					ResetTimer();
				}
			}
		}

		public bool SmartAdjustEnabled
		{
			get
			{
				return _smartAdjustEnabled;
			}
			set
			{
				if (value != SmartAdjustEnabled)
				{
					_smartAdjustEnabled = value;
					ResetTimer();
				}
			}
		}

		public PersonalTrainingSettings(IIfitApiService ifitApiService)
		{
			this.ifitApiService = ifitApiService;
			SetupTimer();
			InitUserSettings();
		}

		private void SetupTimer()
		{
			timer = new System.Timers.Timer();
			timer.Interval = 500.0;
			timer.Elapsed += UpdateUserSettings;
			timer.AutoReset = false;
		}

		private void ResetTimer()
		{
			timer?.Stop();
			timer?.Start();
		}

		protected async Task InitUserSettings()
		{
			await RefreshUserSettings(force: false);
		}

		public async Task RefreshUserSettings(bool force = true)
		{
			try
			{
				User currentlyAuthenticatedUser = ifitApiService.CurrentlyAuthenticatedUser;
				if (currentlyAuthenticatedUser != null)
				{
					UserSettings userSettings = await currentlyAuthenticatedUser.GetSettings(ifitApiService, force);
					UpdateWithUserSettings(userSettings);
					_usersettingsRefreshed.OnNext(userSettings);
				}
			}
			catch (Exception ex)
			{
				Log.Error("PersonalTrainingSettings", "ERROR getting user settings: " + ex.Message, ex);
			}
		}

		protected void UpdateWithUserSettings(UserSettings userSettings)
		{
			_smartAdjustEnabled = userSettings?.SmartAdjust == true;
			_activePulseEnabled = userSettings?.ActivePulse == true;
		}

		public void UpdateUserSettings(object source, ElapsedEventArgs e)
		{
			Task.Run(async delegate
			{
				await updateSettingsLock.WaitAsync();
				try
				{
					User currentlyAuthenticatedUser = ifitApiService.CurrentlyAuthenticatedUser;
					if (currentlyAuthenticatedUser != null)
					{
						currentlyAuthenticatedUser.Settings.ActivePulse = ActivePulseEnabled;
						currentlyAuthenticatedUser.Settings.SmartAdjust = SmartAdjustEnabled;
						Log.Info("PersonalTrainingSettings", $"Saving Personal Training Settings with ActivePulse: {ActivePulseEnabled}, SmartAdjust: {SmartAdjustEnabled}");
						await currentlyAuthenticatedUser.UpdateSettings(ifitApiService);
					}
				}
				catch (Exception ex)
				{
					Log.Error("PersonalTrainingSettings", "ERROR getting user settings: " + ex.Message, ex);
				}
				finally
				{
					updateSettingsLock.Release();
				}
			});
		}

		public void ListenForActivePulseEnabledChanges(IWorkoutFeatureService workoutFeatureService)
		{
			activePulseModeChangedSub?.Dispose();
			activePulseModeChangedSub = workoutFeatureService.WhenActivePulseModeChanged.Subscribe(delegate(bool x)
			{
				ActivePulseEnabled = x;
			});
			activePulseEnabledChangedSub?.Dispose();
			activePulseEnabledChangedSub = WhenActivePulseEnabledChanged.Subscribe(delegate(bool activePulseEnabled)
			{
				if (activePulseEnabled && !_smartAdjustEnabled)
				{
					SmartAdjustEnabled = true;
				}
			});
		}

		public void ListenForSmartAdjustEnabledChanges(IWorkoutFeatureService workoutFeatureService)
		{
			smartAdjustEnabledChangedSub?.Dispose();
			smartAdjustEnabledChangedSub = workoutFeatureService.WhenSmartAdjustModeChanged.Subscribe(delegate(bool x)
			{
				SmartAdjustEnabled = x;
				if (!x)
				{
					ActivePulseEnabled = false;
				}
			});
		}

		public void Dispose()
		{
			Dispose(dispose: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool dispose)
		{
			if (dispose)
			{
				activePulseEnabledChangedSub?.Dispose();
				activePulseEnabledChangedSub = null;
				smartAdjustEnabledChangedSub?.Dispose();
				smartAdjustEnabledChangedSub = null;
				activePulseModeChangedSub?.Dispose();
				activePulseModeChangedSub = null;
				timer?.Close();
			}
		}
	}
	public interface IPlanetFitnessService
	{
		bool ShouldNavigateToUpgradePath();

		bool ShouldNavigateToUpgradePath(MockType mockType);

		bool AllowAccessToAthenaeum();
	}
	public class PlanetFitnessService : IPlanetFitnessService
	{
		private readonly IIfitApiService apiService;

		private readonly IFeatureFlagManager featureFlagManager;

		public PlanetFitnessService(IFeatureFlagManager featureFlagManager, IIfitApiService apiService)
		{
			this.featureFlagManager = featureFlagManager;
			this.apiService = apiService;
		}

		public bool ShouldNavigateToUpgradePath(MockType mockType)
		{
			if (mockType == MockType.Bike || mockType == MockType.Elliptical || mockType == MockType.Rower)
			{
				return ShouldNavigateToUpgradePath();
			}
			return false;
		}

		public bool ShouldNavigateToUpgradePath()
		{
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.IfitLite))
			{
				return false;
			}
			bool valueOrDefault = apiService?.CurrentlyAuthenticatedUser?.Premium == true;
			bool valueOrDefault2 = apiService?.CurrentlyAuthenticatedUser?.IsPlanetFitnessUser == true;
			return valueOrDefault && valueOrDefault2;
		}

		public bool AllowAccessToAthenaeum()
		{
			return featureFlagManager.IsFeatureEnabled(FeatureFlags.PlanetFitnessCanAccessAthenaeum);
		}
	}
	public interface IPreferenceResolver
	{
		bool IsMetric { get; set; }

		IObservable<bool> WhenIsMetricChanged { get; }

		IObservable<double> WhenWeightChanged { get; }

		double GuestWeight { get; set; }

		Task<double> UserWeightKgs();

		Task<double> UserHeightMeters();

		Task<double> UserAge();

