	public class PreferenceResolver : IPreferenceResolver
	{
		private readonly IClubLocalSettings clubLocalSettings;

		private readonly IWebviewSettings webviewSettings;

		private readonly IIfitApiService ifitApi;

		private readonly IBlobCacheService cacheService;

		private TimeSpan GetMeTimeout = TimeSpan.FromSeconds(5.0);

		protected Subject<bool> whenIsMetricChanged = new Subject<bool>();

		private bool _isMetric;

		protected Subject<double> whenWeightChanged = new Subject<double>();

		private double _guestWeight = 83.91;

		public IObservable<bool> WhenIsMetricChanged => whenIsMetricChanged;

		public bool IsMetric
		{
			get
			{
				return _isMetric;
			}
			set
			{
				if (IsMetric != value)
				{
					_isMetric = value;
					whenIsMetricChanged.OnNext(IsMetric);
					cacheService.Flush(_isMetric, "_isMetric", "PreferenceResolver");
				}
			}
		}

		public IObservable<double> WhenWeightChanged => whenWeightChanged;

		public double GuestWeight
		{
			get
			{
				return _guestWeight;
			}
			set
			{
				if (_guestWeight != value)
				{
					_guestWeight = value;
					whenWeightChanged.OnNext(_guestWeight);
				}
			}
		}

		public PreferenceResolver(IClubLocalSettings clubLocalSettings, IBlobCacheService cacheService, IWebviewSettings webviewSettings, IIfitApiService ifitApi)
		{
			this.clubLocalSettings = clubLocalSettings;
			this.cacheService = cacheService;
			this.webviewSettings = webviewSettings;
			this.ifitApi = ifitApi;
		}

		private async Task<IPreferenceResolver> InitializeAsync()
		{
			_isMetric = await cacheService.GetFromCache("_isMetric", "PreferenceResolver", "", temp: false, defaultValue: false);
			return this;
		}

		public static Task<IPreferenceResolver> CreateAsync(IClubLocalSettings clubLocalSettings, IBlobCacheService cacheService, IWebviewSettings webviewSettings, IIfitApiService ifitApi)
		{
			PreferenceResolver preferenceResolver = new PreferenceResolver(clubLocalSettings, cacheService, webviewSettings, ifitApi);
			return preferenceResolver.InitializeAsync();
		}

		public void ResetIsMetric()
		{
			IsMetric = clubLocalSettings.ClubDefaultIsMetric;
		}

		public void ResetGuestWeight()
		{
			GuestWeight = 83.91;
		}

		public async Task<bool> GetIsMetric(User user = null, bool forceUpdate = false)
		{
			try
			{
				if (user != null && !forceUpdate)
				{
					IsMetric = user.IsMetric;
				}
				else if (ifitApi.HasLoggedInUser)
				{
					IsMetric = await GetUserIsMetric(forceUpdate).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception exception)
			{
				Log.Error("PreferenceResolver", "Error getting the user's IsMetric setting", exception);
			}
			return IsMetric;
		}

		protected virtual async Task<bool> GetUserIsMetric(bool forceUpdate)
		{
			return (await GetUser(forceUpdate, populateSettings: true).ConfigureAwait(continueOnCapturedContext: false))?.IsMetric ?? false;
		}

		protected virtual async Task<User> GetUser(bool forceUpdate, bool populateSettings = false)
		{
			User user = ifitApi.CurrentlyAuthenticatedUser;
			try
			{
				user = await User.GetMe(ifitApi, populate: true, forceUpdate).TimeoutAfter(GetMeTimeout);
				if (user != null && user.Settings == null && populateSettings)
				{
					await user.GetSettings(ifitApi, forceUpdate);
				}
			}
			catch (Exception exception)
			{
				Log.Error("PreferenceResolver", "Error getting the user from API", exception);
			}
			return user;
		}

		public async Task<double> UserWeightKgs()
		{
			if (!ifitApi.HasLoggedInUser)
			{
				return 83.91;
			}
			try
			{
				return (await GetUser(forceUpdate: false).ConfigureAwait(continueOnCapturedContext: false))?.Weight ?? 83.91;
			}
			catch (Exception)
			{
				return 83.91;
			}
		}

		public async Task<double> UserHeightMeters()
		{
			if (!ifitApi.HasLoggedInUser)
			{
				return 1.778;
			}
			try
			{
				return (await GetUser(forceUpdate: false).ConfigureAwait(continueOnCapturedContext: false))?.Height ?? 1.778;
			}
			catch (Exception)
			{
				return 1.778;
			}
		}

		public async Task<double> UserAge()
		{
			if (!ifitApi.HasLoggedInUser)
			{
				return 35.0;
			}
			try
			{
				return ((double?)(await GetUser(forceUpdate: false).ConfigureAwait(continueOnCapturedContext: false))?.Age) ?? 35.0;
			}
			catch (Exception)
			{
				return 35.0;
			}
		}

		public async Task<bool?> UserMale()
		{
			if (!ifitApi.HasLoggedInUser)
			{
				return null;
			}
			try
			{
				return (await GetUser(forceUpdate: false).ConfigureAwait(continueOnCapturedContext: false)).Gender.ToLowerInvariant().Equals("male");
			}
			catch (Exception)
			{
				return null;
			}
		}

		protected virtual async Task SetUserIsMetric(bool isMetric)
		{
			User user = await GetUser(forceUpdate: false, populateSettings: true).ConfigureAwait(continueOnCapturedContext: false);
			if (user.IsMetric != isMetric)
			{
				user.IsMetric = isMetric;
				await UpdateUserSettings(user).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public async Task SetIsMetric(bool isMetric, User user = null)
		{
			if (IsMetric != isMetric)
			{
				IsMetric = isMetric;
				webviewSettings.ReloadDashboard = true;
				webviewSettings.ReloadStatData = true;
				webviewSettings.ReloadFeedData = true;
				webviewSettings.ReloadLibraryData = true;
			}
			try
			{
				if (user != null && user.IsMetric != isMetric)
				{
					user.IsMetric = isMetric;
					await UpdateUserSettings(user).ConfigureAwait(continueOnCapturedContext: false);
				}
				else if (ifitApi.HasLoggedInUser)
				{
					await SetUserIsMetric(isMetric).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception exception)
			{
				Log.Error("PreferenceResolver", "Error changing the user's IsMetric setting", exception);
			}
		}

		public Task ToggleUnitOfMeasurement(User user = null)
		{
			return SetIsMetric(!IsMetric, user);
		}

		protected virtual Task UpdateUserSettings(User user)
		{
			return user.UpdateSettings(ifitApi);
		}
	}
	public interface IProgramWorkoutManager
	{
		ProgramData ProgramForName(string name);
	}
	public class ProgramData
	{
		public string Name { get; }

		public IList<string> WorkoutIds { get; }

		public ProgramData(string name, IList<string> workoutIds)
		{
			Name = name;
			WorkoutIds = workoutIds;
		}
	}
	public class ProgramWorkoutManager : IProgramWorkoutManager, IDisposable
	{
		private readonly IDisposable consoleWorkoutsLoadedSub;

		protected IList<ProgramData> Programs { get; private set; }

		public ProgramWorkoutManager(IDataFetcher dataFetcher)
		{
			consoleWorkoutsLoadedSub = dataFetcher.WhenConsoleWorkoutsLoaded.Subscribe(HandleConsoleWorkoutsLoaded);
		}

		public ProgramData ProgramForName(string name)
		{
			foreach (ProgramData program in Programs)
			{
				if (string.Equals(program.Name, name, StringComparison.OrdinalIgnoreCase))
				{
					return program;
				}
			}
			return null;
		}

		protected virtual void HandleConsoleWorkoutsLoaded(ConsoleWorkouts workouts)
		{
			Programs = new List<ProgramData>();
			if (workouts == null)
			{
				return;
			}
			foreach (ConsoleWorkouts.Group group in workouts.Groups)
			{
				if (!string.IsNullOrEmpty(group.Name) && group.Name.ToLower().Contains("program"))
				{
					Programs.Add(ProgramDataFromConsoleWorkout(group));
				}
			}
		}

		private ProgramData ProgramDataFromConsoleWorkout(ConsoleWorkouts.Group workout)
		{
			return new ProgramData(workout.Name, workout.WorkoutIds);
		}

		public void Dispose()
		{
			consoleWorkoutsLoadedSub?.Dispose();
		}
	}
	public class RemainingVideoWorkoutEstimates : RemainingWorkoutEstimates
	{
		private readonly IVideoSyncService videoSyncService;

		public RemainingVideoWorkoutEstimates(IVideoSyncService videoSyncService, IFitnessConsole console, double userWeightKgs, double userHeightMeters, double userAge, bool userMale, Workout mainWorkout, Workout warmup = null, Workout cooldown = null)
			: base(console, userWeightKgs, userHeightMeters, userAge, userMale, mainWorkout, warmup, cooldown)
		{
			this.videoSyncService = videoSyncService;
		}

		protected override Task Estimate()
		{
			if (targetWorkout == mainWorkout)
			{
				videoSyncService?.UpdateGoalTime(targetWorkout, console);
			}
			return base.Estimate();
		}

		protected override double GetCurrentAt(Workout workout, IFitnessConsole fitProConsole)
		{
			if (workout == mainWorkout && videoSyncService != null)
			{
				return videoSyncService.LastVideoPositionSeconds;
			}
			return base.GetCurrentAt(workout, fitProConsole);
		}

		protected override double GetTargetRemaining(double targetValue, double currentAt)
		{
			if (targetWorkout == mainWorkout)
			{
				return Math.Max(0.0, mainWorkout.TargetValue - currentAt);
			}
			return base.GetTargetRemaining(targetValue, currentAt);
		}
	}
