	public interface IScreenSaverHandler
	{
		bool IsScreenSaverVisible { get; }

		IObservable<bool> WhenIsScreenSaverVisibleChanged { get; }

		void Touched();
	}
	public class ScreenSaverHandler : BaseTouchTimeoutService, IScreenSaverHandler
	{
		private const string LogTag = "ScreenSaverHandler";

		private bool _isScreenSaverVisible;

		private readonly Subject<bool> _whenIsScreenSaverVisibleChanged = new Subject<bool>();

		private readonly IMvxMainThreadDispatcher dispatcher;

		private readonly IDialogPresenter presenter;

		private readonly IScreenBrightness screenBrightness;

		private readonly IAppLifecycleService lifecycleService;

		private readonly ICurrentConsoleService currentConsoleService;

		private IDisposable inclineSubscription;

		protected override double TimeoutSeconds => TimeSpan.FromMinutes(5.0).TotalSeconds;

		private double ExcessiveTimeoutTimeChange => TimeSpan.FromDays(1.0).TotalSeconds;

		public bool IsScreenSaverVisible
		{
			get
			{
				return _isScreenSaverVisible;
			}
			private set
			{
				if (_isScreenSaverVisible != value)
				{
					_isScreenSaverVisible = value;
					_whenIsScreenSaverVisibleChanged.OnNext(_isScreenSaverVisible);
				}
			}
		}

		public IObservable<bool> WhenIsScreenSaverVisibleChanged => _whenIsScreenSaverVisibleChanged;

		private bool InDemoMode
		{
			get
			{
				if (Mvx.TryResolve<IDemoModeService>(out var service))
				{
					return service.IsInDemoMode;
				}
				return false;
			}
		}

		public ScreenSaverHandler(ITouchMonitor touchMonitor, IMvxMainThreadDispatcher dispatcher, IDialogPresenter presenter, IScreenBrightness screenBrightness, IAppLifecycleService lifecycleService, ICurrentConsoleService currentConsoleService)
			: base(touchMonitor)
		{
			this.dispatcher = dispatcher;
			this.presenter = presenter;
			this.screenBrightness = screenBrightness;
			this.lifecycleService = lifecycleService;
			this.currentConsoleService = currentConsoleService;
			touchMonitor.Touched = (EventHandler)Delegate.Remove(touchMonitor.Touched, new EventHandler(OnTouched));
			touchMonitor.Touched = (EventHandler)Delegate.Combine(touchMonitor.Touched, new EventHandler(OnTouched));
			touchMonitor.ConsoleStateChanged = (EventHandler<StateChangeEventArgs>)Delegate.Remove(touchMonitor.ConsoleStateChanged, new EventHandler<StateChangeEventArgs>(OnConsoleStateChanged));
			touchMonitor.ConsoleStateChanged = (EventHandler<StateChangeEventArgs>)Delegate.Combine(touchMonitor.ConsoleStateChanged, new EventHandler<StateChangeEventArgs>(OnConsoleStateChanged));
			lifecycleService.AppStateChanged -= LifecycleServiceOnAppStateChanged;
			lifecycleService.AppStateChanged += LifecycleServiceOnAppStateChanged;
		}

		private void LifecycleServiceOnAppStateChanged(object sender, AppStateEventArgs e)
		{
			SetActive(e.CurrentState == AppLifecycleService.AppState.Foreground);
		}

		protected void SetActive(bool isActive)
		{
			Log.Trace("ScreenSaverHandler", "SetActive has been called");
			ITouchMonitor touchMonitor = TouchMonitor;
			touchMonitor.TestTimeoutElapsed = (EventHandler)Delegate.Remove(touchMonitor.TestTimeoutElapsed, new EventHandler(OnTestTimeoutElapsed));
			if (isActive)
			{
				Log.Trace("Navigation", "Screen Saver Handler starting.");
				ITouchMonitor touchMonitor2 = TouchMonitor;
				touchMonitor2.TestTimeoutElapsed = (EventHandler)Delegate.Combine(touchMonitor2.TestTimeoutElapsed, new EventHandler(OnTestTimeoutElapsed));
			}
		}

		public void Touched()
		{
			Log.Trace("ScreenSaverHandler", "The screen has been touched");
			OnTouched(this, EventArgs.Empty);
		}

		private void OnTouched(object sender, EventArgs e)
		{
			IsScreenSaverVisible = false;
			AdjustBrightness(dimmingScreen: false);
			inclineSubscription?.Dispose();
			inclineSubscription = null;
		}

		private void OnConsoleStateChanged(object sender, StateChangeEventArgs stateChangeEventArgs)
		{
			Log.Trace("ScreenSaverHandler", "Console State has changed");
			if (screenBrightness.IsDimmed)
			{
				ConsoleState current = stateChangeEventArgs.StateChange.Current;
				if (current == ConsoleState.Workout || current == ConsoleState.WarmUp)
				{
					AdjustBrightness(dimmingScreen: false);
				}
			}
		}

		protected override void OnTestTimeoutElapsed(object sender, EventArgs e)
		{
			ConsoleState consoleState = currentConsoleService.ActiveConsole?.LatestBasicInfo?.CurrentState ?? ConsoleState.Workout;
			if (consoleState == ConsoleState.Paused || consoleState == ConsoleState.CoolDown)
			{
				TouchMonitor.UpdateLastObservedTouch();
			}
			else
			{
				base.OnTestTimeoutElapsed(sender, e);
			}
		}

		protected override void OnTimeoutSinceTouchDidElapse()
		{
			ConsoleState consoleState = currentConsoleService.Console?.LatestBasicInfo?.CurrentState ?? ConsoleState.Workout;
			Log.Trace("ScreenSaverHandler", $"Screen is dimmed : {screenBrightness.IsDimmed}, SSVisible: {IsScreenSaverVisible}, InDemoMode: {InDemoMode}");
			if (screenBrightness.IsDimmed || IsScreenSaverVisible || InDemoMode)
			{
				return;
			}
			switch (consoleState)
			{
			case ConsoleState.Workout:
			case ConsoleState.WarmUp:
			case ConsoleState.CoolDown:
			case ConsoleState.PauseOverride:
				return;
			case ConsoleState.SafetyKeyRemoved:
				if (presenter.IsDialogShown("SafetyKeyDialogViewModel"))
				{
					AdjustBrightness(dimmingScreen: true);
					return;
				}
				break;
			case ConsoleState.Demo:
			case ConsoleState.Error:
				AdjustBrightness(dimmingScreen: true);
				return;
			}
			if (Math.Abs(TouchMonitor.SecondsSinceLastTouch) > ExcessiveTimeoutTimeChange)
			{
				Log.Trace("ScreenSaverHandler", $"System time change detected {TouchMonitor.SecondsSinceLastTouch} seconds elapsed, not showing screen saver and updating last observed touch");
				TouchMonitor.UpdateLastObservedTouch();
				return;
			}
			if (Mvx.TryResolve<IDialogPresenter>(out var service) && service.IsDialogShown<SimpleConfirmationDialogViewModel>())
			{
				Log.Trace("ScreenSaverHandler", "Hiding Poor Internet Connection Message confirmation dialog");
				BaseViewModel.HideSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.poor_internet_connection_message);
			}
			if (presenter.IsDialogShown("ShopQRCodeViewModel"))
			{
				presenter.CurrentDialogViewModel<ShopQRCodeViewModel>().CloseViewModel.SafeExecute();
			}
			Log.Trace("ScreenSaverHandler", "Attempting to show screen saver dialog");
			dispatcher.RequestMainThreadAction(delegate
			{
				presenter.ShowDialog(typeof(ScreenSaverDialogViewModel).FullName);
			});
			IsScreenSaverVisible = true;
			AdjustBrightness(dimmingScreen: true);
			if (Mvx.TryResolve<IGradeFacade>(out var gradeFacade))
			{
				double originalIncline = gradeFacade.GetMostRecentGrade();
				inclineSubscription?.Dispose();
				inclineSubscription = (from incline in gradeFacade.ObserveGradeChanges()
					where IsScreenSaverVisible
					where Math.Abs(incline.Current - originalIncline) > 0.001
					select incline).Subscribe(delegate
				{
					gradeFacade.SetGrade(originalIncline);
				});
			}
			Log.Trace("ScreenSaverHandler", $"IsSSVisible: {IsScreenSaverVisible}");
		}

		private void AdjustBrightness(bool dimmingScreen)
		{
			if (dimmingScreen && InDemoMode)
			{
				Log.Trace("ScreenSaverHandler", "Not dimming screen while in Demo Mode.");
			}
			else
			{
				AdjustBrightnessAsync(dimmingScreen);
			}
		}

		private async Task AdjustBrightnessAsync(bool dimmingScreen)
		{
			if (dimmingScreen)
			{
				Log.Trace("ScreenSaverHandler", "Dimming Screen");
				await screenBrightness.SetBrightness(0.1f);
				screenBrightness.IsDimmed = true;
				Log.Trace("ScreenSaverHandler", $"Screen is dimmed: {screenBrightness.IsDimmed}");
				return;
			}
			TouchMonitor.UpdateLastObservedTouch();
			float brightness = 1f;
			try
			{
				brightness = await screenBrightness.GetSavedBrightness();
			}
			catch (Exception exception)
			{
				Log.Error("Ipc", "Unable to get saved brightness", exception);
			}
			await screenBrightness.SetBrightness(brightness);
			screenBrightness.IsDimmed = false;
		}
	}
	public enum SecondaryOperationResult
	{
		NoOp,
		InviteSent,
		ErrorSendingInvite,
		SecondaryRemoved,
		ErrorRemovingSecondary,
		ErrorInviteInvalidEmailAddress,
		ErrorInviteAlreadyLinked
	}
	public interface ISecondaryUsersService
	{
		IObservable<SecondaryOperationResult> SecondaryOpStatus { get; }

		Task<SecondaryUserListResult> RetrieveUsers(User currentUser);

		Task InviteAsSecondaryUser(string inviteEmailUsername);

		Task RemoveUserAsSecondary(string secondaryUserId);

		Task RevokeSecondaryInvite(string secondaryUserId);

		Task<IList<User>> GetPendingInvitations(string primaryUserId);

		Task<bool> IsAllAuthenticatedUsersLinked();

		Task<IList<User>> GetAllLinkedUsers(string userId);
	}
	public class SecondaryUsersService : ISecondaryUsersService
	{
		public const int MaxAllowedCoachPlusSecondaryUsers = 5;

		private readonly IIfitApiService ifitApi;

		private readonly IBranchService branchService;

		private readonly Subject<SecondaryOperationResult> _opStatus = new Subject<SecondaryOperationResult>();

		public IObservable<SecondaryOperationResult> SecondaryOpStatus => _opStatus;

		public SecondaryUsersService(IIfitApiService ifitApi, IBranchService branchService = null)
		{
			this.ifitApi = ifitApi;
			this.branchService = branchService;
		}

		public async Task InviteAsSecondaryUser(string inviteEmailUsername)
		{
			if (inviteEmailUsername.IsValidEmail())
			{
				switch (await User.InviteSecondaryUser(ifitApi, ifitApi.CurrentlyAuthenticatedUserId, inviteEmailUsername, new UserInvite()))
				{
				case HttpStatusCode.OK:
					_opStatus.OnNext(SecondaryOperationResult.InviteSent);
					break;
				case HttpStatusCode.Conflict:
					_opStatus.OnNext(SecondaryOperationResult.ErrorInviteAlreadyLinked);
					break;
				default:
					_opStatus.OnNext(SecondaryOperationResult.ErrorSendingInvite);
					break;
				}
			}
			else
			{
				_opStatus.OnNext(SecondaryOperationResult.ErrorInviteInvalidEmailAddress);
			}
		}

		public async Task RemoveUserAsSecondary(string secondaryUserId)
		{
			if (await User.RemoveSecondary(ifitApi, ifitApi.CurrentlyAuthenticatedUserId, secondaryUserId))
			{
				_opStatus.OnNext(SecondaryOperationResult.SecondaryRemoved);
			}
			else
			{
				_opStatus.OnNext(SecondaryOperationResult.ErrorRemovingSecondary);
			}
		}

		public async Task RevokeSecondaryInvite(string secondaryUserId)
		{
			if (await User.RevokeSecondariyInvite(ifitApi, ifitApi.CurrentlyAuthenticatedUserId, secondaryUserId))
			{
				_opStatus.OnNext(SecondaryOperationResult.SecondaryRemoved);
			}
			else
			{
				_opStatus.OnNext(SecondaryOperationResult.ErrorRemovingSecondary);
			}
		}

		public async Task<SecondaryUserListResult> RetrieveUsers(User currentUser)
		{
			if (currentUser == null)
			{
				return new SecondaryUserListResult();
			}
			SecondaryUserListResult result = new SecondaryUserListResult();
			UserInvitedUser userInvitedUser = await GetPrimary(currentUser.Id);
			if (userInvitedUser == null)
			{
				List<User> users = new List<User> { currentUser };
				List<User> list = users;
				list.AddRange(await GetSecondaryUsers(currentUser.Id));
				result.UserList = users;
				return result;
			}
			if (string.IsNullOrEmpty(userInvitedUser.User))
			{
				result.UserList = new List<User> { currentUser };
				return result;
			}
			result.IsSecondary = true;
			User item = await FetchUser(userInvitedUser.User);
			result.UserList = new List<User> { currentUser, item };
			return result;
		}

		public async Task<IList<User>> GetPendingInvitations(string primaryUserId)
		{
			return await GetUsers(User.GetInvites, primaryUserId);
		}

		private async Task<IList<User>> GetSecondaryUsers(string primaryId)
		{
			List<User> list = (await GetUsers(User.GetSecondaries, primaryId)).Where((User user) => user != null).ToList();
			list.ForEach(delegate(User user)
			{
				user.IsSecondary = true;
			});
			return list;
		}

		private async Task<IList<User>> GetUsers(Func<IIfitApiService, string, Task<List<UserInvitedUser>>> invitedUserGetter, string primaryId)
		{
			List<User> users = new List<User>();
			List<Task<User>> userTasks = new List<Task<User>>();
			try
			{
				(from x in await invitedUserGetter(ifitApi, primaryId)
					orderby x.Date
					select x.User into x
					where !primaryId.Equals(x)
					select x).ForEach(delegate(string x)
				{
					userTasks.Add(FetchUser(x));
				});
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Unable to get Secondary Users for primary [user: " + primaryId + "].  Error => " + ex.Message);
			}
			await Task.WhenAll(userTasks);
			userTasks.Select((Task<User> x) => x.Result).ForEach(delegate(User x)
			{
				users.Add(x);
			});
			return users;
		}

		private async Task<User> FetchUser(string id)
		{
			if (id.IsNullOrWhitespace())
			{
				return null;
			}
			try
			{
				return await User.Get(ifitApi, id);
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Unable to get user with id " + id + ".  Error => " + ex.Message);
			}
			return null;
		}

		private async Task<UserInvitedUser> GetPrimary(string currentUserId)
		{
			UserInvitedUser user = null;
			try
			{
				user = await User.GetPrimary(ifitApi, currentUserId);
			}
			catch (ApiException ex)
			{
				if (ex.StatusCode != HttpStatusCode.NotFound)
				{
					Log.Error("Api", $"User id: {currentUserId} returned status {ex.StatusCode}");
				}
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Problem when calling User.GetPrimary with id " + currentUserId, exception);
			}
			return user;
		}

		public async Task<bool> IsAllAuthenticatedUsersLinked()
		{
			if (ifitApi?.AuthenticatedUsers == null || ifitApi.AuthenticatedUsers.Count == 0 || ifitApi.CurrentlyAuthenticatedUser == null)
			{
				return false;
			}
			List<User> authenticatedUsers = ifitApi.AuthenticatedUsers;
			List<string> usersIds = (await GetAllLinkedUsers(ifitApi.CurrentlyAuthenticatedUser.Id)).Select((User user) => user.Id).ToList();
			return authenticatedUsers.All((User user) => usersIds.Contains(user.Id));
		}

		public async Task<IList<User>> GetAllLinkedUsers(string userId)
		{
			List<User> users = new List<User>();
			List<Task<User>> userTasks = new List<Task<User>>();
			Task<UserInvitedUser> primaryUserTask = GetPrimary(userId);
			Task<List<string>> userIdsTask = User.GetAllLinkedUsersIds(ifitApi, userId);
			try
			{
				await Task.WhenAll(primaryUserTask, userIdsTask);
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Unable to get Primary or All Linked Users Ids for user [userId: " + userId + "]. Error => " + ex.Message);
				return users;
			}
			try
			{
				(await userIdsTask).ForEach(delegate(string x)
				{
					userTasks.Add(FetchUser(x));
				});
			}
			catch (Exception ex2)
			{
				Log.Error("Api", "Unable to get Linked Users for user [userId: " + userId + "].  Error => " + ex2.Message);
			}
			await Task.WhenAll(userTasks);
			(from x in userTasks
				where x?.Result != null
				select x.Result).ForEach(delegate(User x)
			{
				x.IsSecondary = x.Id != primaryUserTask.Result?.User;
				users.Add(x);
			});
			return users;
		}
	}
