	public class SetUnitsService : BaseWebViewBehaviorProvider, ISetUnitsService
	{
		private readonly IPreferenceResolver preferenceResolver;

		private readonly IClubLocalSettings clubLocalSettings;

		private readonly IIfitApiService api;

		public const string NativeMethodSetUnits = "SetUnits";

		public const string IsMetricVariableName = "is_metric";

		public const string IsClubOwnerSettingsVariableName = "is_club_owner_settings";

		public override string BehaviorName => "SetUnits";

		public SetUnitsService(IPreferenceResolver preferenceResolver, IClubLocalSettings clubLocalSettings, IIfitApiService api)
		{
			this.preferenceResolver = preferenceResolver;
			this.clubLocalSettings = clubLocalSettings;
			this.api = api;
