		public async Task SetUnits(bool isMetric, bool isClubOwner = false)
		{
			if (isClubOwner)
			{
				clubLocalSettings.ClubDefaultIsMetric = isMetric;
			}
			else if (!api.HasLoggedInUser)
			{
				preferenceResolver.IsMetric = isMetric;
			}
			else
