		public override async Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			if (parameters.ContainsKey("is_metric") && bool.TryParse(parameters["is_metric"], out var result))
			{
				bool isClubOwner = false;
				if (parameters.ContainsKey("is_club_owner_settings") && bool.TryParse(parameters["is_club_owner_settings"], out var result2))
				{
					isClubOwner = result2;
				}
				await SetUnits(result, isClubOwner);
			}
