	public class StartManualWorkoutService : BaseWebViewBehaviorProvider, IStartManualWorkoutService
	{
		public const string NativeMethodStartManualWorkout = "StartManualWorkout";

		private readonly ILocalSettings localSettings;

		private readonly IStartWorkoutService startWorkoutService;

		private readonly IWebviewHolderFactory webviewHolderFactory;

		private readonly IDialogPresenter dialogPresenter;

		private readonly ICurrentConsoleService currentConsoleService;

		public override string BehaviorName => "StartManualWorkout";

		public StartManualWorkoutService(ILocalSettings localSettings, IStartWorkoutService startWorkoutService, IWebviewHolderFactory webviewHolderFactory, IDialogPresenter dialogPresenter, ICurrentConsoleService currentConsoleService)
		{
			this.startWorkoutService = startWorkoutService;
			this.webviewHolderFactory = webviewHolderFactory;
			this.dialogPresenter = dialogPresenter;
			this.currentConsoleService = currentConsoleService;
		}

		public override async Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			AnalyticsSource analyticsSource = new AnalyticsSource(WorkoutSource.Dashboard);
			if (parameters.ContainsKey("workoutSource"))
			{
				try
				{
					string value = parameters["workoutSource"];
					WorkoutSource source = (WorkoutSource)Enum.Parse(typeof(WorkoutSource), value);
					analyticsSource = new AnalyticsSource(source);
				}
				catch (ArgumentException exception)
				{
					Log.Error("Workout", "Could not parse workoutSource to WorkoutSource enum.", exception);
				}
			}
			else
			{
				Log.Trace("Workout", "workoutSource not included in webview parameters.");
			}
			await StartManualWorkout(context.WaitForConsoleReady, context.CloseViewModel, analyticsSource);
		}

		public async Task StartManualWorkout(Func<string, IObservable<StateChange>, Task<ProgressDialogResult>> WaitForConsoleReady, IMvxCommand CloseViewModel, AnalyticsSource analyticsSource = null)
		{
			if (analyticsSource == null)
			{
				analyticsSource = new AnalyticsSource(WorkoutSource.Dashboard);
			}
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.ActiveConsole?.LatestBasicInfo?.CurrentState == ConsoleState.SafetyKeyRemoved)
			{
				ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(string.Empty, Wolf.Core.Resources.AppStrings.safety_key_begin_workout, null, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper(), OnConfirmActionTiming.AfterClose);
				dialogPresenter.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, arbitraryData);
			}
			else if (await startWorkoutService.DoStartManualWorkout(WaitForConsoleReady, analyticsSource))
			{
				webviewHolderFactory.WebviewHolderStore.FlushAll();
				CloseViewModel.Execute();
			}
		}
	}
