	public class StartWorkoutService : IStartWorkoutService, IDisposable
	{
		public const int StartingWorkoutTimeoutMs = 15000;

		private const int MinimumRpmToStartCyclicalManualWorkout = 5;

		private const int CyclicalManualWorkoutStartDelay = 5;

		private readonly IPreferenceResolver preferenceResolver;

		private readonly IWolfTrackingService trackingService;

		private readonly IBleRadioStatusService bleRadioStatusService;

		private readonly IBleConsoleService bleConsoleService;

		private readonly IEquipmentlessConsoleService equipmentlessConsoleService;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IDeviceInformation deviceInformation;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IMockLiveWorkoutService mockLiveWorkoutService;

		private IDisposable maintainRpmToStartManualWorkoutSub;

		private IDisposable startingWorkoutTimeoutSub;

		private readonly Subject<object> _whenWorkoutStartFailed = new Subject<object>();

		private readonly Subject<StartingWorkoutParams> _whenWorkoutStarted = new Subject<StartingWorkoutParams>();

		private readonly Subject<object> _whenPrepareWorkoutFailed = new Subject<object>();

		private readonly Subject<bool> _whenWorkoutIncompatible = new Subject<bool>();

		private readonly Subject<object> _whenUSBError = new Subject<object>();

		private readonly Subject<object> _whenConsoleNotConnected = new Subject<object>();

		private readonly Subject<object> _whenNonconnectedConsoleStartingManualWorkout = new Subject<object>();

		public IObservable<object> WhenWorkoutStartFailed => _whenWorkoutStartFailed?.AsObservable();

		public IObservable<StartingWorkoutParams> WhenWorkoutStarted => _whenWorkoutStarted?.AsObservable();

		public IObservable<object> WhenPrepareWorkoutFailed => _whenPrepareWorkoutFailed?.AsObservable();

		public IObservable<bool> WhenWorkoutIncompatible => _whenWorkoutIncompatible?.AsObservable();

		public IObservable<object> WhenUSBError => _whenUSBError?.AsObservable();

		public IObservable<object> WhenConsoleNotConnected => _whenConsoleNotConnected?.AsObservable();

		public IObservable<object> WhenNonconnectedConsoleStartingManualWorkout => _whenNonconnectedConsoleStartingManualWorkout?.AsObservable();

		public bool StartingWorkout { get; set; }

		public bool IsBuiltInDevice => deviceInformation.IsBuiltIn;

		public StartWorkoutService(ILocalSettings localSettings, IPreferenceResolver preferenceResolver, IEquipmentlessConsoleService equipmentlessConsoleService, IWolfTrackingService trackingService, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IFeatureFlagManager featureFlagManager, IBleRadioStatusService bleRadioStatusService = null, IBleConsoleService bleConsoleService = null, IMockLiveWorkoutService mockLiveWorkoutService = null)
		{
			this.preferenceResolver = preferenceResolver;
			this.equipmentlessConsoleService = equipmentlessConsoleService;
			this.trackingService = trackingService;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
			this.featureFlagManager = featureFlagManager;
			this.bleRadioStatusService = bleRadioStatusService;
			this.bleConsoleService = bleConsoleService;
			this.mockLiveWorkoutService = mockLiveWorkoutService;
		}

		public bool ShowScanIfNeeded()
		{
			if (equipmentlessConsoleService.EquipmentlessConsoleOverrideEnabled)
			{
				return false;
			}
			bool flag = bleConsoleService?.IsConnectedToConsole ?? false;
			if (currentConsoleService.ActiveConsole != null && (IsBuiltInDevice || flag))
			{
				return false;
			}
			if (IsBuiltInDevice)
			{
				_whenUSBError.OnNext(null);
			}
			else
			{
				IBleRadioStatusService obj = bleRadioStatusService;
				if (obj != null && obj.CheckAndRequestBluetooth(notifyIfCannotEnable: true, GetType().Name))
				{
					_whenConsoleNotConnected.OnNext(null);
				}
			}
			return true;
		}

		public bool CanBeginWorkoutPreparations()
		{
			if (StartingWorkout)
			{
				return false;
			}
			StartingWorkout = true;
			startingWorkoutTimeoutSub?.Dispose();
			startingWorkoutTimeoutSub = Observable.Timer(TimeSpan.FromMilliseconds(15000.0)).Subscribe(delegate
			{
				StartingWorkout = false;
			}, delegate(Exception ex)
			{
				Log.Error("Workout", ex.Message);
				StartingWorkout = false;
			});
			return true;
		}

		public void CancelWorkoutPreparations()
		{
			StartingWorkout = false;
			startingWorkoutTimeoutSub?.Dispose();
		}

		public bool CheckStartWorkout()
		{
			if (ShowScanIfNeeded())
			{
				return false;
			}
			if (!currentConsoleService.ActiveConsole.ReadyToStart())
			{
				return false;
			}
			return true;
		}

		private bool ShowBluetoothScreenForNonConnectedTablets()
		{
			if (bleRadioStatusService.CheckAndRequestBluetooth(notifyIfCannotEnable: true, GetType().Name))
			{
				_whenConsoleNotConnected.OnNext(null);
			}
			return false;
		}

		private bool TryStartWorkout(string workoutId, string programId, string challengeId, WorkoutRunnerContext runningContext, AnalyticsSource analyticsSource)
		{
			if (trackingService.IsInWorkout)
			{
				Log.Trace("Workout", "Tried to start a workout when we were already in one");
				StartingWorkout = false;
				return true;
			}
			if (!CheckStartWorkout())
			{
				Log.Error("Workout", "When trying to start workout, CheckStartWorkout returned false");
				StartingWorkout = false;
				return false;
			}
			if (workoutId != null)
			{
				IAchievementStatsService achievementStatsService = Mvx.Resolve<IAchievementStatsService>();
				Task.Run(() => achievementStatsService.FetchAndStoreAchievementStats(workoutId));
			}
			StartingWorkoutParams value = new StartingWorkoutParams
			{
				WorkoutId = workoutId,
				ProgramId = programId,
				ChallengeId = challengeId,
				WorkoutSource = (analyticsSource?.Source ?? WorkoutSource.NA),
				DashboardIndex = (analyticsSource?.DashboardIndex ?? (-1)),
				RunningContext = runningContext
			};
			_whenWorkoutStarted.OnNext(value);
			return true;
		}

		private bool CheckWorkoutCompatibility(Workout workout)
		{
			if (currentConsoleService?.ActiveConsole == null || workout == null)
			{
				return false;
			}
			if (!workout.IsVideoWorkout() && !deviceInformation.IsStrengthMirror)
			{
				return true;
			}
			bool flag = false;
			if ((!deviceInformation.IsHeadlessBikeVault || !currentConsoleService.IsAttachedConsoleActive) ? currentConsoleService.ActiveConsole.CanDoWorkout(workout, deviceInformation.IsStrengthMirror) : currentConsoleService.ActiveConsole.CanDoWorkout(workout, isStrengthMirror: true))
			{
				return true;
			}
			_whenWorkoutIncompatible.OnNext(value: true);
			return false;
		}

		public async Task<bool> DoStartWorkout(Workout workout, WorkoutRunnerContext runningContext, Func<string, IObservable<StateChange>, Task<ProgressDialogResult>> waitForConsoleReady, AnalyticsSource analyticsSource, bool isManualWorkout = false, string programId = null, string challengeId = null)
		{
			bool successful = false;
			if (!CanBeginWorkoutPreparations())
			{
				return false;
			}
			try
			{
				if (workout?.ShouldUseEquipmentlessConsole() ?? false)
				{
					double userKg = await preferenceResolver.UserWeightKgs().ConfigureAwait(continueOnCapturedContext: false);
					double userAge = await preferenceResolver.UserAge().ConfigureAwait(continueOnCapturedContext: false);
					bool userMale = (await preferenceResolver.UserMale().ConfigureAwait(continueOnCapturedContext: false)) ?? true;
					await equipmentlessConsoleService.ReinstantiateConsoleWithWorkout(workout.Type == Workout.WorkoutType.Strength, workout.Target == Workout.TargetType.Seconds, workout.SegmentWorkout(), userKg, userAge, userMale, workout.Metadata?.AverageHeartRate).ConfigureAwait(continueOnCapturedContext: false);
				}
				else
				{
					if (isManualWorkout)
					{
						ICurrentConsoleService obj = currentConsoleService;
						if (obj != null && obj.ActiveConsole?.IsNonconnectedConsole() == true)
						{
							successful = ShowBluetoothScreenForNonConnectedTablets();
							return successful;
						}
					}
					if (!isManualWorkout && !PrepareWorkoutControls(workout))
					{
						return successful;
					}
				}
				if (!isManualWorkout && !CheckWorkoutCompatibility(workout))
				{
					return successful;
				}
				SetMockLiveWorkoutIfNecessary();
				if (TryStartWorkout(workout?.Id, programId, challengeId, runningContext, analyticsSource))
				{
					successful = true;
					return successful;
				}
				IObservable<StateChange> observable = (from x in currentConsoleService?.ActiveConsole?.WhenStateChanged?.Timeout(TimeSpan.FromSeconds(10.0))
					where currentConsoleService.ActiveConsole.ReadyToStart()
					select x);
				if (observable == null)
				{
					Log.Error("Workout", "Console is not fully connected to the app.");
					return successful;
				}
				if (waitForConsoleReady == null)
				{
					Log.Error("Workout", "waitForConsoleReady was null, failed to start workout.");
					_whenWorkoutStartFailed.OnNext(null);
					return successful;
				}
				ProgressDialogResult progressDialogResult = await waitForConsoleReady(Wolf.Core.Resources.AppStrings.communicating_with_equipment, observable);
				if (CheckWorkoutCompatibility(workout) && (currentConsoleService.ActiveConsole.ReadyToStart() || progressDialogResult.Success) && TryStartWorkout(workout?.Id, programId, challengeId, runningContext, analyticsSource))
				{
					successful = true;
					return successful;
				}
				if (progressDialogResult.Error != null)
				{
					Log.Error("Workout", $"Failed to start workout because of {progressDialogResult.Error}.");
				}
				if (currentConsoleService?.ActiveConsole?.LatestBasicInfo == null)
				{
					Log.Error("Workout", "LatestBasicInfo or Console was null");
				}
				else
				{
					Log.Error("Workout", $"Console was in state: {currentConsoleService.ActiveConsole.LatestBasicInfo.CurrentState}");
				}
				if (!Mvx.CanResolve<IDialogPresenter>())
				{
					return successful;
				}
				StartingWorkout = false;
				_whenWorkoutStartFailed.OnNext(null);
			}
			finally
			{
				if (!successful)
				{
					StartingWorkout = false;
					equipmentlessConsoleService?.CleanUpConsole();
					mockLiveWorkoutService?.ClearMockedLiveWorkoutSettings();
				}
			}
			return successful;
		}

		private void SetMockLiveWorkoutIfNecessary()
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.DeveloperFlagMockLiveWorkoutEnabled) && mockLiveWorkoutService != null)
			{
				Log.Trace("Workout", string.Format("{0} flag is enabled, so setting up {1}.", "DeveloperFlagMockLiveWorkoutEnabled", mockLiveWorkoutService.GetType()));
				try
				{
					int startingTime = featureFlagManager.GetInt(FeatureFlags.DeveloperFlagMockLiveWorkoutTimeBegin);
					int endingTime = featureFlagManager.GetInt(FeatureFlags.DeveloperFlagMockLiveWorkoutTimeEnd);
					mockLiveWorkoutService.SetMockedLiveWorkoutSettings(startingTime, endingTime);
				}
				catch (Exception exception)
				{
					Log.Error("Workout", $"{mockLiveWorkoutService.GetType()} setup failed: ", exception);
					mockLiveWorkoutService.ClearMockedLiveWorkoutSettings();
				}
			}
		}

		public async Task<bool> StartCyclicalManualWorkout(Func<string, IObservable<StateChange>, Task<ProgressDialogResult>> waitForConsoleReady, AnalyticsSource analyticsSource)
		{
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			maintainRpmToStartManualWorkoutSub?.Dispose();
			maintainRpmToStartManualWorkoutSub = Observable.Interval(TimeSpan.FromSeconds(1.0)).Skip(1).Take(5)
				.Subscribe(delegate
				{
					if (currentConsoleService?.ActiveConsole?.LatestBasicInfo.Rpm < 5)
					{
						maintainRpmToStartManualWorkoutSub?.Dispose();
						tcs.TrySetResult(result: false);
					}
				}, delegate
				{
					maintainRpmToStartManualWorkoutSub?.Dispose();
					tcs.TrySetResult(result: false);
				}, delegate
				{
					tcs.TrySetResult(result: true);
				});
			if (await tcs.Task)
			{
				return await DoStartWorkout(null, WorkoutRunnerContext.DefaultOnDemandContext, waitForConsoleReady, analyticsSource, isManualWorkout: true);
			}
			return false;
		}

		public async Task<bool> DoStartManualWorkout(Func<string, IObservable<StateChange>, Task<ProgressDialogResult>> waitForConsoleReady, AnalyticsSource analyticsSource)
		{
			return await DoStartWorkout(null, WorkoutRunnerContext.DefaultOnDemandContext, waitForConsoleReady, analyticsSource, isManualWorkout: true);
		}

		public void Dispose()
		{
			maintainRpmToStartManualWorkoutSub?.Dispose();
			maintainRpmToStartManualWorkoutSub = null;
			startingWorkoutTimeoutSub?.Dispose();
			startingWorkoutTimeoutSub = null;
		}

		private bool PrepareWorkoutControls(Workout workout)
		{
			try
			{
				workout.ConvertInclineWorkoutToResistanceIfNecessary(currentConsoleService.ActiveConsole);
				workout.ConvertWorkoutControlsForConsole(currentConsoleService.ActiveConsole);
				workout.RoundInclineControls();
				IFitnessConsole activeConsole = currentConsoleService.ActiveConsole;
				if (activeConsole != null && activeConsole.ConsoleInfo?.MachineType.IsAerobicMachine() == true)
				{
					workout.Controls = workout.ConvertRelativeResistanceControlsToResistance(currentConsoleService.ActiveConsole?.ConsoleInfo);
				}
				return true;
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Exception preparing to start workout " + workout?.Id, exception);
				if (ShowScanIfNeeded())
				{
					return false;
				}
				_whenPrepareWorkoutFailed.OnNext(null);
				return false;
			}
		}
	}
