	public class TelevisionSettings : ITelevisionSettings
	{
		private readonly IBlobCacheService cacheService;

		private const string DefaultTelevisionUrl = "http://192.168.0.14";

		private string _televisionUrl;

		private bool _showClosedCaptions;

		private bool _clubDefaultClosedCaptions;

		public string TelevisionUrl
		{
			get
			{
				return _televisionUrl;
			}
			set
			{
