				{
					_showClosedCaptions = value;
					cacheService.Flush(_showClosedCaptions, "_showClosedCaptions", "ITelevisionSettings");
				}
			}
		}

		public bool ClubDefaultTvClosedCaptions
		{
			get
			{
				return _clubDefaultClosedCaptions;
			}
			set
			{
				if (value != _clubDefaultClosedCaptions)
				{
					_clubDefaultClosedCaptions = value;
					cacheService.Flush(_clubDefaultClosedCaptions, "_clubDefaultClosedCaptions", "ITelevisionSettings");
				}
			}
		}

		public bool GuestTvClosedCaptions { get; set; }

		public TelevisionSettings(IBlobCacheService cacheService)
		{
			this.cacheService = cacheService;
		}

		private async Task<ITelevisionSettings> InitializeAsync()
		{
