	public interface ITelevisionTunerService
	{
		bool? IsAvailable { get; }

		Task IsAvailableCheck { get; }

		void UpdateUrl();

		Task<Response> AwaitAndLogResponse(Func<ITunerApi, Task<Response>> func, string methodName);

		Task<string> GetStreamUri();
	}
	public class TelevisionTunerService : ITelevisionTunerService
	{
		private const string TelevisionStreamPath = ":8080/hls/stream.m3u8";

		private readonly Func<string, ITunerApi> apiFromUrlGetter;

		private readonly ITelevisionSettings televisionSettings;

		private ITunerApi tunerApi;

		public bool? IsAvailable { get; private set; }

		public Task IsAvailableCheck { get; private set; }

		public TelevisionTunerService(Func<string, ITunerApi> apiFromUrlGetter, ITelevisionSettings televisionSettings)
		{
			this.apiFromUrlGetter = apiFromUrlGetter;
			this.televisionSettings = televisionSettings;
			UpdateUrl();
		}

		public void UpdateUrl()
		{
			tunerApi = (string.IsNullOrWhiteSpace(televisionSettings.TelevisionUrl) ? null : apiFromUrlGetter(televisionSettings.TelevisionUrl));
			CheckIsAvailable();
		}

		public async Task<Response> AwaitAndLogResponse(Func<ITunerApi, Task<Response>> func, string requestName)
		{
			if (tunerApi == null)
			{
				LogNullTunerApi(requestName);
				return null;
			}
			LogStartingRequest(requestName);
			try
			{
				Response response = await func(tunerApi);
				LogResponse(response, requestName);
				return response;
			}
			catch (Exception exception)
			{
				Log.Error("Tuner", "Tuner API exception attempting " + requestName, exception);
				return null;
			}
		}

		private void CheckIsAvailable()
		{
			IsAvailableCheck = Task.Run(async delegate
			{
				string requestName = "Feature-Discovery Channel GET";
				if (tunerApi == null)
				{
					LogNullTunerApi(requestName);
					IsAvailable = false;
					return;
				}
				LogStartingRequest(requestName);
				try
				{
					LogResponse(await tunerApi.Channel().ConfigureAwait(continueOnCapturedContext: false), requestName);
					IsAvailable = true;
				}
				catch (ApiException ex)
				{
					IsAvailable = ex.StatusCode == HttpStatusCode.NotFound;
					if (IsAvailable == true)
					{
						Log.Error("Tuner", "Tuner API exception attempting " + requestName + ", so server is up but not fully implemented", ex);
					}
					else
					{
						Log.Error("Tuner", $"Tuner API exception attempting {requestName}, did not expect: {ex}");
					}
				}
				catch (iFit.Api.Support.ConnectivityException ex2)
				{
					IsAvailable = false;
					Log.Error("Tuner", "Tuner API exception attempting " + requestName + ", assuming tuner is absent", ex2.InnerException ?? ex2);
				}
				catch (Exception arg)
				{
					IsAvailable = false;
					Log.Error("Tuner", $"Tuner API exception attempting {requestName}, did not expect: {arg}");
				}
			});
		}

		private static void LogNullTunerApi(string requestName)
		{
			Log.Error("Tuner", "No Tuner API defined, not attempting " + requestName);
		}

		private static void LogStartingRequest(string requestName)
		{
			Log.Trace("Tuner", "Sending " + requestName + " to Tuner API");
		}

		private static void LogResponse(Response response, string requestName)
		{
			if (response == null)
			{
				Log.Trace("Tuner", "Tuner API returned null response to " + requestName);
				return;
			}
			string text = "Tuner API returned Error='" + response.Error + "' to " + requestName;
			if (string.IsNullOrWhiteSpace(response.Error))
			{
				Log.Trace("Tuner", text);
			}
			else
			{
				Log.Error("Tuner", text);
			}
		}

		public async Task<string> GetStreamUri()
		{
			if (IsAvailable != true)
			{
				return null;
			}
			string text = televisionSettings?.TelevisionUrl;
			if (string.IsNullOrWhiteSpace(text))
			{
				return null;
			}
			if (!Uri.TryCreate(text + ":8080/hls/stream.m3u8", UriKind.Absolute, out var uri))
			{
				return null;
			}
			await AwaitAndLogResponse((ITunerApi api) => api.Up(), "Channel Up to Start Stream").ConfigureAwait(continueOnCapturedContext: false);
			await Task.Delay(2000).ConfigureAwait(continueOnCapturedContext: false);
			return uri.ToString();
		}
	}
	public interface ITouchMonitor
	{
		bool IsActive { set; }

		double SecondsSinceLastTouch { get; }

		EventHandler Touched { get; set; }

		EventHandler<StateChangeEventArgs> ConsoleStateChanged { get; set; }

		EventHandler TestTimeoutElapsed { get; set; }

		void UpdateLastObservedTouch();
	}
	public class TouchMonitor : ITouchMonitor, IDisposable
	{
		private readonly TimeSpan DelayBeforeEruVersionCheck = TimeSpan.FromSeconds(5.0);

		private readonly Version MinimumEruVersion = new Version("1.0.47");

		private readonly ILastTouch lastTouch;

		private readonly ICurrentConsoleService currentConsoleService;

		private IIpcVersionInfo versionInfo;

		private readonly IDisposable consoleChangedSub;

		private IDisposable consoleStateChangedSub;

		private IDisposable touchWatchSub;

		private IDisposable workoutStartingSub;

		private IDisposable workoutEndingSub;

		private DateTime LastObservedTouch { get; set; } = DateTime.UtcNow;

		public double SecondsSinceLastTouch => (DateTime.UtcNow - LastObservedTouch).TotalSeconds;

		public EventHandler Touched { get; set; }

		public EventHandler<StateChangeEventArgs> ConsoleStateChanged { get; set; }

		public EventHandler TestTimeoutElapsed { get; set; }

		public bool IsActive
		{
			set
			{
				touchWatchSub?.Dispose();
				touchWatchSub = (value ? Observable.Interval(TimeSpan.FromSeconds(5.0)).SubscribeAsyncWithErrorLogging((long x) => PollLastTouch()) : null);
				if (value)
				{
					UpdateLastObservedTouch();
				}
			}
		}

		public TouchMonitor(ILastTouch lastTouch, IIpcVersionInfo versionInfo, ICurrentConsoleService currentConsoleService)
		{
			this.lastTouch = lastTouch;
			this.versionInfo = versionInfo;
			this.currentConsoleService = currentConsoleService;
			if (currentConsoleService.ActiveConsole == null)
			{
				consoleChangedSub = currentConsoleService?.WhenConsoleChanged.Take(1).SubscribeAsyncWithErrorLogging((IFitnessConsole x) => ConsoleChanged());
			}
			else
			{
				Task.Run(async delegate
				{
					await ConsoleChanged().ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		public void UpdateLastObservedTouch()
		{
			LastObservedTouch = DateTime.UtcNow;
		}

		protected virtual async Task ConsoleChanged()
		{
			await Task.Delay(DelayBeforeEruVersionCheck).ConfigureAwait(continueOnCapturedContext: false);
			if (!(await CheckEruVersion().ConfigureAwait(continueOnCapturedContext: false)))
			{
				Dispose();
				return;
			}
			Touched?.Invoke(this, EventArgs.Empty);
			IsActive = true;
			consoleStateChangedSub = currentConsoleService?.ActiveConsole?.WhenStateChanged.SubscribeWithErrorLogging(delegate(StateChange state)
			{
				ConsoleStateChanged?.Invoke(this, new StateChangeEventArgs(state));
			});
			workoutStartingSub = currentConsoleService?.ActiveConsole?.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WarmUp && x.Old != ConsoleState.Paused).SubscribeWithErrorLogging(delegate
			{
				IsActive = false;
			});
			workoutEndingSub = currentConsoleService?.ActiveConsole?.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WorkoutResults).SubscribeWithErrorLogging(delegate
			{
				IsActive = true;
			});
		}

		private async Task<bool> CheckEruVersion()
		{
			bool versionIsValid = false;
			await versionInfo.GetVersions().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				Version version = Version.Parse(versionInfo.EruVersion);
				versionIsValid = version >= MinimumEruVersion;
			}
			catch (ArgumentException)
			{
				Log.Error("Ipc", "Unable to parse Eru Version: " + versionInfo.EruVersion);
			}
			return versionIsValid;
		}

		private async Task PollLastTouch()
		{
			try
			{
				DateTime dateTime = await lastTouch.GetLastTouchAysnc().ConfigureAwait(continueOnCapturedContext: false);
				if (dateTime > LastObservedTouch)
				{
					LastObservedTouch = dateTime;
				}
			}
			catch (Exception exception)
			{
				Log.Error("Ipc", "Failed getting last touch from Eru.", exception);
			}
			finally
			{
				TestTimeoutElapsed?.Invoke(this, EventArgs.Empty);
			}
		}

		public void Dispose()
		{
			touchWatchSub?.Dispose();
			consoleChangedSub?.Dispose();
			consoleStateChangedSub?.Dispose();
			workoutStartingSub?.Dispose();
			workoutEndingSub?.Dispose();
		}
	}
	public class StateChangeEventArgs : EventArgs
	{
		public StateChange StateChange { get; set; }

		public StateChangeEventArgs(StateChange stateChange)
		{
			StateChange = stateChange;
		}
	}
	public interface IUpgradeService
