	public class UpgradeService : BaseWebViewBehaviorProvider, IUpgradeService
	{
		public const string NativeMethodUpgrade = "upgrade";

		private readonly IDeviceInformation deviceInformation;

		private readonly IIfitApiService ifitApi;

		public override string BehaviorName => "upgrade";

		public UpgradeService(IDeviceInformation deviceInformation, IIfitApiService ifitApi)
		{
			this.deviceInformation = deviceInformation;
			this.ifitApi = ifitApi;
		}

		public override Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			return Upgrade(context);
		}

		public Task Upgrade(IBehaviorContext context)
		{
			if (!(context is PreWorkoutWebviewViewModel) && !ifitApi.HasLoggedInUser)
			{
				context.ShowLoginViewModel(new OnboardingWebViewModel.NavObject
				{
					NavigatedFrom = (context as BaseWebViewViewModel)?.WebviewName
				});
				return Task.CompletedTask;
			}
			if (deviceInformation.IsBuiltIn || context is PreWorkoutWebviewViewModel)
			{
				context.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.ifit_subscription, Wolf.Core.Resources.AppStrings.membership_activation_message);
			}
			else
			{
				context.ShowMarketingViewModel((context as BaseWebViewViewModel)?.WebviewName);
			}
			return Task.CompletedTask;
		}
	}
	public class WolfMembershipSettings : MembershipSettingsBase
	{
		public const string OneYearId = "59e624ef94c348003eb60cc1";

		public const string OneMonthId = "59e53fd46fc2360044e2f982";

		private readonly IIfitApiService ifitApi;

		private List<StoreItem> embeddedSkus;

		public override StoreItem ChosenStoreItem
		{
			get
			{
				return base.ChosenStoreItem;
			}
			set
			{
				base.ChosenStoreItem = value;
				if (value != null)
				{
					bool flag = value.AccountPaymentType == "Yearly";
					base.Months = ((!flag) ? 1 : 12);
					base.Price = value.Price;
					base.PricePerMonth = (int)Math.Ceiling(base.Price / (double)base.Months);
					base.ChosenMembershipPlan = (flag ? Wolf.Core.Resources.AppStrings.payment_chose_yearly : Wolf.Core.Resources.AppStrings.payment_chose_monthly);
				}
			}
		}

		public WolfMembershipSettings(IIfitApiService ifitApi)
		{
			this.ifitApi = ifitApi;
		}

		public override async Task<List<StoreItem>> GetStoreItems()
		{
			if (embeddedSkus.CountSafe() == 0)
			{
				List<StoreItem> items = await ifitApi.Service.GetEmbeddedSkus();
				StoreItem yearlyItem = await ValidateStoreItem(items.GetSafe(0), "59e624ef94c348003eb60cc1");
				StoreItem item = await ValidateStoreItem(items.GetSafe(1), "59e53fd46fc2360044e2f982");
				embeddedSkus = new List<StoreItem> { yearlyItem, item };
			}
			base.YearlyPlanPrice = embeddedSkus[0].Price;
			base.MonthlyPlanPrice = embeddedSkus[1].Price;
			return embeddedSkus;
		}

		private async Task<StoreItem> ValidateStoreItem(StoreItem item, string fallbackStoreId)
		{
			StoreItem storeItem = item;
			if (storeItem == null)
			{
				storeItem = await ifitApi.Service.GetStoreItem(fallbackStoreId);
			}
			return storeItem;
		}
	}
