		{
			_firstRun = await cacheService.GetFromCache("_firstRun", "WolfTrackingService", string.Empty, temp: false, defaultValue: true);
			_isFirstTime = await cacheService.GetFromCache<bool?>("_isFirstTime", "WolfTrackingService");
			_lastRequestedVideoUrl = await cacheService.GetFromCache<string>("_lastRequestedVideoUrl", "WolfTrackingService");
			_lastReviewRequestDate = await cacheService.GetFromCache<DateTime>("_lastReviewRequestDate", "WolfTrackingService");
			completedOnboardingUserIds = await cacheService.GetFromCache("completedOnboardingUserIds", "WolfTrackingService", string.Empty, temp: false, new List<string>());
			return this;
		}

