		{
			get
			{
				if (featureFlagManager == null)
				{
					Mvx.TryResolve<IFeatureFlagManager>(out featureFlagManager);
				}
				IFeatureFlagManager obj = featureFlagManager;
				if (obj != null && obj.IsFeatureEnabled(FeatureFlags.VideoHlsEnabled) && _videoQuality == VideoQuality.Auto)
				{
					return BandwidthVideoQualityMapping.GetVideoQualityFromString(featureFlagManager.GetString(FeatureFlags.VideoPlaybackQualityDefault));
