		public WorkoutSettings(IBlobCacheService cacheService)
		{
			this.cacheService = cacheService;
		}

		private async Task<IWorkoutSettings> InitializeAsync()
		{
			_warmUpSeconds = await cacheService.GetFromCache("_warmUpSeconds", "IWorkoutSettings", "", temp: false, 180);
			_showSliders = await cacheService.GetFromCache<bool?>("_showSliders", "IWorkoutSettings");
			_videoQuality = await cacheService.GetFromCache("newVideoQuality", "IWorkoutSettings", "", temp: false, VideoQuality.Auto);
			_preferredRightWorkoutWidget = await cacheService.GetFromCache<WidgetType?>("_preferredRightWorkoutWidget", "IWorkoutSettings");
			_preferredLeftWorkoutWidget = await cacheService.GetFromCache<WidgetType?>("_preferredLeftWorkoutWidget", "IWorkoutSettings");
			_hideHrWidgetUntilHrm = await cacheService.GetFromCache("_hideHrWidgetUntilHrm", "IWorkoutSettings", "", temp: false, defaultValue: true);
			return this;
		}

		public static Task<IWorkoutSettings> CreateAsync(IBlobCacheService cacheService)
		{
			WorkoutSettings workoutSettings = new WorkoutSettings(cacheService);
			return workoutSettings.InitializeAsync();
		}

		public void ClearAndDisposeWorkoutContainer()
		{
			WorkoutContainer?.Dispose();
			WorkoutContainer = null;
		}

		public void Dispose()
		{
			GC.SuppressFinalize(this);
		}
	}
