		public static IConsoleConfiguration Create(IWorkoutContainer workoutContainer, IConnectivity connectivity, WorkoutRunnerContext runnerContext, IDeviceInformation deviceInfo, IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, IThemeService themeService)
		{
			string configurationFileName = GetConfigurationFileName(workoutContainer.Console.ConsoleInfo.MachineType, workoutContainer.Console.ConsoleInfo.CanSetIncline);
			JsonConsoleConfiguration jsonConsoleConfiguration = new JsonConsoleConfiguration(configurationFileName, workoutContainer, connectivity, runnerContext, deviceInfo, ifitApi, iFitGatewayApi, themeService);
			Log.Trace("Workout", "Configuration: " + jsonConsoleConfiguration.GetType().Name);
			return jsonConsoleConfiguration;
		}

		public static string GetConfigurationFileName(ConsoleType machineType, bool canSetIncline)
		{
			switch (machineType)
			{
			case ConsoleType.Bike:
				if (canSetIncline)
				{
					return "InclineBike.json";
				}
				return "Bike.json";
			case ConsoleType.SpinBike:
				return "SpinBike.json";
			case ConsoleType.Treadmill:
			case ConsoleType.InclineTrainer:
				return "Treadmill.json";
			case ConsoleType.FreeStrider:
				return "FreeStrider.json";
			case ConsoleType.Elliptical:
				return "Elliptical.json";
			case ConsoleType.Strider:
			case ConsoleType.VerticalElliptical:
				return "HIIT.json";
			case ConsoleType.Rower:
				return "Rower.json";
			case ConsoleType.Equipmentless:
			case ConsoleType.Mirror:
				return "Equipmentless.json";
			default:
				throw new NotImplementedException("Could not create console configuration for unknown console type.");
			}
		}
	}
	public interface IInWorkoutSystemVolumeInteractor : IDisposable
	{
		IObservable<bool> WhenVolumeChangeCompleted { get; }

		bool IsProcessingVolumeChanges { get; }

		void SetConsoleVolume(int volume);
	}
	public class InWorkoutSystemVolumeInteractor : IInWorkoutSystemVolumeInteractor, IDisposable
	{
		private readonly IVolumeFacade volumeFacade;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IDeviceInformation deviceInformation;

		private readonly IMediaSettings mediaSettings;

		private readonly IPlatformMediaVolumeService platformMediaVolumeService;

		private readonly TimeSpan processingTimeout;

		private readonly SemaphoreSlim volumeLock = new SemaphoreSlim(1, 1);

		private Subject<bool> _whenVolumeChangeCompleted = new Subject<bool>();

		private bool _isProcessingVolumeChanges;

		private DateTime lastVolumeChange = DateTime.UtcNow;

		private Queue<int> volumeChangeQueue = new Queue<int>();

		private CancellationTokenSource cancellationTokenSource = new CancellationTokenSource();

		public IObservable<bool> WhenVolumeChangeCompleted => _whenVolumeChangeCompleted;

		public bool IsProcessingVolumeChanges
		{
			get
			{
				if (!_isProcessingVolumeChanges)
				{
					return DateTime.UtcNow - lastVolumeChange < processingTimeout;
				}
				return true;
			}
			private set
			{
				_isProcessingVolumeChanges = value;
			}
		}

		public InWorkoutSystemVolumeInteractor(ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IMediaSettings mediaSettings, IPlatformMediaVolumeService platformMediaVolumeService = null, IVolumeFacade volumeFacade = null, long processingTimeoutMs = 200L)
		{
			this.volumeFacade = volumeFacade;
			this.currentConsoleService = currentConsoleService;
			this.deviceInformation = deviceInformation;
			this.mediaSettings = mediaSettings;
			this.platformMediaVolumeService = platformMediaVolumeService;
			processingTimeout = TimeSpan.FromMilliseconds(processingTimeoutMs);
			float? num = platformMediaVolumeService?.GetPlatformMediaVolume();
			if (num.HasValue && deviceInformation.IsStrengthMirror)
			{
				this.mediaSettings.UpdateStrengthMirrorSystemVolume(num.Value, commit: true);
			}
		}

		public void SetConsoleVolume(int volume)
		{
			if (deviceInformation.IsStrengthMirror)
			{
				float num = ((float)volume / 100f).Clamp(0f, 1f);
				platformMediaVolumeService?.SetPlatformMediaVolume(num);
				mediaSettings.UpdateStrengthMirrorSystemVolume(num, commit: true);
				_whenVolumeChangeCompleted?.OnNext(value: true);
			}
			else
			{
				volumeChangeQueue.Enqueue(volume);
				Task.Run((Func<Task>)ProcessVolumeQueue);
			}
		}

		private async Task ProcessVolumeQueue()
		{
			bool completedSuccessfully = false;
			try
			{
				await volumeLock.WaitAsync();
				cancellationTokenSource.Token.ThrowIfCancellationRequested();
				Queue<int> queue = volumeChangeQueue;
				if (queue == null || queue.Count != 0)
				{
					IsProcessingVolumeChanges = true;
					int? num = volumeChangeQueue?.LastOrDefault();
					volumeChangeQueue?.Clear();
					if (num.HasValue)
					{
						await SetConsoleVolumeAsync(num.Value);
					}
					completedSuccessfully = true;
				}
			}
			catch (ObjectDisposedException)
			{
			}
			catch (Exception exception)
			{
				Log.Error("FitPro", "InWorkoutSystemVolumeInteractor - Unable to process volume queue", exception);
			}
			finally
			{
				ReleaseLock();
				_whenVolumeChangeCompleted?.OnNext(completedSuccessfully);
			}
		}

		private async Task SetConsoleVolumeAsync(int volume)
		{
			_ = 1;
			try
			{
				cancellationTokenSource.Token.ThrowIfCancellationRequested();
				if (volumeFacade != null)
				{
					await volumeFacade.SetVolumeAsync(volume);
					await Task.Delay(processingTimeout);
				}
			}
			catch (OperationCanceledException)
			{
			}
			catch (ObjectDisposedException)
			{
			}
			catch (Exception exception)
			{
				Log.Error("FitPro", "InWorkoutSystemVolumeInteractor - Unable to set system volume", exception);
			}
			finally
			{
				lastVolumeChange = DateTime.UtcNow;
			}
		}

		private void ReleaseLock()
		{
			try
			{
				lastVolumeChange = DateTime.UtcNow;
				Queue<int> queue = volumeChangeQueue;
				if (queue != null && queue.Count == 0)
				{
					IsProcessingVolumeChanges = false;
				}
				volumeLock?.Release();
			}
			catch (ObjectDisposedException)
			{
			}
		}

		public void Dispose()
		{
			try
			{
				_whenVolumeChangeCompleted?.Dispose();
				_whenVolumeChangeCompleted = null;
				cancellationTokenSource?.Cancel();
				volumeChangeQueue?.Clear();
				volumeChangeQueue = null;
				volumeLock?.Dispose();
			}
			catch (Exception exception)
			{
				Log.Trace("FitPro", "InWorkoutSystemVolumeInteractor - Unable to dispose fully", exception);
			}
		}
	}
	public static class SystemVolumeHelper
	{
		public const int MinSystemVolumeChange = 10;

		public static int MapVolume(float volume)
		{
			return (volume * 100f).RoundToNearest(10.0);
		}

		public static bool UpdateVolumeLevel(ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IWorkoutSettings workoutSettings, int mappedVolume, bool force = false)
		{
			IFitnessConsole fitnessConsole = (deviceInformation.IsBuiltIn ? currentConsoleService.PhysicalConsole : currentConsoleService.Console);
			int num = fitnessConsole.LatestBasicInfo.Volume.RoundToNearest(10.0);
			if (Math.Abs(mappedVolume - num) < 10 && !force)
			{
				return false;
			}
			workoutSettings?.WorkoutContainer?.InWorkoutSystemVolumeInteractor?.SetConsoleVolume(mappedVolume);
			return true;
		}
	}
