		public WorkoutContainer(IWorkoutRunner runner, ConsoleStateStats stats, IRemainingWorkoutEstimates remainingEstimates, Workout workout, string programId, string challengeId, bool isMetric, double userWeightKgs, double userHeightMeters, ISettingsRouter settingsRouter, IWorkoutChangeLevel workoutChangeLevel, ICurrentConsoleService currentConsoleService, IPreferenceResolver preferenceResolver, IMediaService media, ILockScreenMediaSettings lockScreenMediaSettings = null, IWorkoutMusicInfoService musicInfoService = null)
		{
			this.settingsRouter = settingsRouter;
			this.lockScreenMediaSettings = lockScreenMediaSettings;
			this.currentConsoleService = currentConsoleService;
