			SetupStateChangeSub();
			Media.Music?.UpdateMusicAvailability();
			weightChangeSub = preferenceResolver?.WhenWeightChanged.SubscribeAsync(async delegate
			{
				await WhenWeightChanged();
			});
		}

		private async Task WhenWeightChanged()
		{
			UserWeightKgs = await settingsRouter.GetWeightKgs();
			RemainingEstimates.UpdateUserKgs(UserWeightKgs);
			ChartData.UpdateUserKgs(UserWeightKgs);
		}

		public bool Supports(IHardwareDependent hardwareDependentItem)
		{
			IConsoleInfo consoleInfo = Console?.ConsoleInfo;
			if (consoleInfo == null || hardwareDependentItem == null)
			{
				return false;
			}
			if (!consoleInfo.CanSetKph && hardwareDependentItem.RequiresKph)
			{
				return false;
			}
			if (!consoleInfo.CanSetIncline && hardwareDependentItem.RequiresIncline)
			{
				return false;
			}
			if (!consoleInfo.CanSetResistance && hardwareDependentItem.RequiresResistance)
			{
				return false;
			}
			if (!consoleInfo.CanSetGear && hardwareDependentItem.RequiresGear)
			{
				return false;
			}
			if (hardwareDependentItem.RequiresVerticalNet && (consoleInfo.MachineType == ConsoleType.Elliptical || !consoleInfo.SupportsVerticalNet))
			{
				return false;
			}
			if (hardwareDependentItem.RequiresVerticalGain && (consoleInfo.MachineType == ConsoleType.Elliptical || !consoleInfo.SupportsVerticalGain))
			{
				return false;
			}
			if (Workout.IsManual() && hardwareDependentItem.IsGoalBased)
			{
				return false;
			}
			if (hardwareDependentItem.HideWhenTimeBased && Workout.Target == Workout.TargetType.Seconds)
			{
				return false;
			}
			if (hardwareDependentItem.RequiredFitnessValues.CountSafe() > 0)
			{
				foreach (FitnessValue requiredFitnessValue in hardwareDependentItem.RequiredFitnessValues)
				{
					List<FitnessValue> readableTypes = Console.ReadableTypes;
					if (readableTypes == null || !readableTypes.Contains(requiredFitnessValue))
					{
						return false;
					}
				}
			}
			if (hardwareDependentItem.HideWhenDistanceBased && Workout.Target == Workout.TargetType.Meters && consoleInfo.MachineType == ConsoleType.Rower)
			{
				return false;
			}
			if (hardwareDependentItem.HideWhenTimeBased && Workout.Target == Workout.TargetType.Seconds)
			{
				return false;
			}
			if (hardwareDependentItem.IsGoalBased)
			{
				IWorkoutRunner workoutRunner = WorkoutRunner;
				if (workoutRunner == null || workoutRunner.RunContext.Context != Workout.WorkoutContext.OnDemand)
				{
					return false;
				}
			}
			IFitnessConsole console = Console;
			if (console != null && console.IsMock() && MockConsoleMetricTypeBlacklist.MockConsoleBlacklistedMetrics.Contains(hardwareDependentItem.GetType()))
			{
				return false;
			}
			return true;
		}

		private bool CheckPauseOverrideSupportedByConsoleAndWorkoutTypes()
		{
			IFitnessConsole console = Console;
			if (console == null || !console.SupportsPauseOverride)
			{
				return false;
			}
			IFitnessConsole console2 = Console;
			if (console2 != null && console2.ConsoleInfo?.MachineType.ConsoleTypeAllowsPauseOverrideForAllWorkoutTypes() == true)
			{
				return true;
			}
			Workout workout = Workout;
			if (workout != null && workout.IsVideoWorkout())
			{
				return true;
			}
			return false;
		}

		private void SetupStateChangeSub()
		{
			stateChangedSub?.Dispose();
			stateChangedSub = Console?.WhenStateChanged?.SubscribeWithErrorLogging(HandleConsoleStateChanged);
		}

		private void HandleConsoleStateChanged(StateChange stateChange)
		{
			Media.Music.UpdateMusicAvailability();
			lockScreenMediaSettings.UpdateLockScreenSettings(stateChange.Current, Media.Music?.FeedFm, Media.Music.WorkoutHasMusic);
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		public void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					Log.Trace("Workout", "Disposing workout container");
					WorkoutRunner?.Dispose();
					WorkoutRunner = null;
					Stats?.Dispose();
					Stats = null;
					ConsoleConfiguration?.Dispose();
					ConsoleConfiguration = null;
					RemainingEstimates?.Dispose();
					RemainingEstimates = null;
					InWorkoutSystemVolumeInteractor?.Dispose();
					InWorkoutSystemVolumeInteractor = null;
					ChartData?.Dispose();
					ChartData = null;
					Workout?.Dispose();
					Workout = null;
					MusicInfoService?.Dispose();
					MusicInfoService = null;
					musicInfoServiceSub?.Dispose();
					musicInfoServiceSub = null;
					stateChangedSub?.Dispose();
					stateChangedSub = null;
					weightChangeSub?.Dispose();
					weightChangeSub = null;
					WorkoutChangeLevel?.Dispose();
					WorkoutChangeLevel = null;
					Media.Music.FeedFm?.Dispose();
					Media.Music.FeedFm = null;
					Media.Music.HasInitializedAudioService = false;
				}
				isDisposed = true;
			}
		}
	}
	public interface IWorkoutContainerFactory
	{
