	public class WorkoutContainerFactory : IWorkoutContainerFactory
	{
		private readonly IWorkoutContainerFactoryDependencies dependencies;

		public WorkoutContainerFactory(IWorkoutContainerFactoryDependencies dependencies)
		{
			this.dependencies = dependencies;
		}

		public async Task<IWorkoutContainer> Create(Workout workout, string programId, string challengeId, WorkoutRunnerContext runningContext, AnalyticsSource analyticsSource, bool inRetailDemo = false, bool shouldAutomaticallyShowLeaderboard = true)
		{
			return await Create(await WorkoutContainerContext.Create(dependencies, workout, programId, challengeId, runningContext, analyticsSource, inRetailDemo, shouldAutomaticallyShowLeaderboard));
		}

		public async Task<IWorkoutContainer> Recover(Workout workout, AnalyticsSource analyticsSource)
		{
			return await Create(await WorkoutContainerContext.Recover(dependencies, workout, analyticsSource), isRecoverable: true);
		}

		private async Task<IWorkoutContainer> Create(WorkoutContainerContext context)
		{
			return await Create(context, isRecoverable: false);
		}

		private async Task<IWorkoutContainer> Create(WorkoutContainerContext context, bool isRecoverable)
		{
			WorkoutContainerStateHandler workoutContainerStateHandler = new WorkoutContainerStateHandler(dependencies);
			BaseWorkoutContainerHandler baseWorkoutContainerHandler = workoutContainerStateHandler.AddHandler(new WorkoutContainerControlsHandler(dependencies)).AddHandler(new WorkoutContainerRunnerHandler(dependencies)).AddHandler(new WorkoutContainerSmartAdjust(dependencies))
				.AddHandler(new WorkoutContainerHandler(dependencies))
				.AddHandler(new WorkoutContainerAnalyticsHandler(dependencies))
				.AddHandler(new WorkoutContainerCacheHandler(dependencies));
			if (isRecoverable)
			{
				baseWorkoutContainerHandler.AddHandler(new WorkoutContainerRecoveryHandler(dependencies));
			}
			return await workoutContainerStateHandler.HandleRequest(context);
		}
	}
