namespace Wolf.Core.Services.WorkoutContainer.Handlers
{
	public abstract class BaseWorkoutContainerHandler
	{
		protected IWorkoutContainerFactoryDependencies Dependencies { get; private set; }

		protected IFitnessConsole Console => Dependencies?.CurrentConsoleService?.ActiveConsole;

		protected BaseWorkoutContainerHandler Successor { get; private set; }

		protected BaseWorkoutContainerHandler(IWorkoutContainerFactoryDependencies dependencies)
		{
			Dependencies = dependencies;
