		private WorkoutContainerContext(IWorkoutContainerFactoryDependencies dependencies, bool isMetric, double userWeightKgs, double userHeightMeters, double userAge, bool userMale, Workout workout, string programId, string challengeId, WorkoutRunnerContext runningContext, AnalyticsSource analyticsSource, ConsoleStateStats stats = null, string latestActivityLogId = null, bool inRetailDemo = false, bool shouldAutomaticallyShowLeaderboard = true)
