			UserMale = userMale;
			Workout = workout;
			ProgramId = programId;
			ChallengeId = challengeId;
			Context = runningContext;
			AnalyticsSource = analyticsSource;
			Stats = stats ?? GetDefaultStats(dependencies, workout, runningContext?.Context ?? Workout.WorkoutContext.OnDemand);
			WolfGeneratedId = latestActivityLogId;
			InRetailDemo = inRetailDemo;
			ShouldAutomaticallyShowLeaderboard = shouldAutomaticallyShowLeaderboard;
