		private WorkoutContainerContext(IWorkoutContainerFactoryDependencies dependencies, bool isMetric, double userWeightKgs, double userHeightMeters, double userAge, bool userMale, Workout workout, WorkoutRecoveryInfo recoveryInfo, IConsoleBasicInfo consoleBasicInfo, AnalyticsSource analyticsSource, bool inRetailDemo = false)
		{
			Dependencies = dependencies;
			IsMetric = isMetric;
			UserWeightKgs = userWeightKgs;
			UserHeightMeters = userHeightMeters;
			UserAge = userAge;
			UserMale = userMale;
			Workout = workout;
			Context = recoveryInfo?.RunContext;
			AnalyticsSource = analyticsSource;
			Stats = recoveryInfo?.Stats;
			WolfGeneratedId = recoveryInfo?.WolfGeneratedId;
			RecoveryInfo = recoveryInfo;
			InRetailDemo = inRetailDemo;
