		public static WorkoutContainerContext Create(IWorkoutContainerFactoryDependencies dependencies, bool isMetric, double userWeightKgs, double userHeightMeters, double userAge, bool userMale, Workout workout, string programId, string challengeId, WorkoutRunnerContext runningContext, AnalyticsSource analyticsSource, ConsoleStateStats stats = null, string latestActivityLogId = null, bool inRetailDemo = false, bool shouldAutomaticallyShowLeaderboard = true)
		{
			return new WorkoutContainerContext(dependencies, isMetric, userWeightKgs, userHeightMeters, userAge, userMale, workout, programId, challengeId, runningContext, analyticsSource, stats, latestActivityLogId, inRetailDemo, shouldAutomaticallyShowLeaderboard);
		}

		public static async Task<WorkoutContainerContext> Create(IWorkoutContainerFactoryDependencies dependencies, Workout workout, string programId, string challengeId, WorkoutRunnerContext runningContext, AnalyticsSource analyticsSource, bool inRetailDemo = false, bool shouldAutomaticallyShowLeaderboard = true)
		{
			return new WorkoutContainerContext(dependencies, await (dependencies?.Settings?.GetIsMetric()), await (dependencies?.Settings?.GetWeightKgs()), await (dependencies?.Preferences?.UserHeightMeters()), await (dependencies?.Preferences?.UserAge()), await (dependencies?.Preferences?.UserMale()) == true, workout, programId, challengeId, runningContext, analyticsSource, null, null, inRetailDemo, shouldAutomaticallyShowLeaderboard);
		}

		public static async Task<WorkoutContainerContext> Recover(IWorkoutContainerFactoryDependencies dependencies, Workout workout, AnalyticsSource analyticsSource)
		{
			bool isMetric = await (dependencies?.Preferences?.GetIsMetric());
			WorkoutRecoveryInfo recoveryInfo = await (dependencies?.RecoveryStateManager?.GetRecoveryInfo(dependencies.CurrentConsoleService?.ActiveConsole, dependencies.IFitApi, dependencies.FeatureFlagManager, dependencies.MultiReadResultSetter, isMetric));
			bool isMetric2 = isMetric;
			return new WorkoutContainerContext(dependencies, isMetric2, await (dependencies?.Preferences?.UserWeightKgs()), await (dependencies?.Preferences?.UserHeightMeters()), await (dependencies?.Preferences?.UserAge()), await (dependencies?.Preferences?.UserMale()) == true, workout, recoveryInfo, dependencies?.CurrentConsoleService?.ActiveConsole?.LatestBasicInfo, analyticsSource);
		}

		private ConsoleStateStats GetDefaultStats(IWorkoutContainerFactoryDependencies dependencies, Workout workout, Workout.WorkoutContext runningContext)
		{
			IFitnessConsole fitnessConsole = dependencies?.CurrentConsoleService?.ActiveConsole;
			ConsoleStateStatsFacade consoleStateStatsFacade = new ConsoleStateStatsFacade(dependencies?.MultiReadResultSetter, fitnessConsole?.FacadeRepository, dependencies?.CurrentConsoleService?.FitnessConsoleManager);
			EffortScoreCalculator effortScoreCalculator = new EffortScoreCalculator(dependencies?.IFitApi?.CurrentlyAuthenticatedUser, fitnessConsole, dependencies != null && dependencies.FeatureFlagManager?.IsLeaderboardDataUploadEnabledForWorkout(runningContext) == true, workout?.IsManual() ?? true);
			return new ConsoleStateStats(fitnessConsole, consoleStateStatsFacade, effortScoreCalculator);
		}
	}
	public class WorkoutContainerControlsHandler : BaseWorkoutContainerHandler
	{
		public WorkoutContainerControlsHandler(IWorkoutContainerFactoryDependencies dependencies)
			: base(dependencies)
		{
		}

		public override async Task<IWorkoutContainer> HandleRequest(WorkoutContainerContext context)
		{
			if (context.Context.Context == Workout.WorkoutContext.OnDemand)
			{
				context.Workout.ConvertInclineWorkoutToResistanceIfNecessary(base.Dependencies?.CurrentConsoleService?.ActiveConsole);
				context.Workout.ConvertWorkoutControlsForConsole(base.Dependencies?.CurrentConsoleService?.ActiveConsole);
			}
			context.Workout.Controls = GetControls(context.Workout, context.Context.Context);
			if (base.Successor != null && context.Workout.Controls != null)
			{
				return await base.Successor.HandleRequest(context);
			}
			return null;
		}

		private List<Workout.Control> GetControls(Workout workout, Workout.WorkoutContext context)
		{
			if (base.Dependencies?.CurrentConsoleService?.ActiveConsole == null)
			{
				return null;
			}
			List<Workout.Control> list;
			if (context == Workout.WorkoutContext.OnDemand)
			{
				list = workout.BoundedControls(UnitUtil.EnsureMps(SpeedUnit.Kph, base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo.MaxKph), base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo.MaxIncline, base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo.MinIncline, base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo.MaxResistanceLevel, base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo.MinGear, base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo.MaxGear);
				if (list.CountSafe() < 1 && workout.Category() != Workout.WorkoutCategory.Manual)
				{
					Log.Error("Workout", "Bounded control list was either null or empty. Could not create workout container.");
					return null;
				}
			}
			else
			{
				list = new List<Workout.Control>();
			}
			return list;
		}
	}
	public class WorkoutContainerHandler : BaseWorkoutContainerHandler, IDisposable
	{
		public WorkoutContainerHandler(IWorkoutContainerFactoryDependencies dependencies)
			: base(dependencies)
		{
		}

		public override async Task<IWorkoutContainer> HandleRequest(WorkoutContainerContext context)
		{
			if (context == null)
			{
				Log.Error("Workout", "WorkoutContainerContext was null");
				return null;
			}
			context.Container = await CreateContainer(context);
			if (base.Successor != null && context.Container != null)
			{
				return await base.Successor.HandleRequest(context);
			}
			return null;
		}

		private async Task<WorkoutContainer> CreateContainer(WorkoutContainerContext context)
		{
			WorkoutContainer workoutContainer = null;
			try
			{
				IMediaService mediaService = GetMediaService(context);
				workoutContainer = new WorkoutContainer(context.Runner, context.Stats, GetEstimates(context), context.Workout, context.ProgramId, context.ChallengeId, context.IsMetric, context.UserWeightKgs, context.UserHeightMeters, base.Dependencies?.Settings, context.WorkoutChangeLevel, base.Dependencies?.CurrentConsoleService, base.Dependencies?.Preferences, mediaService, base.Dependencies?.LockScreenMediaSettings, GetMusicInfoService(context, mediaService));
			}
			catch (Exception arg)
			{
				Log.Error("Workout", $"Error creating workout container: {arg}");
			}
			if (workoutContainer == null)
			{
				Log.Error("Workout", "Created WorkoutContainer was null");
				return null;
			}
			Mvx.TryResolve<IPlatformMediaVolumeService>(out var service);
			Mvx.TryResolve<IVolumeFacade>(out var service2);
			workoutContainer.InWorkoutSystemVolumeInteractor = new InWorkoutSystemVolumeInteractor(base.Dependencies?.CurrentConsoleService, base.Dependencies?.DeviceInfo, base.Dependencies?.MediaSettings, service, service2, 200L);
			workoutContainer.ConsoleConfiguration = ConfigurationFactory.Create(workoutContainer, base.Dependencies?.Connectivity, context.Context, base.Dependencies?.DeviceInfo, base.Dependencies?.IFitApi, base.Dependencies?.IFitGatewayApi, base.Dependencies?.ThemeService);
			if (!context.Workout.IsStrengthWorkout())
			{
				workoutContainer.ChartData = new InWorkoutChartDataProvider(base.Dependencies?.CurrentConsoleService?.ActiveConsole, base.Dependencies?.IFitApi, context.Workout, context.Context.Context, workoutContainer.ConsoleConfiguration, context.Stats, context.UserWeightKgs, context.UserHeightMeters, context.UserAge, context.UserMale, context.IsMetric, context.Runner, base.Dependencies?.CaptionParser, base.Dependencies?.HrTrainingService, base.Dependencies?.WorkoutFeatureService);
			}
			SetWorkoutChangeLevelMetrics(context, workoutContainer);
			return workoutContainer;
		}

		private IMediaService GetMediaService(WorkoutContainerContext context)
		{
			if (!Mvx.TryResolve<IMediaService>(out var service))
			{
				return null;
			}
			return service;
		}

		private IWorkoutMusicInfoService GetMusicInfoService(WorkoutContainerContext context, IMediaService media = null)
		{
			if (media != null && media.Music?.WorkoutHasLegacyPopMusic == true)
			{
				return new WorkoutPopMusicInfoService(media.Music.LegacyMix, base.Dependencies?.IFitApi);
			}
			return new WorkoutMusicInfoService(context.Workout, base.Dependencies.BlobCacheService.LocalMachine);
		}

		private RemainingWorkoutEstimates GetEstimates(WorkoutContainerContext context)
		{
			if (!context.Workout.IsVideoWorkout() || base.Dependencies?.VideoSyncService == null)
			{
				return new RemainingWorkoutEstimates(base.Dependencies?.CurrentConsoleService?.ActiveConsole, context.UserWeightKgs, context.UserHeightMeters, context.UserAge, context.UserMale, context.Workout, context.Runner.WarmUp, context.Runner.CoolDown);
			}
			return new RemainingVideoWorkoutEstimates(base.Dependencies.VideoSyncService, base.Dependencies?.CurrentConsoleService?.ActiveConsole, context.UserWeightKgs, context.UserHeightMeters, context.UserAge, context.UserMale, context.Workout, context.Runner.WarmUp, context.Runner.CoolDown);
		}

		private void SetWorkoutChangeLevelMetrics(WorkoutContainerContext context, WorkoutContainer workoutContainer)
		{
			if (context.WorkoutChangeLevel != null && workoutContainer?.Stats?.RunningStats != null)
			{
				context.WorkoutChangeLevel.InWorkoutMetricsManager = workoutContainer.Stats.RunningStats.InWorkoutMetrics;
			}
		}

		public void Dispose()
		{
			base.Dependencies?.Dispose();
		}
	}
	public class WorkoutContainerRecoveryHandler : BaseWorkoutContainerHandler
	{
		public WorkoutContainerRecoveryHandler(IWorkoutContainerFactoryDependencies dependencies)
			: base(dependencies)
		{
		}

		public override async Task<IWorkoutContainer> HandleRequest(WorkoutContainerContext context)
		{
			if (context.Container != null)
			{
				context.Container.IsRecoveryWorkout = true;
				if (context.Container.Console.ChangeManager.Decorators.FirstOrDefault((IFitnessValueDecorator arg) => arg is ICalorieMultiplierRecoverable) is ICalorieMultiplierRecoverable calorieMultiplierRecoverable && context.RecoveryInfo?.CalorieMultiplierRecoveryInfo != null)
				{
					calorieMultiplierRecoverable.Recover(context.RecoveryInfo.CalorieMultiplierRecoveryInfo);
				}
				if (context.Container.Workout.IsVideoWorkout() && (context.RecoveryInfo?.LastVideoTimeSeconds.HasValue ?? false))
				{
					Log.Trace("Workout", string.Format("{0} recovering workout at time {1}", "WorkoutContainerRecoveryHandler", context.RecoveryInfo.LastVideoTimeSeconds));
					base.Dependencies?.Media?.Video?.PreBufferedVideoPlayer?.RecoverVideo(context.RecoveryInfo.LastVideoTimeSeconds.Value);
				}
				else
				{
					Log.Trace("Workout", "WorkoutContainerRecoveryHandler not recovering, no recovery time found");
				}
			}
			if (base.Successor != null)
			{
				return await base.Successor.HandleRequest(context);
			}
			return context.Container;
		}
	}
	public class WorkoutContainerRunnerHandler : BaseWorkoutContainerHandler
	{
		public WorkoutContainerRunnerHandler(IWorkoutContainerFactoryDependencies dependencies)
			: base(dependencies)
		{
		}

		public override async Task<IWorkoutContainer> HandleRequest(WorkoutContainerContext context)
		{
			context.Runner = CreateRunner(context);
			if (base.Successor != null && context.Runner != null)
			{
				return await base.Successor.HandleRequest(context);
			}
			return null;
		}

		private IWorkoutRunner CreateRunner(WorkoutContainerContext context)
		{
			IWorkoutRunner result = null;
			IObservable<bool> whenIsLoading = WhenIsLoadingChanged();
			ConsoleType? consoleType = base.Dependencies?.CurrentConsoleService?.ActiveConsole?.ConsoleInfo?.MachineType;
			IFitnessConsole console = base.Console;
			if (console != null)
			{
				IConsoleInfo consoleInfo = console.ConsoleInfo;
				if (consoleInfo != null)
				{
					_ = consoleInfo.MachineType;
					if (0 == 0)
					{
						if (base.Dependencies?.LocalSettings == null)
						{
							return null;
						}
						try
						{
							Workout warmup = WorkoutResolver.Warmup(consoleType.Value, context.IsMetric, base.Dependencies.WorkoutSettings.WarmUpSeconds, GetInitialIncline(context.Workout));
							Workout cooldown = WorkoutResolver.Cooldown(consoleType.Value, context.IsMetric, 600);
							if (base.Dependencies?.WorkoutRunnerFactory != null && base.Dependencies?.CompetitionService != null)
							{
								base.Dependencies.CompetitionService.SetConsoleStateStats(context.Stats);
								result = base.Dependencies.WorkoutRunnerFactory.CreateWorkoutRunner(base.Dependencies?.CurrentConsoleService?.ActiveConsole, context.IsMetric, context.UserWeightKgs, context.UserAge, context.UserMale, context.Workout, context.Context, base.Dependencies.CompetitionService, base.Dependencies.HrTrainingService, base.Dependencies.WorkoutFeatureService, base.Dependencies.CurrentConsoleService.IsCurrentConsoleClub, base.Dependencies.IFitApi.HasLoggedInUser, warmup, cooldown, whenIsLoading, context.RecoveryInfo?.WolfGeneratedId);
							}
						}
						catch (Exception arg)
						{
							Log.Error("Workout", $"Exception occurred creating workout parts: {arg}");
							return null;
						}
						return result;
					}
				}
			}
			return null;
		}

		private double? GetInitialIncline(Workout workout)
		{
			double? result = null;
			if (workout.Title?.Equals(Workout.ManualWorkoutTitle) == true)
			{
				return workout.Controls.FirstOrDefault((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline && x.At.Equals(0.0))?.Value;
			}
			return result;
		}

		private IObservable<bool> WhenIsLoadingChanged()
		{
			return (base.Dependencies?.Media?.Video?.PreBufferedVideoPlayer)?.WhenIsLoadingChanged;
		}
	}
	public class WorkoutContainerSmartAdjust : BaseWorkoutContainerHandler
	{
		public WorkoutContainerSmartAdjust(IWorkoutContainerFactoryDependencies dependencies)
			: base(dependencies)
		{
		}

		public override async Task<IWorkoutContainer> HandleRequest(WorkoutContainerContext context)
		{
			bool recoveryWorkout = base.Dependencies.CurrentConsoleService.ActiveConsole.LatestBasicInfo?.IsInRecoverableWorkout() ?? false;
			if (base.Dependencies != null)
			{
				base.Dependencies.WorkoutFeatureService.WorkoutStarting(context.Workout, context.Context.Context, base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo?.MachineType ?? ConsoleType.None, base.Dependencies.PersonalTrainingSettings.ActivePulseEnabled, base.Dependencies.PersonalTrainingSettings.SmartAdjustEnabled, recoveryWorkout, context.Workout.IsVideoWorkout());
				if (base.Dependencies.WorkoutFeatureService.IsSmartAdjustAvailableInWorkout())
				{
					ChangeLevelFactory changeLevelFactory = new ChangeLevelFactory(base.Dependencies.InAppNotificationService, base.Dependencies.WorkoutFeatureService, context.Workout, context.IsMetric, base.Dependencies.CurrentConsoleService.ActiveConsole);
					context.WorkoutChangeLevel = new WorkoutChangeLevel(changeLevelFactory, base.Dependencies.WorkoutFeatureService, base.Dependencies.InAppNotificationService, base.Dependencies.CurrentConsoleService.ActiveConsole, context.Workout, context.IsMetric);
					context.Runner.WorkoutChangeLevel = context.WorkoutChangeLevel;
					context.Runner.HRTrainingService.SoftwareNumber = base.Dependencies.DeviceInfo.SoftwareNumber;
					context.Runner.HRTrainingService.ConsoleType = base.Dependencies.CurrentConsoleService.ActiveConsole.ConsoleInfo?.MachineType ?? ConsoleType.None;
				}
			}
			if (base.Successor != null)
			{
				return await base.Successor.HandleRequest(context);
			}
			return context.Container;
		}
	}
	public class WorkoutContainerStateHandler : BaseWorkoutContainerHandler
	{
		public WorkoutContainerStateHandler(IWorkoutContainerFactoryDependencies dependencies)
			: base(dependencies)
		{
		}

		public override async Task<IWorkoutContainer> HandleRequest(WorkoutContainerContext context)
		{
			if (context.Workout == null)
			{
				Log.Error("Workout", "Trying to create workout container with null workout.");
				return null;
			}
			Log.Trace("Workout", "Creating workout container");
			Log.Trace("Workout", "Is Metric: " + context.IsMetric);
			Log.Trace("Workout", "User Weight Kgs: " + context.UserWeightKgs);
			Log.Trace("Workout", "Workout Id: " + context.Workout.Id);
			if (base.Dependencies?.CurrentConsoleService?.ActiveConsole == null)
			{
				Log.Error("Workout", "Trying to create workout container with null console.");
				return null;
			}
			if (base.Dependencies?.CurrentConsoleService?.ActiveConsole?.ConsoleInfo == null)
			{
				Log.Error("Workout", "Trying to create workout container with null console info.");
				return null;
			}
			if (base.Successor != null)
			{
				return await base.Successor.HandleRequest(context);
			}
			return null;
		}
	}
