namespace Wolf.Core.Services.WorkoutContainer.Pages
{
	public class ConstantWattsModel : MvxNotifyPropertyChanged, IDisposable
	{
		private readonly IReadWriteFacadeFactoryDependencies facadeFactoryDependencies;

		private readonly IDisposable targetWattsChangedSub;

		private readonly IDisposable toggleConstantWattsModeChangedSub;

		private int _targetWattsValue = 100;

		private bool _constantWattsEnabled;

		private bool _increaseWattsAvailable = true;

		private bool _decreaseWattsAvailable = true;

		public int MinTarget => 50;

		public int MaxTarget => 250;

		public int StepInterval => 5;

		public int TargetWattsValue
		{
			get
			{
				return _targetWattsValue;
			}
			set
			{
				_targetWattsValue = value;
				if (_targetWattsValue >= MaxTarget)
				{
					IncreaseWattsAvailable = false;
				}
				else if (_targetWattsValue <= MinTarget)
				{
					DecreaseWattsAvailable = false;
				}
				else if (!IncreaseWattsAvailable)
				{
					IncreaseWattsAvailable = true;
				}
				else if (!DecreaseWattsAvailable)
				{
					DecreaseWattsAvailable = true;
				}
				RaisePropertyChanged("TargetWattsValue");
			}
		}

		public bool ConstantWattsEnabled
		{
			get
			{
				return _constantWattsEnabled;
			}
			set
			{
				_constantWattsEnabled = value;
				RaisePropertyChanged("ConstantWattsEnabled");
			}
		}

		public bool IncreaseWattsAvailable
		{
			get
			{
				return _increaseWattsAvailable;
			}
			set
			{
				if (value != _increaseWattsAvailable)
				{
					_increaseWattsAvailable = value;
					RaisePropertyChanged("IncreaseWattsAvailable");
				}
			}
		}

		public bool DecreaseWattsAvailable
		{
			get
			{
				return _decreaseWattsAvailable;
			}
			set
			{
				if (value != _decreaseWattsAvailable)
				{
					_decreaseWattsAvailable = value;
					RaisePropertyChanged("DecreaseWattsAvailable");
				}
			}
		}

		public ConstantWattsModel(IReadWriteFacadeFactoryDependencies facadeFactoryDependencies)
		{
			this.facadeFactoryDependencies = facadeFactoryDependencies;
			targetWattsChangedSub = (from x in facadeFactoryDependencies.WattGoalFacade.ObserveWattGoalChanges()
				select x.Current).Subscribe(UpdatedTargetWatts);
			toggleConstantWattsModeChangedSub = (from x in facadeFactoryDependencies.IsConstantWattsModeFacade.ObserveIsConstantWattsModeChanges()
				select x.Current).Subscribe(UpdateConstantWattsEnabled);
		}

		public void RequestConstantWattsChange(bool enable)
		{
			Log.Debug("CONSTANT_WATTS", $"Requesting constant watts change to {enable}");
			facadeFactoryDependencies.IsConstantWattsModeFacade.SetIsConstantWattsMode(enable);
			ConstantWattsEnabled = enable;
			if (enable)
			{
				RequestTargetWattsChange(_targetWattsValue);
			}
		}

		public void RequestTargetWattsChange(int target)
		{
			if (ConstantWattsEnabled && target >= MinTarget && target <= MaxTarget)
			{
				Log.Debug("CONSTANT_WATTS", $"Requesting Target watts change to {target}");
				facadeFactoryDependencies.WattGoalFacade.SetWattGoal(target);
			}
		}

		private void UpdateConstantWattsEnabled(bool enabled)
		{
			Log.Debug("CONSTANT_WATTS", $"Machine returned constant watts enabled as {enabled}");
			ConstantWattsEnabled = enabled;
		}

		private void UpdatedTargetWatts(int watts)
		{
			Log.Debug("CONSTANT_WATTS", $"Machine returned target watts as {watts}");
			TargetWattsValue = watts;
		}

		public void Dispose()
		{
			targetWattsChangedSub?.Dispose();
			toggleConstantWattsModeChangedSub?.Dispose();
		}
	}
}
