	public class CurrentUserPositionUpdate : UserPostionUpdateBase
	{
		public CurrentUserPositionUpdate(IWorkoutContainer workoutContainer, string userId)
			: base(workoutContainer, userId)
		{
		}

		protected override void SubscribeForDistanceTimeChange()
		{
			ICurrentDistanceFacade currentDistanceFacade = Mvx.Resolve<ICurrentDistanceFacade>();
			updateSub = (from x in currentDistanceFacade.ObserveMeterChanges()
				select x.Current).Subscribe(delegate(double x)
			{
				base.Second = workoutContainer.Console.LatestBasicInfo.TimeSeconds;
				base.Meter = x;
				base.Location = workoutContainer.Workout.Geo.Path.LatLngAtMeter(x).ToGoogleLatLng();
			});
		}
	}
	public interface IUserPositionUpdate : IMvxNotifyPropertyChanged, INotifyPropertyChanged, IDisposable
	{
		double Second { get; }

		double Meter { get; }

		string UserId { get; }

		iFit.Api.Google.LatLng Location { get; }
	}
	public abstract class UserPostionUpdateBase : MvxNotifyPropertyChanged, IUserPositionUpdate, IMvxNotifyPropertyChanged, INotifyPropertyChanged, IDisposable
	{
		private const string nullUserId = "non-logged-in-user-id";

		protected IWorkoutContainer workoutContainer;

		protected IDisposable inRunningModeSub;

		protected IDisposable notInRunningModeSub;

		protected IDisposable workoutCompletedSub;

		protected IDisposable updateSub;

		protected bool isInRunningMode;

		private iFit.Api.Google.LatLng _location = new iFit.Api.Google.LatLng();

		private double _meter;

		private double _second;

		public string UserId { get; protected set; }

		public iFit.Api.Google.LatLng Location
		{
			get
			{
				return _location;
			}
			protected set
			{
				if (_location.IsUnknown || _location.GetDistanceTo(value) > 1.0)
				{
					_location = value;
					RaisePropertyChanged("Location");
				}
			}
		}

		public double Meter
		{
			get
			{
				return _meter;
			}
			protected set
			{
				if (value.AlmostEqual(_meter, 0.001))
				{
					_meter = value;
					RaisePropertyChanged("Meter");
				}
			}
		}

		public double Second
		{
			get
			{
				return _second;
			}
			protected set
			{
				if (value.AlmostEqual(_second, 0.001))
				{
					_second = value;
					RaisePropertyChanged("Second");
				}
			}
		}

		protected UserPostionUpdateBase(IWorkoutContainer workoutContainer, string userId)
		{
			this.workoutContainer = workoutContainer;
			UserId = (string.IsNullOrEmpty(userId) ? "non-logged-in-user-id" : userId);
			inRunningModeSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Workout).Subscribe(delegate
			{
				isInRunningMode = true;
			});
			notInRunningModeSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current != ConsoleState.Workout).Subscribe(delegate
			{
				isInRunningMode = false;
			});
			workoutCompletedSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WorkoutResults || x.Current == ConsoleState.Idle || x.Current == ConsoleState.Sleep).Subscribe(delegate
			{
				Dispose();
			});
			SubscribeForDistanceTimeChange();
		}

		public void Dispose()
		{
			inRunningModeSub?.Dispose();
			notInRunningModeSub?.Dispose();
			workoutCompletedSub?.Dispose();
			updateSub?.Dispose();
		}

		protected abstract void SubscribeForDistanceTimeChange();
	}
}
