	public class SpeedSlider : WorkoutSliderBase
	{
		private readonly IKphFacade kphFacade;

		public override double MetricStepInterval => 0.1;

		public override string DisplayPrecision => "0.0";

		public override string MetricLabel
		{
			get
			{
				if (workoutContainer?.IsMetric != true)
				{
					return Wolf.Core.Resources.AppStrings.mph;
				}
				return Wolf.Core.Resources.AppStrings.kph;
			}
		}

		public override FitnessValue MetricType => FitnessValue.Kph;

		public override double CurrentMetric => (workoutContainer?.Console?.LatestBasicInfo.Kph).GetValueOrDefault();

		public override bool RequiresKph => true;

		protected override Action<double, bool> UpdateControl => UpdateKph;

		protected override double LatestBasicInfoMetric => workoutContainer?.Console?.LatestBasicInfo.Kph ?? 2.0;

		public override Workout.Control.ControlType ControlType => Workout.Control.ControlType.Mps;

		public SpeedSlider(IWorkoutContainer container)
			: base(container)
		{
			UpdateMetricVsStandard(container.IsMetric);
			base.MetricValue = base.Minimum;
			UpdateWithCurrentState();
			kphFacade = Mvx.Resolve<IKphFacade>();
		}

		protected override IObservable<FitnessValueChange<double>> CreateMetricObservable()
		{
			return kphFacade.ObserveKphChanges();
