		{
			kphFacade?.SetKph(newValue);
		}

		protected override double ConvertValueToConsole(double val)
		{
			if (!workoutContainer.IsMetric)
			{
				val = UnitUtil.EnsureKph(SpeedUnit.Mph, val);
			}
			return val;
		}

		protected override double ConvertValueFromConsole(double val)
		{
			if (!workoutContainer.IsMetric)
			{
				val = UnitUtil.EnsureMph(SpeedUnit.Kph, val);
			}
			return val;
		}

		protected void UpdateMetricVsStandard(bool isMetric)
		{
			base.Minimum = (isMetric ? workoutContainer.Console.ConsoleInfo.MinKph : UnitUtil.EnsureMph(SpeedUnit.Kph, workoutContainer.Console.ConsoleInfo.MinKph));
			base.Maximum = (isMetric ? workoutContainer.Console.ConsoleInfo.MaxKph : UnitUtil.EnsureMph(SpeedUnit.Kph, workoutContainer.Console.ConsoleInfo.MaxKph));
		}
	}
	public abstract class WorkoutSliderBase : MvxNotifyPropertyChanged, IWorkoutSlider, IMvxNotifyPropertyChanged, INotifyPropertyChanged, IHardwareDependent, IDisposable
	{
		private const int ControlUpdateTimeoutMs = 3000;

		private const int UserInitiatedChangePendingDefaultDelay = 800;

		protected double stepRound;

		protected IDisposable changeStateSub;

		protected IDisposable changeStateUnSub;

		protected IDisposable changeStatePauseSub;

		protected IDisposable completedSub;

		protected IDisposable metricChangedSub;

		protected IWorkoutContainer workoutContainer;

		private IDisposable userInitiatedChangeUpdateSub;

		private bool isPaused;

		private readonly Shire.Core.Util.AverageTimer timer;

		private double _minimum;

		private double _maximum;

		private int _numberOfMarks = 13;

		private int[] _markValues;

		private double _metricValue;

		private bool _userInitiatedChangePending;

		private readonly Subject<double> whenMetricValueChanged = new Subject<double>();

		private readonly Subject<bool> _whenUserInitiatedChangePendingChanged = new Subject<bool>();

		public IWorkoutChangeLevel WorkoutChangeLevel { get; set; }

		protected abstract Action<double, bool> UpdateControl { get; }

		protected abstract double LatestBasicInfoMetric { get; }

		public abstract double MetricStepInterval { get; }

		public abstract string DisplayPrecision { get; }

		public abstract string MetricLabel { get; }

		public abstract FitnessValue MetricType { get; }

		public abstract double CurrentMetric { get; }

		public virtual bool IsGoalBased => false;

		public virtual bool HideWhenTimeBased => false;

		public virtual bool HideWhenDistanceBased => false;

		public virtual bool RequiresKph => false;

		public virtual bool RequiresIncline => false;

		public virtual bool RequiresResistance => false;

		public virtual bool RequiresGear => false;

		public virtual bool RequiresHeartMonitor => false;

		public virtual bool RequiresVerticalGain => false;

		public virtual bool RequiresVerticalNet => false;

		public virtual IList<FitnessValue> RequiredFitnessValues => null;

		public abstract Workout.Control.ControlType ControlType { get; }

		public double Minimum
		{
			get
			{
				return _minimum;
			}
			set
			{
				if (!value.AlmostEqual(_minimum))
				{
					_minimum = value;
					UpdateSliderMarks();
				}
			}
		}

		public double Maximum
		{
			get
			{
				return _maximum;
			}
			set
			{
				if (!value.AlmostEqual(_maximum))
				{
					_maximum = value;
					UpdateSliderMarks();
				}
			}
		}

		public int NumberOfMarks
		{
			get
			{
				return _numberOfMarks;
			}
			set
			{
				double b = Math.Min(value, ValueRange);
				_numberOfMarks = (int)ValueRange.Clamp(2.0, b);
				UpdateSliderMarks();
			}
		}

		public int[] MarkValues => _markValues;

		public double MetricValue
		{
			get
			{
				return _metricValue;
			}
			protected set
			{
				if (!(Math.Abs(_metricValue - value) < 0.01))
				{
					_metricValue = value;
					whenMetricValueChanged.OnNext(_metricValue);
					RaisePropertyChanged("MetricValue");
				}
			}
		}

		public bool UserInitiatedChangePending
		{
			get
			{
				return _userInitiatedChangePending;
			}
			set
			{
				_userInitiatedChangePending = value;
				_whenUserInitiatedChangePendingChanged.OnNext(_userInitiatedChangePending);
				RaisePropertyChanged("UserInitiatedChangePending");
			}
		}

		public double ValueRange => Math.Max(0.0, Maximum - Minimum);

		public IObservable<double> WhenMetricValueChanged => whenMetricValueChanged;

		public IObservable<bool> WhenUserInitiatedChangePendingChanged => _whenUserInitiatedChangePendingChanged;

		protected WorkoutSliderBase(IWorkoutContainer container)
		{
			timer = new Shire.Core.Util.AverageTimer($"{MetricType}Timer", 1);
			stepRound = 1.0 / MetricStepInterval;
			workoutContainer = container;
			changeStateSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WarmUp || x.Current == ConsoleState.Workout || x.Current == ConsoleState.CoolDown).Subscribe(delegate
			{
				UpdateWithCurrentState();
				SubscribeToMetricChange();
				isPaused = false;
			});
			changeStateUnSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current != ConsoleState.WarmUp && x.Current != ConsoleState.Workout && x.Current != ConsoleState.CoolDown && x.Current != ConsoleState.Paused).Subscribe(delegate
			{
				metricChangedSub?.Dispose();
				isPaused = false;
			});
			changeStatePauseSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Paused).Subscribe(delegate
			{
				isPaused = true;
			});
			completedSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.WorkoutResults || x.Current == ConsoleState.Idle || x.Current == ConsoleState.Sleep).Subscribe(delegate
			{
				isPaused = true;
			});
		}

		private void SubscribeToMetricChange()
		{
			metricChangedSub?.Dispose();
			metricChangedSub = CreateMetricObservable().Subscribe(delegate(FitnessValueChange<double> x)
			{
				UpdateValue(x.Current);
			}, delegate(Exception ex)
			{
				Log.Error("Workout", "Could not update " + MetricType.ToString() + " slider value", ex);
			});
		}

		protected virtual void UpdateWithCurrentState()
		{
			UpdateValue(LatestBasicInfoMetric);
		}

		private bool RequestValueChange(double newValue)
		{
			newValue = ConvertValueToConsole(newValue);
			double a = ConvertValueToConsole(MetricValue);
			if (a.AlmostEqual(newValue, 1) || LatestBasicInfoMetric.AlmostEqual(newValue, 1))
			{
				return false;
			}
			UpdateControl?.Invoke(newValue, arg2: true);
			return true;
		}

		protected void UpdateValue(double newValue)
		{
			MetricValue = ConvertValueFromConsole(newValue);
		}

		protected virtual double ConvertValueToConsole(double val)
		{
			return val;
		}

		protected virtual double ConvertValueFromConsole(double val)
		{
			return val;
		}

		public void RequestUserInitiatedChange(double newValue)
		{
			if (isPaused || UserInitiatedChangePending)
			{
				return;
			}
			double originalValue = MetricValue;
			newValue = ClampAndRound(newValue);
			Log.Trace("Workout", $"User initiated {MetricType.ToString()} change from {originalValue} to {newValue}");
			UserInitiatedChangePending = true;
			timer.Start();
			if (RequestValueChange(newValue))
			{
				userInitiatedChangeUpdateSub = CreateMetricObservable()?.Where((FitnessValueChange<double> x) => x?.Current.AlmostEqual(ConvertValueToConsole(newValue), 1) ?? false)?.Timeout(TimeSpan.FromMilliseconds(3000.0))?.Take(1)?.Subscribe(delegate
				{
					timer.End($"Completed {MetricType.ToString()} change from {originalValue} to {newValue}");
					SetUserInitiatedChangedPending(value: false, 800);
				}, delegate(Exception error)
				{
					timer.End($"Error performing {MetricType.ToString()} change from {originalValue} to {newValue}: {error}");
					SetUserInitiatedChangedPending(value: false, 800);
					UpdateWithCurrentState();
				});
			}
			else
			{
				timer.End($"Did not perform {MetricType.ToString()} change from {originalValue} to {newValue}.");
				SetUserInitiatedChangedPending(value: false, 800);
				UpdateWithCurrentState();
			}
			WorkoutChangeLevel?.UserChangingControl(MetricType, ConvertValueToConsole(newValue));
		}

		public async Task SetUserInitiatedChangedPending(bool value, int delayMiliseconds)
		{
			await Task.Delay(delayMiliseconds);
			UserInitiatedChangePending = value;
		}

		public void StepUp()
		{
			if (!isPaused)
			{
				double newValue = ClampAndRound(_metricValue + MetricStepInterval);
				RequestUserInitiatedChange(newValue);
			}
		}

		public void StepDown()
		{
			if (!isPaused)
			{
				double newValue = ClampAndRound(_metricValue - MetricStepInterval);
				RequestUserInitiatedChange(newValue);
			}
		}

		public double ClampAndRound(double newValue)
		{
			double num = newValue.Clamp(Minimum, Maximum);
			num = Math.Round(num * stepRound) / stepRound;
			if (!double.IsNaN(num))
			{
				return num;
			}
			return Minimum;
		}

		private void UpdateSliderMarks()
		{
			if (NumberOfMarks > 0)
			{
				_markValues = Enumerable.Repeat((int)Minimum, NumberOfMarks).ToArray();
				for (int i = 1; i < NumberOfMarks; i++)
				{
					double num = (double)i / (double)(NumberOfMarks - 1);
					_markValues[i] += (int)Math.Round(num * ValueRange);
				}
			}
		}

		private void WarnIfChangesTakingTooLong()
		{
			IWorkoutRunner workoutRunner = workoutContainer.WorkoutRunner;
			if (workoutRunner != null && workoutRunner.IsRunning && workoutRunner.HasUserOverrideDecoratorOfType(MetricType, out var _) && timer.Average.NumberOfSamplings >= 2 && !(timer.Average.CurrentAverage < workoutRunner.AutoChangeThreshold.TotalMilliseconds))
			{
				IDeviceInformation deviceInformation = Mvx.Resolve<IDeviceInformation>();
				if ((deviceInformation == null || !deviceInformation.IsBuiltIn) && Mvx.TryResolve<IDialogPresenter>(out var service))
				{
					ConfirmationInitializationData arbitraryData = new ConfirmationInitializationData(Wolf.Core.Resources.AppStrings.slow_slider_title, Wolf.Core.Resources.AppStrings.slow_slider_text, null, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.close.ToUpper(), OnConfirmActionTiming.AfterClose);
					service?.ShowDialog<SimpleConfirmationDialogViewModel>(null, showSafely: true, arbitraryData);
				}
			}
		}

		public void HandleUserTouchedSlider()
		{
			Task.Run(delegate
			{
				EnableUserOverrides();
			});
		}

		private void EnableUserOverrides()
		{
			workoutContainer?.WorkoutRunner?.EnableUserOverride(ControlType);
		}

		public virtual void Dispose()
		{
			changeStateSub?.Dispose();
			changeStateUnSub?.Dispose();
			changeStatePauseSub?.Dispose();
			completedSub?.Dispose();
			metricChangedSub?.Dispose();
			userInitiatedChangeUpdateSub?.Dispose();
			workoutContainer = null;
			WorkoutChangeLevel = null;
		}

		protected abstract IObservable<FitnessValueChange<double>> CreateMetricObservable();
	}
}
