	public abstract class MetricBase : MvxNotifyPropertyChanged, IMetric, IHardwareDependent, IDisposable
	{
		private IconType _icon;

		private IconType _hudIcon = IconType.None;

		private double _metricValue;

		private string _metric = Wolf.Core.Resources.AppStrings.blank_stat;

		private string _target;

		private string _label;

		private string _unitLabel;

		private string _labelWithUnits;

		private string _phoneLabel;

		private string _compactLabel;

		private string _mediumLabel;

		private string _subtitleLabel;

		private string _extendedLabel;

		protected IWorkoutContainer workoutContainer;

		protected IDisposable isMetricSub;

		protected IDisposable stateSub;

		protected IDisposable completedSub;

		protected IDisposable sub;

		protected IReadWriteFacadeFactoryDependencies facadeFactoryDependencies;

		protected virtual int DecimalDigits => 2;

		protected virtual bool ShouldTruncateValue => false;

		public IconType Icon
		{
			get
			{
				return _icon;
			}
			protected set
			{
				if (_icon != value)
				{
					_icon = value;
					RaisePropertyChanged("Icon");
				}
			}
		}

		public IconType HudIcon
		{
			get
			{
				return _hudIcon;
			}
			protected set
			{
				if (_hudIcon != value)
				{
