		protected abstract FitnessValue MetricTarget { get; }

		public virtual bool IsGoalBased => false;

		public virtual bool HideWhenTimeBased => false;

		public virtual bool HideWhenDistanceBased => false;

		public virtual bool RequiresKph => false;

		public virtual bool RequiresIncline => false;

		public virtual bool RequiresVerticalGain => false;

		public virtual bool RequiresVerticalNet => false;

		public virtual bool RequiresResistance => false;

		public virtual bool RequiresGear => false;

		public virtual bool RequiresHeartMonitor => false;

		public virtual IList<FitnessValue> RequiredFitnessValues => null;

		public virtual bool HideInCoolDown => false;

		public MetricStats CurrentStateStats
		{
			get
			{
				switch (workoutContainer?.Console?.LatestBasicInfo?.CurrentState)
				{
				case ConsoleState.WarmUp:
					return workoutContainer.Stats?.WarmUpStats;
				case ConsoleState.Workout:
				case ConsoleState.PauseOverride:
					return workoutContainer.Stats?.RunningStats;
				case ConsoleState.CoolDown:
					return workoutContainer.Stats?.CoolDownStats;
				default:
					return null;
				}
			}
		}

		protected virtual double TimeSeconds
		{
			get
			{
				ConsoleState? consoleState = workoutContainer?.Console?.LatestBasicInfo?.CurrentState;
				if (!consoleState.HasValue)
				{
					return 0.0;
				}
				ConsoleState value = consoleState.Value;
				if (value == ConsoleState.WarmUp || value == ConsoleState.CoolDown)
				{
					int num = ((value == ConsoleState.WarmUp) ? workoutContainer.Console.LatestBasicInfo.WarmUpTimeoutSeconds : workoutContainer.Console.LatestBasicInfo.CoolDownTimeoutSeconds);
					return num - workoutContainer.Console.LatestBasicInfo.TimeSeconds;
				}
				return workoutContainer.Console.LatestBasicInfo.RunningTime;
			}
		}

		protected MetricBase(IWorkoutContainer workoutContainer)
		{
			this.workoutContainer = workoutContainer;
			facadeFactoryDependencies = Mvx.Resolve<IReadWriteFacadeFactoryDependencies>();
			isMetricSub = workoutContainer?.ToObservable<bool>("IsMetric")?.SubscribeWithErrorLogging(delegate
			{
				UpdateEverything();
			});
			stateSub = workoutContainer?.Console?.WhenStateChanged?.Where((StateChange x) => x.Current == ConsoleState.WarmUp || x.Current == ConsoleState.Workout || x.Current == ConsoleState.CoolDown)?.SubscribeWithErrorLogging(delegate
			{
				UpdateEverything();
			});
			completedSub = workoutContainer?.Console?.WhenStateChanged?.Where((StateChange x) => x.Current == ConsoleState.WorkoutResults || x.Current == ConsoleState.Idle || x.Current == ConsoleState.Sleep)?.SubscribeWithErrorLogging(delegate
			{
				Dispose();
			});
			UpdateEverything();
			SetSubscription();
		}

		protected void UpdateEverything()
		{
			SetLabels();
			UpdateDynamicLabels();
			SetValues();
		}

		protected virtual void UpdateDynamicLabels()
		{
			if (!string.IsNullOrWhiteSpace(UnitLabel))
			{
				LabelWithUnits = $"{Label} ({UnitLabel})";
			}
			else
			{
				LabelWithUnits = Label;
			}
			UpdatePhoneLabel();
			UpdateCompactLabel();
			UpdateMediumLabel();
		}

		protected virtual void UpdatePhoneLabel()
		{
			PhoneLabel = Label;
		}

		protected virtual void UpdateCompactLabel()
		{
			CompactLabel = LabelWithUnits;
		}

		protected virtual void UpdateMediumLabel()
		{
			MediumLabel = LabelWithUnits;
		}

		protected bool CheckIfCurrentStateStatsIsNull()
		{
			if (CurrentStateStats == null)
			{
				Metric = Wolf.Core.Resources.AppStrings.blank_stat;
				return true;
			}
			return false;
		}

		public virtual void Dispose()
		{
			sub?.Dispose();
			sub = null;
			isMetricSub?.Dispose();
			isMetricSub = null;
			stateSub?.Dispose();
			stateSub = null;
			completedSub?.Dispose();
			completedSub = null;
		}

		protected abstract IObservable<FitnessValueChange<double>> ObserveMetricChanges();

		protected virtual void SetSubscription()
		{
			sub = (from x in ObserveMetricChanges()
				where workoutContainer.Console.LatestBasicInfo.CurrentState != ConsoleState.Paused
				select x)?.Select((FitnessValueChange<double> x) => x.Current)?.SubscribeWithErrorLogging(delegate(double x)
			{
				SetValues(x);
			});
		}

		protected virtual bool WarmupCooldownValueNotAvailable(string metricWarmupCooldownMessage = "")
		{
			if (metricWarmupCooldownMessage == "")
			{
				metricWarmupCooldownMessage = Wolf.Core.Resources.AppStrings.blank_stat;
			}
			IWorkoutContainer obj = workoutContainer;
			if (obj != null && obj.Console?.LatestBasicInfo?.InWarmupCooldown() == true)
			{
				Metric = metricWarmupCooldownMessage;
				return true;
			}
			return false;
		}

		protected string MetricString(double metricValue)
		{
			double num = UnitUtil.Round(metricValue, DecimalDigits);
			if (ShouldTruncateValue)
			{
				num = UnitUtil.Truncate(metricValue, DecimalDigits);
			}
			return num.ToString($"F{DecimalDigits}");
		}

		protected string ReformatSlashes(string originalString)
		{
			if (originalString == null || originalString.Length == 0)
			{
				return originalString;
			}
			return originalString.Replace("/", "\u00a0⁄\u00a0");
		}

		protected abstract void SetLabels();

		protected abstract Task SetValues(double? value = null);
	}
	public static class MetricUtils
	{
		private static readonly List<Type> InclineMetricTypes = new List<Type>
		{
			typeof(InclineMetricBase),
			typeof(ElevationMetricBase),
			typeof(IntervalAverageInclineMetric)
		};

		private static readonly List<Type> ResistanceMetricTypes = new List<Type>
		{
			typeof(ResistanceMetricBase),
			typeof(IntervalAverageResistanceMetric)
		};

		public static bool MetricIsInclineDependent(this IMetric metric)
		{
			if (metric == null)
			{
				return false;
			}
			return InclineMetricTypes.Any((Type t) => t.IsAssignableFrom(metric.GetType()));
		}

		public static bool MetricIsResistanceDependent(this IMetric metric)
		{
			if (metric == null)
			{
				return false;
			}
			return ResistanceMetricTypes.Any((Type t) => t.IsAssignableFrom(metric.GetType()));
		}

		public static bool MetricIsAppropriateForConsole(this IMetric metric, IFitnessConsole console)
		{
			if (metric == null || console == null)
			{
				return false;
			}
			if (metric.MetricIsInclineDependent() && console.ConsoleInfo?.CanSetIncline != true)
			{
				return false;
			}
			if (metric.MetricIsResistanceDependent() && console.ConsoleInfo?.CanSetResistance != true)
			{
				return false;
			}
			return true;
		}
	}
}
