namespace Wolf.Core.Services.WorkoutContainer.Metrics.TotalProgress
{
	public class WorkoutProgressMetric : MetricBase
	{
		private const double WorkoutCompleteThreshold = 0.95;

		public new IconType Icon => IconType.WorkoutProgress;

		protected override FitnessValue MetricTarget => FitnessValue.CurrentTime;

		public override bool IsGoalBased => true;

		public WorkoutProgressMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected override IObservable<FitnessValueChange<double>> ObserveMetricChanges()
		{
			ICurrentTimeFacade currentTimeFacade = Mvx.Resolve<ICurrentTimeFacade>();
			return from x in currentTimeFacade.ObserveCurrentTimeChanges()
				select new FitnessValueChange<double>(x.Type, x.Old, x.Current);
		}

		protected override void SetLabels()
		{
			base.Label = Wolf.Core.Resources.AppStrings.total_progress;
		}

		protected override Task SetValues(double? value = null)
		{
			Task<int> result = Task.FromResult(0);
			if (WarmupCooldownValueNotAvailable())
			{
				return result;
			}
			double valueOrDefault = (workoutContainer?.Workout?.TargetValue).GetValueOrDefault();
			double num = 0.0;
			switch (workoutContainer?.Workout?.Target)
			{
			case Workout.TargetType.Seconds:
				num = (workoutContainer.Console?.LatestBasicInfo?.TimeSeconds).GetValueOrDefault();
				break;
			case Workout.TargetType.Meters:
				num = (workoutContainer.Console?.LatestBasicInfo?.DistanceMeters).GetValueOrDefault();
				break;
			}
			base.MetricValue = (valueOrDefault.AlmostEqual(0.0) ? 0.0 : (num / valueOrDefault));
			base.Metric = MetricString(base.MetricValue);
			if (workoutContainer?.Workout != null && base.MetricValue > 0.95)
			{
				workoutContainer.Workout.IsComplete = true;
			}
			return result;
		}
	}
}
namespace Wolf.Core.Services.WorkoutContainer.Metrics.Time
{
	public class TimeMetric : MetricBase
	{
		private const int JustHoursCutoff = 36000;

		private const int TimeStabilizationSeconds = 5;

		private readonly List<ConsoleState> allowedTimeMetricStates = new List<ConsoleState>
		{
			ConsoleState.Unknown,
			ConsoleState.WarmUp,
			ConsoleState.Workout,
			ConsoleState.CoolDown
		};

		private ConsoleState currentState;

		private DateTime currentStateStartTime;

		public new IconType Icon => IconType.TimeElapsed;

		protected override FitnessValue MetricTarget => FitnessValue.CurrentTime;

		public TimeMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected override IObservable<FitnessValueChange<double>> ObserveMetricChanges()
		{
			ICurrentTimeFacade currentTimeFacade = Mvx.Resolve<ICurrentTimeFacade>();
			return from x in currentTimeFacade.ObserveCurrentTimeChanges()
				select new FitnessValueChange<double>(x.Type, x.Old, x.Current);
		}

		protected override void SetLabels()
		{
			base.Label = Wolf.Core.Resources.AppStrings.flipper_elapsed_time;
			base.SubtitleLabel = Wolf.Core.Resources.AppStrings.flipper_elapsed_time;
			base.ExtendedLabel = Wolf.Core.Resources.AppStrings.flipper_elapsed_time;
		}

		protected override void UpdatePhoneLabel()
		{
			base.PhoneLabel = Wolf.Core.Resources.AppStrings.flipper_elapsed_time_phone;
		}

		protected override void UpdateCompactLabel()
		{
			base.CompactLabel = base.LabelWithUnits;
		}

		private void UpdateUnitLabel(double seconds)
		{
			if (seconds >= 36000.0)
			{
				base.UnitLabel = Wolf.Core.Resources.AppStrings.hrs;
			}
			else
			{
				base.UnitLabel = string.Empty;
			}
		}

		protected override Task SetValues(double? value = null)
		{
			ConsoleState valueOrDefault = (workoutContainer?.Console?.LatestBasicInfo?.CurrentState).GetValueOrDefault();
			if (allowedTimeMetricStates.Contains(valueOrDefault) && valueOrDefault != currentState)
			{
				currentState = valueOrDefault;
				currentStateStartTime = DateTime.UtcNow;
			}
			double valueOrDefault2 = (workoutContainer?.WorkoutRunner?.WorkoutElapsedSeconds).GetValueOrDefault();
			double num = ComputeSecondsValue(valueOrDefault2);
			int num2 = ElapsedTimeSince(currentStateStartTime);
			double val = (TimeSecondsHasStabilized(num, num2) ? num : ((double)num2));
			val = Math.Max(val, 0.0);
			UpdateUnitLabel(val);
			UpdateDynamicLabels();
			Workout.WorkoutContext valueOrDefault3 = (workoutContainer?.WorkoutRunner?.RunContext?.Context).GetValueOrDefault();
			if ((valueOrDefault3 != Workout.WorkoutContext.OnDemand && (double.IsNaN(valueOrDefault2) || valueOrDefault == ConsoleState.WarmUp)) || valueOrDefault == ConsoleState.CoolDown)
			{
				base.Metric = Wolf.Core.Resources.AppStrings.dashed_time;
			}
			else
			{
				base.Metric = ValueFormatters.AbbreviatedTimeFormatter.Format(val, 10);
			}
			return Task.FromResult(0);
		}

		private bool TimeSecondsHasStabilized(double consoleBasedElapsedTime, double secondsSinceLastStateChange)
		{
			if (secondsSinceLastStateChange > 5.0)
			{
				return true;
			}
			if (!(consoleBasedElapsedTime < 5.0))
			{
				return Math.Abs(consoleBasedElapsedTime - secondsSinceLastStateChange).IsSmaller(2.0, 0.1);
			}
			return true;
		}

		private int ElapsedTimeSince(DateTime startTime)
		{
			return (int)Math.Round((DateTime.UtcNow - startTime).TotalSeconds);
		}

		private double ComputeSecondsValue(double timeSecondsValue)
		{
			if (currentState == ConsoleState.WarmUp || currentState == ConsoleState.CoolDown)
			{
				double num = ConsoleStateTotalSeconds(currentState);
				return num - timeSecondsValue;
			}
			return timeSecondsValue;
		}

		private double ConsoleStateTotalSeconds(ConsoleState? consoleState)
		{
			double result = 0.0;
			if (consoleState == ConsoleState.WarmUp)
			{
				result = (workoutContainer?.Console?.LatestBasicInfo?.WarmUpTimeoutSeconds).GetValueOrDefault();
			}
			else if (consoleState == ConsoleState.CoolDown)
			{
				result = (workoutContainer?.Console?.LatestBasicInfo?.CoolDownTimeoutSeconds).GetValueOrDefault();
			}
			return result;
		}
	}
