namespace Wolf.Core.Services.WorkoutContainer.Metrics.Target
{
	public abstract class TargetBaseMetric : MetricBase
	{
		private double _targetValue;

		private double _currentValue;

		private readonly ICurrentTimeFacade currentTimeFacade;

		private IDisposable secondsMetricSubscription;

		protected double TargetValue
		{
			get
			{
				return _targetValue;
			}
			set
			{
				if (!value.Equals(_targetValue))
				{
					_targetValue = value;
					SetLabels();
					UpdateIconIfNecessary();
				}
			}
		}

		protected double CurrentValue
		{
			get
			{
				return _currentValue;
			}
			set
			{
				if (_currentValue != value)
				{
					_currentValue = value;
					UpdateIconIfNecessary();
				}
			}
		}

		protected string TargetString => Wolf.Core.Resources.AppStrings.target_value;

		protected TargetBaseMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
			currentTimeFacade = Mvx.Resolve<ICurrentTimeFacade>();
			if (currentTimeFacade != null)
			{
				secondsMetricSubscription = currentTimeFacade.ObserveCurrentTimeChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<int> x)
				{
					HandleTimeChange(x.Current);
				});
			}
		}

		private void HandleTimeChange(double at)
		{
			UpdateTargetValueIfNeeded(at);
		}

		private void UpdateIconIfNecessary()
		{
			if (CurrentValue < TargetValue)
			{
				IconType icon = (base.HudIcon = IconType.IncreaseIntensity);
				base.Icon = icon;
			}
			else if (CurrentValue >= TargetValue)
			{
				IconType icon = (base.HudIcon = IconType.AchievedIntensity);
				base.Icon = icon;
			}
		}

		public override void Dispose()
		{
			secondsMetricSubscription?.Dispose();
			secondsMetricSubscription = null;
			base.Dispose();
		}

		public abstract void UpdateTargetValueIfNeeded(double at);
	}
	public class TargetRPMMetric : TargetBaseMetric
	{
		protected readonly ControlsTracking RpmControlsTracking;

		protected override FitnessValue MetricTarget => FitnessValue.Rpm;

		protected override int DecimalDigits => 0;

		public override IList<FitnessValue> RequiredFitnessValues => new List<FitnessValue> { FitnessValue.Rpm };

		public TargetRPMMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
			List<Workout.Control> list = workoutContainer?.Workout?.TargetRPMControls ?? (from c in workoutContainer?.Workout?.Controls
				where c.Type == Workout.Control.ControlType.Rpm
				orderby c.At
				select c).ToList();
			if (!list.IsNullOrEmpty())
			{
				RpmControlsTracking = new ControlsTracking(list);
			}
			SetStartingTargetValue();
		}

		private void SetStartingTargetValue()
		{
			UpdateTargetValueIfNeeded(0.0);
		}

		protected override void SetLabels()
		{
			base.Label = ((base.TargetValue <= 0.0) ? Wolf.Core.Resources.AppStrings.no_target_rpm : Wolf.Core.Resources.AppStrings.target_rpm);
			base.Target = ((base.TargetValue <= 0.0) ? "" : string.Format(base.TargetString, MetricString(base.TargetValue)));
		}

		protected override Task SetValues(double? value = null)
		{
			Task<int> result = Task.FromResult(0);
			if (CheckIfCurrentStateStatsIsNull() || base.CurrentStateStats.RpmChanges.Count < 1)
			{
				return result;
			}
			double num = base.CurrentStateStats.RpmChanges.Last?.Value ?? 0.0;
			base.Metric = MetricString(num);
			base.CurrentValue = num;
			return result;
		}

		public override void UpdateTargetValueIfNeeded(double at)
		{
			if (RpmControlsTracking != null)
			{
				double value = RpmControlsTracking.FindControlNearestToTime(at).Value;
				base.TargetValue = value;
				SetLabels();
			}
		}

		protected override IObservable<FitnessValueChange<double>> ObserveMetricChanges()
		{
			IRpmFacade rpmFacade = Mvx.Resolve<IRpmFacade>();
			return from x in rpmFacade.ObserveRpmChanges()
				select new FitnessValueChange<double>(x.Type, x.Old, x.Current);
		}
	}
