	public class StrokesPerMinMetric : StrokesMetricBase
	{
		private IDisposable whenPauseOverrideSub;

		private IDisposable whenResumeRunningSub;

		private bool inPauseOverride;

		protected override int DecimalDigits => 0;

		public new IconType Icon => IconType.RPM;

		protected override FitnessValue MetricTarget => FitnessValue.StrokesPerMin;

		public StrokesPerMinMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
			whenPauseOverrideSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Old == ConsoleState.Workout && x.Current == ConsoleState.PauseOverride).Subscribe(delegate
			{
				inPauseOverride = true;
				base.Metric = MetricString(0.0);
			});
			whenResumeRunningSub = workoutContainer.Console.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Workout).Subscribe(delegate
			{
				inPauseOverride = false;
			});
		}

		protected override void SetLabels()
		{
			base.Label = Wolf.Core.Resources.AppStrings.flipper_stroke_per_min;
			base.SubtitleLabel = Wolf.Core.Resources.AppStrings.flipper_stroke_per_min;
			base.UnitLabel = "";
		}

		protected override Task SetValues(double? value = null)
		{
			Task<int> result = Task.FromResult(0);
			if (CheckIfCurrentStateStatsIsNull() || base.CurrentStateStats.StrokePerMinChanges.Count < 1)
			{
				return result;
			}
			if (inPauseOverride)
			{
				return result;
			}
			double metricValue = base.CurrentStateStats.StrokePerMinChanges.Last?.Value ?? 0.0;
			base.Metric = MetricString(metricValue);
			return result;
		}

		public override void Dispose()
		{
			base.Dispose();
			whenPauseOverrideSub?.Dispose();
			whenPauseOverrideSub = null;
			whenResumeRunningSub?.Dispose();
			whenResumeRunningSub = null;
		}
	}
}
