		}

		protected override Task SetValues(double? value = null)
		{
			double? num = (((!(workoutContainer?.Console?.ConsoleInfo?.MachineType.IsBeltBasedMachine())) ?? false) ? workoutContainer?.Console?.LatestBasicInfo?.ActualKph : workoutContainer?.Console?.LatestBasicInfo?.Kph);
			bool? flag = workoutContainer?.Console?.ConsoleInfo?.MachineType.IsBeltBasedMachine();
			double value2 = ((flag.HasValue && flag != true && (workoutContainer?.Console?.LatestBasicInfo?.Rpm).GetValueOrDefault() == 0) ? 0.0 : (value ?? num.GetValueOrDefault()));
			IWorkoutContainer obj = workoutContainer;
			double metricValue = ((obj != null && obj.IsMetric) ? UnitUtil.EnsureKph(SpeedUnit.Kph, value2, DecimalDigits) : UnitUtil.EnsureMph(SpeedUnit.Kph, value2, DecimalDigits));
			base.Metric = MetricString(metricValue);
