	public abstract class SpeedMetricBase : MetricBase
	{
		protected override int DecimalDigits => 1;

		public override bool RequiresKph => MetricTarget == FitnessValue.Kph;

		public SpeedMetricBase(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected override IObservable<FitnessValueChange<double>> ObserveMetricChanges()
		{
			Mvx.TryResolve<ICurrentConsoleService>(out var service);
			FitnessValue fitnessValue = ((service != null && !service.ConsoleType.IsBeltBasedMachine()) ? FitnessValue.ActualKph : FitnessValue.Kph);
			if (fitnessValue == FitnessValue.ActualKph)
			{
				IActualKphFacade actualKphFacade = Mvx.Resolve<IActualKphFacade>();
				return actualKphFacade.ObserveActualKphChanges();
			}
			IKphFacade kphFacade = Mvx.Resolve<IKphFacade>();
			return kphFacade.ObserveKphChanges();
		}
	}
