			double num = Math.Round(value2, 1, MidpointRounding.AwayFromZero);
			double num2 = (num.AlmostEqual(0.0) ? 0.0 : (3600.0 / num));
			base.UnitLabel = ReformatSlashes(FormattedUnitLabel(num2, workoutContainer?.IsMetric ?? false));
			UpdateDynamicLabels();
			base.Metric = ValueFormatters.AbbreviatedTimeFormatter.Format(num2, 1);
			return result;
		}
	}
	public class PaceMetric : PaceMetricBase
	{
