			base.Metric = ValueFormatters.SecondsFormatter.BlankValue;
		}

		protected override Task SetValues(double? value = null)
		{
			double value2 = value ?? (workoutContainer?.Console?.LatestBasicInfo?.Kph).GetValueOrDefault();
			double paceFrom = PaceMetricBase.GetPaceFrom(SpeedUnit.Kph, workoutContainer?.IsMetric ?? false, value2);
			base.UnitLabel = ReformatSlashes(FormattedUnitLabel(paceFrom, workoutContainer?.IsMetric ?? false));
			UpdateDynamicLabels();
			base.Metric = ValueFormatters.AbbreviatedTimeFormatter.Format(paceFrom, 1);
			return Task.FromResult(result: true);
		}
