	public abstract class PaceMetricBase : MetricBase
	{
		protected const int paceUnitCutoff = 3600;

		protected PaceMetricBase(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected string FormattedUnitLabel(double paceValueSeconds, bool isMetric)
		{
			if (paceValueSeconds >= 3600.0)
			{
				if (!isMetric)
				{
					return Wolf.Core.Resources.AppStrings.hrs_per_mi;
				}
				return Wolf.Core.Resources.AppStrings.hrs_per_km;
			}
			if (!isMetric)
			{
				return Wolf.Core.Resources.AppStrings.min_per_mi;
			}
			return Wolf.Core.Resources.AppStrings.min_per_km;
		}

		public static double GetPaceFrom(SpeedUnit fromUnit, bool isMetric, double value)
		{
			double value2 = (isMetric ? UnitUtil.EnsureKph(fromUnit, value) : UnitUtil.EnsureMph(fromUnit, value));
			double num = Math.Round(value2, 1, MidpointRounding.AwayFromZero);
			double num2 = (num.AlmostEqual(0.0) ? 0.0 : (3600.0 / num));
			num2 = (double.IsInfinity(num2) ? 0.0 : num2);
			return Math.Max(0.0, num2);
		}
	}
