	public abstract class IntervalMetricBase : MetricBase
	{
		public enum IntervalType
		{
			Time,
			Distance
		}

		protected double lastUpdatedIntervalStartPeriod;

		protected double currentIntervalStartDistance;

		protected double currentIntervalStartSeconds;

		protected MetricStats currentIntervalStats;

		protected override int DecimalDigits => 1;

		public double IntervalSize { get; }

		public IntervalType IntervalTypeTarget { get; }

		protected override FitnessValue MetricTarget => FitnessValue.CurrentDistance;

		protected double CurrentValue => GetCurrentValue();

		protected double CurrentIntervalStart => Math.Floor(CurrentValue / IntervalSize) * IntervalSize;

		protected IntervalMetricBase(IWorkoutContainer workoutContainer, double intervalSize, IntervalType type)
			: base(workoutContainer)
		{
			IntervalSize = intervalSize;
			IntervalTypeTarget = type;
		}

		protected override IObservable<FitnessValueChange<double>> ObserveMetricChanges()
		{
			return facadeFactoryDependencies.CurrentDistanceFacade.ObserveMeterChanges();
		}

		private double GetCurrentValue()
		{
			double num = 0.0;
			if (IntervalTypeTarget == IntervalType.Distance && workoutContainer != null)
			{
				double valueOrDefault = (workoutContainer.Console?.LatestBasicInfo?.DistanceMeters).GetValueOrDefault();
				return workoutContainer.IsMetric ? valueOrDefault : UnitUtil.EnsureMiles(DistanceUnit.M, valueOrDefault);
			}
			return (workoutContainer?.Console?.LatestBasicInfo?.TimeSeconds).GetValueOrDefault();
		}

		protected override void SetSubscription()
		{
			if (IntervalTypeTarget == IntervalType.Distance)
			{
				sub = (from x in facadeFactoryDependencies.CurrentDistanceFacade.ObserveMeterChanges().Where((Func<FitnessValueChange<double>, bool>)delegate
					{
						IConsoleBasicInfo latestBasicInfo = workoutContainer.Console.LatestBasicInfo;
						return latestBasicInfo != null && latestBasicInfo.CurrentState == ConsoleState.Workout;
					})
					select x.Current).SubscribeWithErrorLogging(delegate(double x)
				{
					SetValues(x);
				});
			}
			else
			{
				sub = (from x in facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges().Where((Func<FitnessValueChange<int>, bool>)delegate
					{
						IConsoleBasicInfo latestBasicInfo = workoutContainer.Console.LatestBasicInfo;
						return latestBasicInfo != null && latestBasicInfo.CurrentState == ConsoleState.Workout;
					})
					select x.Current).SubscribeWithErrorLogging(delegate(int x)
				{
					SetValues(x);
				});
			}
		}
	}
