	public class CaloriesPerHourMetric : CaloriesMetricBase
	{
		private const int OneHourSeconds = 3600;

		private IConsoleBasicInfo ConsoleBasicInfo => workoutContainer?.Console?.LatestBasicInfo;

		private ConsoleType ConsoleType => workoutContainer?.Console?.ConsoleInfo?.MachineType ?? ConsoleType.None;

		public new IconType Icon => IconType.CaloriesPerHour;

		protected override FitnessValue MetricTarget => FitnessValue.CurrentTime;

		public CaloriesPerHourMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected override void SetSubscription()
		{
			IReadWriteFacadeFactoryDependencies readWriteFacadeFactoryDependencies = Mvx.Resolve<IReadWriteFacadeFactoryDependencies>();
			IWorkoutContainer obj = workoutContainer;
			if (obj == null || obj.Console?.ConsoleInfo?.MachineType != ConsoleType.InclineTrainer)
			{
				IWorkoutContainer obj2 = workoutContainer;
				if (obj2 == null || obj2.Console?.ConsoleInfo?.MachineType != ConsoleType.Treadmill)
				{
					IWorkoutContainer obj3 = workoutContainer;
					if (obj3 != null && obj3.Console?.ConsoleInfo?.MachineType == ConsoleType.Equipmentless)
					{
						sub = (from x in readWriteFacadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges()
							select x.Current)?.SubscribeWithErrorLogging(delegate(int x)
						{
							SetValues(x);
						});
					}
					else
					{
						sub = (from x in readWriteFacadeFactoryDependencies.WattsFacade.ObserveWattChanges()
							select x.Current)?.SubscribeWithErrorLogging(delegate(int x)
						{
							SetValues(x);
						});
					}
					return;
				}
			}
			List<IObservable<object>> sources = new List<IObservable<object>>
			{
				readWriteFacadeFactoryDependencies.GradeFacade.ObserveGradeChanges(),
				readWriteFacadeFactoryDependencies.KphFacade.ObserveKphChanges(),
				readWriteFacadeFactoryDependencies.ResistanceFacade.ObserveResistanceChanges(),
				readWriteFacadeFactoryDependencies.GearFacade.ObserveGearChanges(),
				readWriteFacadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges()
			};
			sub = sources.Merge().SubscribeWithErrorLogging(delegate
			{
				SetValues(0.0);
			});
		}

		protected override void SetLabels()
		{
			base.Label = Wolf.Core.Resources.AppStrings.flipper_calories_per_hour;
			base.SubtitleLabel = Wolf.Core.Resources.AppStrings.flipper_per_hr;
		}

		protected override void UpdateMediumLabel()
		{
			base.MediumLabel = base.Label;
		}

		protected override Task SetValues(double? value = null)
		{
			Task<int> result = Task.FromResult(0);
			if (workoutContainer?.Workout == null)
			{
				base.Metric = "0";
				return result;
			}
			if (workoutContainer?.Console?.LatestBasicInfo == null)
			{
				base.Metric = "0";
				return result;
			}
			if (WarmupCooldownValueNotAvailable("0"))
			{
				base.Metric = "0";
				return result;
			}
			if (!value.HasValue)
			{
				base.Metric = "0";
				return result;
			}
			double metricValue = CaloriesOverTime(3600.0, value.Value);
			base.Metric = MetricString(metricValue);
			return result;
		}

		public double CaloriesOverTime(double seconds, double value)
		{
			double num = 0.0;
			switch (ConsoleType)
			{
			case ConsoleType.Treadmill:
			case ConsoleType.InclineTrainer:
			{
				double mps = UnitUtil.Ensure(SpeedUnit.Kph, SpeedUnit.Mps, ConsoleBasicInfo.Kph);
				double grade = ConsoleBasicInfo.Grade;
				num = CalorieFormulas.Running(workoutContainer.UserWeightKgs, seconds, mps, grade);
				break;
			}
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				num = CalorieFormulas.Bike(workoutContainer.UserWeightKgs, seconds, value);
				break;
			case ConsoleType.Rower:
			{
				double resistance = ConsoleBasicInfo.Resistance;
				num = CalorieFormulas.Rower(seconds, value);
				break;
			}
			case ConsoleType.Elliptical:
			case ConsoleType.Strider:
			case ConsoleType.FreeStrider:
				num = CalorieFormulas.Elliptical(workoutContainer.UserWeightKgs, seconds, value);
				break;
			case ConsoleType.VerticalElliptical:
				num = CalorieFormulas.VerticalElliptical(workoutContainer.UserWeightKgs, seconds, value);
				break;
			case ConsoleType.Equipmentless:
			case ConsoleType.Mirror:
			{
				IEquipmentlessConsoleService equipmentlessConsoleService = Mvx.Resolve<IEquipmentlessConsoleService>();
				double userAge = equipmentlessConsoleService.CalorieBurnEstimator?.UserAge ?? 35.0;
				bool userMale = equipmentlessConsoleService.CalorieBurnEstimator?.UserMale ?? true;
				num = CalorieFormulas.HeartRate(seconds, workoutContainer.Workout?.Metadata?.AverageHeartRate ?? 125.0, workoutContainer.UserWeightKgs, userAge, userMale);
				break;
			}
			default:
				num = 0.0;
				break;
			}
			if (IsOffEquipment())
			{
				double num2 = OffEquipmentCaloriesOverTime(seconds, num);
				if (num2 > 0.0)
				{
					num = num2;
				}
			}
			return num;
		}

		private double OffEquipmentCaloriesOverTime(double seconds, double calories)
		{
			double result = 0.0;
			List<Workout.VideoWorkoutMetadata.CalorieMultiplierEvent> list = workoutContainer?.Workout?.Metadata?.CalorieMultipliers;
			if (list != null && list.Count > 0)
			{
				result = ((!ConsoleType.IsAerobicMachine()) ? Shire.Core.Util.CalorieMultiplierCalculator.CalculateOffEquipmentBeltMachineCalories(ConsoleBasicInfo.TimeSeconds, calories, 0.0, 0.0, list, ConsoleBasicInfo.Kph) : Shire.Core.Util.CalorieMultiplierCalculator.CalculateOffEquipmentAerobicCalories(ConsoleBasicInfo.TimeSeconds, workoutContainer.UserWeightKgs, seconds, list));
			}
			return result;
		}

		private bool IsOffEquipment()
		{
			if (ConsoleType.IsAerobicMachine())
			{
				return ConsoleBasicInfo.Rpm == 0;
			}
			return UnitUtil.EnsureMph(SpeedUnit.Kph, ConsoleBasicInfo.Kph, 1).AlmostEqual(1.0, 1);
		}
	}
	public class CaloriesRemainingMetric : CaloriesMetricBase
	{
		public new IconType Icon => IconType.CaloriesRemaining;

		protected override FitnessValue MetricTarget => FitnessValue.CurrentTime;

		public override bool IsGoalBased => true;

		public CaloriesRemainingMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected override void SetLabels()
		{
			base.Label = Wolf.Core.Resources.AppStrings.flipper_calories_remaining;
			base.SubtitleLabel = Wolf.Core.Resources.AppStrings.flipper_calories_remaining;
		}

		protected override Task SetValues(double? value = null)
		{
			Task<int> result = Task.FromResult(0);
			if (WarmupCooldownValueNotAvailable())
			{
				return result;
			}
			double valueOrDefault = (workoutContainer?.RemainingEstimates?.LatestRemainingStats?.Calories).GetValueOrDefault();
			base.Metric = MetricString(valueOrDefault);
			return result;
		}
	}
	public class EstimatedCalorieBurnMetric : CaloriesMetricBase
	{
		public new IconType Icon => IconType.CaloriesPerHour;

		public override bool IsGoalBased => true;

		protected override FitnessValue MetricTarget => FitnessValue.CurrentCalories;

		public EstimatedCalorieBurnMetric(IWorkoutContainer workoutContainer)
			: base(workoutContainer)
		{
		}

		protected override void SetSubscription()
		{
			IReadWriteFacadeFactoryDependencies readWriteFacadeFactoryDependencies = Mvx.Resolve<IReadWriteFacadeFactoryDependencies>();
			IWorkoutContainer obj = workoutContainer;
			if (obj == null || obj.Console?.ConsoleInfo?.MachineType != ConsoleType.InclineTrainer)
			{
				IWorkoutContainer obj2 = workoutContainer;
				if (obj2 == null || obj2.Console?.ConsoleInfo?.MachineType != ConsoleType.Treadmill)
				{
					sub = (from x in readWriteFacadeFactoryDependencies.WattsFacade.ObserveWattChanges()
						select x.Current)?.SubscribeWithErrorLogging(delegate(int x)
					{
						SetValues(x);
					});
					return;
				}
			}
			sub = (from x in readWriteFacadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges()
				select x.Current)?.SubscribeWithErrorLogging(delegate(int x)
			{
				SetValues(x);
			});
		}

		protected override void SetLabels()
		{
			base.Label = Wolf.Core.Resources.AppStrings.flipper_estimated_calorie_burn;
			base.SubtitleLabel = Wolf.Core.Resources.AppStrings.flipper_est_cal_burn;
		}

		protected override void UpdateMediumLabel()
		{
			base.MediumLabel = base.Label;
		}

		protected override Task SetValues(double? value = null)
		{
			Task<int> result = Task.FromResult(0);
			if (workoutContainer?.Workout == null)
			{
				base.Metric = "0";
				return result;
			}
			if (WarmupCooldownValueNotAvailable("0"))
			{
				return result;
			}
			if (workoutContainer.Console?.LatestBasicInfo == null)
			{
				base.Metric = "0";
				return result;
			}
			base.Metric = MetricString(((base.CurrentStateStats?.CalorieChanges?.Last?.Value).GetValueOrDefault() + workoutContainer?.RemainingEstimates?.LatestRemainingStats?.Calories).GetValueOrDefault());
			return result;
		}
	}
}
