		protected void StartStreetViewService()
		{
			if (workoutContainer.Workout.IsGoogleMap)
			{
				StreetView = new StreetViewService(ifitApi, ifitGatewayApi, workoutContainer.Console, workoutContainer.Workout.Id, deviceInformation.PixelSafeAreaWidth, deviceInformation.PixelSafeAreaHeight);
			}
