		public void Dispose()
		{
			workoutContainer = null;
			LeftSlider?.Dispose();
			RightSlider?.Dispose();
			FlipperGroup1?.ForEach(delegate(IMetric x)
			{
				x.Dispose();
			});
			FlipperGroup2?.ForEach(delegate(IMetric x)
			{
				x.Dispose();
			});
			FlipperGroup3?.ForEach(delegate(IMetric x)
			{
				x.Dispose();
			});
			FlipperGroup4?.ForEach(delegate(IMetric x)
			{
				x.Dispose();
			});
			FlipperGroup5?.ForEach(delegate(IMetric x)
			{
				x.Dispose();
			});
			MusicHeaderMetric1?.Dispose();
			MusicHeaderMetric2?.Dispose();
			MusicHeaderMetric3?.Dispose();
			foreach (IMetric chartHeaderMetric in ChartHeaderMetrics)
			{
				chartHeaderMetric.Dispose();
			}
			ChartHeaderChart?.Dispose();
			HudMetricGroup1?.Dispose();
			HudMetricGroup2?.Dispose();
			HudMetricGroup3?.Dispose();
			HudMetricGroup4?.Dispose();
			HudMetricGroup5?.Dispose();
			HudMetricGroup6?.Dispose();
			HudMetricGroup7?.Dispose();
			HudSideMetric1?.Dispose();
			HudSideMetric2?.Dispose();
			HudCornerMetric?.Dispose();
			HudWheelLargeMetric1?.Dispose();
			HudWheelSmallMetric1?.Dispose();
			HudWheelLargeMetric2?.Dispose();
			HudWheelSmallMetric2?.Dispose();
			HudWheelBottomMetric?.Dispose();
			HudWheelTotalProgress?.Dispose();
			HudWheelLapProgress?.Dispose();
			HudChart?.Dispose();
			StreetView?.Dispose();
			List<IUserPositionUpdate> userUpdates = UserUpdates;
			if (userUpdates == null || userUpdates.Count <= 0)
			{
				return;
			}
			foreach (IUserPositionUpdate userUpdate in UserUpdates)
			{
				userUpdate.Dispose();
			}
		}

		protected void CreateAndAddToFlipperGroup(Type metricType, List<IMetric> target)
		{
			IMetric metric = CreateMetric(metricType);
			if (workoutContainer?.Supports(metric) != true)
			{
				Log.Trace("Workout", $"Not adding metric {metric} to flippers (unsupported by workout or console).");
				metric?.Dispose();
			}
			else
			{
				target.Add(metric);
			}
		}

		protected void CreateFlipperGroup(List<IMetric> target, params Type[] types)
		{
			foreach (Type metricType in types)
			{
				CreateAndAddToFlipperGroup(metricType, target);
			}
		}

		protected void DisposeFlipperGroup(List<IMetric> target)
		{
			foreach (IMetric item in target)
			{
				item.Dispose();
			}
		}

		protected IMetric CreateMetric<TMetric>() where TMetric : IMetric
		{
			return CreateMetric(typeof(TMetric));
		}

		protected IMetric CreateMetric(Type metricType)
		{
			if (metricType == null)
			{
				return null;
			}
			IMetric metric = MetricCache.FirstOrDefault((IMetric x) => x.GetType().Equals(metricType));
			if (metric != null)
			{
				return metric;
			}
			if (!typeof(IMetric).IsAssignableFrom(metricType))
			{
				throw new ArgumentException($"Provided Type {metricType} does not inherit from IMetric.", "metricType");
			}
			return Activator.CreateInstance(metricType, workoutContainer) as IMetric;
		}

		protected IMetric CreateIntervalMetric<TMetric>(double intervalSize, IntervalMetricBase.IntervalType type) where TMetric : IntervalMetricBase
		{
			IntervalMetricBase intervalMetricBase = IntervalCache.FirstOrDefault((IntervalMetricBase x) => x is TMetric && x.IntervalTypeTarget == type && x.IntervalSize.AlmostEqual(intervalSize, 2));
			if (intervalMetricBase != null)
			{
				return intervalMetricBase;
			}
			return (TMetric)Activator.CreateInstance(typeof(TMetric), workoutContainer, intervalSize, type);
		}

		protected IMetricGroup CreateHudMetricGroup(IconType icon, string label, Type metricType1, Type metricType2, Type metricType3)
		{
			IMetric metric = CreateMetric(metricType1);
			IMetric metric2 = CreateMetric(metricType2);
			IMetric metric3 = CreateMetric(metricType3);
			return new MetricGroup(icon, label, metric, metric2, metric3);
		}

		protected virtual void SetPagesForState()
		{
			MainWarmupPages.Clear();
			MainWorkoutPages.Clear();
			MainCooldownPages.Clear();
			if (runnerContext.Context == Workout.WorkoutContext.OnDemand)
			{
				MainWarmupPages.Add(typeof(InWorkoutWarmCoolViewModel));
			}
			if (workoutContainer.Workout.IsGoogleMap && connectivity.IsConnected)
			{
				MainWorkoutPages.Add(typeof(InWorkoutMapViewModel));
			}
			if (workoutContainer.Workout.IsVideoWorkout())
			{
				MainWorkoutPages.Add(typeof(InWorkoutStreamingVideoViewModel));
			}
			if (MainWorkoutPages.Count == 0)
			{
				MainWorkoutPages.Add(typeof(InWorkoutTrackViewModel));
			}
			if (runnerContext.Context == Workout.WorkoutContext.OnDemand)
			{
				MainCooldownPages.Add(typeof(InWorkoutWarmCoolViewModel));
			}
		}
	}
