	public class JsonConsoleConfiguration : ConfigurationBase
	{
		public const string JsonFolderName = "Wolf.Core.Source.Services.WorkoutContainer.Configurations.Json";

		private const double MetersPerLap = 400.0;

		private const double MilesPerLap = 0.25;

		private const string TargetRPMMetricString = "TargetRPMMetric";

		private readonly List<string> TargetMetricTypes = new List<string> { "TargetRPMMetric" };

		private readonly Assembly metricAssembly;

		private readonly List<Type> metricTypes;

		private readonly JsonConsoleConfigurationModel configModel;

		private readonly double interval;

		public JsonConsoleConfiguration(string jsonFileName, IWorkoutContainer workoutContainer, IConnectivity connectivity, WorkoutRunnerContext runnerContext, IDeviceInformation deviceInfo, IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, IThemeService themeService)
			: this(LoadConfigModel(jsonFileName, deviceInfo), workoutContainer, connectivity, runnerContext, deviceInfo, ifitApi, iFitGatewayApi, themeService)
		{
		}

		public JsonConsoleConfiguration(JsonConsoleConfigurationModel configModel, IWorkoutContainer workoutContainer, IConnectivity connectivity, WorkoutRunnerContext runnerContext, IDeviceInformation deviceInfo, IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, IThemeService themeService)
			: base(workoutContainer, connectivity, runnerContext, ifitApi, iFitGatewayApi, deviceInfo, themeService)
		{
			this.configModel = configModel;
			interval = (workoutContainer.IsMetric ? 400.0 : 0.25);
			metricAssembly = typeof(IMetric).GetTypeInfo().Assembly;
			metricTypes = (from t in metricAssembly.GetTypes()
				where typeof(IMetric).IsAssignableFrom(t)
				select t).ToList();
			SetRelevancies();
		}

		private void SetRelevancies()
		{
			SetMetrics();
			SetWorkout();
			SetSliders();
			SetChartGroups();
			base.CanResumeWithButton = configModel.CanResumeWithButton;
		}

		public virtual void SetMetrics()
		{
			SetFlipperMetrics();
			SetMainHudMetrics();
			SetHudSideMetrics();
			SetChartHeaderMetrics();
		}

		private void SetFlipperMetrics()
		{
			List<IMetric>[] array = new List<IMetric>[5] { base.FlipperGroup1, base.FlipperGroup2, base.FlipperGroup3, base.FlipperGroup4, base.FlipperGroup5 };
			for (int i = 0; i < configModel?.Flippers?.CountSafe() && i < array.Length; i++)
			{
				List<IMetric> target = array[i];
				List<string> list = configModel.Flippers[i];
				foreach (string item in list)
				{
					if (!TargetMetricTypes.Contains(item) || WorkoutSupportsTargetMetrics())
					{
						CreateAndAddToFlipperGroup(GetMetricTypeFromName(item), target);
					}
				}
			}
		}

		private void SetMainHudMetrics()
		{
			List<IMetricGroup> list = new List<IMetricGroup>();
			SetHudStatGroup(configModel.Hud?.MainStats?.TopLeft, list);
			SetHudStatGroup(configModel.Hud?.MainStats?.MiddleLeft, list);
			SetHudStatGroup(configModel.Hud?.MainStats?.BottomLeft, list);
			SetHudStatGroup(configModel.Hud?.MainStats?.TopRight, list);
			SetHudStatGroup(configModel.Hud?.MainStats?.MiddleRight, list);
			SetHudStatGroup(configModel.Hud?.MainStats?.BottomRight, list);
			SetHudStatGroup(configModel.Hud?.MainStats?.BottomCenter, list);
			base.HudMetricGroup1 = ((list.Count > 0) ? list[0] : null);
			base.HudMetricGroup2 = ((list.Count > 1) ? list[1] : null);
			base.HudMetricGroup3 = ((list.Count > 2) ? list[2] : null);
			base.HudMetricGroup4 = ((list.Count > 3) ? list[3] : null);
			base.HudMetricGroup5 = ((list.Count > 4) ? list[4] : null);
			base.HudMetricGroup6 = ((list.Count > 5) ? list[5] : null);
			base.HudMetricGroup7 = ((list.Count > 6) ? list[6] : null);
		}

		private void SetHudStatGroup(IList<string> metricTypeNames, IList<IMetricGroup> metricGroupCollection)
		{
			if (metricTypes.CountSafe() >= 1)
			{
				IMetricGroup metricGroup = CreateHudStatsGroupFromTypeNames(metricTypeNames);
				List<string> list = (from x in metricGroup.MetricGroupMetrics
					where workoutContainer.Supports(x) && !(x is BlankMetric)
					select x.GetType().Name).ToList();
				metricGroup?.Dispose();
				metricGroup = null;
				if (list.Any())
				{
					IMetricGroup item = CreateHudStatsGroupFromTypeNames(list);
					metricGroupCollection.Add(item);
				}
			}
		}

		private void SetHudSideMetrics()
		{
			base.HudWheelLargeMetric1 = GetFallbackMetricFromTypeNameList(configModel.Hud?.WheelMetric1) ?? CreateMetric<DistanceTwoDigitsMetric>();
			base.HudWheelLargeMetric2 = CreateMetric<TimeMetric>();
			base.HudWheelLapProgress = CreateIntervalMetric<IntervalProgressMetric>(interval, IntervalMetricBase.IntervalType.Distance);
			IMetric metric = CreateMetric<ElevationGainMetric>();
			if (workoutContainer.Supports(metric))
			{
				base.HudSideMetric1 = metric;
			}
			else
			{
				metric?.Dispose();
			}
			IMetric metric2 = CreateMetric<ElevationLossMetric>();
			if (workoutContainer.Supports(metric2))
			{
				base.HudSideMetric2 = metric2;
			}
			else
			{
				metric2?.Dispose();
			}
			base.HudCornerMetric = GetFallbackMetricFromTypeNameList(configModel.Hud?.Corner);
		}

		private void SetChartHeaderMetrics()
		{
			IMetric metric = CreateMetric<BlankMetric>();
			IMetric metric2 = CreateMetric<BlankMetric>();
			IMetric metric3 = CreateMetric<BlankMetric>();
			IMetric metric4 = CreateMetric<BlankMetric>();
			JsonConsoleConfigurationModel.JsonChartMetrics chartMetrics = configModel.ChartMetrics;
			if (chartMetrics != null && chartMetrics.Large?.CountSafe() > 0)
			{
				metric = GetFallbackMetricFromTypeNameList(configModel.ChartMetrics?.Large) ?? metric;
			}
			JsonConsoleConfigurationModel.JsonChartMetrics chartMetrics2 = configModel.ChartMetrics;
			if (chartMetrics2 != null && chartMetrics2.AdditionalLarge?.CountSafe() > 0)
			{
				metric2 = GetFallbackMetricFromTypeNameList(configModel.ChartMetrics?.AdditionalLarge) ?? metric2;
			}
			JsonConsoleConfigurationModel.JsonChartMetrics chartMetrics3 = configModel.ChartMetrics;
			if (chartMetrics3 != null && chartMetrics3.TopSmall?.CountSafe() > 0)
			{
				metric3 = ((!TargetMetricTypes.Contains(configModel.ChartMetrics?.TopSmall?.First()) || WorkoutSupportsTargetMetrics()) ? (GetFallbackMetricFromTypeNameList(configModel.ChartMetrics?.TopSmall) ?? metric3) : CreateMetric(typeof(RPMMetric)));
			}
			JsonConsoleConfigurationModel.JsonChartMetrics chartMetrics4 = configModel.ChartMetrics;
			if (chartMetrics4 != null && chartMetrics4.BottomSmall?.CountSafe() > 0)
			{
				metric4 = GetFallbackMetricFromTypeNameList(configModel.ChartMetrics?.BottomSmall) ?? metric4;
			}
			base.ChartHeaderMetrics = new List<IMetric> { metric, metric2, metric3, metric4 };
		}

		private IMetricGroup CreateHudStatsGroupFromTypeNames(IList<string> metricTypeNames)
		{
			IMetric[] array = new IMetric[3]
			{
				CreateMetric<BlankMetric>(),
				CreateMetric<BlankMetric>(),
				CreateMetric<BlankMetric>()
			};
			for (int i = 0; i < metricTypeNames.CountSafe(); i++)
			{
				if (TargetMetricTypes.Contains(metricTypeNames[i]) && !WorkoutSupportsTargetMetrics())
				{
					array[i] = SwitchTargetMetricIfNecessary(metricTypeNames[i]);
				}
				else
				{
					array[i] = CreateMetric(GetMetricTypeFromName(metricTypeNames[i]) ?? typeof(BlankMetric)) ?? array[i];
				}
			}
			return new MetricGroup(array[0]?.Icon ?? IconType.None, array[0]?.Label, array[0], array[1], array[2]);
		}

		private void SetChartGroups()
		{
			AddSupportedChartGroups(configModel, base.ChartGroups, workoutContainer, themeService.AppTheme);
		}

		public static void AddSupportedChartGroups(JsonConsoleConfigurationModel configModel, List<ChartGroupModel> targetChartGroups, IWorkoutContainer workoutContainer, Theme currentTheme)
		{
			foreach (ChartGroupModel chartGroup in configModel.ChartGroups)
			{
				if (chartGroup == null)
				{
					continue;
				}
				SplatColor splatColor = chartGroup?.GroupColor?.GetValueSafely(currentTheme)?.Color ?? SplatColor.Gray;
				if (!workoutContainer.Supports(chartGroup) && !chartGroup.AlwaysDisplay)
				{
					continue;
				}
				targetChartGroups.Add(chartGroup);
				chartGroup.Lines.RemoveAll((ChartMetricConfiguration x) => !workoutContainer.Supports(x));
				foreach (ChartMetricConfiguration line in chartGroup.Lines)
				{
					line.Scaler = chartGroup.Scaler;
					line.IsLeftAxis = chartGroup.LeftAxis;
					if (line.IsPredictedLine && line.RenderStyle != ChartRenderType.Filled)
					{
						SplatColor color = SplatColor.FromArgb(splatColor.R, splatColor.G, splatColor.B);
						color.ColorToHSV(out var hue, out var saturation, out var value);
						saturation /= 2.0;
						SplatColor baseColor = Wolf.Core.Util.ColorUtils.ColorFromHSV(hue, saturation, value);
						line.LineColor = SplatColor.FromArgb(100, baseColor);
					}
					else
					{
						line.LineColor = splatColor;
						line.CircleColor = SplatColor.FromArgb(12, splatColor);
					}
				}
			}
		}

		public virtual void SetWorkout()
		{
			if (workoutContainer.Workout.IsManual())
			{
				SetManualWorkoutMetrics();
			}
			else
			{
				SetNonManualWorkoutMetrics();
			}
			if (workoutContainer.Workout.IsGoogleMap)
			{
				base.UserUpdates = new List<IUserPositionUpdate>
				{
					new CurrentUserPositionUpdate(workoutContainer, ifitApi.CurrentlyAuthenticatedUserId)
				};
			}
		}

		protected virtual void SetManualWorkoutMetrics()
		{
			base.HudWheelSmallMetric1 = CreateMetric<BlankMetric>();
			base.HudWheelSmallMetric2 = CreateMetric<BlankMetric>();
			base.HudWheelBottomMetric = CreateIntervalMetric<LapCurrentMetric>(interval, IntervalMetricBase.IntervalType.Distance);
		}

		protected virtual void SetNonManualWorkoutMetrics()
		{
			base.HudWheelSmallMetric1 = GetFallbackMetricFromTypeNameList(configModel.Hud?.WheelSmallMetric1) ?? CreateMetric<DistanceRemainingTwoDigitsMetric>();
			base.HudWheelSmallMetric2 = CreateMetric<TimeRemainingMetric>();
			if (workoutContainer.Workout.Target == Workout.TargetType.Seconds)
			{
				base.HudWheelBottomMetric = CreateIntervalMetric<LapCurrentMetric>(interval, IntervalMetricBase.IntervalType.Distance);
			}
			else
			{
				base.HudWheelBottomMetric = CreateIntervalMetric<LapCurrentAndTotalMetric>(interval, IntervalMetricBase.IntervalType.Distance);
			}
			base.HudWheelTotalProgress = CreateMetric<WorkoutProgressMetric>();
		}

		private IMetric GetFallbackMetricFromTypeNameList(IList<string> typeNames)
		{
			if (typeNames.CountSafe() < 1)
			{
				return null;
			}
			IMetric metric = null;
			Queue<Type> queue = new Queue<Type>(from n in typeNames
				select GetMetricTypeFromName(n) into t
				where t != null
				select t);
			while (metric == null && queue.Count > 0)
			{
				Type metricType = queue.Dequeue();
				IMetric metric2 = CreateMetric(metricType);
				if (metric2 != null && workoutContainer.Supports(metric2))
				{
					metric = metric2;
					continue;
				}
				metric2?.Dispose();
				metric2 = null;
			}
			return metric;
		}

		protected virtual void SetSliders()
		{
			List<Type> source = (from t in metricAssembly.GetTypes()
				where typeof(IWorkoutSlider).IsAssignableFrom(t)
				select t).ToList();
			if (!string.IsNullOrWhiteSpace(configModel.Sliders?.Left) && source.Any((Type t) => t.Name.Equals(configModel.Sliders?.Left)))
			{
				IWorkoutSlider workoutSlider = Activator.CreateInstance(source.First((Type t) => t.Name.Equals(configModel.Sliders?.Left)), workoutContainer) as IWorkoutSlider;
				if (workoutContainer.Supports(workoutSlider))
				{
					base.LeftSlider = workoutSlider;
				}
				else
				{
					workoutSlider?.Dispose();
					workoutSlider = null;
				}
			}
			if (!string.IsNullOrWhiteSpace(configModel.Sliders?.Right) && source.Any((Type t) => t.Name.Equals(configModel.Sliders?.Right)))
			{
				IWorkoutSlider workoutSlider2 = Activator.CreateInstance(source.First((Type t) => t.Name.Equals(configModel.Sliders?.Right)), workoutContainer) as IWorkoutSlider;
				if (workoutContainer.Supports(workoutSlider2))
				{
					base.RightSlider = workoutSlider2;
					return;
				}
				workoutSlider2?.Dispose();
				workoutSlider2 = null;
			}
		}

		private Type GetMetricTypeFromName(string metricName)
		{
			return metricTypes?.FirstOrDefault((Type t) => t.Name == metricName);
		}

		private static string JsonFilePath(string jsonFileName)
		{
			return "Wolf.Core.Source.Services.WorkoutContainer.Configurations.Json." + jsonFileName;
		}

		private static JsonConsoleConfigurationModel LoadConfigModel(string jsonFileName, IDeviceInformation deviceInfo)
		{
			if (string.IsNullOrWhiteSpace(jsonFileName))
			{
				throw new ArgumentNullException("jsonFileName");
			}
			string text = JsonFilePath(jsonFileName);
			string value = null;
			try
			{
				value = EmbeddedResourceUtil.ReadEmbeddedResourceText(typeof(JsonConsoleConfiguration), text);
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error loading json configuration file", exception);
			}
			if (string.IsNullOrWhiteSpace(value))
			{
				throw new Exception("Could not load console configuration json file. Please ensure the config file " + jsonFileName + " exists, is not empty, and is included as an Embedded Resource at the path: " + text);
			}
			List<JsonConsoleConfigurationModel> list = null;
			try
			{
				list = JsonConvert.DeserializeObject<List<JsonConsoleConfigurationModel>>(value);
			}
			catch (Exception exception2)
			{
				Log.Error("Workout", "Error parsing json configuration file", exception2);
			}
			if (list == null)
			{
				throw new Exception("Could not parse console configuration file " + jsonFileName + ". Ensure the formatting is valid, and check logs for possible specifics.");
			}
			return list?.FirstOrDefault((JsonConsoleConfigurationModel m) => m.IsTablet == deviceInfo.IsTablet);
		}

		private bool WorkoutSupportsTargetMetrics()
		{
			Workout workout = workoutContainer.Workout;
			if (workout == null)
			{
				return false;
			}
			Workout.WorkoutContext? workoutContext = workoutContainer?.WorkoutRunner?.RunContext?.Context;
			bool isLiveWorkout = workout.IsLiveWorkout;
			bool flag = workoutContext == Workout.WorkoutContext.ScheduledLive || workoutContext == Workout.WorkoutContext.ScheduledPre;
			if ((workout == null || !workout.TargetRPMControls.IsNullOrEmpty() || workout == null || workout.Controls?.Any((Workout.Control c) => c.Type == Workout.Control.ControlType.Rpm) != false) && !isLiveWorkout && !flag && !workout.IsGoogleMap && !workout.IsManual())
			{
				return !workout.IsStrengthWorkout();
			}
			return false;
		}

		private IMetric SwitchTargetMetricIfNecessary(string metricName)
		{
			if (metricName == "TargetRPMMetric")
			{
				return CreateMetric(typeof(RPMMetric));
			}
			return CreateMetric(typeof(BlankMetric));
		}
	}
