	public static class SummaryStatConfiguration
	{
		private static List<StatInfoLabelType> BuildList(bool canSetIncline, bool hasCadence, bool isRower, bool usingExtra)
		{
			List<StatInfoLabelType> list = new List<StatInfoLabelType>();
			list.Add(StatInfoLabelType.Calories);
			list.Add(StatInfoLabelType.Time);
			if (isRower)
			{
				list.Add(StatInfoLabelType.DistanceInMeters);
			}
			else
			{
				list.Add(StatInfoLabelType.Distance);
			}
			list.Add(StatInfoLabelType.HeartRate);
			if (canSetIncline)
			{
				list.Add(StatInfoLabelType.Incline);
			}
			else
			{
				list.Add(StatInfoLabelType.VerticalGain);
			}
			if (!isRower)
			{
				list.Add(StatInfoLabelType.Speed);
			}
			if (hasCadence)
			{
				list.Add(StatInfoLabelType.Cadence);
				list.Add(StatInfoLabelType.Watts);
			}
			else if (isRower)
			{
				list.Add(StatInfoLabelType.Watts);
			}
			else
			{
				list.Add(StatInfoLabelType.Pace);
			}
			if (canSetIncline)
			{
				list.Add(StatInfoLabelType.Elevation);
			}
			if (isRower)
			{
				list.Add(StatInfoLabelType.StrokesPerMin);
				list.Add(StatInfoLabelType.FiveHundred);
				if (usingExtra)
				{
					list.Add(StatInfoLabelType.TotalReps);
				}
			}
			if (usingExtra)
			{
				list.Add(StatInfoLabelType.Resistance);
				list.Add(StatInfoLabelType.XScore);
			}
			return list;
		}

		public static List<StatInfoLabelType> GetConfigFor(ActivityLog.StatGroup stats, bool usingExtra = true)
		{
			if (stats != null && stats.Reps?.Count > 0)
			{
				return BuildList(canSetIncline: false, hasCadence: false, isRower: true, usingExtra);
			}
			if ((stats?.Rpm?.Count).GetValueOrDefault() == 0)
			{
				return BuildList(canSetIncline: true, hasCadence: false, isRower: false, usingExtra);
			}
			if ((stats?.Incline?.Count).GetValueOrDefault() == 0)
			{
				return BuildList(canSetIncline: false, hasCadence: true, isRower: false, usingExtra);
			}
			return BuildList(canSetIncline: true, hasCadence: true, isRower: false, usingExtra);
		}
	}
