	public interface IWebViewBehaviorProvider
	{
		string BehaviorName { get; }

		string LegacyBehaviorName { get; }

		Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context);

		bool SupportsBehavior(string name);
	}
	public abstract class BaseWebViewBehaviorProvider : IWebViewBehaviorProvider
	{
		public abstract string BehaviorName { get; }

		public virtual string LegacyBehaviorName => BehaviorName;

		public abstract Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context);

		public virtual bool SupportsBehavior(string name)
		{
			if (!(BehaviorName == name))
			{
				return LegacyBehaviorName == name;
			}
			return true;
		}
	}
