	public class CommonWorkoutModalClosedBehaviorProvider : BaseWebViewBehaviorProvider
	{
		public const string NativeMethodModalClosed = "ModalClosed";

		public const string NativeParamScheduleHasChanged = "scheduleHasChanged";

		public const string NativeParamFavoritesHasChanged = "favoriteHasChanged";

		protected readonly ILocalSettings localSettings;

		protected readonly INeedsRefreshService needsRefreshService;

		protected readonly IWebviewSettings webviewSettings;

		public override string BehaviorName => "ModalClosed";

		public CommonWorkoutModalClosedBehaviorProvider(ILocalSettings localSettings, IWebviewSettings webviewSettings, INeedsRefreshService needsRefreshService)
		{
			this.localSettings = localSettings;
			this.webviewSettings = webviewSettings;
			this.needsRefreshService = needsRefreshService;
		}

		public override Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			string value = string.Empty;
			parameters?.TryGetValue("scheduleHasChanged", out value);
			bool.TryParse(value, out var result);
			if (result)
			{
				webviewSettings.ReloadFeedData = true;
			}
			string value2 = string.Empty;
			parameters?.TryGetValue("favoriteHasChanged", out value2);
			bool.TryParse(value2, out var result2);
			if (result2)
			{
				needsRefreshService.RequestRefresh(RefreshCause.Favorites);
			}
			return AfterRunBehavior(behaviorName, parameters, context);
		}

		public virtual Task AfterRunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			return Task.CompletedTask;
		}
	}
