	public class JoinLiveWorkoutBehaviorProvider : BaseWebViewBehaviorProvider
	{
		private const string LogTag = "JoinLiveWorkoutBehaviorProvider";

		private readonly IIfitApiService ifitApiService;

		private readonly IStartWorkoutBehaviorService startWorkoutBehaviorService;

		private bool workoutSelected;

		public override string BehaviorName => "JoinLiveWorkout";

		public JoinLiveWorkoutBehaviorProvider(IIfitApiService ifitApiService, IStartWorkoutBehaviorService startWorkoutBehaviorService)
		{
			this.ifitApiService = ifitApiService;
			this.startWorkoutBehaviorService = startWorkoutBehaviorService;
		}

		public override async Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			if (workoutSelected || StartWorkoutBehaviorService.CheckIfIsLoading(context))
			{
				return;
			}
			workoutSelected = true;
			parameters.TryGetValue("workoutId", out var scheduleId);
			Log.Trace("JoinLiveWorkoutBehaviorProvider", "Joining live workout, schedule id: " + scheduleId);
			if (string.IsNullOrEmpty(scheduleId))
			{
				StartWorkoutBehaviorService.ShowError(context as BaseViewModel, Wolf.Core.Resources.AppStrings.live_schedule_load_error, ErrorCode.WebViewLiveWorkoutScheduleIdIsNullOrEmptyError);
				workoutSelected = false;
				return;
			}
			LiveWorkouts.WorkoutInfo workoutInfo;
			try
			{
				context.SetIsLoading(isLoading: true);
				workoutInfo = await LiveWorkouts.GetWorkout(ifitApiService, scheduleId).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				Log.Error("JoinLiveWorkoutBehaviorProvider", "Error getting live workout info for ID #" + scheduleId + ": #" + ex.Message);
				context.SetIsLoading(isLoading: false);
				workoutSelected = false;
				return;
			}
			if (workoutInfo == null)
			{
				StartWorkoutBehaviorService.ShowError(context as BaseViewModel, Wolf.Core.Resources.AppStrings.live_schedule_load_error, ErrorCode.WebViewLiveWorkoutWorkoutIsNullError);
				context.SetIsLoading(isLoading: false);
				workoutSelected = false;
			}
			else
			{
				WorkoutRunnerContext workoutContext = new WorkoutRunnerContext(workoutInfo.Context, workoutInfo);
				await startWorkoutBehaviorService.StartWorkout(context, workoutInfo.WorkoutId, null, null, workoutContext);
				context.SetIsLoading(isLoading: false);
				workoutSelected = false;
			}
		}
	}
