	public class NavigateToPathBehaviorProvider : BaseWebViewBehaviorProvider
	{
		public const string LogTag = "NavigateToPathBehaviorProvider";

		public const string NativeMethodNavigateToPath = "NavigateToPath";

		public const string NavigateToPathPathArgumentString = "path";

		private readonly IAppLinking appLinking;

		public override string BehaviorName => "NavigateToPath";

		public NavigateToPathBehaviorProvider(IAppLinking appLinking)
		{
			this.appLinking = appLinking;
		}

		public override Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			if (behaviorName == "NavigateToPath")
			{
				NavigateToPath(context, parameters);
			}
			else
			{
				Log.Info("NavigateToPathBehaviorProvider", "Unsupported behavior: " + behaviorName);
			}
			return Task.CompletedTask;
		}

		private void NavigateToPath(IBehaviorContext context, IDictionary<string, string> parameters)
		{
			string text = parameters["path"];
			if (!text.StartsWith("http"))
			{
				StringBuilder stringBuilder = new StringBuilder("https://a.ifit.io");
				if (!text.StartsWith("/"))
				{
					stringBuilder.Append("/");
				}
				stringBuilder.Append(text);
				text = stringBuilder.ToString();
			}
			appLinking.HandleExternalLinkRequest(text, context.GetType());
		}
	}
