	public class PreloadWorkoutBehaviorProvider : BaseWebViewBehaviorProvider, IWebViewBehaviorProvider
	{
		private const string LogTag = "PreloadWorkoutBehaviorProvider";

		public const string PreloadWorkoutBehaviorString = "PreloadWorkout";

		public const string WorkoutIdKey = "workoutId";

		public const string ForceKey = "force";

		private readonly IWorkoutApiService workoutApiService;

		public override string BehaviorName => "PreloadWorkout";

		public PreloadWorkoutBehaviorProvider(IWorkoutApiService workoutApiService)
		{
			this.workoutApiService = workoutApiService;
		}

		public override async Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			if (behaviorName == "PreloadWorkout")
			{
				await PreloadWorkoutAsync(parameters);
				return;
			}
			throw new KeyNotSupportedException("Requested key is not supported");
		}

		private async Task PreloadWorkoutAsync(IDictionary<string, string> parameters)
		{
			parameters.TryGetValue("workoutId", out var workoutId);
			parameters.TryGetValue("force", out var value);
			try
			{
				Log.Trace("PreloadWorkoutBehaviorProvider", "Preloading workout with ID: " + workoutId);
				if (bool.TryParse(value, out var result) && !string.IsNullOrWhiteSpace(workoutId))
				{
					await workoutApiService.Get(workoutId, result);
					return;
				}
				Log.Error("PreloadWorkoutBehaviorProvider", "Invalid workout parameters.");
				throw new ArgumentException("Invalid workout parameters.");
			}
			catch (Exception ex)
			{
				Log.Error("PreloadWorkoutBehaviorProvider", "Error preloading workout with ID " + workoutId + ": #" + ex.Message);
				throw;
			}
		}
	}
