	}
	public class ShareWorkoutBehaviorProvider : BaseWebViewBehaviorProvider, IShareWorkoutBehaviorProvider, IWebViewBehaviorProvider
	{
		public const string NativeMethodShareWorkout = "ShareWorkout";

		public const string ShareTextKey = "posttext";

		public const string ShareUrlKey = "url";

		public const string ShareDefaultUrl = "https://www.ifit.com";

		public const string ShareDefaultText = "I did an iFIT workout!";

		public const string ShareProviderKey = "provider";

		public const string ShareResultKey = "result";

		public const string ShareResultMethod = "SocialShareReturnedResult";

		public const string LogTag = "ShareWorkoutBehaviorProvider";

		private readonly IDeviceInformation deviceInformation;

		private readonly INativeShareService nativeShareService;

		private readonly IConnectivity connectivity;

		private readonly IWolfSharingService wolfSharingService;

		public override string BehaviorName => "ShareWorkout";

		public ShareWorkoutBehaviorProvider(IDeviceInformation deviceInformation, INativeShareService nativeShareService, IConnectivity connectivity, IWolfSharingService wolfSharingService)
		{
			this.deviceInformation = deviceInformation;
			this.nativeShareService = nativeShareService;
			this.connectivity = connectivity;
			this.wolfSharingService = wolfSharingService;
		}

		public override async Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			_ = 1;
			try
			{
				if (parameters.ContainsKey("provider"))
				{
					string url = (parameters.ContainsKey("url") ? parameters["url"] : "https://www.ifit.com");
					string postText = (parameters.ContainsKey("posttext") ? parameters["posttext"] : "I did an iFIT workout!");
					if (!deviceInformation.IsBuiltIn)
					{
						await nativeShareService.ShareViaNativeShareMenu(postText, url);
						return;
					}
					SocialShareProvider type = (SocialShareProvider)Enum.Parse(typeof(SocialShareProvider), parameters["provider"], ignoreCase: true);
					await ShareViaProvider(type, postText, url, context);
					return;
				}
				throw new ArgumentException("The \"provider\" key is missing from the logViewShareWorkout call");
			}
			catch (Exception ex)
			{
				Log.Error("ShareWorkoutBehaviorProvider", ex.Message);
			}
		}

		private async Task ShareViaProvider(SocialShareProvider type, string postText, string url, IBehaviorContext context)
		{
			IConnectivity obj = connectivity;
			if (obj != null && !obj.IsConnected)
			{
				context.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error.ToUpper(), Wolf.Core.Resources.AppStrings.wifi_not_found, null, string.Empty, Wolf.Core.Resources.AppStrings.ok.ToUpper());
				return;
			}
			try
			{
				Log.Trace("ShareWorkoutBehaviorProvider", $"Sharing url {url} on {type}");
				ShareResult shareResult = await wolfSharingService.ShareWorkout(type, postText, url);
				Dictionary<string, string> parameters = new Dictionary<string, string>
				{
					{
						"result",
						shareResult.ToString().ToLowerInvariant()
					},
					{
						"provider",
						type.ToString().ToLowerInvariant()
					}
				};
				context.CallBridge("SocialShareReturnedResult", parameters);
				Log.Trace("ShareWorkoutBehaviorProvider", $"Share result: {shareResult}");
			}
			catch (Exception exception)
			{
				Log.Error("ShareWorkoutBehaviorProvider", $"Share ${type} error", exception);
			}
		}
	}
	public class ShowDetailsBehaviorProvider : BaseWebViewBehaviorProvider
	{
		public const string NativeMethodShowDetails = "ShowDetails";

		public const string ViewModelParameterId = "Id";

		public const string ViewModelParameterWorkoutId = "WorkoutId";

		public const string NativeMethodArgumentUrlRouteName = "UrlRouteName";

		public const string NativeMethodArgumentReferralSource = "ReferralSource";

		public const string ProgramUrlRouteName = "program";

		public const string LogTag = "ShowDetailsBehaviorProvider";

		private readonly IMvxViewDispatcher dispatcher;

		public virtual string NativeMethodArgumentId => "Id";

		public override string BehaviorName => "ShowDetails";

		public ShowDetailsBehaviorProvider(IMvxViewDispatcher dispatcher)
		{
			this.dispatcher = dispatcher;
		}

		public override Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			string urlRouteName = GetUrlRouteName(parameters);
			string referralSource = GetReferralSource(parameters);
			if (!parameters.TryGetValue(NativeMethodArgumentId, out var value) || referralSource == null)
			{
				ShowLoadError(context);
				return Task.CompletedTask;
			}
			if (urlRouteName == null)
			{
				Log.Trace("ShowDetailsBehaviorProvider", "Showing details for preworkout because of an empty route and id " + value + " from viewmodel " + context.GetType().FullName);
				dispatcher.ShowViewModel(new MvxViewModelRequest(typeof(PreWorkoutWebviewViewModel), new MvxBundle(new Dictionary<string, string>
				{
					{ "WorkoutId", value },
					{ "ReferralSource", referralSource }
				}), ShireViewParams.AnimateTransition(isAnimated: false), new MvxRequestedBy(MvxRequestedByType.UserAction)));
			}
			else
			{
				Log.Trace("ShowDetailsBehaviorProvider", "Showing details for route " + urlRouteName + " and id " + value + " from viewmodel " + context.GetType().FullName);
				dispatcher.ShowViewModel(new MvxViewModelRequest(typeof(DetailsViewModel), new MvxBundle(new Dictionary<string, string>
				{
					{ "Id", value },
					{ "ReferralSource", referralSource },
					{ "UrlRouteName", urlRouteName }
				}), CreateProgramPresentationBundle(), new MvxRequestedBy(MvxRequestedByType.UserAction)));
			}
			return Task.CompletedTask;
		}

		protected virtual string GetReferralSource(IDictionary<string, string> parameters)
		{
			parameters.TryGetValue("ReferralSource", out var value);
			return value;
		}

		protected virtual string GetUrlRouteName(IDictionary<string, string> parameters)
		{
			parameters.TryGetValue("UrlRouteName", out var value);
			return value;
		}

		private IMvxBundle CreateProgramPresentationBundle()
		{
			return ShireViewParams.AnimateTransition(isAnimated: false);
		}

		protected void ShowLoadError(IBehaviorContext context)
		{
			context.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.library_load_error);
		}
	}
