	{
		public const string NativeProgramId = "NativeProgramId";

		public const string WebviewWorkoutIdKey = "workoutId";

		public const string WebviewProgramIdKey = "programId";

		public const string WebviewChallengeIdKey = "challengeId";

		public const string NativeMethodStartWorkout = "StartWorkout";

		private readonly IStartWorkoutBehaviorService startWorkoutBehaviorService;

		private bool alreadyStartingWorkout;

		public override string BehaviorName => "StartWorkout";

		public StartWorkoutBehaviorProvider(IStartWorkoutBehaviorService startWorkoutBehaviorService)
