			this.startWorkoutBehaviorService = startWorkoutBehaviorService;
		}

		public override async Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, IBehaviorContext context)
		{
			if (!alreadyStartingWorkout)
			{
				alreadyStartingWorkout = true;
				string value = string.Empty;
				parameters?.TryGetValue("workoutId", out value);
				string value2 = null;
				parameters?.TryGetValue("programId", out value2);
				string value3 = string.Empty;
				parameters?.TryGetValue("challengeId", out value3);
				await startWorkoutBehaviorService.StartWorkout(context, value, value2, value3).ConfigureAwait(continueOnCapturedContext: false);
				alreadyStartingWorkout = false;
			}
		}
	}
	public interface IStartWorkoutBehaviorService
	{
		Task StartWorkout(IBehaviorContext context, string workoutId, string programId = null, string challengeId = null, WorkoutRunnerContext workoutContext = null);
	}
	public class StartWorkoutBehaviorService : IStartWorkoutBehaviorService
	{
		private readonly IDeviceInformation deviceInformation;

		private readonly ICurrentConsoleService currentConsole;

		private readonly IMvxMessenger messenger;

		private readonly IWorkoutApiService workoutApiService;

		private readonly IStartWorkoutService startWorkoutService;

		private const string LogTag = "StartWorkoutBehaviorService";

		public StartWorkoutBehaviorService(IDeviceInformation deviceInformation, ICurrentConsoleService currentConsole, IMvxMessenger messenger, IWorkoutApiService workoutApiService, IStartWorkoutService startWorkoutService)
		{
			this.deviceInformation = deviceInformation;
			this.currentConsole = currentConsole;
			this.messenger = messenger;
			this.workoutApiService = workoutApiService;
			this.startWorkoutService = startWorkoutService;
		}

		public async Task StartWorkout(IBehaviorContext context, string workoutId, string programId = null, string challengeId = null, WorkoutRunnerContext workoutContext = null)
		{
			try
			{
				Workout requestedWorkout = await GetRequestedWorkout(context, workoutId);
				try
				{
					if (CheckIfDisposed(context) || (context as BaseViewModel).ShowErrorIfNoWorkout(requestedWorkout))
					{
						return;
					}
					if (startWorkoutService == null)
					{
						(context as BaseViewModel).ShowErrorIfNoWorkout(null);
					}
					else
					{
						if ((Mvx.TryResolve<ILockScreenHandler>(out var service) && service.IsScreenLocked) || (context as BaseViewModel).ShowDmkError(currentConsole?.Console?.LatestBasicInfo?.CurrentState))
						{
							return;
						}
						if (!(deviceInformation?.IsBuiltIn ?? false))
						{
							ICurrentConsoleService currentConsoleService = currentConsole;
							if (currentConsoleService == null || currentConsoleService.Console?.IsNonconnectedConsole() != false || !currentConsole.Console.CanDoWorkout(requestedWorkout))
							{
								if (requestedWorkout?.IsStrengthWorkout() ?? false)
								{
									await StartRequestedWorkout(context, requestedWorkout, programId, challengeId, workoutContext).ConfigureAwait(continueOnCapturedContext: false);
									return;
								}
								await context.DisplayBlePairFilterVM(messenger, null, delegate
								{
								}, requestedWorkout, async delegate
								{
									await StartRequestedWorkout(context, requestedWorkout, programId, challengeId, workoutContext).ConfigureAwait(continueOnCapturedContext: false);
								}).ConfigureAwait(continueOnCapturedContext: false);
								return;
							}
						}
						await StartRequestedWorkout(context, requestedWorkout, programId, challengeId, workoutContext).ConfigureAwait(continueOnCapturedContext: false);
					}
				}
				finally
				{
					if (requestedWorkout != null)
					{
						((IDisposable)requestedWorkout).Dispose();
					}
				}
			}
			catch (Exception exception)
			{
				Log.Error("StartWorkoutBehaviorService", "Error getting workout data in StartWorkoutBehaviorService", exception);
			}
		}

		private async Task<Workout> GetRequestedWorkout(IBehaviorContext context, string workoutId)
		{
			if (context.RequestedWorkout?.Id != workoutId)
			{
				context.SetIsLoading(isLoading: true);
				context.RequestedWorkout = await workoutApiService.Get(workoutId).ConfigureAwait(continueOnCapturedContext: false);
				context.SetIsLoading(isLoading: false);
			}
			return context.RequestedWorkout;
		}

		private static bool CheckIfDisposed(IBehaviorContext context)
		{
			if (!context.IsDisposed)
			{
				return false;
			}
			ShowError(context as IShowSimpleConfirmationDialog, Wolf.Core.Resources.AppStrings.preparing_workout_error, ErrorCode.StartingWorkoutPrepCompleteFailed);
			return true;
		}

		private async Task StartRequestedWorkout(IBehaviorContext context, Workout requestedWorkout, string programId = null, string challengeId = null, WorkoutRunnerContext workoutRunnerContext = null)
		{
			await EventService.Instance.CreateAsync("Start Workout To Accept Screen Time").ConfigureAwait(continueOnCapturedContext: false);
			WorkoutRunnerContext runningContext = workoutRunnerContext ?? WorkoutRunnerContext.DefaultOnDemandContext;
			if (await startWorkoutService.DoStartWorkout(requestedWorkout, runningContext, context.WaitForConsoleReady, context.AnalyticsSource, isManualWorkout: false, programId, challengeId).ConfigureAwait(continueOnCapturedContext: false))
			{
				context.WebviewHolderFactory.WebviewHolderStore.FlushAll();
				context.CloseViewModel.Execute();
			}
		}

		public static void ShowError(IShowSimpleConfirmationDialog context, string error, ErrorCode errorCode, bool closeAfterDismiss = false)
		{
			context?.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, error, (Func<CancellationToken, Task<object>>)null, false, (Action<Task<object>>)delegate
			{
				if (closeAfterDismiss)
				{
					context.CloseViewModel.Execute(null);
				}
			}, (string)null, Wolf.Core.Resources.AppStrings.ok.ToUpper(), (Action)null, (Action)null, false, false, "", (TaskCompletionSource<object>)null, errorCode.HumanReadable(), true);
		}

		public static bool CheckIfIsLoading(IBehaviorContext context)
		{
			if (!context.GetIsLoading)
			{
				return false;
			}
			ShowError(context as IShowSimpleConfirmationDialog, Wolf.Core.Resources.AppStrings.preparing_workout_error, ErrorCode.StartingWorkoutPrepCompleteFailed);
			return true;
		}
	}
