		public AchievementStatsProvider(IAchievementStatsService achievementStatsService)
		{
			this.achievementStatsService = achievementStatsService;
		}

		public Task<string> GetData(Uri uri)
		{
			string text = "";
			string host = uri.Host;
			if (!(host == "completed-challenges"))
			{
				if (!(host == "pre-workout-user-stats"))
				{
					throw new KeyNotSupportedException();
				}
				text = achievementStatsService.AchievementStats.PreWorkoutUserStats;
			}
			else
			{
				text = achievementStatsService.AchievementStats.ChallengesThatWillComplete;
			}
			return Task.FromResult(text);
		}

