			wolfEnvironment = ifitEnvironment as IWolfEnvironment;
		}

		public override async Task<string> GetData(Uri uri)
		{
			return uri.Host switch
			{
				"api-url" => ifitEnvironment.Endpoint, 
				"gateway-url" => ifitEnvironment.BaseGatewayAPIUrl, 
				"bearer-token" => await ifitApiService.GetToken(), 
				"client-id" => ifitEnvironment.ClientId, 
				"client-secret" => ifitEnvironment.ClientSecret, 
				"segment-id" => ifitEnvironment.SegmentId, 
				"moesif-application-id" => ifitEnvironment.MoesifApplicationId, 
				"raygun-id" => ifitEnvironment.RaygunId, 
				"facebook-app-id" => ifitEnvironment.FacebookAppId, 
				"environment-type" => ifitEnvironment.EnvironmentType.ToString(), 
				"base-site" => ifitEnvironment.BaseSite, 
				"speed-test-endpoint" => ifitEnvironment.SpeedTestEndpoint, 
				"debug-endpoint" => ifitEnvironment.DebugEndpoint, 
				"onboarding-client-id" => GetWolfEnvironmentResult((IWolfEnvironment we) => we.OnboardingClientId), 
				"onboarding-client-secret" => GetWolfEnvironmentResult((IWolfEnvironment we) => we.OnboardingClientSecret), 
				"launch-darkly-mobile-key" => GetWolfEnvironmentResult((IWolfEnvironment we) => we.LaunchDarklyMobileKey), 
				"dashboard-client-id" => GetWolfEnvironmentResult((IWolfEnvironment we) => we.DashboardClientId), 
