		}

		public override async Task<string> GetData(Uri uri)
		{
			string[] array = uri.PathAndQuery.TrimStart('/').Split('/', StringSplitOptions.RemoveEmptyEntries);
			_ = string.Empty;
			string result;
			switch (uri.Host)
			{
			case "workout":
				if (array.Length == 1)
				{
					string id2 = array[0];
					Workout workout = await Workout.Get(api, id2, deviceInformation.SoftwareNumber);
					if (workout != null)
					{
						result = JsonConvert.SerializeObject(workout);
						break;
					}
					throw new KeyNotSupportedException("WebView Api Provider: Workout not found");
				}
				throw new KeyNotSupportedException("WebView Api Provider Workout requires id passed");
			case "series":
				if (array.Length == 1)
				{
					string id3 = array[0];
					Program program = await Program.Get(api, id3);
					if (program != null)
					{
						result = JsonConvert.SerializeObject(program);
						break;
					}
					throw new KeyNotSupportedException("WebView Api Provider: Program not found");
				}
				throw new KeyNotSupportedException("WebView Api Provider Program requires id passed");
			case "trainer":
				if (array.Length == 1)
				{
					string id = array[0];
					Trainer trainer = await Trainer.Get(api, id);
					if (trainer != null)
					{
						result = JsonConvert.SerializeObject(trainer);
						break;
					}
					throw new KeyNotSupportedException("WebView Api Provider: Trainer not found");
				}
				throw new KeyNotSupportedException("WebView Api Provider Trainer requires id passed");
			default:
				throw new KeyNotSupportedException("WebView Api Provider didn't recognize key");
			}
			return result;
