		public const string MaxInclineKeyString = "max-incline";

		public const string MinResistanceKeyString = "min-resistance";

		public const string MaxResistanceKeyString = "max-resistance";

		public const string UnitPreferenceKeyString = "unit-preference";

		public const string SerialNumberKeyString = "serial-number";

		public const string MockTypeKeyString = "mock-type";

		private readonly IDeviceInformation deviceInformation;

		private readonly IModalityChangeService modalityChangeService;

		private readonly ICurrentConsoleService currentConsoleService;

		public override string Scheme => "consoleinfo";

		public WebViewConsoleInfoProvider(IDeviceInformation deviceInformation, IModalityChangeService modalityChangeService, ICurrentConsoleService currentConsoleService)
		{
			this.deviceInformation = deviceInformation;
			this.modalityChangeService = modalityChangeService;
			this.currentConsoleService = currentConsoleService;
		}

		public override string[] GetAllSupportedKeys()
		{
			return new string[10] { "software-number", "console-type", "is-club-unit", "min-speed", "max-speed", "min-incline", "max-incline", "min-resistance", "max-resistance", "unit-preference" };
		}

		public override async Task<string> GetData(Uri uri)
		{
			if ((currentConsoleService.Console == null || currentConsoleService.Console.ConsoleInfo == null) && uri.Host != "software-number" && uri.Host != "console-type")
			{
				throw new KeyNotSupportedException("Console is not attached");
			}
			IConsoleInfo consoleInfo = currentConsoleService?.Console?.ConsoleInfo;
			string result;
			switch (uri.Host)
			{
			case "software-number":
				result = ((!modalityChangeService.HybridSoftwareNumberOverride.IsNullOrWhitespace()) ? modalityChangeService.HybridSoftwareNumberOverride : deviceInformation?.SoftwareNumber.ToString());
				break;
			case "console-type":
				result = ((!modalityChangeService.HybridConsoleTypeOverride.IsNullOrWhitespace()) ? modalityChangeService.HybridConsoleTypeOverride : currentConsoleService?.LastKnownConsoleType.ToString());
				break;
			case "is-club-unit":
				result = consoleInfo.IsClubUnit.ToString();
				break;
			case "min-speed":
				result = consoleInfo.MinKph.ToString();
				break;
			case "max-speed":
				result = consoleInfo.MaxKph.ToString();
				break;
			case "min-incline":
				result = consoleInfo.MinIncline.ToString();
				break;
			case "max-incline":
				result = consoleInfo.MaxIncline.ToString();
				break;
			case "min-resistance":
				result = consoleInfo.MinResistanceLevel.ToString();
				break;
			case "max-resistance":
				result = consoleInfo.MaxResistanceLevel.ToString();
				break;
			case "unit-preference":
				result = consoleInfo.SystemUnits.ToString();
				break;
			case "serial-number":
				result = consoleInfo.SerialNumber.ToString();
				break;
			case "mock-type":
				if (!(currentConsoleService.Console is INonconnectedFitnessConsole { MockType: var mockType }))
				{
					throw new KeyNotSupportedException("Console is not Mock");
				}
				result = mockType.ToString();
				break;
			default:
				throw new KeyNotSupportedException();
			}
			return result;
		}
	}
