	public class WebViewFeatureFlagProvider : BaseWebViewDataProvider, IWebViewFeatureFlagProvider, IWebViewDataProvider
	{
		public const string SchemeString = "featureflag";

		private readonly IFeatureFlagManager featureFlagManager;

		public override string Scheme => "featureflag";

		public WebViewFeatureFlagProvider(IFeatureFlagManager featureFlagManager)
		{
			this.featureFlagManager = featureFlagManager;
		}

		public override Task<string> GetData(Uri uri)
		{
			string message = "Feature flags didn't recognize key " + uri.OriginalString;
			FeatureFlag featureFlag = FeatureFlags.AllFlags.FirstOrDefault((FeatureFlag x) => x.Key == uri.Host);
			if (featureFlag != null)
			{
				try
				{
					return Task.FromResult(featureFlagManager.GetWebviewDataString(featureFlag));
				}
				catch (Exception ex)
				{
					message = ex.Message;
				}
			}
			else
			{
				string text = HttpUtility.ParseQueryString(uri.Query).Get("key");
				string value = HttpUtility.ParseQueryString(uri.Query).Get("type");
				if (string.IsNullOrWhiteSpace(text))
				{
					throw new KeyNotSupportedException(message);
				}
				if (string.IsNullOrWhiteSpace(value))
				{
					throw new TypeNotSupportedException("Invalid flag type");
				}
				try
				{
					FeatureFlagType type = Enum.Parse<FeatureFlagType>(value, ignoreCase: true);
					return Task.FromResult(featureFlagManager.GetWebviewDataString(text, type));
				}
				catch (Exception ex2)
				{
					message = ex2.Message;
				}
			}
			throw new KeyNotSupportedException(message);
		}

		public override string[] GetAllSupportedKeys()
		{
			return FeatureFlags.AllFlags.Select((FeatureFlag x) => x.Key).ToArray();
		}
	}
	public class WebviewHolderFactoryProvider : BaseWebViewDataProvider
	{
		public const string SchemeString = "store";

		public const string PutKeyString = "put";

		public const string DeleteKeyString = "delete";

		public const string GetKeyString = "get";

		private readonly Dictionary<string, string> data = new Dictionary<string, string>();

		public override string Scheme => "store";

		public override Task<string> GetData(Uri uri)
		{
			string text = uri.Host.ToLowerInvariant();
			string absolutePath = uri.AbsolutePath;
			string value = ((uri.Query.Length > 0) ? uri.Query.Substring(1) : "");
			return Task.FromResult(text switch
			{
				"put" => DoPut(absolutePath, value), 
				"get" => DoGet(absolutePath), 
				"delete" => DoDelete(absolutePath), 
				_ => throw new KeyNotSupportedException("Valid keys are put, get, and delete"), 
			});
		}

		private string DoPut(string key, string value)
		{
			data[key] = value;
			return DoGet(key);
		}

		private string DoGet(string key)
		{
			if (data.ContainsKey(key))
			{
				return data[key];
			}
			return null;
		}

		private string DoDelete(string key)
		{
			string result = DoGet(key);
			data.Remove(key);
			return result;
		}

		public override string[] GetAllSupportedKeys()
		{
			return new string[3] { "put", "delete", "get" };
		}
	}
