		private const string CohortAgeString = "cohortage";

		private const string CohortTypeString = "cohorttype";

		private const string CohortDistanceString = "cohortdistance";

		private const string CohortAvatarUrlString = "cohortavatarurl";

		private const string CohortAllString = "cohortall";

		private readonly INativeCompetitionDatabase nativeCompetitionDatabase;

		public override string Scheme => "leaderboard";

		public WebViewLeaderboardProvider(INativeCompetitionDatabase nativeCompetitionDatabase)
		{
			this.nativeCompetitionDatabase = nativeCompetitionDatabase;
		}

		public override string[] GetAllSupportedKeys()
		{
			return new string[9] { "cohortcount", "cohortuserid", "cohortname", "cohorttype", "cohortgender", "cohortage", "cohortdistance", "cohortavatarurl", "cohortall" };
		}

		public override async Task<string> GetData(Uri uri)
		{
			string[] paramsArray = uri.PathAndQuery.TrimStart('/').Split('/', StringSplitOptions.RemoveEmptyEntries);
			return uri.Host switch
			{
				"cohortcount" => $"{nativeCompetitionDatabase.Cohorts.Count}", 
				"cohortuserid" => GetCohortUserIdString(paramsArray), 
				"cohortname" => GetCohortNameString(paramsArray), 
				"cohortgender" => GetCohortGenderString(paramsArray), 
				"cohortage" => GetCohortAgeString(paramsArray), 
				"cohorttype" => GetCohortTypeString(paramsArray), 
				"cohortdistance" => GetCohortDistanceString(paramsArray), 
				"cohortavatarurl" => GetCohortAvatarUrlString(paramsArray), 
				"cohortall" => GetCohortAllString(), 
				_ => throw new KeyNotSupportedException(), 
			};
		}

		private string GetCohortUserIdString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			return nativeCompetitionDatabase.Cohorts[index].UserId;
		}

		private string GetCohortNameString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			return nativeCompetitionDatabase.Cohorts[index].Name;
		}

		private string GetCohortGenderString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			return nativeCompetitionDatabase.Cohorts[index].Gender;
		}

		private string GetCohortAgeString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			return $"{nativeCompetitionDatabase.Cohorts[index].Age}";
		}

		private string GetCohortTypeString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			return nativeCompetitionDatabase.Cohorts[index].Type.ToString();
		}

		private string GetCohortDistanceString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			double value = nativeCompetitionDatabase.Cohorts[index].Stats.Distance.Last().Value;
			return $"{value:0.0}";
		}

		private string GetCohortAvatarUrlString(string[] paramsArray)
		{
			int index = paramsArray.ToIndex();
			return nativeCompetitionDatabase.Cohorts[index].AvatarUrl;
		}

		private string GetCohortAllString()
		{
			int count = nativeCompetitionDatabase.Cohorts.Count;
			object value = nativeCompetitionDatabase.Cohorts.FirstOrDefault((CompetitionParticipant c) => c.Type == ParticipantType.Trainer).PostWorkoutParticipantClean();
			object value2 = nativeCompetitionDatabase.Cohorts.FirstOrDefault((CompetitionParticipant c) => c.Type == ParticipantType.You).PostWorkoutParticipantClean();
			IEnumerable<object> value3 = from c in nativeCompetitionDatabase.Cohorts.FindAll((CompetitionParticipant c) => c.Type == ParticipantType.Other)
				select c.PostWorkoutParticipantClean();
			return JsonConvert.SerializeObject(new Dictionary<string, object>
			{
				{ "cohortCount", count },
				{ "currentUser", value2 },
				{ "trainer", value },
				{ "challengers", value3 }
			});
		}
	}
