	{
		private const string CohortIndexNotFoundExceptionMessage = "WebView Leaderboard Provider: Cohort Index not found";

		public static int ToIndex(this string[] paramsArray)
		{
			if (paramsArray.Length == 1)
			{
				return int.Parse(paramsArray[0]);
			}
			throw new KeyNotSupportedException("WebView Leaderboard Provider: Cohort Index not found");
		}
	}
