		{
			ActivityLog activityLog = await recentActivityLogMonitor.GetLatestLog();
			string text = ((activityLog == null) ? "" : JsonConvert.SerializeObject(activityLog));
			string host = uri.Host;
			if (!(host == "latest"))
			{
				if (!(host == "latestwithstats"))
				{
