			coreAssemblies = (from x in AppDomain.CurrentDomain.GetAssemblies()
				where assembliesToInclude.Any((string y) => x.FullName.ToLower().Contains(y))
				select x).ToList();
		}

		public override async Task<string> GetData(Uri uri)
		{
			if (uri.PathAndQuery.Contains("/SoftwareNumber"))
			{
				return await modalityChangeService.GetOverrideSoftwareNumber(deviceInformation?.SoftwareNumber.ToString());
			}
			if (uri.PathAndQuery.Contains("/LastKnownConsoleType"))
			{
				return modalityChangeService.GetOverrideConsoleType(currentConsoleService?.LastKnownConsoleType.ToString());
			}
			string typeName = uri.Host;
			Stack<string> stack = new Stack<string>(Enumerable.Reverse(uri.PathAndQuery.TrimStart('/').Split('/')));
			if (stack.Count == 0)
			{
				throw new KeyNotSupportedException("At least one field is required to be passed");
			}
			Type type = coreAssemblies.SelectMany((Assembly x) => x.GetTypes()).FirstOrDefault((Type x) => x.Name?.ToLower() == typeName);
			if (type != null && Mvx.TryResolve(type, out var service))
			{
				return GetData(service, type, stack);
			}
			throw new KeyNotSupportedException("Requested type does not exist");
		}

		private string GetData(object obj, Type objType, Stack<string> fieldNames)
		{
			if (fieldNames.Count == 0)
			{
				throw new KeyNotSupportedException("Reflection data provider didn't recognize key");
			}
			string fieldName = fieldNames.Pop();
			PropertyInfo[] properties = objType.GetProperties();
			PropertyInfo propertyInfo = properties.FirstOrDefault((PropertyInfo x) => x.Name.ToLower() == fieldName.ToLower());
			if (propertyInfo == null || propertyInfo.PropertyType.IsArray)
			{
				throw new KeyNotSupportedException("Reflection data provider didn't recognize key " + fieldName);
			}
			Type underlyingType = Nullable.GetUnderlyingType(propertyInfo.PropertyType);
			if ((propertyInfo.PropertyType.IsGenericType && propertyInfo.PropertyType.GetGenericTypeDefinition() == typeof(List<>)) || (underlyingType != null && underlyingType.IsGenericType && underlyingType.GetGenericTypeDefinition() == typeof(List<>)))
			{
				return System.Text.Json.JsonSerializer.Serialize(propertyInfo.GetValue(obj, null));
			}
			if (propertyInfo.PropertyType.IsEnum || propertyInfo.PropertyType.IsPrimitive || propertyInfo.PropertyType == typeof(Guid) || propertyInfo.PropertyType == typeof(string) || underlyingType == typeof(Guid) || underlyingType == typeof(string) || ((object)underlyingType != null && underlyingType.IsEnum) || ((object)underlyingType != null && underlyingType.IsPrimitive))
			{
				string text = obj.GetPropertyValueAsString(propertyInfo);
				if (fieldName == "BrainboardSerialNumber")
				{
					text = text.ToAsciiHexString();
				}
				return text;
			}
			object value = propertyInfo.GetValue(obj, null);
			if (value == null)
			{
				throw new KeyNotSupportedException("Reflection data provider didn't recognize key");
			}
			return GetData(value, propertyInfo.PropertyType, fieldNames);
		}

		public override string[] GetAllSupportedKeys()
		{
			return new string[1] { "" };
		}
	}
