	[Serializable]
	public class WebViewBehaviorsService : IWebViewBehaviorsService
	{
		public const string NativeMethodRunBehavior = "RunBehavior";

		public const string WebViewMethodBehaviorRan = "BehaviorRan";

		public const string WebViewMethodRunBehaviorEcho = "RunBehaviorEcho";

		public const string RespondKey = "respond";

		public const string ResponseKey = "response";

		public const string BehaviorNameKey = "key";

		public const string ErrorKey = "error";

		public const string BridgeCallKey = "bridgeCall";

		private const string LogTag = "WebViewBehaviorsService";

		private readonly List<IWebViewBehaviorProvider> providers = new List<IWebViewBehaviorProvider>();

		private readonly IShareWorkoutBehaviorProvider shareWorkoutBehaviorProvider;

		private readonly ILogOutService logOutService;

		private readonly ISetUnitsService setUnitsService;

		private List<string> behaviorsCache = new List<string>();

		public WebViewBehaviorsService(IShareWorkoutBehaviorProvider shareWorkoutBehaviorProvider, ILogOutService logOutService, ISetUnitsService setUnitsService)
		{
			this.shareWorkoutBehaviorProvider = shareWorkoutBehaviorProvider;
			this.logOutService = logOutService;
			this.setUnitsService = setUnitsService;
			InitializeProviders();
		}

		private void InitializeProviders()
		{
			RegisterProvider(new ShowDialogBehaviorProvider());
			RegisterProvider(new CloseViewModelBehaviorProvider());
			RegisterProvider(new WebviewControlsBackNavBehaviorProvider());
			RegisterProvider(new NavigateBackBehaviorProvider());
			RegisterProvider(new ToggleNativeLoadingIndicatorBehaviorProvider());
			RegisterProvider(Mvx.IocConstruct<NavigateToPathBehaviorProvider>());
			RegisterProvider(new ShowUpgradeFlowBehaviorProvider());
			RegisterProvider(new HandleWebviewErrorBehaviorProvider());
			RegisterProvider(new PaymentBehaviorProvider());
			RegisterProvider(shareWorkoutBehaviorProvider);
			RegisterProvider(Mvx.IocConstruct<UpgradeService>());
			RegisterProvider(Mvx.IocConstruct<StartManualWorkoutService>());
			RegisterProvider(setUnitsService as IWebViewBehaviorProvider);
			RegisterProvider(logOutService as IWebViewBehaviorProvider);
			RegisterProvider(Mvx.IocConstruct<CommonWorkoutModalClosedBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<DeleteActivityLogBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<StartWorkoutBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<JoinLiveWorkoutBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<OpenUrlBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<ScrollBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<ForceRefreshUserBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<ShowNativeWhoopsScreenBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<PreloadWorkoutBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<ProgramSelectedBehaviorProvider>());
			RegisterProvider(Mvx.IocConstruct<ShowDetailsBehaviorProvider>());
		}

		public Task RunBehavior(string behaviorName, IDictionary<string, string> parameters, BaseWebViewViewModel viewModel)
		{
			if (string.IsNullOrWhiteSpace(behaviorName))
			{
				throw new KeyNotSupportedException("Behavior name is empty");
			}
			if (parameters == null)
			{
				parameters = new Dictionary<string, string>();
			}
			string text = (parameters.Any() ? (" with parameters: " + string.Join(", ", parameters.Take(100))) : string.Empty);
			string text2 = "Behavior run requested: " + behaviorName + ", by " + viewModel.LogTag + text;
			Log.Trace("WebViewBehaviorsService", text2);
			if (SupportsBehavior(behaviorName))
			{
				return DoRunBehavior(behaviorName, parameters, viewModel);
			}
			Log.Error("WebViewBehaviorsService", "No provider found for behavior name " + behaviorName);
			throw new KeyNotSupportedException("No provider found for behavior name " + behaviorName);
		}

		public async Task DoRunBehavior(string behaviorName, IDictionary<string, string> parameters, BaseWebViewViewModel viewModel)
		{
			IWebViewBehaviorProvider webViewBehaviorProvider = providers.Last((IWebViewBehaviorProvider p) => p.SupportsBehavior(behaviorName));
			if (viewModel.BeforeBehaviorRun(behaviorName, parameters))
			{
				await webViewBehaviorProvider.RunBehavior(behaviorName, parameters, viewModel);
				viewModel.AfterBehaviorRun(behaviorName, parameters);
			}
		}

		public bool SupportsBehavior(string name)
		{
			return GetAllBehaviors().Contains(name);
		}

		public void RegisterProvider(IWebViewBehaviorProvider provider)
		{
			IEnumerable<string> allBehaviors = GetAllBehaviors();
			if (allBehaviors.Any((string x) => provider.BehaviorName == x))
			{
				throw new ArgumentException("Attempted to register a provider, that contains behaviors that were already registered");
			}
			if (!providers.Contains(provider))
			{
				providers.Add(provider);
				behaviorsCache.Add(provider.BehaviorName);
				if (provider.BehaviorName != provider.LegacyBehaviorName)
				{
					behaviorsCache.Add(provider.LegacyBehaviorName);
				}
			}
			else
			{
				Log.Warn("WebViewBehaviorsService", $"Warning: Attempted to register a provider, but the instance is already registered. The provider's scheme is '{provider.GetType()}'.");
			}
		}

		public void RegisterProviderAndOverride(IWebViewBehaviorProvider provider)
		{
			if (!providers.Contains(provider))
			{
				providers.Add(provider);
				behaviorsCache.Add(provider.BehaviorName);
				if (provider.BehaviorName != provider.LegacyBehaviorName)
				{
					behaviorsCache.Add(provider.LegacyBehaviorName);
				}
			}
			else
			{
				Log.Warn("WebViewBehaviorsService", $"Warning: Attempted to register a provider, but the instance is already registered. The provider's scheme is '{provider.GetType()}'.");
			}
		}

		public void UnregisterProvider(IWebViewBehaviorProvider provider)
		{
			providers.Remove(provider);
			behaviorsCache.Remove(provider.BehaviorName);
			if (provider.BehaviorName != provider.LegacyBehaviorName)
			{
				behaviorsCache.Remove(provider.LegacyBehaviorName);
			}
		}

		public IEnumerable<string> GetAllBehaviors()
		{
			return behaviorsCache.Distinct();
		}
	}
