	public class WebViewConfigService : IWebViewConfigService
	{
		private const string OrientationLandscape = "landscape";

		private const string OrientationPortrait = "portrait";

		private readonly IAppVersionService appVersionService;

		private readonly IDeviceInformation deviceInformation;

		private readonly IHardwareInfo hardwareInfo;

		private readonly IIfitApiService ifitApiService;

		private readonly ISettingsRouter settingsRouter;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IThemeService themeService;

		private readonly IModalityChangeService modalityChangeService;

		private readonly IChangeLanguageService changeLanguageService;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWolfTrackingService trackingService;

		private readonly IReadOnlyDictionary<RequiredConfigs, string> requiredConfigKeys = new Dictionary<RequiredConfigs, string>
		{
			[RequiredConfigs.AppVersion] = "appVersion",
			[RequiredConfigs.DeviceType] = "deviceType",
			[RequiredConfigs.SoftwareNumber] = "softwareNumber",
			[RequiredConfigs.Embedded] = "isEmbedded",
			[RequiredConfigs.ColorScheme] = "colorScheme",
			[RequiredConfigs.PlanetFitnessUser] = "isPlanetFitnessUser",
			[RequiredConfigs.Platform] = "platform",
			[RequiredConfigs.GatewayUrl] = "baseGatewayAPIUrl",
			[RequiredConfigs.UseMetricUnits] = "useMetricUnits",
			[RequiredConfigs.DeviceOrientation] = "deviceOrientation",
			[RequiredConfigs.IsClub] = "isClub",
			[RequiredConfigs.EquipmentType] = "equipmentType",
			[RequiredConfigs.IsStrengthMirror] = "isVault",
			[RequiredConfigs.Language] = "language",
			[RequiredConfigs.AvailableMemory] = "availableMemory",
			[RequiredConfigs.TotalMemory] = "totalMemory",
			[RequiredConfigs.LowMemoryThreshold] = "lowMemoryThreshold"
		};

		private readonly IReadOnlyDictionary<OptionalConfigs, string> optionalConfigKeys = new Dictionary<OptionalConfigs, string>
		{
			[OptionalConfigs.UserId] = "userId",
			[OptionalConfigs.BearerToken] = "token",
			[OptionalConfigs.MembershipType] = "membershipType",
			[OptionalConfigs.IsFirstRun] = "isFirstRun",
			[OptionalConfigs.FeatureFlags] = "featureFlags"
		};

		private string appVersion => appVersionService?.MainAppVersionInfo?.AppVersion ?? string.Empty;

		private Task<string> bearerToken => ifitApiService?.GetToken();

		private string deviceType
		{
			get
			{
				IDeviceInformation obj = deviceInformation;
				if (obj != null && !obj.IsTablet)
				{
					return WebviewParamValues.Phone;
				}
				return WebviewParamValues.Tablet;
			}
		}

		private string equipmentType
		{
			get
			{
				if (!modalityChangeService.HybridConsoleTypeOverride.IsNullOrWhitespace())
				{
					return modalityChangeService.HybridConsoleTypeOverride;
				}
				return currentConsoleService?.GetCurrentConsoleType(ConsoleType.None).ToString();
			}
		}

		private string gatewayUrl => ifitApiService?.Environment.BaseGatewayAPIUrl.TrimEnd('/');

		private string isPlanetFitnessUser
		{
			get
			{
				IIfitApiService obj = ifitApiService;
				return (obj != null && obj.CurrentlyAuthenticatedUser?.IsPlanetFitnessUser == true).WebviewParamValue();
			}
		}

		private string softwareNumber
		{
			get
			{
				if (!modalityChangeService.HybridSoftwareNumberOverride.IsNullOrWhitespace())
				{
					return modalityChangeService.HybridSoftwareNumberOverride;
				}
				return deviceInformation?.SoftwareNumber.ToString();
			}
		}

		private string isEmbedded => (deviceInformation?.IsBuiltIn ?? false).WebviewParamValue();

		private string isClub => (currentConsoleService?.IsBuiltinClub ?? false).WebviewParamValue();

		private string platform => hardwareInfo.OperatingSystem.ToLowerInvariant();

		private string membershipType
		{
			get
			{
				IIfitApiService obj = ifitApiService;
				if (obj == null || obj.CurrentlyAuthenticatedUser?.Premium != true)
				{
					return User.SubscriptionTypes.Free.GetAttribute<EnumMemberAttribute>().Value;
				}
				return User.SubscriptionTypes.Premium.GetAttribute<EnumMemberAttribute>().Value;
			}
		}

		private string colorScheme
		{
			get
			{
				IDeviceInformation obj = deviceInformation;
				if (obj != null && obj.UseHeadlessBikeTheme)
				{
					return Theme.StrengthMirror.GetEnumMemberAttributeValue();
				}
				return (themeService?.CurrentTheme() ?? Theme.Light).GetEnumMemberAttributeValue();
			}
		}

		private string isStrengthMirror => (deviceInformation?.IsStrengthMirror ?? false).WebviewParamValue();

		private string languageCode => changeLanguageService.WebviewLanguageCode;

		private Task<string> useMetricUnits => Task.Run(async () => (await settingsRouter.GetIsMetric()).WebviewParamValue());

		private string userId => ifitApiService?.CurrentlyAuthenticatedUserId;

		private string deviceOrientation
		{
			get
			{
				IDeviceInformation obj = deviceInformation;
				if (obj != null && obj.IsStrengthMirror)
				{
					return "portrait";
				}
				return deviceInformation?.DeviceOrientation;
			}
		}

		public WebViewConfigService(IAppVersionService appVersionService, IDeviceInformation deviceInformation, IHardwareInfo hardwareInfo, IIfitApiService ifitApiService, ISettingsRouter settingsRouter, IFeatureFlagManager featureFlagManager, IThemeService themeService, IModalityChangeService modalityChangeService, IChangeLanguageService changeLanguageService, IWolfTrackingService trackingService, ICurrentConsoleService currentConsoleService)
		{
			this.appVersionService = appVersionService;
			this.deviceInformation = deviceInformation;
			this.hardwareInfo = hardwareInfo;
			this.ifitApiService = ifitApiService;
			this.settingsRouter = settingsRouter;
			this.featureFlagManager = featureFlagManager;
			this.themeService = themeService;
			this.modalityChangeService = modalityChangeService;
			this.changeLanguageService = changeLanguageService;
			this.currentConsoleService = currentConsoleService;
			this.trackingService = trackingService;
		}

		public async Task<Dictionary<string, string>> GetBaseConfigsExcluding(OptionalConfigs excludeConfigs = (OptionalConfigs)0)
		{
			return (await GetRequiredConfigs()).Union(await GetOptionalConfigs(excludeConfigs)).ToDictionary((KeyValuePair<string, string> k) => k.Key, (KeyValuePair<string, string> v) => v.Value);
		}

		private async Task<Dictionary<string, string>> GetRequiredConfigs()
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>
			{
				{
					requiredConfigKeys[RequiredConfigs.AppVersion],
					appVersion
				},
				{
					requiredConfigKeys[RequiredConfigs.DeviceType],
					deviceType
				}
			};
			Dictionary<string, string> dictionary2 = dictionary;
			string key = requiredConfigKeys[RequiredConfigs.SoftwareNumber];
			dictionary2.Add(key, await modalityChangeService.GetOverrideSoftwareNumber(softwareNumber));
			dictionary.Add(requiredConfigKeys[RequiredConfigs.Embedded], isEmbedded);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.ColorScheme], colorScheme);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.PlanetFitnessUser], isPlanetFitnessUser);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.Platform], platform);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.GatewayUrl], gatewayUrl);
			Dictionary<string, string> dictionary3 = dictionary;
			string key2 = requiredConfigKeys[RequiredConfigs.UseMetricUnits];
			dictionary3.Add(key2, await useMetricUnits);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.DeviceOrientation], deviceOrientation);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.IsClub], isClub);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.EquipmentType], modalityChangeService.GetOverrideConsoleType(equipmentType));
			dictionary.Add(requiredConfigKeys[RequiredConfigs.IsStrengthMirror], isStrengthMirror);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.Language], languageCode);
			dictionary.Add(requiredConfigKeys[RequiredConfigs.AvailableMemory], deviceInformation.AvailableMemory.ToString());
			dictionary.Add(requiredConfigKeys[RequiredConfigs.TotalMemory], deviceInformation.TotalMemory.ToString());
			dictionary.Add(requiredConfigKeys[RequiredConfigs.LowMemoryThreshold], deviceInformation.LowMemoryThreshold.ToString());
			return dictionary;
		}

		private async Task<Dictionary<string, string>> GetOptionalConfigs(OptionalConfigs excludeConfigs)
		{
			if (excludeConfigs == OptionalConfigs.All)
			{
				return new Dictionary<string, string>();
			}
			Dictionary<string, string> optionalConfigs = new Dictionary<string, string>(optionalConfigKeys.Count);
			if (!excludeConfigs.HasFlag(OptionalConfigs.UserId))
			{
				optionalConfigs.Add(optionalConfigKeys[OptionalConfigs.UserId], userId);
			}
			if (!excludeConfigs.HasFlag(OptionalConfigs.BearerToken))
			{
				Dictionary<string, string> dictionary = optionalConfigs;
				string key = optionalConfigKeys[OptionalConfigs.BearerToken];
				dictionary.Add(key, await bearerToken);
			}
			if (!excludeConfigs.HasFlag(OptionalConfigs.MembershipType))
			{
				optionalConfigs.Add(optionalConfigKeys[OptionalConfigs.MembershipType], membershipType);
			}
			if (!excludeConfigs.HasFlag(OptionalConfigs.IsFirstRun))
			{
				optionalConfigs.Add(optionalConfigKeys[OptionalConfigs.IsFirstRun], (trackingService?.FirstRun ?? true).WebviewParamValue());
			}
			if (!excludeConfigs.HasFlag(OptionalConfigs.FeatureFlags))
			{
				optionalConfigs.Add(optionalConfigKeys[OptionalConfigs.FeatureFlags], GetFeatureFlagConfigs());
			}
			return optionalConfigs;
		}

		private string GetFeatureFlagConfigs()
		{
			if (featureFlagManager == null)
			{
				return null;
			}
			Dictionary<string, object> value = FeatureFlags.AllFlags.ToDictionary((FeatureFlag x) => x.Key, GetFeatureFlagValue);
			return JsonConvert.SerializeObject(value);
			object GetFeatureFlagValue(FeatureFlag featureFlag)
			{
				switch (featureFlag.Type)
				{
				case FeatureFlagType.Bool:
					return featureFlagManager.IsFeatureEnabled(featureFlag);
				case FeatureFlagType.String:
				case FeatureFlagType.WebviewUrl:
				{
					string text = featureFlagManager.GetString(featureFlag) ?? "";
					try
					{
						return (JObject)JsonConvert.DeserializeObject(text);
					}
					catch
					{
						return text;
					}
				}
				case FeatureFlagType.Int:
					return featureFlagManager.GetInt(featureFlag);
				default:
					return string.Empty;
				}
			}
		}
	}
