		public const string WebMethodDataAvailable = "DataAvailable";

		public static readonly string[] SensitiveDataKeys = new string[29]
		{
			"api-url", "gateway-url", "bearer-token", "client-id", "client-secret", "segment-id", "moesif-application-id", "raygun-id", "facebook-app-id", "environment-type",
			"base-site", "speed-test-endpoint", "debug-endpoint", "onboarding-client-id", "onboarding-client-secret", "launch-darkly-mobile-key", "dashboard-client-id", "dashboard-client-secret", "log-screen-client-id", "log-screen-client-secret",
			"library-client-id", "library-client-secret", "email", "facebook", "google", "location", "first-name", "full-name", "last-name"
		};

		private readonly List<IWebViewDataProvider> providers = new List<IWebViewDataProvider>();

