		public WebViewDataService(IWebViewConsoleInfoProvider webViewConsoleInfoProvider, IWebViewApiInfoProvider webViewApiInfoProvider, IWebViewDeviceInfoProvider webViewDeviceInfoProvider, IWebViewFeatureFlagProvider webViewFeatureFlagProvider, IWebViewUserInfoProvider webViewUserInfoProvider, IWebViewAppInfoProvider webViewAppInfoProvider, IWebViewRecentActivityLogProvider webViewRecentLogActivitiesDataProvider, IWebViewApiProvider webViewApiProvider, IModalityChangeService modalityChangeService, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IAchievementStatsProvider achievementStatsProvider, IWebViewLeaderboardProvider webViewLeaderboardProvider)
		{
