		public Task<string> GetData(string uri)
		{
			if (!Uri.IsWellFormedUriString(uri, UriKind.Absolute))
			{
				throw new KeyNotSupportedException();
			}
			return GetData(new Uri(uri));
		}

		public Task<string> GetData(Uri uri)
		{
			Log.Trace("WebViewDataService", "Data item requested: " + uri.OriginalString);
			string scheme = uri.Scheme;
			if (SupportsScheme(scheme))
			{
				IWebViewDataProvider webViewDataProvider = providers.First((IWebViewDataProvider p) => p.Scheme == scheme);
				return webViewDataProvider.GetData(uri);
			}
			Log.Error("WebViewDataService", "No scheme provider found for " + uri.Scheme);
			throw new SchemeNotSupportedException("Scheme provider '" + scheme + "' not supported");
		}

		public bool SupportsScheme(string scheme)
		{
			return providers.Any((IWebViewDataProvider p) => p.Scheme == scheme);
		}

		public void RegisterProvider(IWebViewDataProvider provider)
		{
			if (SupportsScheme(provider.Scheme))
			{
				Log.Warn("WebViewDataService", "Warning: Registering a provider for scheme '" + provider.Scheme + "', but another provider already handles that scheme. Behavior may be undefined.");
			}
			if (!providers.Contains(provider))
			{
				providers.Add(provider);
			}
			else
			{
				Log.Warn("WebViewDataService", "Warning: Attempted to register a provider, but the instance is already registered. The provider's scheme is '" + provider.Scheme + "'.");
			}
		}

		public void UnregisterProvider(IWebViewDataProvider provider)
		{
			providers.Remove(provider);
		}

		public List<IWebViewDataProvider> GetRegisteredProviders()
		{
			return providers;
		}

		public async Task<IDictionary<string, string>> GetData(IDictionary<string, string> obj)
		{
			string value = null;
			if (!obj.TryGetValue("keys", out value) || obj["keys"] == null)
			{
				Log.Trace("WebViewDataService", $"No keys requested. Param object was: {obj}");
				return null;
			}
			string[] array = (from k in value.Split(',')
				select k.Trim()).ToArray();
			Dictionary<string, string> dict = new Dictionary<string, string>();
			if (obj.TryGetValue("echo", out var value2))
			{
				dict["echo"] = value2;
			}
			List<string> errorKeys = new List<string>();
			string[] array2 = array;
			foreach (string uri in array2)
			{
				try
				{
					Dictionary<string, string> dictionary = dict;
					string key = uri;
					dictionary[key] = await GetData(uri);
				}
				catch (SchemeNotSupportedException exception)
				{
					Log.Trace("WebViewDataService", "SchemeNotSupported: " + uri + ":", exception);
					errorKeys.Add(uri);
				}
				catch (KeyNotSupportedException exception2)
				{
					Log.Trace("WebViewDataService", "KeyNotSupported: " + uri, exception2);
					errorKeys.Add(uri);
				}
				catch (Exception exception3)
				{
					Log.Trace("WebViewDataService", "KeyThrewException: " + uri, exception3);
					errorKeys.Add(uri);
				}
			}
			if (errorKeys.Any())
			{
				dict["errors"] = string.Join(',', errorKeys);
			}
			return dict;
		}
	}
