	}
	public class WebViewUrlParameterService : IWebViewUrlParameterService
	{
		private readonly ILocalSettings localSettings;

		private readonly IFeatureFlagManager featureFlags;

		private readonly IThemeService themeService;

		private readonly IWebviewSettings webviewSettings;

		private readonly IDeviceInformation deviceInformation;

		private static FragmentAppendMode UrlFragmentAppendMode => FragmentAppendMode.AfterQueryString;

		public WebViewUrlParameterService(ILocalSettings localSettings, IFeatureFlagManager featureFlags, IThemeService themeService, IWebviewSettings webviewSettings, IDeviceInformation deviceInformation)
		{
			this.localSettings = localSettings;
			this.featureFlags = featureFlags;
			this.themeService = themeService;
			this.webviewSettings = webviewSettings;
			this.deviceInformation = deviceInformation;
		}

		public string GenerateWebViewUrlWithParameters(string url, IDictionary<string, string> webViewQueryParameters = null)
		{
			if (webViewQueryParameters == null)
			{
				webViewQueryParameters = GetVerboseAndColorSchemeParameters(webviewSettings.IsWebviewVerboseMode, featureFlags.IsFeatureEnabled(FeatureFlags.WolfColorSchemeFeature) || deviceInformation.IsStrengthMirror);
			}
			string text = null;
			try
			{
				try
				{
					text = new Uri(url).GetUrlFragment();
				}
				catch (Exception exception)
				{
					Log.Error("WebView", "Could not parse fragment from webview url: " + (url ?? "<null>"), exception);
				}
				Uri uri = new Uri(url).AppendOrReplaceQueryVars(webViewQueryParameters, MergeMode.MergeReplacingExisting, shouldUrlEncodeParams: true, text, UrlFragmentAppendMode);
				return uri.AbsoluteUri;
			}
			catch (Exception exception2)
			{
				Log.Error("WebView", "Could not generate webview url with provided params (" + (webViewQueryParameters?.BuildQueryStringFromVars() ?? "<null>") + ") and fragment (" + (text ?? "<null>") + "). Base url: " + url, exception2);
				return url;
			}
		}

		public Dictionary<string, string> GetVerboseAndColorSchemeParameters(bool appendVerboseToUrl, bool appendColorSchemeToUrl)
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			if (appendVerboseToUrl && webviewSettings.IsWebviewVerboseMode)
			{
				dictionary["verbose"] = null;
			}
			if (appendColorSchemeToUrl && (deviceInformation.IsStrengthMirror || featureFlags.IsFeatureEnabled(FeatureFlags.WolfColorSchemeFeature)))
			{
				Theme theme = ((!deviceInformation.IsStrengthMirror) ? Theme.Light : Theme.StrengthMirror);
				if (themeService != null)
				{
					theme = ((!deviceInformation.UseHeadlessBikeTheme) ? themeService.CurrentTheme() : Theme.StrengthMirror);
				}
				dictionary["colorScheme"] = theme.GetEnumMemberAttributeValue();
			}
			return dictionary;
		}
	}
