namespace Wolf.Core.Services.UploadWorkoutLogs
{
	public interface IAppleHealthUploadLogService
	{
		Task<UploadWorkoutLogItem> UploadLog(ActivityLog log);
	}
	public class AppleHealthUploadLogService : IAppleHealthUploadLogService
	{
		private readonly IActivityLogRepository activityLogRepository;

		private readonly IFailedUploadMonitor failedUploadMonitor;

		private readonly IWorkoutSettings workoutSettings;

		private HashSet<string> WorkoutTypesThatRequireMinimumDistance => new HashSet<string>
		{
			Workout.WorkoutType.Run.GetEnumMemberAttributeValue(),
			Workout.WorkoutType.Cycle.GetEnumMemberAttributeValue()
		};

		public AppleHealthUploadLogService(IActivityLogRepository activityLogRepository, IFailedUploadMonitor failedUploadMonitor, IWorkoutSettings workoutSettings)
		{
			this.activityLogRepository = activityLogRepository;
			this.failedUploadMonitor = failedUploadMonitor;
			this.workoutSettings = workoutSettings;
		}

		public async Task<UploadWorkoutLogItem> UploadLog(ActivityLog log)
		{
			UploadWorkoutLogItem workoutLogItem = new UploadWorkoutLogItem
			{
				ActivityLog = log
			};
			if (log == null)
			{
				Log.Warn("HealthKit", "Attempted to upload null ActivityLog from AppleHealthUploadLogService");
				workoutLogItem.UploadResult = new DetailedUploadResult(UploadResult.NoLog, ErrorCode.LogUploadLogNullError);
			}
			else if (log.Duration < workoutSettings.MinimumWorkoutDuration)
			{
				Log.Debug("HealthKit", string.Format("Failed to upload ActivityLog in {0} because its duration ({1}) is under the minimum required ({2}). Will not retry", "AppleHealthUploadLogService", log.Duration, workoutSettings.MinimumWorkoutDuration));
				workoutLogItem.UploadResult = (DetailedUploadResult)UploadResult.UnderMinTime;
			}
			else if (!HasMinimumDistance(log))
			{
				Log.Debug("HealthKit", string.Format("Failed to upload ActivityLog in {0} because its distance ({1}) is under the minimum required ({2}). Will not retry", "AppleHealthUploadLogService", log.Summary?.TotalMeters ?? 0.0, workoutSettings.MinimumWorkoutDistance));
				workoutLogItem.UploadResult = (DetailedUploadResult)UploadResult.UnderMinDistance;
			}
			else
			{
				UploadWorkoutLogItem uploadWorkoutLogItem = workoutLogItem;
				uploadWorkoutLogItem.UploadResult = await activityLogRepository.AttemptToUploadLog(log, isRetry: false);
				switch (workoutLogItem.UploadResult.Result)
				{
				case UploadResult.APIUploadErrorRetry:
				case UploadResult.UnknownUploadError:
				case UploadResult.NoNetwork:
				case UploadResult.Timeout:
					await failedUploadMonitor.AddLogToQueue(workoutLogItem);
					break;
				}
			}
			return workoutLogItem;
		}

		private bool HasMinimumDistance(ActivityLog log)
		{
			if (WorkoutTypesThatRequireMinimumDistance.Contains(log.Type ?? ""))
			{
				if (log.Summary == null)
				{
					return false;
				}
				return log.Summary.TotalMeters >= workoutSettings.MinimumWorkoutDistance;
			}
			return true;
		}
	}
	public interface IFailedUploadMonitor
	{
		Task AddLogToQueue(UploadWorkoutLogItem workoutLogItem);

		Task RemoveLogItem(Guid logItemId);

		Task AttemptToUploadOldLogs();

		void StartRetryTimer();
	}
	public class FailedUploadMonitor : IFailedUploadMonitor
	{
		private const int MaxQueuedLogs = 10;

		private static readonly int[] DelayMinutes = new int[5] { 1, 5, 15, 30, 60 };

		private static readonly TimeSpan ExpirationTime = TimeSpan.FromDays(7.0);

		private static readonly TimeSpan Forever = TimeSpan.FromDays(365.0);

		private const string LogsCacheKey = "failedActivityLogs";

		private const string LogTag = "FailedUploadMonitor";

		private readonly string InstanceName;

		private readonly IIfitApiService ifitApi;

		private readonly ILocalSettings localSettings;

		private readonly IConnectivity connectivity;

		private readonly IActivityLogRepository activityLogRepository;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IBlobCacheService blobCacheService;

		private readonly Random randomizer;

		private readonly IEnumerable<ConsoleState> restrictedConsoleStates = new ConsoleState[5]
		{
			ConsoleState.WarmUp,
			ConsoleState.Workout,
			ConsoleState.CoolDown,
			ConsoleState.Paused,
			ConsoleState.PauseOverride
		};

		private SemaphoreSlim attemptLock;

		private bool connectedToInternet;

		private bool isAttempting;

		private int currentDelayPosition;

		private IDisposable periodicTimerSub;

		private List<UploadWorkoutLogItem> queuedActivityLogs;

		private readonly bool persistLogsOnDisk;

		private readonly Task initialization;

		public FailedUploadMonitor(ILocalSettings localSettings, IIfitApiService ifitApi, IConnectivity connectivity, IActivityLogRepository activityLogRepository, IBlobCacheService blobCacheService, IWorkoutSettings workoutSettings, string instanceName = "", bool persistLogsOnDisk = true)
		{
			this.ifitApi = ifitApi;
			this.localSettings = localSettings;
			this.connectivity = connectivity;
			this.activityLogRepository = activityLogRepository;
			this.workoutSettings = workoutSettings;
			this.persistLogsOnDisk = persistLogsOnDisk;
			this.blobCacheService = blobCacheService;
			initialization = Task.Run((Func<Task>)LoadSavedLogs);
			randomizer = new Random();
			attemptLock = new SemaphoreSlim(1, 1);
			InstanceName = instanceName;
			connectedToInternet = connectivity.IsConnected;
			connectivity.ConnectivityChanged -= ConnectivityChanged;
			connectivity.ConnectivityChanged += ConnectivityChanged;
		}

		private async Task LoadSavedLogs()
		{
			if (!persistLogsOnDisk)
			{
				queuedActivityLogs = new List<UploadWorkoutLogItem>();
				return;
			}
			try
			{
				queuedActivityLogs = await blobCacheService.Secure.GetObject<List<UploadWorkoutLogItem>>("failedActivityLogs");
			}
			catch (KeyNotFoundException)
			{
			}
			catch (Exception exception)
			{
				Log.Error("FailedUploadMonitor", "Caught exception getting queued logs", exception);
			}
			if (queuedActivityLogs == null)
			{
				queuedActivityLogs = new List<UploadWorkoutLogItem>();
			}
		}

		public void StartRetryTimer()
		{
			if (periodicTimerSub == null)
			{
				ResetPeriodicTimer();
			}
		}

		private void ResetPeriodicTimer()
		{
			periodicTimerSub?.Dispose();
			periodicTimerSub = Observable.Timer(PeriodBetweenUploadAttempts()).SubscribeWithErrorLogging(delegate
			{
				Task.Run((Func<Task>)AttemptToUploadOldLogs);
			});
			currentDelayPosition = (currentDelayPosition + 1).Clamp(0, DelayMinutes.Length - 1);
			Log.Trace("Wifi", $"UploadWorkoutLogsService (instance: {InstanceName}): Periodic timer reset to {DelayMinutes[currentDelayPosition]} minute(s).");
		}

		private TimeSpan PeriodBetweenUploadAttempts()
		{
			int num = DelayMinutes[currentDelayPosition.Clamp(0, DelayMinutes.Length - 1)];
			if (num == 1)
			{
				return TimeSpan.FromMinutes(1.0);
			}
			int num2 = Convert.ToInt32((double)num * 0.25 * randomizer.NextDouble());
			return TimeSpan.FromMinutes(randomizer.NextBoolean() ? (num + num2) : (num - num2));
		}

		private void ConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			Task.Run(async delegate
			{
				await CheckConnectivity();
			});
		}

		private async Task CheckConnectivity()
		{
			bool flag = connectedToInternet;
			connectedToInternet = connectivity?.IsConnected ?? false;
			if (flag != connectedToInternet && connectedToInternet)
			{
				await AttemptToUploadOldLogs();
			}
		}

		public async Task AddLogToQueue(UploadWorkoutLogItem workoutLogItem)
		{
			await initialization;
			await attemptLock.WaitAsync();
			try
			{
				workoutLogItem.LogItemId = Guid.NewGuid();
				queuedActivityLogs.Add(workoutLogItem);
				while (queuedActivityLogs.Count > 10)
				{
					queuedActivityLogs.RemoveAt(0);
				}
				currentDelayPosition = 0;
				ResetPeriodicTimer();
				await SaveQueuedActivityLogsOntoDisk();
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Could not add activity log to UploadWorkoutLogsService stack", exception);
			}
			finally
			{
				attemptLock?.Release();
			}
		}

		public async Task AttemptToUploadOldLogs()
		{
			await initialization;
			if (queuedActivityLogs.CountSafe() == 0)
			{
				return;
			}
			Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Starting old log upload attempt...");
			if (isAttempting)
			{
				Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Already attempting right now.");
				return;
			}
			if (!connectivity.IsConnected)
			{
				Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Internet connection required.");
				return;
			}
			if (!ifitApi.HasLoggedInUser)
			{
				Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Logged in user required.");
				return;
			}
			if (!IsAppropriateToUploadLogs())
			{
				Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Inappropriate time to upload logs.");
				return;
			}
			await attemptLock.WaitAsync();
			isAttempting = true;
			Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Attempt loop began.");
			List<Guid> guidsToRemove = new List<Guid>();
			foreach (UploadWorkoutLogItem logItem in queuedActivityLogs)
			{
				if (logItem?.ActivityLog != null)
				{
					Log.Trace("Api", $"FailedUploadMonitor (instance: {InstanceName}): Attempting to upload stored workout log: {logItem.LogItemId}");
					DetailedUploadResult detailedUploadResult = await activityLogRepository.AttemptToUploadLog(logItem.ActivityLog, isRetry: true);
					switch (detailedUploadResult.Result)
					{
					case UploadResult.APIUploadErrorRetry:
						Log.Error("Api", $"FailedUploadMonitor (instance: {InstanceName}): Encountered API error while trying to re-upload workout log (id: {logItem.LogItemId})--will try again later.");
						break;
					case UploadResult.NoNetwork:
						Log.Error("Api", $"FailedUploadMonitor (instance: {InstanceName}): Attempted to re-upload workout log (id: {logItem.LogItemId}) with no network--will try again later.");
						break;
					case UploadResult.Timeout:
						Log.Error("Api", $"FailedUploadMonitor (instance: {InstanceName}): Timed out while attempting to re-upload workout log (id: {logItem.LogItemId})--will try again later.");
						break;
					case UploadResult.SQLiteException:
						Log.Error("Api", $"FailedUploadMonitor (instance: {InstanceName}): A SQLite Exception occured while attempting to re-upload workout log (id: {logItem.LogItemId})--will try again later.");
						break;
					case UploadResult.UnknownUploadError:
						Log.Error("Api", $"FailedUploadMonitor (instance: {InstanceName}): An unknown error occurred while attempting to re-upload workout log (id: {logItem.LogItemId})--will try again later.");
						break;
					case UploadResult.Success:
						Log.Trace("Api", $"FailedUploadMonitor (instance: {InstanceName}): Successfully uploaded workout log (id: {logItem.LogItemId}) on re-upload attempt.");
						guidsToRemove.Add(logItem.LogItemId);
						logItem.ActivityLog.Dispose();
						break;
					case UploadResult.UnderMinTime:
					case UploadResult.UnderMinDistance:
					case UploadResult.APIUploadErrorNoRetry:
					case UploadResult.NoResult:
					case UploadResult.NoLog:
						Log.Error("Api", $"FailedUploadMonitor (instance: {InstanceName}): Encountered error ({detailedUploadResult.ToString()}) while trying to re-upload workout log (id: {logItem.LogItemId})--will NOT retry.");
						guidsToRemove.Add(logItem.LogItemId);
						logItem.ActivityLog.Dispose();
						break;
					default:
						Log.Error("Workout", $"It looks like we added the UploadResult case of {detailedUploadResult} and did not explicitly handle it explicitly.  This should not happen.");
						break;
					}
					if (!guidsToRemove.Contains(logItem.LogItemId) && DateTime.Now - logItem.ActivityLog.Start > ExpirationTime)
					{
						guidsToRemove.Add(logItem.LogItemId);
						logItem.ActivityLog.Dispose();
					}
				}
			}
			foreach (Guid guid in guidsToRemove)
			{
				queuedActivityLogs.RemoveAll((UploadWorkoutLogItem x) => x.LogItemId.Equals(guid));
			}
			await SaveQueuedActivityLogsOntoDisk();
			isAttempting = false;
			attemptLock?.Release();
			ResetPeriodicTimer();
			Log.Trace("Api", "UploadWorkoutLogsService (instance: " + InstanceName + "): Attempt loop ended.");
		}

		private bool IsAppropriateToUploadLogs()
		{
			ConsoleState? currentConsoleState = workoutSettings.WorkoutContainer?.Console?.LatestBasicInfo?.CurrentState;
			return IsAppropriateToUploadLogs(currentConsoleState);
		}

		private bool IsAppropriateToUploadLogs(ConsoleState? currentConsoleState)
		{
			if (currentConsoleState.HasValue)
			{
				return !restrictedConsoleStates.Contains(currentConsoleState.Value);
			}
			return true;
		}

		public async Task RemoveLogItem(Guid logItemId)
		{
			await initialization;
			await attemptLock.WaitAsync();
			try
			{
				queuedActivityLogs.RemoveAll((UploadWorkoutLogItem x) => x.LogItemId.Equals(logItemId));
				await SaveQueuedActivityLogsOntoDisk();
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Could not add remove log item from UploadWorkoutLogsService stack", exception);
			}
			finally
			{
				attemptLock?.Release();
			}
		}

		private async Task SaveQueuedActivityLogsOntoDisk()
		{
			if (persistLogsOnDisk)
			{
				await blobCacheService.Secure.InsertObject("failedActivityLogs", queuedActivityLogs, Forever);
			}
		}
	}
