	public interface IRecentActivityLogMonitor
	{
		Task AddLog(UploadWorkoutLogItem workoutLogItem);

		Task<ActivityLog> GetLatestLog();

		Task RemoveLogItem(Guid logItemId);
	}
	public class RecentActivityLogMonitor : IRecentActivityLogMonitor
	{
		private const int MaxQueuedLogs = 1;

		private static readonly TimeSpan ExpirationTime = TimeSpan.FromDays(365.0);

		private const string LogTag = "RecentActivityLogMonitor";

		public const string LogsCacheKey = "recentActivityLogs_v2";

		private List<ActivityLogWithSaveableStats> recentActivityLogs;

		private readonly SemaphoreSlim writeLock;

		private readonly IBlobCacheService blobCacheService;

		private readonly Task initialization;

		public RecentActivityLogMonitor(IBlobCacheService blobCacheService)
		{
			this.blobCacheService = blobCacheService;
			writeLock = new SemaphoreSlim(1, 1);
			initialization = Task.Run((Func<Task>)LoadSavedLogs);
		}

		private async Task LoadSavedLogs()
		{
			try
			{
				recentActivityLogs = await blobCacheService.Secure.GetObject<List<ActivityLogWithSaveableStats>>("recentActivityLogs_v2");
			}
			catch (KeyNotFoundException)
			{
			}
			catch (Exception exception)
			{
				Log.Error("RecentActivityLogMonitor", "Caught exception getting recent logs", exception);
			}
			if (recentActivityLogs == null)
			{
				recentActivityLogs = new List<ActivityLogWithSaveableStats>();
			}
		}

		public async Task AddLog(UploadWorkoutLogItem workoutLogItem)
		{
			await initialization;
			await writeLock.WaitAsync();
			try
			{
				workoutLogItem.LogItemId = Guid.NewGuid();
				recentActivityLogs.Add(new ActivityLogWithSaveableStats(workoutLogItem.ActivityLog, workoutLogItem.LogItemId));
				while (recentActivityLogs.Count > 1)
				{
					recentActivityLogs[0].ActivityLog.Dispose();
					recentActivityLogs.RemoveAt(0);
				}
				await blobCacheService.Secure.InsertObject("recentActivityLogs_v2", recentActivityLogs, ExpirationTime);
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Could not add activity log to RecentActivityLogMonitor stack", exception);
			}
			finally
			{
				writeLock.Release();
			}
		}

		public async Task<ActivityLog> GetLatestLog()
		{
			await initialization;
			await writeLock.WaitAsync();
			ActivityLogWithSaveableStats activityLogWithSaveableStats = recentActivityLogs.LastOrDefault();
			writeLock.Release();
			return activityLogWithSaveableStats?.ActivityLog;
		}

		public async Task RemoveLogItem(Guid logItemId)
		{
			await initialization;
			await writeLock.WaitAsync();
			try
			{
				recentActivityLogs = recentActivityLogs.Where((ActivityLogWithSaveableStats x) => x.LogItemId != logItemId).ToList();
				await blobCacheService.Secure.InsertObject("recentActivityLogs_v2", recentActivityLogs, ExpirationTime);
			}
			catch (Exception exception)
			{
				Log.Error("Api", "Could not remove activity log from RecentActivityLogMonitor stack", exception);
			}
			finally
			{
				writeLock.Release();
			}
		}
	}
