	public interface IUploadWorkoutLogsService
	{
		Task<UploadWorkoutLogItem> UploadLog(ActivityLog log, Workout.WorkoutContext workoutContext);

		Task RemoveLogItem(Guid logItemId);
	}
	public class UploadWorkoutLogsService : IUploadWorkoutLogsService
	{
		private readonly IActivityLogRepository activityLogRepository;

		private readonly IFailedUploadMonitor failedUploadMonitor;

		private readonly ILocalSettings localSettings;

		private readonly IIfitApiService apiService;

		private readonly IWorkoutApiService workoutApiService;

		private readonly ICrashReporter crashReporter;

		private readonly IRecentActivityLogMonitor recentActivityLogMonitor;

		private readonly IWorkoutSettings workoutSettings;

		private ExecutionTimer uploadProfiler { get; set; }

		public UploadWorkoutLogsService(IActivityLogRepository activityLogRepository, IFailedUploadMonitor failedUploadMonitor, ILocalSettings localSettings, IIfitApiService apiService, IWorkoutApiService workoutApiService, ICrashReporter crashReporter, IRecentActivityLogMonitor recentActivityLogMonitor, IWorkoutSettings workoutSettings)
		{
			uploadProfiler = new ExecutionTimer("UploadWorkoutLogsService.UploadLog", start: false);
			this.activityLogRepository = activityLogRepository;
			this.failedUploadMonitor = failedUploadMonitor;
			this.localSettings = localSettings;
			this.apiService = apiService;
			this.workoutApiService = workoutApiService;
			this.crashReporter = crashReporter;
			this.recentActivityLogMonitor = recentActivityLogMonitor;
			this.workoutSettings = workoutSettings;
		}

		public virtual async Task<UploadWorkoutLogItem> UploadLog(ActivityLog log, Workout.WorkoutContext workoutContext)
		{
			uploadProfiler.ResetAndStart();
			UploadWorkoutLogItem workoutLogItem = new UploadWorkoutLogItem
			{
				ActivityLog = log
			};
			_ = log?.MachineId == "Equipmentless";
			Workout workout = null;
			if (!string.IsNullOrWhiteSpace(log?.WorkoutId))
			{
				try
				{
					workout = await workoutApiService.Get(log.WorkoutId).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (Exception exception)
				{
					Log.Error("Api", "Could not fetch workout object in UploadWorkoutLogsService", exception);
				}
			}
			if (log == null)
			{
				SendErrorReport(new UploadWorkoutLogServiceLogNullException());
				workoutLogItem.UploadResult = new DetailedUploadResult(UploadResult.NoLog, ErrorCode.LogUploadLogNullError);
			}
			else if (log.Duration < workoutSettings.MinimumWorkoutDuration)
			{
				workoutLogItem.UploadResult = (DetailedUploadResult)UploadResult.UnderMinTime;
			}
			else
			{
				Workout workout2 = workout;
				if (workout2 == null || workout2.Type != Workout.WorkoutType.Strength)
				{
					ActivityLog.StatSummary summary = log.Summary;
					int num;
					if (summary == null)
					{
						num = 1;
					}
					else
					{
						_ = summary.TotalMeters;
						num = 0;
					}
					if (num != 0 || log.Summary?.TotalMeters < workoutSettings.MinimumWorkoutDistance)
					{
						workoutLogItem.UploadResult = (DetailedUploadResult)UploadResult.UnderMinDistance;
						goto IL_04bd;
					}
				}
				if (workout?.IsStrengthWorkout() ?? false)
				{
					log.Type = Workout.WorkoutType.Strength.ToString().ToLowerInvariant();
				}
				uploadProfiler.Mark("AddLogToQueue");
				workoutLogItem.UploadResult = (DetailedUploadResult)UploadResult.NoNetwork;
				await failedUploadMonitor.AddLogToQueue(workoutLogItem);
				uploadProfiler.Mark("AttemptToUploadLog");
				UploadWorkoutLogItem uploadWorkoutLogItem = workoutLogItem;
				uploadWorkoutLogItem.UploadResult = await activityLogRepository.AttemptToUploadLog(log, isRetry: false);
				uploadProfiler.Mark("RemoveLogFromQueue");
				switch (workoutLogItem.UploadResult.Result)
				{
				case UploadResult.Success:
					await failedUploadMonitor.RemoveLogItem(workoutLogItem.LogItemId);
					recentActivityLogMonitor.AddLog(workoutLogItem);
					PostWorkoutWebviewViewModel.PreloadWebview(workoutLogItem.ActivityLog.Id, workoutContext);
					break;
				case UploadResult.APIUploadErrorNoRetry:
					await failedUploadMonitor.RemoveLogItem(workoutLogItem.LogItemId);
					break;
				}
			}
			goto IL_04bd;
			IL_04bd:
			uploadProfiler.Finish();
			workout?.Dispose();
			return workoutLogItem;
		}

		public async Task RemoveLogItem(Guid logItemId)
		{
			await recentActivityLogMonitor.RemoveLogItem(logItemId);
			await failedUploadMonitor.RemoveLogItem(logItemId);
		}

		private async Task SendErrorReport(Exception exception)
		{
			try
			{
				await crashReporter.ReportError($"{exception.GetType()}: {exception.Message}", exception, null);
			}
			catch (Exception exception2)
			{
				Log.Error("Workout", "Error in ActivityLogRepository.SendErrorReport", exception2);
			}
		}
	}
	public class UploadWorkoutLogServiceLogNullException : Exception
	{
		public override string Message => "Workout Log object null. No upload will be attempted.";
	}
}
