	public class InWorkoutLogUploadInteractor : IInWorkoutLogUploadInteractor
	{
		private readonly ILocalSettings localSettings;

		private readonly IUploadWorkoutLogsService uploadWorkoutLogsService;

		private readonly IIfitApiService ifitApi;

		private readonly IStatsToActivityLogTranslator statsToActivityLogTranslator;

		private readonly IActivityLogRepository activityLogRepository;

		private readonly IIdleLogoutService idleLogoutService;

		private readonly IWolfAnalytics analytics;

		private readonly ICompetitionService competitionService;

		private readonly ILocalSettings settings;

		private readonly IConnectivity connectivity;

		private readonly IStartPeriodicDataTimingMonitor timingMonitor;

		private readonly IDormantUpdateChecker dormantUpdateChecker;

		private readonly IPreferenceResolver preferenceResolver;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWorkoutSettings workoutSettings;

		private readonly SemaphoreSlim backgroundUploadSemaphore = new SemaphoreSlim(1);

		public const int MinDurationForLogoutContinueOnBuiltinClubInMillis = 60000;

		public const int MaxDurationForLogoutContinueOnBuiltinClubMillis = 2700000;

		private const int MinimumWorkoutDistanceInMeters = 8;

		private EventHandler OnWorkoutFinished;

		private Task<Task<UploadWorkoutLogItem>> createWorkoutLogTask;

		private Task<UploadWorkoutLogItem> workoutLogItem;

		private ActivityLog log;

		private IInWorkoutUploadViewPresenter viewPresenter;

		private BaseLogScreenViewModel.LogScreenNavObject navObject;

		private ILogScreenNavigator logScreenNavigator;

		private DetailedUploadResult workoutUploadResult;

		private UploadWorkoutLogItem workoutLogItemResult;

		private bool hasLoggedInUser => ifitApi?.HasLoggedInUser ?? false;

		public InWorkoutLogUploadInteractor(ILocalSettings localSettings, IUploadWorkoutLogsService uploadWorkoutLogsService, IIfitApiService ifitApi, IStatsToActivityLogTranslator statsToActivityLogTranslator, IActivityLogRepository activityLogRepository, ICompetitionService competitionService, ILocalSettings settings, IConnectivity connectivity, IDormantUpdateChecker dormantUpdateChecker, ICurrentConsoleService currentConsoleService, IPreferenceResolver preferenceResolver, IWorkoutSettings workoutSettings, IStartPeriodicDataTimingMonitor timingMonitor = null, IIdleLogoutService idleLogoutService = null, IWolfAnalytics analytics = null)
		{
			this.localSettings = localSettings;
			this.uploadWorkoutLogsService = uploadWorkoutLogsService;
			this.ifitApi = ifitApi;
			this.statsToActivityLogTranslator = statsToActivityLogTranslator;
			this.activityLogRepository = activityLogRepository;
			this.idleLogoutService = idleLogoutService;
			this.analytics = analytics;
			this.competitionService = competitionService;
			this.settings = settings;
			this.connectivity = connectivity;
			this.timingMonitor = timingMonitor;
			this.dormantUpdateChecker = dormantUpdateChecker;
			this.preferenceResolver = preferenceResolver;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
		}

		public void Initialize(IInWorkoutUploadViewPresenter viewModel)
		{
			viewPresenter = viewModel;
		}

		public async Task BeginBackgroundUpload()
		{
			await backgroundUploadSemaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			if (createWorkoutLogTask != null || workoutLogItem != null)
			{
				backgroundUploadSemaphore.Release();
				return;
			}
			log = await statsToActivityLogTranslator.ToActivityLog(workoutSettings.WorkoutContainer?.Stats?.RunningStats);
			if (log != null)
			{
				log.WorkoutContext = (workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.Context).GetValueOrDefault();
				if (log.WorkoutContext != Workout.WorkoutContext.OnDemand)
				{
					log.LiveWorkoutScheduleId = workoutSettings?.WorkoutContainer?.WorkoutRunner?.RunContext?.ScheduleInfo?.Id;
				}
			}
			createWorkoutLogTask = Task.Factory.StartNew(delegate
			{
				idleLogoutService?.SetActive(active: false);
				return uploadWorkoutLogsService.UploadLog(log, (workoutSettings.WorkoutContainer?.WorkoutRunner?.RunContext?.Context).GetValueOrDefault());
			});
			workoutLogItem = await createWorkoutLogTask.ConfigureAwait(continueOnCapturedContext: false);
			backgroundUploadSemaphore.Release();
		}

		public async Task<UploadResult> UploadAndNavigateAway(ILogScreenNavigator logScreenNavigator, bool endingWorkoutDueToError, EventHandler onWorkoutFinished = null)
		{
			OnWorkoutFinished = onWorkoutFinished;
			if (activityLogRepository != null)
			{
				await activityLogRepository.UpdateDiagnosticStats().ConfigureAwait(continueOnCapturedContext: false);
			}
			this.logScreenNavigator = logScreenNavigator;
			await BeginBackgroundUpload();
			workoutLogItemResult = await workoutLogItem.ConfigureAwait(continueOnCapturedContext: false);
			if (workoutLogItemResult != null)
			{
				workoutUploadResult = workoutLogItemResult.UploadResult;
			}
			else
			{
				workoutUploadResult = new DetailedUploadResult(UploadResult.NoResult);
			}
			GenerateNavObject(workoutLogItemResult);
			idleLogoutService?.SetActive(active: true);
			if (dormantUpdateChecker != null)
			{
				dormantUpdateChecker.UpdateCheckCompletedWorkout = true;
			}
			await AddCompletedWorkoutToAnalytics(endingWorkoutDueToError, workoutLogItemResult);
			if (Mvx.TryResolve<ILockScreenHandler>(out var service) && service.CanShowLockScreen && (service.LockWhenFinishProcess || service.IsScreenLocked))
			{
				service.LockWhenFinishProcess = false;
				service.NavigateToLockScreen();
				return workoutUploadResult.Result;
			}
			log = null;
			await CheckActivityLog();
			return workoutUploadResult.Result;
		}

		private void GenerateNavObject(UploadWorkoutLogItem logItem)
		{
			if (logItem == null)
			{
				navObject = new BaseLogScreenViewModel.LogScreenNavObject
				{
					PostWorkout = true,
					UploadResult = UploadResult.NoResult,
					UploadErrorCode = ErrorCode.LogUploadUnknownError
				};
			}
			else
			{
				navObject = new BaseLogScreenViewModel.LogScreenNavObject
				{
					PostWorkout = true,
					UploadLogItemId = logItem.LogItemId,
					UploadResult = logItem.UploadResult.Result,
					UploadErrorCode = logItem.UploadResult.ErrorCode,
					ActivityLogId = logItem.ActivityLog?.Id
				};
			}
		}

		private async Task AddCompletedWorkoutToAnalytics(bool endingWorkoutDueToError, UploadWorkoutLogItem uploadWorkoutLogItem)
		{
			if (analytics == null)
			{
				LogAnalyticsTrace("analytics service is null");
				return;
			}
			if (endingWorkoutDueToError)
			{
				LogAnalyticsTrace("ended workout due to error");
				return;
			}
			if (workoutSettings?.WorkoutContainer?.Workout == null)
			{
				LogAnalyticsTrace("workout object is null");
				return;
			}
			UploadResult? uploadResult = uploadWorkoutLogItem?.UploadResult?.Result;
			if ((uploadResult.HasValue && uploadResult == UploadResult.UnderMinTime) || uploadResult == UploadResult.UnderMinDistance || uploadResult == UploadResult.NoLog)
			{
				LogAnalyticsTrace($"UploadResult is ${uploadResult}");
			}
			else if (!uploadResult.HasValue)
			{
				Log.Trace("Workout", "AddCompletedWorkoutToAnalytics - UploadResult was null.");
			}
			else
			{
				await analytics.CompletedWorkout(workoutSettings?.WorkoutContainer, currentConsoleService.Console, uploadWorkoutLogItem?.ActivityLog, timingMonitor?.PeriodicDataTimingReport);
			}
		}

		private void LogAnalyticsTrace(string message)
		{
			Log.Trace("Workout", "AddCompletedWorkoutToAnalytics - $" + message + ", not logging completed workout to analytics.");
		}

		private void NavigateNotLoggedInUser(ILogScreenNavigator logScreenNavigator)
		{
			Log.Trace("Workout", "User is not logged in, forcing navigation to no wifi screen.");
			IMvxBundle presentationBundle = CreatePresentationBundle();
			navObject = new BaseLogScreenViewModel.LogScreenNavObject
			{
				PostWorkout = true,
				UploadLogItemId = Guid.Empty,
				UploadResult = UploadResult.Success
			};
			dormantUpdateChecker.UpdateCheckCompletedWorkout = true;
			logScreenNavigator.ShowLogScreen(navObject, presentationBundle);
		}

		private IMvxBundle CreatePresentationBundle()
		{
			MvxBundle existingParams = ShireViewParams.AnimateTransition(isAnimated: false);
			existingParams = existingParams.AnimateClose(isAnimated: false);
			return ShireViewParams.ClearStackToRequested().AppendOrUpdate(existingParams);
		}

		public async Task CheckActivityLog()
		{
			switch (workoutUploadResult.Result)
			{
			case UploadResult.UnderMinTime:
				await competitionService.DeleteCurrentCompetitionData();
				DisplayWorkoutNotSavedErrorMessage(Wolf.Core.Resources.AppStrings.workout_too_short_text, bounceToDashboard: true, null, isWarning: true);
				CleanUpActivityLog();
				break;
			case UploadResult.NoLog:
				await competitionService.DeleteCurrentCompetitionData();
				DisplayWorkoutNotSavedErrorMessage(Wolf.Core.Resources.AppStrings.workout_malformed_text, bounceToDashboard: true, null, isWarning: true);
				CleanUpActivityLog();
				break;
			case UploadResult.UnderMinDistance:
			{
				await competitionService.DeleteCurrentCompetitionData();
				double value = (preferenceResolver.IsMetric ? 8.0 : UnitUtil.EnsureFeet(DistanceUnit.M, 8.0));
				string text = (preferenceResolver.IsMetric ? Wolf.Core.Resources.AppStrings.meters_label_full : Wolf.Core.Resources.AppStrings.feet_label_full);
				string text2 = ValueFormatters.IntegerFormatter.Format(value);
				string arg = text2 + " " + text;
				DisplayWorkoutNotSavedErrorMessage(string.Format(Wolf.Core.Resources.AppStrings.workout_less_than_min_distance_text, arg), bounceToDashboard: true, null, isWarning: true);
				CleanUpActivityLog();
				break;
			}
			case UploadResult.APIUploadErrorNoRetry:
				DisplayWorkoutNotSavedErrorMessage(Wolf.Core.Resources.AppStrings.upload_workout_no_retry, bounceToDashboard: false, Wolf.Core.Resources.AppStrings.unable_to_upload_workout, isWarning: true);
				CleanUpActivityLog();
				break;
			case UploadResult.APIUploadErrorRetry:
			case UploadResult.UnknownUploadError:
			case UploadResult.NoResult:
			case UploadResult.SQLiteException:
				DisplayWorkoutNotSavedErrorMessage(Wolf.Core.Resources.AppStrings.upload_workout_error_message, bounceToDashboard: false, Wolf.Core.Resources.AppStrings.unable_to_upload_workout, isWarning: true);
				break;
			case UploadResult.NoNetwork:
			case UploadResult.Timeout:
				DisplayWorkoutNotSavedErrorMessage(Wolf.Core.Resources.AppStrings.upload_workout_no_internet, bounceToDashboard: false, Wolf.Core.Resources.AppStrings.unable_to_upload_workout, isWarning: true);
				break;
			case UploadResult.Success:
				logScreenNavigator.ShowLogScreen(navObject, CreatePresentationBundle());
				CleanUpActivityLog();
				break;
			default:
				Log.Error("Workout", $"It looks like we added the UploadResult case of {workoutUploadResult.Result} and did not explicitly handle it explicitly.  This should not happen.");
				break;
			}
		}

		private void DisplayWorkoutNotSavedErrorMessage(string errMsg, bool bounceToDashboard, string title = null, bool isWarning = false)
		{
			viewPresenter.ShowSimpleConfirmationDialog(title ?? Wolf.Core.Resources.AppStrings.workout_not_saved, errMsg, delegate
			{
				OnDialogConfirm(bounceToDashboard);
			}, cancellableOperation: false, null, null, Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), null, null, dismissible: false, cancellable: false, "", null, navObject.UploadErrorCode.HumanReadable(), isWarning);
		}

		private void OnDialogConfirm(bool bounceToDashboard)
		{
			if (bounceToDashboard)
			{
				viewPresenter.FinishAndNavigateAway();
				CleanUpWorkout();
				OnWorkoutFinished?.Invoke(this, EventArgs.Empty);
			}
			else
			{
				logScreenNavigator.ShowLogScreen(navObject, CreatePresentationBundle());
			}
		}

		public void NavigateAway(Action logOut, Action<object, bool> navigateToDashboard, Func<object, IMvxBundle, MvxRequestedBy, bool> showViewModel)
		{
			if (currentConsoleService.IsBuiltinClub && log != null)
			{
				ActivityLog activityLog = log;
				if (activityLog == null || activityLog.Duration >= 60000)
				{
					if (ifitApi.HasLoggedInUser)
					{
						ActivityLog activityLog2 = log;
						if (activityLog2 != null && activityLog2.Duration < 2700000)
						{
							showViewModel(new DashboardViewModel.NavObject
							{
								ShouldShowLogoutContinue = true
							}, ShireViewParams.ClearStackToRequested(), null);
							return;
						}
					}
					logOut();
					return;
				}
			}
			navigateToDashboard(null, arg2: true);
		}

		private void CleanUpWorkout()
		{
			workoutSettings?.ClearAndDisposeWorkoutContainer();
		}

		private void CleanUpActivityLog()
		{
			if (workoutLogItemResult?.ActivityLog != null)
			{
				workoutLogItemResult.ActivityLog.Dispose();
				workoutLogItemResult.ActivityLog = null;
			}
		}
	}
	public interface IStatsCalculationService
	{
		double DefaultWeightKg { get; }

		double CalculateElevationGain(ActivityLog log);

		double CalculateStatSummary(List<ActivityLog.StatGroup.Stat> stats);

		(double, double?, double?) CalculateStatSummary(List<ActivityLog.StatGroup.Stat> stats, bool ignoreZeroes, long duration);

		double CalculateNormalizedPower(List<ActivityLog.StatGroup.Stat> watts, long duration);

		Task<double> CalculateTotalCalories(ActivityLog log);

		Task CalculateSteps(ActivityLog log);
	}
	public class StatsCalculationService : IStatsCalculationService
	{
		private readonly IIfitApiService ifitApi;

		public double DefaultWeightKg => 84.0;

		public StatsCalculationService(IIfitApiService ifitApi)
		{
			this.ifitApi = ifitApi;
		}

		public async Task<double> ActivityCalories(string logType, long seconds)
		{
			User user = await User.GetMe(ifitApi);
			double num = Activities.Current.FirstOrDefault((Activities.Activity x) => x.Key == logType)?.CalorieRate ?? 0.0;
			double num2 = user?.Weight ?? DefaultWeightKg;
			long num3 = seconds / 60;
			double num4 = num2 * 2.20462;
			return num * (double)num3 * num4;
		}

		public double CalculateNormalizedPower(List<ActivityLog.StatGroup.Stat> watts, long duration)
		{
			if (watts.IsNullOrEmpty())
			{
				return 0.0;
			}
			int i = 0;
			List<double> list = new List<double>();
			double num = 0.0;
			double num2 = 0.0;
			int num3 = 0;
			for (int j = 0; j * 1000 <= duration; j++)
			{
				while (i + 1 < watts.Count && watts[i + 1].Offset <= j * 1000)
				{
					for (i++; watts[i].Offset == 0L; i++)
					{
					}
				}
				double valueOrDefault = watts[i].Value.GetValueOrDefault();
				list.Add(valueOrDefault);
				num += valueOrDefault;
				if (j - 31 > 0 && list.Count > j - 31)
				{
					num -= list[j - 31];
				}
				if (j >= 30)
				{
					double x = num / 31.0;
					num2 += Math.Pow(x, 4.0);
					num3++;
				}
			}
			double x2 = ((num3 > 0) ? (num2 / (double)num3) : 0.0);
			return Math.Pow(x2, 0.25);
		}

		public double CalculateStatSummary(List<ActivityLog.StatGroup.Stat> stats)
		{
			if (!stats.IsNullOrEmpty())
			{
				return stats.Last().Value.GetValueOrDefault();
			}
			return 0.0;
		}

		public (double, double?, double?) CalculateStatSummary(List<ActivityLog.StatGroup.Stat> stats, bool ignoreZeroes, long duration)
		{
			if (stats.IsNullOrEmpty())
			{
				return (0.0, 0.0, 0.0);
			}
			long num = duration;
			double num2 = 0.0;
			long num3 = 0L;
			double? num4 = null;
			double? num5 = null;
			for (int num6 = stats.Count - 1; num6 >= 0; num6--)
			{
				ActivityLog.StatGroup.Stat stat = stats[num6];
				long num7 = num - stat.Offset;
				num = stat.Offset;
				double valueOrDefault = stat.Value.GetValueOrDefault();
				if (!ignoreZeroes || valueOrDefault != 0.0)
				{
					num5 = Math.Min(num5 ?? 1.7976931348623157E+308, valueOrDefault);
					num4 = Math.Max(num4 ?? (-1.7976931348623157E+308), valueOrDefault);
					num3 += num7;
					num2 += valueOrDefault * (double)num7;
				}
			}
			if (num3 == 0L)
			{
				return (0.0, num4, num5);
			}
			return (num2 / (double)num3, num4, num5);
		}

		public double CalculateElevationGain(ActivityLog log)
		{
			if (log.Stats.Elevation.IsNullOrEmpty())
			{
				return 0.0;
			}
			double totalGain = 0.0;
			double prevElevation = log.Stats.Elevation[0].Value.GetValueOrDefault();
			log.Stats.Elevation.ForEach(delegate(ActivityLog.StatGroup.Stat item)
			{
				double valueOrDefault = item.Value.GetValueOrDefault();
				if (valueOrDefault > prevElevation)
				{
					totalGain += valueOrDefault - prevElevation;
				}
				prevElevation = valueOrDefault;
			});
			return totalGain;
		}

		public async Task<double> CalculateTotalCalories(ActivityLog log)
		{
			return (!log.Stats.Calories.IsNullOrEmpty()) ? log.Stats.Calories.Last().Value.GetValueOrDefault() : ((!IsRowerType(log)) ? (await ActivityCalories(log.Type, (long)TimeSpan.FromMilliseconds(log.Duration).TotalSeconds)) : CalculateRowerCalories(log));
		}

		public double RowerActual(double seconds, double watts)
		{
			double num = RowerVo2(watts);
			return num * seconds / 200.0;
		}

		public double RowerVo2(double power)
		{
			return 0.20833 * power + 6.92;
		}

		public async Task CalculateSteps(ActivityLog log)
		{
			User user = await User.GetMe(ifitApi);
			bool flag = log.Type == Activities.Cycle.Key && user != null && user.Settings?.CalculateStepsForCycle == true;
			if (log.Type != Activities.Run.Key && !flag)
			{
				return;
			}
			int num = 0;
			double? num2 = 0.0;
			long num3 = 0L;
			foreach (ActivityLog.StatGroup.Stat item in log.Stats.Meters ?? new List<ActivityLog.StatGroup.Stat>())
			{
				long time = item.Offset - num3;
				num += CountStepsFromDistance(user, (item.Value - num2).GetValueOrDefault(), time, flag);
				log.Stats.Steps.Add(new ActivityLog.StatGroup.Stat(item.Offset, num));
				num3 = item.Offset;
				num2 = item.Value;
			}
		}

		public int CountStepsFromDistance(User person, double distance, long time, bool cycle)
		{
			if (time == 0L)
			{
				return 0;
			}
			string gender = person?.Gender ?? "male";
			double num = person?.Height ?? GetDefaultHeight(gender);
			if (cycle)
			{
				double num2 = 0.514 * num;
				return (int)Math.Round(distance / (2.85 * num2));
			}
			double speed = distance / (double)time;
			double strideLength = GetStrideLength(num, gender, speed);
			return (int)Math.Round(distance / strideLength);
		}

		public double GetDefaultHeight(string gender)
		{
			if (!(gender == "male"))
			{
				return 1.62;
			}
			return 1.76;
		}

		public double GetStrideLength(double height, string gender, double speed)
		{
			if (speed < 2.0)
			{
				return height * 0.42;
			}
			if (gender == "male")
			{
				return (0.153 * speed + 0.171) * height;
			}
			return (0.134 * speed + 0.244) * height;
		}

		private double CalculateRowerCalories(ActivityLog log)
		{
			ActivityLog.StatGroup stats = log.Stats;
			if (stats != null && stats.Watts?.Count > 0)
			{
				double valueOrDefault = log.Stats.Watts.Last().Value.GetValueOrDefault();
				if (valueOrDefault > 0.0)
				{
					return RowerActual(log.Duration, valueOrDefault);
				}
			}
			return 0.0;
		}

		private bool IsRowerType(ActivityLog log)
		{
			if (!(log.Type == "row"))
			{
				return log.Type == "rowing";
			}
			return true;
		}
	}
	public interface IStatsToActivityLogTranslator
	{
		Task<ActivityLog> ToActivityLog(MetricStats metricStats);
	}
	public class StatsToActivityLogTranslator : IStatsToActivityLogTranslator
	{
		private readonly ILocalSettings localSettings;

		private readonly IIfitApiService ifitApi;

		private readonly IStatsCalculationService statsCalculationService;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IDeviceInformation deviceInformation;

		private readonly IWorkoutSettings workoutSettings;

		public StatsToActivityLogTranslator(ILocalSettings localSettings, IIfitApiService ifitApi, IStatsCalculationService statsCalculationService, ICurrentConsoleService currentConsoleService, IDeviceInformation deviceInformation, IWorkoutSettings workoutSettings)
		{
			this.localSettings = localSettings;
			this.ifitApi = ifitApi;
			this.currentConsoleService = currentConsoleService;
			this.statsCalculationService = statsCalculationService;
			this.deviceInformation = deviceInformation;
			this.workoutSettings = workoutSettings;
		}

		public async Task<ActivityLog> ToActivityLog(MetricStats metricStats)
		{
			ActivityLog log = await GenerateActivityLogFromStats(metricStats);
			if (log == null)
			{
				return log;
			}
			await statsCalculationService.CalculateSteps(log);
			SanitizeWorkoutStatGroupForAscendingValues(log.Stats);
			await GenerateLogSummary(log);
			if (workoutSettings.WorkoutContainer?.WorkoutRunner?.WolfGeneratedId == null)
			{
				Log.Warn("MvxTrace", "Cannot find WolfGeneratedId in WorkoutRunner. Creating a new WolfGeneratedId for " + log.Id);
				log.WolfGeneratedId = Guid.NewGuid().ToString();
			}
			else
			{
				log.WolfGeneratedId = workoutSettings.WorkoutContainer.WorkoutRunner.WolfGeneratedId;
			}
			return log;
		}

		private async Task<ActivityLog> GenerateActivityLogFromStats(MetricStats metricStats)
		{
			if (localSettings == null)
			{
				return null;
			}
			string userId = ifitApi?.CurrentlyAuthenticatedUserId;
			int softwareNumber = deviceInformation.SoftwareNumber;
			string workoutId = workoutSettings?.WorkoutContainer?.Workout?.Id;
			string programId = workoutSettings?.WorkoutContainer?.ProgramId;
			string challengeId = workoutSettings?.WorkoutContainer?.ChallengeId;
			return await MetricStatsToActivityLog.FromConsole(metricStats, currentConsoleService?.ActiveConsole?.ConsoleInfo, userId, softwareNumber, workoutId, programId, challengeId);
		}

		private void SanitizeWorkoutStatGroupForAscendingValues(ActivityLog.StatGroup statGroup)
		{
			if (statGroup != null)
			{
				if (SanitizeWorkoutStatListForAscendingValues(statGroup.Calories))
				{
					LogSantizationWarning("Calories");
				}
				if (SanitizeWorkoutStatListForAscendingValues(statGroup.Meters))
				{
					LogSantizationWarning("Meters");
				}
			}
		}

		private bool SanitizeWorkoutStatListForAscendingValues(List<ActivityLog.StatGroup.Stat> stats)
		{
			switch (stats.CountSafe())
			{
			case 0:
				return false;
			case 1:
				Log.Trace("Workout", "StatsToActivityLogTranslator - SanitizeWorkoutStatGroupForAscendingValues: Emptied stat list because it only contained one value.");
				stats.RemoveAt(0);
				return true;
			default:
			{
				ActivityLog.StatGroup.Stat stat = stats.Last();
				List<ActivityLog.StatGroup.Stat> list = new List<ActivityLog.StatGroup.Stat>();
				List<ActivityLog.StatGroup.Stat> list2 = stats.OrderBy((ActivityLog.StatGroup.Stat s) => s.Offset).ToList();
				double? value = stats.First().Value;
				foreach (ActivityLog.StatGroup.Stat item in list2)
				{
					bool flag = item.Value < value;
					bool flag2 = item.Offset > stat.Offset;
					bool flag3 = item.Value > stat.Value;
					bool flag4 = item != stat;
					if ((flag || flag2 || flag3) && flag4)
					{
						list.Add(item);
					}
					else
					{
						value = item.Value;
					}
				}
				foreach (ActivityLog.StatGroup.Stat item2 in list)
				{
					stats.Remove(item2);
				}
				return list.Count > 0;
			}
			}
		}

		private async Task GenerateLogSummary(ActivityLog log)
		{
			double totalMeters = statsCalculationService.CalculateStatSummary(log.Stats.Meters);
			double averageFiveHundredSplit = statsCalculationService.CalculateStatSummary(log.Stats.AverageFiveHundredSplit);
			double totalSteps = statsCalculationService.CalculateStatSummary(log.Stats.Steps);
			double totalReps = statsCalculationService.CalculateStatSummary(log.Stats.Reps);
			double totalCalories = await statsCalculationService.CalculateTotalCalories(log);
			double totalElevationGain = statsCalculationService.CalculateElevationGain(log);
			(double, double?, double?) tuple = statsCalculationService.CalculateStatSummary(log.Stats.Bpm, ignoreZeroes: true, log.Duration);
			(double, double?, double?) tuple2 = statsCalculationService.CalculateStatSummary(log.Stats.Watts, ignoreZeroes: false, log.Duration);
			(double, double?, double?) tuple3 = statsCalculationService.CalculateStatSummary(log.Stats.Spm, ignoreZeroes: false, log.Duration);
			(double, double?, double?) tuple4 = statsCalculationService.CalculateStatSummary(log.Stats.FiveHundredSplit, ignoreZeroes: false, log.Duration);
			(double, double?, double?) tuple5 = statsCalculationService.CalculateStatSummary(log.Stats.Rpm, ignoreZeroes: false, log.Duration);
			(double, double?, double?) tuple6 = statsCalculationService.CalculateStatSummary(log.Stats.Resistance, ignoreZeroes: false, log.Duration);
			double normalizedPower = statsCalculationService.CalculateNormalizedPower(log.Stats.Watts, log.Duration);
			log.Summary = new ActivityLog.StatSummary
			{
				TotalMeters = totalMeters,
				TotalCalories = totalCalories,
				AverageFiveHundredSplit = averageFiveHundredSplit,
				TotalSteps = (int)totalSteps,
				TotalReps = (int)totalReps,
				TotalElevationGain = totalElevationGain,
				AverageBpm = tuple.Item1,
				MaxBpm = tuple.Item2,
				AverageWatts = tuple2.Item1,
				MaxWatts = tuple2.Item2,
				NormalizedPower = normalizedPower,
				AverageSPM = tuple3.Item1,
				MaxSPM = tuple3.Item2,
				MaxFiveHundredSplit = tuple4.Item2,
				MinFiveHundredSplit = tuple4.Item3,
				AverageResistance = tuple6.Item1,
				AverageRPM = tuple5.Item1
			};
		}

		private void LogSantizationWarning(string statGroupName)
		{
			Log.Warn("Workout", "StatsToActivityLogTranslator - SanitizeWorkoutStatGroupForAscendingValues - " + statGroupName + " stats list contained non-ascending values and was sanitized.");
		}
	}
}
namespace Wolf.Core.Services.TimeZone
{
	public class AvailableTimeZone
	{
		public bool Selected { get; set; }

		public TimeZoneTypes TimeZoneType { get; }

		public string Text { get; }

		public int UTCOffset { get; }

		public string AndroidName { get; }

		public bool IsCurrentTimeZone => TimeZoneInfo.Local.BaseUtcOffset.TotalHours.RoundToNearest(1.0) == UTCOffset;

		public AvailableTimeZone(TimeZoneTypes timeZoneType, string text, string androidName, int offset)
		{
			TimeZoneType = timeZoneType;
			Text = text;
			AndroidName = androidName;
			UTCOffset = offset;
		}

		public override bool Equals(object obj)
		{
			if ((AvailableTimeZone)obj == null || GetType() != obj.GetType())
			{
				return false;
			}
			if (TimeZoneType.Equals(((AvailableTimeZone)obj).TimeZoneType))
			{
				return UTCOffset.Equals(((AvailableTimeZone)obj).UTCOffset);
			}
			return false;
		}

		public override int GetHashCode()
		{
			int num = 3;
			int num2 = 29;
			int num3 = num;
			num3 = (num3 * num2) ^ TimeZoneType.GetHashCode();
			return (num3 * num2) ^ UTCOffset.GetHashCode();
		}
	}
	public interface ISetTimeZone
	{
		Task<bool> SetTimeZoneAsync(AvailableTimeZone timeZone);
	}
