	{
		Task<bool> SetTimeZoneAsync(AvailableTimeZone timeZone);

		AvailableTimeZone GetTimeZoneFromType(TimeZoneTypes type);

		AvailableTimeZone GetTimeZoneFromString(string timeZoneName);

		string GetCurrentTimeZone();

