		public TimeZoneService(IDeviceInformation deviceInformation)
		{
			this.deviceInformation = deviceInformation;
		}

		public async Task<bool> SetTimeZoneAsync(AvailableTimeZone timeZone)
		{
			Mvx.TryResolve<ISetTimeZone>(out var service);
			if (service == null)
			{
				if (!deviceInformation.IsBuiltIn)
				{
					throw new NotImplementedException("This method isn't implemented for BLE");
				}
				throw new InvalidOperationException("Mvx Could Not Resolve SetTimeZone, If platform is iOS this method should never be called.");
			}
			try
			{
				bool flag = await service.SetTimeZoneAsync(timeZone).ConfigureAwait(continueOnCapturedContext: false);
				Log.Trace("Settings", (flag ? "Was able to set timezone to " : "Failed to set timezone to ") + " " + timeZone.AndroidName);
				return flag;
			}
			catch (Exception exception)
			{
				Log.Error("Settings", "Failed to set timezone to " + timeZone.AndroidName, exception);
				throw;
			}
		}

		public AvailableTimeZone GetTimeZoneFromType(TimeZoneTypes type)
		{
			return _timeZones.FirstOrDefault((KeyValuePair<string, AvailableTimeZone> x) => x.Value.TimeZoneType == type).Value;
		}

		public AvailableTimeZone GetTimeZoneFromString(string timeZoneName)
		{
			if (!_timeZones.TryGetValue(timeZoneName, out var value))
			{
				return null;
			}
			return value;
		}

		public string GetCurrentTimeZone()
		{
			string text = _timeZones.FirstOrDefault((KeyValuePair<string, AvailableTimeZone> x) => x.Value.IsCurrentTimeZone).Value?.Text ?? TimeZoneInfo.Local.DisplayName.Replace('_', ' ');
			Log.Trace("Settings", "The current timezone was " + text);
			return text;
		}

		public List<AvailableTimeZone> GetIfitTimeZones()
		{
			return _timeZones.Select((KeyValuePair<string, AvailableTimeZone> x) => x.Value)?.ToList();
		}
	}
