namespace Wolf.Core.Services.Theming
{
	public enum Theme
	{
		[EnumMember(Value = "default")]
		Default,
		[EnumMember(Value = "light")]
		Light,
		[EnumMember(Value = "dark")]
		Dark,
		[EnumMember(Value = "vault")]
		StrengthMirror,
		[EnumMember(Value = "rainbow")]
		Rainbow,
		[EnumMember(Value = "headlessBike")]
		StrengthHeadlessBike
	}
	public interface IThemeService : IDisposable
	{
		IObservable<Theme> WhenAppThemeChanged { get; }

		Theme AppTheme { get; set; }

		bool EnableStrengthMirrorColorSchemeSwitching { get; set; }

		string CurrentWebViewUrl { get; set; }

		Theme CurrentTheme();

		void NotifyAppThemeChanged(Theme newTheme);

		bool IsCurrentThemeDarkVariant();
	}
	public class ThemeService : IThemeService, IDisposable
	{
		private readonly IDeviceInformation deviceInfo;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IBlobCacheService cacheService;

		private Subject<Theme> _whenAppThemeChanged = new Subject<Theme>();

		private Theme _inWorkoutTheme;

		private bool _enableStrengthMirrorColorSchemeSwitching;

		public IObservable<Theme> WhenAppThemeChanged => _whenAppThemeChanged?.AsObservable();

		public Theme AppTheme
		{
			get
			{
				if (_inWorkoutTheme == Theme.Default)
				{
					if (deviceInfo.UseHeadlessBikeTheme)
					{
						return Theme.StrengthHeadlessBike;
					}
					if (deviceInfo.IsStrengthMirror)
					{
						return Theme.StrengthMirror;
					}
					return Theme.Light;
				}
				return _inWorkoutTheme;
			}
			set
			{
				_inWorkoutTheme = value;
				cacheService.Flush(_inWorkoutTheme, "_inWorkoutTheme", "ThemeService");
			}
		}

		public bool EnableStrengthMirrorColorSchemeSwitching
		{
			get
			{
				return _enableStrengthMirrorColorSchemeSwitching;
			}
			set
			{
				if (value != _enableStrengthMirrorColorSchemeSwitching)
				{
					_enableStrengthMirrorColorSchemeSwitching = value;
					cacheService.Flush(_enableStrengthMirrorColorSchemeSwitching, "_enableStrengthMirrorColorSchemeSwitching", "ThemeService");
				}
			}
		}

		public string CurrentWebViewUrl { get; set; }

		public ThemeService(IDeviceInformation deviceInfo, IFeatureFlagManager featureFlagManager, IBlobCacheService cacheService)
		{
			this.deviceInfo = deviceInfo;
			this.featureFlagManager = featureFlagManager;
			this.cacheService = cacheService;
			_inWorkoutTheme = cacheService.GetFromCache("_inWorkoutTheme", "ThemeService", "", temp: false, Theme.Default).Result;
			_enableStrengthMirrorColorSchemeSwitching = cacheService.GetFromCache("_enableStrengthMirrorColorSchemeSwitching", "ThemeService", "", temp: false, defaultValue: false).Result;
		}

		public Theme CurrentTheme()
		{
			if (deviceInfo.UseHeadlessBikeTheme)
			{
				return Theme.StrengthHeadlessBike;
			}
			if (deviceInfo.IsStrengthMirror && !EnableStrengthMirrorColorSchemeSwitching)
			{
				return Theme.StrengthMirror;
			}
			IFeatureFlagManager obj = featureFlagManager;
			if (obj == null || !obj.IsFeatureEnabled(FeatureFlags.WolfColorSchemeFeature))
			{
				return Theme.Light;
			}
			if (!deviceInfo.IsTablet)
			{
				return Theme.Light;
			}
			return AppTheme;
		}

		public void NotifyAppThemeChanged(Theme newTheme)
		{
			_whenAppThemeChanged?.OnNext(newTheme);
		}

		public bool IsCurrentThemeDarkVariant()
		{
			Theme theme = CurrentTheme();
			if (theme != Theme.Dark)
			{
				return theme == Theme.StrengthMirror;
			}
			return true;
		}

		public void Dispose()
		{
			_whenAppThemeChanged?.Dispose();
			_whenAppThemeChanged = null;
		}
	}
}
namespace Wolf.Core.Services.StartWorkout
{
	public interface IConsoleStartButtonInteractor : IDisposable
	{
		void OnViewShown();

		void OnViewHidden();

		void AttachPresenter(IConsoleStartButtonPresenter consoleStartButtonPresenter);
	}
	public class ConsoleStartButtonInteractor : IConsoleStartButtonInteractor, IDisposable
	{
		private readonly IBleConsoleService bleConsoleService;

		private readonly IStartWorkoutService startWorkoutService;

		private readonly ILocalSettings localSettings;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly ILockScreenHandler lockScreenHandler;

		private IConsoleStartButtonPresenter consoleStartButtonPresenter;

		private IDisposable consoleStartButtonSub;

		private IDisposable bleConsoleConnectedSub;

		private bool shouldInterceptConsoleStartButton => consoleStartButtonPresenter?.ShouldInterceptConsoleStartButton ?? false;

		private Workout workoutForConsoleStartButtonInterception => consoleStartButtonPresenter?.WorkoutForConsoleStartButtonInterception;

		public ConsoleStartButtonInteractor(IStartWorkoutService startWorkoutService, ILocalSettings localSettings, ICurrentConsoleService currentConsoleService, IBleConsoleService bleConsoleService = null, ILockScreenHandler lockScreenHandler = null)
		{
			this.bleConsoleService = bleConsoleService;
			this.startWorkoutService = startWorkoutService;
			this.localSettings = localSettings;
			this.currentConsoleService = currentConsoleService;
			this.lockScreenHandler = lockScreenHandler;
		}

		public void AttachPresenter(IConsoleStartButtonPresenter consoleStartButtonPresenter)
		{
			this.consoleStartButtonPresenter = consoleStartButtonPresenter;
		}

		public void OnViewShown()
		{
			if (shouldInterceptConsoleStartButton)
			{
				CreateConsoleConnectedSub();
				CreateConsoleStartButtonSub();
			}
		}

		private void CreateConsoleConnectedSub()
		{
			CleanupConsoleConnectedSub();
			if (bleConsoleService != null)
			{
				bleConsoleConnectedSub = bleConsoleService.WhenConnectionStateChanged?.Where((ConsoleConnectionState state) => state == ConsoleConnectionState.Connected)?.SubscribeWithErrorLogging(delegate
				{
					CreateConsoleStartButtonSub();
				});
			}
		}

		private void CreateConsoleStartButtonSub()
		{
			IFitnessConsole fitnessConsole = currentConsoleService?.ActiveConsole;
			if (fitnessConsole != null)
			{
				fitnessConsole.StartKeyEnabled = true;
			}
			consoleStartButtonSub?.Dispose();
			if (fitnessConsole == null || fitnessConsole.ConsoleInfo?.MachineType.IsAerobicMachine() != true)
			{
				IStartRequestedFacade startRequestedFacade = Mvx.Resolve<IStartRequestedFacade>();
				consoleStartButtonSub = (from x in startRequestedFacade.ObserveStartRequestedChanges()
					select x.Current into wasRequested
					where wasRequested
					select wasRequested)?.SubscribeAsyncWithErrorLogging(async delegate
				{
					await InterceptConsoleStartButton();
				});
			}
		}

		private async Task InterceptConsoleStartButton()
		{
			Log.Trace("Workout", "Intercepted console START button in " + GetType().Name + ".");
			if (Mvx.TryResolve<IScreenSaverHandler>(out var service) && service.IsScreenSaverVisible && !currentConsoleService.Console.ConsoleInfo.IsClub)
			{
				Log.Trace("Workout", "Screensaver is showing and unit is not a club unit, so not going to start workout.");
			}
			else if (lockScreenHandler?.IsScreenLocked ?? false)
			{
				Log.Trace("Workout", "Screen is Locked, so not going to start workout.");
			}
			else if (currentConsoleService.ActiveConsole?.LatestBasicInfo?.IsInRecoverableWorkout() == true)
			{
				Log.Trace("Workout", "Console is already in a workout, so not attempting to start a new one.");
			}
			else
			{
				if (startWorkoutService == null)
				{
					return;
				}
				if (startWorkoutService.StartingWorkout)
				{
					Log.Trace("Workout", "Workout is already starting according to StartWorkoutService, so not starting another one.");
					return;
				}
				IConsoleBasicInfo latestBasicInfo = currentConsoleService.ActiveConsole.LatestBasicInfo;
				if (latestBasicInfo == null || latestBasicInfo.CurrentState != ConsoleState.Idle)
				{
					Log.Trace("Workout", "Console isn't in " + ConsoleState.Idle.ToString() + " state, so waiting for that...");
					await WaitForConsoleReady(Wolf.Core.Resources.AppStrings.communicating_with_equipment, currentConsoleService.ActiveConsole.WhenStateChanged);
				}
				if (!string.IsNullOrWhiteSpace(workoutForConsoleStartButtonInterception?.Id))
				{
					await startWorkoutService.DoStartWorkout(workoutForConsoleStartButtonInterception, WorkoutRunnerContext.DefaultOnDemandContext, WaitForConsoleReady, new AnalyticsSource(WorkoutSource.NA));
				}
				else if (!(await (consoleStartButtonPresenter?.ShowWorkoutForConsoleStartButton())))
				{
					Log.Trace("Workout", "Workout is defaulting to manual.");
					if (currentConsoleService.CurrentConsoleType?.IsAerobicMachine() ?? false)
					{
						await startWorkoutService.StartCyclicalManualWorkout(WaitForConsoleReady, new AnalyticsSource(WorkoutSource.NA));
					}
					else
					{
						await startWorkoutService.DoStartManualWorkout(WaitForConsoleReady, new AnalyticsSource(WorkoutSource.NA));
					}
				}
				else
				{
					await startWorkoutService.DoStartWorkout(workoutForConsoleStartButtonInterception, WorkoutRunnerContext.DefaultOnDemandContext, WaitForConsoleReady, new AnalyticsSource(WorkoutSource.NA));
				}
			}
		}

		private async Task<ProgressDialogResult> WaitForConsoleReady(string message, IObservable<StateChange> whenConsoleStateChanged)
		{
			if (consoleStartButtonPresenter == null)
			{
				return ProgressDialogResult.FromError(new Exception("consoleStartButtonPresenter is null in ConsoleStartButtonInteractor.WaitForConsoleReady"));
			}
			return await consoleStartButtonPresenter.ShowProgressDialog(message, whenConsoleStateChanged);
		}

		private void CleanupConsoleConnectedSub()
		{
			bleConsoleConnectedSub?.Dispose();
			bleConsoleConnectedSub = null;
		}

		private void CleanupConsoleStartButtonSub()
		{
			if (consoleStartButtonSub != null)
			{
				consoleStartButtonSub?.Dispose();
				consoleStartButtonSub = null;
				if (currentConsoleService?.ActiveConsole != null)
				{
					currentConsoleService.ActiveConsole.StartKeyEnabled = false;
				}
			}
		}

		public void Dispose()
		{
			CleanupConsoleStartButtonSub();
			CleanupConsoleConnectedSub();
			consoleStartButtonPresenter = null;
		}

		public void OnViewHidden()
		{
			CleanupConsoleStartButtonSub();
			CleanupConsoleConnectedSub();
		}
	}
	public interface IConsoleStartButtonPresenter
	{
		bool ShouldInterceptConsoleStartButton { get; }

		Workout WorkoutForConsoleStartButtonInterception { get; }

		Task<ProgressDialogResult> ShowProgressDialog(string title, IObservable<object> observable, Action<object> onNext = null, Action<Exception> onError = null, TimeSpan timeout = default(TimeSpan), string dialogTag = "", bool showSafely = true);

		Task<bool> ShowWorkoutForConsoleStartButton();
	}
}
namespace Wolf.Core.Services.Sharing
{
	public interface IWolfSharingService
	{
		ISocialShareUtil SocialShareUtil { get; }

		Task<ShareResult> ShareWorkout(SocialShareProvider type, string postText, string url);
	}
	public class WolfSharingService : IWolfSharingService
	{
		private readonly IIfitApiService ifitApi;

		public ISocialShareUtil SocialShareUtil { get; }

		public WolfSharingService(ISocialShareUtil socialShareUtil, IIfitApiService ifitApi)
		{
			SocialShareUtil = socialShareUtil;
			this.ifitApi = ifitApi;
		}

		public async Task<ShareResult> ShareWorkout(SocialShareProvider type, string postText, string url)
		{
			if (string.IsNullOrEmpty(url))
			{
				Log.Trace("Workout", "No Workout URL provided for sharing");
				return ShareResult.Failed;
			}
			return await SocialShareUtil.Share(type, postText, url);
		}
	}
