namespace Wolf.Core.Services.SettingsMigration
{
	public class SettingsMigrationService
	{
		private readonly IBlobCacheService cacheService;

		private const string settingsCacheKey = "local-settings";

		private const string log = "SettingsMigration";

		private JObject localSettingsValues;

		public SettingsMigrationService(IBlobCacheService cacheService)
		{
			this.cacheService = cacheService;
		}

		public async Task GetLocalSettings()
		{
			try
			{
				localSettingsValues = await cacheService.Secure.GetObject<JObject>("local-settings");
				Log.Trace("SettingsMigration", "Successful in loading settingsCacheKey into localSettingsValues in SettingsMigrationService");
			}
			catch (Exception arg)
			{
				Log.Trace("SettingsMigration", "Error in loading settingsCacheKey into localSettingsValues in SettingsMigrationService");
				Log.Trace("SettingsMigration", $"{arg}");
			}
		}

		public async Task MigrateSettings()
		{
			if (localSettingsValues == null)
			{
				Log.Trace("SettingsMigration", "localSettingsValues is null");
				return;
			}
			if (Mvx.TryResolve<IDormantUpdateChecker>(out var service))
			{
				Log.Trace("SettingsMigration", "Successful in loading IDormantUpdateChecker into SettingsMigrationService");
				MigrateDormantUpdateChecker(service);
			}
			if (Mvx.TryResolve<IWolfTrackingService>(out var service2))
			{
				Log.Trace("SettingsMigration", "Successful in loading IWolfTrackingService into SettingsMigrationService");
				MigrateWolfTrackingService(service2);
			}
			if (Mvx.TryResolve<IDeveloperSettings>(out var service3))
			{
				Log.Trace("SettingsMigration", "Successful in loading IDeveloperSettings into SettingsMigrationService");
				MigrateDeveloperSettings(service3);
			}
		}

		private void MigrateDormantUpdateChecker(IDormantUpdateChecker dormantUpdateChecker)
		{
			if (localSettingsValues.TryGetValue("UpdateCheckCompletedWorkout", out JToken value))
			{
				dormantUpdateChecker.UpdateCheckCompletedWorkout = value.ToObject<bool>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "UpdateCheckCompletedWorkout", dormantUpdateChecker.UpdateCheckCompletedWorkout));
			}
		}

		private void MigrateWolfTrackingService(IWolfTrackingService wolfTrackingService)
		{
			if (localSettingsValues.TryGetValue("FirstRun", out JToken value))
			{
				wolfTrackingService.FirstRun = value.ToObject<bool>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "FirstRun", wolfTrackingService.FirstRun));
			}
			if (localSettingsValues.TryGetValue("IsFirstTime", out JToken value2))
			{
				wolfTrackingService.IsFirstTime = value2.ToObject<bool?>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "IsFirstTime", wolfTrackingService.IsFirstTime));
			}
			if (localSettingsValues.TryGetValue("LastRequestedVideoUrl", out JToken value3))
			{
				wolfTrackingService.LastRequestedVideoUrl = value3.ToString();
				Log.Trace("SettingsMigration", "LastRequestedVideoUrl has been set to " + wolfTrackingService.LastRequestedVideoUrl);
			}
			if (localSettingsValues.TryGetValue("LastReviewRequestDate", out JToken value4))
			{
				wolfTrackingService.LastReviewRequestDate = new DateTime(value4.ToObject<long>());
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "LastReviewRequestDate", wolfTrackingService.LastReviewRequestDate));
			}
			if (!localSettingsValues.TryGetValue("completedOnboardingUserIds", out JToken value5))
			{
				return;
			}
			List<string> list = value5.ToObject<List<string>>();
			foreach (string item in list)
			{
				wolfTrackingService.SetCompletedOnboarding(item);
				Log.Trace("SettingsMigration", "SetCompletedOnboarding is setting " + item);
			}
		}

		private void MigrateDeveloperSettings(IDeveloperSettings developerSettings)
		{
			if (localSettingsValues.TryGetValue("EnableSafetyStartForDev", out JToken value))
			{
				developerSettings.EnableSafetyStartForDev = value.ToObject<bool>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "EnableSafetyStartForDev", developerSettings.EnableSafetyStartForDev));
			}
			if (localSettingsValues.TryGetValue("AppVersionOverlayEnabled", out JToken value2))
			{
				developerSettings.AppVersionOverlayEnabled = value2.ToObject<bool>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "AppVersionOverlayEnabled", developerSettings.AppVersionOverlayEnabled));
			}
			if (localSettingsValues.TryGetValue("SpoofSubscriptionType", out JToken value3) && value3.ToString() != "")
			{
				developerSettings.SpoofSubscriptionType = value3.ToObject<User.SubscriptionTypes?>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "SpoofSubscriptionType", developerSettings.SpoofSubscriptionType));
			}
			if (localSettingsValues.TryGetValue("SpoofIsPlanetFitnessUser", out JToken value4))
			{
				developerSettings.SpoofIsPlanetFitnessUser = value4.ToObject<bool>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "SpoofIsPlanetFitnessUser", developerSettings.SpoofIsPlanetFitnessUser));
			}
			if (localSettingsValues.TryGetValue("LastTcpIpVirtualConsoleAddress", out JToken value5))
			{
				developerSettings.LastTcpIpVirtualConsoleAddress = value5.ToObject<string>();
				Log.Trace("SettingsMigration", "LastTcpIpVirtualConsoleAddress has been set to " + developerSettings.LastTcpIpVirtualConsoleAddress);
			}
			if (localSettingsValues.TryGetValue("ShowHRDebugInfo", out JToken value6))
			{
				developerSettings.ShowHRDebugInfo = value6.ToObject<bool>();
				Log.Trace("SettingsMigration", string.Format("{0} has been set to {1}", "ShowHRDebugInfo", developerSettings.ShowHRDebugInfo));
			}
		}
	}
	public class SettingsMigrationServiceV2
	{
		private readonly IBlobCacheService cacheService;

		private const string settingsCacheKey = "local-settings";

		private const string log = "SettingsMigration";

		private JObject localSettingsValues;

		public SettingsMigrationServiceV2(IBlobCacheService cacheService)
		{
			this.cacheService = cacheService;
		}

		public async Task GetLocalSettings()
		{
			try
			{
				localSettingsValues = await cacheService.Secure.GetObject<JObject>("local-settings");
				Log.Trace("SettingsMigration", "Successful in loading settingsCacheKey into localSettingsValues in SettingsMigrationServiceV2");
			}
			catch (Exception arg)
			{
				Log.Trace("SettingsMigration", "Error in loading settingsCacheKey into localSettingsValues in SettingsMigrationServiceV2");
				Log.Trace("SettingsMigration", $"{arg}");
			}
		}

		public async Task MigrateSettings()
		{
			if (localSettingsValues != null)
			{
				if (Mvx.TryResolve<ICurrentConsoleService>(out var service))
				{
					Log.Trace("SettingsMigration", "Successful in loading ICurrentConsoleService into SettingsMigrationServiceV2");
					MigrateCurrentConsoleService(service);
				}
				if (Mvx.TryResolve<IDeviceInformation>(out var service2))
				{
