namespace Wolf.Core.Services.Repository
{
	public interface ILogDeletedObserver : IDisposable
	{
		IObservable<string> WhenActivityLogDeleted { get; }

		void NotifyActivityLogDeleted(string activityLogId);
	}
	public class LogDeletedObserver : ILogDeletedObserver, IDisposable
	{
		private readonly Subject<string> _whenActivityLogDeleted = new Subject<string>();

		private IDisposable whenIfitApiActivityLogDeleted;

		public IObservable<string> WhenActivityLogDeleted => _whenActivityLogDeleted;

		public LogDeletedObserver(IIfitApiService apiService)
		{
			whenIfitApiActivityLogDeleted = apiService.WhenActivityLogDeleted.Subscribe(NotifyActivityLogDeleted);
		}

		public void NotifyActivityLogDeleted(string activityLogId)
		{
			_whenActivityLogDeleted.OnNext(activityLogId);
		}

