namespace Wolf.Core.Services.Refreshing
{
	public interface INeedsRefreshService : IDisposable
	{
		IObservable<IRefreshPayload> WhenNeedsRefresh { get; }

		void RequestRefresh(RefreshCause cause);
	}
	public class NeedsRefreshService : INeedsRefreshService, IDisposable
	{
		private const int MaxDayChangedStaggerMinutes = 120;

		private readonly IConnectivity connectivity;

		private readonly IScreenSaverHandler screenSaverHandler;

		private readonly ILockScreenHandler lockScreenHandler;

		private IDisposable dayChangedSub;

		private IDisposable environmentChangedSub;

		private IDisposable userChangedSub;

		private IDisposable bleStateChangeSub;

		private IDisposable metricChangedSub;

		private IDisposable accessTokenRefreshedSub;

		private Subject<IRefreshPayload> whenNeedsRefresh = new Subject<IRefreshPayload>();

		public DateTime LastSentTime = DateTime.Now;

		public IObservable<IRefreshPayload> WhenNeedsRefresh => whenNeedsRefresh;

		public int DayChangedStaggerMilliseconds { get; set; } = new Random().Next(7200000);

		public NeedsRefreshService(ILocalSettings localSettings, IIfitApiService ifitApi, ISchedulerService schedulerService, IConnectivity connectivity, IScreenSaverHandler screenSaverHandler, IFeatureFlagManager featureFlagManager, IPreferenceResolver preferenceResolver, IBleConsoleService bleConsoleService = null, ILockScreenHandler lockScreenHandler = null)
		{
			this.connectivity = connectivity;
			this.screenSaverHandler = screenSaverHandler;
			this.lockScreenHandler = lockScreenHandler;
			connectivity.ConnectivityChanged -= ConnectivityChanged;
			connectivity.ConnectivityChanged += ConnectivityChanged;
			environmentChangedSub = ifitApi.WhenApiEnvironmentChanged.SubscribeWithErrorLogging(delegate
			{
				RequestRefresh(RefreshCause.EnvironmentChanged);
			});
			userChangedSub = ifitApi.WhenCurrentUserIdChanged.SubscribeWithErrorLogging(delegate
			{
				RequestRefresh(RefreshCause.AuthenticatedUserChanged);
			});
			metricChangedSub = preferenceResolver.WhenIsMetricChanged.SubscribeWithErrorLogging(delegate
			{
				RequestRefresh(RefreshCause.MetricsChanged);
			});
			dayChangedSub = schedulerService.WhenDayChanged.SubscribeWithErrorLogging(async delegate
			{
				await DayChanged();
			});
			accessTokenRefreshedSub = ifitApi.WhenAccessTokenRefreshed.SubscribeWithErrorLogging(delegate
			{
				RequestRefresh(RefreshCause.TokenRefreshed);
			});
			if (bleConsoleService != null)
			{
				bleStateChangeSub = bleConsoleService.WhenConsoleChanged.SubscribeWithErrorLogging(ConsoleChanged);
			}
		}

		public void RequestRefresh(RefreshCause cause)
		{
			DateTime now = DateTime.Now;
			TimeSpan timeSpan = now - LastSentTime;
			LastSentTime = now;
			Log.Trace("Analytics", $"Refresh Requested with cause '{cause.ToString()}' - {timeSpan} milli's since last update");
			whenNeedsRefresh.OnNext(new RefreshPayload(cause, now, timeSpan));
		}

		private void ConsoleChanged(IFitnessConsole console)
		{
			if (console != null && console.Initialized)
			{
				RequestRefresh(RefreshCause.ConsoleConnected);
			}
			else
			{
				RequestRefresh(RefreshCause.ConsoleLost);
			}
		}

		private void ConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			Log.Trace("Analytics", $"NeedsRefreshService is called while ScreenSaverVisible is {screenSaverHandler.IsScreenSaverVisible}");
			if (screenSaverHandler.IsScreenSaverVisible)
			{
				return;
			}
			if (!e.IsConnected)
			{
				ILockScreenHandler obj = lockScreenHandler;
				if (obj != null && obj.IsScreenLocked)
				{
					lockScreenHandler.LockWhenFinishProcess = true;
					return;
				}
			}
			if (e.IsConnected)
			{
				ILockScreenHandler obj2 = lockScreenHandler;
				if (obj2 != null && obj2.LockWhenFinishProcess)
				{
					lockScreenHandler.LockWhenFinishProcess = false;
					lockScreenHandler.NavigateToLockScreen();
				}
				else
				{
					RequestRefresh(RefreshCause.GainedInternet);
				}
			}
			else
			{
				RequestRefresh(RefreshCause.LostInternet);
			}
		}

		private async Task DayChanged()
		{
			await Task.Delay(DayChangedStaggerMilliseconds);
			RequestRefresh(RefreshCause.DayChanged);
		}

		public void Dispose()
		{
			connectivity.ConnectivityChanged -= ConnectivityChanged;
			dayChangedSub?.Dispose();
			dayChangedSub = null;
			environmentChangedSub?.Dispose();
			environmentChangedSub = null;
			userChangedSub?.Dispose();
			userChangedSub = null;
			bleStateChangeSub?.Dispose();
			bleStateChangeSub = null;
			metricChangedSub?.Dispose();
			metricChangedSub = null;
			whenNeedsRefresh?.OnCompleted();
			whenNeedsRefresh?.Dispose();
			whenNeedsRefresh = null;
			accessTokenRefreshedSub?.Dispose();
			accessTokenRefreshedSub = null;
		}
	}
	public enum RefreshCause
	{
		LostInternet,
		GainedInternet,
		ConsoleConnected,
		ConsoleLost,
		EnvironmentChanged,
		MetricsChanged,
		DayChanged,
		AuthenticatedUserChanged,
		Favorites,
		TokenRefreshed,
		Unspecified
	}
	public interface IRefreshPayload
	{
		RefreshCause Cause { get; }

		DateTime Time { get; }

		TimeSpan ElapsedTime { get; }
	}
	public class RefreshPayload : IRefreshPayload
	{
		public RefreshCause Cause { get; private set; }

		public DateTime Time { get; private set; }

		public TimeSpan ElapsedTime { get; private set; }

		public RefreshPayload(RefreshCause cause, DateTime time, TimeSpan elapsedTime)
		{
			Cause = cause;
			Time = time;
			ElapsedTime = elapsedTime;
		}
	}
}
namespace Wolf.Core.Services.PreWorkout
{
	public interface IPreWorkoutNavigator
	{
		bool IsPreWorkoutWebviewEnabled { get; }
	}
	public class PreWorkoutNavigator : IPreWorkoutNavigator
	{
		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IDeviceInformation deviceInfo;

		public bool IsPreWorkoutWebviewEnabled
		{
			get
			{
				if (featureFlagEnabled)
				{
					if (!isTablet)
					{
						return isPhoneFeatureFlagEnabled;
					}
					return true;
				}
				return false;
			}
		}

		private bool featureFlagEnabled => featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfUsePreworkoutWebview);

		private bool isTablet => deviceInfo.IsTablet;

		private bool isPhoneFeatureFlagEnabled => featureFlagManager.IsFeatureEnabled(FeatureFlags.WolfUsePrePostWebviewPhone);

		public PreWorkoutNavigator(IFeatureFlagManager featureFlagManager, IDeviceInformation deviceInfo)
		{
			this.featureFlagManager = featureFlagManager;
			this.deviceInfo = deviceInfo;
		}
	}
}
namespace Wolf.Core.Services.PostWorkout
{
	public interface IActivityLogRepository
	{
		Task<DetailedUploadResult> AttemptToUploadLog(ActivityLog log, bool isRetry);

		Task<ActivityLogPopulateResult> PopulateActivityLog(string activityLogId, string workoutId, string programId, string challengeId, MetricStats runningStats, WorkoutRunnerContext workoutRunnerContext);

		Task<ActivityLog> FetchActivityLog(string activityLogId, bool force = false);

		Task<ErrorCode> DeleteActivityLog(string activityLogId);

		Task UpdateDiagnosticStats();
	}
	public class ActivityLogRepository : IActivityLogRepository
	{
		private static readonly string LogTag = "ActivityLogRepository";

		private readonly IIfitApiService ifitApi;

		private readonly ILocalSettings localSettings;

		private readonly IConnectivity connectivity;

		private readonly IDeviceInformation deviceInfo;

		private readonly ICrashReporter crashReporter;

		private readonly IStatsToActivityLogTranslator statsToActivityLogTranslator;

		private readonly IWolfAnalytics analytics;

		private readonly IBlobCacheFileManager blobCacheFileManager;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWorkoutSettings workoutSettings;

		private readonly IAppleHealthDataSyncService appleHealthDataSyncService;

		public ActivityLogRepository(IIfitApiService ifitApi, ILocalSettings localSettings, IConnectivity connectivity, IDeviceInformation deviceInfo, ICrashReporter crashReporter, IStatsToActivityLogTranslator statsToActivityLogTranslator, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IWolfAnalytics analytics = null, IBlobCacheFileManager blobCacheFileManager = null, IAppleHealthDataSyncService appleHealthDataSyncService = null)
		{
			this.ifitApi = ifitApi;
			this.localSettings = localSettings;
			this.connectivity = connectivity;
			this.deviceInfo = deviceInfo;
			this.crashReporter = crashReporter;
			this.statsToActivityLogTranslator = statsToActivityLogTranslator;
			this.analytics = analytics;
			this.blobCacheFileManager = blobCacheFileManager;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
			this.appleHealthDataSyncService = appleHealthDataSyncService;
		}

		public async Task<DetailedUploadResult> AttemptToUploadLog(ActivityLog log, bool isRetry)
		{
			DetailedUploadResult uploadResult = (DetailedUploadResult)UploadResult.Success;
			Exception exception = null;
			if (connectivity.IsConnected)
			{
				try
				{
					Log.Trace("Api", "UploadWorkoutLogsService: Attempting to upload ActivityLog...");
					await UploadActivityLog(log);
					SaveLogToAppleHealthInBackground(log);
				}
				catch (TaskCanceledException ex)
				{
					Log.Trace("Api", "UploadWorkoutLogsService: Upload workout timed out.", ex);
					uploadResult = new DetailedUploadResult(UploadResult.Timeout, ErrorCode.LogUploadTimeout);
					exception = ex;
				}
				catch (iFit.Api.Support.ConnectivityException ex2)
				{
					Log.Trace("Api", "UploadWorkoutLogsService: Encountered a connectivity problem while uploading an activity log", ex2);
					uploadResult = new DetailedUploadResult(UploadResult.NoNetwork, ErrorCode.LogUploadConnectivityError);
					exception = ex2;
				}
				catch (JsonSerializationException ex3)
				{
					uploadResult = await HandleJSONException(ex3, log);
					exception = ex3;
				}
				catch (SQLiteException ex4)
				{
					Log.Trace("Api", "UploadWorkoutLogsService: Encountered a SQL problem while uploading an activity log", ex4);
					uploadResult = new DetailedUploadResult(UploadResult.SQLiteException, ErrorCode.LogUploadUnknownSqliteError);
					exception = ex4;
					blobCacheFileManager?.LogCacheInformation();
				}
				catch (ApiException ex5)
				{
					uploadResult = await HandleApiException(ex5, log);
					exception = ex5;
				}
				catch (Exception ex6)
				{
					Log.Trace("Api", $"UploadWorkoutLogsService: Encountered an unknown exception uploading an activity log: {ex6.GetType()}, {ex6.Message}", ex6);
					await SendErrorReport(log, ex6);
					uploadResult = new DetailedUploadResult(UploadResult.UnknownUploadError, ErrorCode.LogUploadUnknownError);
					exception = ex6;
				}
			}
			else
			{
				uploadResult = new DetailedUploadResult(UploadResult.NoNetwork, ErrorCode.LogUploadNoConnection);
			}
			Log.Trace("Api", $"ActivityLogRepository: Upload result was: {uploadResult}");
			await analytics.ActivityLogUploadAttempt(log, uploadResult, isRetry, exception);
			return uploadResult;
		}

		private async Task UploadActivityLog(ActivityLog log)
		{
			ActivityLog activityLog = await log.Create(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
			if (activityLog != null)
			{
				log.Id = activityLog.Id;
				log.End = activityLog.End;
				log.Summary = activityLog.Summary;
				log.Origin = activityLog.Origin;
				activityLog.Dispose();
			}
		}

		public async Task<ActivityLogPopulateResult> PopulateActivityLog(string activityLogId, string workoutId, string programId, string challengeId, MetricStats runningStats, WorkoutRunnerContext workoutRunnerContext)
		{
			ActivityLogPopulateResult log = new ActivityLogPopulateResult();
			if (runningStats != null)
			{
				log.PopulatedFromApi = false;
				ActivityLogPopulateResult activityLogPopulateResult = log;
				activityLogPopulateResult.ActivityLog = await GetActivityFromStats(workoutId, programId, challengeId, runningStats, workoutRunnerContext);
				log.ActivityLog.Id = activityLogId;
				return log;
			}
			if (!string.IsNullOrEmpty(activityLogId) && connectivity.IsConnected && ifitApi.HasLoggedInUser)
			{
				log.PopulatedFromApi = true;
				ActivityLogPopulateResult activityLogPopulateResult = log;
				activityLogPopulateResult.ActivityLog = await GetActivityFromApi(activityLogId);
			}
			if (log.ActivityLog == null && runningStats != null)
			{
				log.PopulatedFromApi = false;
				ActivityLogPopulateResult activityLogPopulateResult = log;
				activityLogPopulateResult.ActivityLog = await GetActivityFromStats(workoutId, programId, challengeId, runningStats, workoutRunnerContext);
			}
			return log;
		}

		public async Task<ActivityLog> FetchActivityLog(string activityLogId, bool force = false)
		{
			try
			{
				return await ActivityLog.Get(ifitApi, activityLogId, force);
			}
			catch (Exception exception)
			{
				Log.Error("Workout", "Error loading activity log from api", exception);
				return null;
			}
		}

		private async Task<ActivityLog> GetActivityFromApi(string activityLogId)
		{
			if (!connectivity.IsConnected)
			{
				return null;
			}
			ActivityLog activityLog;
			try
			{
				activityLog = await ActivityLog.Get(ifitApi, activityLogId);
			}
			catch (Exception ex)
			{
				Log.Trace("Workout", $"Error loading activity log from api - {ex.GetBaseException()}");
				return null;
			}
			if (activityLog == null)
			{
				Log.Trace("Workout", "Received null activity log from api - log id: " + activityLogId);
				return null;
			}
			if (string.IsNullOrWhiteSpace(activityLog.WorkoutId))
			{
				Log.Trace("Workout", "Log has null or blank workout id - log id: " + activityLogId);
				return null;
			}
			return activityLog;
		}

		protected virtual async Task<ActivityLog> GetActivityFromStats(string workoutId, string programId, string challengeId, MetricStats stats, WorkoutRunnerContext workoutRunnerContext)
		{
			ActivityLog log = null;
			try
			{
				log = await MetricStatsToActivityLog.FromConsole(stats, currentConsoleService?.ActiveConsole?.ConsoleInfo, ifitApi?.CurrentlyAuthenticatedUserId, deviceInfo?.SoftwareNumber ?? 0, workoutId, programId, challengeId);
			}
			catch (Exception ex)
			{
				Log.Trace("Workout", $"Exception when converting workout MetricStats to ActivityLog. Exception: {ex.GetBaseException()}");
			}
			if (log == null)
			{
				log = new ActivityLog();
			}
			log.Summary = new ActivityLog.StatSummary
			{
				TotalMeters = ((stats == null || stats.DistanceChanges.IsNullOrEmpty()) ? 0.0 : stats.DistanceChanges.Last.Value),
				TotalCalories = ((stats == null || stats.CalorieChanges.IsNullOrEmpty()) ? 0.0 : stats.CalorieChanges.Last.Value)
			};
			log.WorkoutContext = workoutRunnerContext?.Context ?? Workout.WorkoutContext.OnDemand;
			if (workoutRunnerContext == null || workoutRunnerContext.Context != Workout.WorkoutContext.OnDemand)
			{
				log.LiveWorkoutScheduleId = workoutRunnerContext?.ScheduleInfo?.Id;
			}
			return log;
		}

		public async Task<ErrorCode> DeleteActivityLog(string activityLogId)
		{
			ErrorCode deleteResult = ErrorCode.None;
			try
			{
				Log.Trace(LogTag, "Attempting to delete activity log " + activityLogId + " ...");
				await ifitApi.DeleteActivityLog(activityLogId);
			}
			catch (TaskCanceledException exception)
			{
				Log.Trace(LogTag, "Delete activity log timed out", exception);
				deleteResult = ErrorCode.LogDeleteTimeout;
			}
			catch (iFit.Api.Support.ConnectivityException exception2)
			{
				Log.Trace(LogTag, "Encountered a connectivity problem while deleting an activity log", exception2);
				deleteResult = ErrorCode.LogDeleteNoConnection;
			}
			catch (JsonSerializationException exception3)
			{
				Log.Trace(LogTag, "Encountered a JSON problem while deleting an activity log", exception3);
				deleteResult = ErrorCode.LogDeleteJsonError;
			}
			catch (SQLiteException exception4)
			{
				Log.Trace(LogTag, "Encountered a SQL problem while deleting an activity log", exception4);
				deleteResult = ErrorCode.LogDeleteSqliteError;
			}
			catch (ApiException ex)
			{
				Log.Trace(LogTag, "Encountered a server error while deleting an activity log", ex);
				deleteResult = (ErrorCode)(78000 + ex.StatusCode);
			}
			catch (Exception exception5)
			{
				Log.Trace(LogTag, "Encountered an unknown exception deleting an activity log", exception5);
				deleteResult = ErrorCode.LogDeleteUnknownError;
			}
			return deleteResult;
		}

		public async Task<DetailedUploadResult> HandleJSONException(JsonSerializationException exception, ActivityLog log)
		{
			if (exception.Message.StartsWith("Unexpected end when deserializing object", StringComparison.Ordinal) || exception.Message.StartsWith("Unexpected end when setting", StringComparison.Ordinal))
			{
				Log.Trace("Api", "Upload was probably successful.  Treating as success despite encountering a deserialization error.", exception);
				return (DetailedUploadResult)UploadResult.Success;
			}
			Log.Trace("Api", "Encountered a JSON Serialization error", exception);
			await SendErrorReport(log, exception);
			return new DetailedUploadResult(UploadResult.JSONException, ErrorCode.LogUploadUnknownJsonError);
		}

		private async Task<DetailedUploadResult> HandleApiException(ApiException exception, ActivityLog log)
		{
			ErrorCode displayableCode = exception.StatusCode.BackgroundErrorCode();
			HttpStatusCode statusCode = exception.StatusCode;
			switch (statusCode)
			{
			default:
				switch (statusCode)
				{
				case HttpStatusCode.BadRequest:
					Log.Trace("Api", "Made a Bad Request while trying to upload an activity log, but we will still retry.", exception);
					await SendErrorReport(log, exception, exception.Content);
					return new DetailedUploadResult(UploadResult.APIUploadErrorRetry, displayableCode);
				case HttpStatusCode.RequestEntityTooLarge:
					Log.Trace("Api", "Encountered an issue with the upload request being too large.  We should try again later.");
					return new DetailedUploadResult(UploadResult.APIUploadErrorRetry, displayableCode);
				default:
					Log.Trace("Api", $"Encountered an error while trying to upload an activity log (Status Code: {exception.StatusCode}).  We should try again later", exception);
					await SendErrorReport(log, exception, exception.Content);
					return new DetailedUploadResult(UploadResult.APIUploadErrorRetry, displayableCode);
				}
			case HttpStatusCode.Unauthorized:
			case HttpStatusCode.Forbidden:
				Log.Trace("Api", "Encountered an issue with user's auth token while trying to upload an activity log.  We should try again later.");
				return new DetailedUploadResult(UploadResult.APIUploadErrorRetry, displayableCode);
			case HttpStatusCode.RequestTimeout:
				Log.Trace("Api", "Timed out while trying to upload an activity log.  We should try again later.");
				return new DetailedUploadResult(UploadResult.Timeout, displayableCode);
			case HttpStatusCode.InternalServerError:
			case HttpStatusCode.NotImplemented:
			case HttpStatusCode.BadGateway:
			case HttpStatusCode.ServiceUnavailable:
			case HttpStatusCode.GatewayTimeout:
			case HttpStatusCode.HttpVersionNotSupported:
			case HttpStatusCode.VariantAlsoNegotiates:
			case HttpStatusCode.InsufficientStorage:
			case HttpStatusCode.LoopDetected:
			case (HttpStatusCode)509:
			case HttpStatusCode.NotExtended:
			case HttpStatusCode.NetworkAuthenticationRequired:
			case (HttpStatusCode)512:
			case (HttpStatusCode)513:
			case (HttpStatusCode)514:
