		private async Task SendErrorReport(ActivityLog activityLog, Exception exception, string content = "")
		{
			try
			{
				IDictionary<string, object> customData = analytics.ActivityLogProperties(activityLog);
				await crashReporter.ReportError($"{exception.GetType()}: {exception.Message} {content}", new PostWorkoutLogUploadException(exception.Message, exception, content), customData);
			}
			catch (Exception exception2)
			{
				Log.Error("Workout", "Error in ActivityLogRepository.SendErrorReport", exception2);
			}
		}

		public async Task UpdateDiagnosticStats()
		{
			using (ActivityLog activityLog = await statsToActivityLogTranslator.ToActivityLog(workoutSettings.WorkoutContainer?.Stats?.RunningStats))
			{
				if (activityLog == null || activityLog?.Duration < workoutSettings.MinimumWorkoutDuration || activityLog?.Summary?.TotalMeters < workoutSettings.MinimumWorkoutDistance)
				{
					return;
				}
			}
			try
			{
				deviceInfo.NumberOfWorkouts++;
			}
			catch (OverflowException exception)
			{
				Log.Error("Settings", "Adding To Number Of Workouts Would Result In Value Greater Than uint.MaxValue", exception);
				deviceInfo.NumberOfWorkouts = 4294967295u;
			}
		}

		private void SaveLogToAppleHealthInBackground(ActivityLog log)
		{
			if (appleHealthDataSyncService == null)
			{
				return;
			}
			Task.Run(async delegate
			{
				try
				{
					await appleHealthDataSyncService.SaveLogToHealthStoreAsync(log);
				}
				catch (Exception ex)
				{
					Log.Trace("HealthKit", $"An error occurred when attempting to save activity log (id: {log.Id}) to HealthKit store: {ex.GetType()}, {ex.Message}", ex);
				}
			});
		}
	}
