	public class PostWorkoutInteractor : IPostWorkoutInteractor
	{
		public const int MinDurationForLogoutContinueOnBuiltinClubInMillis = 60000;

		public const int MaxDurationForLogoutContinueOnBuiltinClubMillis = 2700000;

		private const int MinimumWorkoutDistanceInMeters = 8;

		private readonly ILocalSettings settings;

		private readonly IDialogPresenter dialogPresenter;

		private readonly IDeviceInformation deviceInfo;

		private readonly IUploadWorkoutLogsService uploadWorkoutLogsService;

		private readonly IConnectivity connectivity;

		private readonly IActivityLogRepository activityLogRepository;

		private readonly ICompetitionService competitionService;

		private readonly IIfitApiService ifitApi;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IWorkoutSettings workoutSettings;

		private BaseLogScreenViewModel.LogScreenNavObject navObject;

		private IPostWorkoutViewPresenter viewPresenter;

		public bool HasNavigatedAway { get; set; }

		public bool HasFailedAlready { get; set; }

		public bool IsStartingNewWorkout { get; set; }

		public bool IsDialogVisible { get; set; }

		public UploadResult? WorkoutUploadResult => navObject.UploadResult;

		public PostWorkoutInteractor(ILocalSettings settings, IDialogPresenter dialogPresenter, IDeviceInformation deviceInfo, IUploadWorkoutLogsService uploadWorkoutLogsService, IConnectivity connectivity, IActivityLogRepository activityLogRepository, ICompetitionService competitionService, IIfitApiService ifitApi, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings)
		{
			this.settings = settings;
			this.dialogPresenter = dialogPresenter;
			this.deviceInfo = deviceInfo;
			this.uploadWorkoutLogsService = uploadWorkoutLogsService;
			this.connectivity = connectivity;
			this.activityLogRepository = activityLogRepository;
			this.competitionService = competitionService;
			this.ifitApi = ifitApi;
			this.currentConsoleService = currentConsoleService;
			this.workoutSettings = workoutSettings;
		}

		public void Initialize(BaseLogScreenViewModel.LogScreenNavObject navObject, IPostWorkoutViewPresenter viewPresenter)
		{
			this.viewPresenter = viewPresenter;
			this.navObject = navObject;
		}

		public void DisableStartKey()
		{
			if (currentConsoleService.Console != null)
			{
				currentConsoleService.Console.StartKeyEnabled = false;
			}
		}

		public void CheckAndShowSafetyKeyDialog()
		{
			ConsoleState? consoleState = currentConsoleService.Console?.LatestBasicInfo?.CurrentState;
			if (consoleState == ConsoleState.SafetyKeyRemoved || consoleState == ConsoleState.Demo)
			{
				ConsoleStateChangeHandler<SafetyKeyDialogViewModel>.ShowDialogViewModelSafely(dialogPresenter, shouldNotShowDismiss: false, wasShowingScreenSaver: false);
			}
		}

		public void CheckAndShowConsoleErrorDialog()
		{
			if (currentConsoleService.Console?.LatestBasicInfo?.CurrentState == ConsoleState.Error)
			{
				ConsoleStateChangeHandler<ConsoleErrorDialogViewModel>.ShowDialogViewModelSafely(dialogPresenter, shouldNotShowDismiss: false, wasShowingScreenSaver: false);
			}
		}

		public void CleanWorkout()
		{
			workoutSettings?.ClearAndDisposeWorkoutContainer();
		}

		public async Task<ActivityLogPopulateResult> PopulateActivityLog(string activityLogId, string workoutId, string programId, string challengeId, MetricStats runningStats, WorkoutRunnerContext workoutRunnerContext)
		{
			return await activityLogRepository.PopulateActivityLog(activityLogId, workoutId, programId, challengeId, runningStats, workoutRunnerContext);
		}

		public void DisplayLogLoadErrorMessage()
		{
			viewPresenter.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.error_ifit_loading_log, null, string.Empty, Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), delegate
			{
				viewPresenter.CloseViewModel.Execute(null);
			}, null, dismissible: false, cancellable: false, "", null, navObject.UploadErrorCode.HumanReadable(), isWarning: true);
		}

		public async Task DeleteActivityLog(string activityLogId)
		{
			if (navObject.UploadResult != UploadResult.Success)
			{
				await (uploadWorkoutLogsService?.RemoveLogItem(navObject.UploadLogItemId));
				viewPresenter.FinishAndNavigateAway();
				return;
			}
			ErrorCode errorCode = await activityLogRepository.DeleteActivityLog(activityLogId);
			if (!HasNavigatedAway)
			{
				if (errorCode == ErrorCode.None)
				{
					viewPresenter.FinishAndNavigateAway();
				}
				else
				{
					viewPresenter.ShowSimpleConfirmationDialog(Wolf.Core.Resources.AppStrings.error, Wolf.Core.Resources.AppStrings.delete_workout_save_error, viewPresenter.FinishAndNavigateAway, cancellableOperation: false, null, string.Empty, Wolf.Core.Resources.AppStrings.okay_title.ToUpper(), null, null, dismissible: false, cancellable: true, "", null, errorCode.HumanReadable(), isWarning: true);
				}
			}
		}

		public void NavigateAway(double activityLogDuration, Action logOut, Action<object, bool> navigateToDashboard, Func<object, IMvxBundle, MvxRequestedBy, bool> showViewModel)
		{
			CleanWorkout();
			if (currentConsoleService.IsBuiltinClub)
			{
				if (activityLogDuration >= 60000.0)
				{
					if (ifitApi.HasLoggedInUser && activityLogDuration < 2700000.0)
					{
						showViewModel(new DashboardViewModel.NavObject
						{
							ShouldShowLogoutContinue = true
						}, ShireViewParams.ClearStackToRequested(), null);
					}
					else
					{
						logOut();
					}
				}
				else
				{
					navigateToDashboard(null, arg2: true);
				}
			}
			else if (!ifitApi.HasLoggedInUser && activityLogDuration >= 60000.0)
			{
				logOut();
			}
			else
			{
				navigateToDashboard(null, arg2: true);
			}
		}
	}
	public interface IPostWorkoutViewPresenter : IShowSimpleConfirmationDialog
	{
		void FinishAndNavigateAway();

		void ShowNoWifiLogScreen(BaseLogScreenViewModel.LogScreenNavObject navObject);
	}
