	public interface IPlatformMediaVolumeService
	{
		void SetPlatformMediaVolume(float volume);

		float GetPlatformMediaVolume();
	}
	public static class PlatformMediaVolumeServiceExtension
	{
		public static void IncreaseVolumeIfNeeded(this IPlatformMediaVolumeService mediaService, bool isBuiltIn, bool headphonesConnected, int previousSystemVolume, int currentSystemVolume)
		{
			if (!isBuiltIn || mediaService == null)
			{
				return;
			}
			float num = (headphonesConnected ? 0.7f : 1f);
			float platformMediaVolume = mediaService.GetPlatformMediaVolume();
			if (!platformMediaVolume.AlmostEqual(num) && !(platformMediaVolume >= num))
			{
				int num2 = currentSystemVolume - previousSystemVolume;
				if (!((float)num2 <= 0f))
				{
					float platformMediaVolume2 = (platformMediaVolume + (float)num2 / 100f).Clamp(0f, num);
					mediaService.SetPlatformMediaVolume(platformMediaVolume2);
				}
			}
		}
	}
