	public class MetricSubscriber
	{
		public readonly INC<double> Value = new NC<double>();

		public MetricType MetricType { get; private set; }

		public MetricSubscriber(MetricType metricType)
		{
			MetricType = metricType;
		}
	}
	public class MetricUpdate : MetricUpdateBase
	{
		public MetricSubscriber MetricSubscriber { get; private set; }

		public MetricUpdate(MetricType metricType)
		{
			MetricSubscriber = new MetricSubscriber(metricType);
			MetricSubscriber.Value.Changed += base.ValueUpdated;
			UnitsChanged(isMetric: false);
		}

		protected override string GetFormattedValueString()
		{
			return MetricSubscriber.MetricType.GetFormattedValue(MetricSubscriber.Value.Value);
		}

		protected override string GetLabelString(bool isMetric)
		{
			return MetricSubscriber.MetricType.GetLabel(isMetric);
		}
	}
	public abstract class MetricUpdateBase
	{
		public readonly INC<string> FormattedValue = new NC<string>();

		public readonly INC<string> Label = new NC<string>();

		protected void ValueUpdated(object sender, EventArgs e)
		{
			IMvxMainThreadDispatcher mvxMainThreadDispatcher = Mvx.Resolve<IMvxMainThreadDispatcher>();
			mvxMainThreadDispatcher.RequestMainThreadAction(delegate
			{
				FormattedValue.Value = GetFormattedValueString();
			});
		}

		protected void UnitsChanged(bool isMetric)
		{
			IMvxMainThreadDispatcher mvxMainThreadDispatcher = Mvx.Resolve<IMvxMainThreadDispatcher>();
			mvxMainThreadDispatcher.RequestMainThreadAction(delegate
			{
				Label.Value = GetLabelString(isMetric);
				FormattedValue.Value = GetFormattedValueString();
			});
		}

		protected abstract string GetFormattedValueString();

		protected abstract string GetLabelString(bool isMetric);
	}
