				if (lockPinService.IsLockPinEnabled && lockPinService.IsLockPinNumberConfigured)
				{
					return !consoleStateFacade.GetMostRecentConsoleState().IsWorkout();
				}
				return false;
			}
		}

		public bool LockWhenFinishProcess { get; set; }

		public bool IsScreenLocked { get; private set; }

		public Type NavigateFrom { get; set; }

		public LockScreenHandler(ILockPinService lockPinService, ICurrentConsoleService currentConsoleService, IDialogPresenter dialogPresenter, IMainThreadService mainThreadService, IConsoleStateFacade consoleStateFacade)
		{
			this.lockPinService = lockPinService;
			this.currentConsoleService = currentConsoleService;
			this.dialogPresenter = dialogPresenter;
			this.mainThreadService = mainThreadService;
			this.consoleStateFacade = consoleStateFacade;
		}

		public void NavigateToLockScreen(Type navigateFrom = null, bool forceLoggedInUserToDashboard = false)
		{
			if (!CanShowLockScreen)
			{
				Log.Trace("LockScreenHandler", "Can't Lock Screen");
				return;
			}
			IsScreenLocked = true;
			NavigateFrom = navigateFrom;
			Log.Trace("LockScreenHandler", "Screen Locked!");
			dialogPresenter?.ShowDialog<LockScreenDialogViewModel>(null, showSafely: true, forceLoggedInUserToDashboard);
		}

		public bool NavigateToLockScreenWhenGainConnection(Action closeCurrentView)
		{
			if (LockWhenFinishProcess)
			{
				LockWhenFinishProcess = false;
				NavigateToLockScreen();
				closeCurrentView?.Invoke();
				return true;
			}
			if (IsScreenLocked)
			{
				NavigateToLockScreen();
				return true;
			}
			return false;
		}

		public async Task UnlockScreen(bool continueWorkout = false)
		{
			if (!continueWorkout)
			{
				await StopWorkout().ConfigureAwait(continueOnCapturedContext: false);
			}
			IsScreenLocked = false;
			Log.Trace("LockScreenHandler", "Screen Unlocked!");
		}

		private async Task StopWorkout()
		{
			ICurrentConsoleService obj = currentConsoleService;
			if (obj == null || !obj.IsInWorkout)
			{
				return;
			}
			ConsoleState consoleState = currentConsoleService?.Console?.LatestBasicInfo?.CurrentState ?? ConsoleState.Idle;
			if (consoleState == ConsoleState.Paused)
			{
				IWorkoutFacade workoutFacade = Mvx.Resolve<IWorkoutFacade>();
				Shire.Core.Util.NonGenericSubject obs = new Shire.Core.Util.NonGenericSubject();
				mainThreadService?.InvokeOnMainThreadAsync(() => ((BaseViewModel)dialogPresenter.CurrentMainViewModel)?.ShowProgressDialog(Wolf.Core.Resources.AppStrings.in_workout_lock_screen_finishing_workout, obs.ReactiveSubject, null, null, default(TimeSpan), "", showSafety: false).ConfigureAwait(continueOnCapturedContext: false));
				await ConsoleStateAwaiterFactory.Builder().FromCurrentState(ConsoleState.Idle).AfterConsoleCommand(async delegate
				{
					await workoutFacade.EndWorkoutAsync();
				})
					.WithSkipCondition(consoleState != ConsoleState.Idle && consoleState != ConsoleState.WorkoutResults)
					.Run()
					.ConfigureAwait(continueOnCapturedContext: false);
				obs.OnNext();
			}
		}
	}
}
namespace Wolf.Core.Services.LockPin
{
	public interface ILockPinService
	{
		bool IsLockPinEnabled { get; }

		bool IsLockPinNumberConfigured { get; }

		string GetLockPinNumber();

		void SaveLockPinNumber(string lockPinNumber);
	}
	public class LockPinService : ILockPinService
	{
		private readonly IPersistentLockPinSettings persistentLockPinSettings;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ICurrentConsoleService currentConsoleService;

		public bool IsLockPinEnabled => CheckIsLockPinEnabled();

		public bool IsLockPinNumberConfigured
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(persistentLockPinSettings.LockPinNumber))
				{
					return persistentLockPinSettings.LockPinNumber.Length == 4;
				}
				return false;
			}
		}

		public LockPinService(IPersistentLockPinSettings persistentLockPinSettings, IFeatureFlagManager featureFlagManager, ICurrentConsoleService currentConsoleService)
		{
			this.persistentLockPinSettings = persistentLockPinSettings;
			this.featureFlagManager = featureFlagManager;
			this.currentConsoleService = currentConsoleService;
		}

		public string GetLockPinNumber()
		{
			return persistentLockPinSettings.LockPinNumber;
		}

		public void SaveLockPinNumber(string lockPinNumber)
		{
			persistentLockPinSettings.LockPinNumber = lockPinNumber;
		}

		private bool CheckIsLockPinEnabled()
		{
			if (featureFlagManager == null || !featureFlagManager.IsFeatureEnabled(FeatureFlags.LockPinEnabled))
			{
				return false;
			}
			IConsoleInfo consoleInfo = currentConsoleService.PhysicalConsole?.ConsoleInfo;
			if (consoleInfo == null || !consoleInfo.MachineType.IsBeltBasedMachine())
			{
				return false;
			}
			return true;
		}
	}
}
namespace Wolf.Core.Services.Leaderboard
{
	public interface ILeaderboardAnalyticTracker
	{
		bool IsInitialized { get; }

		void Initialize();

		void TrackLeaderboardAnalytics(WidgetType oldMode, WidgetType newMode);

		void TrackLeaderboardAnalytics(WidgetType oldMode, WidgetType newMode, double currentTime);

		Task LogLeaderboardAnalytics(Workout workout, ConsoleStateStats stats, WidgetType currentWidget, int rank);
	}
	public class LeaderboardAnalyticTracker : ILeaderboardAnalyticTracker
	{
		protected const string Tag = "Leaderboard";

		private readonly IWolfAnalytics analytics;

		private readonly ICurrentConsoleService currentConsoleService;

		private double leaderboardStartTime;

		private double leaderboardEndTime;

		private double leaderboardShowingSeconds;

		public bool IsInitialized { get; private set; }

		public LeaderboardAnalyticTracker(ILocalSettings localSettings, IWolfAnalytics analytics, ICurrentConsoleService currentConsoleService)
		{
			this.analytics = analytics;
			this.currentConsoleService = currentConsoleService;
		}

		public void Initialize()
		{
			leaderboardStartTime = 0.0;
			leaderboardEndTime = 0.0;
			leaderboardShowingSeconds = 0.0;
			IsInitialized = true;
		}

		public void TrackLeaderboardAnalytics(WidgetType oldMode, WidgetType newMode)
		{
			if (IsInitialized)
			{
				int valueOrDefault = (currentConsoleService?.ActiveConsole?.LatestBasicInfo?.RunningTime).GetValueOrDefault();
				TrackLeaderboardAnalytics(oldMode, newMode, valueOrDefault);
			}
		}

		public void TrackLeaderboardAnalytics(WidgetType oldMode, WidgetType newMode, double currentTime)
		{
			if (IsInitialized && ((oldMode == WidgetType.Leaderboard) ^ (newMode == WidgetType.Leaderboard)))
			{
				if (newMode == WidgetType.Leaderboard)
				{
					leaderboardStartTime = currentTime;
				}
				else if (oldMode == WidgetType.Leaderboard)
				{
					leaderboardEndTime = currentTime;
					leaderboardShowingSeconds += Math.Max(leaderboardEndTime - leaderboardStartTime, 0.0);
				}
			}
		}

		public async Task LogLeaderboardAnalytics(Workout workout, ConsoleStateStats stats, WidgetType currentWidget, int rank)
		{
			if (analytics == null || !IsInitialized)
			{
				return;
			}
			int num = (int)(stats?.RunningStats?.MaxDuration).GetValueOrDefault();
			if (num == 0)
			{
				Log.Error("Leaderboard", "LeaderboardAnalyticTracker RunningStats didn't have any stats with a duration > 0, not logging analytics");
				return;
			}
			TrackLeaderboardAnalytics(currentWidget, WidgetType.None, num);
			if (leaderboardShowingSeconds > (double)num)
			{
				Log.Error("Leaderboard", string.Format("{0} had leaderboard seconds {1} longer than duration {2}", "LeaderboardAnalyticTracker", leaderboardShowingSeconds, num));
				leaderboardShowingSeconds = num;
			}
			await analytics.LeaderboardPercentageOfTimeOn(workout, (int)leaderboardShowingSeconds, num, rank);
			IsInitialized = false;
		}
	}
	public class LeaderboardWebViewDelegate : IDisposable
	{
		private const string UpdateMomentMethod = "updateMoment";

		private const string MomentProperty = "moment";

		private const string DelayProperty = "delay";

		private IJavascriptBridge bridge;

		private Action webViewRenderProcessGone;

		private Func<bool> isInFullscreenMode;

		private Func<ConsoleState> workoutMode;

		private WidgetManager widgetManager;

		private string workoutId;

		private bool isLiveWorkout;

		private readonly IIfitApiService ifitApi;

		private readonly IMainThreadService mainThreadService;

		private readonly IWebViewConfigService webViewConfigService;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IWorkoutSettings workoutSettings;

		private readonly ICompetitionService competitionsService;

		private readonly IAppLifecycleService appLifecycleService;

		private readonly IConnectivity connectivity;

		private readonly IWebviewHolderFactory webviewHolderFactory;

		private readonly ICurrentConsoleService currentConsoleService;

		private readonly IPreferenceResolver preferenceResolver;

		private readonly IWebviewSettings webviewSettings;

		private ILeaderboardAnalyticTracker leaderboardAnalytics;

		private IDisposable competitionNextMomentSub;

		private IDisposable webviewReloaderSub;

		public string LogTag => "Workout";

		public bool ShouldCacheWebPages => false;

		public bool EnableChromeDebugging => false;

		public IWebviewReloader AutomaticWebviewReloader { get; private set; }

		public Action RetryLoadWebView { get; set; }

		public Func<string> GetViewUrl { get; set; }

		private bool ShouldAutomaticallyShowLeaderboard
		{
			get
			{
				IWorkoutSettings obj = workoutSettings;
				if (obj == null)
				{
					return false;
				}
				return obj.PreferredRightWorkoutWidget == WidgetType.Leaderboard;
			}
		}

		public string WebviewUrl
		{
			get
			{
				if (featureFlagManager.GetString(FeatureFlags.LiveLeaderboardWebViewUrl).IsNullOrWhitespace())
				{
					return "";
				}
				Uri uri = new Uri(featureFlagManager.GetString(FeatureFlags.LiveLeaderboardWebViewUrl));
				return uri.AppendOrReplaceQueryVars(WebviewParameters).ToString();
			}
		}

		private string MomentField
		{
			get
			{
				IWorkoutSettings obj = workoutSettings;
				if (obj == null || obj.WorkoutContainer?.Workout?.Target != Workout.TargetType.Meters)
				{
					return "seconds";
				}
				return "meters";
			}
		}

		private Dictionary<string, string> WebviewParameters
		{
			get
			{
				string value = ((workoutSettings?.WorkoutContainer?.Workout?.IsVideoWorkout() == true) ? "video" : ((workoutSettings?.WorkoutContainer?.Workout?.IsGoogleMap == true) ? "map" : "manual"));
				Dictionary<string, string> dictionary = new Dictionary<string, string>
				{
					{
						"userId",
						ifitApi?.CurrentlyAuthenticatedUserId
					},
					{ "workoutId", workoutId },
					{
						"activityLogId",
						competitionsService?.WolfGeneratedId
					},
					{
						"equipmentType",
						currentConsoleService?.GetCurrentConsoleType(ConsoleType.None).ToString()
					},
					{ "momentField", MomentField },
					{
						"useMetricUnits",
						preferenceResolver?.IsMetric.ToString().ToLower()
					},
					{ "workoutType", value },
					{
						"isLiveWorkout",
						isLiveWorkout.ToString().ToLowerInvariant()
					}
				};
				IWebviewSettings obj = webviewSettings;
				if (obj != null && obj.IsWebviewVerboseMode)
				{
					dictionary["verbose"] = null;
				}
				return dictionary;
			}
		}

		public LeaderboardWebViewDelegate(IIfitApiService ifitApi, IMainThreadService mainThreadService, IWebViewConfigService webViewConfigService, IFeatureFlagManager featureFlagManager, ICompetitionService competitionsService, IAppLifecycleService appLifecycleService, IConnectivity connectivity, IWebviewHolderFactory webViewStore, ICurrentConsoleService currentConsoleService, IPreferenceResolver preferenceResolver, IWebviewSettings webviewSettings, IWorkoutSettings workoutSettings)
		{
			this.ifitApi = ifitApi;
			this.mainThreadService = mainThreadService;
			this.webViewConfigService = webViewConfigService;
			this.featureFlagManager = featureFlagManager;
			this.competitionsService = competitionsService;
			this.appLifecycleService = appLifecycleService;
			this.connectivity = connectivity;
			webviewHolderFactory = webViewStore;
			this.currentConsoleService = currentConsoleService;
			this.preferenceResolver = preferenceResolver;
			this.webviewSettings = webviewSettings;
			this.workoutSettings = workoutSettings;
		}

		public void Init(WidgetManager widgetManager, string workoutId, bool isLiveWorkout, Action webViewRenderProcessGone, Func<bool> isInFullscreenMode, Func<ConsoleState> workoutMode, ILeaderboardAnalyticTracker leaderboardAnalytics)
		{
			this.widgetManager = widgetManager;
			this.workoutId = workoutId;
			this.isLiveWorkout = isLiveWorkout;
			this.webViewRenderProcessGone = webViewRenderProcessGone;
			this.isInFullscreenMode = isInFullscreenMode;
			this.workoutMode = workoutMode;
			this.leaderboardAnalytics = leaderboardAnalytics;
			AutomaticWebviewReloader = new WebviewReloader(connectivity, webviewHolderFactory, new WebviewReloaderProperties(WebviewUrl, handleNoInternetRecovery: true));
			webviewReloaderSub = AutomaticWebviewReloader.ReloadStatusChanged.SubscribeWithErrorLogging(HandleWebviewReloadStatusChanged);
		}

		public void BuildBridge(IJavascriptBridge bridge)
		{
			this.bridge = bridge;
		}

		private void HandleWebviewReloadStatusChanged(WebviewReloaderStatus status)
		{
			switch (status)
			{
			case WebviewReloaderStatus.Finished:
				OnWebviewFinishedNavigating(null, null);
				break;
			case WebviewReloaderStatus.ShouldReload:
				RetryLoadWebView();
				break;
			case WebviewReloaderStatus.WaitingOnReload:
			case WebviewReloaderStatus.NoInternet:
			case WebviewReloaderStatus.Failed:
				break;
			}
		}

		public void OnWebviewFinishedNavigating(object sender, EventArgs e)
		{
			IIfitEnvironment env = ifitApi.Environment;
			mainThreadService.InvokeOnMainThreadAsync(async delegate
			{
				Dictionary<string, string> info = (await (webViewConfigService?.GetBaseConfigsExcluding(OptionalConfigs.UserId))) ?? new Dictionary<string, string>();
				Dictionary<string, string> dictionary = info;
				dictionary["bearerToken"] = "Bearer " + await ifitApi.GetToken();
				info["baseIfitAPIUrl"] = env.BaseSite;
				info["ifitAPIUrlVersion"] = "v1";
				info["clientId"] = env.ClientId;
				info["clientSecret"] = env.ClientSecret;
				info["rankEveryXms"] = featureFlagManager.GetString(FeatureFlags.LeaderboardRankEveryX);
				bridge.Call("setupApp", info);
				string leaderboardDelayMillis = ((workoutSettings.WorkoutContainer.WorkoutRunner.RunContext.Context != Workout.WorkoutContext.OnDemand) ? featureFlagManager.GetInt(FeatureFlags.LiveLeaderboardDelayMillis).ToString() : featureFlagManager.GetInt(FeatureFlags.LeaderboardDelayMillis).ToString());
				competitionNextMomentSub?.Dispose();
				competitionNextMomentSub = null;
				competitionNextMomentSub = competitionsService.SendNextMoment.Subscribe(delegate(int m)
				{
					if (!appLifecycleService.IsAppInBackground && widgetManager.IsLeaderboardVisible.Value)
					{
						bridge.Call("updateMoment", new Dictionary<string, string>
						{
							["moment"] = m.ToString(),
							["delay"] = leaderboardDelayMillis
						});
					}
				});
				if (!isInFullscreenMode() && workoutMode() == ConsoleState.Workout && ShouldAutomaticallyShowLeaderboard && !widgetManager.IsLeaderboardVisible.Value)
				{
					widgetManager.ToggleLeaderboardWidget();
				}
			});
		}

		public void OnWebViewErrorLoading(object sender, EventArgs e)
		{
			AutomaticWebviewReloader?.StartReload(GetViewUrl, waitForNoInternetRecovery: true);
		}

		public void OnWebViewRenderProcessGone()
		{
			webViewRenderProcessGone();
		}

		public void Dispose()
		{
			bridge?.Dispose();
			bridge = null;
			competitionNextMomentSub?.Dispose();
			competitionNextMomentSub = null;
			webviewReloaderSub?.Dispose();
			webviewReloaderSub = null;
			AutomaticWebviewReloader?.Dispose();
			AutomaticWebviewReloader = null;
		}
	}
}
