	public class InAppPurchaseOrder
	{
		public enum PurchaseSource
		{
			iOS,
			Android
		}

		public PurchaseSource Source { get; set; }

		public string PaymentType { get; set; }

		public string KitOrItemId { get; set; }

		public string ReceiptData { get; set; }

		public string PackageName { get; set; }

		public string ProductId { get; set; }

		public string PurchaseToken { get; set; }

		public bool IsValid
		{
			get
			{
				if (!IsValidiOS)
				{
					return IsValidAndroid;
				}
				return true;
			}
		}

		public bool IsValidAndroid
		{
			get
			{
				if (Source == PurchaseSource.Android && IsValidOrderData && !string.IsNullOrWhiteSpace(PackageName) && !string.IsNullOrWhiteSpace(ProductId))
				{
					return !string.IsNullOrWhiteSpace(PurchaseToken);
				}
				return false;
			}
		}

		public bool IsValidiOS
		{
			get
			{
				if (Source == PurchaseSource.iOS && IsValidOrderData)
				{
					return !string.IsNullOrWhiteSpace(ReceiptData);
				}
				return false;
			}
		}

		private bool IsValidOrderData
		{
			get
			{
				if (!string.IsNullOrWhiteSpace(PaymentType))
				{
					return !string.IsNullOrWhiteSpace(KitOrItemId);
				}
				return false;
			}
		}

		public InAppPurchaseOrder()
		{
		}

		public InAppPurchaseOrder(InAppPurchaseIos iosPurchase)
		{
			Source = PurchaseSource.iOS;
			ReceiptData = iosPurchase.ReceiptData;
			PaymentType = iosPurchase.PaymentType;
			KitOrItemId = iosPurchase.KitOrItemId;
		}

		public InAppPurchaseOrder(InAppPurchaseAndroid androidPurchase)
		{
			Source = PurchaseSource.Android;
			PackageName = androidPurchase.PackageName;
			ProductId = androidPurchase.ProductId;
			PurchaseToken = androidPurchase.PurchaseToken;
			PaymentType = androidPurchase.PaymentType;
			KitOrItemId = androidPurchase.KitOrItemId;
		}

		public WebDataObject GetPurchase()
		{
			if (Source == PurchaseSource.iOS)
			{
				return new InAppPurchaseIos
				{
					ReceiptData = ReceiptData,
					PaymentType = PaymentType,
					KitOrItemId = KitOrItemId
				};
			}
			return new InAppPurchaseAndroid
			{
				PackageName = PackageName,
				ProductId = ProductId,
				PurchaseToken = PurchaseToken,
				PaymentType = PaymentType,
				KitOrItemId = KitOrItemId
			};
		}
	}
