	public abstract class InAppPurchaseService : IInAppPurchaseService, IInAppBillingVerifyPurchase
	{
		protected const string Tag = "InAppPurchase";

		private string[] SubscriptionSkus = new string[2] { "ifmmse", "ifmysekit102" };

		protected IIfitApiService apiService;

		protected IWolfAnalytics wolfAnalytics;

		protected InAppBillingPurchase currentPurchase;

		protected readonly Subject<bool> _onPurchaseSyncStatusChanged = new Subject<bool>();

		protected readonly Subject<InAppPurchaseException> _onPurchaseSyncError = new Subject<InAppPurchaseException>();

		public IObservable<bool> OnPurchaseSynced => _onPurchaseSyncStatusChanged;

		public IObservable<InAppPurchaseException> OnPurchaseSyncError => _onPurchaseSyncError;

		public bool IsBillingSupported => CrossInAppBilling.IsSupported;

		public IDictionary<string, string> PricingInfo { get; }

		public IBlobCache Cache { get; set; }

		public abstract Task<bool> VerifyPurchase(string signedData, string signature, string productId = null, string transactionId = null);

		public abstract Task<SubscriptionStatus> GetSubscriptionStatus();

		protected abstract Task SyncPurchase(InAppPurchaseOrder order);

		protected InAppPurchaseService(IBlobCacheService cacheService, IIfitApiService apiService, IWolfAnalytics wolfAnalytics)
		{
			Cache = cacheService.Secure;
			this.apiService = apiService;
			this.wolfAnalytics = wolfAnalytics;
			PricingInfo = new Dictionary<string, string>();
		}

		public async Task RegisterFailedPurchase(InAppPurchaseOrder purchase, string userId)
		{
			try
			{
				await Cache.InsertObject(userId, purchase);
			}
			catch (Exception ex)
			{
				Log.Error("InAppPurchase", "Error registering failed purchase", ex.GetBaseException());
			}
		}

		public async Task<InAppPurchaseOrder> FailedPurchaseForUser(string userId)
		{
			InAppPurchaseOrder inAppPurchaseOrder;
			try
			{
				inAppPurchaseOrder = await Cache.GetObject<InAppPurchaseOrder>(userId);
			}
			catch (KeyNotFoundException)
			{
				return null;
			}
			try
			{
				if (inAppPurchaseOrder != null && await RenewalStatus.CheckStatus(apiService))
				{
					await ClearFailedPurchase(userId);
					return null;
				}
			}
			catch (ApiException)
			{
			}
			return inAppPurchaseOrder;
		}

		public async Task ClearFailedPurchase(string userId)
		{
			await Cache.InvalidateObject<InAppPurchaseOrder>(userId);
		}

		public async Task<bool> OpenConnection()
		{
			if (!CrossInAppBilling.IsSupported)
			{
				throw new BillingNotSupportedException();
			}
			return await CrossInAppBilling.Current.ConnectAsync();
		}

		protected abstract string GetSignedDataFromPurchase(InAppBillingPurchase inAppBillingPurchase);

		public virtual async Task<bool> MakePurchase(string sku)
		{
			currentPurchase = await CrossInAppBilling.Current.PurchaseAsync(sku, ItemType.Subscription);
			string signedDataFromPurchase = GetSignedDataFromPurchase(currentPurchase);
			await VerifyPurchase(signedDataFromPurchase, currentPurchase.Signature, currentPurchase.ProductId, currentPurchase.TransactionIdentifier);
			InAppBillingPurchase inAppBillingPurchase = currentPurchase;
			return (object)inAppBillingPurchase != null && inAppBillingPurchase.State == PurchaseState.Purchased;
		}

		public virtual async Task ProcessPurchase(string paymentType, string itemId)
		{
			try
			{
				await CrossInAppBilling.Current.FinalizePurchaseAsync(currentPurchase.PurchaseToken);
			}
			catch (Exception exception)
			{
				Log.Error("InAppPurchase", "FinalizePurchaseAsync failed", exception);
			}
			await CrossInAppBilling.Current.DisconnectAsync();
		}

		public virtual async Task SyncFailedPurchase(InAppPurchaseOrder order, string userId)
		{
			if (order.IsValid)
			{
				await SyncPurchase(order);
			}
			else
			{
				Log.Trace("InAppPurchase", "Clearing out invalid failed purchase");
			}
			await ClearFailedPurchase(userId);
		}

		public virtual async Task CloseConnection()
		{
			currentPurchase = null;
			await CrossInAppBilling.Current.DisconnectAsync();
		}

		protected async Task PurchaseSyncCompleted()
		{
			await ClearFailedPurchase(apiService.CurrentlyAuthenticatedUserId);
			_onPurchaseSyncStatusChanged.OnNext(value: true);
		}

		protected async Task PurchaseSyncFailed(InAppPurchaseOrder purchaseOrder, Exception e)
		{
			string userId = apiService.CurrentlyAuthenticatedUserId;
			await ClearFailedPurchase(userId);
			await RegisterFailedPurchase(purchaseOrder, userId);
			_onPurchaseSyncError.OnNext(new InAppPurchaseException(Wolf.Core.Resources.AppStrings.onboarding_payment_finalize_error, $"ERROR making ifit API call after successful IAP: {e}"));
		}

		public async Task PreFetchPricingInfo()
		{
			bool connected = false;
			bool success = false;
			object obj = null;
			int num = 0;
			try
			{
				_ = 1;
				try
				{
					connected = await OpenConnection();
					if (!connected)
					{
						Log.Trace("InAppPurchase", "ERROR pulling currency code from app store: Connection.");
					}
					else
					{
						IEnumerable<InAppBillingProduct> enumerable = await CrossInAppBilling.Current.GetProductInfoAsync(ItemType.Subscription, SubscriptionSkus);
						if (enumerable == null || !enumerable.Any())
						{
							Log.Trace("InAppPurchase", "ERROR pulling currency code from app store: GetProductInfoAsync didn't return any products.");
						}
						else
						{
							PricingInfo["currencyCode"] = enumerable.First().CurrencyCode;
							foreach (InAppBillingProduct item in enumerable)
							{
								PricingInfo[item.ProductId + "Price"] = item.LocalizedPrice;
							}
							InAppBillingProduct inAppBillingProduct = enumerable.FirstOrDefault();
							Log.Trace("InAppPurchase", "IAP> Pricing info successfully fetched: " + inAppBillingProduct?.CurrencyCode + ", " + inAppBillingProduct?.LocalizedPrice);
							success = true;
						}
					}
				}
				catch (InAppBillingPurchaseException exception)
				{
					wolfAnalytics.HandledInAppBillingPurchaseException(exception);
					Log.Error("InAppPurchase", "ERROR pulling currency code from store: IAP exception", exception);
					goto end_IL_0041;
				}
				catch (BillingNotSupportedException exception2)
				{
					wolfAnalytics.HandledInAppPurchaseException(exception2);
					Log.Error("InAppPurchase", "ERROR billing is not supported on this device.");
					goto end_IL_0041;
				}
				catch (Exception exception3)
				{
					wolfAnalytics.HandledInAppUnexpectedPurchaseException(exception3);
					Log.Error("InAppPurchase", "ERROR pulling currency code from store: Unknown", exception3);
					goto end_IL_0041;
				}
				num = 1;
				end_IL_0041:;
			}
			catch (object obj2)
			{
				obj = obj2;
			}
			if (connected)
			{
				if (!success)
				{
					await Task.Delay(1000);
				}
				await CloseConnection();
			}
			object obj3 = obj;
			if (obj3 != null)
			{
				if (!(obj3 is Exception source))
				{
					throw obj3;
				}
				ExceptionDispatchInfo.Capture(source).Throw();
			}
			if (num != 1)
			{
			}
		}

		public async Task<bool> MakePayment(IDictionary<string, string> obj, Action<string, string, bool> onBillingError, Func<InAppBillingPurchaseException, Task> onBillingPurchaseException)
		{
			Log.Trace("InAppPurchase", "IAP> Started");
			string sku;
			string paymentType;
			string kitOrItemId;
			try
			{
				sku = obj["membershipSku"];
				paymentType = obj["paymentType"];
				kitOrItemId = obj["kitOrItemId"];
			}
			catch (Exception ex)
			{
				Log.Fatal("InAppPurchase", "Error parsing web's MakePayment info.", ex);
				onBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_parsing_payment_error, string.Format("Error parsing payment info. obj was {0} Exception: {1}", (obj == null) ? "null" : JsonConvert.SerializeObject(obj), ex), arg3: false);
				return false;
			}
			try
			{
				Log.Trace("InAppPurchase", "IAP> Prompting the user to purchase");
				if (!(await MakePurchase(sku)))
				{
					onBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_incomplete, "IAP> Purchase returned a null value", arg3: true);
					return false;
				}
			}
			catch (InAppBillingPurchaseException ex2)
			{
				await onBillingPurchaseException(ex2);
				if (ex2.PurchaseError != PurchaseError.UserCancelled)
				{
					wolfAnalytics.HandledInAppBillingPurchaseException(ex2);
				}
				return false;
			}
			catch (SubscriptionActiveException ex3)
			{
				onBillingError(ex3.UserError, ex3.Message, arg3: false);
				wolfAnalytics.HandledInAppPurchaseException(ex3);
				return false;
			}
			catch (SubscriptionStatusException ex4)
			{
				onBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_incomplete, ex4.Message, arg3: false);
				wolfAnalytics.HandledInAppPurchaseException(ex4);
				return false;
			}
			catch (Exception ex5)
			{
				onBillingError(Wolf.Core.Resources.AppStrings.onboarding_payment_incomplete, $"Error purchasing subscription: {ex5}", arg3: false);
				wolfAnalytics.HandledInAppBillingPurchaseException(ex5);
				return false;
			}
			Log.Trace("InAppPurchase", "IAP> Purchase was successful");
			wolfAnalytics.SuccessfulInAppPurchase(obj);
			await ProcessPurchase(paymentType, kitOrItemId);
			return true;
		}
	}
