		public void AddMarker(string id, iFit.Api.Google.LatLng point, byte[] icon)
		{
			if (webViewLoaded)
			{
				string value = JsonConvert.SerializeObject(point, settings);
				StringBuilder stringBuilder = new StringBuilder();
				foreach (byte value2 in icon)
