namespace Wolf.Core.Services.FitProBytesLog
{
	public class FitProBytesLogEnabledByFeatureFlag : IFitProBytesLogger
	{
		private readonly FeatureFlag featureFlag;

		private readonly IFitProBytesLogger logger;

		private readonly ConcurrentQueue<(PacketType packetType, byte[] bytes)> bytesToLog;

		private IFeatureFlagManager _featureFlagManager;

		private bool Enabled => FeatureFlagManager?.IsFeatureEnabled(featureFlag) ?? false;

		private IFeatureFlagManager FeatureFlagManager
		{
			get
			{
				_featureFlagManager = _featureFlagManager ?? GetFeatureFlagManager();
				return _featureFlagManager;
			}
		}

		private IFeatureFlagManager GetFeatureFlagManager()
		{
			if (!Mvx.TryResolve<IFeatureFlagManager>(out var service))
			{
				return null;
			}
			return service;
		}

		public FitProBytesLogEnabledByFeatureFlag(FeatureFlag featureFlag, IFitProBytesLogger logger)
		{
			this.featureFlag = featureFlag;
			this.logger = logger;
			bytesToLog = new ConcurrentQueue<(PacketType, byte[])>();
		}

		public void LogBytes(byte[] bytes, PacketType packetType)
		{
			bytesToLog.Enqueue((packetType, bytes));
			TryLogBytes();
		}

		private void TryLogBytes()
		{
			if (FeatureFlagManager != null && !Enabled)
			{
				bytesToLog.Clear();
			}
			else
			{
				if (!Enabled)
				{
					return;
				}
				List<(PacketType, byte[])> list = new List<(PacketType, byte[])>();
				(PacketType, byte[]) result;
				while (!bytesToLog.IsEmpty && bytesToLog.TryDequeue(out result))
				{
					try
					{
						logger.LogBytes(result.Item2, result.Item1);
					}
					catch (Exception ex)
					{
						list.Add(result);
						string text = "Failed to log bytes, enqueue to the end of queue" + Environment.NewLine + ex.Message;
						Log.Error("FitProBytesLogEnabledByFeatureFlag", text, ex);
					}
				}
				foreach (var item in list)
				{
					bytesToLog.Enqueue(item);
				}
			}
		}
	}
	public class FitProBytesLogFileServiceDestination : IFitProBytesLogDestination
	{
		private readonly ILogFileService logFileService;

		public FitProBytesLogFileServiceDestination(ILogFileService logFileService)
		{
			this.logFileService = logFileService;
		}

		public void Append(string log)
		{
			logFileService.WriteTextToFile("FitProBytes.txt", log);
		}
	}
	public class FitProBytesLogger : IFitProBytesLogger
	{
		private readonly IFitProBytesLogDestination destination;

		private readonly IDictionary<PacketType, string> delimiters = new Dictionary<PacketType, string>
		{
			{
				PacketType.Request,
				"+"
			},
			{
				PacketType.Response,
				"#"
			}
		};

		public FitProBytesLogger(IFitProBytesLogDestination destination)
		{
			this.destination = destination;
		}

		public void LogBytes(byte[] bytes, PacketType packetType)
		{
			if (bytes.IsValid())
			{
				string text = BitConverter.ToString(bytes);
				string text2 = DateTime.Now.ToString("MM/dd HH:mm:ss.fff");
				string text3 = delimiters[packetType];
				string log = "[" + text2 + "] " + text3 + text + text3;
				destination.Append(log);
			}
		}
	}
	public static class FitProBytesLoggerFactory
	{
		public static IFitProBytesLogger Create(ILogFileService logFileService)
		{
			return null;
		}
	}
	public interface IFitProBytesLogDestination
	{
		void Append(string log);
	}
}
namespace Wolf.Core.Services.File
{
	public interface IApplicationFileService
	{
		void Clear();
	}
	public interface IStorageSpaceCleanupMonitor
	{
		Task CleanupStorage(DiskSpaceEvent diskSpaceEvent);
	}
	public class StorageSpaceCleanupMonitor : IStorageSpaceCleanupMonitor
	{
		private const string LogTag = "DiskSpace";

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly IDeviceInformation deviceInformation;

		private readonly ISystemResources systemResources;

		private readonly StorageSpaceMonitor storageSpaceMonitor;

		private readonly IBlobCacheService blobCacheService;

		private readonly IFatalityService fatalityService;

		private readonly ICoreAnalytics analytics;

		public StorageSpaceCleanupMonitor(IFeatureFlagManager featureFlagManager, IDeviceInformation deviceInformation, ISystemResources systemResources, StorageSpaceMonitor storageSpaceMonitor, IBlobCacheService blobCacheService, IFatalityService fatalityService, ICoreAnalytics analytics)
		{
			this.featureFlagManager = featureFlagManager;
			this.deviceInformation = deviceInformation;
			this.systemResources = systemResources;
			this.storageSpaceMonitor = storageSpaceMonitor;
			this.blobCacheService = blobCacheService;
			this.fatalityService = fatalityService;
			this.analytics = analytics;
			this.storageSpaceMonitor.LowDiskSpaceEvent += CleanupStorage;
		}

		public async Task CleanupStorage(DiskSpaceEvent diskSpaceEvent)
		{
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.StorageSpaceCleanupEnabled))
			{
				Log.Trace("DiskSpace", "Storage monitor reclaiming storage space.");
				try
				{
					await CacheUtil.WipeEntireCacheAsync(blobCacheService.LocalMachine, handleExceptions: false);
				}
				catch (Exception exception)
				{
					Log.Error("DeviceAdmin", "Wiping LocalMachine Cache failed", exception);
					string displayMessage = ((deviceInformation?.IsBuiltIn ?? false) ? Shire.Core.Resources.AppStrings.database_malformed_error : Wolf.Core.Resources.AppStrings.fatal_please_restart);
					fatalityService.ReportFatalEvent(exception, displayMessage, isPermanent: true);
					return;
				}
				diskSpaceEvent.AddPostCleanupData(systemResources.ExternalFreeDiskSpace, systemResources.InternalFreeDiskSpace, systemResources.ExternalPercentFreeDiskSpace, systemResources.InternalPercentFreeDiskSpace);
			}
			try
			{
				await analytics.LowDiskSpace(diskSpaceEvent);
			}
			catch (Exception exception2)
			{
				Log.Error("DeviceAdmin", "Failed to report disk cleanup results to Segment", exception2);
			}
		}
	}
}
namespace Wolf.Core.Services.FanVolume
{
	public interface IFanVolumeHandler : IDisposable
	{
		IObservable<FanVolumeUpdate> WhenFanOrVolumeChange { get; }
	}
	public class FanVolumeHandler : IFanVolumeHandler, IDisposable
	{
		private const int MaxSemaphoreCount = 1;

		private readonly ILocalSettings localSettings;

		private readonly IReadWriteFacadeFactoryDependencies facadeFactoryDependencies;

		private readonly IMvxMainThreadDispatcher dispatch;

		private readonly IDeviceInformation deviceInformation;

		private readonly IWorkoutSettings workoutSettings;

		private SemaphoreSlim semaphoreSlim = new SemaphoreSlim(1, 1);

		private IDisposable volumeChangeSub;

		private IDisposable fanChangeSub;

		private IDisposable consoleSub;

		private Subject<FanVolumeUpdate> _whenFanOrVolumeChange = new Subject<FanVolumeUpdate>();

		public IObservable<FanVolumeUpdate> WhenFanOrVolumeChange => _whenFanOrVolumeChange?.AsObservable();

		public FanVolumeHandler(ILocalSettings localSettings, IMvxMainThreadDispatcher dispatch, IDeviceInformation deviceInformation, ICurrentConsoleService currentConsoleService, IWorkoutSettings workoutSettings, IReadWriteFacadeFactoryDependencies facadeFactoryDependencies)
		{
			this.localSettings = localSettings;
			this.dispatch = dispatch;
			this.deviceInformation = deviceInformation;
			this.workoutSettings = workoutSettings;
			this.facadeFactoryDependencies = facadeFactoryDependencies;
			consoleSub = currentConsoleService.WhenConsoleChanged.SubscribeWithErrorLogging(ConsoleChanged);
			ConsoleChanged(currentConsoleService?.ActiveConsole);
		}

		public virtual void ConsoleChanged(IFitnessConsole console)
		{
			DisposePeriodicSubs();
			if (console is IEquipmentlessConsole)
			{
				return;
			}
			volumeChangeSub = (from x in facadeFactoryDependencies.VolumeFacade.ObserveVolumeChanges().Where((Func<FitnessValueChange<int>, bool>)delegate
				{
					IWorkoutContainer workoutContainer = workoutSettings.WorkoutContainer;
					if (workoutContainer == null || !workoutContainer.Workout.IsVideoWorkout())
					{
						IWorkoutContainer workoutContainer2 = workoutSettings.WorkoutContainer;
						if (workoutContainer2 == null)
						{
							return true;
						}
						return workoutContainer2.Workout?.IsGoogleMap != true;
					}
					return false;
				})
				select x.Current).SubscribeWithErrorLogging(SendVolumeUpdate);
			fanChangeSub = (from x in facadeFactoryDependencies.FanStateFacade.ObserveFanStateChanges()
				where x.Current != FanState.Unknown
				select x.Current).SubscribeWithErrorLogging(SendFanUpdate);
		}

		private void DisposePeriodicSubs()
		{
			volumeChangeSub?.Dispose();
			volumeChangeSub = null;
			fanChangeSub?.Dispose();
			fanChangeSub = null;
		}

		private void SendVolumeUpdate(int volume)
		{
			SendUpdate(new FanVolumeUpdate(volume));
		}

		private void SendFanUpdate(FanState newState)
		{
			SendUpdate(new FanVolumeUpdate(newState));
		}

		private void SendUpdate(FanVolumeUpdate update)
		{
			semaphoreSlim?.Wait();
			_whenFanOrVolumeChange?.OnNext(update);
			if (deviceInformation.IsBuiltIn && Mvx.TryResolve<IDialogPresenter>(out var presenter))
			{
				dispatch.RequestMainThreadAction(delegate
				{
					presenter.ShowDialog<FanVolumeDialogViewModel>(null, showSafely: true, update);
				});
			}
			semaphoreSlim?.Release();
		}

		public void Dispose()
		{
			DisposePeriodicSubs();
			consoleSub?.Dispose();
			consoleSub = null;
			if ((semaphoreSlim?.CurrentCount ?? 0) < 1)
			{
				semaphoreSlim?.Release();
			}
			semaphoreSlim?.Dispose();
			semaphoreSlim = null;
			_whenFanOrVolumeChange?.Dispose();
			_whenFanOrVolumeChange = null;
		}
	}
	public class FanVolumeUpdate
	{
		public bool IsFanUpdate { get; set; }

