namespace Wolf.Core.Services.Dashboard
{
	public interface INoWifiDashboardService : IDisposable
	{
		IObservable<string> WhenAttemptingToConnect { get; }

		IObservable<string> WhenSuccessfullyConnected { get; }

		IObservable<string> WhenFailedToConnect { get; }

		void ResetState();

		Task TryAgain();
	}
	public class NoWifiDashboardService : INoWifiDashboardService, IDisposable
	{
		public TimeSpan FeatureFlagSyncTimeout = TimeSpan.FromSeconds(15.0);

		private Subject<string> attemptingToConnect = new Subject<string>();

		private Subject<string> successfullyConnected = new Subject<string>();

		private Subject<string> failedToConnect = new Subject<string>();

		private readonly IConnectivity connectivity;

		private readonly INeedsRefreshService needsRefreshService;

		private readonly IIfitApiService ifitApi;

		private readonly IWebviewHolderFactory webviewHolderFactory;

		private bool isAttemptingToConnect;

		private IDisposable gainedInternetSub;

		private IDisposable urlFlagsUpdatedSub;

		public IObservable<string> WhenAttemptingToConnect => attemptingToConnect;

		public IObservable<string> WhenSuccessfullyConnected => successfullyConnected;

		public IObservable<string> WhenFailedToConnect => failedToConnect;

		public NoWifiDashboardService(IConnectivity connectivity, INeedsRefreshService needsRefreshService, IIfitApiService ifitApi, IWebviewHolderFactory webviewHolderFactory)
		{
			this.connectivity = connectivity;
			this.needsRefreshService = needsRefreshService;
			this.ifitApi = ifitApi;
			this.webviewHolderFactory = webviewHolderFactory;
			SetupGainedInternetSub();
		}

		private void SetupGainedInternetSub()
		{
			gainedInternetSub?.Dispose();
			gainedInternetSub = needsRefreshService.WhenNeedsRefresh.Where((IRefreshPayload payload) => payload.Cause == RefreshCause.GainedInternet).SubscribeAsyncWithErrorLogging(async delegate
			{
				await OnInternetGained();
			});
		}

		public void ResetState()
		{
			isAttemptingToConnect = false;
		}

		public async Task TryAgain()
		{
			if (!isAttemptingToConnect)
			{
				if (!connectivity.IsConnected)
				{
					failedToConnect?.OnNext(Wolf.Core.Resources.AppStrings.unable_to_connect);
				}
				else
				{
					await OnInternetGained().ConfigureAwait(continueOnCapturedContext: false);
				}
			}
		}

		private async Task OnInternetGained()
		{
			if (isAttemptingToConnect)
			{
				return;
			}
			try
			{
				isAttemptingToConnect = true;
				attemptingToConnect?.OnNext(Wolf.Core.Resources.AppStrings.attempting_to_reconnect);
				if (Mvx.TryResolve<ILockScreenHandler>(out var service) && service != null && service.LockWhenFinishProcess)
				{
					service.LockWhenFinishProcess = false;
					service.NavigateToLockScreen();
				}
				else
				{
					string text = null;
					if (Mvx.TryResolve<IFeatureFlagManager>(out var service2))
					{
						text = MainToolbarViewModel.GetWallEUrlWhenNeed(service2, FeatureFlags.WallEDashboardUrl, FeatureFlags.WolfDashboardWebviewUrl);
					}
					if (text.IsNullOrEmpty())
					{
						webviewHolderFactory.WebviewHolderStore.FlushAll();
					}
					else
					{
						webviewHolderFactory.WebviewHolderStore.FlushAllExcluding(text);
					}
				}
				bool flag = !ifitApi.HasLoggedInUser;
				bool flag2 = flag;
				if (!flag2)
				{
					flag2 = await User.FetchMe(ifitApi) != null;
				}
				if (flag2)
				{
					successfullyConnected?.OnNext(string.Empty);
					return;
				}
				failedToConnect?.OnNext(Wolf.Core.Resources.AppStrings.unable_to_connect);
				isAttemptingToConnect = false;
			}
			catch
			{
				isAttemptingToConnect = false;
				throw;
			}
		}

		public void Dispose()
		{
			gainedInternetSub?.Dispose();
			gainedInternetSub = null;
			attemptingToConnect?.OnCompleted();
			attemptingToConnect?.Dispose();
			attemptingToConnect = null;
			successfullyConnected?.OnCompleted();
			successfullyConnected?.Dispose();
			successfullyConnected = null;
			failedToConnect?.OnCompleted();
			failedToConnect?.Dispose();
			failedToConnect = null;
			urlFlagsUpdatedSub?.Dispose();
			urlFlagsUpdatedSub = null;
		}
	}
}
