namespace Wolf.Core.Services.Configuration
{
	public abstract class ConfigurationFileServiceBase<TConfigData> : IConfigurationFileService<TConfigData> where TConfigData : class
	{
		protected const string StorageDirectoryName = ".wolfConfig";

		protected const string ActiveDirectoryName = ".activeConfig";

		protected const string DisabledFileSuffix = ".disabled";

		protected abstract string LogTag { get; }

		protected abstract string MainAppStoragePath { get; }

		protected abstract string ActiveConfigFileName { get; }

		public abstract TConfigData DefaultConfig { get; }

		protected string StorageDirectoryPath => CombinePaths(MainAppStoragePath, ".wolfConfig");

		protected string ActiveDirectoryPath => CombinePaths(MainAppStoragePath, ".activeConfig");

		protected string ActiveConfigFilePath => CombinePaths(ActiveDirectoryPath, ActiveConfigFileName);

		protected string DisabledConfigFileName => ActiveConfigFileName + ".disabled";

		protected string DisabledConfigFilePath => CombinePaths(ActiveDirectoryPath, DisabledConfigFileName);

		public TConfigData CurrentActiveConfig { get; private set; }

		public bool IsConfigDisabled => DoesFileExist(DisabledConfigFilePath);

		public void PrepareActiveDirectory(bool enableConfig = true)
		{
			if (!DoesDirectoryExist(ActiveDirectoryPath))
			{
				Log.Trace(LogTag, "Creating new active directory for " + GetType().Name + " at: " + ActiveDirectoryPath);
				CreateDirectory(ActiveDirectoryPath);
			}
			if (enableConfig)
			{
				EnableConfig();
			}
		}

		public void DeleteActiveConfig()
		{
			DeleteFile(ActiveConfigFilePath);
			DeleteFile(DisabledConfigFilePath);
		}

		public void DisableConfig()
		{
			if (IsConfigDisabled)
			{
				Log.Trace(LogTag, "Disabled config file already exists: " + DisabledConfigFilePath);
				RefreshCurrentConfigFromActiveFile();
			}
			else if (DoesFileExist(ActiveConfigFilePath))
			{
				Log.Trace(LogTag, "Disabling configuration, moving from " + ActiveConfigFilePath + " to " + DisabledConfigFilePath + ".");
				MoveFile(ActiveConfigFilePath, DisabledConfigFilePath);
				RefreshCurrentConfigFromActiveFile();
			}
			else
			{
				Log.Trace(LogTag, "No active configuration found at: " + ActiveConfigFilePath + ".");
				RefreshCurrentConfigFromActiveFile();
			}
		}

		public void EnableConfig(bool copyFromStorageIfRequired = true, bool createDefaultsIfFileDoesNotExist = false)
		{
			if (IsConfigDisabled)
			{
				if (DoesFileExist(ActiveConfigFilePath))
				{
					Log.Trace(LogTag, "Active and disabled config files already exist. Deleting inactive one...");
					DeleteFile(DisabledConfigFilePath);
					RefreshCurrentConfigFromActiveFile();
					return;
				}
				Log.Trace(LogTag, "Enabling existing active config at " + DisabledConfigFilePath + ", moving to " + ActiveConfigFilePath + "...");
				MoveFile(DisabledConfigFilePath, ActiveConfigFilePath);
				RefreshCurrentConfigFromActiveFile();
				return;
			}
			if (DoesFileExist(ActiveConfigFilePath))
			{
				Log.Trace(LogTag, "Active config file already exists at: " + ActiveConfigFilePath);
				RefreshCurrentConfigFromActiveFile();
				return;
			}
			string storedConfigFilePathOrDefault = GetStoredConfigFilePathOrDefault();
			if (copyFromStorageIfRequired && !string.IsNullOrWhiteSpace(storedConfigFilePathOrDefault))
			{
				Log.Trace(LogTag, "Stored config file found at: " + storedConfigFilePathOrDefault + ", copying to active location...");
				try
				{
					CopyFile(storedConfigFilePathOrDefault, ActiveConfigFilePath);
				}
				catch (Exception exception)
				{
					Log.Error(LogTag, "Error copying stored file at: " + storedConfigFilePathOrDefault + " to new file: " + ActiveConfigFilePath, exception);
				}
				RefreshCurrentConfigFromActiveFile();
			}
			else if (createDefaultsIfFileDoesNotExist && string.IsNullOrWhiteSpace(storedConfigFilePathOrDefault))
			{
				Log.Trace(LogTag, "No stored config file found at: " + storedConfigFilePathOrDefault + ", creating default config...");
				try
				{
					WriteAllFileContent(ActiveConfigFilePath, SerializeContent(DefaultConfig));
				}
				catch (Exception exception2)
				{
					Log.Error(LogTag, $"Error writing default config to new active file at: {ActiveConfigFilePath} with default content: {DefaultConfig}", exception2);
				}
				RefreshCurrentConfigFromActiveFile();
			}
			else
			{
				RefreshCurrentConfigFromActiveFile();
			}
		}

		public void RefreshCurrentConfigFromActiveFile(TConfigData defaultResult = null)
		{
			try
			{
				if (DoesFileExist(ActiveConfigFilePath))
				{
					if (TryParseConfigFile(ReadAllFileContent(ActiveConfigFilePath), out var configData))
					{
						CurrentActiveConfig = configData;
						Log.Trace(LogTag, "Current " + GetType().Name + " configuration updated: " + (CurrentActiveConfig?.ToString() ?? "<null>"));
						return;
					}
					Log.Error(LogTag, "Could not parse the current config from: " + (ActiveConfigFilePath ?? "<null>"));
				}
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error occurred trying to refresh the current config from: " + (ActiveConfigFilePath ?? "<null>"), exception);
			}
			CurrentActiveConfig = defaultResult;
		}

		protected bool TryParseConfigFile(string fileContent, out TConfigData configData)
		{
			if (string.IsNullOrWhiteSpace(fileContent))
			{
				configData = null;
				return false;
			}
			try
			{
				configData = DeserializeContent(fileContent);
				return configData != null;
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error while parsing configuration file.", exception);
			}
			configData = null;
			return false;
		}

		protected virtual TConfigData DeserializeContent(string serialized, TConfigData errorResult = null)
		{
			if (string.IsNullOrWhiteSpace(serialized))
			{
				return errorResult;
			}
			try
			{
				return JsonConvert.DeserializeObject<TConfigData>(serialized);
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Could not deserialize config data: " + serialized, exception);
				return errorResult;
			}
		}

		public bool StoredOrActiveConfigFileExists()
		{
			try
			{
				return DoesFileExist(ActiveConfigFilePath) || GetStoredConfigFilePathOrDefault() != null;
			}
			catch (Exception exception)
			{
				Log.Error(LogTag, "Error checking " + GetType().Name + " StoredOrActiveConfigFileExists.", exception);
			}
			return false;
		}

		protected virtual string SerializeContent(TConfigData config)
		{
			return JsonConvert.SerializeObject(config);
		}

		protected abstract string ReadAllFileContent(string filePath);

		protected abstract void WriteAllFileContent(string filePath, string content);

		protected abstract bool DoesFileExist(string filePath);

		protected abstract bool DoesDirectoryExist(string folderPath);

		protected abstract string CombinePaths(params string[] paths);

		protected abstract void DeleteFile(string filePath);

		protected abstract void DeleteDirectory(string folderPath);

		protected abstract void CreateDirectory(string folderPath);

		protected abstract void CopyFile(string originalPath, string copiedPath);

		protected abstract void MoveFile(string currentPath, string newPath);

		protected abstract string GetStoredConfigFilePathOrDefault(string defaultResult = null);
	}
	public interface IConfigurationFileService<TConfigData> where TConfigData : class
	{
		TConfigData DefaultConfig { get; }

		TConfigData CurrentActiveConfig { get; }

		bool IsConfigDisabled { get; }

		void PrepareActiveDirectory(bool enableConfig = true);

		void DeleteActiveConfig();

		void DisableConfig();

		void EnableConfig(bool copyFromStorageIfRequired = true, bool createDefaultsIfFileDoesNotExist = false);

		void RefreshCurrentConfigFromActiveFile(TConfigData defaultResult = null);

		bool StoredOrActiveConfigFileExists();
	}
}
