		public InWorkoutChartDataProvider(IFitnessConsole console, IIfitApiService ifitApi, Workout workout, Workout.WorkoutContext workoutContext, IConsoleConfiguration configuration, ConsoleStateStats stats, double userWeightKgs, double userHeightMeters, double userAge, bool userMale, bool isMetric, IWorkoutRunner runner, ICaptionParser captionParser, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService)
		{
			InWorkoutChartDataProvider inWorkoutChartDataProvider = this;
			this.captionParser = captionParser;
			this.hrTrainingService = hrTrainingService;
			this.workoutFeatureService = workoutFeatureService;
			SupportsIncline.Value = console.ConsoleInfo.CanSetIncline;
			HasFixedIncline.Value = console.ConsoleInfo.MaxIncline > 0.0 && console.ConsoleInfo.MinIncline.AlmostEqual(console.ConsoleInfo.MaxIncline, 0.1);
			SupportsResistance.Value = console.ConsoleInfo.CanSetResistance;
			SupportsGear.Value = console.ConsoleInfo.CanSetGear;
			SupportsFiveHundredSplit.Value = console.ReadableTypes?.Contains(FitnessValue.FiveHundredSplit) ?? false;
			SupportsSpeed.Value = !Enumerable.Contains(consolesWithoutSpeed, console.ConsoleInfo.MachineType);
			XAxisFormatter = new WorkoutChartLabelUtil(workout.Target);
			targetValue = workout.TargetValue;
			runner.WhenScalingControlAdapterChanged.Subscribe(SetupScaleOwner);
			if (workout.IsManual())
			{
				IsManualWorkout = true;
				targetValue = TimeSpan.FromMinutes(40.0).TotalSeconds;
				EnableAddLabels.Value = true;
			}
			else if (workoutContext != Workout.WorkoutContext.OnDemand)
			{
				targetValue = TimeSpan.FromMinutes(40.0).TotalSeconds;
				EnableAddLabels.Value = true;
			}
			IsVideoWorkout = workout.IsVideoWorkout();
			chartDataProcessor = new ChartDataProcessor(workout, isMetric, console, userWeightKgs, userHeightMeters, userAge, userMale);
			this.ifitApi = ifitApi;
			Task.Run(async delegate
			{
				if (!inWorkoutChartDataProvider.IsManualWorkout)
				{
					await inWorkoutChartDataProvider.chartDataProcessor.ProcessControlsForTarget(workout.TargetValue);
				}
				inWorkoutChartDataProvider.PredictedDistance = (inWorkoutChartDataProvider.IsManualWorkout ? 16000.0 : inWorkoutChartDataProvider.chartDataProcessor.PredictedDistance);
				inWorkoutChartDataProvider.InitializeCurrentModels();
				inWorkoutChartDataProvider.InitializeMetricModels();
				inWorkoutChartDataProvider.InitializeLegendVisibility();
				inWorkoutChartDataProvider.InitializeInitialGroupDisabled();
				await inWorkoutChartDataProvider.ProcessMetricConfiguration(configuration.ChartGroups.Where((ChartGroupModel x) => x != null), console, workout, workoutContext, stats);
				await inWorkoutChartDataProvider.InitHRMetrics(console, workout, workoutContext, stats);
				inWorkoutChartDataProvider.DataInitialized.Value = true;
			});
		}

