		private void SetupScaleOwner(IScalingControlAdapter controlAdapter)
		{
			ChartMetricModel[] metricModels = MetricModels;
			for (int i = 0; i < metricModels.Length; i++)
			{
				ChartDataProvider chartDataProvider = metricModels[i]?.DataProvider;
				if (chartDataProvider != null && chartDataProvider is PredictedChartDataProviderBase predictedChartDataProviderBase)
				{
					predictedChartDataProviderBase.ControlAdapter = controlAdapter;
				}
			}
		}

		private async Task ProcessMetricConfiguration(IEnumerable<ChartGroupModel> groups, IFitnessConsole console, Workout workout, Workout.WorkoutContext workoutContext, ConsoleStateStats stats)
		{
			int metricIndex = 0;
			int currentIndex = 0;
			foreach (ChartGroupModel chartGroup in groups)
			{
				Groups.Add(chartGroup);
				SetLegendVisibility(chartGroup);
				chartGroup.GroupEnabled.Value = true;
				foreach (ChartMetricConfiguration metric in chartGroup.Lines)
				{
					INC<bool> safe = MetricEnabledList.GetSafe(metricIndex);
					if (safe != null)
					{
						safe.Value = true;
						chartGroup.RegisterDependentVisibility(safe);
						ChartDataProvider chartDataProvider = await GetProviderFromConfig(console, workout, workoutContext, stats, metric);
						MetricModels[metricIndex] = new ChartMetricModel
						{
							DataProvider = chartDataProvider,
							ChartData = GetChartDataFromProvider(chartDataProvider),
							DataConfig = metric
						};
						if (metric.ShowCurrentValue)
						{
							_ = currentIndex;
							CurrentMetrics[currentIndex] = MetricModels[metricIndex];
							INC<Tuple<double, double>> currentVal = CurrentList[currentIndex];
							INC<bool> showCurrent = CurrentEnabledList[currentIndex];
							RegisterCurrentValueHandlers(MetricModels[metricIndex], chartGroup, currentVal, showCurrent);
							currentIndex++;
						}
						metricIndex++;
					}
				}
			}
		}

