				};
				Dictionary<Theme, JsonConsoleConfigurationModel.ThemeColorModel> dictionary = new Dictionary<Theme, JsonConsoleConfigurationModel.ThemeColorModel>
				{
					{
						Theme.Light,
						value2
					},
					{
						Theme.Dark,
						value2
					},
					{
						Theme.StrengthMirror,
						value2
					},
					{
						Theme.Rainbow,
						value2
					}
				};
				PredictedHRGroup = new ChartGroupModel(ChartGroupType.PredictedHR, dictionary, displayLegend: true, leftAxis: true)
				{
					GroupColor = dictionary
				};
				HRPredictedModelEnabled.Value = true;
				PredictedHRGroup.RegisterDependentVisibility(HRPredictedModelEnabled);
				SetLegendVisibility(PredictedHRGroup);
			}
		}

		private void SetLegendVisibility(ChartGroupModel groupModel)
		{
			if (LegendVisibility.ContainsKey(groupModel.GroupType.ToString()))
			{
				LegendVisibility[groupModel.GroupType.ToString()].Value = true;
			}
			groupModel.RegisterLegendVisibility(LegendVisibility);
		}

		private void RegisterCurrentValueHandlers(ChartMetricModel metricModel, ChartGroupModel group, INC<Tuple<double, double>> currentVal, INC<bool> showCurrent)
		{
			CurrentSubscriptions.Add(metricModel.ChartData.ObservableEvent().Subscribe(delegate
			{
				currentVal.Value = metricModel.DataProvider.ProviderData.Last();
			}));
			group?.RegisterDependentVisibility(showCurrent);
			showCurrent.Value = true;
		}

