		protected async Task<ChartDataProvider> GetProviderFromConfig(IFitnessConsole console, Workout workout, Workout.WorkoutContext workoutContext, ConsoleStateStats stats, ChartMetricConfiguration config)
		{
			bool flag = workoutContext == Workout.WorkoutContext.OnDemand;
			ChartDataProvider provider;
			switch (config.Metric)
			{
			case ChartMetricConfiguration.MetricType.PredictedSpeed:
				provider = new PredictedSpeedChartDataProvider(console, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.PredictedIncline:
				provider = new PredictedInclineChartDataProvider(console, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.PredictedElevation:
				provider = new PredictedVerticalNetChartDataProvider(console, chartDataProcessor.PredictedElevationProfile, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.PredictedResistance:
				provider = new PredictedResistanceChartDataProvider(console, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.PredictedGear:
				provider = new PredictedGearChartDataProvider(console, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.PredictedHeartRate:
				provider = new PredictedHeartRateChartDataProvider(console, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.PredictedWidgetHeartRate:
				provider = new PredictedSmoothHeartRateChartDataProvider(console, workout, config.Metric, workout.ToMetricChangeType());
				break;
			case ChartMetricConfiguration.MetricType.HeartRate:
				if (flag)
				{
					FitnessValue dataType3 = config.DataType;
					MetricStatList statsFromMetricType3 = GetStatsFromMetricType(console, stats, config.Metric);
					ChartMetricConfiguration.MetricType metric3 = config.Metric;
					FitnessValue metricKey2 = workout.ToMetricChangeType();
					provider = new HistoricalStatChartDataProvider(console, workout, dataType3, statsFromMetricType3, HistoricalStatChartDataProvider.DataType.Binned, metric3, HistoricalStatChartDataProvider.MaxTailingRangeType.Key, null, metricKey2, await GetHeartRateBinsForProvider());
				}
				else
				{
					FitnessValue dataType4 = config.DataType;
					MetricStatList statsFromMetricType4 = GetStatsFromMetricType(console, stats, config.Metric);
					ChartMetricConfiguration.MetricType metric4 = config.Metric;
					ICaptionParser obj2 = captionParser;
					FitnessValue metricKey = workout.ToMetricChangeType();
					provider = new LiveWorkoutChartDataProvider(console, workout, dataType4, statsFromMetricType4, HistoricalStatChartDataProvider.DataType.Binned, metric4, obj2, HistoricalStatChartDataProvider.MaxTailingRangeType.Key, null, metricKey);
				}
				break;
			default:
			{
				FitnessValue metricKey;
				if (flag)
				{
					FitnessValue dataType = config.DataType;
					MetricStatList statsFromMetricType = GetStatsFromMetricType(console, stats, config.Metric);
					ChartMetricConfiguration.MetricType metric = config.Metric;
					metricKey = workout.ToMetricChangeType();
					return new HistoricalStatChartDataProvider(console, workout, dataType, statsFromMetricType, HistoricalStatChartDataProvider.DataType.Raw, metric, HistoricalStatChartDataProvider.MaxTailingRangeType.Key, null, metricKey);
				}
				FitnessValue dataType2 = config.DataType;
				MetricStatList statsFromMetricType2 = GetStatsFromMetricType(console, stats, config.Metric);
				ChartMetricConfiguration.MetricType metric2 = config.Metric;
				ICaptionParser obj = captionParser;
				metricKey = workout.ToMetricChangeType();
				return new LiveWorkoutChartDataProvider(console, workout, dataType2, statsFromMetricType2, HistoricalStatChartDataProvider.DataType.Raw, metric2, obj, HistoricalStatChartDataProvider.MaxTailingRangeType.Key, null, metricKey);
			}
			}
			if (provider is PredictedChartDataProviderBase predictedChartDataProviderBase)
			{
				await predictedChartDataProviderBase.InitAsync();
			}
			return provider;
		}

		private MetricStatList GetStatsFromMetricType(IFitnessConsole console, ConsoleStateStats stats, ChartMetricConfiguration.MetricType type)
		{
			if (stats?.RunningStats == null)
			{
				Log.Trace("Charting", "GetStatsFromMetricType: Stats was null, returning null");
				return null;
			}
			switch (type)
			{
			case ChartMetricConfiguration.MetricType.Speed:
				if (console != null && console.ConsoleInfo?.MachineType.IsBeltBasedMachine() == true)
				{
					return stats.RunningStats.KphChanges;
				}
				return stats.RunningStats.ActualKphChanges;
			case ChartMetricConfiguration.MetricType.Incline:
				return stats.RunningStats.GradeChanges;
			case ChartMetricConfiguration.MetricType.Elevation:
				return stats.RunningStats.VerticalMetersNetChanges;
			case ChartMetricConfiguration.MetricType.HeartRate:
				return stats.RunningStats.PulseChanges;
			case ChartMetricConfiguration.MetricType.Rpm:
				return stats.RunningStats.RpmChanges;
			case ChartMetricConfiguration.MetricType.Resistance:
				return stats.RunningStats.ResistanceChanges;
			case ChartMetricConfiguration.MetricType.Gear:
				return stats.RunningStats.GearChanges;
			case ChartMetricConfiguration.MetricType.FiveHundredSplit:
				return stats.RunningStats.FiveHundredSplitDecimalChanges;
			default:
				throw new ArgumentException($"InWorkoutChartProvider stats not found for metric type {type}");
			}
		}

		protected ChartDataCollection GetChartDataFromProvider(ChartDataProvider provider)
		{
			if (provider is HistoricalStatChartDataProvider historicalStatChartDataProvider)
			{
				if (!historicalStatChartDataProvider.IsDataBinned)
				{
					return historicalStatChartDataProvider.ProviderData;
				}
				return historicalStatChartDataProvider.BinnedData;
			}
			return provider.ProviderData;
		}

		public void Dispose()
		{
			foreach (IDisposable currentSubscription in CurrentSubscriptions)
			{
				currentSubscription?.Dispose();
			}
			foreach (ChartGroupModel group in Groups)
			{
				group.Clear();
			}
			Groups.Clear();
			ChartMetricModel[] metricModels = MetricModels;
			for (int i = 0; i < metricModels.Length; i++)
			{
				metricModels[i]?.DataProvider?.Dispose();
			}
			HRPredictedModel?.DataProvider?.Dispose();
			HRWidgetPredictedModel?.DataProvider?.Dispose();
			chartDataProcessor?.Dispose();
		}

		private async Task<List<Tuple<double, double>>> GetHeartRateBinsForProvider()
		{
			UserHeartRateSettings userHRSettings;
			try
			{
				userHRSettings = await (await User.GetMe(ifitApi)).GetHeartRateSettings(ifitApi, force: true);
			}
			catch (Exception exception)
			{
				Log.Error("InWorkoutChartDataProvider", "Failed to set up HR zones for charting", exception);
				userHRSettings = await hrTrainingService.CalculateDefaultHRSettings();
			}
			userHRSettings?.Zones?.Sort((UserHeartRateZone x, UserHeartRateZone y) => x.MinBpm.CompareTo(y.MinBpm));
			return userHRSettings?.Zones?.Select((UserHeartRateZone z) => new Tuple<double, double>(z.MinBpm, z.MaxBpm)).ToList();
		}
	}
	public class WorkoutChartLabelUtil : ChartLabelUtil
	{
		private Workout.TargetType targetType { get; set; }

		public WorkoutChartLabelUtil(Workout.TargetType targetType)
		{
			this.targetType = targetType;
		}

		public override string GetMileLabelForIndex(long i)
		{
			return string.Format(Wolf.Core.Resources.AppStrings.chart_miles, base.GetMileLabelForIndex(i));
		}

		public override string GetCalorieLabelForIndex(long i)
		{
			return string.Format(Wolf.Core.Resources.AppStrings.chart_calories, base.GetCalorieLabelForIndex(i));
		}

		public override string GetKmLabelForIndex(long i)
		{
			return string.Format(Wolf.Core.Resources.AppStrings.chart_km, base.GetKmLabelForIndex(i));
		}

		public override string ResolveLabel(long i, bool isMetric = true)
		{
			switch (targetType)
			{
			case Workout.TargetType.Calories:
				return GetCalorieLabelForIndex(i);
			case Workout.TargetType.Seconds:
				return GetTimeLabelForIndex(i);
			default:
				if (!isMetric)
				{
					return GetMileLabelForIndex(i);
				}
				return GetKmLabelForIndex(i);
			}
		}
	}
