namespace Wolf.Core.Services.BleOnboarding
{
	public interface IBleOnboardingConnectingService
	{
		IBleDevice CurrentDevice { get; }

		Task<IBleDevice> Connect(IBleDevice device, CancellationToken token);

		Task Disconnect();

		string GetCurrentConsoleType();
	}
	public class BleOnboardingConnectingService : IBleOnboardingConnectingService
	{
		private const int DefaultConnectionTimeoutSeconds = 60;

		private readonly ILocalSettings localSettings;

		private readonly IBleConsoleService bleConsoleService;

		private readonly IBleTcpConnectionService bleTcpConnectionService;

		public double TimeoutMilliseconds { get; set; } = 60000.0;

		public IBleDevice CurrentDevice => bleConsoleService?.CurrentDevice;

		public BleOnboardingConnectingService(ILocalSettings localSettings, IBleConsoleService bleConsoleService, IBleTcpConnectionService bleTcpConnectionService)
		{
			this.localSettings = localSettings;
			this.bleConsoleService = bleConsoleService;
			this.bleTcpConnectionService = bleTcpConnectionService;
		}

		public async Task<IBleDevice> Connect(IBleDevice device, CancellationToken token)
		{
			if (bleConsoleService.CurrentDevice == device && bleConsoleService.ConnectionState == ConsoleConnectionState.Connected)
			{
				return device;
			}
			if (device is TcpDevice tcpDevice && bleTcpConnectionService != null && !(await bleTcpConnectionService.PromptForVirtualConsoleAddress(tcpDevice)))
			{
				throw new BleOnboardingConnectFailedException("Couldn't retrieve valid IP for TCP device");
			}
			try
			{
				await bleConsoleService.Connect(device, 60).ConfigureAwait(continueOnCapturedContext: false);
				if ((await WaitForConnected(token).ConfigureAwait(continueOnCapturedContext: false) == ConsoleConnectionState.Connected) & await WaitForConsoleInitialized(token).ConfigureAwait(continueOnCapturedContext: false))
				{
					Log.Trace("Ble", "Device connected, successful connection.");
					return bleConsoleService.CurrentDevice;
				}
			}
			catch (OperationCanceledException)
			{
				throw;
			}
			catch (Exception ex2)
			{
				Log.Error("Ble", "Error connecting to BLE device: ", ex2);
				throw new BleOnboardingConnectFailedException("Error connecting to BLE device: " + ex2.Message);
			}
			throw new BleOnboardingConnectFailedException("Failed to connect to device");
		}

		public async Task Disconnect()
		{
			await bleConsoleService.Disconnect(forgetDevice: true).ConfigureAwait(continueOnCapturedContext: false);
		}

		public string GetCurrentConsoleType()
		{
			switch (bleConsoleService.Console?.ConsoleInfo?.MachineType)
			{
			case ConsoleType.Rower:
				return "rower";
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return "cycle";
			case ConsoleType.Treadmill:
			case ConsoleType.InclineTrainer:
				return "treadmill";
			case ConsoleType.Elliptical:
			case ConsoleType.VerticalElliptical:
				return "elliptical";
			case ConsoleType.Strider:
			case ConsoleType.FreeStrider:
				return "strider";
			default:
				return "none";
			}
		}

		private async Task<ConsoleConnectionState> WaitForConnected(CancellationToken token)
		{
			if (bleConsoleService.ConnectionState == ConsoleConnectionState.Connected)
			{
				return ConsoleConnectionState.Connected;
			}
			return await bleConsoleService.WhenConnectionStateChanged.Where((ConsoleConnectionState x) => x == ConsoleConnectionState.Connected).Timeout(TimeSpan.FromMilliseconds(TimeoutMilliseconds)).Take(1)
				.ToTask(token)
				.ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task<bool> WaitForConsoleInitialized(CancellationToken token)
		{
			if (bleConsoleService.IsConnectedToConsole && bleConsoleService.Console.Initialized)
			{
				return true;
			}
			try
			{
				await bleConsoleService.WhenConsoleInitialized.Timeout(TimeSpan.FromMilliseconds(TimeoutMilliseconds)).Take(1).ToTask(token)
					.ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (TimeoutException)
			{
				return false;
			}
			return true;
		}
	}
	public class BleOnboardingConnectFailedException : Exception
	{
		public BleOnboardingConnectFailedException(string message)
			: base(message)
		{
		}
	}
	public interface IBleOnboardingScanningService : IDisposable
	{
		bool IsNewPairing { get; set; }

		IObservable<List<IBleDevice>> WhenDeviceAdded { get; }

		IObservable<IBleDevice> WhenShouldConnectToDevice { get; }

		Task<IBleDevice> GetDeviceWithPairKey(string pairKey);

		Task ClearAndStartScan();

		Task StartScan();

		void StopScan();
	}
	public class BleOnboardingScanningService : IBleOnboardingScanningService, IDisposable
	{
		private readonly ILocalSettings localSettings;

		private readonly IBleConsoleService bleConsoleService;

		private readonly IDeveloperSettings developerSettings;

		private readonly IScanner scanner;

		private readonly SemaphoreSlim deviceCollectionSemaphore;

		private Subject<List<IBleDevice>> whenDeviceAdded = new Subject<List<IBleDevice>>();

		private Subject<IBleDevice> whenShouldConnectToDevice = new Subject<IBleDevice>();

		private IDisposable deviceFoundSub;

		public bool IsNewPairing { get; set; }

		public ImprovedObservableCollection<IBleDevice> Devices { get; }

		public IObservable<List<IBleDevice>> WhenDeviceAdded => whenDeviceAdded;

		public IObservable<IBleDevice> WhenShouldConnectToDevice => whenShouldConnectToDevice;

		public BleOnboardingScanningService(ILocalSettings localSettings, IBleConsoleService bleConsoleService, IScanner scanner, IDeveloperSettings developerSettings)
		{
			this.localSettings = localSettings;
			this.bleConsoleService = bleConsoleService;
			this.scanner = scanner;
			this.developerSettings = developerSettings;
			deviceCollectionSemaphore = new SemaphoreSlim(1);
			Devices = new ImprovedObservableCollection<IBleDevice>();
		}

		public async Task<IBleDevice> GetDeviceWithPairKey(string pairKey)
		{
			try
			{
				await deviceCollectionSemaphore.WaitAsync();
				return Devices?.FirstOrDefault((IBleDevice x) => x.PairKey == pairKey);
			}
			finally
			{
				deviceCollectionSemaphore.Release();
			}
		}

		public async Task ClearAndStartScan()
		{
			try
			{
				await deviceCollectionSemaphore.WaitAsync();
				Devices?.Clear();
			}
			finally
			{
				deviceCollectionSemaphore.Release();
			}
			await StartScan();
		}

		public async Task StartScan()
		{
			ConsoleConnectionState connectionState = bleConsoleService.ConnectionState;
			if (connectionState == ConsoleConnectionState.NotConnected)
			{
				Log.Trace("Ble", "Console state is not connected. Disconnecting from device " + bleConsoleService?.CurrentDevice?.PairKey);
				bleConsoleService.DisconnectImmediate(forgetDevice: true);
			}
			if (!IsNewPairing && (connectionState == ConsoleConnectionState.Connecting || connectionState == ConsoleConnectionState.Connected) && !(bleConsoleService.CurrentDevice is NonConnectedMockDevice))
			{
				whenShouldConnectToDevice.OnNext(bleConsoleService.CurrentDevice);
				return;
			}
			if (bleConsoleService.CurrentDevice != null && !(bleConsoleService.CurrentDevice is NonConnectedMockDevice))
			{
				await AddDevice(bleConsoleService.CurrentDevice);
			}
			if (developerSettings.MockDevicesEnabled)
			{
				try
				{
					await deviceCollectionSemaphore.WaitAsync();
					MockDeviceUtil.AddMockDevices(Devices);
					Devices?.Add(TcpDevice.SharedDevice);
					Devices.SortDevices();
					whenDeviceAdded.OnNext(Devices?.ToList());
				}
				finally
				{
					deviceCollectionSemaphore.Release();
				}
			}
			deviceFoundSub = scanner.ScanWithFilter(new FitProDeviceFilter()).Distinct((IBleDevice x) => x.PairKey).SubscribeAsyncWithErrorLogging(AddDevice);
		}

		public async Task AddDevice(IBleDevice device)
		{
			Log.Trace("Ble", $"AddDevice device parameter is not null: {device != null}");
			if (device == null || device is NonConnectedMockDevice)
			{
				return;
			}
			Guid id = device.Id;
			Guid? obj = bleConsoleService.CurrentDevice?.Id;
			if (id == obj && device != bleConsoleService.CurrentDevice && bleConsoleService.ConnectionState != ConsoleConnectionState.Connecting)
			{
				Log.Trace("Ble", GetType().Name + " automatically connected to device " + device?.Name + " (" + device?.PairKey + ")");
				whenShouldConnectToDevice.OnNext(device);
				return;
			}
			try
			{
				await deviceCollectionSemaphore.WaitAsync();
				IBleDevice bleDevice = Devices.FirstOrDefault((IBleDevice x) => x.Id == device.Id || x.Name.Equals(device.Name, StringComparison.OrdinalIgnoreCase));
				if (bleDevice == null)
				{
					Log.Trace("Ble", GetType().Name + " added new device " + device?.Name + " (" + device?.PairKey + ")");
					Devices.Add(device);
				}
				else if (device.PairKey.IsNotNullOrWhiteSpace())
				{
					Log.Trace("Ble", GetType().Name + " replaced device " + bleDevice?.Name + " (" + bleDevice?.PairKey + ") with " + device?.Name + " (" + device?.PairKey + ")");
					Devices.Remove(bleDevice);
					Devices.Add(device);
				}
				else
				{
					Log.Warn("Ble", GetType().Name + " did not add device " + device?.Name + " because duplicate device " + bleDevice?.Name + " (" + bleDevice?.PairKey + ") was present and had valid pair key while this one did not");
				}
				Devices.SortDevices();
				whenDeviceAdded.OnNext(Devices.ToList());
			}
			catch (Exception ex)
			{
				Log.Trace("Ble", GetType().Name + " exception (" + ex.Message + ") while adding new device " + device?.Name + " (" + device?.PairKey + ")");
			}
			finally
			{
				deviceCollectionSemaphore.Release();
			}
		}

		public void StopScan()
		{
			scanner.StopScan();
		}

		public void Dispose()
		{
			deviceFoundSub?.Dispose();
			deviceFoundSub = null;
			whenDeviceAdded?.OnCompleted();
			whenDeviceAdded?.Dispose();
			whenDeviceAdded = null;
			whenShouldConnectToDevice?.OnCompleted();
			whenShouldConnectToDevice?.Dispose();
			whenShouldConnectToDevice = null;
		}
	}
}
