	public class WorkoutApiService : IWorkoutApiService
	{
		private readonly IDeviceInformation deviceInformation;

		private readonly IIfitApiService api;

		private readonly IWorkoutFeatureService workoutFeatureService;

		private readonly ICurrentConsoleService currentConsoleService;

		public WorkoutApiService(IDeviceInformation deviceInformation, IIfitApiService api, IWorkoutFeatureService workoutFeatureService, ICurrentConsoleService currentConsoleService)
		{
			this.deviceInformation = deviceInformation;
			this.api = api;
			this.workoutFeatureService = workoutFeatureService;
			this.currentConsoleService = currentConsoleService;
		}

		public async Task<Workout> Get(string id, bool force = false, CancellationToken cancelToken = default(CancellationToken))
		{
			bool doEnableScaling = !HRTrainingService.IsHRTestWorkoutId(id) && ShouldEnableScaling();
			int softwareNumber = deviceInformation.SoftwareNumber;
			if (deviceInformation.IsHeadlessBikeVault && (currentConsoleService?.IsAttachedConsoleActive ?? false))
			{
				int? num = currentConsoleService?.ActiveConsole?.ConsoleInfo?.PartNumber;
				if (num.HasValue)
				{
					softwareNumber = num.Value;
				}
			}
			Log.Info("Api", $"Retrieving workout data for Id={id} softwareNumber={softwareNumber} doEnableScaling={doEnableScaling}");
			Workout workout = await Workout.Get(api, id, softwareNumber, force, doEnableScaling).ConfigureAwait(continueOnCapturedContext: false);
			if (workout == null || (doEnableScaling && workout.GetScaledWorkoutDetails() == null))
			{
				Log.Trace("Api", "Forcing reload of workout (id: " + id + ") because workout was null or missing controls");
				Workout workout2 = await Workout.Get(api, id, softwareNumber, force: true, doEnableScaling).ConfigureAwait(continueOnCapturedContext: false);
				if (workout != null && workout != workout2)
				{
					workout.Dispose();
					workout = null;
				}
				if (cancelToken.IsCancellationRequested)
				{
					workout?.Dispose();
					workout2?.Dispose();
					return null;
				}
				workout = workout2;
			}
			return workout;
		}

		public async Task<List<Workout>> GetWorkouts(List<string> workoutIds, bool trim = true)
		{
			int value = currentConsoleService?.ActiveConsole?.ConsoleInfo?.PartNumber ?? deviceInformation.SoftwareNumber;
			bool doEnableScaling = ShouldEnableScaling();
			try
			{
				return (await Workout.GetWorkouts(api, workoutIds, value, trim, doEnableScaling).ConfigureAwait(continueOnCapturedContext: false)) ?? new List<Workout>();
			}
			catch (Exception ex)
			{
				Log.Error("Api", "Couldn't get workouts: " + ex.Message);
				return new List<Workout>();
			}
		}

		public async Task<string> Create(Workout workout)
		{
			return await workout.Create(api);
		}

		private bool ShouldEnableScaling()
		{
			if (!workoutFeatureService.IsSmartAdjustAvailable(currentConsoleService?.ActiveConsole?.ConsoleInfo?.MachineType))
			{
				return workoutFeatureService.IsActivePulseAvailable(currentConsoleService?.ActiveConsole?.ConsoleInfo?.MachineType);
			}
			return true;
		}
	}
