{
	public interface IConnectedBluetoothAccessories : IDisposable
	{
		int DeviceCount { get; }

		IObservable<int> WhenDeviceCountChanged { get; }
	}
	public class ConnectedBluetoothAccessories : IConnectedBluetoothAccessories, IDisposable
	{
		protected bool isDisposed;

		private readonly Subject<int> _whenDeviceCountChanged = new Subject<int>();

		private int _deviceCount;

		private readonly HeadphoneConnectionHelperBase headphoneConnectionHelper;

		private readonly IHeartRateHelper heartRateConnectionHelper;

		private readonly IDisposable headphoneConnectionChangedSub;

		private readonly IDisposable heartRateConnectionChangedSub;

		public IObservable<int> WhenDeviceCountChanged => _whenDeviceCountChanged;

		public int DeviceCount
		{
			get
			{
				return _deviceCount;
			}
			set
			{
				if (value != _deviceCount)
				{
					_deviceCount = value;
					_whenDeviceCountChanged.OnNext(_deviceCount);
				}
			}
		}

		public ConnectedBluetoothAccessories(IHeartRateService heartRateService, HeadphoneConnectionHelperBase headphoneConnectionHelper)
		{
			this.headphoneConnectionHelper = headphoneConnectionHelper;
			heartRateConnectionHelper = heartRateService.HeartRate;
			_deviceCount = CountConnectedDevices();
			headphoneConnectionChangedSub = headphoneConnectionHelper.OnConnected.SubscribeWithErrorLogging(HandleHeadphoneConnectionStateChanged);
			heartRateConnectionChangedSub = heartRateService.HeartRate.WhenConnectionChanged.SubscribeWithErrorLogging(HandleHRMConnectionStateChanged);
		}

		private void HandleHeadphoneConnectionStateChanged(bool isConnected)
		{
			int num = 0;
			num += (isConnected ? 1 : 0);
			num += (heartRateConnectionHelper.IsConnected ? 1 : 0);
			DeviceCount = num;
		}

		private void HandleHRMConnectionStateChanged(bool _)
		{
			DeviceCount = CountConnectedDevices();
		}

		private int CountConnectedDevices()
		{
			int num = 0;
			num += (headphoneConnectionHelper.IsConnected() ? 1 : 0);
			return num + (heartRateConnectionHelper.IsConnected ? 1 : 0);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					headphoneConnectionChangedSub.Dispose();
					heartRateConnectionChangedSub.Dispose();
				}
				isDisposed = true;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
}
