		};

		private readonly Dictionary<IMetric, TimeBasedMetric> runningTimeMetricsDictionary = new Dictionary<IMetric, TimeBasedMetric>();

		private Dictionary<IMetric, MetricEntry> metricsDictionary = new Dictionary<IMetric, MetricEntry>();

		private bool isRecordingStarted;

		public IList<IMetric> VisibleMetrics { get; private set; }

		public int MinRecordingTimeInSeconds { get; }

		public InWorkoutFlipperMetricsManager()
		{
			VisibleMetrics = new List<IMetric>();
			MinRecordingTimeInSeconds = 5;
		}

		public void InitializeVisibleMetrics(IEnumerable<IMetric> defaultVisibleMetrics)
		{
			runningTimeMetricsDictionary.Clear();
			metricsDictionary = defaultVisibleMetrics.ToDictionary((IMetric metric) => metric, (IMetric metric) => new MetricEntry(metric.ToString(), 0));
			VisibleMetrics = new List<IMetric>(defaultVisibleMetrics);
			if (isRecordingStarted)
			{
				StartOrResumeRecordingAllMetrics();
			}
		}

		public void UpdateVisibleMetric(IMetric oldMetric, IMetric newMetric)
		{
			UpdateVisibleMetricsList(oldMetric, newMetric);
			if (!metricsDictionary.ContainsKey(newMetric))
			{
				MetricEntry value = new MetricEntry(newMetric.ToString(), 0);
				metricsDictionary.Add(newMetric, value);
			}
			if (isRecordingStarted)
			{
				DateTime utcNow = DateTime.UtcNow;
				StopRecordingMetric(oldMetric, utcNow);
				StartRecordingMetric(newMetric, utcNow);
			}
		}

		public void StartOrResumeRecordingAllMetrics()
		{
			DateTime utcNow = DateTime.UtcNow;
			foreach (IMetric visibleMetric in VisibleMetrics)
			{
				runningTimeMetricsDictionary[visibleMetric] = new TimeBasedMetric(isMetricRunning: true, utcNow);
			}
			if (!isRecordingStarted)
			{
				isRecordingStarted = true;
			}
		}

		public void StopRecordingAllMetrics(DateTime stopTime)
		{
			PauseRecordingAllMetrics(stopTime);
			isRecordingStarted = false;
			VisibleMetrics.Clear();
			runningTimeMetricsDictionary.Clear();
		}

		public void PauseRecordingAllMetrics(DateTime stopTime)
		{
			foreach (KeyValuePair<IMetric, TimeBasedMetric> item in runningTimeMetricsDictionary)
			{
				StopRecordingMetric(item.Key, stopTime);
			}
		}

		public Dictionary<string, object> FlipperMetricsToAnalytics()
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			foreach (KeyValuePair<IMetric, MetricEntry> item in metricsDictionary)
			{
				if (item.Value.Value >= MinRecordingTimeInSeconds)
				{
					string metric = GetMetric(item.Key);
					if (metric == null)
					{
						Log.Trace("InWorkoutFlipperMetricsManager", string.Format("Unknown metric: {0}, {1} is null.", item.Key, "flipperMetric"));
					}
					else
					{
						dictionary.Add(metric, item.Value.Value);
					}
				}
			}
			metricsDictionary.Clear();
			return dictionary;
		}

		private void UpdateVisibleMetricsList(IMetric oldMetric, IMetric newMetric)
		{
			int num = VisibleMetrics.IndexOf(oldMetric);
			if (num != -1)
			{
				VisibleMetrics.RemoveAt(num);
				VisibleMetrics.Insert(num, newMetric);
			}
			else
			{
				Log.Trace("InWorkoutFlipperMetricsManager", string.Format("{0} don't containt metric {1}", "VisibleMetrics", oldMetric));
				VisibleMetrics.Insert(0, newMetric);
			}
		}

		private void StopRecordingMetric(IMetric metric, DateTime stopTime)
		{
			if (!runningTimeMetricsDictionary.TryGetValue(metric, out var value) || !value.IsMetricRunning)
			{
				return;
			}
			DateTime startTime = value.StartTime;
			if (metricsDictionary.TryGetValue(metric, out var value2))
			{
				double num = stopTime.Subtract(startTime).TotalSeconds + (double)value2.Value;
				if (num >= 0.0)
				{
					value2.Value = (int)num;
					value2.DoubleValue = num;
					value.IsMetricRunning = false;
				}
			}
		}

		private void StartRecordingMetric(IMetric metric, DateTime startTime)
		{
			runningTimeMetricsDictionary[metric] = new TimeBasedMetric(isMetricRunning: true, startTime);
		}

		private string GetMetric(IMetric metric)
		{
			string name = metric.GetType().Name;
			if (flipperMetricsDictionary.TryGetValue(name, out var value))
			{
				return value;
			}
			return null;
		}
	}
