		private void SharedSetup()
		{
			SetGoogleAnalyticsUserProperties(delegate(Dictionary<string, object> props)
			{
				AddSharedEventProperties(props, forGoogleAnalytics: true);
			});
			base.WhenConsoleChangedSub = currentConsoleService.WhenConsoleChanged.Subscribe(OnConsoleChanged);
			lifecycleService.AppStateChanged -= OnAppStateChanged;
			lifecycleService.AppStateChanged += OnAppStateChanged;
			if (Mvx.TryResolve<IDeveloperSettings>(out var service))
			{
				UpdateVisibleAnalytics(service.VisibleAnalytics);
			}
		}

		protected override void ReportException(string message, Exception ex)
		{
			if (ex is SQLiteException ex2 && ex2.Message.Contains("disk is full"))
			{
				blobCacheFileManager?.LogCacheInformation();
				Log.Fatal("Analytics", message, ex);
			}
			else
			{
				Log.Error("Analytics", message, ex);
			}
		}

