		private void OnAppStateChanged(object sender, AppStateEventArgs e)
		{
			if (e.CurrentState == AppLifecycleService.AppState.Background)
			{
				PostEvent("Application Backgrounded");
			}
			else if (e.CurrentState == AppLifecycleService.AppState.Foreground)
			{
				PostEvent("App Session Started");
			}
		}

