		public async Task StartedWorkout(WorkoutContainerContext workoutContainerContext, IFitnessConsole console)
		{
			Workout workout = workoutContainerContext.Workout;
			AnalyticsSource analyticsSource = workoutContainerContext.AnalyticsSource;
			Workout.WorkoutContext? workoutContext = workoutContainerContext.Context?.Context;
			Guid? guid = workoutContainerContext.Container?.WorkoutAnalyticsId;
			LiveWorkouts.WorkoutInfo liveWorkoutInfo = workoutContainerContext.Context?.ScheduleInfo;
			IDictionary<string, object> properties = WorkoutProperties(workout);
			if (liveWorkoutInfo != null)
			{
				properties["liveContext"] = liveWorkoutInfo.Context.ToString();
				properties["liveScheduleId"] = liveWorkoutInfo.Id;
			}
			properties["source"] = analyticsSource.Source.ToString();
			if (analyticsSource.DashboardIndex != -1)
			{
				properties["sourceIndex"] = analyticsSource.DashboardIndex;
			}
			AddWorkoutFilterProperties(properties, workout);
			properties["wolfGeneratedId"] = workoutContainerContext.WolfGeneratedId;
			properties["workoutInstanceId"] = guid;
			if (!string.IsNullOrWhiteSpace(workoutContainerContext.ProgramId))
			{
				properties["programId"] = workoutContainerContext.ProgramId;
			}
			if (!string.IsNullOrWhiteSpace(workoutContainerContext.ChallengeId))
			{
				properties["challengeId"] = workoutContainerContext.ChallengeId;
			}
			properties["isNonConnected"] = console?.IsNonconnectedConsole();
			await TrackWithGoogleAnalytics("Started_Workout", properties, throwIfInvalid: true);
			if (liveWorkoutInfo != null)
			{
				properties["liveStartTime"] = liveWorkoutInfo.AirDateStartTime;
			}
			AddWebviewProperties(properties);
			await AddConsoleUuid(properties);
			if (workout.IsLiveWorkout)
			{
				properties["isLivePreRecordedWorkout"] = workoutContext == Workout.WorkoutContext.ScheduledPre;
			}
			if (base.IpcVersionInfo?.WebViewVersion != null)
			{
				properties["webViewVersion"] = base.IpcVersionInfo?.WebViewVersion;
			}
			properties["isFeedFmPlaybackEnabled"] = !mediaSettings.HasDisabledFeedFmPlayback;
			bool flag = (base.FeatureFlagManager?.IsFeatureEnabled(FeatureFlags.LeaderboardOffScreenDisposal) ?? false) && !workoutContainerContext.ShouldAutomaticallyShowLeaderboard;
			properties["leaderboardDisabled"] = flag;
			if (base.IsSegmentEnabled)
			{
				await PostEvent("Started Workout", properties);
			}
			sKAdNetworkConversionUpdater?.SendConversionEvent("Started Workout");
		}

		public async Task InWorkoutWidgetInteraction(Workout workout, string interactionType, bool on, string widgetType)
		{
			IDictionary<string, object> dictionary = WorkoutProperties(workout);
			dictionary.Add("workoutWidgetInteractionType", interactionType);
			dictionary.Add("workoutWidgetOn", on);
			dictionary.Add("workoutWidgetType", widgetType);
			await PostEvent("In Workout Widget Interaction", dictionary);
		}

		public async Task CompletedWorkout(IWorkoutContainer workoutContainer, IFitnessConsole console, ActivityLog activityLog = null, StartPeriodicDataTimingReport timingReport = null)
		{
			Workout workout = workoutContainer.Workout;
			ConsoleStateStats stats = workoutContainer.Stats;
			Workout.WorkoutContext workoutContext = workoutContainer.WorkoutRunner.RunContext.Context;
			Guid workoutAnalyticsId = workoutContainer.WorkoutAnalyticsId;
			LiveWorkouts.WorkoutInfo liveWorkoutInfo = workoutContainer.WorkoutRunner?.RunContext?.ScheduleInfo;
			Dictionary<string, object> allProperties = WorkoutProperties(workout).ToDictionary();
			if (activityLog != null)
			{
				IDictionary<string, object> coreActivityLogProperties = CoreAnalytics.GetCoreActivityLogProperties(activityLog);
				if (allProperties.ContainsKey("workoutId"))
				{
					allProperties.Remove("workoutId");
				}
				allProperties = allProperties.Union(coreActivityLogProperties).ToDictionary();
			}
			allProperties["workoutInstanceId"] = workoutAnalyticsId;
			if (liveWorkoutInfo != null)
			{
				allProperties["liveContext"] = liveWorkoutInfo.Context.ToString();
				allProperties["liveScheduleId"] = liveWorkoutInfo.Id;
			}
			allProperties["isNonConnected"] = console?.IsNonconnectedConsole();
			allProperties["incompleteWorkout"] = !workout.IsComplete && !workout.IsManual();
			if (!string.IsNullOrWhiteSpace(workoutContainer.ProgramId))
			{
				allProperties["programId"] = workoutContainer.ProgramId;
				allProperties["workoutCount"] = deviceInfo.NumberOfWorkouts;
			}
			if (!string.IsNullOrWhiteSpace(workoutContainer.ChallengeId))
			{
				allProperties["challengeId"] = workoutContainer.ChallengeId;
			}
			Dictionary<string, object> dictionary = allProperties.ToDictionary();
			if (!workout.WorkoutFilters.IsNullOrEmpty())
			{
				dictionary["workout_filters"] = string.Join(',', workout.WorkoutFilters);
			}
			await TrackWithGoogleAnalytics("Completed_Workout", dictionary, throwIfInvalid: true);
			IDictionary<string, object> second = PostWorkoutProperties(workout, stats);
			allProperties = allProperties.Union(second).ToDictionary();
			CoreAnalytics.AddExtraActivityLogProperties(activityLog, allProperties);
			AddWorkoutFilterProperties(allProperties, workout);
			AddWebviewProperties(allProperties);
			await AddConsoleUuid(allProperties);
			if (workout.IsLiveWorkout)
			{
				allProperties["isLivePreRecordedWorkout"] = workoutContext == Workout.WorkoutContext.ScheduledPre;
			}
			if (liveWorkoutInfo != null)
			{
				allProperties["liveStartTime"] = liveWorkoutInfo.AirDateStartTime;
				allProperties["liveSecondsCompleted"] = (int)Math.Round(stats.RunningStats.TimeSeconds.MaxTimestamp);
			}
			if (base.IpcVersionInfo?.WebViewVersion != null)
			{
				allProperties["webViewVersion"] = base.IpcVersionInfo.WebViewVersion;
			}
			allProperties["isFeedFmPlaybackEnabled"] = !mediaSettings.HasDisabledFeedFmPlayback;
			allProperties["userStartedMusicCount"] = workoutSettings.WorkoutContainer.AudioControlMetrics.UserStartedMusicCount;
			allProperties["userStoppedMusicCount"] = workoutSettings.WorkoutContainer.AudioControlMetrics.UserStoppedMusicCount;
			if (!string.IsNullOrWhiteSpace(workoutContainer.ProgramId))
			{
				allProperties["userFirstWorkout"] = deviceInfo.NumberOfWorkouts == 1;
			}
			if (workout.IsStrengthWorkout())
			{
				allProperties["workoutEstAvgBpm"] = (workout.Metadata?.AverageHeartRate).GetValueOrDefault();
			}
			timingReport?.GetAnalyticsProperties(allProperties);
			if (base.IsSegmentEnabled)
			{
				await PostEvent("Completed Workout", allProperties).ConfigureAwait(continueOnCapturedContext: false);
			}
			sKAdNetworkConversionUpdater?.SendConversionEvent("Completed Workout");
		}

