			if (base.FeatureFlagManager?.IsFeatureEnabled(FeatureFlags.UnexpectedShutdown) ?? false)
			{
				Dictionary<string, object> properties = new Dictionary<string, object>
				{
					{ "screen", lastGoodStateReporterInfo.CurrentViewModel },
					{ "totalMemory", lastGoodStateReporterInfo.TotalMemory },
					{ "availableMemory", lastGoodStateReporterInfo.AvailableMemory },
					{ "lowMemoryThreshold", lastGoodStateReporterInfo.LowMemoryThreshold },
					{ "machineType", lastGoodStateReporterInfo.MachineType }
				};
				await TrackWithGoogleAnalytics("Unexpected_Shutdown", properties, throwIfInvalid: false);
				if (base.IsSegmentEnabled)
				{
					await PostEvent("Unexpected Shutdown", properties);
				}
			}
		}

		public async Task UnexpectedShutdownInWorkout(WorkoutRecoveryInfo workoutRecoveryInfo)
		{
			Log.Fatal("Workout", "Wolf did not shut down cleanly last time");
			bool flag = (base.FeatureFlagManager?.IsFeatureEnabled(FeatureFlags.LeaderboardOffScreenDisposal) ?? false) && !workoutRecoveryInfo.ShouldAutomaticallyShowLeaderboard;
			Dictionary<string, object> properties = workoutRecoveryInfo.ToDictionary("workoutId");
			properties["leaderboardDisabled"] = flag;
			await TrackWithGoogleAnalytics("Unexpected_Shutdown_In_Workout", properties, throwIfInvalid: true);
