		private static string GetSafeString(string value)
		{
			if (!string.IsNullOrWhiteSpace(value))
			{
				return value;
			}
			return "null";
		}

		public async Task SendCpuUtilizationReport(CpuUtilizationReport cpuUtilReport)
		{
			if (cpuUtilReport != null)
			{
				Dictionary<string, object> properties = new Dictionary<string, object>
				{
					{ "workoutId", cpuUtilReport.WorkoutId },
					{ "workoutCategory", cpuUtilReport.WorkoutCategory },
					{
						"isRecoveredWorkout",
						cpuUtilReport.IsRecoveryWorkout?.ToString() ?? "unknown"
					},
					{ "samplingIntervalMs", cpuUtilReport.SamplingIntervalMs },
					{ "cpuThresholdPercent", cpuUtilReport.CpuHighUsageThreshold }
				};
				AddCpuReportProperties(properties, cpuUtilReport.Warmup, "warmup");
				AddCpuReportProperties(properties, cpuUtilReport.InWorkout, "inWorkout");
				AddCpuReportProperties(properties, cpuUtilReport.Cooldown, "cooldown");
				await PostEvent("CPU Utilization Report", properties);
			}
		}

		private void AddCpuReportProperties(Dictionary<string, object> properties, CpuUtilizationReportSection reportSection, string reportTypePrefix)
		{
			properties[reportTypePrefix + "SamplesOverThreshold"] = reportSection.SamplesOverHighUsageThreshold;
			properties[reportTypePrefix + "StartingCpuPercent"] = (int)Math.Round(reportSection.StartingCpuUtil);
			properties[reportTypePrefix + "AvgCpuPercent"] = (int)Math.Round(reportSection.AvgCpuUtil);
			properties[reportTypePrefix + "MaxCpuPercent"] = (int)Math.Round(reportSection.MaxCpuUtil);
			properties[reportTypePrefix + "NumSamples"] = reportSection.NumSamples;
		}

		public async Task SendMemoryUtilizationReport(MemoryUtilizationReport memUtilReport)
		{
			if (memUtilReport != null)
			{
				Dictionary<string, object> properties = new Dictionary<string, object>
				{
					{ "workoutId", memUtilReport.WorkoutId },
					{ "workoutCategory", memUtilReport.WorkoutCategory },
					{
						"isRecoveredWorkout",
						memUtilReport.IsRecoveryWorkout?.ToString() ?? "unknown"
					},
					{ "samplingIntervalMs", memUtilReport.SamplingIntervalMs },
					{ "androidTotalMemoryKb", memUtilReport.AndroidTotalMemoryKb },
					{ "androidThresholdMemoryKb", memUtilReport.AndroidThresholdMemoryKb }
				};
				AddMemoryReportProperties(properties, memUtilReport.Warmup.StartingSample, "warmup", "Starting");
				AddMemoryReportProperties(properties, memUtilReport.InWorkout.StartingSample, "inWorkout", "Starting");
				AddMemoryReportProperties(properties, memUtilReport.Cooldown.StartingSample, "cooldown", "Starting");
				AddMemoryReportProperties(properties, memUtilReport.Warmup.AverageValues, "warmup", "Avg");
				AddMemoryReportProperties(properties, memUtilReport.InWorkout.AverageValues, "inWorkout", "Avg");
				AddMemoryReportProperties(properties, memUtilReport.Cooldown.AverageValues, "cooldown", "Avg");
				AddMemoryReportProperties(properties, memUtilReport.Warmup.MaxValues, "warmup", "Max");
				AddMemoryReportProperties(properties, memUtilReport.InWorkout.MaxValues, "inWorkout", "Max");
				AddMemoryReportProperties(properties, memUtilReport.Cooldown.MaxValues, "cooldown", "Max");
				await PostEvent("Memory Utilization Report", properties);
			}
		}

		private void AddMemoryReportProperties(Dictionary<string, object> properties, MemoryUtilizationReport.MemorySample sample, string reportTypePrefix, string dataType)
		{
			properties[reportTypePrefix + dataType + "AndroidAvailMemKb"] = sample.AndroidAvailableMemoryKb;
			properties[reportTypePrefix + dataType + "AndroidPrivateDirtyMemKb"] = sample.AndroidTotalPrivateDirtyKb;
			properties[reportTypePrefix + dataType + "AndroidPssKb"] = sample.AndroidTotalProportionalSetSizeKb;
			properties[reportTypePrefix + dataType + "LinuxRssPages"] = sample.LinuxResidentSetSizePages;
			properties[reportTypePrefix + dataType + "MonoTotalManagedMemKb"] = sample.MonoTotalManagedMemoryKb;
		}

		private void OnConsoleChanged(IFitnessConsole fitProConsole)
		{
			base.Console = fitProConsole;
			if (fitProConsole == null)
			{
				SetGoogleAnalyticsUserProperties(null);
				return;
			}
			if (fitProConsole.Initialized)
			{
				SetGoogleAnalyticsUserProperties(fitProConsole.ConsoleInfo);
			}
			base.WhenConsoleInitializedSub = base.Console.WhenConsoleInitialized.Subscribe(OnConsoleInitialized);
		}

		private void OnConsoleInitialized(IConsoleInfo arg)
		{
			base.WhenConsoleInitializedSub?.Dispose();
			SetGoogleAnalyticsUserProperties(arg);
			base.WhenConsoleInitializedSub = base.Console?.WhenStateChanged?.Take(1).SubscribeAsync(async delegate
			{
				base.WhenConsoleInitializedSub?.Dispose();
				await OnUserChanged();
			});
		}

		protected override void AddSharedEventProperties(IDictionary<string, object> properties, bool forGoogleAnalytics)
		{
			base.AddSharedEventProperties(properties, forGoogleAnalytics);
			if (!forGoogleAnalytics)
			{
				properties["deviceName"] = deviceInfo.DeviceName;
				properties["screenSizeInches"] = (int)Math.Round(deviceInfo.DisplaySizeInches);
				properties["screenResolution"] = deviceInfo.CreateDisplayResolutionString();
				properties["isStrengthMirror"] = deviceInfo.IsStrengthMirror;
				properties["strengthMirrorSerialNumber"] = deviceInfo.StrengthMirrorSerialNumber;
				if (deviceInfo.FontScale.HasValue)
				{
					properties["fontScale"] = deviceInfo.FontScale;
				}
				if (deviceInfo.DpiDensity.HasValue)
				{
					properties["dpiDensity"] = deviceInfo.DpiDensity;
				}
				if (Mvx.TryResolve<IChangeLanguageService>(out var service))
				{
					properties["currentLanguage"] = service.GetTwoLetterISOCode(localSettings.CurrentLanguage);
				}
			}
		}

