		{
			webviewEventMap["Unknown"] = "Unknown Webview Event";
			webviewEventMap["JoinProgram"] = "Joined Program";
			webviewEventMap["LeaveProgram"] = "Left Program";
			webviewEventMap["FavoriteWorkout"] = "Favorited Workout";
			webviewEventMap["UnfavoriteWorkout"] = "Unfavorited Workout";
			webviewEventMap["FavoriteProgram"] = "Favorited Program";
			webviewEventMap["UnfavoriteProgram"] = "Unfavorited Program";
			webviewEventMap["ScheduleWorkout"] = "Scheduled Workout";
			webviewEventMap["DeleteScheduledWorkout"] = "Deleted Scheduled Workout";
			webviewEventMap["AppliedFilters"] = "Applied Filters";
			webviewEventMap["LoadedALibraryPage"] = "Loaded A Library Page";
		}

		public async Task WebviewEvent(IDictionary<string, string> args)
		{
			string value = string.Empty;
			if (args?.TryGetValue("event", out value) ?? false)
			{
				var (eventName, properties) = ParseWebViewData(value, args);
				await PostEvent(eventName, properties);
			}
			else
			{
				Log.Warn("WolfAnalytics", "No event name was provided from webview analytics call to WebviewEvent!");
			}
		}

		private (string webViewEvent, IDictionary<string, object> properties) ParseWebViewData(string eventString, IDictionary<string, string> args)
		{
			string item = (webviewEventMap.ContainsKey(eventString) ? webviewEventMap[eventString] : webviewEventMap["Unknown"]);
			IDictionary<string, object> item2 = null;
			try
			{
				if ((eventString == "AppliedFilters" || eventString == "LoadedALibraryPage") && args.TryGetValue("properties", out var value))
				{
					item2 = JsonConvert.DeserializeObject<Dictionary<string, object>>(value);
				}
			}
			catch (Exception exception)
			{
				Log.Error("Analytics", "Unable to read WebViewEvent properties data", exception);
			}
			return (webViewEvent: item, properties: item2);
		}

