		private string CurrentViewModelName()
		{
			if (Mvx.TryResolve<IDialogPresenter>(out var service))
			{
				return service?.CurrentMainViewModel?.GetType().Name ?? string.Empty;
			}
			return string.Empty;
		}

		public async Task ErrorCodeDisplayed(string title, string message, string errorCode)
		{
			Dictionary<string, object> properties = new Dictionary<string, object>
			{
				{ "dialogTitle", title },
				{ "dialogMessage", message },
				{ "errorCode", errorCode }
			};
			Dictionary<string, object> dictionary = properties;
			if (message.Length >= 100)
			{
				dictionary = new Dictionary<string, object>(properties);
				dictionary["dialogMessage"] = message.Substring(0, 100);
			}
			await TrackWithGoogleAnalytics("Error_Code_Displayed", dictionary, throwIfInvalid: false);
			if (base.IsSegmentEnabled)
			{
				await PostEvent("Error Code Displayed", properties);
			}
		}

