			await PostEvent("Language Initialized", properties).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task OnLanguageChanged(string deviceLanguage, string selectedLanguage, string oldLanguage = null)
		{
			Dictionary<string, object> properties = PropertiesForLanguage(deviceLanguage, selectedLanguage, oldLanguage);
			await PostEvent("Language Changed", properties).ConfigureAwait(continueOnCapturedContext: false);
		}

		private Dictionary<string, object> PropertiesForLanguage(string deviceLanguage, string selectedLanguage, string oldLanguage = null)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>
			{
				{ "deviceLanguage", deviceLanguage },
				{ "toLanguage", selectedLanguage }
			};
			if (oldLanguage != null)
			{
				dictionary["fromLanguage"] = oldLanguage;
			}
			return dictionary;
		}

